insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1740, '15', '치매 대상자의 주보호자인 며느리가 다음과 같이 말할 때 요양보호사의 대처방법은? "시아버지를 돌보고 있는데 남편은 고맙다는 말 한마디도 안 하고, 딸은 자기를 하나도 챙기지 않는다며 투정해요. 내가 집에서 노는 줄 알아요."', '["\"남편분에게 얼마나 힘든지 해보라고 하세요.\"", "\"가족들이 몰라주는 것 같아 속상하시겠어요.\"", "\"딸이 엄마를 도와주지는 못할망정 너무하네요.\"", "\"며느리가 돌보는건 당연해요. 조금만 참으세요.\"", "\"제가 가족들에게 도와주라고 말해 볼게요.\""]'::jsonb, 2, '치매 환자를 돌보는 주보호자의 감정에 대해 공감하고, 적절한 대처 방법을 찾는 것.', 'Tìm hiểu cảm xúc của người chăm sóc chính bệnh nhân Alzheimer và tìm cách xử lý phù hợp.', '{"1": ""}'::jsonb, '[{"term_ko": "주보호자", "term_vi": "Người chăm sóc chính", "def_ko": "환자를 곁에서 가장 많이 도와주는 사람", "def_vi": "Người giúp đỡ bệnh nhân nhiều nhất ở bên cạnh"}, {"term_ko": "시아버지", "term_vi": "Bố chồng", "def_ko": "남편의 아버지", "def_vi": "Bố của chồng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1739, '15', '치매 대상자가 주변에 아무도 없는데 저리 가!라고 소리치며 저기 검은 옷 입은 사람이 자꾸 나를 쳐다봐.라고 말할 때 올바른 대처방법은?', '["아무도 없다고 대상자에게 말한다.", "저리 가라고 대상자와 같이 소리친다.", "잘못한 일을 혼내려고 왔나보다고 말한다.", "간식을 제공하거나 좋아하는 활동을 하게 한다.", "기운이 없어서 헛것이 보이는 것이라고 말한다."]'::jsonb, 4, '치매 대상자의 이상 행동에 대한 올바른 대처 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', 'Đây là câu hỏi để đánh giá xem bạn có hiểu cách xử lý hành vi bất thường của người bị bệnh Alzheimer hay không.', '{"1": "대상자에게 아무도 없다고 말하는 것은 대상자의 불안을 더욱 심화시킬 수 있습니다.\nNói với bệnh nhân rằng không có ai sẽ làm trầm trọng thêm sự lo lắng của họ.", "2": "함께 소리치는 것은 상황을 더욱 악화시킬 수 있으므로 적절하지 않습니다.\nHét cùng với bệnh nhân có thể làm tình huống tồi tệ hơn và không thích hợp.", "3": "잘못한 일을 혼내려고 왔다고 말하는 것은 불필요한 혼란을 일으킬 수 있습니다.\nNói rằng bạn đến để la mắng họ có thể gây ra sự nhầm lẫn không cần thiết.\n\n[정답]", "4": "Cung cấp thức ăn nhẹ hoặc cho họ tham gia hoạt động yêu thích là cách xử lý phù hợp.", "5": "기운이 없어서 헛것이 보인다고 말하는 것은 대상자를 불안하게 만들 수 있습니다.\nNói rằng họ mệt mỏi và thấy ảo giác có thể làm tăng lo lắng cho bệnh nhân."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và suy nghĩ."}, {"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "보호를 받는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "불안", "term_vi": "Lo lắng", "def_ko": "걱정스러운 감정", "def_vi": "Cảm xúc lo lắng"}, {"term_ko": "대처 방법", "term_vi": "Cách xử lý", "def_ko": "문제를 해결하는 방식", "def_vi": "Cách giải quyết vấn đề"}, {"term_ko": "활동", "term_vi": "Hoạt động", "def_ko": "어떤 행동이나 작업", "def_vi": "Hành động hoặc công việc nào đó"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1738, '15', '치매 대상자가 다음과 같은정신행동증상을 보일 때 대처방법은? "목걸이가 없어졌어. 며느리가 가져간게 분명해. 내 방에 몰래 들어가는 걸 봤거든."', '["\"지난번에도 그러시더니, 또 의심하시네요.\"", "\"그래요? 반지나 팔찌는 없어지지 않았어요?\"", "\"앞으로는 저한테 맡기세요. 잘 보관해 드릴게요.\"", "\"목걸이 여기 있잖아요. 왜 그렇게 의심이 많으세요?\"", "\"목걸이가 없어져서 많이 속상하시겠어요.\"라며 함께 찾아본다."]'::jsonb, 5, '대체적으로 치매 대상자의 정신행동증상에 적합한 대처방법을 묻고 있습니다.', 'Hỏi về phương pháp ứng phó phù hợp với triệu chứng hành vi tâm thần của người bị sa sút trí tuệ.', '{"1": "대상자의 감정을 무시하고 비난하는 것이므로 부적절합니다.\nCách này không đúng vì phớt lờ cảm xúc của người bệnh và chỉ trích họ.", "2": "의심을 덜게 하기 위한 방식이지만, 상황을 인정하지 않아서 적절하지 않습니다.\nCách này không phù hợp vì không thừa nhận tình huống, mặc dù nó có thể làm giảm sự nghi ngờ.\n\n[정답]", "5": "Phương pháp này là tiếp cận phù hợp nhất vì hiểu cảm xúc của người bệnh và muốn cùng giải quyết vấn đề.", "3": "책임을 떠넘기는 것이므로 신뢰를 구축하기 어렵습니다.\nCách này sẽ khó xây dựng niềm tin vì chuyển trách nhiệm cho người khác.", "4": "비난의 요소가 있으며 대상자의 감정을 더욱 나쁘게 할 수 있습니다.\nCách này có yếu tố chỉ trích và có thể làm cho cảm xúc của bệnh nhân tồi tệ hơn."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "인지능력이 감소하는 병증", "def_vi": "Bệnh giảm khả năng nhận thức"}, {"term_ko": "대상자", "term_vi": "Người được chữa trị", "def_ko": "치료를 받는 사람", "def_vi": "Người nhận được trị liệu"}, {"term_ko": "정신행동증상", "term_vi": "Triệu chứng hành vi tâm thần", "def_ko": "정신적 또는 행동적 문제를 나타내는 증상", "def_vi": "Triệu chứng biểu hiện vấn đề về tâm lý hoặc hành vi"}, {"term_ko": "대처방법", "term_vi": "Phương pháp ứng phó", "def_ko": "특정 상황에 대한 대응 방법", "def_vi": "Phương pháp đáp ứng với một tình huống cụ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1737, '15', '치매 대상자가 자신의 옷에 배설한 것을 인지하지 못하고 의자에 앉아있을 때 대처방법은?', '["\"어휴 냄새...어르신은 냄새도 안 나세요?\"", "\"왜, 자꾸 실수하시는 거예요? 화장실은 저쪽에 있잖아요.\"", "\"화장실에 가서 옷 갈아입어요.\" 조용하고 부드럽게 말한다.", "\"대변을 봤으면 말씀을 하셔야지, 가만히 계시면 어떻게 해요?\"", "\"너무 많이 드셨나 봐요. 식사량과 음료수 섭취량을 줄여야겠네요.\""]'::jsonb, 3, '치매 환자에 대한 적절한 대처 방법을 묻는 문제입니다.', 'Câu hỏi này hỏi về cách đối phó phù hợp với bệnh nhân mất trí nhớ.', '{"1": "치매 환자에게는 냄새에 대한 말이 불안감이나 수치심을 유발할 수 있습니다.\nNói về mùi hôi có thể gây ra lo lắng hoặc xấu hổ cho bệnh nhân mất trí nhớ.", "2": "치매 환자에게 책임을 묻는 발언은 부정적인 반응을 일으킬 수 있습니다.\nViệc hỏi trách nhiệm có thể gây ra phản ứng tiêu cực từ bệnh nhân mất trí nhớ.\n\n[정답]", "3": "Nói nhẹ nhàng và êm ái sẽ giúp ích cho bệnh nhân mất trí nhớ.", "4": "책임을 묻는 질문은 치매 환자의 자존감에 해롭고, 부정적인 감정을 초래할 수 있습니다.\nCâu hỏi đặt trách nhiệm có thể gây hại cho lòng tự trọng và mang lại cảm giác tiêu cực cho bệnh nhân mất trí nhớ.", "5": "이러한 발언은 치료보다는 문제를 가중시킬 수 있습니다.\nCâu nói này có thể làm nặng thêm vấn đề hơn là chữa trị."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억과 사고에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và tư duy"}, {"term_ko": "대처", "term_vi": "Xử lý", "def_ko": "문제나 상황에 맞게 행동함", "def_vi": "Hành động phù hợp với tình huống hoặc vấn đề"}, {"term_ko": "부드럽다", "term_vi": "Mềm mại", "def_ko": "외부에 심한 영향이 없다", "def_vi": "Không có ảnh hưởng mạnh mẽ đến bên ngoài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1736, '15', '시도 때도 없이 먹으려 하는 치매 대상자가 다음과 말할 때 대처 방법은? "저녁 준비하고 있어? 나 밥 안 먹었는데, 밥 안 줬잖아?"', '["\"제가 방금 드렸잖아요.\" 라고 말한다.", "\"지금은 바빠서준비할 수 없습니다.\" 라고 말한다.", "\"조금만 기다려 주세요.\" 라고 말하며 화초를 닦아 달라고 말한다.", "\"하루 종일 너무 많이 드셔서 드릴 수 없습니다.\"라고 말한다.", "\"밥을 더 드리면 따님에게 혼나요. 이해해 주세요.\"라고 말한다."]'::jsonb, 3, '치매 환자에게 적절한 대처 방법을 이해하고 적용하는 능력을 평가하기 위해 제시한 질문입니다.', 'Câu hỏi được đưa ra nhằm đánh giá khả năng hiểu và áp dụng phương pháp đối phó phù hợp với bệnh nhân Alzheimer.', '{"1": "''제가 방금 드렸잖아요.'' 라고 말한다는 것은 환자의 불안감을 오히려 악화시킬 수 있습니다.\nCâu trả lời này có thể làm tăng thêm sự lo lắng cho bệnh nhân.\n\n[정답]", "3": "Nói ''Chỉ cần chờ một chút.'' và đề nghị bệnh nhân lau cây cũng có thể có hiệu quả tích cực bằng cách chuyển sự chú ý của họ sang điều khác.", "2": "''지금은 바빠서 준비할 수 없습니다.''라고 말하는 것은 환자를 실망시키고 상황을 악화시킬 수 있습니다.\nNói ''Bây giờ tôi bận nên không thể chuẩn bị'' có thể khiến bệnh nhân thất vọng và làm tình hình trở nên xấu đi.", "4": "''하루 종일 너무 많이 드셔서 드릴 수 없습니다.''라고 말하는 것은 환자의 기분이 상할 수 있습니다.\nNói ''Bạn đã ăn quá nhiều suốt cả ngày nên không thể đưa cho bạn được'' có thể làm tổn thương tâm trạng của bệnh nhân.", "5": "''밥을 더 드리면 따님에게 혼나요. 이해해 주세요.''라고 말하는 것은 환자에게 혼란을 줄 수 있습니다.\nNói ''Nếu bạn ăn thêm cơm, bạn sẽ bị con gái mắng. Xin hãy hiểu.'' có thể gây nhầm lẫn cho bệnh nhân."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 인지 기능이 점차적으로 저하되는 질환", "def_vi": "Bệnh lí suy giảm trí nhớ và chức năng nhận thức dần dần"}, {"term_ko": "대처", "term_vi": "Đối phó", "def_ko": "문제에 대응하는 방법", "def_vi": "Cách ứng phó với vấn đề"}, {"term_ko": "불안감", "term_vi": "Dùng từ", "def_ko": "마음이 편안하지 않은 상태", "def_vi": "Trạng thái không thoải mái trong tâm trí"}, {"term_ko": "주변", "term_vi": "Xung quanh", "def_ko": "인근 지역, 주변 환경", "def_vi": "Khu vực xung quanh, môi trường xung quanh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1735, '15', '치매 대상자가 같은 곳을 왔다 갔다 하고, 침을 뱉는 행동을 반복할 때 대처 방법은?', '["그만하라고 야단을 친다.", "반복하는행동을 못하게 한다.", "반복 행동을 지적하여 바로 잡는다.", "뒤에서 다가가 큰소리로 대상자를 부른다.", "수건 접기를 하여 관심을 다른 곳으로 유도한다."]'::jsonb, 5, '치매 환자에 대한 대처 방법을 이해하고 있는지를 평가한다.', 'Đánh giá khả năng hiểu biết về phương pháp xử lý đối với bệnh nhân bị bệnh mất trí nhớ.', '{"1": "그만하라고 야단을 친다.\n이 방법은 오히려 치매 환자에게 혼란과 불안을 초래할 수 있다.\nPhương pháp này có thể tạo ra sự nhầm lẫn và lo lắng cho bệnh nhân bị mất trí nhớ.", "2": "반복하는 행동을 못하게 한다.\n역시 이 방법은 치매 환자의 행동을 억제하기보다는 이해하고 대처하는 것이 필요하다.\nCách này cũng không nên vì cần phải hiểu và xử lý hành vi của bệnh nhân thay vì kiềm chế.", "3": "반복 행동을 지적하여 바로 잡는다.\n치매 환자는 인지능력이 떨어져 잘 이해하지 못할 수 있다.\nBệnh nhân mất trí nhớ có thể không nhận thức được do khả năng nhận thức giảm.", "4": "뒤에서 다가가 큰소리로 대상자를 부른다.\n이 방법은 치매 환자에게 놀라움을 줄 수 있어서 피해야 한다.\nCách này có thể gây bất ngờ cho bệnh nhân và nên tránh.\n\n[정답]", "5": "수건 접기를 하여 관심을 다른 곳으로 유도한다.\n이 방법은 부정적인 행동을 줄이고 긍정적인 대처 방법으로 환자의 관심을 전환시킨다.\nCách này giúp giảm bớt hành vi tiêu cực và chuyển sự chú ý của bệnh nhân sang một hoạt động tích cực khác.", "6": "(없음)"}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력을 잃는 질환", "def_vi": "Bệnh làm mất khả năng nhớ"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "돌보는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "반복 행동", "term_vi": "Hành vi lặp lại", "def_ko": "같은 행동을 여러 번 하는 것", "def_vi": "Làm hành động nhiều lần"}, {"term_ko": "수건", "term_vi": "Khăn", "def_ko": "물건의 일종, 일반적으로 사용", "def_vi": "Một loại đồ vật, sử dụng chung"}, {"term_ko": "관심", "term_vi": "Sự quan tâm", "def_ko": "주목하는 것", "def_vi": "Điều được chú ý"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1734, '15', '공격성이 나타나는 치매 대상자의 옷을 갈아입히는 방법으로 옳은 것은?', '["강제로 옷을 갈아입힌다.", "대상자가 화를 내면 같이 화를 낸다.", "옷에 물을 쏟아 젖게 하여 갈아입힌다.", "요양보호사의 기분이 좋을 때 갈아입힌다.", "가족에게 도움을 요청하여 함께 갈아입힌다."]'::jsonb, 3, '치매 환자에게 옷을 갈아입힐 때 필요한 접근 방식을 이해하고 있는지를 평가한다.', 'Đánh giá khả năng hiểu cách tiếp cận cần thiết khi thay quần áo cho bệnh nhân mắc chứng mất trí nhớ.', '{"1": "Ép buộc mặc quần áo không chỉ gây căng thẳng cho bệnh nhân mà còn không an toàn.\n\n[정답]", "3": "Khi bệnh nhân mất trí nhớ có biểu hiện hung hăng, cần phải có cách tiếp cận nhẹ nhàng, và việc làm ướt quần áo để thay có thể làm giảm cảm giác lo lắng cho bệnh nhân.", "4": "Tâm trạng của người chăm sóc không quan trọng, mà tình trạng của bệnh nhân cần được ưu tiên.", "5": "Việc yêu cầu sự giúp đỡ từ gia đình có thể là một phương pháp tốt, nhưng cần có cách tiếp cận mà có thể tự làm một mình."}'::jsonb, '[{"term_ko": "공격성", "term_vi": "Aggression", "def_ko": "환자가 보이는 스트레스나 감정의 폭발", "def_vi": "Những sự bùng nổ cảm xúc hoặc căng thẳng của bệnh nhân"}, {"term_ko": "갈아입히다", "term_vi": "Thay đồ", "def_ko": "옷을 입히기 위해 변화를 주다", "def_vi": "Thay đổi để mặc một bộ quần áo khác"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자의 돌봄을 담당하는 전문가", "def_vi": "Chuyên gia chịu trách nhiệm chăm sóc bệnh nhân"}, {"term_ko": "가족", "term_vi": "Gia đình", "def_ko": "친척이나 가까운 사람", "def_vi": "Người thân hoặc những người gần gũi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1733, '15', '치매 대상자가 인사를 하거나 말을 걸어도 반응이 없고, 의자에 가만히 앉아있을 때 요양보호사의 대처방법은?', '["대답하지 않으면 말 걸지 말고 그냥 둔다.", "대상자의 흥미를 유발할 수 있는 활동을 시도한다.", "대상자의 사소한 말이나 행동에는 관심을 두지 않는다.", "혼자 있는 시간을 갖도록 배려한다.", "걱정거리가 있는지 물어본다."]'::jsonb, 2, '치매 대상자에 대한 올바른 대처 방법을 물어보는 문제입니다.', 'Câu hỏi này hỏi về cách ứng phó đúng với người bị chứng mất trí nhớ.', '{"1": "대답하지 않으면 말 걸지 말고 그냥 둔다.\n대상자와의 소통이 부족해질 수 있습니다.\nNếu không trả lời, có thể dẫn đến sự thiếu giao tiếp với người bệnh.\n\n[정답]", "2": "대상자의 흥미를 유발할 수 있는 활동을 시도한다.\n대상자가 반응하도록 유도할 수 있는 효과적인 방법입니다.\nThử các hoạt động có thể kích thích sự hứng thú của người bệnh là cách hiệu quả để khuyến khích phản ứng.", "3": "대상자의 사소한 말이나 행동에는 관심을 두지 않는다.\n관심을 두지 않으면 소통이 더 어려워질 수 있습니다.\nNếu không quan tâm đến những lời nói hay hành động nhỏ của người bệnh, việc giao tiếp sẽ càng khó khăn hơn.", "4": "혼자 있는 시간을 갖도록 배려한다.\n상황에 따라 적절한 보살핌이 필요합니다.\nCần phải cân nhắc việc chăm sóc phù hợp tùy thuộc vào tình huống.", "5": "걱정거리가 있는지 물어본다.\n반응이 없는 상태에서 질문은 부담을 줄 수 있습니다.\nHỏi về những lo lắng có thể gây áp lực cho người bệnh trong trạng thái không phản ứng."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력, 사고력의 저하로 인한 증상", "def_vi": "Triệu chứng giảm trí nhớ và khả năng tư duy"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "요양보호 서비스의 수혜자", "def_vi": "Người nhận dịch vụ chăm sóc"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "자극에 대한 응답", "def_vi": "Đáp ứng với kích thích"}, {"term_ko": "소통", "term_vi": "Giao tiếp", "def_ko": "의사소통하는 것", "def_vi": "Việc giao tiếp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1732, '15', '치매 대상자의 목욕을 도와주려고 샤워기로 물을 뿌리자 대상자가 놀라서 소리를 지르며 밖으로 나가려고 할 때, 돕는 방법은?', '["욕실 문을 잠그고 빨리 씻긴다.", "목욕 도중에 소리를 질러도 무시한다.", "샤워기 물을 잠그고 대상자 혼자 욕실에 두고 나온다.", "목욕 후 대상자가 좋아하는 일을 하자며 목욕을 유도한다.", "대상자보다 큰소리로 야단치며 행동을 제압한다."]'::jsonb, 4, '치매 대상자에게 적절한 안전한 목욕 도와주기 방법을 찾기 위한 문제입니다.', 'Câu hỏi nhằm tìm ra phương pháp hỗ trợ tắm an toàn và hợp lý cho người bệnh đã bị mất trí nhớ.', '{"1": "Khóa cửa nhà tắm và tắm nhanh. Điều này không an toàn cho đối tượng và có thể làm họ hoảng sợ.", "2": "Bỏ qua tiếng hét giữa khi tắm. Điều này có thể làm tăng thêm lo lắng cho đối tượng.\n\n[정답]", "4": "Khuyến khích người bệnh tắm bằng cách hứa hẹn điều họ thích sau khi tắm. Đây là phương pháp giúp an tâm và hiệu quả.", "3": "Tắt vòi sen và để người bệnh ở một mình trong phòng tắm. Đây là hành động bỏ mặc họ, rất nguy hiểm.", "5": "La lớn hơn và kiểm soát hành động của bệnh nhân. Điều này sẽ làm tăng sự lo lắng cho họ và ảnh hưởng đến sự tin tưởng."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고 기능이 손상된 상태", "def_vi": "Tình trạng tổn thương trí nhớ và khả năng suy nghĩ"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "간호나 돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc hoặc điều trị"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 물로 씻는 것", "def_vi": "Hành động rửa sạch cơ thể bằng nước"}, {"term_ko": "욕실", "term_vi": "Phòng tắm", "def_ko": "목욕을 하는 방", "def_vi": "Phòng dành cho việc tắm"}, {"term_ko": "안심", "term_vi": "Yên tâm", "def_ko": "불안하지 않게 하는 것", "def_vi": "Làm cho người khác không lo lắng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1731, '15', '중풍으로 오른쪽 팔과 다리가 불편한 대상자가 치매 증상이 십해지면서 옷을 갈아 입지 않으려고 할 때 돕는 방법은?', '["냄새나도 모른척하며 다른 일을 한다.", "갈아입을 옷을 주고 혼자서 갈아입게 한다.", "대상자가 거부해도 강제로 옷을 갈아입힌다.", "갈아입지 않으려는 이유를 설명해 달라고 한다.", "가족과 상의하여 동일한 유형의 옷을 구입하여 입게 한다."]'::jsonb, 5, '대상자의 치매 증상과 의사소통의 어려움을 고려하여 적절한 방법을 찾는 것.', 'Câu hỏi yêu cầu tìm phương pháp hợp lý trong bối cảnh bệnh nhân bị chứng mất trí nhớ và khó khăn trong giao tiếp.', '{"1": "환자의 정서와 위생을 고려하지 않는 방법이다.\nPhương pháp này không xem xét cảm xúc và vệ sinh của bệnh nhân.", "2": "환자가 혼자서 옷을 갈아입는 것은 위험할 수 있다.\nViệc để bệnh nhân tự thay quần áo có thể gây nguy hiểm.\n\n[정답]", "5": "Phương pháp này xem xét sự thoải mái và sở thích của bệnh nhân.", "3": "강제로 옷을 입히는 것은 대상자의 신뢰를 잃게 만든다.\nViệc ép buộc thay đồ có thể làm mất lòng tin của bệnh nhân.", "4": "이유를 물어보는 것은 치매 환자에게 적합하지 않다.\nHỏi lý do là không phù hợp với bệnh nhân mắc chứng mất trí nhớ."}'::jsonb, '[{"term_ko": "중풍", "term_vi": "Đột quỵ", "def_ko": "뇌졸중", "def_vi": "tổn thương do máu không lưu thông đến não"}, {"term_ko": "옷", "term_vi": "Quần áo", "def_ko": "착용하는 물건", "def_vi": "vật dụng mặc trên người"}, {"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억 상실증", "def_vi": "chứng bệnh liên quan đến trí tuệ"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "치료 또는 간호를 받는 사람", "def_vi": "người nhận điều trị hoặc chăm sóc"}, {"term_ko": "갈아입다", "term_vi": "Thay quần áo", "def_ko": "착용하던 것을 벗고 새로운 것을 착용하다", "def_vi": "bỏ cái cũ và mặc cái mới"}, {"term_ko": "강제로", "term_vi": "Bằng cách cưỡng chế", "def_ko": "힘을 사용하여", "def_vi": "sử dụng sức mạnh để thực hiện hành động"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1730, '14', '세면하기를 거부하는 치매 대상자에게 적합한 요양보호사의돌봄 방법은? 치매로 진단받은 73세 남성은 씻지 않은 지 일주일이 되어간다. 가족들이 설득하여 억지로 씻기려고 했지만, 그때마다 소리를 지르고 화를 내서 너무 힘들었다고 한다.', '["진정제를 먹인 후 씻긴다.", "가족과 함께 강제로 씻긴다.", "더러워서 씻어야 한다고 대상자를 설득한다.", "요양보호사가 물로 씻는 시늉을 보이며 스스로 씻게 한다.", "거부가 심하면 서비스 제공이 어렵다고 가족에게 말한다."]'::jsonb, 4, '치매 대상자에 대한 효과적인 돌봄 방법을 평가하는 것이다.', 'Đánh giá phương pháp chăm sóc hiệu quả cho bệnh nhân mắc bệnh Alzheimer.', '{"1": "진정제를 사용하여 강제로 씻기면 대상자의 불안을 증대시킬 수 있다.\nViệc sử dụng thuốc an thần để cưỡng chế tắm có thể làm tăng lo lắng của bệnh nhân.", "2": "가족과 강제로 씻기면 대상자는 더욱 반항할 수 있다.\nCưỡng chế tắm cùng gia đình có thể làm cho bệnh nhân phản ứng mạnh hơn.", "3": "단순 설득은 효과가 없으며, 대상자의 의사와 감정을 존중해야 한다.\nViệc chỉ thuyết phục đơn giản không hiệu quả, cần tôn trọng ý chí và cảm xúc của bệnh nhân.\n\n[정답]", "4": "Phương pháp để nhân viên chăm sóc chỉ cho bệnh nhân bằng cách bắt chước sẽ tôn trọng tính tự chủ và giảm lo âu của bệnh nhân.", "5": "서비스 제공이 어렵다는 위협은 대화를 단절시킬 수 있다.\nGây ra sự đổ vỡ trong giao tiếp bằng cách đe dọa rằng sẽ khó khăn khi cung cấp dịch vụ."}'::jsonb, '[{"term_ko": "세면", "term_vi": "Rửa mặt", "def_ko": "씻는 것", "def_vi": "Rửa cơ thể"}, {"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력 및 사고력 손상", "def_vi": "Giảm sút khả năng ghi nhớ và tư duy"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "돌봄 받을 사람이자 환자", "def_vi": "Người nhận chăm sóc và bệnh nhân"}, {"term_ko": "강제", "term_vi": "Cưỡng chế", "def_ko": "억지로, 할 수 없이", "def_vi": "Ép buộc, không thể khác"}, {"term_ko": "자율성", "term_vi": "Tính tự chủ", "def_ko": "스스로 결정할 수 있는 능력", "def_vi": "Khả năng tự quyết định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1729, '14', '다음 사례에서 치매 대상자의 올바른 돌봄 방법으로 옳은 것은? 치매 대상자인 85세 남성은 식사할 때 수저를 사용하지 않고 손으로 음식을 집어 먹으려고 한다. 요양보호사가 수저로 먹으라고 하면 몇 번 서툴게 먹다가 다시 손으로 음식을 집는다.', '["포크나 젓가락을 사용하게 한다.", "\"손으로먹으면 더럽잖아요.\" 말하면 먹여준다.", "\"수저로 드셔야지요.\" 하고 몸짓과 함께 부드럽게 말한다.", "\"어르신은 말도 안 듣고 고집이 참 세네요.\" 하며 그냥 둔다.", "\"수저 사용은 안 하려면 식사하지 마세요.\" 말하며 식사를 치운다."]'::jsonb, 3, '치매 대상자를 올바르게 돌보는 방법을 이해하고 적용하는지 확인하기 위함입니다.', 'Kiểm tra hiểu biết và áp dụng cách chăm sóc đúng cho người mắc chứng mất trí.', '{"1": "포크나 젓가락은 치매 대상자에게 적합한 도구가 아닐 수 있습니다.\nDùng nĩa hoặc đũa có thể không phải là dụng cụ thích hợp cho người mắc chứng mất trí.\n\n[정답]", "3": "Cần sử dụng lời nói nhẹ nhàng và cử chỉ để hướng dẫn cách đúng.", "4": "고집을 부리는 태도는 부정적인 행동으로, 돌봄에 적절하지 않습니다.\nThái độ cứng đầu là hành động tiêu cực và không phù hợp trong việc chăm sóc.", "5": "식사를 치우는 것은 대상자의 필요를 충족하지 않으므로 부적절합니다.\nDọn dẹp thức ăn không đáp ứng nhu cầu của bệnh nhân là không phù hợp."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "알츠하이머 병 등으로 인한 기억력 상실 및 인지 능력 장애", "def_vi": "Mất trí nhớ và rối loạn nhận thức do các bệnh như Alzheimer."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1728, '14', '다음 사례에서 치매 대상자의 적합한 돌봄 방법으로 옳은 것은? 치매 대상자인 80세 여성은 물컵을 손으로 잡고 물을 마시지만 대부분 흘린다. 요양보호사의 도움으로 물을 다 마시고 나면 컵을 테이블에 놓지 못하고 바닥에 떨어뜨린다.', '["물 대신 국을 많이 먹게 한다.", "컵에 빨대를 꽂아 물을 마시게 한다.", "깨질 수 있으니 컵 사용을 못하게 한다.", "요실금을 예방하기 위해 물 섭취를 제한한다.", "언제 물을 마셨는지를 기억했다가 물을 마시게 한다."]'::jsonb, 5, '치매 대상자에게 적합한 돌봄 방법을 찾는 것이며, 적절한 수분 섭취를 중요시합니다.', 'Tìm ra phương pháp chăm sóc phù hợp cho bệnh nhân mắc chứng sa sút trí tuệ, quan trọng việc cung cấp đủ nước cho họ.', '{"1": "물 대신 국을 많이 먹게 한다.\n국이 수분을 제공하더라도, 치매 환자가 이를 인지하기 어려운 경우가 많습니다.\nMặc dù nước súp có thể cung cấp độ ẩm, nhưng bệnh nhân sa sút trí tuệ thường gặp khó khăn trong việc nhận thức điều này.\n\n[정답]", "5": "언제 물을 마셨는지를 기억했다가 물을 마시게 한다.\n이 방법은 환자가 수분을 섭취하도록 도와줄 수 있습니다.\nPhương pháp này có thể giúp bệnh nhân nhớ để uống nước.", "3": "깨질 수 있으니 컵 사용을 못하게 한다.\n컵 사용을 금지하면 환자는 수분 섭취에 어려움을 겪을 수 있습니다.\nCấm sử dụng cốc có thể khiến bệnh nhân gặp khó khăn trong việc uống nước.", "4": "요실금을 예방하기 위해 물 섭취를 제한한다.\n수분 섭취를 제한하면 탈수 위험이 있으므로 바람직하지 않습니다.\nGiới hạn lượng nước sẽ làm tăng nguy cơ mất nước, vì vậy không nên."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력이나 사고 능력이 점차적으로 저하되는 질병", "def_vi": "Bệnh suy giảm trí nhớ hoặc khả năng suy nghĩ dần dần"}, {"term_ko": "적합한", "term_vi": "Phù hợp", "def_ko": "적절한, 알맞은", "def_vi": "Thích hợp, đúng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1727, '14', '심폐소생술을 할 때 자동심장충격기를 사용하는 방법으로 옳은 것은?', '["30회의 가슴압박을 마친 후에 전원을 켠다.", "패드는 옷 위에 붙여서 감전을 방지한다.", "분석 중이라는 음성지시가 나오면 심폐소생술을 시작한다.", "정상 호흡은있으나 반응이 없는 대상자에게 사용한다.", "심장충격 실시 후 즉시 가슴압박을 실시한다."]'::jsonb, 5, '심폐소생술과 자동심장충격기 사용에 대한 이해를 평가하고자 함.', 'Đánh giá sự hiểu biết về hồi sức tim phổi và cách sử dụng máy khử rung tim tự động.', '{"1": "가슴압박 후 전원을 켜는 것은 잘못된 순서임.\nViệc bật nguồn sau khi ấn ngực là thứ tự sai.\n\n[정답]", "5": "Hành động đúng là thực hiện nén ngực ngay sau khi sốc tim.", "2": "패드는 직접 피부에 붙여야 하며, 옷 위에 붙이면 감전 위험이 있음.\nMiếng dán phải được dán trực tiếp lên da, dán trên quần áo sẽ gây nguy hiểm điện giật.", "3": "분석 중일 때는 심폐소생술을 중지해야 함.\nTrong khi phân tích, hồi sức tim phổi phải ngừng lại.", "4": "정상 호흡이 있는 경우 전혀 사용하지 않음.\nTrong trường hợp có sự thở bình thường thì không sử dụng."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장과 호흡이 정지된 상태에서 생명을 구하기 위한 응급 처치법", "def_vi": "Phương pháp cấp cứu nhằm cứu sống khi tim và hô hấp ngừng lại"}, {"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장을 전기적으로 자극하여 정상 리듬으로 회복시키는 장치", "def_vi": "Thiết bị kích thích tim điện để phục hồi nhịp sinh lý"}, {"term_ko": "가슴압박", "term_vi": "Nén ngực", "def_ko": "심장을 압박하여 혈액 순환을 돕는 행위", "def_vi": "Hành động ấn tim để hỗ trợ tuần hoàn máu"}, {"term_ko": "패드", "term_vi": "Miếng dán", "def_ko": "전기 신호를 전달하는 장비의 일부분", "def_vi": "Một phần của thiết bị truyền tín hiệu điện"}, {"term_ko": "정상 호흡", "term_vi": "Hơi thở bình thường", "def_ko": "정상적인 호흡 상태", "def_vi": "Trạng thái hô hấp bình thường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1726, '14', '자동심장충격기 사용 시 심장충격 후 즉시 해야하는 것은?', '["인공호흡을 한다.", "가슴압박을 한다.", "대상자에게서 손을 뗀다.", "턱을 위로 당겨 기도를 열어준다.", "패드를 떼었다가 다시 붙인다."]'::jsonb, 2, '(한국어 의도) 자동심장충격기 사용 후 적절한 후속 조치를 확인하는 것
(베트남어 의도) Xác định các bước thích hợp sau khi sử dụng máy khử rung tim tự động', NULL, '{"1": "Thực hiện hô hấp nhân tạo. (Không khuyến nghị thực hiện hô hấp nhân tạo ngay lập tức sau khi sốc điện)\n\n[정답]", "2": "Thực hiện ép ngực. (Cần bắt đầu ép ngực ngay lập tức sau khi sốc điện)", "3": "Rời tay khỏi người bệnh. (Chỉ nên rời tay sau khi kiểm tra an toàn)", "4": "Kéo cằm lên để mở đường thở. (Chỉ cần làm nếu có triệu chứng hoặc nhận thấy cần thiết)", "5": "Lột rồi dán lại điện cực. (Các điện cực nên được giữ cố định trong khi thực hiện ép ngực)"}'::jsonb, '[{"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장 문제가 생겼을 때 전기 충격을 주어 심장을 정상으로 되돌리기 위한 기계", "def_vi": "Máy dùng để cung cấp sốc điện để khôi phục nhịp tim bình thường khi có vấn đề về tim"}, {"term_ko": "가슴압박", "term_vi": "Ép ngực", "def_ko": "심장 기능이 멈췄을 때 혈액 순환을 유지하기 위해 가슴을 눌러주는 것", "def_vi": "Hành động đè lên ngực để duy trì lưu thông máu khi chức năng tim ngừng"}, {"term_ko": "인공호흡", "term_vi": "Hô hấp nhân tạo", "def_ko": "호흡이 정지된 사람에게 공기를 불어넣는 조치", "def_vi": "Biện pháp thổi không khí vào người đã ngừng thở"}, {"term_ko": "기도", "term_vi": "Đường thở", "def_ko": "공기가 통과하는 경로", "def_vi": "Lộ trình không khí đi qua"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1725, '14', '자동심장충격기의 쇼크 버튼을 눌러야 하는 시점으로 옳은 것은?', '["전원을 켜자마자", "인공호흡을 한 후", "패드를 부착한 직후", "심장리듬을 분석하기 직전", "에너지 충전이 완료된 후"]'::jsonb, 5, '이 문제는 자동심장충격기의 적절한 사용 시점을 평가하는 것을 목표로 합니다.', 'Câu hỏi này nhằm đánh giá thời điểm sử dụng đúng cách máy khử rung tim tự động.', '{"1": "Khi vừa bật nguồn của máy khử rung tim tự động, nhưng không phải là thời điểm cần nhấn nút sốc.", "2": "Sau khi hô hấp nhân tạo, cần phải phân tích nhịp tim, vì vậy không nên nhấn nút sốc.", "3": "Ngay sau khi gắn các pad, đó là thời điểm cần phân tích nhịp tim, vì vậy không nên nhấn nút sốc.", "4": "Ngay trước khi phân tích nhịp tim, vì vậy không nên nhấn nút này tại thời điểm này.\n\n[정답]", "5": "Phải nhấn nút sốc sau khi đã hoàn tất việc nạp năng lượng."}'::jsonb, '[{"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장 리듬 이상 시 전기 충격을 주는 장치", "def_vi": "Thiết bị cung cấp điện cho nhịp tim bất thường"}, {"term_ko": "전원", "term_vi": "Nguồn", "def_ko": "기계의 작동을 시작하기 위한 전기", "def_vi": "Điện cần thiết để khởi động thiết bị"}, {"term_ko": "패드", "term_vi": "Pad", "def_ko": "몸에 부착하여 전기를 전달하는 전극", "def_vi": "Điện cực được gắn lên cơ thể để truyền điện"}, {"term_ko": "심장리듬", "term_vi": "Nhịp tim", "def_ko": "심장의 전기적 활동을 나타내는 주기", "def_vi": "Hoạt động điện của tim"}, {"term_ko": "에너지 충전", "term_vi": "Nạp năng lượng", "def_ko": "기계가 작동을 위해 필요 전기를 저장하는 과정", "def_vi": "Quá trình lưu trữ điện năng cần thiết cho thiết bị hoạt động"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1724, '14', '자동심장충격기 사용 시 가슴 압박을 반드시 중단해야 하는 경우는?', '["자동심장충격기의 전원을 켤 때", "자동심장충격기의 패드를 부착할 때", "자동심장충격기에서 심장리듬을 분석할 때", "자동심장충격기가 에너지를 충전하는 동안", "자동심장충격기의 쇼크 버튼을 누른 후 2분 동안"]'::jsonb, 3, '자동심장충격기 사용 시 가슴 압박을 중단해야 하는 상황에 대한 이해를 테스트하는 것입니다.', 'Bài kiểm tra nhằm kiểm tra sự hiểu biết về tình huống khi cần ngừng ép ngực khi sử dụng máy khử rung tim tự động.', '{"1": "Khi bật nguồn của máy khử rung tim tự động, không cần ngừng ép ngực.\n\n[정답]", "3": "Khi máy khử rung tim tự động phân tích nhịp tim, phải ngừng ép ngực.", "2": "Khi gắn các miếng đệm của máy khử rung tim tự động, không cần ngừng ép ngực.", "4": "Phải ngừng ép ngực trong khi máy khử rung tim tự động đang sạc năng lượng.", "5": "Sau khi nhấn nút sốc của máy khử rung tim tự động, phải tiếp tục ép ngực trong 2 phút."}'::jsonb, '[{"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장 기능이 정지된 환자에게 전기 쇼크를 주어 심장을 다시 뛰게 하는 기기", "def_vi": "Thiết bị dùng để cung cấp sốc điện cho bệnh nhân bị ngừng tim"}, {"term_ko": "압박", "term_vi": "Ép", "def_ko": "힘을 가하여 누르다", "def_vi": "Đẩy lực để nhấn"}, {"term_ko": "패드", "term_vi": "Miếng đệm", "def_ko": "전극이 부착된 판", "def_vi": "Tấm có điện cực gắn vào"}, {"term_ko": "심장리듬", "term_vi": "Nhịp tim", "def_ko": "심장이 뛰는 규칙적인 패턴", "def_vi": "Mô hình nhịp đập của tim"}, {"term_ko": "에너지", "term_vi": "Năng lượng", "def_ko": "일을 하는 능력", "def_vi": "Khả năng thực hiện công việc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1723, '14', '자동심장충격기를 사용하고 관리하는 방법으로 옳은 것은?', '["충전 중에는 가슴압박을 멈추고 기다린다.", "심장충격 버튼을 누르기 전 대상자에게서 손을 뗀다.", "전극패드 부착 후 즉시 심장충격을 시행한다.", "전기 충격이 전달된 즉시 대상자에게서 손을 뗀다.", "자동심장충격기는 매년 1회정기 점검한다."]'::jsonb, 2, '자동심장충격기 사용법에 대해 이해하고 있는지를 평가하기 위함입니다.', 'Để đánh giá khả năng hiểu biết về cách sử dụng máy khử rung tim tự động.', '{"1": "충전 중에는 가슴압박을 멈추고 기다려야 하며, 이는 잘못된 방법입니다.\nKhi sạc, bạn cần dừng ép ngực và chờ, đây là cách sai.\n\n[정답]", "2": "심장충격 버튼을 누르기 전 대상자에게서 손을 떼어야 하며, 이는 올바른 방법입니다.\nTrước khi nhấn nút sốc tim, bạn cần rút tay khỏi người bệnh, đây là cách đúng.", "3": "전극패드 부착 후 즉시 심장충격을 시행하는 것은 위험할 수 있으며, 올바르지 않습니다.\nViệc thực hiện sốc tim ngay lập tức sau khi gắn miếng điện cực có thể gây nguy hiểm và không đúng.", "4": "전기 충격이 전달된 즉시 대상자에게서 손을 뗀다는 것은 전극패드 부착과 관련하여 염두에 두어야 할 사항으로, 순서가 맞지 않습니다.\nViệc rút tay ngay lập tức sau khi điện được truyền cần lưu ý liên quan đến việc gắn miếng điện cực và không đúng thứ tự.", "5": "자동심장충격기는 매년 1회 정기 점검을 원칙으로 하지만, 실제로는 사용 빈도에 따라 다를 수 있습니다.\nMáy khử rung tim tự động nên được kiểm tra định kỳ hàng năm nhưng thực tế có thể khác tùy thuộc vào tần suất sử dụng."}'::jsonb, '[{"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "자동으로 심장충격을 주는 장비", "def_vi": "Thiết bị tự động cung cấp sốc điện cho tim"}, {"term_ko": "가슴압박", "term_vi": "Ép ngực", "def_ko": "심폐소생술의 일환으로 심장을 압박하는 행동", "def_vi": "Hành động ép tim trong hồi sức tim phổi"}, {"term_ko": "전극패드", "term_vi": "Miếng điện cực", "def_ko": "심장에 부착하는 전극판", "def_vi": "Miếng dán vào tim"}, {"term_ko": "심장충격", "term_vi": "Sốc tim", "def_ko": "심장에 전기 충격을 주는 행위", "def_vi": "Hành động cung cấp sốc điện cho tim"}, {"term_ko": "정기 점검", "term_vi": "Kiểm tra định kỳ", "def_ko": "정해진 주기로 점검하는 것", "def_vi": "Kiểm tra theo chu kỳ đã định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1722, '14', '심폐소생술을 할 때 자동심장충격기를 사용하는 방법으로 옳은 것은?', '["패드를 붙인 후 전원을 켠다.", "심장리듬 분석 주에는 인공 호흡을 한다.", "심장 충격을 위한 충전 중에는 가슴 압박을 한다.", "가슴압박과 동시에 쇼크 버튼을 누른다.", "충격이 전달된 즉시 대상자의 반응과 호흡을 재확인한다."]'::jsonb, 3, '(한국어 의도: 심폐소생술과 관련된 자동심장충격기 사용 방법에 대한 이해 여부 확인)
(베트남어 의도: Kiểm tra sự hiểu biết về cách sử dụng máy khử rung tim tự động liên quan đến hồi sức tim phổi)', NULL, '{"1": "Đáp án này sai vì máy khử rung tim tự động cần được bật sau khi dán miếng dán.\n\n[정답]", "3": "Điều này có nghĩa là tiếp tục ấn ngực trong quá trình nạp điện để sốc tim.", "2": "Đáp án này sai vì trong quá trình phân tích nhịp tim không nên thực hiện hô hấp nhân tạo.", "4": "Đáp án này sai vì không nên ấn nút sốc cùng lúc với việc ấn ngực.", "5": "Đáp án này sai vì xác nhận phản ứng và hơi thở nên được thực hiện sau khi sốc đã được thực hiện."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심정지환자를 위한 응급처치법", "def_vi": "Phương pháp cấp cứu cho bệnh nhân ngừng tim"}, {"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장을 자동으로 충격하여 회복시키는 장치", "def_vi": "Thiết bị tự động sốc tim để phục hồi"}, {"term_ko": "패드", "term_vi": "Miếng dán", "def_ko": "전극이 부착된 부위", "def_vi": "Vị trí dán điện cực"}, {"term_ko": "가슴 압박", "term_vi": "Ấn ngực", "def_ko": "심폐소생술의 한 방법", "def_vi": "Một phương pháp trong hồi sức tim phổi"}, {"term_ko": "충전", "term_vi": "Nạp", "def_ko": "충격을 위한 에너지를 저장하는 과정", "def_vi": "Quá trình lưu trữ năng lượng cho sốc"}, {"term_ko": "호흡", "term_vi": "Hô hấp", "def_ko": "공기를 들이마시는 행동", "def_vi": "Hành động hít vào không khí"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1721, '14', '심폐소생술을 할 때 자동심장충격기를 사용하는 방법으로 옳은 것은?', '["심장리듬을 분석한후 패드를 부착한다.", "심장리듬 분석 중에는 가슴압박을 지속한다.", "심장충격 버튼을 누르기 전에 대상자를 꽉 잡는다.", "심폐소생술 중 자동심장충격기가 도착하면 지체없이 전원을 켠다.", "심장충격 버튼을누르고 1분 후에 가슴압박을 시작한다."]'::jsonb, 4, '자동심장충격기를 사용할 때 올바른 사용 방법을 이해하고 있는지를 평가하는 문제입니다.', 'Câu hỏi nhằm đánh giá khả năng hiểu đúng cách sử dụng máy khử rung tim tự động.', '{"1": "심장리듬을 분석한 후 패드를 부착한다.\n이 순서는 잘못되었습니다. 패드는 심장 리듬을 분석하기 전에 부착해야 합니다.\nCách này là sai. Miếng dán nên được gắn trước khi phân tích nhịp tim.", "2": "심장리듬 분석 중에는 가슴압박을 지속한다.\n이것은 잘못된 방법입니다. 심장 리듬 분석 중에는 압박을 중단해야 합니다.\nCách này sai. Trong khi phân tích nhịp tim, cần ngừng ép ngực.", "3": "심장충격 버튼을 누르기 전에 대상자를 꽉 잡는다.\n대상자를 잡는 것은 필요하지 않으며 올바른 방법이 아닙니다.\nViệc giữ chặt bệnh nhân là không cần thiết và không phải là cách đúng.\n\n[정답]", "4": "Trong khi sơ cứu, khi máy khử rung tim tự động đến, cần bật ngay lập tức.", "5": "심장충격 버튼을 누르고 1분 후에 가슴압박을 시작한다.\n이 방법은 잘못되었습니다. 가슴압박은 심장충격 버튼을 누르자마자 시작해야 합니다.\nCách này sai. Cần bắt đầu ép ngực ngay sau khi nhấn nút khử rung tim."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심정지 환자를 위한 응급처치", "def_vi": "Sơ cứu cho bệnh nhân ngừng tim"}, {"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장리듬에 따라 심장을 다시 뛰게 하는 기기", "def_vi": "Thiết bị giúp tim hồi phục theo nhịp tim"}, {"term_ko": "가슴압박", "term_vi": "Ép ngực", "def_ko": "심장소생에서 가슴을 눌러주는 행동", "def_vi": "Hành động đè lên ngực trong hồi sức tim"}, {"term_ko": "심장리듬", "term_vi": "Nhịp tim", "def_ko": "심장의 전기적 활동 상태", "def_vi": "Trạng thái hoạt động điện của tim"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1720, '14', '자동심장 충격기를 사용하는 방법으로 옳은 것은?', '["두 개의 패드를 부착 후 전원 버튼을 누른다.", "심장 리듬 분석을 5분마다 한다.", "심장리듬 분석 중에는 가슴압박을 중단한다.", "심장충격 버튼을 누르기 전 인공호흡을 집중적으로 한다.", "전극 패드를 왼쪽 빗장뼈 (쇄골)와 오른쪽 젖꼭지 아래에 붙인다."]'::jsonb, 3, '자동심장 충격기를 사용하는 올바른 방법을 이해하고 선택하는 것이 중요하다.', 'Việc hiểu và chọn cách sử dụng máy sốc điện tim tự động là rất quan trọng.', '{"1": "자동심장 충격기를 사용할 때 두 개의 패드를 부착하는 것은 필수적이지만, 전원을 누르는 시점은 고정적이지 않다.\nViệc gắn hai tấm điện cực là cần thiết khi sử dụng máy sốc điện nhưng thời điểm bấm nút nguồn không cố định.", "2": "심장 리듬 분석은 5분마다 하는 것이 아니라, 자동심장 충격기가 필요할 때마다 이루어진다.\nPhân tích nhịp tim không thực hiện mỗi 5 phút mà được thực hiện khi máy sốc điện tự động cần thiết.\n\n[정답]", "3": "Phải ngừng ép ngực trong quá trình phân tích nhịp tim để tăng độ chính xác của phân tích nhịp tim.", "4": "심장충격 버튼을 누르기 전에 인공호흡을 집중적으로 하는 것은 필요하지 않으며, 심장 충격 후에 가슴 압박을 계속해야 한다.\nKhông cần tập trung vào việc hô hấp nhân tạo trước khi nhấn nút sốc tim, mà cần tiếp tục ép ngực sau khi sốc tim.", "5": "전극 패드는 정확한 위치에 부착해야 하지만, 왼쪽 빗장뼈와 오른쪽 젖꼭지 아래에 붙이는 것은 잘못된 정보이다.\nCác tấm điện cực cần phải được gắn đúng vị trí, nhưng thông tin này về việc gắn vào xương đòn bên trái và dưới núm vú bên phải là sai."}'::jsonb, '[{"term_ko": "자동심장 충격기", "term_vi": "Máy sốc điện tim tự động", "def_ko": "사람이 심장마비 시 전기 충격을 주어 심장을 다시 정상적으로 뛰게 하는 장치", "def_vi": "Thiết bị gây sốc điện cho tim để làm cho tim đập lại bình thường trong trường hợp ngừng tim"}, {"term_ko": "심장 리듬", "term_vi": "Nhịp tim", "def_ko": "심장의 전기적 활동 상태", "def_vi": "Trạng thái hoạt động điện của tim"}, {"term_ko": "가슴압박", "term_vi": "Ép ngực", "def_ko": "심장을 압박하여 혈액을 순환시키는 행위", "def_vi": "Hành động ép tim để tuần hoàn máu"}, {"term_ko": "전극 패드", "term_vi": "Tấm điện cực", "def_ko": "자동심장 충격기를 사용하여 전기충격을 주기 위해 필요한 장비", "def_vi": "Thiết bị cần thiết để gây sốc điện bằng máy sốc điện tim tự động"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1719, '14', '다음 중 자동심장충격기를 사용해야 하는 대상자는?', '["호흡이 미세한 대상자", "심 정지 대상자", "의식이 없는 대상자", "출혈이 심한 대상자", "경련중인 대상자"]'::jsonb, 2, '자동심장충격기의 사용이 필요한 상황을 이해하고 있는지를 평가하기 위한 질문입니다.', 'Câu hỏi này nhằm đánh giá liệu người học có hiểu tình huống nào cần sử dụng máy shock tim tự động hay không.', '{"1": "호흡이 미세한 대상자는 심정지 상태가 아니므로 자동심장충격기를 사용하지 않습니다.\nNgười có hơi thở yếu không phải là trường hợp ngừng tim, vì vậy không sử dụng máy shock tim tự động.\n\n[정답]", "2": "Người ngừng tim là tình huống cần sử dụng máy shock tim tự động.", "3": "의식이 없는 대상자는 심정지인지 확인이 필요하므로 자동심장충격기를 사용할 필요가 없습니다.\nNgười không có ý thức cần phải kiểm tra xem có thực sự ngừng tim hay không, do đó không cần sử dụng máy shock tim tự động.", "4": "출혈이 심한 대상자는 심정지 상태가 아님으로 사용하지 않습니다.\nNgười bị chảy máu nhiều không phải là trường hợp ngừng tim, do đó không sử dụng.", "5": "경련중인 대상자는 심정지 상태가 아니므로 자동심장충격기를 사용하지 않습니다.\nNgười đang co giật không phải là trường hợp ngừng tim, vì vậy không sử dụng máy shock tim tự động."}'::jsonb, '[{"term_ko": "자동심장충격기", "term_vi": "Máy shock tim tự động", "def_ko": "심장 정지를 감지하여 전기 충격을 주는 기기", "def_vi": "Thiết bị phát hiện ngừng tim và cung cấp cú sốc điện"}, {"term_ko": "심 정지", "term_vi": "Ngừng tim", "def_ko": "심장이 멈춘 상태", "def_vi": "Tình trạng tim ngừng đập"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "자신의 상태를 인식하는 능력", "def_vi": "Khả năng nhận thức về tình trạng của bản thân"}, {"term_ko": "출혈", "term_vi": "Chảy máu", "def_ko": "혈액이 외부로 나오거나 내부에서 새는 것", "def_vi": "Máu ra ngoài hoặc chảy bên trong"}, {"term_ko": "경련", "term_vi": "Co giật", "def_ko": "불수의적인 근육 수축", "def_vi": "Cơn co thắt cơ không tự nguyện"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1718, '14', '자동심장충격기 사용 순서로 옳은 것은? 가. 전원켜기 나. 심장리듬 분석 다. 심장충격 시행 라.패드 부착 마. 즉시 심폐소생술 시행', '["가 - 다 - 나 - 라 - 마", "가 - 다 - 라 - 나 - 마", "가 - 라 - 나 - 다 - 마", "가 - 나 - 다 - 라 - 마", "가 - 나 - 라 - 다 - 마"]'::jsonb, 3, '자동심장충격기의 사용 절차에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "전원 켜고 심장 충격 시행 순서가 잘못되어 있습니다.", "2": "전원 켜고 심장 충격 시행 후 심장 리듬 분석을 하는 순서가 잘못되어 있습니다.\n[정답]", "3": "전원 켜고 패드를 부착 후 심장 리듬 분석 후 충격을 시행하는 순서입니다.", "4": "전원 켜고 리듬 분석이 먼저 나와야 하므로 잘못된 순서입니다.", "5": "전원 켜고 패드 부착 후 심장 리듬 분석이 뒤에 있으므로 잘못된 순서입니다."}'::jsonb, '[{"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장에서 부정맥이나 급성 심장마비를 상황에서 전기 충격을 주는 기기", "def_vi": "Thiết bị cung cấp sốc điện trong trường hợp rối loạn nhịp tim hoặc ngừng tim"}, {"term_ko": "심장리듬", "term_vi": "Nhịp tim", "def_ko": "심장이 활동하는 양상", "def_vi": "Hình thức hoạt động của tim"}, {"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장과 호흡이 멈춘 사람을 살리기 위한 응급 처치", "def_vi": "Thao tác cấp cứu cho người ngừng tim và ngừng thở"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1717, '14', '요양보호사가 심폐소생술을 종료해야 할 시점은?', '["맥박이 없을 때", "호흡이 없을 때", "자동심장충격기 사용 후", "가족이 멈추길 원할 때", "119 구급 대원에게 인계할 때"]'::jsonb, 5, '심폐소생술을 종료해야 하는 상황에 대한 이해를 평가하기 위해 출제되었습니다.', NULL, '{"1": "심폐소생술은 맥박이 없을 때에도 계속 진행해야 합니다.", "2": "호흡이 없을 경우에도 심폐소생술을 계속해야 합니다.\n[정답]", "3": "자동심장충격기를 사용할 후에도 심폐소생술은 지속해야 합니다.", "4": "가족이 멈추기를 희망하더라도, 전문가의 판단에 따라 심폐소생술이 지속되어야 할 수 있습니다.", "5": "119 구급 대원에게 인계할 때 심폐소생술을 종료해야 합니다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장과 호흡이 멈춘 환자에게 다시 호흡과 순환을 회복시키기 위한 응급조치", "def_vi": "Biện pháp cấp cứu nhằm phục hồi hô hấp và tuần hoàn cho bệnh nhân khi tim và hô hấp ngừng lại"}, {"term_ko": "자동심장충격기", "term_vi": "Máy shock tim tự động", "def_ko": "심장 박동을 재개시키기 위해 전기적 충격을 주는 기기", "def_vi": "Thiết bị cung cấp sốc điện để khôi phục nhịp tim"}, {"term_ko": "구급 대원", "term_vi": "Nhân viên cấp cứu", "def_ko": "응급 상황에서 환자를 돕는 전문가", "def_vi": "Chuyên gia giúp đỡ bệnh nhân trong tình huống khẩn cấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1716, '14', '심폐소생술 시 가슴압박을 실시하는 방법으로 옳은 것은?', '["가슴이 3cm 눌릴 정도로 압박한다.", "가슴뼈 아래쪽 명치 부위를 강하게 압박한다.", "대상자의 몸과수직이 되도록 하여 가슴을 압박한다.", "압박된 가슴이 이완되지 않도록 빠르게 압박한다.", "체중을 실어 깍지를 낀 두 손의 손바닥으로 압박한다."]'::jsonb, 3, '심폐소생술 시 가슴압박의 정확한 방법을 평가하고자 합니다.', NULL, '{"1": "가슴압박 깊이는 일반적으로 5-6cm로 권장되며 3cm는 부족하다.\n[정답]", "3": "가슴을 압박할 때는 대상자의 몸과 수직이 되어야 올바른 압박이 이루어진다.", "2": "명치 부위를 압박하면 정확한 가슴압박이 이루어지지 않는다.", "4": "압박 후 가슴이 이완되지 않으면 효과적인 순환이 이루어지지 않는다.", "5": "두 손의 손바닥을 사용하되, 체중을 실어서 압박하는 것이 효과적이다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "환자의 호흡과 맥박이 멈췄을 때 실시하는 응급처치", "def_vi": "Sơ cứu khi bệnh nhân ngừng thở và ngừng mạch"}, {"term_ko": "가슴압박", "term_vi": "Ép ngực", "def_ko": "심장을 압박하여 혈액 순환을 도와주는 행위", "def_vi": "Hành động ấn vào ngực để hỗ trợ tuần hoàn máu"}, {"term_ko": "명치", "term_vi": "Xương ức", "def_ko": "가슴 중앙 아래쪽에 위치하는 부위", "def_vi": "Vùng ở giữa dưới ngực"}, {"term_ko": "체중", "term_vi": "Khối lượng", "def_ko": "몸의 무게", "def_vi": "Trọng lượng cơ thể"}, {"term_ko": "압박", "term_vi": "Áp lực", "def_ko": "힘을 가하거나 눌러서 누르는 행위", "def_vi": "Hành động gây sức ép"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1715, '14', '심폐소생술을 할 때 가슴을 압박하는 방법으로 옳은 것은?', '["복장뼈의 하단 칼돌기를 직접 압박한다.", "분당 100~120회 속도로 압박한다.", "대상자의 골반에 걸터앉아서 압박한다.", "등 밑에 낮은 베개를 고인후 압박한다.", "압박 위칠를 바꾸어 가면서 실시한다."]'::jsonb, 2, '심폐소생술에 대한 이해와 올바른 방법을 평가하기 위한 문제입니다.', NULL, '{"1": "복장뼈의 하단 칼돌기를 직접 압박하는 것은 잘못된 방법입니다.  \n[정답]", "2": "분당 100~120회 속도로 압박하는 것이 올바른 가슴 압박 속도입니다.", "3": "대상자의 골반에 걸터앉아서 압박하는 것은 올바른 방법이 아닙니다.", "4": "등 밑에 낮은 베개를 고인후 압박하는 것은 올바른 시행 방법이 아닙니다.", "5": "압박 위치를 바꾸어 가면서 실시하는 것은 권장되지 않는 방법입니다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "생명을 구하기 위한 응급처치", "def_vi": "Cứu sinh khẩn cấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1714, '14', '심폐소생술 시 가슴압박을 실시하는 방법으로 옳은 것은?', '["압박된 가슴이 눌린 상태로 유지되게 압박한다.", "분당 60회의 속도로 가슴을 압박한다.", "손가락을 가슴에 대고 압박한다.", "양쪽 팔을 45도 정도 굽혀 압박한다.", "가슴이 5cm 눌릴 정도로 압박한다."]'::jsonb, 5, '심폐소생술에서 올바른 가슴압박 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "압박된 가슴이 눌린 상태로 유지되게 압박한다: 가슴 압박 시 눌린 상태가 유지되어야 하지 않습니다.\n[정답]", "5": "가슴이 5cm 눌릴 정도로 압박한다: 심폐소생술의 올바른 가슴압박 깊이입니다.", "3": "손가락을 가슴에 대고 압박한다: 손가락으로 압박하는 것은 부적절합니다.", "4": "양쪽 팔을 45도 정도 굽혀 압박한다: 팔의 각도는 똑바로 펴는 것이 더 적절합니다.", "2": "분당 60회의 속도로 가슴을 압박한다: 가슴압박 속도는 분당 100-120회가 적절합니다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장과 호흡이 멈춘 환자를 살리기 위한 응급처치", "def_vi": "Cấp cứu cho bệnh nhân khi tim và hô hấp ngừng lại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1713, '14', '심폐소생술 시 가슴 압박을 위한 손 위치는?', '["오른쪽 가슴", "왼쪽 가슴", "흉골 아래쪽 절반부위", "명치 아래", "상복부"]'::jsonb, 3, '심폐소생술의 정확한 시행 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "오른쪽 가슴 부위에서는 효과적인 압박이 불가능합니다.", "2": "왼쪽 가슴도 마찬가지로 효과적이지 않습니다.\n[정답]", "3": "흉골 아래쪽 절반부위가 심폐소생술 시 가슴 압박을 위한 올바른 위치입니다.", "4": "명치 아래는 적절한 위치가 아닙니다.", "5": "상복부도 심폐소생술 시 적용되지 않습니다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi phục tim phổi", "def_ko": "생명을 구하기 위한 응급 처치법", "def_vi": "Phương pháp cấp cứu nhằm cứu sống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1712, '14', '심폐소생술을 시행하는 순서로 옳은 것은?', '["도움요청 - 반응확인 - 호흡확인 - 가슴압박 - 회복자세", "도움요청 - 호흡확인 - 반응확인 - 가슴압박 - 회복자세", "반응확인 - 호흡확인 - 가슴압박 - 인공호흡 - 도움요청", "반응확인 - 도움요청 - 호흡확인 - 가슴압박 - 회복자세", "호흡확인 - 가슴압박 - 반응확인 - 도움요청 - 회복자세"]'::jsonb, 4, '심폐소생술의 올바른 순서를 아는 것이 중요하다.', NULL, '{"1": "도움요청을 먼저 해야 하지만, 반응확인을 먼저 한 후에 도움을 요청해야 한다.\n[정답]", "4": "반응확인을 먼저 한 후 도움요청, 호흡확인, 가슴압박, 회복자세를 취해야 한다.", "3": "반응확인 후 호흡확인을 해야 하지만, 도움요청이 늦어진다.", "2": "호흡확인을 먼저 하는 것은 잘못된 순서다.", "5": "호흡확인을 먼저 하는 것은 잘못된 순서다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장을 다시 뛰게 하려는 응급처치 방법", "def_vi": "Phương pháp cấp cứu để làm tim hoạt động trở lại"}, {"term_ko": "가슴압박", "term_vi": "Ép ngực", "def_ko": "심장 압박을 통해 혈액 순환을 돕는 방법", "def_vi": "Phương pháp hỗ trợ tuần hoàn máu thông qua việc thúc đẩy tim"}, {"term_ko": "회복자세", "term_vi": "Tư thế hồi phục", "def_ko": "의식을 회복한 사람의 올바른 자세", "def_vi": "Tư thế đúng cho người đã hồi phục ý thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1711, '14', '쓰러져 있는 대상자를 발견했을 때 가장 먼저 해야 하는 것은?', '["도움 요청", "반응 확인", "호흡 확인", "가슴 압박", "회복 자세"]'::jsonb, 2, '환자를 발견했을 때 즉각적으로 반응을 확인하여 중증도와 필요한 조치를 결정하기 위한 것이다.', NULL, '{"1": "도움 요청: 도움이 필요하지만, 우선 반응을 확인해야 한다.\n[정답]", "2": "반응 확인: 대상자의 상태를 파악하기 위해 가장 먼저 확인해야 하는 점이다.", "3": "호흡 확인: 반응을 확인한 후 수행하는 과정이다.", "4": "가슴 압박: 호흡이나 반응이 없을 때 지침에 따라 진행해야 한다.", "5": "회복 자세: 대상자의 상태에 따라 필요할 수 있지만, 먼저 반응 확인이 필요하다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "사람(환자)", "def_vi": "bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1710, '14', '호흡이 없는 대상자에게 심폐소생술을 할 때 가슴압박을 하는 이유는?', '["의식 회복", "통증 감소", "합병증 예방", "폐에 산소공급", "심장과 뇌로 충분한 혈액공급"]'::jsonb, 5, '호흡이 없는 대상자에게 심폐소생술을 할 때의 기본 원리를 이해하고 있는지를 묻는 문제입니다.', NULL, '{"1": "의식 회복은 심폐소생술의 목적 중 하나일 수 있지만, 가슴 압박의 직접적인 이유는 아닙니다.\n[정답]", "5": "심장과 뇌로 충분한 혈액 공급이 가장 중요한 이유입니다. 가슴 압박을 통해 심장의 펌프 기능을 대체하여 혈류를 유지합니다.", "3": "합병증 예방은 심폐소생술 후 고려해야 할 사항이지 가슴 압박의 직접적인 이유는 아닙니다.", "4": "폐에 산소 공급은 인공호흡을 통해 이루어지지만 가슴 압박의 목적은 아닙니다.", "2": "통증 감소는 심폐소생술의 주목적이 아닙니다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "생명을 구하기 위한 응급처치", "def_vi": "Cách cấp cứu để cứu sống"}, {"term_ko": "호흡", "term_vi": "Hô hấp", "def_ko": "숨쉬는 것", "def_vi": "Việc thở"}, {"term_ko": "가슴압박", "term_vi": "Ép ngực", "def_ko": "가슴을 누르는 기술", "def_vi": "Kỹ thuật nén ngực"}, {"term_ko": "혈액", "term_vi": "Máu", "def_ko": "몸안의 액체", "def_vi": "Chất lỏng trong cơ thể"}, {"term_ko": "산소", "term_vi": "Oxy", "def_ko": "생명 유지에 필요한 기체", "def_vi": "Khí cần thiết cho sự sống"}, {"term_ko": "합병증", "term_vi": "Biến chứng", "def_ko": "원인이 복잡한 질환", "def_vi": "Bệnh lý phức tạp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1709, '14', '심정지 대상자에게 심폐소생술을 하는 일차적인 목적은?', '["폐 기능 회복", "뇌 손상 최소화", "면역 기능 강화", "신장 기능 향상", "근골격 손상 회복"]'::jsonb, 2, '심정지 상황에서 심폐소생술의 주요 목적을 이해하고 있는지 확인하기 위한 문제입니다.', NULL, '{"1": "폐 기능 회복: 심폐소생술은 폐 기능을 직접적으로 회복하는 것이 아닙니다.\n[정답]", "2": "뇌 손상 최소화: 심정지 후 뇌는 산소 공급이 중단되어 손상이 발생할 수 있는데, 심폐소생술은 이를 방지하기 위한 조치입니다.", "3": "면역 기능 강화: 면역 기능과는 직접적인 관련이 없습니다.", "4": "신장 기능 향상: 신장 기능을 향상시키는 것은 심폐소생술의 목표가 아닙니다.", "5": "근골격 손상 회복: 근골격 손상은 심폐소생술과 관련이 없습니다."}'::jsonb, '[{"term_ko": "심정지", "term_vi": "Ngừng tim", "def_ko": "심장이 멈춘 상태", "def_vi": "Trạng thái tim ngừng hoạt động"}, {"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장을 재시작하기 위한 응급처치 방법", "def_vi": "Phương pháp cấp cứu để khôi phục hoạt động của tim"}, {"term_ko": "뇌", "term_vi": "Não", "def_ko": "인간의 두뇌", "def_vi": "Bộ não của con người"}, {"term_ko": "손상", "term_vi": "Tổn thương", "def_ko": "신체나 정신의 해를 입음", "def_vi": "Gây hại cho cơ thể hoặc tâm trí"}, {"term_ko": "최소화", "term_vi": "Giảm thiểu", "def_ko": "가장 적은 정도로 줄이다", "def_vi": "Giảm đến mức tối thiểu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1708, '14', '산책하던 대상자가 넘어져 손목 골절이 의심될 때 대처방법은?', '["손목 부위를 지압해 준다.", "튀어나온 뼈를 압박한다.", "반지와 시계를 제거해 준다.", "손을 심장 위치보다 낮게 내리게 한다.", "손목을 반복적으로 털어 보게 한다."]'::jsonb, 3, '대상자가 넘어져 손목 골절이 의심될 때 적절한 대처 방법을 묻는 문제입니다.', NULL, '{"1": "손목 부위를 지압해 주는 것은 부상이 악화될 수 있으므로 부적절합니다.\n[정답]", "3": "손목의 부종 예방 및 혈액 순환을 위해 반지와 시계를 제거해 주는 것이 필요합니다.", "2": "튀어나온 뼈를 압박하는 것은 더욱 큰 피해를 줄 수 있으므로 절대 하면 안 됩니다.", "4": "손을 심장 위치보다 낮게 내리면 혈액 순환에 문제가 생길 수 있으므로 좋지 않습니다.", "5": "손목을 반복적으로 털어 보게 하는 것은 통증을 유발할 수 있어 적절하지 않습니다."}'::jsonb, '[{"term_ko": "손목", "term_vi": "Cổ tay", "def_ko": "손과 팔을 연결해 주는 관절", "def_vi": "Khớp nối giữa tay và cánh tay"}, {"term_ko": "골절", "term_vi": "Gãy xương", "def_ko": "뼈가 부러진 상태", "def_vi": "Tình trạng xương bị gãy"}, {"term_ko": "부종", "term_vi": "Sưng", "def_ko": "부풀어 오르는 것", "def_vi": "Sự phồng lên"}, {"term_ko": "혈액", "term_vi": "Máu", "def_ko": "몸 속에서 흐르는 액체", "def_vi": "Chất lỏng chảy trong cơ thể"}, {"term_ko": "압박", "term_vi": "Ép", "def_ko": "눌러서 압력을 가하는 것", "def_vi": "Nhấn để tạo áp lực"}, {"term_ko": "대처", "term_vi": "Xử lý", "def_ko": "상황에 맞게 행동하는 것", "def_vi": "Hành động phù hợp với tình huống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1707, '14', '발가락 골절이 의심되는 대상자를 돕는 방법으로 옳은 것은?', '["발가락 부위를 붕대로 압박한다.", "부종 예방을 위해 파스를 뿌려 준다.", "혈액 순환이 잘 되도록 온찜질을 한다.", "손상 부위에 외형상 변형이 있는지 관찰한다.", "크기가 넉넉한 신발을 신기고 걸어 보게 한다."]'::jsonb, 4, '발가락 골절에 대한 적절한 응급조치를 이해하고 있는지를 측정하고자 함.', NULL, '{"1": "발가락 부위를 압박하면 추가적인 손상을 유발할 수 있습니다.\n[정답]", "4": "손상 부위의 외형상 변형 여부를 관찰하는 것은 골절을 의심할 때 중요한 사항입니다.", "2": "부종 예방을 위해 파스를 뿌리는 것은 일반적인 조치가 아닙니다.", "3": "온찜질은 초기 손상 시에는 적절하지 않습니다.", "5": "크기가 넉넉한 신발을 신게 하여 걸어보게 하는 것은 오히려 추가적인 통증을 유발할 수 있습니다."}'::jsonb, '[{"term_ko": "발가락", "term_vi": "Ngón chân", "def_ko": "발의 끝 부분", "def_vi": "Phần đầu của bàn chân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1706, '14', '다음 중 가장 먼저 응급처치를 해야 하는 대상자는?', '["설사와 복통을 호소하는 대상자", "운동 직후 혈압이 상승한 대상자", "손가락을 베어 출혈이 있는 대상자", "발목 염좌로 통증을 호소하는 대상자", "얼굴에 화상을 입어 호흡이 곤란한 대상자"]'::jsonb, 5, '응급상황에서 우선적으로 어떤 대상을 치료해야 하는지를 평가하는 문제입니다.', NULL, '{"1": "설사와 복통은 통증이 있지만 급성 위험 요소는 낮습니다.", "2": "운동 직후의 혈압 상승은 주의가 필요하지만 즉각적인 응급처치는 아닙니다.", "3": "손가락 출혈은 관리가 필요하지만 호흡과 관련이 없어 우선순위는 낮습니다.\n[정답]", "4": "얼굴에 화상을 입어 호흡이 곤란한 경우 즉각적인 조치가 요구됩니다.", "5": "발목 염좌는 통증이 있더라도 생명이 위태로운 상황은 아닙니다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Xử lý khẩn cấp", "def_ko": "긴급 상황에서 수행하는 치료", "def_vi": "Điều trị trong tình huống khẩn cấp"}, {"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "치료를 받는 환자", "def_vi": "Bệnh nhân nhận điều trị"}, {"term_ko": "호흡", "term_vi": "Hô hấp", "def_ko": "공기를 흡입하고 내보내는 과정", "def_vi": "Quá trình hít vào và thải ra không khí"}, {"term_ko": "출혈", "term_vi": "Chảy máu", "def_ko": "혈액이 신체 밖으로 나오는 것", "def_vi": "Máu ra ngoài cơ thể"}, {"term_ko": "염좌", "term_vi": "Bong gân", "def_ko": "인대가 손상되는 증상", "def_vi": "Triệu chứng tổn thương dây chằng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1705, '14', '정수기를 사용하던 대상자가 뜨거운 물에 손을 데었을 때 대처방법은?', '["손이 붓기 전에 반지를 빼 준다.", "화상 부위에 핸드크림을 발라준다.", "얼음 조각을 대주어 열기를 식혀준다.", "물집이 생기지 않도록 압박붕대를 감아 준다.", "손으로 화상 부위를 만져서 감각이 있는지 확인한다."]'::jsonb, 1, '화상의 경우 적절한 응급처치 방법을 이해하고 있는지를 평가하고자 한다.', NULL, '{"1": "손이 붓기 전에 반지를 빼 준다. - 화상으로 인한 부종을 고려할 때, 지속적인 압박을 줄 수 있는 반지는 제거해야 한다.\n[정답]", "2": "화상 부위에 핸드크림을 발라준다. - 핸드크림을 사용하면 화상을 악화시킬 수 있으므로 적절하지 않다.", "3": "얼음 조각을 대주어 열기를 식혀준다. - 얼음은 직접 대면 화상을 심하게 할 수 있으므로 사용하지 않는 것이 좋다.", "4": "물집이 생기지 않도록 압박붕대를 감아 준다. - 압박은 오히려 물집을 악화시킬 수 있으므로 권장되지 않는다.", "5": "손으로 화상 부위를 만져서 감각이 있는지 확인한다. - 감각을 확인하는 것은 불필요하며, 감각을 확인하기 위해 만지는 것은 추천하지 않는다."}'::jsonb, '[{"term_ko": "정수기", "term_vi": "Máy lọc nước", "def_ko": "정수기(한국어)", "def_vi": "Máy lọc nước"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1704, '14', '대상자가 팔에 뜨거운 물을 쏟아 화상을 입었을 때 응급처치 방법은?', '["물집이 생기면 터뜨려 준다.", "경미한 화상은 기름을 발라준다.", "수돗물을 화상 부위에 세게 틀어 준다.", "통증이 없어질 때까지 15분 이상 찬물에 담근다.", "화상의 심한 정도를 잘 모르면 상태를 지켜본다."]'::jsonb, 4, '화상에 대한 응급처치 방법을 알고 있는지를 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "화상 부위의 물집은 감염의 위험이 있으므로 터뜨리지 않아야 합니다.", "2": "기름을 바르는 것은 화상 치료에 적절하지 않습니다.", "3": "세게 틀면 더욱 상처가 심해질 수 있으니 주의해야 합니다.\n[정답]", "4": "찬물에 담그는 방법이 올바르며, 추천되는 시간입니다.", "5": "화상 정도에 따라 즉각적인 응급조치가 필요합니다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "응급 상황에서의 치료 방법", "def_vi": "Phương pháp điều trị trong tình huống khẩn cấp"}, {"term_ko": "화상", "term_vi": "Bỏng", "def_ko": "피부가 뜨거운 물체에 닿아 손상된 상태", "def_vi": "Tình trạng tổn thương da do tiếp xúc với vật nóng"}, {"term_ko": "물집", "term_vi": "Bọng nước", "def_ko": "피부 위에 생긴 액체가 고여 있는 부분", "def_vi": "Vùng chứa chất lỏng nổi trên da"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔을 느끼는 상태", "def_vi": "Tình trạng cảm thấy đau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1703, '14', '대상자가 한꺼번에 많은 약을 먹은 후 의식을 잃고 쓰러져 있을 때 대처방법은?', '["하임리히법을 적용한다.", "따뜻한 보리차를 먹게 한다.", "엎드려 고개를 옆으로 돌린 자세로 눕힌다.", "남은 약과 용기를 119 대원에게 전달한다.", "구토물을 즉시 치워 주위를 깨끗하게 한다."]'::jsonb, 4, '대상자가 약물을 과다 복용했을 때 적절한 응급조치를 알고 있는지를 평가하기 위함입니다.', NULL, '{"1": "하임리히법은 기도가 막혔을 때 사용하는 방법으로, 약을 과다 복용한 상황에서는 적절하지 않습니다.\n[정답]", "2": "따뜻한 보리차를 먹게 하는 것은 도움되지 않으며, 의식을 잃은 상태에서는 음식을 섭취할 수 없습니다.", "3": "엎드려 고개를 옆으로 돌린 자세로 눕히는 것은 기도를 확보하는 방법이지만, 상황에 따라 다를 수 있습니다.", "4": "남은 약과 용기를 119 대원에게 전달하는 것은 응급 상황에서 중요한 정보 제공이며 올바른 대처 방법입니다.", "5": "구토물을 즉시 치워 주위를 깨끗하게 하는 것은 중요하지만, 먼저 의식을 잃은 대상자를 적절히 응급처치 하는 것이 우선입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "정신(한국어)", "def_vi": "Tinh thần"}, {"term_ko": "약", "term_vi": "Thuốc", "def_ko": "약품(한국어)", "def_vi": "Dược phẩm"}, {"term_ko": "고개", "term_vi": "Cái đầu", "def_ko": "머리(한국어)", "def_vi": "Đầu"}, {"term_ko": "구토", "term_vi": "Nôn", "def_ko": "토하다(한국어)", "def_vi": "Nôn"}, {"term_ko": "대원", "term_vi": "Nhân viên", "def_ko": "구성원(한국어)", "def_vi": "Nhân viên"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1702, '14', '대상자가 한꺼번에 많은 약물을 복용하여 약물중독이 되었을 때 대처방법은?', '["구토를 억제하는 약물을 제공한다.", "입 안에 손가락을 넣어 약을 구토하게 한다.", "옷을 느슨하게 하고 따뜻한 우유를 먹인다.", "주변에 있는 먹고 남은 약과 용기를 치운다.", "의식이 없으면 천장을 바라보는 자세로 눕힌다."]'::jsonb, 5, '약물중독이 발생했을 때의 대처법을 묻는 문제입니다.', NULL, '{"1": "구토를 억제하는 약물을 제공하는 것은 위험한 상황에서 적절하지 않습니다.\n[정답]", "5": "의식이 없으면 환자를 천장을 바라보는 자세로 눕히는 것이 안전합니다.", "2": "손가락을 넣는 것은 위험할 수 있으며 추천되지 않습니다.", "3": "옷을 느슨하게 하고 따뜻한 우유를 주는 것은 효과적이지 않습니다.", "4": "남은 약과 용기를 치우는 것은 중요하지만, 즉각적인 대처 방법은 아닙니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "Thuốc"}, {"term_ko": "중독", "term_vi": "Ngộ độc", "def_ko": "독에 빠진 상태(한국어)", "def_vi": "Tình trạng bị độc"}, {"term_ko": "구토", "term_vi": "Nôn mửa", "def_ko": "토하는 것(한국어)", "def_vi": "Nôn"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "인지능력(한국어)", "def_vi": "Khả năng nhận thức"}, {"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "신체의 위치(한국어)", "def_vi": "Vị trí cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1701, '14', '장구 연주를 하던 대상자가 몸이 뻣뻣해지고 침을 흘리며 쓰러질 때 대처방법은?', '["제자리에 앉혀 머리를 뒤로 젖히게 한다.", "얼굴을 옆으로 돌려 눕히고 장구를 치운다.", "대상자를 부축하여 안전한 곳으로 옮긴다.", "장구채를 손수건으로 싸서 입에 물려 준다.", "똑바로 눕히고 목 아래에 베개를 받쳐 준다."]'::jsonb, 2, '대상자가 장구를 치고 있는 도중 쓰러질 경우의 올바른 대처방법을 묻는 문제입니다.', NULL, '{"1": "제자리에 앉혀 머리를 뒤로 젖히게 하는 것은 기도를 막을 수 있으므로 위험합니다.\n[정답]", "2": "얼굴을 옆으로 돌려 눕히고 장구를 치운다. 이는 대상자의 안전을 보장하고 기도 보호를 위한 올바른 방법입니다.", "3": "대상자를 부축하여 안전한 곳으로 옮기는 것은 적절한 대처가 아니며, 상황이 심각할 수 있습니다.", "4": "장구채를 손수건으로 싸서 입에 물려 주는 것은 안전하지 않으며, 다칠 위험이 있습니다.", "5": "똑바로 눕히고 목 아래에 베개를 받쳐주는 것은 기도를 막을 수 있으므로 부적절한 방법입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1700, '14', '산책을 하던 대상자가 쓰러져 경련을 할 때 응급처치 방법은?', '["찬물을 마시게 한다.", "119가 올 때까지 가슴 압박을 한다.", "머리를 뒤로 젖혀 기도를 유지한다.", "상체를 높여 편하게 호흡하게 한다.", "상의 단추를 풀고 옆에서 조용히 관찰한다."]'::jsonb, 5, '대상자가 경련을 할 때 응급처치의 올바른 방법을 묻고 있습니다.', NULL, '{"1": "찬물을 마시게 하는 것은 일반적으로 도움이 되지 않습니다.\n[정답]", "5": "상의 단추를 풀고 옆에서 조용히 관찰하는 것이 가장 적절한 대처입니다.", "2": "119가 올 때까지 가슴 압박을 하는 것은 부적절한 대처입니다.", "3": "머리를 뒤로 젖혀 기도를 유지하는 것도 해당 상황에서 불필요합니다.", "4": "상체를 높이기보다 안정된 자세를 유지하는 것이 중요합니다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Xử lý khẩn cấp", "def_ko": "긴급한 상황에서 치료해주는 방법", "def_vi": "Phương pháp điều trị trong tình huống khẩn cấp"}, {"term_ko": "경련", "term_vi": "Co giật", "def_ko": "갑자기 벌떡 일어나는 흔들림", "def_vi": "Sự co giật đột ngột"}, {"term_ko": "기도", "term_vi": "Đường thở", "def_ko": "호흡할 수 있는 경로", "def_vi": "Lối để thở"}, {"term_ko": "관찰", "term_vi": "Quan sát", "def_ko": "상황을 주의 깊게 지켜보는 것", "def_vi": "Theo dõi tình huống một cách cẩn thận"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1699, '14', '대상자가 경련을 일으킬 때 대처방법으로 옳은 것은?', '["인공호흡을 한다.", "팔 다리를 꽉 잡고 발작을 멈추게 한다.", "똑바로 눕혀 머리가 바닥에 직접 닿게 한다.", "침으로 숨쉬기 힘든 경우 손수건을 입에 넣어준다.", "119에 신고하고 경련이 발생한 시각을 기록한다."]'::jsonb, 5, '대상자가 경련을 일으켰을 때 적절한 대처 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "인공호흡은 경련 시 필요하지 않으며 상황에 따라 부적절할 수 있습니다.\n[정답]", "5": "119에 신고하고 경련이 발생한 시각을 기록하는 것이 가장 올바른 대처입니다.", "2": "팔과 다리를 꽉 잡는 것은 부상의 위험이 있으며, 발작을 멈추게 할 수 없습니다.", "3": "똑바로 눕히는 것은 위험할 수 있으며, 머리가 바닥에 직접 닿는 것은 바람직하지 않습니다.", "4": "손수건을 입에 넣는 것은 기도 막힘의 위험이 있어 매우 위험합니다."}'::jsonb, '[{"term_ko": "경련", "term_vi": "Co giật", "def_ko": "발작(한국어)", "def_vi": "Cơn co giật(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1698, '14', '대상자가 넘어져 팔에 찰과상을 입고 출혈이 심할 때 응급처치 방법은?', '["지혈제를 뿌려준다.", "깨끗한 수건으로 상처를 압박한다.", "출혈부위를 흐르는 물로 씻는다.", "손으로 직접 출혈부위를 압박한다.", "상처를 압박한 첫 번째 패드를 반복 교체한다."]'::jsonb, 2, '응급처치의 기본 원칙과 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "지혈제를 뿌리는 것은 일반적인 응급처치 방법이 아닙니다.\n[정답]", "2": "깨끗한 수건으로 상처를 압박하면 출혈을 멈추게 할 수 있습니다.", "3": "출혈부위를 흐르는 물로 씻는 것은 상처를 청소하기 위한 방법이지만, 출혈이 심할 경우에는 적합하지 않습니다.", "4": "손으로 직접 출혈부위를 압박하는 것은 가능하지만, 깨끗한 수건이나 천으로 압박하는 것이 더 효과적입니다.", "5": "상처를 압박한 첫 번째 패드를 반복 교체하기보다는 처음에 단단히 압박하는 것이 중요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "몸", "term_vi": "Cơ thể", "def_ko": "신체(한국어)", "def_vi": "Cơ thể"}, {"term_ko": "출혈", "term_vi": "Chảy máu", "def_ko": "피가 나는 것(한국어)", "def_vi": "Chảy máu"}, {"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "긴급한 상황에서의 의료적인 도움(한국어)", "def_vi": "Sơ cứu"}, {"term_ko": "압박하다", "term_vi": "Ép", "def_ko": "누르다(한국어)", "def_vi": "Ép"}, {"term_ko": "수건", "term_vi": "Khăn", "def_ko": "물건을 닦는 천(한국어)", "def_vi": "Khăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1697, '14', '대상자가 날카로운 물건에 손을 베어 피가 날 때 응급처치 방법은?', '["따뜻한 물에 손을 담가준다.", "출혈이 있는 손을 알코올로 씻어 준다.", "장갑을 착용하고 멸균거즈로 압박한다.", "압박붕대를 감은 뒤, 멸균거즈로 지혈한다.", "출혈이 지속되면 상처를 압박한 패드를 교체한다."]'::jsonb, 3, '응급처치 방법에 대한 기본적인 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "따뜻한 물에 담그는 것은 출혈을 막는 방법이 아닙니다.", "2": "알코올로 씻는 것은 상처에 자극을 줄 수 있으므로 적절하지 않습니다.\n[정답]", "3": "장갑을 착용하고 멸균거즈로 압박하는 것이 올바른 응급처치 방법입니다.", "4": "압박붕대를 감은 뒤 멸균거즈로 지혈하는 것도 필요하지만, 기본적으로는 압박이 선행되어야 합니다.", "5": "압박한 패드를 교체하는 것은 추가적인 처치이므로 초기 대응으로는 적절하지 않습니다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "즉각적인 치료 또는 대응", "def_vi": "Sự điều trị hoặc phản ứng ngay lập tức"}, {"term_ko": "출혈", "term_vi": "Chảy máu", "def_ko": "피가 흐르는 상태", "def_vi": "Tình trạng máu chảy"}, {"term_ko": "장갑", "term_vi": "Găng tay", "def_ko": "손을 보호하는 의복", "def_vi": "Trang phục bảo vệ tay"}, {"term_ko": "멸균거즈", "term_vi": "Gạc vô trùng", "def_ko": "세균이 없는 거즈", "def_vi": "Băng gạc không có vi khuẩn"}, {"term_ko": "압박붕대", "term_vi": "Băng ép", "def_ko": "압박을 위한 붕대", "def_vi": "Băng cho áp lực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1696, '14', '급성 저혈압 (쇼크)에 대한 설명과 대처방법으로 옳은 것은?', '["혈액순환에 필요한 혈액량이 과도해서 발생한다.", "팔과 다리로 혈액량을 증가시키기 위한 조치를 한다.", "심부전 환자는 눕기보다 앉아서 호흡하게 한다.", "상황이 종료될 때까지 반복적으로 숨을 몰아쉬게 한다.", "선 자세에서 천천히 제자리걸음을 걷게 한다."]'::jsonb, 3, '급성 저혈압(쇼크)의 원인 및 대처 방법에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "혈액순환에 필요한 혈액량이 부족해서 발생하는 것이지 과도해서 발생하지 않습니다.\n[정답]", "2": "팔과 다리로 혈액량을 증가시키기 위한 조치는 일반적으로 사용하는 방법은 아닙니다.", "3": "심부전 환자는 눕기보다 앉아서 호흡을 하는 것이 더 좋은 방법입니다.", "4": "상황이 종료될 때까지 반복적으로 숨을 몰아쉬게 하는 것은 바람직하지 않습니다.", "5": "선 자세에서 제자리걸음을 걷는 것은 저혈압 환자에게 좋지 않은 방법입니다."}'::jsonb, '[{"term_ko": "급성 저혈압", "term_vi": "Hạ huyết áp cấp tính", "def_ko": "갑작스럽고 심각한 혈압 저하(한국어)", "def_vi": "Giảm huyết áp đột ngột và nghiêm trọng"}, {"term_ko": "쇼크", "term_vi": "Sốc", "def_ko": "생명 위협적 상태(한국어)", "def_vi": "Tình trạng đe dọa đến tính mạng"}, {"term_ko": "심부전", "term_vi": "Suy tim", "def_ko": "심장이 혈액을 충분히 펌프하지 못하는 상태(한국어)", "def_vi": "Tình trạng tim không bơm đủ máu"}, {"term_ko": "혈액량", "term_vi": "Lượng máu", "def_ko": "혈관에 존재하는 혈액의 총량(한국어)", "def_vi": "Tổng lượng máu trong mạch"}, {"term_ko": "호흡", "term_vi": "Hô hấp", "def_ko": "산소를 흡입하고 이산화탄소를 내보내는 과정(한국어)", "def_vi": "Quá trình hít oxy và thải carbon dioxide"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1695, '14', '심장 질환이 있는 대상자에게 급성 저혈압인 쇼크가 발생했을 때 응급처치 방법은?', '["원활한 호흡을 위해 측위로 눕힌다.", "다리가 30cm정도 올라가도록 해준다.", "상황이 종료될 때까지 물을 제공한다.", "혈압과 맥박이 안정되기를 기다렸다가 119에 신고한다.", "입에서 토사물이 나오면 기도유지를 위해 고개를 뒤로 젖힌다."]'::jsonb, 2, '심장 질환이 있는 대상자가 급성 저혈압인 쇼크에 처했을 때의 응급처치 방법에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "원활한 호흡을 위해 측위로 눕히는 것은 필요하지만, 저혈압 상태에서는 다리를 올리는 것이 중요합니다.\n[정답]", "2": "다리가 30cm 정도 올라가게 해주는 것은 저혈압을 개선하는 응급처치 방법입니다.", "3": "상황 종료 전까지 물을 제공하는 것은 위험할 수 있습니다.", "4": "혈압과 맥박이 안정될 때까지 기다리면서 신고하는 것은 응급처치 순서에서 우선적으로 행동해야 할 사항이 아닙니다.", "5": "입에서 토사물이 나오는 경우 기도유지를 위해 고개를 젖히는 것은 바른 방법이 아닙니다."}'::jsonb, '[{"term_ko": "심장", "term_vi": "Tim", "def_ko": "심장(한국어)", "def_vi": "Tim(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1694, '14', '급성 저혈압 증상으로 옳은 것은?', '["호흡수가 감소한다.", "손발에 열감이 있다.", "피부색이 붉게 변한다.", "혈압이 80/50 이하로 낮아진다.", "맥박 수가 100회 이상으로 빨라진다."]'::jsonb, 5, '급성 저혈압의 증상에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "호흡수가 감소하는 것은 일반적으로 저혈압의 증상과 일치하지 않습니다.\n[정답]", "5": "맥박 수가 100회 이상으로 빨라지는 것은 저혈압의 일반적인 반응입니다.", "2": "손발에 열감이 있는 것은 저혈압 증상과 관련이 없습니다.", "3": "피부색이 붉게 변하는 것은 저혈압이 아닌 고혈압에서 나타나는 증상입니다.", "4": "혈압이 80/50 이하로 낮아지는 것은 저혈압의 주된 특징이나, 증상 접근에서는 맥박 수의 변화를 더 강조합니다."}'::jsonb, '[{"term_ko": "급성", "term_vi": "저혈압", "def_ko": "급성(한국어) / cấp tính(베트남어)", "def_vi": "저혈압(한국어) / huyết áp thấp(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1693, '14', '식사를 하던 대상자가 갑자기 의식을 잃고 쓰러졌을 때 대처방법은?', '["가슴압박과 인공호흡을 한다.", "손가락을 입에 넣어 구토시킨다.", "편평한 바닥에 눕히고 머리를 뒤로 젖힌다.", "옷의 단추를 풀어 주고 심호흡을 하게 한다.", "119에 신고하고 심폐소생술을 실시한다."]'::jsonb, 5, '응급 상황에서의 적절한 대처 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "가슴압박과 인공호흡은 심정지 시에 시행하는 방법으로, 의식을 잃고 쓰러진 경우에는 필요한 조치가 아닙니다.\n[정답]", "5": "119에 신고하고 심폐소생술을 실시하는 것이 가장 올바른 대처 방법입니다.", "2": "손가락을 입에 넣어 구토시키는 것은 위급할 때 권장되지 않으며, 오히려 위험할 수 있습니다.", "3": "편평한 바닥에 눕히고 머리를 뒤로 젖히는 것은 기도의 확보에는 도움이 되지만, 신속한 대처가 필요합니다.", "4": "옷의 단추를 풀어주고 심호흡을 하게 하는 것은 응급처치로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "응급상황", "term_vi": "Tình huống khẩn cấp", "def_ko": "즉각적인 도움이 필요한 상황", "def_vi": "Tình huống cần sự giúp đỡ ngay lập tức"}, {"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장이 멈춘 경우에 시행하는 처치", "def_vi": "Biện pháp thực hiện khi tim ngừng đập"}, {"term_ko": "구토", "term_vi": "Nôn", "def_ko": "음식물을 토해내는 것", "def_vi": "Nôn thức ăn ra ngoài"}, {"term_ko": "기대", "term_vi": "Mong đợi", "def_ko": "의식을 잃지 않고 계신 상태", "def_vi": "Trạng thái không mất ý thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1692, '14', '하임리히법을 적용하는 경우로 옳은 것은?', '["이물질로 인한 질식", "식중독에 의한 복통", "심정지 상태", "경련", "골절"]'::jsonb, 1, '하임리히법의 적용대상을 이해하고 있는지를 묻는 문제입니다.', NULL, '{"1": "하임리히법은 이물질로 인해 기도가 막힌 경우에 적용해야 합니다.\n[정답]", "2": "식중독은 주로 식사를 통해 감염되는 문제이며 하임리히법과는 관련이 없습니다.", "3": "심정지는 응급상황이지만 하임리히법과는 직접적으로 무관합니다.", "4": "경련은 다른 응급처치가 필요하며 하임리히법과는 관련이 없습니다.", "5": "골절은 뼈에 관련된 문제로 하임리히법과는 관계가 없습니다."}'::jsonb, '[{"term_ko": "하임리히법", "term_vi": "Phương pháp Heimlich", "def_ko": "기도가 막힌 환자를 구하기 위한 응급처치 방법", "def_vi": "Phương pháp sơ cứu cho bệnh nhân bị nghẹt thở"}, {"term_ko": "이물질", "term_vi": "Dị vật", "def_ko": "신체에 들어가서 문제를 일으키는 물질", "def_vi": "Chất gây vấn đề khi vào cơ thể"}, {"term_ko": "심정지", "term_vi": "Ngừng tim", "def_ko": "심장이 멈춘 상태", "def_vi": "Tình trạng tim ngừng đập"}, {"term_ko": "경련", "term_vi": "Co giật", "def_ko": "불수의적인 수축과 이완", "def_vi": "Co cơ không tự nguyện"}, {"term_ko": "골절", "term_vi": "Gãy xương", "def_ko": "뼈가 부러진 상태", "def_vi": "Tình trạng xương bị gãy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1691, '14', '대상자가 보호자와 함께 떡을 먹다가 기도가 막혀 괴로운 표정을 지을 때 응급처치 방법은?', '["바닥에 주저 앉힌 후 팔다리를 주물러 준다.", "5cm 깊이로 눌리도록 가슴을 압박한다.", "손가락을 입에 넣어 궅를 유발하여 빼낸다.", "뒤에서 주먹을 쥔 손을 감싸 배꼽과 명치 중간을 후상방으로 밀어올린다.", "등 두드리기와 복부 밀어내기를 교대로 실시한다."]'::jsonb, 4, '대상자가 기도로 음식이 막혀 어지러운 증상을 보일 때 적절한 응급처치를 파악하는 것이 중요하다.', NULL, '{"1": "바닥에 주저 앉히는 것은 응급처치로 적절하지 않다.\n[정답]", "4": "뒤에서 주먹을 쥔 손을 감싸 배꼽과 명치 중간을 후상방으로 밀어올리는 방법은 기도를 확보하는 데 효과적이다.", "3": "손가락을 넣어 궈를 유발하는 방법은 위험할 수 있기 때문에 사용하지 않는다.", "2": "가슴을 압박하는 방법은 부적절하다.", "5": "등 두드리기와 복부 밀어내기를 교환하는 방법은 좋지만, 주먹을 감싸고 압력을 가하는 것이 더 효과적이다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "긴급 상황에서 즉각적으로 필요한 치료", "def_vi": "Điều trị cần thiết ngay lập tức trong tình huống khẩn cấp"}, {"term_ko": "기도", "term_vi": "Đường thở", "def_ko": "공기가 인체 내로 들어가고 나가는 통로", "def_vi": "Lối không khí vào và ra trong cơ thể"}, {"term_ko": "표정", "term_vi": "Biểu cảm", "def_ko": "얼굴의 감정을 나타내는 방법", "def_vi": "Cách thể hiện cảm xúc trên khuôn mặt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1690, '14', '목 안에 이물질이 걸려 육안으로 보일 때 올바른 응급처치는?', '["큰 기침을 하게 하여 뱉어내게 한다.", "입 안에 손가락을 넣어 빼낸다.", "천천히 심호흡을 하도록 유인한다.", "즉시 인공호흡을 실시한다.", "물과 함께 삼키도록 한다."]'::jsonb, 1, '이 문제는 이물질이 목에 걸렸을 때 적절한 응급처치 방법을 평가하기 위해 출제되었다.', NULL, '{"1": "큰 기침을 하게 하여 뱉어내게 한다. - 기침으로 이물질을 제거하는 것이 가장 효과적이다.\n[정답]", "2": "입 안에 손가락을 넣어 빼낸다. - 이 방법은 손가락이 이물질을 더 밀어넣을 위험이 있다.", "3": "천천히 심호흡을 하도록 유인한다. - 이 방법은 이물질을 제거하는 데 도움이 되지 않는다.", "4": "즉시 인공호흡을 실시한다. - 인공호흡은 기도가 막혀 있는 상태에서 실시해선 안 된다.", "5": "물과 함께 삼키도록 한다. - 물로 이물질을 넘기는 것은 위험할 수 있다."}'::jsonb, '[{"term_ko": "이물질", "term_vi": "Dị vật", "def_ko": "뜻(한국어)", "def_vi": "nghĩa(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1689, '14', '대상자가 기침을 하며 기침을 하며 호흡 곤란, 목을 조르는 듯한 자세를 할 때 의심해야 할 것은?', '["경련", "저산소증", "열사병", "심부전", "질식"]'::jsonb, 5, '대상자의 기침 및 호흡 곤란 상태에서의 적절한 응급처치를 위한 증상 이해를 요구하는 문제입니다.', NULL, '{"1": "경련은 근육의 수축으로 인한 증상으로, 기침과 직접적인 연관성이 없습니다.\n[정답]", "5": "질식은 호흡이 방해받는 상태를 설명하며, 기침과 호흡 곤란 증상은 질식과 관련이 있습니다.", "3": "열사병은 고온 환경에서 발생하는 증상이며, 기침과는 관련이 없습니다.", "4": "심부전은 심장의 기능 저하로 발생하며, 기침보다는 다른 증상들이 주로 나타납니다.", "2": "저산소증은 산소 부족을 의미하지만, 기침 및 특정 자세는 질식을 의심하게 합니다."}'::jsonb, '[{"term_ko": "기침", "term_vi": "호흡 곤란", "def_ko": "기침(ho)", "def_vi": "숨쉬기 어려움(khó thở)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1688, '14', '감염성 질환 관리 중 코로나19에 대한 설명으로 옳은 것은?', '["잠복기 없이 인체에 감염된다.", "격리가 필요 없는 가벼운 감기 증상이다.", "감염된 사람의 물건을 함께 사용해도 된다.", "만성폐쇄성 폐질환이 있는 후기고령자에서 사망 위험이 높다.", "실내에서 전파속도를 늦추기 위해 외부 공기를 차단한다."]'::jsonb, 4, '코로나19의 특성과 관리 방법에 대한 이해를 평가하고자 함.', NULL, '{"1": "코로나19는 일반적으로 잠복기가 존재한다. 따라서 이 설명은 옳지 않다.\n[정답]", "4": "만성폐쇄성 폐질환이 있는 후기고령자에서 사망 위험이 높다는 연구 결과가 있다.", "2": "코로나19는 심각한 질병으로 간주되며 격리가 필요하다.", "3": "감염된 사람의 물건을 함께 사용하면 감염 위험이 증가하므로 이 설명은 틀리다.", "5": "외부 공기를 차단하는 것은 오히려 전파를 증가시킬 수 있다."}'::jsonb, '[{"term_ko": "감염성 질환", "term_vi": "Bệnh truyền nhiễm", "def_ko": "감염이 원인인 질병", "def_vi": "Bệnh do nhiễm trùng gây ra"}, {"term_ko": "격리", "term_vi": "Cách ly", "def_ko": "감염된 사람을 다른 사람과 분리하는 조치", "def_vi": "Biện pháp tách người nhiễm bệnh ra khỏi người khác"}, {"term_ko": "사망 위험", "term_vi": "Nguy cơ tử vong", "def_ko": "사망할 가능성", "def_vi": "Khả năng tử vong"}, {"term_ko": "만성폐쇄성 폐질환", "term_vi": "Bệnh phổi tắc nghẽn mãn tính", "def_ko": "호흡기 질환의 일종", "def_vi": "Một loại bệnh hô hấp"}, {"term_ko": "잠복기", "term_vi": "Thời gian ủ bệnh", "def_ko": "병이 발생하기 전 감염된 상태", "def_vi": "Trạng thái nhiễm trùng trước khi phát bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1687, '14', '감염성 질환에 대한 설명과 감염관리 방법으로 옳은 것은?', '["옴 - 감염 대상자의 수건, 혈압계, 체온계를 함께 사용한다.", "독감 - 회복 중 발열과 누런 가래가 생기는 것은 정상이다.", "결핵 - 퇴원 후자택에서 결핵관리 전담간호사의 관리를 받는다.", "이 - 사면발이와 머릿니는 두피에 가려움증을 유발시킨다.", "노로바이러스 장염 - 요양보호사의증상이 경미하면 마스크를 착용하고 업무를 본다."]'::jsonb, 3, '감염성 질환에 대한 이해와 올바른 감염 관리 방법을 모색하기 위함입니다.', NULL, '{"1": "옴은 감염성 질환이지만, 감염 대상자의 위생 용품을 함께 사용하지 않아야 합니다.\n[정답]", "3": "결핵은 퇴원 후 자택에서 전문 간호사의 관리가 필요합니다.", "2": "독감 회복 중의 발열과 증상은 비정상이므로 주의가 필요합니다.", "4": "사면발이와 머릿니는 가려움증을 유발하지만, 이는 일반적인 증상이며 관리가 중요합니다.", "5": "노로바이러스 장염에 걸린 경우, 경미한 증상일지라도 요양보호사는 감염 예방을 위해 마스크 착용이 필수입니다."}'::jsonb, '[{"term_ko": "감염성 질환", "term_vi": "감염관리", "def_ko": "전염병 (Bệnh truyền nhiễm)", "def_vi": "quản lý nhiễm trùng (Quản lý nhiễm trùng)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1686, '14', '시설을 감염 예방을 위해 반드시 따로 처리해야 하는 것은?', '["천식 대상자가 사용한 식기", "대상포진 대상자의 세면도구", "요실금 대상자의 얼룩진 침구", "결핵 대상자의 가래가 묻은 휴지", "접촉성피부염 대상자의 오염된 의복"]'::jsonb, 4, '방역 및 감염 예방에 관한 지식을 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "천식은 호흡기 질환으로 감염과 직접적인 연관이 없습니다. \n[정답]", "2": "결핵은 공기를 통해 전파되는 감염병으로, 이에 따라 세면도구는 반드시 따로 처리해야 합니다.", "3": "요실금은 일반적으로 감염 위험이 낮으나, 상황에 따라 적절한 처리가 필요합니다.", "4": "결핵 대상자의 가래가 묻은 휴지는 감염 위험이 크므로 반드시 따로 처리해야 합니다.", "5": "접촉성 피부염은 일반적으로 전파되지 않으나, 오염된 의복은 적절히 처리해야 합니다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "인감", "def_ko": "감염(感染)", "def_vi": "nhiễm trùng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1685, '14', '오염된 물질이 묻었을 때 처리하는 방법으로 옳은 것은?', '["심각하게 오염된 침구류는 분리하여 버린다.", "체액이 묻은 유리 조각은 일반 쓰레기로 버린다.", "침구에 쏟아진 체액은 표백제를 사용하여 닦아낸다.", "분비물에 오염된 장갑은 신속하게 세척 후 사용한다.", "바닥에 쏟아진 혈액은 표백제와 물을 1:9로 혼합하여 닦아낸다."]'::jsonb, 5, '오염된 물질 처리 방법에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "심각하게 오염된 침구류는 분리하여 안전하게 처분하는 것이 맞지만, 처리 방법이 아닌 단순 폐기에 대한 설명이므로 오답입니다.\n[정답]", "5": "바닥에 쏟아진 혈액은 표백제와 물을 1:9로 혼합하여 안전하게 처리하는 방법이므로 정답입니다.", "3": "침구에 쏟아진 체액은 표백제를 사용하여 닦아내기 전에 먼저 적절한 방법으로 처리해야 하므로 오답입니다.", "4": "분비물에 오염된 장갑은 세척 후 재사용할 수 없으며, 폐기해야 하므로 오답입니다.", "2": "체액이 묻은 유리 조각은 반드시 위험 폐기물로 처리해야 하며, 일반 쓰레기로 버릴 수 없으므로 오답입니다."}'::jsonb, '[{"term_ko": "오염", "term_vi": "Ô nhiễm", "def_ko": "더럽혀지다(한국어)", "def_vi": "Bị bẩn(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1684, '14', '호흡기 감염병이 유행하는 시기에 요양보호사의 안전을 위한 가장 경제적이며 효과적인 감염 예방은?', '["보습제를 바른다.", "예방접종을 한다.", "6단계 손 씻기를 한다.", "채소를 반드시 익혀 먹는다.", "고용량 비타민제를 복용한다."]'::jsonb, 3, '호흡기 감염병 예방을 위한 요양보호사의 안전 수칙을 이해하는지 평가하기 위함입니다.', NULL, '{"1": "보습제를 바르는 것은 호흡기 감염 예방과 직접적인 연관이 없습니다.\n[정답]", "2": "예방접종은 감염병 예방에 중요하지만, 경제적으로 가장 효과적인 방법은 아닙니다.", "3": "6단계 손 씻기는 감염 예방에 가장 효과적이고 경제적인 방법입니다.", "4": "채소를 익혀 먹는 것은 식중독 예방에는 도움이 되지만, 호흡기 감염 예방에는 관계가 없습니다.", "5": "고용량 비타민제를 복용하는 것은 면역력 증진에 도움이 될 수 있지만, 경제적인 방법으로는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "호흡기", "term_vi": "Hô hấp", "def_ko": "숨 쉬는 기관", "def_vi": "cơ quan hô hấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1683, '14', '근무 중 감염 예방을 위한 손 위생 방법으로 옳은 것은?', '["세면대에 깨끗한 물을받아 충분히 씻는다.", "반지나 팔찌는 손을 씻은 후 착용한다.", "엄지손가락은 반대편 엄지손가락으로 문질러 씻는다.", "손가락 끝을 반대편 손바닥에 문질러 손톱 밑까지 씻는다.", "세균 번식을 막기 위해 젖은 수건은 말려서 다시 사용한다."]'::jsonb, 4, '손 위생의 중요성과 올바른 방법을 확인하기 위해 제시된 질문입니다.', NULL, '{"1": "세면대에 깨끗한 물을 받아 씻는 것은 기본적인 단계지만, 단순히 물로 씻는 것만으로는 충분하지 않습니다.\n[정답] (④) 손가락 끝을 반대편 손바닥에 문질러 손톱 밑까지 씻는 것이 올바른 손 위생 방법입니다.", "2": "반지나 팔찌는 손을 씻은 후 착용하는 것이 아니라, 착용하기 전 반드시 제거해야 합니다.", "3": "엄지손가락은 반대편 엄지손가락으로 문질러 씻는 것이 아니며, 손 전체를 잘 씻어야 합니다.", "5": "젖은 수건을 재사용하는 것은 세균 번식을 유발할 수 있으므로 잘못된 방법입니다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염(한국어)", "def_vi": "Nhiễm trùng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1682, '14', '감염 예방을 위해 손을 씻는 방법으로 옳은 것은?', '["손을 씻은 후 물기는 털어서 말린다.", "손이 건조하면 손 씻기 횟수를 줄인다.", "배설물을 처리한 손은 마른 휴지로 닦는다.", "멸균제품을 개봉하기 전 반드시 손을 씻는다.", "기침 후에는 흐르는 물과 비누로 10초 동안 씻는다."]'::jsonb, 4, '손 씻기를 통한 감염 예방의 중요성을 이해하고, 올바른 손 씻기 방법을 알고 있는지를 평가하기 위해 출제되었습니다.', NULL, '{"1": "손을 씻은 후 물기를 털어서 말리는 것은 올바르지 않습니다. 물기를 닦기 위해서는 깨끗한 수건이나 기구를 사용하는 것이 좋습니다.\n[정답]", "4": "멸균제품을 개봉하기 전 반드시 손을 씻는 것은 올바른 방법입니다. 감염 예방을 위해서는 항상 청결한 상태를 유지해야 합니다.", "3": "배설물을 처리한 손은 마른 휴지로 닦는 것은 적절하지 않으며, 반드시 손을 씻어야 합니다.", "2": "손이 건조하더라도 손 씻기 횟수를 줄여서는 안 됩니다. 감염 예방을 위해서는 손 씻기가 중요합니다.", "5": "기침 후에는 흐르는 물과 비누로 10초 이상 씻는 것이 권장됩니다. 10초는 불충분합니다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염(한국어)", "def_vi": "sự nhiễm trùng"}, {"term_ko": "예방", "term_vi": "Ngăn ngừa", "def_ko": "예방(한국어)", "def_vi": "sự phòng ngừa"}, {"term_ko": "손", "term_vi": "Tay", "def_ko": "손(한국어)", "def_vi": "tay"}, {"term_ko": "비누", "term_vi": "Xà phòng", "def_ko": "비누(한국어)", "def_vi": "xà phòng"}, {"term_ko": "멸균", "term_vi": "Tiệt trùng", "def_ko": "멸균(한국어)", "def_vi": "sự tiệt trùng"}, {"term_ko": "청결", "term_vi": "Sạch sẽ", "def_ko": "청결(한국어)", "def_vi": "sạch sẽ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1681, '14', '감염 예방을 위한 개인 보호구 사용 방법으로 옳은 것은?', '["옷을 갈아입힐 때 일회용 장갑을 작용한다.", "대상자와 산책할 때 안면보호구를 착용한다.", "목욕할 때는 보안경을 착용하고 몸을 씻긴다.", "기저귀를 갈 때 일회용 방수성가운을 착용한다.", "결핵 대상자를 돌볼 때 일회용 마스크와 장갑을 착용한다."]'::jsonb, 5, '감염 예방을 위한 개인 보호구의 올바른 사용 방법을 파악하는 것.', NULL, '{"1": "옷을 갈아입힐 때 일회용 장갑을 사용하는 것은 맞지만 특정 상황에 따라 달라질 수 있다. 그러나 일반적으로 권장되지 않는다.", "2": "대상자와 산책할 때 안면보호구를 착용하는 것은 반드시 필요한 상황이 아니므로 옳지 않다.", "3": "목욕할 때 보안경을 착용하는 것은 일반적이지 않으며, 필요하지 않다.", "4": "기저귀를 갈 때 일회용 방수성 가운을 착용하는 것은 적절하지 않을 수 있다.\n[정답]", "5": "결핵 대상자를 돌볼 때는 감염 예방을 위해 일회용 마스크와 장갑을 착용해야 한다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염", "def_vi": "Nhiễm trùng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1680, '14', '돌봄제공자인 요양보호사가 감염예방 원칙을 준수한 경우는?', '["휴지로 손을 닦고 장갑을 착용하였다.", "대상자의 배설물을 맨손으로 만졌다.", "사용한 장갑을 착용하고 깨끗한 물건을 만지지 않았다.", "대상자의 혈액이 몸에 닿아서 업무를 모두 마치고 닦았다.", "대상자의 분비물이 몸에 묻을 우려가 있어도 장갑만 착용했다."]'::jsonb, 3, '감염 예방 원칙을 준수하는 방법에 대해 평가하기 위함입니다.', NULL, '{"1": "휴지로 손을 닦고 장갑을 착용하였다. - 손을 닦는 것이 아니라 세척해야 합니다.\n[정답]", "3": "사용한 장갑을 착용하고 깨끗한 물건을 만지지 않았다. - 감염 예방 원칙을 잘 준수한 경우입니다.", "2": "대상자의 배설물을 맨손으로 만졌다. - 감염 예방 원칙을 위반한 것입니다.", "4": "대상자의 혈액이 몸에 닿아서 업무를 모두 마치고 닦았다. - 즉시 적절한 처치를 해야 합니다.", "5": "대상자의 분비물이 몸에 묻을 우려가 있어도 장갑만 착용했다. - 장갑 외에 추가적인 예방 조치가 필요합니다."}'::jsonb, '[{"term_ko": "감염 예방", "term_vi": "Phòng ngừa lây nhiễm", "def_ko": "감염을 막는 방법", "def_vi": "Các phương pháp ngăn chặn sự lây lan của vi trùng"}, {"term_ko": "장갑", "term_vi": "Găng tay", "def_ko": "손을 보호하는 착용물", "def_vi": "Đồ bảo vệ tay"}, {"term_ko": "세척", "term_vi": "Rửa", "def_ko": "깨끗하게 씻다", "def_vi": "Làm sạch bằng nước"}, {"term_ko": "배설물", "term_vi": "Phân", "def_ko": "신체에서 나오는 노폐물", "def_vi": "Chất thải từ cơ thể"}, {"term_ko": "혈액", "term_vi": "Máu", "def_ko": "몸속의 액체", "def_vi": "Chất lỏng trong cơ thể"}, {"term_ko": "분비물", "term_vi": "Chất tiết", "def_ko": "몸에서 나오는 액체", "def_vi": "Dịch tiết từ cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1679, '14', '감염성 질환에 이환된 대상자를 돌보는 방법으로 옳은 것은?', '["젖은 수건은 건조한후 반복 사용한다.", "오염된 장갑은 깨끗이 씻어 재사용한다.", "마스크만 착용하고 대상자의 배설물을 만진다.", "일을 마친 후 착용했던 장갑 상태로 업무를 본다.", "질병의 전파를 막기 일회용 방수가운을 착용한다."]'::jsonb, 5, '감염성 질환에 이환된 대상자를 돌볼 때 올바른 방법을 이해하고 있는지를 평가하려는 의도이다.', NULL, '{"1": "젖은 수건은 건조한 후 반복 사용하지 않아야 한다. 오염을 방지하기 위함이다.\n[정답]", "5": "질병의 전파를 막기 위해 일회용 방수가운을 착용하는 것이 올바른 방법이다.", "2": "오염된 장갑은 깨끗이 씻어 재사용해서는 안 된다. 오염물질이 남을 수 있다.", "3": "마스크만 착용하고 대상자의 배설물을 만지는 것은 위험하다. 장갑 등 추가적인 보호장구가 필요하다.", "4": "일을 마친 후 착용했던 장갑 상태로 업무를 보면 안 된다. 반드시 교체해야 한다."}'::jsonb, '[{"term_ko": "감염성 질환", "term_vi": "Bệnh truyền nhiễm", "def_ko": "감염 bệnh", "def_vi": "Bệnh do vi khuẩn hoặc virus gây ra"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1678, '14', '감염의 6가지 연결고리에 대한 설명으로 옳은 것은?', '["미생물은 인체 밖에서 바로 소멸한다.", "요양보호사는 감염의 민감한 대상자에 속한다.", "6가지 중 한 가지만 통제해서는 전파를 막을 수 없다.", "미생물은 손과 손을 접촉하는 직접 접촉경로만 전파된다.", "면역기능이 떨어진 대상자는 질병 전파를 막기 위해서 격리한다."]'::jsonb, 2, '감염의 전파 경로와 관련된 지식을 평가하기 위함입니다.', NULL, '{"1": "미생물은 인체 밖에서 바로 소멸하지 않습니다. 적절한 환경에서는 생존할 수 있습니다.\n[정답]", "2": "요양보호사는 감염에 취약한 대상자에게 직접적으로 접촉하기 때문에 민감한 대상자에 속합니다.", "3": "감염의 6가지 연결고리 중 하나의 통제로는 전파를 완전히 막을 수 없습니다. 모든 고리를 통제해야 효과적인 예방이 가능합니다.", "4": "미생물은 직접 접촉경로 외에도 공기, 물 등을 통해 전파될 수 있습니다.", "5": "면역기능이 떨어진 대상자는 감염을 예방하기 위해 격리할 수 있지만, 이는 일반적인 경우는 아닙니다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염(한국어)", "def_vi": "Nhiễm trùng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1677, '14', '전기 사고를 예방하고 안전하게 사용하는 방법으로 옳은 것은?', '["전선에서 불꽃이 일어나면 물을 뿌린다.", "정전으로 해동된 식품은 다시 냉동한다.", "벗겨진 전기코드는 청테이프로 감아 사용한다.", "정전 시 누전차단기의 이상 유무를 확인한다.", "콘센트에서 플러그를 뺄 때에는 지그재그로 움직여 뺀다."]'::jsonb, 4, '전기 사고를 예방하기 위한 안전 지침을 묻는 문제입니다.', NULL, '{"1": "전선에서 불꽃이 나는 경우 물을 사용하면 더 큰 사고를 유발할 수 있습니다.\n[정답]", "4": "정전 시 누전차단기의 이상 유무를 확인하는 것은 안전을 유지하는 데 중요합니다.", "2": "해동된 식품은 다시 냉동할 경우 세균 증식의 위험이 있습니다.", "3": "벗겨진 전기코드를 청테이프로 감아 사용하는 것은 잘못된 방법입니다.", "5": "콘센트에서 플러그를 빼는 방법은 수직으로 당겨 빼야 합니다."}'::jsonb, '[{"term_ko": "전기 사고", "term_vi": "Tai nạn điện", "def_ko": "전기 gây 발생하는 사고(한국어)", "def_vi": "Tai nạn xảy ra do điện(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1676, '14', '가정용 산소호흡기를 사용하는 재가대상자의 가정에 정전이 발생했을 때 대처방법은?', '["누전차단기를 즉시 교체한다.", "대상자와 함께 밖으로 대피한다.", "119에 신고하여 긴급후송을 준비한다.", "전선을 잡고 플러그를 빼서 다시 꽂는다.", "젖은 수건으로 콘센트의 쌓인 먼지를 닦는다."]'::jsonb, 3, '가정에서 산소호흡기를 사용하는 재가대상자의 안전을 위한 올바른 대처 방법을 이해하는 것이다.', NULL, '{"1": "누전차단기를 즉시 교체하는 것은 적절하지 않다. 정전 시에는 전기 배선을 건드리는 것이 위험할 수 있다.\n[정답]", "2": "대상자와 함께 밖으로 대피하는 것은 안전한 선택일 수 있지만, 재가대상자의 상태에 따라 다를 수 있다.", "3": "119에 신고하여 긴급후송을 준비하는 것이 가장 안전한 대처이다. 산소 공급이 중단될 경우 위험하기 때문에 신속하게 조치를 취해야 한다.", "4": "전선을 잡고 플러그를 빼서 다시 꽂는 것은 위험한 행동이다. 전기가 흐르고 있는 상황에서는 매우 위험하다.", "5": "젖은 수건으로 콘센트의 쌓인 먼지를 닦는 것은 전기 사고를 유발할 수 있으므로 절대 해서는 안 된다."}'::jsonb, '[{"term_ko": "가정용", "term_vi": "Thiết bị gia đình", "def_ko": "가정에서 사용하는 것", "def_vi": "Sử dụng trong gia đình"}, {"term_ko": "산소호흡기", "term_vi": "Máy thở oxy", "def_ko": "산소를 공급하는 기계", "def_vi": "Thiết bị cung cấp oxy"}, {"term_ko": "정전", "term_vi": "Mất điện", "def_ko": "전기가 공급되지 않는 상태", "def_vi": "Trạng thái không có điện"}, {"term_ko": "대처방법", "term_vi": "Phương pháp xử lý", "def_ko": "문제를 해결하기 위한 조치", "def_vi": "Biện pháp giải quyết vấn đề"}, {"term_ko": "응급후송", "term_vi": "Chuyển viện khẩn cấp", "def_ko": "응급환자를 병원으로 이송하는 것", "def_vi": "Vận chuyển bệnh nhân khẩn cấp ra bệnh viện"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1675, '14', '지진이 발생하여 집이 흔들릴 때 대처 방법은?', '["창문을 열고 환기한다.", "가스밸브를 점검한 후에 열어둔다.", "흔들름이 멈추면 바로 전기를 사용한다.", "탁자가 없으면 머리를 팔로 감싸고 우으린다.", "밖으로 나가 건물의 계단 밑으로 대피한다."]'::jsonb, 4, '지진 발생 시 어떻게 대처해야 하는지 인식하고 있는지를 평가하기 위해 출제되었습니다.', NULL, '{"1": "창문을 열고 환기하는 것은 지진 발생 시 안전에 도움이 되지 않습니다.\n[정답]", "2": "가스밸브를 점검한 후 열어두는 것은 안전하지 않은 행동입니다.", "3": "흔들림이 멈춘 후 전기를 사용하는 것은 위험할 수 있습니다.", "4": "탁자가 없으면 머리를 팔로 감싸고 우는 것이 위험으로부터 스스로를 보호하는 올바른 행동입니다.", "5": "밖으로 나가 건물의 계단 밑으로 대피하는 것은 지진 발생 시 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "지진", "term_vi": "Động đất", "def_ko": "지구의 내부에서 발생하는 진동", "def_vi": "Sự rung chuyển xảy ra trong lòng đất"}, {"term_ko": "대처", "term_vi": "Ứng phó", "def_ko": "어떤 상황에 대해 행동하는 것", "def_vi": "Hành động đối với một tình huống"}, {"term_ko": "탁자", "term_vi": "Bàn", "def_ko": "사각형의 가구", "def_vi": "Một đồ vật có bốn chân dùng để đặt đồ"}, {"term_ko": "계단", "term_vi": "Cầu thang", "def_ko": "건물 내부의 걸어 올라가거나 내려가는 구조물", "def_vi": "Cấu trúc để đi lên hoặc đi xuống trong tòa nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1674, '14', '가정에서 지진이 발생했을 때 대처방법은?', '["흔들리는 동안에는 탁자 위에 엎드린다.", "흔들림은 잠시 멈추면 출입문을 잠근다.", "깨지기 쉬운 물건은 높은 곳에 올려 둔다.", "엘리베이터를 타고 신속하게 밖으로 나간다.", "식탁 밑으로 들어가 식탁 다리를 잡고 웅크린다."]'::jsonb, 5, '지진 발생 시 안전한 대처 방법을 묻는 질문입니다.', NULL, '{"1": "흔들리는 동안에는 탁자 위에 엎드리는 것은 매우 위험합니다. 지진 중에는 탁자 위가 아닌 튼튼한 물체 아래로 들어가야 합니다.\n[정답]", "5": "식탁 밑으로 들어가 식탁 다리를 잡고 웅크리는 것이 가장 안전한 방법입니다.", "3": "깨지기 쉬운 물건은 높은 곳에 두면 안 되고, 저지대에 두어야 합니다.", "4": "엘리베이터를 타는 것은 끔찍한 위험을 초래할 수 있습니다. 지진 중에는 엘리베이터 사용을 피해야 합니다.", "2": "흔들림이 멈추면 출입문을 잠그는 것은 적절한 행동이 아닙니다."}'::jsonb, '[{"term_ko": "지진", "term_vi": "Động đất", "def_ko": "지구의 내부에서 발생하는 강한 진동", "def_vi": "Sự rung lắc mạnh xảy ra trong lòng đất"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1673, '14', '홍수로 인해 수해가 발생했을 때 대처방법은?', '["가스밸브를 열어 개통상태를 점검한다.", "물이 집 안으로 밀려오는 경우 모래주머니로 막는다.", "밀려온 물이 집 안에서 빠진 직후 전기 차단기를 올린다.", "홍수로 밀려온 물에 몸이 젖은 경우 수건으로 닦는다.", "집 안의 물이 빠지고 나면 라이터를 사용하여 불을 켠다."]'::jsonb, 2, '홍수 발생 시 안전하고 적절한 대처 방법을 알고 있는지를 확인하기 위함입니다.', NULL, '{"1": "가스 누출 위험이 있으므로 가스밸브를 점검하는 것이 적절한 상황이 아닙니다.\n[정답]", "2": "물이 집 안으로 밀려오는 경우 모래주머니로 막는 것이 가장 안전한 대처 방법입니다.", "3": "전기 차단기는 물이 빠진 후에 올려야 안전합니다.", "4": "몸이 젖은 경우 수건으로 닦는 것은 대처 방법이 아닙니다.", "5": "불을 켜는 것은 매우 위험하며, 물이 빠지고 난 후에도 위험합니다."}'::jsonb, '[{"term_ko": "홍수", "term_vi": "Lũ lụt", "def_ko": "물이 넘쳐흐르는 현상", "def_vi": "Hiện tượng nước tràn"}, {"term_ko": "수해", "term_vi": "Thiệt hại do nước", "def_ko": "물로 인한 피해", "def_vi": "Thiệt hại do nước gây ra"}, {"term_ko": "모래주머니", "term_vi": "Bao cát", "def_ko": "물리적 장치로 물을 차단", "def_vi": "Thiết bị vật lý dùng để chặn nước"}, {"term_ko": "전기 차단기", "term_vi": "Công tắc điện", "def_ko": "전기를 끊는 장치", "def_vi": "Thiết bị ngắt điện"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1672, '14', '태풍 예보를 듣고 대비하는 방법으로 옳은 것은?', '["현관문과 창문을 열어둔다.", "차량을 낮은 지대로 옮긴다.", "욕조에 물을 미리 받아둔다.", "주유되어 있는 자동차의 연료를 비운다.", "전기 차단기를 내리고 통신 기기는 끈다."]'::jsonb, 3, '태풍 상황에서 안전하게 대처하는 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "현관문과 창문을 열어두면 바람의 영향으로 피해를 입을 수 있으므로 위험합니다.\n[정답]", "3": "욕조에 물을 미리 받아두는 것은 비상시 필요한 물을 확보하는 좋은 방법입니다.", "2": "차량을 낮은 지대로 옮기는 것은 홍수 등의 위험에 노출될 수 있기에 바람직하지 않습니다.", "4": "주유된 자동차의 연료를 비우는 것은 비상 상황에서 필요할 수 있는 연료를 아끼는 것과는 반대로 위험을 초래할 수 있습니다.", "5": "전기 차단기를 내리고 통신 기기를 끄는 것은 필요한 정보를 받아들이는 데 방해가 될 수 있습니다."}'::jsonb, '[{"term_ko": "태풍", "term_vi": "Bão", "def_ko": "강한 바람과 비를 동반한 자연현상", "def_vi": "Hiện tượng thiên nhiên có gió mạnh và mưa"}, {"term_ko": "예보", "term_vi": "Dự báo", "def_ko": "미리 예측하는 것", "def_vi": "Dự đoán trước"}, {"term_ko": "대비", "term_vi": "Chuẩn bị", "def_ko": "준비하는 것", "def_vi": "Hành động chuẩn bị"}, {"term_ko": "욕조", "term_vi": "Bồn tắm", "def_ko": "욕실에 있는 큰 물탱크", "def_vi": "Bể chứa nước lớn trong phòng tắm"}, {"term_ko": "차량", "term_vi": "Xe", "def_ko": "자동차", "def_vi": "Ô tô"}, {"term_ko": "연료", "term_vi": "Nhiên liệu", "def_ko": "자동차가 운행하는 데 필요한 물질", "def_vi": "Chất cần thiết cho việc vận hành ô tô"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1671, '14', '유해가스가 방출되는 화재 발생 시 대처방법과 안전 수칙으로 옳은 것은?', '["마른 수건으로 입을 감싼다.", "숨을 깊이 들이마시며 대피한다.", "두 손으로 벽을 짚으며 밖으로 나간다.", "''불이야''라고 소리치고 비상벨을 누른다.", "화재를 대비하여 옥상 출입문을 항상 잠가둔다."]'::jsonb, 4, '유해가스가 방출되는 화재 발생 시 안전하게 대처하는 방법을 알고 있는지 확인하기 위한 문제입니다.', NULL, '{"1": "마른 수건으로 입을 감싸는 것은 가스의 흡입을 줄이는 방법이지만 대처 방법으로는 효과적이지 않습니다.\n[정답]", "4": "''불이야''라고 소리치고 비상벨을 누르는 것이 가장 적절한 대처 방법입니다.", "3": "두 손으로 벽을 짚으며 밖으로 나가는 것은 방향을 잃지 않기 위한 방법이지만 불필요하게 시간을 소모할 수 있습니다.", "2": "숨을 깊이 들이마시며 대피하는 것은 유해가스를 더 많이 흡입하게 되는 위험한 행동입니다.", "5": "화재를 대비하여 옥상 출입문을 잠가두는 것은 종종 잘못된 대비책으로, 불시의 대피가 어려워질 수 있습니다."}'::jsonb, '[{"term_ko": "유해가스", "term_vi": "Khí độc", "def_ko": "해로운 기체", "def_vi": "Khí gây hại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1670, '14', '시설에서 화재가 발생했을 때 대처방법으로 옳은 것은?', '["엘리베이터를 타고 이동한다.", "연기로 앞이 보이지 않으면 그대로 서 있는다.", "코와 입을 감싸고 최대한 자세를 높여 이동한다.", "불길이 천장까지 닿으면 소화기로 신속하게 진화한다.", "방향을 알기 힘들 때에는 계속 한쪽 손으로 벽을 짚으면서 나간다."]'::jsonb, 5, '화재 발생 시 적절한 대처 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "엘리베이터는 화재 시에 사용하면 안 되는 이동 수단입니다.\n[정답]", "2": "연기로 앞이 보이지 않는 상황에서는 서 있지 말고 안전한 방향으로 이동해야 합니다.", "3": "코와 입을 감싸고 자세를 낮추는 것이 중요하나, 자세를 높여 이동하는 것은 안전하지 않습니다.", "4": "불길이 천장까지 닿으면 소화기로 진화 시도가 위험하므로 즉각 대피해야 합니다.", "5": "방향을 알기 힘들 때에는 벽을 짚으며 이동하는 것이 안전한 방법입니다."}'::jsonb, '[{"term_ko": "화재", "term_vi": "이동", "def_ko": "불 화재(화재)", "def_vi": "이동(di chuyển)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1669, '14', '화재 예방을 위해 지켜야 하는 안전 수칙으로 옳은 것은?', '["요리가 끝날 때까지 주방에 있는다.", "세탁물은 난로 바로옆에 널어말린다.", "실내 소화기 위치를 자주 바꾸어 놓는다.", "소화기사용 시 벽을 등지고 소화기 분말을 쏜다.", "콘센트 하나에 여러 개의 전열기구 플러그를 꽂는다."]'::jsonb, 1, '화재 예방을 위한 안전 수칙을 이해하고 있는지를 평가하려는 의도입니다.', NULL, '{"1": "주방에서 요리를 하고 있을 때는 화재를 예방하기 위해 주방에 있는 것이 중요합니다.\n[정답]", "2": "난로 바로 옆에 세탁물을 널면 화재의 위험이 증가합니다.", "3": "실내 소화기의 위치를 자주 바꾸는 것은 위기 시 혼란을 초래할 수 있습니다.", "4": "소화기 사용 시 벽을 등지는 것이 바람직하지 않습니다.", "5": "콘센트 하나에 여러 개의 전열 기구를 꽂는 것은 과열의 위험이 있습니다."}'::jsonb, '[{"term_ko": "화재", "term_vi": "Hỏa hoạn", "def_ko": "불이 나는 것", "def_vi": "Lửa cháy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1668, '14', '가스레인지 불에 음식을 올려놓고 자꾸 잊어버리는 대상자를 돕는 방법은?', '["배달 음식으로 식단표를 작성하게 한다.", "휴대용 가스레인지를 사용하게 한다.", "가족과 상의하여 가스레인지를 없앤다.", "조리할 때는 주방을 떠나지 않도록 교육한다.", "일주일 분량의 음식을 한꺼번에 준비해둔다."]'::jsonb, 4, '가스레인지 불에 음식을 올려놓고 잊어버리는 대상자를 위한 안전한 대처 방법을 묻는 문제입니다.', NULL, '{"1": "배달 음식으로 식단표를 작성하는 것은 대처 방법이 아닙니다.\n[정답]", "2": "휴대용 가스레인지를 사용하게 하는 것은 상황을 오히려 악화시킬 수 있습니다.", "3": "가족과 상의하여 가스레인지를 없애는 것은 비현실적인 접근입니다.", "4": "조리할 때는 주방을 떠나지 않도록 교육하는 것은 매우 효과적인 방법입니다.", "5": "일주일 분량의 음식을 한꺼번에 준비해두는 것은 장기적인 해결책이지만, 즉각적인 대처에는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "가스레인지", "term_vi": "Bếp gas", "def_ko": "가스를 연료로 사용하는 조리 기구", "def_vi": "Thiết bị nấu ăn sử dụng khí đốt"}, {"term_ko": "음식", "term_vi": "Thức ăn", "def_ko": "조리한 식사", "def_vi": "Món ăn đã nấu"}, {"term_ko": "대상자", "term_vi": "Người cần giúp đỡ", "def_ko": "도움을 필요한 사람", "def_vi": "Người cần trợ giúp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1667, '14', '방문요양 시 대상자에게 응급상황이발생했을 때 요양보호사는 언제까지 응급처치를 해야 하는가?', '["근무시간이 끝날 때까지", "시설장이 도착할 떄까지", "보호자가 도착할 때까지", "119 구급대원이 도착할 때까지", "동료 요양보호사가 도착할 때까지"]'::jsonb, 4, '요양보호사가 응급상황에서의 역할과 책임을 이해하고 있는지 평가하기 위한 문제입니다.', NULL, '{"1": "요양보호사가 근무시간이 끝날 때까지 응급처치를 해야 한다는 것은 적절하지 않습니다.\n[정답]", "4": "요양보호사는 응급 상황 발생 시 119 구급대원이 도착할 때까지 응급처치를 계속해야 합니다.", "3": "보호자가 도착할 때까지는 응급처치를 기다릴 수 없으며,", "2": "시설장이 도착할 때까지도 반응이 필요합니다.", "5": "동료 요양보호사가 도착할 때까지 응급처치를 중단하는 것은 위험합니다."}'::jsonb, '[{"term_ko": "응급상황", "term_vi": "Tình huống khẩn cấp", "def_ko": "응급 상황(한국어)", "def_vi": "Tình huống gấp rút(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1666, '14', '위기 상황에 대한 대처 방법으로 옳은 것은?', '["응급처치를 먼저 한 후에 119에 신고한다.", "갖고과 연락이 되지 않으면 응급처치를 미룬다.", "대상자가 명료하게 대답을 했어도 119에 신고한다.", "119에 신고 시 보호자의 연락처, 가족 정보를 알려준다.", "심한 통증을 호소하면 전문적인 치료가 필요하다고 판단한다."]'::jsonb, 5, '위기 상황에서 응급처치와 119 신고의 절차를 이해하고 있는지를 평가하고자 합니다.', NULL, '{"1": "응급처치는 상황에 따라 다르게 적용되며, 즉시 신고가 우선될 수 있습니다.\n[정답]", "2": "응급처치는 반드시 진행해야 하며 연락이 되지 않더라도 미룰 수 없습니다.", "3": "대상자가 명료하게 대답했다고 하더라도, 그 응급 상황의 심각성을 고려해 119에 신고해야 합니다.", "4": "119에 신고할 때는 보호자의 연락처와 가족 정보가 중요하므로 꼭 알려줘야 합니다.", "5": "심한 통증이 있을 경우 전문적인 치료를 요구할 수 있으니 이를 반드시 인지해야 합니다."}'::jsonb, '[{"term_ko": "위기", "term_vi": "Tình huống khẩn cấp", "def_ko": "위기 상황(상급의 문제나 심각한 상황)", "def_vi": "Tình huống nghiêm trọng hoặc vấn đề cấp bách"}, {"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "즉각적으로 처리하는 치료", "def_vi": "Điều trị ngay lập tức"}, {"term_ko": "신고하다", "term_vi": "Báo cáo", "def_ko": "공식적으로 알리는 것", "def_vi": "Thông báo chính thức"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "신체의 고통", "def_vi": "Đau đớn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1665, '14', '의학적 위기상황에 대한 대처 방법으로 옳은 것은?', '["가장 먼저 가족 또는 기관장에게 보고한다.", "119에 신고를 했다면 전화를 끊고 응급처치를 한다.", "신고를 해야 할지 고민이 되는 상황이라면 신고한다.", "호흡이나 맥박이 정상적이어도 119에 신고한다.", "상황이 종료되었다면 기록은 작성하지 않아도 된다."]'::jsonb, 3, '의학적 위기 상황에서의 대처 방법을 알고 있는지를 평가하는 문제입니다.', NULL, '{"1": "일반적으로는 지금 당장 대처하는 것이 먼저지만, 위기상황에서도 가족 또는 기관장에게 즉시 보고하는 것은 종종 중요합니다.\n[정답]", "2": "응급처치를 즉시 시행해야 하며, 신고 후 응급처치가 이어져야 합니다.", "3": "신고가 필요한 상황이라면 반드시 신고해야 하며, 고민할 시간이 없습니다.", "4": "정상적인 호흡이나 맥박이 확인되더라도, 안전을 위해 신고하는 것이 중요합니다.", "5": "상황이 종료된 후에는 반드시 기록을 남겨야 하며, 기록에 대한 의무가 있습니다."}'::jsonb, '[{"term_ko": "의학적", "term_vi": "Y học", "def_ko": "의학에 관한", "def_vi": "Liên quan đến y học"}, {"term_ko": "위기상황", "term_vi": "Tình huống khẩn cấp", "def_ko": "심각한 상황", "def_vi": "Tình huống nghiêm trọng"}, {"term_ko": "대처", "term_vi": "Xử lý", "def_ko": "문제를 해결하기 위한 행위", "def_vi": "Hành động để giải quyết vấn đề"}, {"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "응급 상황에서 시행하는 치료", "def_vi": "Điều trị trong tình huống khẩn cấp"}, {"term_ko": "보고", "term_vi": "Báo cáo", "def_ko": "상황을 알리는 행위", "def_vi": "Hành động thông báo"}, {"term_ko": "기록", "term_vi": "Ghi chép", "def_ko": "사건이나 상황을 남기는 것", "def_vi": "Việc ghi lại sự kiện hoặc tình huống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1664, '14', '다음 중 의학적 위기 상황으로 응급처치를 실시해야 하는 상황은?', '["호흡이 안정적일 때", "기침이 자주나올 때", "맥박이 강하게 뛸 때", "의식의 변화가 있을 때", "전신에 피로를 느낄 때"]'::jsonb, 4, '응급처치가 필요한 의학적 위기 상황에 대한 이해를 확인하기 위한 문제입니다.', NULL, '{"1": "호흡이 안정적이라는 것은 위기 상황이 아님을 나타냅니다.", "2": "기침이 자주 나온다고 해서 즉각적인 응급처치가 필요한 상황은 아닙니다. \n[정답]", "3": "맥박이 강하게 뛰는 것은 상황에 따라 다르지만, 반드시 응급처치가 필요한 것은 아닙니다.", "4": "의식의 변화가 있으면 즉각적인 응급처치가 필요합니다.", "5": "전신에 피로를 느낀다고 해서 응급처치가 필요한 상황은 아닙니다."}'::jsonb, '[{"term_ko": "의학적", "term_vi": "Y học", "def_ko": "의학과 관련된", "def_vi": "Liên quan đến y học"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1663, '13', '호스피스, 완화의료 서비스에 대한 설명으로 옳은 것은?', '["말기질환을 가진 환자에게만 제공되는 의료서비스이다.", "만성폐쇄성 호흡기 질호나자는 입원형 이용이 가능하다.", "자문형은 자택으로전문인력이 방문하여 서비스를 제공한다.", "만성 간경화 환자는 자문형 서비스를 이용할 수 있다.", "입원형은 가정에서 돌보기 어려운 노인을 대상으로 한다."]'::jsonb, 4, '호스피스 및 완화의료 서비스의 개념과 유형에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "호스피스는 말기환자에게 뿐만 아니라 다양한 상태의 환자에게 제공될 수 있는 서비스입니다.\n[정답]", "2": "만성폐쇄성호흡기질환(COPD) 환자는 입원형 서비스를 이용할 수 있습니다.", "3": "자문형 서비스는 자택에서 제공되는 것이 맞지만, 전문 인력이 방문하는 형태는 맞지만 자문형으로만 한정될 수 없습니다.", "4": "만성 간경화 환자는 자문형 서비스를 이용할 수 있습니다.", "5": "입원형 서비스는 가정에서 돌보기 어려운 환자를 위한 서비스입니다."}'::jsonb, '[{"term_ko": "호스피스", "term_vi": "Chăm sóc giảm nhẹ", "def_ko": "말기환자에게 제공되는 의료 및 정서적 지원 서비스", "def_vi": "Dịch vụ hỗ trợ y tế và tinh thần dành cho bệnh nhân giai đoạn cuối"}, {"term_ko": "완화의료", "term_vi": "Y tế giảm nhẹ", "def_ko": "환자의 고통을 줄이고 삶의 질을 향상시키기 위한 의료", "def_vi": "Y tế nhằm giảm nhẹ nỗi đau và cải thiện chất lượng cuộc sống của bệnh nhân"}, {"term_ko": "입원형", "term_vi": "Hình thức nhập viện", "def_ko": "병원에서 제공되는 형태", "def_vi": "Hình thức cung cấp dịch vụ tại bệnh viện"}, {"term_ko": "자문형", "term_vi": "Hình thức tư vấn", "def_ko": "전문가가 환자의 집으로 방문하여 제공하는 서비스", "def_vi": "Dịch vụ được cung cấp qua việc chuyên gia đến thăm nhà bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1662, '13', '호스피스, 완화의료 이용에 대한 설명으로 옳은 것은?', '["국내에서는 입원형 서비스만 제공한다.", "치료 가능한 말기질환을 가진 환자와 가족을 대상으로 한다.", "후천성면역결핍증 환자는 입원형 서비스를 이용할 수 있다.", "가정형은 외래진료를 보듯이 환자가 방문하는 형태이다.", "통증, 신체적, 심리적, 영적 고통을 완화하여 삶의 질을 향상시키는 의료서비스이다."]'::jsonb, 5, '호스피스와 완화의료의 기본 개념과 특성을 이해하고 있는지를 평가하고자 한다.', NULL, '{"1": "국내에서는 입원형 서비스만 제공한다. (잘못된 설명으로, 국내에서는 가정형 호스피스 서비스도 제공된다.)\n[정답]", "5": "통증, 신체적, 심리적, 영적 고통을 완화하여 삶의 질을 향상시키는 의료서비스이다. (옳은 설명으로, 호스피스의 주요 목적이기도 하다.)", "3": "후천성면역결핍증 환자는 입원형 서비스를 이용할 수 있다. (옳지 않은 설명으로, 호스피스는 일단 치료가 불가능한 상태에서 제공된다.)", "4": "가정형은 외래진료를 보듯이 환자가 방문하는 형태이다. (잘못된 설명으로, 가정형 호스피스는 환자가 집에서 받는 서비스이다.)", "2": "치료 가능한 말기질환을 가진 환자와 가족을 대상으로 한다. (잘못된 설명으로, 호스피스는 치료가 불가능한 말기환자를 대상으로 한다.)"}'::jsonb, '[{"term_ko": "호스피스", "term_vi": "Chăm sóc giảm nhẹ", "def_ko": "환자의 마지막 단계를 지원하는 의료 서비스", "def_vi": "Dịch vụ y tế hỗ trợ bệnh nhân ở giai đoạn cuối"}, {"term_ko": "완화의료", "term_vi": "Chăm sóc giảm nhẹ", "def_ko": "치료가 불가능한 환자의 고통을 줄이는 의료", "def_vi": "Y tế nhằm giảm bớt khổ sở"}, {"term_ko": "입원형", "term_vi": "Nhập viện", "def_ko": "병원에 누워 치료를 받는 형태", "def_vi": "Hình thức điều trị tại bệnh viện"}, {"term_ko": "가정형", "term_vi": "Hỗ trợ tại nhà", "def_ko": "집에서 치료를 받는 형태", "def_vi": "Dịch vụ y tế tại nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1661, '13', '사전연명의료의향서에 대한 설명으로 옳은 것은?', '["말기환자나 임종과정에 있는 사람만 작성할 수 있다.", "사전연명의료의향서 등록기관에 등록해야만 효력이 생긴다.", "등록 후에는 내용을 변경, 철회할 수 없다.", "등록기관에 등록하면 모든 의료기관에 자동 연동된다.", "통증완화를 위한 의료행위와 영양분 및 물 공급을 중단한다."]'::jsonb, 2, NULL, NULL, NULL, NULL);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1660, '13', '다음 중에서 사전연명의료의향서의 효력이 발생하는 경우는?', '["17세 청소년이 자발적 의사로 직접 작성한 경우", "30세 위암 환자의 부탁으로 가족이 작성한 경우", "65세 대장암 환자가 자발적으로 요청한 경우", "70세 노인의 요청에 따라 담당 의사가 작성한 경우", "80세 뇌졸중 환자의 요양보호사가 대리로 작성한 경우"]'::jsonb, 3, '사전연명의료의향서의 효력 발생 조건에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "17세 청소년은 법적으로 자율적인 의사결정 능력이 부족하여 효력이 인정되지 않습니다.\n[정답]", "3": "65세 대장암 환자가 자발적으로 요청한 경우, 법적으로 유효한 사전연명의료의향서로 인정됩니다.", "2": "30세 위암 환자의 부탁으로 가족이 작성한 경우, 본인의 자발적 의사에 따른 것이 아니므로 효력이 없습니다.", "4": "70세 노인의 요청에 따라 담당 의사가 작성한 경우, 법적 효력을 갖기 위해서는 환자가 자발적으로 작성해야 합니다.", "5": "80세 뇌졸중 환자의 요양보호사가 대리로 작성한 경우, 대리 작성은 법적으로 인정되지 않으므로 효력이 없습니다."}'::jsonb, '[{"term_ko": "사전연명의료의향서", "term_vi": "Văn bản nguyện vọng chăm sóc y tế trước", "def_ko": "사전의료의향서(한국어)", "def_vi": "Văn bản ý muốn chăm sóc y tế được lập trước (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1659, '13', '시설 대상자가 요양보호사에게 사전연명의료의향서를 대신 작성해 달라고 할 때 반응으로 옳은 것은?', '["\"시설에 오기 전에 작성했어야 합니다.\"", "\"시설장과 상의해서 작성해야만 합니다.\"", "\"잔여ㅢ동의가 있어야 작성할 수 있습니다.\"", "\"어르신이 직접 작성하는 것이 원칙입니다.\"", "\"작성과 동시에 효력이 발생하여 신중하셔야 합니다.\""]'::jsonb, 4, '시설 대상자의 권리와 요양보호사의 역할 인식', NULL, '{"1": "시설에 오기 전에 혼자서 결정하고 작성해야 한다는 의미의 발언으로 공감과 이해를 도와주지 못한다.", "2": "시설장과의 논의는 필요하나, 직접 작성해야 한다는 원칙은 변하지 않는다.", "3": "잔여 동의가 필요하다는 것은 잘못된 정보로, 어르신의 의사에 따라 작성할 수 있다.\n[정답]", "4": "어르신이 직접 작성하는 것이 원칙으로, 요양보호사는 이에 대해 지원할 수 있으며, 직접 작성하는 것을 권장한다.", "5": "작성과 동시에 효력이 발생하는 것이 아니라, 어르신의 의사를 반영하는 것이 우선시 되어야 한다."}'::jsonb, '[{"term_ko": "사전연명의료의향서", "term_vi": "Tài liệu ý kiến y tế trước", "def_ko": "의사가 환자의 의사를 존중하여 생명유지 치료에 대한 권리를 정하는 문서", "def_vi": "Tài liệu xác định quyền của bệnh nhân về việc điều trị duy trì sự sống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1658, '13', '사전연명의료의향서에 관한 설명으로 옳은 것은?서', '["65세가 되어야 작성할 수 있다.", "본인이 직접 작성하지 않은 경우 효력이 없다.", "작성한 후 병, 의원 어디서나 등록할 수 있다.", "연명의료중단 시 물과 영양분 공급이 중단된다.", "작성자가 글씨를 쓸 수 없는 경우에는 사전연명의료의향서를 작성할 수 없다."]'::jsonb, 2, '사전연명의료의향서에 대한 이해도를 평가하기 위한 문제이다.', NULL, '{"1": "65세가 아닌, 성인이면 누구나 작성할 수 있다. \n[정답]", "2": "본인이 직접 작성해야 효력이 있다.", "3": "등록은 보건소에 해야 하며, 병의원에서는 등록할 수 없다.", "4": "연명의료중단 시 물과 영양분 공급은 계속 유지된다.", "5": "작성자가 글씨를 쓸 수 없더라도 대리인이 작성할 수 있다."}'::jsonb, '[{"term_ko": "사전연명의료의향서", "term_vi": "Giấy chỉ đạo y tế trước khi chết", "def_ko": "사전으로 고안된 의료 지침서", "def_vi": "Tài liệu chỉ đạo y tế đã được lập trước"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1657, '13', '말기 암환자가 사전연명의료의향서를 작성하면 치료가 어떻게 되는지 물을 때 요양 보호사의 반응으로 옳은 것은?', '["\"모든 치료가중단됩니다.\"", "\"혈액투석은 계속 진행됩니다.\"", "\"항암제 치료는 의사가 판단하여 결정합니다.\"", "\"통증완화를 위한 진통제와 물은 계속 공급됩니다.\"", "\"인공호흡기 치료는 비용을 부담하면 계속할 수 있습니다.\""]'::jsonb, 4, '말기 암환자의 치료 및 연명의료의향서에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "치료 중단에 대한 설명은 과장된 부분이 있어 옳지 않습니다.\n[정답]", "4": "통증 완화를 위한 진통제와 기본적인 수분 공급은 계속 진행됩니다. 이는 환자의 편안함을 위해 중요합니다.", "2": "혈액 투석은 일반적으로 연명의료의향서와 관련이 없으므로 정확한 설명이 아닙니다.", "3": "항암제 치료는 환자의 상태와 의사의 판단에 따라 다르지만, 연명의료의향서에 따라 선택되지 않을 가능성이 높습니다.", "5": "인공호흡기 치료는 연명의료 포함에 따라 관리되므로 누락된 부분이 있습니다."}'::jsonb, '[{"term_ko": "말기", "term_vi": "Giai đoạn cuối", "def_ko": "말기의, 사람이 더 이상 회복되지 않는 단계", "def_vi": "Giai đoạn không thể phục hồi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1656, '13', '사전연명의료의향서''를 등록한 대상자가 임종과정에 있을 때 제공 받을 수 있는 것은?', '["혈액 투석", "산소 공급", "심폐소생술", "항암제 투여", "혈압상승제 투여"]'::jsonb, 2, '''사전연명의료의향서''에 대해 이해하고, 해당 문서에 따라 제공받을 수 있는 의료 행위를 파악하는 것이 목적입니다.', NULL, '{"1": "혈액 투석은 임종과정에서 생명을 연장하기 위한 방법으로 간주되며, 사전연명의료의향서의 적용을 받지 않습니다.\n[정답]", "2": "산소 공급은 호흡을 지원하기 위한 방법으로, 임종과정에 있을 때 필수적인 지원으로 제공될 수 있습니다.", "3": "심폐소생술은 생명 연장을 위한 조치를 포함하며, 일반적으로 사전연명의료의향서에서 배제됩니다.", "4": "항암제 투여는 체내의 암세포를 치료하기 위한 비즈니스적 접근으로, 임종과정에서 시행되지 않습니다.", "5": "혈압상승제 투여는 환자의 생명을 연장하기 위한 치료의 일환으로 간주되어 제공되지 않습니다."}'::jsonb, '[{"term_ko": "사전연명의료의향서", "term_vi": "Hồ sơ ý chí chăm sóc y tế trước", "def_ko": "환자가 자신의 연명치료에 대한 의사를 사전에 밝히는 문서", "def_vi": "Tài liệu mà bệnh nhân công bố ý chí của mình về điều trị sự sống trước"}, {"term_ko": "임종과정", "term_vi": "Quá trình cuối đời", "def_ko": "생명이 끝나는 과정", "def_vi": "Quá trình mà cuộc sống kết thúc"}, {"term_ko": "산소 공급", "term_vi": "Cung cấp oxy", "def_ko": "호흡을 지원하는 행위", "def_vi": "Hành động hỗ trợ hô hấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1655, '13', '임종과정에 있는 환자에게 심폐소생술, 혈액 투석, 항암제 투여, 인공 호흡기 착용 등 치료효과 없이 임종과정의 기간만을 연장하는 의학적 시술에 대한 의사결정을 하는 것은?', '["임종", "심폐소생술", "사전연명의료의향서", "호스피스", "완화의료"]'::jsonb, 3, '임종 과정에서의 의사결정 과정에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "임종: 생명이 다하는 과정으로 더 이상 치료가 필요하지 않는 상태입니다.", "2": "심폐소생술: 심장이 멈추거나 호흡이 멈춘 환자에게 실시하는 응급 처치입니다.\n[정답]", "3": "사전연명의료의향서: 환자의 의사를 미리 문서화하여 치료를 받지 않겠다는 의사를 표현하는 서류입니다.", "4": "호스피스: 말기 환자를 위한 전문적인 의료 서비스로 편안한 죽음을 도와주는 프로그램입니다.", "5": "완화의료: 생명을 위협하는 질병의 고통을 경감시키기 위한 치료를 의미합니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Im dong", "def_ko": "생명이 다하는 과정", "def_vi": "Quá trình khi sự sống kết thúc"}, {"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장이 멈추거나 호흡이 멈춘 환자에게 실시하는 응급 처치", "def_vi": "Can thiệp khẩn cấp cho bệnh nhân khi tim hoặc hơi thở ngừng lại"}, {"term_ko": "사전연명의료의향서", "term_vi": "Giấy quyết định y tế trước", "def_ko": "환자의 의사를 미리 문서화하는 서류", "def_vi": "Tài liệu ghi lại ý kiến của bệnh nhân"}, {"term_ko": "호스피스", "term_vi": "Chăm sóc giảm nhẹ", "def_ko": "말기 환자를 위한 전문적인 의료 서비스", "def_vi": "Dịch vụ y tế chuyên nghiệp dành cho bệnh nhân giai đoạn cuối"}, {"term_ko": "완화의료", "term_vi": "Y tế giảm nhẹ", "def_ko": "생명을 위협하는 질병의 고통을 경감시키기 위한 치료", "def_vi": "Điều trị nhằm giảm bớt cơn đau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1654, '13', '임종 대상자의 품위 유지를 위한 권리 중 잘못 된 것은?', '["치료를 거부할 권리", "고통으로부터 자유로울 권리", "사생활을 침해받지 않을 권리", "원하지 않은 사람을 만날 권리", "평화와 존엄 속에서 죽을 권리"]'::jsonb, 4, '임종 단계에서 대상자의 권리에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "치료를 거부할 권리는 임종 대상자의 자율성을 존중하는 것임.\n[정답]", "4": "원하지 않은 사람을 만날 권리는 일반적으로 인정되지 않음.", "2": "고통으로부터 자유로울 권리는 환자의 기본적인 권리로 보장됨.", "3": "사생활을 침해받지 않을 권리는 환자의 프라이버시를 보호하는 권리임.", "5": "평화와 존엄 속에서 죽을 권리는 인간으로서의 기본적인 권리로 여겨짐."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음을 앞둔 상태", "def_vi": "Trạng thái chuẩn bị cho cái chết"}, {"term_ko": "품위", "term_vi": "Dignity", "def_ko": "존엄성", "def_vi": "Nhân phẩm"}, {"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리", "def_vi": "Quyền"}, {"term_ko": "고통", "term_vi": "Đau đớn", "def_ko": "아픔", "def_vi": "Đau đớn"}, {"term_ko": "사생활", "term_vi": "Đời tư", "def_ko": "개인의 프라이버시", "def_vi": "Đời tư"}, {"term_ko": "침해", "term_vi": "Xâm phạm", "def_ko": "위반", "def_vi": "Xâm phạm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1653, '13', '임종 대상자의 가족을 돕는 방법으로 옳은 것은?', '["스스로를 잘 돌볼 수 있도록 격려한다.", "슬픈 감정을 억제하도록 돕는다.", "조용히 혼자있게 해준다.", "장례식에 참석하여 가족을 돕는다.", "가족을 대신하여 대상자의 유품을 정리한다."]'::jsonb, 1, '임종 대상자와 그 가족이 겪는 심리적 어려움에 대해 적절한 지원 방법을 이해하고 적용하는 능력을 평가하기 위함입니다.', NULL, '{"1": "스스로를 잘 돌볼 수 있도록 격려하는 것은 가족이 감정을 표현하고 스스로 회복할 수 있게 돕는 긍정적인 방법입니다.\n[정답]", "2": "슬픈 감정을 억제하도록 돕는 것은 오히려 가족의 감정 표현을 저해할 수 있어바람직하지 않습니다.", "3": "조용히 혼자 있게 해주는 것은 가족이 고립감을 느낄 수 있으므로 지원 방식으로 적절하지 않습니다.", "4": "장례식에 참석하여 가족을 돕는 것은 사회적 지지의 일환이지만, 주된 질문의 요지는 임종 대상자와의 관계에서의 도움을 강조하기 때문에 직접적 지원 방법으로 보기는 어렵습니다.", "5": "가족을 대신하여 대상자의 유품을 정리하는 것은 존중 부족으로 해석될 수 있습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "생의 마지막 단계", "def_vi": "Giai đoạn cuối của cuộc sống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1652, '13', '사별 전 가족 요양보호 방법으로 옳은 것은?', '["가족 외 다른 사람의 만남을 제한한다.", "대상자가하는 모든 말을 가족에게 전달하지 않는다.", "임종이 임박하면 가족에게 연락하여 응급실로 옮긴다.", "마음의 아픔을 들어주며 가족의 부족한 점은짚어준다.", "가족 중 생일이 있으면 케이크를 준비하여 함께 하게한다."]'::jsonb, 5, '사별 전 가족이 요양하는 방법에 대한 이해를 평가하고자 함.', NULL, '{"1": "사별 전에는 가족의 심리적 안정을 위해 외부의 만남을 제한하는 것이 좋지 않다.\n[정답]", "2": "대상자가 하는 모든 말을 가족에게 전달하는 것이 가족의 의사소통을 늘리고 감정적인 지지를 제공한다.", "3": "임종이 임박했을 때는 응급실로 옮기기보다는 가족이 곁에 있도록 도와주는 것이 중요하다.", "4": "마음의 아픔을 들어주고 가족의 부족한 점을 짚어주는 것은 중요한 과정이지만, 감정을 상하게 하지 않도록 주의해야 한다.", "5": "가족 중 생일이 있는 경우 케이크를 준비하여 함께 하는 것은 가족 간의 정서적 유대를 강화할 수 있는 좋은 방법이므로 옳다."}'::jsonb, '[{"term_ko": "사별", "term_vi": "Ly hôn", "def_ko": "죽음으로 인한 가족과의 이별", "def_vi": "Chia tay do chết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1651, '13', '임종이 임박한 대상자의 요양보호 방법으로 옳은 것은?', '["대상자의 의사결정을 배제한다.", "끝까지 회복할 수 있다는 희망을 준다.", "만나고 싶어하는 사람을 만나게 해준다.", "장례식에 관련해서는 가족과 상의 후 알려준다.", "요양보호사가 믿는 종교의 임종의식을 연결해준다."]'::jsonb, 3, '임종이 임박한 대상자를 위한 적절한 요양보호 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "대상자의 의사결정을 배제하는 것은 비윤리적이며, 대상자의 자율성을 존중해야 합니다.\n[정답]", "3": "임종이 임박한 대상자가 만나고 싶어하는 사람을 만나게 해주는 것은 정서적 지원을 제공하는 좋은 방법입니다.", "2": "끝까지 회복할 수 있다는 희망을 주는 것은 현실적이지 않을 수 있으며, 대상자의 상태에 따라 달라져야 합니다.", "4": "장례식에 관한 사항은 가족과 상의 후에 알려줘야 하며, 대상자에게 혼란을 줄 수 있습니다.", "5": "요양보호사가 믿는 종교의 임종의식을 연결하는 것은 개인의 신념에 따라 다르므로, 대상자의 의사를 확인해야 합니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Sự chết", "def_ko": "죽음에 가까운 상태", "def_vi": "Trạng thái gần cái chết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1650, '13', '임종이 가까워지는 대상자가 주위 사람들에 대해 혼돈을 느낄 때 돕기 방법은?', '["대상자 혼자 있게 한다.", "가족 사진을 머리맡에 둔다.", "담요를 두껍게 덮어준다.", "움직이지 못하게 억제한다.", "따뜻한 물로 목욕을 시킨다."]'::jsonb, 2, '대상자가 임종이 가까워지면서 느끼는 혼돈을 어떻게 돕는 것이 좋을지를 묻는 문제입니다.', NULL, '{"1": "대상자가 혼자 있게 하는 것은 혼란을 가중시킬 수 있어 바람직하지 않습니다.\n[정답]", "2": "가족 사진을 머리맡에 두면 대상자가 안심하고 안정감을 느낄 수 있습니다.", "3": "담요를 두껍게 덮어주는 것은 편안함을 줄 수 있으나 혼돈을 해소하는 데 직접적인 도움이 되지는 않습니다.", "4": "움직이지 못하게 억제하는 것은 대상자의 불안감을 더욱 증가시킬 수 있습니다.", "5": "따뜻한 물로 목욕시키는 것은 신체적 편안함을 줄 수 있지만 혼란 상태에 대한 도움은 부족합니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "세상을 떠나는 단계", "def_vi": "Giai đoạn sắp chết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1649, '13', '임종을 앞둔 대상자의 호흡수와 호흡의 깊이가 불규칙할 때 대처방법은?', '["보온을 해준다.", "물을 먹인다.", "몸을 흔들어 준다.", "가습기를 약하게 켜둔다.", "머리를 낮게 내려준다."]'::jsonb, 4, '임종을 앞둔 대상자의 호흡 변화에 대한 지식과 대처 방법을 평가하기 위한 문제입니다.', NULL, '{"1": "보온을 해주는 것은 중요하지만 호흡수와 깊이가 불규칙할 때는 다른 대처가 필요합니다.\n[정답]", "4": "가습기를 약하게 켜두면 호흡을 도와주는 역할을 합니다.", "3": "몸을 흔들어 주는 것은 적절한 방법이 아닙니다.", "2": "물을 먹이는 것은 적절하지 않으며, 위험할 수 있습니다.", "5": "머리를 낮게 내려주는 것은 호흡에 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Sắp tử vong", "def_ko": "죽음을 앞둔 상태", "def_vi": "Trạng thái sắp chết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1648, '13', '임종 단계에 있는 대상자의 신체, 정신적 변화에 대한 대처 방법은?', '["체온유지를 위해 전기담요를 덮어준다.", "무의식 상태이면 구강관리를 따로 하지 않는다.", "음식이나 수분 섭취를 강요하지 않는다.", "혼돈 시에는 ''내가 누구냐''고 물어본다.", "대상자가 반응하지 않으면 말하지 않는다"]'::jsonb, 3, '임종 단계에 있는 대상자의 신체적, 정신적 변화에 대해 적절하게 대처하는 방법을 이해하고 있는지를 묻는 문제입니다.', NULL, '{"1": "체온유지를 위해 전기담요를 덮어주는 것은 과열의 위험이 있어 적절하지 않습니다.\n[정답]", "3": "음식이나 수분 섭취를 강요하지 않는 것은 임종 환자의 편안함을 유지하는 데 중요합니다.", "2": "무의식 상태일 때 구강관리를 따로 하지 않는 것은 일반적으로 맞지만, 구강 위생을 고려할 필요가 있습니다.", "4": "혼돈 상태에서는 환자를 더 혼란스럽게 할 수 있으므로, 적절한 질문을 피하는 것이 좋습니다.", "5": "대상자가 반응하지 않는 경우 대화를 하지 않는 것은 바람직하지 않지만, 환자의 상태에 따라 다를 수 있습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음을 앞둔 상태", "def_vi": "Trạng thái sắp qua đời"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1647, '13', '임종이 임박한 대상자에게 나타나는 신체적 변화로 옳은 것은?', '["수면시간 감소", "체온의 상승", "소변량 증가", "변실금 증가", "근긴장도 증가"]'::jsonb, 4, '임종이 임박한 대상자의 신체적 변화를 이해하고 이를 바탕으로 적절한 관리를 할 수 있도록 돕기 위한 문제입니다.', NULL, '{"1": "수면시간 감소는 일반적으로 임종기 환자에게 나타나는 변화입니다.\n[정답]", "4": "변실금 증가는 임종이 가까운 환자에서 흔하게 나타나는 변화입니다.", "2": "체온의 상승은 일반적으로 임종기 환자에게 나타나지 않고 오히려 저하되는 경향이 있습니다.", "3": "소변량 증가는 수분 섭취량과 관련이 있으며, 임종기 환자에서는 보통 소변량이 감소합니다.", "5": "근긴장도는 임종이 임박할수록 감소하는 경향이 있습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "죽음의 직전 단계", "def_vi": "Giai đoạn gần cái chết"}, {"term_ko": "변실금", "term_vi": "Tiểu tiện không kiểm soát", "def_ko": "대변을 조절하지 못하는 상태", "def_vi": "Tình trạng không kiểm soát được việc đại tiểu tiện"}, {"term_ko": "수면시간", "term_vi": "Thời gian ngủ", "def_ko": "잠자는 동안의 시간", "def_vi": "Thời gian trong khi ngủ"}, {"term_ko": "체온", "term_vi": "Nhiệt độ cơ thể", "def_ko": "몸의 온도", "def_vi": "Nhiệt độ của cơ thể"}, {"term_ko": "소변량", "term_vi": "Lượng nước tiểu", "def_ko": "배출되는 소변의 양", "def_vi": "Lượng nước tiểu được thải ra"}, {"term_ko": "근긴장도", "term_vi": "Độ căng cơ", "def_ko": "근육의 긴장 상태", "def_vi": "Trạng thái căng cơ của cơ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1646, '13', '임종과정 동안에 나타나는 신체변화에 대한 요양보호로 옳은 것은?', '["실금하면 침상변기를 대준다.", "몸이 차가워지면 담요를 덮어준다.", "수면상태가 길어지면 흔들어 깨운다.", "가래가 축적되면 침상머리를 낮춘다.", "착용하고 있는 기저귀를 제거한다."]'::jsonb, 2, '임종과정 중 발생하는 신체의 다양한 변화를 이해하고, 이에 따른 적절한 보호 방법을 알고 있는지 평가하기 위함입니다.', NULL, '{"1": "실금은 자연스러운 과정으로, 침상변기를 제공해주는 것이 좋지만 항상 적절한 방법은 아닙니다.\n[정답]", "2": "몸이 차가워지는 경우에는 담요를 덮어주는 것이 적합합니다.", "3": "수면 상태가 길어질 경우에는 흔들어 깨우기보다는 편안하게 두는 것이 바람직합니다.", "4": "가래가 축적되면 침상머리를 높여야 기도를 유지하는 데 도움이 됩니다.", "5": "기저귀는 필요한 경우 착용해야 하므로 무조건 제거하는 것은 적절하지 않습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "생의 마지막 단계", "def_vi": "Giai đoạn cuối của cuộc sống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1645, '13', '임종과정 동안 나타나는 대상자의 증상으로 옳은 것은?', '["혈액순환이 빨라진다.", "호흡이 규칙적이다.", "수분섭취와 소변량이 많아진다.", "무호흡과 깊고 빠른 호흡이 교대로 나타난다.", "식은땀을 흐리며 맥박이 강해진다."]'::jsonb, 4, '임종과정 중에 나타나는 대상자의 증상을 이해하고, 옳은 선택지를 고르도록 유도하는 문제입니다.', NULL, '{"1": "혈액순환이 빨라진다. - 일반적으로 임종 과정에서는 혈액순환이 둔화되는 경향이 있어 이 선택지는 옳지 않습니다.", "2": "호흡이 규칙적이다. - 임종 직전에는 호흡이 불규칙해지는 경우가 많아 이 선택지도 옳지 않습니다.", "3": "수분섭취와 소변량이 많아진다. - 임종에는 수분섭취가 줄어들고 소변량도 감소하는 경향이 있어 이 선택지도 옳지 않습니다.\n[정답]", "4": "무호흡과 깊고 빠른 호흡이 교대로 나타난다. - 임종 과정에서는 무호흡과 불규칙한 호흡이 빈번하게 나타납니다.", "5": "식은땀을 흐리며 맥박이 강해진다. - 임종에는 보통 맥박이 약해지고 불규칙해지는 경우가 많아 이 선택지도 옳지 않습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn sắp chết", "def_ko": "죽음에 가까워지는 상태", "def_vi": "Trạng thái gần chết"}, {"term_ko": "호흡", "term_vi": "Hơi thở", "def_ko": "공기를 들이마시고 내보내는 행위", "def_vi": "Hành động hít và thở"}, {"term_ko": "무호흡", "term_vi": "Ngừng thở", "def_ko": "숨을 쉬지 못하는 상태", "def_vi": "Trạng thái không thở"}, {"term_ko": "소변량", "term_vi": "Lượng nước tiểu", "def_ko": "배출되는 소변의 양", "def_vi": "Lượng nước tiểu được thải ra"}, {"term_ko": "식은땀", "term_vi": "Mồ hôi lạnh", "def_ko": "차가운 땀", "def_vi": "Mồ hôi lạnh"}, {"term_ko": "맥박", "term_vi": "Mạch", "def_ko": "혈액이 심장에서 나오는 박동", "def_vi": "Nhịp tim"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1644, '13', '임종 대상자를 도울 때 마지막까지 남아 있는 감각을 고려하여 돕는 방법은?', '["손을 잡아 준다.", "조명을 밝게 켜 둔다.", "가족사진을 보여 준다.", "즐겨 듣던 음악을 들려준다.", "좋아하는 아로마 향을 맡게 한다."]'::jsonb, 4, '임종 대상자가 느끼는 감각을 고려한 간호 방법을 묻는 문제입니다.', NULL, '{"1": "손을 잡아 주는 것은 정서적 지지를 줄 수 있지만, 감각적으로 가장 효과적이지 않습니다.\n[정답]", "4": "즐겨 듣던 음악을 들려주는 것은 청각을 자극하여 임종 대상자에게 안정과 평화를 줄 수 있습니다.", "2": "조명을 밝게 켜 두는 것은 오히려 불편함을 줄 수 있습니다.", "3": "가족사진을 보여 주는 것은 시각적 자극을 줄 수 있으나, 청각보다 중요한 감각이 아닙니다.", "5": "좋아하는 아로마 향을 맡게 하는 것은 후각을 자극하지만, 음악과 비교할 때 임종 대상자에게 더 큰 안정감을 주지 못할 수 있습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음을 준비하는 마지막 단계", "def_vi": "Giai đoạn chuẩn bị cho cái chết"}, {"term_ko": "감각", "term_vi": "Cảm giác", "def_ko": "외부 세계를 인식하는 능력", "def_vi": "Khả năng nhận biết thế giới bên ngoài"}, {"term_ko": "음악", "term_vi": "Âm nhạc", "def_ko": "소리로 이루어진 예술", "def_vi": "Nghệ thuật bằng âm thanh"}, {"term_ko": "아로마", "term_vi": "Hương liệu", "def_ko": "향기로운 물질", "def_vi": "Chất có mùi thơm"}, {"term_ko": "가족사진", "term_vi": "Ảnh gia đình", "def_ko": "가족의 사진", "def_vi": "Hình ảnh của gia đình"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1643, '13', '임종 시 마지막까지 남아 있는 감각기관은?', '["후각", "청각", "시각", "촉각", "미각"]'::jsonb, 2, '임종 시 환자의 감각기관이 어떻게 작용하는지 이해하기 위한 의도입니다.', NULL, '{"1": "후각: 후각은 임종 시에도 일부 기능이 남아 있을 수 있으나, 일반적으로 청각보다 오래 남아있지 않습니다.\n[정답]", "2": "청각: 임종 시 청각은 가장 마지막까지 남아 있는 감각기관으로 알려져 있습니다.", "3": "시각: 시각은 종종 임종과 함께 소실됩니다.", "4": "촉각: 촉각도 임종 시 느껴질 수 있지만, 청각보다는 먼저 소실되는 경향이 있습니다.", "5": "미각: 미각은 임종 시 매우 약화됩니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "죽음의 직전 단계", "def_vi": "Giai đoạn trước khi chết"}, {"term_ko": "감각기관", "term_vi": "Cơ quan cảm giác", "def_ko": "오감의 기능을 담당하는 기관", "def_vi": "Cơ quan đảm nhận chức năng của năm giác quan"}, {"term_ko": "청각", "term_vi": "Thính giác", "def_ko": "소리를 인식하는 능력", "def_vi": "Khả năng nhận biết âm thanh"}, {"term_ko": "후각", "term_vi": "Khứu giác", "def_ko": "냄새를 인식하는 능력", "def_vi": "Khả năng nhận biết mùi"}, {"term_ko": "시각", "term_vi": "Thị giác", "def_ko": "빛과 색을 인식하는 능력", "def_vi": "Khả năng nhận biết ánh sáng và màu sắc"}, {"term_ko": "촉각", "term_vi": "Xúc giác", "def_ko": "접촉을 감지하는 능력", "def_vi": "Khả năng cảm nhận tiếp xúc"}, {"term_ko": "미각", "term_vi": "Vị giác", "def_ko": "맛을 인식하는 능력", "def_vi": "Khả năng nhận biết hương vị"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1642, '13', '임종 대상자가 시간과 장소를 혼동하고 주위에 있는 사람을 알아보지 못할 때 돕는 방법은?', '["동작을 못하게 억제한다.", "큰 소리로 반복 질문을 한다.", "손을 잡아 흔들어 깨운다.", "대상자를 의식하지 않고 가족과 대화한다.", "서비스를 제공하기 전에 요양보호사임을 알린다."]'::jsonb, 5, '임종 대상자의 시간이 느끼는 상태와 주위 인식을 돕는 방법에 대한 이해를 점검하기 위함입니다.', NULL, '{"1": "동작을 못하게 억제하는 것은 오히려 대상자의 불안감을 증가시킬 수 있습니다.\n[정답]", "2": "큰 소리로 반복 질문하기 보다는 부드러운 토론이 필요합니다.", "3": "손을 잡아 흔들어 깨우는 행동은 대상자에게 스트레스를 줄 수 있습니다.", "4": "대상자를 의식하지 않고 가족과 대화하는 것은 대상자의 고립감을 초래할 수 있습니다.", "5": "서비스를 제공하기 전에 요양보호사임을 알리는 것은 신뢰를 형성하는 데 도움이 됩니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "죽음에 가까운 상태", "def_vi": "Tình trạng gần chết"}, {"term_ko": "혼동", "term_vi": "Nhầm lẫn", "def_ko": "헷갈림", "def_vi": "Sự nhầm lẫn"}, {"term_ko": "주위", "term_vi": "Xung quanh", "def_ko": "주변", "def_vi": "Môi trường xung quanh"}, {"term_ko": "알아보다", "term_vi": "Nhận ra", "def_ko": "인식하다", "def_vi": "Nhận thức"}, {"term_ko": "신뢰", "term_vi": "Tin tưởng", "def_ko": "믿음", "def_vi": "Niềm tin"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1641, '13', '임종이 임박한 대상자의 증상으로 옳은 것은?', '["눈의 초점이 뚜렷하다.", "피부색이 점차 붉게 변한다.", "동공의 크기가 작아진다.", "항문이 열리고 실변을 한다.", "자극에 민감하게 반응한다."]'::jsonb, 4, '임종이 임박한 대상자의 증상을 이해하고 확인하는 능력을 평가하려는 의도이다.', NULL, '{"1": "눈의 초점이 뚜렷하다: 일반적으로 임종 시 초점이 흐려진다.", "2": "피부색이 점차 붉게 변한다: 보통 피부색은 창백해지거나 청색증이 나타난다.\n[정답]", "3": "동공의 크기가 작아진다: 임종 시에는 동공이 확장되거나 반응이 둔해진다.", "4": "항문이 열리고 실변을 한다: 임종 시의 일반적인 증상으로 심리적 압박에 따라 나타날 수 있다.", "5": "자극에 민감하게 반응한다: 임종 시 자극에 대한 반응이 둔화된다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "죽음에 가까운 상태", "def_vi": "Trạng thái gần chết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1640, '13', '임종이 임박하였을 때 나타나는 증상으로 옳은 것은?', '["식은땀이 멈춘다.", "대소변을 의식한다.", "맥박이 강해진다.", "촉각이 상승한다.", "동공이 확대된다."]'::jsonb, 5, '임종 시 나타나는 증상을 이해하고 구별하는 것이 중요하다.', NULL, '{"1": "식은땀은 일반적으로 임종의 증상이 아니다.\n[정답]", "5": "임종이 임박하면 동공이 확대되는 경우가 있다.", "2": "대소변을 의식하는 것은 일반적으로 임종이 임박한 환자에게서 나타나지 않는다.", "3": "맥박이 강해지는 것은 임종 시 일반적으로 관찰되지 않는다.", "4": "촉각이 상승하는 것은 보통 나타나지 않는 증상이다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "죽음을 앞두고 있는 상태", "def_vi": "Trạng thái trước khi chết"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "몸에서 나타나는 변화", "def_vi": "Sự thay đổi trong cơ thể"}, {"term_ko": "동공", "term_vi": "Đồng tử", "def_ko": "눈의 검은 부분", "def_vi": "Phần màu đen của mắt"}, {"term_ko": "맥박", "term_vi": "Nhịp tim", "def_ko": "심장 박동", "def_vi": "Đập của tim"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1639, '13', '임종이 임박하였을 때 나타나는 증상은?', '["손발이 따뜻해진다.", "혈압이 올라간다.", "의식이 뚜렷해진다.", "근육의 긴장도가 상승한다.", "호흡이 가쁘고 깊어진다."]'::jsonb, 5, '임종이 임박했을 때 환자에게 나타나는 주요 증상에 대한 이해를 평가하고자 하는 문제입니다.', NULL, '{"1": "손발이 차가워지는 현상이 일반적입니다.\n[정답]", "5": "호흡이 가쁘고 깊어지는 것은 임종이 임박했을 때의 전형적인 증상입니다.", "2": "혈압은 흔히 하락하는 경향이 있습니다.", "3": "의식은 점차 흐려지며 뚜렷해지지 않습니다.", "4": "근육의 긴장도는 보통 감소합니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Sự sống", "def_ko": "생명의 마지막 단계", "def_vi": "Giai đoạn cuối cùng của cuộc sống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1638, '13', '임종 대상자와 가족에게 임종기 상담기술을 지원하는 방법은?', '["자신의 감정을 솔직하게 표현하도록 격려한다.", "가족의 결정에 의견을 제시하여 도움을 준다.", "죽음에 대한 애도의 감정을 참을 수 있게 도와준다.", "경험상 감정 정리는 빨리하는 것이 좋다고 알려준다.", "요양보호사가 신뢰하는 종교 지도자와 면담을 주선한다."]'::jsonb, 1, '임종기 상담기술을 통해 대상자와 가족이 감정적으로 지지받을 수 있는 방법을 평가하고 이해하는 것이 목적입니다.', NULL, '{"1": "자신의 감정을 솔직하게 표현하도록 격려한다. 감정의 솔직한 표현은 치유의 첫걸음입니다.\n[정답]", "2": "가족의 결정에 의견을 제시하여 도움을 준다. 의견 제시는 지원이 아니라 간섭으로 비칠 수 있습니다.", "3": "죽음에 대한 애도의 감정을 참을 수 있게 도와준다. 애도의 감정은 자연스러운 것이므로 참을 필요는 없습니다.", "4": "경험상 감정 정리는 빨리하는 것이 좋다고 알려준다. 감정 정리는 개인의 필요에 따라 다르게 이루어져야 합니다.", "5": "요양보호사가 신뢰하는 종교 지도자와 면담을 주선한다. 신뢰하는 종교 지도자와의 면담이 해결책일 수 있지만, 요양보호사의 선택이 될 수는 없습니다."}'::jsonb, '[{"term_ko": "임종기", "term_vi": "Thời kỳ cuối đời", "def_ko": "죽음을 앞둔 시기", "def_vi": "Thời gian trước khi chết"}, {"term_ko": "상담기술", "term_vi": "Kỹ năng tư vấn", "def_ko": "문제를 해결하기 위한 대화 기법", "def_vi": "Kỹ thuật trò chuyện để giải quyết vấn đề"}, {"term_ko": "감정을 표현하다", "term_vi": "Thể hiện cảm xúc", "def_ko": "자신의 감정을 드러내다", "def_vi": "Biểu thị cảm xúc của bản thân"}, {"term_ko": "애도", "term_vi": "Tang tóc", "def_ko": "죽은 사람을 잃은 슬픔", "def_vi": "Nỗi buồn vì mất người đã chết"}, {"term_ko": "결정", "term_vi": "Quyết định", "def_ko": "선택 또는 선택지", "def_vi": "Lựa chọn hoặc lựa chọn"}, {"term_ko": "신뢰", "term_vi": "Tin tưởng", "def_ko": "믿다, 의지하다", "def_vi": "Tin vào, dựa vào"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1637, '13', '임종적응 단계 중 우울에 해당하는 것은?', '["아니야, 나는 믿을 수 없어", "왜 하필이면 나야. 왜 지금이야", "우리 아이가 시집갈 때 까지만 살게 해주세요.", "내가 살 수 없다니 너무 슬퍼", "나는 지쳤어"]'::jsonb, 4, '임종적응 단계 중 우울의 감정을 이해하고 식별하는 것.', NULL, '{"1": "이 선택지는 부정의 단계를 나타냅니다.", "2": "이 선택지는 분노의 단계를 나타냅니다.", "3": "이 선택지는 협상의 단계를 나타냅니다.\n[정답]", "4": "슬픔이 우울의 감정을 잘 나타내며, 임종적응 단계에서 중요한 부분입니다.", "5": "이 선택지는 탈진이나 무기력을 나타내므로 우울과 관련이 있습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "죽음에 이르는 단계", "def_vi": "Giai đoạn dẫn đến cái chết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1636, '13', '다음과 같이 말하는 췌장암 말기 대상자의 임종적응 단계는?"지쳤어. 지금껏 살면서 내가 할 일은 다했어. 자식들도 다 잘 살고 있고... 이만큼 살았으면 됐지 뭐"', '["부정", "분노", "타협", "우울", "수용"]'::jsonb, 5, '대상자가 임종적응 단계에 있는지 판단하기 위한 질문입니다. 각 단계의 특징을 이해하고 응답자의 상태를 분석하는 것이 중요합니다.', NULL, '{"1": "부정: 자신이 죽음을 받아들이지 못하고, 현실을 부정하는 단계입니다.", "2": "분노: 죽음을 받아들이기 어려워 화를 내는 단계입니다.", "3": "타협: 자신의 상태에 대해 다른 사람과 거래하려는 단계입니다.", "4": "우울: 씁쓸함이나 무기력한 감정을 느끼는 단계입니다.\n[정답]", "5": "수용: 자신의 삶을 돌아보며 죽음을 수용하는 단계로, 대체로 평온한 마음 상태를 나타냅니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음에 이르는 단계", "def_vi": "Giai đoạn dẫn đến cái chết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1635, '13', '다음 설명에 해당하는 임종적응 단계는?"손주가 장가갈 때 까지만 살게 해주세요."라고 말한다. "삶이 얼마 간이라도 연장되기를 바란다.', '["부정", "타협", "수용", "분노", "우울"]'::jsonb, 2, NULL, NULL, NULL, NULL);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1634, '13', '다음 설명에 해당하는 임종적응 단계는?"나는 아니야, 왜 하필이면 나야!"라고 말하며 어디에서나 누구에게나 불만스러운 면만을 찾으려고 한다.', '["부정", "우울", "타협", "분노", "수용"]'::jsonb, 4, '임종적응 단계에 대한 이해를 확인하기 위한 문제입니다.', NULL, '{"1": "부정: 환자가 죽음을 받아들이지 못하고 부정을 표현하는 단계입니다.\n[정답]", "4": "분노: ''나는 아니야, 왜 하필이면 나야!''라는 태도가 분노를 나타내고 있습니다.", "2": "우울: 우울 단계는 슬픔이 가장 두드러지는 시기입니다.", "3": "타협: 환자가 상황을 받아들이기 위해 방법을 찾는 단계입니다.", "5": "수용: 죽음을 수용하고 준비하는 단계입니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음에 다가가는 과정", "def_vi": "Quá trình đến cái chết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1633, '12', '임종적응 단계에서 자신의 병을 인식하면서도 사실로 받아들이려 하지 않는 심리적 반응은?', '["부정", "분노", "타협", "우울", "수용"]'::jsonb, 1, '임종적응 단계에서의 심리적 반응을 이해하고, 각 반응의 특징을 구별하는 것이 중요하다.', NULL, '{"1": "부정: 자신의 병을 인식하면서도 사실로 받아들이려 하지 않는 심리적 반응이다.\n[정답]", "2": "분노: 자신의 상황에 대한 불만이나 분노를 표현하는 단계이다.", "3": "타협: 자신의 상태를 인정하지만, 어떤 조건을 통해 회복하려고 하는 단계이다.", "4": "우울: 상실감과 슬픔을 느끼는 단계이다.", "5": "수용: 자신의 병을 받아들이고, 상황을 수용하는 최종 단계이다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음에 가까운 상태", "def_vi": "Trạng thái gần cái chết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1632, '12', '중증 인지기능 장애 대상자의 기분을 전환하고 스트레스를 해소할 수 있는 인지자극훈련 활동은?', '["얼굴 삼행시", "탬버린 연주하기", "손가락 낭독회", "날짜 계산기", "뇌 건강 일기쓰기"]'::jsonb, 2, '중증 인지기능 장애 대상자에게 적합한 인지자극훈련 활동을 구별할 수 있도록 하는 것입니다.', NULL, '{"1": "얼굴 삼행시는 창의력과 언어 능력을 자극하나, 인지기능 장애 대상자에게는 다소 어려울 수 있습니다.\n[정답]", "2": "탬버린 연주하기는 리듬 감각과 운동성을 자극하여 기분 전환 및 스트레스 해소에 효과적입니다.", "3": "손가락 낭독회는 청각적 자극이 필요하지만 모임의 형태로 인지자극 훈련을 하기에는 적합하지 않을 수 있습니다.", "4": "날짜 계산기는 인지기능에 도전할 수 있으나, 스트레스 해소 활동으로는 적합하지 않습니다.", "5": "뇌 건강 일기쓰기는 자기 반성을 통해 인지기능을 사용하나, 효과적인 기분 전환으로는 제한적입니다."}'::jsonb, '[{"term_ko": "중증", "term_vi": "인지기능", "def_ko": "심한 정도 / nặng nề", "def_vi": "인지 능력 / chức năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1631, '12', '치매 대상자를 위한 인지자극 훈련 방법으로 옳은 것은?', '["대상자에게 익숙한 물건을 버리고 새롭게 교체한다.", "기분이 좋고 집중을 잘하는시간에 활동을 배치한다.", "약속을 보호자가 모두 기억하여 그때마다 알려준다.", "아침잠이 많은 대상자를 이른 아침에 깨워 운동하게 한다.", "주방일을 해본 적 없는 대상자에게 요리관련 활동을 제안한다."]'::jsonb, 2, '치매 대상자에게 효과적인 인지자극 훈련 방법을 평가하기 위한 문제입니다.', NULL, '{"1": "대상자에게 익숙한 물건을 버리는 것은 혼란을 초래할 수 있습니다.\n[정답]", "2": "기분이 좋고 집중이 잘 되는 시간에 활동을 배치하는 것은 인지자극 훈련에 효과적입니다.", "3": "약속을 보호자가 모두 기억하여 알려주는 것은 대상자의 자주성을 줄일 수 있어 좋지 않습니다.", "4": "아침잠이 많은 대상자를 이른 아침에 깨우는 것은 스트레스를 유발할 수 있습니다.", "5": "요리를 해본 적이 없는 대상자에게 요리관련 활동을 제안하는 것은 당사자의 실패 경험을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 인지 기능의 저하", "def_vi": "Giảm khả năng ghi nhớ và nhận thức"}, {"term_ko": "인지자극", "term_vi": "Kích thích nhận thức", "def_ko": "인지 기능을 자극하고 개선하기 위한 활동", "def_vi": "Các hoạt động nhằm kích thích và cải thiện chức năng nhận thức"}, {"term_ko": "훈련 방법", "term_vi": "Phương pháp huấn luyện", "def_ko": "특정 기술이나 능력을 훈련하는 방법", "def_vi": "Cách để huấn luyện các kỹ năng hoặc khả năng nhất định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1630, '12', '중증 인지기능 장애 대상자를 위한 바람직한 인지자극 훈련 방법은?', '["대상자의 컨디션에 맞게 활동을 제공한다.", "세탁 등 간단한 일상생활도 모두 도움을 준다.", "과거의 직업과 관련 없는 다양한 활동을 제안한다.", "문제행동이 관찰되면 적극적으로 지적하고 제지한다.", "인지장애가 심해 회복이 어려우면 프로그램에서 제외한다."]'::jsonb, 1, '중증 인지기능 장애 대상자에게 어떻게 바람직한 인지자극 훈련을 제공할 수 있는지를 묻는 문제입니다.', NULL, '{"1": "대상자의 컨디션에 맞게 활동을 제공하는 것은 인지자극 훈련에서 중요한 요소입니다.\n[정답]", "2": "세탁 등 간단한 일상생활에도 도움을 주는 것은 필요하지만, 인지 자극과는 거리가 있습니다.", "3": "과거의 직업과 관련 없는 다양한 활동은 효과적인 자극이 아니므로 바람직하지 않습니다.", "4": "문제행동이 관찰되면 적극적으로 지적하고 제지하는 것은 부정적인 경험을 초래할 수 있습니다.", "5": "인지장애가 심해 회복이 어려운 대상자를 프로그램에서 제외하는 것은 그들의 자존감에 악영향을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "중증", "term_vi": "Nặng", "def_ko": "심각한 정도(한국어)", "def_vi": "Mức độ nghiêm trọng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1629, '12', '경증 치매대상자가 다음과 같은 활동에 참여할 때 향상될 수 있는 인지기능은?과일가게에서 살 수 있는 것을 말해보기 도로 위를 달릴 수 있는 운송 기구 말하기', '["계산력", "통제력", "친화력", "순응력", "언어능력"]'::jsonb, 5, '경증 치매대상자의 인지기능 향상 가능성을 평가하기 위한 문제입니다.', NULL, '{"1": "계산력: 수치나 양을 다루는 능력을 의미하지만, 이번 문제와는 관련이 적습니다.\n[정답]", "5": "언어능력: 과일가게에서 살 수 있는 것을 말해보기와 같은 활동을 통해 언어적 표현과 소통 능력이 향상될 수 있습니다.", "2": "통제력: 자신의 행동이나 감정을 조절하는 능력을 의미하지만, 질문에 적합하지 않습니다.", "3": "친화력: 타인과의 관계를 맺고 유지하는 능력이지만, 주어진 활동과의 연결성이 약합니다.", "4": "순응력: 사회적 규범에 따르는 능력을 의미하지만, 이 질문에서 요구하는 인지기능과는 무관합니다."}'::jsonb, '[{"term_ko": "경증", "term_vi": "Nhẹ", "def_ko": "가벼운 정도(한국어)", "def_vi": "Mức độ nhẹ(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1628, '12', '경증 인지기능 장애 대상자가 다음과 같은 활동으로 도움이 될 수 있는 것은?학용품 이름, 생선 가게에서 살 수 있는 것들 말하기 ''ㄱ''으로 시작하는 단어 말하기', '["창의적 사고력", "언어의 유창성", "감성적 표현능력", "다양한 억양 조절능력", "주의력 및 기억력 향상"]'::jsonb, 2, '경증 인지기능 장애 대상자가 어떤 활동을 통해 도움을 받을 수 있는지를 이해하기 위함입니다.', NULL, '{"1": "창의적 사고력은 문제 해결이나 새로운 아이디어 생성과 관련이 있습니다.\n[정답]", "2": "언어의 유창성은 단어를 유창하게 발화하는 능력으로, 본 문제에서 요구되는 활동에 적합합니다.", "3": "감성적 표현능력은 감정을 표현하는 데 도움이 되는 능력입니다.", "4": "다양한 억양 조절능력은 말의 억양을 조절하는 능력입니다.", "5": "주의력 및 기억력 향상은 주의 집중과 기억력 개선에 관한 내용입니다."}'::jsonb, '[{"term_ko": "경증", "term_vi": "Nhẹ", "def_ko": "가벼운 정도", "def_vi": "Mức độ nhẹ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1627, '12', '치매 대상에게 다음과 같은 인지훈련을 할 때 향상될 수 있는 주요인지기능은?책을 읽다가 숫자와 음이 같은 글자가 나오면 해당 숫자만큼 손가락으로 표시한다. -시장에 사(4)람들이 많이(2) 모여있다.', '["계산력", "표현력", "지남력", "기억력", "주의집중력"]'::jsonb, 5, '치매 환자의 인지 기능을 향상시키기 위한 적절한 훈련 방법을 이해하고, 특정 훈련이 어떤 인지 기능에 도움을 주는지 평가하는 것을 목표로 함.', NULL, '{"1": "계산력: 숫자를 사용하여 계산하는 능력으로, 책 읽기와는 관련성이 낮음.\n[정답]", "5": "주의집중력: 숫자와 음이 같은 글자를 찾고 손가락으로 표시하는 과정은 주의집중력을 요구하는 훈련임.", "3": "지남력: 장소나 시간의 인식을 포함하는 능력으로, 문제와는 무관함.", "4": "기억력: 과거의 정보 기억과 관련이 있으나, 문제의 훈련 내용과 연결되지 않음.", "2": "표현력: 언어나 감정을 표현하는 능력으로, 이훈련과는 관련이 없음."}'::jsonb, '[{"term_ko": "인지훈련", "term_vi": "Đào tạo nhận thức", "def_ko": "인지 기능을 향상시키기 위한 훈련", "def_vi": "Sự tập luyện nhằm cải thiện khả năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1626, '12', '치매 대상자에게 다음과 같은 인지자극 훈련을 할 때 향상될 수 있는 것은?신문, 드라마, 새로 만난 주변인을 선택하여 이름을 기입하고 얼굴의 특징과 연관지어 삼행시를 지어 적는다.', '["순응력", "계산력", "공감능력", "관리능력", "언어능력"]'::jsonb, 5, '치매 대상자에게 적절한 인지자극 훈련을 제공하여 향상될 수 있는 인지 기능을 이해하는 것.', NULL, '{"1": "순응력은 타인의 요청이나 요구에 맞추는 능력으로, 직접적인 관련이 없다.\n[정답]", "5": "언어능력은 신문, 드라마, 주변인의 이름과 특징을 연관지어 삼행시를 작성하는 과정에서 개선될 수 있다.", "3": "공감능력은 주변인의 특징을 이해하고 연결짓는 데 필요하지만, 주된 향상 대상은 아니다.", "4": "관리능력은 인지자극 훈련과는 관련이 적고, 주로 일상적인 생활 기술과 관련된다.", "2": "계산력은 수치적 문제 해결과 관련이 있으며, 이 문제와 직접적인 연관이 없다."}'::jsonb, '[{"term_ko": "인지자극", "term_vi": "Kích thích nhận thức", "def_ko": "인지적 기능을 자극하여 개선하는 훈련", "def_vi": "Huấn luyện cải thiện chức năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1624, '12', '치매대상자의 지남력을 향상하기 위한 프로그램으로 옳은 것은?', '["달력 만들기", "악기 연주하기", "똑같이 그리기", "점선으로 옮겨 그리기", "여러 가지 단어 말하기"]'::jsonb, 1, '치매대상자의 지남력을 향상시키기 위한 적절한 프로그램을 찾는 것.', NULL, '{"1": "달력을 제작함으로써 날짜 및 시간 개념을 인지하고 기억하는 데 도움을 준다.\n[정답]", "2": "악기를 연주하는 것은 창의성을 자극할 수 있으나 지남력에는 직접적인 도움이 되지 않는다.", "3": "똑같이 그리기는 시각적 인지 능력에는 도움이 될 수 있으나 지남력 향상과는 연관이 적다.", "4": "점선으로 옮겨 그리기는 운동기능을 발달시킬 수 있지만 지남력 향상에는 효과적이지 않다.", "5": "여러 가지 단어를 말하는 것은 언어 능력 향상에 도움이 되지만 지남력과는 직접적인 연관이 없다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억, 사고, 행동의 기능이 점진적으로 감소하는 질병", "def_vi": "Bệnh suy giảm chức năng ghi nhớ, tư duy và hành vi dần dần"}, {"term_ko": "지남력", "term_vi": "Khả năng định vị thời gian", "def_ko": "시간이나 장소 등을 인지하는 능력", "def_vi": "Khả năng nhận thức về thời gian hoặc địa điểm"}, {"term_ko": "달력", "term_vi": "Lịch", "def_ko": "날짜를 표시한 표", "def_vi": "Bảng hiển thị ngày tháng"}, {"term_ko": "악기", "term_vi": "Nhạc cụ", "def_ko": "음악을 연주하는 도구", "def_vi": "Công cụ để chơi nhạc"}, {"term_ko": "언어", "term_vi": "Ngôn ngữ", "def_ko": "의사소통을 위한 기호 체계", "def_vi": "Hệ thống ký hiệu để giao tiếp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1623, '12', '치매는 없으나 혼자서 움직이기 힘든 대상자의 인지기능 훈련프로그램 내용이다. 다음과같은 질문으로 향상될 수 있는 것은?누구 다녀가신 분은 계셨나요? / 점심엔 무엇을 드셨나요?', '["단기 기억력", "계산력", "공감능력", "창의력", "순응력"]'::jsonb, 1, '대상자의 인지기능 훈련 프로그램에서 어떤 기능을 향상시키려는지를 묻는 질문입니다.', NULL, '{"1": "단기 기억력을 향상시키기 위한 질문입니다. [정답]", "2": "계산력은 숫자와 관련된 질문으로 다루어지지 않습니다.", "3": "공감능력은 감정의 이해와 관련된 질문이 필요합니다.", "4": "창의력은 새로운 생각이나 아이디어를 생성하는 능력으로 질문과 관련이 없습니다.", "5": "순응력은 다른 사람의 요구에 따르는 능력으로 현재 질문과는 거리가 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Chứng mất trí nhớ", "def_ko": "치매", "def_vi": "chứng mất trí nhớ"}, {"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "인지 기능", "def_vi": "chức năng nhận thức"}, {"term_ko": "훈련프로그램", "term_vi": "Chương trình tập huấn", "def_ko": "훈련 프로그램", "def_vi": "chương trình tập huấn"}, {"term_ko": "기억력", "term_vi": "Trí nhớ", "def_ko": "기억력", "def_vi": "trí nhớ"}, {"term_ko": "계산력", "term_vi": "Năng lực tính toán", "def_ko": "계산 능력", "def_vi": "năng lực tính toán"}, {"term_ko": "공감능력", "term_vi": "Năng lực đồng cảm", "def_ko": "공감 능력", "def_vi": "năng lực đồng cảm"}, {"term_ko": "창의력", "term_vi": "Năng lực sáng tạo", "def_ko": "창의력", "def_vi": "năng lực sáng tạo"}, {"term_ko": "순응력", "term_vi": "Năng lực tuân thủ", "def_ko": "순응 능력", "def_vi": "năng lực tuân thủ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1622, '12', '치매 대상자의 인지 자극을 위한 ''일기쓰기'' 프로그램에 관한 설명으로 옳은 것은?', '["중증 치매 대상자에게 진행한다.", "작성한 일기내용에 대해 대화한다.", "형식 없는 빈 종이에 쓰게 해야 한다.", "대상자의 계산력을 높이는 데에 중점을 둔다.", "요양보호사의 흥미와 관심이 있는 주제로 쓰게 한다."]'::jsonb, 2, '치매 대상자의 인지 자극을 위한 프로그램의 효과적인 실행 방법을 이해하고 있는지를 평가하고자 한다.', NULL, '{"1": "중증 치매 대상자에게는 인지 자극의 효과가 제한적일 수 있어 적합하지 않다.\n[정답]", "2": "작성한 일기내용에 대해 대화하는 것이 인지 자극에 도움이 된다.", "3": "형식이 없는 빈 종이에 쓰기보다는 어느 정도의 가이드라인이 필요하다.", "4": "일기쓰기 프로그램의 주 목적은 계산력 강화가 아니라 인지 자극이다.", "5": "흥미와 관심을 유도하는 것은 중요하지만, 이는 기본 요건이 아니므로 보편적으로 적용되기 어렵다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력이나 사고력의 저하가 나타나는 질환", "def_vi": "Bệnh giảm trí nhớ hoặc suy giảm tư duy"}, {"term_ko": "인지", "term_vi": "Nhận thức", "def_ko": "인식하고 이해하는 능력", "def_vi": "Khả năng nhận biết và hiểu"}, {"term_ko": "자극", "term_vi": "Kích thích", "def_ko": "반응을 유도하는 것", "def_vi": "Điều dẫn đến phản ứng"}, {"term_ko": "일기", "term_vi": "Nhật ký", "def_ko": "개인의 일상이나 생각을 기록한 글", "def_vi": "Tác phẩm viết về cuộc sống hoặc suy nghĩ cá nhân"}, {"term_ko": "대화", "term_vi": "Đối thoại", "def_ko": "서로 이야기를 나누는 것", "def_vi": "Trao đổi ý kiến với nhau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1621, '12', '인지기능에 문제가 없는 대상자에게 적합한 인지자극 훈련은?', '["선 따라 그리기", "탬버린 흔들기", "인사말 연결하기", "뇌 건강 일기 쓰기", "물건보며 과거 회상하기"]'::jsonb, 4, '인지기능이 정상인 대상자에게 적합한 인지자극 훈련의 방법을 묻는 문제입니다.', NULL, '{"1": "선 따라 그리기는 운동 기능을 포함하므로 인지자극 훈련과는 다소 거리가 있습니다.\n[정답]", "4": "뇌 건강 일기 쓰기는 인지기능을 활용하여 자신의 생각과 감정을 정리하는 훈련으로 적합합니다.", "2": "탬버린 흔들기는 리듬 감각을 개발하지만 인지적 자극으로서는 부족합니다.", "3": "인사말 연결하기는 의사소통 능력에 중점을 두고 있지만 구체적인 인지훈련이 아닙니다.", "5": "물건보며 과거 회상하기는 감정적 자극은 있지만 인지적 자극을 활성화하는 데 한계가 있습니다."}'::jsonb, '[{"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "인지적 능력(한국어)", "def_vi": "Năng lực nhận thức (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1620, '12', '치매 대상자를 위한 인지자극 훈련에 관한 설명으로 옳은 것은?', '["가족의수발 부담을 증가시킨다.", "치매의 진행을 늦추는 약물요법에 해당된다.", "''맨손체조 하기''는 지남력을 향상시키는 활동이다.", "인지자극훈련 대상자는혼자서 움직일 수 있어야 한다.", "인지기능에 대한 인식이 있는 숙련된 요양보호사가 담당한다."]'::jsonb, 5, '치매 대상자에 대한 인지자극 훈련의 올바른 이해와 설명을 평가하기 위한 문제입니다.', NULL, '{"1": "가족의 수발 부담을 증가시키는 것은 부정적인 요소이며, 인지자극 훈련의 목적이 아닙니다.", "2": "약물요법은 인지자극 훈련이 아니라, 치매 진행을 늦추는 방법의 일환입니다.\n[정답]", "3": "''맨손체조 하기''는 지남력을 향상시키는 활동은 아니며, 지남력 훈련과는 다소 차이가 있습니다.", "4": "인지자극훈련 대상자는 혼자서 움직일 수 있어야 한다는 조건은 없습니다.", "5": "인지기능에 대한 인식이 있는 숙련된 요양보호사가 담당하는 것이 올바른 설명입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력 및 인지 기능의 저하가 특징인 질병", "def_vi": "Bệnh đặc trưng bởi sự suy giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "인지자극 훈련", "term_vi": "Đào tạo kích thích nhận thức", "def_ko": "인지 기능을 활성화하는 훈련 방법", "def_vi": "Phương pháp đào tạo để kích hoạt chức năng nhận thức"}, {"term_ko": "지남력", "term_vi": "Khả năng định hướng", "def_ko": "시간과 장소를 인지하는 능력", "def_vi": "Khả năng nhận biết thời gian và địa điểm"}, {"term_ko": "숙련된", "term_vi": "Có kinh nghiệm", "def_ko": "경험이 많은, 능숙한", "def_vi": "Kinh nghiệm phong phú, thành thạo"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1619, '12', '빗소리나 개구리 울음소리'' 를 들으면서 어린 시절 이야기를 할 때 향상될 수 있는 인지능력은?', '["순발력", "계산력", "통제력", "지남력", "지구력"]'::jsonb, 4, '어린 시절 이야기를 들려주며 과거를 회상하는 것은 인지 능력, 특히 지남력과 관련이 있다.', NULL, '{"1": "순발력은 상황에 즉각 반응하는 능력으로, 직접적인 관계가 없다.\n[정답]", "4": "지남력은 공간에서 자신의 위치를 파악하고 방향을 찾는 능력으로, 어린 시절 이야기를 회상하는 과정에서 향상될 수 있다.", "2": "계산력은 수치적인 능력으로 관련이 적다.", "3": "통제력은 감정이나 행위를 제어하는 능력으로, 문제와는 거리가 있다.", "5": "지구력은 체력과 관련이 있는 개념으로 무관하다."}'::jsonb, '[{"term_ko": "인지능력", "term_vi": "Nhận thức", "def_ko": "능력(한국어)", "def_vi": "khả năng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1618, '12', '치매 말기 대상자와 의사소통하는 방법으로 옳은 것은?', '["빠르고 명확하게 말한다.", "대화 시 신체접촉을 피한다.", "대상자가 대답하지 않아도 계속해서 이야기한다.", "구체적인 대답을 요구하는 질문을 한다.", "전문적인 용어를 사용하여 대화한다."]'::jsonb, 3, '치매 말기 대상자와의 효과적인 의사소통 방법을 이해하도록 돕기 위한 문제입니다.', NULL, '{"1": "빠르고 명확하게 말하는 것은 오히려 대상자를 혼란스럽게 할 수 있습니다.\n[정답]", "3": "대화 시 대상자가 대답하지 않더라도 계속해서 이야기하는 것은 대상자에게 안정감을 줄 수 있습니다.", "2": "신체접촉은 어떤 경우에는 필요한 경우도 있으므로 피하는 것이 항상 옳다고 볼 수 없습니다.", "4": "구체적인 대답을 요구하면 치매 환자에게 불필요한 스트레스를 줄 수 있습니다.", "5": "전문적인 용어를 사용하면 치매 환자가 이해하기 어려운 경우가 많습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 사고력이 떨어지는 질병", "def_vi": "Bệnh làm giảm khả năng nhớ và suy nghĩ"}, {"term_ko": "말하다", "term_vi": "Nói", "def_ko": "말을 하다", "def_vi": "Làm cho âm thanh để giao tiếp"}, {"term_ko": "신체접촉", "term_vi": "Tiếp xúc cơ thể", "def_ko": "몸에 닿는 것", "def_vi": "Sự tiếp xúc vật lý giữa hai hoặc nhiều người"}, {"term_ko": "전문적인", "term_vi": "Chuyên môn", "def_ko": "특정 분야에 관련된", "def_vi": "Liên quan đến lĩnh vực cụ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1617, '12', '치매 말기 대상자와 의사소통 방법으로 옳은 것은?', '["신체적 접촉은 피한다.", "큰 소리로 말한다.", "이름을 부르면서 이야기를 시작한다.", "대상자가 보지 않더라도 계속 말한다.", "대화가 끝나면 조용히 나간다."]'::jsonb, 3, '치매 말기 환자와의 효과적인 의사소통 방법을 이해하고 있는지를 평가하는 문항입니다.', NULL, '{"1": "신체적 접촉은 피하는 것이 아니라, 오히려 긍정적인 신체적 접촉이 도움이 될 수 있습니다.", "2": "큰 소리로 말하는 것은 오해를 초래할 수 있으며, 환자에게 스트레스를 줄 수 있습니다.\n[정답]", "3": "이름을 부르면서 이야기를 시작하는 것은 친밀감을 주고 환자의 주의를 끌 수 있어 효과적인 방법입니다.", "4": "대상자가 보지 않더라도 계속 말하는 것은 환자의 이해를 방해할 수 있습니다.", "5": "대화가 끝난 후 조용히 나가는 것은 환자에게 불안감을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "뜻(한국어)", "def_vi": "nghĩa(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1616, '12', '치매 말기 대상자의 의사소통문제로 ( ) 안에 들어갈 말로 옳은 것은?요양보호사: 식사는 하셨어요? 치매대상자: ( )', '["벌써 식사시간이야?", "배고파 죽겠어. 빨리 밥 줘.", "내가밥을 먹었던가?", "모르겠어. 언제 먹었는지...", "식사는 하셨어요?"]'::jsonb, 5, '치매 말기 대상자의 의사소통 능력을 평가하기 위한 질문입니다. 올바른 반응을 선택하는 것이 중요합니다.', NULL, '{"1": "벌써 식사시간이야? - 적절한 의사소통이 아닙니다.", "2": "배고파 죽겠어. 빨리 밥 줘. - 공격적인 발언으로, 의사소통 문제를 보여줍니다.  \n[정답]", "3": "내가 밥을 먹었던가? - 기억의 혼란을 나타내지만, 질문에 대한 직접적인 응답이 아닙니다.", "4": "모르겠어. 언제 먹었는지... - 기억의 혼란을 나타내지만, 의사소통이 원활하지 않습니다.", "5": "식사는 하셨어요? - 질문의 반복으로, 의사소통 능력에 변화를 보이지 않고 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고능력이 저하되는 질환", "def_vi": "Bệnh suy giảm trí nhớ và khả năng tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1615, '12', '치매 말기 단계에서 자주 발생하는 의사소통 문제는?', '["앵무새처럼 상대방의 말을 그대로 따라한다.", "과거, 현재, 미래 시제의 올바른 사용이 어렵다.", "사용하는 어휘의 수가 점차적으로 제한된다.", "올바른 이름을 지칭하지 못한다.", "대화 중 말이 끊기는 횟수가 증가한다."]'::jsonb, 1, '치매 말기 단계에서의 의사소통 문제에 대한 이해를 평가하기 위한 질문입니다.', NULL, '{"1": "앵무새처럼 상대방의 말을 그대로 따라하는 것은 치매 환자에서 흔하게 나타날 수 있는 의사소통 방법입니다.\n[정답]", "2": "과거, 현재, 미래 시제의 올바른 사용이 어렵다는 증상도 있을 수 있지만, 이 문제는 치매 말기 단계에서 특정하기에는 부족합니다.", "3": "사용하는 어휘의 수가 점차적으로 제한된다는 것은 사실이지만, 이는 모든 치매 환자에게서 발생하지 않습니다.", "4": "올바른 이름을 지칭하지 못하는 경우는 치매 환자가 겪는 일반적인 어려움이긴 하지만, 앵무새와 같은 증상보다는 덜 구체적입니다.", "5": "대화 중 말이 끊기는 횟수가 증가하는 것은 증상 중 하나일 수 있으나, 문제에서 묻는 의사소통 문제의 범위와는 거리가 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "치매", "def_vi": "bệnh Alzheimer"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1614, '12', '치매 중기 단계에서 자주 나타나는 의사소통 문제는?', '["대화 중에 말이 끊기는 횟수가 증가한다.", "자주 확인하고 설명을 요구한다.", "물건이나 사람의이름을 부르는 것이 어렵다.", "대화 시 시선을 맞추는 것을 어려워한다.", "말이 없어진다."]'::jsonb, 1, '치매 중기 단계에서 나타날 수 있는 의사소통 문제를 이해하고 확인하기 위한 문제입니다.', NULL, '{"1": "대화 중에 말이 끊기는 횟수가 증가하는 것은 치매 중기 단계에서 자주 나타나는 증상입니다.\n[정답]", "2": "자주 확인하고 설명을 요구하는 경우도 있지만, 이는 중기의 주요 의사소통 문제와는 거리가 있습니다.", "3": "물건이나 사람의 이름을 부르는 것이 어려운 경우도 있지만, 상대적으로 덜 자주 나타나는 문제입니다.", "4": "대화 시 시선을 맞추는 것을 어려워하는 것은 보편적으로 나타나는 경향은 아니며, 개인차가 큽니다.", "5": "말이 없어진다는 것은 더 진행된 단계에서 나타나는 주된 증상으로, 중기 단계의 주요 문제와는 다소 차이가 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억, 사고, 외부 자극에 대해 반응을 제대로 하지 못하는 상태", "def_vi": "Trạng thái không thể phản ứng đúng với trí nhớ, suy nghĩ và kích thích từ bên ngoài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1613, '12', '치매 초기 단계에서 자주 나타나는 의사소통 문제는?', '["애매모호한 내용을 이야기한다.", "명칭 실어증을 보인다.", "대화의 주제가 자주 바뀐다.", "시선을 맞추는데 어려움이 있다.", "무언증이 나타난다."]'::jsonb, 3, '치매 초기 단계에서의 의사소통 문제를 파악하기 위한 질문입니다.', NULL, '{"1": "애매모호한 내용을 이야기한다는 초기 단계에서 나타날 수 있으나, 명확한 특징은 아닙니다.\n[정답]", "2": "명칭 실어증은 치매의 진행 단계에서 나타나는 증상입니다.", "3": "대화의 주제가 자주 바뀌는 것은 치매 초기 단계에서 자주 보이는 의사소통 문제입니다.", "4": "시선을 맞추는데 어려움이 있는 것은 보통 후기에 주로 나타나는 증상입니다.", "5": "무언증이 나타나는 것은 치매가 진행된 상태에서 주로 관찰됩니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "알츠하이머병(다른 형태의 인지장애 포함)", "def_vi": "Bệnh khó khăn về trí nhớ và nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1612, '12', '치매 대상자와 의사소통 방법으로 옳은 것은?', '["항상 현재 상황을 알려준다.", "대상자 옆에서 이야기한다.", "목소리 톤을 높여서 말한다.", "유행어를 사용한다.", "대상자의 행동을 복잡하게 해석한다."]'::jsonb, 1, '치매 대상자와의 효과적인 의사소통 방법을 이해하고 선택하도록 하는 문제입니다.', NULL, '{"1": "항상 현재 상황을 알려준다. - 치매 대상자는 기억이 저하되어 있으므로, 현재 상황을 주기적으로 알려주는 것이 필요합니다.\n[정답]", "2": "대상자 옆에서 이야기한다. - 옆에서 이야기하는 것이 아니라, 시선을 맞춰주며 대화하는 것이 더 효과적입니다.", "3": "목소리 톤을 높여서 말한다. - 목소리를 높이는 것은 불필요한 긴장을 유발할 수 있습니다.", "4": "유행어를 사용한다. - 유행어는 치매 대상자가 이해하기 어려운 경우가 많습니다.", "5": "대상자의 행동을 복잡하게 해석한다. - 복잡한 해석은 대상자의 혼란을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력 손상으로 인한 인지기능 저하", "def_vi": "Suy giảm chức năng nhận thức do mất trí nhớ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1611, '12', '다른 내용은 언어적 의사소통의 기본원칙에 어긋난 행동이다. 해당되는 것은?요양보호사가 74세 치매 할아버지에게 "10시가 되면 병원에 가야하니까 양말을 벗지 말고 거실에 앉아 계세요." 라고 말한다.', '["일상적인어휘 사용하기", "적절한 존칭어 사용하기", "한 번에 한 가지씩 시행 유도하기", "현재 상황 제시하기", "얼굴 마주보고 대화하기"]'::jsonb, 3, '언어적 의사소통의 기본 원칙에 어긋나는 행동을 파악하게 하려는 의도입니다.', NULL, '{"1": "일상적인 어휘를 사용하는 것은 의사소통의 기본 원칙에 부합합니다.\n[정답]", "3": "한 번에 한 가지씩 시행 유도하지 않는 것은 의사소통의 원칙에 어긋나므로 정답입니다.", "2": "적절한 존칭어 사용은 의사소통의 기본 원칙에 잘 맞습니다.", "4": "현재 상황을 제시하는 것은 의사소통의 원칙에 부합합니다.", "5": "얼굴을 마주보고 대화하는 것은 효과적인 의사소통 방식입니다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "대화하거나 정보를 주고받는 것", "def_vi": "Hành động nói chuyện hoặc trao đổi thông tin"}, {"term_ko": "기본원칙", "term_vi": "Nguyên tắc cơ bản", "def_ko": "기본적으로 따라야 하는 원칙", "def_vi": "Nguyên tắc cần tuân theo"}, {"term_ko": "적절한", "term_vi": "Thích hợp", "def_ko": "알맞고 적합한", "def_vi": "Đúng và phù hợp"}, {"term_ko": "존칭어", "term_vi": "Kính ngữ", "def_ko": "상대방을 존중하는 언어", "def_vi": "Ngôn ngữ tôn trọng đối phương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1610, '12', '치매 대상자와 대화 시 올바른 방법은?', '["뒤에서 어깨를 감싸며 부드럽게 다가간다.", "가까운곳에서 얼굴을 마주보고 말한다.", "몸동작을 크게 과장해서 표현한다.", "길고 자세하게 설명한다.", "대상자가이해하지 못하면 대화를 멈춘다."]'::jsonb, 2, '치매 대상자와 효과적으로 의사소통하는 방법을 이해하고 평가하는 것.', NULL, '{"1": "뒤에서 어깨를 감싸며 다가가는 것은 대상자가 위축될 수 있어 좋지 않은 접근이다.\n[정답]", "2": "가까운 곳에서 얼굴을 마주보고 말하는 것은 대상자가 대화를 이해하는 데 도움을 준다.", "3": "몸동작을 크게 과장하는 것은 대상자가 혼란스러울 수 있다.", "4": "길고 자세하게 설명하는 것은 치매 대상자에게 부담을 줄 수 있다.", "5": "대상자가 이해하지 못하면 대화를 멈추는 것은 오히려 더 소외감을 줄 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 상실이나 인지 기능 저하를 보이는 질환", "def_vi": "Bệnh mà người bệnh bị suy giảm trí nhớ hoặc chức năng nhận thức"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보를 주고받는 과정", "def_vi": "Quá trình trao đổi thông tin"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "케어를 받는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "이해", "term_vi": "Hiểu", "def_ko": "내용을 파악하는 과정", "def_vi": "Quá trình nắm bắt nội dung"}, {"term_ko": "소외감", "term_vi": "Cảm giác bị cô lập", "def_ko": "사회에서 소외된 느낌", "def_vi": "Cảm giác tách biệt khỏi xã hội"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1609, '12', '인지능력 저하로 자기 마음대로 생각하는 치매 대상자와 의사소통 방법은?', '["대화주제를 자주 바꾼다.", "새로운 물건을 활용하여 대화를 시도한다.", "''네'', ''아니오''로 답할 수 있는 질문을 한다.", "대상자가 반응하지 않으면 대화를 바꾼다.", "대상자의 행동을 자의적으로 해석하여 의미를 파악한다."]'::jsonb, 3, '인지 능력이 저하된 치매 대상자와의 효과적인 의사소통 방법을 이해하고 선택하도록 하는 문제입니다.', NULL, '{"1": "대화주제를 자주 바꾸는 것은 혼란을 야기할 수 있으므로 좋지 않습니다.", "2": "새로운 물건을 활용하여 대화를 시도하는 것은 도움이 될 수 있으나, 응답을 유도하기 위해서는 제한된 선택지가 필요합니다.\n[정답]", "3": "''네'', ''아니오''로 답할 수 있는 질문은 간단하고 명확하여 치매 대상자가 쉽게 반응할 수 있도록 돕습니다.", "4": "대상자가 반응하지 않는 경우 대화를 바꾸는 것은 효과적이지 않을 수 있으며, 반응을 기다리는 것이 더 중요합니다.", "5": "대상자의 행동을 자의적으로 해석하여 의미를 파악하는 것은 잘못된 해석을 초래할 수 있어 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "인지능력", "term_vi": "자기", "def_ko": "능력或 khả năng nhận thức", "def_vi": "자신 hoặc bản thân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1608, '12', '종이접기'' 프로그램에 참여한 치매 대상자가 따라 하지 못하고 머뭇거릴 때 돕는 방법은?', '["어린아이 대하듯 한다.", "이해하지 못하면 반복적으로 설명을 한다.", "말 이외에다른 신호는 사용하지 않는다.", "문제행동 시 ''왜'' 그랬냐고 묻는다.", "한 번에 여러 가지 일을 알려준다."]'::jsonb, 2, '치매 대상자가 종이접기 프로그램을 수행하는 과정에서 도움을 제공하는 방법에 대한 이해를 질문하는 문제입니다.', NULL, '{"1": "어린아이 대하듯 한다는 것은 대상자의 자존감을 상해할 수 있어 부적절한 방법입니다.\n[정답]", "2": "이해하지 못하면 반복적으로 설명을 하는 것은 치매 환자에게 필요한 지원 방법입니다.", "3": "말 이외의 다른 신호를 사용하지 않는 것은 다양하고 효과적인 소통 방법을 제한합니다.", "4": "문제행동 시 ''왜'' 그랬냐고 묻는 것은 오히려 환자에게 스트레스를 줄 수 있습니다.", "5": "한 번에 여러 가지 일을 알려주는 것은 치매 환자가 혼란스러워질 수 있으므로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "종이접기", "term_vi": "Gấp giấy", "def_ko": "종이를 접어서 만드는 예술 또는 활동", "def_vi": "Nghệ thuật hoặc hoạt động tạo ra từ việc gấp giấy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1607, '12', '치매 대상자와의 의사소통 원칙으로 옳은 것은?', '["주로 \"왜\"라고 묻고 답하게 한다.", "대상자의 속도에맞춘다.", "자세하고 길게 설명한다.", "신체적 접촉을 삼간다.", "과거를 회상하지 않도록 한다."]'::jsonb, 2, '치매 대상자와의 효과적인 의사소통 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "''왜''라는 질문은 치매 환자에게 혼란을 줄 수 있습니다.\n[정답]", "2": "대상자의 속도에 맞추는 것은 의사소통에서 매우 중요합니다.", "3": "자세하고 길게 설명하면 오히려 이해를 어렵게 만들 수 있습니다.", "4": "신체적 접촉은 오히려 신뢰를 쌓는데 도움이 될 수 있습니다.", "5": "과거를 회상하는 것은 치매 환자와의 의사소통에서 긍정적인 효과를 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Chứng mất trí nhớ", "def_ko": "기억과 인지 기능의 감소를 초래하는 상태", "def_vi": "Tình trạng giảm chức năng ghi nhớ và nhận thức"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보와 감정을 교환하는 과정", "def_vi": "Quá trình trao đổi thông tin và cảm xúc"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "도움이나 지원이 필요한 사람", "def_vi": "Người cần sự giúp đỡ hoặc hỗ trợ"}, {"term_ko": "속도", "term_vi": "Tốc độ", "def_ko": "어떤 일이 진행되는 빠르기", "def_vi": "Độ nhanh của một công việc"}, {"term_ko": "신체적 접촉", "term_vi": "Tiếp xúc cơ thể", "def_ko": "신체를 통해 하는 접촉", "def_vi": "Sự tiếp xúc qua cơ thể"}, {"term_ko": "회상", "term_vi": "Hồi tưởng", "def_ko": "과거의 일을 기억하거나 떠올리는 것", "def_vi": "Nhớ lại hoặc gợi lại những sự việc trong quá khứ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1606, '12', '치매 대상자의 대화 중 의사소통 방법이 옳은 것은?요양보호사: 오늘 목욕하기로 한 날이에요. 목욕 시작하실까요? 대상자: (목욕하지 않은 상태) 나 목욕 다 했어. 빨래도 다 했다고.', '["목욕 안 하셨잖아요. 다 알아요.", "그러지 말고 목욕한 후에 같이 외출해요.", "언제 목욕하셨어요?", "잘 하셨어요. 그럼 이제 샤워하실래요?", "거짓말하시면 앞으로 목욕 안 할 거예요."]'::jsonb, 4, '치매 환자와의 의사소통에서 올바른 접근 방법을 이해하고 선택하는 것을 확인하기 위함입니다.', NULL, '{"1": "목욕을 하지 않은 사실을 지적하므로 부적절합니다.\n[정답]", "4": "긍정적인 반응을 통해 환자가 샤워를 하도록 유도하는 방법입니다.", "2": "거부감을 줄 수 있는 제안으로 부적절합니다.", "3": "과거의 행동을 물어보는 것은 치매 환자에게 혼란을 줄 수 있습니다.", "5": "부정적인 어조로 말하여 환자의 불안감을 증가시킬 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 사고 기능에 문제가 생기는 질환", "def_vi": "Bệnh lý xảy ra với chức năng trí nhớ và tư duy"}, {"term_ko": "대화", "term_vi": "Giao tiếp", "def_ko": "사람들 간의 말이나 글로 이루어지는 의사소통", "def_vi": "Sự trao đổi thông tin bằng lời nói hoặc chữ viết"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보를 주고받는 과정", "def_vi": "Quá trình truyền đạt và nhận thông tin"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 깨끗이 하기 위한 행동", "def_vi": "Hành động làm sạch cơ thể"}, {"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "서비스 받는 사람, 보호 대상", "def_vi": "Người nhận dịch vụ, người đang được chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1605, '12', '치매 대상자와의 의사소통으로 옳은 것은?', '["허리가 많이 아프세요?", "8시가 되면 약 드세요.", "할머니 오늘은 기분이 괜찮아?", "우유는 드셔도 되지만 콜라는 안 돼요.", "식사를 왜 조금만 하세요?"]'::jsonb, 1, '치매 대상자와의 의사소통에서 적절한 질문이나 표현 방법을 이해하고 평가하는 것이 의도이다.', NULL, '{"1": "허리가 많이 아프세요? (치매 대상자의 신체적 불편함을 확인하는 질문으로 적절하다.)\n[정답]", "2": "8시가 되면 약 드세요. (치매 환자에게 시간 엄수를 강조하는 표현은 적절하지 않다.)", "3": "할머니 오늘은 기분이 괜찮아? (부드러운 질문이지만 직접적인 질문은 치매 환자에게 혼란을 줄 수 있다.)", "4": "우유는 드셔도 되지만 콜라는 안 돼요. (식이 제한을 알리는 것이 적절치 않다.)", "5": "식사를 왜 조금만 하세요? (치매 환자에게 질문하는 것보다는 지지적인 표현이 필요하다.)"}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력 및 인지 기능의 저하로 인한 질병", "def_vi": "Bệnh mất trí nhớ và giảm chức năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1604, '12', '치매 대상자에게 질문을 할 때 올바른 방법은?', '["어떤 음식을 좋아하세요?", "사과드실래요?", "식사하고 양치질한 후에 외출해요.", "거기에 가만히 앉아서 기다리세요.", "거실은 되지만 방에는 들어가지 마세요."]'::jsonb, 2, '치매를 앓고 있는 대상자와의 의사소통 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "어떤 음식을 좋아하세요? : 치매 환자에게는 구체적인 질문보다는 단순하고 명확한 질문이 필요합니다.\n[정답]", "2": "사과드실래요? : 간단하고 이해하기 쉬운 질문으로, 대답하기 용이합니다.", "3": "식사하고 양치질한 후에 외출해요. : 지시형 질문으로, 치매 환자에게 혼란을 줄 수 있습니다.", "4": "거기에 가만히 앉아서 기다리세요. : 명령형으로, 찬반을 묻거나 의견을 물어볼 수 있는 질문이 아닙니다.", "5": "거실은 되지만 방에는 들어가지 마세요. : 제한적인 지시로서 이해하기 낫습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억이나 사고 기능이 상실되는 질병", "def_vi": "Bệnh không còn khả năng ghi nhớ hoặc suy nghĩ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1603, '12', '치매 대상자와 의사소통하는 방법으로 옳은 것은?', '["어제는 무엇을 드셨어요?", "몸이 어떻게 아프세요?", "우유 드실래요? 주스 드실래요?", "어디로 여행가고 싶으세요?", "식사 후 양치하고 산책하실래요?"]'::jsonb, 3, '치매 대상자와 의사소통이 필요한 상황에서, 적절한 질문이나 제안을 통해 의사소통의 효과를 높이고자 하는 의도입니다.', NULL, '{"1": "''어제는 무엇을 드셨어요?''와 같은 질문은 치매 환자가 기억하기 어려울 수 있습니다.", "2": "''몸이 어떻게 아프세요?''는 구체적인 증상을 확인할 수 있지만, 복잡한 질문일 수 있습니다.\n[정답]", "3": "''우유 드실래요? 주스 드실래요?''는 간단하고 선택지를 제공하여 의사소통을 용이하게 합니다.", "4": "''어디로 여행가고 싶으세요?''는 추상적인 질문으로 치매 대상자가 이해하기 어려울 수 있습니다.", "5": "''식사 후 양치하고 산책하실래요?''는 여러 가지 활동을 한 번에 제안하여 혼란을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력 및 사고 능력이 감소하는 질환", "def_vi": "Bệnh giảm khả năng ghi nhớ và tư duy"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보를 주고받는 행위", "def_vi": "Hành động trao đổi thông tin"}, {"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "서비스나 도움을 받는 사람", "def_vi": "Người nhận dịch vụ hoặc hỗ trợ"}, {"term_ko": "선택지", "term_vi": "Lựa chọn", "def_ko": "여러 가지 중에서 선택할 수 있는 것", "def_vi": "Những điều có thể chọn từ nhiều cái"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1602, '12', '다음 중 치매대상자와 의사소통 방법으로 옳은 것은? 대상자: 손주가 나랑 여행가자고 하는데 어떻게 할까? 요양보호사: ( )', '["어르신 생각은 어떠세요?", "어르신 하고 싶은 데로 하세요.", "어디로 여행가고 싶으세요?", "가고 싶세요? 가고 싶지 않으세요?", "건강검진 받고 사진도 찍고 여권도 만들어야지요."]'::jsonb, 4, '치매대상자와의 효과적인 의사소통 방법을 묻고 있다.', NULL, '{"1": "어르신의 생각을 물어보는 질문으로, 치매환자가 이해하기 어려울 수 있다.\n[정답]", "4": "가고 싶습니다라고 대답할 수 있는 명확한 선택지를 제공한다.", "3": "여행지를 물어보는 질문으로, 치매환자가 기억하지 못할 위험이 있다.", "5": "장기적인 건강 관리에 대한 내용으로, 치매대상자의 현재 의사소통에는 적합하지 않다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력이나 사고력의 저하로 인한 질환", "def_vi": "Bệnh do suy giảm trí nhớ hoặc khả năng tư duy"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "서로 의견을 주고받는 행위", "def_vi": "Hành động trao đổi ý kiến với nhau"}, {"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "서비스나 도움을 받는 사람", "def_vi": "Người nhận dịch vụ hoặc sự giúp đỡ"}, {"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인이나 환자 등을 돌보는 직업", "def_vi": "Nghề chăm sóc người cao tuổi hoặc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1601, '12', '다음 대화 중 효과적인 의사소통으로 옳은 것은?대상자: 아이고 아파. 배가 아파 죽겠어. 요양보호사: ( )', '["또 왜 그러세요?", "오늘 점심 못 드시겠네요?", "그럼 누워계세요.", "어제 무엇을 얼마나 드셨어요?", "(배를 맍지며) 여기가 아프세요?"]'::jsonb, 5, '대화의 맥락 속에서 효과적인 의사소통이 무엇인지 확인하고, 적절한 반응을 찾기 위함입니다.', NULL, '{"1": "또 왜 그러세요? - 단순히 질문을 반복하는 것으로, 상황을 파악하는 데 비효율적입니다.\n[정답]", "2": "(배를 맍지며) 여기가 아프세요? - 직접적인 질문으로, 대상자의 증상을 더 잘 이해할 수 있게 도와줍니다.", "3": "그럼 누워계세요. - 상황을 무시하고 단순한 지시만 합니다.", "4": "어제 무엇을 얼마나 드셨어요? - 질문이 적절하지만, 현재의 아픔과는 연결되지 않습니다.", "5": "오늘 점심 못 드시겠네요? - 아픔에 대한 적절한 반응이 아닙니다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "의사전달(한국어)", "def_vi": "Truyền đạt ý kiến"}, {"term_ko": "대화", "term_vi": "Cuộc trò chuyện", "def_ko": "서로 이야기함(한국어)", "def_vi": "Nói chuyện với nhau"}, {"term_ko": "효과적", "term_vi": "Hiệu quả", "def_ko": "성과가 있는(한국어)", "def_vi": "Có kết quả"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "돌봄받는 사람(한국어)", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "병이 나타나는 상태(한국어)", "def_vi": "Trạng thái xuất hiện bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1600, '12', '혼자서 요리를 할 수 없는 치매 대상자가 된장국을 끓이겠다고 고집을 부릴 때 대처방법으로 옳은 것은?', '["제가 도와드릴게요. 같이 끓일까요?", "요리가 하고 싶어도 하면 안돼요. 위험해요.", "제가 해 드릴테니 조금만 기다리세요.", "그럼 끓여보세요. 맛이 어떨지 궁금하네요.", "어떻게 끓일지 먼저 설명해 보세요."]'::jsonb, 1, '치매 대상자와의 소통 및 안전한 대처 방법을 묻는 의도입니다.', NULL, '{"1": "제가 도와드릴게요. 같이 끓일까요? - 동행을 통해 안전하게 요리할 수 있도록 돕는 좋은 방법입니다.\n[정답]", "2": "요리가 하고 싶어도 하면 안돼요. 위험해요. - 치매 대상자의 자율성을 위축시키는 부정적인 방법입니다.", "3": "제가 해 드릴테니 조금만 기다리세요. - 자기 주도성을 줄이고 대화를 단절할 수 있습니다.", "4": "그럼 끓여보세요. 맛이 어떨지 궁금하네요. - 위험한 상황을 초래할 수 있습니다.", "5": "어떻게 끓일지 먼저 설명해 보세요. - 대상자의 기억력과 이해를 고려하지 않은 방법입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력과 인지 기능의 저하로 일상생활에 어려움을 겪는 상태", "def_vi": "Tình trạng suy giảm trí nhớ và khả năng nhận thức gây khó khăn trong sinh hoạt hàng ngày"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1599, '12', '다음 대화에서 요양보호사의 적절한 대처방법은?딸:"엄마! 맛이 없으니까 이제 음식하지 마세요." 대상자: (화가 나서방으로 들어가며) 그럼, 네가 알아서해 먹어. 난 안 먹어 요양보호사: (대상자에게 다가가) ( )', '["\"엄마가 힘드실까봐 일부러 한 말일 거예요.\"", "\"밥을 안 드시면 본인만 손해예요. 참으세요.\"", "\"음식 솜씨가 예전 같지 않다고하니 속상하시지요.\"", "\"이제부터는 따님한테 하라고 하세요.\"", "\"앞으로 제가 음식을 만들어드릴게요.\""]'::jsonb, 3, '요양보호사가 대상자의 감정과 상황을 이해하고 적절하게 대처하는 방법을 묻고자 하는 의도입니다.', NULL, '{"1": "요양보호사가 사정없이 대화를 이어가는 것은 바람직하지 않습니다.\n[정답]", "3": "대상자의 기분을 이해하고 공감하는 대화가 적절합니다.", "2": "대화의 진행이 아니라 대상자를 자극할 수 있는 발언입니다.", "4": "요양보호사의 역할에 어긋나는 발언입니다.", "5": "자신이 해야 하는 일로 상황을 더 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "적절한", "term_vi": "phù hợp", "def_ko": "적합한(한국어)", "def_vi": "thích hợp(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1598, '12', '시설에서 생활하는 치매대상자가 거실에 나와 바지를 벗으며 성기를 노출할 경우 대처방법은?', '["스스로 옷을 입을 때까지 기다린다.", "경범죄로 처벌받을 수 있다고 경고한다.", "거실에 있는 사람들은 다른 곳으로 이동시킨다.", "여러사람 앞에서 망신을 주어 행동을 멈추게 한다.", "좋아하는 물건이나 활동을 통해 관심 전환을 유도한다."]'::jsonb, 5, '치매대상자의 행동에 대한 적절한 대처 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "스스로 옷을 입을 때까지 기다리는 것은 적절하지 않은 대처 방법입니다.\n[정답]", "5": "좋아하는 물건이나 활동을 통해 관심 전환을 유도하는 것은 효과적인 대처 방법입니다.", "2": "경범죄로 처벌받을 수 있다고 경고하는 것은 적절하지 않으며, 오히려 불안감을 조성할 수 있습니다.", "3": "거실에 있는 사람들을 다른 곳으로 이동시키는 것은 상황을 악화시킬 수 있습니다.", "4": "여러 사람 앞에서 망신을 주는 것은 치매대상자의 심리적 상처를 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억이나 사고 기능의 점진적인 손실", "def_vi": "Sự mất mát dần dần về khả năng nhớ hoặc suy nghĩ"}, {"term_ko": "대처 방법", "term_vi": "Cách xử lý", "def_ko": "문제 상황에 대처하기 위한 방법", "def_vi": "Phương pháp ứng phó với tình huống"}, {"term_ko": "관심 전환", "term_vi": "Chuyển hướng sự chú ý", "def_ko": "주의를 다른 곳으로 돌리는 것", "def_vi": "Đổi hướng sự chú ý sang nơi khác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1597, '12', '시설 치매대상자가 담당 요양보호사를 애인이라고 하면서 다음과 같은 행동을 할 때 대처방법은?', '["가족에게 알려 계약을 종료하겠다고 말한다.", "성희롱으로 노인보호전문기관에 신고한다고 말한다.", "치매 대상자에게 나타나는증상이라고 이해하고 넘어간다.", "애인이 아니라 어르신을 돌보는 전문가라고 권위적으로 말한다.", "멈추지 않으면 담당 요양보호사 변경을 요청하겠다고 경고한다."]'::jsonb, 5, '요양보호사가 치매 환자와의 관계 설정에서 적절한 대처 방법을 묻는 문제입니다.', NULL, '{"1": "가족에게 알려 계약을 종료하겠다고 말하는 것은 적절한 대처가 아닙니다.\n[정답]", "5": "멈추지 않으면 담당 요양보호사 변경을 요청하겠다고 경고하는 것은 상황을 개선하기 위한 적절한 방법입니다.", "3": "치매 대상자에게 나타나는 증상이라고 이해하고 넘어가는 것은 문제 해결이 되지 않습니다.", "4": "애인이 아니라 어르신을 돌보는 전문가라고 권위적으로 말하는 것은 부적절한 접근입니다.", "2": "성희롱으로 신고한다고 하는 것은 상황을 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "담당", "term_vi": "Người phụ trách", "def_ko": "책임을 맡은", "def_vi": "người chịu trách nhiệm"}, {"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인을 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc người cao tuổi"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고력이 저하되는 질병", "def_vi": "Bệnh giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "행동", "term_vi": "Hành động", "def_ko": "몸의 움직임이나 태도", "def_vi": "Di chuyển hoặc thái độ của cơ thể"}, {"term_ko": "성과", "term_vi": "Hiệu quả", "def_ko": "효과", "def_vi": "Kết quả"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1596, '12', '프로그램 참여 중에 남자 치매대상자가 옆에 앉은 여자 대상자의 가슴을 만질 때 대처방법은?', '["무슨 짓이냐고 손을 때려서 제지한다.", "여자 대상자에게 사과하라고 한다.", "내일부터 참여시키지 않겠다고 한다.", "여자 대상자를 다른 장소로 이동시킨다.", "큰 소리로 당장 방으로 들어가라고 한다."]'::jsonb, 4, '치매 환자의 행동 관리에 대한 대처 방법을 평가한다.', NULL, '{"1": "무슨 짓이냐고 손을 때려서 제지하는 것은 폭력을 유발할 수 있다. \n[정답]", "4": "여자 대상자를 다른 장소로 이동시키는 것은 상황을 잠재우는 적절한 방법이다.", "2": "여자 대상자에게 사과하라고 하는 것은 적절한 대화 방식이 아니다.", "3": "내일부터 참여시키지 않겠다고 하는 것은 문제 해결이 아니다.", "5": "큰 소리로 당장 방으로 들어가라고 하는 것은 불필요한 위협을 줄 수 있다."}'::jsonb, '[{"term_ko": "프로그램", "term_vi": "Chương trình", "def_ko": "프로그램(한국어)", "def_vi": "chương trình(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1595, '12', '치매 대상자가 반복적으로 바지 지퍼를 내리면서 요양보호사에게 올려 달라고 할 때 대처방법은?', '["지퍼가 없는 바지로 갈아입힌다.", "창피를 주어 행동을 멈추게 한다.", "계속하면 서비스를 중단하겠다고 한다.", "가족에게 상황을 설명하고 퇴소를 권한다.", "도와줄 수 없으니 스스로 지퍼를 올리라고 한다."]'::jsonb, 1, '치매 대상자가 보이는 행동에 대한 올바른 대처 방법을 이해하고 판단하는 것이 중요하다.', NULL, '{"1": "지퍼가 없는 바지로 갈아입힘으로써 대상자의 불편함을 해소할 수 있다. \n[정답]", "2": "창피를 주는 것은 오히려 대처 방법으로 부적절하다.", "3": "서비스를 중단하겠다고 위협하는 것은 대상자에게 부정적인 영향을 미칠 수 있다.", "4": "가족에게 퇴소를 권하는 것은 문제 해결보다는 회피에 가까운 방법이다.", "5": "스스로 지퍼를 올리라고 요구하는 것은 치매 환자의 상황을 고려하지 않은 대처 방법이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Mất trí", "def_ko": "기억력을 잃는 질환", "def_vi": "Bệnh mất trí nhớ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1594, '12', '다음 사례에서 치매 대상자를 돕는 방법으로 옳은 것은?시설에서 낮 동안 잘 지내던 대상자가해질녘이 되면 "오늘도 수고하셨어요. 저는 퇴근합니다."라고 하면서 밖으로 나가려고 한다.', '["아직 일이 끝나지 않아 못 간다고 말한다.", "요양시설이라 나갈 수 없다고 설득한다.", "조명을 어둡게 하여 밤이라는 것을 알린다.", "빠른 박자의 음악을 크게 틀어준다.", "대상자가 좋아하는 텔레비전 프로그램을 켜준다."]'::jsonb, 5, '치매 환자의 행동을 이해하고 적절히 대응하는 방법을 묻는 문제입니다.', NULL, '{"1": "아직 일이 끝나지 않아 못 간다고 말한다. 치매 환자는 현실을 정확히 이해하지 못할 수 있으므로 이 방법은 도움이 되지 않습니다.\n[정답]", "5": "대상자가 좋아하는 텔레비전 프로그램을 켜준다. 이는 대상자의 관심을 끌고 안정을 취하게 하여 퇴근하려는 행동을 완화시킬 수 있습니다.", "3": "조명을 어둡게 하여 밤이라는 것을 알린다. 치매 환자에게 혼란을 줄 수 있는 방법입니다.", "4": "빠른 박자의 음악을 크게 틀어준다. 이는 오히려 불안을 유발할 수 있습니다.", "2": "요양시설이라 나갈 수 없다고 설득한다. 설득이 통하지 않을 가능성이 높습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 인지 기능의 저하로 인한 질환", "def_vi": "Bệnh suy giảm trí nhớ và nhận thức"}, {"term_ko": "요양시설", "term_vi": "Cơ sở dưỡng lão", "def_ko": "노인이나 장애인을 위한 시설", "def_vi": "Nơi chăm sóc người già hoặc người khuyết tật"}, {"term_ko": "퇴근", "term_vi": "Về nhà", "def_ko": "일을 마치고 집으로 돌아가는 것", "def_vi": "Trở về nhà sau khi làm việc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1593, '12', '시설 치매 대상자가 해 질 무렵이 되면 가방을 들고 아들 집으로 가겠다고 할 때 대처방법은?', '["들고 있는 가방을 보이지 않는 곳으로 치운다.", "침실 조명을 어둡게 하여 잠을 청하게 한다.", "좋아하는 따뜻한 음료를 마시러 가자고 한다.", "아들이 여행을 가서 집에 아무도 없다고 말한다.", "지금은 늦었으니 내일 아들을 만나러 가자고 한다."]'::jsonb, 3, '치매 환자의 감정을 이해하고 적절히 대처하는 방법을 묻는 문제입니다.', NULL, '{"1": "가방을 치우는 것은 환자의 불안을 증가시킬 수 있습니다.\n[정답]", "3": "환자의 좋아하는 음료를 제안하여 긍정적인 방향으로 유도하는 것이 좋습니다.", "2": "침실 조명을 어둡게 하면 불안감을 느낄 수 있습니다.", "4": "아들이 여행 중이라고 말하는 것은 신뢰를 해치게 될 수 있습니다.", "5": "내일 만나자고 하는 것은 환자가 느끼는 즉각적인 욕구를 무시하는 것입니다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "시설", "def_ko": "장소(한국어)", "def_vi": "địa điểm(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1592, '12', '치매 대상자가 해질녘만 되면 다른 대상자를 따라다니며 여보 무서워. 같이 있자.라고 할 때 대처방법은?', '["\"겁이 많아지셨네요. 뭐가 무서운지 말씀해 보세요.\"", "\"거짓말하면서 자꾸 괴롭히면 여기서 나가셔야 돼요.\"", "\"할아버지는 작년에 돌아가셨어요. 이젠 받아들이세요.\"", "\"저분이 할아버지로 보이세요? 사진하고 많이 다르잖아요.\"", "\"할아버지를 많이 의지하셨나봐요. 할아버지 이야기 좀 해주세요.\""]'::jsonb, 5, '치매 환자의 정서적 지지를 위해 적절한 대처방법을 묻고 있다.', NULL, '{"1": "단순히 겁을 인정하는 대화보다는 감정을 나누는 것이 더 중요하다.\n[정답]", "5": "할아버지에 대한 긍정적인 기억을 회상하도록 유도하여 안정감을 줄 수 있다.", "3": "과거의 사실을 진술하는 것은 대처로 적절하지 않다.", "4": "환자가 느끼는 감정을 이해하지 않고 비판하는 것은 좋지 않다.", "2": "부정적인 언행은 환자의 불안을 더욱 악화시킬 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Hội chứng suy giảm trí nhớ", "def_ko": "기억력과 사고 능력 저하", "def_vi": "Suy giảm khả năng ghi nhớ và tư duy"}, {"term_ko": "대처방법", "term_vi": "Phương pháp ứng phó", "def_ko": "상황에 적절히 대응하는 방법", "def_vi": "Cách đối phó phù hợp với tình huống"}, {"term_ko": "정서적 지지", "term_vi": "Hỗ trợ tinh thần", "def_ko": "정서적으로 지원하는 것", "def_vi": "Hỗ trợ về mặt cảm xúc"}, {"term_ko": "안정감", "term_vi": "Cảm giác ổn định", "def_ko": "심리적으로 편안한 상태", "def_vi": "Trạng thái tâm lý thoải mái"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1591, '12', '치매 대상자가 해질녘만 되면 다른 대상자의 사물함에서 옷을 꺼낼 때 대처방법은?', '["\"어르신 옷을 같이 찾아봐요.\"라며 이끈다.", "\"왜 남의 옷에 손을 대세요!\"라며 소리친다.", "다른 대상자에게 귓속말로 이해하라고 말한다.", "\"옷은 내일 찾고 주무세요.\"라고 하며 조명을 끈다.", "\"남의 옷을 마음대로 가져가면 안돼요.\"라며 옷을 정리한다."]'::jsonb, 1, '치매 대처 방법에 대한 이해와 적절한 대응 방안을 묻는 문제입니다.', NULL, '{"1": "''어르신 옷을 같이 찾아봐요.''라며 이끈다. - 긍정적이고 지지적인 대처로, 대상을 안정시키는 방법입니다.\n[정답]", "2": "''왜 남의 옷에 손을 대세요!''라며 소리친다. - 부정적인 반응으로, 대상자를 혼란스럽게 할 수 있습니다.", "3": "다른 대상자에게 귓속말로 이해하라고 말한다. - 비공식적인 방법으로 문제 해결에 도움이 되지 않을 수 있습니다.", "4": "''옷은 내일 찾고 주무세요.''라고 하며 조명을 끈다. - 해결책 제시보다는 회피하는 태도로, 적절하지 않습니다.", "5": "''남의 옷을 마음대로 가져가면 안돼요.''라며 옷을 정리한다. - 따지는 방식으로, 대상자에게 불쾌감을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력 및 사고 능력의 저하(한국어)", "def_vi": "Sự suy giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "도움이 필요한 사람(한국어)", "def_vi": "Người cần sự trợ giúp"}, {"term_ko": "대처방법", "term_vi": "Cách đối phó", "def_ko": "문제를 해결하기 위한 방법(한국어)", "def_vi": "Phương pháp giải quyết vấn đề"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1590, '12', '다음 상황에서 요양보호사의 대처방법은?시설 치매대상자가 해질녘이 되면 "죽어야 하는데...죽지도않는다."라며 운다.', '["죽음에 대해서 말하지 말라고 한다.", "눈물을 닦아주며 옆에 있어준다.", "나이 들면 누구나 드는 생각이라고 말한다.", "그렇게 말하는 사람이 더 오래 산다고 말한다.", "다른 대상자에게 피해가 되니 조용히 하라고 한다."]'::jsonb, 2, '요양보호사가 치매 대상자의 감정을 이해하고 적절히 대처하는 방법을 묻는 문제입니다.', NULL, '{"1": "죽음에 대해서 말하지 말라고 한다. - 대상자의 감정을 무시하는 대처법입니다.\n[정답]", "2": "눈물을 닦아주며 옆에 있어준다. - 대상자의 감정을 공감하고 지지해주는 올바른 대처입니다.", "3": "나이 들면 누구나 드는 생각이라고 말한다. - 대상자의 감정을 간과하고 일반화하는 대처법입니다.", "4": "그렇게 말하는 사람이 더 오래 산다고 말한다. - 대화의 흐름을 이해하지 않는 비유적 표현입니다.", "5": "다른 대상자에게 피해가 되니 조용히 하라고 한다. - 대상자의 감정을 억압하는 대처법입니다."}'::jsonb, '[{"term_ko": "대처방법", "term_vi": "Phương pháp đối phó", "def_ko": "대처하는 방법(한국어)", "def_vi": "Cách phản ứng trong tình huống"}, {"term_ko": "눈물", "term_vi": "Nước mắt", "def_ko": "울때 나오는 액체(한국어)", "def_vi": "Chất lỏng chảy ra khi khóc"}, {"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고력이 저하되는 질환(한국어)", "def_vi": "Bệnh suy giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "도움을 받는 사람(한국어)", "def_vi": "Người nhận được sự chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1589, '12', '치매 대상자에게 발생하는 석양증후군의 문제 행동 유형으로 옳은 것은?', '["낮에는 유순하지만 저녁이 되면 방을 왔다갔다하며 불안해한다.", "짐을 싸다가 다시풀어놓는 행동을 반복한다.", "손에 만져지는 것은 무엇이든 먹으려고 한다.", "아무런 목적지도 없이 돌아다닌다.", "다른 사람이 자신의 물건을 훔쳐갔다고 의심하며 화를 낸다."]'::jsonb, 1, '치매 대상자에게 나타나는 석양증후군의 행동 유형을 이해하고 평가할 수 있도록 하는 문제입니다.', NULL, '{"1": "낮에는 유순하지만 저녁이 되면 방을 왔다갔다하며 불안해한다. [정답] 이는 석양증후군에서 흔히 나타나는 행동으로, 저녁 시간에 불안이 증가하는 것을 의미합니다.", "2": "짐을 싸다가 다시풀어놓는 행동을 반복한다. 이 행동은 석양증후군과 관련이 적습니다.", "3": "손에 만져지는 것은 무엇이든 먹으려고 한다. 이는 다른 행동 유형으로, 석양증후군과는 직접적인 연관이 없습니다.", "4": "아무런 목적지도 없이 돌아다닌다. 이 행동은 석양증후군의 일부로 볼 수 있으나, 더 일반적인 행동입니다.", "5": "다른 사람이 자신의 물건을 훔쳐갔다고 의심하며 화를 낸다. 이는 편집증적 행동으로 석양증후군의 특성과는 다릅니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Nâng cao chức năng tâm thần", "def_ko": "기억 및 사고 능력의 지속적인 감소", "def_vi": "Giảm khả năng ghi nhớ và tư duy một cách liên tục"}, {"term_ko": "석양증후군", "term_vi": "Hội chứng chiều tà", "def_ko": "저녁에 행동 문제를 증가시키는 상태", "def_vi": "Tình trạng tăng cường vấn đề hành vi vào buổi tối"}, {"term_ko": "불안", "term_vi": "Lo lắng", "def_ko": "열린 마음 상태", "def_vi": "Trạng thái tâm trí lo âu"}, {"term_ko": "편집증", "term_vi": "Hoang tưởng", "def_ko": "타인에 대한 강한 의심 및 불신", "def_vi": "Sự nghi ngờ và bất tín nhiệm mạnh mẽ đối với người khác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1588, '12', '치매 대상자가 석양증후군으로 밤에 잠을 못 잘 때 돕는 방법은?', '["수면제를 제공한다.", "낮에 움직이거나 활동하게 한다.", "혼자 쉴 수 있는 시간을 준다.", "텔레비전을 끄고 조명을 은은하게 해준다.", "낮 시간에 프로그램 참여를 제한한다."]'::jsonb, 2, '석양증후군에 대한 이해와 적절한 대처 방법을 평가하고자 합니다.', NULL, '{"1": "수면제를 제공하는 것은 의존성을 초래할 수 있습니다.\n[정답]", "2": "낮에 움직이거나 활동하게 하는 것은 밤에 수면을 개선하는 데 도움을 줍니다.", "3": "혼자 쉴 수 있는 시간을 주면 좋지만, 활동적인 낮이 더 효과적입니다.", "4": "조명을 은은하게 해주는 것 또한 중요하나 낮 동안의 활동이 우선입니다.", "5": "낮 시간에 프로그램 참여를 제한하는 것은 오히려 부정적 영향을 미칠 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력의 저하와 인지기능의 감소가 있는 질병", "def_vi": "Một bệnh lý mà khả năng ghi nhớ và chức năng nhận thức suy giảm"}, {"term_ko": "석양증후군", "term_vi": "Hội chứng hoàng hôn", "def_ko": "저녁에 증상이 악화되는 현상", "def_vi": "Hiện tượng triệu chứng xấu đi vào buổi tối"}, {"term_ko": "수면제", "term_vi": "Thuốc an thần", "def_ko": "수면을 유도하는 약물", "def_vi": "Thuốc giúp tạo giấc ngủ"}, {"term_ko": "혼자", "term_vi": "Một mình", "def_ko": "다른 사람 없이", "def_vi": "Không có người khác"}, {"term_ko": "조명", "term_vi": "Ánh sáng", "def_ko": "빛을 비추는 장치", "def_vi": "Thiết bị chiếu sáng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1587, '12', '시설 치매대상자가 내가 대장이다! 나를 따르라!라고 소리를 지르며 따라오지 않는 다른 대상자에게 화를 낼 때 대처방법은?', '["진짜 대장같이 멋있다고 칭찬해 준다.", "행동이 잦아들 때까지 자리를 피한다.", "모든 대상자들을 대장놀이에 참여시킨다.", "오늘만 대장하고 내일은 다른 사람 시키자고 한다.", "좋아하는 드라마를 보자며 텔레비전을 틀어준다."]'::jsonb, 5, '치매 환자의 행동에 대한 적절한 대처 방법을 이해하고 적용할 수 있는지를 평가하는 문제입니다.', NULL, '{"1": "진짜 대장 같다고 칭찬하는 것은 오히려 환자의 행동을 부추길 수 있습니다.\n[정답]", "2": "행동이 잦아들 때까지 자리를 피하는 것은 환자의 감정을 무시할 수 있습니다.", "3": "모든 대상자를 대장놀이에 참여시키는 것은 상황을 더 복잡하게 만들 수 있습니다.", "4": "오늘만 대장으로 하고 내일은 다른 사람 시키자고 하는 것은 일관성이 없으므로 환자를 혼란스럽게 만들 수 있습니다.", "5": "좋아하는 드라마를 보자며 텔레비전을 틀어주는 것은 환자의 집중을 다른 곳으로 돌리는 효과적인 방법입니다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Đơn vị", "def_ko": "기관, 시설", "def_vi": "cơ sở, tổ chức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1586, '12', '치매 대상자가 큰 소리로 욕을 하며 의자를 던지려고 할 때 대처방법은?', '["신속하게 자리를 피한다.", "힘으로 제압하며 진정시킨다.", "방 안에 혼자 있게 하여 행동을 수정한다.", "화가 난 것을 이해 한다고 부드럽게 말한다.", "폭력적인 행동을 계속하면 퇴소시킨다고 경고한다."]'::jsonb, 4, '치매 대상자에게 적절한 대처 방법을 묻는 문제이다.', NULL, '{"1": "신속하게 자리를 피하는 것은 상황을 악화시킬 수 있다.\n[정답]", "4": "화가 난 것을 이해한다고 부드럽게 말하는 것은 치매 대상자의 감정을 인정하고 안정시킬 수 있다.", "2": "힘으로 제압하는 것은 폭력을 유발할 수 있으므로 바람직하지 않다.", "3": "혼자 있게 하는 것은 외롭고 두려움을 느끼게 할 수 있다.", "5": "퇴소 경고는 상황을 더욱 악화시킬 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고력의 약화로 인한 질병", "def_vi": "Bệnh do suy yếu trí nhớ và khả năng suy luận"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1585, '12', '치매 대상자가 흥분하여 탁자를 치며 난폭한 행동을 보일 때 대처방법은?', '["탁자를 다른 곳으로 치운다.", "힘으로 제압하여 행동을 제지한다.", "흥분이 가라앉을 때까지 지켜본다.", "정원으로 데리고 나가 안정시킨다.", "권위적이고 강압적인 태도로 경고한다."]'::jsonb, 4, '치매 대상자에게 적절한 대처 방법을 평가하는 문제입니다.', NULL, '{"1": "탁자를 다른 곳으로 치우는 것은 상황을 악화시킬 수 있습니다.\n[정답]", "4": "정원으로 데리고 나가 안정시키는 것이 가장 효과적인 방법입니다.", "2": "힘으로 제압하는 것은 더 큰 문제를 일으킬 수 있습니다.", "3": "흥분이 가라앉을 때까지 지켜보는 것은 위험할 수 있습니다.", "5": "권위적이고 강압적인 태도의 경고는 오히려 대상자의 불안을 증가시킬 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 인지 기능의 저하", "def_vi": "Sự suy giảm trí nhớ và khả năng nhận thức"}, {"term_ko": "흥분", "term_vi": "Hưng phấn", "def_ko": "감정이 격해지거나 뜨거워지는 상태", "def_vi": "Trạng thái cảm xúc tăng cao hoặc nóng nảy"}, {"term_ko": "난폭한", "term_vi": "Bạo lực", "def_ko": "폭력적이거나 통제되지 않는 상태", "def_vi": "Tình trạng bạo lực hoặc không thể kiểm soát"}, {"term_ko": "대처방법", "term_vi": "Phương pháp xử lý", "def_ko": "문제를 해결하기 위한 행동이나 방법", "def_vi": "Hành động hoặc phương pháp để giải quyết vấn đề"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1584, '12', '프로그램에 참여 중이던 치매 대상자가 흥분하여 갑자기 고함을 지르며 공격적인 행동을 할 때 대처방법은?', '["참여 중인 활동을 중지하고 다른 자극을 주지 않는다.", "스스로 화가 풀릴 때까지 그대로 둔다.", "모든 프로그램에서 제외시킨다고 경고한다.", "다른 프로그램을 진행하여 관심변화를 유도한다.", "진정된 후 대상자의 이상 행동을 상기시킨다."]'::jsonb, 1, '치매 대상자에게 적절한 대처방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "참여 중인 활동을 중지하고 다른 자극을 주지 않는다. (이 방법은 대상자가 흥분할 때 즉각적인 대처로 효과적입니다.)\n[정답]", "2": "스스로 화가 풀릴 때까지 그대로 둔다. (이 방법은 대상자를 방치하는 것이므로 바람직하지 않습니다.)", "3": "모든 프로그램에서 제외시킨다고 경고한다. (이 방법은 대상자의 불안감을 증가시킬 수 있습니다.)", "4": "다른 프로그램을 진행하여 관심변화를 유도한다. (대상자가 흥분했을 때 즉각적으로 다른 자극은 부적절할 수 있습니다.)", "5": "진정된 후 대상자의 이상 행동을 상기시킨다. (이 방법은 흥분 상태에서는 효과적이지 않으며, 이후에 조치하는 것이 좋습니다.)"}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자 또는 구성원", "def_vi": "Bệnh nhân hoặc thành viên"}, {"term_ko": "흥분", "term_vi": "Hưng phấn", "def_ko": "감정적으로 긴장한 상태", "def_vi": "Trạng thái cảm xúc căng thẳng"}, {"term_ko": "공격적인 행동", "term_vi": "Hành vi tấn công", "def_ko": "남을 해치거나 위협하는 행동", "def_vi": "Hành động gây hại hoặc đe dọa đến người khác"}, {"term_ko": "참여", "term_vi": "Tham gia", "def_ko": "어떤 활동에 참여함", "def_vi": "Tham gia vào một hoạt động"}, {"term_ko": "진정", "term_vi": "Trấn tĩnh", "def_ko": "마음이나 감정을 편안하게 만드는 것", "def_vi": "Làm dịu tâm trí hoặc cảm xúc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1583, '12', '치매 대상자가 시설에서 같은 방을 쓰는 동료 노인과 마주칠 때마다, 욕하고 화를 내며 매일 말싸움을 할 때 돕는 방법은?', '["단호한 어조로 제지한다.", "싸울 때마다 사과하게 한다.", "왜 그러는지 이유를 물어본다.", "퇴소할 수 있다고 경고한다.", "방을 바꾸어서 서로 마주치지 않게 한다."]'::jsonb, 5, '치매 대상자인 노인이 동료 노인과 마주칠 때 발생하는 갈등 상황을 해결하기 위한 적절한 대처 방안을 찾는 것이 문제의 핵심이다.', NULL, '{"1": "단호한 어조로 제지한다: 이 방법은 상황을 악화시킬 수 있으며, 대상자의 감정을 헤아리지 못하는 방식이다.\n[정답]", "5": "방을 바꾸어서 서로 마주치지 않게 한다: 이는 근본적인 문제 해결로, 서로 간의 갈등을 예방하는 방법이다.", "3": "왜 그러는지 이유를 물어본다: 대상자가 감정적으로 어려움을 겪고 있는 상황에서 이해를 요청하는 것은 불필요할 수 있다.", "4": "퇴소할 수 있다고 경고한다: 이는 대상자에게 위협을 주어 심리적 부담만 가중할 수 있다.", "2": "싸울 때마다 사과하게 한다: 이는 문제를 해결하기보다는 대처를 그르치는 결과를 초래할 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "질병(한국어)", "def_vi": "Bệnh thiếu trí nhớ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1582, '12', '치매 대상자에게 나타나는 파괴적 행동의 특징은?', '["매일 반복적으로 나타난다.", "질병 초기에 나타난다.", "에너지가 소모되어도 계속된다.", "수개월 이상 지속된다.", "치매 대상자 모두에게 나타나는 증상이다."]'::jsonb, 2, '치매 대상자의 파괴적 행동의 일반적인 특징을 심리적으로 이해하고, 어느 시기에 주로 나타나는지 알기 위한 문제이다.', NULL, '{"1": "매일 반복적으로 나타나는 것은 아닙니다. 치매에 따라 다르기 때문입니다.\n[정답]", "2": "질병 초기에 나타나는 특징으로 빈번하게 감지가 됩니다.", "3": "에너지가 소모되더라도 일시적일 수 있습니다.", "4": "수개월 이상 지속될 수도 있지만 개인차가 큽니다.", "5": "모든 치매 대상자에게 나타나는 증상은 아닙니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 인지 기능이 저하되는 상태", "def_vi": "Tình trạng suy giảm trí nhớ và chức năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1581, '12', '다음과 같은 치매 대상자의 문제행동 유형은?• 난폭한 행동이 자주 일어나지 않는다. • 난폭한 행동이 오래 지속되지 않는다. • 초기 분노 에너지가 소모되면 행동을 중지한다.', '["파괴적 행동", "망상", "배회", "석양증후군", "섬망"]'::jsonb, 1, '치매 대상자의 다양한 문제행동을 이해하고, 그 중에서 난폭한 행동의 특성을 파악하는 것이 의도임.', NULL, '{"1": "파괴적 행동: 난폭한 행동이 주된 특성이며, 이 문제의 설명에 부합함.\n[정답]", "2": "망상: 비현실적인 믿음이나 생각을 나타내는 행동이지만, 난폭한 행동과는 관련이 적음.", "3": "배회: 정처 없이 돌아다니는 행동으로, 문제에서 제시된 특성과 일치하지 않음.", "4": "석양증후군: 저녁에 더 심해지는 행동 양상으로, 여기서 설명하는 상황과 맞지 않음.", "5": "섬망: 혼란 상태를 의미하며, 난폭한 행동과는 구별되는 개념임."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 상실과 인지 기능 저하를 특징으로 하는 질병", "def_vi": "Bệnh có đặc trưng là mất trí nhớ và suy giảm chức năng nhận thức"}, {"term_ko": "난폭한", "term_vi": "Hung hăng", "def_ko": "주위나 사람에게 해를 끼치는 행동", "def_vi": "Hành vi gây hại cho người khác hoặc môi trường xung quanh"}, {"term_ko": "파괴적", "term_vi": "Phá hoại", "def_ko": "무언가를 부수거나 해치려는 성향", "def_vi": "Xu hướng muốn đập vỡ hoặc làm hại cái gì đó"}, {"term_ko": "망상", "term_vi": "Ảo giác", "def_ko": "비현실적인 믿음", "def_vi": "Niềm tin không thực tế"}, {"term_ko": "배회", "term_vi": "Lang thang", "def_ko": "방향 없이 돌아다니는 것", "def_vi": "Đi lang thang không có mục đích"}, {"term_ko": "석양증후군", "term_vi": "Hội chứng hoàng hôn", "def_ko": "저녁 시간에 나타나는 행동 양상", "def_vi": "Hành vi xảy ra vào buổi tối"}, {"term_ko": "섬망", "term_vi": "Rối loạn ý thức", "def_ko": "혼란 상태", "def_vi": "Tình trạng nhầm lẫn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1580, '12', '시설에서 생활하고 있는 치매 대상자가 다음과 같은 행동을 할 때 대처방법으로 옳은 것은?• 거실에 있는 의자가 자신의 것이라면서 다른 사람이 앉지 못하게 한다. • 다른 사람이 앉지 못하게 긴 의자를 혼자 차지하고 눕는다.', '["거실에 있는 의자를 없앤다.", "시설의 규칙을 단호하게 말한다.", "대상자를 거실에 나오지 못하게 한다.", "날짜를 지정하여 앉는 순서를 정한다.", "차분하게 대하고 다른 곳으로 관심을 유도한다."]'::jsonb, 5, '대상자의 행동을 이해하고 적절한 대처 방법을 선택할 수 있는 능력을 평가하기 위함입니다.', NULL, '{"1": "거실에 있는 의자를 없애는 것은 대상자의 기본 권리를 침해할 수 있습니다.\n[정답]", "5": "차분하게 대하고 다른 곳으로 관심을 유도하는 방법은 대상자의 감정을 조절하고 긍정적인 방향으로 풀어나가는 데 도움이 됩니다.", "2": "시설의 규칙을 단호하게 말하는 것은 오히려 대립을 초래할 수 있습니다.", "3": "대상자를 거실에 나오지 못하게 하는 것은 사회적 고립을 초래할 수 있습니다.", "4": "날짜를 지정하여 앉는 순서를 정하는 것은 특정한 규칙성을 가져오지만, 대상자의 상태에 따라 불리할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억, 사고, 행동의 변화로 인해 발생하는 증상", "def_vi": "Triệu chứng thay đổi về trí nhớ, suy nghĩ và hành vi"}, {"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "도움이 필요한 사람", "def_vi": "Người cần giúp đỡ"}, {"term_ko": "의자", "term_vi": "Ghế", "def_ko": "앉는 가구", "def_vi": "Đồ dùng ngồi"}, {"term_ko": "거실", "term_vi": "Phòng khách", "def_ko": "집의 한 부분", "def_vi": "Một phần của nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1579, '12', '치매 대상자가 자신의 양말을 다른 사람이 훔쳐갔다고 의심하며 화를 낼 때 대처방법은?', '["누가 가져갔다고 생각되는지 물어본다.", "나중에 찾아주겠다고 단호하게 말한다.", "같은 양말을 준비했다가 쉽게 찾을 수 있게 한다.", "아무도 가져간 사람이 없다고 차분하게 설명한다.", "물건을 찾아주고 훈계한다."]'::jsonb, 3, '치매 환자의 행동과 심리를 이해하고, 적절한 대처 방법을 선택하는 능력을 평가하고자 하는 문제입니다.', NULL, '{"1": "누가 가져갔다고 생각되는지 물어보는 것은 환자의 불안감을 증폭시킬 수 있습니다.\n[정답]", "3": "같은 양말을 준비했다가 쉽게 찾을 수 있게 하는 것은 환자의 불안감을 해소하는 효과적인 방법입니다.", "2": "나중에 찾아주겠다고 단호하게 말하는 것은 환자의 감정을 이해하지 못하는 것으로 비춰질 수 있습니다.", "4": "아무도 가져간 사람이 없다고 차분하게 설명하는 것은 환자의 현실 인식과 다를 수 있어, 효과적이지 않을 수 있습니다.", "5": "물건을 찾아주고 훈계하는 것은 환자에게 부정적인 감정을 유발할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억과 사고능력이 저하된 상태", "def_vi": "Tình trạng suy giảm trí nhớ và khả năng tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1578, '12', '치매 대상자가 도둑망상으로 자신의 방을 지키려고 고집을 부리는 경우 올바른 대처방법은?', '["도둑이 없다고 설득한다.", "귀중품은 맡겨 놓으라고 한다.", "위험하지 않으면 방에 있게 한다.", "화를 내며 방 밖으로 데리고 나간다.", "방 문을 잠그고 들어가지 못하게 한다."]'::jsonb, 3, '치매 환자의 도둑망상에 대한 적절한 대처 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "도둑이 없다고 설득하는 것은 오히려 환자의 불안감을 증가시킬 수 있습니다.\n[정답]", "3": "위험하지 않으면 방에 있게 하는 것이 환자의 자율성을 존중하고 불필요한 스트레스를 줄이는 방법입니다.", "2": "귀중품을 맡기라고 하는 것은 환자의 어려움을 이해하지 못한 대처 방식입니다.", "4": "화를 내며 방 밖으로 데리고 나가는 것은 환자에게 불안과 스트레스를 초래할 수 있습니다.", "5": "방 문을 잠그고 들어가지 못하게 하는 것은 환자의 안전을 위협하는 방법이 될 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력과 인지 기능의 감퇴가 나타나는 상태", "def_vi": "Tình trạng suy giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "도둑망상", "term_vi": "Ảo tưởng trộm cắp", "def_ko": "누군가가 자신을 훔치려 한다는 잘못된 믿음", "def_vi": "Niềm tin sai lầm rằng có người muốn ăn cắp của mình"}, {"term_ko": "고집", "term_vi": "Cố chấp", "def_ko": "고집스럽게 주장하거나 반대하지 않고 계속 유지하는 것", "def_vi": "Đòi hỏi một cách cứng rắn hoặc kiên trì không thay đổi"}, {"term_ko": "대처방법", "term_vi": "Cách ứng phó", "def_ko": "문제를 해결하기 위한 방법", "def_vi": "Phương pháp để giải quyết vấn đề"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1577, '12', '시설에서 치매 대상자가 같은 방을 쓰는 다른 대상자를 가리키며 다음과 같이 말할 때, 요양보호사의 대처방법은?대상자: 저 여편네는 참 뻔뻔스러워. 남의 집에 들어와 살면서 몇 달 째 월세를 안 내고 있어 요양보호사: ( )', '["못 들은 척 하면서 반응하지 않는다.", "누구한테 그런 말을 들었는지 확인한다.", "월세 납입증명서를 임의로 만들어 보여준다.", "시설에 있는 사실을 지속저긍로 인식시킨다.", "다른 대상자에게 귓속말로 ''신경 쓰지 마세요''라고 이야기 해준다."]'::jsonb, 4, '치매 대상자의 혼란을 이해하고 적절한 대응 방법을 제시하는 능력을 평가하고자 하는 의도이다.', NULL, '{"1": "특정 상황에서 반응하지 않는 것은 부적절한 대응이다.\n[정답]", "4": "시설에 있는 사실을 지속적으로 인식시켜주는 것이 치매 환자에게 적절한 대처 방법이다.", "2": "누가 그런 말을 했는지 확인하는 것은 상황 해결에 도움이 되지 않는다.", "3": "임의로 증명서를 보여주는 것은 신뢰를 떨어뜨릴 수 있다.", "5": "다른 대상자에게 조용히 이야기하는 것은 문제가 해결되지 않는다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고 능력의 저하 질환", "def_vi": "Bệnh suy giảm trí nhớ và khả năng tư duy"}, {"term_ko": "대처방법", "term_vi": "Phương pháp đối phó", "def_ko": "문제에 대한 응답 또는 해결책", "def_vi": "Câu trả lời hoặc giải pháp cho một vấn đề"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 전문인", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "혼란", "term_vi": "Sự nhầm lẫn", "def_ko": "불확실한 상태", "def_vi": "Tình trạng không chắc chắn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1576, '12', '치매 대상자에게 식사를 제공할 때, 다음과 같은 경우 대처방법으로 옳은 것은?대상자: 누가 나를 죽이려고, 내 밥에 농약을 넣었어. 안 먹어 요양보호사: ( )', '["왜 농약을 넣었다고 생각하세요?", "경찰서에 신고할까요?", "그래요? 누가 넣었는지 보셨어요?", "안 넣었으니까 안심하고 드세요.", "제가 먼저 먹어볼게요. 같이 드세요."]'::jsonb, 5, '치매 대상자의 불안감을 이해하고, 적절하게 대처하는 방법을 묻는 문제입니다.', NULL, '{"1": "왜 농약을 넣었다고 생각하세요? (대상자의 불안을 부추길 수 있는 질문입니다.)", "2": "경찰서에 신고할까요? (이 또한 대상자의 불안을 증가시킬 수 있습니다.)", "3": "그래요? 누가 넣었는지 보셨어요? (의심을 더욱 키우는 질문으로 잘못된 대처입니다.)\n[정답]", "4": "안 넣었으니까 안심하고 드세요. (대상자의 감정을 무시하고, 단순한 대답으로 심리적 안정을 주지 못합니다.)", "5": "제가 먼저 먹어볼게요. 같이 드세요. (이 행동은 대상자의 불안을 줄이고, 식사에 대한 신뢰를 주는 대처입니다.)"}'::jsonb, '[{"term_ko": "치매", "term_vi": "Người mất trí nhớ", "def_ko": "기억 상실과 인지 기능 저하", "def_vi": "Người có sự suy giảm trí nhớ và chức năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1575, '12', '치매 대상자가 갈비 굽는 냄새가 난다며 없는 갈비를 달라고 할 때 요양보호사의 대처방법은?', '["\"무슨 말씀이세요. 갈비는 없어요.\"", "\"조금 전에 같이 갈비 먹었잖아요.\"", "\"갈비가 드시고 싶군요. 함께 사러 나가요.\"", "\"있지도 않은 갈비 냄새가 어디서 난다고 그러세요?\"", "\"어제도 그러시더니 오늘 또 그러시네요.\""]'::jsonb, 3, '치매 환자의 감정이나 요구를 이해하고 올바르게 대처하는 방법을 평가하고자 함.', NULL, '{"1": "치매 환자의 필요를 무시하는 태도를 보임. 이는 오히려 상처를 줄 수 있음.", "2": "환자의 기억을 부정하여 혼란을 줄 수 있어 부적절함.\n[정답]", "3": "환자의 감정을 인정하고 함께 행동함으로써 긍정적인 대처가 됨.", "4": "치매 환자의 감정을 무시하는 태도를 보이며 부적절한 대처임.", "5": "같은 행동을 반복적으로 언급하여 환자를 혼란스럽게 할 수 있음."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 사고 능력에 장애가 있는 질병", "def_vi": "Bệnh gây cản trở khả năng nhớ và suy nghĩ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1574, '12', '치매 대상자가 자신의 지갑을 잃어버렸다며 의심할 때 대처방법은?', '["함께 경찰서에 가서 신고하자고 말한다.", "원래부터 지갑은 없었다고 인식시킨다.", "지갑에 돈을 얼마나 넣어두었는지 물어본다.", "평소에 지갑을 두는 장소로 같이 가서 찾아본다.", "지갑은 시설에서 보관하고 있다고 설명한다."]'::jsonb, 4, '치매 대상자가 잃어버린 물건에 대해 의심하는 상황에서 적절한 대처 방법을 묻는 것.', NULL, '{"1": "경찰서에 신고하는 것은 치매 환자에게 추가적인 스트레스를 줄 수 있다.\n[정답]", "4": "지갑을 두는 장소로 같이 가서 찾아보는 것은 치매 대상자의 기억을 자극하고 안정을 줄 수 있는 방법이다.", "2": "지갑이 없었다고 인식시키는 것은 환자의 현실 감각을 혼란스럽게 한다.", "3": "돈의 양을 묻는 것은 환자의 불안감을 증대시킬 수 있다.", "5": "시설에서 보관하고 있다고 설명하는 것은 환자의 불안감을 해소하지 못할 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억이나 인지 기능의 장애", "def_vi": "Rối loạn trí nhớ hoặc khả năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1573, '12', '치매 대상자가 자신의 반지를 누가 훔쳐 갔다며 의심할 때 대처방법은?', '["반지를 함께 찾아본다.", "남을 의심하시면 안 된다고 말한다.", "똑같은 반지를 사 주겠다고 다독인다.", "평소에 귀중품 두는 곳을 알려 달라고 한다.", "눈가 반지를 가져갔다고 생각하는지 물어본다."]'::jsonb, 1, '치매 대상자의 의심 증상에 대한 적절한 대처 방법을 이해하는 것.', NULL, '{"1": "치매 환자에게 반지를 함께 찾아본다고 하면 그들의 불안을 해소하는 데 도움을 줄 수 있다.\n[정답]", "2": "남을 의심하면 안 된다고 말하는 것은 오히려 환자의 감정을 상처받게 할 수 있다.", "3": "똑같은 반지를 사 주겠다고 다독이는 것은 일시적인 진정이 될 수 있지만 근본적인 문제 해결이 아니다.", "4": "평소 귀중품 두는 곳을 알려 달라고 하는 것은 환자가 불안함을 더 느낄 수 있는 방법이다.", "5": "눈가 반지를 가져갔다고 생각하는지 물어보는 것은 환자의 의심을 더 부추길 수 있는 접근이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 사고력을 잃는 병", "def_vi": "Bệnh mất khả năng ghi nhớ hoặc tư duy"}, {"term_ko": "대처", "term_vi": "Xử lý", "def_ko": "어떤 상황에 대한 반응이나 처리", "def_vi": "Phản ứng hoặc xử lý với một tình huống"}, {"term_ko": "의심", "term_vi": "Nghi ngờ", "def_ko": "의심하는 마음", "def_vi": "Tâm trạng nghi ngờ"}, {"term_ko": "반지", "term_vi": "Nhẫn", "def_ko": "손가락에 끼는 장신구", "def_vi": "Trang sức được đeo trên ngón tay"}, {"term_ko": "귀중품", "term_vi": "Đồ quý giá", "def_ko": "소중한 물건", "def_vi": "Những vật phẩm quý giá"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1572, '12', '망상증이 있는 치매 대상자가 아들이 내 퇴직금 통장을 가져갔어.라며 화를 낼 때 대처방법은?', '["아들에게 연락하여 확인한다.", "통장을 직접 찾아서 건네준다.", "아들은 그럴 사람이 아니라고 말한다.", "통장을 가져가는 것을 보았는지 물어본다.", "이야기를 들어 주며 속상하겠다고 다독인다."]'::jsonb, 5, '치매 환자에게서 나타날 수 있는 망상증에 대한 적절한 대처 방법을 묻는 문제입니다.', NULL, '{"1": "아들에게 연락하여 확인한다.\n상대방의 망상에 대해 직접적인 확인을 시도하는 것은 환자의 감정을 더 상하게 할 수 있습니다.\n\n[정답]", "5": "이야기를 들어 주며 속상하겠다고 다독인다.\n환자의 감정을 공감하고 듣는 것이 중요합니다.", "3": "아들은 그럴 사람이 아니라고 말한다.\n환자의 생각을 부정하는 것은 신뢰를 잃게 할 수 있습니다.", "4": "통장을 가져가는 것을 보았는지 물어본다.\n망상에 대한 추가 질문은 환자의 불안을 증대시킬 수 있습니다.", "2": "통장을 직접 찾아서 건네준다.\n환자의 요구를 즉시 충족시키는 것은 적절한 대처가 아닙니다."}'::jsonb, NULL);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1571, '12', '치매 대상자가 아무도 없는 창밖을 보면서 우리 아들 왔네! 엄마가 금방 나갈게. 라고 할 때 대처방법은?', '["\"밖에는 아무도 없어요.\" 라며 커튼을 친다.", "\"아들이 보고 싶군요.\" 라며 손을 잡아둔다.", "\"밖에 사람이 잇는지 눈을 크게 뜨고 보세요.\"라고 말한다.", "\"기력이 없으셔서 헛것이 보이는 거예요.\"라며 간식을 준다.", "\"아들을 지금 회사에서 일하고 있어요.\"라며 하던 일을 계속한다."]'::jsonb, 2, '치매 환자의 비현실적인 발언에 적절히 반응하여 불안을 줄이고 감정을 이해하는 방법을 묻는 문제입니다.', NULL, '{"1": ""}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "중증의 기억력 및 인지 기능 장애", "def_vi": "Rối loạn nghiêm trọng về trí nhớ và chức năng nhận thức"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "도움을 받는 사람", "def_vi": "Người nhận trợ giúp"}, {"term_ko": "대처방법", "term_vi": "Phương pháp ứng phó", "def_ko": "문제에 대처하는 방법", "def_vi": "Cách đối phó với vấn đề"}, {"term_ko": "간식", "term_vi": "Bánh nhẹ", "def_ko": "간단한 음식이나 간편한 음식을 가리킴", "def_vi": "Thức ăn nhẹ hoặc thực phẩm đơn giản"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1570, '12', '시설 치매대상자가 사무실로 뛰어 들어와 누군가 나를 잡으러 왔어.라며 책상 밑으로 숨을 때 대처방법은?', '["무슨 사건인지 이야기하게 한다.", "잡으러 온 사람이 누구인지 물어본다.", "책상 밑은 위험하다고 차분히 설명한다.", "시설에는 아무도 못들어온다고 말한다.", "이제 가고 없다며 안심시키고 같이 있어 준다."]'::jsonb, 5, '치매 대상자의 안전하고 안정된 대처 방법을 이해하고 평가하는 것.', NULL, '{"1": "무슨 사건인지 이야기하게 하여 상황을 진정시키고 이해시킬 수 있다.\n[정답]", "5": "이제 가고 없다며 안심시키고 같이 있어 주는 것이 최선의 방법이다.", "2": "잡으러 온 사람이 누구인지 물어보면 상황이 더욱 불안해질 수 있다.", "3": "책상 밑이 위험하다고 차분히 설명하는 것은 대상자가 듣지 못할 수 있다.", "4": "시설에는 아무도 못들어온다고 말하는 것은 신뢰를 떨어뜨릴 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억과 인지 기능이 저하되는 상태", "def_vi": "Tình trạng suy giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "사무실", "term_vi": "Văn phòng", "def_ko": "업무를 수행하는 공간", "def_vi": "Không gian làm việc"}, {"term_ko": "대처방법", "term_vi": "Cách ứng phó", "def_ko": "문제 상황에 대응하는 방법", "def_vi": "Phương pháp đối phó với tình huống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1569, '12', '치매 할아버지가 키가 작고 파마머리를 한 요양보호사만 보면 여보라고 부르며 따라 다닌다. 대처방법으로 옳은 것은?', '["(따뜻하게 손을 잡으며) \"할머니는 돌아가셨어요.\"", "(정색하며) \"할아버지 저는 할머니가 아니여요.\"", "(마주보며) \"할머니가 보고싶으신가 봐요.\"", "(웃으며) \"여보 불렀어요?\"", "(가까이 가서) \"제가 할머니로 보이세요?\""]'::jsonb, 3, '치매 환자의 의사소통과 감정적 지지를 이해하고 적절한 대처법을 선택하는 것이 중요하다.', NULL, '{"1": "(할아버지가 혼란스러워할 수 있으므로 부드럽게 설명하는 것이 좋지만, 감정적 지지를 제공하기보다는 직접적인 거부감이 생길 수 있다.)\n[정답]", "3": "(할아버지의 감정을 인정하며 대화를 시도하는 것이 가장 적절하다.)", "2": "(정색은 할아버지를 더 혼란스럽게 할 수 있으므로 바람직하지 않다.)", "4": "(웃음을 통해 상황을 넘길 수는 있지만, 할아버지의 감정을 소중히 여기는 것이 좋다.)", "5": "(제자리에 서 있으면서 할아버지를 더 혼란스럽게 만들 수 있다.)"}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력과 사고의 능력이 줄어드는 질병", "def_vi": "Căn bệnh giảm khả năng ghi nhớ và tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1568, '12', '시설 치매대상자가 자신의 집으로 가겠다며 소란을 피울 때 요양보호사의 반응으로 적절한 것은?', '["\"혼자서는 집에 못 가시잖아요.\"", "\"저기 앉아서 텔레비전 보세요.\"", "\"집에 가도 이제 아무도 없어요.\"", "\"어르신이 나가시면 제가 원장님께 혼나요.\"", "\"아들이 모시러 올 때까지 우리 퍼즐 맞춰요.\""]'::jsonb, 5, '치매 대상자에 대한 적절한 대응 및 소통 방법을 평가하고자 하는 문제입니다.', NULL, '{"1": "혼자서 집에 가기 어려운 상황을 설명하며 대화를 유도하려는 의도나 다소 부정적인 반응입니다.", "2": "치매 대상자의 관심을 다른 곳으로 돌리려는 시도지만, 효과적이지 않을 수 있습니다.", "3": "집에 아무도 없다는 이야기는 대상자의 감정을 상하게 할 수 있습니다.", "4": "원장님께 혼날 수 있다는 표현도 대상자에게 부정적인 감정을 유발할 수 있습니다.\n[정답]", "5": "아들이 올 때까지 함께 퍼즐을 맞추자는 제안은 대상자의 감정을 존중하고, 긴장을 완화시킬 수 있는 긍정적인 반응입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억 또는 사고 능력 감소로 인해 일상생활에 어려움이 있는 상태", "def_vi": "Tình trạng giảm khả năng nhớ hoặc tư duy gây khó khăn trong sinh hoạt hàng ngày"}, {"term_ko": "소란", "term_vi": "Sự ồn ào", "def_ko": "시끄럽고 분주한 상태", "def_vi": "Trạng thái ồn ào và bận rộn"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "상황에 대한 반응", "def_vi": "Phản ứng đối với một tình huống"}, {"term_ko": "퍼즐", "term_vi": "Đồ chơi ghép hình", "def_ko": "서로 맞춰야 하는 조각들로 이루어진 게임", "def_vi": "Trò chơi bao gồm các mảnh ghép cần phải khớp với nhau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1567, '12', '야간에 거실에서 배회하는 치매 대상자를 돕는 방법으로 옳은 것은?', '["새로운 방으로 바꾸어 준다.", "실내조명을 어둡게 하여 동선을 줄인다.", "실외에 배회 코스를 만들어 다녀오게 한다.", "현관문을 열어 신선한 공기를 마시게 한다.", "학창시절에 대한 이야기를 하며 추억을 나눈다."]'::jsonb, 5, '치매 대상자의 야간 배회 문제를 해결하기 위해 적절한 방법을 찾는 것이다.', NULL, '{"1": "새로운 방으로 바꾸어 준다: 치매 환자에게 새로운 환경은 혼란을 줄 수 있다. \n[정답]", "5": "학창시절에 대한 이야기를 하며 추억을 나눈다: 치매 환자와의 감정적 유대감을 높이는 데 도움이 된다.", "3": "실외에 배회 코스를 만들어 다녀오게 한다: 외부 환경이 위험할 수 있어 적절하지 않다.", "4": "현관문을 열어 신선한 공기를 마시게 한다: 안전상 문제가 될 수 있다.", "2": "실내조명을 어둡게 하여 동선을 줄인다: 어두운 환경은 불안감을 증가시킬 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억이나 사고 능력이 감퇴되는 상태", "def_vi": "Tình trạng suy giảm khả năng nhớ hoặc suy nghĩ"}, {"term_ko": "배회", "term_vi": "Đi lang thang", "def_ko": "정해진 장소를 벗어나 돌아다님", "def_vi": "Đi ra ngoài khu vực đã xác định"}, {"term_ko": "충분한", "term_vi": "Đầy đủ", "def_ko": "양이 많이 있음", "def_vi": "Có nhiều lượng"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태", "def_vi": "Tình trạng không có nguy hiểm"}, {"term_ko": "추억", "term_vi": "Kỉ niệm", "def_ko": "과거의 기억", "def_vi": "Kỷ niệm từ quá khứ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1566, '12', '치매 대상자가 남편 밥을 해줘야 한다며 집에 가야 돼.라고 말할 때 대처방법은?', '["\"저랑 같이 가실까요?\"라며 산책을 한다.", "\"남편은 식사했어요.\"라고 안심시킨다.", "\"아들이 와야 나가실 수 있어요.\"라고 말한다.", "\"이제는 어르신만 신경 쓰세요!\"라고 말한다.", "\"밖이 어두워져서 갈 수 없어요.\"라며 단념시킨다."]'::jsonb, 1, '치매 환자가 비현실적인 주장이나 요구를 할 때 적절하고 안전한 대처방법을 평가하는 것이 문제의 의도이다.', NULL, '{"1": "환자를 안심시키며 산책하는 것은 긍정적인 대처 방법이다.\n[정답]", "2": "''남편은 식사했어요.''라는 말은 사실을 기반으로 하지만, 안심시키는 방법으로 더 좋은 접근이 필요하다.", "3": "아들의 방문을 기다려야 한다고 말하는 것은 환자의 불안을 증가시킬 수 있다.", "4": "어르신만 신경 쓰라는 것은 환자의 감정을 무시한 표현으로 적절하지 않다.", "5": "밖이 어두워져서 간섭하는 것은 환자를 더 불안하게 할 수 있는 방법이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억을 잃고 정신적인 기능이 저하된 상태", "def_vi": "Tình trạng mất khả năng ghi nhớ và suy giảm chức năng tinh thần"}, {"term_ko": "대처방법", "term_vi": "Phương pháp đối phó", "def_ko": "상황에 따라 적절한 처치를 하는 방식", "def_vi": "Cách xử lý phù hợp trong từng tình huống"}, {"term_ko": "안심시키다", "term_vi": "Yên tâm", "def_ko": "걱정을 덜어 주고 안전감을 주다", "def_vi": "Giảm bớt lo lắng và mang lại cảm giác an toàn"}, {"term_ko": "신경 쓰다", "term_vi": "Chú ý", "def_ko": "주의하거나 염려하다", "def_vi": "Quan tâm hoặc lo lắng về điều gì đó"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1565, '12', '치매 대상자가 목적 없이 집 안의 이곳저곳을 배회할 때 대처방법은?', '["배회하지 못하게 주의를 준다.", "색칠하기 활동을 하게 한다.", "취침 직전에 운동량을 늘려 준다.", "증상이 사라질 때까지 기다려준다.", "밖으로 나가 집 주변을 걷게 한다."]'::jsonb, 2, '치매 대상자가 집 안에서 목적 없이 배회하는 상황에서 효과적인 대처 방법을 묻고 있다.', NULL, '{"1": "배회하지 못하게 주의를 준다.\n배회가 자연스러운 상태일 경우, 피해갈 수 없는 반응이기 때문에 주의를 주는 것은 효과적이지 않다.\n[정답]", "2": "색칠하기 활동을 하게 한다.\n색칠하기 활동은 집중력을 향상시키고 배회하는 행동을 줄이는 데 도움을 줄 수 있다.", "3": "취침 직전에 운동량을 늘려 준다.\n운동량을 늘리는 것은 수면에 도움이 될 수 있지만, 배회 행동을 직접적으로 감소시키지는 않는다.", "4": "증상이 사라질 때까지 기다려준다.\n단순히 기다리는 것은 반응적이지 않으며, 예방적 접근이 필요하다.", "5": "밖으로 나가 집 주변을 걷게 한다.\n밖으로 나가는 활동은 오히려 불안감을 증가시킬 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 상실증, 인지 장애를 초래하는 질병", "def_vi": "Bệnh gây ra sự suy giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "배회", "term_vi": "Đi lang thang", "def_ko": "목적 없이 돌아다니는 것", "def_vi": "Đi lại không có mục đích"}, {"term_ko": "주지", "term_vi": "Nhắc nhở", "def_ko": "주의하여 알려줌", "def_vi": "Nhắc nhở một cách chú ý"}, {"term_ko": "운동량", "term_vi": "Mức độ vận động", "def_ko": "신체 활동의 정도", "def_vi": "Mức độ hoạt động thể chất"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "병의 징후", "def_vi": "Dấu hiệu của bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1564, '12', '치매 대상자가 야간에 실내에서 계속 배회할 때 대처방법은?', '["따뜻한 녹차를 제공한다.", "이불과 베개를 새것으로 바꿔준다.", "실내조명을 끄고 침대에 눕게 한다.", "출입이 가능한 모든 곳의 문을 잠근다.", "빨래를 개면서 에너지를 소모하게 한다."]'::jsonb, 4, '치매 대상자가 야경을 배회하는 행동을 예방하고 안전하게 보호할 수 있는 방법을 묻는 문제입니다.', NULL, '{"1": "따뜻한 녹차를 제공하는 것은 이완 효과를 줄 수 있지만, 해결책이 아닙니다.\n[정답]", "4": "출입이 가능한 모든 곳의 문을 잠그는 것이 안전하게 보호할 수 있는 방법입니다.", "2": "이불과 베개를 새것으로 바꿔주는 것만으로는 문제를 해결할 수 없습니다.", "3": "실내조명을 끄고 침대에 눕게 하는 것은 오히려 불안감을 증대시킬 수 있습니다.", "5": "빨래를 개는 것은 에너지를 소모하게 할 수 있지만, 배회 행동을 예방하는 방법이 아닙니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억이나 인지 기능에 장애가 있는 상태", "def_vi": "Trạng thái rối loạn trí nhớ hoặc chức năng nhận thức"}, {"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "특정한 서비스를 받는 사람", "def_vi": "Người nhận dịch vụ cụ thể"}, {"term_ko": "야간", "term_vi": "Ban đêm", "def_ko": "밤 시간", "def_vi": "Thời gian vào ban đêm"}, {"term_ko": "배회", "term_vi": "Đi lang thang", "def_ko": "같은 곳을 이리 저리 돌아다니는 행동", "def_vi": "Hành vi di chuyển qua lại ở cùng một nơi"}, {"term_ko": "실내", "term_vi": "Trong nhà", "def_ko": "내부 공간", "def_vi": "Không gian nội bộ"}, {"term_ko": "출입", "term_vi": "Ra vào", "def_ko": "들어오고 나가는 것", "def_vi": "Vào và ra"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1563, '12', '야간에 배회하는 치매 대상자를 돕는 방법은?', '["침대 옆에 옷가지를 걸어 둔다.", "복잡한 일을 주어 집중하게 한다.", "집 안의 보행로를 따라 걷게 한다.", "실내조명을 어둡게 하여 동선을 줄인다.", "창문을 열어 신선한 공기를 마시게 한다."]'::jsonb, 3, '치매 환자가 야간에 배회할 때 적절한 도움 방법을 묻고 있습니다.', NULL, '{"1": "침대 옆에 옷가지를 걸어 두는 것은 효과적일 수 있지만, 환자가 혼란스러워질 수 있습니다.\n[정답]", "3": "집 안의 보행로를 따라 걷게 하는 것은 안정감을 제공하고 배회하는 것을 줄이는 데 도움을 줄 수 있습니다.", "2": "복잡한 일을 주어 집중하게 하는 것은 오히려 혼란을 유발할 수 있습니다.", "4": "실내조명을 어둡게 하여 동선을 줄이는 것은 안전에 좋지 않을 수 있습니다.", "5": "창문을 열어 신선한 공기를 마시게 하는 것은 도움이 되지만, 배회하는 행동을 직접적으로 해결하지는 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고 능력이 저하되는 질환", "def_vi": "Bệnh giảm trí nhớ và khả năng tư duy"}, {"term_ko": "배회", "term_vi": "Đi lang thang", "def_ko": "정해진 경로 없이 돌아다니는 것", "def_vi": "Đi lại mà không có lộ trình xác định"}, {"term_ko": "조명", "term_vi": "Ánh sáng", "def_ko": "빛을 제공하는 장치", "def_vi": "Thiết bị cung cấp ánh sáng"}, {"term_ko": "안정감", "term_vi": "Cảm giác an toàn", "def_ko": "편안함과 안전함을 느끼는 것", "def_vi": "Cảm giác thoải mái và an toàn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1562, '12', '프로그램에 참여하던 치매 대상자가 갑자기 일어나서 안절부절 못하며 배회할 때 대처방법은?', '["신체적 욕구가 있는지 확인한다.", "커튼을 쳐서 실내를 어둡게 한다.", "그대로 놔둔 채 프로그램을 진행한다.", "조용한 방으로 데려가 혼자 있게 한다.", "프로그램에 집중하라고 권유한다."]'::jsonb, 1, '치매 대상자가 프로그램 도중 불안 정서를 보일 때, 적절한 대처 방법을 아는 것이 중요하다.', NULL, '{"1": "신체적 욕구가 있는지 확인한다. - 치매 대상자가 불안해하는 이유를 파악하기 위해서는 이 방법이 중요하다.\n[정답]", "2": "커튼을 쳐서 실내를 어둡게 한다. - 밝은 환경에서 불안감이 증대할 수 있으므로 위험하다.", "3": "그대로 놔둔 채 프로그램을 진행한다. - 대처를 하지 않는 것은 바람직하지 않다.", "4": "조용한 방으로 데려가 혼자 있게 한다. - 혼자 두는 것은 더 불안감을 조성할 수 있다.", "5": "프로그램에 집중하라고 권유한다. - 치매 대상자의 불안은 강요로 해결될 수 없다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고 능력을 잃는 상태", "def_vi": "Tình trạng mất trí nhớ và khả năng suy nghĩ"}, {"term_ko": "불안", "term_vi": "Lo âu", "def_ko": "걱정이나 두려움을 느끼는 상태", "def_vi": "Trạng thái cảm thấy lo lắng hoặc sợ hãi"}, {"term_ko": "상황", "term_vi": "Tình huống", "def_ko": "특정한 여건이나 환경", "def_vi": "Điều kiện hoặc môi trường cụ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1561, '12', '프로그램에 참여하던 치매 대상자가 갑자기 일어나서 안절부절 못하며 배회할 때 대처방법은?', '["신체적 욕구가 있는지 확인한다.", "커튼을 쳐서 실내를 어둡게 한다.", "그대로 놔둔 채 프로그램을 진행한다.", "조용한 방으로 데려가 혼자 있게 한다.", "프로그램에 집중하라고 권유한다."]'::jsonb, 1, '치매 대상자의 행동 변화에 따른 적절한 대처 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "신체적 욕구가 있는지 확인한다. [정답] 치매 대상자가 불안해하는 경우 신체적 욕구가 있을 수 있으므로, 이를 확인하는 것이 중요합니다.", "2": "커튼을 쳐서 실내를 어둡게 한다. 실내를 어둡게 하는 것은 대상자가 불안감을 느끼게 할 수 있으며, 적절한 대처가 아닙니다.", "3": "그대로 놔둔 채 프로그램을 진행한다. 대상자의 행동을 무시하고 프로그램을 진행하는 것은 문제를 악화시킬 수 있습니다.", "4": "조용한 방으로 데려가 혼자 있게 한다. 혼자 있게 하는 것은 대상자가 더 외롭고 불안하게 느낄 수 있으므로 지양해야 합니다.", "5": "프로그램에 집중하라고 권유한다. 주의가 산만한 상태에서 집중하도록 요구하는 것은 부적절합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "노인성 치매(일반적으로 기억력이나 판단력이 저하되는 상태)", "def_vi": "Đặc điểm tình trạng giảm trí nhớ hoặc phán đoán của người già"}, {"term_ko": "프로그램", "term_vi": "Chương trình", "def_ko": "특정 목표를 위해 구성된 일련의 행위나 활동", "def_vi": "Chuỗi hành động hoặc hoạt động được tổ chức nhằm đạt được mục tiêu nhất định"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스나 지원을 받는 사람", "def_vi": "Người nhận dịch vụ hoặc hỗ trợ"}, {"term_ko": "배회", "term_vi": "Giao thông", "def_ko": "정해진 장소나 경로 없이 이리저리 돌아다님", "def_vi": "Đi vòng quanh mà không theo địa điểm hay lộ trình nhất định"}, {"term_ko": "안절부절", "term_vi": "Lo lắng", "def_ko": "불안한 마음으로 자리를 편안히 하지 못함", "def_vi": "Tâm trí không thoải mái, không thể ngồi yên"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1560, '12', '고향에 간다며 자주 주변을 돌아다니는 치매 대상자를 돕는 방법으로 옳은 것은?', '["시설의 주소와 전화번호를 외우게 한다.", "텔레비전을 크게 틀어 주어 집중하게 한다.", "대상자의 신분증은 보호자가 소지하게 한다.", "외출할 때 입을 겉옷을 문 입구에 걸어둔다.", "기관의 협조를 받아 사전에 지문을 등록해둔다."]'::jsonb, 5, '치매 대상자의 안전과 관리 방법을 이해하고 있는지를 평가하고자 함.', NULL, '{"1": "시설의 주소와 전화번호를 외우게 하는 것은 치매 대상자에게 어려울 수 있다.\n[정답]", "5": "기관의 협조를 받아 사전에 지문을 등록해두면, 대상자의 안전을 더욱 보장할 수 있다.", "2": "텔레비전을 크게 틀어 주는 것은 오히려 혼란을 줄 수 있다.", "3": "신분증을 보호자가 소지하게 하는 것은 필요할 수 있지만, 외출 시의 안전과는 관련이 없다.", "4": "입을 겉옷을 문 입구에 걸어두는 것은 정리가 필요하지만, 안전과는 연결되지 않는다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "알츠하이머병과 같은 인지기능 저하 질환", "def_vi": "Bệnh suy giảm chức năng nhận thức như bệnh Alzheimer"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1559, '12', '밤에 잠을 이루지 못하고 거실을 서성거리는 치매 대상자를 돕는 방법은?', '["산책을 원하면 다녀오게 한다.", "부족한 잠은 낮잠으로 보충하게 한다.", "낮 시간에 간단한 야외활동ㅇ르 하게 한다.", "저녁 식사 후 고강도 근력운동을 하게 한다.", "잠이 들기 전까지 좋아하는 드라마를 보게 한다."]'::jsonb, 3, '치매 대상자의 수면 패턴과 행동 관찰을 통해 적절한 개입 방법을 찾는 것이다.', NULL, '{"1": "산책을 원하면 다녀오게 한다: 치매 대상자가 원하는 활동을 허용하는 것은 좋지만, 밤에 야외활동은 위험할 수 있다.\n[정답]", "2": "부족한 잠은 낮잠으로 보충하게 한다: 낮잠을 통해 부족한 잠을 보충할 수 있으나, 낮잠이 너무 길면 밤에 더 잠을 이루기 어려울 수 있다.", "3": "낮 시간에 간단한 야외활동을 하게 한다: 낮 시간의 활동은 밤의 수면에 긍정적 영향을 미칠 수 있다.", "4": "저녁 식사 후 고강도 근력운동을 하게 한다: 고강도 운동은 오히려 수면을 방해할 수 있다.", "5": "잠이 들기 전까지 좋아하는 드라마를 보게 한다: 이는 수면을 방해할 수 있는 요소가 될 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고력이 감소하는 질병", "def_vi": "Bệnh giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "야외활동", "term_vi": "Hoạt động ngoài trời", "def_ko": "밖에서 하는 신체활동", "def_vi": "Hoạt động thể chất diễn ra bên ngoài"}, {"term_ko": "근력운동", "term_vi": "Tập thể dục sức mạnh", "def_ko": "근육을 강화하는 운동", "def_vi": "Bài tập giúp tăng cường cơ bắp"}, {"term_ko": "수면", "term_vi": "Giấc ngủ", "def_ko": "잠을 자는 상태", "def_vi": "Trạng thái ngủ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1558, '12', '최근에 입소한 치매 대상자가 2~3일 간 밤에 잠을 못 이룰 때 대처 방법은?', '["시설 규칙에 대해 설명한다.", "포만감을 느낄 수 있는 음식을 제공한다.", "누구에게나 적응 기간이 필요하다고 설명한다.", "취짐 전에 시원한 옥수수차를 충분히 마시게 한다.", "침대에 눕게 한 후에 가족에 대해 이야기를 나눈다."]'::jsonb, 5, '최근에 입소한 치매 대상자의 수면 문제를 해결하기 위한 적절한 대처 방법을 평가하는 문제입니다.', NULL, '{"1": "시설 규칙에 대해 설명하는 것은 가이드를 제공할 수 있지만, 수면 문제 해결에는 직접적인 도움이 되지 않습니다.\n[정답]", "5": "침대에 눕게 한 후 가족에 대해 이야기를 나누는 것은 안정감을 주어 수면에 도움을 줄 수 있습니다.", "2": "포만감을 느낄 수 있는 음식을 제공하는 것은 수면 문제 해결에 큰 영향이 없습니다.", "3": "누구에게나 적응 기간이 필요하다고 설명하는 것만으로는 적절한 대처가 되지 않습니다.", "4": "취침 전에 시원한 옥수수차를 마시게 하는 것은 수면에 도움을 줄 수 있으나, 가족 이야기를 나누는 것만큼 효과적이지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고력의 저하를 동반하는 질환", "def_vi": "Bệnh suy giảm trí nhớ và khả năng tư duy"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "도움이나 치료가 필요한 사람", "def_vi": "Người cần sự giúp đỡ hoặc điều trị"}, {"term_ko": "포만감", "term_vi": "Cảm giác no", "def_ko": "배가 찬 느낌", "def_vi": "Cảm giác dạ dày đầy"}, {"term_ko": "규칙", "term_vi": "Quy tắc", "def_ko": "정해진 법칙이나 원칙", "def_vi": "Những quy định hoặc nguyên tắc đã được thiết lập"}, {"term_ko": "안정감", "term_vi": "Cảm giác an toàn", "def_ko": "마음의 평온함", "def_vi": "Sự bình yên trong tâm hồn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1557, '12', '밤낮이 바뀐 치매 대상자의 수면을 돕는 방법으로 옳은 것은?', '["낮잠을 자는 동안 커튼을 쳐준다.", "취침 전에 따뜻한 녹차를 제공한다.", "낮에 졸고 있을 때 말을 걸지 않는다.", "수면 상태를 관찰하여 원인을 파악한다.", "포만감을 느낄 수 있도록 야식을 제공한다."]'::jsonb, 4, '치매 환자의 수면 문제와 적절한 대처 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "낮잠을 자는 동안 커튼을 쳐준다: 밤낮이 바뀐 환자에게 낮시간에 빛을 차단하는 것은 도움이 될 수 있으나, 이 방법은 직접적인 수면을 돕는 방법이 아닙니다.\n[정답]", "2": "취침 전에 따뜻한 녹차를 제공한다: 카페인 함량을 고려해 볼 때, 녹차는 수면을 방해할 수 있으므로 적절한 방법이 아닙니다.", "3": "낮에 졸고 있을 때 말을 걸지 않는다: 이 방법은 환자가 낮에 졸리지 않도록 하기 위한 노력에는 도움이 되지만, 수면 문제를 해결하는 데에는 도움이 되지 않습니다.", "4": "수면 상태를 관찰하여 원인을 파악한다: 수면 문제의 근본 원인을 이해하고 대처하기 위한 첫 단계로 매우 중요합니다.", "5": "포만감을 느낄 수 있도록 야식을 제공한다: 늦은 시간의 식사는 오히려 수면을 방해할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 및 사고 능력의 저하를 초래하는 질환", "def_vi": "Bệnh gây suy giảm khả năng nhớ và suy nghĩ"}, {"term_ko": "수면", "term_vi": "Giấc ngủ", "def_ko": "잠을 자는 상태", "def_vi": "Trạng thái ngủ"}, {"term_ko": "관찰", "term_vi": "Quan sát", "def_ko": "주의 깊게 살펴보는 것", "def_vi": "Việc nhìn hoặc xem một cách cẩn thận"}, {"term_ko": "원인", "term_vi": "Nguyên nhân", "def_ko": "어떤 일이 일어나는 이유", "def_vi": "Lý do cho những gì xảy ra"}, {"term_ko": "야식", "term_vi": "Đồ ăn vặt vào ban đêm", "def_ko": "밤에 주로 먹는 간단한 음식", "def_vi": "Thức ăn đơn giản thường ăn vào ban đêm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1556, '12', '치매 대상자가 갑자기 주머니에 있는 휴지를 먹는 증상은?', '["폭식증", "과식증", "이식증", "거식증", "금식증"]'::jsonb, 3, '치매와 관련된 행동을 이해하고, 잘못된 행동을 구별하기 위한 문제입니다.', NULL, '{"1": "폭식증: 일회에 많이 먹는 행동으로, 본 문제와 관련이 없습니다.\n[정답]", "3": "이식증: 비정상적으로 비식용 물질을 먹는 증상이며, 치매와 관련이 있습니다.", "2": "과식증: 일반적인 과식을 의미하며, 치매와는 관계가 없습니다.", "4": "거식증: 식사를 거부하거나 먹지 않는 증상으로, 반대 개념입니다.", "5": "금식증: 식사를 하지 않는 상태로, 역시 문제와 관련이 없습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 사고력의 기능이 저하되는 질환", "def_vi": "Là căn bệnh giảm chức năng ghi nhớ và suy nghĩ"}, {"term_ko": "주머니", "term_vi": "Túi", "def_ko": "물건을 담는 부분", "def_vi": "Phần chứa đồ vật"}, {"term_ko": "휴지", "term_vi": "Giấy vệ sinh", "def_ko": "냅킨이나 종이로 만든 것", "def_vi": "Vật làm bằng khăn giấy hoặc giấy"}, {"term_ko": "폭식증", "term_vi": "Chứng ăn uống quá độ", "def_ko": "저녁 대식증으로, 과도한 식사", "def_vi": "Ăn một cách thái quá"}, {"term_ko": "과식증", "term_vi": "Chứng ăn thái quá", "def_ko": "일반적인 먹는 양 이상의 식사", "def_vi": "Ăn nhiều hơn lượng bình thường"}, {"term_ko": "이식증", "term_vi": "Chứng ăn đồ không phải thực phẩm", "def_ko": "비식용 물질을 먹는 증상", "def_vi": "Triệu chứng ăn các vật không phải là thực phẩm"}, {"term_ko": "거식증", "term_vi": "Chứng biếng ăn", "def_ko": "식사를 거부하는 것이란 뜻", "def_vi": "Nghĩa là từ chối ăn"}, {"term_ko": "금식증", "term_vi": "Chứng nhịn ăn", "def_ko": "식사를 하지 않는 상태", "def_vi": "Trạng thái không ăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1555, '12', '치매 대상자가 밤중에 잠에서 깨어 베개 솜을 뜯어먹고 있을 때 대처방법은?', '["수면제를 먹인다.", "장갑을 끼고 잠을 자게 한다.", "가족에게 세 베개를 사 오게 한다.", "솜 베개 대신 두꺼운 수건을 베게 한다.", "먹으면 안 된다고 설명하고 다른 베개로 바꿔준다."]'::jsonb, 4, '치매 환자의 안전과 건강을 고려한 대처 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "수면제를 먹이는 것은 증상을 악화시킬 수 있습니다.\n[정답]", "4": "솜 베개 대신 두꺼운 수건을 베게 하는 것은 안전성을 높이고, 환자가 베개를 뜯어먹지 않도록 도와줍니다.", "2": "장갑을 끼고 잠을 자게 하는 것은 불편함을 초래할 수 있습니다.", "3": "가족에게 세 베개를 사 오게 하는 것은 문제를 해결하는 데 도움이 되지 않습니다.", "5": "먹으면 안 된다고 설명하는 것은 치매 환자에게 효과적이지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력과 사고 능력의 감소", "def_vi": "giảm trí nhớ và khả năng suy nghĩ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1554, '12', '치매 대상자가 조금 전 식사한 것을 잊어버리고 계속 음식을 요구할 때 대처방법은?', '["과식을 하면 건강에 해롭다고 설명한다.", "먹고 난 식기를 보이는 곳에 그대로 둔다.", "배가 고픈지, 먹고 싶은 간식이 있는지 물어본다.", "함께 식사한 다른 대상자로부터 확인을 받게 한다.", "음식을 계속 요구하면 식사 제공을 중단한다고 말한다."]'::jsonb, 2, '치매 환자 관리에 대한 이해 및 적절한 대처 방법을 묻기 위함입니다.', NULL, '{"1": "과식이 건강에 해롭다는 것은 사실이지만, 치매 환자에게 이를 설명하는 것은 효과적이지 않습니다. \n[정답]", "2": "식기를 보이는 장소에 두면 환자가 식사 후의 상황을 인식하는 데 도움이 됩니다.", "3": "배고픔을 확인하는 것은 중요하지만, 치매 환자는 자신의 상태를 정확히 이해하지 못할 수 있습니다.", "4": "다른 대상자의 확인은 환자에게 혼란을 줄 수 있습니다.", "5": "진행 중인 요구를 중단한다는 것은 부적절한 대처 방법이며, 환자를 더 혼란스럽게 할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고력이 상실되는 상태", "def_vi": "trạng thái mất khả năng nhớ và suy nghĩ"}, {"term_ko": "대처", "term_vi": "Phương pháp đối phó", "def_ko": "적절하게 대응하는 것", "def_vi": "cách đứng ra đáp ứng"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "일정한 시간에 음식을 섭취하는 것", "def_vi": "việc tiêu thụ thực phẩm vào thời gian nhất định"}, {"term_ko": "간식", "term_vi": "Đồ ăn nhẹ", "def_ko": "주식 이외의 가벼운 음식", "def_vi": "thực phẩm nhẹ ngoài thức ăn chính"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1553, '12', '수저 사용이 어려운 치매 대상자의 식사를 돕는 방법으로 옳은 것은?', '["음식을 갈아 빨대로 먹게 한다.", "식사를 마칠 때까지 먹여 준다.", "경관을 통해 영양액을 제공한다.", "수저를 사용해서 스스로 먹을 때까지 지켜본다.", "손으로 집어 먹을 수 있는 음식을 준비한다."]'::jsonb, 5, '치매 환자의 식사 보조 방법을 이해하고 올바른 방법을 선택할 수 있는 능력을 평가하기 위함입니다.', NULL, '{"1": "음식을 갈아 빨대로 먹게 하는 것은 대체 방법이지만, 치매 환자가 손으로 집어 먹는 경험을 통해 스스로 식사하는 것이 더 좋다.\n[정답]", "5": "손으로 집어 먹을 수 있는 음식을 준비하면 치매 환자가 스스로 먹는 데 도움을 줄 수 있다.", "2": "식사를 마칠 때까지 먹여 주는 것은 환자의 자율성을 떨어뜨리고 의존성을 높일 수 있다.", "3": "경관을 통해 영양액을 제공하는 것은 심각한 상황에 해당되며, 일반적인 식사 보조와는 다르다.", "4": "수저를 사용해서 스스로 먹을 때까지 지켜보는 것은 환자의 독립적인 식사 능력을 개발하는 데 도움이 되지만, 아예 수저 사용이 어려운 경우에는 적절하지 않다."}'::jsonb, '[{"term_ko": "수저", "term_vi": "Muỗng", "def_ko": "숟가락(한국어)", "def_vi": "thìa(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1552, '12', '치매 대상자가 제공된 음식을 못 먹고 쳐다보고만 있을 때 대처방법은?', '["식사할 때까지 옆에 계속 있어 준다.", "계속 거부하면 음식을 치운다고 한다.", "식사하는 방법을 순서대로 가르쳐 준다.", "식사를 거르면 건강에 해롭다고 설명한다.", "스스로 먹을 때까지 음식을 그대로 놔둔다."]'::jsonb, 3, '치매 대상자가 음식을 먹지 않고 쳐다보고 있는 상황에서 어떻게 대처해야 하는지를 묻는 문제입니다.', NULL, '{"1": "식사할 때까지 옆에 계속 있어 준다. - 이는 대상자가 긴장하지 않도록 도와줄 수 있으나, 직접적인 해결방법이 아닙니다.\n[정답]", "2": "식사하는 방법을 순서대로 가르쳐 준다. - 치매 대상자는 기억력이 떨어지기 때문에, 방법을 단계적으로 가르치는 것이 중요합니다.", "3": "계속 거부하면 음식을 치운다고 한다. - 이는 스트레스를 유발할 수 있으며, 권장되지 않습니다.", "4": "식사를 거르면 건강에 해롭다고 설명한다. - 이는 이해하기 어려운 설명일 수 있으며, 효과적이지 않습니다.", "5": "스스로 먹을 때까지 음식을 그대로 놔둔다. - 대상자의 자율성을 존중할 수 있지만, 적극적인 개입이 필요합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고에 영향을 주는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và suy nghĩ"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "도움을 받는 사람", "def_vi": "Người nhận sự giúp đỡ"}, {"term_ko": "대처방법", "term_vi": "Cách ứng phó", "def_ko": "해결책", "def_vi": "Giải pháp"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 것", "def_vi": "Sự ăn uống"}, {"term_ko": "거부", "term_vi": "Từ chối", "def_ko": "받아들이지 않음", "def_vi": "Không chấp nhận"}, {"term_ko": "건강", "term_vi": "Sức khoẻ", "def_ko": "신체와 정신의 상태", "def_vi": "Tình trạng thể chất và tinh thần"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1551, '12', '치매 대상자의 음식 섭취를 돕는 방법으로 옳은 것은?', '["배회가 있는 대상자는 섭취 열량을 줄인다.", "특정 음식을 좋아하면 계속 그 음식을 준다.", "배고픔을 호소할 때마다 음식을 충분히 준다.", "식사할 때 옆에 앉아서 생선 가시를 제거해 준다.", "치매 마리에는 갈거나 으깬 걸쭉한 음식을 준다."]'::jsonb, 5, '치매 대상자의 음식 섭취 방법에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "배회가 있는 대상자는 섭취 열량을 줄이기보다는 적절한 열량을 섭취할 수 있도록 도와야 합니다.\n[정답]", "2": "특정 음식을 좋아한다고 계속 그 음식을 주는 것은 편식을 유발할 수 있으므로 그 자체로 옳지 않습니다.", "3": "배고픔을 호소할 때마다 음식을 충분히 주는 것보다 조금씩 자주 주는 것이 더 좋습니다.", "4": "식사할 때 옆에 앉아 가시를 제거해 주는 것보다 스스로 먹을 수 있도록 돕는 것이 중요합니다.", "5": "치매 환자에게는 갈거나 으깬 걸쭉한 음식을 주어야 안전하게 섭취할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 상실과 같은 정신적 기능 저하", "def_vi": "Sự suy giảm chức năng tâm thần như mất trí nhớ"}, {"term_ko": "음식", "term_vi": "Thực phẩm", "def_ko": "먹을 것", "def_vi": "Thứ để ăn"}, {"term_ko": "섭취", "term_vi": "Tiêu thụ", "def_ko": "먹는 것", "def_vi": "Việc ăn uống"}, {"term_ko": "열량", "term_vi": "Năng lượng", "def_ko": "에너지의 단위", "def_vi": "Đơn vị năng lượng"}, {"term_ko": "갈다", "term_vi": "Xay", "def_ko": "잘게 부수다", "def_vi": "Nghiền nát"}, {"term_ko": "으깨다", "term_vi": "Nghiền", "def_ko": "부서뜨리다", "def_vi": "Nát"}, {"term_ko": "걸쭉한", "term_vi": "Đặc", "def_ko": "부드러운", "def_vi": "Đặc, mềm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1550, '12', '치매 대상자가 식사 때마다 음식을 지나치게 많이 먹을 때 대처방법은?', '["하루에 두 끼만 제공한다.", "반찬 가짓수를 줄여 제공한다.", "매 식사 후에 소화제를 제공한다.", "작은 그릇에 담아 식사량을 조절한다.", "쓴맛이 나는 재료를 음식에 섞어 제공한다."]'::jsonb, 4, '치매 대상자의 식사 관리 방법에 대한 이해 여부를 묻고 있다.', NULL, '{"1": "하루에 두 끼만 제공한다는 것은 영양 불균형을 초래할 수 있다.\n[정답]", "4": "작은 그릇에 담아 식사량을 조절하는 방법은 효과적이다.", "2": "반찬 가짓수를 줄여 제공하는 것은 영양 섭취에 좋지 않을 수 있다.", "3": "매 식사 후에 소화제를 제공하는 것은 근본적인 해결책이 아니다.", "5": "쓴맛이 나는 재료를 음식에 섞어 제공하는 것은 식욕을 떨어뜨릴 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력이나 사고 능력이 감소하는 질병", "def_vi": "Bệnh giảm trí nhớ hoặc khả năng suy nghĩ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1548, '12', '방금 식사를 마친 치매 대상자가 계속 밥을 달라고 할 때 반응으로 적절한 것은?', '["\"계속해서 식사를 달라고 하시니 제가 너무 힘들어요.\"", "\"다 드셨다고요! 요즘 들어 자주 깜빡깜빡하시네요.\"", "\"밥 대신 뻥튀기, 떡 중에서 무엇을 드릴까요?\"", "\"다음 식사를 준비하고 있으니 조금만 기다리세요.\"", "\"식사가 부족하셨군요. 식사량이 점점 늘고 있네요.\""]'::jsonb, 4, '치매 대상자에게 적절하게 반응하는 방법을 이해하기 위한 문제이다.', NULL, '{"1": "치매 대상자가 힘들다는 표현은 적절치 않다.\n[정답]", "4": "다음 식사를 준비 중임을 알리며 기다리게 하는 것이 적절하다.", "2": "대상자의 상태를 비하하는 표현이다.", "3": "대체 식품을 제안하는 것은 좋지 않다.", "5": "식사의 부족을 언급하는 것은 불필요한 혼란을 줄 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Chứng mất trí nhớ", "def_ko": "망각증(한국어)", "def_vi": "Mất trí nhớ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1547, '12', '치매 대상자가 누워만 있으려고 할 때 대처방법은?', '["대상자가 원하는 대로 누워있게 한다.", "누워만 있으려고 하는 이유를 물어본다.", "게으른 습관은 건강을 헤친다고 설명한다.", "대상자가 좋아하는 화분에 물을 주게 한다.", "주기적으로 환경을 바꾸어 기분을 전환해준다."]'::jsonb, 4, '치매 대상자의 행동에 대한 적절한 대처 방법을 이해하고 적용할 수 있는지 평가하기 위함입니다.', NULL, '{"1": "대상자가 원하는 대로 누워있게 하는 것은 장기적으로 건강에 좋지 않기 때문에 신중해야 합니다.\n[정답]", "4": "대상자가 좋아하는 화분에 물을 주는 것은 그들의 관심을 끌고 기분 전환을 도울 수 있는 좋은 방법입니다.", "2": "누워만 있으려고 하는 이유를 물어보는 것도 중요하지만, 즉각적인 대처 방법이 아닙니다.", "3": "게으른 습관이 건강에 나쁘다고 설명하는 것은 오히려 대상자에게 스트레스를 줄 수 있습니다.", "5": "주기적으로 환경을 바꾸는 것도 중요한 방법이지만, 구체적인 행동 지침으로서는 화분에 물 주기가 더 효과적일 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고력을 손상시키는 질병", "def_vi": "Bệnh làm suy giảm trí nhớ và khả năng tư duy"}, {"term_ko": "대상자", "term_vi": "Người nhận trợ giúp", "def_ko": "도움을 받는 사람", "def_vi": "Người cần nhận sự hỗ trợ"}, {"term_ko": "간호", "term_vi": "Chăm sóc", "def_ko": "환자에게 돌보는 행위", "def_vi": "Hành động chăm sóc cho bệnh nhân"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주변의 상태나 상황", "def_vi": "Tình trạng hoặc hoàn cảnh xung quanh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1546, '12', '치매 대상자가 신발장에 있는 신발을 모두 꺼내어 거실로 던지는 행동을 반복할 때 대처방법은?', '["\"어떤 신발을 찾길래 이러시는 거예요?\"", "\"신발을 거실에 던지시니 제가 너무 힘들어요!\"", "\"다 꺼내신 다음에는 다시 신발장에 넣으세요.\"", "\"꺼내놓은 신발 중에 안 신는 신발은 버릴게요.\"", "\"이 신발이 가장 예쁘네요. 이거 신고 함께 산책해요.\""]'::jsonb, 5, '치매 대상자의 행동에 대한 적절한 대처 방법을 알고 있는지를 평가한다.', NULL, '{"1": "치매 환자의 신발에 대한 관심을 유도하는 질문이지만, 오히려 혼란을 줄 수 있다.\n[정답]", "5": "신발에 대한 긍정적인 반응을 보임으로써 환자의 행동을 안정시키고 친밀감을 형성할 수 있다.", "2": "감정적으로 반응하여 상황을 악화시킬 수 있다.", "3": "환자에게 불가능한 요구를 하고 있어 효과적이지 않다.", "4": "부정적인 과정을 포함하고 있어 환자에게 상처를 줄 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 인지 기능의 저하로 인한 상태", "def_vi": "Trạng thái suy giảm trí nhớ và chức năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1545, '12', '시설 치매대상자가 우리 며느리가 나 데리러 언제 와?라며 반복적으로 물을 때 대처방법은?', '["물을 때마다 며느리와 통화하게 한다.", "방금 왔다 갔으니 기억해보라고 한다.", "여기가 집이니 며느리를 기다리지 말라고 한다.", "며느리를 기다리도록 문 앞에 의자를 놓아 준다.", "달력에 적힌 며느리의 방문 일정을 보이며 알려준다."]'::jsonb, 5, '치매 대상자의 반복적인 질문에 적절하게 응답하는 방법을 이해하는 것이 중요하다.', NULL, '{"1": "며느리와 통화하게 하는 것은 환자의 불안감을 증가시킬 수 있다.\n[정답]", "5": "달력에 적힌 며느리의 방문 일정을 보이며 알려주는 것은 환자의 인지적 능력을 활용하여 안정감을 줄 수 있다.", "2": "방금 왔다는 말을 하면 환자가 혼란스러워 할 수 있다.", "3": "여기가 집이라고 말하는 것은 환자의 감정을 무시하는 것일 수 있다.", "4": "문 앞에 의자를 놓는 것은 효과적일 수 있지만, 근본적인 질문에 대한 대답이 아니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 인지에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1544, '12', '치매 대상자가 자신이 좋아하는 꽃무늬 스웨터를 접었다 폈다 하면서 잠을 자지 않을 때 대처방법은?', '["수건으로 바꾸어 주고 계속하게 한다.", "세탁해 주겠다며 스웨터를 가져간다.", "스웨터를 입고 자자며 다독인다.", "그런 행동을 하는 이유를 물어본다.", "늦었으니 내일 다시 하라고 한다."]'::jsonb, 3, '치매 환자에게 안정감을 주고 긍정적인 대처방법을 찾는 것이 중요함을 묻는 문제입니다.', NULL, '{"1": "수건으로 바꾸어 주고 계속하게 한다. - 수건으로 대체하는 것은 오히려 혼란을 줄 수 있습니다.\n[정답]", "3": "스웨터를 입고 자자며 다독인다. - 환자의 감정을 이해하고 안정감을 주는 방법입니다.", "2": "세탁해 주겠다며 스웨터를 가져간다. - 환자의 소중한 물건을 없애는 것은 좋지 않은 방법입니다.", "4": "그런 행동을 하는 이유를 물어본다. - 치매 환자는 이유를 잘 설명하기 어렵습니다.", "5": "늦었으니 내일 다시 하라고 한다. - 환자의 현재 요구를 무시하는 것이므로 부적절한 대처입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 사고 기능이 저하된 상태", "def_vi": "Trạng thái suy giảm trí nhớ hoặc khả năng tư duy"}, {"term_ko": "대처방법", "term_vi": "Phương pháp đối phó", "def_ko": "문제를 해결하기 위한 방법", "def_vi": "Cách để giải quyết vấn đề"}, {"term_ko": "안정감", "term_vi": "Cảm giác an toàn", "def_ko": "마음이 편안한 느낌", "def_vi": "Cảm giác bình an trong tâm trí"}, {"term_ko": "다독이다", "term_vi": "An ủi", "def_ko": "부드럽게 말하며 위로하다", "def_vi": "Nói nhẹ nhàng để khuyến khích"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1543, '12', '치매 대상자가 반복적으로 수건을 접었다 폈다 하며 콧노래를 할 때 대처방법은?', '["접고 있는 수건을 치운다.", "콧노래를 그만하라고 한다.", "왜 반복 행동을 하는지 물어본다.", "중단시키지 말고 조용히 지켜본다.", "안 보이는 곳에 가서 하라고 한다."]'::jsonb, 4, '치매 대상자의 행동에 대한 적절한 대처 방법을 이해하고 평가하기 위함입니다.', NULL, '{"1": "대상자가 반복적인 행동을 통해 안정감을 찾는 경우가 많으므로 수건을 치우는 것은 좋지 않습니다.\n[정답]", "4": "반복적인 행동은 때로 치매 환자에게 도움이 될 수 있으므로 중단시키기보다는 조용히 지켜보는 것이 바람직합니다.", "2": "치매 대상자에게 명령조로 이야기를 하는 것은 스트레스를 줄 수 있습니다.", "3": "대화가 잘 통하지 않는 치매 환자에게 물어보는 것은 의미가 없습니다.", "5": "이런 행동을 피하게 하려는 방법은 오히려 대상을 더욱 불안하게 만들 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 인지능력의 감소를 동반한 질병", "def_vi": "Bệnh gây suy giảm trí nhớ và khả năng nhận thức"}, {"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "반복", "term_vi": "Lặp lại", "def_ko": "같은 행동을 여러 번 하는 것", "def_vi": "Làm cùng một hành động nhiều lần"}, {"term_ko": "대처 방법", "term_vi": "Phương pháp ứng xử", "def_ko": "문제를 해결하기 위한 방법", "def_vi": "Cách giải quyết vấn đề"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1542, '12', '치매 대상자가 혼잣말을 하면서 책상을 계속 두드릴 때 대처방법은?', '["관심을 두지 않고 자리를 피한다.", "책상을 두드리는 이유를 물어본다.", "책상이 부서질 수 있다고 주의 준다.", "손뼉을 치며 좋아하는 노래를 함께 부른다.", "다른 어르신이 불편하니 조용히 하라고 한다."]'::jsonb, 4, '치매 환자가 혼잣말을 하면서 책상을 두드리는 행동은 불안감이나 스트레스의 표현일 수 있다. 이러한 행동에 대해 긍정적인 반응을 통해 환자의 감정을 안정시키려고 하는 방법을 묻고 있다.', NULL, '{"1": "환자의 행동을 무시하고 자리를 피하는 것은 바람직하지 않다. 직접적인 대화나 활동이 없으면 환자에게 고립감을 줄 수 있다.\n[정답]", "4": "손뼉을 치며 좋아하는 노래를 함께 부르는 것은 환자의 행동에 긍정적으로 반응하고, 공동의 활동을 통해 소통을 시도하는 방법이다.", "3": "책상이 부서질 수 있다고 주의 주는 것은 환자를 더욱 불안하게 만들 수 있다.", "5": "다른 어르신이 불편하니 조용히 하라고 하는 것은 환자를 배제하는 느낌을 줄 수 있으므로 좋지 않다.", "2": "책상을 두드리는 이유를 물어보는 것은 좋으나, 환자가 그 이유를 잘 설명하지 못할 수 있기 때문에 더 적절한 대처가 필요하다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억과 사고를 잃는 상태", "def_vi": "Trạng thái mất khả năng nhớ và suy nghĩ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1541, '12', '재가 치매대상자의 환경을 안전하게 관리하는 방법은?', '["다른 사람의 눈에 잘 띄지 않는 방으로 배정한다.", "노출된 온수파이프는 주방용 랩으로 감싸 둔다.", "냉장고에 과일 모양의 자석을 붙여 놓는다.", "유리그릇은 보관장에 넣고 보관장을 잠가 둔다.", "음식물이 담긴 쓰레기봉투는 부엌 안쪽에 둔다."]'::jsonb, 4, '재가 치매대상자의 환경을 안전하게 관리하기 위한 방법을 묻는 문제입니다.', NULL, '{"1": "다른 사람의 눈에 잘 띄지 않는 방으로 배정하는 것은 치매 대상자의 안전성을 높이지 않습니다.\n[정답]", "2": "노출된 온수파이프는 주방용 랩으로 감싸 두어 물리적 상해를 예방할 수 있습니다.", "3": "냉장고에 과일 모양의 자석을 붙여놓는 것은 안전과 관련성이 낮습니다.", "4": "유리그릇은 보관장에 넣고 보관장을 잠가 두는 것이 치매대상자의 안전을 위해 필요합니다.", "5": "음식물이 담긴 쓰레기봉투를 부엌 안쪽에 두는 것은 악취 및 위생 문제를 야기할 수 있습니다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Tại nhà", "def_ko": "가정에서 제공되는 돌봄", "def_vi": "Chăm sóc được cung cấp tại nhà"}, {"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억 상실증", "def_vi": "Rối loạn trí nhớ"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주위 상태", "def_vi": "Trạng thái xung quanh"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태", "def_vi": "Tình trạng không có nguy hiểm"}, {"term_ko": "유리", "term_vi": "Thủy tinh", "def_ko": "깨지기 쉬운 재료", "def_vi": "Vật liệu dễ vỡ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1540, '12', '중증 치매대상자의 욕실을 안전하게 조성하는 방법은?', '["높이가 높은 욕조를 설치한다.", "온수기의 온도를 40도 이상 높여 놓는다.", "욕실에 문턱을 만들어 물이 넘치지 않게 한다.", "비누는 사용하기 쉽게 눈에 잘 띄는 곳에 둔다.", "거울에 덮개를 씌워 자신의 모습을 보고 놀라지 않게 한다."]'::jsonb, 5, '중증 치매 대상자의 안전한 욕실 환경 조성을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "높이가 높은 욕조는 위험할 수 있어 적절하지 않습니다.", "2": "온수기의 온도를 40도 이상 높이면 화상의 위험이 있습니다.", "3": "문턱이 있으면 넘어질 위험이 커질 수 있습니다.\n[정답]", "4": "비누는 사용하기 쉽게 눈에 잘 띄는 곳에 두는 것이 중요합니다.", "5": "거울에 덮개를 씌우는 것은 자신을 보고 놀라지 않게 할 수 있습니다."}'::jsonb, '[{"term_ko": "중증", "term_vi": "치매", "def_ko": "중증(Trung bình nặng)", "def_vi": "치매(Bệnh sa sút trí tuệ)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1539, '12', '낙상 우려가 있는 치매 대상자의 안전사고 예방을 위한 방법은?', '["밤에는 화장실 전등을 꺼둔다.", "복용하는 약은 식탁 위에 놓는다.", "방과 거실 사이에 단차를 설치한다.", "현관에 안 신는 신발을 놓아둔다.", "침대보다는 바닥에 요와 이불을 깔아 둔다."]'::jsonb, 5, '낙상 우려가 있는 치매 대상자의 안전을 확보하기 위한 방안 탐색.', NULL, '{"1": "밤에는 화장실 전등을 꺼두면 어둠으로 인해 낙상 위험이 커진다.\n[정답]", "5": "바닥에 요와 이불을 깔아 두면 침대에서 떨어지는 낙상을 예방할 수 있다.", "2": "복용하는 약을 식탁 위에 두면 치매 환자가 약을 놓칠 수 있어 위험하다.", "3": "방과 거실 사이에 단차를 설치하면 오히려 걸려 넘어질 위험이 있다.", "4": "현관에 안 신는 신발을 둔다면 신고 나가는 데 어려움을 겪을 수 있다."}'::jsonb, '[{"term_ko": "낙상", "term_vi": "치매", "def_ko": "낙하(우려) - ngã: nguy cơ ngã", "def_vi": "기억 상실증 - sa sút trí tuệ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1538, '12', '치매 대상자의 일상생활이 안전하도록 돕는 방법으로 옳은 것은?', '["방을 화려하고 다양하게 꾸민다.", "밤에도 낮처럼 환하게 불을 켜 둔다.", "난간, 출입구 등을 같은 색으로 칠한다.", "대상자의 눈높이에 맞추어 ''화장실'' 표시를 한다.", "현관 앞에 이동이 가능한 매트를 깔아 놓는다."]'::jsonb, 4, '치매 대상자의 일상생활에서 안전을 보장하기 위한 적절한 방법을 찾는 것', NULL, '{"1": "방을 화려하고 다양하게 꾸미면 오히려 혼란을 일으킬 수 있다.\n[정답]", "2": "밤에도 낮처럼 환하게 불을 켜 둬야 시각적인 안전이 확보된다.", "3": "난간이나 출입구를 같은 색으로 칠하면 구분하기 어려워질 수 있다.", "4": "대상자의 눈높이에 맞추어 ''화장실'' 표시를 하는 것은 인지적 도움을 준다.", "5": "현관 앞에 이동이 가능한 매트를 깔아 두면 넘어지는 사고를 유발할 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 및 사고 기능에 문제가 있는 상태", "def_vi": "Trạng thái có vấn đề về trí nhớ và chức năng suy nghĩ"}, {"term_ko": "일상생활", "term_vi": "Cuộc sống hàng ngày", "def_ko": "매일 하는 일", "def_vi": "Những công việc hằng ngày"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험을 방지하는 상태", "def_vi": "Trạng thái ngăn ngừa nguy hiểm"}, {"term_ko": "눈높이", "term_vi": "Tầm mắt", "def_ko": "시각의 높이", "def_vi": "Độ cao của thị giác"}, {"term_ko": "표시", "term_vi": "Biển hiệu", "def_ko": "알아볼 수 있도록 나타내는 것", "def_vi": "Cách thể hiện để nhận biết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1537, '12', '재가 치매대상자의 안전을 고려한 주거환경 관리 방법은?', '["현관문을 열어 대상자가 자유롭게 출입하게 한다.", "화장실 문은 밖에서도 열 수 있는 것으로 설치한다.", "방 안이 따뜻하도록 대상자 옆에 난로를 켜둔다.", "방에 큰 거울을 두어 자신의 모습을 인식하게 한다.", "현관 출입문은 투명한 유리로 설치하여 밖이 잘 보이게 한다."]'::jsonb, 2, '재가 치매대상자의 안전을 확보하기 위한 주거환경 관리 방법을 이해하고 적용할 수 있는지를 평가하는 문제입니다.', NULL, '{"1": "현관문을 열어 대상을 자유롭게 출입하게 하는 것은 안전을 위협할 수 있습니다.\n[정답]", "2": "화장실 문을 밖에서도 열 수 있는 것으로 설치하면 긴급상황 시 신속하게 대처할 수 있습니다.", "3": "방 안이 따뜻하도록 난로를 켜두면 화재의 위험성이 높아집니다.", "4": "방에 큰 거울을 두면 혼란을 유발할 수 있습니다.", "5": "현관 출입문을 투명한 유리로 설치하면 외부의 자극으로 인해 불안감을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Tại gia", "def_ko": "집에서 돌보는 것", "def_vi": "Chăm sóc tại nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1536, '12', '치매 대상자의 환경을 안전하게 조성하는 방법은?', '["가스선의 중간 밸브는 열어둔다.", "자극을 받지 않도록 차 안에서는 창문을 열어둔다.", "지남력 지원을 위해 시계, 달력, 가족사진을 가까이에 둔다.", "치매 대상자의 기능적인 손상을 고려하여 환경을 수시로 바꾼다.", "언어의 이해가 떨어지면, 그림보다는 글로 쓰인 단서를 사용한다."]'::jsonb, 3, '치매 대상자를 위한 안전한 환경 조성의 중요성을 이해하고 제대로 된 방법을 선택하도록 유도하는 문제입니다.', NULL, '{"1": "가스선의 중간 밸브를 열어두는 것은 안전하지 않은 환경을 조성할 수 있습니다.", "2": "자극을 받지 않도록 차 안에서 창문을 여는 것은 오히려 위험할 수 있습니다.\n[정답]", "3": "지남력 지원을 위해 시계, 달력, 가족사진을 가까이에 두는 것은 치매 대상자에게 도움이 되는 안전한 환경을 제공합니다.", "4": "치매 대상자의 기능적인 손상을 고려하여 환경을 수시로 바꾸는 것은 혼란을 증대시킬 수 있습니다.", "5": "언어의 이해가 떨어지면, 그림보다는 글로 쓰인 단서를 사용하는 것은 오히려 이해를 어렵게 할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 인지 기능의 저하로 일어나는 질환", "def_vi": "Bệnh gây suy giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "지남력", "term_vi": "Khả năng định hướng", "def_ko": "시간, 장소, 사람 등을 인식하는 능력", "def_vi": "Khả năng nhận thức về thời gian, địa điểm, và con người"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "둘러싼 물리적 상태나 주변", "def_vi": "Tình trạng vật lý xung quanh hoặc môi trường"}, {"term_ko": "가족사진", "term_vi": "Hình ảnh gia đình", "def_ko": "가족의 사진", "def_vi": "Ảnh của gia đình"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1535, '12', '치매 대상자의 운동 돕기 방법으로 옳은 것은?', '["모든 종류의 운동을 선택한다.", "균형을 잡을 수 있으면 앉아서 운동한다.", "운동은 심장에서 가까운 쪽부터 시작한다.", "매일 같은 시간대에 운동한다.", "운동하면서 대상자와 친숙해진다."]'::jsonb, 4, '치매 대상자의 운동을 돕는 올바른 방법을 평가하기 위한 질문입니다.', NULL, '{"1": "모든 종류의 운동을 선택하는 것은 부적절합니다. 대상자의 상태에 맞는 운동을 해야 합니다.\n[정답]", "4": "매일 같은 시간대에 운동하는 것은 일관성을 제공하여 정신적 안정감을 주며 좋습니다.", "3": "운동은 심장에서 먼 쪽부터 시작하는 것이 일반적입니다. 이는 심리적 안전을 보장하는 방법입니다.", "5": "운동 중 친숙해지는 것은 중요하지만 운동 방법 그 자체를 묻고 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Người bị sa sút trí tuệ", "def_ko": "기억과 사고를 방해하는 질병", "def_vi": "Bệnh nhân bị ảnh hưởng đến trí nhớ và nhận thức"}, {"term_ko": "운동", "term_vi": "Vận động", "def_ko": "신체를 움직이는 활동", "def_vi": "Hoạt động di chuyển cơ thể"}, {"term_ko": "균형", "term_vi": "Cân bằng", "def_ko": "몸의 안정적인 상태", "def_vi": "Tình trạng ổn định của cơ thể"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "보살핌을 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "시간대", "term_vi": "Khoảng thời gian", "def_ko": "특정 시간", "def_vi": "Thời gian cụ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1534, '12', '치매 대상자의 운동을 돕는 방법은?', '["걷는 시간을 서서히 늘린다.", "산책로를 자주 바꾸어 걷게 한다.", "숨을 쉬기 힘들어 하면 쉬었다가 운동하게 한다.", "팔다리 관절을 빠르게 움직이며 운동하게 한다.", "심장병 대상자에게는 계단 오르내리기를 시킨다."]'::jsonb, 1, '치매 대상자의 운동을 효율적으로 도와주는 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "걷는 시간을 서서히 늘리는 것은 치매 환자에게 적절한 운동 강도를 유지하는 데 도움이 된다.\n[정답]", "2": "산책로를 자주 바꿔서 걷게 하는 것은 혼란을 초래할 수 있어 피해야 한다.", "3": "숨을 쉬기 힘들어 하면 쉬었다가 운동하게 하는 것은 사실이지만, 운동 지속성을 감소시킬 수 있다.", "4": "팔다리 관절을 빠르게 움직이는 것은 오히려 치매 대상자에게 부담을 줄 수 있다.", "5": "심장병 대상자에게 계단 오르내리기를 시키는 것은 치매 환자에게 적절하지 않다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고에 영향을 미치는 질환", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1533, '12', '치매 대상자의 옷을 갈아입히는 방법으로 옳은 것은?', '["선 자세에서 옷을 갈아입힌다.", "옷 입는 시간이 걸리면 전부 입혀준다.", "앞뒤를 구분하지 못하면 환자복을 입힌다.", "순서대로 못 입을 경우 겉옷부터 차례로 놓아둔다.", "갈아입기를 거부하면 목욕 시간을 이용한다."]'::jsonb, 5, '치매 대상자에게 옷을 갈아입히는 올바른 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "선 자세에서 옷을 갈아입히는 것은 불안정할 수 있으므로 권장하지 않다.\n[정답]", "5": "갈아입기를 거부하면 목욕 시간을 이용해 편하게 옷을 입힐 수 있도록 하는 것이 올바른 방법이다.", "2": "옷 입는 시간이 걸린다고 해서 전부 입혀주는 것은 환자의 자립성을 무시하는 것이다.", "3": "앞뒤를 구분하지 못하는 환자에게는 환자복을 입히기보다 가능한 한 쉽게 입힐 수 있는 방법을 사용해야 한다.", "4": "순서대로 입혀주지 못하고 겉옷부터 놓는 것은 환자가 혼란스러울 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력, 사고력 등이 저하되는 증상", "def_vi": "Triệu chứng suy giảm trí nhớ, tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1532, '12', '치매 대상자의 옷 갈아입기를 돕는 방법으로 옳은 것은?', '["계절과 무관한 옷을 입힌다.", "장식이 많이 달린 옷을 입힌다.", "무늬가 화려한 옷을 입힌다.", "시간이 걸려도 혼자 입도록 격려한다.", "단추를 채우지 못하면 지퍼가 달린 옷을 입힌다."]'::jsonb, 4, '치매 대상자에게 적절한 옷 갈아입기 방법을 이해하는 것이 중요하다.', NULL, '{"1": "계절과 무관한 옷을 입힌다: 치매 환자는 계절에 맞는 옷을 입는 것이 좋다.\n[정답]", "4": "시간이 걸려도 혼자 입도록 격려한다: 자율성을 높이고 스스로 할 수 있도록 지지하는 것이 올바른 방법이다.", "2": "장식이 많이 달린 옷을 입힌다: 장식이 많은 옷은 혼란을 초래할 수 있다.", "3": "무늬가 화려한 옷을 입힌다: 화려한 무늬는 인식에 방해가 될 수 있다.", "5": "단추를 채우지 못하면 지퍼가 달린 옷을 입힌다: 단추가 아닌 지퍼의 경우도 어려움이 있을 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력과 인지 기능의 장애", "def_vi": "Rối loạn trí nhớ và chức năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1531, '12', '치매 대상자의 옷 입기를 돕는 방법으로 옳은 것은?', '["옷 입기를 거부하면 입히지 않는다.", "시간이 오래 걸리므로 직접 입혀준다.", "색상이 화려하고 장식이 달린 옷을 제공한다.", "수치심을 느끼지 않도록 혼자 입게 둔다.", "순서대로 입지 못하는 경우 속옷부터 순서대로 놓아준다."]'::jsonb, 5, '치매 대상자의 옷 입기를 돕는 적절한 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "옷 입기를 거부하는 경우 강제로 입히지 않도록 해야 하며, 대안적인 방법을 고려해야 합니다.\n[정답]", "5": "순서대로 입지 못하는 경우 속옷부터 차례로 놓아주는 방법이 적합합니다.", "2": "시간의 유무에 관계 없이 대상자가 스스로 할 수 있도록 돕는 것이 중요합니다.", "3": "화려한 옷은 치매 환자에게 혼란을 줄 수 있으므로 피하는 것이 좋습니다.", "4": "환자가 수치심을 느끼지 않도록 지켜보며 적절한 도움을 주는 것이 중요합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고 능력이 저하되는 질병", "def_vi": "Bệnh suy giảm trí nhớ và khả năng tư duy"}, {"term_ko": "방식", "term_vi": "Cách", "def_ko": "방법", "def_vi": "phương pháp"}, {"term_ko": "순서", "term_vi": "Thứ tự", "def_ko": "차례", "def_vi": "thứ tự"}, {"term_ko": "속옷", "term_vi": "Đồ lót", "def_ko": "속옷", "def_vi": "quần áo trong"}, {"term_ko": "수치심", "term_vi": "Xấu hổ", "def_ko": "부끄러움", "def_vi": "sự xấu hổ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1530, '12', '치매 대상자의 옷 선택 시 옳은 것은?', '["계절과 무관한 옷", "색깔이 화려한 옷", "대상자가 좋아하는 옷", "지퍼가 뒤에 달린 옷", "장식이 많이 달린 옷"]'::jsonb, 3, '치매 대상자의 상황에 맞는 적절한 옷 선택의 중요성을 묻는 질문으로, 환자의 선호를 고려해야 함을 반영한 문제임.', NULL, '{"1": "계절과 무관한 옷: 계절에 맞는 옷을 선택하는 것이 중요하므로 적절하지 않음.", "2": "색깔이 화려한 옷: 과한 색감은 혼란을 초래할 수 있어 좋지 않음.\n[정답]", "3": "대상자가 좋아하는 옷: 환자의 선호를 존중하는 것이 중요하여 올바른 선택임.", "4": "지퍼가 뒤에 달린 옷: 입고 벗기기 불편하므로 적절하지 않음.", "5": "장식이 많이 달린 옷: 과한 장식은 혼란을 줄 수 있으므로 좋지 않음."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 상실증(한국어)", "def_vi": "Bệnh không nhớ"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Người bệnh"}, {"term_ko": "선택", "term_vi": "Lựa chọn", "def_ko": "고르다(한국어)", "def_vi": "Chọn"}, {"term_ko": "옥색", "term_vi": "Màu sắc", "def_ko": "색깔(한국어)", "def_vi": "Màu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1529, '12', '치아가 없는 치매 대상자의 식후 구강위생 방법은?', '["차 또는 물을 마시도록 한다.", "소금물로 입안을 헹구게 한다.", "면봉으로 잇몸을 닦아준다.", "거즈를 감은 설압자에 물치약을 묻혀서 닦는다.", "치아가 없는 경우에는 구강위생을 하지 않는다."]'::jsonb, 1, '치매 대상자의 구강위생 관리의 중요성을 묻는 문제입니다.', NULL, '{"1": "구강위생을 위해 차나 물을 섭취하는 것은 입안의 세균을 줄일 수 있는 방법입니다.\n[정답]", "2": "소금물로 헹구는 것은 효과적이지만 치아가 없는 경우의 권장 사항은 아닙니다.", "3": "면봉으로 잇몸을 닦는 것은 특정 상황에서 도움이 될 수 있으나 일반적이지 않습니다.", "4": "물치약을 묻혀 닦는 것은 권장되지 않습니다.", "5": "구강위생 관리는 치아 유무와 관계없이 중요합니다."}'::jsonb, '[{"term_ko": "구강위생", "term_vi": "Vệ sinh miệng", "def_ko": "입안을 깨끗하게 유지하는 방법", "def_vi": "Phương pháp giữ cho miệng sạch sẽ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1528, '12', '치아가 없는 치매 대상자의 식후 구강위생 방법은?', '["차 또는 물을 마시도록 한다.", "소금물로 입안을 헹구게 한다.", "면봉으로 잇몸을 닦아준다.", "거즈를 감은 설압자에 물치약을 묻혀서 닦는다.", "치아가 없는 경우에는 구강위생을 하지 않는다."]'::jsonb, 1, '치매 환자의 구강위생 관리 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "차 또는 물을 마시도록 한다. 구강 건조를 예방하고 구강위생을 개선하는 방법입니다.\n[정답]", "2": "소금물로 입안을 헹구게 한다. 치아가 없더라도 구강세정이 도움이 되지만, 물이나 차에 비해 허용도가 낮습니다.", "3": "면봉으로 잇몸을 닦아준다. 이는 잇몸과 구강 내 세균 제거에 효과적일 수 있습니다.", "4": "거즈를 감은 설압자에 물치약을 묻혀서 닦는다. 구강위생 관리의 방법 중 하나이지만, 치아가 없을 경우 우선순위는 아닙니다.", "5": "치아가 없는 경우에는 구강위생을 하지 않는다. 이는 잘못된 인식으로, 구강 건강을 위해서 최소한의 관리가 필요합니다."}'::jsonb, '[{"term_ko": "치아", "term_vi": "Răng", "def_ko": "이(한국어)", "def_vi": "răng"}, {"term_ko": "구강위생", "term_vi": "Vệ sinh miệng", "def_ko": "구강 위생(한국어)", "def_vi": "vệ sinh miệng"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "치매(한국어)", "def_vi": "sa sút trí tuệ"}, {"term_ko": "면봉", "term_vi": "Bông gòn", "def_ko": "면봉(한국어)", "def_vi": "bông gòn"}, {"term_ko": "거즈", "term_vi": "Gạc", "def_ko": "거즈(한국어)", "def_vi": "gạc"}, {"term_ko": "설압자", "term_vi": "Dụng cụ ấn", "def_ko": "설압자(한국어)", "def_vi": "dụng cụ ấn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1527, '12', '누워서 지내는 치매 대상자의 양치질을 돕는 방법으로 옳은 것은?', '["치아에서 잇몸 방향으로 세심하게 닦는다.", "칫솔을 혀 안쪽까지 깊숙이 넣어 닦는다.", "입안을 차가운 물로 한번만 헹군다.", "대상자의 뺨에 물받이 그릇을 대준다.", "치아가 없는 경우에는 구강위생관리를 하지 않는다."]'::jsonb, 4, '치매 대상자의 구강 위생 관리 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "치아에서 잇몸 방향으로 세심하게 닦는 것은 올바른 방법이지만, 누워서 지내는 경우에는 좀 더 주의가 필요합니다.\n[정답]", "4": "대상자의 뺨에 물받이 그릇을 대주는 것은 침이 흘러나오거나 물이 튀는 것을 방지하기 위해 매우 중요합니다.", "2": "칫솔을 혀 안쪽까지 깊숙이 넣어 닦는 것은 역류를 유발할 수 있어 피해야 합니다.", "3": "입안을 차가운 물로 한번만 헹군다면 충분한 구강 세척이 이루어지지 않습니다.", "5": "치아가 없는 경우에도 구강 위생 관리는 여전히 중요합니다."}'::jsonb, '[{"term_ko": "구강 위생", "term_vi": "Vệ sinh miệng", "def_ko": "입안의 청결을 유지하는 것", "def_vi": "Giữ sạch sẽ trong miệng"}, {"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력, 사고능력이 저하되는 상태", "def_vi": "Tình trạng suy giảm trí nhớ, khả năng suy nghĩ"}, {"term_ko": "물받이 그릇", "term_vi": "Bát nhận nước", "def_ko": "흘러내린 물을 받는 그릇", "def_vi": "Cái bát để đựng nước chảy ra"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1526, '12', '치매 대상자의 구강위생을 돕는 방법으로 옳은 것은?', '["모가 딱딱한 칫솔을 사용한다.", "삼켜도 되는 어린이용 치약을 사용한다.", "의치는 항상 끼워 놓는다.", "의치는 매일 정해진 시간에 닦아준다.", "양치질을 거부할 경우 면봉으로 닦아준다."]'::jsonb, 2, '치매 대상자의 구강위생을 적절히 관리하는 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "보통 딱딱한 칫솔은 안전하지 않으며, 잇몸을 다칠 수 있습니다.\n[정답]", "2": "어린이용 치약은 삼켜도 안전하므로 치매 환자에게 적합합니다.", "3": "의치를 항상 끼워 놓는 것은 구강위생에 좋지 않습니다.", "4": "의치는 매일 일정하게 관리해야 하지만, 닦아주는 것이 중요합니다.", "5": "양치질을 거부할 경우 면봉으로도 닦을 수 있지만 최선의 방법은 아닙니다."}'::jsonb, '[{"term_ko": "구강위생", "term_vi": "Vệ sinh miệng", "def_ko": "입과 관련된 위생 관리", "def_vi": "Quản lý vệ sinh liên quan đến miệng"}, {"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억과 정신 기능의 감소", "def_vi": "Sự giảm sút trí nhớ và chức năng tâm thần"}, {"term_ko": "의치", "term_vi": "Răng giả", "def_ko": "인공치아", "def_vi": "Răng giả"}, {"term_ko": "양치질", "term_vi": "Đánh răng", "def_ko": "이를 닦는 행위", "def_vi": "Hành động chải răng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1525, '12', '치매 대상자가 열이 나는데도 목욕을 시켜 달라고 할 때 대처방법은?', '["시원한 물로 목욕시킨다.", "해열제를 먹인 후 목욕시킨다.", "목욕 대신 물놀이를 하게 한다.", "미지근한 물수건으로 몸을 닦아 준다.", "고열의 위험성에 대해 자세히 설명한다."]'::jsonb, 4, '치매 환자의 목욕 요구에 대한 적절한 대처 방법을 평가하기 위함입니다.', NULL, '{"1": "시원한 물로 목욕시킨다. 목욕 시 체온 조절을 고려하지 않은 매우 위험한 방법입니다.\n[정답]", "4": "미지근한 물수건으로 몸을 닦아 준다. 체온을 조절하면서 개인위생을 유지할 수 있는 안전한 방법입니다.", "2": "해열제를 먹인 후 목욕시킨다. 약물 투여는 의료인의 처방이 필요하며, 안전하지 않을 수 있습니다.", "3": "목욕 대신 물놀이를 하게 한다. 환자의 현재 상태에 따라 다르지만, 고열이 있을 때는 피해야 할 방법입니다.", "5": "고열의 위험성에 대해 자세히 설명한다. 설명은 중요하지만, 즉각적인 행동 대응이 필요한 상황입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 사고 능력이 저하된 상태", "def_vi": "Trạng thái suy giảm khả năng nhớ và suy nghĩ"}, {"term_ko": "열", "term_vi": "Sốt", "def_ko": "체온이 상승한 상태", "def_vi": "Tình trạng nhiệt độ cơ thể gia tăng"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 씻는 행위", "def_vi": "Hành động rửa cơ thể"}, {"term_ko": "미지근한", "term_vi": "Ấm", "def_ko": "따뜻한 정도", "def_vi": "Mức độ ấm"}, {"term_ko": "고열", "term_vi": "Sốt cao", "def_ko": "높은 체온 상태", "def_vi": "Trạng thái nhiệt độ cơ thể cao"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1524, '12', '치매 대상자가 물에 대한 거부반응을 보일 때 목욕 돕기 방법은?', '["작은 그릇에 물을 떠서 장난하게 해준다.", "목욕을 안 하면 간식을 안 준다고 경고한다.", "목욕을 하면 기분이 좋아진다며 설득한다.", "목욕을 거부하더라도 강제로 시행한다.", "수치심을 느끼지 않게 혼자 목욕하게 한다."]'::jsonb, 1, '치매 대상자의 목욕 도우미를 위한 적절한 방법을 평가하고 선택하는 것이다.', NULL, '{"1": "작은 그릇에 물을 떠서 장난하게 해주는 것은 치매 대상자의 거부감을 감소시키는 효과가 있다. \n[정답]", "2": "목욕을 안 하면 간식을 안 준다고 경고하는 것은 부정적인 방법으로, 대상자의 심리를 더 악화시킬 수 있다.", "3": "목욕을 하면 기분이 좋아진다며 설득하는 것이 허용될 수 있으나, 대체로 치매 대상자에게는 효과적이지 않다.", "4": "목욕을 거부하더라도 강제로 시행하는 것은 인권을 침해할 수 있다.", "5": "수치심을 느끼지 않게 혼자 목욕하게 하는 것은 치매 대상자의 안전과 안녕을 고려하지 않은 잘못된 접근이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "NCTT", "def_ko": "인지 기능의 감소로 인한 기억 상실증", "def_vi": "Giảm sút chức năng nhận thức dẫn đến mất trí nhớ"}, {"term_ko": "거부반응", "term_vi": "Phản ứng từ chối", "def_ko": "어떤 것에 대한 반대의 감정이나 행동", "def_vi": "Cảm xúc hoặc hành vi phản đối một cái gì đó"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 씻는 행위", "def_vi": "Hành động rửa cơ thể"}, {"term_ko": "강제", "term_vi": "Bắt buộc", "def_ko": "억지로 하는 것", "def_vi": "Làm điều gì đó một cách miễn cưỡng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1523, '12', '치매 대상자의 목욕 돕기 방법으로 옳은 것은?', '["욕조 바닥에 미끄럼방지 매트를 깔아준다.", "욕실 바닥에 따뜻한 물을 뿌려둔다.", "목욕물의 온도는 대상자가 확인하게 한다.", "사생활 유지를 위해 혼자 목욕하게 한다.", "운동실조증이 있는 대상자는 탕 목욕보다 샤워를 시킨다."]'::jsonb, 1, '치매 대상자의 목욕을 안전하고 효과적으로 돕기 위한 방법을 이해하는지 평가하고자 한다.', NULL, '{"1": "욕조 바닥에 미끄럼방지 매트를 깔아준다: 목욕 시 안전을 위하여 미끄럼방지 매트를 사용하는 것은 매우 중요하다.\n[정답]", "2": "욕실 바닥에 따뜻한 물을 뿌려둔다: 이는 미끄러짐을 예방하는 데 도움이 되지만, 따뜻한 물이 바닥에 고여있으면 위험할 수 있다.", "3": "목욕물의 온도는 대상자가 확인하게 한다: 치매 환자는 온도 감각이 저하될 수 있으므로, 반드시 보호자가 확인해야 한다.", "4": "사생활 유지를 위해 혼자 목욕하게 한다: 치매 대상자는 혼자 목욕하는 것이 위험할 수 있으므로, 항상 도움을 줘야 한다.", "5": "운동실조증이 있는 대상자는 탕 목욕보다 샤워를 시킨다: 운동실조증 환자는 샤워가 안전하지만, 반드시 전문가의 판단이 필요하다."}'::jsonb, '[{"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "씻는 행위", "def_vi": "Hành động rửa"}, {"term_ko": "목욕물", "term_vi": "Nước tắm", "def_ko": "목욕하기 위해 사용하는 물", "def_vi": "Nước sử dụng để tắm"}, {"term_ko": "미끄럼방지", "term_vi": "Chống trơn", "def_ko": "미끄러운 것을 방지함", "def_vi": "Ngăn chặn sự trơn trượt"}, {"term_ko": "사생활", "term_vi": "Cuộc sống riêng tư", "def_ko": "개인적인 생활", "def_vi": "Cuộc sống cá nhân"}, {"term_ko": "운동실조증", "term_vi": "Rối loạn vận động", "def_ko": "운동 조정 문제가 있는 질병", "def_vi": "Bệnh gây ra vấn đề điều chỉnh vận động"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1522, '12', '치매 대상자의 목욕을 돕는 방법을 옳은 것은?', '["대상자를 욕조에 앉힌 후 물을 채운다.", "욕실 바닥에 따뜻한 물을 뿌린다.", "물에 대한 거부반응이 있더라도 목욕을 시킨다.", "목욕을 강요하지 말고 목욕과정을 단순화 시킨다.", "사생활 보호를 위해 욕실에 혼자 둔다."]'::jsonb, 3, '치매 환자의 목욕 보조 방법에 대한 이해를 평가하려는 의도입니다.', NULL, '{"1": "대상자를 욕조에 앉힌 후 물을 채우는 것은 안전하지 않은 방법입니다.\n[정답]", "3": "물에 대한 거부반응이 있더라도 목욕을 강요하는 것은 바람직하지 않습니다.", "2": "욕실 바닥에 따뜻한 물을 뿌리는 것은 바람직하지 않습니다.", "4": "목욕을 강요하지 말고 목욕과정을 단순화 시키는 것은 좋은 방법입니다.", "5": "사생활 보호를 위해 욕실에 혼자 두는 것은 안전하지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력 및 인지 기능의 장애가 있는 상태", "def_vi": "Tình trạng rối loạn trí nhớ và khả năng nhận thức"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "신체를 씻는 행위", "def_vi": "Hành động rửa cơ thể"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "돌봐야 할 환자", "def_vi": "Bệnh nhân cần được chăm sóc"}, {"term_ko": "강요하다", "term_vi": "Ép buộc", "def_ko": "억지로 하게 하다", "def_vi": "Buộc phải làm gì đó"}, {"term_ko": "사생활", "term_vi": "Quyền riêng tư", "def_ko": "개인의 생활이나 비밀", "def_vi": "Cuộc sống cá nhân hoặc bí mật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1521, '12', '치매 대상자가 변비인 경우 돕는 방법으로 옳은 것은?', '["수분 섭취량을 줄인다.", "섬유질 음식섭취를 제한한다.", "대상자가 요구 시 즉시 관장을 한다.", "증상이 비슷한 다른 대상자의 변비약을 먹인다.", "일정한 시간 간겨긍로 변기에 앉혀 배변을 유도한다."]'::jsonb, 5, '치매 환자의 변비 문제 해결 방안을 이해하고 적용할 수 있는지를 평가하려는 의도입니다.', NULL, '{"1": "수분 섭취량을 줄이는 것은 변비를 악화시킬 수 있습니다.\n[정답]", "5": "일정한 시간 간격으로 변기에 앉혀 배변을 유도하는 것은 변비 예방과 관리에 효과적입니다.", "2": "섬유질 음식섭취를 제한하는 것은 변비에 좋지 않은 영향을 미칩니다.", "3": "대상자가 요구 시 즉시 관장을 하는 것은 불필요한 자극을 줄 수 있습니다.", "4": "증상이 비슷한 다른 대상자의 변비약을 먹이는 것은 개인의 건강 상태에 따라 다를 수 있으므로 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "대변이 단단해져서 배출이 어려운 상태", "def_vi": "Tình trạng khó khăn trong việc bài tiết phân do phân cứng lại"}, {"term_ko": "수분 섭취", "term_vi": "Lượng nước uống", "def_ko": "신체의 수분을 섭취하는 것", "def_vi": "Việc hấp thụ nước cho cơ thể"}, {"term_ko": "섬유질", "term_vi": "Chất xơ", "def_ko": "식이섬유가 풍부한 음식", "def_vi": "Thực phẩm giàu chất xơ"}, {"term_ko": "관장", "term_vi": "Thụt tháo", "def_ko": "대장에 약물을 주입하여 배변을 유도하는 방법", "def_vi": "Phương pháp đưa thuốc vào đại tràng để kích thích đi vệ sinh"}, {"term_ko": "배변", "term_vi": "Đi vệ sinh", "def_ko": "대변을 배출하는 행위", "def_vi": "Hành động bài tiết phân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1520, '12', '치매 대상자가 실금하여 옷이 젖은 것을 발견했을 때 대처 방법은?', '["상황을 기록하고 기저귀를 채운다.", "더러워진 옷을 갈아입히고 안정시킨다.", "하루 동안 수분섭취를 제한한다.", "소변이 마렵다고 하면 간이변기를 대준다.", "보호자와 유치도뇨관 삽입에 대해 의논한다."]'::jsonb, 2, '치매 환자가 실금을 앓고 있는 상황에서 올바른 대처 방법을 알고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "상황을 기록하는 것은 중요하나, 기저귀를 채우는 것은 즉각적인 대처로 적절하지 않습니다.\n[정답]", "2": "더러워진 옷을 갈아입히고 안정시켜 주는 것이 가장 적절한 대처입니다.", "3": "수분 섭취 제한은 건강에 해로울 수 있으며, 해결 방법이 아닙니다.", "4": "간이변기를 제공하는 것은 필요할 때 좋은 방법이나 현재 상황에서 긴급하게 필요한 대처는 아닙니다.", "5": "유치도뇨관 삽입은 의료적인 절차이기 때문에, 보호자와 의논하는 것은 적절하나 현재의 즉각적인 대책이 아닙니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 인지 기능의 감퇴로 나타나는 질병", "def_vi": "Bệnh gây suy giảm khả năng ghi nhớ và chức năng nhận thức"}, {"term_ko": "실금", "term_vi": "Tiểu không tự chủ", "def_ko": "무의식적으로 소변을 보는 현상", "def_vi": "Hiện tượng đi tiểu một cách không kiểm soát"}, {"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "소변을 흡수하는 패드", "def_vi": "Tấm lót thấm nước tiểu"}, {"term_ko": "보호자", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1519, '12', '치매 대상자에게 요실금이 나타날 때 돕는 방법으로 옳은 것은?', '["수분섭취를 제한하여 소변량을 줄인다.", "배뇨 후 치골상부를 눌러준다.", "밤에는 기저귀를 채운다.", "실금을 하면 주의를 준다.", "낮에는 4시간, 밤에는 2시간 간격으로 배뇨훈련을 시킨다."]'::jsonb, 2, '치매 대상자의 요실금 관리 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "수분 섭취를 제한하는 것은 건강에 해로울 수 있습니다.\n[정답]", "2": "배뇨 후 치골상부를 눌러주는 방법은 실제로 소변 배출을 도울 수 있습니다.", "3": "밤에 기저귀를 채우는 방법은 일시적인 해결책이지만, 이 방법을 상시로 사용할 경우 위생 문제가 발생할 수 있습니다.", "4": "실금을 할 때 주의를 주는 것은 환자의 자존감을 해칠 수 있습니다.", "5": "배뇨훈련은 간격을 조절해야 하며, 일반적인 권장 간격은 다를 수 있습니다."}'::jsonb, '[{"term_ko": "요실금", "term_vi": "Tiểu không tự chủ", "def_ko": "소변을 스스로 조절하지 못하는 상태", "def_vi": "Tình trạng không kiểm soát được nước tiểu"}, {"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억력과 사고력의 감퇴로 발생하는 질환", "def_vi": "Bệnh gây giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "배뇨", "term_vi": "Đi tiểu", "def_ko": "소변을 봄", "def_vi": "Hành động bài tiết nước tiểu"}, {"term_ko": "훈련", "term_vi": "Đào tạo", "def_ko": "일정한 목표를 향해 연습하는 것", "def_vi": "Hành động thực hành với mục tiêu nhất định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1518, '12', '요실금 대상자의 배설을 돕는 방법은?', '["침대 옆에 이동변기를 둔다.", "체중을 늘려 골반근육을 강화시킨다.", "활동을 제한하여 배뇨횟수를 조절한다.", "아랫배를 눌러 주어 방광을 완전히 비운다.", "소변을 볼 때 더운 물주머니를 복부에 대준다."]'::jsonb, 4, '요실금 대상자의 배설을 지원하는 효과적인 방법을 묻는 문제입니다.', NULL, '{"1": "침대 옆에 이동변기를 두는 것은 편리할 수 있지만, 배설을 돕는 최적의 방법은 아닙니다.\n[정답]", "4": "아랫배를 눌러 주어 방광을 완전히 비우는 것은 요실금 대상자의 배설을 효과적으로 돕는 방법입니다.", "2": "체중을 늘려 골반근육을 강화하는 것은 도움이 될 수 있지만, 즉각적인 배설 도움에는 한계가 있습니다.", "3": "활동을 제한하여 배뇨횟수를 조절하는 것은 일반적인 접근 방식이지만, 배설을 돕는 직접적인 방법은 아닙니다.", "5": "소변을 볼 때 더운 물주머니를 복부에 대주는 것은 불편함을 줄일 수 있지만, 배설을 돕는 방법이라고 보기 어렵습니다."}'::jsonb, '[{"term_ko": "요실금", "term_vi": "Tiểu không tự chủ", "def_ko": "소변을 제어하지 못하는 상태", "def_vi": "Tình trạng không kiểm soát được việc tiểu tiện"}, {"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "신체에서 쓰레기나 노폐물이 나오는 과정", "def_vi": "Quá trình thải ra chất thải hoặc chất cặn bã từ cơ thể"}, {"term_ko": "골반근육", "term_vi": "Cơ vùng chậu", "def_ko": "골반 부위의 근육", "def_vi": "Cơ bắp trong khu vực xương chậu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1517, '12', '초기 치매 대상자의 배설관리 방법으로 옳은 것은?', '["변기 앞에 안전 손잡이를 설치한다.", "활동이 많은 낮 시간에는 기저귀를 채운다.", "식사 전후에는 매번 변기에 앉혀 변을 보게 한다.", "취침 전에는 반드시 화장실에 다녀오도록 한다.", "안전을 위해 야간에는 이동식 변기를 사용한다."]'::jsonb, 5, '초기 치매 대상자의 배설 관리를 위한 적절한 방법을 이해하고 있는지를 평가하고자 함.', NULL, '{"1": "변기 앞에 안전 손잡이를 설치하는 것은 도움이 되지만, 필수적인 방법은 아님.\n[정답]", "5": "야간에는 안전을 위해 이동식 변기를 사용하는 것이 바람직하다.", "2": "낮 시간에 기저귀를 채우는 것은 적극적인 관리 방법이라고 보기 어려움.", "3": "식사 전후에 매번 변기 앉히는 것은 스트레스를 유발할 수 있음.", "4": "취침 전 화장실에 다녀오는 것은 좋지만 필수는 아님."}'::jsonb, '[{"term_ko": "초기", "term_vi": "Giai đoạn đầu", "def_ko": "시작 단계(한국어)", "def_vi": "Giai đoạn bắt đầu(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1516, '12', '치매 대상자가 기저귀 안으로 손을 자주 넣어 성기에 상처를 낼 때 대처방법은?', '["손에 장갑을 끼워준다.", "손톱을 짧게 깎아준다.", "부끄러운 행동임을 지적한다.", "하의를 벗겨 시원하게 해준다.", "계속하면 서비스를 중단하겠다고 말한다."]'::jsonb, 2, '치매 환자의 행동 원인과 대처 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "손에 장갑을 끼워주는 것은 일시적인 해결책이나, 근본적인 원인을 해결하지 못합니다.\n[정답]", "2": "손톱을 짧게 깎아주는 것은 환자가 기저귀 안에 손을 넣었을 때 상처를 방지하는 데 도움이 됩니다.", "3": "부끄러운 행동이라고 지적하는 것은 환자에게 추가적인 부정적 감정을 유발할 수 있습니다.", "4": "하의를 벗겨주는 것은 상황에 따라 적절할 수 있으나, 모든 환자에게 적용될 수 있는 방법이 아닙니다.", "5": "서비스를 중단하겠다고 말하는 것은 강압적이며, 환자의 정서에 부정적인 영향을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "노인성 정신질환으로 기억력과 일상생활 기능이 상실되는 상태", "def_vi": "Tình trạng mất trí nhớ và khả năng hoạt động hàng ngày của người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1515, '12', '치매 대상자의 배설을 돕는 방법으로 옳은 것은?', '["실금하면 4시간마다 이동변기를 대어 준다.", "변기를 차갑게 하여 변의를 자극한다.", "뒤처리 방법을 시범 보여 스스로 하게 한다.", "화장실 문 앞에 화분을 놓아 위치를 표시한다.", "취침 전에 물이나 음료를 충분히 마시게 한다."]'::jsonb, 3, '치매 대상자에게 적절한 배설 도움 방법을 이해하고 선택할 수 있는지를 묻는 문제입니다.', NULL, '{"1": "실금하면 4시간마다 이동변기를 대어 주는 것은 배설 교육의 효과를 저하시킬 수 있습니다.\n[정답]", "3": "뒤처리 방법을 시범 보여 스스로 하게 하여 자존감을 높이고 독립성을 기르는 것이 좋습니다.", "2": "변기를 차갑게 하여 변의를 자극하는 것은 오히려 불편함을 초래할 수 있습니다.", "4": "화장실 문 앞에 화분을 놓아 위치를 표시하는 것은 실질적인 도움이 되지 않습니다.", "5": "취침 전에 물이나 음료를 충분히 마시게 하는 것은 수면 중 배뇨 문제를 유발할 수 있습니다."}'::jsonb, '[{"term_ko": "배설", "term_vi": "Tiểu tiện", "def_ko": "대소변을 버리는 행위", "def_vi": "Hành động đi vệ sinh"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "인지 기능이 저하되는 질병", "def_vi": "Bệnh suy giảm chức năng nhận thức"}, {"term_ko": "뒤처리", "term_vi": "Dọn dẹp", "def_ko": "청소 및 정리하는 과정", "def_vi": "Quá trình làm sạch và sắp xếp"}, {"term_ko": "자존감", "term_vi": "Giá trị bản thân", "def_ko": "자신의 가치에 대한 인식", "def_vi": "Nhận thức về giá trị của chính mình"}, {"term_ko": "독립성", "term_vi": "Tính độc lập", "def_ko": "스스로 할 수 있는 능력", "def_vi": "Khả năng tự làm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1514, '12', '치매 대상자의 배설 돕기로 옳은 것은?', '["정해진 시간에 배설을 하도록 강요한다.", "화장실 가까운 곳에 방을 배치한다.", "야간에 수분 섭취를 늘린다.", "벨트와 단추가 있는 바지를 입힌다.", "옷에 배설물이 묻었을 경우 주의시킨다."]'::jsonb, 2, '치매 환자의 배설 관리를 올바르게 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "환자에게 정해진 시간에 맞춰 배설을 강요하는 것은 치매 환자에게 스트레스를 줄 수 있습니다.\n[정답]", "2": "화장실 가까운 곳에 방을 배치하는 것은 치매 환자가 배설을 쉽게 할 수 있도록 도와줍니다.", "3": "야간에 수분 섭취를 늘리는 것은 수면에 방해가 될 수 있습니다.", "4": "벨트와 단추가 있는 바지는 치매 환자가 스스로 옷을 벗거나 입는 데 어려움을 줄 수 있습니다.", "5": "배설물이 묻었을 때 주의시키는 것은 오히려 환자에게 불안감을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 및 사고의 기능 장애(한국어)", "def_vi": "Rối loạn chức năng của trí nhớ và tư duy"}, {"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "소변이나 대변을 보는 것(한국어)", "def_vi": "Thực hiện việc đi vệ sinh"}, {"term_ko": "강요하다", "term_vi": "Ép buộc", "def_ko": "힘으로 시키다(한국어)", "def_vi": "Buộc phải làm điều gì đó"}, {"term_ko": "수분", "term_vi": "Thủy nước", "def_ko": "물의 양(한국어)", "def_vi": "Lượng nước"}, {"term_ko": "방 배치", "term_vi": "Bố trí phòng", "def_ko": "방을 어떻게 배열하는가(한국어)", "def_vi": "Cách sắp xếp phòng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1513, '12', '대상자가 바지 뒷부분을 잡고 안절부절 못하며 구석진 곳을 찾을 때 대처방법은?', '["화장실로 데리고 간다.", "옷을 갈아입힌다.", "좋아하는 음식을 제공한다.", "함께 산책을 나간다.", "실내 온도를 낮추어 시원하게 해준다."]'::jsonb, 1, '이 문제는 대상자가 불안감을 느끼거나 화장실을 필요로 할 때 적절한 대처 방법을 묻고 있습니다.', NULL, '{"1": "화장실로 데리고 간다. 이 방법은 대상자가 화장실을 필요로 하는 경우에 적절한 대처입니다.\n[정답]", "2": "옷을 갈아입힌다. 이 방법은 대상자의 불안감을 해소하는 데 도움이 되지 않습니다.", "3": "좋아하는 음식을 제공한다. 음식 제공은 불안감 해소와는 관련이 없습니다.", "4": "함께 산책을 나간다. 산책이 도움이 될 수 있지만, 긴급한 상황에는 부적절할 수 있습니다.", "5": "실내 온도를 낮추어 시원하게 해준다. 온도의 변화가 불안감을 해소하는 데 도움이 되지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Bệnh nhân", "def_ko": "특정 치료나 돌봄을 받는 사람", "def_vi": "Người nhận điều trị hoặc chăm sóc"}, {"term_ko": "안절부절 못하다", "term_vi": "Bồn chồn", "def_ko": "불안하거나 초조한 상태", "def_vi": "Tình trạng lo lắng hoặc hồi hộp"}, {"term_ko": "대처방법", "term_vi": "Phương pháp ứng phó", "def_ko": "문제를 해결하기 위한 방법", "def_vi": "Cách giải quyết vấn đề"}, {"term_ko": "화장실", "term_vi": "Nhà vệ sinh", "def_ko": "소변이나 대변을 보기 위한 장소", "def_vi": "Địa điểm đi vệ sinh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1512, '12', '치매 대상자에게 원인을 알 수 없는 체중감소가 나타났을 때 돕는 방법은?', '["기름진 음식을 제공한다.", "음식을 수시로 제공한다.", "고열량의 액체음식을 제공한다.", "경관영양을 한다.", "식사량을 두 배로 늘린다."]'::jsonb, 3, '치매 환자에게 체중 감소가 발생한 경우, 이를 해결하기 위한 적절한 영양 보충 방법에 대해 묻고 있다.', NULL, '{"1": "기름진 음식을 제공하는 것은 오히려 소화에 부담을 줄 수 있다.\n[정답]", "2": "음식을 수시로 제공하는 것은 환자의 기호와 필요에 따라 좋지만, 과도할 경우 비만을 초래할 수 있다.", "3": "고열량의 액체음식을 제공하는 것은 체중 증가에 효과적이다.", "4": "경관영양을 하는 것은 극단적인 경우에 해당하며, 반드시 필요한 상황이다.", "5": "식사량을 두 배로 늘리는 것은 환자의 상태에 따라 부작용이 있을 수 있다."}'::jsonb, '[{"term_ko": "체중감소", "term_vi": "Giảm cân", "def_ko": "체중이 줄어드는 현상", "def_vi": "Hiện tượng giảm trọng lượng cơ thể"}, {"term_ko": "고열량", "term_vi": "Lượng calo cao", "def_ko": "높은 칼로리", "def_vi": "Calo cao"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1511, '12', '치매 대상자가 식사를 하지 않아 체중이 감소되었을 때 대처방법은?', '["의료진에게 알리고 원인을 파악한다.", "식사량을 평소보다 두 배 제공한다.", "걸쭉한 액체음식을 준다.", "고지방의 음식을 준다.", "큰 그릇에 한꺼번에 음식을 담아 제공한다."]'::jsonb, 1, '치매 환자가 식사를 하지 않다가 체중이 감소하는 문제 상황에서 올바른 대처방법을 제시하는 것이 목표입니다.', NULL, '{"1": "의료진에게 알리고 원인을 파악한다.\n[정답]", "2": "식사량을 평소보다 두 배 제공한다.\n식사량을 늘리는 것이 좋다고 판단하더라도, 단순히 두 배로 늘리는 것은 체중 증가에 효과적이지 않을 수 있습니다.", "3": "걸쭉한 액체음식을 준다.\n걸쭉한 액체 음식으로도 도움이 될 수 있지만, 기본적으로 치료와 원인 파악이 우선입니다.", "4": "고지방의 음식을 준다.\n고지방 음식이 반드시 도움이 되는 것은 아니며 영양 균형이 중요합니다.", "5": "큰 그릇에 한꺼번에 음식을 담아 제공한다.\n이런 접근은 오히려 환자의 식욕을 감소시킬 우려가 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력과 사고를 저하시키는 질병", "def_vi": "Bệnh làm giảm trí nhớ và khả năng tư duy"}, {"term_ko": "의료진", "term_vi": "Nhân viên y tế", "def_ko": "환자의 건강 상태를 치료하거나 관리하는 전문가", "def_vi": "Chuyên gia điều trị hoặc quản lý tình trạng sức khỏe của bệnh nhân"}, {"term_ko": "체중", "term_vi": "Cân nặng", "def_ko": "신체 질량의 양", "def_vi": "Khối lượng cơ thể"}, {"term_ko": "대처방법", "term_vi": "Cách ứng phó", "def_ko": "문제를 해결하기 위한 방법", "def_vi": "Phương pháp giải quyết vấn đề"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1510, '12', '치매 대상자의 식사를 돕는 방법으로 옳은 것은?', '["식탁에 앉힌 후 음식을 차려준다.", "여러 가지 음식을 한꺼번에 내어 놓는다.", "유리컵에 마실 물을 담아 놓는다.", "생선 가시는 미리 발라서 준다.", "경쾌한 음악을 틀어 식사 분위기를 조성한다."]'::jsonb, 4, '치매 대상자의 식사 보조에 대한 올바른 방법을 이해하고 있는지를 평가하고자 함.', NULL, '{"1": "식탁에 앉힌 후 음식을 차려주는 것은 기본적인 방법이지만, 이 자체로는 치매 환자의 식사 보조에 충분하지 않음.\n[정답]", "4": "생선 가시는 미리 발라서 주는 것이 안전하고 좋으며, 치매 환자의 식사를 돕는 바람직한 방법임.", "2": "여러 가지 음식을 한꺼번에 내어 놓으면 선택이 어려워 혼란을 줄 수 있음.", "3": "유리컵에 마실 물을 담아 놓는 것은 다치기 쉽고, 치매 환자가 다루기 힘들 수 있음.", "5": "경쾌한 음악을 틀어 식사 분위기를 조성하는 것은 좋지만, 직접적인 식사 보조와는 관계가 없음."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력이나 사고 능력이 저하된 상태", "def_vi": "Tình trạng suy giảm trí nhớ hoặc khả năng suy nghĩ"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn uống"}, {"term_ko": "음식", "term_vi": "Thức ăn", "def_ko": "먹을 것", "def_vi": "Thực phẩm"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태", "def_vi": "Tình trạng không có nguy hiểm"}, {"term_ko": "혼란", "term_vi": "Nhầm lẫn", "def_ko": "심리적으로 불안정한 상태", "def_vi": "Tình trạng tâm lý không ổn định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1509, '12', '치매 대상자에게 식사를 제공할 때 돕는 방법으로 옳은 것은?', '["앞치마보다는 턱받이를 해준다.", "음식은 떠먹기 좋게 큼직하게 자른다.", "가벼운 숟가락과 젓가락을 사용하게 한다.", "한 가지 음식을 먹고 난 후 다른 음식을 내어 놓는다.", "식사 전 음식의 온도를 대상자가 확인하게 한다."]'::jsonb, 4, '치매 대상자의 식사 보조 방법에 대한 이해를 평가하고자 함.', NULL, '{"1": "앞치마보다는 턱받이를 해주는 것이 더 효과적이다.\n[정답]", "2": "음식은 떠먹기 좋게 자르는 것이 중요하지만 큼직하게 자르는 것은 적절하지 않다.", "3": "가벼운 숟가락과 젓가락을 사용하는 것이 좋지만, 각각의 상황에 맞는 도구를 선택해야 한다.", "4": "한 가지 음식을 먹고 난 후 다른 음식을 내어 놓는 것이 바람직하다.", "5": "식사 전 음식의 온도를 대상자가 확인하는 것은 필요하지 않다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억 및 사고 능력의 감퇴", "def_vi": "Giảm khả năng ghi nhớ và tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1508, '12', '치매 대상자의 식사 돕기 방법으로 옳은 것은?', '["사발보다 접시를 사용한다.", "배고픔을 호소할 때마다 음식을 제공한다.", "사레에 자주 걸리면 묽은 음식을 제공한다.", "색깔이 있는 유리 그릇에 음식을 담아 제공한다.", "빨대와 플라스틱 덮개가 부착된 물컵을 준비한다."]'::jsonb, 5, '치매 대상자에게 적절한 식사 지원 방법을 이해하고 있는지 평가하기 위함입니다.', NULL, '{"1": "사발보다 접시를 사용한다는 일반적으로 맞는 이야기지만, 치매 대상자의 상황에 따라 다를 수 있습니다.\n[정답]", "5": "빨대와 플라스틱 덮개가 부착된 물컵은 치매 대상자가 음료를 쉽게 섭취할 수 있도록 도와줍니다.", "3": "사레에 자주 걸리면 묽은 음식을 제공하는 것은 상황에 따라 적절할 수 있으나, 5번이 더 적합합니다.", "2": "배고픔을 호소할 때마다 음식을 제공하는 것은 지속적인 식사 지원에는 도움이 될 수 있지만, 주의가 필요합니다.", "4": "색깔이 있는 유리 그릇에 음식을 담아 제공하는 것은 치매 환자에게 혼란을 줄 수 있어 주의해야 합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 사고력이 떨어지는 질환", "def_vi": "Bệnh làm giảm khả năng ghi nhớ và suy nghĩ"}, {"term_ko": "사레", "term_vi": "Sặc", "def_ko": "음식이나 음료가 기도로 들어가는 것", "def_vi": "Thực phẩm hoặc đồ uống đi vào đường hô hấp"}, {"term_ko": "빨대", "term_vi": "Ống hút", "def_ko": "음료를 마시는 도구", "def_vi": "Dụng cụ dùng để uống"}, {"term_ko": "플라스틱", "term_vi": "Nhựa", "def_ko": "합성수지로 만들어진 물질", "def_vi": "Vật liệu tổng hợp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1507, '12', '치매 대상자의 식사를 돕는 방법으로 옳은 것은?', '["TV를 크게 틀어준다.", "식사 장소를 자주 바꿔준다.", "식사 시간은 자유롭게 정한다.", "무게감 있는 숟가락을 사용하게 한다.", "모든 음식은 믹서로 갈아서 제공한다."]'::jsonb, 4, '치매 대상자의 식사 보조 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "TV를 크게 틀어주는 것은 오히려 주의 집중을 방해할 수 있습니다.\n[정답]", "4": "무게감 있는 숟가락을 사용하면 치매 대상자가 식사 시 안정감을 느끼며 식사를 할 수 있습니다.", "2": "식사 장소를 자주 바꿔주는 것은 혼란을 초래할 수 있습니다.", "3": "식사 시간을 자유롭게 정하면 규칙적인 식사가 어려워질 수 있습니다.", "5": "모든 음식은 믹서로 갈아서 제공하면 씹는 감각을 잃을 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고력이 감소하는 뇌의 질병", "def_vi": "Bệnh của não bộ khiến suy giảm trí nhớ và khả năng suy nghĩ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1506, '12', '치매 대상자가 음식을 손으로 먹는 등 장난을 칠 때 요양보호사의 행동으로 옳은 것은?', '["일시적으로 금식을 시킨다.", "단호하게 야단친다.", "여러 가지 음식을 내놓는다.", "안정 될 때까지 방에 가둔다.", "비닐로 된 식탁보를 깔아둔다."]'::jsonb, 5, '치매 대상자가 음식과 관련하여 장난을 치는 상황에서 요양보호사가 어떻게 대처해야 하는지를 평가하는 문제입니다.', NULL, '{"1": "일시적으로 금식을 시키는 것은 오히려 불안감을 증가시킬 수 있으므로 바람직하지 않습니다.", "2": "단호하게 야단치는 것은 치매 환자의 정서를 상하게 할 수 있으므로 적절하지 않습니다.", "3": "여러 가지 음식을 내놓는 것은 혼란을 초래할 수 있으므로 상황에 맞지 않습니다.\n[정답]", "5": "비닐로 된 식탁보를 깔아두면 청소가 용이하고, 대상자가 음식을 손으로 먹더라도 큰 문제가 되지 않습니다.", "4": "안정 될 때까지 방에 가두는 것은 인권 침해의 소지가 있으므로 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": null, "def_ko": "기억력 및 사고가 손상된 상태", "def_vi": null}, {"term_ko": "요양보호사", "term_vi": null, "def_ko": "노인이나 환자를 도와주는 직업", "def_vi": null}, {"term_ko": "장난", "term_vi": null, "def_ko": "심각한 것 아닌 재미있는 행동", "def_vi": null}, {"term_ko": "금식", "term_vi": null, "def_ko": "음식을 먹지 않는 상태", "def_vi": null}, {"term_ko": "야단치다", "term_vi": null, "def_ko": "큰 소리로 혼내다", "def_vi": null}, {"term_ko": "안정", "term_vi": null, "def_ko": "평온하고 고요한 상태", "def_vi": null}, {"term_ko": "가두다", "term_vi": null, "def_ko": "어떤 곳에 가두거나 닫다", "def_vi": null}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1505, '12', '치매 대상자의 식사 돕기 중 옳은 것은?', '["졸려할 때는 식사를 천천히 준다.", "작고 딱딱한 음식을 제공한다.", "소금이나 간장은 식탁 위에 두고 스스로 간을 맞추게 한다.", "사레가 자주 걸리면 좀 더 걸쭉한 액체음식을 제공한다.", "투명한 유리제품에 제공한다."]'::jsonb, 4, '치매 대상자에게 식사를 어떻게 도와야 하는지를 평가하는 문제다.', NULL, '{"1": "졸려할 때는 식사를 천천히 주는 것이 좋지만, 최적의 방법은 아닐 수 있다. \n[정답]", "4": "사레가 자주 걸리는 경우에는 걸쭉한 액체 음식을 제공하는 것이 안전하다.", "2": "작고 딱딱한 음식은 치매 환자에게 위험할 수 있다.", "3": "소금이나 간장을 스스로 맞추게 하는 것은 건강에 좋지 않은 영향을 미칠 수 있다.", "5": "투명한 유리제품은 깨질 위험이 있어 피하는 것이 좋다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억을 잃는 질병", "def_vi": "Bệnh mất khả năng nhớ"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn uống"}, {"term_ko": "사레", "term_vi": "Nghẹn", "def_ko": "기도가 막히는 현상", "def_vi": "Hiện tượng tắc thở"}, {"term_ko": "액체", "term_vi": "Chất lỏng", "def_ko": "물질이 흐르는 상태", "def_vi": "Trạng thái của chất chảy"}, {"term_ko": "제품", "term_vi": "Sản phẩm", "def_ko": "어떤 물건", "def_vi": "Đồ vật nào đó"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1504, '12', '씹는 행위를 잊어버린 치매 대상자에게 고기를 제공할 때 올바른 방법은?', '["굵게 썰어서 제공한다.", "푹 삶아서 제공한다.", "갈아서 제공한다.", "구워서 제공한다.", "잘게 썰어서 제공한다."]'::jsonb, 3, '치매 환자의 식사 보조 방법을 평가하고, 그에 적합한 고기의 제공 방식을 이해하도록 돕기 위한 문제입니다.', NULL, '{"1": "굵게 썰어서 제공하면 치매 환자가 씹기에 어려움을 겪을 수 있습니다.\n[정답]", "2": "푹 삶아서 제공할 경우 질감이 부드럽지만 찢어 먹기 어려울 수 있습니다.", "3": "갈아서 제공하면 환자가 쉽게 먹을 수 있습니다.", "4": "구워서 제공할 경우 딱딱해져 씹기에 문제를 일으킬 수 있습니다.", "5": "잘게 썰어서 제공하면 일정 부분 도움이 되지만, 완전히 갈아주는 것보다는 여전히 어렵습니다."}'::jsonb, '[{"term_ko": "씹다", "term_vi": "Nhai", "def_ko": "물건을 입으로 물고 부수다(한국어)", "def_vi": "nhai"}, {"term_ko": "행위", "term_vi": "Hành vi", "def_ko": "어떤 일을 하는 것(한국어)", "def_vi": "hành động"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억과 사고에 장애가 생기는 질환(한국어)", "def_vi": "sự suy giảm trí nhớ"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "보호를 받는 사람(한국어)", "def_vi": "người được bảo vệ"}, {"term_ko": "고기", "term_vi": "Thịt", "def_ko": "동물의 살(한국어)", "def_vi": "thịt"}, {"term_ko": "제공하다", "term_vi": "Cung cấp", "def_ko": "주다(한국어)", "def_vi": "cung cấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1503, '12', '치매 대상자의 식사를 돕는 방법으로 옳은 것은?', '["손으로 음식을 먹는 경우 턱받이를 해준다.", "의치가 느슨하면 의치를 뺴고 식사하게 한다.", "간식으로 알사탕과 떡을 제공한다.", "처방 받은 비타민은 음식에 섞어서 먹게 한다.", "휴대전화로 좋아하는 가요 영상을 보여 준다."]'::jsonb, 2, '치매 대상자의 안전하고 효과적인 식사 보조 방법을 알아보도록 유도하는 문제입니다.', NULL, '{"1": "손으로 음식을 먹는 경우 턱받이를 해준다.\n턱받이는 음식물이 옷에 묻는 것을 방지할 수 있지만, 치매 대상자는 손으로 음식을 자주 먹을 경우 피부의 건강에도 영향을 미칠 수 있으므로 신중할 필요가 있습니다.", "2": "[정답] 의치가 느슨하면 의치를 뺴고 식사하게 한다.\n의치가 불편할 경우에는 제거하고 식사하는 것이 안전하고 편안할 수 있습니다.", "3": "간식으로 알사탕과 떡을 제공한다.\n딱딱한 간식은 치아에 부담을 줄 수 있어 적절하지 않을 수 있습니다.", "4": "처방 받은 비타민은 음식에 섞어서 먹게 한다.\n비타민의 성질에 따라 섞는 것이 오히려 효과를 떨어뜨릴 수 있습니다.", "5": "휴대전화로 좋아하는 가요 영상을 보여 준다.\n관심을 끌 수 있으나 식사 보조와는 직접적인 관련이 없습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 사고능력이 감소하는 질환", "def_vi": "Bệnh liên quan đến suy giảm trí nhớ hoặc khả năng tư duy"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn uống"}, {"term_ko": "의치", "term_vi": "Răng giả", "def_ko": "인공치아", "def_vi": "Răng được làm giả"}, {"term_ko": "턱받이", "term_vi": "Khăn ăn", "def_ko": "음식물이 옷에 묻지 않도록 하는 천", "def_vi": "Vải để ngăn thức ăn dính vào quần áo"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1502, '12', '치매 대상자의 식사 돕기 기본원칙으로 옳은 방법은?', '["혼자 먹을 수 있다면 자리를 비켜준다.", "사례가 자주 걸리면 수분이 없는 음식을 제공한다.", "초조해 하는 경우에도 정해진 식사는 제공한다.", "접시보다는 사발을 사용하여 덜 흘리게 한다.", "음식을 한꺼번에 섞어 제공한다."]'::jsonb, 4, '치매 대상자의 식사 지원 시 안전하고 편안한 방법을 파악하기 위함입니다.', NULL, '{"1": "혼자 먹을 수 있다면 자리를 비켜준다. - 독립성을 존중하나, 상황에 따라 도움을 줄 필요가 있다.\n[정답]", "4": "접시보다는 사발을 사용하여 덜 흘리게 한다. - 사발은 사용이 용이하고 흘릴 가능성을 줄여준다.", "2": "사례가 자주 걸리면 수분이 없는 음식을 제공한다. - 수분 섭취가 중요하므로 잘못된 방법이다.", "3": "초조해 하는 경우에도 정해진 식사는 제공한다. - 초조함을 해소하기 위해 유연하게 대처해야 한다.", "5": "음식을 한꺼번에 섞어 제공한다. - 식사의 즐거움을 해칠 수 있으므로 바람직하지 않다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억과 인지 기능이 감소하는 질환", "def_vi": "Bệnh suy giảm trí nhớ và chức năng tư duy"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 섭취하는 행위", "def_vi": "Hành động tiêu thụ thực phẩm"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위협 없이 상태", "def_vi": "Trạng thái không có mối đe dọa"}, {"term_ko": "독립성", "term_vi": "Tính độc lập", "def_ko": "스스로 처리할 수 있는 능력", "def_vi": "Khả năng tự xử lý"}, {"term_ko": "유연하게", "term_vi": "Linh hoạt", "def_ko": "상황에 따라 조정하는 방식", "def_vi": "Phương pháp điều chỉnh theo tình huống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1501, '12', '의치를 사용하는 치매 대상자가 식사 중 가장 조심해야 할 것은?', '["과식", "구토", "질식", "기침", "설사"]'::jsonb, 3, '식사 중 주의해야 할 위험 요소를 파악하기 위한 질문입니다.', NULL, '{"1": "과식은 위장에 부담을 줄 수 있지만, 가장 큰 위험은 아닙니다.\n[정답]", "3": "질식은 의치를 사용하는 치매 대상자에게 매우 위험한 상황으로, 특히 응급 상황이 발생할 수 있습니다.", "2": "구토는 불편을 초래하지만, 바로 위험 요소라고 보기는 어렵습니다.", "4": "기침은 식사 중 발생할 수 있으나, 질식처럼 즉각적인 위험 요소는 아닙니다.", "5": "설사는 식사와 관련된 문제일 수 있으나, 당장 위험한 상황은 아닙니다."}'::jsonb, '[{"term_ko": "의치", "term_vi": "Răng giả", "def_ko": "치아 대체물(한국어)", "def_vi": "Vật thay thế cho răng"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력 및 사고력을 저하시켜 일상 생활에 영향을 미치는 질환(한국어)", "def_vi": "Bệnh làm giảm trí nhớ và khả năng tư duy, ảnh hưởng đến cuộc sống hàng ngày"}, {"term_ko": "질식", "term_vi": "Nghẹt thở", "def_ko": "호흡에 장애가 생기는 상태(한국어)", "def_vi": "Trạng thái khó thở"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1500, '12', '치매 대상자가 식사를 하지 않으려고 할 때 돕는 방법은?', '["식사해야 하는 이유를 설명한다.", "음식을 요청할 때까지 금식 시킨다.", "모든 음식을 섞어서 갈아준다.", "직접 식사를 준비하게 한다.", "약의 부작용인지 확인한다."]'::jsonb, 5, '치매 환자의 식사 지원 방법에 대한 이해 여부를 확인하려는 의도입니다.', NULL, '{"1": "식사에 대한 이유를 설명하는 것은 도움을 줄 수 있지만, 바로 효과적이지 않을 수 있습니다.\n[정답]", "5": "약의 부작용을 확인하는 것은 중요한 단계입니다. 치매 환자의 식사 거부가 약물의 부작용 때문일 수 있기 때문에 확인이 필요합니다.", "2": "금식은 환자의 건강을 해칠 수 있으므로 적절하지 않습니다.", "3": "모든 음식을 섞어서 갈아주는 것은 환자의 기호를 무시할 수 있습니다.", "4": "환자에게 직접 식사를 준비하게 하는 것은 오히려 부담을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 상실과 관련된 질병", "def_vi": "Bệnh liên quan đến sự suy giảm trí nhớ"}, {"term_ko": "반드시", "term_vi": "Nhất thiết", "def_ko": "반드시 필요하다", "def_vi": "Cần thiết phải"}, {"term_ko": "부작용", "term_vi": "Tác dụng phụ", "def_ko": "약물이 몸에 미치는 어떤 부정적인 효과", "def_vi": "Tác động tiêu cực của thuốc"}, {"term_ko": "금식", "term_vi": "Nhịn ăn", "def_ko": "음식을 먹지 않음", "def_vi": "Không ăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1499, '12', '치매 대상자에게 일상생활 사고가 많이 발생하는 이유는?', '["상황을 분석하거나 평가를 잘한다.", "금방 잊어버린다.", "병으로 할 수 없게 된 일은 쉽게 포기한다.", "새로운 일을 쉽게 받아들인다.", "갑작스런 변화에 잘 대처한다."]'::jsonb, 2, '치매 환자에게 일상생활에서 자주 발생하는 사고의 원인을 파악하는 문제이다.', NULL, '{"1": "치매 환자는 상황 분석이나 평가가 어려워 사고를 예방하기 어렵다.\n[정답]", "2": "치매는 기억력 저하를 유발하여 중요한 상황을 금방 잊어버리게 한다.", "3": "병으로 인해 일상적인 TASK를 쉽게 포기할 수 있다.", "4": "새로운 일을 받아들이는 데 어려움을 겪는 경우가 많다.", "5": "갑작스러운 변화에 대처하기가 어렵다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억을 잃어버리는 질병", "def_vi": "Bệnh mất trí nhớ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1498, '12', '시설 치매 대상자의 일상생활을 지원하는 방법으로 옳은 것은?', '["주변 환경을 자주 바꾸어 활력을 준다.", "습관적으로 해오던 일은 스스로 하게 한다.", "치매 증상이 호전되면 약물 용량을 줄여 준다.", "사소한 것이라도 요양보호사가 전적으로 돕는다.", "치매로 인해 일상생활을 할 수 없는 것이라고 설명한다."]'::jsonb, 2, '치매 대상자의 일상생활 지원 방법에 대한 이해를 평가하고자 함.', NULL, '{"1": "주변 환경을 자주 바꾸면 오히려 혼란을 초래할 수 있으므로 바람직하지 않다.\n[정답]", "2": "습관적으로 해오던 일은 스스로 하게 하는 것이 자립을 돕는 방법이다.", "3": "치매 증상이 호전된 경우 약물 용량 조정은 반드시 의사와 상의해야 한다.", "4": "요양보호사는 필요할 때 지원하더라도, 가능한 한 대상자가 스스로 할 수 있도록 도와야 한다.", "5": "치매 대상자의 상황을 부정적이고 단정적으로 설명하는 것은 바람직하지 않다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "시설(한국어)", "def_vi": "Cơ sở"}, {"term_ko": "치매", "term_vi": "Chứng mất trí", "def_ko": "치매(한국어)", "def_vi": "Chứng mất trí"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "대상자(한국어)", "def_vi": "Đối tượng"}, {"term_ko": "일상생활", "term_vi": "Cuộc sống hàng ngày", "def_ko": "일상생활(한국어)", "def_vi": "Cuộc sống hàng ngày"}, {"term_ko": "지원", "term_vi": "Hỗ trợ", "def_ko": "지원(한국어)", "def_vi": "Hỗ trợ"}, {"term_ko": "스스로", "term_vi": "Tự mình", "def_ko": "스스로(한국어)", "def_vi": "Tự mình"}, {"term_ko": "자립", "term_vi": "Tự lập", "def_ko": "자립(한국어)", "def_vi": "Tự lập"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1497, '12', '입소한 지 얼마 되지 않은 치매 대상자의 일상생활을 돕는 방법은?', '["새로운 습관을 갖도록 도와준다.", "안전을 위해 침상에서 절대 안정하게 한다.", "기분 전환을 위해 가구 위치를 매일 바꿔 준다.", "원한다면 집에서 쓰던 이불을 가져와 쓰게 한다.", "복용하던 치매약을 스스로 관리하게 한다."]'::jsonb, 4, '치매 환자의 일상생활 지원 방법을 이해하고 적용하도록 유도하는 문제입니다.', NULL, '{"1": "새로운 습관을 갖도록 도와주는 것은 오히려 혼란을 줄 수 있습니다.\n[정답]", "4": "원한다면 집에서 쓰던 이불을 가져와 쓰게 하는 것은 안정감을 주고, 치매 환자의 정서적 지지를 도모합니다.", "2": "안전을 위해 침상에서 절대 안정하게 하는 것은 오히려 활동을 제한하여 부정적인 영향을 줄 수 있습니다.", "3": "기분 전환을 위해 가구 위치를 매일 바꿔 주는 것은 혼란을 초래할 수 있습니다.", "5": "복용하던 치매약을 스스로 관리하게 하는 것은 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 인지 기능이 저하되는 상태", "def_vi": "Trạng thái giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "일상생활", "term_vi": "Cuộc sống hàng ngày", "def_ko": "매일 수행하는 기본적인 활동", "def_vi": "Các hoạt động cơ bản thực hiện hàng ngày"}, {"term_ko": "안정감", "term_vi": "Cảm giác an toàn", "def_ko": "감정적으로 안정된 상태", "def_vi": "Trạng thái cảm xúc ổn định"}, {"term_ko": "복용하다", "term_vi": "Uống", "def_ko": "약을 먹다", "def_vi": "Ăn thuốc"}, {"term_ko": "관리하다", "term_vi": "Quản lý", "def_ko": "책임을 가지고 다루다", "def_vi": "Xử lý có trách nhiệm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1496, '12', '치매약 처방이 바뀐 뒤 대상자가 불안해 하며 방 안을 왔다 갔다 할 때 돕는 방법은?', '["약의 용량을 늘려서 제공한다.", "이전에 복용하던 치매약을 준다.", "증상을 메모하여 병원에 가지고 간다.", "보호자의 허락을 받고 복용량을 줄인다.", "증상이 좋아지며 나타나는 현상이라고 안심시킨다."]'::jsonb, 3, '대상자가 불안해 하는 이유에 대해 이해하고, 적절한 대처 방안을 찾는 것.', NULL, '{"1": "약의 용량을 늘리는 것은 의료 전문가의 판단 없이 행할 수 없다.\n[정답]", "3": "증상을 메모하여 병원에 가지고 가는 것이 적절한 대처 방법이다.", "2": "이전에 복용하던 치매약을 주는 것은 현재의 처방과 다를 수 있어 위험하다.", "4": "보호자의 허락 없이 복용량을 조절하는 것은 법적으로나 윤리적으로 문제가 있다.", "5": "증상이 좋아지며 나타나는 현상이라는 것은 의사와의 상담 후 판단해야 한다."}'::jsonb, '[{"term_ko": "치매약", "term_vi": "Thuốc mất trí nhớ", "def_ko": "알츠하이머나 기타 형태의 치매를 치료하는 약", "def_vi": "Thuốc điều trị chứng mất trí nhớ như Alzheimer"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1495, '12', '치매 대상자의 가족에게 치매 약물 복용의 중요성을 올바르게 설명한 것은?', '["\"치매약 복용은 늦게 시작할수록 안전해요.\"", "\"치매약은 인지기능 개선에 도움이 돼요.\"", "\"치매약은 부작용이 없고, 완치가 가능해요.\"", "\"증상이 좋아지지 않으면 용량을 두 배로 늘려야 해요.\"", "\"치매약은 한 가지를 꾸준히 드셔야 증상을 늦출 수 있어요.\""]'::jsonb, 2, '치매 약물의 중요성과 복용 방법에 대한 이해도를 평가하고자 함.', NULL, '{"1": "치매약 복용은 늦게 시작할수록 안전하다는 주장은 잘못된 정보입니다.\n[정답]", "2": "치매약은 인지기능 개선에 도움이 된다는 점이 맞습니다.", "3": "치매약은 부작용이 없고, 완치가 가능하다는 설명은 사실이 아닙니다.", "4": "증상이 좋아지지 않으면 용량을 두 배로 늘려야 한다는 것은 위험한 판단입니다.", "5": "치매약은 한 가지를 꾸준히 드셔야 증상을 늦출 수 있다는 것은 어느 정도 맞지만, 특정한 약물에 대한 의존성도 고려해야 합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고 능력의 감소를 특징으로 하는 질환", "def_vi": "Bệnh đặc trưng bởi sự giảm khả năng ghi nhớ và tư duy"}, {"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "의학적 치료를 위해 사용하는 물질", "def_vi": "Chất được sử dụng cho điều trị y tế"}, {"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "사고와 이해 능력", "def_vi": "Khả năng suy nghĩ và hiểu biết"}, {"term_ko": "부작용", "term_vi": "Tác dụng phụ", "def_ko": "약물 사용의 예기치 않은 반응", "def_vi": "Phản ứng bất ngờ khi sử dụng thuốc"}, {"term_ko": "완치", "term_vi": "Chữa khỏi", "def_ko": "질병이 완전히 치료되는 것", "def_vi": "Bệnh hoàn toàn được điều trị"}, {"term_ko": "용량", "term_vi": "Liều lượng", "def_ko": "약물의 천장 섭취량", "def_vi": "Lượng thuốc được sử dụng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1494, '12', '치매 가족과의 의사소통 기법 중 다음 설명에 해당하는 것은?• "힘내세요.", "포기하지 마시고 계속하시면 좋은 결과가 있을 거예요."라고 격려한다. • 다른 가족들이 비슷한 상황을 잘 극복한 긍정적인 사례 등을 전해주어 희망을 준다.', '["공감", "관심 전달", "힘 돋우기", "조언 및 정보제공", "나-메시지 전달법"]'::jsonb, 3, '치매를 앓고 있는 가족과의 의사소통에서 긍정적인 격려의 중요성을 강조하기 위함입니다.', NULL, '{"1": "공감: 다른 사람의 감정을 이해하고 느끼는 것을 의미하지만, 이 문제에서는 격려의 구체적인 방법이므로 맞지 않습니다.", "2": "관심 전달: 상대방의 상황에 대한 관심을 보여주는 것이나, 격려의 방식에 직접적으로 관련이 없습니다.\n[정답]", "3": "힘 돋우기: 긍정적인 말을 통해 힘을 주고 격려하는 방식으로, 문제의 설명과 일치합니다.", "4": "조언 및 정보제공: 정보나 조언을 주는 것과 관련되지만, 격려와는 다른 개념입니다.", "5": "나-메시지 전달법: 자신의 감정을 표현하는 방법이지만, 문제의 내용과 관련이 없습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력과 인지 기능이 저하되는 질병", "def_vi": "Bệnh suy giảm trí nhớ và chức năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1493, '12', '치매 가족과의 의사소통 기법으로 옳은 것은?', '["치매 가족이 표현한 내용 뒤에 숨겨진감정은 모른척 한다.", "다른 치매 가족들의 실패한 돌봄 사례들은 전해준다.", "기존의 돌봄 방법을 무시하고 다른 방법을 권유한다.", "잘못된 방법은 설명의 과정보다 충고나 지적을 먼저 한다.", "가족의 돌봄 방법이나 지식의 긍정적인 면을 인정해 준다."]'::jsonb, 5, '치매 환자 가족과 효과적으로 소통하기 위한 기법을 이해하고 평가하는 데 목적이 있다.', NULL, '{"1": "치매 가족이 표현한 내용 뒤에 숨겨진 감정은 모른척 하는 것은 의사소통에 좋지 않다.\n[정답]", "5": "가족의 돌봄 방법이나 지식의 긍정적인 면을 인정해 주는 것이 효과적이다.", "3": "기존의 돌봄 방법을 무시하고 다른 방법을 권유하는 것은 가족의 신뢰를 떨어뜨릴 수 있다.", "4": "잘못된 방법은 설명의 과정보다 충고나 지적을 먼저 하는 것은 비효율적이다.", "2": "다른 치매 가족들의 실패한 돌봄 사례들을 전해주는 것은 도움이 되지 않는다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력 및 사고력의 저하를 동반하는 질환", "def_vi": "Bệnh kèm theo sự suy giảm trí nhớ và khả năng tư duy"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "상대방과 정보를 주고받는 과정", "def_vi": "Quá trình trao đổi thông tin với nhau"}, {"term_ko": "돌봄", "term_vi": "Chăm sóc", "def_ko": "신체적, 정서적으로 지원하는 행위", "def_vi": "Hành động hỗ trợ về thể chất và tình cảm"}, {"term_ko": "긍정적인", "term_vi": "Tích cực", "def_ko": "좋은, 긍정적", "def_vi": "Tốt, tích cực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1492, '12', '치매 가족에게 관심 전달을 하기 위한 의사소통 기법으로 옳은 것은?', '["방어적인 자세를 취한다.", "옆이나 뒤에서 이야기한다.", "마주 보며 큰 목소리로 이야기한다.", "''나는 당신을 존중한다.''고 표현한다.", "친근감을 표현하기 위해 밀착하여 대화한다."]'::jsonb, 4, '치매 환자와 그 가족과의 효과적인 의사소통 방법을 이해하고 적용하는 것이다.', NULL, '{"1": "방어적인 자세를 취하는 것은 의사소통을 오히려 방해할 수 있다.\n[정답]", "4": "''나는 당신을 존중한다.''고 표현하는 것은 긍정적인 의사소통 기법이다.", "2": "옆이나 뒤에서 이야기하는 것은 상대방에게 불안감을 줄 수 있다.", "3": "마주 보며 큰 목소리로 이야기하면 의사소통이 원활해질 수도 있으나, 큰 목소리는 공격적으로 들릴 수 있다.", "5": "친근감을 표현하기 위해 밀착하여 대화하는 것은 개인적인 공간을 침해할 수 있기 때문에 바람직하지 않다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "주고받는 의견이나 감정을 나누는 것", "def_vi": "Chia sẻ ý kiến hoặc cảm xúc"}, {"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고의 능력이 감소하는 질병", "def_vi": "Bệnh suy giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "방어적인", "term_vi": "Có tính phòng thủ", "def_ko": "상대방의 공격이나 비판에 방어하는 것", "def_vi": "Bảo vệ khỏi sự công kích hoặc chỉ trích"}, {"term_ko": "존중", "term_vi": "Tôn trọng", "def_ko": "상대방의 가치를 인정하는 것", "def_vi": "Nhận thức giá trị của người khác"}, {"term_ko": "친근감", "term_vi": "Cảm giác thân thiện", "def_ko": "가까이 다가가고 싶거나 다정한 감정을 느끼는 것", "def_vi": "Cảm thấy gần gũi và muốn tiếp xúc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1491, '12', '치매 가족과의 의사소통 방법으로 옳은 것은?', '["요양보호사의 관점에서 치매가족을 이해한다.", "치매 가족의 기분이 좋다, 나쁘다 정도만 파악한다.", "가족의 대상자를 돌보는 능력을 최대한 지지한다.", "치매가족이 절망적인 감정을 숨길 수 있도록 조언한다.", "고개를 끄덕이는 등의 비언어적인 표현은 사용하지 않는다."]'::jsonb, 3, '치매 환자의 가족과의 의사소통에서 올바른 접근 방법을 평가하는 것입니다.', NULL, '{"1": "요양보호사가 치매 가족의 입장을 이해하는 것은 중요하지만, 이 방법은 무엇이 옳은지를 묻는 질문에서는 부적절합니다.\n[정답]", "3": "가족의 돌봄 능력을 지지하는 것은 효과적인 의사소통의 중요한 부분입니다.", "2": "기분의 정도만 파악하는 것은 소통의 깊이를 부족하게 합니다.", "4": "절망적인 감정을 숨기도록 하는 것은 건강한 소통이 아닙니다.", "5": "비언어적 표현은 의사소통에서 매우 중요하므로 사용하지 않는 것은 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 및 사고에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1490, '12', '치매 가족이 느끼는 부담 중 신체적 부담에 해당하는 것은?', '["죄책감", "소외감", "불안감", "수면장애", "무기력감"]'::jsonb, 4, '치매 가족이 느끼는 부담의 종류를 이해하기 위한 문제입니다.', NULL, '{"1": "죄책감: 정서적 부담으로 분류됩니다.", "2": "소외감: 정서적 부담으로, 대인관계에서 오는 스트레스입니다.", "3": "불안감: 정서적 부담으로, 미래에 대한 걱정에서 기인합니다.\n[정답]", "4": "수면장애: 신체적 증상으로 치매 환자를 돌보는 과정에서 발생하는 신체적 부담입니다.", "5": "무기력감: 정서적 부담으로, 힘든 상황에 대한 반응입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억과 사고 능력이 감소하는 상태", "def_vi": "Tình trạng giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "부담", "term_vi": "Gánh nặng", "def_ko": "스트레스나 압박감", "def_vi": "Sự căng thẳng hoặc áp lực"}, {"term_ko": "신체적", "term_vi": "Về thể chất", "def_ko": "신체와 관련된", "def_vi": "Liên quan đến cơ thể"}, {"term_ko": "수면장애", "term_vi": "Rối loạn giấc ngủ", "def_ko": "잠을 제대로 자지 못하는 상태", "def_vi": "Tình trạng không thể ngủ đúng cách"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1489, '12', '치매 가족이 느끼는 부담 중 신체적 부담에 해당하는 것은?', '["죄책감", "소외감", "불안감", "수면장애", "무기력감"]'::jsonb, 4, '치매 가족이 경험하는 다양한 부담을 이해하고, 그중 신체적 부담이 무엇인지 파악하는 것이 중요하다.', NULL, '{"1": "죄책감은 정서적 부담에 해당한다.", "2": "소외감 역시 정서적 부담이다.", "3": "불안감은 주로 심리적 부담으로 분류된다.\n[정답]", "4": "수면장애는 신체적 상태에 직접적인 영향을 미치는 문제이다.", "5": "무기력감은 정서적인 반응으로 볼 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고력을 잃는 질병", "def_vi": "Bệnh mất trí nhớ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1488, '12', '치매 가족이 느끼는 부담에 대한 설명으로 옳은 것은?', '["치매 대상자가 나아질 것 같지 않은 무기력감을 느낀다.", "치매 대상자를 돌보는 것에 정서적 안도감을 느낀다.", "사회적 접촉이 늘어나면서 사회적 역할이 많아진다.", "가족의 상호이해와 협동으로 가족관계가 긍정적으로 변한다.", "전문가의 지원으로 역기능적 상호작용의 연쇄과정이 발생한다."]'::jsonb, 1, '치매가 가족에게 미치는 정신적, 정서적 부담을 이해하고 이를 설명할 수 있는지를 묻는 문제입니다.', NULL, '{"1": "치매 대상자가 나아질 것 같지 않은 무기력감을 느낀다.\n[정답] 치매에 대한 부정적인 인식으로 인해 가족 구성원들이 느끼는 무기력감과 부담을 적절히 설명합니다.", "2": "치매 대상자를 돌보는 것에 정서적 안도감을 느낀다.\n정서적 안도감이 아닌 부담을 느낌이 강조되는 문제입니다.", "3": "사회적 접촉이 늘어나면서 사회적 역할이 많아진다.\n오히려 사회적 접촉이 줄어들며 역할이 제한되는 경향이 있습니다.", "4": "가족의 상호이해와 협동으로 가족관계가 긍정적으로 변한다.\n부담이 증가하면서 관계가 부정적으로 변할 수 있습니다.", "5": "전문가의 지원으로 역기능적 상호작용의 연쇄과정이 발생한다.\n전문가 지원은 보통 긍정적인 영향을 미칩니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억이나 사고가 망가지는 질병", "def_vi": "Bệnh gây suy giảm trí nhớ hoặc tư duy"}, {"term_ko": "무기력감", "term_vi": "Cảm giác bất lực", "def_ko": "힘이 없고 무기력한 느낌", "def_vi": "Cảm giác không có sức mạnh hoặc khả năng"}, {"term_ko": "정서적", "term_vi": "Cảm xúc", "def_ko": "감정에 관한", "def_vi": "Liên quan đến tình cảm"}, {"term_ko": "상호이해", "term_vi": "Hiểu biết lẫn nhau", "def_ko": "서로의 이해", "def_vi": "Sự hiểu biết giữa hai hay nhiều người"}, {"term_ko": "전문가", "term_vi": "Chuyên gia", "def_ko": "특정 분야의 전문가", "def_vi": "Người có kiến thức chuyên sâu trong một lĩnh vực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1487, '11', '치매 노인의 환경적 자극의 질과 조정을 위한 방법으로 옳은 것은?', '["만남을 촉진하는 공간 배치를 한다.", "꽃 향기 등으로 감성을 자극한다.", "스스로 식사할 수 있는 환경을 만든다.", "걸려 넘어질 수 있는 바닥의 턱을 없앤다.", "의자, 탁자와 같은 소품을 여러 곳에 배치한다."]'::jsonb, 2, '치매 노인의 환경적 자극의 질과 조정을 이해하고, 적절한 방안을 선택할 수 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "만남을 촉진하는 공간 배치는 중요한 요소지만, 이 문제에서 요구하는 환경적 자극의 질과는 다소 거리가 있습니다.\n[정답]", "2": "꽃 향기 등으로 감성을 자극하면 치매 노인의 정서 및 인지적 반응을 긍정적으로 유도할 수 있습니다.", "3": "스스로 식사할 수 있는 환경을 만드는 것은 좋지만, 환경적 자극의 질 조정과는 직접적인 관련이 없습니다.", "4": "걸려 넘어질 수 있는 바닥의 턱을 없애는 것은 안전을 위한 조치이나, 자극의 질과는 관계가 없습니다.", "5": "의자, 탁자와 같은 소품을 여러 곳에 배치하는 것은 공간의 활용에 관한 것이지, 자극의 질과는 관련이 적습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력 및 인지 능력이 감소하는 노인성 질환", "def_vi": "Bệnh suy giảm trí nhớ và khả năng nhận thức ở người già"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주변의 상황과 조건", "def_vi": "Các tình huống và điều kiện xung quanh"}, {"term_ko": "자극", "term_vi": "Kích thích", "def_ko": "감각이나 반응을 일으키는 것", "def_vi": "Điều gợi ra cảm giác hay phản ứng"}, {"term_ko": "질", "term_vi": "Chất lượng", "def_ko": "무엇의 성질이나 상태", "def_vi": "Tính chất hoặc trạng thái của cái gì"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1486, '11', '장기요양기관에서 생활하는 치매대상자의 환경지원 지침 영역으로 다음 내용에 해당되는 것은?• 스스로 식사할 수 있는 환경을 조성한다. • 요리, 빨래, 장보기 등 활동을 할 수 있는 환경을 만든다.', '["지남력 지원", "자기 선택을 위한 지원", "기능적인 능력 지원", "환경적 자극의 질과 조정", "대상자의 교류를 위한 지원"]'::jsonb, 3, '장기요양기관에서 치매대상자의 환경지원을 어떻게 할 것인지에 대한 이해도를 묻고 있다.', NULL, '{"1": "지남력 지원: 지남력을 향상시키기 위한 방법, 문제의 내용과는 무관하다.", "2": "자기 선택을 위한 지원: 치매환자가 자신의 선택을 할 수 있도록 돕는 방법, 해당 내용과 부분적으로 관련 있다.\n[정답]", "3": "기능적인 능력 지원: 스스로 식사하고 활동할 수 있는 환경을 조성하는 것이면 기능적 능력을 지원하는 것에 해당한다.", "4": "환경적 자극의 질과 조정: 환경 자극의 질을 조정하는 것에 관한 것으로, 문제의 주제와는 다소 차이가 있다.", "5": "대상자의 교류를 위한 지원: 다른 사람과의 소통을 지원하는 것, 문제의 핵심과는 다르다."}'::jsonb, '[{"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기적으로 요양 및 치료를 제공하는 기관", "def_vi": "Nơi cung cấp chăm sóc và điều trị dài hạn"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고능력이 감소하는 질병", "def_vi": "Bệnh suy giảm trí nhớ và khả năng tư duy"}, {"term_ko": "환경지원", "term_vi": "Hỗ trợ môi trường", "def_ko": "지원을 통해 환경을 조성하는 것", "def_vi": "Tạo điều kiện môi trường thông qua hỗ trợ"}, {"term_ko": "기능적인 능력", "term_vi": "Khả năng chức năng", "def_ko": "필요한 작용을 수행할 수 있는 능력", "def_vi": "Khả năng thực hiện các chức năng cần thiết"}, {"term_ko": "자기 선택", "term_vi": "Lựa chọn cá nhân", "def_ko": "개인이 직접 선택하는 것", "def_vi": "Việc tự lựa chọn của cá nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1485, '11', '다음 내용에 해당하는 치매노인 환경지원 지침의 영역은?• 대상자가 생활하는 공간 입구에 이름표를 붙인다. • 시계나 달력을 잘 보이는 곳에 걸어둔다.', '["지남력 지원", "기능적인 능력지원", "자기 선택을 위한 지원", "안전, 안심을 위한 지원", "환경적 자극의 질과 조정"]'::jsonb, 1, '치매노인 환경지원 지침에 대해 이해하고 적용할 수 있는지를 평가하기 위함이다.', NULL, '{"1": "대상자가 지남력을 유지하도록 돕기 위해 환경을 조정하는 방안이다.\n[정답]", "2": "기능적인 능력을 유지할 수 있도록 돕는 것과는 관련이 없다.", "3": "자기 선택을 위한 지원과 관련된 내용은 아니다.", "4": "안전과 안심을 위한 지원은 해당 내용과는 관련이 없다.", "5": "환경적 자극의 질과 조정은 다른 측면이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고력의 기능이 저하되는 질병", "def_vi": "Bệnh suy giảm trí nhớ và khả năng tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1484, '11', '재가에서 청소하는 방법으로 옳은 것은?', '["방바닥의 먼지는 빗자루로 제거한다.", "양변기의 물때는 솔에 식초를 묻혀 닦는다.", "습기가 많은 화장실은 문을 닫아 놓는다.", "사용하지 않는 물건은 옮기거나 처분한다.", "쓰레기통에서 냄새가 나는 경우 방향제를 뿌린다."]'::jsonb, 2, '재가에서의 청소 방법에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "방바닥의 먼지는 빗자루로 제거하는 것은 기본적인 청소법이지만, 재가 청소에서는 진공청소기를 사용하는 것이 일반적입니다.\n[정답]", "2": "양변기의 물때는 솔에 식초를 묻혀 닦는 것이 효과적인 청소 방법입니다.", "3": "습기가 많은 화장실은 문을 닫아 놓으면 더욱 습해질 수 있으므로, 적절한 환기가 필요합니다.", "4": "사용하지 않는 물건은 옮기거나 처분하는 것이 맞지만, 이 방법이 청소 방법으로 보기는 어렵습니다.", "5": "쓰레기통에서 냄새가 나는 경우 방향제를 뿌리는 것보다는 쓰레기를 제때 비우는 것이 중요합니다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Tại nhà", "def_ko": "가정에서 요양 서비스가 제공되는 것", "def_vi": "Dịch vụ chăm sóc được cung cấp tại nhà"}, {"term_ko": "청소", "term_vi": "Dọn dẹp", "def_ko": "더러운 것을 치우는 것", "def_vi": "Làm sạch những thứ bẩn"}, {"term_ko": "양변기", "term_vi": "Bồn cầu", "def_ko": "욕실에서 사용하는 화장실 기구", "def_vi": "Thiết bị vệ sinh trong nhà tắm"}, {"term_ko": "물때", "term_vi": "Vết bẩn", "def_ko": "물이 마르면서 남는 더러운 자국", "def_vi": "Dấu bẩn còn lại khi nước khô"}, {"term_ko": "식초", "term_vi": "Giấm", "def_ko": "발효를 통해 만들어진 액체", "def_vi": "Chất lỏng được làm từ sự lên men"}, {"term_ko": "환기", "term_vi": "Thông gió", "def_ko": "공기가 순환하는 것", "def_vi": "Sự lưu thông không khí"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1483, '11', '재가 방문 시 청소하는 방법으로 옳은 것은?', '["배수구에 소독제 원액을 부어준다.", "시트나 침구는 가능한 낮에 정리한다.", "주변정돈 시 요양보호사가 알아서 정리한다.", "실내 청소를 할 때 젖은 걸레로 먼지를 제거한다.", "음식물 쓰레기는 모아 두었다가 일주일에 한 번 버린다."]'::jsonb, 4, '재가 방문 시 청소 방법에 대한 기본 지식 확인.', NULL, '{"1": "배수구에 소독제 원액을 부어주는 것은 부당하며, 적절히 희석하여 사용해야 한다.\n[정답]", "4": "실내 청소를 할 때 젖은 걸레로 먼지를 제거해야 청결을 유지할 수 있다.", "2": "시트나 침구는 낮에 정리하기 보다는 사용 후 즉시 정리하는 것이 바람직하다.", "3": "주변정돈 시 요양보호사가 아닌 환자가 직접 정리하는 것이 최선이다.", "5": "음식물 쓰레기는 즉시 처리하는 것이 위생적이다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Tại gia", "def_ko": "가정에서 요양을 제공받는 것", "def_vi": "Nhận được sự chăm sóc tại nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1482, '11', '대상자의 쾌적하고 안전한 실내 환경을 만드는 방법으로 옳은 것은?', '["커튼으로 자연채광을 차단한다.", "전체난방 보다는 국소난방을 한다.", "환기 시에는 직접환기방법을 사용한다.", "가스레인지는 대상자의 손이 닿지 않는 높이로 조정한다.", "현관이나 계단에 발밑을 비추는 조명을 설치한다."]'::jsonb, 5, '대상자의 쾌적하고 안전한 환경을 조성하기 위한 적절한 방법을 묻고 있습니다.', NULL, '{"1": "커튼으로 자연채광을 차단하면 실내 환경이 어두워져 쾌적하지 않다.\n[정답]", "5": "현관이나 계단에 발밑을 비추는 조명을 설치하면 안전사고를 예방할 수 있다.", "2": "전체난방보다 국소난방은 오히려 쾌적하지 않을 수 있다.", "3": "환기 시 직접환기방법은 불필요한 외부 공기를 유입시켜 쾌적하지 않을 수 있다.", "4": "가스레인지는 대상자의 손이 닿지 않는 높이에 조정하는 것이 좋지만 주의해야 할 점이 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối diện", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "쾌적", "term_vi": "Thoải mái", "def_ko": "편안함(한국어)", "def_vi": "Sự thoải mái"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주위 상황(한국어)", "def_vi": "Môi trường"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태(한국어)", "def_vi": "An toàn"}, {"term_ko": "조명", "term_vi": "Ánh sáng", "def_ko": "빛(한국어)", "def_vi": "Ánh sáng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1481, '11', '대상자의 안전하고 쾌적한 실내 환경을 조성하는 방법으로 옳은 것은?', '["현관이나 계단의 문턱을 낮춘다.", "가구 모서리에 덧대기를 한다.", "다리 간격이 좁은 식탁을 사용한다.", "안전손잡이는 마비가 있는 쪽으로 설치한다.", "환기 시에는 대상자가 바람을 직접 쐬게 한다."]'::jsonb, 2, '대상자의 안전과 쾌적함을 고려한 실내 환경 조성 방법에 대한 이해도를 평가하고자 함.', NULL, '{"1": "현관이나 계단의 문턱을 낮추는 것은 안전에 도움이 되지만, 직접적인 쾌적함과는 다소 거리가 있다.\n[정답]", "2": "가구 모서리에 덧대기를 하는 것은 사고를 예방하고 안전한 환경을 조성하는 방법이다.", "3": "다리 간격이 좁은 식탁은 오히려 불편함을 초래할 수 있다.", "4": "안전손잡이는 마비가 없는 쪽으로 설치해야 하며, 마비 있는 쪽은 불안정할 수 있어 주의가 필요하다.", "5": "환기 시 대상자가 직접 바람을 쐬는 것은 건강에 좋지 않을 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người chăm sóc", "def_ko": "환자, 대상", "def_vi": "Bệnh nhân, đối tượng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1480, '11', '쾌적하고 안전한 실내 환경을 조성하는 방법으로 옳은 것은?', '["야간에는 수면을 위해 전체 소등한다.", "실내에 직사광선이 들어오게 한다.", "여름에는 제습기, 겨울에는 가습기를 사용한다.", "배설물을 치울 때는 간접 조명을 사용한다.", "여름은 16~18도, 겨울은 25~26도의 실내온도를 유지한다."]'::jsonb, 3, '쾌적하고 안전한 실내 환경을 조성하는 방법을 이해하고 판단하는지 평가하기 위함입니다.', NULL, '{"1": "야간에는 수면을 위해 전체 소등하는 것은 안전과 관련하여 문제가 될 수 있습니다.\n[정답]", "3": "여름에는 제습기, 겨울에는 가습기를 사용하여 실내 환경의 습도를 조절하는 것은 매우 효과적입니다.", "2": "실내에 직사광선이 들어오게 하는 것은 온도를 불편하게 할 수 있습니다.", "4": "배설물을 치울 때 간접 조명을 사용하면 안전이 저하될 수 있습니다.", "5": "여름온도를 16~18도로 설정하는 것은 오히려 건강에 좋지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "쾌적", "term_vi": "안전", "def_ko": "편안한, dễ chịu", "def_vi": "안전한, an toàn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1479, '11', '대상자의 쾌적하고 안전한 실내 환경을 위한 방법으로 옳은 것은?', '["전기코드는 바닥에 고정시킨다.", "밤에는 거실과 화장실 조명을 끈다.", "욕실에 작은 나무 발판을 설치한다.", "몸이 충분히 잠기도록 깊은 욕조를 선택한다.", "하루 3번, 2~3시간 간격으로 창문을 열어 환기한다."]'::jsonb, 5, '대상자의 안전하고 쾌적한 생활 환경을 조성하는 방법에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "전기코드를 바닥에 고정시키는 것은 안전하지만, 가장 쾌적한 환경을 만드는 방법은 아닙니다.\n[정답]", "5": "하루 3번, 2~3시간 간격으로 창문을 열어 환기하는 것은 실내 공기를 쾌적하게 유지하는 가장 효과적인 방법입니다.", "3": "욕실에 작은 나무 발판을 설치하는 것은 안전에 도움이 될 수 있지만, 쾌적한 환경을 만드는 데에는 제한적입니다.", "4": "몸이 충분히 잠기도록 깊은 욕조를 선택하는 것은 편안함을 줄 수 있으나, 안전성을 고려하지 않아 위험할 수 있습니다.", "2": "밤에 거실과 화장실 조명을 끄는 것은 안전을 해칠 수 있는 행동입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Người nhận chăm sóc"}, {"term_ko": "쾌적", "term_vi": "Dễ chịu", "def_ko": "쾌적한 상태", "def_vi": "Trạng thái thoải mái"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태", "def_vi": "Tình trạng không có nguy hiểm"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주위의 상황", "def_vi": "Tình huống xung quanh"}, {"term_ko": "환기", "term_vi": "Thông gió", "def_ko": "공기의 흐름을 좋게 하다", "def_vi": "Cải thiện luồng không khí"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1478, '11', '대상자의 주거환경을 안전하게 관리하는 방법은?', '["화장실은 멀리 둔다.", "현관 입구를 좁게 만든다.", "대상자의 방에 비상벨을 달아둔다.", "창가에 작은 화분을 여러 개 놓는다.", "계단은 일직선의 계단으로 설치한다."]'::jsonb, 3, '대상자의 주거환경에서의 안전한 관리 방법을 이해하고 선택하는 것.', NULL, '{"1": "화장실을 멀리 두는 것은 안전과 관련이 없으며, 오히려 불편함을 초래할 수 있다.", "2": "현관 입구를 좁게 만드는 것은 접근성을 줄이며 위험할 수 있다.\n[정답]", "3": "대상자의 방에 비상벨을 달아두는 것은 안전을 위해 매우 중요하다.", "4": "창가에 작은 화분을 여러 개 놓는 것은 안전과 관계없이 장식적인 요소로, 사고를 유발할 수 있다.", "5": "계단은 일직선으로 설치하는 것이 아니라, 안전성을 고려하여 설계해야 한다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "환자를 받는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "주거환경", "term_vi": "Môi trường sống", "def_ko": "주거 공간의 안전 및 환경", "def_vi": "An toàn và môi trường sống"}, {"term_ko": "비상벨", "term_vi": "Chuông báo khẩn cấp", "def_ko": "긴급 상황을 알리는 장치", "def_vi": "Thiết bị báo động trong tình huống khẩn cấp"}, {"term_ko": "화분", "term_vi": "Chậu cây", "def_ko": "식물을 심는 용기", "def_vi": "Đồ dùng để trồng cây"}, {"term_ko": "접근성", "term_vi": "Khả năng tiếp cận", "def_ko": "접근할 수 있는 정도", "def_vi": "Mức độ tiếp cận"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1477, '11', '대상자의 안전한 주거환경으로 옳은 것은?', '["필요한 물품은 높은 곳에 정리해 둔다.", "방과 거실을 구분하기 위해 문턱을 둔다.", "현관에 신발을 신고 벗을 수 있게 의자를 놓아둔다.", "화장실은 안을 볼 수 있는 유리문으로 설치한다.", "싱크대는 손이 닿지 않는 높이로 조정한다."]'::jsonb, 3, '대상자의 안전한 주거환경 조성을 이해하고, 관련된 안전 수칙을 평가하기 위함입니다.', NULL, '{"1": "필요한 물품은 높은 곳에 정리해 둠으로써 오히려 안전에 위협이 될 수 있습니다.", "2": "방과 거실을 구분하기 위한 문턱은 넘어질 위험을 증가시킬 수 있습니다.\n[정답]", "3": "현관에 신발을 신고 벗을 수 있게 의자를 두는 것은 안전성을 높이는 좋은 방법입니다.", "4": "화장실은 안을 볼 수 있는 유리문으로 설치할 경우 사생활이 침해될 수 있습니다.", "5": "싱크대는 손이 닿지 않는 높이로 조정하면 사용이 불편해질 수 있습니다."}'::jsonb, '[{"term_ko": "안전", "term_vi": "An toàn", "def_ko": "안전(한국어)", "def_vi": "An toàn(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1476, '11', '대상자가 안전하게 화장실을 이용할 수 있도록 돕는 방법으로 옳은 것은?', '["화장실 문고리는 막대형으로 한다.", "화장실 표시는 입구 아래쪽에 한다.", "화장실 조명의 조도는 낮게 유지한다.", "화장실 복도에 화분을 두어 미관을 좋게 한다.", "화장실에 갈 때 신고 벗기 쉽게 슬리퍼를 신긴다."]'::jsonb, 1, '대상자가 안전하게 화장실을 이용할 수 있는 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "막대형 문고리는 손이 약한 노인이거나 장애인을 위해 사용하기 쉽습니다.\n[정답]", "2": "입구 아래쪽에 표지하면 시각적으로 불편함을 초래할 수 있습니다.", "3": "조도가 낮으면 화장실을 사용할 때 위험할 수 있습니다.", "4": "화분은 이동 시 장애가 될 수 있으므로 두지 않는 것이 좋습니다.", "5": "신고 벗기 쉬운 슬리퍼는 안전을 고려한 선택이 아닙니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người dùng", "def_ko": "이용의 객체(한국어)", "def_vi": "Đối tượng sử dụng"}, {"term_ko": "화장실", "term_vi": "Nhà vệ sinh", "def_ko": "개인 화장실(한국어)", "def_vi": "Phòng tắm cá nhân"}, {"term_ko": "조명", "term_vi": "Ánh sáng", "def_ko": "빛(한국어)", "def_vi": "Ánh sáng"}, {"term_ko": "복도", "term_vi": "Hành lang", "def_ko": "긴 통로(한국어)", "def_vi": "Hành lang"}, {"term_ko": "막대형", "term_vi": "Kiểu thanh", "def_ko": "긴 막대 모양(한국어)", "def_vi": "Dạng thanh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1475, '11', '재가대상자에게 일상업무 대행을 지원하는 방법으로 옳은 것은?', '["약국에서 대상자의 약품을 대신 받아준다.", "대상자 가족의 물품을 택배로 보낸다.", "대상자 집에 방문한 아들의 옷을 세탁한다.", "배우자의 심부름을 해준다.", "요양보호사의 사적인 업무를 함께 본다."]'::jsonb, 1, '재가대상자에게 제공할 수 있는 적절한 지원 방법을 이해하는지 평가하기 위함입니다.', NULL, '{"1": "약국에서 대상자의 약품을 대신 받아주는 것은 재가대상자의 일상업무 대행을 지원하는 올바른 방법입니다.\n[정답]", "2": "가족의 물품을 택배로 보내는 것은 재가대상자의 업무가 아니므로 부적절합니다.", "3": "아들의 옷을 세탁하는 것은 개인적인 일로, 재가대상자와의 관련이 없습니다.", "4": "배우자의 심부름을 해주는 것은 해당 업무에 해당하지 않습니다.", "5": "요양보호사의 사적인 업무를 돕는 것은 전문적인 서비스 제공과 관련이 없습니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người chăm sóc tại nhà", "def_ko": "가정에서 요양 서비스를 받는 사람", "def_vi": "Người nhận dịch vụ điều dưỡng tại nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1474, '11', '대상자의 관공서 업무대행 시 요양보호사의 올바른 태도는?', '["대행 경비에 서비스 비용을 추가하여 요구한다.", "대상자의 요구가 있을 경우 업무 담당자를 연계하여 준다.", "필요한 정보나 자료는 업무대행 중 대상자에게 전화로 확인한다.", "불만족하여 재요청 시는 정중히 거절한다.", "업무 대행 후 처리 결과만 전달한다."]'::jsonb, 2, '대상자의 관공서 업무를 대행하는 과정에서 요양보호사가 어떤 태도를 가져야 하는지를 평가하는 문제입니다.', NULL, '{"1": "대행 경비에 서비스 비용을 추가하여 요구하는 것은 부당한 행동입니다.\n[정답]", "2": "대상자의 요구가 있을 경우 업무 담당자를 연계하여 주는 것은 올바른 태도입니다.", "3": "필요한 정보나 자료를 업무대행 중 대상자에게 전화로 확인하는 것은 기본적으로 바람직하지 않습니다.", "4": "불만족하여 재요청 시 정중히 거절하는 것은 서비스 제공자로서 적절한 태도가 아닙니다.", "5": "업무 대행 후 처리 결과만 전달하는 것은 불완전한 서비스입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 서비스 요청자", "def_vi": "Người yêu cầu dịch vụ"}, {"term_ko": "관공서", "term_vi": "Cơ quan nhà nước", "def_ko": "정부 기관", "def_vi": "Cơ quan của chính phủ"}, {"term_ko": "업무대행", "term_vi": "Đại diện công việc", "def_ko": "업무 수행", "def_vi": "Thực hiện công việc"}, {"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "돌보는 사람", "def_vi": "Người chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1473, '11', '대상자와 외출 시 동행하는 방법으로 옳은 것은?', '["외출 시 필요한 준비물은 대상자가 챙기도록 한다.", "대상자의 개인물품은 분실할 수도 있음을 미리 알려준다.", "요양보호사의 자동차를 이용한다.", "외출장소 및 시간은 요양보호사가 정한다.", "오출 후 대상자의 만족 정도를 확인한다."]'::jsonb, 5, '대상자와 외출 시 동행하는 상황에서 올바른 행동 방침을 이해하고 선택하도록 하는 것.', NULL, '{"1": "외출 시 필요한 준비물은 대개 요양보호사가 챙기므로 대상자가 혼자 챙기는 것은 바람직하지 않다.", "2": "대상자의 개인물품 분실 가능성은 알고 있지만 미리 알려주는 것은 필요하지 않다.\n[정답]", "3": "요양보호사는 요청이나 상황에 따라 자동차를 이용할 수 있지만 반드시 그렇지는 않다.", "4": "외출장소 및 시간은 대상자와 협의하여 정하는 것이 적절하다.", "5": "외출 후 대상자의 만족 정도를 확인하는 것은 중요한 점검 사항으로 올바른 행동이다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "người bệnh hoặc người nhận sự chăm sóc"}, {"term_ko": "동행", "term_vi": "Đi cùng", "def_ko": "함께 가는 것", "def_vi": "đi cùng nhau"}, {"term_ko": "개인물품", "term_vi": "Đồ dùng cá nhân", "def_ko": "개인 소지품", "def_vi": "đồ cá nhân"}, {"term_ko": "분실", "term_vi": "Mất mát", "def_ko": "잃어버리는 것", "def_vi": "hành động đã mất"}, {"term_ko": "만족 정도", "term_vi": "Mức độ hài lòng", "def_ko": "만족하는 정도", "def_vi": "mức độ hài lòng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1472, '11', '대상자의 일상업무를 대행하기 전 확인해야 할 사항으로 옳은 것은?', '["경제적 능력 상태를 확인한다,", "함께 할 동료가 있는지 확인한다.", "업무 대행 전에 준비할 자료나 경비를 점검한다,", "어무 대행을 대신해 줄 사람이 있는지 확인한다.", "가족이 추가로 요구한 사항이 있는지 확인한다."]'::jsonb, 3, '대상자의 일상업무를 대행하기 전에 확인해야 할 사항에 대한 이해도를 평가하는 문제입니다.', NULL, '{"1": "경제적 능력 상태를 확인하는 것은 중요하지만, 대행 전에 확인할 주된 사항은 아닙니다.\n[정답]", "3": "업무 대행 전에 준비할 자료나 경비를 점검하는 것은 필수적입니다.", "2": "함께 할 동료가 있는지 확인하는 것도 중요하지만, 직접적인 대행 업무와는 관련이 없습니다.", "4": "어무 대행을 대신해 줄 사람이 있는지 확인하는 것은 상황에 따라 달라질 수 있습니다.", "5": "가족이 추가로 요구한 사항이 있는지 확인하는 것도 중요하지만, 우선적으로 준비해야 할 사항과는 거리가 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자나 도움을 받는 사람", "def_vi": "Người bệnh hoặc người nhận sự chăm sóc"}, {"term_ko": "일상업무", "term_vi": "Công việc hàng ngày", "def_ko": "일상의 작업이나 활동", "def_vi": "Công việc hoặc hoạt động trong cuộc sống hàng ngày"}, {"term_ko": "대행", "term_vi": "Thay thế", "def_ko": "다른 사람의 일을 대신하다", "def_vi": "Làm công việc của người khác"}, {"term_ko": "확인", "term_vi": "Xác nhận", "def_ko": "정확히 알거나 검토하다", "def_vi": "Biết hoặc xem xét một cách chính xác"}, {"term_ko": "준비", "term_vi": "Chuẩn bị", "def_ko": "필요한 것을 미리 갖추다", "def_vi": "Có sẵn những điều cần thiết trước"}, {"term_ko": "자료", "term_vi": "Tài liệu", "def_ko": "필요한 정보나 문서", "def_vi": "Thông tin hoặc văn bản cần thiết"}, {"term_ko": "경비", "term_vi": "Chi phí", "def_ko": "비용이나 지출", "def_vi": "Chi phí hoặc chi tiêu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1471, '11', '재가 대상자와 병원방문 동행 시 돕는 방법으로 옳은 것은?', '["진료 당일에는 복용하던 약을 중단하게 한다.", "요양보호사가 아는 병원으로 모시고 간다.", "장기요양인정서와 주민등록본을 준비한다.", "대상자의 신체 상태를 고려하여 이동보조기구를 준비한다.", "진료 후 알게 된 대상자의 상태를 기관장에게 비밀로 한다."]'::jsonb, 4, '재가 대상자에게 적절한 도움을 제공하는 방법을 이해하는지 평가하기 위함입니다.', NULL, '{"1": "대상자의 약 복용 중단은 의료진의 판단에 따라야 하므로 부적절합니다.\n[정답]", "2": "대상자의 편안함을 위해 아는 병원으로 가는 것이 적절하지 않을 수 있습니다.", "3": "필요한 서류는 준비해야 하지만, 이를 선택할 때 주의해야 합니다.", "4": "이동보조기구 준비는 대상자의 신체 상태에 따른 적절한 조치입니다.", "5": "진료 후 대상자의 상태는 비밀이 아닙니다. 관련 정보는 공유되어야 합니다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Chăm sóc tại nhà", "def_ko": "가정에서 요양을 받는 것", "def_vi": "Nhận chăm sóc tại ngôi nhà"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "요양이나 치료를 받는 사람", "def_vi": "Người nhận chăm sóc hoặc điều trị"}, {"term_ko": "신체 상태", "term_vi": "Tình trạng thể chất", "def_ko": "몸의 건강 상태", "def_vi": "Tình trạng sức khỏe của cơ thể"}, {"term_ko": "이동보조기구", "term_vi": "Thiết bị hỗ trợ di chuyển", "def_ko": "이동을 돕는 도구", "def_vi": "Công cụ giúp di chuyển"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1470, '11', '대상자가 진료를 받기 위해 병원을 방문할 때 동행하는 방법으로 옳은 것은?', '["비용을 아끼기 위해서", "방충효과각 약해지기 때문에", "오랫동안 사용하기 위해서", "냄새를 억제하기 위해서", "화학변화를 일으켜 옷감이 변질되므로"]'::jsonb, 3, '대상자가 병원에 방문할 때 동행하는 원인이나 목적에 대한 이해를 평가하는 문제입니다.', NULL, '{"1": "비용을 아끼기 위해서: 동행의 목적이 아닙니다.\n[정답]", "3": "오랫동안 사용하기 위해서: 대상자의 필요에 따라 동행이 필요할 수 있습니다.", "2": "방충효과가 약해지기 때문에: 동행의 목적과 관련이 없습니다.", "4": "냄새를 억제하기 위해서: 동행의 목적인 이 설명은 적절하지 않습니다.", "5": "화학변화를 일으켜 옷감이 변질되므로: 동행의 목적과 관계가 없습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1469, '11', '대상자의 옷을 보관할 때 한 가지 종류의 방충제를 사용해야 하는 가장 중요한 이유는?', '["비용을 아끼기 위해서", "방충효과가 약해지기 때문에", "오랫동안 사용하기 위해서", "냄새를 억제하기 위해서", "화학변화를 일으켜 옷감이 변질되므로"]'::jsonb, 5, '대상자의 옷을 보관할 때 방충제 사용의 중요성을 이해하고 선택하는 데 도움을 주기 위함입니다.', NULL, '{"1": "비용을 아끼기 위해서: 방충제를 사용하려는 주된 이유가 아닙니다.\n[정답]", "2": "방충효과가 약해지기 때문에: 방충제를 여러 가지 사용하는 것이 방충효과를 감소시킬 수 있습니다.", "3": "오랫동안 사용하기 위해서: 여러 종류의 방충제를 사용하면 오히려 문제가 발생할 수 있습니다.", "4": "냄새를 억제하기 위해서: 방충제의 기본 목적과는 거리가 있습니다.", "5": "화학변화를 일으켜 옷감이 변질되므로: 방충제가 여러 가지일 경우 화학적 반응이 일어나 옷감이 변질될 수 있습니다."}'::jsonb, '[{"term_ko": "방충제", "term_vi": "Thuốc chống côn trùng", "def_ko": "해충을 막기 위한 화학물질", "def_vi": "Hóa chất để ngăn côn trùng"}, {"term_ko": "변질", "term_vi": "Biến chất", "def_ko": "질이 나빠지거나 변하는 것", "def_vi": "Sự xấu đi hoặc thay đổi chất lượng"}, {"term_ko": "비용", "term_vi": "Chi phí", "def_ko": "지불해야 하는 금액", "def_vi": "Số tiền phải trả"}, {"term_ko": "효과", "term_vi": "Hiệu quả", "def_ko": "특정한 결과를 만들어내는 능력", "def_vi": "Khả năng tạo ra kết quả nhất định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1468, '11', '대상자의 의류를 관리하는 방법으로 옳은 것은?', '["다리미가 앞으로 나갈 때는 앞쪽에 힘을 준다.", "의류가 눅눅해지면 직사광선을 쏘인다.", "곰팡이가 생기면 2시간 이상 그늘에 건조시킨다.", "견 블라우스를 보관 시에는 방충제를 넣어둔다.", "방충제는 보관용기의 아래쪽 구석에 넣어둔다."]'::jsonb, 4, '대상자의 의류 관리에 대한 올바른 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "다리미 사용 시 힘을 주는 방향에 대한 설명은 올바르지 않습니다.\n[정답]", "2": "의류가 눅눅해졌을 때 직사광선에 노출하는 것은 적절하지 않습니다.", "3": "곰팡이가 발생했을 경우 건조시키는 방법이 잘못되었습니다.", "4": "견 블라우스를 보관할 때 방충제를 사용하는 것은 올바른 방법입니다.", "5": "방충제를 보관할 때 위치가 잘못된 설명입니다."}'::jsonb, '[{"term_ko": "의류", "term_vi": "Quần áo", "def_ko": "옷(한국어)", "def_vi": "đồ mặc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1467, '11', '다음 중 의류의 제품별 건조 방법으로 옳은 것은?', '["흰색 면직물 - 그늘에서 건조한다.", "청바지류 - 지퍼를 열고 뒤집어서 건조한다.", "니트류 - 옷걸이에 걸어서 건조한다.", "함성섬유류 - 햇빛에 건조한다.", "색상, 무늬가 있는 의류 - 햇빛에 건조한다."]'::jsonb, 2, '의류의 제품별 건조 방법에 대한 이해도를 평가하기 위한 문제이다.', NULL, '{"1": "흰색 면직물은 그늘에서 건조하는 것이 옳지 않다. 햇빛에 건조해야 색상을 유지할 수 있다.\n[정답]", "2": "청바지류는 지퍼를 열고 뒤집어서 건조하는 것이 적절하다. 이렇게 해야 형태가 변형되지 않는다.", "3": "니트류는 옷걸이에 걸어서 건조하는 것이 좋지 않고, 평평하게 놓고 건조해야 한다.", "4": "함성섬유류는 햇빛에서 건조하면 변색될 수 있으니 그늘에서 건조하는 것이 권장된다.", "5": "색상, 무늬가 있는 의류는 햇빛에 건조하면 색이 바랠 수 있다."}'::jsonb, '[{"term_ko": "의류", "term_vi": "건조", "def_ko": "옷, hàng hóa may mặc", "def_vi": "말리기, làm khô"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1466, '11', '대상자 옷을 세탁하는 방법으로 옳은 것은?', '["삶을 때 뚜겅을 덮고 삶는다.", "탈수시간을 길게하여 건조시간ㅇ르 줄인다.", "립스틱 얼룩은 초벌 세탁 후 아세톤을 묻혀 지운다.", "옷이 푹 잠기도록 비눗물을 넣어서 삶는다.", "세탁물은 비눗물을 여러번 헹군 후에 탈수한다."]'::jsonb, 1, '대상자의 옷을 올바르게 세탁하는 방법에 대한 이해도를 평가하고자 함.', NULL, '{"1": "삶을 때 뚜겅을 덮고 삶는다. - 옷이 고르게 세탁되며 위생적인 방법이다.\n[정답]", "2": "탈수시간을 길게하여 건조시간을 줄인다. - 탈수 시간이 길어지면 옷 손상이 우려된다.", "3": "립스틱 얼룩은 초벌 세탁 후 아세톤을 묻혀 지운다. - 아세톤은 특정 원단에 손상을 줄 수 있다.", "4": "옷이 푹 잠기도록 비눗물을 넣어서 삶는다. - 비누의 농도가 너무 높으면 옷에 잔여물이 남을 수 있다.", "5": "세탁물은 비눗물을 여러 번 헹군 후에 탈수한다. - 그러나 비누가 잔여물로 남을 가능성이 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "세탁하다(한국어)", "def_vi": "Giặt"}, {"term_ko": "비눗물", "term_vi": "Nước xà phòng", "def_ko": "비누와 물의 혼합물(한국어)", "def_vi": "Hỗn hợp xà phòng và nước"}, {"term_ko": "탈수", "term_vi": "Vắt nước", "def_ko": "오염물을 제거하기 위하여 물기를 짜내다(한국어)", "def_vi": "Ép nước để loại bỏ tạp chất"}, {"term_ko": "아세톤", "term_vi": "Acetone", "def_ko": "특정 물질(한국어)", "def_vi": "Chất bằng với aceton"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1465, '11', '대상자의 의류를 세탁하는 방법으로 옳은 것은?', '["혈액이나 체액은 더운 물로 제거 후 찬물로 헹군다.", "튀김기름 얼룩은 알코올로 제거한 후 세탁한다.", "면직물 속옷은 삶고 난 후 세탁한다.", "파운데이션 얼룩은 알코올이 함유된 화장수로 지운다.", "냄새가 심한 세탁물은 붕산수에 담갔다 헹군다."]'::jsonb, 4, '대상자의 의류 세탁에 대한 올바른 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "혈액이나 체액은 더운 물로 제거 후 찬물로 헹군다. - 혈액이나 체액은 찬물로 헹구어야 얼룩이 덜 남는다.\n[정답]", "2": "튀김기름 얼룩은 알코올로 제거한 후 세탁한다. - 튀김기름 얼룩은 알코올로 제거하기에는 적합하지 않다.", "3": "면직물 속옷은 삶고 난 후 세탁한다. - 삶은 후 세탁하지 않고, 세탁기를 사용하여 세탁한다.", "4": "파운데이션 얼룩은 알코올이 함유된 화장수로 지운다. - 파운데이션 얼룩은 알코올로 효과적으로 지울 수 있다.", "5": "냄새가 심한 세탁물은 붕산수에 담갔다 헹군다. - 붕산수로 헹구는 방법이 정확하지 않다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "người bệnh hoặc người nhận sự chăm sóc"}, {"term_ko": "의류", "term_vi": "Quần áo", "def_ko": "옷", "def_vi": "quần áo"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "세탁하기", "def_vi": "giặt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1464, '11', '변실금이 있는 대상자의 속옷을 세탁하는 방법으로 옳은 것은?', '["본세탁 전에 애벌빨래를 한다.", "삶을 때에는 뚜껑을 열고 삶는다.", "비눗물에 세탁물이 깊이 잠길 정도로 넣고 삶는다.", "얼룩을 제거한 후 표백제에 오래 담가 둔다.", "붕산수에 담갔다가 여러 번 헹구어 말린다."]'::jsonb, 1, '변실금이 있는 대상자의 속옷 세탁 방법에 대한 정확한 지식을 평가하기 위한 문제입니다.', NULL, '{"1": "변실금으로 인해 오염된 속옷은 본세탁 전에 애벌빨래를 통해 초기 오염 물질을 제거해야 합니다.\n[정답]", "2": "삶을 때에는 뚜껑을 열고 삶아야 고온의 증기가 효과적으로 작용하여 오염 물질이 제거됩니다.", "3": "비눗물에 세탁물이 깊이 잠길 정도로 넣고 삶는 것은 정확한 세탁 방법이 아닙니다.", "4": "얼룩을 제거한 후 표백제에 오래 담가 두는 것은 옷감 손상을 초래할 수 있습니다.", "5": "붕산수에 담갔다가 여러 번 헹구어 말리는 것은 일반적인 세탁 방법이 아닙니다."}'::jsonb, '[{"term_ko": "변실금", "term_vi": "Incontinence", "def_ko": "정해진 시간에 의식적으로 대변을 보고 못하는 상태(한국어)", "def_vi": "Tình trạng không thể kiểm soát việc đi vệ sinh theo giờ định sẵn"}, {"term_ko": "속옷", "term_vi": "Quần lót", "def_ko": "몸에 입는 속의 옷(한국어)", "def_vi": "Quần áo mặc ở bên trong"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "더러운 것을 씻어내는 것(한국어)", "def_vi": "Hành động rửa sạch vết bẩn"}, {"term_ko": "얼룩", "term_vi": "Vết bẩn", "def_ko": "더러운 부분(한국어)", "def_vi": "Phần bẩn"}, {"term_ko": "표백제", "term_vi": "Chất tẩy trắng", "def_ko": "옷감을 하얗게 만드는 화학물질(한국어)", "def_vi": "Hóa chất làm trắng vải"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1463, '11', '다음 중 옷을 세탁하는 방법으로 옳은 것은?', '["오염이 심할 때에는 불리거나 부분세탁을 병용한다.", "얼룩이 많은 옷은 모아서 한꺼번에 세탁한다.", "혈흔이 묻은 옷은 뜨거운 물에 세탁한다.", "속옷은 충분히 헹구어 그늘에 말린다.", "커피 얼룩은 샴푸를 이용하여 세탁한다."]'::jsonb, 1, '옷을 올바르게 세탁하는 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "오염이 심할 때에는 불리거나 부분세탁을 병용한다. [정답] 이는 특정 오염에 적합한 세탁 방법으로 옳습니다.", "2": "얼룩이 많은 옷은 모아서 한꺼번에 세탁한다. 이는 오히려 얼룩이 더 깊어질 수 있어 잘못된 방법입니다.", "3": "혈흔이 묻은 옷은 뜨거운 물에 세탁한다. 빨리 제거해야 하지만 뜨거운 물은 오히려 혈흔을 고착시킬 수 있어 잘못된 방법입니다.", "4": "속옷은 충분히 헹구어 그늘에 말린다. 이는 좋은 방법이지만, 세탁 방법을 두고 하는 질문에서 옳지 않습니다.", "5": "커피 얼룩은 샴푸를 이용하여 세탁한다. 이는 잘못된 방법으로, 전문 세정제를 사용하는 것이 바람직합니다."}'::jsonb, '[{"term_ko": "오염", "term_vi": "Ô nhiễm", "def_ko": "더러워짐(한국어)", "def_vi": "Sự bẩn thỉu"}, {"term_ko": "부분세탁", "term_vi": "Giặt một phần", "def_ko": "부분적으로 세탁하는 것(한국어)", "def_vi": "Giặt một phần"}, {"term_ko": "혈흔", "term_vi": "Vết máu", "def_ko": "피의 자국(한국어)", "def_vi": "Dấu vết của máu"}, {"term_ko": "뜨거운 물", "term_vi": "Nước nóng", "def_ko": "높은 온도의 물(한국어)", "def_vi": "Nước với nhiệt độ cao"}, {"term_ko": "속옷", "term_vi": "Đồ lót", "def_ko": "내부 옷(한국어)", "def_vi": "Quần áo bên trong"}, {"term_ko": "샴푸", "term_vi": "Shampoo", "def_ko": "머리 감는 물질(한국어)", "def_vi": "Chất tẩy rửa tóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1462, '11', '다음 중 옷을 세탁하는 방법으로 옳은 것은?', '["수선이 필요한 경우 세탁 후 수선한다.", "세탁물에 실금, 하혈이 있으면 재빨리 세탁한다.", "옷의 종류와 색상에 따라 분류하여 세탁한다.", "땀 얼룩이 묻은 옷은 그늘에서 말린 후 세탁한다.", "립스틱 얼룩은 표백제를 희석한 물에 담갔다 세탁한다."]'::jsonb, 3, '옷 세탁 방법에 대한 기본 지식을 평가하는 문제입니다.', NULL, '{"1": "수선이 필요한 경우에는 세탁 전에 수선하는 것이 일반적입니다.\n[정답]", "3": "옷의 종류와 색상에 따라 분류하여 세탁하는 것이 올바른 방법입니다.", "2": "세탁물에 실금이나 하혈이 있을 경우, 재빨리 세탁하기보다는 적절한 처리 후 세탁하는 것이 좋습니다.", "4": "땀 얼룩은 즉시 세탁이 필요하며, 그늘에서 말리는 것이 가장 좋습니다.", "5": "립스틱 얼룩은 표백제가 아닌 얼룩 제거제로 처리해야 합니다."}'::jsonb, '[{"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "세탁(한국어)", "def_vi": "Giặt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1461, '11', '대상자의 침구를 선택하고 관리하는 방법으로 옳은 것은?', '["시트는 색이 진하고 습기를 흡수하지 않는 재질을 사용한다.", "베개는 깃털이나 솜으로 된 소재를 선택한다.", "베개 높이는 척추와 머리가 수평이 되게 한다.", "감염대상자의 경우 베개를 매일 교환한다.", "시트는 정해진 날짜에만 바꾼다."]'::jsonb, 3, '대상자의 침구 관리에 대한 올바른 지식을 평가하기 위한 문제입니다.', NULL, '{"1": "시트는 색이 진하고 습기를 흡수하지 않는 재질을 사용한다. - 잘못된 정보입니다. 시트는 습기를 흡수할 수 있는 재질이 바람직합니다.\n[정답]", "2": "베개는 깃털이나 솜으로 된 소재를 선택한다. - 자주 사용되는 소재지만, 특정 상황에 따라 선호되지 않을 수 있습니다.", "3": "베개 높이는 척추와 머리가 수평이 되게 한다. - 적절한 높이의 베개가 척추 정렬에 중요한 역할을 합니다.", "4": "감염대상자의 경우 베개를 매일 교환한다. - 감염 위험이 높은 경우 매일 교환이 필요하지만, 모든 상황에서 그러한 것은 아닙니다.", "5": "시트는 정해진 날짜에만 바꾼다. - 필요에 따라 자주 바꾸어 주는 것이 좋습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Người nhận chăm sóc"}, {"term_ko": "침구", "term_vi": "Ga trải giường", "def_ko": "침대에 사용하는 직물", "def_vi": "Vải sử dụng cho giường"}, {"term_ko": "관리", "term_vi": "Quản lý", "def_ko": "관리와 보존", "def_vi": "Quản lý và bảo vệ"}, {"term_ko": "베개", "term_vi": "Gối", "def_ko": "머리를 받치는 기구", "def_vi": "Đồ vật đỡ đầu"}, {"term_ko": "척추", "term_vi": "Cột sống", "def_ko": "등뼈", "def_vi": "Xương sống"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "세균이나 바이러스에 감염되는 것", "def_vi": "Nhiễm vi khuẩn hoặc virus"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1460, '11', '침대에서 생활하는 대상자의 욕창을 예방하는 방법으로 옳은 것은?', '["풀을 먹인 시트를 사용한다.", "두겁고 재봉선이 있는 시트로 선택한다.", "시트의 주름을 반듯하고 팽팽하게 펴준다.", "베개는 습기와 열을 흡수하는 재질을 사용한다.", "침대 시트가 젖었을 때에는 체위변경을 한다."]'::jsonb, 3, '대상자의 욕창 예방을 위한 적절한 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "풀을 먹인 시트는 욕창 예방과는 관련이 없습니다.\n[정답]", "3": "시트의 주름을 반듯하고 팽팽하게 펴주는 것은 압박을 최소화하고 욕창을 예방하는 데 중요합니다.", "2": "두껍고 재봉선이 있는 시트는 오히려 압력을 증가시킬 수 있습니다.", "4": "베개는 습기와 열을 흡수하는 재질이어야 하나 욕창 예방과 직접적인 연관은 적습니다.", "5": "침대 시트가 젖었을 때 체위변경이 필요하지만, 시트 주름을 펴주는 것이 더욱 중요합니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부가 눌려서 손상되는 것(한국어)", "def_vi": "Vết thương do áp lực trên da(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1459, '11', '대상자의 침구류 관리 방법으로 옳은 것은?', '["두껍고 무거운 이불을 사용한다.", "매트리스는 푹신한 것이 좋다.", "시트의 크기는 매트리스와 같게 한다.", "양모와 오리털 이불은 그늘에서 말린다.", "습기를 흡수하는 매트리스를 사용한다."]'::jsonb, 4, '대상자의 침구류 관리 방법에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "두껍고 무거운 이불은 관리와 사용에 불편함을 줄 수 있습니다.\n[정답]", "4": "양모와 오리털 이불은 그늘에서 말리는 것이 적합하여 옳은 방법입니다.", "2": "매트리스는 개인의 선호에 따라 결정되지만 푹신한 것만이 좋은 것은 아닙니다.", "3": "시트의 크기는 매트리스보다 약간 더 크게 하는 것이 이상적입니다.", "5": "습기를 흡수하는 매트리스는 위생적인 측면에서 문제를 일으킬 수 있습니다."}'::jsonb, '[{"term_ko": "침구류", "term_vi": "Chăn ga", "def_ko": "침대에 사용하는 다양한 물품(한국어)", "def_vi": "Các vật dụng khác nhau sử dụng trên giường ngủ(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1458, '11', '야간 외출 시 대상자의 복장으로 바람직한 것은?', '["단추가 많은 하의를 입힌다.", "장식이 많은 상의를 입힌다.", "몸에 꽉 끼는 옷을 입힌다.", "밝은 색의 겉옷을 입힌다.", "신고 벗기 쉬운 슬리퍼를 신긴다."]'::jsonb, 4, '대상자가 야간 외출 시 안전하고 편리한 복장을 선택하도록 하는 것이다.', NULL, '{"1": "단추가 많은 하의를 입히는 것은 쉽게 벗겨질 수 있어 바람직하지 않다.", "2": "장식이 많은 상의를 입히는 경우 실용적이지 않으며 외출 시 불편할 수 있다.\n[정답]", "4": "밝은 색의 겉옷을 입히는 것은 야간에 시인성을 높여 안전을 증진할 수 있다.", "3": "몸에 꽉 끼는 옷은 편안함을 해칠 수 있으므로 적합하지 않다.", "5": "신고 벗기 쉬운 슬리퍼는 안전성을 고려했을 때 바람직하지 않다."}'::jsonb, '[{"term_ko": "복장", "term_vi": "Trang phục", "def_ko": "옷차림(한국어)", "def_vi": "Trang phục(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1457, '11', '대상자의 의복과 신발을 선택할 때 옳은 것은?', '["저녁 외출 시에는 어두운 색의 옷이 좋다.", "노인의 체형보다 큰 디자인이어야 한다.", "움직이는 데 불편이 없고 과도한 장식을 피한다.", "신발은 굽이 낮고 폭이 좁은 것이 좋다.", "시원하게 뒤가 트인 슬리퍼가 좋다."]'::jsonb, 3, '대상자의 의복과 신발 선택에 대한 올바른 이해를 평가하기 위함입니다.', NULL, '{"1": "저녁 외출 시 어두운 색의 옷이 좋지 않은 경우가 많습니다. 일반적으로 활동이나 안전을 고려할 때 밝은 색이 더 효과적입니다.\n[정답]", "3": "대상자가 움직일 때 편안해야 하며, 과도한 장식을 피해야 하는 것이 맞습니다.", "2": "노인의 체형보다 큰 디자인은 불편함을 줄 수 있으므로 적절하지 않습니다.", "4": "신발은 굽이 낮고 폭이 넓은 것이 좋습니다. 좁은 신발은 발에 압박을 줄 수 있습니다.", "5": "시원한 슬리퍼는 때때로 안전하지 않을 수 있으므로 권장되지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 돌보아야 할 사람", "def_vi": "Người bệnh hoặc người cần được chăm sóc"}, {"term_ko": "의복", "term_vi": "Trang phục", "def_ko": "옷", "def_vi": "Quần áo"}, {"term_ko": "신발", "term_vi": "Giày", "def_ko": "발을 보호하고 지탱하는 용품", "def_vi": "Sản phẩm bảo vệ và hỗ trợ chân"}, {"term_ko": "디자인", "term_vi": "Thiết kế", "def_ko": "외형이나 양식", "def_vi": "Hình dạng hoặc kiểu dáng"}, {"term_ko": "장식", "term_vi": "Trang trí", "def_ko": "꾸밈 또는 액세서리", "def_vi": "Sự trang trí hoặc phụ kiện"}, {"term_ko": "굽", "term_vi": "Gót", "def_ko": "신발의 높이 부분", "def_vi": "Phần cao của giày"}, {"term_ko": "폭", "term_vi": "Chiều rộng", "def_ko": "넓이", "def_vi": "Kích thước rộng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1456, '11', '대상자의 의복을 관리하는 기본원칙으로 옳은 것은?', '["속옷은 2~3일에 한 번 갈아입는 것이 좋다.", "얼룩이나 더러움이 심한 옷은 즉시 세탁한다.", "낡은 의류는 요양보호사가 판단하여 버린다.", "평소에 늘 입는 옷은 수납장 깊이 정리해 둔다.", "감염이 의심되는 대상자의 의류는 무조건 버린다."]'::jsonb, 2, '대상자의 의복 관리에 대한 기본적인 원칙을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "속옷은 2~3일에 한 번 갈아입는 것이 좋다. - 일반적으로 속옷은 하루에 한 번 갈아입는 것이 기본 원칙입니다.\n[정답]", "2": "얼룩이나 더러움이 심한 옷은 즉시 세탁한다. - 의복 관리의 기본 원칙으로 올바른 선택입니다.", "3": "낡은 의류는 요양보호사가 판단하여 버린다. - 의류의 처리는 고객의 동의를 받아야 합니다.", "4": "평소에 늘 입는 옷은 수납장 깊이 정리해 둔다. - 자주 입는 옷은 쉽게 접근할 수 있도록 정리해야 합니다.", "5": "감염이 의심되는 대상자의 의류는 무조건 버린다. - 감염 의심 시 세탁이나 소독이 필요하며, 무조건 버리는 것은 아닙니다."}'::jsonb, '[{"term_ko": "의복", "term_vi": "관리", "def_ko": "옷, trang phục", "def_vi": "관리하다, quản lý"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1455, '11', '주방의 위생관리 방법으로 옳은 것은?', '["냉장실을 자주 환기하여 냄새를 제거한다.", "변색된 음식은 가열한 후 냉장 보관한다.", "소독제 원액을 배수구에 부어 악취를 없앤다.", "싱크대 곰팡이는 주방용 세저제로 닦는다.", "수세미는 소독제를 희석한 물에 담가 두었다가 건조한다."]'::jsonb, 5, '주방의 위생관리 방법에 대한 올바른 지식을 확인하려는 의도입니다.', NULL, '{"1": "냉장실을 자주 환기하는 것은 좋지만, 냄새를 제거하는 방법으로는 부족합니다.\n[정답]", "2": "변색된 음식은 가열해도 안전하지 않기 때문에 냉장 보관이 적절하지 않습니다.", "3": "소독제 원액을 직접 배수구에 부으면 독성이 있을 수 있어서 위험합니다.", "4": "싱크대의 곰팡이는 주방용 세제로 닦는 것보다는 전문 세제를 사용하는 것이 효과적입니다.", "5": "수세미는 소독제를 희석한 물에 담가 두었다가 건조하는 것이 올바른 위생 관리 방법입니다."}'::jsonb, '[{"term_ko": "주방", "term_vi": "Nhà bếp", "def_ko": "주방(한국어)", "def_vi": "Nơi nấu nướng hoặc chế biến thực phẩm"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결(한국어)", "def_vi": "Sự sạch sẽ"}, {"term_ko": "소독제", "term_vi": "Thuốc tẩy", "def_ko": "소독약(한국어)", "def_vi": "Chất tẩy rửa diệt khuẩn"}, {"term_ko": "변색", "term_vi": "Thay đổi màu sắc", "def_ko": "색이 변함(한국어)", "def_vi": "Màu sắc không bình thường"}, {"term_ko": "세제", "term_vi": "Chất tẩy rửa", "def_ko": "세정제(한국어)", "def_vi": "Đồ dùng để làm sạch"}, {"term_ko": "수세미", "term_vi": "Miếng bọt biển", "def_ko": "주방용 스펀지(한국어)", "def_vi": "Đồ dụng làm sạch"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1454, '11', '식기 및 주방용품의 위생관리로 옳은 것은?', '["고무장갑은 사용 후 겉면만 세제로 씻는다.", "행주는 세척한 뒤 삶아서 건조한 후 보고나한다.", "기름기가 많은 그릇은 세제로 여러번 닦는다.", "수세미는 그물형보다 스펀지형이 위생적이다.", "유통기한이 지난 식재료는 냉동실에 얼린다."]'::jsonb, 2, '식기 및 주방용품의 올바른 위생 관리 방법을 이해하는지 평가하고자 함.', NULL, '{"1": "고무장갑은 사용 후 안쪽도 잘 씻어야 하며, 겉면만 세제로 씻는 것은 위생적이지 않음.\n[정답]", "2": "행주는 세척한 뒤 삶아서 건조하면 위생적으로 관리할 수 있음.", "3": "기름기가 많은 그릇은 세제를 사용하되 여러 번 닦는 것보다는 흡수력이 좋은 수세미로 한 번 닦아내는 것이 더 효과적임.", "4": "수세미는 그물형보다 스펀지형이 일반적으로 세척력이 높지만, 각기 장단점이 있어 사용 목적에 따라 다름.", "5": "유통기한이 지난 식재료는 냉동실에 얼려도 안전하지 않으므로 폐기해야 함."}'::jsonb, '[{"term_ko": "식기", "term_vi": "Dụng cụ ăn", "def_ko": "그릇(한국어)", "def_vi": "Đồ dùng ăn uống"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결(한국어)", "def_vi": "Sạch sẽ"}, {"term_ko": "관리", "term_vi": "Quản lý", "def_ko": "운영(한국어)", "def_vi": "Điều hành"}, {"term_ko": "행주", "term_vi": "Khăn bếp", "def_ko": "주방타올(한국어)", "def_vi": "Khăn dùng trong nhà bếp"}, {"term_ko": "세척", "term_vi": "Rửa", "def_ko": "씻다(한국어)", "def_vi": "Làm sạch"}, {"term_ko": "유통기한", "term_vi": "Hạn sử dụng", "def_ko": "유통 기간(한국어)", "def_vi": "Thời gian sử dụng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1453, '11', '식기 및 주방의 위생관리 방법으로 옳은 것은?', '["곰팡이가 발생한 싱크대는 희석한 알코올로 닦아준다.", "냉장실 선반은 희석한 락스로 닦고 건조한다.", "앞치마는 조리용과 청소용을 구분없이 함께 사용한다.", "냉장고를 청소하는 동안 꺼내둔 식품은 서늘한 곳에 모아둔다.", "고무장갑을 1개로 쓰는 경우에는 세제로 깨끗이 씻어 사용한다."]'::jsonb, 1, '식기 및 주방 위생관리에 대한 올바른 지식을 평가하고자 하는 문제입니다.', NULL, '{"1": "곰팡이가 발생한 싱크대는 희석한 알코올로 닦아준다. [정답] 이는 곰팡이를 제거하는 적절한 방법입니다.", "2": "냉장실 선반은 희석한 락스로 닦고 건조한다. 이는 올바른 위생관리 방법이지만 냉장실에서는 원래 식품이 잔류할 수 있습니다.", "3": "앞치마는 조리용과 청소용을 구분없이 함께 사용한다. 이는 위생상 바람직하지 않습니다.", "4": "냉장고를 청소하는 동안 꺼내둔 식품은 서늘한 곳에 모아둔다. 이는 안전지침이 아닙니다.", "5": "고무장갑을 1개로 쓰는 경우에는 세제로 깨끗이 씻어 사용한다. 고무장갑은 세척하여 재사용하기 어려운 경우가 많습니다."}'::jsonb, '[{"term_ko": "식기", "term_vi": "Dụng cụ ăn uống", "def_ko": "식사를 위한 그릇과 기구", "def_vi": "Bát đĩa và đồ dùng cho bữa ăn"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결하게 유지되는 상태", "def_vi": "Tình trạng được giữ sạch sẽ"}, {"term_ko": "곰팡이", "term_vi": "Nấm mốc", "def_ko": "곰팡이류의 세균", "def_vi": "Vi khuẩn thuộc nhóm nấm mốc"}, {"term_ko": "희석", "term_vi": "Pha loãng", "def_ko": "농도를 낮추는 것", "def_vi": "Làm giảm nồng độ"}, {"term_ko": "조리용", "term_vi": "Dùng để nấu ăn", "def_ko": "요리하기 위한 목적", "def_vi": "Mục đích để nấu ăn"}, {"term_ko": "청소용", "term_vi": "Dùng để dọn dẹp", "def_ko": "청소하기 위한 목적", "def_vi": "Mục đích để dọn dẹp"}, {"term_ko": "고무장갑", "term_vi": "Găng tay cao su", "def_ko": "고무로 만들어진 장갑", "def_vi": "Găng tay làm bằng cao su"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1452, '11', '도마와 칼이 한 개 밖에 없는 경우 사용 순서로 옳은 것은?', '["채소,과일 - 닭고기 - 육류 - 생선류", "채소,과일 - 육류 - 생선류 - 닭고기", "육류 - 채소,과일 - 닭고기 - 생선류", "생선류 - 채소,과일 - 육류 - 닭고기", "육류 - 닭고기 - 생선류 - 채소,과일"]'::jsonb, 2, '도마와 칼의 위생적인 사용을 이해하고 올바른 사용 순서를 파악하는 것.', NULL, '{"1": "채소와 과일을 먼저 다룬 후, 고기류를 다루는 것은 위생에 좋지 않다.\n[정답]", "2": "채소와 과일을 먼저 다루고, 그 다음에 육류와 생선류를 다룰 경우 식중독의 위험이 줄어든다.", "3": "육류를 먼저 다루는 것은 위생적이지 않다.", "4": "생선류를 먼저 다루는 것은 위생적이지 않다.", "5": "채소와 과일을 마지막에 다루는 것은 좋지 않다."}'::jsonb, '[{"term_ko": "도마", "term_vi": "Thớt", "def_ko": "나무나 플라스틱으로 만든 요리 도구", "def_vi": "Dụng cụ nấu ăn làm bằng gỗ hoặc nhựa"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1451, '11', '안전한 식품을 섭취하는 방법으로 옳은 것은?', '["계란 및 생선류는 살짝 가열하여 조리한다.", "음식이 부족하지 않도록 많은 양을 조리한다.", "과일은 100ppm 농도로 희석된 소독액으로 소독한다.", "조리된 음식, 육류, 생선은 같은 칸에 보관한다.", "냉동식품은 실온에서 해동시킨다."]'::jsonb, 3, '식품 안전과 위생에 대한 지식을 평가하기 위한 문제입니다.', NULL, '{"1": "계란과 생선류는 충분히 익혀서 조리해야 안전합니다.\n[정답]", "3": "과일은 소독액으로 소독하는 것이 안전한 섭취 방법입니다.", "2": "음식이 부족하지 않도록 조리하는 것도 중요하지만, 안전한 조리를 위한 방법은 아닙니다.", "4": "조리된 음식과 육류, 생선은 오염을 방지하기 위해 따로 보관해야 합니다.", "5": "냉동식품은 냉장고에서 해동해야 안전합니다."}'::jsonb, '[{"term_ko": "안전", "term_vi": "식품", "def_ko": "안전(한국어) / an toàn(베트남어)", "def_vi": "식품(한국어) / thực phẩm(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1450, '11', '다음 중 식중독을 유발하는 원인으로 옳은 것은?', '["고기를 60도로 요리했다.", "생육과 조리된 음식을 구분하여 보관한다.", "음식물이 남지 않도록 적당량만 조리한다.", "조리한 식품을 실온에 2시간 이상 방치하지 않는다.", "도마, 칼은 가열과 비가열 식품용으로 구분하여 사용한다."]'::jsonb, 1, '식중독의 원인과 예방 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "고기를 60도로 요리하여도 식중독을 유발할 수 있는 균이 살아남을 수 있습니다. [정답]", "2": "생육과 조리된 음식을 구분하여 보관하는 것은 식중독 예방에 매우 중요합니다.", "3": "음식물이 남지 않도록 조리하는 것은 위생적이나 식중독과는 직접적으로 관련이 없습니다.", "4": "조리한 식품을 실온에 2시간 이상 방치하는 것은 식중독의 위험을 증가시킵니다.", "5": "도마와 칼을 구분하여 사용하는 것은 안전한 조리를 위한 접근이나, 직접적인 식중독 유발 원인은 아닙니다."}'::jsonb, '[{"term_ko": "식중독", "term_vi": "Ngộ độc thực phẩm", "def_ko": "음식에 의해 발생하는 질병", "def_vi": "Bệnh do thực phẩm gây ra"}, {"term_ko": "원인", "term_vi": "Nguyên nhân", "def_ko": "어떤 일이 일어나는 이유", "def_vi": "Lý do xảy ra sự việc"}, {"term_ko": "예방", "term_vi": "Phòng ngừa", "def_ko": "사전에 방지하다", "def_vi": "Ngăn chặn trước"}, {"term_ko": "균", "term_vi": "Vi khuẩn", "def_ko": "미생물의 종류", "def_vi": "Loại vi sinh vật"}, {"term_ko": "조리", "term_vi": "Chế biến", "def_ko": "음식 만들기", "def_vi": "Làm thức ăn"}, {"term_ko": "실온", "term_vi": "Nhiệt độ phòng", "def_ko": "방 온도", "def_vi": "Nhiệt độ thông thường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1449, '11', '다음 중 식품을 보관하는 방법으로 옳은 것은?', '["생선은 통째로 냉동실에 보관한다.", "망고, 아보카도는 냉장실에 보관한다.", "오래 두고 먹는 달걀은 냉장실 문쪽에 보관한다.", "육류는 잘게 썰어 냉동 보관한다.", "냉장보관 시 음식을 담은 용기의 간격을 띄어 놓는다."]'::jsonb, 5, '식품 보관의 올바른 방법을 이해하는지 평가하기 위함입니다.', NULL, '{"1": "생선은 통째로 냉동실에 보관하면 품질이 저하될 수 있다.\n[정답]", "5": "냉장보관 시 음식을 담은 용기의 간격을 띄어 놓으면 공기가 순환되어 음식의 신선도가 유지된다.", "2": "망고와 아보카도는 일반적으로 상온에서 숙성 후 냉장 보관하는 것이 좋다.", "3": "달걀은 냉장실 문쪽에 보관하면 온도 변화로 인해 품질이 나빠질 수 있다.", "4": "육류는 통째로 냉동 보관하는 것이 품질 유지에 더 효과적이다."}'::jsonb, '[{"term_ko": "식품", "term_vi": "Thực phẩm", "def_ko": "음식(한국어)", "def_vi": "thực phẩm(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1448, '11', '다음 중 식중독이 발생할 가능성이 높은 경우는?', '["두부는 냉장 보관한다.", "달걀은 비벼 씻어서 보관한다.", "먹고 남은 음식은 즉시 버린다.", "생선과 조개류는 냉동 보관한다.", "육류는 냉장실에서 해동하거나 전자레인지를 이용한다."]'::jsonb, 2, '식중독의 발생 가능성을 이해하고, 안전한 식품 보관 방법에 대한 지식을 평가하기 위함입니다.', NULL, '{"1": "두부는 냉장 보관하여야 안전하게 유지된다.\n[정답]", "2": "달걀은 반드시 깨끗하게 씻어야 하지만, 비비는 방식은 오히려 오염을 초래할 수 있다.", "3": "먹고 남은 음식은 즉시 처분하는 것이 바람직하며, 이는 식중독 예방에 필수적이다.", "4": "생선과 조개류는 냉동 보관하여 안전하게 식품을 유지할 수 있다.", "5": "육류는 냉장실에서 안전하게 해동해야 하며, 전자레인지를 사용할 경우 균일하게 해동하지 못할 수 있다."}'::jsonb, '[{"term_ko": "식중독", "term_vi": "Ngộ độc thực phẩm", "def_ko": "음식으로 인해 발생하는 질병", "def_vi": "Bệnh xảy ra do thực phẩm"}, {"term_ko": "비비다", "term_vi": "Chà xát", "def_ko": "서로 문지르다", "def_vi": "Làm sạch bằng cách cọ xát"}, {"term_ko": "보관하다", "term_vi": "Bảo quản", "def_ko": "저장하다", "def_vi": "Lưu trữ"}, {"term_ko": "확신하다", "term_vi": "Tin chắc", "def_ko": "확실하게 믿다", "def_vi": "Tin tưởng một cách chắc chắn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1447, '11', '감자와 고구마를 보관하는 방법으로 옳은 것은?', '["통풍이 잘 되며 서늘하고 어두운 곳에 보관한다.", "끓는 물에 데쳐 냉동보관한다.", "표면에 식용유를 발라 냉장보관한다.", "신문지에 하나씩 포장하여 냉장ㅂ관한다.", "물을 뿌린 신문지에 싸서 실온에 보관한다."]'::jsonb, 1, '감자와 고구마의 보관에 대한 올바른 방법을 묻고 있다.', NULL, '{"1": "통풍이 잘 되며 서늘하고 어두운 곳에 보관한다. - 감자와 고구마는 적절한 보관 환경이 필요하므로 올바른 방법이다.\n[정답]", "2": "끓는 물에 데쳐 냉동보관한다. - 감자와 고구마는 데치면 영양소가 손실될 수 있어 잘못된 방법이다.", "3": "표면에 식용유를 발라 냉장보관한다. - 식용유를 바르면 부패가 촉진될 수 있어 잘못된 방법이다.", "4": "신문지에 하나씩 포장하여 냉장보관한다. - 냉장보관이 적합하지 않아서 잘못된 방법이다.", "5": "물을 뿌린 신문지에 싸서 실온에 보관한다. - 적절하지 않은 보관 방법으로 잘못된 방법이다."}'::jsonb, '[{"term_ko": "감자", "term_vi": "Khoai tây", "def_ko": "감자(한국어)", "def_vi": "Khoai tây (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1446, '11', '다음 중 식품을 위생적으로 보관하는 방법은?', '["열대과일은 냉잦ㅇ 보관한다.", "달걀은 물로 깨끗이 씻어 보관한다.", "생선은 통째로 소금을 뿌려 냉장보관한다.", "채소는 이물질 제거 후 밀폐용기에 담아 냉장보관한다.", "해동한 식품은 다시 냉동하여 재사용한다."]'::jsonb, 4, '식품 위생 관리의 중요성을 이해하고 올바른 보관 방법을 익히는 것이 의도입니다.', NULL, '{"1": "열대과일은 냉장 보관하는 것이 일반적으로 적절하나, 특정 과일은 상온에서 보관할 수 있습니다.", "2": "달걀은 물로 씻을 경우 세균이 침투할 수 있어, 세척하지 않고 보관하는 것이 좋습니다.\n[정답]", "4": "채소는 이물질 제거 후 밀폐용기에 담아 냉장보관하는 것이 위생적인 방법입니다.", "3": "생선은 소금을 뿌린 뒤 곧바로 냉장 보관하는 것이 바람직하지 않으며, 소금처리 후 오랫동안 냉장 하면 품질이 떨어질 수 있습니다.", "5": "해동한 식품은 재냉동이 안전하지 않으며, 반드시 조리 후 소비해야 합니다."}'::jsonb, '[{"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결을 유지하는 것", "def_vi": "Duy trì sự sạch sẽ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1445, '11', '대상자의 집 냉장고에서 부패한 계란찜을 발견했을 때 올바른 대처방법은?', '["끓여서 다시 먹을 수 있도록 한다.", "냉장고의 온도와 다른 음식의 상태를 점검한다.", "상한 부분만 버리고 다시 냉장 보관한다.", "즉시 폐기한 후 나중에 설명한다.", "가능한 빨리 섭취하도록 알려준다."]'::jsonb, 2, '대상자의 음식 안전 및 위생 관리에 대한 올바른 대처 방법을 평가하기 위함입니다.', NULL, '{"1": "끓여서 다시 먹을 수 있도록 하는 것은 잘못된 방법입니다. 부패한 음식은 안전하지 않으므로 섭취해서는 안 됩니다.\n[정답]", "2": "냉장고의 온도와 다른 음식의 상태를 점검하는 것은 올바른 대처 방법입니다. 이는 위생적이고 안전한 음식 관리를 위해 필수적입니다.", "3": "상한 부분만 버리고 다시 냉장 보관하는 것은 적절하지 않습니다. 부패는 음식 전체에 퍼질 수 있기 때문입니다.", "4": "즉시 폐기한 후 나중에 설명하는 것은 대처 방법이긴 하지만, 음식 안전 관점에서 필요할 경우 점검이 우선시 되어야 합니다.", "5": "가능한 빨리 섭취하도록 알려주는 것은 부패한 음식을 권장하는 잘못된 조치입니다."}'::jsonb, '[{"term_ko": "부패", "term_vi": "Hư hỏng", "def_ko": "음식의 상태가 나빠지는 것", "def_vi": "Trạng thái bị xấu đi của thực phẩm"}, {"term_ko": "냉장고", "term_vi": "Tủ lạnh", "def_ko": "음식을 차갑게 보관하는 기계", "def_vi": "Thiết bị bảo quản thực phẩm lạnh"}, {"term_ko": "온도", "term_vi": "Nhiệt độ", "def_ko": "어떤 대상을 이루고 있는 열의 정도", "def_vi": "Độ nóng của một đối tượng"}, {"term_ko": "음식", "term_vi": "Thực phẩm", "def_ko": "사람이 섭취하는 것", "def_vi": "Những thứ mà con người ăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1444, '11', '질환에 따라 섭취해야 할 음식으로 옳은 것은?', '["당뇨병: 꿀, 육류", "고혈압: 젓갈류, 장아찌", "골다공증: 미역, 두부", "만성신부전: 많은 양의 물", "변비: 콜라, 녹차"]'::jsonb, 3, '질환별로 적절한 식이요법을 이해하고 있는지 평가하기 위함입니다.', NULL, '{"1": "당뇨병 환자는 꿀과 육류를 피해야 합니다. 당뇨병 관리에 적합하지 않은 식사입니다.", "2": "고혈압 환자는 젓갈류와 장아찌와 같은 나트륨 함량이 높은 음식은 피해야 합니다.\n[정답]", "3": "골다공증은 칼슘이 풍부한 미역과 두부를 섭취하는 것이 좋습니다.", "4": "만성신부전 환자는 수분 섭취를 제한해야 하므로 많은 양의 물은 부적합합니다.", "5": "변비에는 섬유소가 풍부한 음식을 섭취해야 하며, 콜라와 녹차는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "질환", "term_vi": null, "def_ko": "병", "def_vi": null}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1443, '11', '변비로 고생하는 대상자의 식사 원칙으로 옳은 것은?', '["보리, 검정콩, 미역을 섭취한다.", "생과일 대신 과일 통조림을 섭취한다.", "비타민 D와 칼슘보충제를 함께 복용한다.", "가급적 도정을 많이 한 곡류를 섭취한다.", "식이섬유의 흡수를 위해 수분 섭취를 제한한다."]'::jsonb, 1, '대상자의 변비 완화를 위한 적절한 식사 원칙을 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "보리, 검정콩, 미역은 식이섬유가 풍부하여 변비 개선에 도움을 줍니다.\n[정답]", "2": "생과일 대신 과일 통조림은 섬유질이 상대적으로 적어 변비 해소에 도움이 되지 않습니다.", "3": "비타민 D와 칼슘보충제는 변비에 특별한 영향을 미치지 않습니다.", "4": "도정을 많이 한 곡류는 섬유질이 적어 변비에 좋지 않습니다.", "5": "수분 섭취는 오히려 변비 예방에 필요하므로 제한해서는 안 됩니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "배변이 어려운 상태", "def_vi": "Tình trạng khó đi tiêu"}, {"term_ko": "식사 원칙", "term_vi": "Nguyên tắc ăn uống", "def_ko": "건강한 식사를 위한 규칙", "def_vi": "Quy tắc cho bữa ăn lành mạnh"}, {"term_ko": "식이섬유", "term_vi": "Chất xơ", "def_ko": "식물에서 발견되는 영양소", "def_vi": "Dinh dưỡng có trong thực vật"}, {"term_ko": "비타민", "term_vi": "Vitamin", "def_ko": "몸에 필요한 유기 화합물", "def_vi": "Hợp chất hữu cơ cần thiết cho cơ thể"}, {"term_ko": "칼슘", "term_vi": "Canxi", "def_ko": "뼈와 이의 건강에 필요한 미네랄", "def_vi": "Khoáng chất cần thiết cho xương và răng"}, {"term_ko": "수분", "term_vi": "Nước", "def_ko": "몸의 기능을 유지하는 물", "def_vi": "Nước cần thiết cho chức năng của cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1442, '11', '다음 중 변비 완화에 도움이 되는 식품은?', '["돼지고기", "커피, 콜라", "홍차, 녹차", "초콜릿, 치즈", "잡곡류. 생과일, 생채소"]'::jsonb, 5, '변비 완화에 도움이 되는 식품을 구분하는 문제입니다.', NULL, '{"1": "돼지고기는 식이섬유가 적어 변비 완화에 비효율적입니다.\n[정답]", "5": "잡곡류, 생과일, 생채소는 식이섬유가 풍부하여 변비 완화에 효과적입니다.", "2": "커피와 콜라는 이뇨 작용이 있지만 변비에 직접적인 도움이 되지 않습니다.", "3": "홍차와 녹차는 카페인이 들어 있어 사실상 탈수 효과가 있어 변비에 좋지 않습니다.", "4": "초콜릿과 치즈는 변비를 악화시킬 수 있는 식품입니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "장이 제대로 기능하지 않아 대변이 딱딱해지는 상태", "def_vi": "Tình trạng ruột không hoạt động đúng cách gây ra phân cứng"}, {"term_ko": "완화", "term_vi": "Giảm nhẹ", "def_ko": "증상을 덜어주는 것", "def_vi": "Làm nhẹ triệu chứng"}, {"term_ko": "식품", "term_vi": "Thực phẩm", "def_ko": "먹을 수 있는 것", "def_vi": "Những thứ có thể ăn"}, {"term_ko": "잡곡류", "term_vi": "Ngũ cốc hỗn hợp", "def_ko": "섞인 곡물", "def_vi": "Các loại ngũ cốc trộn lẫn"}, {"term_ko": "생과일", "term_vi": "Trái cây tươi", "def_ko": "갓 따온 과일", "def_vi": "Trái cây vừa hái"}, {"term_ko": "생채소", "term_vi": "Rau sống", "def_ko": "신선한 채소", "def_vi": "Rau tươi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1441, '11', '음식물을 삼키는 데에 어려움이 있는 대상자의 식사를 돕는 방법은?', '["국수를 돌돌 말아서 먹게 한다.", "과일은 건더기 없이 주스로 먹인다.", "익힌 챗소보다 신선한 생채소를 먹인다.", "물을 마실 때 점도 증진제를 사용하지 않는다.", "한 번에 조금씩 떠 먹이고 여러 번에 걸쳐 삼키게 한다."]'::jsonb, 5, '음식물을 삼키는 데 어려움이 있는 대상자에게 안전하고 효율적인 식사 방법을 묻는 문제입니다.', NULL, '{"1": "국수를 돌돌 말아서 먹게 하면 삼키기 어려울 수 있습니다.\n[정답]", "5": "한 번에 조금씩 떠 먹이고 여러 번에 걸쳐 삼키게 하면 안전하게 식사를 도울 수 있습니다.", "2": "과일을 주스로 먹이는 것은 영양소 섭취에는 도움이 되지만 식사는 본래의 형태를 유지하는 것이 좋습니다.", "3": "익힌 챗소보다 신선한 생채소를 먹이는 것은 소화에 불리할 수 있습니다.", "4": "물을 마실 때 점도 증진제를 사용하는 것이 일반적으로 도움이 될 수 있습니다."}'::jsonb, '[{"term_ko": "음식물", "term_vi": "Thức ăn", "def_ko": "음식", "def_vi": "Thức ăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1440, '11', '삼킴 자애를 가진 대상자의 식사를 돕는 방법으로 옳은 것은?', '["밥을 국인 물에 말아 먹인다.", "사과를 숟가락으로 긁어 먹인다.", "계란은 반숙보다 완숙으로 한다.", "채소는 신맛이 강한 소스를 뿌려 먹인다.", "떠먹이는 것보다 마시는 형태의 유제품을 먹인다."]'::jsonb, 2, '(삼킴 자애를 가진 대상자가 안전하게 음식을 섭취할 수 있는 방법을 묻는 문제입니다.)', NULL, '{"1": "밥을 국인 물에 말아 먹이는 것은 삼킴 자애를 가진 대상자에게 위험할 수 있습니다.\n[정답]", "2": "사과를 숟가락으로 긁어 먹이는 것은 삼킴 자애를 가진 대상자가 안전하게 음식을 섭취하는 방법입니다.", "3": "계란은 반숙보다 완숙으로 하는 것은 사실상 영향이 적습니다.", "4": "채소는 신맛이 강한 소스를 뿌려 먹이는 것은 삼킴 장애가 있는 대상자에게 적합하지 않습니다.", "5": "떠먹이는 것보다 마시는 형태의 유제품을 먹이는 것은 삼킴에 도움을 줄 수 있지만, 모든 형태에 따라 다를 수 있습니다."}'::jsonb, '[{"term_ko": "삼킴 자애", "term_vi": null, "def_ko": "인 swallowing difficulties(한국어)", "def_vi": null}, {"term_ko": "안전", "term_vi": null, "def_ko": "안전한 것 safe(한국어)", "def_vi": null}, {"term_ko": "사과", "term_vi": null, "def_ko": "apple(한국어)", "def_vi": null}, {"term_ko": "숟가락", "term_vi": null, "def_ko": "spoon(한국어)", "def_vi": null}, {"term_ko": "반숙", "term_vi": null, "def_ko": "soft-boiled(한국어)", "def_vi": null}, {"term_ko": "완숙", "term_vi": null, "def_ko": "hard-boiled(한국어)", "def_vi": null}, {"term_ko": "채소", "term_vi": null, "def_ko": "vegetable(한국어)", "def_vi": null}, {"term_ko": "소스", "term_vi": null, "def_ko": "sauce(한국어)", "def_vi": null}, {"term_ko": "형태", "term_vi": null, "def_ko": "form(한국어)", "def_vi": null}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1439, '11', '고혈압이 있는 대상자에게 섭취를 제한해야 하는 음식은?', '["저지방 우유", "빵, 베이컨", "보리밥, 삶은 양배추", "현미밥, 콩나물국", "카레가루를 입혀 구운 삼치"]'::jsonb, 2, '고혈압 환자에게 적절한 식이를 알려주기 위함입니다.', NULL, '{"1": "저지방 우유는 고혈압 환자에게 권장되는 음식입니다.\n[정답]", "2": "빵, 베이컨은 나트륨 함량이 높아 섭취를 제한해야 합니다.", "3": "보리밥과 삶은 양배추는 고혈압 환자에게 좋습니다.", "4": "현미밥과 콩나물국도 권장됩니다.", "5": "카레가루를 입혀 구운 삼치는 나트륨이 적지만, 조리 방법에 따라 다를 수 있습니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "대상자", "def_ko": "높은 huyết áp", "def_vi": "bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1438, '11', '고혈압 대상자가 섭취할 음식으로 옳은 것은?', '["찐 고구마", "강된장", "깻잎장아찌", "삼겹살 구이", "자반 고등어조림"]'::jsonb, 1, '고혈압 환자에게 적합한 식단에 대한 이해를 확인하고자 하는 문제입니다.', NULL, '{"1": "찐 고구마는 식이섬유와 칼륨이 풍부해 고혈압 관리에 도움이 됩니다.\n[정답]", "2": "강된장은 나트륨이 많아 고혈압에 좋지 않습니다.", "3": "깻잎장아찌 또한 나트륨이 포함되어 있어 고혈압에 부적합합니다.", "4": "삼겹살 구이는 지방 함량이 높아 고혈압 환자에게 좋지 않습니다.", "5": "자반 고등어조림은 염분이 많아 고혈압에 좋지 않습니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "Tăng huyết áp", "def_ko": "높은 혈압 상태", "def_vi": "Tình trạng huyết áp cao"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1437, '11', '당뇨병 대상자의 식사 관리로 옳은 것은?', '["혈당지수가 높은 식품을 제공한다.", "포만감을 주는 식이섬유 섭취를 제한한다.", "식사 때마다 튀김이나 볶음 요리를 제공한다.", "향신료를 이용하여 음식을 싱겁게 조리한다.", "배고픔을 느끼지 않도록 식사를 자주 하게 한다."]'::jsonb, 4, '당뇨병 대상자의 올바른 식사 관리를 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "혈당지수가 높은 식품은 혈당을 급격하게 높일 수 있어 잘못된 선택입니다.\n[정답]", "4": "향신료를 이용해 음식을 싱겁게 조리하면 나트륨 섭취를 줄이는데 도움이 됩니다.", "2": "포만감을 주는 식이섬유는 오히려 섭취를 권장해야 합니다.", "3": "튀김이나 볶음 요리는 지방이 많아 건강에 좋지 않으므로 피해야 합니다.", "5": "식사를 자주 하는 것은 좋지만 그 양과 내용에 따라 조절이 필요합니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "식사", "def_ko": "성인병, bệnh tiểu đường", "def_vi": "식사, bữa ăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1436, '11', '당뇨병 대상자의 혈당 관리에 도움이 되는 혈당지수가 낮은 식품은?', '["수박", "흰밥", "찐감자", "미역", "식빵"]'::jsonb, 4, '당뇨병 대상자의 식단에서 혈당 지수가 낮은 식품을 선택하도록 함으로써 혈당 관리의 중요성을 강조하려는 의도입니다.', NULL, '{"1": "수박: 혈당 지수가 비교적 높아 혈당 관리에 적합하지 않음.\n[정답]", "4": "미역: 혈당 지수가 낮아 당뇨병 관리에 도움이 되는 식품.", "2": "흰밥: 혈당 지수가 높아 피해야 할 식품.", "3": "찐감자: 혈당 지수가 높아 당뇨 관리에 적절하지 않음.", "5": "식빵: 혈당 지수가 높아 적합하지 않음."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "병으로 인슐린 분비의 이상 또는 세포의 저항으로 혈당이 상승하는 질병", "def_vi": "Bệnh khiến độ đường trong máu tăng do sự bất thường trong tiết insulin hoặc sự kháng insulin của tế bào"}, {"term_ko": "혈당", "term_vi": "Đường huyết", "def_ko": "혈액에 있는 포도당의 양", "def_vi": "Lượng glucose trong máu"}, {"term_ko": "식품", "term_vi": "Thực phẩm", "def_ko": "섭취할 수 있는 음식의 종류", "def_vi": "Loại thực phẩm có thể tiêu thụ"}, {"term_ko": "지수", "term_vi": "Chỉ số", "def_ko": "비교의 기준이 되는 수치나 등급", "def_vi": "Con số hoặc thứ hạng được sử dụng làm tiêu chuẩn so sánh"}, {"term_ko": "관리", "term_vi": "Quản lý", "def_ko": "상태를 잘 유지하도록 돌보거나 조정하는 것", "def_vi": "Hành động chăm sóc hoặc điều chỉnh để duy trì tình trạng tốt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1435, '11', '당뇨병 대상자의 식품섭취 방법으로 옳은 것은?', '["식사 전 술을 마신다.", "커피, 탄산음료수를 자주 마신다.", "흰밥보다 잡곡밥을 섭취한다.", "생과일보다 광리주스를 섭취한다.", "설탕이나 꿀 등 단순당을 주로 섭취한다."]'::jsonb, 3, '당뇨병 대상자가 건강한 식품섭취 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "식사 전 술을 마신다. - 술은 혈당에 영향을 미칠 수 있어 당뇨병 환자에게 좋지 않다.\n[정답]", "3": "흰밥보다 잡곡밥을 섭취한다. - 잡곡밥은 섬유소가 많고 혈당 조절에 도움이 된다.", "2": "커피, 탄산음료수를 자주 마신다. - 당뇨병 환자는 단 음료를 피하는 것이 좋다.", "4": "생과일보다 광리주스를 섭취한다. - 생과일에는 섬유소가 있어 좋다.", "5": "설탕이나 꿀 등 단순당을 주로 섭취한다. - 단순당은 혈당을 급격히 올릴 수 있다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "병 상태(한국어)", "def_vi": "Tình trạng bệnh"}, {"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "특정 개인(한국어)", "def_vi": "Cá nhân cụ thể"}, {"term_ko": "식품섭취", "term_vi": "Thực phẩm tiêu thụ", "def_ko": "음식 섭취 활동(한국어)", "def_vi": "Hoạt động tiêu thụ thực phẩm"}, {"term_ko": "잡곡밥", "term_vi": "Cơm gạo lứt", "def_ko": "여러 곡물의 혼합(한국어)", "def_vi": "Hỗn hợp nhiều loại ngũ cốc"}, {"term_ko": "혈당", "term_vi": "Đường huyết", "def_ko": "혈액 중의 포도당(한국어)", "def_vi": "Glucose trong máu"}, {"term_ko": "단순당", "term_vi": "Đường đơn", "def_ko": "쉽게 소화되는 당(한국어)", "def_vi": "Đường dễ tiêu hóa"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1434, '11', '당뇨병 대상자의 식사 돕기 방법으로 옳은 것은?', '["단순당질 섭취를 제한한다.", "해조류의 섭취를 줄인다.", "식사를 많이 하여 체중을 늘린다.", "동물성 지방 섭취를 많이 한다.", "혈당지수가 높은 식품을 선택한다."]'::jsonb, 1, '당뇨병 대상자의 건강한 식사 관리를 이해하고 있는지 평가하기 위한 문제입니다.', NULL, '{"1": "단순당질 섭취를 제한하는 것은 당뇨병 관리에 필수적입니다.\n[정답]", "2": "해조류의 섭취를 줄이는 것은 특정 상황에서 필요할 수 있지만, 일반적으로 해조류는 영양소가 풍부하여 권장됩니다.", "3": "식사를 많이 하여 체중을 늘리는 것은 당뇨병 관리에 적합하지 않습니다.", "4": "동물성 지방 섭취를 많이 하는 것은 건강에 좋지 않으며, 당뇨병 관리에 도움이 되지 않습니다.", "5": "혈당지수가 높은 식품을 선택하는 것은 당뇨병에 해롭습니다."}'::jsonb, '[{"term_ko": "단순당질", "term_vi": "Carbohydrate đơn giản", "def_ko": "단순한 설탕과 같은 간단한 형태의 탄수화물", "def_vi": "dạng carbohydrate đơn giản như đường"}, {"term_ko": "해조류", "term_vi": "Rong biển", "def_ko": "바다에서 나는 식물", "def_vi": "thực vật mọc dưới biển"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 것", "def_vi": "việc ăn uống"}, {"term_ko": "체중", "term_vi": "Cân nặng", "def_ko": "신체의 무게", "def_vi": "trọng lượng cơ thể"}, {"term_ko": "동물성 지방", "term_vi": "Chất béo động vật", "def_ko": "동물에서 유래한 지방", "def_vi": "chất béo có nguồn gốc từ động vật"}, {"term_ko": "혈당지수", "term_vi": "Chỉ số đường huyết", "def_ko": "혈당을 오르는 속도를 나타내는 지수", "def_vi": "chỉ số thể hiện tốc độ tăng đường huyết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1433, '11', '영양밀도를 높이고 먹기 쉽게 조리하는 방법으로 옳은 것은?', '["나물류는 미리 무쳐서 놓는다.", "식품 자체의 맛보다 양념 맛을 강조한다.", "샐러듣드레싱으로 마요네즈를 이용한다.", "쑥갓나물 무침에 삶아서 으깬 두부를 넣는다.", "사태나 양지는 결 방향으로 잘라 높은 온도로 단시간 조리한다."]'::jsonb, 4, '영양밀도를 높이고 먹기 쉽게 조리하는 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "나물류는 미리 무쳐서 놓으면 풍미가 증가하지만 영양밀도에는 한계가 있습니다.\n[정답]", "4": "쑥갓나물 무침에 삶아서 으깬 두부를 넣으면 단백질과 영양밀도를 높일 수 있는 좋은 방법입니다.", "2": "식품 자체의 맛보다 양념 맛을 강조하는 것은 영양학적으로 바람직하지 않습니다.", "3": "샐러드 드레싱으로 마요네즈를 이용하면 칼로리는 높아지지만 영양밀도 향상에는 도움이 되지 않습니다.", "5": "사태나 양지는 결 방향으로 잘라 높은 온도로 단시간 조리하면 식감이 좋지만 영양밀도와는 직접적인 연관이 없습니다."}'::jsonb, '[{"term_ko": "영양밀도", "term_vi": "Mật độ dinh dưỡng", "def_ko": "영양 밀도가 높다는 뜻입니다.", "def_vi": "nghĩa là có mật độ dinh dưỡng cao."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1432, '11', '음식 조리 시 나트륨을 줄이는 방법으로 옳은 것은?', '["국수 등 면을 삶을 때는 소금을 첨가한다.", "건더기보다는 국물 위주로 제공한다.", "쌈장을 만들 때 데쳐서 으깬 두부를 넣는다.", "양배추, 오이보다는 절인 배추를 이용한다.", "간을 맞출 때는 간장보다 소금을 이용한다."]'::jsonb, 3, '음식 조리 시 나트륨을 줄이는 방법을 이해하고 있는지를 평가하려는 의도입니다.', NULL, '{"1": "면을 삶을 때 소금을 첨가하면 나트륨이 증가하므로 잘못된 정보입니다.\n[정답]", "3": "데쳐서 으깬 두부를 넣으면 나트륨 섭취를 줄일 수 있는 방법입니다.", "2": "국물 위주로 제공하면 일반적으로 나트륨 섭취가 늘어날 수 있습니다.", "4": "절인 배추는 나트륨이 많이 포함되어 있어 바람직하지 않습니다.", "5": "간장보다 소금은 더 많은 나트륨을 포함하고 있어 잘못된 선택입니다."}'::jsonb, '[{"term_ko": "나트륨", "term_vi": "Natri", "def_ko": "소금의 주요 성분", "def_vi": "Thành phần chính của muối"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1431, '11', '고혈압을 예방하기 위해 소금 섭취를 줄이는 방법은?', '["간을 점차적으로 진하게 한다.", "음식이 뜨거울 때 간을 맞춘다.", "두부와 가공식품은 끓는 물에 데쳐서 사용한다.", "고추장, 된장, 간장을 이용하여 음식을 조리한다.", "다른 맛이나 향이 나는 양념과 채소를 쓰지 않는다."]'::jsonb, 3, '고혈압 예방을 위한 소금 섭취 감소 방법에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "간을 진하게 하는 것은 소금 섭취를 줄이지 않습니다.\n[정답]", "3": "두부와 가공식품을 끓는 물에 데쳐서 사용하면 소금 섭취를 줄일 수 있습니다.", "2": "음식이 뜨거울 때 간을 맞추는 것은 권장되지 않습니다.", "4": "고추장, 된장, 간장을 사용하는 것은 소금을 추가하는 방법입니다.", "5": "다른 맛이나 향이 나는 양념과 채소를 사용하지 않는 것은 요리의 다양성을 제한합니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "Huyết áp cao", "def_ko": "높은 혈압(한국어)", "def_vi": "Huyết áp cao(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1430, '11', '대상자를 위한 음식의 조리 방법으로 옳은 것은?', '["볶기 - 저온에서 오랜 시간 볶는다.", "굽기 - 생선구이는 바싹하게 오래 굽는다.", "삶기 - 조리수를 많이 잡아 삶은 후 물은 버린다.", "나물 - 데쳐서 참기름이나 들기름을 넣어 무친다.", "튀기기 - 낮은 온도에서 조리하여 재료를 부드럽게 한다."]'::jsonb, 4, '대상자를 위한 올바른 음식 조리 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "볶기는 고온에서 빠르게 조리하는 것이 일반적이며, 저온에서 오랜 시간 볶는 것은 음식의 질감을 떨어뜨릴 수 있습니다.\n[정답]", "4": "나물은 데쳐서 참기름이나 들기름을 넣어 무치는 것이 올바른 조리법입니다.", "2": "굽기는 생선이 바삭해질 정도로 조리하는 것이 일반적이며, 바싹하게 오래 굽는 것은 육즙을 잃게 합니다.", "3": "삶기는 조리수의 양을 최소한으로 하여 영양소를 보존하는 조리법입니다.", "5": "튀기기는 고온에서 조리하여 바삭함을 주는 것이 일반적입니다."}'::jsonb, '[{"term_ko": "조리", "term_vi": "Chế biến", "def_ko": "요리하다(한국어)", "def_vi": "chế biến(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1429, '11', '치아 손실이 있는 재가대상자의 식사를 조리하는 방법은?', '["감자는 바싹 튀겨 소금을 뿌린다.", "흰떡은 큼직하게 썰어 기름에 볶는다.", "양배추는 센 불로 익힌 후 약불로 줄여서 찐다.", "문어는 물을 충분히 붓고 오랫동안 삶는다.", "소고기는 납작하게 저며서 말려 육포로 만든다."]'::jsonb, 3, '치아 손실이 있는 재가대상자의 식사 조리에 대한 이해도를 평가하고자 함.', NULL, '{"1": "감자는 바싹 튀겨 소금을 뿌리는 방법은 치아가 없는 대상자가 먹기에 어려움이 있다.\n[정답]", "3": "양배추는 센 불로 익힌 후 약불로 줄여서 찌는 방법은 부드럽고 소화가 잘 되어 안전한 식사 조리 방법이다.", "2": "흰떡은 큼직하게 썰어 기름에 볶는 것은 치아 손실 대상자에게 적합하지 않다.", "4": "문어는 물을 충분히 붓고 오랫동안 삶는 방법은 질긴 식감을 남길 수 있다.", "5": "소고기는 납작하게 저며서 말려 육포로 만들면 쉽게 씹지 못할 수 있다."}'::jsonb, '[{"term_ko": "치아", "term_vi": "Răng", "def_ko": "이(한국어)", "def_vi": "Răng"}, {"term_ko": "손실", "term_vi": "Mất", "def_ko": "잃음(한국어)", "def_vi": "Mất"}, {"term_ko": "재가대상자", "term_vi": "Đối tượng cư trú tại nhà", "def_ko": "방문 요양을 받는 대상자(한국어)", "def_vi": "Đối tượng nhận chăm sóc tại nhà"}, {"term_ko": "조리", "term_vi": "Nấu ăn", "def_ko": "요리하다(한국어)", "def_vi": "Nấu ăn"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식(한국어)", "def_vi": "Bữa ăn"}, {"term_ko": "양배추", "term_vi": "Bắp cải", "def_ko": "배추(한국어)", "def_vi": "Bắp cải"}, {"term_ko": "센 불", "term_vi": "Lửa lớn", "def_ko": "강한 불(한국어)", "def_vi": "Lửa lớn"}, {"term_ko": "약불", "term_vi": "Lửa nhỏ", "def_ko": "작은 불(한국어)", "def_vi": "Lửa nhỏ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1428, '11', '식사를 준비하면서 재가대상자에게 설명한 것으로 옳은 것은?', '["\"국 끓이고 남은 재료를 제가 먹을게요.\"", "\"두부 사고 남은 돈은 딸에게 주었어요.\"", "\"냉장고에 있던 우유는 오래된 것 같아서 버렸어요.\"", "\"어르신은 편찮으시니까 흰죽만 드시는 것이 좋겠어요.\"", "\"혈당이 높으니 어르신이 좋아하는 잡곡밥을 해 드릴게요.\""]'::jsonb, 5, '어르신의 식사 준비와 관련된 올바른 설명을 찾는 것입니다.', NULL, '{"1": "''국 끓이고 남은 재료를 제가 먹을게요.''는 어르신의 건강과 관계없는 개인적인 언급입니다.", "2": "''두부 사고 남은 돈은 딸에게 주었어요.''는 재가대상자와 관련이 없는 가족 이야기입니다.", "3": "''냉장고에 있던 우유는 오래된 것 같아서 버렸어요.''는 식사 준비에 대한 긍정적인 설명이 아닙니다.", "4": "''어르신은 편찮으시니까 흰죽만 드시는 것이 좋겠어요.''는 올바른 조언이지만 식사 준비에 대한 직접적인 설명이 아닙니다.\n[정답]", "5": "''혈당이 높으니 어르신이 좋아하는 잡곡밥을 해 드릴게요.''는 어르신의 건강 상태를 고려한 올바른 설명입니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người có nhu cầu được chăm sóc tại nhà", "def_ko": "재가에서 서비스를 받는 대상자", "def_vi": "Người đang nhận dịch vụ tại nhà"}, {"term_ko": "편찮으시다", "term_vi": "Bệnh", "def_ko": "아프다", "def_vi": "Bị đau"}, {"term_ko": "잡곡밥", "term_vi": "Cơm nhiều loại ngũ cốc", "def_ko": "여러 가지 곡물이 섞인 밥", "def_vi": "Cơm làm từ nhiều loại ngũ cốc"}, {"term_ko": "혈당", "term_vi": "Đường huyết", "def_ko": "혈액의 당 성분", "def_vi": "Đường trong máu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1427, '11', '식사 준비를 위한 올바른 식재료 구매 방법은?', '["값싼 식재료는 대량으로 구매한다.", "유통기한을 넘긴 할인식품을 구매한다.", "대상자와 구매목록을 상의하지 않는다.", "구매 시 보관방법 및 보고나상태를 확인한다.", "식단은 식재료를 구입 후 작성한다."]'::jsonb, 4, '식사 준비에 필요한 올바른 식재료 구매 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "값싼 식재료는 대량으로 구매하는 것이 비용 절감에 도움을 줄 수 있지만, 품질이 중요하므로 주의해야 합니다.", "2": "유통기한을 넘긴 할인식품을 구매하는 것은 건강에 위험할 수 있으므로 피해야 합니다.", "3": "대상자와 구매목록을 상의하지 않는 것은 식사 준비에 중요한 정보를 놓칠 수 있습니다.\n[정답]", "4": "구매 시 보관방법 및 보고나 상태를 확인하는 것은 식품 안전을 위해 필수적입니다.", "5": "식단은 식재료를 구입 후 작성하는 것이 아니라 미리 계획해야 효율적입니다."}'::jsonb, '[{"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "식사를 준비하는 과정", "def_vi": "Quá trình chuẩn bị bữa ăn"}, {"term_ko": "식재료", "term_vi": "Nguyên liệu thực phẩm", "def_ko": "요리를 위해 필요한 재료", "def_vi": "Nguyên liệu cần thiết để nấu ăn"}, {"term_ko": "구매", "term_vi": "Mua sắm", "def_ko": "물품을 사는 행위", "def_vi": "Hành động mua hàng"}, {"term_ko": "유통기한", "term_vi": "Hạn sử dụng", "def_ko": "식품이 안전하게 소비될 수 있는 기한", "def_vi": "Thời gian mà thực phẩm có thể được tiêu thụ an toàn"}, {"term_ko": "보관방법", "term_vi": "Phương pháp bảo quản", "def_ko": "식품을 저장하는 방법", "def_vi": "Cách lưu trữ thực phẩm"}, {"term_ko": "상태", "term_vi": "Trạng thái", "def_ko": "상황이나 상태", "def_vi": "Tình trạng hoặc trạng thái"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1426, '11', '식사를 준비하기 위한 장보기 방법으로 옳은 것은?', '["한 번에 많은 양의 식품을 구입한다.", "가족이 먹고 싶은 음식을 확인하여 구입한다.", "요양보호사 자신에게 필요한 물품을 함께 구입한다.", "물품구매 후 경비 결산은 한 달에 한 번 한다.", "대상자의 건강상태를 고려하여 식단을 작성한다."]'::jsonb, 5, '식사를 준비하기 위해 장보기를 할 때 고려해야 할 중요한 사항을 알고 있는지를 평가하고자 한다.', NULL, '{"1": "한 번에 많은 양의 식품을 구입하는 것은 식품의 신선도와 품질을 고려했을 때 바람직하지 않다.\n[정답]", "2": "가족이 먹고 싶은 음식을 확인하여 구입하는 것은 중요한 사항이나, 특히 요양보호사로서의 역할을 고려할 때 대상자의 건강 상태를 더 우선해야 한다.", "3": "요양보호사 자신에게 필요한 물품을 함께 구입하는 것은 비효율적일 수 있다.", "4": "물품구매 후 경비 결산을 한 달에 한 번 하는 것은 적절하지 않다. 주기적으로 점검하는 것이 좋다.", "5": "대상자의 건강상태를 고려하여 식단을 작성하는 것은 가장 중요한 사항이다."}'::jsonb, '[{"term_ko": "장보기", "term_vi": "Mua sắm", "def_ko": "쇼핑(한국어)", "def_vi": "Mua sắm(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1425, '11', '식사 준비를 위한 장보기 수칙으로 옳은 것은?', '["대상자의 질병 상태와 상관없이 구매한다.", "요양보호사 마음대로 구매한다.", "냉장고 안의 품목을 확인한다.", "가공식품 위주로 구매한다.", "전문 재래시장 이용을 삼간다."]'::jsonb, 3, '식사 준비를 위한 올바른 장보기 수칙을 파악하는 것.', NULL, '{"1": "대상자의 질병 상태에 따라 식사 재료가 달라져야 하므로 잘못된 설명이다.", "2": "요양보호사는 대상자의 건강을 고려하여 구매해야 하므로 잘못된 설명이다.\n[정답]", "3": "냉장고 안의 품목을 확인하는 것은 필요한 재료를 구매하기 위해 중요하다.", "4": "가공식품 위주로 구매하는 것은 건강에 좋지 않을 수 있으므로 잘못된 설명이다.", "5": "전문 재래시장이 아닌 곳에서 구매해도 되며, 상황에 따라 다르므로 잘못된 설명이다."}'::jsonb, '[{"term_ko": "식사", "term_vi": "준비", "def_ko": "식사(한국어) / bữa ăn: bữa ăn(베트남어)", "def_vi": "준비(한국어) / chuẩn bị: chuẩn bị(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1424, '11', '대상자에게 일상생활 지원을 할 때 지켜야 할 기본원칙은?', '["대상자의 욕구보다 주변 정리를 우선으로 한다.", "서비스 제공에 대해 상세하게 기록한다.", "요양보호사의 생활방식과 가치관을 우선한다.", "물품을 요양보호사가 알아서 적당히 쓴다.", "인지능력이 없는 경우 설명하지 않는다."]'::jsonb, 2, '대상자에게 일상생활 지원을 할 때 어떤 기본원칙을 지켜야 하는지를 묻고 있다.', NULL, '{"1": "대상자의 욕구를 우선해야 하며, 주변 정리는 그 다음이다.\n[정답]", "2": "서비스 제공에 대해 상세하게 기록하는 것은 매우 중요하다.", "3": "요양보호사의 개인적인 생활방식이나 가치관은 대상자에게 강요해서는 안 된다.", "4": "물품 사용에 있어서는 대상자의 동의를 구해야 한다.", "5": "인지능력이 없는 경우에도 상항에 따라 적절한 설명이 필요하다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "지원을 받는 사람", "def_vi": "Người nhận sự hỗ trợ"}, {"term_ko": "일상생활", "term_vi": "Cuộc sống hàng ngày", "def_ko": "매일의 삶에서 필요한 활동", "def_vi": "Những hoạt động cần thiết trong cuộc sống hàng ngày"}, {"term_ko": "기본원칙", "term_vi": "Nguyên tắc cơ bản", "def_ko": "기본적인 규칙", "def_vi": "Quy tắc cơ bản"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "제공되는 도움", "def_vi": "Sự trợ giúp được cung cấp"}, {"term_ko": "기록하다", "term_vi": "Ghi chép", "def_ko": "작성하다", "def_vi": "Viết lại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1423, '11', '일상생활 지원의 기본 원칙으로 옳은 것은?', '["요양보호사의 판단으로 결정한다.", "대상자의 물품을 임의대로 배치한다.", "위생을 위해 일회용품을 사용한다.", "대상자의 가족을 지원한다.", "대상자의 특성과 욕구를 파악하여 서비스를 제공한다."]'::jsonb, 5, '일상생활 지원의 기본 원칙에 대해 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "요양보호사는 대상자의 입장을 최우선으로 고려해야 하므로 판단만으로 결정할 수 없습니다.\n[정답]", "5": "대상자의 특성과 욕구를 파악하고 이를 바탕으로 서비스를 제공하는 것이 일상생활 지원의 기본 원칙입니다.", "2": "대상자의 물품을 임의대로 배치하는 것은 대상자의 권리를 침해할 수 있습니다.", "3": "위생을 위해 일회용품을 사용하는 것이 좋지만 기본 원칙이라고 하기엔 부족합니다.", "4": "대상자의 가족을 지원하는 것도 중요하지만 그것이 전부는 아닙니다."}'::jsonb, '[{"term_ko": "일상생활", "term_vi": "Hoạt động hàng ngày", "def_ko": "일상 속에서 하는 모든 활동", "def_vi": "Mọi hoạt động xảy ra trong cuộc sống hàng ngày"}, {"term_ko": "지원", "term_vi": "Hỗ trợ", "def_ko": "돕다, 보조하다", "def_vi": "Giúp đỡ, hỗ trợ"}, {"term_ko": "특성", "term_vi": "Đặc điểm", "def_ko": "특징, 성격", "def_vi": "Tính chất, tính cách"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "원하는 것", "def_vi": "Những thứ mong muốn"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결", "def_vi": "Sạch sẽ"}, {"term_ko": "일회용품", "term_vi": "Sản phẩm dùng một lần", "def_ko": "한 번만 쓸 수 있는 물건", "def_vi": "Vật phẩm chỉ dùng một lần"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1422, '10', '치매 대상자가 길을 잃었을 때 실종을 방지하기 위해 사용하는 복지용구는?', '["배회감지기", "목욕리프트", "경사로", "안전손잡이", "실버카"]'::jsonb, 1, '치매 대상자가 길을 잃는 문제를 방지하기 위한 기구에 대해 묻고 있습니다.', NULL, '{"1": "배회감지기는 치매 대상자들이 길을 잃지 않도록 도와주는 기구입니다.\n[정답]", "2": "목욕리프트는 욕실에서 안전하게 목욕할 수 있도록 도와주는 용구입니다.", "3": "경사로는 휠체어 사용자가 이동하기 용이하도록 만들어진 구조물입니다.", "4": "안전손잡이는 이동 시 안전성을 제공하는 장치입니다.", "5": "실버카는 노인들이 보행 시 사용하도록 돕는 보조기구입니다."}'::jsonb, '[{"term_ko": "배회감지기", "term_vi": "Cảm biến đi lang thang", "def_ko": "길을 잃는 것을 감지하여 알림", "def_vi": "Phát hiện việc lạc đường và thông báo"}, {"term_ko": "목욕리프트", "term_vi": "Thang tắm", "def_ko": "안전하게 목욕할 수 있도록 돕는 기구", "def_vi": "Thiết bị hỗ trợ tắm an toàn"}, {"term_ko": "경사로", "term_vi": "Dốc nghiêng", "def_ko": "휠체어 사용자를 위한 구조물", "def_vi": "Cấu trúc dành cho người sử dụng xe lăn"}, {"term_ko": "안전손잡이", "term_vi": "Tay cầm an toàn", "def_ko": "이동 시 도움을 주는 장치", "def_vi": "Thiết bị hỗ trợ sự an toàn khi di chuyển"}, {"term_ko": "실버카", "term_vi": "Xe lăn dành cho người già", "def_ko": "노인을 위한 보조기구", "def_vi": "Thiết bị hỗ trợ đi lại cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1421, '10', '침대를 사용하는 대상자를 돕는 방법으로 옳은 것은?', '["자주 사용하는 물건은 침대 가까이 둔다.", "바퀴의 잠금장치는 항상 열린 상태로 둔다.", "대상자가 내려오기 쉽도록 침대 난간을 항상 내려 놓는다.", "등판, 다리판 작동 손잡이는 신속하게 작동한다.", "안전을 위해 잠금장치 후 이동한다."]'::jsonb, 1, '대상자를 침대에서 안전하게 도울 수 있는 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "자주 사용하는 물건은 침대 가까이 두어 쉽게 접근할 수 있게 한다.\n[정답]", "2": "바퀴의 잠금장치는 항상 열린 상태로 두는 것은 안전하지 않다.", "3": "대상자가 내려오기 쉽도록 침대 난간을 항상 내려 놓는 것은 도움이 되지 않는다.", "4": "등판, 다리판 작동 손잡이는 신속하게 작동해야 하지만 안전도 고려해야 한다.", "5": "안전을 위해 잠금장치 후 이동하는 것이 일반적으로 안전하다."}'::jsonb, '[{"term_ko": "침대", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "Giường (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1420, '10', '수동침대를 사용하는 대상자를 돕는 방법으로 옳은 것은?', '["등판, 다리판 작동을 위해 크랭크는 항상 펴서 둔다.", "침대에 오를 때는 침대 난간을 잡고 오른다.", "이동하지 않을 때는 바퀴의 잠금 장치를 잠근다.", "사용하지 않을 때는 높납이를 높게 한다.", "침대 이동 시 침대 난간을 잡고 이동한다."]'::jsonb, 3, '수동침대를 사용하는 환자를 안전하고 효과적으로 도와주는 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "등판 및 다리판 작동을 위해 크랭크를 펴서 두는 것은 올바른 방법이 아닙니다.\n[정답]", "3": "이동하지 않을 때는 바퀴의 잠금 장치를 잠그는 것이 안전합니다.", "2": "침대에 오를 때는 침대 난간을 잡고 오르는 것이 일반적인 권장 방법입니다.", "4": "사용하지 않을 때는 높납이를 높게 하는 것은 불필요할 수 있습니다.", "5": "침대 이동 시 침대 난간을 잡고 이동하는 것은 올바른 방법이 아닙니다."}'::jsonb, '[{"term_ko": "수동침대", "term_vi": "Giường thủ công", "def_ko": "수동으로 조작하는 침대", "def_vi": "Giường điều khiển bằng tay"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1419, '10', '거동이 불편한 대상자가 사용하는 자세변환용 쿠션의 조건으로 적합한 것은?', '["마찰이 적은 소재로 표면이 미끄러워야 한다.", "커버는 분리되지 않아야 한다.", "쿠션의 재질이 딱딱해야 한다.", "쿠션에 부착된 지퍼는 감춰져 있어야 한다.", "커버는 소독할 수 있고 변색이 잘 되어야 한다."]'::jsonb, 4, '대상자의 거동을 돕기 위해 사용되는 자세변환용 쿠션의 조건을 이해하고 평가하기 위한 질문이다.', NULL, '{"1": "마찰이 적은 소재는 중요하지만, 표면이 미끄럽다면 오히려 안전하지 않다.\n[정답]", "2": "커버는 분리되지 않아야 하며, 위생적인 관리가 필요하기 때문에 지퍼가 감춰져 있어야 한다.", "3": "쿠션의 재질은 부드러워야 하며 딱딱해서는 안 된다.", "4": "쿠션에 부착된 지퍼는 감춰져 있어야 한다. 따라서 고른 안전성을 위해 지퍼가 드러나지 않는 것이 이상적이다.", "5": "커버는 소독할 수 있어야 하지만 변색이 잘 되어서는 안 된다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Hành động", "def_ko": "움직임(한국어)", "def_vi": "Di chuyển(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1418, '10', '욕창예방 매트리스를 사용하는 방법으로 옳은 것은?', '["하루 12시간만 사용한다.", "하루에 한 번씩 기구에 올라가 정상 동작을 확인한다.", "매트리스는 찜질기와 함께 사용한다.", "등과 엉덩이 밑에 손을 넣어 환자를 부양하는지 확인한다.", "매트리스 셀과 커버는 알코올로 적신 천으로 깨끗이 닦는다."]'::jsonb, 4, '욕창 예방을 위한 매트리스 사용 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "하루 12시간만 사용한다는 것은 부족한 사용 시간으로, 권장 사항이 아닙니다.\n[정답]", "2": "하루에 한 번씩 기구에 올라가 정상 동작을 확인하는 것은 필요 없는 행동입니다.", "3": "매트리스는 찜질기와 함께 사용해서는 안 되며, 서로의 효과를 저하할 수 있습니다.", "4": "등과 엉덩이 밑에 손을 넣어 환자를 부양하는지 확인하는 것은 올바른 방법입니다.", "5": "매트리스 셀과 커버는 알코올로 적신 천으로 닦는 것이 바람직하지 않으며, 특정 세정제를 사용해야 합니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부가 손상되어 생긴 염증", "def_vi": "Viêm do tổn thương da"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1417, '10', '체중으로 인한 압력을 분산시키고 통풍을 원활하게 하기 위한 복지용구는?', '["욕창예방 매트리스", "휠체어", "목욕리프트", "자세변환 용구", "이동욕조"]'::jsonb, 1, '복지용구의 기능과 역할을 이해하고, 체중 분산을 위한 적합한 도구를 선택하게 하는 문제입니다.', NULL, '{"1": "욕창예방 매트리스는 체중을 분산시키고 통풍을 원활하게 하여 욕창을 예방합니다.\n[정답]", "2": "휠체어는 이동을 돕는 기구이며, 압력을 분산시키는 기능은 없습니다.", "3": "목욕리프트는 목욕 시 도움을 주는 용구지만, 압력을 분산시키는 역할과는 관련이 없습니다.", "4": "자세변환 용구는 자세를 바꾸는 데 도움을 주지만, 통풍과 체중 분산과는 직접적인 관계가 없습니다.", "5": "이동욕조는 목욕과 관련된 용구로, 체중 분산과 관련성은 없습니다."}'::jsonb, '[{"term_ko": "욕창예방 매트리스", "term_vi": "Nệm phòng ngừa loét", "def_ko": "욕창을 예방하기 위한 매트리스", "def_vi": "Nệm giúp ngăn ngừa loét"}, {"term_ko": "체중", "term_vi": "Trọng lượng", "def_ko": "몸의 무게", "def_vi": "Cân nặng của cơ thể"}, {"term_ko": "압력", "term_vi": "Áp lực", "def_ko": "물체나 단위 면적에 가해지는 힘", "def_vi": "Lực tác động lên một vật thể hoặc diện tích"}, {"term_ko": "통풍", "term_vi": "Thông gió", "def_ko": "공기가 잘 통하는 상태", "def_vi": "Tình trạng không khí lưu thông tốt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1416, '10', '욕창예방 방석의 사용, 관리 방법으로 옳은 것은?', '["커버는 한 달에 한 번 세탁한다.", "공기를 주입하면 뺄 수 없으므로 주의한다.", "열탕으로 소독하거나 햇볕에 말려서 사용한다.", "특정 부위에 신체 압력을 주기 위한 특수방석이다.", "소독할 때는 공기를 빼고 흐르는 물로 씻고 건조시킨다."]'::jsonb, 5, '욕창 예방 방석의 올바른 사용과 관리 방법에 대한 이해를 요구하는 문제입니다.', NULL, '{"1": "커버는 한 달에 한 번 세탁하는 것이 아니라, 상황에 따라 더 자주 세탁해야 합니다.\n[정답]", "5": "소독할 때는 공기를 빼고 흐르는 물로 씻고 건조시켜야 안전하게 사용할 수 있습니다.", "2": "공기를 주입하면 뺄 수 없다는 것은 사실이 아닙니다. 공기 주입 후 밸브를 통해 공기를 빼는 것이 가능합니다.", "3": "열탕 소독이나 햇볕에 말리는 방법은 해당 방석에 적합하지 않을 수 있습니다.", "4": "특정 부위에 신체 압력을 주기 위한 특수 방석의 기능과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부가 손상되는 상태(한국어)", "def_vi": "Trạng thái tổn thương da"}, {"term_ko": "방석", "term_vi": "Đệm", "def_ko": "앉거나 눕는 데 사용하는 패드(한국어)", "def_vi": "Đệm sử dụng để ngồi hoặc nằm"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "더러운 것을 깨끗이 하다(한국어)", "def_vi": "Làm sạch những thứ bẩn"}, {"term_ko": "소독", "term_vi": "Khử trùng", "def_ko": "병원균을 죽이는 과정(한국어)", "def_vi": "Quá trình giết chết vi khuẩn"}, {"term_ko": "압력", "term_vi": "Áp lực", "def_ko": "힘이 가해지는 정도(한국어)", "def_vi": "Độ dư sức ép"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1415, '10', '이동욕조를 사용하는 방법으로 옳은 것은?', '["욕조 바닥면이 매끄러워야 한다.", "두 사람이 함께 사용할 수 있다.", "대상자가 욕조를 잡고 일어나게 한다.", "평평하고 이물질 없는 장소에서 사용한다.", "응급상황 발생 시에는 즉시 공기밸브를 열어준다."]'::jsonb, 4, '이동욕조 사용 방법의 올바른 이해를 평가하기 위한 질문입니다.', NULL, '{"1": "욕조 바닥면이 매끄러워야 한다. - 매끄러운 바닥면은 안전과 직결되지 않으므로 별로 중요하지 않습니다.\n[정답]", "2": "두 사람이 함께 사용할 수 있다. - 이동욕조는 일반적으로 1인이 사용하므로 잘못된 정보입니다.", "3": "대상자가 욕조를 잡고 일어나게 한다. - 이는 올바른 사용 방법이 아닙니다.", "4": "평평하고 이물질 없는 장소에서 사용한다. - 안전을 위해 필요한 조건입니다.", "5": "응급상황 발생 시에는 즉시 공기밸브를 열어준다. - 이는 올바른 응급 대처가 아닙니다."}'::jsonb, '[{"term_ko": "이동욕조", "term_vi": "Bồn tắm di động", "def_ko": "이동할 수 있는 욕조", "def_vi": "Bồn tắm có thể di chuyển"}, {"term_ko": "평평하다", "term_vi": "Bằng phẳng", "def_ko": "고르다", "def_vi": "Đều"}, {"term_ko": "이물질", "term_vi": "Vật lạ", "def_ko": "불순물", "def_vi": "Tạp chất"}, {"term_ko": "응급상황", "term_vi": "Tình huống khẩn cấp", "def_ko": "급히 대처해야 하는 상황", "def_vi": "Tình huống cần xử lý khẩn cấp"}, {"term_ko": "공기밸브", "term_vi": "Van khí", "def_ko": "공기를 조절하는 밸브", "def_vi": "Van điều chỉnh không khí"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1414, '10', '목욕리프트에 대한 설명으로 옳은 것은?', '["철제로 된 튼튼한 재질이어야 한다.", "높낮이가 수동으로 조절되어야 한다.", "다리가 불편한 대상자가 목욕할 때 편리하다.", "안전을 위해 등받이 각도가 고정된 것이어야 한다.", "혼자서 앉을 수 없는 대상자는 사용할 수 없다."]'::jsonb, 3, '목욕리프트의 기능과 사용대상에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "목욕리프트는 다양한 소재로 제작될 수 있으며, 반드시 철제로 만들어야 하는 것은 아닙니다.\n[정답]", "2": "목욕리프트는 전동식이 많으며, 높낮이가 수동으로 조절되어야 하는 것은 아닙니다.", "3": "다리가 불편한 대상자가 목욕할 때 사용하기에 매우 편리합니다.", "4": "등받이 각도가 고정된 것은 안전을 위해 권장되지만, 반드시 모든 모델이 그렇게 설계된 것은 아닙니다.", "5": "혼자서 앉을 수 없는 대상자도 특별한 방법으로 지원을 받아 사용할 수 있으므로 부정확한 설명입니다."}'::jsonb, '[{"term_ko": "목욕리프트", "term_vi": "Ghế tắm", "def_ko": "목욕을 돕기 위해 사용하는 장치", "def_vi": "Thiết bị hỗ trợ việc tắm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1413, '10', '거동이 불편한 대상자의 안전을 위해 적절한 목욕의자는?', '["팔걸이가 없는 의자", "등받이가 낮은 의자", "구멍이나 흠이 없는 의자", "앉는 자리가 미끄럽지 않은 의자", "두 발이 바닥에 닿지 않는 높이의 의자"]'::jsonb, 4, '거동이 불편한 대상자가 안전하게 목욕을 할 수 있도록 적절한 목욕의자를 선택하는 것이 중요하다.', NULL, '{"1": "팔걸이가 없는 의자는 지지력이 부족해 안전하지 않을 수 있다.", "2": "등받이가 낮은 의자는 편안함을 제공하지 못할 수 있다.\n[정답]", "3": "구멍이나 흠이 없는 의자는 위생적이며, 안전성을 높인다.", "4": "앉는 자리가 미끄럽지 않은 의자는 안전성을 높여주는 중요한 요소이며, 따라서 가장 적절하다.", "5": "두 발이 바닥에 닿지 않는 높이의 의자는 불안정성을 유발할 수 있다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Hành động", "def_ko": "움직임(한국어)", "def_vi": "di chuyển(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1412, '10', '휴대용 경사로 선정 시 고려해야 할 사항으로 옳은 것은?', '["색상", "균형감", "디자인", "회사명", "청결성"]'::jsonb, 2, '휴대용 경사로를 선택할 때의 주요 고려 사항을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "색상은 선택의 중요한 요소가 아닙니다.\n[정답]", "2": "균형감은 안전과 직결되므로 매우 중요합니다.", "3": "디자인은 기능성보다 덜 중요합니다.", "4": "회사명은 제품 선택의 중요한 요소가 아닙니다.", "5": "청결성은 사용 후 고려할 수 있는 사항일 뿐, 선택 시 직접적인 고려요소는 아닙니다."}'::jsonb, '[{"term_ko": "휴대용", "term_vi": "Di động", "def_ko": "이동할 수 있는(한국어)", "def_vi": "Có thể di chuyển(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1411, '10', '거동이 불편한 대상자의 생활공간에 안전손잡이를 설치해야 하는 이유는?', '["근력과 지구력 향상", "스트레칭과 운동능력 강화", "근육의 유연성과 신장성 향상", "유산소 운동과 폐기능 강화", "자립성 향상과 신체 균형 유지"]'::jsonb, 5, '거동이 불편한 대상자의 생활공간에 안전손잡이를 설치함으로써 대상자가 보다 안전하고 쉽게 움직일 수 있도록 돕기 위한 이유를 묻는 질문이다.', NULL, '{"1": "근력과 지구력 향상은 일상적인 운동이나 활동에 의한 결과이지 안전손잡이 설치와는 직접적인 연관성이 없다.\n[정답]", "5": "자립성 향상과 신체 균형 유지가 안전손잡이를 설치하는 가장 중요한 이유로, 안전손잡이는 대상자가 이동할 때 균형을 유지하고 자립적으로 행동할 수 있도록 도와준다.", "2": "스트레칭과 운동능력 강화는 안전손잡이와의 관계가 명확하지 않다.", "3": "근육의 유연성과 신장성 향상은 안전손잡이 설치의 목적과는 거리가 멀다.", "4": "유산소 운동과 폐기능 강화는 안전손잡이와 관련이 없다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Hành động", "def_ko": "행동이나 움직임", "def_vi": "Hành vi hoặc chuyển động"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "안전손잡이", "term_vi": "Tay nắm an toàn", "def_ko": "넘어지지 않도록 도와주는 장치", "def_vi": "Thiết bị giúp ngăn ngừa ngã"}, {"term_ko": "자립성", "term_vi": "Tính tự lập", "def_ko": "스스로 할 수 있는 능력", "def_vi": "Khả năng tự mình làm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1410, '10', '지팡이를 사용할 때 안전을 위해 점검해야 하는 것은?', '["청결 상태", "손잡이 끈 유무", "손잡이 마모 정도", "페인트 도장 상태", "바닥 끝 고무의 닳은 정도"]'::jsonb, 5, '지팡이를 사용할 때의 안전을 위해 점검해야 할 요소를 이해하는 것이다.', NULL, '{"1": "지팡이의 청결 상태는 중요하나 안전과 직접적인 관련이 적다.\n[정답]", "5": "바닥 끝 고무가 닳은 정도는 지팡이의 미끄러짐과 관련이 있어 안전에 직접적인 영향을 미친다.", "2": "손잡이 끈 유무는 보조 장치 점검이 필요하지만 기본적인 안전 요소는 아니다.", "3": "손잡이 마모 정도는 중요하나 바닥 끝 고무의 상태가 더 직접적인 영향을 미친다.", "4": "페인트 도장 상태는 미관상의 문제일 뿐이다."}'::jsonb, '[{"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "보조 도구로 사용하는 막대기", "def_vi": "Cái được sử dụng như một công cụ hỗ trợ"}, {"term_ko": "청결", "term_vi": "Sạch sẽ", "def_ko": "깨끗함", "def_vi": "Sự sạch sẽ"}, {"term_ko": "손잡이", "term_vi": "Tay cầm", "def_ko": "잡는 부분", "def_vi": "Phần cầm"}, {"term_ko": "마모", "term_vi": "Mòn", "def_ko": "닳음", "def_vi": "Bị mòn"}, {"term_ko": "페인트", "term_vi": "Sơn", "def_ko": "물감", "def_vi": "Sơn"}, {"term_ko": "고무", "term_vi": "Cao su", "def_ko": "고무", "def_vi": "Cao su"}, {"term_ko": "닳다", "term_vi": "Mòn", "def_ko": "닳다", "def_vi": "Bị mòn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1409, '10', '지팡이를 안전하게 사용하는 방법으로 옳은 것은?', '["사용 시 안전을 위해 청결 상태를 점검한다.", "팔꿈치를 직각으로 구부린 높이가 안정적이다.", "지팡이 길이는 바닥면에서 둔부까지로 맞춘다.", "대상자가 설 수 없는 경우 네발 지팡이를 선택한다.", "불편한 쪽 발의 앞 15CM, 옆 15CM 지점에 지팡이 끝을 내민다."]'::jsonb, 3, '지팡이를 안전하고 효과적으로 사용하는 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "사용 시 안전을 위해 청결 상태를 점검하는 것은 중요하지만, 지팡이를 안전하게 사용하는 방법으로는 적합하지 않습니다.\n[정답]", "2": "팔꿈치를 직각으로 구부린 높이는 안정적이지 않으며, 사용자의 신체에 따라 다를 수 있습니다.", "3": "지팡이 길이는 바닥면에서 둔부까지로 맞추는 것이 맞습니다. 이는 안전한 지팡이 사용을 위한 기본 원칙입니다.", "4": "대상자가 설 수 없는 경우 네발 지팡이를 선택하는 것은 적절하지 않으며, 적절한 보행 보조기를 선택해야 합니다.", "5": "불편한 쪽 발의 앞 15CM, 옆 15CM 지점에 지팡이 끝을 내미는 것은 올바른 사용 방법이 아닙니다."}'::jsonb, '[{"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "보행 보조 도구", "def_vi": "thiết bị hỗ trợ đi lại"}, {"term_ko": "청결", "term_vi": "Sạch sẽ", "def_ko": "깨끗함", "def_vi": "sự sạch sẽ"}, {"term_ko": "팔꿈치", "term_vi": "Khuỷu tay", "def_ko": "팔의 굽힌 부분", "def_vi": "phần khủy tay"}, {"term_ko": "안정적", "term_vi": "Ổn định", "def_ko": "안전성이 있는 상태", "def_vi": "trạng thái có độ an toàn"}, {"term_ko": "둔부", "term_vi": "Mông", "def_ko": "엉덩이", "def_vi": "mông"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1408, '10', '지팡이를 안전하게 사용하는 방법으로 옳은 것은?', '["사용 시 안전을 위해 청결 상태를 점검한다.", "팔꿈치를 직각으로 구부린 높이가 안정적이다.", "지팡이 길이는 바닥면에서 둔부까지로 맞춘다.", "대상자가 설 수 없는 경우 네발 지팡이를 선택한다.", "불편한 쪽 발의 앞 15CM, 옆 15CM 지점에 지팡이 끝을 내민다."]'::jsonb, 3, '지팡이를 사용할 때의 안전한 사용 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "사용 시 청결 상태를 점검하는 것은 중요하지만 지팡이의 안전한 사용 방법에 직접적으로 관련된 설명은 아닙니다.\n[정답]", "2": "팔꿈치를 직각으로 구부린 높이는 안정적이지만, 지팡이의 적절한 길이가 더 중요합니다.", "3": "지팡이 길이는 바닥면에서 둔부까지 맞춰야 합니다. 이는 올바른 자세 유지에 도움이 됩니다.", "4": "대상자가 설 수 없는 경우 네발 지팡이를 선택하는 것이 일반적이나, 질문에서는 지팡이를 사용하는 방법에 대한 것이므로 해당 선택지는 부적절합니다.", "5": "불편한 쪽 발 근처에 지팡이 끝을 내미는 것은 잘못된 방법입니다. 지팡이는 바닥면에서 둔부까지 맞춰야 합니다."}'::jsonb, '[{"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "지원 도구(한국어)", "def_vi": "Dụng cụ hỗ trợ"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없고 보호된 상태(한국어)", "def_vi": "Trạng thái không có nguy hiểm"}, {"term_ko": "팔꿈치", "term_vi": "Khuỷu tay", "def_ko": "팔과 손 사이의 관절(한국어)", "def_vi": "Khớp giữa tay và cánh tay"}, {"term_ko": "설 수 없다", "term_vi": "Không thể đứng", "def_ko": "서 있지 못하다(한국어)", "def_vi": "Không đứng được"}, {"term_ko": "네발 지팡이", "term_vi": "Gậy bốn chân", "def_ko": "네 개의 다리를 가진 지팡이(한국어)", "def_vi": "Gậy có bốn chân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1407, '10', '다음 중 보행자 설명으로 옳은 것은?', '["실내에서만 사용하는 보행 보조도구이다.", "지팡이보다 안전성이 약하다.", "요양보호사는 항상 대상자 가까이 있어야 한다.", "뒤로 잘 넘어지는 사람에게 유용하다.", "뇌졸증으로 반신마비의 대상자가 사용하기에 적합하다."]'::jsonb, 3, '보행자에 대한 올바른 이해와 인식을 평가하기 위한 문제입니다.', NULL, '{"1": "보행 보조도구는 실외에서도 사용할 수 있습니다.", "2": "일반적으로 지팡이보다 안전성이 높은 편입니다.\n[정답]", "3": "요양보호사는 항상 대상자 가까이 있어야 하며, 이로 인해 안전을 확보할 수 있습니다.", "4": "보행자는 뒤로 넘어지는 데 도움을 주지 않기 때문에 그와 관련된 설명은 잘못되었습니다.", "5": "뇌졸증으로 반신마비 대상자가 사용하기에는 그 용도가 조금 다를 수 있습니다."}'::jsonb, '[{"term_ko": "보행자", "term_vi": "Người đi bộ", "def_ko": "걷기에 도움을 주는 기구", "def_vi": "Thiết bị hỗ trợ đi bộ"}, {"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "손으로 잡고 지지하는 도구", "def_vi": "Công cụ được giữ và hỗ trợ"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "돌봄 받는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "안전성", "term_vi": "Độ an toàn", "def_ko": "안전의 정도", "def_vi": "Mức độ an toàn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1406, '10', '복지용구를 소독, 관리하는 방법으로 옳은 것은?', '["목욕의자 - 열탕소독 한다.", "수동침대 - 흐르는 물로 씻어 건조시킨다.", "휠체어 - 소독용 알코올을 적신 천으로 닦는다.", "목욕리프트 - 소독액이나 뜨거운 물로 씻는다.", "성인용 보행기 - 세제로 닦고 햇볕에 말린다."]'::jsonb, 3, '복지용구의 소독과 관리 방법에 대한 지식 평가.', NULL, '{"1": "목욕의자는 열탕소독이 비현실적임.\n[정답]", "3": "휠체어는 소독용 알코올을 적신 천으로 닦는 것이 올바른 방법임.", "2": "수동침대는 흐르는 물로 씻으나, 소독에 대한 언급이 부족함.", "4": "목욕리프트는 적절한 소독 방법을 제시하지 않음.", "5": "성인용 보행기는 햇볕에 말리는 것이 아니라, 다른 소독 방법으로 관리해야 함."}'::jsonb, '[{"term_ko": "복지용구", "term_vi": "Dụng cụ hỗ trợ", "def_ko": "복지 분야에서 사용하는 도구나 장비", "def_vi": "Công cụ hoặc thiết bị được sử dụng trong lĩnh vực phúc lợi"}, {"term_ko": "소독", "term_vi": "Khử trùng", "def_ko": "병원균을 죽이는 과정을 의미", "def_vi": "Quá trình tiêu diệt vi khuẩn"}, {"term_ko": "관리", "term_vi": "Quản lý", "def_ko": "도구나 장비를 잘 다루는 것", "def_vi": "Sử dụng và chăm sóc công cụ hoặc thiết bị tốt"}, {"term_ko": "전신", "term_vi": "Toàn thân", "def_ko": "모든 신체 부위를 포함하여", "def_vi": "Bao gồm tất cả các bộ phận của cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1405, '10', '휠체어가 잘 굴러가지 않고 잠금장치가 고정되지 않을 때 먼저 점검해야 하는 곳은?', '["앞바퀴", "받침쇠", "발 받침대", "타이어 공기압", "바퀴 손잡이"]'::jsonb, 4, '휠체어의 기능과 안전에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "앞바퀴는 휠체어의 방향 전환에 영향을 미치지만 잠금장치와는 관련이 없습니다.\n[정답]", "4": "타이어 공기압이 낮으면 휠체어의 이동이 어려울 수 있으며, 잠금장치가 제대로 작동하지 않을 수 있습니다.", "2": "받침쇠는 휠체어의 구조물로, 잠금장치와는 직접적인 관계가 없습니다.", "3": "발 받침대는 사용자의 편안함을 위한 부분으로, 이동성과는 직접 관련이 없습니다.", "5": "바퀴 손잡이는 이동 시 조작에 도움을 주지만 잠금장치의 고정과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "휠체어(한국어)", "def_vi": "xe lăn(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1404, '10', '휠체어를 관리하는 방법으로 옳은 것은?', '["사용하지 않을 때에는 잠금장치를 풀어둔다.", "뒷바퀴 공기압이 낮을수록 잠금장치가 잘 걸린다.", "뒷바퀴 공기압이 너무 높으면 충격을 흡수하지 못한다.", "적정 공기압은 엄지로 눌렀을 때 들어가지 않아야 한다.", "휠체어를 편 상태에서 보관한다."]'::jsonb, 3, '휠체어 관리에 대한 기본적인 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "사용하지 않을 때에는 잠금장치를 풀어두면 안전하지 않으므로 잘못된 설명입니다.\n[정답]", "3": "뒷바퀴 공기압이 너무 높으면 충격을 흡수하지 못하므로 올바른 설명입니다.", "2": "뒷바퀴 공기압이 낮아도 잠금장치가 잘 걸리는 것은 아니므로 잘못된 설명입니다.", "4": "적정 공기압은 엄지로 눌렀을 때 들어가지 않아야 하지만 이는 한도에 따라 달라질 수 있어 해석이 모호합니다.", "5": "휠체어를 편 상태에서 보관하면 안전하고 적절하지만, 보관 방법에는 여러 가지가 있으므로 다소 잘못된 설명이 될 수 있습니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "전동 또는 수동으로 이동하는 의자", "def_vi": "Ghế di chuyển tự động hoặc bằng tay"}, {"term_ko": "공기압", "term_vi": "Áp suất lốp", "def_ko": "타이어 내부의 압력", "def_vi": "Áp suất bên trong lốp"}, {"term_ko": "잠금장치", "term_vi": "Khóa", "def_ko": "안전을 위한 기계장치", "def_vi": "Thiết bị cơ khí để đảm bảo an toàn"}, {"term_ko": "충격", "term_vi": "Sốc", "def_ko": "외부 힘이 가해지는 상태", "def_vi": "Trạng thái khi lực bên ngoài tác động"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1403, '10', '복지용구 중에서 요실금 팬티를 사용하는 방법으로 옳은 것은?', '["요실금 팬티는 세탁 후 반복사용이 가능하다.", "실금량이 적을 때는 말려서 재사용한다.", "요실금 팬티 위에 일반 팬티를 덧입힌다.", "신체보다 한두 치수 큰 것으로 사용한다.", "흘림량이 500ML 이상인 대상자에게 사용한다."]'::jsonb, 1, '요실금 팬티 사용법에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "요실금 팬티는 세탁 후 반복사용이 가능하다. [정답] 요실금 팬티는 세탁하여 반복적으로 사용할 수 있습니다.", "2": "실금량이 적을 때는 말려서 재사용한다. 이 방법은 권장되지 않습니다.", "3": "요실금 팬티 위에 일반 팬티를 덧입힌다. 이는 바람직하지 않은 방법입니다.", "4": "신체보다 한두 치수 큰 것으로 사용한다. 적절한 사이즈를 선택해야 합니다.", "5": "흘림량이 500ML 이상인 대상자에게 사용한다. 요실금 팬티는 흘림량이 적은 경우에 더 적합합니다."}'::jsonb, '[{"term_ko": "요실금 팬티", "term_vi": "Quần lót tiểu không tự chủ", "def_ko": "배뇨를 제어하지 못하는 사람을 위한 팬티", "def_vi": "Quần lót dành cho người không kiểm soát được tiểu tiện"}, {"term_ko": "재사용", "term_vi": "Tái sử dụng", "def_ko": "다시 사용하는 것", "def_vi": "Sử dụng lại"}, {"term_ko": "치수", "term_vi": "Kích thước", "def_ko": "사이즈", "def_vi": "Kích cỡ"}, {"term_ko": "흘림량", "term_vi": "Lượng tiểu", "def_ko": "누수되는 양", "def_vi": "Lượng nước tiểu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1402, '10', '간이변기를 사용하여 침상 배설을 하는 대상자를 돕는 방법은?', '["대상자 스스로 변기 위에 앉게 한다.", "팔걸이와 등받이에 기대어 힘을 주게 한다.", "변의가 확실하지 않으면 장시간 대어 준다.", "열량으로 소독할 수 있는 변기를 사용한다.", "협조할 수 없는 대상자는 옆으로 누워 사용한다."]'::jsonb, 4, '간이변기를 사용하여 침상에서 배설을 해야 하는 상황에서 올바른 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "대상자가 스스로 변기 위에 앉는 것이 아니라, 보호자가 도와야 하는 경우입니다.\n[정답]", "2": "팔걸이와 등받이에 기대어 힘을 주도록 하는 것은 적절하나, 소독이 우선이기 때문에 변기의 청결이 중요합니다.", "3": "변의가 확실하지 않은 경우 장시간 대기하는 것은 좋지 않습니다.", "4": "열량으로 소독할 수 있는 변기를 사용하는 것이 가장 올바른 방법입니다.", "5": "협조할 수 없는 대상자가 옆으로 누워 사용하도록 하는 것은 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "간이변기", "term_vi": "Bồn cầu di động", "def_ko": "이동 가능한 화장실(한국어)", "def_vi": "Nhà vệ sinh có thể di chuyển(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1401, '10', '화장실까지 이동하기 어려운 대상자의 배설을 돕기 위한 이동변기로 적절한 것은?', '["팔걸이와 등받이가 없는 것", "바퀴가 붙어있어 이동하기 쉬운 것", "양변기 시트에 올려놓을 수 있는 것", "본체와 변기통이 일체형인 것", "뜨거운 물로 세척할 수 있는 것"]'::jsonb, 5, '대상자의 이동 불편을 고려한 적절한 배설용 기구 선택에 대한 이해를 평가한다.', NULL, '{"1": "팔걸이와 등받이가 없는 것은 안전성과 편안함을 제공하지 않을 수 있어 적절하지 않다.\n[정답]", "2": "바퀴가 붙어있어 이동하기 쉬운 것은 이동성을 고려할 때 긍정적이나, 해당 문제에서 요구하는 조건을 충족하지 않는다.", "3": "양변기 시트에 올려놓을 수 있는 것은 고정되지 않아 안전성이 떨어질 수 있다.", "4": "본체와 변기통이 일체형인 것은 위생관리에 용이하여 적절하다.", "5": "뜨거운 물로 세척할 수 있는 것은 위생적으로 매우 중요하며, 배설물의 처리 과정에서 매우 유용하다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자, 혹은 보호가 필요한 사람", "def_vi": "Người bệnh hoặc người cần được chăm sóc"}, {"term_ko": "배설", "term_vi": "Phân bài", "def_ko": "소변이나 대변을 처리하는 것", "def_vi": "Việc xử lý nước tiểu hoặc phân"}, {"term_ko": "이동", "term_vi": "Di chuyển", "def_ko": "움직이는 것", "def_vi": "Hành động di chuyển"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결 상태", "def_vi": "Tình trạng sạch sẽ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1400, '10', '노인장기요양보험 급여로 대여할 수 있는 복지용구는?', '["이동변기", "목욕의자", "안전손잡이", "성인용보행기", "욕창예방 매트리스"]'::jsonb, 5, '노인장기요양보험에서 대여 가능한 복지용구를 알아보는 문제입니다.', NULL, '{"1": "이동변기는 대여 가능합니다.", "2": "목욕의자도 대여 가능합니다.", "3": "안전손잡이 역시 대여 가능합니다.\n[정답]", "5": "욕창예방 매트리스는 대여할 수 있는 복지용구가 아닙니다.", "4": "성인용보행기도 대여 가능합니다."}'::jsonb, '[{"term_ko": "급여", "term_vi": "Chế độ trợ cấp", "def_ko": "급스러운 이익(보장)", "def_vi": "Lợi ích khẩn cấp"}, {"term_ko": "복지용구", "term_vi": "Thiết bị hỗ trợ", "def_ko": "도움이 되는 기구", "def_vi": "Thiết bị giúp đỡ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1399, '10', '다음 주 노인장기요양보험 급여로 대여할 수 있는 복지용구는?', '["지팡이", "간이변기", "안전손잡이", "수동 휠체어", "욕창예방 방석"]'::jsonb, 4, '노인장기요양보험에서 대여 가능한 복지용구를 인식하고 있는지를 평가하기 위해 출제되었습니다.', NULL, '{"1": "지팡이는 보조기구로 사용할 수 있지만, 대여 항목에 포함되지 않습니다.\n[정답]", "4": "수동 휠체어는 노인장기요양보험에서 대여할 수 있는 복지용구입니다.", "2": "간이변기는 특정 조건 하에 사용 가능하지만, 기본적으로 대여항목에 포함되지 않습니다.", "3": "안전손잡이는 보조기구에 해당하지만, 대여 목록에 없습니다.", "5": "욕창예방 방석은 치료적 기능이 있지만, 대여 대상에 포함되지 않습니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인 및 장애인을 위한 장기 요양 및 돌봄 보험", "def_vi": "Bảo hiểm dành cho người cao tuổi và người khuyết tật"}, {"term_ko": "복지용구", "term_vi": "Thiết bị hỗ trợ", "def_ko": "요양 보조 기기", "def_vi": "Thiết bị hỗ trợ trong chăm sóc"}, {"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "보행을 돕는 도구", "def_vi": "Dụng cụ hỗ trợ đi lại"}, {"term_ko": "간이변기", "term_vi": "Bồn vệ sinh kiểu đơn giản", "def_ko": "이동이나 사용이 용이한 화장실", "def_vi": "Nhà vệ sinh dễ di chuyển"}, {"term_ko": "안전손잡이", "term_vi": "Tay vịn an toàn", "def_ko": "미끄러지지 않도록 돕는 도구", "def_vi": "Dụng cụ giúp không bị trượt"}, {"term_ko": "수동 휠체어", "term_vi": "Xe lăn tay", "def_ko": "사람이 직접 밀어 이동하는 휠체어", "def_vi": "Xe lăn mà người dùng tự đẩy"}, {"term_ko": "욕창예방 방석", "term_vi": "Đệm phòng ngừa loét", "def_ko": "욕창을 예방하는 기구", "def_vi": "Dụng cụ phòng ngừa loét"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1398, '10', '노인장기요양보험 급여로 대여할 수 있는 복지용구는?', '["목욕의자", "배회감지기", "지팡이", "이동변기", "성인용 비행기"]'::jsonb, 2, '노인장기요양보험에서 지급하는 복지용구에 대한 이해도를 평가하기 위한 문제입니다.', NULL, NULL, '[{"term_ko": "복지용구", "term_vi": "Thiết bị phúc lợi", "def_ko": "도움이 되는 장비", "def_vi": "Thiết bị hỗ trợ"}, {"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 의료보장제도", "def_vi": "Hệ thống bảo hiểm y tế cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1397, '10', '다음 중 노인장기요양보험 급여로 구입 가능한 복지용구는?', '["전동침대", "수동침대", "요실금팬티", "이동욕조", "배회감지기"]'::jsonb, 3, '노인장기요양보험과 관련된 복지용구에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "전동침대는 노인장기요양보험 급여로 구입할 수 있는 항목입니다.\n[정답]", "3": "요실금팬티는 개인의 위생을 위한 용구로 급여에 해당하지 않습니다.", "2": "수동침대 또한 노인장기요양보험 급여로 구입 가능합니다.", "4": "이동욕조는 노인의 목욕을 돕기 위한 용구로 급여에 포함됩니다.", "5": "배회감지기는 안전을 위한 장비지만, 급여 항목에는 포함되지 않습니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "복지용구", "def_ko": "장기 chăm sóc cho người cao tuổi", "def_vi": "thiết bị hỗ trợ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1396, '10', '노인장기요양 보험 급여로 구입할 수 있는 복지용구는?', '["수동 휠체어", "목욕리프트", "백회감지기", "이동욕조", "안전손잡이"]'::jsonb, 5, '노인장기요양 보험 급여로 구입 가능한 복지용구에 대한 이해를 평가하고자 합니다.', NULL, '{"1": "수동 휠체어는 노인에게 필요한 복지용구 중 하나입니다.\n[정답]", "2": "목욕리프트는 노인이 목욕 중 안전하게 이동할 수 있도록 도와주는 장비입니다.", "3": "백회감지기는 안전과 관련이 있지만, 급여로 구입할 수 있는 복지용구는 아닙니다.", "4": "이동욕조는 노인이 편리하게 목욕할 수 있도록 도와주는 장비입니다.", "5": "안전손잡이는 노인들이 안전하게 이동하는 데 도움을 주지만, 급여로 구입할 수 없습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người lớn tuổi"}, {"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기요양(한국어)", "def_vi": "Dịch vụ chăm sóc lâu dài"}, {"term_ko": "보험", "term_vi": "Bảo hiểm", "def_ko": "보험(한국어)", "def_vi": "Bảo hiểm"}, {"term_ko": "급여", "term_vi": "Trợ cấp", "def_ko": "급여(한국어)", "def_vi": "Trợ cấp"}, {"term_ko": "복지용구", "term_vi": "Thiết bị phúc lợi", "def_ko": "복지용구(한국어)", "def_vi": "Thiết bị phúc lợi"}, {"term_ko": "수동 휠체어", "term_vi": "Xe lăn cầm tay", "def_ko": "수동휠체어(한국어)", "def_vi": "Xe lăn cầm tay"}, {"term_ko": "목욕리프트", "term_vi": "Thang tắm", "def_ko": "목욕리프트(한국어)", "def_vi": "Thang tắm"}, {"term_ko": "안전손잡이", "term_vi": "Tay cầm an toàn", "def_ko": "안전손잡이(한국어)", "def_vi": "Tay cầm an toàn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1395, '10', '오른쪽 다리가 불편한 대상자의 보행기 사용 방법은?', '["보행기와 오른쪽 다리가 함께 - 왼쪽 다리", "보행기와 왼쪽 다리가 함께 - 오른쪽 다리", "보행기 - 오른쪽 다리 - 왼쪽 다리", "보행기 - 왼쪽 다리 - 오른쪽 다리", "오른쪽 다리 - 왼쪽 다리 - 보행기"]'::jsonb, 1, '대상자의 보행 보조 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "보행기와 오른쪽 다리가 함께 이동하는 것이 적절하며, 왼쪽 다리가 그 뒤를 따릅니다.\n[정답]", "2": "보행기와 왼쪽 다리가 함께 이동하는 것은 하지 않아야 합니다.", "3": "보행기와 오른쪽 다리가 함께 이동하는 순서가 아닙니다.", "4": "보행기와 왼쪽 다리가 동시에 이동하는 것은 올바른 방법이 아닙니다.", "5": "오른쪽 다리를 먼저 내리고 나서 보행기를 사용하는 것은 적절하지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 병원에 있는 사람", "def_vi": "Bệnh nhân, người được chăm sóc"}, {"term_ko": "보행기", "term_vi": "Khung hỗ trợ đi bộ", "def_ko": "보행 보조기구", "def_vi": "Thiết bị hỗ trợ đi bộ"}, {"term_ko": "불편한", "term_vi": "Không thoải mái", "def_ko": "어려움이 있는", "def_vi": "Gặp khó khăn"}, {"term_ko": "방법", "term_vi": "Phương pháp", "def_ko": "수단, 절차", "def_vi": "Cách thức, quy trình"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1394, '10', '양족 다리가 약한 대상자의 보행기 사용 방법으로 옳은 것은?', '["오른발 - 왼발 - 보행기", "왼발 - 오른발 - 보행기", "보행기 - 오른발 - 왼발", "보행기 - 양쪽 발을 동시에", "양쪽 발을 동시에 - 보행기"]'::jsonb, 3, '양쪽 다리가 약한 대상자가 보행기를 사용할 때 올바른 방법을 이해하고 있는지를 평가하려는 의도입니다.', NULL, '{"1": "오른발 - 왼발 - 보행기: 다리를 교차하여 보행기를 사용하는 방법은 부적절합니다.", "2": "왼발 - 오른발 - 보행기: 잘못된 순서로 보행기를 사용할 때, 균형을 잃을 수 있습니다.\n[정답]", "3": "보행기 - 오른발 - 왼발: 보행기를 먼저 이동한 후, 오른발과 왼발을 순서대로 이동하는 방법이 안전합니다.", "4": "보행기 - 양쪽 발을 동시에: 두 발을 동시에 이동하는 것은 균형을 잃을 위험이 큽니다.", "5": "양쪽 발을 동시에 - 보행기: 잘못된 순서로, 보행기를 사용한 후에는 균형을 잃을 수 있습니다."}'::jsonb, '[{"term_ko": "보행기", "term_vi": "Xe đi lại", "def_ko": "이동 보조 기구", "def_vi": "Thiết bị hỗ trợ di chuyển"}, {"term_ko": "약한", "term_vi": "Yếu", "def_ko": "힘이 부족한", "def_vi": "Thiếu sức"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "도움을 필요로 하는 사람", "def_vi": "Người cần hỗ trợ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1393, '10', '오른쪽 다리가 불편한 대상자가 계단을 내려갈 때 순서로 옳은 것은?', '["왼쪽 다리 - 지팡이 - 오른쪽 다리", "왼쪽 다리 - 오른쪽 다리 - 지팡이", "오른쪽 다리 - 지팡이 - 왼쪽 다리", "지팡이 - 왼쪽 다리 - 오른쪽 다리", "지팡이 - 오른쪽 다리 - 왼쪽 다리"]'::jsonb, 5, '대상자가 계단을 내려갈 때 올바른 순서를 선택하도록 하는 것이며, 특히 다리가 불편한 경우의 안전한 이동 방법을 강조합니다.', NULL, '{"1": "왼쪽 다리로 먼저 내려가는 것은 불편한 오른쪽 다리에 부담을 줄 수 있습니다.\n[정답]", "5": "지팡이를 먼저 사용하여 균형을 잡고, 오른쪽 다리를 먼저 내린 후 왼쪽 다리로 따라 내려가는 것이 안전합니다.", "2": "오른쪽 다리로 내려가는 것은 더욱 불안정하게 만들 수 있습니다.", "3": "오른쪽 다리로 시작하면 안전하지 않습니다.", "4": "지팡이 사용이 먼저 이루어져야 하므로, 순서가 바르지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자, 피험자", "def_vi": "Bệnh nhân, đối tượng thử nghiệm"}, {"term_ko": "다리", "term_vi": "Chân", "def_ko": "우리 몸의 일부로, 걷고 움직이는 데 사용", "def_vi": "Một phần của cơ thể, được sử dụng để đi và di chuyển"}, {"term_ko": "계단", "term_vi": "Cầu thang", "def_ko": "여러 단으로 구성된 이동수단", "def_vi": "Phương tiện di chuyển được tạo thành từ nhiều bậc"}, {"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "균형을 잡기 위해 사용하는 도구", "def_vi": "Dụng cụ được sử dụng để giữ thăng bằng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1392, '10', '오른쪽 편마비 대상자가 평지를 이동할 때 지팡이 사용 순서로 옳은 것은?', '["지팡이 - 왼쪽 다리 - 오른쪽 다리", "지팡이 - 오른쪽 다리 -왼쪽 다리", "왼쪽 다리 - 지팡이 - 오른쪽 다리", "왼쪽 다리 - 오른쪽 다리 - 지팡이", "오른쪽 다리 - 지팡이 - 왼쪽 다리"]'::jsonb, 2, '대상자의 편마비에 따른 안전한 이동 방법을 이해하고 적용하는 능력을 평가하기 위한 문제입니다.', NULL, '{"1": "지팡이 사용 시, 균형을 유지하기 어려우므로 다른 다리부터 시작하는 것은 위험합니다.\n[정답]", "2": "오른쪽 다리와 지팡이를 함께 사용하여 이동하는 방식이로, 편마비 대상자에게 적합합니다.", "3": "왼쪽 다리 먼저 움직일 경우, 지팡이의 지지점을 잃게 되어 이동이 힘들 수 있습니다.", "4": "오른쪽 다리와 지팡이를 동시에 사용하지 않아 비효율적입니다.", "5": "오른쪽 다리부터 시작하는 것은 편마비 대상자에게 안전하지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽으로 몸이 마비된 상태", "def_vi": "Trạng thái liệt một bên cơ thể"}, {"term_ko": "지팡이", "term_vi": "Gậy chống", "def_ko": "보행 시 사용하는 보조기구", "def_vi": "Thiết bị hỗ trợ khi đi bộ"}, {"term_ko": "평지", "term_vi": "Mặt đất bằng phẳng", "def_ko": "고르지 않은 땅이나 바닥이 아닌 평탄한 땅", "def_vi": "Đất không có gồ ghề, bằng phẳng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1391, '10', '왼쪽 편마비 대상자가 지팡이를 이용하여 버스를 탈 때 순서로 옳은 것은?', '["지팡이 - 오른발 - 왼발", "지팡이 - 왼발 - 오른발", "왼발 - 지팡이 - 오른발", "오른발 - 지팡이 - 왼발", "왼발 - 오른발 - 지팡이"]'::jsonb, 1, '편마비 환자가 버스를 탈 때의 올바른 순서를 이해하고 적용할 수 있는지 평가하기 위한 문제입니다.', NULL, '{"1": "지팡이를 사용하여 안정성을 확보한 후 오른발로 먼저 올라가고, 이어서 왼발을 올리는 순서가 가장 안전합니다.\n[정답]", "2": "왼발로 먼저 올라가는 방법은 편마비 대상자에게 위험할 수 있습니다.", "3": "왼발을 먼저 들고 지팡이를 뒤로 두는 것은 균형을 잃을 위험이 있습니다.", "4": "오른발을 먼저 올리는 것은 편마비 대상자에게 적절하지 않습니다.", "5": "지팡이를 마지막에 사용하는 것은 안정성을 떨어트릴 수 있습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bệnh liệt nửa người", "def_ko": "한쪽 신체가 마비된 상태", "def_vi": "Tình trạng bị liệt một bên cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1390, '10', '왼쪽 편마비 대상자가 지팡이 없이 계단을 올라갈 때 순서로 옳은 것은?', '["오른쪽 다리 - 왼쪽 다리 - 계단 손잡이", "오른쪽 다리 - 계단 손잡이 - 왼쪽 다리", "왼쪽 다리 - 오른쪽 다리 - 계단 손잡이", "계단 손잡이 - 오른쪽 다리 - 왼쪽 다리", "계단 손잡이 - 왼쪽 다리 - 오른쪽 다리"]'::jsonb, 4, '왼쪽 편마비 환자의 안전한 계단 오르기 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "오른쪽 다리를 먼저 내딛는 것은 안전하지 않으며, 왼쪽 편마비를 가진 환자에게 적절하지 않습니다.", "2": "오른쪽 다리를 밟은 후 계단 손잡이를 사용하는 것은 불안정할 수 있습니다.\n[정답]", "3": "왼쪽 다리가 올라가기는 하지만 순서가 잘못되어 있습니다.", "4": "계단 손잡이를 먼저 잡고 오른쪽 다리를 올리는 것은 안전하게 계단을 오르는 방법입니다.", "5": "계단 손잡이를 잡고 왼쪽 다리를 올리는 것은 편마비 환자에게 안전하지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 신체의 기능이 소실된 상태(한국어)", "def_vi": "Tình trạng mất chức năng ở một bên cơ thể"}, {"term_ko": "계단", "term_vi": "Cầu thang", "def_ko": "사람이나 물체가 올라가거나 내려가는데 사용되는 구조물(한국어)", "def_vi": "Cấu trúc được sử dụng để lên hoặc xuống cho người hoặc vật"}, {"term_ko": "손잡이", "term_vi": "Tay nắm", "def_ko": "물건을 잡고 지탱하는 데 사용되는 물체(한국어)", "def_vi": "Đồ vật được sử dụng để cầm nắm và hỗ trợ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1389, '10', '왼쪽 편마비 대상자가 지팡이를 사용하여 보행할 때 돕는 방법은?', '["왼손으로 지팡이를 잡게 한다.", "지팡이를 앞에 놓고 왼쪽 발부터 이동한다.", "대상자로부터 비스듬히 20cm 뒤에서 속도를 맞춰 걷는다.", "왼쪽 발의 앞 15cm, 옆 15cm 지점에 지팡이 끝을 놓는다.", "지팡이 쪽에 건강한 발을 놓고 불편한 발을 축으로 방향을 바꾼다."]'::jsonb, 2, '왼쪽 편마비 환자의 올바른 보행 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "왼손으로 지팡이를 잡게 한다: 왼쪽 편마비가 있는 환자가 오른손으로 지팡이를 잡는 것이 일반적입니다.\n[정답]", "2": "지팡이를 앞에 놓고 왼쪽 발부터 이동한다: 이는 올바른 지팡이 사용법으로, 편마비 쪽에 지팡이를 먼저 놓고 건강한 발을 후속으로 이동하여 균형을 유지하는 방식입니다.", "3": "대상자로부터 비스듬히 20cm 뒤에서 속도를 맞춰 걷는다: 지팡이를 사용하는 대상자와의 적절한 거리 유지가 중요하지만, 속도를 맞추는 것이 우선이 아닙니다.", "4": "왼쪽 발의 앞 15cm, 옆 15cm 지점에 지팡이 끝을 놓는다: 지팡이를 놓는 위치가 부적절합니다.", "5": "지팡이 쪽에 건강한 발을 놓고 불편한 발을 축으로 방향을 바꾼다: 이 방법은 뒤틀림을 유발할 수 있으므로 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반신 불구(한국어)", "def_vi": "Tình trạng mất khả năng vận động của một bên cơ thể."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1388, '10', '자동차에 앉아있는 편마비 대상자를 휠체어로 옮기는 순서는?', '["가 - 나 - 다 - 라 - 마", "가 - 나 - 라 - 다 - 마", "나 - 가 - 라 - 다 - 마", "나 - 가 - 다 - 라 - 마", "나 - 라 - 다 - 가 - 마"]'::jsonb, 3, '자동차에 앉아 있는 편마비 대상자를 안전하고 적절하게 휠체어로 옮기는 순서를 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "안전벨트를 풀어주는 것이 첫 단계입니다. 이는 대상자를 휠체어로 옮기는 데 필요합니다.\n[정답]", "3": "휠체어를 자동차에 평행하게 놓고 잠금장치를 잠근 후 발 받침대를 접는 것이 중요합니다. 이는 안정성을 확보하는 단계입니다.", "2": "대상자의 두 발이 바닥을 충분히 지지하게 하는 것은 무게 중심을 유지하기 위한 단계입니다.", "4": "대상자 다리를 한쪽씩 자동차 밖으로 내리는 것은 옮기는 과정에서 필수적인 단계입니다.", "5": "마지막으로 마비된 쪽 무릎을 지지하면서 몸을 돌려 휠체어에 앉히는 것이 완료 단계입니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Người bị liệt nửa người", "def_ko": "한쪽 팔다리가 마비됨(편 liệt)", "def_vi": "Bị tê liệt chỉ một bên của cơ thể"}, {"term_ko": "안전벨트", "term_vi": "Dây an toàn", "def_ko": "자동차 안전장치", "def_vi": "Thiết bị an toàn của xe ô tô"}, {"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "이동 보조용 기구", "def_vi": "Thiết bị hỗ trợ di chuyển"}, {"term_ko": "잠금장치", "term_vi": "Thiết bị gắn chặt", "def_ko": "고정 장치", "def_vi": "Thiết bị giữ cố định"}, {"term_ko": "발 받침대", "term_vi": "Bệ chân", "def_ko": "다리 받치기", "def_vi": "Đế giữ chân"}, {"term_ko": "무릎", "term_vi": "Đầu gối", "def_ko": "사람의 다리 관절", "def_vi": "Khớp của chân người"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1387, '10', '편마비 대상자를 휠체어에서 자동차로 옮길 때 앉히는 순서로 옳은 것은?', '["엉덩이 - 양쪽 다리 동시에", "엉덩이 - 건강한 다리 - 마비된 다리", "마비된 다리 - 엉덩이 - 건강한 다리", "건강한 다리 - 엉덩이 - 마비된 다리", "마비된 다리 - 건강한 다리 - 엉덩이"]'::jsonb, 2, '편마비와 같은 신체적 제약을 가진 환자를 안전하게 이동시키기 위한 올바른 순서를 이해하고 적용할 수 있는지를 평가하고자 함.', NULL, '{"1": "엉덩이를 가장 먼저 옮기는 것은 바람직하지 않음.\n[정답]", "2": "엉덩이 - 건강한 다리 - 마비된 다리 순으로 옮기는 것이 안전함.", "3": "마비된 다리를 기준으로 하는 것은 오류임.", "4": "건강한 다리를 먼저 올리는 것은 마비된 쪽에 부담을 줄 수 있음.", "5": "마비된 다리를 먼저 이동하는 것은 위험함."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸의 팔이나 다리가 마비되는 것", "def_vi": "Tình trạng mất khả năng vận động một bên cơ thể"}, {"term_ko": "엉덩이", "term_vi": "Mông", "def_ko": "몸의 아래쪽 부분", "def_vi": "Phần dưới cơ thể"}, {"term_ko": "다리", "term_vi": "Chân", "def_ko": "사람의 하체", "def_vi": "Phần cơ thể ở dưới"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1386, '10', '대상자를 휠체어에서 자동차로 이동할 때 돕는 방법은?', '["휠체어를 자동차와 수직으로 놓는다.", "무릎으로 대상자의 마비측 무릎을 지지하고 일으킨다.", "엉덩이를 마지막에 자동차 시트에 앉힌다.", "대상자의 건강한 손으로 자동차 시트를 짚게 한다.", "대상자와 동승하는 경우 대상자의 앞자리에 앉는다."]'::jsonb, 2, '대상자를 휠체어에서 자동차로 안전하게 이동시키는 방법을 이해하는 것이다.', NULL, '{"1": "휠체어를 자동차와 수직으로 놓으면 이동이 원활하지 않다.\n[정답]", "2": "무릎으로 대상자의 마비측 무릎을 지지하고 일으키는 것은 올바른 방법이다.", "3": "엉덩이를 마지막에 자동차 시트에 앉히는 것은 순서가 아니라 방법에 대한 설명이 부족하다.", "4": "대상자의 건강한 손으로 자동차 시트를 짚게 하는 것은 도움을 줄 수 있지만 이동 방식에는 부적절하다.", "5": "대상자와 동승하는 경우 앞자리에 앉는 것은 유용할 수 있지만 이동 방법에 대한 설명이 아니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1385, '10', '대상자를 휠체어에서 이동변기로 옮기는 순서로 옳은 것은?', '["가 - 라 - 나 - 다", "가 - 다 - 라 - 나", "가 - 라 - 다 - 나", "다 - 가 - 라 - 나", "다 - 라 - 나 - 가"]'::jsonb, 2, '대상자를 안전하게 휠체어에서 이동변기로 옮기는 올바른 방법을 평가하기 위한 문제입니다.', NULL, '{"1": "이동 방법을 설명하고 휠체어의 잠금장치를 잠그는 것은 필수적인 첫 단계입니다.\n[정답]", "2": "건강한 다리에 힘을 주게 하여 엉덩이를 이동시켜 앉히는 단계입니다.", "3": "발받침대를 접고 대상자의 두 발을 바닥에 내려놓게 하는 과정이 필요합니다.", "4": "건강한 손으로 이동변기의 먼 쪽 손잡이를 잡게 하는 것이 중요합니다.", "5": "제대로 된 순서를 따라야 목적지로 안전하게 이동할 수 있습니다."}'::jsonb, '[{"term_ko": "이동변기", "term_vi": "휠체어", "def_ko": "이사 vệ sinh di động", "def_vi": "xe lăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1384, '10', '대상자의 안전을 위해 휠체어를 뒤로 이동해야 하는 경우는?', '["언덕을 오를 때, 언덕을 내려갈 때", "언덕을 오를 때, 문턱을 내려갈 때", "문턱을 내려갈 때, 언덕을 내려갈 때", "문턱을 내려갈 때, 문턱을 오를 때", "문턱을 오를 때, 언덕을 내려갈 때"]'::jsonb, 3, '대상자가 휠체어를 사용할 때 안전하게 이동하는 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "언덕을 오를 때, 언덕을 내려갈 때는 휠체어가 불안정해질 수 있어 위험합니다.\n[정답]", "3": "문턱을 내려갈 때, 언덕을 내려갈 때는 휠체어를 뒤로 이동해야 안전합니다.", "2": "언덕을 오를 때, 문턱을 내려갈 때는 휠체어의 균형이 깨질 수 있습니다.", "4": "문턱을 내려갈 때, 문턱을 오를 때는 휠체어의 안정성을 해칠 수 있습니다.", "5": "문턱을 오를 때, 언덕을 내려갈 때는 휠체어를 뒤로 이동할 필요가 없습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자 또는 고객", "def_vi": "Bệnh nhân hoặc khách hàng"}, {"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "장애인을 위한 이동 수단", "def_vi": "Phương tiện di chuyển cho người khuyết tật"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험 요소가 없는 상태", "def_vi": "Tình trạng không có yếu tố nguy hiểm"}, {"term_ko": "언덕", "term_vi": "Đồi", "def_ko": "경사가 있는 땅", "def_vi": "Mặt đất có độ dốc"}, {"term_ko": "문턱", "term_vi": "Ngưỡng cửa", "def_ko": "출입문이나 방의 바닥과 바닥 사이의 경계", "def_vi": "Ranh giới giữa sàn của cửa ra vào hoặc giữa hai phòng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1383, '10', '스스로 자세를 움직일 수 없는 대상자가 휠체어에 앉아있을 때 올바른 자세는?', '["몸통이 한쪽으로 기울어져 있다.", "발 받침대에 발이 올라가 있다.", "잠금장치가 풀어진 상태에서 쉬고 있다.", "휠체어 끝에 앉아서 얼굴은 바닥을 향해 있다.", "욕창예방 방석 없이 3시간 이상 휠체어에 앉아있다."]'::jsonb, 2, '대상자의 휠체어에서의 올바른 자세에 대한 이해를 확인하기 위함입니다.', NULL, '{"1": "몸통이 한쪽으로 기울어져 있다: 올바른 자세가 아닙니다.\n[정답]", "2": "발 받침대에 발이 올라가 있다: 올바른 자세입니다.", "3": "잠금장치가 풀어진 상태에서 쉬고 있다: 올바른 자세가 아닙니다.", "4": "휠체어 끝에 앉아서 얼굴은 바닥을 향해 있다: 올바른 자세가 아닙니다.", "5": "욕창예방 방석 없이 3시간 이상 휠체어에 앉아있다: 올바른 자세가 아닙니다."}'::jsonb, '[{"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "자세(한국어)", "def_vi": "tư thế (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1382, '10', '휠체어를 펴는 순서로 옳은 것은?', '["잠금 장치 - 팔걸이 펼침 - 시트 누름 - 발 받침대 내림", "잠금 장치 - 발 받침대 내림 - 시트 누름 - 팔걸이 펼침", "잠금 장치 - 시트 누름 - 팔걸이 펼침 - 발 받침대 내림", "팔걸이 펼침 - 시트 누름 - 발 받침대 내림 - 잠금 장치", "발 받침대 내림 - 잠금 장치 - 시트 누름 - 팔걸이 펼침"]'::jsonb, 1, '휠체어의 올바른 조작 방법을 이해하고 있는지 평가하기 위함입니다.', NULL, '{"1": "잠금 장치 - 팔걸이 펼침 - 시트 누름 - 발 받침대 내림\n[정답]", "2": "잠금 장치 - 발 받침대 내림 - 시트 누름 - 팔걸이 펼침", "3": "잠금 장치 - 시트 누름 - 팔걸이 펼침 - 발 받침대 내림", "4": "팔걸이 펼침 - 시트 누름 - 발 받침대 내림 - 잠금 장치", "5": "발 받침대 내림 - 잠금 장치 - 시트 누름 - 팔걸이 펼침"}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "휠체어(한국어)", "def_vi": "Xe lăn (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1381, '10', '오른쪽으로 누워있는 왼쪽 편마비 대상자의 욕창발생 부위는?', '["천골", "목뒤", "오른쪽 귀", "복장 뼈", "발등"]'::jsonb, 3, '대상자가 오른쪽으로 누워 있을 때, 왼쪽 편마비로 인해 욕창이 발생할 수 있는 부위를 확인하는 것이다.', NULL, '{"1": "천골: 보통 인체의 압력이 많이 가해지는 부위로, 옆으로 누워 있을 경우에는 발생 가능성이 있다. 그러나 왼쪽 편마비 대상자의 경우 더 중요하지 않은 부위이다.\n[정답]", "3": "오른쪽 귀: 왼쪽 편마비 대상자가 오른쪽으로 누워있을 때 압력이 가해져 욕창 발생 가능성이 높은 부위이다.", "2": "목뒤: 일반적으로 압력이 덜 가해지는 부위로, 욕창 발생 가능성이 낮다.", "4": "복장 뼈: 뼈 부분이 아니라 일반적으로 욕창 발생 부위가 아닌 곳이다.", "5": "발등: 발가락이나 발바닥보다 더 압력이 덜 가해지는 부분으로, 욕창 발생 가능성이 낮다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부의 손상(한국어)", "def_vi": "Vết thương trên da"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1380, '10', '대상자의 아래 증상을 완화시킬 수 있는 자세로 옳은 것은?', '["엎드린 자세", "서있는 자세", "앉은 자세", "바로 누운 자세", "옆으로 누운 자세"]'::jsonb, 1, '대상자의 통증을 완화하고 욕창 예방을 위한 올바른 자세를 찾는 것임.', NULL, '{"1": "엎드린 자세는 등과 어깨의 부담을 줄일 수 있어 통증 완화에 도움을 줄 수 있다.\n[정답]", "2": "서있는 자세는 하중이 균일하지 않아 통증이 악화될 수 있다.", "3": "앉은 자세는 장시간 유지 시 통증을 유발할 수 있다.", "4": "바로 누운 자세는 허리에 압박을 줄 수 있어 통증을 유발할 수 있다.", "5": "옆으로 누운 자세는 압력을 특정 부위에 가해 욕창을 초래할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1378, '10', '장기간 침상생활을 하는 대상자의 관절강직과 변형을 예방하는 방법은?', '["탄력스타킹 착용", "체위변경", "방수포 사용", "공기침대 사용", "뜨거운 물주머니 찜질"]'::jsonb, 2, '장기간 침상생활을 하는 대상자에게 적절한 보호 방법을 묻는 문제이다.', NULL, '{"1": "탄력스타킹 착용은 하지정맥 혈전증 예방에 도움이 되지만 관절강직 예방에는 효과적이지 않다.\n[정답]", "2": "체위변경은 장시간 같은 자세로 있는 것을 방지하여 관절의 강직과 변형을 예방하는 중요한 방법이다.", "3": "방수포 사용은 기저귀나 침대의 오염을 예방하는 데 좋지만 관절강직 예방과는 직접적인 관련이 없다.", "4": "공기침대 사용은 욕창 예방에 도움이 되나, 관절 강직 예방에는 효과가 적다.", "5": "뜨거운 물주머니 찜질은 일시적으로 통증 완화에 도움을 줄 수 있지만 관절강직 예방에 대한 효과는 미미하다."}'::jsonb, '[{"term_ko": "장기간", "term_vi": "Thời gian dài", "def_ko": "오랜 시간 동안", "def_vi": "Trong thời gian dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1377, '10', '체위변경의 목적으로 옳은 것은?', '["페 확장이 감소된다.", "관절의 움직임이 제한된다.", "부종과 혈전을 예방한다.", "욕창이 심해진다.", "고정된 자세를 만들어 준다."]'::jsonb, 3, '체위변경이 필요한 이유와 그 효과에 대한 이해를 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "체위변경은 폐의 확장을 돕는 데 기여하므로 확장이 감소된다라는 설명은 틀립니다.\n[정답]", "3": "체위변경은 부종과 혈전을 예방하는 데 효과적입니다.", "2": "체위변경은 관절의 움직임을 촉진시켜 제한이 되지 않도록 도와줍니다.", "4": "체위변경은 욕창을 예방하는 데 도움을 주기 때문에 심해진다는 것은 잘못된 설명입니다.", "5": "고정된 자세보다 다양한 체위를 유지하는 것이 체위변경의 목적이므로 이는 틀린 설명입니다."}'::jsonb, '[{"term_ko": "체위변경", "term_vi": "Thay đổi tư thế", "def_ko": "환자의 자세를 바꾸는 것", "def_vi": "Thay đổi vị trí của bệnh nhân"}, {"term_ko": "부종", "term_vi": "Phù nề", "def_ko": "몸의 일부에 액체가 고인 상태", "def_vi": "Tình trạng tích tụ dịch tại một phần cơ thể"}, {"term_ko": "혈전", "term_vi": "Huyết khối", "def_ko": "혈액이 고여 생긴 덩어리", "def_vi": "Khối máu đông hình thành trong mạch máu"}, {"term_ko": "욕창", "term_vi": "Loét", "def_ko": "계속 압력이 가해져 피부가 손상된 상태", "def_vi": "Tình trạng da bị tổn thương do áp lực liên tục"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1376, '10', '편마비 대상자를 옆에서 보조하면서 일으켜 세울 때 순서로 옳은 것은?가. 대퇴부를 지지하던 손을 가슴 부위로 옮겨 상체를 펴게 한다. 나. 요양보호사의 발을 대상자의 마비된 발 바로 뒤에 놓는다. 다. 마비된 대퇴부와 반대쪽 허리를 부축하여 일으켜 세운다. 라. 대상자를 침대 끝에 앉혀 양 발을 무릎보다 뒤쪽에 놓는다.', '["라-나-다-가", "나-라-가-다", "가-나-라-다", "가-라-나-다", "가-다-나-라"]'::jsonb, 1, '편마비 대상자를 안전하게 일으키고 보조하는 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "위의 설명과 일치하므로 옳은 순서입니다.", "2": "나-라-가-다: 순서가 잘못되었습니다.", "3": "가-나-라-다: 순서가 잘못되었습니다.", "4": "가-라-나-다: 순서가 잘못되었습니다.", "5": "가-다-나-라: 순서가 잘못되었습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bệnh liệt nửa người", "def_ko": "신체의 한쪽이 마비된 상태", "def_vi": "Tình trạng liệt bên một cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1375, '10', '편마비 대상자의 상체를 일으킬 때 돕는 방법으로 옳은 것은?', '["한꺼번에 신속히 일으킨다.", "대상자의 마비된 쪽에 선다.", "양손을 가슴위에 올려놓는다.", "대상자의 양쪽 무릎을 곧게 편다.", "팔을 대상자의 목 밑에 깊숙하게 넣어 등과 어깨를 지지한다."]'::jsonb, 5, '편마비 대상자에게 안전하고 효과적으로 도움을 줄 수 있는 방법을 이해하고 평가하는 것이다.', NULL, '{"1": "한꺼번에 신속히 일으키는 것은 위험할 수 있다.\n[정답]", "5": "팔을 대상자의 목 밑에 깊숙하게 넣어 등과 어깨를 지지하는 것은 올바른 방법이다.", "2": "대상자의 마비된 쪽에 서는 것은 바람직하지 않다.", "3": "양손을 가슴 위에 올려놓는 것은 지지력을 줄 수 없다.", "4": "대상자의 양쪽 무릎을 곧게 펴는 것은 필요하지 않다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 팔이나 다리의 운동이 제한된 상태(한국어)", "def_vi": "Trạng thái hạn chế vận động của một bên tay hoặc chân (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1373, '10', '편마비 대상자를 옆으로 돌려 눕히려고 할 때 지지해야 할 부분은?', '["어깨와 엉덩이", "목과 어깨", "양쪽 팔", "허리와 엉덩이", "한쪽 팔과 다리"]'::jsonb, 2, '편마비 대상을 옆으로 돌려 눕힐 때 어떤 지점을 지지해야 하는지를 묻고 있습니다.', NULL, '{"1": "어깨와 엉덩이는 지지해야 할 부분이 아닙니다.\n[정답]", "2": "목과 어깨는 편마비 대상자를 지지하는 올바른 부분입니다.", "3": "양쪽 팔은 편마비 대상자의 지지를 위해 적절하지 않습니다.", "4": "허리와 엉덩이 역시 올바른 지지 부분이 아닙니다.", "5": "한쪽 팔과 다리는 지지해야 할 주요 부위가 아닙니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸이 마비된 상태", "def_vi": "Tình trạng bị liệt một bên cơ thể"}, {"term_ko": "지지하다", "term_vi": "Hỗ trợ", "def_ko": "지탱하거나 받쳐주다", "def_vi": "Đỡ hoặc nâng đỡ"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "눕히다", "term_vi": "Đặt nằm", "def_ko": "눕게 하다", "def_vi": "Để nằm xuống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1372, '10', '침대에 누워있는 왼쪽 편마비 대상자를 건강한 쪽으로 돌려 눕히는 순서로 옳은 것은?가. 엉덩이와 아래쪽 어깨를 움직여 편안하게 해준다. 나. 무릎을 세우고 양손을 가슴 위에 포개 놓는다. 다. 엉덩이와 어깨를 지지하여 돌려 눕힌다. 라. 대상자의 오른쪽에 선다.', '["가-다-라-나", "나-라-가-다", "다-가-나-라", "라-가-나-다", "라-나-다-가"]'::jsonb, 1, '대상자의 안전하고 편안한 자세 변화를 돕기 위한 올바른 간호 순서를 이해하도록 하는 문제입니다.', NULL, '{"1": "엉덩이와 아래쪽 어깨를 움직여 편안하게 해준다.\n[정답] (다) 엉덩이와 어깨를 지지하여 돌려 눕힌다.\n(나) 무릎을 세우고 양손을 가슴 위에 포개 놓는다.\n(라) 대상자의 오른쪽에 선다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa", "def_ko": "한쪽 몸의 마비 상태", "def_vi": "Trạng thái liệt ở một bên cơ thể"}, {"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "특정한 위치 또는 방향", "def_vi": "Vị trí hoặc hướng cụ thể"}, {"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "돌봄 받는 사람", "def_vi": "Người được chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1371, '10', '대상자를 옆으로 돌려 눕히는 방법으로 옳은 것은?', '["요양보호사는 돌려 눕히려는 반대쪽에 선다.", "엉덩이 - 어깨 - 얼굴의 순으로 돌려 눕힌다.", "눕히려는 반대쪽의 손을 위로 올린다.", "눕는 방향과 반대쪽 발을 다른 발 위에 올려놓는다.", "엉덩이를 앞으로 이동시켜 자세를 편안하게 한다."]'::jsonb, 5, '대상자를 안전하고 효과적으로 돌려 눕히기 위한 올바른 방법을 묻고 있다.', NULL, '{"1": "요양보호사는 돌려 눕히려는 반대쪽에 선다.\n[정답]", "2": "엉덩이 - 어깨 - 얼굴의 순으로 돌려 눕힌다.", "3": "눕히려는 반대쪽의 손을 위로 올린다.", "4": "눕는 방향과 반대쪽 발을 다른 발 위에 올려놓는다.", "5": "엉덩이를 앞으로 이동시켜 자세를 편안하게 한다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "눕히다", "term_vi": "Nằm", "def_ko": "눕게 하다(옮기다)", "def_vi": "Đặt nằm"}, {"term_ko": "엉덩이", "term_vi": "Mông", "def_ko": "엉덩이 부위", "def_vi": "Phần mông"}, {"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "체위, 자세", "def_vi": "Tư thế"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1370, '10', '침대 위에서 이동 시 대상자를 끌어당기거나 한꺼번에 많이 이동하지 않고, 조금씩 나누어 이동하는 이유는?', '["관절구축 예방", "욕창예방", "낙상예방", "근육수축 예방", "호흡곤란 예방"]'::jsonb, 4, '대상자를 안전하게 이동시키는 방법과 그 이유를 이해하도록 하기 위함입니다.', NULL, '{"1": "관절구축 예방은 장기간 비활동으로 인해 관절이 굳는 것을 방지하는 방법입니다. 하지만 이는 주된 이유는 아닙니다.\n[정답]", "4": "근육수축 예방은 대상자의 근육이 과도하게 긴장하거나 수축하지 않도록 하여 부상을 방지하는 방법입니다.", "2": "욕창 예방은 장시간 같은 자세로 있을 때 생기는 피부 손상을 방지하기 위한 것이므로 이와는 관련이 적습니다.", "3": "낙상 예방은 대상자의 안전을 위해 중요하지만, 이동 시에 한꺼번에 많이 이동하는 것과의 직접적인 연관성은 낮습니다.", "5": "호흡곤란 예방 역시 중요한 사항이나 여기서는 근육 수축 예방이 더 관련이 높습니다."}'::jsonb, '[{"term_ko": "이동", "term_vi": "Di chuyển", "def_ko": "이동(한국어)", "def_vi": "di chuyển(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1369, '10', '오른쪽 편마비 대상자가 왼쪽으로 쏠려 누워 있을 때 침대 중앙으로 이동시키는 순서로 옳은 것은?가. 요양보호사는 대상자의 오른쪽에 선다. 나. 목에서 겨드랑이와 허리 아래에 손을 넣어 상반신을 이동시킨다. 다. 대상자의 두 팔을 가슴 위에 포갠다. 라. 하반신은 허리와 엉덩이 밑을 받쳐서 이동시킨다. 마. 머리에 베개를 받치고 침대 시트를 바르게 한다.', '["가 - 나 - 다 - 라 - 마", "나 - 가 - 다 - 마 - 라", "다 - 가 - 나 - 라 - 마", "나 - 다 - 가 - 마 - 라", "가 - 다 - 나 - 라 - 마"]'::jsonb, 2, '대상자의 안전한 이동 방법을 알고 있는지를 묻는 문제입니다.', NULL, '{"1": "요양보호사가 대상자의 오른쪽에 서는 것은 편마비 환자에게 적절한 위치가 아닙니다.\n[정답]", "2": "요양보호사는 먼저 목에서 겨드랑이와 허리 아래에 손을 넣어 상반신을 이동시키고, 이후에 대상자의 두 팔을 가슴 위에 포갠 후, 하반신을 옮기는 방법이 안전합니다.", "3": "이 순서는 비효율적이며 안전하지 않습니다.", "4": "이 순서도 적절하지 않습니다.", "5": "요양보호사가 먼저 오른쪽에 서는 것은 편마비 환자 이동 시 부적절한 위치입니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸이 마비된 상태", "def_vi": "Tình trạng tê liệt một bên cơ thể"}, {"term_ko": "상반신", "term_vi": "Thân trên", "def_ko": "허리 위의 몸", "def_vi": "Phần cơ thể trên hông"}, {"term_ko": "하반신", "term_vi": "Thân dưới", "def_ko": "허리 아래의 몸", "def_vi": "Phần cơ thể dưới hông"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc bệnh nhân"}, {"term_ko": "베개", "term_vi": "Gối", "def_ko": "머리를 받치는 물건", "def_vi": "Vật kê đầu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1368, '10', '침상 내에서 대상자의 잔존기능을 유지하며 안전하게 이동하는 방법은?', '["이동 시 동작은 한번에 신속하게 시행한다.", "대상자의 동의를 구한 뒤 천천히 이동한다.", "변경 가능한 체위를 보호자와 상의한다.", "의식 상태가 있는 대상자에게만 설명한다.", "편마비 대상자는 전적으로 도와준다."]'::jsonb, 5, '대상자의 안전한 이동 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "이동 시 동작은 한번에 신속하게 시행하는 것은 좋지 않으며, 신중하게 접근해야 합니다.\n[정답]", "5": "편마비 대상자는 전적으로 도와주는 것이 필요합니다.", "2": "대상자의 동의를 구한 뒤 천천히 이동하는 것이 안전하며, 동의를 받는 것이 중요합니다.", "3": "변경 가능한 체위를 보호자와 상의하는 것은 필요하지만, 직접적인 이동 방법에는 해당되지 않습니다.", "4": "의식 상태가 있는 대상자에게만 설명하는 것은 바람직하지 않으며, 가능한 모든 대상자에게 설명이 필요합니다."}'::jsonb, '[{"term_ko": "잔존기능", "term_vi": "Chức năng còn lại", "def_ko": "남아있는 기능", "def_vi": "Chức năng còn lại"}, {"term_ko": "대상자", "term_vi": "Người dùng", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "동의", "term_vi": "Đồng ý", "def_ko": "동의", "def_vi": "Sự đồng ý"}, {"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "편측만 마비됨", "def_vi": "Liệt một bên"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1367, '10', '대상자를 이동시킬 때 요양보호사의 신체손상을 예방하는 방법은?', '["무릎을 펴고 허리를 구부린다.", "신체의 작은 근육을 사용한다.", "발을 벌리고 서서 지지면을 넓게 한다.", "무릎을 펴고 무게중심을 높게 둔다.", "배에 힘을 배고 척추를 구부린다."]'::jsonb, 2, '대상자를 안전하게 이동시키기 위한 방법을 이해하도록 하는 것.', NULL, '{"1": "무릎을 펴고 허리를 구부리면 허리에 부담이 가중되어 부상을 초래할 수 있다.\n[정답]", "2": "신체의 작은 근육을 사용하면 부상의 위험을 줄일 수 있다.", "3": "발을 벌리고 지지면을 넓히면 안정성을 증가시킬 수 있지만, 작은 근육 사용이 더 효과적이다.", "4": "무릎을 펴고 무게중심을 높게 둔다면 균형을 잃기 쉽다.", "5": "배에 힘을 주고 척추를 구부리면 오히려 부상을 유발할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "이동", "term_vi": "Di chuyển", "def_ko": "움직이다(한국어)", "def_vi": "Di chuyển"}, {"term_ko": "신체", "term_vi": "Cơ thể", "def_ko": "몸(한국어)", "def_vi": "Cơ thể"}, {"term_ko": "근육", "term_vi": "Cơ bắp", "def_ko": "근육(한국어)", "def_vi": "Cơ bắp"}, {"term_ko": "무게중심", "term_vi": "Trọng tâm", "def_ko": "무게의 중심(한국어)", "def_vi": "Trọng tâm"}, {"term_ko": "부상", "term_vi": "Chấn thương", "def_ko": "상처(한국어)", "def_vi": "Chấn thương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1366, '10', '대상자를 이동시킬 때 요양보호사가 신체정렬을 유지하는 목적은?', '["신속한 이동을 할 수 있다.", "관절의 굳어짐을 증가시킨다.", "근육의 사용을 감소시킨다.", "관절의 변형을 증가시킨다.", "편안함을 제공하고 손상의 위험을 줄인다."]'::jsonb, 3, '대상자를 이동시킬 때 신체 정렬의 중요성을 이해하고 그 목적을 아는가?', NULL, '{"1": "신속한 이동을 할 수 있다는 것은 잘못된 진술이다.\n[정답]", "3": "근육의 사용이 감소되지 않도록 신체의 정렬을 유지하는 것이 중요하다.", "2": "관절의 굳어짐은 감소시켜야 한다.", "4": "관절의 변형이 증가하지 않도록 해야 한다.", "5": "편안함을 제공하고 손상의 위험을 줄이는 것이 목적이다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Người nhận dịch vụ chăm sóc"}, {"term_ko": "이동", "term_vi": "Di chuyển", "def_ko": "움직이다", "def_vi": "Di chuyển từ nơi này sang nơi khác"}, {"term_ko": "신체정렬", "term_vi": "Sắp xếp cơ thể", "def_ko": "바른 자세", "def_vi": "Tư thế cơ thể đúng"}, {"term_ko": "관절", "term_vi": "Khớp", "def_ko": "관절", "def_vi": "Khớp của cơ thể"}, {"term_ko": "근육", "term_vi": "Cơ", "def_ko": "근육", "def_vi": "Các mô trong cơ thể"}, {"term_ko": "손상", "term_vi": "Chấn thương", "def_ko": "손해", "def_vi": "Tổn thương xảy ra"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1365, '10', '오른쪽 편마비 대상자의 하의를 입히는 순서로 옳은 것은?가. 왼쪽 발을 하의에 넣게 한다. 나. 오른쪽 발을 하의에 넣게 한다. 다. 바지의 양쪽 허리선을 잡고 올려서 입힌다. 라. 무릎을 세우고 엉덩이를 들어 올리게 한다.', '["가 - 나 - 라 - 다", "가 - 나 - 다 - 라", "나 - 가 - 라 - 다", "나 - 가 - 다 - 라", "라 - 나 - 가 - 다"]'::jsonb, 5, '오른쪽 편마비가 있는 대상자의 하의를 착용하는 올바른 순서를 이해하고 판단하는 것을 목표로 하고 있습니다.', NULL, '{"1": "왼쪽 발을 하의에 넣는 것이 먼저입니다. 오른쪽 편마비이므로 왼쪽부터 시작해야 합니다. \n[정답]", "5": "무릎을 세우고 엉덩이를 들어 올리는 행동이 먼저 필요합니다. 그 후 오른쪽 발, 왼쪽 발 순으로 하의를 착용하고 바지를 올리는 것이 적절합니다.", "3": "나 - 가 - 라 - 다의 순서는 하의 착용 순서에 맞지 않습니다. 하의를 입힐 때 무릎을 세우고 엉덩이를 들어 올리는 것이 먼저입니다.", "4": "나 - 가 - 다 - 라도 잘못된 순서입니다. 하의를 착용하려면 꼭 먼저 무릎을 세우고 엉덩이를 들어 올려야 합니다.", "2": "가 - 나 - 다 - 라의 순서는 올바르지 않으며, 무릎을 세우고 엉덩이를 들어 올리는 과정을 포함해야합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽 몸이 마비된 상태", "def_vi": "Tình trạng bị liệt một nửa cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1364, '10', '왼쪽 편마비 대상자의 하의를 버기는 순서로 옳은 것은?가. 오른쪽 다리의 하의를 벗긴다. 나. 왼쪽 다리의 하의를 벗긴다. 다. 두 다리를 모아 무릎을 세운다. 라. 무릎으로 마비된 쪽의 발을 지지하고, 엉덩이를 들어 올리게 한다.', '["가 - 다 - 라 - 나", "가 - 라 - 다 - 나", "나 - 다 - 라 - 가", "다 - 라 - 나 - 가", "다 - 라 - 가 - 나"]'::jsonb, 3, '대상자의 하의를 벗기는 올바른 순서를 이해하고 있는지를 평가하고자 한다.', NULL, '{"1": "오른쪽 다리의 하의를 먼저 벗기는 것은 잘못된 순서이다.\n[정답]", "2": "왼쪽 다리의 하의를 벗기기 전에 무릎을 세워야 한다는 점을 강조한다.", "3": "무릎을 세우고 엉덩이를 들어 올리는 것이 마비된 쪽의 다리를 더 쉽게 벗길 수 있다.", "4": "다시 오른쪽 다리의 하의를 벗기는 것은 잘못된 순서다.", "5": "무릎을 세우는 단계가 없이 하의를 벗기는 것은 부적절하다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bệnh liệt nửa người", "def_ko": "한쪽 몸이 마비된 상태(한국어)", "def_vi": "Tình trạng tê liệt một bên cơ thể"}, {"term_ko": "무릎", "term_vi": "Đầu gối", "def_ko": "무릎관절(한국어)", "def_vi": "Khớp gối"}, {"term_ko": "하의", "term_vi": "Quần", "def_ko": "하체의 의류(한국어)", "def_vi": "Trang phục phần dưới cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1363, '10', '엉덩이를 들 수 없는 대상자의 하의를 갈아입히는 방법으로 옳은 것은?', '["침상머리를 높여 앉힌 후 입힌다.", "다리를 모아 무릎을 세운 후 벗긴다.", "똑바로 누운 상태에서 한꺼번에 벗긴다.", "좌우로 체위를 변경하며 한쪽씩 벗긴다.", "한 손으로 대상자의 허리를 지지한 후 입힌다."]'::jsonb, 5, '대상자의 하의를 갈아입히는 올바른 방법을 묻는 문제입니다.', NULL, '{"1": "침상머리를 높여 앉힌 후 입힌다. - 대상자의 엉덩이를 들 수 없기 때문에 적절하지 않은 방법입니다.\n[정답]", "5": "한 손으로 대상자의 허리를 지지한 후 입힌다. - 대상자의 하의를 갈아입히는 가장 안전하고 효과적인 방법입니다.", "2": "다리를 모아 무릎을 세운 후 벗긴다. - 엉덩이를 들 수 없으므로 잘못된 방법입니다.", "3": "똑바로 누운 상태에서 한꺼번에 벗긴다. - 무리한 방법으로, 안전하지 않습니다.", "4": "좌우로 체위를 변경하며 한쪽씩 벗긴다. - 엉덩이를 들 수 없는 경우에 적합하지 않습니다."}'::jsonb, '[{"term_ko": "엉덩이", "term_vi": "Mông", "def_ko": "엉덩이(한국어)", "def_vi": "Mông (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1362, '10', '수액이 있는 왼쪽 편마비 대상자의 단추 있는 옷을 벗길 때 순서로 옳은 것은?', '["오른쪽 팔 - 수액주머니 - 왼쪽 팔", "오른쪽 팔 - 왼쪽 팔 - 수액주머니", "왼쪽 팔 - 수액주머니 - 오른쪽 팔", "수액주머니 - 오른쪽 팔 - 왼쪽 팔", "수액주머니 - 왼쪽 팔 - 오른쪽 팔"]'::jsonb, 4, '왼쪽 편마비 대상자에게 적절한 착용 및 벗기기 방법을 알아보는 것.', NULL, '{"1": "오른쪽 팔을 먼저 벗기면 왼쪽 편마비로 인해 불편함이 있을 수 있다.\n[정답]", "4": "수액주머니를 먼저 제거한 뒤, 오른쪽 팔을 벗기고 마지막으로 왼쪽 팔을 벗겨야 안전하다.", "2": "왼쪽 팔을 먼저 벗기면 수액주머니에 손상을 줄 수 있다.", "3": "왼쪽 팔을 먼저 벗기면 수액주머니를 다치게 할 위험이 있다.", "5": "수액주머니를 고려하지 않고 순서를 정하면 위험할 수 있다."}'::jsonb, '[{"term_ko": "수액", "term_vi": "Dung dịch truyền", "def_ko": "액체 영양분이 포함된 의료용액", "def_vi": "Dung dịch dinh dưỡng có chứa các chất lỏng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1361, '10', '오른쪽 편마비 대상자의 앞이 막힌 상의를 벗기는 순서는?', '["왼쪽 팔 - 머리 - 오른쪽 팔", "왼쪽 팔 - 오른쪽 팔 - 머리", "오른쪽 팔 - 머리 - 왼쪽 팔", "오른쪽 팔 - 왼쪽 팔 - 머리", "머리 - 왼쪽 팔 - 오른쪽 팔"]'::jsonb, 1, '상체 마비가 있는 대상자의 옷을 벗기는 방법을 이해하고 있는지를 묻는 문제입니다.', NULL, '{"1": "왼쪽 팔을 먼저 들어준 후 머리를 벗기는 것이 마비된 오른쪽 팔에 부담을 주지 않아 올바른 방법입니다.\n[정답]", "2": "오른쪽 팔을 벗긴 후 머리를 먼저 벗기면 마비된 팔에 부담이 가해질 수 있습니다.", "3": "오른쪽 팔을 먼저 벗기는 것은 잘못된 순서입니다.", "4": "오른쪽 팔을 벗긴 후 왼쪽 팔을 벗기는 것은 비효율적입니다.", "5": "머리부터 벗기는 것은 마비된 팔에 불편을 초래합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽 몸이 마비된 상태", "def_vi": "Tình trạng mất cảm giác một nửa cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1360, '10', '왼쪽 편마비 대상자에게 앞이 막힌 상의를 입히는 순서는?', '["왼쪽 팔 - 머리 - 오른쪽 팔", "왼쪽 팔 - 오른쪽 팔 - 머리", "오른쪽 팔 - 머리 - 왼쪽 팔", "오른쪽 팔 - 왼쪽 팔 - 머리", "머리 - 왼쪽 팔 - 오른쪽 팔"]'::jsonb, 1, '왼쪽 편마비 대상자에게 적절하게 상의를 입히는 방법을 묻고 있습니다.', NULL, '{"1": "왼쪽 팔에 옷을 먼저 입히면 편마비로 인해 오른쪽 팔로 도움을 줄 수 있어 원활하게 입힐 수 있습니다. [정답]", "2": "왼쪽 팔과 오른쪽 팔을 동시에 다루면 불편할 수 있습니다.", "3": "오른쪽 팔부터 시작하면 왼쪽 팔 입히기가 어려울 수 있습니다.", "4": "오른쪽 팔부터 입히면 다시 왼쪽으로 이동해야 하므로 비효율적입니다.", "5": "머리부터 입히면 편마비 환자의 팔 작동에 방해가 되어 입히기 힘듭니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽에만 마비가 있는 상태", "def_vi": "Tình trạng bị liệt chỉ một bên"}, {"term_ko": "상위", "term_vi": "Áo", "def_ko": "위쪽에 입는 옷", "def_vi": "Trang phục mặc trên cơ thể"}, {"term_ko": "입히다", "term_vi": "Mặc", "def_ko": "옷을 착용하게 하다", "def_vi": "Đưa trang phục lên người"}, {"term_ko": "순서", "term_vi": "Thứ tự", "def_ko": "어떤 것이 먼저인지의 차례", "def_vi": "Sự sắp xếp thứ tự"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1359, '10', '오른쪽 편마비 대상자의 옷 갈아입히는 방법으로 옳은 것은?', '["오른쪽부터 벗고 오른쪽부터 입는다.", "오른쪽부터 벗고 왼쪽부터 입는다.", "왼쪽부터 벗고 왼쪽부터 입는다.", "왼쪽부터 벗고 오른쪽부터 입는다.", "대상자가 원하는 쪽부터 벗고 입힌다."]'::jsonb, 1, '편마비 대상자의 의복 착탈의 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "오른쪽부터 벗고 오른쪽부터 입는다. - 오른쪽 편마비 대상자에게 적합한 방법입니다.\n[정답]", "2": "오른쪽부터 벗고 왼쪽부터 입는다. - 오른쪽은 우선 벗지만, 왼쪽부터 입는 것은 비효율적입니다.", "3": "왼쪽부터 벗고 왼쪽부터 입는다. - 편마비에 적합하지 않은 방법입니다.", "4": "왼쪽부터 벗고 오른쪽부터 입는다. - 잘못된 순서입니다.", "5": "대상자가 원하는 쪽부터 벗고 입힌다. - 사용자의 필요를 고려하나, 편마비 환자에게는 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 신체가 마비된 상태", "def_vi": "Tình trạng một bên cơ thể bị liệt"}, {"term_ko": "옷 갈아입히다", "term_vi": "Thay áo", "def_ko": "옷을 입고 벗는 것", "def_vi": "Thay đổi quần áo"}, {"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "요양 서비스를 받는 사람", "def_vi": "Người nhận dịch vụ chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1358, '10', '편마비 대상자의 옷 갈아입히는 순서로 옳은 것은?', '["벗을 때는 불편한 쪽부터 벗긴다.", "입을 때는 불편한 쪽부터 입힌다.", "요양보호사가 편한 쪽부터 입힌다.", "대상자가 원하는 쪽부터 입힌다.", "어느 쪽이든 상관없다."]'::jsonb, 2, '편마비 대상자의 옷 갈아입히는 올바른 순서를 이해하는 것이 중요하다.', NULL, '{"1": "벗을 때는 불편한 쪽부터 벗긴다. - 옷을 벗을 때는 편한 쪽부터 벗기는 것이 일반적이다.\n[정답]", "2": "입을 때는 불편한 쪽부터 입힌다. - 편마비 환자에게는 불편한 쪽부터 옷을 입히는 것이 적절하다.", "3": "요양보호사가 편한 쪽부터 입힌다. - 요양보호사는 불편한 쪽을 먼저 입혀야 한다.", "4": "대상자가 원하는 쪽부터 입힌다. - 환자 의사보다 효과적인 방법이 더 중요하다.", "5": "어느 쪽이든 상관없다. - 옷 입히는 순서를 무시하는 것은 바람직하지 않다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽이 마비된 상태", "def_vi": "Trạng thái bị liệt một bên"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1357, '10', '편마비 대상자의 옷을 선택하는 방법으로 옳은 것은?', '["상의와 하의가 연결된 옷이 좋다.", "허리와 소매가 조이는 옷이 좋다.", "앞여밈이 있거나 단추 있는 옷이 좋다.", "신축성이 없는 옷이 좋다.", "무겁고 두꺼운 옷이 좋다."]'::jsonb, 3, '편마비 대상자가 입는 옷의 선택 방법에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "상의와 하의가 연결된 옷은 편마비 환자가 입기 어렵기 때문에 적합하지 않습니다.\n[정답]", "3": "앞여밈이 있거나 단추 있는 옷은 편리하게 입을 수 있어 적합합니다.", "2": "허리와 소매가 조이는 옷은 불편할 수 있습니다.", "4": "신축성이 없는 옷은 착용이 어렵고 불편할 수 있습니다.", "5": "무겁고 두꺼운 옷은 입기 힘들고 이동에 불편을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽 몸이 마비됨(한국어)", "def_vi": "Bị liệt một bên cơ thể"}, {"term_ko": "상의", "term_vi": "Áo trên", "def_ko": "윗옷(한국어)", "def_vi": "Trang phục phần trên"}, {"term_ko": "하의", "term_vi": "Quần", "def_ko": "아랫옷(한국어)", "def_vi": "Trang phục phần dưới"}, {"term_ko": "조이다", "term_vi": "Chật", "def_ko": "꽉 끼다(한국어)", "def_vi": "Bị chật"}, {"term_ko": "신축성", "term_vi": "Độ co giãn", "def_ko": "늘어나는 성질(한국어)", "def_vi": "Tính đàn hồi"}, {"term_ko": "무겁다", "term_vi": "Nặng", "def_ko": "체중이 많이 나가다(한국어)", "def_vi": "Nặng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1356, '10', '침상을 정리하는 방법으로 옳은 것은?', '["창문을 닫고 더러워진 시트를 벗긴다.", "이불을 기온과 보호자의 요구에 따라 조절한다.", "방수포 밑에 반시트를 깔아둔다.", "시트 중앙선이 침대 중앙에 오도록 한다.", "침상배설을 하는 대상자는 방수포만 깔아둔다."]'::jsonb, 4, '침상을 정리하는 적절한 방법을 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "창문을 닫고 더러워진 시트를 벗기는 것은 침상의 정리 방법 중 첫 단계일 수 있지만, 정답이 아닙니다.\n[정답]", "2": "이불을 기온과 보호자의 요구에 따라 조절하는 것은 침상 정리의 중요한 요소입니다.", "3": "방수포 밑에 반시트를 깔아두는 것은 잘못된 방법입니다.", "4": "시트 중앙선이 침대 중앙에 오도록 하는 것은 침상을 정리할 때 가장 기본적인 방법이므로 정답입니다.", "5": "침상배설을 하는 대상자는 방수포만 깔아두는 것은 적절하지 않습니다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "Giường ngủ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1355, '10', '침상 목욕 시 신체 부위에 따른 목욕 방법으로 옳은 것은?', '["유방은 위아래로 번갈아 가며 닦는다.", "둔부는 엉덩이 사이와 항문 주위를 닦는다.", "복부는 배꼽을 중심으로 시계 반대 방향으로 닦는다.", "팔은 어깨 - 손끝 방향, 다리는 허버지 - 발끝 방향으로 닦는다.", "뼈가 돌출된 등에 피부발적이 보이면 목욕 후 등 마사지를 한다."]'::jsonb, 2, '침상 목욕 시 신체 부위에 대한 올바른 목욕 방법을 이해하고 있는지를 평가하려는 의도이다.', NULL, '{"1": "유방은 위아래로 번갈아 가며 닦는다. (잘못된 방법) \n[정답]", "2": "둔부는 엉덩이 사이와 항문 주위를 닦는다. (올바른 방법)", "3": "복부는 배꼽을 중심으로 시계 반대 방향으로 닦는다. (잘못된 방법)", "4": "팔은 어깨 - 손끝 방향, 다리는 허벅지 - 발끝 방향으로 닦는다. (잘못된 방법)", "5": "뼈가 돌출된 등에 피부발적이 보이면 목욕 후 등 마사지를 한다. (잘못된 방법)"}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대 위", "def_vi": "trên giường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1354, '10', '침상 목욕 시 복부를 배꼽을 중심으로 시계방향으로 닦아주는 이유는?', '["혈액순환을 위해서", "욕창을 예방하기 위해서", "소화기능을 돕기 위해서", "긴장감을 완화하기 위해서", "장운동을 촉진하기 위해서"]'::jsonb, 5, '침상 목욕 시 복부를 시계방향으로 닦는 이유를 이해하고, 그 효과에 대한 정확한 지식을 확인하기 위함입니다.', NULL, '{"1": "혈액순환을 위해서\n복부 목욕 시에는 직접적인 혈액순환과 관련이 적습니다.\n[정답]", "2": "장운동을 촉진하기 위해서\n복부를 시계방향으로 닦는 것은 장운동을 자극하여 소화에 도움이 됩니다.", "3": "소화기능을 돕기 위해서\n장운동 촉진과 연관이 있지만, 직접적인 목적은 아닙니다.", "4": "긴장감을 완화하기 위해서\n일반적으로 긴장감 완화와는 관련이 부족합니다.", "5": "욕창을 예방하기 위해서\n욕창 예방은 바른 자세와 피부 관리가 중요합니다."}'::jsonb, '[{"term_ko": "침상 목욕", "term_vi": "Tắm trên giường", "def_ko": "침대에서 하는 목욕", "def_vi": "Tắm cho bệnh nhân nằm trên giường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1353, '10', '침상 목욕으 돕는 방법 중 올바른 것은?', '["눈은 바깥에서 안쪽으로 닦는다.", "몸의 중심부에서 말초 부위로 닦는다.", "복부는 배꼽을 중심으로 시계방향으로 닦는다.", "목욕 후 등마사지는 삼간다.", "목욕을 마친 후 식사를 하게 한다."]'::jsonb, 3, '올바른 침상 목욕 방법을 이해하고 실천할 수 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "눈은 바깥에서 안쪽으로 닦는다. - 고르지 않은 방법입니다. 눈은 안쪽에서 바깥쪽으로 닦아야 합니다.\n[정답]", "2": "몸의 중심부에서 말초 부위로 닦는다. - 최적의 방법이 아닙니다. 말초 부위에서 중심으로 닦는 것이 권장됩니다.", "3": "복부는 배꼽을 중심으로 시계방향으로 닦는다. - 올바른 방법입니다.", "4": "목욕 후 등마사지는 삼간다. - 권장되지 않는 방법입니다. 보통 마사지는 좋습니다.", "5": "목욕을 마친 후 식사를 하게 한다. - 맞지 않는 방법입니다. 식사는 목욕 전후로 주의해야 합니다."}'::jsonb, '[{"term_ko": "침상 목욕", "term_vi": "Tắm trên giường", "def_ko": "침대에서 하는 목욕", "def_vi": "Tắm cho bệnh nhân nằm trên giường"}, {"term_ko": "올바른", "term_vi": "Đúng", "def_ko": "정확한", "def_vi": "Chính xác"}, {"term_ko": "복부", "term_vi": "Bụng", "def_ko": "배", "def_vi": "Phần bụng"}, {"term_ko": "배꼽", "term_vi": "Rốn", "def_ko": "배꼽", "def_vi": "Rốn"}, {"term_ko": "시계방향", "term_vi": "Chiều kim đồng hồ", "def_ko": "시계 방향", "def_vi": "Hướng kim đồng hồ"}, {"term_ko": "등마사지", "term_vi": "Massage lưng", "def_ko": "등 마사지", "def_vi": "Xoa bóp lưng"}, {"term_ko": "식사", "term_vi": "Ăn uống", "def_ko": "음식을 먹다", "def_vi": "Ăn uống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1352, '10', '여성 대상자의 침상 목욕 돕기로 옳은 것은?', '["유방은 원을 그리듯이 닦는다.", "어깨에서 손목 쪽으로 닦는다.", "허벅지에서 발끝 쪽으로 닦는다.", "옆으로 눕게 하여 둔부에서 목 뒤까지 닦는다.", "회음부는 항문에서 요도 방향으로 닦는다."]'::jsonb, 1, '여성 대상자의 침상 목욕 시 올바른 방법을 알고 있는지를 평가하기 위해 출제되었습니다.', NULL, '{"1": "유방은 원을 그리듯이 닦는다. 이 방법은 적절한 방법입니다. [정답]", "2": "어깨에서 손목 쪽으로 닦는다. 이는 일반적으로 올바른 방법이지만, 유방 세정에는 적합하지 않습니다.", "3": "허벅지에서 발끝 쪽으로 닦는다. 일반적인 세정법이지만 여성 대상자에게는 비위생적일 수 있습니다.", "4": "옆으로 눕게 하여 둔부에서 목 뒤까지 닦는다. 이 방법은 올바르지 않습니다. 둔부는 직접적으로 세정하여야 합니다.", "5": "회음부는 항문에서 요도 방향으로 닦는다. 이 방법은 잘못된 방법입니다. 회음부 세정은 요도에서 항문 방향으로 닦아야 합니다."}'::jsonb, '[{"term_ko": "여성 대상자", "term_vi": "Người nữ", "def_ko": "여성 환자", "def_vi": "Bệnh nhân nữ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1351, '10', '침상 목욕을 돕는 방법으로 옳은 것은?', '["얼굴은 입 주위부터 닦는다.", "유방은 위에서 아래로 닦는다.", "양쪽 상지는 손목 쪽에서 팔 쪽으로 닦는다.", "다리는 허벅지에서 발끝으로 닦는다.", "복부는 배꼽을 중심으로 시계 반대방향으로 닦는다."]'::jsonb, 3, '침상 목욕을 하는 방법에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "얼굴은 입 주위부터 닦는 것이 아니라, 코에서 귀쪽으로 닦아야 합니다.\n[정답]", "3": "양쪽 상지는 손목 쪽에서 팔 쪽으로 닦는 것이 올바른 방법입니다.", "2": "유방은 위에서 아래로 닦지 않고, 아래에서 위로 닦아야 합니다.", "4": "다리는 허벅지에서 발끝으로 닦는 것이 맞습니다.", "5": "복부는 배꼽을 중심으로 시계 방향으로 닦아야 합니다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường ngủ", "def_ko": "침대에서 누워 있는 상태", "def_vi": "trạng thái nằm trên giường"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 씻는 행위", "def_vi": "hành động rửa cơ thể"}, {"term_ko": "유방", "term_vi": "Ngực", "def_ko": "여성의 가슴", "def_vi": "ngực của phụ nữ"}, {"term_ko": "복부", "term_vi": "Bụng", "def_ko": "배 부분", "def_vi": "phần bụng"}, {"term_ko": "시계 반대방향", "term_vi": "Ngược chiều kim đồng hồ", "def_ko": "시계와 반대 방향", "def_vi": "ngược chiều của kim đồng hồ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1350, '10', '대상자의 통 목욕을 돕는 방법으로 옳은 것은?', '["물의 온도는 18~20도로 맞춘다.", "목욕 직전 따뜻한 우유나 차를 마시도록 한다.", "목욕 중 창문을 열어 수증기를 없앤다.", "몸통 - 팔 - 다리 - 회음부 순서로 닦아낸다.", "목욕 후 오일 등 피부유연제를 발라준다."]'::jsonb, 5, '대상자의 통 목욕을 돕는 올바른 방법을 이해하고 있는지를 평가하고자 함.', NULL, '{"1": "물의 온도는 개인의 피부 상태 및 환경에 따라 다를 수 있으므로, 36도 이상으로 맞추는 것이 일반적이다.\n[정답]", "5": "목욕 후 오일 등 피부유연제를 사용하여 피부를 보호하고 보습하는 것이 중요하다.", "2": "따뜻한 음료를 마시는 것은 도움이 될 수 있지만 필수는 아니다.", "3": "목욕 중에 창문을 열면 오히려 체온 저하가 우려되므로 바람이 차가운 경우에는 하지 않는 것이 좋다.", "4": "목욕 시 세척 순서는 다소 다를 수 있으며, 일반적으로 몸통부터 시작하는 것이 좋다."}'::jsonb, '[{"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "목욕(한국어)", "def_vi": "Tắm(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1349, '10', '편마비 대상자의 통목욕을 돕는 방법으로 옳은 것은?', '["건강한 쪽 겨드랑이를 잡고 욕조로 이동시킨다.", "마비된 쪽 다리부터 욕조에 들어가게 한다.", "말초에서 중심 방향으로 닦아 준다.", "마비된 쪽 손으로 안전손잡이를 잡게 한다.", "욕조에서 머리를 감긴 후 밖으로 나오게 한다."]'::jsonb, 3, '편마비 대상자의 통목욕 시 안전하고 효율적인 방법을 이해하고 선택하도록 하기 위함입니다.', NULL, '{"1": "건강한 쪽 겨드랑이를 잡고 욕조로 이동시킨다. (잘못된 방법입니다, 통목욕 시 안전을 위해서는 마비된 쪽이 아닌 안전한 쪽을 잡는 것이 좋습니다.)\n[정답]", "2": "마비된 쪽 다리부터 욕조에 들어가게 한다. (오류입니다, 먼저 건강한 쪽 다리를 넣는 것이 안전합니다.)", "3": "말초에서 중심 방향으로 닦아 준다. (정확한 방법으로, 원활한 혈류를 유지하게 도와줍니다.)", "4": "마비된 쪽 손으로 안전손잡이를 잡게 한다. (잘못된 방법입니다, 마비된 쪽 손의 힘이 약할 수 있어 안전하지 않습니다.)", "5": "욕조에서 머리를 감긴 후 밖으로 나오게 한다. (위험할 수 있는 방법이며, 일반적으로 욕조에 들어가기 전에 머리를 감기는 것이 바람직합니다.)"}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽이 마비된 상태", "def_vi": "Tình trạng bị liệt một bên"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1348, '10', '편마비 대상자의 통목욕을 돕는 방법으로 옳은 것은?', '["실내 온도를 30~40도로 맞춘다.", "혈압이 높으면 물의 온도를 뜨겁게 한다.", "요양보호사의 발끝으로 물의 온도를 확인한다.", "욕조 턱 높이와 목욕의자 높이를 같게 맞춘다.", "목욕 후 선 채로 옷을 입힌다."]'::jsonb, 4, '편마비 대상자를 안전하게 통목욕시키기 위한 올바른 방법을 이해하는 것이다.', NULL, '{"1": "실내 온도를 30~40도로 맞추는 것은 저온으로 인한 체온 감소를 조절하기 위한 것이지만, 적정 온도는 상황에 따라 다를 수 있다.\n[정답]", "4": "욕조 턱 높이와 목욕의자 높이를 같게 맞추면 대상자가 안전하게 목욕할 수 있다.", "2": "혈압이 높으면 물의 온도를 뜨겁게 하는 것은 위험할 수 있다.", "3": "요양보호사의 발끝으로 물의 온도를 확인하는 것은 안전한 방법이 아니다.", "5": "목욕 후 선 채로 옷을 입히는 것은 넘어질 위험이 있어 바람직하지 않다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa", "def_ko": "한쪽 신체가 마비된 상태", "def_vi": "Tình trạng liệt một bên cơ thể"}, {"term_ko": "통목욕", "term_vi": "Tắm toàn thân", "def_ko": "전신 목욕", "def_vi": "Tắm cho toàn bộ cơ thể"}, {"term_ko": "욕조", "term_vi": "Bồn tắm", "def_ko": "목욕을 위한 큰 용기", "def_vi": "Thiết bị lớn dùng để tắm"}, {"term_ko": "턱", "term_vi": "Bậc", "def_ko": "높이", "def_vi": "Chiều cao"}, {"term_ko": "높이", "term_vi": "Chiều cao", "def_ko": "높음", "def_vi": "Độ cao"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1347, '10', '오른쪽 편마비 대상자가 통목욕을 할 때 돕는 방법은?', '["식사 직전이나 직후에 실시한다.", "욕실로 이동 시에는 왼쪽을 지지한다.", "욕조 안에 미끄럼방지 매트를 깔아둔다.", "욕조에 30분 정도 담그게 한다.", "욕조의 중앙에 중심을 잡고 앉게 한다."]'::jsonb, 3, '편마비 대상자의 안전한 목욕 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "식사 직전이나 직후에 목욕을 실시하는 것은 피해야 합니다.\n[정답]", "2": "욕실로 이동할 때 왼쪽을 지지해야 안전합니다.", "3": "욕조 안에 미끄럼방지 매트를 깔아두는 것은 안전을 위한 필수 사항입니다.", "4": "욕조에 30분 동안 담그는 것은 장시간 노출에 대한 위험이 있습니다.", "5": "욕조의 중앙에 중심을 잡고 앉게 하는 것은 균형 유지에 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한 쪽 몸이 마비된 상태", "def_vi": "Trạng thái bị yếu một bên cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1346, '10', '편마비 대상자의 통 목욕 시 욕조에 들어가고 나가는 방법으로 옳은 것은?', '["건강한 쪽으로 먼저 들어가고 마비된 쪽으로 먼저 나온다.", "마비된 쪽으로 먼저 들어가고 건강한 쪽으로 먼저 나온다.", "건강한 쪽으로 먼저 들어가고 건강한 쪽으로 먼저 나온다.", "마비된 쪽으로 먼저 들어가고 마비된 쪽으로 먼저 나온다.", "어느 쪽이든 상관없다."]'::jsonb, 3, '편마비 환자의 안전한 목욕 방법에 대해 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "건강한 쪽으로 먼저 들어가고 마비된 쪽으로 먼저 나온다. : 잘못된 방법입니다. 이렇게 할 경우 마비된 쪽으로 나올 때 낙상의 위험이 있습니다.\n[정답]", "2": "마비된 쪽으로 먼저 들어가고 건강한 쪽으로 먼저 나온다. : 잘못된 방법입니다. 마비된 쪽으로 먼저 들어가는 것은 불안정합니다.", "3": "건강한 쪽으로 먼저 들어가고 건강한 쪽으로 먼저 나온다. : 올바른 방법입니다. 안전성을 최우선으로 고려한 접근입니다.", "4": "마비된 쪽으로 먼저 들어가고 마비된 쪽으로 먼저 나온다. : 잘못된 방법입니다. 이는 환자를 불안정하게 할 수 있습니다.", "5": "어느 쪽이든 상관없다. : 잘못된 접근입니다. 안전을 고려해야 합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bại liệt nửa người", "def_ko": "한쪽 몸이 마비된 상태", "def_vi": "Tình trạng liệt một bên cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1345, '10', '통 목욕 시 욕조에 들어가기 전에 씻기는 순서로 옳은 것은?', '["팔 - 몸통 - 회음부 - 다리", "팔 - 몸통 - 다리 - 회음부", "회음부 - 다리 - 팔 - 몸통", "다리 - 회음부 - 팔 - 몸통", "다리 - 팔 - 몸통 - 회음부"]'::jsonb, 5, '욕조에서 통 목욕을 할 때 올바른 씻는 순서를 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "팔, 몸통, 회음부, 다리 순서로 씻는 것은 일반적인 순서가 아닙니다.", "2": "팔, 몸통, 다리, 회음부 순서도 비효율적입니다.", "3": "회음부를 가장 먼저 씻는 것은 hygiene 관점에서 바람직하지 않습니다.", "4": "다리, 회음부, 팔, 몸통 순서 또한 일반적이지 않습니다.\n[정답]", "5": "다리, 팔, 몸통, 회음부 순서가 올바른 씻는 순서입니다. 다리부터 시작해 상반신으로 이동하고 마지막에 회음부를 씻어야 위생적입니다."}'::jsonb, '[{"term_ko": "욕조", "term_vi": "Bồn tắm", "def_ko": "목욕용 수조", "def_vi": "Bồn chứa nước để tắm"}, {"term_ko": "씻다", "term_vi": "Rửa", "def_ko": "깨끗하게 하다", "def_vi": "làm sạch"}, {"term_ko": "회음부", "term_vi": "Vùng kín", "def_ko": "생식기와 항문 사이의 부위", "def_vi": "Vùng giữa cơ quan sinh dục và hậu môn"}, {"term_ko": "다리", "term_vi": "Chân", "def_ko": "인간의 하체 부분", "def_vi": "Phần dưới cơ thể của con người"}, {"term_ko": "팔", "term_vi": "Tay", "def_ko": "인간의 상체 부분", "def_vi": "Phần trên cơ thể của con người"}, {"term_ko": "몸통", "term_vi": "Thân", "def_ko": "신체의 중심 부분", "def_vi": "Phần trung tâm của cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1344, '10', '대상자의 통목욕을 돕는 방법으로 옳은 것은?', '["욕조물에 30분 정도 담근 후 씻긴다.", "목욕물의 온도는 22~26도를 유지한다.", "욕조에 들어가기 전에 목욕의자에 앉혀 머리를 감긴다.", "체온이 유지되도록 몸에 따뜻한 물을 자주 뿌려준다.", "혈액순환을 위해 몸의 중심에서 말초 방향으로 닦는다."]'::jsonb, 4, '대상자의 통목욕을 안전하고 효과적으로 돕는 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "욕조물에 30분 정도 담근 후 씻기는 것은 과다한 수압과 체온 저하를 초래할 수 있습니다.\n[정답]", "4": "체온이 유지되도록 몸에 따뜻한 물을 자주 뿌려주는 것이 중요합니다.", "2": "목욕물의 온도는 22~26도는 너무 낮아도 체온 저하의 위험이 있습니다.", "3": "욕조에 들어가기 전에 목욕의자에 앉혀 머리를 감기는 것은 위생 문제로 바람직하지 않습니다.", "5": "혈액순환을 위해 몸의 중심에서 말초 방향으로 닦는 것은 잘못된 방법입니다."}'::jsonb, '[{"term_ko": "통목욕", "term_vi": "Tắm toàn thân", "def_ko": "전신을 목욕하는 것", "def_vi": "Tắm cho toàn bộ cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1343, '10', '목욕 돕기 방법으로 옳은 것은?', '["기분이 불쾌하거나 피로할 때 목욕을 한다.", "욕실에 손잡이를 붙인다.", "목욕은 1시간 이상 여유있게 한다.", "목욕 중에는 말을 걸지 않는다.", "식사 직전에 목욕을 한다."]'::jsonb, 2, '목욕을 도울 때의 올바른 방법을 이해하고 적용하는지를 확인하기 위한 문제입니다.', NULL, '{"1": "기분이 좋지 않거나 피로할 때는 목욕을 피하는 것이 좋습니다.\n[정답]", "2": "욕실에 손잡이를 설치하는 것은 안전성을 높이는 좋은 방법입니다.", "3": "목욕은 편안한 시간을 위해 여유있게 진행해야 하지만 1시간 이상 계속할 필요는 없습니다.", "4": "목욕 중에 이용자의 안정을 위해 대화를 자제하는 것이 좋습니다.", "5": "식사 직전에 목욕을 하는 것은 소화에 좋지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "목욕(한국어)", "def_vi": "Tắm(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1342, '10', '대상자의 목욕 돕기 방법으로 옳은 것은?', '["목욕 전에 대, 소변을 보게 한다.", "욕실 문을 열어 놓는다.", "심장에서 가까운 곳부터 물이 닿도록 한다.", "목욕을 거부하는 치매 대상자는 강제로 목욕을 시킨다.", "안전사고 예방을 위해 대상자를 전적으로 돕는다."]'::jsonb, 1, '대상자의 목욕을 어떻게 도와야 하는지에 대한 이해와 안전성을 평가하기 위함입니다.', NULL, '{"1": "목욕 전에 대, 소변을 보게 하는 것은 위생과 안전을 고려한 올바른 방법입니다.\n[정답]", "2": "욕실 문을 열어 놓는 것은 사생활 보호에 대한 배려가 부족합니다.", "3": "심장에서 가까운 곳부터 물이 닿도록 하는 방법은 목욕 시 안전하게 물 온도를 조절하는 데 도움이 됩니다.", "4": "목욕을 거부하는 치매 대상자는 강제로 목욕을 시키는 것은 정신적 스트레스를 유발할 수 있어 바람직하지 않습니다.", "5": "안전사고 예방을 위해 대상자를 전적으로 돕는 것은 대상자의 자율성을 해칠 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1341, '10', '대상자의 면도를 도울 때 피부손상을 예방하는 방법은?', '["수염이 자란 반대 방향으로 면도한다.", "면도크림은 수염이 난 방향으로 바른다.", "짧게 나누어 일정한 속도로 면도한다.", "면도할 부위의 거품을 깨끗이 씻어낸 후 면도한다.", "수염의 강도가 강한 부위에서 약한 부위의 순으로 면도한다."]'::jsonb, 3, '대상자의 면도를 안전하고 효율적으로 도와주기 위한 피부손상 예방 방법을 평가하는 것이다.', NULL, '{"1": "면도 방향이 중요하지만, 수염이 자란 반대 방향으로 면도할 경우 피부가 면도기와 닿을 때 자극을 받을 수 있다.\n[정답]", "3": "면도를 짧게 나누어 일정한 속도로 하는 것이 피부 손상을 예방하는 데 효과적이다.", "2": "면도크림은 수염 방향에 따라 바르지만 이에 따른 피부손상 예방 효과는 제한적이다.", "4": "면도 후 거품을 깨끗이 씻어내는 것이 아니라, 면도 전과 후에 모두 깨끗하게 씻어내야 한다.", "5": "수염의 강도가 강한 부위에서 약한 부위로 면도하는 것은 오히려 피부 자극을 증가시킬 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người dùng", "def_ko": "환자 또는 서비스 이용자", "def_vi": "Bệnh nhân hoặc người sử dụng dịch vụ"}, {"term_ko": "면도", "term_vi": "Cạo râu", "def_ko": "수염을 깎는 행위", "def_vi": "Hành động cạo tóc trên mặt"}, {"term_ko": "피부손상", "term_vi": "Tổn thương da", "def_ko": "피부에 발생하는 손상", "def_vi": "Tổn thương xảy ra trên da"}, {"term_ko": "면도크림", "term_vi": "Kem cạo", "def_ko": "면도 전 피부에 바르는 크림", "def_vi": "Kem bôi lên da trước khi cạo"}, {"term_ko": "거품", "term_vi": "Bọt", "def_ko": "면도크림이 발라진 후 생기는 기포", "def_vi": "Bọt hình thành sau khi thoa kem cạo"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1340, '10', '대상자에게 면도 돕기를 할 때 옳은 것은?', '["침상에 반듯하게 누운 상태로 면도한다.", "주름진 피부는 위로 잡아당겨 면도한다.", "면도 전 따뜻한 물수건으로 덮어 건조함을 완화한다.", "면도날은 얼굴피부와 90도 정도의 각도를 유지한다.", "전기면도기 사용을 피한다."]'::jsonb, 3, '대상자에게 면도 시 올바른 방법을 이해하고 있는지를 평가하기 위한 문제이다.', NULL, '{"1": "침상에 반듯하게 누운 상태로 면도하는 것은 올바르지 않다. 대상자는 편안하게 있는 것이 중요하다.", "2": "주름진 피부를 위로 잡아당겨 면도하는 것은 피부를 상하게 할 수 있으므로 주의해야 한다.\n[정답]", "3": "면도 전 따뜻한 물수건으로 덮어 건조함을 완화하는 것은 피부 건강에 좋다.", "4": "면도날은 얼굴 피부와 90도 정도의 각도를 유지하는 것은 위험할 수 있다. 각도를 조절해야 한다.", "5": "전기면도기 사용을 피하는 것은 잘못된 정보이다. 전기면도기를 사용할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1339, '10', '대사자의 세수를 돕는 방법으로 옳은 것은?', '["침대를 수평으로 하여 눕힌다.", "귓바퀴와 귀의 뒷면은 닦지 않는다.", "숸에 비누를 묻혀 눈 주변을 닦는다.", "비염 예방을 위해 코 안쪽 코털도 모두 깎아준다.", "안경은 하루에 한 번 이상 깨끗하게 닦는다."]'::jsonb, 5, '대사자의 세수를 돕는 올바른 방법에 대한 이해를 평가하고자 함.', NULL, '{"1": "침대를 수평으로 하여 눕힌다: 대사자의 편안한 세수를 돕기 위해서 필요한 조치이나 세수 도우미와 관련이 뚜렷하지 않다.", "2": "귓바퀴와 귀의 뒷면은 닦지 않는다: 위생 관점에서 잘못된 정보로, 세수 시 귀 주변도 닦아야 한다.", "3": "숸에 비누를 묻혀 눈 주변을 닦는다: 눈 주위는 민감하기 때문에 비누를 직접 사용해선 안 된다.\n[정답]", "4": "비염 예방을 위해 코 안쪽 코털도 모두 깎아준다: 코 안쪽 코털을 깎는 것은 위생에 좋지만 해당 문장은 세수와 직접적 관련이 없다.", "5": "안경은 하루에 한 번 이상 깨끗하게 닦는다: 세수와 관련된 위생 관리의 중요한 요소로 올바른 지침이다."}'::jsonb, '[{"term_ko": "대사자", "term_vi": "Người hỗ trợ", "def_ko": "환자를 도와주는 사람", "def_vi": "Người giúp người bệnh"}, {"term_ko": "세수", "term_vi": "Rửa mặt", "def_ko": "얼굴을 씻는 행위", "def_vi": "Hành động rửa mặt"}, {"term_ko": "귓바퀴", "term_vi": "Vành tai", "def_ko": "귀의 바깥 부분", "def_vi": "Phần bên ngoài của tai"}, {"term_ko": "비염", "term_vi": "Viêm mũi", "def_ko": "코의 염증", "def_vi": "Viêm của mũi"}, {"term_ko": "안경", "term_vi": "Kính", "def_ko": "시력을 보조하는 기구", "def_vi": "Thiết bị hỗ trợ thị lực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1338, '10', '대상자의 세수를 돕는 방법으로 옳은 것은?', '["눈썹은 면도칼로 다듬어 준다.", "면봉으로 귀 안쪽의 귀지를 닦아낸다.", "코 안과 코 볼, 둘레를 세심히 닦는다.", "입술과 그 주변을 알코올 솜으로 닦는다.", "사용한 수건의 면으로 양쪽 눈을 번갈아 가며 닦는다."]'::jsonb, 3, '대상자의 세수를 돕는 방법에 대해 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "눈썹은 면도칼로 다듬어 주지 않아야 한다. 면도칼은 안전하지 않다.\n[정답]", "3": "코 안과 코 볼, 둘레를 세심히 닦아주는 것이 올바른 방법이다.", "2": "면봉으로 귀 안쪽을 다루는 것은 위험할 수 있다.", "4": "입술과 그 주변은 알코올 솜으로 닦지 않고 부드러운 천으로 닦아야 한다.", "5": "사용한 수건의 면으로 양쪽 눈을 번갈아 가며 닦는 것은 위생적으로 좋지 않다."}'::jsonb, '[{"term_ko": "세수", "term_vi": "Tắm rửa", "def_ko": "얼굴을 씻다(세 mặt)", "def_vi": "Rửa mặt"}, {"term_ko": "눈썹", "term_vi": "Lông mày", "def_ko": "눈의 털", "def_vi": "Lông trên mắt"}, {"term_ko": "면도칼", "term_vi": "Dao cạo", "def_ko": "면도를 하는 도구", "def_vi": "Dụng cụ cạo"}, {"term_ko": "귀지", "term_vi": "Ráy tai", "def_ko": "귀 안의 오염물질", "def_vi": "Vật bẩn trong tai"}, {"term_ko": "입술", "term_vi": "Môi", "def_ko": "입의 부위", "def_vi": "Phần của miệng"}, {"term_ko": "알코올", "term_vi": "Cồn", "def_ko": "소독하는 물질", "def_vi": "Chất khử trùng"}, {"term_ko": "눈", "term_vi": "Mắt", "def_ko": "시각 기관", "def_vi": "Cơ quan thị giác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1337, '10', '침상에 누워있는 대상자의 세수를 돕는 방법으로 옳은 것은?', '["코 안은 알코올 솜으로 닦는다.", "귀 입구와 귓바퀴, 뒷면을 닦는다.", "눈의 바깥쪽에서 안쪽으로 닦는다.", "깊숙한 곳의 귀지는 면봉으로 제거한다.", "이마 - 눈 - 귀 - 코 순으로 닦는다."]'::jsonb, 2, '대상자의 세수를 돕는 방법에 대한 올바른 절차를 이해하고 있는지를 점검하기 위함이다.', NULL, '{"1": "코 안은 알코올 솜으로 닦는다. (코 안을 알코올로 닦는 것은 피부 자극과 감염 위험이 있으므로 부적절하다.)\n[정답]", "2": "귀 입구와 귓바퀴, 뒷면을 닦는다. (귀를 청결히 유지하는 것은 중요하며, 이 방법이 올바르다.)", "3": "눈의 바깥쪽에서 안쪽으로 닦는다. (눈은 바깥쪽에서 안쪽으로 닦는 것이 좋지만, 이 문제가 묻는 세수의 내용과는 다소 다르다.)", "4": "깊숙한 곳의 귀지는 면봉으로 제거한다. (귀지를 깊숙히 제거하는 것은 오히려 귀를 손상시킬 수 있다.)", "5": "이마 - 눈 - 귀 - 코 순으로 닦는다. (세수의 절차로는 다소 부적절하다.)"}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "Giường"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "세수", "term_vi": "Rửa mặt", "def_ko": "얼굴을 씻는 것(한국어)", "def_vi": "Rửa mặt"}, {"term_ko": "귓바퀴", "term_vi": "Sụn tai", "def_ko": "귀의 일부분(한국어)", "def_vi": "Phần sụn của tai"}, {"term_ko": "귀", "term_vi": "Tai", "def_ko": "귀(한국어)", "def_vi": "Tai"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1336, '10', '남성 대상자의 회음부를 청결하게 하는 방법은?', '["둔부 밑에 변기를 넣은 다음 아래에 방수포를 깐다.", "차가운 물을 음부에 끼얹은 다음 비누로 닦는다.", "음경을 수건으로 잡고 피부가 겹치는 부분과 음낭의 뒷면을 닦는다.", "변기를 빼낸 후 둔부에 남아 있는 물기를 젖은 수건으로 닦아낸다.", "목욕담요를 마름모꼴로 펴서 대상자의 무릎 아래를 덮는다."]'::jsonb, 3, '남성 대상자의 회음부 청결 관리 방법에 대한 이해를 확인하기 위한 문제입니다.', NULL, '{"1": "둔부 아래에 변기를 두고 방수포를 깐다면 오히려 청결 유지에 방해가 될 수 있습니다.\n[정답]", "3": "음경을 수건으로 잡고 피부가 겹치는 부분과 음낭의 뒷면을 닦는 방법이 가장 적절합니다.", "2": "차가운 물을 음부에 끼얹는 것은 피부에 불쾌감을 줄 수 있으며, 비누를 사용하기 전에 이렇게 하는 것은 좋지 않습니다.", "4": "변기를 빼낸 후 둔부에 남아 있는 물기를 닦는 것은 청결을 유지하는 방법이지만, 음부 청결 관리의 주체가 아닙니다.", "5": "목욕담요를 마름모꼴로 펴는 것은 개별적인 청결과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": "Vùng bìu", "def_ko": "생식기와 항문 사이의 부위(한국어)", "def_vi": "Đoạn giữa bộ phận sinh dục và hậu môn"}, {"term_ko": "변기", "term_vi": "Nồi tiểu", "def_ko": "소변을 보는 용기(한국어)", "def_vi": "Chậu đi tiểu"}, {"term_ko": "비누", "term_vi": "Xà phòng", "def_ko": "세척제(한국어)", "def_vi": "Chất tẩy rửa"}, {"term_ko": "음경", "term_vi": "Dương vật", "def_ko": "남성의 성기(한국어)", "def_vi": "Bộ phận sinh dục nam"}, {"term_ko": "음낭", "term_vi": "Bìu", "def_ko": "남성의 성기를 보호하는 주머니 모양의 피부(한국어)", "def_vi": "Túi da bảo vệ dương vật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1335, '10', '회음부 청결을 돕는 방법으로 옳은 것은?', '["작업공간의 확보를 위해 스크린을 치지 않는다.", "회음부에 염증이 있으면 연고를 발라준다.", "따뜻한 물을 음부에 끼얹는 다음 비눗물을 묻힌다.", "물수건으로 뒤쪽에서 앞쪽으로 닦는다.", "청결을 위해 처음부터 끝까지 요양보호사가 닦아준다."]'::jsonb, 3, '회음부 청결 관리에 대한 이해도를 평가하고, 올바른 방법을 선택할 수 있는 능력을 확인하고자 함.', NULL, '{"1": "스크린을 치지 않으면 개인의 사생활 보호에 문제가 생길 수 있다. 따라서 잘못된 방법이다.\n[정답]", "2": "염증이 있을 경우 연고 사용은 추천되지 않으며, 의료인의 처방이 필요하다.", "3": "따뜻한 물을 음부에 끼얹은 다음 비눗물을 묻힌다. 이는 올바른 청결 방법이다.", "4": "물수건으로 닦을 때는 앞에서 뒤쪽으로 닦아야 하며, 반대는 잘못된 방법이다.", "5": "청결을 위해 요양보호사가 처음부터 끝까지 닦아주는 것은 환자의 자율성을 침해할 수 있다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": "Perineum", "def_ko": "인체의 생식기와 항문 사이의 부위", "def_vi": "Vùng giữa cơ quan sinh dục và hậu môn"}, {"term_ko": "비눗물", "term_vi": "Nước xà phòng", "def_ko": "비누와 물이 섞인 것", "def_vi": "Hỗn hợp giữa xà phòng và nước"}, {"term_ko": "청결", "term_vi": "Vệ sinh", "def_ko": "더러움이 없는 상태", "def_vi": "Trạng thái không có bụi bẩn"}, {"term_ko": "자율성", "term_vi": "Quyền tự chủ", "def_ko": "스스로 결정할 수 있는 능력", "def_vi": "Khả năng tự quyết định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1334, '10', '여성 대상자의 회음부를 청결하게 하는 방법으로 옳은 것은?', '["침대 머리를 높인 상태에서 돕는다.", "소독제로 손을 닦은 후 멸균장갑을 착용한다.", "누워서 다리를 쭉 편 상태에서 닦는다.", "목욕담요를 마름모꼴로 펴서 아랫단 가운데 부분으로 회음부를 덮어준다.", "회음부에 분비물이 있으면 좌욕을 하게 한다."]'::jsonb, 4, '여성 대상자의 회음부 청결 관리 방법을 이해하고 정확하게 적용할 수 있는지를 평가하고자 함.', NULL, '{"1": "침대 머리를 높인 상태에서 돕는 것은 회음부 청결과 직접적인 관련이 없다.\n[정답]", "4": "목욕담요를 마름모꼴로 펴서 아랫단 가운데 부분으로 회음부를 덮어주면 청결 유지에 도움이 된다.", "3": "누워서 다리를 쭉 편 상태에서 닦는 것은 적절한 자세이나, 청결 방법으로는 부족하다.", "2": "소독제로 손을 닦은 후 멸균장갑을 착용하는 것은 기본적인 위생 절차이나, 회음부 청결 방법 자체가 아니다.", "5": "회음부에 분비물이 있을 경우 좌욕은 도움이 되지만, 기본적인 청결 방법으로는 회음부를 덮는 방법이 더 맞다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": "Âm hộ", "def_ko": "여성 생식기의 하부 부분", "def_vi": "Phần dưới của cơ quan sinh dục nữ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1333, '10', '회음부 청결을 위해 닦아주는 순서로 옳은 것은?', '["요도 - 질- 항문", "질 - 요도 - 항문", "질 - 항문 - 요도", "항문 - 요도 - 질", "항문 - 질 - 요도"]'::jsonb, 1, '회음부 청결 유지에 대한 올바른 절차를 확인하기 위한 문제입니다.', NULL, '{"1": "요도 - 질 - 항문 순서가 청결을 유지하기에 적절합니다.", "2": "질 - 요도 - 항문은 순서가 잘못되었습니다.", "3": "질 - 항문 - 요도 또한 청결 유지에 부적절한 순서입니다.", "4": "항문 - 요도 - 질은 청결을 해칠 위험이 큽니다.", "5": "항문 - 질 - 요도도 순서적으로 올바르지 않습니다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": "Vùng hậu môn sinh dục", "def_ko": "생식기와 항문 사이의 부위", "def_vi": "Khu vực giữa cơ quan sinh dục và hậu môn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1332, '10', '여성 대상자의 회음부 청결을 통해 예방할 수 있는 질환은?', '["자궁암", "치질", "요실금", "요로감염", "매독"]'::jsonb, 4, '여성 대상자의 회음부 청결이 질병 예방에 미치는 영향을 질문하는 문제입니다.', NULL, '{"1": "자궁암은 회음부 청결과 직접적인 관련이 없습니다.\n[정답]", "4": "요로감염은 회음부 청결을 통해 효과적으로 예방할 수 있습니다.", "2": "치질은 회음부와는 관련성 있지만, 청결로 예방되지는 않습니다.", "3": "요실금은 근육과 관련된 문제로 청결이 예방에 큰 영향을 미치지 않습니다.", "5": "매독은 성병으로, 청결과 직접적인 연관이 없습니다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": "Perineum", "def_ko": "여성의 생식기와 항문 사이의 부위", "def_vi": "Vùng giữa cơ quan sinh dục nữ và hậu môn"}, {"term_ko": "청결", "term_vi": "Vệ sinh", "def_ko": "깨끗하게 하는 것", "def_vi": "Làm sạch"}, {"term_ko": "요로감염", "term_vi": "Nhiễm trùng đường tiết niệu", "def_ko": "소변이 감염되는 것", "def_vi": "Nhiễm trùng trong đường tiết niệu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1331, '10', '대상자가 부끄럽다며 회음부 씻는 것을 거부할 때 대처방법은?', '["대상자가 요청할 때까지 기다린다.", "보호자에게 연락하여 도움을 요청한다.", "청결을 위해 본인 의사와 관계없이 씻긴다.", "전용 물수건을 제공하여 스스로 씻을 수 있게 한다.", "대상자를 존중하여 거부 의사를 받아드린다."]'::jsonb, 4, '대상자의 부끄러움과 개인적인 경계를 존중하며 적절한 대처 방법을 찾는 것을 이끌어내기 위한 문제입니다.', NULL, '{"1": "대상자의 요청을 기다리는 것은 수동적인 대처로, 청결 문제 해결에 효과적이지 않습니다.\n[정답]", "4": "전용 물수건을 제공하여 스스로 씻을 수 있게 하는 방법은 대상자의 자율성을 존중하면서 청결을 유지할 수 있는 좋은 방법입니다.", "2": "보호자에게 도움을 요청하는 것은 상황에 따라 유용할 수 있으나, 대상자의 의사를 존중해야 합니다.", "3": "본인 의사와 관계없이 씻기는 것은 대상자의 동의를 무시하는 행동으로 바람직하지 않습니다.", "5": "거부 의사를 받아들이는 것 또한 중요하지만, 청결을 유지하는 방법을 제시해야 할 필요가 있습니다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": null, "def_ko": "신체의 생식 기관과 항문 사이의 부분", "def_vi": null}, {"term_ko": "부끄럽다", "term_vi": null, "def_ko": "쑥쓰럽거나 수치스러운 느낌", "def_vi": null}, {"term_ko": "청결", "term_vi": null, "def_ko": "깨끗함", "def_vi": null}, {"term_ko": "자율성", "term_vi": null, "def_ko": "스스로 선택할 권리", "def_vi": null}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1330, '10', '대상자의 발톱이 살 안쪽으로 심하게 파고들어 상처가 났을 경우 대처방법은?', '["온찜질을 해준다.", "간호사에게 보고한다.", "발톱을 짧게 잘라준다.", "붕대로 발톱을 감싸준다.", "발톱을 둥글게 잘라준다."]'::jsonb, 2, '대상자의 발톱 문제에 대한 적절한 대처 방법을 묻는 문제입니다.', NULL, '{"1": "온찜질은 발톱 문제에 도움이 되지 않습니다.\n[정답]", "2": "간호사에게 보고하는 것이 중요합니다.", "3": "발톱을 짧게 자르는 것은 위험할 수 있습니다.", "4": "붕대로 감싸는 것은 상처에 대한 올바른 대처가 아닙니다.", "5": "발톱을 둥글게 자르는 방법은 권장되지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "치료를 받는 사람", "def_vi": "Người nhận điều trị"}, {"term_ko": "발톱", "term_vi": "Móng chân", "def_ko": "손가락의 끝에 있는 굳은 부분", "def_vi": "Phần cứng ở đầu ngón tay"}, {"term_ko": "상처", "term_vi": "Vết thương", "def_ko": "피부에 난 손상", "def_vi": "Tổn thương trên da"}, {"term_ko": "간호사", "term_vi": "Y tá", "def_ko": "환자의 건강을 돌보는 전문인", "def_vi": "Người chăm sóc sức khỏe cho bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1329, '10', '대상자 발의 청결을 돕는 방법으로 옳은 것은?', '["가능하면 대상자를 앉힌다.", "발가락 사이를 알코올로 닦는다.", "발을 씻기 전에 발톱을 자른다.", "무좀이 있는 발은 젖은 수건으로 감싸둔다.", "살 안쪽으로 심하게 파고든 발톱은 잘라낸다."]'::jsonb, 1, '대상자의 발의 청결을 유지하는 올바른 방법을 묻는 문제입니다.', NULL, '{"1": "가능하면 대상자를 앉힌다. 대상자의 안정성을 높이고 청결을 돕기 위한 기본적인 행동입니다.\n[정답]", "2": "발가락 사이를 알코올로 닦는다. 발가락 사이를 청결하게 하기 위해 적절하지 않으며 피부 자극을 줄 수 있습니다.", "3": "발을 씻기 전에 발톱을 자른다. 이 방법은 청결을 위한 올바른 순서지만, 발을 씻기 전에 해야 하는 것은 아닙니다.", "4": "무좀이 있는 발은 젖은 수건으로 감싸둔다. 이는 오히려 상태를 악화시킬 수 있으므로 권장되지 않습니다.", "5": "살 안쪽으로 심하게 파고든 발톱은 잘라낸다. 이는 위험할 수 있으며 전문적인 처치가 필요할 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1328, '10', '대상자의 손과 발을 관리하는 방법으로 옳은 것은?', '["모직으로 된 양말을 신긴다.", "발의 티눈은 손톱깎이로 제거한다.", "따뜻한 물에 손과 발을 10~15분간 담근다.", "두꺼워진 발톱은 식초물에 담갔다가 자른다.", "발콥 주위에 염증이 있을 경우 소독을 해준다."]'::jsonb, 3, '대상자의 손과 발 관리에 대한 올바른 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "모직으로 된 양말은 통기성이 좋지 않아 발에 땀이나 습기가 차서 피부 문제를 일으킬 수 있습니다.\n[정답]", "3": "따뜻한 물에 손과 발을 10~15분간 담그는 것은 혈액순환을 촉진하고 피부를 부드럽게 하여 관리에 적합합니다.", "2": "발의 티눈은 손톱깎이로 제거할 경우 상처를 낼 수 있어 적절하지 않습니다.", "4": "두꺼워진 발톱은 식초물에 담근 후 자르기 보다는 전문적인 도움을 받는 것이 좋습니다.", "5": "발콥 주위에 염증이 있을 경우 소독을 해주는 것은 좋지만, 정확한 치료가 필요해 즉시 전문의를 찾아야 합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "손과 발", "term_vi": "Tay và chân", "def_ko": "손과 발", "def_vi": "Tay và chân"}, {"term_ko": "티눈", "term_vi": "Mắt cá chân", "def_ko": "피부의 굳은살", "def_vi": "Mụn cóc trên da"}, {"term_ko": "소독", "term_vi": "Khử trùng", "def_ko": "감염 예방을 위한 청결 행위", "def_vi": "Hành động làm sạch để ngăn ngừa nhiễm trùng"}, {"term_ko": "혈액순환", "term_vi": "Tuần hoàn máu", "def_ko": "혈액이 몸 속을 흐르는 과정", "def_vi": "Quy trình máu lưu thông trong cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1327, '10', '노인의 피부 건조를 예방하는 방법으로 옳은 것은?', '["수분 섭취량을 줄인다.", "지성용 비누를 사용한다.", "오일이나 로션을 주기적으로 발라준다.", "실내를 따뜻하고 건조하게 한다.", "매일 뜨거운 물로 목욕을 한다."]'::jsonb, 3, '노인의 피부 건조를 예방하기 위해 적절한 방법을 찾는 문제입니다.', NULL, '{"1": "수분 섭취량을 줄이는 것은 피부 건조를 악화시킬 수 있습니다.\n[정답]", "3": "오일이나 로션을 주기적으로 발라주는 것은 피부의 수분을 유지하는 데 도움이 됩니다.", "2": "지성용 비누는 피부를 더욱 건조하게 만들 수 있습니다.", "4": "실내를 따뜻하고 건조하게 하는 것은 피부 건조를 유발할 수 있습니다.", "5": "매일 뜨거운 물로 목욕하는 것은 피부의 기름을 제거하여 건조를 악화시킵니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "고령의 사람", "def_vi": "Người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1326, '10', '침상에 누워 지내는 대상자의 머리를 손질하는 방법으로 옳은 것은?', '["머리카락이 엉켰을 경우 잘라 낸다.", "모발 끝에서 두피 방향을 빗질한다.", "거울을 제공하여 머리 모양을 확인하게 한다.", "탈모 예방을 위해 이틀에 한 번씩 빗질한다.", "요양보호사의 기호에 따라 머리 모양을 정리한다."]'::jsonb, 3, '대상자의 머리를 어떻게 손질해야 하는지를 묻는 문제이다.', NULL, '{"1": "머리카락이 엉켰을 경우 잘라 낸다. 잘라내는 것은 바람직하지 않다.\n[정답]", "2": "모발 끝에서 두피 방향을 빗질한다. 이 방법이 올바른 방법이다.", "3": "거울을 제공하여 머리 모양을 확인하게 한다. 대상자가 스스로 확인할 수 있게 돕는 것은 중요하다.", "4": "탈모 예방을 위해 이틀에 한 번씩 빗질한다. 이는 빈도가 부족하다.", "5": "요양보호사의 기호에 따라 머리 모양을 정리한다. 대상자의 선호를 무시하는 것은 바람직하지 않다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "giường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1325, '10', '대상자의 머리카락이 엉켰을 경우 올바른 손질 방법은?', '["세게 잡아당겨 빗질한다.", "물을 적신 후 큰 빗으로 빗긴다.", "두피세정제를 발라 빗긴다.", "참빗으로 빗어 머리카락을 펴준다.", "가족의 동의를 얻어 엉킨 머리카락을 자른다."]'::jsonb, 2, '대상자의 머리카락 손질 시 올바른 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "머리카락을 세게 잡아당기면 통증을 유발할 수 있어 잘못된 방법입니다.\n[정답]", "2": "물을 적신 후 큰 빗으로 빗는 방법은 엉킨 머리카락을 부드럽게 풀 수 있는 올바른 방법입니다.", "3": "두피세정제를 발라서 빗는 것은 좋은 방법이지만, 세정제 없이 물을 적신 상태에서 빗는 것이 더 효과적입니다.", "4": "참빗으로 빗는 방법은 잘못된 방법이 아니지만, 두피와 머리카락을 부드럽게 다루는 것이 우선입니다.", "5": "가족의 동의를 얻어 머리카락을 자르는 것은 엉킨 머리카락을 자르는 극단적인 방법으로, 가능한 지양해야 합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc hoặc chăm sóc"}, {"term_ko": "머리카락", "term_vi": "Tóc", "def_ko": "인간의 머리에서 자라는 털", "def_vi": "Sợi tóc mọc trên đầu người"}, {"term_ko": "엉키다", "term_vi": "Rối", "def_ko": "서로 얽히거나 엮이다", "def_vi": "Bị vướng hoặc mắc vào nhau"}, {"term_ko": "손질", "term_vi": "Chăm sóc", "def_ko": "다듬거나 관리하는 것", "def_vi": "Cắt tỉa hoặc quản lý"}, {"term_ko": "세정제", "term_vi": "Chất tẩy rửa", "def_ko": "청결을 위해 쓰는 약물", "def_vi": "Chất dùng để làm sạch"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1324, '10', '드라이샴푸를 이용하여 머리를 감기는 방법으로 옳은 것은?', '["물과 샴푸를 1:1로 섞어서 사용한다.", "샴푸를 머리에 바르고 수건으로 덮어 둔다.", "샴푸 거품을 두피에 발라 흡수시킨 후 물로 헹군다.", "샴푸를 머리카락에 발라 거품을 낸 후 수건으로 닦아낸다.", "머리카락에 물을 적신 후, 샴푸를 바르고 빗으로 빗어준다."]'::jsonb, 4, '드라이샴푸 사용법에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "물과 샴푸를 1:1로 섞는 방법은 드라이샴푸의 사용법이 아닙니다.\n[정답]", "4": "드라이샴푸는 머리카락에 바르고 수건으로 닦아내는 방법으로 사용합니다.", "2": "샴푸를 머리에 바르고 수건으로 덮어 두는 방법은 적합하지 않습니다.", "3": "샴푸 거품을 두피에 발라 흡수시킨 후 물로 헹구는 것은 일반 샴푸 사용법입니다.", "5": "머리카락에 물을 적신 후, 샴푸를 바르고 빗으로 빗는 방법은 드라이샴푸가 아닌 일반 샴푸에 해당합니다."}'::jsonb, '[{"term_ko": "드라이샴푸", "term_vi": "Dầu gội khô", "def_ko": "물 없이 사용하는 샴푸", "def_vi": "Dầu gội không cần nước"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1323, '10', '침상에 누워있는 대상자의 머리를 감기는 방법으로 옳은 것은?', '["눈과 귀에 수건을 올려 덮는다.", "수건으로 가슴부터 허리까지 감싼다.", "대상자의 어깨가 침대 모서리에 오도록 한다.", "뒷머리는 목을 좌우로 돌리면서 헹군다.", "린스를 한 후 수건으로 닦아 말린다."]'::jsonb, 4, '대상자의 머리를 감기는 방법으로 안전하고 효과적인 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "눈과 귀에 수건을 올려 덮는다. 이 방법은 적절하지 않으며, 대상자의 시야를 가릴 수 있어 위험할 수 있습니다.\n[정답]", "2": "수건으로 가슴부터 허리까지 감싼다. 이는 보호를 위한 방법으로 잘못된 방법입니다.", "3": "대상자의 어깨가 침대 모서리에 오도록 한다. 올바른 방법이지만 가장 좋은 방법은 아닙니다.", "4": "뒷머리는 목을 좌우로 돌리면서 헹군다. 이는 머리를 감길 때 적절한 방법입니다.", "5": "린스를 한 후 수건으로 닦아 말린다. 역시 중요한 단계이지만 올바른 첫 번째 방법이 아닙니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1322, '10', '침대에서 대상자의 머리를 감기는 방법으로 옳은 것은?', '["침대 모서리에 머리가 오도록 한다.", "방수포를 머리부터 엉덩이까지 깐다.", "목욕담요를 덮고, 이불은 다리까지 접어 내린다.", "머리 밑에 패드를 펴고 패드 끝은 매트리스 밑으로 접어 넣는다.", "패드가 없으면 이불을 말아서 사용한다."]'::jsonb, 1, '대상자의 머리를 감기는 올바른 방법을 이해하고 평가하는 것이다.', NULL, '{"1": "대상자의 머리를 침대 모서리에 위치시키는 것이 좋다. 머리를 감기기 용이함이 확보된다.\n[정답]", "2": "방수포는 머리부터 엉덩이까지 깔 필요가 없다. 반드시 필요한 범위를 넘어가는 내용이다.", "3": "목욕담요를 덮는 것은 타당하지만, 이불을 다리까지 접어 내리는 것은 선택적이다.", "4": "머리 밑에 패드를 펴는 방식은 필요하지만, 패드 끝이 매트리스 밑으로 접혀야 한다는 지시는 없으므로 반드시 필요하진 않다.", "5": "패드가 없을 경우 이불을 말아 사용하는 것은 일반적이지 않다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1321, '10', '두발 청결을 위한 머리 감기기 방법으로 옳은 것은?', '["문과 창문을 열어놓는다.", "겨울에는 오전 시간을 이용한다.", "귐가이 솜으로 양쪽 귀를 막는다.", "목욕의자의 앉혀 머리를 뒤로 젖히고 감긴다.", "한기를 느끼지 않도록 물의 온도를 뜨겁게 한다."]'::jsonb, 3, '두발 청결을 유지하기 위해 머리 감기기 방법 중 올바른 방법을 묻는 문제이다.', NULL, '{"1": "문과 창문을 열어놓는 것은 환기를 위해 좋지만, 머리 감기기 방법으로는 직접적인 관련이 없다.\n[정답]", "2": "겨울에 오전 시간을 이용하는 것은 머리 감기기 방법으로 적절하지 않다. 겨울철은 외부 온도가 낮아 추가적인 주의가 필요하다.", "3": "귐가이 솜으로 양쪽 귀를 막는 것은 귀에 물이 들어가는 것을 방지할 수 있어 좋은 방법이다.", "4": "목욕의자에 앉혀 머리를 뒤로 젖히는 것은 안전하지만 올바른 방법이 아니다. 적절한 위치에서 감겨야 한다.", "5": "한기를 느끼지 않도록 물의 온도를 뜨겁게 하는 것은 피부에 손상을 줄 수 있다. 적정 온도를 유지해야 한다."}'::jsonb, '[{"term_ko": "두발", "term_vi": "Tóc", "def_ko": "머리카락과 몸의 털", "def_vi": "Tóc và lông trên cơ thể"}, {"term_ko": "청결", "term_vi": "Sạch sẽ", "def_ko": "깨끗함", "def_vi": "Sự sạch sẽ"}, {"term_ko": "겨울", "term_vi": "Mùa đông", "def_ko": "찬 계절", "def_vi": "Mùa lạnh"}, {"term_ko": "목욕의자", "term_vi": "Ghế tắm", "def_ko": "목욕 시 앉는 의자", "def_vi": "Ghế ngồi khi tắm"}, {"term_ko": "귐가이 솜", "term_vi": "Bông gòn bịt tai", "def_ko": "귀를 막는 솜", "def_vi": "Bông gòn để bịt tai"}, {"term_ko": "물의 온도", "term_vi": "Nhiệt độ nước", "def_ko": "물의 뜨거운 정도", "def_vi": "Mức độ nóng của nước"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1320, '10', '대상자의 머리를 감기는 방법으로 옳은 것은?', '["저녁 식사 후에 감긴다.", "10도 정도의 물로 감긴다.", "머리를 감기 전에 대소변을 보게 한다.", "두피에 염증이 있으면 두피보호제를 바른다.", "수건으로 감싼 머리카락을 비벼가며 물기를 제거한다."]'::jsonb, 3, '대상자의 머리를 감기는 가장 적절한 방법을 알아보는 것이다.', NULL, '{"1": "저녁 식사 후에 감기는 방법은 특정하지 않으며, 개인의 상황에 따라 다를 수 있다.\n[정답]", "3": "머리를 감기 전에 대소변을 보게 하는 것은 대상자의 편안함과 청결을 위한 중요한 과정이다.", "2": "10도 정도의 물로 감기는 것은 너무 차가운 물로 대상자에게 불편함을 줄 수 있다.", "4": "두피에 염증이 있는 경우는 두피보호제를 사용하는 것이 좋지만, 반드시 그렇다고 할 수는 없다.", "5": "수건으로 비비며 물기를 제거하는 것은 두피에 손상을 줄 수 있으므로 바람직하지 않다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người theo dõi", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "두피", "term_vi": "Da đầu", "def_ko": "머리의 피부", "def_vi": "Da của đầu"}, {"term_ko": "대소변", "term_vi": "Đi vệ sinh", "def_ko": "배변", "def_vi": "Đi đại tiện"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "부종", "def_vi": "Sưng"}, {"term_ko": "보호제", "term_vi": "Sản phẩm bảo vệ", "def_ko": "지키는 것", "def_vi": "Sản phẩm bảo vệ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1319, '10', '대상자의 머리를 감기는 방법으로 옳은 것은?', '["두피를 손톱으로 마사지한다.", "공복과 식후를 피하여 감긴다.", "두피에 상처가 있으면 연고를 바른다.", "감긴 후에 남은 물기는 자연 건조한다.", "헤어드라이어를 두피에 바짝 대고 신속하게 말린다."]'::jsonb, 2, '대상자의 머리 감기는 과정에서 주의해야 하는 사항을 평가하기 위함이다.', NULL, '{"1": "두피를 손톱으로 마사지한다는 것은 두피에 상처를 유발할 수 있어 적절하지 않다.\n[정답]", "2": "공복과 식후를 피하여 감긴다는 것은 대상자의 안전을 위해 매우 중요한 사항이다.", "3": "두피에 상처가 있으면 연고를 바르는 것은 해당 상황에 맞는 조치가 아니다. 상처를 치료하기 위해서는 의사의 상담이 필요하다.", "4": "감긴 후에 남은 물기를 자연 건조하는 것은 바람직한 방법이나, 적절한 방법은 대상자의 상태에 따라 다르다.", "5": "헤어드라이어를 두피에 바짝 대고 신속하게 말린다는 것은 화상을 입힐 위험이 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "머리", "term_vi": "Đầu", "def_ko": "머리 부분", "def_vi": "Phần đầu"}, {"term_ko": "감기", "term_vi": "Gội", "def_ko": "씻다", "def_vi": "Rửa"}, {"term_ko": "공복", "term_vi": "Nhịn ăn", "def_ko": "음식을 먹지 않은 상태", "def_vi": "Trạng thái không ăn thức ăn"}, {"term_ko": "식후", "term_vi": "Sau khi ăn", "def_ko": "음식을 먹은 후", "def_vi": "Sau khi ăn"}, {"term_ko": "상처", "term_vi": "Vết thương", "def_ko": "다치다", "def_vi": "Bị thương"}, {"term_ko": "연고", "term_vi": "Thuốc mỡ", "def_ko": "치료용 연고", "def_vi": "Thuốc chữa bệnh"}, {"term_ko": "자연 건조하다", "term_vi": "Khô tự nhiên", "def_ko": "자연 상태로 말리다", "def_vi": "Làm khô tự nhiên"}, {"term_ko": "헤어드라이어", "term_vi": "Máy sấy tóc", "def_ko": "드라이기", "def_vi": "Máy sấy tóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1318, '10', '의치를 세척할 때 의치세정제가 없을 경우 대신 사용할 수 있는 것은?', '["알코올", "표백제", "레몬즙", "주방세제", "과산화수소"]'::jsonb, 4, '의치를 세척하는 방법에 대한 이해를 확인하기 위한 문제입니다.', NULL, '{"1": "알코올은 소독에는 효과적이나 의치 세척에는 적합하지 않습니다.\n[정답]", "4": "주방세제는 의치세정제로 사용할 수 있는 적절한 대체품입니다.", "2": "표백제는 의치에 손상을 줄 수 있습니다.", "3": "레몬즙은 산성 성분이 있어 의치에 해를 끼칠 수 있습니다.", "5": "과산화수소는 의치 세척에 적합하지 않습니다."}'::jsonb, '[{"term_ko": "의치", "term_vi": "Hàm giả", "def_ko": "의수를 위한 인공 치아", "def_vi": "Răng giả"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1317, '10', '대상자의 의치를 관리하는 방법으로 옳은 것은?', '["의치를 소독할 때에는 표백제에 담근다.", "격일로 의치를 빼놓아 잇몸의 압박을 줄인다.", "윗니를 끼울 때에는 손바닥으로 밀어서 끼운다.", "의치를 끼우기 전에 전자레인지에 1분간 데워준다.", "찬물이 담긴 용기에 의치를 넣어 보관한다."]'::jsonb, 5, '대상자의 의치를 올바르게 관리할 수 있는 방법에 대한 지식을 평가하기 위함이다.', NULL, '{"1": "의지를 소독할 때에는 표백제 대신 전용 소독제를 사용해야 한다.\n[정답]", "5": "찬물에 담긴 용기에 보관하여 의치가 변형되는 것을 방지한다.", "2": "격일로 의치를 빼놓는 것은 잇몸의 건강에 좋지 않다.", "3": "윗니를 끼울 때에는 밀어서가 아니라 적절한 방법으로 착용해야 한다.", "4": "전자레인지에 데우는 것은 의치의 소재에 따라 손상을 줄 수 있다."}'::jsonb, '[{"term_ko": "의치", "term_vi": "Hàm giả", "def_ko": "틀니", "def_vi": "Hàm giả"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1316, '10', '대상자의 의치를 관리하는 방법으로 옳은 것은?', '["베타딘 용액에 담가 보관한다.", "세면기에 물을 받아서 의치를 헹군다.", "윗니와 아랫니 의치를 동시에 끼운다.", "의치 삽입 전에 구강세정제로 입안을 헹구게 한다.", "인지저하나 마비가 있는 경우 의치 사용을 못하게 한다."]'::jsonb, 4, '대상자의 의치를 관리하는 올바른 방법을 이해하고 있는지 확인하려는 의도이다.', NULL, '{"1": "베타딘 용액은 의치에 적합하지 않으며, 의치의 손상을 초래할 수 있다.\n[정답]", "4": "의치 삽입 전에 구강세정제로 입안을 헹구게 하는 것은 전반적인 구강 위생을 증진시킨다.", "2": "세면기에 물을 받아서 의치를 헹구는 것은 비위생적일 수 있다.", "3": "윗니와 아랫니 의치를 동시에 끼우는 것은 올바른 관리 방법이 아니다.", "5": "인지저하나 마비가 있는 경우에도 의치 사용은 가능하나, 적절한 관리가 필요하다."}'::jsonb, '[{"term_ko": "의치", "term_vi": "Răng giả", "def_ko": "틀니", "def_vi": "hàm giả"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1315, '10', '대상자의 의치를 관리하는 방법으로 옳은 것은?', '["뜨거운 물에 삶아서 소독한다.", "깨끗한 휴지에 싸서 보관한다.", "의치를 세척하여 끼운 채로 자게 한다.", "의치를 끼우기 전에 잇몸 마사지를 해준다.", "의치를 뺄 때에는 아래쪽을 먼저 빼 준다."]'::jsonb, 4, '대상자의 의치 관리에 대한 올바른 방법을 묻는 문제입니다.', NULL, '{"1": "뜨거운 물은 의치의 변형을 초래할 수 있으므로 소독 방법으로 적절하지 않습니다.\n[정답]", "2": "깨끗한 휴지에 싸서 보관하는 것은 올바른 방법이 아니며, 적절한 보관 방법이 필요합니다.", "3": "의치를 끼운 채로 자게 하는 것은 치아에 부담을 줄 수 있으므로 올바른 방법이 아닙니다.", "4": "의치를 끼우기 전에 잇몸 마사지를 해주는 것은 잇몸의 혈액순환을 돕고 적응을 도울 수 있기 때문에 올바른 방법입니다.", "5": "의치를 뺄 때에는 위쪽을 먼저 빼는 것이 원칙입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "의치", "term_vi": "Răng giả", "def_ko": "인공 치아", "def_vi": "Răng nhân tạo"}, {"term_ko": "소독", "term_vi": "Khử trùng", "def_ko": "감염 예방을 위한 청결한 처리", "def_vi": "Xử lý sạch sẽ để ngăn ngừa nhiễm trùng"}, {"term_ko": "마사지", "term_vi": "Mát xa", "def_ko": "부드럽게 주물러 주는 행동", "def_vi": "Hành động xoa bóp nhẹ nhàng"}, {"term_ko": "잇몸", "term_vi": "Nướu", "def_ko": "치아가 심어진 부위", "def_vi": "Vùng mà răng được gắn vào"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1314, '10', '잠을 자기 전에 대상자의 의치를 빼 주는 이유는?', '["침 분비 촉진", "잇몸 압박 예방", "의치 변형 방지", "의치 유연성 유지", "턱뼈의 골밀도 유지"]'::jsonb, 2, '대상자의 의치를 빼 주는 이유를 묻는 것으로, 요양보호사가 의치를 관리할 때 고려해야 할 중요한 사항을 이해하고 있는지를 평가합니다.', NULL, '{"1": "침 분비 촉진: 의치를 빼는 것과 직접적인 관련이 없습니다.\n[정답]", "2": "잇몸 압박 예방: 의치를 착용하고 자면 잇몸에 지속적인 압력이 가해져 통증이나 손상을 초래할 수 있습니다.", "3": "의치 변형 방지: 의치가 변형되는 것은 착용 상태와 관련이 있으며, 빼는 것과는 관계가 적습니다.", "4": "의치 유연성 유지: 의치는 일반적으로 고정되어 있어 유연성과 관계가 없습니다.", "5": "턱뼈의 골밀도 유지: 턱뼈와 의치의 관계는 복잡하며, 의치를 빼는 것이 골밀도와 직접적으로 연결되지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1313, '10', '누워 있는 대상자의 구강청결 방법으로 옳은 것은?', '["치아 안쪽은 칫솔질을 삼간다.", "구토를 막기 위해 혀는 닦지 않는다.", "양치물을 삼기지 않도록 상체를 올려준다.", "입안을 헹구기 어려운 경우에는 거즈로 닦아낸다.", "칫솔질은 매 식사 전에 3분간 세심하게 닦는다."]'::jsonb, 3, '대상자의 구강청결을 위한 올바른 방법을 묻는 문제입니다.', NULL, '{"1": "구강청결 시, 치아 안쪽도 소홀히 하지 않아야 합니다.", "2": "구토를 막기 위해서는 혀를 닦는 것이 중요합니다.\n[정답]", "3": "양치물을 삼기지 않도록 상체를 올리는 것이 필요합니다.", "4": "입안을 헹구기 어려운 경우에는 거즈로 닦아내는 것이 좋은 방법입니다.", "5": "칫솔질은 매 식사 후에 하는 것이 바람직합니다."}'::jsonb, '[{"term_ko": "구강청결", "term_vi": "Vệ sinh miệng", "def_ko": "입 안을 깨끗하게 하는 것", "def_vi": "Làm sạch bên trong miệng"}, {"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "환자 또는 돌봐줄 필요가 있는 사람", "def_vi": "Bệnh nhân hoặc người cần chăm sóc"}, {"term_ko": "상체", "term_vi": "Thân trên", "def_ko": "몸의 윗부분", "def_vi": "Phần trên của cơ thể"}, {"term_ko": "헹구다", "term_vi": "Súc", "def_ko": "입안을 씻다", "def_vi": "Rửa miệng"}, {"term_ko": "거즈", "term_vi": "Gạc", "def_ko": "의료용 천", "def_vi": "Vải y tế"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1312, '10', '대상자의 칫솔질 돕기 방법으로 옳은 것은?', '["많은 양의 치약을 칫솔모 위에 눌러 짠다.", "칫솔을 90도 각도로 치아에 대고 닦는다.", "머리를 뒤로 젖히게 하고 칫솔질을 한다.", "컵 사용이 어려울 경우 빨대 달린 컵을 사용하게 한다.", "혈액응고장애가 있으면 칫솔 대신 치실을 사용한다/"]'::jsonb, 4, '대상자의 칫솔질을 돕기 위한 올바른 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "많은 양의 치약을 칫솔모 위에 눌러 짜면 치아에 고르게 닿지 않아 효과적인 칫솔질이 어렵다.\n[정답]", "4": "컵 사용이 어려운 경우 빨대 달린 컵을 사용하는 것은 수분 섭취를 용이하게 하는 좋은 방법이다.", "2": "칫솔을 90도 각도로 치아에 대고 닦는 것은 올바른 방법이 아니다. 보통 45도 각도로 기울여 닦아야 한다.", "3": "머리를 뒤로 젖히게 하면 구강 내에서 물이 흘러나와 불편할 수 있다.", "5": "혈액응고장애가 있는 경우 칫솔 대신 치실을 사용하는 것은 위험할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(병원, 요양시설 등에서 돌보는 사람)", "def_vi": "Người được chăm sóc trong bệnh viện, cơ sở điều dưỡng."}, {"term_ko": "칫솔질", "term_vi": "Đánh răng", "def_ko": "이와 같은 행동(입안의 이와 턱 청소)", "def_vi": "Hành động làm sạch răng miệng."}, {"term_ko": "혈액응고장애", "term_vi": "Rối loạn đông máu", "def_ko": "혈액이 응고되는 데 문제가 있는 상태", "def_vi": "Tình trạng gặp vấn đề trong việc đông máu."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1311, '10', '대상자의 칫솔질 돕기 방법으로 옳은 것은?', '["칫솔 위에 두툼하게 치약을 올린다.", "잇몸에서부터 치아 쪽 방향으로 닦는다.", "칫솔질을 할 때는 치아만 닦는다.", "칫솔을 옆으로 강하게 문지른다.", "치약의 청량감이 오래가도록 입안을 물로 한번만 헹군다."]'::jsonb, 2, '대상자의 올바른 칫솔질 방법을 이해하고 있는지를 평가하려는 의도입니다.', NULL, '{"1": "칫솔에 치약을 두툼하게 올리는 것은 비효율적입니다.\n[정답]", "2": "잇몸에서부터 치아 쪽 방향으로 닦는 것이 올바른 방법입니다.", "3": "칫솔질을 할 때는 치아 외에도 잇몸을 함께 닦아야 합니다.", "4": "칫솔을 옆으로 강하게 문지르는 것은 잇몸에 손상을 줄 수 있습니다.", "5": "치약의 청량감을 오래 유지하기 위해서는 여러 번 헹궈 주는 것이 좋습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 돌봐야 할 사람", "def_vi": "Người bệnh hoặc người cần chăm sóc"}, {"term_ko": "칫솔질", "term_vi": "Đánh răng", "def_ko": "이빨을 닦는 행위", "def_vi": "Hành động làm sạch răng"}, {"term_ko": "치약", "term_vi": "Kem đánh răng", "def_ko": "이빨을 닦을 때 사용하는 제품", "def_vi": "Sản phẩm sử dụng khi đánh răng"}, {"term_ko": "잇몸", "term_vi": "Nướu", "def_ko": "치아를 둘러싼 부드러운 조직", "def_vi": "Tổ chức mềm bao quanh răng"}, {"term_ko": "헹구다", "term_vi": "Súc miệng", "def_ko": "입안을 물로 씻어내다", "def_vi": "Rửa miệng bằng nước"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1310, '10', '혈액응고장애가 있는 대상자의 칫솔질을 돕는 방법은?', '["칫솔모가 단단한 칫솔에 치약을 두툼하게 올린다.", "치아에서 잇몸 방향으로 회전하면서 칫솔질하게 한다.", "칫솔로 치아뿐 아니라 혀의 깊숙한 곳까지 닦게 한다.", "치실로 음식물 찌꺼기를 제거한 후 칫솔질하게 한다.", "매 식사 후 30분 이내와 잠자기 전에 칫솔질하게 한다."]'::jsonb, 5, '혈액응고장애가 있는 대상자가 안전하게 칫솔질을 할 수 있는 방법을 알아보는 것이며, 적절한 칫솔질 방법이 무엇인지 확인하는 것입니다.', NULL, '{"1": "칫솔모가 단단한 칫솔은 잇몸에 상처를 유발할 수 있어 부적절하다.\n[정답]", "5": "매 식사 후 30분 이내와 잠자기 전에 칫솔질하는 것이 가장 안전하고 중요하다.", "3": "혀의 깊숙한 곳까지 닦는 것은 필요하지만 혈액응고장애가 있는 경우에는 조심해야 한다.", "2": "치아에서 잇몸 방향으로 회전하는 방법은 잘못된 방법이 아니나, 혈액응고장애가 있는 경우 신중해야 한다.", "4": "치실로 제거한 후 칫솔질하는 것은 좋으나, 칫솔질의 타이밍이 더 중요하다."}'::jsonb, '[{"term_ko": "혈액응고장애", "term_vi": "Rối loạn đông máu", "def_ko": "혈액이 제대로 응고되지 않는 질병", "def_vi": "Bệnh khiến máu không đông đúng cách"}, {"term_ko": "칫솔질", "term_vi": "Đánh răng", "def_ko": "이가 닦이는 행동", "def_vi": "Hành động chải răng"}, {"term_ko": "자주", "term_vi": "Thường xuyên", "def_ko": "빈도가 높은", "def_vi": "Tần suất cao"}, {"term_ko": "잇몸", "term_vi": "Nướu", "def_ko": "치아를 둘러싼 부위", "def_vi": "Vùng xung quanh răng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1309, '10', '의식이 없는 대상자의 구강 청결을 돕는 방법으로 옳은 것은?', '["구강에 상처가 있으면 소독해준다.", "똑바로 누운 자세로 상반신을 낮춘다.", "생리식염수로 입안을 헹구어 준다.", "물에 적신 일회용 스펀지 브러시로 닦는다.", "건조해지지 않도록 입 주변의 물기는 닦지 않는다."]'::jsonb, 4, '의식이 없는 대상자의 구강 청결을 어떻게 효율적으로 도울 수 있는지를 평가하고자 하는 문제입니다.', NULL, '{"1": "구강에 상처가 있을 경우 소독을 하는 것은 중요하지만, 의식이 없는 환자에게는 즉각적으로 할 수 있는 조치가 아닙니다.\n[정답]", "4": "물에 적신 일회용 스펀지 브러시로 닦는 것은 안전하고 효과적인 방법입니다.", "3": "생리식염수로 입안을 헹구는 것은 의식이 있는 환자에게 적용할 수 있으며, 의식이 없는 환자에게는 적합하지 않습니다.", "2": "똑바로 누운 자세로 상반신을 낮추는 것은 안전하지 않으며, 청결을 돕는 데 비효율적입니다.", "5": "입 주변의 물기를 닦지 않는 것은 오히려 구강 건강에 장애가 될 수 있습니다."}'::jsonb, '[{"term_ko": "구강", "term_vi": "Khóe miệng", "def_ko": "입안(한국어)", "def_vi": "Vùng xung quanh miệng"}, {"term_ko": "청결", "term_vi": "Sự sạch sẽ", "def_ko": "청결함(한국어)", "def_vi": "Sự sạch sẽ"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "자각(한국어)", "def_vi": "Ý thức"}, {"term_ko": "상반신", "term_vi": "Thân trên", "def_ko": "상체(한국어)", "def_vi": "Thân trên"}, {"term_ko": "스펀지", "term_vi": "Bọt biển", "def_ko": "스폰지(한국어)", "def_vi": "Bọt biển"}, {"term_ko": "일회용", "term_vi": "Dùng một lần", "def_ko": "한 번 사용(한국어)", "def_vi": "Dùng một lần"}, {"term_ko": "브러시", "term_vi": "Bàn chải", "def_ko": "솔(한국어)", "def_vi": "Bàn chải"}, {"term_ko": "헹구다", "term_vi": "Súc", "def_ko": "헹구다(한국어)", "def_vi": "Súc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1308, '10', '의식이 없는 대상자의 입안을 닦을 때 순서로 옳은 것은?가. 윗니와 잇몸 나. 아래쪽 이와 잇몸 다. 입청장 라. 혀 마. 볼 안쪽', '["가-나-다-라-마", "가-다-나-라-마", "나-라-가-마-다", "나-가-다-라-마", "다-나-가-마-라"]'::jsonb, 1, '의식이 없는 대상자의 입안을 닦는 올바른 순서를 이해하는 것이 목적입니다.', NULL, '{"1": "윗니와 잇몸을 닦은 후 아래쪽 이와 잇몸을 닦고, 입청장, 혀, 볼 안쪽 순서로 닦는 것이 올바른 방법입니다.\n[정답]", "2": "윗니와 잇몸을 먼저 닦고, 입청장 다음에 아래쪽 이와 잇몸을 닦아야 하므로 잘못된 순서입니다.", "3": "아래쪽 이와 잇몸을 먼저 닦는 것은 올바른 순서가 아닙니다.", "4": "입청장을 먼저 닦는 것은 올바르지 않습니다.", "5": "입청장을 먼저 닦는 것은 잘못된 방법입니다."}'::jsonb, '[{"term_ko": "입안", "term_vi": "Miệng", "def_ko": "구강(입의 내부)", "def_vi": "Khoang miệng (phần bên trong miệng)"}, {"term_ko": "의식", "term_vi": "Nhận thức", "def_ko": "의식(상태)", "def_vi": "Tình trạng nhận thức"}, {"term_ko": "이", "term_vi": "Răng", "def_ko": "치아(이빨)", "def_vi": "Răng (a tooth)"}, {"term_ko": "잇몸", "term_vi": "Nướu", "def_ko": "잇몸(치아에 연결된 조직)", "def_vi": "Nướu (gums)"}, {"term_ko": "혀", "term_vi": "Lưỡi", "def_ko": "혀(말하는 기관)", "def_vi": "Lưỡi (tongue)"}, {"term_ko": "볼", "term_vi": "Má", "def_ko": "뺨(얼굴의 옆 부분)", "def_vi": "Má (cheek)"}, {"term_ko": "청장", "term_vi": "Màu", "def_ko": "구강 쪽의 구조물", "def_vi": "Cấu trúc trong miệng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1307, '10', '치아가 없거나 연하장애가 있는 대상자에게 제공하는 구강청결 방법은?', '["칫솔질하기", "입안닦아내기", "입안 헹구기", "의치 손질하기", "치실하기"]'::jsonb, 2, '구강청결 방법에 대한 이해를 확인하기 위함입니다.', NULL, '{"1": "칫솔질은 치아가 있는 대상자에게 적합한 방법입니다.\n[정답]", "2": "입안닦아내기는 치아가 없거나 연하장애가 있는 대상자에게 적합한 방법입니다.", "3": "입안 헹구기는 물을 사용하는 방법으로 연하장애가 있는 경우 적합하지 않습니다.", "4": "의치 손질은 의치를 사용하는 대상자에게 해당되지만 입안청결에는 적용되지 않습니다.", "5": "치실 사용은 치아가 있는 경우에 적합한 방법입니다."}'::jsonb, '[{"term_ko": "구강청결", "term_vi": "Vệ sinh miệng", "def_ko": "입이나 구강을 청결하게 하는 것", "def_vi": "Làm sạch miệng hoặc khoang miệng"}, {"term_ko": "연하장애", "term_vi": "Khó nuốt", "def_ko": "음식을 삼키기 어려운 장애", "def_vi": "Khó khăn trong việc nuốt thức ăn"}, {"term_ko": "입안", "term_vi": "Trong miệng", "def_ko": "구강의 내부", "def_vi": "Bên trong khoang miệng"}, {"term_ko": "의치", "term_vi": "Hàm giả", "def_ko": "인공 치아", "def_vi": "Răng giả"}, {"term_ko": "치실", "term_vi": "Chỉ nha khoa", "def_ko": "치아 사이의 이물질을 제거하는 도구", "def_vi": "Dụng cụ làm sạch giữa các răng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1306, '10', '식사 전에 입안을 헹구는 이유로 옳은 것은?', '["식욕을 억제하기 위해", "식도 역류를 예방하기 위해", "타액 분비를 줄이기 위해", "위액 분비를 줄이기 위해", "구강건조를 막기 위해"]'::jsonb, 5, '식사 전에 입안을 헹구는 이유를 이해하고 올바른 선택지를 찾는 것입니다.', NULL, '{"1": "식욕을 억제하기 위해: 입안을 헹구는 것이 직접적으로 식욕을 억제하지는 않습니다.\n[정답]", "5": "구강건조를 막기 위해: 입안을 헹구면 구강 내 수분을 유지하여 구강건조를 예방할 수 있습니다.", "2": "식도 역류를 예방하기 위해: 입안을 헹구는 것이 식도 역류와 직접적인 연관이 없습니다.", "3": "타액 분비를 줄이기 위해: 헹구는 것은 타액 분비를 줄이지 않습니다.", "4": "위액 분비를 줄이기 위해: 입안을 헹구는 것이 위액 분비와는 관련이 없습니다."}'::jsonb, '[{"term_ko": "식사", "term_vi": "입안", "def_ko": "식사(식사)", "def_vi": "입(miệng)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1305, '10', '대상자의 구강 청결을 돕는 방법으로 옳은 것은?', '["혀 안쪽과 목젖 안까지 깊숙이 닦는다.", "입안에 상처나 염증이 있는지 확인한다.", "냄새가 심하면 구취제거 스프레이를 뿌린다.", "의식이 없는 대상자는 일주일에 한 번 닦는다.", "거부하는 치매 대상자는 두 손가락으로 입을 벌린 후 닦는다."]'::jsonb, 2, '대상자의 구강 청결 관리의 중요성을 이해하고, 적절한 방법을 선택할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "혀와 목젖까지 깊숙이 닦는 것은 안전하지 않으며, 손상이나 질병을 유발할 수 있습니다.\n[정답]", "2": "입안의 상처나 염증이 있는지 확인하는 것은 구강 청결을 도우는 데 중요합니다.", "3": "구취제거 스프레이 사용은 근본적인 문제를 해결하지 않으므로 권장되지 않습니다.", "4": "의식이 없는 대상자는 일주일에 한 번 구강 청결을 하는 것이 아니라 전문가의 조치가 필요합니다.", "5": "치매 대상자를 강제로 입을 벌리는 것은 부상을 초래할 수 있으므로 피해야 합니다."}'::jsonb, '[{"term_ko": "구강", "term_vi": "Miệng", "def_ko": "입 안", "def_vi": "bên trong của miệng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1304, '10', '장루를 착용하고 있는 대상자를 돕는 방법으로 옳은 것은?', '["주머니 교환하는 날에는 목욕을 금한다.", "복통을 호소하면 장루주머니를 떼어준다.", "장운동의 부담을 덜기 위해 식사량을 줄인다.", "배설물이 1/3~1/2 정도 채워지면 주머니를 비운다.", "숭일간 배설물이 차지 않으면 주머니를 교체한다."]'::jsonb, 4, '장루 관리의 올바른 방법을 파악하기 위함입니다.', NULL, '{"1": "주머니 교환하는 날에는 목욕을 금하는 것은 옳지 않습니다. 목욕은 필요시 할 수 있습니다.", "2": "복통을 호소할 때 장루 주머니를 떼어주는 것은 적절한 조치가 아닙니다.\n[정답]", "3": "장운동의 부담을 덜기 위해 식사량을 줄이는 것은 일반적으로 권장되지 않습니다. 적절한 영양 섭취가 필요합니다.", "4": "배설물이 1/3~1/2 정도 채워지면 주머니를 비우는 것이 올바른 방법입니다.", "5": "특정 기간 동안 배설물이 차지 않더라도, 주머니를 교체할 필요는 없습니다."}'::jsonb, '[{"term_ko": "장루", "term_vi": "Đường hầm", "def_ko": "인체의 장기를 외부로 연결하기 위한 수술적 조치", "def_vi": "Phương pháp phẫu thuật kết nối các cơ quan trong cơ thể với bên ngoài"}, {"term_ko": "배설물", "term_vi": "Chất bài tiết", "def_ko": "소화 후 몸에서 나오는 찌꺼기", "def_vi": "Chất thải trong cơ thể sau khi tiêu hóa"}, {"term_ko": "주머니", "term_vi": "Túi", "def_ko": "배설물을 담는 용기", "def_vi": "Bình chứa chất bài tiết"}, {"term_ko": "복통", "term_vi": "Đau bụng", "def_ko": "배가 아픈 증상", "def_vi": "Triệu chứng đau ở bụng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1303, '10', '장루관리에 대한 설명으로 옳은 것은?', '["수분 섭취를 제한한다.", "통목욕 시에는 주머니를 떼고 한다.", "배설 주머니가 가득 차면 비워준다.", "장루주머니는 주 1회 주기로 교환한다.", "복벽을 통하여 체외로 소변을 배출시키기 위해 만든 구멍이다."]'::jsonb, 4, '장루 관리에 대한 기본적인 이해를 요구하는 문제입니다.', NULL, '{"1": "장루 관리 시 수분 섭취는 중요하며, 제한하지 않습니다.\n[정답]", "2": "통목욕 시에는 장루주머니를 떼지 않고 그대로 유지해야 합니다.", "3": "배설 주머니가 가득 차면 비워주지만, 이는 필요에 따라 다를 수 있습니다.", "4": "장루주머니는 주 1회 주기로 교환해야 합니다.", "5": "복벽을 통해 소변을 배출하는 것은 장루가 아닌 신루입니다."}'::jsonb, '[{"term_ko": "장루", "term_vi": "Rò đại tràng", "def_ko": "대변을 체외로 배출하기 위해 복부에 만들어진 구멍", "def_vi": "Lỗ được tạo ra ở bụng để bài tiết phân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1302, '10', '대상자의 요루관리 방법으로 옳은 것은?', '["요루는 좌측하복부에 위치하고 있다.", "요루 주머니는 매일 교환한다.", "통목욕 시에는 소변을 비우고 주머니를 착용한다.", "샤워 시에는 반드시 요루 주머니를 착용한다.", "소변이 요루 주머니에 배출될 때마다 비워낸다."]'::jsonb, 3, '대상자의 요루 관리 방법에 대한 이해도를 평가하고자 함.', NULL, '{"1": "요루는 대개 우측하복부에 위치한다. 따라서 이 정보는 틀리다.\n[정답]", "3": "통목욕 시 소변을 비우고 주머니를 착용하는 것이 올바른 방법이다.", "2": "요루 주머니는 일반적으로 매일 교환할 필요는 없고, 필요한 경우에만 교환한다.", "4": "샤워 시에는 요루 주머니를 착용하되, 반드시 착용해야 하는 것은 아니다. 개인의 상태에 따라 다르다.", "5": "소변이 요루 주머니에 배출될 때마다 비울 필요는 없고, 주머니의 용량이 충분할 때까지 기다린다."}'::jsonb, '[{"term_ko": "요루", "term_vi": "Yoru", "def_ko": "장기를 외부로 연결하는 인공적인 구멍", "def_vi": "Lỗ mở nhân tạo kết nối cơ quan bên ngoài"}, {"term_ko": "주머니", "term_vi": "Túi", "def_ko": "요루에서 배출된 것을 저장하는 기구", "def_vi": "Thiết bị lưu trữ chất thải từ ostomy"}, {"term_ko": "통목욕", "term_vi": "Tắm chung", "def_ko": "여러 사람이 함께 하는 목욕", "def_vi": "Tắm với nhiều người"}, {"term_ko": "비우다", "term_vi": "Xả", "def_ko": "차서 쌓인 것을 빼내다", "def_vi": "Lấy ra chất lỏng đã chứa"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1301, '10', '요루관리에 대한 설명으로 옳은 것은?', '["요루 주머니에 소변이 가득 차면 버린다.", "요루 주머니는 주 2~3회 교환한다.", "통목욕 시에는 요루 주머니를 떼고 한다.", "요루에 출혈이 있으면 알코올로 소독한다.", "복벽에 만든 구멍에 주머니를 연결하여 대변을 배출한다."]'::jsonb, 2, '요루관리에 대한 기본적인 지식을 평가하기 위함입니다.', NULL, '{"1": "요루 주머니는 소변이 가득 차면 버리는 것이 아니라, 정해진 주기에 맞추어 교환해야 합니다.\n[정답]", "2": "요루 주머니는 일반적으로 주 2~3회 교환하는 것이 적절합니다.", "3": "통목욕 시에는 요루 주머니를 떼지 않고도 목욕이 가능하게 관리합니다.", "4": "요루에 출혈이 있어도 알코올로 소독하는 것은 적절하지 않으며, 전문적인 처치가 필요합니다.", "5": "복벽에 만든 구멍은 대변을 배출하는 것이 아니라, 요루를 통해 소변을 배출하는 방식입니다."}'::jsonb, '[{"term_ko": "요루", "term_vi": "Yoru", "def_ko": "인체에 인위적으로 생성한 구멍", "def_vi": "Lỗ được tạo ra nhân tạo trên cơ thể"}, {"term_ko": "주머니", "term_vi": "Túi", "def_ko": "물건을 담는 가방", "def_vi": "Bao đựng đồ"}, {"term_ko": "소변", "term_vi": "Nước tiểu", "def_ko": "대사 후 남은 배설물", "def_vi": "Chất thải sau chuyển hóa"}, {"term_ko": "출혈", "term_vi": "Chảy máu", "def_ko": "혈액이 외부로 나오는 현상", "def_vi": "Hiện tượng máu chảy ra ngoài"}, {"term_ko": "소독", "term_vi": "Khử trùng", "def_ko": "세균을 죽이는 것", "def_vi": "Giết chết vi khuẩn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1300, '10', '대상자가 유치도뇨관을 사용할 때 간호사에게 보고하지 않아도 되는 것은?', '["소변량이 적어진 경우", "소변색이 탁해진 경우", "도뇨관이 빠지는 경우", "소변이 많이 나오는 경우", "체온 상승이 있는 경우"]'::jsonb, 4, '대상자가 유치도뇨관을 사용할 때 어떤 상황이 간호사에게 보고할 필요가 없는지를 묻고 있다.', NULL, '{"1": "소변량이 적어진 경우에는 문제가 발생할 수 있으므로 보고해야 한다.", "2": "소변색이 탁해진 경우는 감염 등의 문제가 있을 수 있으니 보고해야 한다.", "3": "도뇨관이 빠지는 경우는 즉시 보고해야 한다.\n[정답]", "4": "소변이 많이 나오는 경우는 일반적으로 이상이 아닐 수 있으므로 보고하지 않아도 된다.", "5": "체온 상승이 있는 경우는 감염의 징후일 수 있으므로 보고해야 한다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "체내에서 소변을 배출하기 위해 삽입된 관", "def_vi": "Ống được đặt vào cơ thể để thải nước tiểu"}, {"term_ko": "소변량", "term_vi": "Lượng nước tiểu", "def_ko": "배출되는 소변의 양", "def_vi": "Khối lượng nước tiểu được thải ra"}, {"term_ko": "소변색", "term_vi": "Màu nước tiểu", "def_ko": "소변의 색깔", "def_vi": "Màu sắc của nước tiểu"}, {"term_ko": "체온", "term_vi": "Nhiệt độ cơ thể", "def_ko": "신체의 온도", "def_vi": "Nhiệt độ của cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1299, '10', '대상자가 유치도뇨관 사용 시 간호사에게 긴급히 보고해야 할 상황은?', '["연결관이 꺾여 있을 때", "소변주머니가 가득 차 있을 때", "소변주머니를 들고 걸어 다닐 때", "소변주머니의 배출구가 잠겨 있을 때", "도뇨관 밖으로 소변이 샐 때"]'::jsonb, 5, '유치도뇨관 사용 중 발생할 수 있는 긴급 상황을 파악하도록 하는 문제입니다.', NULL, '{"1": "연결관이 꺾여 있을 때: 끼었다고 해서 긴급한 상황이 아님.\n[정답]", "5": "도뇨관 밖으로 소변이 샐 때: 이는 즉각적인 조치가 필요한 심각한 상황입니다.", "2": "소변주머니가 가득 차 있을 때: 호출하여 비우는 것이 필요하지만 긴급한 상황은 아님.", "3": "소변주머니를 들고 걸어 다닐 때: 적절하지 않지만 긴급 상황은 아님.", "4": "소변주머니의 배출구가 잠겨 있을 때: 배출이 필요하나 긴급 상황으로 보긴 어려움."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "방광에 카테터를 삽입하는 방법", "def_vi": "Phương pháp đặt catheter vào bàng quang"}, {"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 담는 주머니", "def_vi": "Túi chứa nước tiểu"}, {"term_ko": "배출구", "term_vi": "Cửa thoát", "def_ko": "배출의 부분", "def_vi": "Phần thoát nước"}, {"term_ko": "긴급", "term_vi": "Khẩn cấp", "def_ko": "신속한 조치가 필요한 상황", "def_vi": "Tình huống cần phải hành động ngay lập tức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1298, '10', '유치도뇨관을 강제로 빼낼 경우 발생할 수 있는 문제는?', '["방광감염", "요로파열", "요로감염", "체온상승", "요도점막 손상"]'::jsonb, 5, '유치도뇨관을 강제로 제거했을 때 어떤 문제가 발생할 수 있는지를 이해하고 있는지 확인하고자 함.', NULL, '{"1": "방광감염: 유치도뇨관을 제거했을 때 방광에 감염이 올 수 있지만, 이는 주된 문제가 아니다.\n[정답]", "5": "요도점막 손상: 강제로 빼낼 경우 점막이 손상되어 출혈이나 염증이 발생할 수 있다.", "2": "요로파열: 주로 외부 힘에 의해 발생하며, 유치도뇨관 제거로 인한 일반적인 문제는 아니다.", "3": "요로감염: 유치도뇨관을 제거하면서 감염 위험이 증가할 수 있지만, 가장 흔한 상황은 아니다.", "4": "체온상승: 체온은 여러 요인에 의해 영향을 받을 수 있으며, 유치도뇨관과의 직접적인 연관성이 적다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống dẫn nước tiểu", "def_ko": "환자의 방광에서 소변을 배출하기 위해 설치하는 관", "def_vi": "Ống đặt vào bàng quang để thoát nước tiểu của bệnh nhân"}, {"term_ko": "요도점막", "term_vi": "Niêm mạc niệu đạo", "def_ko": "요도 내벽의 점막", "def_vi": "Niêm mạc bên trong niệu đạo"}, {"term_ko": "방광", "term_vi": "Bàng quang", "def_ko": "소변을 저장하는 기관", "def_vi": "Cơ quan chứa nước tiểu"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "세균이나 바이러스에 의해 발생하는 병", "def_vi": "Bệnh do vi khuẩn hoặc virus gây ra"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1297, '10', '유치도뇨관을 삽입하고 있는 대상자르 돕는 방법으로 옳은 것은?', '["수면 중에는 연결관을 잠가둔다.", "소변색이 탁하면 방광을 세척한다.", "금기사항이 없는 한 수분 섭취를 권장한다.", "소변이 새면 유치도뇨관을 즉시 제거한다.", "소변이 배출되지 않으면 유치도뇨관을 교체한다."]'::jsonb, 3, '유치도뇨관을 삽입 받고 있는 환자를 어떻게 돕는 것이 옳은지 판단하는 문제입니다.', NULL, '{"1": "수면 중에는 연결관을 잠가두는 것은 소변 배출에 문제가 생길 수 있어 부적절합니다.\n[정답]", "3": "금기사항이 없는 한 수분 섭취를 권장하는 것은 환자의 건강 상태에 따라 중요합니다.", "2": "소변색이 탁하면 방광을 세척하는 것은 꼭 필요한 조치가 아닙니다.", "4": "소변이 새면 유치도뇨관을 즉시 제거하는 것은 상황에 따라 다르며, 먼저 의사와 상담해야 합니다.", "5": "소변이 배출되지 않으면 유치도뇨관을 교체하는 대신 적절한 평가 후 조치를 취해야 합니다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "소변을 밖으로 배출하기 위해 방광에 삽입하는 튜브", "def_vi": "Ống được chèn vào bàng quang để thoát nước tiểu"}, {"term_ko": "소변", "term_vi": "Nước tiểu", "def_ko": "배설된 액체 형태의 노폐물", "def_vi": "Chất thải ở dạng lỏng được thải ra"}, {"term_ko": "세척", "term_vi": "Rửa", "def_ko": "청소하거나 씻어내는 것", "def_vi": "Làm sạch hoặc gột rửa"}, {"term_ko": "금기사항", "term_vi": "Chống chỉ định", "def_ko": "어떤 행동을 해서는 안 되는 사항", "def_vi": "Các điều không được thực hiện"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1296, '10', '유치도뇨관을 삽입한 대상자를 돕는 방법으로 옳은 것은?', '["산책하는 동안에는 유치도뇨관을 제거한다.", "소변량이 적은 경우 연결관의 꼬임 여부를 확인한다.", "소변주머니를 비운 후 배출구를 비눗물로 세척한다.", "유치도뇨관이 고정되어 있는지 수시로 당겨 본다.", "하복부가 불편하다고 할 때 소변주머니를 비워 준다."]'::jsonb, 2, '유치도뇨관의 관리와 관련된 올바른 지식을 평가하기 위함입니다.', NULL, '{"1": "유치도뇨관은 필요시 언제든지 제거할 수 없으며, 산책 중에도 신중히 관리해야 합니다.\n[정답]", "2": "소변량이 적은 경우 연결관의 꼬임 여부를 확인하는 것이 중요합니다.", "3": "소변주머니의 배출구는 비워도 세척할 필요가 없습니다.", "4": "유치도뇨관이 고정되어 있는지 수시로 당기는 것은 권장되지 않습니다.", "5": "하복부 불편 시에는 우선 원인을 파악하고 소변주머니를 비워야 합니다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "배뇨를 돕기 위해 삽입하는 카테터", "def_vi": "Ống được lắp đặt để hỗ trợ việc tiểu tiện"}, {"term_ko": "소변량", "term_vi": "Lượng nước tiểu", "def_ko": "소변의 양", "def_vi": "Số lượng nước tiểu"}, {"term_ko": "연결관", "term_vi": "Ống nối", "def_ko": "유치도뇨관과 소변주머니를 연결하는 관", "def_vi": "Ống kết nối giữa ống thông tiểu và túi nước tiểu"}, {"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 저장하기 위한 주머니", "def_vi": "Túi để lưu trữ nước tiểu"}, {"term_ko": "배출구", "term_vi": "Cửa xả", "def_ko": "소변주머니의 밝힐 수 있는 구멍", "def_vi": "Lỗ có thể xả nước tiểu từ túi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1295, '10', '유치도뇨관을 삽입하고 있는 대상자가 방광이 팽창하여 불편함을 호소할 때 올바른 돕기 방법은?', '["아랫배를 따뜻하게 해준다.", "소변주머니를 비워준다.", "연결관이 꺾여 있는지 확인한다.", "소변 줄을 팽팽하게 당겨 위치를 조정한다.", "수분 섭취량을 제한하고 금식하게 한다."]'::jsonb, 3, '유치도뇨관을 삽입한 환자가 방광의 팽창으로 인한 불편함을 느낄 때 적절한 도움을 통해 불편함을 해소하는 방법을 묻고 있다.', NULL, '{"1": "아랫배를 따뜻하게 해주면 불편함을 완화할 수 있지만, 문제의 근본적인 해결책이 아니다.\n[정답]", "2": "소변주머니를 비워주는 것은 방광의 압력을 줄이고 불편함을 완화시킬 수 있는 적절한 방법이다.", "3": "연결관이 꺾여 있는지를 확인하는 것은 불편함의 원인이 될 수 있는 요소를 점검하는 것이므로 중요하다.", "4": "소변 줄을 팽팽하게 당기는 것은 오히려 불편할 수 있으며, 잘못된 조치일 수 있다.", "5": "수분 섭취량을 제한하고 금식하게 하는 것은 불필요한 방법이며, 오히려 방광의 상태를 악화시킬 수 있다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "방광에 소변을 배출하는 튜브", "def_vi": "Ống dẫn nước tiểu đến bàng quang"}, {"term_ko": "방광", "term_vi": "Bàng quang", "def_ko": "소변을 저장하는 기관", "def_vi": "Cơ quan chứa nước tiểu"}, {"term_ko": "소변주머니", "term_vi": "Túi tiểu", "def_ko": "수집 용기", "def_vi": "Bình chứa nước tiểu"}, {"term_ko": "압력", "term_vi": "Áp lực", "def_ko": "힘, 압박", "def_vi": "Lực, sự áp bức"}, {"term_ko": "불편함", "term_vi": "Khó chịu", "def_ko": "괴로움, 고통", "def_vi": "Sự khó chịu, nỗi đau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1294, '10', '유치도뇨관을 삽입하고 있는 대상자의 소변주머니를 관리하는 방법은?', '["소변주머니는 정해진 시간에만 비운다.", "소변주머니는 1일 1회 세척한다.", "소변주머니를 비운 후 배출구를 잠근다.", "소변주머니의 배출구가 바닥에 닿게 놓는다.", "도뇨관과 소변주머니의 연결 부위를 분리하여 소변을 버린다."]'::jsonb, 3, '유치도뇨관 관리 및 소변주머니 관리의 중요성을 이해하도록 하는 문제입니다.', NULL, '{"1": "소변주머니는 정해진 시간에만 비우는 것은 적절하지 않습니다. 수시로 비워야 합니다.\n[정답]", "3": "소변주머니를 비운 후 배출구를 잠그는 것이 중요합니다. 감염 예방을 위해 배출구를 잠가야 합니다.", "2": "소변주머니는 1일 1회 세척하는 것은 부족합니다. 주기적으로 세척해야 합니다.", "4": "소변주머니의 배출구가 바닥에 닿게 놓는 것은 위생적이지 않으며, 감염의 위험을 높입니다.", "5": "도뇨관과 소변주머니의 연결 부위를 분리하여 소변을 버리는 것은 부적절합니다. 연결 부위를 항상 유지해야 합니다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "소변을 체외로 배출하기 위해 삽입되는 관", "def_vi": "Ống dùng để thoát nước tiểu ra ngoài cơ thể"}, {"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 모으는 주머니", "def_vi": "Túi đựng nước tiểu"}, {"term_ko": "세척", "term_vi": "Rửa", "def_ko": "깨끗이 씻어 내는 것", "def_vi": "Làm sạch"}, {"term_ko": "배출구", "term_vi": "Cửa xả", "def_ko": "소변을 배출하는 부분", "def_vi": "Phần thoát nước"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "바이러스나 세균에 의해 발생하는 질병", "def_vi": "Bệnh do virus hoặc vi khuẩn gây ra"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1293, '10', '대상자가 유치돈관을 사용할 때 돕는 방법으로 옳은 것은?', '["하루에 한 번 소변량과 색깔을 확인한다.", "소변주머니를 비운 후 배출구는 알코올 솜으로 닦는다.", "요도관이 빠진 경우 신속하게 끼워 넣는다.", "수분 섭취를 제한하여 배뇨량을 조절한다.", "소변을 보고 싶다고 하면 화장실을 이용하도록 돕는다."]'::jsonb, 2, '대상자가 유치돈관을 사용할 때의 올바른 관리 방법을 이해하고 있는지를 묻는 문제이다.', NULL, '{"1": "하루에 한 번 소변량과 색깔을 확인하는 것은 필요하지만, 유치돈관 관리의 핵심 항목은 아니다.\n[정답]", "2": "소변주머니를 비운 후 배출구는 알코올 솜으로 닦는 것이 옳은 방법이다. 이는 감염 예방을 위한 중요한 절차이다.", "3": "요도관이 빠진 경우 신속하게 끼워 넣는 것은 위험한 행동이다. 전문적인 도움을 받아야 한다.", "4": "수분 섭취를 제한하여 배뇨량을 조절하는 것은 권장되지 않는다. 오히려 충분한 수분 섭취가 필요하다.", "5": "소변을 보고 싶다고 하면 화장실을 이용하도록 돕는 것이 좋지만, 유치돈관을 사용하는 목적에 따라 소변주머니를 이용하도록 해야 한다."}'::jsonb, '[{"term_ko": "유치돈관", "term_vi": "Ống thông tiểu", "def_ko": "배뇨를 돕기 위해 삽입하는 관", "def_vi": "Ống được đưa vào để hỗ trợ việc tiểu tiện"}, {"term_ko": "소변", "term_vi": "Nước tiểu", "def_ko": "배출된 액체", "def_vi": "Chất lỏng thải ra"}, {"term_ko": "소변주머니", "term_vi": "Túi đựng nước tiểu", "def_ko": "소변을 모으는 기구", "def_vi": "Thiết bị thu gom nước tiểu"}, {"term_ko": "알코올 솜", "term_vi": "Bông cồn", "def_ko": "세균을 제거하는 데 사용하는 물체", "def_vi": "Đối tượng được sử dụng để loại bỏ vi khuẩn"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "병원균에 의해 신체가 영향을 받는 상태", "def_vi": "Tình trạng cơ thể bị ảnh hưởng bởi vi khuẩn"}, {"term_ko": "배뇨", "term_vi": "Tiểu tiện", "def_ko": "소변을 보는 행위", "def_vi": "Hành động đi tiểu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1292, '10', '유치도뇨관을 삽입하고 있는 대상자를 돕는 방법은?', '["자유로이 움직일 수 있다고 알려 준다.", "소변주머니는 매 식사 전에 비워준다.", "도뇨관이 막힌 경우 즉시 교체한다.", "프로그램에 참여하는 동안에는 연결관을 잠근다.", "소변주머니에서 냄새가 나면 주머니를 세척한다."]'::jsonb, 1, '대상자의 유치도뇨관 관리와 관련된 안전한 행동을 이해하도록 돕기 위함입니다.', NULL, '{"1": "유치도뇨관을 사용하는 대상자는 약간의 이동이 가능하므로 자유롭게 움직일 수 있다고 알려주는 것이 중요합니다.\n[정답]", "2": "소변주머니는 매 식사 전에 비워주는 것이 아니라 필요에 따라 비워야 합니다.", "3": "도뇨관이 막힌 경우, 즉시 교체하는 것이 아니라 의료진에게 보고하여 적절한 처치를 받도록 해야 합니다.", "4": "프로그램에 참여하는 동안 연결관을 잠그면 소변이 제대로 흐르지 않을 수 있으므로, 이 방법은 잘못된 접근입니다.", "5": "소변주머니에서 냄새가 나면 주머니를 세척하는 것이 아니라, 소변주머니를 청결하게 유지해야 하며, 필요시 교체해야 합니다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Đường ống dẫn tiểu", "def_ko": "체내에 넣어 소변을 배출하는 관", "def_vi": "Ống được đưa vào cơ thể để dẫn nước tiểu ra ngoài"}, {"term_ko": "소변주머니", "term_vi": "Túi đựng nước tiểu", "def_ko": "소변을 담는 주머니", "def_vi": "Túi chứa nước tiểu"}, {"term_ko": "교체", "term_vi": "Thay thế", "def_ko": "바꾸다", "def_vi": "Thay đổi"}, {"term_ko": "냄새", "term_vi": "Mùi", "def_ko": "특정한 기운", "def_vi": "Một mùi nhất định"}, {"term_ko": "막히다", "term_vi": "Bị tắc", "def_ko": "통과가 막히다", "def_vi": "Bị chặn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1291, '10', '유치도뇨관을 사용하는 대상자를 돕는 방법으로 옳은 것은??', '["소변량, 색깔을 매 2~3시간 마다 확인한다.", "걸을 때는 소변주머니를 아랫배보다 높이 든다.", "도뇨관 밖으로 소변이 새는 경우 즉시 교체한다.", "소변주머니는 가득 찰 때까지 기다렸다가 비운다.", "소변색이 이상하거나 탁해진 경우 즉시 버린다."]'::jsonb, 1, '유치도뇨관을 사용하는 대상자에게 적절한 관리방법을 이해하고 있는지 확인하기 위함이다.', NULL, '{"1": "소변량과 색깔을 정기적으로 확인하는 것은 필수적이며, 건강 상태를 모니터링하는 데 중요한 방법이다.\n[정답]", "2": "걸을 때는 소변주머니를 아랫배보다 낮게 두어야 소변 흐름을 원활히 한다.", "3": "도뇨관 밖으로 소변이 새는 경우는 즉시 교체하기 보다는 원인을 확인해야 한다.", "4": "소변주머니는 가득 찰 때까지 기다리지 말고, 정기적으로 비워야 감염 예방에 도움이 된다.", "5": "소변색이 이상할 경우 즉시 버리기보다는 의사의 진료를 받는 것이 적절하다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "소변을 배출하기 위해 체내에 삽입하는 관", "def_vi": "Ống được đưa vào cơ thể để thoát nước tiểu"}, {"term_ko": "소변량", "term_vi": "Lượng nước tiểu", "def_ko": "배출되는 소변의 양", "def_vi": "Số lượng nước tiểu được thải"}, {"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 모으는 용기", "def_vi": "Bình chứa nước tiểu"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "병균이나 바이러스에 의해 일어나는 질병", "def_vi": "Bệnh do vi khuẩn hoặc virus gây ra"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1290, '10', '소변주머니를 방광의 위치보다 낮게 두어야 하는 이유는?', '["역류성 감염을 예방하기 위해", "보행의 편의를 위해", "유치도뇨관이 빠지지 않게 하기 위해", "냄새의 유출을 방지하기 위해", "연결관이 꺾이지 않게 하기 위해"]'::jsonb, 1, '소변주머니의 위치와 관련된 위생적 측면을 이해하도록 유도하는 문제입니다.', NULL, '{"1": "소변주머니를 방광보다 낮게 두어야 하여 역류하는 소변으로 인해 감염이 발생하지 않도록 예방해야 합니다.\n[정답]", "2": "보행의 편의를 위해 소변주머니를 낮게 두는 것은 주 목적이 아닙니다.", "3": "유치도뇨관이 빠지지 않게 하기 위해서는 주의가 필요하지만, 위치와는 큰 관련이 없습니다.", "4": "냄새의 유출을 방지하는 것도 고려해야 할 사항이나, 주된 이유는 아닙니다.", "5": "연결관이 꺾이지 않게 하는 것은 편의성을 위한 것이나, 감염 예방이 우선입니다."}'::jsonb, '[{"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 모으는 주머니", "def_vi": "Túi để chứa nước tiểu"}, {"term_ko": "방광", "term_vi": "Bàng quang", "def_ko": "소변이 저장되는 기관", "def_vi": "Cơ quan lưu trữ nước tiểu"}, {"term_ko": "역류", "term_vi": "Trào ngược", "def_ko": "물이 거꾸로 흐르는 현상", "def_vi": "Hiện tượng nước chảy ngược"}, {"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "소변을 계속 뽑아내는 도관", "def_vi": "Đường ống để dẫn nước tiểu ra ngoài"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "세균이나 바이러스로 인해 병이 생기는 것", "def_vi": "Bệnh do vi khuẩn hoặc virus gây ra"}, {"term_ko": "냄새", "term_vi": "Mùi hôi", "def_ko": "불쾌한 향기", "def_vi": "Mùi khó chịu"}, {"term_ko": "연결관", "term_vi": "Ống nối", "def_ko": "두 개의 기구를 연결하는 관", "def_vi": "Ống dùng để kết nối hai thiết bị"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1289, '10', '대상자가 유치도뇨관을 사용할 때 돕는 방법으로 옳은 것은?', '["소변주머니는 매일 교체한다.", "소변주머니는 방광의 위치보다 낮게 둔다.", "방광에 통증이 오면 즉시 유치도뇨관을 빼준다.", "연결관이 빠지지 않도록 침상에 누워 있게 한다.", "소변주머니에 소변이 고이지 않을 경우 하복부를 눌러준다."]'::jsonb, 2, '대상자가 유치도뇨관을 사용하는 경우 안전하고 효과적으로 관리할 수 있는 방법을 이해하고 있는지를 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "소변주머니는 하루에 한 번 이상 정기적으로 교체해야 하지만, 매일 교체하는 것은 필요하지 않다. \n[정답]", "2": "소변주머니는 방광의 위치보다 낮게 두어야 하여 소변이 자연스럽게 흐를 수 있도록 해야 한다.", "3": "방광에 통증이 올 경우에는 우선적으로 의료진과 상담해야 하며, 즉시 제거하는 것은 바람직하지 않다.", "4": "연결관이 빠지지 않도록 침상에서 안정적으로 지내는 것도 중요하지만, 눕는 것만으로는 부족하다.", "5": "소변주머니에 소변이 고이지 않을 경우 하복부를 눌러주는 것은 부적절한 방법이며, 다른 방안으로 문제를 해결해야 한다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "방광에 소변을 배출하기 위해 삽입되는 관", "def_vi": "Ống được đưa vào bàng quang để thoát nước tiểu"}, {"term_ko": "소변주머니", "term_vi": "Túi đựng nước tiểu", "def_ko": "소변을 수집하는 주머니", "def_vi": "Túi để thu thập nước tiểu"}, {"term_ko": "방광", "term_vi": "Bàng quang", "def_ko": "소변이 저장되는 기관", "def_vi": "Cơ quan lưu trữ nước tiểu"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "신체의 고통이나 불편함", "def_vi": "Cơn đau hoặc khó chịu trên cơ thể"}, {"term_ko": "침상", "term_vi": "Giường", "def_ko": "누워 있는 장소", "def_vi": "Nơi để nằm"}, {"term_ko": "하복부", "term_vi": "Hạ bụng", "def_ko": "복부의 아랫부분", "def_vi": "Phần bụng dưới"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1288, '10', '침상에 누워있는 대상자의 기저귀 사용을 돕는 방법은?', '["대상자가 거부하면 교체하지 않는다.", "기저귀를 교환할 때마다 시설장에게 보고한다.", "피부가 붉어진 경우 더운 물주머니를 대어 준다.", "기저귀가 뭉치지 않도록 잘 펴서 둔부를 감싸준다.", "엉덩이에 발적이 있으면 도넛 모양의 베개를 대어 준다."]'::jsonb, 4, '기저귀 사용에 대한 적절한 관리 방법을 평가하고 바른 지식을 습득하도록 하는 것.', NULL, '{"1": "대상자가 거부하면 기저귀를 교체하지 않으면 안됩니다. 환자의 편안함과 위생을 위해서는 필요한 경우 반드시 교체해야 합니다.\n[정답]", "4": "기저귀를 교환할 때는 누워 있는 대상자의 엉덩이가 아프지 않도록 잘 펴서 감싸주는 것이 매우 중요합니다.", "2": "기저귀 교환 시 시설장에게 보고하는 것은 일반적이지 않으며, 필요할 경우 보호자나 다른 간호 인력에게 보고합니다.", "3": "피부가 붉어진 경우에는 더운 물주머니를 사용하여 마사지할 것이 아니라 적절한 피부 간호를 해야 합니다.", "5": "엉덩이에 발적이 있다고 해서 도넛 모양의 베개를 즉각 대주는 것은 필요한 조치가 아닙니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "Tã lót"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Người nhận điều trị"}, {"term_ko": "엉덩이", "term_vi": "Mông", "def_ko": "엉덩이(한국어)", "def_vi": "Mông"}, {"term_ko": "발적", "term_vi": "Đỏ da", "def_ko": "발적(한국어)", "def_vi": "Đỏ da"}, {"term_ko": "교체", "term_vi": "Thay", "def_ko": "교체하다(한국어)", "def_vi": "Thay thế"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1287, '10', '침상에서 대상자의 기저귀를 교환하는 방법으로 옳은 것은?', '["윗옷을 가슴까지 올리고 바지를 벗긴다.", "무릎을 편 상태에서 허리를 들어 올린다.", "둔부 밑에 새 기저귀의 바깥면이 보이도록 한다.", "기저귀를 교환하는 동안 창문을 열어 환기한다.", "꼬리뼈 부위에 피부 발적이 있는지 살펴본다."]'::jsonb, 5, '기저귀 교환 시 올바른 방법과 주의 사항을 파악하기 위한 문제입니다.', NULL, '{"1": "윗옷을 가슴까지 올리고 바지를 벗기는 것은 환자의 편안함을 고려하지 않은 방법입니다.\n[정답]", "5": "꼬리뼈 부위에 피부 발적이 있는지 살펴보는 것은 기저귀 교환 시 중요한 피부 상태 확인 방법입니다.", "2": "무릎을 편 상태에서 허리를 들어 올리는 것은 수동적인 방법이며 환자에게 부담을 줄 수 있습니다.", "3": "둔부 밑에 새 기저귀의 바깥면이 보이도록 한다는 것은 올바른 교환 방법이 아닌 장비 배치의 의미가 아닙니다.", "4": "기저귀를 교환하는 동안 창문을 열어 환기하는 것은 필요할 수도 있으나 안전이나 프라이버시와 관련된 문제를 고려해야 합니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "Tã"}, {"term_ko": "꼬리뼈", "term_vi": "Xương cụt", "def_ko": "xương cụt(한국어)", "def_vi": "xương cụt"}, {"term_ko": "피부", "term_vi": "Da", "def_ko": "피부(한국어)", "def_vi": "Da"}, {"term_ko": "환기", "term_vi": "Thông gió", "def_ko": "환기(한국어)", "def_vi": "thông gió"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1286, '10', '대상자의 기저귀를 교환하는 방법으로 옳은 것은?', '["기저귀는 정해진 시간에 교환한다.", "이불을 다리 아래로 내린 후에 면덮개를 덮는다.", "기저귀를 교환하는 동안에 문을 열어 환기한다.", "허리를 들 수 있는 대상자는 옆으로 돌려 눕혀 교환한다.", "오염된 기저귀는 바깥 면이 보이도록 말아서 버린다."]'::jsonb, 5, '기저귀 교환의 올바른 절차와 주의 사항을 이해하고 이행하는 능력을 평가하기 위한 문제입니다.', NULL, '{"1": "기저귀는 주기적으로 교환해야 하지만, 정해진 시간에만 교환하는 것은 적절하지 않습니다.\n[정답]", "5": "오염된 기저귀는 항상 바깥 면이 보이도록 말아서 버려야 합니다. 이는 위생상의 이유로 매우 중요합니다.", "2": "이불을 다리 아래로 내린 후에 면덮개를 덮는 것은 일반적으로 권장하지 않는 방법입니다.", "3": "기저귀를 교환하는 동안 문을 열어 두는 것은 환기를 위해 좋지 않으며, 개인 정보 보호 측면에서도 문제가 됩니다.", "4": "허리를 들 수 있는 대상자는 옆으로 돌려 눕혀 교환하는 것이 올바른 방법입니다. 그러나 이 방식은 대상자의 상태에 따라 다르게 적용될 수 있습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "Tã(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1285, '10', '기저귀를 교환할 때 대상자의 둔부를 가볍게 두드려 마사지하는 이유는?', '["변의 자극", "근육 이완", "욕창 예방", "장운동 촉진", "호르몬 분비 촉진"]'::jsonb, 3, '기저귀 교환 시 마사지의 중요성을 이해하고, 어떤 효과를 목적으로 하는지 파악하는 것이다.', NULL, '{"1": "변의 자극: 변의 자극을 위한 것이 아니다. \n[정답]", "3": "욕창 예방: 마사지가 둔부의 혈액순환을 도와 욕창을 예방하는 효과가 있다.", "2": "근육 이완: 마사지가 근육 이완의 목적이 아니므로 정답이 아니다.", "4": "장운동 촉진: 장운동 촉진과는 관련이 없다.", "5": "호르몬 분비 촉진: 호르몬 분비와는 관련이 없다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "Tã"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1284, '10', '허리를 들 수 없는 대상자의 기저귀를 교환하는 방법은?', '["둔부는 수시로 알코올 소독 한다.", "둔부를 들어 방수포를 깔아 준다.", "대상자를 옆으로 돌려 눕혀 기저귀를 갈아준다.", "무릎을 세우고 똑바로 누운 상태에서 갈아준다.", "냄새가 나지 않도록 기저귀를 단단히 조인다."]'::jsonb, 3, '대상자의 상태에 따라 기저귀 교환 방법을 적절히 선택하는 능력을 평가하기 위함입니다.', NULL, '{"1": "둔부는 수시로 알코올 소독 한다. - 소독은 필요하지만, 허리를 들 수 없는 환자에 대한 적절한 방법이 아닙니다.\n[정답]", "2": "대상자를 옆으로 돌려 눕혀 기저귀를 갈아준다. - 허리를 들 수 없는 경우, 옆으로 눕혀서 기저귀를 교환하는 것이 가장 안전하고 효율적인 방법입니다.", "3": "무릎을 세우고 똑바로 누운 상태에서 갈아준다. - 허리가 불편한 환자에게는 적합하지 않은 방법입니다.", "4": "둔부를 들어 방수포를 깔아 준다. - 둔부를 들어주는 방법은 허리를 들 수 없는 대상자에게 적합하지 않습니다.", "5": "냄새가 나지 않도록 기저귀를 단단히 조인다. - 기저귀의 새는 것을 방지하는 방법은 필요하지만, 이 질문의 주제와는 관련이 없습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "tã"}, {"term_ko": "듬부", "term_vi": "Mông", "def_ko": "둔부(한국어)", "def_vi": "mông"}, {"term_ko": "소독", "term_vi": "Khử trùng", "def_ko": "소독(한국어)", "def_vi": "Khử trùng"}, {"term_ko": "상태", "term_vi": "Tình trạng", "def_ko": "상태(한국어)", "def_vi": "tình trạng"}, {"term_ko": "세우다", "term_vi": "Đứng", "def_ko": "세우다(한국어)", "def_vi": "đứng"}, {"term_ko": "눕다", "term_vi": "Nằm", "def_ko": "눕다(한국어)", "def_vi": "nằm"}, {"term_ko": "방수포", "term_vi": "Tấm trải chống thấm", "def_ko": "방수포(한국어)", "def_vi": "tấm trải chống thấm"}, {"term_ko": "조인다", "term_vi": "Cài", "def_ko": "조인다(한국어)", "def_vi": "cài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1283, '10', '기저귀를 사용하는 대상자를 돕는 방법으로 옳은 것은?', '["둔부에 발적이 있으면 연고를 발라준다.", "둔부주변을 강한 압력으로 마사지해 준다.", "기저귀에 소변이 조금 묻은 경우 말려서 재사용 한다.", "허리를 들 수 없으면 엎드린 채로 기저귀를 교환한다.", "교환 전에 면덮개를 이불 위에 덮은 후 이불만 다리 아래로 내린다."]'::jsonb, 5, '기저귀를 사용하는 대상자에 대한 올바른 관리 방법을 평가하기 위함입니다.', NULL, '{"1": "둔부에 발적이 있을 경우 연고를 발라주는 것은 필요하지만, 대상자를 돕는 방법으로는 적절하지 않습니다.\n[정답]", "5": "면덮개를 이불 위에 덮고 이불만 다리 아래로 내리는 방법은 기저귀 교환 시 안전하고 위생적인 접근법입니다.", "3": "기저귀에 소변이 묻은 경우, 재사용하는 것은 위생적이지 않으므로 옳지 않습니다.", "2": "강한 압력으로 마사지를 하는 것은 피부 손상을 유발할 수 있으므로 바람직하지 않습니다.", "4": "허리를 들 수 없는 경우에는 엎드린 채 기저귀를 교환하는 것은 안전하지 않으며 권장되지 않습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "기저귀(한국어)", "def_vi": "Bỉm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1282, '10', '기저귀를 사용하는 대상자를 돕는 방법은?', '["기저귀를 사용해도 변기 사용을 시도한다.", "회음부는 뒤에서 앞으로 닦아준다.", "물티슈로 닦아내고 바로 기저귀를 채운다.", "하루에 세 번 규칙적으로 기저귀를 갈아준다.", "피부 발적이 보이면 문지르며 마사지해준다."]'::jsonb, 1, '기저귀를 사용하는 대상자에게 올바른 돌봄 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "기저귀를 사용하더라도 변기 사용을 시도할 수 있는 환경을 조성하는 것이 좋습니다.\n[정답]", "2": "회음부는 앞에서 뒤로 닦아야 감염 예방에 도움이 됩니다.", "3": "물티슈로 닦은 후 기저귀를 바로 채우는 것은 올바르지 않으며, 피부 건조가 필요합니다.", "4": "기저귀를 하루에 세 번 갈기보다는 피부 상태에 따라 유동적으로 갈아야 합니다.", "5": "피부 발적이 있을 때는 문지르지 않고, 피부에 적절한 크림을 사용하여 진정시키는 것이 필요합니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "기저귀(한국어)", "def_vi": "bỉm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1281, '10', '대상자가 몇 번 실금을 했어도 기저귀를 바로 사용하면 안 되는 이유는?', '["욕창이 발생하기 때문에", "움직임이 제한되기 때문에", "기저귀 구입 비용이 부담되기 때문에", "비뇨기계 감염 발생이 우려되기 때문에", "스스로 배설하는 습관이 약화될 수 있기 때문에"]'::jsonb, 5, '대상자의 배설 습관을 고려하고, 기저귀 사용이 스스로의 배설 능력에 미치는 영향을 이해하게 하려는 의도입니다.', NULL, '{"1": "욕창이 발생하기 때문에\n욕창은 기저귀 사용으로 인한 압력이 원인이 될 수 있지만, 실금 여부와 직접적인 관계는 없습니다.\n[정답]", "5": "스스로 배설하는 습관이 약화될 수 있기 때문에\n기저귀를 자주 사용하게 되면 배설의 자연스러운 패턴이 무너질 수 있습니다.", "2": "움직임이 제한되기 때문에\n기저귀 사용이 운동능력을 제한하는 것은 아니므로 해당 이유는 아닙니다.", "3": "기저귀 구입 비용이 부담되기 때문에\n비용 문제는 의학적 결정에 영향을 미치는 주된 요소가 아닙니다.", "4": "비뇨기계 감염 발생이 우려되기 때문에\n비뇨기계 감염은 기저귀 사용의 결과일 수 있지만, 직접적인 실금 상황에서의 이유는 아닙니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "실금", "term_vi": "Tiểu không tự chủ", "def_ko": "소변을 자제하지 못하는 상태", "def_vi": "Trạng thái không kiểm soát được việc tiểu tiện"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "아기용 기저귀", "def_vi": "Tã lót trẻ em"}, {"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부 손상 상태", "def_vi": "Tổn thương da"}, {"term_ko": "배설", "term_vi": "Đi tiểu", "def_ko": "소변 또는 대변을 배출하는 행동", "def_vi": "Hành động đi tiểu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1280, '10', '대상자가 몇 번 실금을 했어도 기저귀를 바로 사용하면 안 되는 이유는?', '["욕창이 발생하기 때문에", "움직임이 제한되기 때문에", "기저귀 구입 비용이 부담되기 때문에", "비뇨기계 감염 발생이 우려되기 때문에", "스스로 배설하는 습관이 약화될 수 있기 때문에"]'::jsonb, 5, '기저귀 사용과 관련된 문제로, 대상자의 배설 습관이 약화될 수 있는 이유를 묻고 있다.', NULL, '{"1": "욕창이 발생하기 때문에\n기저귀를 사용한다고 해서 바로 욕창이 발생하지는 않는다. 따라서 이 보기는 적절하지 않다.\n[정답]", "5": "스스로 배설하는 습관이 약화될 수 있기 때문에\n기저귀를 자주 사용하면 스스로 배설하는 습관이 약화될 수 있어 정답이다.", "2": "움직임이 제한되기 때문에\n기저귀 사용은 움직임과는 직접적인 관련이 없다.", "3": "기저귀 구입 비용이 부담되기 때문에\n비용 문제는 직접적인 이유가 아니다.", "4": "비뇨기계 감염 발생이 우려되기 때문에\n기저귀 사용이 꼭 비뇨기계 감염을 유발한다고 할 수 없다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "기저귀(한국어)", "def_vi": "Bỉm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1279, '10', '기저귀가 젖었을 때 속히 갈아주어야 하는 이유는?', '["혈액순환을 촉진하기 위해", "요실금 횟수를 줄이기 위해", "피부 손상을 예방하기 위해", "기저귀 의존성을 줄이기 위해", "체온이 떨어지는 것을 막기 위해"]'::jsonb, 3, '기저귀 교체의 중요성을 이해하고, 피부 건강을 유지하는 방법을 파악하기 위함입니다.', NULL, '{"1": "혈액순환을 촉진하기 위해: 기저귀 갈기는 혈액순환과 직접적으로 관련이 없습니다.\n[정답]", "3": "피부 손상을 예방하기 위해: 기저귀가 젖으면 피부에 자극이 되고 손상을 줄 수 있으므로, 이로 인해 빠른 교체가 필요합니다.", "2": "요실금 횟수를 줄이기 위해: 기저귀 교체는 요실금 관리를 위한 것이 아닙니다.", "4": "기저귀 의존성을 줄이기 위해: 기저귀 교체는 의존성과는 관련이 없습니다.", "5": "체온이 떨어지는 것을 막기 위해: 기저귀 교체는 체온 유지와 직접적인 관련이 없습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "Tã(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1278, '10', '기저귀를 장시간 교체하지 않을 경우 대상자에게 발생할 수 있는 질환은?', '["건선", "대상포진", "피부발적", "건조증", "아토피 피부염"]'::jsonb, 3, '기저귀를 장시간 교체하지 않을 경우 발생할 수 있는 피부 질환을 파악하는 것이다.', NULL, '{"1": "건선: 만성 염증성 피부 질환으로, 기저귀와는 관련이 없다.\n[정답]", "3": "피부발적: 장시간 기저귀를 착용하면 피부가 자극을 받아 발적이 발생할 수 있다.", "2": "대상포진: 바이러스성 질환으로 기저귀와는 관련이 없다.", "4": "건조증: 주로 수분 부족으로 발생하며, 기저귀 사용과 직접적인 연관은 없다.", "5": "아토피 피부염: 알레르기성 피부 질환이지만 기저귀 사용으로 인해 직접적으로 발생하지 않는다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "tã(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1277, '10', '대상자가 장기적으로 기저귀를 사용할 때 돕는 방법으로 옳은 것은?', '["오염된 둔부는 마른 수건으로 닦고 건조시킨다.", "피부발적, 상처, 통증을 호소하는지 살핀다.", "환기를 위해 창문을 열고 교체한다.", "하루 세 번 정해진 시간에 갈아준다.", "피부 상태를 확인하기 위해 하의를 벗겨둔다."]'::jsonb, 2, '대상자의 기저귀 사용시 피부 상태를 점검하고 관리하는 방법을 묻는 문제입니다.', NULL, '{"1": "오염된 둔부는 마른 수건으로 닦고 건조시킨다는 것은 부적절한 방법입니다. 적절한 세정이 필요합니다.\n[정답]", "2": "피부발적, 상처, 통증을 호소하는지를 살핀다는 것은 매우 중요한 관리 방법입니다.", "3": "환기를 위해 창문을 열고 교체하는 것은 상황에 따라 필요할 수 있지만, 직접적인 기저귀 교체 방법은 아닙니다.", "4": "하루 세 번 정해진 시간에 갈아주는 것은 각 대상자의 상태에 따라 다를 수 있습니다.", "5": "피부 상태를 확인하기 위해 하의를 벗겨둔다면 불필요한 노출이 될 수 있어 주의해야 합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1276, '10', '누워있는 대상자의 기저귀 사용을 돕는 방법으로 옳은 것은?', '["대상자가 실금하면 바로 기저귀를 채운다.", "기저귀를 한 번 사용하면 계속 채운다.", "젖은 기저귀 안에 속 기저귀를 덧대어 준다.", "배뇨, 배변 시간에 맞추어 기저귀를 자주 살펴본다.", "기저귀를 깨끗이 갈아주기 위해서 최대한 신체노출을 한다."]'::jsonb, 4, '대상자의 기저귀 사용에 대한 올바른 방법을 이해하는지를 평가하기 위함입니다.', NULL, '{"1": "대상자가 실금하면 즉시 기저귀를 채우는 것은 맞지 않으며, 우선 청결과 안전을 고려해야 합니다.\n[정답]", "4": "배뇨, 배변 시간에 맞추어 기저귀를 자주 살펴보는 것이 올바른 방법입니다.", "2": "한 번 사용한 기저귀를 계속 사용하는 것은 위생적으로 바람직하지 않습니다.", "3": "젖은 기저귀 안에 속 기저귀를 덧대어 주는 것은 불쾌감을 초래할 수 있으며, 권장되지 않습니다.", "5": "기저귀를 갈아주기 위해 최대한 신체노출을 하는 것은 대상자의 사생활을 존중하지 않는 행동입니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "속옷(한국어)", "def_vi": "Tã của người dùng"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Người bệnh"}, {"term_ko": "실금", "term_vi": "Tiểu không kiểm soát", "def_ko": "소변 누출(한국어)", "def_vi": "Sự mất kiểm soát khi tiểu tiện"}, {"term_ko": "배뇨", "term_vi": "Đi tiểu", "def_ko": "소변을 보는 행위(한국어)", "def_vi": "Hành động đi tiểu"}, {"term_ko": "청결", "term_vi": "Sạch sẽ", "def_ko": "깨끗한 상태(한국어)", "def_vi": "Trạng thái sạch sẽ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1275, '10', '기저귀 사용 돕기 중 기저귀를 채우는 시점으로 옳은 것은?', '["배설욕구를 전혀 느끼지 못하는 경우", "화장실에 가기 싫어하는 경우", "실금이 가끔씩 나타나는 경우", "약간의 도움으로 이동이 가능한 경우", "다리부상으로 허리를 들 수 있는 경우"]'::jsonb, 1, '기저귀 사용의 적절한 시점을 이해하고, 이를 통해 올바른 요양보조 방법을 익히도록 하는 것이 문제의 의도입니다.', NULL, '{"1": "기저귀를 채우는 핵심 조건으로, 배설욕구를 전혀 느끼지 못하는 경우에는 기저귀 사용이 필수적입니다.\n[정답]", "2": "화장실에 가기 싫어하는 경우는 기저귀 사용을 정당화하지 않는 상황입니다.", "3": "실금이 가끔씩 나타나는 경우는 기저귀 사용을 고려해야 하나, 항상 필요한 것은 아닙니다.", "4": "약간의 도움으로 이동이 가능한 경우는 화장실 이용이 가능할 수 있어 기저귀 사용의 필요성이 낮아집니다.", "5": "다리부상으로 허리를 들 수 있는 경우도 화장실에 갈 수 있는지의 여부에 따라 기저귀 필요성이 달라질 수 있습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "Tã"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1274, '10', '편마비 대상자의 이동변기 사용을 돕는 순서로 옳은 것은?가. 배설 중에 하반신을 수건이나 무릎덮개로 덮어준다. 나. 커튼이나 스크린으로 가려준다. 다. 이동변기를 대상자의 건강한 쪽에 붙인다. 라. 침대 높이와 이동변기의 높이가 같도록 맞춘다.', '["가 - 나 - 다 - 라", "나- 라 - 다 - 가", "나 - 다 - 라 - 가", "다 - 가 - 라 - 나", "라 - 나 - 다 - 가"]'::jsonb, 2, '편마비 특성을 고려하여 개인의 배변을 도와주는 적절한 절차를 이해하고자 함.', NULL, '{"1": "배설 중 개인의 사생활을 존중하기 위해 하반신을 덮어주는 것은 중요하다.\n[정답]", "2": "배설을 할 때 커튼이나 스크린으로 가려서 사생활을 보호하는 것이 우선이다.", "3": "건강한 쪽에 이동변기를 붙이는 것은 대상자의 편안함과 안정성을 증가시킨다.", "4": "침대 높이와 이동변기의 높이를 맞추는 것은 물리적 이동을 용이하게 하여 안전성을 높인다.", "5": "순서대로 진행되는 것이 아니라, 상황별로 적절한 조치를 취해야 한다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽 몸이 마비된 상태", "def_vi": "Tình trạng bị liệt một bên cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1273, '10', '오른쪽 편마비 대상자의 이동변기 사용을 돕는 방법은?', '["대상자의 오른쪽에 이동변기를 놓는다.", "이동변기 밑에 작은 수건을 깔아준다.", "변기 손잡이를 오른손으로 잡게 한다.", "이동변기를 조절하여 두 발이 바닥에 닿게 한다.", "배설 중에는 몸이 기울지 않도록 왼쪽을 지지해준다."]'::jsonb, 4, '오른쪽 편마비 대상자가 안전하게 이동변기를 사용할 수 있도록 돕는 방법을 묻는 문제입니다.', NULL, '{"1": "대상자의 오른쪽에 이동변기를 놓는 것은 편마비 환자에게 오히려 불편을 줄 수 있습니다.\n[정답]", "4": "이동변기를 조절하여 두 발이 바닥에 닿게 하는 것은 안정적인 자세를 유지하도록 도와주는 중요한 방법입니다.", "2": "이동변기 밑에 작은 수건을 깔아주는 것은 청결을 유지하는 방법일 수 있지만, 이동변기 사용을 직접 도와주기 위한 방법은 아닙니다.", "3": "변기 손잡이를 오른손으로 잡게 하는 것은 오른쪽 편마비 대상자에게는 도움이 되지 않습니다.", "5": "배설 중 몸이 기울지 않도록 왼쪽을 지지해주는 것은 좋지만, 이동변기를 올바로 조정하는 것이 더 중요합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 팔과 다리에 힘이 없고 움직이지 못하는 상태", "def_vi": "Tình trạng không có sức và không thể di chuyển một bên cánh tay và chân"}, {"term_ko": "이동변기", "term_vi": "Bồn cầu di động", "def_ko": "이동식 화장실", "def_vi": "Cái bồn cầu có thể di chuyển"}, {"term_ko": "손잡이", "term_vi": "Tay nắm", "def_ko": "잡을 수 있는 부분", "def_vi": "Phần để có thể cầm"}, {"term_ko": "배설", "term_vi": "Đại tiện", "def_ko": "소변 또는 대변을 보는 행위", "def_vi": "Hành động đi vệ sinh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1272, '10', '대상자의 이동변기 사용을 돕는 방법으로 옳은 것은?', '["이동변기는 하루에 한번 세척한다.", "수치심을 일으키지 않도록 스크린을 설치해준다.", "배변 중 환기를 위해 창문을 열어 둔다.", "대상자의 두 발이 바닥에 닿지 않게 한다.", "배설 시 조용한 환경을 만들어 준다."]'::jsonb, 2, '대상자의 이동변기 사용 시 올바른 지원 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "이동변기는 청결 유지를 위해 필요한 빈도에 따라 세척해야 합니다. 하루에 한 번만 세척하는 것은 부족할 수 있습니다.\n[정답]", "2": "수치심을 줄이기 위해 스크린을 설치하는 것은 매우 중요합니다. 이는 대상자가 보다 편안하게 배변할 수 있도록 도와줍니다.", "3": "배변 중 환기를 위해 창문을 여는 것은 허용될 수 있지만, 환자의 안전과 사생활을 고려해야 합니다.", "4": "대상자의 두 발이 바닥에 닿지 않도록 하려면 안전한 자세를 유지하기 어려울 수 있으므로, 바닥에 닿게 하는 것이 바람직합니다.", "5": "배설 시 조용한 환경을 제공하는 것도 중요하지만, 이 문제에서 가장 핵심적인 지원 방법은 아닌 것으로 보입니다."}'::jsonb, '[{"term_ko": "이동변기", "term_vi": "Bô di động", "def_ko": "이동 가능한 화장실", "def_vi": "Nhà vệ sinh di động"}, {"term_ko": "수치심", "term_vi": "Cảm giác xấu hổ", "def_ko": "부끄러움, 창피함", "def_vi": "Sự xấu hổ"}, {"term_ko": "스크린", "term_vi": "Màn chắn", "def_ko": "분리막", "def_vi": "Màn ngăn"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "환경", "def_vi": "Môi trường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1271, '10', '편마비 대상자의 이동변기 사용을 돕는 방법으로 옳은 것은?', '["변기는 불편한 쪽으로 45도 각도로 놓는다.", "이동변기 앞에 미끄럼방지 매트를 깔아 둔다.", "침대와 변기의 높이가 같도록 맞춰준다.", "차가운 물을 끼얹어 변의를 자극한다.", "배설 후에는 물티슈로 손을 닦게 한다."]'::jsonb, 3, '편마비 대상자가 이동변기를 안전하고 편리하게 사용할 수 있도록 돕는 방법에 대한 이해 확인.', NULL, '{"1": "변기를 불편한 쪽으로 45도 각도로 놓는 것은 오히려 안전하지 않을 수 있다.\n[정답]", "2": "이동변기 앞에 미끄럼방지 매트를 깔아 두는 것은 안전을 위해 중요하지만 정답이 아니다.", "3": "침대와 변기의 높이가 같도록 맞춰주는 것이 편마비 대상자가 이동변기를 사용할 때 가장 안전하고 편리하다.", "4": "차가운 물을 끼얹어 변의를 자극하는 것은 비인간적이며 건강에 해로울 수 있다.", "5": "배설 후에는 물티슈로 손을 닦는 것은 위생적이지 않으며, 손 씻기가 더 바람직하다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽 몸이 마비된 상태", "def_vi": "Tình trạng bị liệt một bên cơ thể"}, {"term_ko": "이동변기", "term_vi": "Bồn vệ sinh di động", "def_ko": "이동용 화장실", "def_vi": "Nhà vệ sinh di động"}, {"term_ko": "미끄럼방지 매트", "term_vi": "Thảm chống trượt", "def_ko": "미끄럼 방지를 위한 매트", "def_vi": "Thảm chống trượt"}, {"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "소변과 대변의 배출", "def_vi": "Sự bài tiết"}, {"term_ko": "물티슈", "term_vi": "Khăn ướt", "def_ko": "물로 적신 티슈", "def_vi": "Khăn thấm nước"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1270, '10', '이동변기 사용 돕기의 방법으로 옳은 것은?', '["배변하는 동안 계속 말을 건다.", "이동변기 밑에 미끄럼방지 매트를 깐다.", "이동변기는 침대와 90도가 되도록 놓는다.", "배설 중에는 하반신을 노출시킨다.", "배설 후 냄새가 나지 않도록 뚜껑을 닫아 둔다."]'::jsonb, 2, '이 문제는 이동변기를 사용할 때의 적절한 방법을 알고 있는지 평가하고자 하는 의도입니다.', NULL, '{"1": "배변하는 동안 말을 건 것은 오히려 환자의 집중을 방해할 수 있습니다.\n[정답]", "2": "이동변기 밑에 미끄럼방지 매트를 깔면 안전성을 높이고 사고를 예방할 수 있습니다.", "3": "이동변기는 침대와 90도가 아닌 가까운 위치에 두어야 안전합니다.", "4": "배설 중 하반신을 노출시키는 것은 프라이버시를 침해할 수 있습니다.", "5": "배설 후 냄새를 줄이기 위해 뚜껑을 닫는 것은 좋지만, 이동변기의 적절한 사용을 돕기 위한 방법이 아닙니다."}'::jsonb, '[{"term_ko": "이동변기", "term_vi": "Bồn vệ sinh di động", "def_ko": "이동에 용이한 변기", "def_vi": "Bồn vệ sinh dễ di chuyển"}, {"term_ko": "미끄럼방지", "term_vi": "Chống trượt", "def_ko": "미끄럽지 않도록 하는 것", "def_vi": "Làm không trơn trượt"}, {"term_ko": "배설", "term_vi": "Đi vệ sinh", "def_ko": "대변을 보는 것", "def_vi": "Đi đại tiện"}, {"term_ko": "프라이버시", "term_vi": "Quyền riêng tư", "def_ko": "개인적인 공간", "def_vi": "Không gian cá nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1269, '10', '배설이 어려울 때 미지근한 물을 항문이나 요도에 흘려주는 이유는?', '["청결하게 하기 위해서", "냄새를 제거하기 위해서", "수치심을 줄이기 위해서", "배변 후 닦기 쉽게 하기 위해서", "괄약근을 이완시켜 변의를 자극하기 위해서"]'::jsonb, 5, '배설이 어려운 상황에서 환자가 느끼는 불편함을 덜어주기 위한 방법에 대해 질문하고 있다.', NULL, '{"1": "청결하게 하기 위해서: 미지근한 물을 흘려주는 주된 이유는 아니다.\n[정답]", "5": "괄약근을 이완시켜 변의를 자극하기 위해서: 이 경우가 가장 적절한 이유이다.", "2": "냄새를 제거하기 위해서: 냄새 제거는 미지근한 물을 사용하는 주요 목적이 아니다.", "3": "수치심을 줄이기 위해서: 수치심 경감도 직접적인 목적이 아니다.", "4": "배변 후 닦기 쉽게 하기 위해서: 배변 후의 청결과는 관련이 있지만, 이 질문의 목적과는 다르다."}'::jsonb, '[{"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "대소변을 배출하는 것", "def_vi": "Việc thải chất thải ra ngoài cơ thể"}, {"term_ko": "미지근한", "term_vi": "Ấm áp", "def_ko": "약간 따뜻한", "def_vi": "Hơi ấm"}, {"term_ko": "항문", "term_vi": "Hậu môn", "def_ko": "대변이 나오는 구멍", "def_vi": "Lỗ ra của phân"}, {"term_ko": "요도", "term_vi": "Niệu đạo", "def_ko": "소변이 나오는 구멍", "def_vi": "Lỗ ra của nước tiểu"}, {"term_ko": "괄약근", "term_vi": "Cơ vòng", "def_ko": "배변과 배뇨를 조절하는 근육", "def_vi": "Cơ điều tiết việc đi vệ sinh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1268, '10', '다음과 같은 대상자에게 가장 좋은 배설 돕기 방법은?서서나 앉는 것은 가능하지만 화장실까지 걷기 어려운 대상자', '["화장실 사용 돕기", "기저귀 사용 돕기", "침상배설 돕기", "이동 변기 사용 돕기", "유치도뇨관 사용 돕기"]'::jsonb, 4, NULL, NULL, NULL, NULL);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1267, '10', '이동변기를 사용하는 대상자를 돕는 방법으로 옳은 것은?', '["침대높이보다 이동변기를 낮게 한다.", "변기를 차가운 수건으로 닦아준다.", "배설물은 모아서 한꺼번에 버린다.", "요의를 호소할 때 즉시 배설할 수 있도록 돕는다.", "배설이 끝날 때까지 옆에서 지켜본다."]'::jsonb, 4, '이 문제는 요양보호사가 이동변기를 사용하는 대상자를 돕기 위한 적절한 방법을 묻고 있습니다. 이동변기 사용 시 중요한 사항을 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "이동변기를 침대보다 낮게 설정하면 대상자가 안전하게 사용할 수 없습니다.\n[정답]", "4": "요의를 호소할 때 즉시 배설할 수 있도록 돕는 것이 가장 올바른 방법입니다.", "2": "차가운 수건으로 변기를 닦는 것은 위생적으로 좋지 않습니다.", "3": "배설물을 한꺼번에 버리는 것은 위생상 좋지 않습니다.", "5": "배설이 끝날 때까지 옆에서 지켜보는 것은 개인의 사생활을 침해할 수 있습니다."}'::jsonb, '[{"term_ko": "이동변기", "term_vi": "Bồn vệ sinh di động", "def_ko": "이동 가능한 변기", "def_vi": "Bồn vệ sinh có thể di chuyển"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1266, '10', '대상자의 배설 도움 시 비뇨기계 감염이 발생할 우려가 있는 상황은?', '["매일 수분을 충분히 섭취하게 한다.", "소변주머니를 방광보다 낮은 위치에 둔다.", "항문을 닦을 때에는 앞에서 뒤로 닦아 준다.", "배설물을 처리하기 전과 후에는 손을 씻는다.", "소변이 자주 마려워도 하루에 세 번 규칙적으로 보게 한다."]'::jsonb, 5, '대상자의 배설 도움을 줄 때 비뇨기계 감염 발생과 관련된 위험 요소를 이해하고 평가하는 것.', NULL, '{"1": "매일 수분을 충분히 섭취하게 하는 것은 오히려 비뇨기계 감염 예방에 도움이 된다.", "2": "소변주머니를 방광보다 낮은 위치에 두는 것은 감염 예방을 위한 올바른 방법이다.", "3": "항문을 닦을 때에는 앞에서 뒤로 닦아 주는 것이 감염 예방에 중요하다.", "4": "배설물을 처리하기 전과 후에는 손을 씻는 것은 기본적인 위생 수칙이다.\n[정답]", "5": "소변이 자주 마려워도 하루에 세 번 규칙적으로 보게 하는 것은 사실, 잦은 배뇨는 감염의 위험을 높일 수 있다."}'::jsonb, '[{"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "배뇨 혹은 대변을 배출하는 행위", "def_vi": "Hành động bài tiết nước tiểu hoặc phân"}, {"term_ko": "비뇨기계", "term_vi": "Hệ tiết niệu", "def_ko": "소변을 형성하고 배설하는 기관의 시스템", "def_vi": "Hệ thống cơ quan hình thành và bài tiết nước tiểu"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "병원체가 체내에 침입하여 발생하는 질병 상태", "def_vi": "Tình trạng bệnh tật do mầm bệnh xâm nhập vào cơ thể"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결을 유지하여 질병을 예방하는 방법", "def_vi": "Phương pháp giữ gìn sạch sẽ để ngăn ngừa bệnh tật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1265, '10', '배설물의 특이사항으로 간호사에게 보고해야 할 사항은?가. 점액질이 섞인 대변 나. 거품이 있는 소변 다. 냄새가 심한 소변 라. 황금색의 굵은 대변', '["가,나,라", "가,다,라", "가,나,다", "나,다,라", "가,나,다,라"]'::jsonb, 3, '배설물의 특이사항을 통해 환자의 건강 상태를 평가하고 적절한 보고가 필요함을 이해하도록 하기 위함입니다.', NULL, '{"1": "점액질이 섞인 대변은 소화기관의 이상을 나타낼 수 있으므로 보고할 필요가 있습니다.\n[정답]", "3": "거품이 있는 소변은 신장 또는 대사적 문제가 있을 수 있으므로 반드시 보고해야 합니다.\n냄새가 심한 소변은 탈수나 감염 등의 가능성이 있으나 긴급하게 보고할 상황은 아닙니다.\n황금색의 굵은 대변은 정상적인 소화 상태를 나타내므로 보고할 필요가 없습니다."}'::jsonb, '[{"term_ko": "배설물", "term_vi": "Chất thải", "def_ko": "배설된 물질(한국어)", "def_vi": "Vật chất được đưa ra khỏi cơ thể"}, {"term_ko": "특이사항", "term_vi": "Đặc điểm đặc biệt", "def_ko": "다른 것과 다른 특성(한국어)", "def_vi": "Tính chất khác với những cái khác"}, {"term_ko": "거품", "term_vi": "Bọt", "def_ko": "둥글고 공기 방울이 있는 것(한국어)", "def_vi": "Vật tròn có bọt khí bên trong"}, {"term_ko": "황금색", "term_vi": "Màu vàng kim", "def_ko": "금빛의 색 (한국어)", "def_vi": "Màu sắc của vàng"}, {"term_ko": "굵은", "term_vi": "Dày", "def_ko": "두껍고 튼튼한 것(한국어)", "def_vi": "Dày và chắc"}, {"term_ko": "냄새", "term_vi": "Mùi", "def_ko": "물체가 발산하는 기체의 특성(한국어)", "def_vi": "Tính chất của khí tỏa ra từ vật thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1264, '10', '침상 배설을 돕는 방법 중 옳은 것은?', '["잦은 배변 시에는 식사량을 줄인다.", "변기를 찬 수건으로 닦은 후 대준다.", "배변 중 창문을 열어둔다.", "배변이 끝나면 침대 머리를 높인다.", "배변 후 대상자의 손을 씻게 한다."]'::jsonb, 5, '침상 배설을 돕는 방법에 대해 올바른 선택지를 가려내기 위함입니다.', NULL, '{"1": "잦은 배변 시 식사량을 줄이는 것은 잘못된 접근입니다. 배변에 영향을 주기보다는 적절한 식사량이 중요합니다.", "2": "변기를 찬 수건으로 닦는 것은 위생적이지 않으며, 매번 깨끗하게 소독해야 합니다.", "3": "배변 중 창문을 열어두는 것은 사생활 보호를 해치고 대상자에게 불편을 줄 수 있습니다.", "4": "배변이 끝난 후 침대 머리를 높인다는 것은 일반적인 방법이 아니며, 오히려 불편할 수 있습니다.\n[정답]", "5": "배변 후 대상자의 손을 씻게 하는 것은 위생을 고려한 올바른 방법입니다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대", "def_vi": "Giường ngủ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1263, '10', '편마비 대상자의 침상 배설을 돕는 방법은?', '["소변을 참지 못하고 실금하면 기저귀를 채운다.", "배설하지 못했으면 변의가 생길 때 다시 대어 준다.", "변의가 생기도록 찬 수건으로 항문 주위를 자극한다.", "건강한 쪽으로 돌려 눕혀 힘주기 쉬운 자세를 취하게 한다.", "점액질이 섞인 배설물은대상자에게 확인시킨 후 버린다."]'::jsonb, 2, '편마비 대상자의 적절한 배설 지원 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "소변을 참지 못하고 실금하면 기저귀를 채우는 것은 필요할 수 있지만, 배설을 돕는 방법으로는 부적절합니다.\n[정답]", "2": "배설하지 못했으면 변의가 생길 때 다시 대어 주는 것은 올바른 행동입니다.", "3": "변의가 생기도록 찬 수건으로 항문 주위를 자극하는 것은 부적절한 방법입니다.", "4": "건강한 쪽으로 돌려 눕혀 힘주기 쉬운 자세를 취하게 하는 것은 도움이 될 수 있지만, 변의가 생길 때를 고려해야 합니다.", "5": "점액질이 섞인 배설물은 대상자에게 확인시킨 후 버리는 것은 잘못된 방법입니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 팔과 다리에 힘이 없거나 마비된 상태", "def_vi": "Trạng thái không có sức mạnh hoặc bị liệt ở một bên tay và chân"}, {"term_ko": "배설", "term_vi": "Đi vệ sinh", "def_ko": "신체의 노폐물을 내보내는 행위", "def_vi": "Hành động thải chất thải ra khỏi cơ thể"}, {"term_ko": "변의", "term_vi": "Cảm giác đi vệ sinh", "def_ko": "대변을 보고싶은 느낌", "def_vi": "Cảm giác muốn đi vệ sinh"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "배설할 때 사용하는 일회용 또는 세탁 가능한 보호 용품", "def_vi": "Đồ bảo vệ dùng khi đi vệ sinh, có thể là một lần hoặc giặt lại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1262, '10', '침상에서 배설하는 대상자를 돕는 방법으로 옳은 것은?', '["대상자가 스스로 변기 위에 앉게 한다.", "침상머리를 올려 좌위를 취하게 한다.", "변기 놓을 자리에 젖은 수건을 깔아 준다.", "변의가 확실하지 않으면 변기를 장시간 대어 준다.", "협조할 수 없는 대상자는 무릎을 세우고 엉덩이를 들게 하여 변기를 대준다."]'::jsonb, 2, '침상에서 배설하는 대상자를 도와주는 올바른 방법에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "대상자가 스스로 변기 위에 앉는 것은 자립성을 돕는 방법이지만, 현재 상황에서는 적절하지 않습니다.\n[정답]", "2": "침상머리를 올려 좌위를 취하게 하는 것은 배변을 용이하게 도와주며 올바른 방법입니다.", "3": "변기 놓을 자리에 젖은 수건을 깔아주는 것은 위생적이지 않으며 바람직하지 않습니다.", "4": "변의가 확실하지 않으면 변기를 장시간 대어 주는 것은 불편함을 초래할 수 있습니다.", "5": "협조할 수 없는 대상자를 위해 무릎을 세우고 엉덩이를 들게 하는 방법은 오히려 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 환자와 돌봄 대상", "def_vi": "bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1261, '10', '간이변기를 사용하여 침상 배설하는 대상자를 돕는 방법은?', '["간이변기는 세척하여 침상 위에 놓아둔다.", "간이변기 옆에 미끄럼방지 매트를 깔아 준다.", "엉덩이 밑에 방수포를 깔고 간이변기를 대어 준다.", "변기를 침대 난간과 90도가 되게 놓은 후 대상자를 앉힌다.", "협조할 수 없는 대상자는 옆으로 누운 상태로 변기를 사용한다."]'::jsonb, 3, '간이변기를 사용할 때 안전하고 올바른 방법을 알고 있는지를 평가하고자 함.', NULL, '{"1": "간이변기를 세척하여 침상 위에 놓아두는 것은 비위생적이며 바람직하지 않다.\n[정답]", "2": "엉덩이 밑에 방수포를 깔고 간이변기를 대어 주는 것은 환자의 편안함과 청결을 유지하는 방법이다.", "3": "변기를 침대 난간과 90도가 되게 놓은 후 대상자를 앉히는 것은 불안정할 수 있어 위험하다.", "4": "협조할 수 없는 대상자는 옆으로 누운 상태로 변기를 사용하는 것은 바람직하지 않다."}'::jsonb, '[{"term_ko": "간이변기", "term_vi": "Bệ ngồi toilet di động", "def_ko": "임시 사용을 위한 변기", "def_vi": "Bồn cầu tạm thời"}, {"term_ko": "방수포", "term_vi": "Tấm nhựa chống thấm", "def_ko": "물이 스며들지 않는 포", "def_vi": "Vật liệu không thấm nước"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1260, '10', '대상자의 침상 배설을 돕기 위한 방법으로 옳은 것은?', '["대사앚가 협조할 수 없으면 기저귀를 채운다.", "차가운 변기를 대주어 변의를 자극한다.", "찬물을 항문에 끼얹어 배설을 빨리하게 한다.", "침대를 올려주어 배에 힘을 주기 쉬운 자세를 취해준다.", "스크린을 치운 후 옷을 입혀준다."]'::jsonb, 4, '대상자의 침상 배설을 돕기 위한 바른 방법을 익히도록 한다.', NULL, '{"1": "대상자가 협조할 수 없으면 기저귀를 채운다.", "2": "차가운 변기를 대주어 변의를 자극한다.", "3": "찬물을 항문에 끼얹어 배설을 빨리하게 한다.\n[정답]", "4": "침대를 올려주어 배에 힘을 주기 쉬운 자세를 취해준다.", "5": "스크린을 치운 후 옷을 입혀준다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 고객", "def_vi": "Bệnh nhân, khách hàng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1259, '10', '침상 배설을 돕는 방법으로 옳은 것은?', '["힘을 주기 쉽게 침대 머리를 낮춰준다.", "비언어적 표현에는 대응하지 않는다.", "소변이 튀지 않도록 회음부에 화장지를 댄다.", "항문부위를 물수건으로 닦은 후 바지를 입힌다.", "편안한 배설을 위해 최대한 노출을 한다."]'::jsonb, 3, '환자의 침상 배설을 돕는 적절한 방법에 대한 이해 확인', NULL, '{"1": "힘을 주기 쉽게 침대 머리를 낮추는 방법은 일반적으로 옳지 않다.\n[정답]", "3": "소변이 튀지 않도록 회음부에 화장지를 대는 것은 적절한 배설 보조 방법이다.", "2": "비언어적 표현에는 대응하지 않는 것은 올바른 접근이 아니다.", "4": "항문부위를 물수건으로 닦는 것보다 더 신중하고 위생적인 방법이 필요하다.", "5": "편안한 배설을 위해 최대한 노출을 하는 것은 오히려 환자를 불편하게 할 수 있다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "Giường bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1258, '10', '침상 배설을 돕는 방법으로 옳은 것은?', '["무릎 아래에 방수포를 깐다.", "소리 나는 것을 방지하기 위해 변기에 물을 채운다.", "대상자가 협조할 수 없는 경우 방수포를 깔지 않는다.", "바지를 내린 후 허리 아래쪽에 무릎덮개를 덮어준다.", "변기 중앙에 항문이 오도록 변기를 밀어 넣는다."]'::jsonb, 5, '침상 배설을 돕는 방법에 대한 이해를 평가하고자 함.', NULL, '{"1": "무릎 아래에 방수포를 깔면 불필요한 오염을 줄일 수 있으나, 상황에 따라 다를 수 있다.\n[정답]", "5": "변기 중앙에 항문이 오도록 변기를 밀어 넣는 것이 적절한 방법이다.", "2": "소리 나는 것을 방지하기 위해 변기에 물을 채우는 것은 잘못된 방법이다.", "3": "대상자가 협조할 수 없는 경우에도 방수포를 깔아야 한다.", "4": "바지를 내린 후 허리 아래쪽에 무릎덮개를 덮어주는 것은 잘못된 처치 방법이다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대 위", "def_vi": "trên giường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1257, '10', '여성 대상자가 침상 배뇨를 할 때 소리로 인한 수치심을 덜 느끼도록 돕는 방법은?', '["변기에 물을 채운다.", "음악을 틀어준다.", "무릎에 담요를 덮어준다.", "변기 아래에 방수포를 깔아준다.", "수건을 말아 허리 밑에 대준다."]'::jsonb, 2, '여성 대상자가 침상 배뇨를 할 때 수치심을 줄여주는 방법을 이해하고 적용하는 것.', NULL, '{"1": "변기에 물을 채우면 소리가 줄어들지만 수치심을 덜 느끼게 하는 방법이 아님.\n[정답]", "2": "음악을 틀어주면 소음으로 인해 수치심을 덜 느끼게 할 수 있다.", "3": "무릎에 담요를 덮어주는 것은 체온 유지에는 도움이 되지만 수치심 해소와는 관련이 없다.", "4": "변기 아래에 방수포를 깔아주는 것은 안전성을 높일 수 있지만 수치심과는 무관하다.", "5": "수건을 말아 허리 밑에 대주는 것은 편안함을 주겠지만 수치심 해소에는 기여하지 않는다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대 위", "def_vi": "trên giường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1256, '10', '변기를 따뜻하게 데워주는 이유는?', '["피부발진을 예방하기 위해", "항문 괄약근을 이완시키기 위해", "요실금을 예방하기 위해", "수치심을 줄이기 위해", "치질을 예방하기 위해"]'::jsonb, 2, '변기를 따뜻하게 데워주는 이유를 통하여 환자의 편안함과 배변 시의 신체 반응을 이해하도록 하는 것이 목적입니다.', NULL, '{"1": "피부발진을 예방하기 위해: 온도가 피부 발진 예방과 직접적인 연관이 없습니다.\n[정답]", "2": "항문 괄약근을 이완시키기 위해: 따뜻한 온도가 항문 괄약근을 이완시켜 배변을 용이하게 합니다.", "3": "요실금을 예방하기 위해: 요실금 예방과는 관련이 없습니다.", "4": "수치심을 줄이기 위해: 온도가 수치심에 영향을 미치지 않습니다.", "5": "치질을 예방하기 위해: 치질 예방과 연관된 효과는 없습니다."}'::jsonb, '[{"term_ko": "변기", "term_vi": "Bệ ngồi", "def_ko": "화장실에서 사용하는 기구", "def_vi": "Thiết bị sử dụng trong nhà vệ sinh"}, {"term_ko": "따뜻하게", "term_vi": "Làm ấm", "def_ko": "따뜻한 상태로 만들다", "def_vi": "Tạo ra trạng thái ấm"}, {"term_ko": "항문", "term_vi": "Hậu môn", "def_ko": "대변을 배출하는 곳", "def_vi": "Nơi bài tiết phân"}, {"term_ko": "괄약근", "term_vi": "Cơ vòng", "def_ko": "근육으로 이루어진 고리 구조", "def_vi": "Cấu trúc vòng được tạo thành từ cơ"}, {"term_ko": "요실금", "term_vi": "Tiểu không tự chủ", "def_ko": "소변을 조절하지 못하는 상태", "def_vi": "Tình trạng không kiểm soát được tiểu tiện"}, {"term_ko": "치질", "term_vi": "Trĩ", "def_ko": "항문 주위의 정맥이 부풀어 올라 아픈 상태", "def_vi": "Tình trạng tĩnh mạch quanh hậu môn phình ra và gây đau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1255, '10', '누워있는 대상자의 침상 배설을 돕는 방법으로 옳은 것은?', '["간이변기 사용 직후에 기저귀를 채워준다.", "조용한 환경에서 배설할 수 있게 한다.", "상태를 살피기 위해 스크린을 열어둔다.", "변기는 따뜻하게 데워서 사용한다.", "배설 후 뒤에서 앞으로 닦는다."]'::jsonb, 4, '대상자의 배설을 돕는 방법에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "간이변기 사용 직후에 기저귀를 채워주는 것은 바람직하지 않습니다.\n[정답]", "2": "조용한 환경에서 배설할 수 있게 하는 것은 중요하고 옳은 방법입니다.", "3": "상태를 살피기 위해 스크린을 열어두는 것은 사생활 보호에 반하는 행동입니다.", "4": "변기는 따뜻하게 데워서 사용해야 대하죠. 이는 대비세를 감소시킬 수 있습니다.", "5": "배설 후 닦는 방향은 앞에서 뒤로가 아니라, 뒤에서 앞으로가 올바릅니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 응급환자, 간병 대상자", "def_vi": "Bệnh nhân, Người được chăm sóc, Người bệnh khẩn cấp"}, {"term_ko": "침상", "term_vi": "Giường bệnh", "def_ko": "병상의 침대", "def_vi": "Giường nằm"}, {"term_ko": "배설", "term_vi": "Tiểu tiện", "def_ko": "대변과 소변을 배출하다.", "def_vi": "Đáh bài tiểu"}, {"term_ko": "변기", "term_vi": "Bồn cầu", "def_ko": "화장실의 설비", "def_vi": "Thiết bị trong nhà vệ sinh"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "아기가 사용하는 기저귀", "def_vi": "Tã cho trẻ em"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주변의 상태", "def_vi": "Tình trạng xung quanh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1254, '10', '침상 배설을 도울 때 제일 먼저 해야 하는 것은?', '["TV를 켜거나 음악을 틀어놓는다.", "커튼이나 스크린으로 가린다.", "대상자를 확인하고 절차를 설명한다.", "일회용 장갑을 착용한다.", "따뜻한 물로 변기를 데워놓는다."]'::jsonb, 3, '침상 배설 시의 바른 절차와 안전을 이해하도록 하는 의도입니다.', NULL, '{"1": "TV를 켜거나 음악을 틀어놓는 것은 집중이 필요한 상황에서 부적절한 행동입니다.\n[정답]", "3": "대상자를 확인하고 절차를 설명하는 것이 가장 우선되어야 합니다.", "2": "커튼이나 스크린으로 가리는 것은 사생활 보호를 위한 단계입니다.", "4": "일회용 장갑을 착용하는 것은 위생을 위해 필요하지만, 사전에 대상자를 확인하는 것이 먼저입니다.", "5": "따뜻한 물로 변기를 데워놓는 것은 편안함을 위한 조치이지만, 가장 먼저 할 일은 아닙니다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대 위", "def_vi": "Trên giường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1253, '10', '나도 모르게 오줌이 나와 속옷이 자꾸 젖어요라고 호소하는 대상자를 돕는 방법으로 옳은 것은?', '["기저귀를 채운다.", "배뇨 훈련에 참여하도록 격려한다.", "수분 섭취량을 줄인다.", "변기에 오랫동안 앉아있게 한다.", "복부에 얼음주머니를 대준다."]'::jsonb, 2, '대상자가 경험하는 불편함을 이해하고, 그에 대한 적절한 도움을 제공하는 방법을 묻는 문제입니다.', NULL, '{"1": "기저귀를 채우는 것은 일시적인 해결책일 뿐, 근본적인 문제 해결이 아닙니다.\n[정답]", "2": "배뇨 훈련에 참여하도록 격려하는 것은 장기적으로 도움이 되는 방법입니다.", "3": "수분 섭취량을 줄이는 것은 건강에 해로울 수 있으며, 문제가 해결되지 않을 수 있습니다.", "4": "변기에 오랫동안 앉게 하는 것은 불편함을 증가시킬 수 있습니다.", "5": "복부에 얼음주머니를 대는 것은 통증 완화에 도움이 될 수 있지만, 문제 해결에는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "오줌", "term_vi": "Nước tiểu", "def_ko": "소변(한국어)", "def_vi": "nước tiểu(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1252, '10', '침상에서 배변하는 대상자를 돕는 방법은?', '["요의나 변의를 호소할 때 참도록 유도한다.", "오염을 예방하기 위해 옷을 모두 벗긴다.", "복부를 시계방향으로 마사지 한다.", "배변하는 동안 피부 상태를 살펴본다.", "참지 못하고 실수하는 경우 주의를 준다."]'::jsonb, 3, '침상에서 배변하는 대상자를 도울 때 유의해야 할 방법이나 절차에 대해 평가하고자 하는 의도입니다.', NULL, '{"1": "요의나 변의를 호소할 때 참도록 유도하는 것은 일반적인 방법이지만, 실상 배변이 필요한 시점에서는 그러한 유도가 도움이 되지 않을 수 있습니다.\n[정답]", "3": "복부를 시계방향으로 마사지하는 것은 장운동을 촉진할 수 있어 도움이 되는 방법입니다.", "2": "오염을 예방하기 위해 옷을 모두 벗기는 것은 필요하지 않으며, 최소한의 의복만 제거하는 것이 바람직합니다.", "4": "배변하는 동안 피부 상태를 살펴보는 것은 중요하지만, 이는 배변을 도와주는 방법이라고 볼 수는 없습니다.", "5": "참지 못하고 실수하는 경우 주의를 주는 것은 부정적인 경험을 초래할 수 있으므로 주의가 필요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 집중환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1251, '10', '편마비 대상자가 휠체어로 이동하여 화장실을 사용할 때 돕는 방법은?', '["대상자의 불편한 쪽에 휠체어를 둔다.", "휠체어 의자 끝에 걸터앉게 하여 이동한다.", "휠체얼르 타고 내릴 때는 잠금장치를 해제한다.", "대상자의 겨드랑이를 감싸 일으킨 후 몸을 90도 회전시켜 변기에 앉힌다.", "배설이 끝나 대상자가 호출하기 전까지 다른 업무를 본다."]'::jsonb, 4, '편마비 환자의 화장실 사용 시 적절한 지원 방법을 평가하기 위함입니다.', NULL, '{"1": "대상자의 불편한 쪽에 휠체어를 두는 것은 이동 시 불편함을 초래할 수 있습니다.\n[정답]", "2": "휠체어 의자 끝에 걸터앉게 하여 이동하는 방법은 안전하지 않으며, 대상자의 불편함을 증가시킬 수 있습니다.", "3": "휠체어를 타고 내릴 때는 잠금장치를 해제해야 안전하므로 올바른 방법이 아닙니다.", "4": "대상자의 겨드랑이를 감싸 일으킨 후 몸을 90도 회전시켜 변기에 앉히는 것은 올바른 지원 방법입니다.", "5": "배설이 끝나기 전까지 다른 업무를 보는 것은 대상자의 안전을 보장하지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "일방의 팔과 다리가 마비된 상태", "def_vi": "Tình trạng tê liệt một bên tay và chân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1250, '10', '배설 돕기 시 대상자가 부끄러우니 밖에서 기다려 달라고 할 때, 올바른 대처방법은?', '["즉시 자리를 피해준다.", "낙상 위험이 있으므로 옆에 있기를 고집한다.", "커튼으로 가려주고 가끔 들여다본다.", "호출기를 쥐어주고 밖에서 기다린다.", "문을 활짝 열어놓고 밖에서 지켜본다."]'::jsonb, 4, '대상자의 사생활과 편안함을 보장하면서 안전하게 배설을 도와주는 방법을 묻는 질문입니다.', NULL, '{"1": "즉시 자리를 피해주는 것은 대상자의 안전을 위협할 수 있습니다.\n[정답]", "4": "호출기를 쥐어주고 밖에서 기다리는 것은 대상자가 편안하게 배설할 수 있게 도와주면서도 안전을 확보하는 좋은 방법입니다.", "2": "낙상 위험이 있으므로 옆에 있기를 고집하는 것은 대상자의 의사를 무시하는 것입니다.", "3": "커튼으로 가려주고 가끔 들여다보는 것은 오히려 대상자를 불편하게 할 수 있습니다.", "5": "문을 활짝 열어놓고 밖에서 지켜보는 것은 프라이버시를 침해하는 행동입니다."}'::jsonb, '[{"term_ko": "배설", "term_vi": "Đi vệ sinh", "def_ko": "배변(한국어)", "def_vi": "Đi tiêu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1249, '10', '화장실에 가기 위해 누워 있는 대상자를 일으킨 후 잠시 앉아 있게 해야 하는 이유는?', '["땀이 날 수 있으므로", "숨이 찰 수 있으므로", "혈압 저하로 어지러울 수 있으므로", "맥박 저하로 가슴 통증이 있으므로", "소변을 참도록 연습시키기 위해서"]'::jsonb, 3, '대상자의 안전한 이동을 위해 왜 잠시 앉아 있게 해야 하는지를 묻고 있습니다.', NULL, '{"1": "땀은 운동이나 긴장으로 인해 발생할 수 있지만, 앉아 있는 것과 직접적인 관계는 적습니다.\n[정답]", "2": "숨이 찰 수 있지만, 주로 이동 직후가 아니라 앉아있는 동안 발생하는 경우가 많습니다.", "3": "혈압 저하로 인해 대상자가 어지러움을 느낄 수 있으므로, 움직임에 대한 준비가 필요합니다.", "4": "맥박 저하로 인한 가슴 통증은 대부분 심각한 상태에서 나타나며, 이 문제와의 연관성이 적습니다.", "5": "소변을 참도록 연습하는 것은 대상자의 필요가 아닙니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1248, '10', '침대에 누워 있는 편마비 대상자가 휠체어를 이용하여 화장실을 갈 때 돕는 방법은?', '["마비된 쪽에 휠체어를 놓는다.", "침대에 일으켜 앉혔을 때 어지러움을 호소하는지 살핀다.", "침대에서 최대한 멀리 휠체어를 놓는다.", "휠체어에 앉을 때 잠금장치를 풀어둔다.", "옷을 입고 벗기 쉽게 속옷을 입히지 않는다."]'::jsonb, 2, '편마비 환자의 화장실 이동 중 안전한 보조 방법을 이해하는 것.', NULL, '{"1": "마비 측에 휠체어를 놓는 것은 환자가 안전하게 이동할 수 없게 할 수 있다.\n[정답]", "2": "어지러움 여부를 확인하는 것은 중요한 안전 절차이다.", "3": "휠체어를 멀리 놓는 것은 환자의 이동을 더 어렵게 만든다.", "4": "휠체어의 잠금장치를 푸는 것은 위험할 수 있다.", "5": "속옷을 입히지 않는 것은 환자의 위생에 좋지 않다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸이 마비된 상태", "def_vi": "Tình trạng cơ thể bị liệt một nửa"}, {"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "이동을 돕는 의자", "def_vi": "Ghế hỗ trợ di chuyển"}, {"term_ko": "어지러움", "term_vi": "Chóng mặt", "def_ko": "비틀거리거나 머리가 아픈 증상", "def_vi": "Triệu chứng choáng váng hoặc đau đầu"}, {"term_ko": "잠금장치", "term_vi": "Thiết bị khóa", "def_ko": "고정하는 장치", "def_vi": "Công cụ giữ cố định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1247, '10', '대상자가 화장실을 안전하게 이용할 수 있도록 돕는 방법은?', '["화장실 이동 시 재촉한다.", "배뇨하는 동안 바로 옆에서 지켜본다.", "배설할 때는 옷을 최대한 벗긴다.", "바닥에 흐트러진 물건들을 정리한다.", "편안하게 배설하도록 조명을 어둡게 한다."]'::jsonb, 4, '대상자가 화장실을 안전하게 이용할 수 있도록 도와주는 방법을 묻고 있습니다.', NULL, '{"1": "화장실 이동 시 재촉한다. - 이는 대상자의 안전을 위협할 수 있습니다.\n[정답]", "4": "바닥에 흐트러진 물건들을 정리한다. - 이는 안전성을 높이는 중요한 방법입니다.", "2": "배뇨하는 동안 바로 옆에서 지켜본다. - 대인적인 사생활을 침해할 수 있습니다.", "3": "배설할 때는 옷을 최대한 벗긴다. - 이는 불편함을 초래할 수 있습니다.", "5": "편안하게 배설하도록 조명을 어둡게 한다. - 이는 범죄나 사고 위험을 증가시킬 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(병원이나 요양시설에서 돌봄을 받는 사람)", "def_vi": "Người nhận sự chăm sóc tại bệnh viện hoặc cơ sở chăm sóc."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1246, '10', '거동이 불편한 대상자가 화장실을 이용할 때 낙상위험을 줄이는 방법으로 옳은 것은?', '["이동하는 동안 슬리퍼를 신긴다.", "화장실 가는 중간에 의자를 둔다.", "화장실 문 앞에 작은 매트를 깔아준다.", "변기 옆에 손잡이를 설치하여 필요 시 잡도록 한다.", "화장실 문밖에 응급벨을 설치한다."]'::jsonb, 4, '거동이 불편한 대상자의 낙상 위험을 줄이기 위한 적절한 방법을 이해하고 적용하는지 평가하려는 의도입니다.', NULL, '{"1": "이동하는 동안 슬리퍼를 신기는 하여 불편함을 증가시킬 수 있습니다.\n[정답]", "4": "변기 옆에 손잡이를 설치하여 필요 시 잡도록 하면 안정성을 높일 수 있습니다.", "2": "화장실 가는 중간에 의자를 두는 것은 오히려 불편할 수 있습니다.", "3": "화장실 문 앞에 작은 매트를 깔면 미끄러짐의 위험을 증가시킬 수 있습니다.", "5": "화장실 문밖에 응급벨을 설치하는 것도 중요하지만, 직접적인 낙상 예방과는 관련이 적습니다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "대상자", "def_ko": "행동, di chuyển", "def_vi": "환자, người dùng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1245, '10', '대상자가 휠체어 사용 시 화장실 이용을 돕는 방법으로 옳은 것은?', '["처음부터 끝까지 도와준다.", "휠체어를 타고 내릴 때는 잠금장치를 풀어놓는다.", "대상자를 변기로 옮기는 동안 발 받침대는 내려놓는다.", "건조하지 않도록 화장실 바닥에 물을 뿌린다.", "배뇨 후 도움이 필요한 부분을 도와준다."]'::jsonb, 5, '대상자가 휠체어를 사용할 때 화장실 이용 시의 올바른 도움 방법을 평가하는 것.', NULL, '{"1": "처음부터 끝까지 도와주는 것은 대상자의 자율성을 영어.\n[정답]", "5": "배뇨 후 도움이 필요한 부분만 도와주는 것이 올바른 방법이다.", "3": "변기로 옮길 때 발 받침대를 내려놓는 것은 안전상 문제를 야기할 수 있다.", "2": "휠체어를 타고 내릴 때 잠금장치를 풀어놓으면 사고의 위험이 있다.", "4": "화장실 바닥에 물을 뿌리는 것은 미끄러짐의 원인이 될 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1244, '10', '대상자의 배설요구 표현으로 볼 수 있는 것은?', '["웃옷을 벗는 행위", "물을 마시지 않는 행위", "머리를 자주 긁는 행위", "안절부절 못하며 허리를 들썩이는 행위", "손을 자꾸 입으로 가져가는 행위"]'::jsonb, 4, '대상자가 배설에 대한 불편함을 표현하는 비언어적 신호를 인식하는 데 중점을 두고 있습니다.', NULL, '{"1": "웃옷을 벗는 행위는 배설과 연관되지 않음.\n[정답]", "4": "안절부절 못하며 허리를 들썩이는 행위는 배설의 요구를 나타낼 수 있음.", "2": "물을 마시지 않는 행위는 배설 요구와 무관함.", "3": "머리를 자주 긁는 행위는 불편함 표시일 수 있으나 배설 요구와는 관련이 없음.", "5": "손을 자꾸 입으로 가져가는 행위는 다른 심리적 불안을 의미할 수 있음."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "특정 환자나 사람", "def_vi": "Người bệnh hoặc cá nhân cụ thể"}, {"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "소변이나 대변을 배출하는 행위", "def_vi": "Hành động thải nước tiểu hoặc phân"}, {"term_ko": "행위", "term_vi": "Hành động", "def_ko": "특정한 행동 또는 동작", "def_vi": "Hành vi cụ thể hoặc động tác"}, {"term_ko": "불편함", "term_vi": "Sự không thoải mái", "def_ko": "편안하지 않음", "def_vi": "Không thoải mái"}, {"term_ko": "신호", "term_vi": "Tín hiệu", "def_ko": "특정한 정보나 경고를 전달하는 방법", "def_vi": "Phương thức truyền đạt thông tin hoặc cảnh báo"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1243, '10', '대상자가 소변이 마려워라고 말할 때 돕는 방법으로 옳은 것은?', '["걸을 수 있는 대상자는 혼자 가게 한다.", "신체적, 심리적 상태를 파악하여 보조한다.", "화장실 문을 열어 놓고 배설하게 한다.", "낙상 예방을 위해 이동변기 사용을 적극 권유한다.", "배설물처리 시 냄새가 난다며 솔직히 말한다."]'::jsonb, 2, '대상자가 소변을 마려워할 때 적절한 돕는 방법을 평가하기 위함입니다.', NULL, '{"1": "걸을 수 있는 대상자는 혼자 가게 한다: 혼자 가게 하는 것은 안전하지 않을 수 있습니다.\n[정답]", "2": "신체적, 심리적 상태를 파악하여 보조한다: 대상자의 상태를 제대로 파악하고 돕는 것이 가장 적절한 방법입니다.", "3": "화장실 문을 열어 놓고 배설하게 한다: 사생활을 존중하지 않는 행동입니다.", "4": "낙상 예방을 위해 이동변기 사용을 적극 권유한다: 이동변기는 필요할 때에만 사용해야 하며, 이동하기 어려운 경우에 적절합니다.", "5": "배설물처리 시 냄새가 난다며 솔직히 말한다: 대상자의 자존심에 상처를 줄 수 있는 부적절한 대화입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "환자, 수혜자", "def_vi": "Bệnh nhân, người thụ hưởng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1242, '10', '베설 요양보호의 일반적 원칙으로 옳은 것은?', '["대상자의 요구사항을 무시한다.", "대상자가 편안하게 배설하도록 배려한다.", "배설을 하면 모아서 한꺼번에 치운다.", "요양보호사가 전적으로 도와준다.", "항문은 뒤에서 앞으로 닦는다."]'::jsonb, 2, '배설 요양보호의 일반적인 원칙에 대한 이해를 평가하려는 목적입니다.', NULL, '{"1": "대상자의 요구사항을 무시하는 것은 요양보호의 원칙에 반합니다.\n[정답]", "2": "대상자가 편안하게 배설하도록 배려하는 것은 중요한 원칙입니다.", "3": "배설물을 모아서 한꺼번에 치우는 것은 바람직하지 않습니다.", "4": "요양보호사가 전적으로 도와주는 것이 아니라, 대상자의 자율성을 존중해야 합니다.", "5": "항문을 닦는 방향은 뒤에서 앞으로가 아니라 앞으로 뒤로입니다."}'::jsonb, '[{"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "배변 또는 소변을 보는 것", "def_vi": "việc đi tiểu hoặc đại tiện"}, {"term_ko": "요양보호", "term_vi": "Chăm sóc người cao tuổi", "def_ko": "노인을 돌보는 일", "def_vi": "công việc chăm sóc cho người lớn tuổi"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 혹은 돌봐야 할 사람", "def_vi": "bệnh nhân hoặc người cần được chăm sóc"}, {"term_ko": "편안하다", "term_vi": "Thoải mái", "def_ko": "안락하고 불편함이 없다", "def_vi": "không khó chịu và dễ chịu"}, {"term_ko": "자율성", "term_vi": "Tự chủ", "def_ko": "스스로 결정할 수 있는 능력", "def_vi": "khả năng tự quyết định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1241, '10', '약의 변질을 먹기 위한 올바른 방법은?', '["안약, 귀약은 상온의 그늘진 곳에서 보관한다.", "알약은 습기가 많은 상온에서 보관한다.", "가루약을 먹일 때 물기가 있는 숟가락을 사용한다.", "시럽제는 약 용기 째 빨아 먹는다.", "꺼낸 시럽은 다시 병에 넣어 보관한다."]'::jsonb, 1, '약물 보관과 사용 방법에 대한 올바른 지식을 측정하기 위함입니다.', NULL, '{"1": "안약, 귀약은 상온의 그늘진 곳에서 보관한다.\n[정답]", "2": "알약은 습기가 많은 상온에서 보관한다. 이는 약의 변질을 유발할 수 있다.", "3": "가루약을 먹일 때 물기가 있는 숟가락을 사용한다. 이는 약의 변질을 일으킬 수 있다.", "4": "시럽제는 약 용기 째 빨아 먹는다. 이는 오염의 위험이 있다.", "5": "꺼낸 시럽은 다시 병에 넣어 보관한다. 이는 약의 변질을 초래할 수 있다."}'::jsonb, '[{"term_ko": "약", "term_vi": "Thuốc", "def_ko": "약물(한국어)", "def_vi": "Dược phẩm(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1240, '10', '대상자의 약품을 보관하는 방법으로 옳은 것은?', '["가루약은 물에 녹여 냉장 보관한다.", "시럽제는 햇빛이 잘 드는 곳에 보관한다.", "알약은 건조한 곳에 보관한다.", "안약은 냉장고에 보관한다.", "치매 대상자의 약은 침상 옆에 보관한다."]'::jsonb, 3, '약품 보관 방법에 대한 지식을 평가하기 위함입니다.', NULL, '{"1": "가루약은 물에 녹여 냉장 보관하는 것이 아니라, 건조하고 서늘한 곳에 보관해야 합니다.\n[정답]", "3": "알약은 반드시 건조한 곳에 보관해야 하며, 습기와 열을 피해야 합니다.", "2": "시럽제는 햇빛이 잘 드는 곳에 보관하는 것이 아니라, 직사광선을 피해야 합니다.", "4": "안약은 냉장고에 보관할 수 있지만, 사용 전에는 실온으로 두어야 하며, 제조사의 지침을 따라야 합니다.", "5": "치매 대상자의 약은 침상 옆에 보관하는 것이 아니라, 안전한 곳에 보관하여 잘못된 사용을 방지해야 합니다."}'::jsonb, '[{"term_ko": "약품", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "Thuốc"}, {"term_ko": "보관", "term_vi": "Lưu trữ", "def_ko": "저장(한국어)", "def_vi": "Lưu trữ"}, {"term_ko": "가루약", "term_vi": "Thuốc bột", "def_ko": "분말 약(한국어)", "def_vi": "Thuốc dạng bột"}, {"term_ko": "알약", "term_vi": "Viên thuốc", "def_ko": "알약(한국어)", "def_vi": "Viên thuốc"}, {"term_ko": "시럽제", "term_vi": "Sirop", "def_ko": "시럽 형태의 약(한국어)", "def_vi": "Sirop"}, {"term_ko": "안약", "term_vi": "Thuốc nhỏ mắt", "def_ko": "안구 치료제(한국어)", "def_vi": "Thuốc nhỏ cho mắt"}, {"term_ko": "치매", "term_vi": "Lú lẫn", "def_ko": "치매(한국어)", "def_vi": "Giai đoạn lơ đãng"}, {"term_ko": "대상자", "term_vi": "Bệnh nhân", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1239, '10', '정맥주사 주입 중 대상자가 주사부위의 토증을 호소할 때 올바른 대처방법은?', '["주사바늘을 즉시 제거한다.", "주사주입 속도를 줄인다.", "통증 부위를 냉찜질 한다.", "수액병을 심장보다 아래로 내려준다.", "조저릭를 잠근 후 즉시 간호사에게 보고한다."]'::jsonb, 5, '주사 중 발생할 수 있는 합병증에 대해 올바른 대처 방법을 평가하기 위함입니다.', NULL, '{"1": "주사바늘을 제거하는 것은 불필요한 조치이며, 상태를 확인하기 전에 시행하면 상황을 악화시킬 수 있다.\n[정답]", "5": "조저릭을 잠근 후 즉시 간호사에게 보고하는 것이 안전한 조치이며, 상황을 관리하는 데 필요하다.", "2": "주사주입 속도를 줄이는 것은 즉각적인 대처 방법으로 적절하지 않으며, 증상이 심각할 수 있다.", "3": "통증 부위를 냉찜질 하는 것은 일시적인 완화일 수 있으나, 근본 원인을 해결하지 않는다.", "4": "수액병을 심장보다 아래로 내려주는 것은 혈류에 영향을 미치지 않으며, 적절한 대처 방법이 아니다."}'::jsonb, '[{"term_ko": "정맥주사", "term_vi": "Tiêm tĩnh mạch", "def_ko": "정맥으로 하는 주사", "def_vi": "Tiêm vào tĩnh mạch"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "토증", "term_vi": "Buồn nôn", "def_ko": "메스꺼움", "def_vi": "Cảm giác buồn nôn"}, {"term_ko": "조저릭", "term_vi": "Van điều chỉnh", "def_ko": "주입 속도 조절 장치", "def_vi": "Thiết bị điều chỉnh tốc độ truyền"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1238, '10', '대상자에게 주사주입 시 수액 병의 높이로 옳은 것은?', '["심장 위", "심장 아래", "방광 아래", "허리 아래", "허리에서 심장 사이"]'::jsonb, 1, '주사 주입 시 수액 병이 위치해야 하는 높이를 이해하고 있는지 확인하는 문제입니다.', NULL, '{"1": "주사 주입 시 수액 병은 심장보다 높아야만 적절한 압력으로 수액이 주입됩니다.\n[정답]", "2": "심장 아래에 위치하면 수액 주입이 어려워집니다.", "3": "방광 아래는 적합하지 않습니다.", "4": "허리 아래는 수액 주입의 원리에 맞지 않습니다.", "5": "허리에서 심장 사이도 주입 원리에 맞지 않습니다."}'::jsonb, '[{"term_ko": "주사", "term_vi": "주입", "def_ko": "주사(tiêm)", "def_vi": "주입(cho vào)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1237, '10', '대상자에게 주사주입 시 돕기 방법으로 옳은 것은?', '["수액세트가 팽팽하게 당겨지도록 한다.", "의복을 갈아입었을 때 주사바늘을 빼둔다.", "주사부위에 부종이 생기면 주사바늘을 제거한다.", "정맥주입 속도가 일정하게 유지되는지 수시로 확인한다.", "주사바늘을 제거한 후 알코올 솜을 비벼준다."]'::jsonb, 4, '주사주입에 대한 기본적인 지식과 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "수액세트를 팽팽하게 당겨지는 것은 불필요하며, 이로 인해 혈관에 압력이 가해질 수 있습니다.\n[정답]", "4": "정맥주입 속도를 수시로 확인하는 것은 주사 시 매우 중요한 절차입니다.", "3": "주사부위에 부종이 생겼을 때는 주사바늘을 제거하는 것이 맞지만, 제거하지 않은 경우에도 이유가 있을 수 있으므로 신중해야 합니다.", "2": "의복을 갈아입었을 때 주사바늘을 빼둬서는 안 되며, 주사 주입을 진행해야 합니다.", "5": "주사바늘을 제거한 후 알코올 솜을 비비는 것은 올바르지 않습니다."}'::jsonb, '[{"term_ko": "주사", "term_vi": "Tiêm", "def_ko": "주사기나 바늘로 약물을 체내에 넣는 것", "def_vi": "Sử dụng ống tiêm hoặc kim để đưa thuốc vào cơ thể"}, {"term_ko": "주입", "term_vi": "Truyền", "def_ko": "체내에 약액을 넣는 행위", "def_vi": "Hành động đưa chất lỏng vào cơ thể"}, {"term_ko": "부위", "term_vi": "Vị trí", "def_ko": "신체의 특정 장소", "def_vi": "Một địa điểm cụ thể trên cơ thể"}, {"term_ko": "주사부위", "term_vi": "Vị trí tiêm", "def_ko": "주사가 시행되는 구역", "def_vi": "Khu vực được tiêm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1236, '10', '왼쪽 귀에 염증이 있는 대상자에게 귀약을 투여할 때 올바른 방법은?', '["왼쪽 귀를 위쪽으로 하여 편안한 자세를 취하도록 한다.", "귓바퀴를 후하방으로 잡아당겨 약물투여가 쉽도록 한다.", "약물이 잘 흡수되도록 귀입구를 문질러 준다.", "투여 직후 왼쪽 귀를 아래로 하여 5분간 누워있게 한다.", "투여 후 하루동안 귓구멍에 작은 솜을 끼워 놓는다."]'::jsonb, 1, '耳약 투여 시 올바른 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "올바른 자세를 유지하여 귀약이 효과적으로 투여될 수 있도록 돕는다.\n[정답]", "2": "귓바퀴를 후하방으로 잡아당기는 것은 귀약이 더 잘 투여되도록 하기 위한 올바른 방법이지만, 1번이 보다 좋은 방법이다.", "3": "귀입구를 문질러 주는 것은 보통 권장되지 않는 방법이다. 약물이 귀에 직접적으로 침투할 수 있도록 하는 관리가 필요하다.", "4": "투여 직후 누워 있는 것이 도움이 될 수 있으나, 5분간 누워 있을 필요는 없다.", "5": "투여 후 솜을 끼워 놓는 것은 권장되지 않는다. 이는 귀약에 따라 달라질 수 있으나, 일반적으로는 필요하지 않다."}'::jsonb, '[{"term_ko": "귀약", "term_vi": "Thuốc nhỏ tai", "def_ko": "약물 치료를 위해 귀에 넣는 약", "def_vi": "thuốc dùng để điều trị cho tai"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1235, '10', '한쪽 귀에 통증이 있는 대상자에게 귀약을 투여할 때 옳은 방법은?', '["똑바로 누운 자세에서 투여한다.", "약을 넣기 전에 면봉으로 귓속을 깨끗이 닦아 준다.", "점적 후 솜을 이관 내에 꼭 끼워 눌러 준다.", "이도 중앙에 정확한 방울 수의 약물을 점적한다.", "점적 후 귀입구를 부드럽게 눌러주고 5분간 누워있게 한다."]'::jsonb, 5, '귀약 투여 시 올바른 자세와 방법을 알고 있는지를 평가하기 위함입니다.', NULL, '{"1": "똑바로 누운 자세는 귀약 투여에 적합하지 않습니다.", "2": "약을 넣기 전에 면봉으로 귓속을 깨끗이 닦는 것은 권장되지 않습니다.\n[정답]", "5": "점적 후 귀입구를 부드럽게 눌러주고 5분간 누워있게 하는 것이 올바른 방법입니다.", "3": "점적 후 솜을 이관 내에 꼭 끼워 눌러 주는 것은 잘못된 방법입니다.", "4": "이도 중앙에 정확한 방울 수의 약물을 점적하는 것은 중요하지만, 다른 방법과 함께 시행해야 합니다."}'::jsonb, '[{"term_ko": "귀약", "term_vi": "Thuốc nhỏ tai", "def_ko": "귀에 사용하는 약물", "def_vi": "Thuốc dùng cho tai"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1234, '10', '귀약을 투여하는 방법으로 옳은 것은?', '["냉장고에서 꺼내 바로 사용한다.", "점적 전에 면봉으로 귓바퀴와 외이도를 닦는다.", "치료할 귀를 아래쪽으로 향하게 한다.", "점적 후 귓바퀴를 후하방으로 잡아당긴다.", "작은 솜을 안쪽 깊이 끼워넣는다."]'::jsonb, 2, '귀약 투여에 대한 올바른 방법을 이해하고 있는지를 묻는 문제입니다.', NULL, '{"1": "냉장고에서 보관된 약물은 사용 전에 실온에 두어야 합니다.\n[정답]", "2": "점적 전에 면봉으로 귓바퀴와 외이도를 닦는 것이 중요합니다.", "3": "치료할 귀를 아래쪽으로 향하는 것이 꼭 필요한 것은 아닙니다.", "4": "점적 후 귓바퀴를 후하방으로 잡아당겨야 약물이 잘 들어갑니다.", "5": "작은 솜을 깊이 끼워넣는 것은 금지되어 있습니다."}'::jsonb, '[{"term_ko": "귀약", "term_vi": "Thuốc nhỏ tai", "def_ko": "귀에 사용하는 약", "def_vi": "Thuốc sử dụng cho tai"}, {"term_ko": "점적", "term_vi": "Nhỏ giọt", "def_ko": "떨어뜨리다", "def_vi": "Hành động làm nhỏ giọt"}, {"term_ko": "귓바퀴", "term_vi": "Vành tai", "def_ko": "귓속에서 겉으로 보이는 부분", "def_vi": "Phần bên ngoài của tai"}, {"term_ko": "외이도", "term_vi": "Ống tai ngoài", "def_ko": "귀의 바깥쪽 통로", "def_vi": "Đường dẫn bên ngoài của tai"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1233, '10', '냉장고에 보관 중인 약물을 귀에 투여할 때 옳은 방법은?', '["전자레인지에 넣고 데운다.", "햇볕이 잘 드는 창가에 둔다.", "끓는 물에 담가 데운다.", "차가운 상태로 바로 복용한다.", "손으로 따뜻하게 하여 사용한다."]'::jsonb, 5, '귀에 투여할 약물의 올바른 보관 및 사용 방법을 확인하는 문제입니다.', NULL, '{"1": "전자레인지에 넣고 데우는 것은 약물의 효과를 저하시킬 수 있으므로 잘못된 방법입니다.\n[정답]", "5": "손으로 따뜻하게 하여 사용하는 방법은 귀에 투여하기 전에 약물을 적정 온도로 맞춰주는 올바른 방법입니다.", "3": "끓는 물에 담가 데우는 것은 약물의 성분을 변질시킬 수 있어 위험합니다.", "4": "차가운 상태로 바로 복용하는 것은 약물의 효과를 감소시킬 수 있습니다.", "2": "햇볕이 잘 드는 창가에 두는 것은 온도 조절이 제대로 이루어지지 않아 문제가 될 수 있습니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "thuốc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1232, '10', '안연고를 투여하는 방법으로 옳은 것은?', '["처음 나온 연고는 거즈로 닦아 버린다.", "동공에 직접 대고 짜 넣는다.", "약을 넣은 후 눈을 감고 안구를 고정시킨다.", "눈꺼풀 밖으로 나온 연고는 멸균 솜으로 밀어 넣는다.", "눈 바깥쪽에서 안쪽으로 짜 넣는다."]'::jsonb, 1, '안연고의 올바른 투여 방법에 대한 이해를 확인하고자 하는 문제입니다.', NULL, '{"1": "처음 나온 연고는 거즈로 닦아 버린다.\n[정답]", "2": "동공에 직접 대고 짜 넣는다.", "3": "약을 넣은 후 눈을 감고 안구를 고정시킨다.", "4": "눈꺼풀 밖으로 나온 연고는 멸균 솜으로 밀어 넣는다.", "5": "눈 바깥쪽에서 안쪽으로 짜 넣는다."}'::jsonb, '[{"term_ko": "안연고", "term_vi": "Thuốc mỡ mắt", "def_ko": "눈에 사용하는 약물", "def_vi": "Thuốc dùng cho mắt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1231, '10', '대상자에게 안약을 투여하는 방법으로 옳은 것은?', '["위 눈꺼풀에 멸균솜을 대어 준다.", "대상자에게 아래를 보게 한다.", "안약을 각막에 점적한다.", "안약을 점적한 후 비루관을 눌러 준다.", "멸균솜으로 눈 바깥쪽에서 안쪽으로 닦는다."]'::jsonb, 4, '안약 투여 방법에 대한 정확한 이해도를 평가하기 위함입니다.', NULL, '{"1": "위 눈꺼풀에 멸균솜을 대는 것은 안약 투여 방법이 아닙니다.\n[정답]", "2": "대상자에게 아래를 보게 하는 것은 부적절하며, 각막이 아닌 아래쪽을 향하게 됩니다.", "3": "안약을 각막에 점적하는 것은 맞지만, 추가 조치가 필요합니다.", "4": "안약을 점적한 후 비루관을 눌러주는 것은 약물의 흡수율을 높이기 위한 올바른 방법입니다.", "5": "멸균솜으로 닦는 것은 필요 없는 조치입니다."}'::jsonb, '[{"term_ko": "안약", "term_vi": "Thuốc nhỏ mắt", "def_ko": "눈에 사용하는 약물", "def_vi": "thuốc dùng cho mắt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1230, '10', '한쪽 눈에만 감염이 있을 때, 반대편 눈에 전염되지 않도록 멸균 솜을 이용하여 닦아내는 방향은?', '["어느 방향이든 상관없다.", "눈 바깥쪽에서 안쪽으로 닦는다.", "눈 안쪽에서 바깥쪽으로 닦는다.", "눈 주위를 둥근 원을 그리며 닦는다.", "눈 주위를 위에서 아래로 닦는다."]'::jsonb, 3, '한쪽 눈에 감염이 있는 경우, 반대편 눈에 전염되지 않도록 올바른 닦기 방향을 묻는 문제입니다.', NULL, '{"1": "어느 방향이든 상관없다. - 잘못된 정보로, 감염 예방을 위한 정확한 방법이 아닙니다.\n[정답]", "3": "눈 안쪽에서 바깥쪽으로 닦는다. - 이 방법이 감염 전파를 예방하는데 가장 안전한 방법입니다.", "2": "눈 바깥쪽에서 안쪽으로 닦는다. - 잘못된 방법으로 감염이 확산될 수 있습니다.", "4": "눈 주위를 둥근 원을 그리며 닦는다. - 효과적인 방법이 아니며, 감염 위험이 있습니다.", "5": "눈 주위를 위에서 아래로 닦는다. - 이 방법도 감염 확산의 위험이 있습니다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염(한국어)", "def_vi": "nhiễm trùng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1229, '10', '물약을 따르기 전에 흔들어서 섞는 이유는?', '["변질을 막기 위해", "냄새를 없애기 위해", "약의 흡수를 위해", "쓴맛을 없애기 위해", "농도를 맞추기 위해"]'::jsonb, 5, '물약을 따를 때 흔들어서 섞는 이유에 대한 이해를 평가하기 위한 질문입니다.', NULL, '{"1": "변질을 막기 위해\n약물이 변질되지 않도록 흔드는 것은 중요하지만, 주요 목적은 아닙니다.\n[정답]", "5": "농도를 맞추기 위해\n물약의 성분이 고르게 섞여 농도가 일정하게 유지되도록 하기 위해 흔듭니다.", "3": "약의 흡수를 위해\n흔드는 것이 약물의 흡수에 직접적인 영향을 주지는 않습니다.", "4": "쓴맛을 없애기 위해\n쓴맛은 흔드는 것과는 별개로, 맛을 조절하는 과정이 필요합니다.", "2": "냄새를 없애기 위해\n냄새를 줄이는 것은 흔드는 것과 관련이 없습니다."}'::jsonb, '[{"term_ko": "물약", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "thuốc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1228, '10', '대상자에게 물약을 투여할 때 돕기 방법으로 옳은 것은?', '["계량컵이 없을 때에는 종이컵을 이용한다.", "라벨이 붙은 쪽 방향으로 용액을 따른다.", "용량을 초과해서 따른 약은 약병에 다시 넣는다.", "병 뚜껑을 씌우기 전에 복용량을 확인한다.", "약의 용량이 적을 때는 바늘을 제거한 주사기를 이용하여 투여한다."]'::jsonb, 5, '대상자에게 물약을 안전하게 투여하는 방법을 묻고 있습니다.', NULL, '{"1": "계량컵이 없을 경우 종이컵은 일반적인 계량 도구가 아니므로 정확성을 보장할 수 없습니다.\n[정답]", "2": "라벨이 붙은 쪽 방향으로 용액을 따르면 혼동을 방지할 수 있어 옳은 방법입니다.", "3": "용량을 초과한 약은 재사용하면 안 되므로 잘못된 방법입니다.", "4": "병 뚜껑을 씌우기 전에 복용량을 확인하는 것은 중요하지만, 복용 전 확인이 필요합니다.", "5": "약의 용량이 적은 경우 바늘을 제거한 주사기를 이용하여 투여하는 것이 적절한 방법입니다."}'::jsonb, '[{"term_ko": "물약", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "thuốc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1227, '10', '대상자의 약 복용을 돕는 방법으로 옳은 것은?', '["삼키기 어려운 알약은 갈아서 먹인다.", "약을 먹인 후 물은 조금만 준다.", "알약이 많을 경우에도 한번에 먹인다.", "약을 떨어뜨릴 우려가 있는 대상자는 직접 입안에 넣어준다.", "남은 알약은 다른 용기에 담아 냉장 보관한다."]'::jsonb, 4, '대상자의 약 복용을 돕는 올바른 방법을 이해하고 판단하는지 평가하기 위함이다.', NULL, '{"1": "삼키기 어려운 알약은 갈아서 먹인다. 이는 약의 성분 변화를 초래할 수 있어 위험하다.\n[정답]", "4": "약을 떨어뜨릴 우려가 있는 대상자는 직접 입안에 넣어준다. 이는 안전한 방법이다.", "2": "약을 먹인 후 물은 조금만 준다. 충분한 물을 제공해야 약의 효과가 제대로 나타난다.", "3": "알약이 많을 경우에도 한번에 먹인다. 여러 번에 나눠서 먹이는 것이 안전하다.", "5": "남은 알약은 다른 용기에 담아 냉장 보관한다. 약의 보관 방법을 준수해야 한다."}'::jsonb, '[{"term_ko": "약", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "Thuốc"}, {"term_ko": "복용", "term_vi": "Uống thuốc", "def_ko": "복용(한국어)", "def_vi": "Uống thuốc"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Người bệnh"}, {"term_ko": "알약", "term_vi": "Viên thuốc", "def_ko": "알약(한국어)", "def_vi": "Viên thuốc"}, {"term_ko": "보관", "term_vi": "Bảo quản", "def_ko": "보관(한국어)", "def_vi": "Bảo quản"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1226, '10', '물약 복용 돕기 방법으로 옳은 것은?', '["햇볕이 잘 드는 곳에 약을 보관한다.", "병뚜껑 안쪽이 바닥을 향하도록 놓는다.", "계량컵을 눈높이로 들고 따른다.", "남은 약은 다시 부어 넣는다.", "주사기에 1회분씩 나누어 보관한다."]'::jsonb, 3, '물약 복용 보조 방법에 대한 이해를 평가하고자 하는 문제입니다.', NULL, '{"1": "햇볕이 잘 드는 곳에 약을 보관하면 약의 효능이 떨어질 수 있어 올바른 방법이 아닙니다.\n[정답]", "3": "계량컵을 눈높이로 들고 따르는 것은 정확한 양을 측정하는 데 도움이 됩니다.", "2": "병뚜껑 안쪽이 바닥을 향하도록 놓으면 보관하기 어려우며, 사용하기 불편합니다.", "4": "남은 약은 다시 부어 넣는 것은 오염의 위험이 있기 때문에 바람직하지 않습니다.", "5": "주사기에 1회분씩 나누어 보관하는 것은 부적절한 방법으로, 약물의 효능을 저하시킬 수 있습니다."}'::jsonb, '[{"term_ko": "물약", "term_vi": "Thuốc", "def_ko": "약물(한국어)", "def_vi": "thuốc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1225, '10', '대상자의 경구 약 복용 방법으로 옳은 것은?', '["알약은 병에 손가락을 넣어 꺼낸다.", "물약은 라벨이 없는 쪽을 잡고 용액을 따른다.", "색이 변하거나 혼탁한 약물은 잘 흔들어 먹인다.", "물약은 뚜껑 안쪽이 위로 가도록 놓는다.", "병뚜껑을 씌우기 전에 손으로 입구를 닦는다."]'::jsonb, 4, '대상자의 경구 약 복용 방법에 대한 이해를 평가하기 위한 질문입니다.', NULL, '{"1": "알약은 병에 손가락을 넣어 꺼내는 것은 위생적이지 않으므로 잘못된 방법입니다.\n[정답]", "2": "물약은 라벨이 없는 쪽을 잡고 용액을 따르는 것은 라벨이 있는 쪽을 잡아야 하므로 잘못된 방법입니다.", "3": "색이 변하거나 혼탁한 약물은 잘 흔들어 먹이는 것이 아니라, 사용하지 않아야 하는 약물입니다.", "4": "물약은 뚜껑 안쪽이 위로 가도록 놓는 것이 올바른 방법입니다.", "5": "병뚜껑을 씌우기 전에 손으로 입구를 닦는 것은 위생적인 방법입니다."}'::jsonb, '[{"term_ko": "경구", "term_vi": "Đường uống", "def_ko": "입을 통해 복용하는 것", "def_vi": "Sử dụng qua miệng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1224, '10', '자주 사레들리는 대상자의 가루약 복용을 돕는 방법은?', '["가루약을 입안에 넣은 후 물을 먹인다.", "음식이나 우유에 섞어서 먹인다.", "물약에 섞어 빨대로 천천히 먹인다.", "입 안에 물을 먼저 넣고 가루약을 털어 넣는다.", "숟가락에 약을 담아 물로 녹여 먹인다."]'::jsonb, 5, '대상자의 가루약 복용 방법을 이해하고 실천할 수 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "가루약을 입안에 넣은 후 물을 먹인다: 입안의 가루약이 불편하게 느껴질 수 있어 권장되지 않습니다.\n[정답]", "2": "음식이나 우유에 섞어서 먹인다: 가루약을 섞어 복용하는 것은 좋은 방법이지만, 약의 종류에 따라 효과가 떨어질 수 있습니다.", "3": "물약에 섞어 빨대로 천천히 먹인다: 물약과 섞이는 과정에서 약효가 감소할 수 있습니다.", "4": "입 안에 물을 먼저 넣고 가루약을 털어 넣는다: 두 가지가 동시에 들어가 불편할 수 있습니다.", "5": "숟가락에 약을 담아 물로 녹여 먹인다: 올바른 방법으로, 약을 잘 섭취할 수 있는 방법입니다."}'::jsonb, '[{"term_ko": "사레", "term_vi": "Sare", "def_ko": "기침이나 숨막힘", "def_vi": "ho hoặc khó thở"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "치료를 받는 사람", "def_vi": "người nhận điều trị"}, {"term_ko": "가루약", "term_vi": "Thuốc bột", "def_ko": "분말 형태의 약", "def_vi": "thuốc ở dạng bột"}, {"term_ko": "복용", "term_vi": "Sử dụng", "def_ko": "약을 먹는 과정", "def_vi": "quá trình uống thuốc"}, {"term_ko": "물", "term_vi": "Nước", "def_ko": "액체, 음료", "def_vi": "chất lỏng, đồ uống"}, {"term_ko": "음식", "term_vi": "Thức ăn", "def_ko": "식사", "def_vi": "bữa ăn"}, {"term_ko": "우유", "term_vi": "Sữa", "def_ko": "유제품", "def_vi": "sản phẩm từ sữa"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1223, '10', '대상자의 약 복용을 돕는 방법으로 옳은 것은?', '["처방된 이외의 약은 섞어준다.", "용량이 많은 물약은 주사기를 이용하여 복용한다.", "잘못 복용했을 경우 토하게 한다.", "개수가 많은 알약은 2~3번에 나누어 투약한다.", "계량컵을 눈높이 보다 위로 들고 따른다."]'::jsonb, 4, '대상자의 약 복용 방법에 대한 이해와 적용 능력을 평가하기 위함입니다.', NULL, '{"1": "처방된 이외의 약은 섞어주면 안 되므로 잘못된 방법입니다.\n[정답]", "2": "용량이 많은 물약은 주사기로 정확히 측정하여 복용하는 것이 좋습니다.", "3": "잘못 복용했을 경우 안전한 방법은 의료진에게 연락하는 것이지 토하게 하는 것은 위험할 수 있습니다.", "4": "개수가 많은 알약은 2~3번에 나누어 투약하는 것이 올바른 방법입니다.", "5": "계량컵은 눈높이와 일치하게 들고 따라야 정확한 양을 측정할 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1222, '10', '경구약 복용으로 돕는 방법으로 옳은 것은?', '["알약은 손바닥에 따른다.", "알약은 가루로 만들어 복용하게 한다.", "가급적 물은 소량만 먹인다.", "스스로 먹을 수 있도록 대상자 손에 직접준다.", "질문을 하여 입안에 약이 남아 있는지 확인한다."]'::jsonb, 5, '환자가 경구약을 올바르게 복용하는 방법을 이해하고 있는지를 평가하는 질문입니다.', NULL, '{"1": "알약이 손바닥에 따라서는 안 됩니다. 복용 시 안정성이 중요합니다.\n[정답]", "5": "질문을 통해 입안에 약이 남아 있는지 확인하는 것은 중요합니다.", "2": "알약을 가루로 만들어 복용하게 하는 것은 환자에게 혼란을 줄 수 있습니다.", "3": "물은 충분히 먹여야 약물이 제대로 작용할 수 있습니다.", "4": "스스로 복용 할 수 있도록 돕는 것은 중요하지만, 항상 직접 넘겨주는 것은 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "경구약", "term_vi": "Thuốc uống", "def_ko": "입으로 복용하는 약", "def_vi": "Thuốc được uống qua miệng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1221, '10', '약물 복용 시 치아착색을 방지하기 위해 사용하는 도구는?', '["빨대", "유리컵", "약병뚜껑", "플라스틱 스푼", "플라스틱 컵"]'::jsonb, 1, '약물을 복용할 때 치아 착색을 방지하는 방법에 대해 질문하고 있습니다.', NULL, '{"1": "빨대를 사용하면 약물이 치아에 직접 닿지 않아 착색을 예방할 수 있습니다.\n[정답]", "2": "유리컵은 약물을 담는 용도로 사용되지만, 치아 착색을 방지하는 데는 도움이 되지 않습니다.", "3": "약병뚜껑은 약물을 따르는 용도로 불편하며 착색을 방지하지 못합니다.", "4": "플라스틱 스푼은 약물을 복용하는 방법일 뿐 치아 착색에는 영향이 없습니다.", "5": "플라스틱 컵도 치아에 직접적인 영향을 미치는 것이 아니므로 착색을 방지하지 않습니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "thuốc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1220, '10', '대상자의 복약을 돕는 방법으로 옳은 것은?', '["금식 중이라도 혈압약은 투약한다.", "유효기간이 지난 약은 냉장보관 한다.", "잘못 복용했을 경우 물을 많이 마시게 한다.", "캡슐약은 캡슐을 벗기고 투약한다.", "약을 삼키지 못할 경우 갈거나 쪼갠다."]'::jsonb, 1, '대상자의 복약 관리에 있어 올바른 방법을 알고 있는지 평가하고자 함.', NULL, '{"1": "금식 중에도 혈압약은 생명 유지와 연관되어 반드시 투약해야 한다.\n[정답]", "2": "유효기간이 지난 약은 효과가 없으므로 냉장 보관해서는 안 된다.", "3": "잘못 복용했을 경우 물을 많이 마시게 하는 것은 권장되지 않는다.", "4": "캡슐약은 그대로 복용해야 하며 벗기면 약효가 달라질 수 있다.", "5": "약을 삼키지 못할 경우에는 의사와 상담 후 적절한 방법을 결정해야 한다."}'::jsonb, '[{"term_ko": "복약", "term_vi": "Dùng thuốc", "def_ko": "약을 복용하는 것", "def_vi": "Uống thuốc"}, {"term_ko": "혈압약", "term_vi": "Thuốc huyết áp", "def_ko": "혈압 조절을 위한 약", "def_vi": "Thuốc điều chỉnh huyết áp"}, {"term_ko": "유효기간", "term_vi": "Thời hạn sử dụng", "def_ko": "약의 사용이 가능한 기간", "def_vi": "Thời gian thuốc có thể sử dụng"}, {"term_ko": "잘못", "term_vi": "Sai", "def_ko": "잘못된 것", "def_vi": "Điều không đúng"}, {"term_ko": "삼키다", "term_vi": "Nuốt", "def_ko": "입으로 넘기는 것", "def_vi": "Đưa vào trong cơ thể qua miệng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1219, '10', '경관 영양액 주입 중 시설장, 간호사에게 즉시 보고해야 할 사항은?', '["입 안의 건조", "갈증", "다뇨", "변비", "구토"]'::jsonb, 5, '경관 영양 중 발생할 수 있는 부작용 중 즉각적으로 보고해야 할 사항을 확인하기 위함입니다.', NULL, '{"1": "입 안의 건조는 일반적인 증상이나 즉시 보고할 정도는 아닙니다.", "2": "갈증은 느낄 수 있지만, 긴급한 상황은 아닙니다.", "3": "다뇨는 지켜봐야 하는 증상이나 즉각적인 위험은 아닙니다.", "4": "변비는 흔한 문제이나 긴급한 사항에 포함되지 않습니다.\n[정답]", "5": "구토는 경관 영양 시 즉각적으로 보고해야 할 심각한 증상입니다."}'::jsonb, '[{"term_ko": "경관", "term_vi": "Dinh dưỡng ống", "def_ko": "위장관으로 음식을 공급하는 방식", "def_vi": "Phương thức cung cấp thức ăn qua ống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1218, '10', '스스로 식사할 수 없는 대상자의 경관영양을 돕는 방법은?', '["구강간호는 하지 않아도 된다.", "비위관이 빠졌을 경우 신속히 밀어 넣는다.", "고농도의 영양액을빠르게 주입한다.", "비위관이 잘 고정되어 있는지 확인한다.", "영양 주머니에 영양액을 가득 채운다."]'::jsonb, 4, '경관영양을 필요로 하는 환자에게 올바른 관리 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "구강간호는 경관영양을 받는 환자에게도 필요하다. 따라서 하지 않아도 된다는 것은 잘못된 정보이다.\n[정답]", "2": "비위관이 빠졌을 경우 즉시 재삽입해야 하지만, 밀어 넣는 것은 위험하다.", "3": "고농도의 영양액을 빠르게 주입하는 것은 환자에게 부담이 될 수 있으므로 적절하지 않다.", "4": "비위관이 잘 고정되어 있는지 확인하는 것은 매우 중요하다.", "5": "영양 주머니에 영양액을 가득 채우는 것은 필요하지만, 과다 추입은 피해야 한다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua ống thông", "def_ko": "위에 튜브를 통해 영양을 공급하는 것", "def_vi": "Cung cấp dinh dưỡng thông qua ống vào dạ dày"}, {"term_ko": "비위관", "term_vi": "Ống thông dạ dày", "def_ko": "위에 넣는 관", "def_vi": "Ống được đưa vào dạ dày"}, {"term_ko": "영양액", "term_vi": "Dung dịch dinh dưỡng", "def_ko": "영양이 포함된 액체", "def_vi": "Chất lỏng chứa dinh dưỡng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1217, '10', '침상에 누워있는 경관영양액 주입 대상자를 오른쪽으로 눕혀서 제공하는 이유는?', '["비위관이 새지 않게 하기 위해서", "영양액 속도를 조절하기 위해서", "비위관을 빼지 못하게 하기 위해서", "편안한 자세 유지를 위해서", "기도로의 역류 가능성을 줄이기 위해서"]'::jsonb, 5, '경관영양 주입 시 환자의 안전과 편안함을 고려하는 이유를 이해하기 위한 문제입니다.', NULL, '{"1": "비위관이 새지 않게 하기 위해서\n비위관이 새지 않도록 하는 것은 중요하지만, 주로 코 위치나 관의 상태에 따라 결정되므로 오른쪽으로 눕히는 주된 이유는 아닙니다.", "2": "영양액 속도를 조절하기 위해서\n영양액 속도 조절은 주입 관리와 관련된 사항이며, 자세 변경과는 큰 관련이 없습니다.", "3": "비위관을 빼지 못하게 하기 위해서\n비위관을 제자리에 두는 것도 중요하지만, 이는 환자의 자세와 직접적인 관련이 없습니다.", "4": "편안한 자세 유지를 위해서\n편안한 자세 유지도 고려 사항이지만, 오른쪽으로 눕히는 주된 이유는 기도로의 역류 가능성을 줄이기 위함입니다.\n[정답]", "5": "기도로의 역류 가능성을 줄이기 위해서\n경관영양을 주입하는 환자를 오른쪽으로 눕히면 기도로의 영양액 역류를 방지하여 흡인 위험을 줄일 수 있습니다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "Giường ngủ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1216, '10', '경관영양 대상자를 돕는 방법으로 옳은 것은?', '["침상머리를 올려 대상자를 앉게 한다.", "의식이 없는 경우에만 경관영양을 한다.", "영양액 주머니는 침대 난간 아래에 건다.", "영양액이 역류하면 영양주머니를 높여준다.", "비위관이 막히거나 혼탁할 경우 세척을 위해 빼낸다."]'::jsonb, 1, '경관영양의 올바른 시행 방법에 대한 이해와 적용을 묻는 문제입니다.', NULL, '{"1": "경관영양을 실시할 때 환자의 안전을 위해 침상머리를 올려 앉히는 것이 올바른 방법입니다.\n[정답]", "2": "의식이 있는 환자도 필요시 경관영양을 할 수 있으며, 의식이 없는 경우만 해당되지 않습니다.", "3": "영양액 주머니는 침대 난간 위에 걸어야 하며, 아래에 걸면 역류의 위험이 있습니다.", "4": "영양액이 역류하면 영양주머니를 낮춰야 하며, 높이면 더욱 악화될 수 있습니다.", "5": "비위관이 막히거나 혼탁할 경우에는 세척을 하지만, 반드시 빼내는 것은 아닙니다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua ống dẫn", "def_ko": "인공적으로 음식을 공급하는 방법", "def_vi": "Phương pháp cung cấp thức ăn một cách nhân tạo"}, {"term_ko": "침상", "term_vi": "Giường bệnh", "def_ko": "병상", "def_vi": "Giường của bệnh nhân"}, {"term_ko": "역류", "term_vi": "Trào ngược", "def_ko": "되돌아오는 현상", "def_vi": "Hiện tượng quay trở lại"}, {"term_ko": "비위관", "term_vi": "Ống thông dạ dày", "def_ko": "위장관의 일종", "def_vi": "Một loại ống dẫn trong dạ dày"}, {"term_ko": "세척", "term_vi": "Rửa", "def_ko": "씻어내는 것", "def_vi": "Việc rửa sạch"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1215, '10', '경관영양을 하는 대상자를 돕는 방법으로 옳은 것은?', '["고농도의 진한 영양액을 준비한다.", "청색증이 나타나면 천천히 주입한다.", "영양액 주입 후 알코올 솜으로 입안을 닦아준다.", "비위관 삽입 부위에 윤활제를 바른다.", "영양액 주머니는 매번 소독하여 사용한다."]'::jsonb, 4, '경관영양을 시행하는 과정에서 알맞은 방법을 이해하고 있는지를 평가하기 위한 문제이다.', NULL, '{"1": "고농도의 진한 영양액을 준비하는 것은 위험할 수 있으며, 일반적으로 권장되지 않는다.\n[정답]", "2": "청색증이 나타날 경우에는 주입 속도를 줄여야 하나 무조건 천천히 주입하는 것은 아니라서 틀리다.", "3": "영양액 주입 후 입안을 닦는 것은 일반적이지 않으며 필요하지 않다.", "4": "비위관 삽입 부위에 윤활제를 바르는 것은 올바른 방법이다.", "5": "영양액 주머니는 매번 소독할 필요 없이 청결하게 관리하면 된다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua ống thông", "def_ko": "위나 장을 통해 영양을 공급하는 방법", "def_vi": "Phương pháp cung cấp dinh dưỡng qua dạ dày hoặc ruột"}, {"term_ko": "청색증", "term_vi": "Xanh tím", "def_ko": "피부와 점막이 파랗게 변하는 상태", "def_vi": "Tình trạng da và niêm mạc chuyển sang màu xanh"}, {"term_ko": "비위관", "term_vi": "Ống thông dạ dày", "def_ko": "위에 삽입하는 관", "def_vi": "Ống được đặt vào dạ dày"}, {"term_ko": "윤활제", "term_vi": "Chất bôi trơn", "def_ko": "마찰을 줄이고 부드럽게 하는 물질", "def_vi": "Chất làm giảm ma sát và làm cho bề mặt trơn tru"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1214, '10', '영양액의 주입이 빠르거나 고농도의 영양을 주입할 때 나타날 수 있는 증상은?', '["혈변", "변비", "설사", "혈뇨", "단백뇨"]'::jsonb, 3, '영양액 주입 속도 및 농도의 영향을 이해하고 관련 증상을 파악하는 것.', NULL, '{"1": "혈변: 소화관에서 출혈이 발생할 경우 나타날 수 있는 증상으로, 영양액 주입과는 관련이 적다.", "2": "변비: 배변이 어려운 상태로, 영양액 주입과 직접적인 연결이 없다.\n[정답]", "3": "설사: 빠르거나 고농도의 영양액 주입 시 장에 자극을 줄 수 있어 설사가 발생할 수 있다.", "4": "혈뇨: 비뇨기계의 출혈로 인한 증상으로, 영양액과 관련이 없다.", "5": "단백뇨: 신장 문제에 의한 증상으로, 직접적인 연관성은 적다."}'::jsonb, '[{"term_ko": "영양액", "term_vi": "Dịch dinh dưỡng", "def_ko": "영양 chất이 포함된 액체(한국어)", "def_vi": "chất lỏng chứa dinh dưỡng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1213, '10', '경관영양을 받고 있는 대상자가 설사를 계속할 때 주의해서 관찰해야 하는것은?', '["탈수", "구토", "오심", "부종", "다뇨"]'::jsonb, 1, '경관영양을 받는 대상자의 상태 변화를 인식하여 적절한 대처를 하도록 유도하는 문제입니다.', NULL, '{"1": "설사를 지속할 경우 탈수가 발생할 수 있으므로 주의 깊게 관찰해야 합니다.\n[정답]", "2": "구토는 탈수와 관련성 있지만 우선적으로 관찰해야 하는 것은 아닙니다.", "3": "오심은 불편감을 초래하나 탈수와 직접적인 연관이 없습니다.", "4": "부종은 경관영양과 관련이 적고, 주의해야 할 사항이 아닙니다.", "5": "다뇨는 다른 건강문제를 시사할 수 있지만, 설사와의 직접적인 연관은 적습니다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua ống", "def_ko": "위나 장을 통해 영양을 공급하는 방법", "def_vi": "Phương pháp cung cấp dinh dưỡng qua dạ dày hoặc ruột"}, {"term_ko": "탈수", "term_vi": "Mất nước", "def_ko": "체내 수분이 부족한 상태", "def_vi": "Tình trạng thiếu nước trong cơ thể"}, {"term_ko": "구토", "term_vi": "Nôn", "def_ko": "입이나 코를 통해 위 내용물이 나오는 것", "def_vi": "Sự thoát ra của thức ăn từ dạ dày qua miệng hoặc mũi"}, {"term_ko": "오심", "term_vi": "Buồn nôn", "def_ko": "메스꺼움과 구토를 유발하는 불쾌한 감정", "def_vi": "Cảm giác khó chịu gây nôn mửa"}, {"term_ko": "부종", "term_vi": "Phù", "def_ko": "체내에 수분이 축적되어 부풀어 오르는 상태", "def_vi": "Tình trạng tích tụ nước trong cơ thể gây sưng"}, {"term_ko": "다뇨", "term_vi": "Tiểu nhiều", "def_ko": "소변의 양이 비정상적으로 많아지는 현상", "def_vi": "Hiện tượng lượng nước tiểu bất thường tăng lên"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1212, '10', '경관영양 돕기 시 시설장, 간호사에게 반드시 보고해야 할 사항은?', '["비위관이 눌려 있을 때", "비위관이 새고 있을 때", "영양액이 천천히 들어가고 있을 때", "대상자가 무의식적으로 빼려고 할 때", "비위관이 꺾여 있을 때"]'::jsonb, 2, '경관영양 중 비위관과 관련된 중요한 사항을 파악하고, 간호사나 시설장에게 보고해야 할 상황을 이해하는 것이다.', NULL, '{"1": "비위관이 눌려 있을 때는 보고할 필요가 있다. 하지만 긴급히 보고해야 할 상황은 아니다.\n[정답]", "2": "비위관이 새고 있을 때는 즉시 보고해야 하는 중요한 사항이다.", "3": "영양액이 천천히 들어가고 있을 때는 문제의 소지가 있으나, 보고해야 할 사항은 아니다.", "4": "대상자가 무의식적으로 빼려고 할 때는 주의가 필요하나, 보고해야 할 사항으로 보기는 어렵다.", "5": "비위관이 꺾여 있을 때는 상황을 점검해야하나, 즉각 보고할 사항은 아니다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua ống", "def_ko": "인공적으로 영양을 공급하는 방법(비위관)", "def_vi": "Phương pháp cung cấp dinh dưỡng một cách nhân tạo (ống dẫn dinh dưỡng)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1211, '10', '경관영양 돕기의 기본원칙으로 옳은 것은?', '["유효기간이 지난 영양액은 끓여서 주입한다.", "영양주머니는 하루에 한 번 세척하여 건조시킨다.", "대상자가 의식이 없어도 식사 시작과 끝을 알린다.", "비위관이 새거나 영양액이 역류되면 비위관을 즉시 뺀다.", "관이 막히지 않도록 영양액을 빠르게 주입한다."]'::jsonb, 3, '경관영양을 수행하는 요양보호사가 지켜야 할 기본 원칙에 대한 이해를 평가하고자 함.', NULL, '{"1": "유효기간이 지난 영양액은 끓여서 주입하면 안 된다. 이는 안전과 효과를 보장하지 못하기 때문이다.\n[정답]", "3": "대상자가 의식이 없어도 식사 시작과 끝을 알리는 것은 의사소통을 통한 안정감을 제공할 수 있기 때문이다.", "2": "영양주머니는 매일 세척할 필요는 없으며, 제조사 지침에 따라 관리해야 한다.", "4": "비위관이 새거나 영양액이 역류될 경우에는 확인 후 조치를 취해야 하며, 즉시 제거하는 것은 상황에 따라 달라질 수 있다.", "5": "영양액은 천천히 주입해야 관과 대상자의 안전을 보장할 수 있다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua ống", "def_ko": "비경구적 방법으로 영양을 공급하는 것", "def_vi": "Phương pháp cung cấp dinh dưỡng không qua đường miệng"}, {"term_ko": "영양액", "term_vi": "Dung dịch dinh dưỡng", "def_ko": "체내에 공급되는 영양소가 포함된 액체", "def_vi": "Chất lỏng chứa các chất dinh dưỡng được cung cấp cho cơ thể"}, {"term_ko": "비위관", "term_vi": "Ống thông dạ dày", "def_ko": "위에 영양액을 공급하기 위한 관", "def_vi": "Ống được sử dụng để cung cấp dung dịch dinh dưỡng vào dạ dày"}, {"term_ko": "역류", "term_vi": "Trào ngược", "def_ko": "액체가 원래 있던 위치로 되돌아가는 현상", "def_vi": "Hiện tượng chất lỏng trở lại vị trí ban đầu"}, {"term_ko": "유효기간", "term_vi": "Thời hạn sử dụng", "def_ko": "제품이 안전하고 효과적으로 사용될 수 있는 기간", "def_vi": "Khoảng thời gian sản phẩm có thể được sử dụng một cách an toàn và hiệu quả"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1210, '10', '경관영양을 해야 하는 대상자는?', '["편식하는 대상자", "영양공급이 충분한 대상자", "식사를 거부하는 대상자", "의식이 없거나 혼수에 빠진 대상자", "의치를 착용하고 있는 대상자"]'::jsonb, 4, '경관영양이 필요한 대상자를 이해하고 평가하기 위한 질문이다.', NULL, '{"1": "편식하는 대상자는 경관영양이 필요하지 않다.\n[정답]", "3": "의식이 없거나 혼수에 빠진 대상자는 경관영양이 반드시 필요하다.", "2": "영양공급이 충분한 대상자는 경관영양이 필요하지 않다.", "4": "의치를 착용하고 있는 대상자는 경관영양이 필요하지 않다.", "5": "식사를 거부하는 대상자는 경관영양이 필요할 수 있으나, 의식이 없거나 혼수에 빠진 경우가 더 명확하다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua đường dẫn", "def_ko": "위장관에 직접 영양을 공급하는 방법", "def_vi": "Phương pháp cung cấp dinh dưỡng trực tiếp vào đường tiêu hóa"}, {"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "도움이나 지원이 필요한 사람", "def_vi": "Người cần sự trợ giúp hoặc hỗ trợ"}, {"term_ko": "편식", "term_vi": "Kén ăn", "def_ko": "특정 음식만 고집하는 것", "def_vi": "Chỉ ăn một số loại thực phẩm nhất định"}, {"term_ko": "혼수", "term_vi": "Hôn mê", "def_ko": "의식이 없는 상태", "def_vi": "Trạng thái không có ý thức"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "스스로 알고 느끼는 상태", "def_vi": "Trạng thái tự nhận thức và cảm nhận"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1209, '10', '왼쪽 편마비 대상자에게 침상에서 식사를 제공하는 방법으로 옳은 것은?', '["대상자의 왼쪽에서 식사를 돕는다.", "입안의 왼쪽에 음식을 넣어준다.", "오른쪽 상체를 베개로 지지해준다.", "오른손에 식사보조도구를 끼워준다.", "식후 왼쪽의 입안에 음식 찌꺼기가 남아 있는지 확인한다."]'::jsonb, 5, '왼쪽 편마비 대상자에게 적절한 식사 제공 방법을 이해하고 평가하기 위함입니다.', NULL, '{"1": "대상자의 왼쪽에서 식사를 돕는 것은 편마비 환자에게 불편할 수 있습니다.\n[정답]", "5": "식후 왼쪽의 입안에 음식 찌꺼기가 남아 있는지 확인하는 것은 안전을 위해 매우 중요합니다.", "2": "입안의 왼쪽에 음식을 넣어주는 것은 잘못된 방법입니다.", "3": "오른쪽 상체를 베개로 지지해주는 것은 도움이 될 수 있지만 기준이 아닙니다.", "4": "오른손에 식사보조도구를 끼우는 것은 편마비 환자에게 적절하지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "편측 마비(사람의 한 쪽의 신체가 마비됨을 의미함)", "def_vi": "Tình trạng cơ thể bị liệt ở một bên"}, {"term_ko": "입안", "term_vi": "Miệng", "def_ko": "입의 안쪽", "def_vi": "Bên trong miệng"}, {"term_ko": "음식 찌꺼기", "term_vi": "Thức ăn thừa", "def_ko": "음식을 먹은 뒤 남은 것", "def_vi": "Phần thức ăn còn lại sau khi ăn"}, {"term_ko": "식사 보조 도구", "term_vi": "Dụng cụ hỗ trợ ăn uống", "def_ko": "식사할 때 사용하는 전문 도구", "def_vi": "Dụng cụ chuyên dụng để ăn uống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1208, '10', '연하곤란이 있는 대상자에게 식사를 제공할 때 사레를 예방하는 방법은?', '["대화하면서 식사를 제공한다.", "국물이 많은 음식을 제공한다.", "식사 전에 입안을 물로 헹궈 목을 축이게 한다.", "다양한 향신료를 넣은 음식을 제공한다.", "음식을 완전히 삼키기 전에 더 넣어 준다."]'::jsonb, 3, '연하곤란이 있는 대상자가 안전하게 식사하도록 도와주기 위한 올바른 방법을 묻는 문제입니다.', NULL, '{"1": "대화하면서 식사를 제공하면 집중력이 떨어져 사레가 발생할 수 있습니다.\n[정답]", "3": "식사 전에 입안을 물로 헹궈 목을 축이면 삼키는 데 도움이 됩니다.", "2": "국물이 많은 음식을 제공하면 삼키기 어려운 경우가 있어 위험합니다.", "4": "다양한 향신료를 넣은 음식은 자극적일 수 있어 사레를 유발할 수 있습니다.", "5": "음식을 완전히 삼키기 전에 더 넣어 주면 기도가 막힐 위험이 있습니다."}'::jsonb, '[{"term_ko": "연하곤란", "term_vi": "Khó khăn trong việc nuốt", "def_ko": "삼키기 어려운 증상", "def_vi": "Triệu chứng khó nuốt"}, {"term_ko": "사레", "term_vi": "Sặc", "def_ko": "기도가 막혀서 발생하는 현상", "def_vi": "Hiện tượng tắc nghẽn đường thở"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn uống"}, {"term_ko": "입안", "term_vi": "Miệng", "def_ko": "입의 안쪽", "def_vi": "Phần bên trong của miệng"}, {"term_ko": "헹구다", "term_vi": "Rửa", "def_ko": "헹구거나 씻어내는 행위", "def_vi": "Hành động rửa hoặc làm sạch"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1207, '10', '편마비 대상자의 식사 돕기 방법으로 옳은 것은?', '["시력이 저하된 대상자는 음식을 한꺼번에 섞어서 제공한다.", "식사 중 연하곤란이 있는지 주의 깊게 관찰한다.", "마비된 쪽의 입가에 흐르는 음식물은 그대로 둔다.", "식사 중에도 수시로 질문하여 상태를 확인한다.", "식사 후 바로 누워 쉬게 한다."]'::jsonb, 2, '편마비 대상자의 안전하고 효과적인 식사 보조 방법에 대한 이해를 확인하기 위함입니다.', NULL, '{"1": "시력이 저하된 대상자에게 음식물을 섞어서 제공하는 것은 혼란을 줄 수 있으며, 이는 옳지 않은 방법입니다.\n[정답]", "2": "식사 중 연하곤란 여부를 주의 깊게 관찰하는 것은 매우 중요합니다. 대상자의 안전을 위해 반드시 체크해야 합니다.", "3": "마비된 쪽의 입가에 흐르는 음식물은 즉시 제거해야 하며, 방치하는 것은 위험합니다.", "4": "식사 중에 질문하여 상태를 확인하는 것은 필요하지만, 너무 자주 질문하는 것은 대상자에게 스트레스를 줄 수 있습니다.", "5": "식사 후 바로 누워 쉬게 하는 것은 소화에 좋지 않으며, 바른 자세로 앉아 있게 하는 것이 좋습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸이 마비된 상태", "def_vi": "Tình trạng mất khả năng vận động một bên cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1206, '10', '대상자에게 숟가락을 사용하여 음식을 제공할 때 올바른 방법은?', '["숟가락으로 음식을 가득 떠서 넣어준다.", "숟가락 끝부분으로 입술 옆쪽에 대고 먹인다.", "숟가락을 입속 중앙으로 넣어 먹인다.", "대상자가 오른손잡이라면 왼쪽에서 먹인다.", "편마비 대상자는 불편한 쪽에서 넣어준다."]'::jsonb, 2, '대상자에게 음식을 제공할 때 올바른 방법을 이해하고 평가하는 것.', NULL, '{"1": "숟가락으로 음식을 가득 떠서 넣어주는 것은 적절하지 않다. 너무 많은 양을 한 번에 넣는 것은 위험할 수 있다.\n[정답]", "2": "숟가락 끝부분으로 입술 옆쪽에 대고 먹이는 것은 대상자가 편안하게 음식을 먹을 수 있도록 돕는 바른 방법이다.", "3": "숟가락을 입속 중앙으로 넣어 먹이는 것은 대상자의 안전을 고려할 때 좋지 않은 방법이다.", "4": "대상자가 오른손잡이라면 왼쪽에서 먹이는 것은 바람직하지 않다; 일반적으로 오른손잡이는 오른쪽에서 음식을 서빙받는 것이 편하다.", "5": "편마비 대상자는 불편한 쪽에서 넣어주는 것은 도움이 되지 않으므로, 편한 쪽에서 접근할 필요가 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "환자 또는 수혜자", "def_vi": "Bệnh nhân hoặc người thụ hưởng"}, {"term_ko": "숟가락", "term_vi": "Muỗng", "def_ko": "음식 제공 도구", "def_vi": "Công cụ để cung cấp thực phẩm"}, {"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸의 마비 상태", "def_vi": "Tình trạng bị liệt một bên cơ thể"}, {"term_ko": "입술", "term_vi": "Môi", "def_ko": "입 주위의 부위", "def_vi": "Vùng xung quanh miệng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1205, '10', '편마비 대상자의 식사를 돕는 방법으로 옳은 것은?', '["똑바로 누운 자세를 취한다.", "대상자의 상체를 낮춘다.", "국을 한 숟가락 먹인 후 밥을 준다.", "마비된 쪽의 입가로 음식을 넣어준다.", "국물은 가는 빨대를 이용하여 마시게 한다."]'::jsonb, 3, '편마비 대상자가 식사할 때 안전하게 도움을 주기 위한 방법을 묻는 문제입니다.', NULL, '{"1": "똑바로 누운 자세는 식사 시 안전하지 않아 권장되지 않습니다.\n[정답]", "3": "국을 한 숟가락 먹인 후 밥을 주는 방법은 식사를 안전하고 효율적으로 돕는 방식입니다.", "2": "대상자의 상체를 낮추는 것은 식사에 적절하지 않습니다.", "4": "마비된 쪽의 입가로 음식을 넣는 것은 위험할 수 있습니다.", "5": "가는 빨대를 사용하는 것은 식사 방법으로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 신체가 마비된 상태", "def_vi": "Tình trạng một bên cơ thể bị liệt"}, {"term_ko": "식사", "term_vi": "Ăn uống", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1204, '10', '대상자의 식사 돕기를 할 때 가장 먼저 해야 하는 것은?', '["배설여부를 확인한다.", "구강을 청결하게 한다.", "침대 머리를 올려 상체를 높인다.", "주변을 편안하고 깨끗하게 정리한다.", "어떤 음식이 나왔는지 대상자에게 알려준다."]'::jsonb, 1, '대상자의 식사 돕기 절차를 숙지하고 있는지 확인하기 위함입니다.', NULL, '{"1": "배설여부를 확인한다. 대상자의 식사가 이루어지기 전에 배설 여부를 확인하는 것이 중요합니다.\n[정답]", "2": "구강을 청결하게 한다. 식사 전에 구강 위생을 유지하는 것도 중요하지만, 먼저 배설 여부를 확인해야 합니다.", "3": "침대 머리를 올려 상체를 높인다. 이 단계는 식사 상황에서 구체적인 행동이지만, 배설 여부 확인이 먼저입니다.", "4": "주변을 편안하고 깨끗하게 정리한다. 환경 정리는 중요하지만, 우선적으로 대상자의 생리적 상태를 확인해야 합니다.", "5": "어떤 음식이 나왔는지 대상자에게 알려준다. 음식에 대한 안내는 식사 준비의 일부이지만, 배설 여부 확인이 선행되어야 합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "식사", "def_ko": "환자, người bệnh", "def_vi": "ăn uống, bữa ăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1203, '10', '다음 중 사레 들리기 쉬운 대상자가 주의해야 하는 과일은?', '["배", "수박", "바나나", "홍시", "자몽"]'::jsonb, 5, '(사레 들리기 쉬운 과일을 알고 있는지 확인하고자 하는 문제입니다.)', NULL, '{"1": "배는 비교적 안전한 과일입니다.\n[정답]", "2": "자몽은 사레 들리기 쉬운 과일로, 특히 주의가 필요합니다.", "3": "바나나도 주의가 필요하지만 자몽보다 덜 위험합니다.", "4": "홍시는 일반적으로 안전하지만 개인 차가 있을 수 있습니다.", "5": "수박은 대체로 안전한 과일입니다."}'::jsonb, '[{"term_ko": "사레", "term_vi": "사́u", "def_ko": "목에 걸린 것(한국어)", "def_vi": "điều khiển nào đó (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1202, '10', '대ㅐ상자에게 신맛이 나는 음식을 제한하는 이유는?', '["입맛이 떨어진다.", "설사를 유발한다.", "메스꺼움이 심해진다.", "사레 들릴 수 있다.", "입안이 건조해진다."]'::jsonb, 4, '대상자에게 신맛이 나는 음식을 제한하는 이유를 이해하고, 그에 따른 영향을 알고 있는지를 평가하기 위함입니다.', NULL, '{"1": "신맛이 나는 음식이 입맛을 떨어트릴 수 있지만, 주된 이유는 아닙니다.\n[정답]", "2": "신맛이 나는 음식은 메스꺼움을 유발하기 때문에 사레에 들릴 위험이 있습니다.", "3": "신맛이 나는 음식이 설사를 유발하는 경우는 있으나, 이는 일반적이지 않습니다.", "4": "신맛이 나는 음식은 메스꺼움을 심화시킬 수 있는 요소입니다.", "5": "신맛이 나는 음식은 입안을 건조하게 할 수 있으나, 다른 영향보다 덜 중요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được phục vụ", "def_ko": "치료를 받거나 도움을 필요로 하는 사람", "def_vi": "Người cần điều trị hoặc trợ giúp"}, {"term_ko": "신맛", "term_vi": "Vị chua", "def_ko": "신맛을 느끼는 맛", "def_vi": "Vị cảm nhận chua"}, {"term_ko": "설사", "term_vi": "Tiêu chảy", "def_ko": "변이 묽어지는 증상", "def_vi": "Triệu chứng phân lỏng"}, {"term_ko": "메스꺼움", "term_vi": "Buồn nôn", "def_ko": "구역질을 느끼는 증상", "def_vi": "Triệu chứng cảm thấy buồn nôn"}, {"term_ko": "사레", "term_vi": "Nghẹn", "def_ko": "기도가 막히거나 걸리는 현상", "def_vi": "Hiện tượng bị tắc nghẽn khí quản"}, {"term_ko": "입안", "term_vi": "Miệng", "def_ko": "구강 내부", "def_vi": "Phần bên trong của miệng"}, {"term_ko": "건조", "term_vi": "Khô", "def_ko": "수분이 부족함", "def_vi": "Thiếu độ ẩm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1201, '10', '연하곤란이 있는 대상자에게 식사를 제공 시 옳은 것은?', '["기침을 하면 쉬었다 먹인다.", "음식을 빨리 먹도록 재촉한다.", "사레가 들리면 식사를 중단하고 즉시 시설장에게 보고한다.", "사레 위험이 있으므로 식사 전에 물을 먹이지 않는다.", "배 부위와 가슴을 압박하는 옷으로 등을 펴게 한다."]'::jsonb, 3, '연하곤란이 있는 대상자에게 안전하게 식사를 제공하는 방법을 이해하고 평가하는 것.', NULL, '{"1": "기침을 하면 잠시 쉬도록 하는 것이 필요하지만, 오래 쉬게 하는 것은 좋지 않다.\n[정답]", "3": "사레가 들리면 즉시 식사를 중단하고 필요한 조치를 취해야 한다.", "2": "음식을 재촉하는 것은 위험할 수 있다.", "4": "식사 전에 물을 먼저 주는 것은 오히려 위험을 증가시킬 수 있다.", "5": "압박 옷은 호흡을 어렵게 할 수 있어 주의해야 한다."}'::jsonb, '[{"term_ko": "연하곤란", "term_vi": "Khó khăn trong việc nuốt", "def_ko": "삼키는 것이 어려운 상태", "def_vi": "Tình trạng khó nuốt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1200, '10', '사레들리기 쉬운 대상자가 바나나를 먹고 싶어 할 때 대처방법은?', '["불에 익혀서 준다.", "통째로 준다.", "얼음으로 얼려서 준다.", "숟가락으로 긁어서 준다.", "한 입에 들어갈 크기로 잘라서 준다."]'::jsonb, 4, '대상자의 안전한 식사를 보장하기 위한 적절한 대처 방법을 이해하도록 하기 위함입니다.', NULL, '{"1": "불에 익혀서 준다: 바나나를 익히는 것은 식감이나 영양소에 영향을 줄 수 있다.\n[정답]", "4": "숟가락으로 긁어서 준다: 식사가 어려운 대상자에게 적합한 방법이다.", "2": "통째로 준다: 통째로 주는 것은 대상자가 삼키기 어려울 수 있다.", "3": "얼음으로 얼려서 준다: 얼음으로 제공하면 효과적인 식사가 어려울 수 있다.", "5": "한 입에 들어갈 크기로 잘라서 준다: 잘라서는 방법이지만, 대상자의 상황에 따라 적합하지 않을 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1199, '10', '연하곤란이 있는 대상자에게 식사를 제공하는 방법으로 옳은 것은?', '["많은 양의 음식을 한꺼번에 준다.", "딱딱한 음식을 제공한다.", "레몬 소스를 곁들인 샐러드를 제공한다.", "똑바로 누운 상태에서 천천히 제공한다.", "충분히 삼킬 수 있는 적은 양을 입에 넣어준다."]'::jsonb, 5, '연하곤란이 있는 대상자에게 안전하고 효과적으로 식사를 제공하는 방법에 대한 이해를 확인하는 것입니다.', NULL, '{"1": "많은 양의 음식을 한꺼번에 준다. - 연하곤란이 있는 경우, 많은 양을 한꺼번에 주는 것은 위험합니다.\n[정답]", "2": "충분히 삼킬 수 있는 적은 양을 입에 넣어준다. - 적은 양을 천천히 제공하는 것이 안전하며, 삼킬 수 있는 양을 고려해야 합니다.", "3": "레몬 소스를 곁들인 샐러드를 제공한다. - 산성이 강한 음식은 연하곤란 환자에게 적합하지 않습니다.", "4": "똑바로 누운 상태에서 천천히 제공한다. - 눕힌 상태에서 식사를 제공하면 기도막힘 등이 발생할 수 있습니다.", "5": "딱딱한 음식을 제공한다. - 딱딱한 음식은 연하곤란 환자에게 적합하지 않습니다."}'::jsonb, '[{"term_ko": "연하곤란", "term_vi": "Khó khăn trong việc nuốt", "def_ko": "삼키는 데 어려움이 있는 상태", "def_vi": "Tình trạng khó khăn trong việc nuốt"}, {"term_ko": "대상자", "term_vi": "Người nhận sự chăm sóc", "def_ko": "돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "제공하다", "term_vi": "Cung cấp", "def_ko": "제공하다, 주다", "def_vi": "Cung cấp, cho"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1198, '10', '대상자의 식욕을 증진시키는 방법으로 옳은 것은?', '["식사 전에 수면을 취하게 한다.", "식사 전에 몸을 움직이지 못하게 한다.", "조명을 어둡고 차분하게 한다.", "식사 전에 간식을 제공한다.", "식사 전에 밖으로 나가 맑은 공기를 마시게 한다."]'::jsonb, 5, '대상자의 식욕을 증진시키는 방법을 이해하고 있는지를 평가하고자 함.', NULL, '{"1": "식사 전에 수면을 취하게 하는 것은 식욕을 증진시키지 않음.\n[정답]", "5": "식사 전에 밖으로 나가 맑은 공기를 마시게 하는 것은 식욕을 증진시킬 수 있음.", "3": "조명을 어둡고 차분하게 하는 것은 식욕에 도움을 주지 않음.", "2": "식사 전에 몸을 움직이지 못하게 하는 것은 식욕을 오히려 저하시킬 수 있음.", "4": "간식을 제공하는 것은 식사를 대신할 수 있어 식욕에 부정적 영향을 줄 수 있음."}'::jsonb, '[{"term_ko": "식욕", "term_vi": "Thèm ăn", "def_ko": "식사를 하고 싶은 마음", "def_vi": "Ý muốn ăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1197, '10', '의자에 앉아 있는 대상자가 등이 구부정한 상태에서 식사할 경우 발생할 수 있는 합병증은?', '["식도염", "천식", "폐결핵", "폐렴", "후두염"]'::jsonb, 4, '대상자가 편안한 자세에서 식사를 하도록 유도하는 것이 중요하다는 것을 인식하도록 하기 위함입니다.', NULL, '{"1": "식도염은 주로 위산의 역류와 관련된 질환입니다.\n[정답]", "4": "폐렴은 구부정한 자세로 식사할 경우 음식물이 기도로 잘 들어가면서 발생할 수 있는 합병증입니다.", "2": "천식은 주로 알레르기와 관련이 깊고 식사 자세와는 관계가 없습니다.", "3": "폐결핵은 전염성 질환으로 자세와는 직접적인 연관이 없습니다.", "5": "후두염은 주로 바이러스 감염이나 사용을 과도하게 한 경우에 발생하는 질환입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1196, '10', '음식물을 삼키기 힘들어 하는 대상자를 돕는 방법으로 옳은 것은?', '["삼키기 쉽도록 턱을 위로 들게 하여 식사를 제공한다.", "대상자가 원하는 만큼의 양을 입에 넣어준다.", "완전히 삼켰는지 확인한 후 음식을 제공한다.", "천천히 식사하도록 자주 질문을 한다.", "대상자 스스로 식사할 수 있으면 자리를 비켜준다."]'::jsonb, 3, '대상자가 음식물을 삼키기 힘들어 할 때 적절한 도움을 제공하는 방법을 이해하고 있는지를 평가하고자 한다.', NULL, '{"1": "삼키기 쉽도록 턱을 위로 들게 하여 식사를 제공하는 것은 오히려 삼키기 어려운 자세가 될 수 있다.\n[정답]", "3": "완전히 삼켰는지 확인한 후 음식을 제공하는 것이 안전한 방법이다.", "2": "대상자가 원하는 만큼의 양을 입에 넣어주는 것은 과다 섭취로 이어질 수 있어 위험하다.", "4": "천천히 식사하도록 자주 질문하는 것은 대상자가 불안해할 수 있어 권장되지 않는다.", "5": "대상자 스스로 식사할 수 있으면 자리를 비켜주는 것은 안전 문제를 고려해야 하므로 조심해야 한다."}'::jsonb, '[{"term_ko": "삼키다", "term_vi": "Nuốt", "def_ko": "목구멍으로 음식을 통과시키다(한국어)", "def_vi": "Làm cho thức ăn đi qua cổ họng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1195, '10', '왼쪽 편마비 대상자가 침상에서 편안하게 식사하도록 돕는 방법은?', '["오른쪽을 밑으로 하여 약간 옆으로 누운 자세를 취한다.", "상체를 세운 후 얼굴을 왼쪽으로 돌린다.", "침상 식탁에 왼팔을 올려 주고 똑바로 앉힌다.", "사례가 들리면 침대 머리를 최대한 올려준다.", "식후 오른쪽 뺨 부위에 음식물이 남아 있는지 확인한다."]'::jsonb, 1, '왼쪽 편마비 대상자가 안전하고 편안하게 식사할 수 있도록 돕는 방안을 질문하고 있습니다.', NULL, '{"1": "오른쪽을 밑으로 하여 약간 옆으로 누운 자세를 취하면 왼쪽 편마비가 있는 환자가 식사하기에 더 편안해질 수 있습니다.\n[정답]", "2": "상체를 세운 후 얼굴을 왼쪽으로 돌린다면 편마비 쪽으로 음식이 들어가기 어려워 식사에 도움이 되지 않습니다.", "3": "왼팔을 올려주고 똑바로 앉히는 것은 편안한 식사를 도와주지 않습니다.", "4": "침대 머리를 올리는 것은 식사 시 도움이 될 수 있지만, 정답이 아닙니다.", "5": "식후 오른쪽 뺨에 음식물이 남아 있는지 확인하는 것은 중요하지만, 식사 방법이 아닙니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bệnh liệt nửa người", "def_ko": "한쪽 신체의 마비(한국어)", "def_vi": "Tình trạng liệt một bên cơ thể"}, {"term_ko": "침상", "term_vi": "Giường bệnh", "def_ko": "침대(한국어)", "def_vi": "Giường dùng trong bệnh viện"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식 먹기(한국어)", "def_vi": "Thời gian ăn uống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1194, '10', '오른쪽 편마비가 있는 대상자가 누워있는 상태에서 식사를 할 때 돕기 방법은?', '["침대에 똑바로 누운 상태에서 천천히 음식을 제공한다.", "왼쪽을 밑으로 하여 약간 옆으로 누운 자세에서 음식을 제공한다.", "오른쪽을 밑으로 하여 약간 옆으로 누운 자세에서 음식을 제공한다.", "왼쪽을 베개나 쿠션으로 지지하여 안정감을 준다.", "오른쪽 입에 빨대를 고정시켜 국물을 제공한다."]'::jsonb, 2, '대상자의 오른쪽 편마비 상태에서 안전하게 식사를 도와줄 수 있는 방법을 묻고 있다.', NULL, '{"1": "침대에 똑바로 누운 상태에서는 오른쪽 편마비로 인해 음식물이 잘 넘어갈 수 없고, 안전하지 않다.\n[정답]", "2": "왼쪽을 밑으로 하여 약간 옆으로 누운 자세는 오른쪽 편마비 환자가 안정적으로 식사를 할 수 있도록 도와준다.", "3": "오른쪽을 밑으로 하여 누운 자세는 편마비된 쪽에 대한 식사가 불리할 수 있다.", "4": "왼쪽을 베개나 쿠션으로 지지하는 것은 필요한 지원이지만, 측면 자세로 음식을 제공하는 것이 효과적이다.", "5": "오른쪽 입에 빨대를 고정시키는 것은 비효율적이며, 잘못된 방법이다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nữa người", "def_ko": "한쪽 몸에 힘이 없거나 마비된 상태", "def_vi": "Trạng thái mất sức hoặc liệt một bên cơ thể"}, {"term_ko": "지지", "term_vi": "Hỗ trợ", "def_ko": "물체를 받쳐서 안정감을 주는 것", "def_vi": "Đặt vật gì đó để tạo sự ổn định"}, {"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "어떤 방식으로 몸을 두는 것", "def_vi": "Cách cơ thể được đặt"}, {"term_ko": "안정감", "term_vi": "Cảm giác an toàn", "def_ko": "편안함과 안전함을 느끼는 감정", "def_vi": "Cảm giác thoải mái và an toàn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1193, '10', '침상에 누워 있는 대상자에게 식사를 제공할 때 사례를 예방하는 방법으로 옳은 것은?', '["물기가 없는 음식을 제공한다.", "상체를 높이고 턱을 든 자세를 취하게 한다.", "입맛을 돋우기 위해 신맛 나는 음식을 먼저 준다.", "음식을 먹고 있는 도중에 말을 시킨다.", "침상 머리를 30~60도 높인 후 음식을 제공한다."]'::jsonb, 5, '대상자에게 식사를 안전하게 제공하는 방법을 묻는 문제입니다.', NULL, '{"1": "물기가 없는 음식을 제공한다는 것은 식사를 더 안전하게 만드는 방법은 아닙니다.\n[정답]", "5": "침상 머리를 30~60도 높인 후 음식을 제공하는 것이 가장 안전한 방법입니다.", "3": "신맛 나는 음식을 먼저 주는 것은 입맛을 돋우는 데 도움이 될 수 있으나, 안전과는 관련이 없습니다.", "4": "음식을 먹고 있는 도중에 말하는 것은 위험할 수 있습니다.", "2": "상체를 높이고 턱을 든 자세는 도움이 되나, 충분한 각도를 유지하는 것이 중요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자, 또는 돌봄이 필요한 사람", "def_vi": "Bệnh nhân hoặc người cần chăm sóc"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식 먹는 것", "def_vi": "Việc ăn uống"}, {"term_ko": "사례", "term_vi": "Trường hợp", "def_ko": "사고나 문제가 발생하는 경우", "def_vi": "Khi có sự cố hoặc vấn đề xảy ra"}, {"term_ko": "예방", "term_vi": "Ngăn ngừa", "def_ko": "미리 방지하다", "def_vi": "Phòng ngừa trước"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1192, '10', '대상자가 식탁에서 식사할 때 올바른 자세는?', '["의자에 깊숙이 앉고 식탁 위에 팔꿈치를 올린다.", "음식을 먹는 경우 머리를 뒤로 젖힌다.", "의자의 앞쪽 끝부분에 걸터 앉게 한다.", "발가락 끝이 바닥에 닿게 의자 높이를 조절한다.", "등받이에 등이 닿지 않게 한다."]'::jsonb, 1, '대상자가 식사할 때 올바른 자세를 파악하고, 적절한 자세를 알려주는 것을 목표로 한다.', NULL, '{"1": "의자에 깊숙이 앉고 식탁 위에 팔꿈치를 올리는 것은 올바른 자세이다.\n[정답]", "2": "음식을 먹는 경우 머리를 뒤로 젖히는 것은 올바르지 않다.", "3": "의자의 앞쪽 끝부분에 걸터 앉게 하는 것은 올바르지 않다.", "4": "발가락 끝이 바닥에 닿게 의자 높이를 조절해야 하는 것은 올바르지 않다.", "5": "등받이에 등이 닿지 않게 하는 것은 올바르지 않다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1191, '10', '거동이 불편한 대상자의 식사를 돕는 방법으로 옳은 것은?', '["바퀴가 달린 의자에 앉게 한다.", "팔 받침이 없는 의자에 앉게 한다.", "발바닥이 바닥에 닿도록 의자 높이를 조절한다.", "식탁 상판의 높이를 대상자의 가슴 위치로 조절한다.", "휠체어에 안장서 식사할 때는 식탁과 충분한 간격을 둔다."]'::jsonb, 3, '대상자의 식사를 돕는 방법 중 올바른 의자 높이 조절에 대한 이해를 평가하려는 의도입니다.', NULL, '{"1": "바퀴가 달린 의자에 앉게 하는 것은 이동에 편리할 수 있으나, 안정성을 고려할 때 식사 시 적합하지 않습니다.\n[정답]", "3": "발바닥이 바닥에 닿도록 의자 높이를 조절하는 것은 안정성을 제공하며 올바른 자세를 유지할 수 있도록 도와줍니다.", "2": "팔 받침이 없는 의자에 앉게 하는 것은 팔의 지지 없이 불편함을 초래할 수 있습니다.", "4": "식탁 상판의 높이를 대상자의 가슴 위치로 조절하는 것은 식사 시 편리하지 않을 수 있습니다.", "5": "휠체어에 안장서 식사할 때는 식탁과의 간격이 너무 멀면 불편할 수 있습니다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "거 động", "def_ko": "움직임(한국어)", "def_vi": "sự di chuyển(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1190, '10', '대상자가 식탁에서 식사할 때 식탁의 높이로 옳은 것은?', '["턱 밑", "가슴 위", "배 아래", "가슴과 배꼽 사이", "최대한 높게 한다."]'::jsonb, 4, '대상자가 식사할 때 식탁의 적절한 높이에 대한 이해를 확인하고자 함.', NULL, '{"1": "턱 밑: 식사가 불편하고 잘 보이지 않을 수 있음.", "2": "가슴 위: 불편함을 초래할 수 있음.\n[정답]", "3": "배 아래: 식탁이 너무 낮아 편안하지 않을 수 있음.", "4": "가슴과 배꼽 사이: 적절한 높이로 식사 시 편안함을 제공함.", "5": "최대한 높게 한다: 지나치게 높으면 불편하게 될 수 있음."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "환자, 이용자", "def_vi": "Bệnh nhân, người sử dụng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1189, '10', '대상자가 삼키는 능력이 없고 의식장애가 있을 때 비위관을 통하여 제공하는 식이의 종류는?', '["일반식", "저작 도움식", "경관 유동식", "경구 유동식", "연하 도움식"]'::jsonb, 3, '대상자의 삼키는 능력이 없고 의식장애가 있을 경우에 적절한 식이를 제공하기 위한 지식을 평가하는 것이 의도입니다.', NULL, '{"1": "일반식은 삼키는 능력이 있는 자에게 제공하는 식사입니다.", "2": "저작 도움식은 저작이 가능한 대상자에게 적합한 식사입니다.\n[정답]", "3": "경관 유동식은 비위관을 통해 제공할 수 있는 식사로, 삼키는 능력이 없는 대상자에게 적합합니다.", "4": "경구 유동식은 입을 통한 섭취가 가능한 대상자에게 제공됩니다.", "5": "연하 도움식은 연하 문제가 있는 대상자에게 저작이 가능할 때 사용하는 식사입니다."}'::jsonb, '[{"term_ko": "삼키다", "term_vi": "Nuốt", "def_ko": "먹다(한국어)", "def_vi": "ăn(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1188, '10', '저작과 연하 능력이 떨어져 씹고 삼키기 어려운 대상자에게 제공하는 식이의 종류는?', '["경관 유동식", "경구 유동식", "연하 도움식", "저작 도움식", "일반식"]'::jsonb, 3, '저작과 연하 능력이 떨어진 환자에게 적절한 식이를 제공하는 방법을 묻는 문제입니다.', NULL, '{"1": "경관 유동식: 특정한 경로(예: 비위관 등)로 제공되는 액체 형태의 식사입니다.\n[정답]", "2": "연하 도움식: 연하 장애가 있는 환자를 위해 고안된, 꼭 필요한 영양소를 포함하는 식사입니다.", "3": "경구 유동식: 구강을 통해 유동적으로 섭취할 수 있는 식사입니다.", "4": "저작 도움식: 저작에 도움이 되도록 조리된 식사입니다.", "5": "일반식: 일반인이 섭취할 수 있는 평범한 식사입니다."}'::jsonb, '[{"term_ko": "저작", "term_vi": "Nhai", "def_ko": "씹는 행위", "def_vi": "Hành động nhai"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1187, '10', '저작능력이 떨어져 단단하고 질긴 음식을 먹기 어려운 대상자에게 제공하는 식이의 종류는?', '["저작 도움식", "연하 도움식", "경구 유동식", "일반식", "경관 유동식"]'::jsonb, 1, '저작능력이 떨어지는 대상자에게 적합한 식이의 종류를 묻는 문제입니다.', NULL, '{"1": "저작에 도움이 되는 음식을 제공하는 식이입니다.\n[정답]", "2": "연하(삼킴)에 어려움을 겪는 대상자를 위한 식이입니다.", "3": "구강을 통해 섭취하는 유동식으로 쉽게 흡수되지만 저작능력 문제와는 직접적인 연관이 없습니다.", "4": "일반적인 식사로 저작능력과 관계없이 제공됩니다.", "5": "경관을 통해 제공되는 유동식으로 저작능력의 문제를 해결하기 위한 것은 아닙니다."}'::jsonb, '[{"term_ko": "저작능력", "term_vi": "Khả năng nhai", "def_ko": "음식을 씹는 능력", "def_vi": "Khả năng nhai thức ăn"}, {"term_ko": "연하", "term_vi": "Nuốt", "def_ko": "음식을 삼키는 능력", "def_vi": "Khả năng nuốt thức ăn"}, {"term_ko": "일반식", "term_vi": "Bữa ăn thông thường", "def_ko": "일반적인 식사", "def_vi": "Bữa ăn bình thường"}, {"term_ko": "경관", "term_vi": "Ống dẫn", "def_ko": "인공적으로 주입하는 방식", "def_vi": "Phương pháp tiêm qua ống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1186, '10', '노인 대상자의 영양부족 상태를 알 수 있는 지표에 해당하는 것은?', '["체중 증가", "인지 수준 변화", "식욕 증가", "신체기능 증진", "안정된 심리상태"]'::jsonb, 2, '노인 대상자의 영양부족 상태를 평가할 수 있는 지표를 이해하고 선택하는 것이다.', NULL, '{"1": "체중 증가: 영양부족 상태와는 반대로 나타나는 징후이다.\n[정답]", "2": "인지 수준 변화: 영양부족으로 인해 인지 능력이 저하될 수 있다.", "3": "식욕 증가: 영양부족 시 식욕이 감소하는 경향이 있다.", "4": "신체기능 증진: 영양부족 상태에서는 신체기능이 저하되는 경우가 많다.", "5": "안정된 심리상태: 영양부족은 심리적 불안감을 초래할 수 있다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1185, '10', '식사를 할 때 영양부족이 발생할 가능성이 있는 대상자는?', '["녹내장 대상자", "언어장애 대상자", "연하장애 대상자", "변비가 있는 대상자", "요실금이 있는 대상자"]'::jsonb, 3, '식사 시 영양부족 발생 가능성이 있는 대상을 파악하기 위함입니다.', NULL, '{"1": "녹내장은 시각적 문제로 식사와 직접적 연관성이 적습니다.", "2": "언어장애는 식사와의 연관성은 있으나 영양부족과는 직접적인 관련이 없습니다.\n[정답]", "3": "연하장애는 음식 섭취에 어려움이 있어 영양부족이 발생할 수 있습니다.", "4": "변비는 영양부족과는 직접적인 관련이 없습니다.", "5": "요실금도 영양부족과 관련이 없습니다."}'::jsonb, '[{"term_ko": "영양부족", "term_vi": "대상자", "def_ko": "영양 thiếu hụt", "def_vi": "đối tượng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1184, '10', '노인의 영양부족을 초래하는 위험 요인으로 옳은 것은?', '["체중 증가", "비타민 복용", "인지능력 상승", "약물사용", "규칙적인 식사"]'::jsonb, 4, '노인의 영양부족을 초래하는 여러 요인 중에서 위험 요인을 찾기 위해서 문제를 제시하였다.', NULL, '{"1": "체중 증가: 체중 증가 자체는 영양부족과 관계가 없다.\n[정답]", "4": "약물사용: 약물은 노인의 영양 상태에 영향을 미칠 수 있는 위험 요인이다.", "3": "인지능력 상승: 인지능력의 상승은 일반적으로 영양 부족과 무관하다.", "2": "비타민 복용: 비타민 복용은 영양 보충의 일환으로 볼 수 있다.", "5": "규칙적인 식사: 규칙적인 식사는 영양 부족을 예방하는데 도움이 된다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1183, '10', '노인의 건강상태를 관찰할 때 영양부족이 의심되는 상황은?', '["상처의 회복이 지연된다.", "정상적인 배설을 한다.", "수분을 충분히 섭취한다.", "종합 비타민을 복용하고 있다.", "담배를 하루에 한 갑씩 피우고 있다."]'::jsonb, 1, '노인의 건강상태에서 영양부족이 나타나는 징후를 파악하는 것이다.', NULL, '{"1": "상처의 회복이 지연된다: 영양부족 시 상처 회복이 느려지므로 적절한 선택이다.\n[정답]", "2": "정상적인 배설을 한다: 정상적인 배설은 영양부족과 관계가 없다.", "3": "수분을 충분히 섭취한다: 충분한 수분 섭취는 영양부족과 무관하다.", "4": "종합 비타민을 복용하고 있다: 비타민 복용이 영양부족을 해결하는 것은 아니다.", "5": "담배를 하루에 한 갑씩 피우고 있다: 담배 흡연은 영양상태와 직접적인 연관이 없다."}'::jsonb, '[{"term_ko": "영양부족", "term_vi": "상처", "def_ko": "영양 thiếu hụt", "def_vi": "vết thương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1182, '10', '연하곤란이 있는 대상자에게 식사를 제공할 때 주의 깊게 관찰해야 하는 것은?', '["탈수", "부종", "청색증", "소양증", "피부 발적"]'::jsonb, 3, '연하곤란이 있는 대상자에게 식사를 제공할 때 주의 깊게 관찰해야 할 증상을 확인하는 것이다.', NULL, '{"1": "탈수: 식사 중 수분 섭취 부족으로 인한 증상으로 연관성이 적다.", "2": "부종: 체액 저류로 인한 부풀음으로 연하곤란과 직접적인 연관성이 없다.\n[정답]", "3": "청색증: 산소 부족으로 인해 입술이나 피부가 푸르게 변하는 증상으로, 연하곤란시 가장 주의해야 하는 증상이다.", "4": "소양증: 가려움증으로 연하곤란과 큰 연관이 없다.", "5": "피부 발적: 피부의 염증으로, 연하곤란과 직접적인 연관성이 적다."}'::jsonb, '[{"term_ko": "연하곤란", "term_vi": "Khó nuốt", "def_ko": "삼키기 어려움", "def_vi": "Khó khăn trong việc nuốt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1181, '10', '섭취 요양보호의 일반적 원칙으로 옳은 것은?', '["대상자의 식사습관과 소화능력은 고려하지 않는다.", "식사방법, 속도는 요양보호사에게 맞춘다.", "식사 중에 주변 환경을 청결히 정리한다.", "대상자의 요구를 최대한 반영한다.", "식사 중에만 대상자를 주의 깊게 관찰한다."]'::jsonb, 4, '섭취 요양보호의 일반적인 원칙을 이해하고, 이를 바탕으로 올바른 선택을 할 수 있는지를 평가하고자 함.', NULL, '{"1": "대상자의 식사습관과 소화능력은 고려하지 않는다. (옳지 않음: 대상자의 특성을 고려해야 함.)", "2": "식사방법, 속도는 요양보호사에게 맞춘다. (옳지 않음: 대상자에게 맞춰야 함.)\n[정답]", "3": "식사 중에 주변 환경을 청결히 정리한다. (옳음: 청결한 환경을 유지해야 하므로 옳은 원칙임.)", "4": "대상자의 요구를 최대한 반영한다. (옳음: 대상자의 욕구를 반영하는 것이 중요함.)", "5": "식사 중에만 대상자를 주의 깊게 관찰한다. (옳지 않음: 항상 관찰해야 함.)"}'::jsonb, '[{"term_ko": "섭취", "term_vi": "섭 thu", "def_ko": "먹는 것(한국어)", "def_vi": "Đồ ăn(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1180, '9', '다음에서 설명하는 주요 내용을 다루는 회의는?• 요양보호사의 업무와 관련된 정보와 업무 준수사항을 전달한다. • 기관운영, 인사, 복리후생에 대해 의견 및 애로사항을 듣는다.', '["사례회의", "점검회의", "검토회의", "월례회의", "평가회의"]'::jsonb, 4, '요양보호사의 업무와 기관 운영에 관한 내용을 다루는 회의를 묻는 것이다.', NULL, '{"1": "사례회의: 특정 사례에 대한 논의가 필요한 회의로, 설명한 내용과는 차이가 있다.\n[정답]", "4": "월례회의: 정기적으로 개최되어 요양보호사의 업무와 기관 운영 관련 사항을 점검하고 의견을 주고받는 회의이다.", "3": "검토회의: 제안된 안건이나 자료를 검토하는 회의로, 일반적으로 정기적이지 않다.", "2": "점검회의: 특정 업무의 진행 상황을 점검하는 회의지만, 요양보호사 업무에 초점을 맞추지 않을 수 있다.", "5": "평가회의: 성과를 평가하는 회의로, 업무 준수 사항을 다루기보다는 결과에 초점을 두고 있다."}'::jsonb, '[{"term_ko": "업무", "term_vi": "Công việc", "def_ko": "일(일하는 것)", "def_vi": "Công việc hoặc nhiệm vụ"}, {"term_ko": "기관", "term_vi": "Cơ quan", "def_ko": "시설, 조직", "def_vi": "Tổ chức hoặc cơ sở"}, {"term_ko": "복리후생", "term_vi": "Phúc lợi", "def_ko": "직원의 복지 향상", "def_vi": "Cải thiện phúc lợi cho nhân viên"}, {"term_ko": "회의", "term_vi": "Cuộc họp", "def_ko": "의견을 교환하는 모임", "def_vi": "Cuộc họp để trao đổi ý kiến"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1179, '9', '장기요양기관에서 실시하는 사례회의의 목적은?', '["기관의 신규 사업 홍보", "요양보호사의 업무 평가", "요양보호사의 업무와 관련된 정보 공유", "요양보호사 복리후생에 대한 의견 수렴", "서비스제공 계획의 타당성 검토와 조정"]'::jsonb, 5, '장기요양기관에서 사례회의의 목적과 역할을 이해하는 것이다.', NULL, '{"1": "기관의 신규 사업 홍보는 사례회의의 직접적인 목적이 아니다.\n[정답]", "5": "서비스제공 계획의 타당성 검토와 조정은 사례회의의 주된 목적 중 하나이다.", "2": "요양보호사의 업무 평가 역시 사례회의의 주 목적이 아니다.", "3": "요양보호사의 업무와 관련된 정보 공유는 중요하지만 사례회의의 핵심 목적은 아니다.", "4": "요양보호사 복리후생에 대한 의견 수렴도 사례회의의 목적과는 거리가 있다."}'::jsonb, '[{"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기적인 요양을 제공하는 기관", "def_vi": "Cơ sở cung cấp dịch vụ chăm sóc dài hạn"}, {"term_ko": "사례회의", "term_vi": "Cuộc họp trường hợp", "def_ko": "사례를 논의하기 위한 회의", "def_vi": "Cuộc họp để thảo luận về các trường hợp"}, {"term_ko": "서비스제공 계획", "term_vi": "Kế hoạch cung cấp dịch vụ", "def_ko": "서비스 제공을 위한 계획", "def_vi": "Kế hoạch để cung cấp dịch vụ"}, {"term_ko": "타당성", "term_vi": "Tính hợp lý", "def_ko": "적절하거나 의미가 있는 것", "def_vi": "Điều gì đó phù hợp hoặc có ý nghĩa"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1178, '9', '대상자의 상황과 제공되는 서비스를 점검하고 평가하여, 대상자의 욕구에 맞는 서비스를 제공하기 위해 개최하는 회의는?', '["월례회의", "사례회의", "업무보고회의", "동급평가회의", "장기요양회의"]'::jsonb, 2, '대상자의 상황을 파악하고 적절한 서비스를 제공하기 위한 회의의 구체적인 명칭을 묻고 있다.', NULL, '{"1": "월례회의: 정기적으로 개최되는 회의로, 특정한 상황 평가와는 관련이 적다.\n[정답]", "2": "사례회의: 대상자의 욕구에 맞춰 서비스를 제공하기 위해 개최되는 회의이다.", "3": "업무보고회의: 업무 상황을 보고하는 회의로, 평가와는 거리가 있다.", "4": "동급평가회의: 서로 동등한 위치의 사람들끼리 평가하는 회의로, 대상자 욕구와는 관련이 없다.", "5": "장기요양회의: 장기요양에 관련된 사항을 논의하는 회의지만, 특정 대상자의 욕구에 중점을 두지는 않다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자 또는 서비스를 받는 사람", "def_vi": "Bệnh nhân hoặc người nhận dịch vụ"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "필요나 원하는 것", "def_vi": "điều cần thiết hoặc điều mong muốn"}, {"term_ko": "제공", "term_vi": "Cung cấp", "def_ko": "공급하다", "def_vi": "cung cấp"}, {"term_ko": "회의", "term_vi": "Cuộc họp", "def_ko": "사람들의 모임", "def_vi": "cuộc họp của mọi người"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1177, '9', '요양보호사가 업무수행 시 서면보고를 해야 하는 경우로 옳은 것은?', '["긴급을 요할 때", "사안이 가벼울 때", "신속하게 보고해야 할 때", "정확히 보고할 필요가 있을 때", "자료를 보존할 필요가 없을 때"]'::jsonb, 4, '요양보호사가 업무를 수행할 때 서면보고가 필요한 경우를 이해하는 것이 목적입니다.', NULL, '{"1": "긴급을 요할 때는 구두보고가 우선될 수 있습니다.", "2": "사안이 가벼울 때는 서면보고가 필요하지 않을 수 있습니다.\n[정답]", "3": "신속하게 보고해야 할 때 서면보고는 오히려 시간 지연을 초래할 수 있습니다.", "4": "정확히 보고할 필요가 있을 때 서면보고는 필수적입니다.", "5": "자료를 보존할 필요가 없을 때는 서면보고의 필요성이 없습니다."}'::jsonb, '[{"term_ko": "업무수행", "term_vi": "Thực hiện công việc", "def_ko": "일을 수행하는 것", "def_vi": "Làm công việc"}, {"term_ko": "서면보고", "term_vi": "Báo cáo bằng văn bản", "def_ko": "서면으로 하는 보고", "def_vi": "Báo cáo bằng văn bản"}, {"term_ko": "긴급", "term_vi": "Khẩn cấp", "def_ko": "급한 상황", "def_vi": "Tình huống khẩn cấp"}, {"term_ko": "신속", "term_vi": "Nhanh chóng", "def_ko": "빠르게", "def_vi": "Nhanh chóng"}, {"term_ko": "정확히", "term_vi": "Chính xác", "def_ko": "틀림없이", "def_vi": "Chính xác"}, {"term_ko": "자료", "term_vi": "Tài liệu", "def_ko": "필요할 수 있는 정보", "def_vi": "Thông tin có thể cần"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1175, '9', '신속하게 보고할 수 있다는 장점이 있으나 정확한 기록을 남길 수 없다는 단점이 있는 업무보고 형식은?', '["구두보고", "서면보고", "사건보고", "전산망 보고", "정기 업무보고"]'::jsonb, 1, '업무보고 형식 중 장단점을 비교하고 이해하는 것을 의도함.', NULL, '{"1": "구두보고는 신속하게 전달할 수 있으나 기록이 남지 않아 정확한 확인이 어렵다.\n[정답]", "2": "서면보고는 정확한 기록을 남길 수 있으나 즉시 전달하는 데 시간이 걸린다.", "3": "사건보고는 특정 사건에 대한 기록으로 단순 비교가 어렵다.", "4": "전산망 보고는 디지털 방식으로 정보를 기록하나, 즉각적인 의사소통에는 제약이 있을 수 있다.", "5": "정기 업무보고는 정기적으로 정보를 공유하나, 비정기적인 긴급 상황에는 적합하지 않다."}'::jsonb, '[{"term_ko": "구두보고", "term_vi": "Báo cáo miệng", "def_ko": "말로 전달하는 보고 방식", "def_vi": "Cách báo cáo bằng lời nói"}, {"term_ko": "서면보고", "term_vi": "Báo cáo bằng văn bản", "def_ko": "문서로 기록하는 보고 방식", "def_vi": "Cách báo cáo bằng tài liệu"}, {"term_ko": "사건보고", "term_vi": "Báo cáo sự kiện", "def_ko": "특정 사건에 대한 보고", "def_vi": "Báo cáo về một sự kiện cụ thể"}, {"term_ko": "전산망", "term_vi": "Mạng điện tử", "def_ko": "전자적 정보 시스템", "def_vi": "Hệ thống thông tin điện tử"}, {"term_ko": "정기 업무보고", "term_vi": "Báo cáo công việc định kỳ", "def_ko": "정해진 시간마다 하는 보고", "def_vi": "Báo cáo được thực hiện vào những thời điểm cố định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1174, '9', '요양보호 업무 수행 시 반드시 기관에 보고를 해야 할 사항은?', '["대상자의 상태가 평상시와 같을 때", "서비스에 변화가 없을 때", "업무를 잘못 수행했을 때", "대상자에게 기저귀를 채울 때", "대상자의 가족이 방문했을 때"]'::jsonb, 3, '요양보호사 업무 수행 시 어떤 상황에서 반드시 기관에 보고해야 하는지를 이해하는 것이 중요하다.', NULL, '{"1": "대상자의 상태가 평상시와 같을 때는 보고할 필요가 없다.", "2": "서비스에 변화가 없을 때도 보고할 필요가 없다.\n[정답]", "3": "업무를 잘못 수행했을 때는 반드시 보고해야 한다.", "4": "대상자에게 기저귀를 채울 때는 보고할 사항이 아니다.", "5": "대상자의 가족이 방문했을 때는 보고할 필요가 없다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1173, '9', '요양보호사가 근무 중 대상자와 관련하여 상황이 급하거나 사안이 가벼울 때 보고하는 형식은?', '["구두보고", "서면보고", "전산망보고", "주간보고", "월간보고"]'::jsonb, 1, '요양보호사가 근무 중 대상자와 관련하여 상황에 따라 적절한 보고 형식을 선택하는 것을 평가하기 위함입니다.', NULL, '{"1": "구두보고는 상황이 급할 때 신속하게 정보를 전달하는 방식입니다.\n[정답]", "2": "서면보고는 공식적인 기록을 남기기 위한 방법이지만 긴급 상황에서는 적절하지 않을 수 있습니다.", "3": "전산망보고는 정보 관리 시스템을 통한 보고 방식으로, 긴급 상황에서는 구두보고가 더 적합합니다.", "4": "주간보고는 주기적으로 이루어지는 보고 형식으로, 긴급 상황에는 해당하지 않습니다.", "5": "월간보고는 월 단위로 작성되므로 긴급 상황에서 빠르게 대처하기 어렵습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌봄 제공자", "def_vi": "Người cung cấp dịch vụ chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1172, '9', '요양보호사의 업무보고 방법으로 옳은 것은?', '["숫자나 표가 포함된 내용을 구두로 보고한다.", "대상자 가족의 개인정보를 수시로 보고한다.", "업무를 잘못 수행했을 때에는 해결한 후 보고한다.", "업무 중 느낀 점을 정확하게 기록하여 보고한다.", "예기치 못한 사고 시 즉시 시설장에게 보고한다."]'::jsonb, 5, '요양보호사의 업무보고 방법에 대한 정확한 이해를 평가하고자 한다.', NULL, '{"1": "숫자나 표가 포함된 내용을 구두로 보고하는 것은 비효율적일 수 있다.\n[정답]", "5": "예기치 못한 사고 시 즉시 시설장에게 보고해야 한다.", "3": "업무를 잘못 수행했을 경우에는 즉시 보고해야 한다.", "4": "업무 중 느낀 점을 기록하는 것은 중요하지만, 보고는 후속 조치 후에 이루어져야 한다.", "2": "대상자 가족의 개인정보는 그들의 동의 없이 보고할 수 없다."}'::jsonb, '[{"term_ko": "업무보고", "term_vi": "업무", "def_ko": "보고 công việc", "def_vi": "công việc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1171, '9', '다음 중 업무보고 시기로 적절하지 않은 것은?', '["대상자의 상태에 변화가 있을 때", "서비스에 변화가 없을 때", "사고가 발생했을 때", "새로운 업무방법을 찾았을 때", "서비스를 추가하거나 변경할 필요가 있을 때"]'::jsonb, 2, '업무보고의 적절한 시기를 이해하고 적용하는 능력을 평가하고자 함.', NULL, '{"1": "대상자의 상태에 변화가 있을 때는 반드시 보고해야 한다.\n[정답]", "2": "서비스에 변화가 없을 때는 업무보고가 필요하지 않다.", "3": "사고가 발생했을 때는 즉시 보고해야 한다.", "4": "새로운 업무방법을 찾았을 때는 관련 정보를 보고해야 한다.", "5": "서비스를 추가하거나 변경할 필요가 있을 때는 반드시 보고해야 한다."}'::jsonb, '[{"term_ko": "업무보고", "term_vi": "Báo cáo công việc", "def_ko": "업무에 대한 임무 및 상태를 알리는 것", "def_vi": "Thông báo về nhiệm vụ và tình trạng công việc"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스의 수혜자", "def_vi": "Người hưởng lợi từ dịch vụ"}, {"term_ko": "변화", "term_vi": "Thay đổi", "def_ko": "상태나 조건이 달라지는 것", "def_vi": "Việc thay đổi trạng thái hoặc điều kiện"}, {"term_ko": "사고", "term_vi": "Tai nạn", "def_ko": "의도치 않은 사건", "def_vi": "Sự cố không mong muốn"}, {"term_ko": "업무방법", "term_vi": "Phương pháp làm việc", "def_ko": "일을 수행하는 방식", "def_vi": "Cách thức thực hiện công việc"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "제공되는 도움이나 지원", "def_vi": "Giúp đỡ hoặc hỗ trợ được cung cấp"}, {"term_ko": "추가하다", "term_vi": "Thêm vào", "def_ko": "더하다", "def_vi": "Thêm"}, {"term_ko": "변경하다", "term_vi": "Thay đổi", "def_ko": "바꾸다", "def_vi": "Thay đổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1166, '9', '대상자의 아들이 외국으로 나간다고 할 때 요양보호사의 대처방법으로 옳은 것은?', '["서비스를 계속한다.", "다른 시설을 소개해준다.", "외국에 같이 데리고 가라고 한다.", "비용을 할인해 준다.", "시설장에게 보고한다."]'::jsonb, 5, '대상자의 아들이 외국으로 나갈 때 요양보호사가 어떻게 대처해야 하는지를 묻고 있다.', NULL, '{"1": "서비스를 계속한다. - 서비스의 지속 여부는 아들의 결정에 달려 있으므로 옳지 않다.\n[정답]", "5": "시설장에게 보고한다. - 요양보호사는 대상자의 상태와 요양 상황을 관리하기 위해 시설장에게 보고해야 한다.", "2": "다른 시설을 소개해준다. - 다른 시설로의 전환은 대상자의 의사를 고려해야 하므로 옳지 않다.", "3": "외국에 같이 데리고 가라고 한다. - 이를 요청하는 것은 비현실적이므로 옳지 않다.", "4": "비용을 할인해 준다. - 비용 할인은 계약과 관계되므로 무단으로 결정할 수 없다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "간호사와 비슷한 직업으로 요양 서비스를 제공하는 사람(한국어)", "def_vi": "Người cung cấp dịch vụ chăm sóc"}, {"term_ko": "대처방법", "term_vi": "Cách xử lý", "def_ko": "문제를 해결하는 방법(한국어)", "def_vi": "Phương pháp để giải quyết vấn đề"}, {"term_ko": "시설장", "term_vi": "Quản lý cơ sở", "def_ko": "요양 시설을 관리하는 사람(한국어)", "def_vi": "Người quản lý cơ sở"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1165, '9', '방문요양서비스 제공 중 관리책임자에게 보고하지 않아도 되는 상황은?', '["대상자가 넘어져 타박상을 입었을 때", "대상자가 하루 종일 텔레비전을 볼 때", "대사자가 당뇨병 진단받은 것을 알았을 때", "베란다에서 배변 중인 대상자를 처음 발견했을 때", "대상자가 유효기간이 지난 음식을 먹고 복통을 호소할 때"]'::jsonb, 2, '방문요양서비스 제공 중 관리책임자에게 보고할 필요성이 있는 상황과 그렇지 않은 상황을 구분하는 것.', NULL, '{"1": "이 상황은 사고가 발생한 것이므로 관리책임자에게 보고해야 함.\n[정답]", "2": "단순히 텔레비전을 보는 것은 관리책임자에게 보고할 필요가 없음.", "3": "당뇨병 진단은 건강 상태에 변동이 있는 사항이므로 보고해야 함.", "4": "베란다에서 배변 중인 경우는 위생상 문제와 관련하여 보고해야 할 사항임.", "5": "유효기간이 지난 음식을 먹고 복통을 호소하는 경우 건강에 큰 영향을 미칠 수 있어 반드시 보고해야 함."}'::jsonb, '[{"term_ko": "방문요양서비스", "term_vi": "Dịch vụ chăm sóc tại nhà", "def_ko": "가정에서 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc được cung cấp tại nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1164, '9', '방문요양서비스 제공 시 관리책임자에게 신속하게 보고해야 하는 상황은?', '["체납 고지서를 발견하였다.", "쓰레기를 분리 배출하지 않았다.", "방문을 열 때마다 삐걱 소리가 난다.", "대상자가 현기증과 두통을 호소한다.", "근처에 사는 친척이 방문하였다."]'::jsonb, 4, '방문요양서비스에서 제공해야 하는 보고 상황을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "체납 고지서는 서비스 제공과 직접적인 관련이 없습니다.", "2": "쓰레기를 분리 배출하지 않는 것은 관리자의 보고 사항이 아닙니다.", "3": "삐걱 소리는 안전 문제일 수 있으나 긴급한 상황은 아닙니다.\n[정답]", "4": "대상자가 현기증과 두통을 호소하는 경우 즉각적인 조치가 필요하므로 관리책임자에게 보고해야 합니다.", "5": "친척의 방문은 특별히 보고할 필요가 없습니다."}'::jsonb, '[{"term_ko": "방문요양서비스", "term_vi": "Dịch vụ chăm sóc tại nhà", "def_ko": "집에서 요양서비스를 제공하는 것", "def_vi": "Cung cấp dịch vụ chăm sóc tại nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1163, '9', '다음 중 업무보고의 방법으로 옳은 것은?', '["모든 보고는 문서로 한다.", "사고 발생 시 요양보호사의 판단으로 처리한다.", "보고내용이 중복되지 않도록 한다.", "대상자의 건강상태에 변화가 생겼을 때에만 보고한다.", "추가적인 서비스를 요청 시 보호자와 상의한다."]'::jsonb, 3, '업무보고의 적절한 방법에 대한 이해를 확인하고자 함.', NULL, '{"1": "모든 보고는 문서로 해야 한다는 것은 잘못된 내용으로, 구두 보고도 허용된다.\n[정답]", "3": "보고내용이 중복되지 않도록 하는 것은 중요하며, 업무의 효율성을 높인다.", "2": "사고 발생 시 요양보호사의 판단만으로 처리하는 것은 적절하지 않다.", "4": "건강상태 변화가 있을 때만 보고하는 것은 보고의 필요성을 제한하는 문제이다.", "5": "추가적인 서비스 요청 시 보호자와 상의해야 하지만, 항상 보호자와의 협의가 필요한 것은 아니다."}'::jsonb, '[{"term_ko": "업무보고", "term_vi": "Báo cáo công việc", "def_ko": "임무에 대한 정보를 제공하는 것", "def_vi": "Cung cấp thông tin về nhiệm vụ"}, {"term_ko": "보고내용", "term_vi": "Nội dung báo cáo", "def_ko": "전달하는 정보나 데이터", "def_vi": "Thông tin hoặc dữ liệu được truyền đạt"}, {"term_ko": "중복되지 않다", "term_vi": "Không bị trùng lặp", "def_ko": "같은 내용이 두 번 이상 존재하지 않다", "def_vi": "Không tồn tại cùng một nội dung nhiều hơn một lần"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1162, '9', '요양보호사가 일일업무 보고를 할 때 옳은 것은?', '["구두로만 보고한다.", "중요한 사항만 보고한다.", "보고내용은 사실과 다름이 없이 정확하게 보고한다.", "공식화된 용어보다 쉬운 용어를 사용한다.", "자신의 생각을 중심으로 보고한다."]'::jsonb, 3, '요양보호사가 일일업무 보고를 할 때의 올바른 방법을 이해하고 적용할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "구두로만 보고하는 것은 불완전할 수 있습니다.", "2": "중요한 사항만 보고하는 것은 전체적인 내용을 놓칠 수 있습니다.\n[정답]", "3": "보고내용은 사실과 다름이 없이 정확하게 보고해야 합니다.", "4": "공식화된 용어보다 쉬운 용어를 사용하는 것은 필요하지만, 전문 용어를 적절히 사용하는 것이 중요합니다.", "5": "자신의 생각을 중심으로 보고하는 것은 객관성을 해칠 수 있습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 요양하는 사람", "def_vi": "Người chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1161, '9', '요양보호사의 업무보고 원칙으로 옳은 것은?', '["주관적인 사실을 보고한다.", "육하원칙에 따라 보고한다.", "근무종료 후 보고한다.", "중요한 내용은 반복해서 보고한다.", "일주일 단위로 모아서 보고한다."]'::jsonb, 2, '요양보호사의 업무 보고 방식에 대한 이해를 평가하는 문제입니다.', NULL, '{"1": "주관적인 사실을 보고하면 신뢰성이 떨어질 수 있으므로 옳지 않습니다.\n[정답]", "2": "육하원칙에 따라 보고하는 것이 업무 보고의 기본 원칙입니다.", "3": "근무종료 후 보고하는 것은 업무의 연속성을 해칠 수 있어 적절하지 않습니다.", "4": "중요한 내용은 반복해서 보고할 필요가 없고, 명확히 보고해야 합니다.", "5": "일주일 단위로 모아서 보고하는 것은 즉각적인 정보 전달을 방해할 수 있습니다."}'::jsonb, '[{"term_ko": "업무보고", "term_vi": "Báo cáo công việc", "def_ko": "질의, 정보 제공을 위한 단계", "def_vi": "Giai đoạn để truy vấn và cung cấp thông tin"}, {"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "기본적인 규칙", "def_vi": "Quy tắc cơ bản"}, {"term_ko": "주관적", "term_vi": "Chủ quan", "def_ko": "개인적인 판단", "def_vi": "Đánh giá cá nhân"}, {"term_ko": "육하원칙", "term_vi": "Nguyên tắc 5W1H", "def_ko": "5W1H의 원칙", "def_vi": "Quy tắc 5W1H"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1160, '9', '업무보고의 중요성으로 옳은 것은?', '["대상자의 단점을 파악할 수 있다.", "보호자와 관계가 돈독해진다.", "사고대응을 신속하게 할 수 있다.", "대사자의 질병치료를 할 수 있다.", "업무성과를 평가 받을 수 있다."]'::jsonb, 3, '업무보고의 중요성을 이해하고 관련된 내용을 명확히 파악하기 위함니다.', NULL, '{"1": "대상자의 단점 파악은 업무보고의 직접적인 목적이 아니다.\n[정답]", "3": "사고대응을 신속하게 할 수 있다는 것은 업무보고의 중요한 효과 중 하나이다.", "2": "보호자와의 관계는 중요하지만 업무보고의 직접적인 결과는 아니다.", "4": "대사자의 질병치료는 업무보고의 결과가 아니다.", "5": "업무성과 평가에 대한 것은 결과적으로 영향을 미칠 수 있지만 주요 목적이 아니다."}'::jsonb, '[{"term_ko": "업무보고", "term_vi": "Báo cáo công việc", "def_ko": "일의 진행 상황을 정리해서 보고하는 것", "def_vi": "Việc tổng hợp và báo cáo tiến độ công việc"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "보살핌을 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "보호자", "term_vi": "Người chăm sóc", "def_ko": "환자의 가족이나 대리인", "def_vi": "Gia đình hoặc đại diện của bệnh nhân"}, {"term_ko": "사고대응", "term_vi": "Phản ứng sự cố", "def_ko": "사고 발생 시의 대처 방안", "def_vi": "Phương án ứng phó khi xảy ra sự cố"}, {"term_ko": "질병치료", "term_vi": "Điều trị bệnh", "def_ko": "질병을 치료하는 행동", "def_vi": "Hành động điều trị bệnh"}, {"term_ko": "업무성과", "term_vi": "Kết quả công việc", "def_ko": "일의 결과와 성과", "def_vi": "Kết quả và thành tích của công việc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1159, '9', '장기요양급여 제공기록지 작성 시 올바른 방법은?', '["방문요양서비스는 서비스 제공 시작과 종료 시간을 기록한다.", "방문요양서비스는 세부 서비스별 제공시간을 ''시간'' 단위로 기재한다.", "방문목욕서비스의 경우 장기요양요원 1명의 성명을 기재한다.", "주 야간 보호 서비스는 세부 서비스별 제공시간을 기재하지 않는다.", "시설급여서비스의 경우 특이사항은 기재하지 않는다."]'::jsonb, 1, '장기요양급여 제공기록지 작성에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "방문요양서비스는 서비스 제공 시작과 종료 시간을 기록한다.\n[정답]", "2": "방문요양서비스는 세부 서비스별 제공시간을 ''시간'' 단위로 기재한다.", "3": "방문목욕서비스의 경우 장기요양요원 1명의 성명을 기재한다.", "4": "주 야간 보호 서비스는 세부 서비스별 제공시간을 기재하지 않는다.", "5": "시설급여서비스의 경우 특이사항은 기재하지 않는다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기사용을 위한 요양서비스 제공", "def_vi": "Dịch vụ chăm sóc dài hạn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1158, '9', '방문 요양 시 장기요양급여 제공기록지에 기록할 내용으로 옳은 것은?', '["월 급여한도액", "수급자 가족 수", "수급자 희망급여", "총 급여제공시간", "보호자 직업"]'::jsonb, 4, '장기요양급여 제공 시 어떤 내용이 기록되어야 하는지를 확인하는 것.', NULL, '{"1": "월 급여한도액은 기록하지 않음.", "2": "수급자 가족 수는 제공 기록지에 포함되지 않음.\n[정답]", "3": "총 급여제공시간은 반드시 기록해야 하는 내용임.", "4": "보호자 직업은 기록할 필요가 없음."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Trợ cấp chăm sóc dài hạn", "def_ko": "장기 요양을 위한 재정 지원", "def_vi": "Hỗ trợ tài chính cho chăm sóc dài hạn"}, {"term_ko": "제공기록지", "term_vi": "Bảng ghi chép cung cấp", "def_ko": "급여 제공 내용을 기록한 문서", "def_vi": "Tài liệu ghi lại nội dung cung cấp trợ cấp"}, {"term_ko": "수급자", "term_vi": "Người hưởng trợ cấp", "def_ko": "지원 혜택을 받는 사람", "def_vi": "Người nhận hỗ trợ"}, {"term_ko": "총", "term_vi": "Tổng", "def_ko": "전체", "def_vi": "Tổng thể"}, {"term_ko": "희망", "term_vi": "Hy vọng", "def_ko": "원하는", "def_vi": "Mong muốn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1157, '9', '장기요양급여 제공기록지에 기재 되지 않은 것은?', '["장기요양등급", "서비스 제공일자", "장기요양 인정번호", "장기요양 유효기간", "서비스 시작시간 및 종료시간"]'::jsonb, 4, '장기요양급여 제공기록지의 필수 기재 항목을 이해하고 있는지 확인하기 위함입니다.', NULL, '{"1": "장기요양등급은 기록지에 필수로 포함되어야 하는 요소입니다.\n[정답]", "4": "장기요양 유효기간은 제공기록지에 기재되지 않아야 하는 사항입니다.", "2": "서비스 제공일자는 필수 기재 사항입니다.", "3": "장기요양 인정번호 또한 중요한 항목으로 기록되어야 합니다.", "5": "서비스 시작시간 및 종료시간은 제공기록지에 반드시 기재해야 하는 내용입니다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Chăm sóc lâu dài", "def_ko": "장기 요양 서비스를 통해 제공되는 혜택", "def_vi": "Sự hỗ trợ từ dịch vụ chăm sóc lâu dài"}, {"term_ko": "기록지", "term_vi": "Sổ ghi chép", "def_ko": "기록을 위한 문서", "def_vi": "Tài liệu để ghi lại"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "제공하는 돌봄 활동", "def_vi": "Hoạt động chăm sóc cung cấp"}, {"term_ko": "유효기간", "term_vi": "Thời hạn hiệu lực", "def_ko": "사용이 가능한 기간", "def_vi": "Thời gian có thể sử dụng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1156, '9', '요양보호 기록 시 주의해야 할 사항으로 옳은 것은?', '["개인정보는 제3자에게 노출시킬 수 있다.", "업무상 알게 된 정보는 외부에 유출할 수 있다.", "대상자의 동의 없이 개인 정보 수집을 할 수 있다.", "기록은 반드시 잠금장치가 되어 있는 장소에 보관한다.", "대상자의 기록은 누구나 열람할 수 있다."]'::jsonb, 4, '요양보호사의 기록 관리 및 개인정보 보호에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "개인정보는 제3자에게 노출시킬 수 없다. 이는 개인 정보 보호의 원칙에 위배됩니다.\n[정답]", "4": "기록은 반드시 잠금장치가 되어 있는 장소에 보관해야 안전하게 보호될 수 있습니다.", "2": "업무상 알게 된 정보는 외부에 유출할 수 없다. 이는 윤리적 문제를 일으킵니다.", "3": "대상자의 동의 없이 개인 정보 수집을 할 수 없다. 이는 법적으로 금지되어 있습니다.", "5": "대상자의 기록은 누구나 열람할 수 없다. 기록은 관련된 사람만 접근할 수 있어야 합니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "Chăm sóc", "def_ko": "돌봄과 지원을 제공하는 일", "def_vi": "Công việc cung cấp sự hỗ trợ và chăm sóc"}, {"term_ko": "기록", "term_vi": "Hồ sơ", "def_ko": "정보나 사건을 기록한 자료", "def_vi": "Tài liệu ghi lại thông tin hoặc sự kiện"}, {"term_ko": "개인정보", "term_vi": "Thông tin cá nhân", "def_ko": "개인에 대한 특정 정보", "def_vi": "Thông tin cụ thể về cá nhân"}, {"term_ko": "동의", "term_vi": "Sự đồng ý", "def_ko": "허락, 승인", "def_vi": "Sự chấp thuận, công nhận"}, {"term_ko": "유출", "term_vi": "Rò rỉ", "def_ko": "비밀을 누설하다", "def_vi": "Tiết lộ bí mật"}, {"term_ko": "보관", "term_vi": "Lưu trữ", "def_ko": "안전하게 지키거나 저장하다", "def_vi": "Bảo vệ hoặc lưu giữ an toàn"}, {"term_ko": "잠금장치", "term_vi": "Khóa", "def_ko": "잠금장치가 있는 기계", "def_vi": "Thiết bị có cơ chế khóa"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1155, '9', '요양보호사가 관찰한 내용을 기록하는 방법으로 옳은 것은?', '["식탁에 오래된 빵이 있다.", "한참을 산책하였다.", "청소하는데 오래 걸렸다.", "오전 10시에 죽 한 그릇을 드셨다.", "며칠만에 대변을 시원하게 보았다."]'::jsonb, 4, '요양보호사가 환자의 상태나 활동을 기록하는 방법에 대한 올바른 선택을 찾는 것입니다.', NULL, '{"1": "식탁에 오래된 빵이 있다. (객관적인 관찰이 아닌 주관적 판단의 요소가 포함됨)\n[정답]", "4": "오전 10시에 죽 한 그릇을 드셨다. (정확한 시간과 행동이 기록되어 있어 객관적으로 관찰된 내용)", "2": "한참을 산책하였다. (정확하지 않은 시간 정보가 부족함)", "3": "청소하는데 오래 걸렸다. (구체적인 시간 정보가 부족하며 주관적 요소가 강함)", "5": "며칠만에 대변을 시원하게 보았다. (숫자 표현과 주관적인 표현이 혼합됨)"}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자나 노인을 돌보는 일을 하는 사람", "def_vi": "Người chăm sóc bệnh nhân hoặc người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1154, '9', '요양보호사의 업무기록 방법으로 옳은 것은?', '["오랜만에 입맛이 좋아 보였다.", "얼마 전부터 식사량이 꽤 늘었다.", "평소보다 낮잠을 많이 잤다.", "오후 3시에 간식으로 나온 수박을 안 드셨다.", "며칠 만에 기분이 좋아 보인다."]'::jsonb, 4, '요양보호사가 환자의 상태를 정확히 기록할 수 있는 방법을 이해하는지를 평가하기 위함입니다.', NULL, '{"1": "오랜만에 입맛이 좋아 보였다는 주관적인 표현으로, 기록으로 적합하지 않습니다.\n[정답]", "4": "오후 3시에 간식으로 나온 수박을 안 드셨다는 구체적인 사실을 기록하여, 요양보호사의 업무 기록으로 적합합니다.", "2": "얼마 전부터 식사량이 꽤 늘었다는 주관적인 기술로서, 구체적인 수치를 포함하지 않아 정확한 기록에 부족합니다.", "3": "평소보다 낮잠을 많이 잤다는 주관적 기술이며, 구체적인 시간 또는 양이 부족합니다.", "5": "며칠 만에 기분이 좋아 보인다는 주관적인 감정 표현으로 정확한 기록으로 적합하지 않습니다."}'::jsonb, '[{"term_ko": "업무기록", "term_vi": "Ghi chép công việc", "def_ko": "작업 기록(한국어)", "def_vi": "Ghi chép công việc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1153, '9', '요양보호사가 기록한 내용 중 올바른 것은?', '["어르신이 평소보다 식사를 많이 함", "피부 발적이 심하게 나타남", "쵝근 들어 체중이 많이 줄었음", "7월 10일, 오후 3시, 방에서 300CC의 소변을 봄", "점심에 경관영양을 400ML 제공 함"]'::jsonb, 4, '요양보호사가 기록한 내용을 평가하여 적절한 방법으로 기록할 수 있는 능력을 확인하기 위한 문제입니다.', NULL, '{"1": "어르신이 평소보다 식사를 많이 했다는 내용은 주관적인 판단이 들어갈 수 있어 기록으로서 적절하지 않습니다.", "2": "피부 발적이 심하게 나타났다는 표현은 상태를 정확히 파악하기 어려워, 구체적인 수치나 조건이 요구됩니다.", "3": "체중 변화에 관한 내용은 정확한 수치가 부족하여 신뢰도가 낮습니다.\n[정답]", "4": "7월 10일, 오후 3시, 방에서 300CC의 소변을 본 내용은 구체적이고 명시적인 숫자를 포함하고 있어 기록으로서 올바른 표현입니다.", "5": "경관영양 제공에 관한 내용은 양이 정해져 있지만, 기록 시 참고가 필요할 수 있는 다른 정보가 부족합니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 돌보고 관리하는 사람", "def_vi": "Người chăm sóc và quản lý bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1152, '9', '요양보호사의 업무기록 방법으로 옳은 것은?', '["주관적인 판단으로 작성한다.", "한꺼번에 모아서 기록한다.", "우회적으로 장황하게 기록한다.", "정정 시 지우거나 덧칠을 한다.", "서비스의 과정과 결과를 정확하게 기록한다."]'::jsonb, 5, '요양보호사가 적절한 업무기록 방법을 이해하고 있는지 평가하기 위한 문제입니다.', NULL, '{"1": "주관적인 판단으로 작성하는 것은 바람직하지 않습니다.\n[정답]", "5": "서비스의 과정과 결과를 정확하게 기록해야 합니다.", "2": "모든 기록을 한꺼번에 모아서 작성하는 것은 비효율적입니다.", "3": "우회적이고 장황한 기록은 명확성을 저하시킵니다.", "4": "정정 시 지우거나 덧칠하는 것은 기록의 신뢰성을 떨어뜨릴 수 있습니다."}'::jsonb, '[{"term_ko": "업무기록", "term_vi": "Ghi chép công việc", "def_ko": "일에 대한 기록방법", "def_vi": "Phương pháp ghi chép về công việc"}, {"term_ko": "주관적", "term_vi": "Chủ quan", "def_ko": "자신의 판단에 따라", "def_vi": "Dựa trên phán đoán của cá nhân"}, {"term_ko": "정정", "term_vi": "Sửa chữa", "def_ko": "수정 작업", "def_vi": "Thao tác chỉnh sửa"}, {"term_ko": "과정", "term_vi": "Quá trình", "def_ko": "어떤 일이 진행되는 단계", "def_vi": "Giai đoạn diễn ra của một công việc"}, {"term_ko": "결과", "term_vi": "Kết quả", "def_ko": "어떤 결과가 생기는 것", "def_vi": "Kết quả mà một công việc tạo ra"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1151, '9', '요양보호 기록의 원칙으로 옳은 것은?', '["대상자의 사생활을 기록한다.", "서비스의 결과만 기록한다.", "기록은 한 달에 한번 한다.", "공식화된 용어를 사용한다.", "요양보호사의 생각을 사실대로 기록한다."]'::jsonb, 4, '요양보호 기록의 중요성과 원칙을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "대체로 사생활은 보호되어야 하며, 기록에 포함되면 안 되는 경우가 많습니다.\n[정답]", "4": "공식화된 용어를 사용해야 정보를 명확히 전달할 수 있습니다.", "2": "서비스의 결과만 기록하는 것은 불완전한 기록으로, 발생한 모든 사항을 기재해야 합니다.", "3": "기록은 주기적으로 해야 하며, 한 달에 한번으로 제한되지 않습니다.", "5": "요양보호사의 주관적인 생각보다는 사실에 기반한 객관적인 기록이 필요합니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "Chăm sóc", "def_ko": "돌봄이 필요한 사람을 도와주는 서비스", "def_vi": "Dịch vụ giúp đỡ người cần chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1150, '9', '요양보호 기록의 원칙으로 옳은 것은?', '["서비스의 제공 과정만 기록한다.", "업무종결 후 한꺼번에 기록한다.", "서비스내용은 간단명료하게 기록한다.", "주관적인 생각과 판단을 토대로 기록한다.", "중요한 내용은 보호자의 동의를 구한 후 기록한다."]'::jsonb, 3, '요양보호 기록의 올바른 원칙을 이해하고 있는지를 평가하기 위함이다.', NULL, '{"1": "서비스 제공의 모든 과정이 아니라 특정한 점들을 기록해야 하는데, 이 항목은 틀린 것이다.\n[정답]", "3": "서비스 내용은 간결하고 명확하게 기록해야 한다. 이는 기록의 원칙 중 하나이다.", "2": "업무 후에 한 번에 기록하는 것은 비효율적이며, 상황이 기억에서 사라질 수 있으므로 올바르지 않다.", "4": "기록은 주관적인 판단이 아니라 사실에 기반해야 하므로 틀린 주장이다.", "5": "중요한 내용을 기록하기 위해서는 보호자의 동의가 필요할 수 있으나, 모든 사항을 해당 원칙으로 기록할 필요는 없다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "Ghi chép", "def_ko": "돌봄 제공", "def_vi": "ghi chép"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1149, '9', '요양보호 기록의 원칙으로 옳은 것은?', '["동료와 기록을 공유한다.", "요양보호사의 주관적 생각도 기록한다.", "육하원칙을 바탕으로 기록한다.", "서비스의 결과만 기록한다.", "길고 자세하게 기록한다."]'::jsonb, 3, '요양보호 기록의 원칙에 대해 평가하기 위함입니다.', NULL, '{"1": "동료와 기록을 공유하는 것은 보안 문제로 옳지 않습니다.\n[정답]", "3": "육하원칙을 바탕으로 기록하는 것이 기본 원칙입니다.", "2": "요양보호사의 주관적 생각은 기록에 포함되지 않아야 합니다.", "4": "서비스의 결과만 기록하는 것이 아니라 과정도 중요합니다.", "5": "길고 자세하게 기록하기 보다는 간결하고 명확한 것이 중요합니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "기록", "def_ko": "돌봄 서비스(서비스 chăm sóc)", "def_vi": "기록(ghi chép)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1148, '9', '요양보호사가 퇴직, 휴직 등으로 인하여 업무를 그만둘 때 직원간의 업무인수인계를 위해 기록하는 것은?', '["방문일지", "사고보고서", "상태기록지", "장기요양급여제공기록지", "인수인계서"]'::jsonb, 5, '요양보호사가 업무를 그만두는 경우, 후임자에게 원활한 인수인계를 위해 필요한 기록을 이해하는 것이 중요합니다.', NULL, '{"1": "방문일지: 환자의 방문 기록을 남기는 문서로, 인수인계와는 무관합니다.", "2": "사고보고서: 사고가 발생했을 때 작성하는 문서로, 인수인계와는 관련이 없습니다.", "3": "상태기록지: 환자의 상태를 기록하는 문서로, 인수인계의 목적에는 적합하지 않습니다.\n[정답]", "4": "장기요양급여제공기록지: 요양급여 제공 내용을 기록하는 문서이나, 인수인계의 목적으로는 사용되지 않습니다.", "5": "인수인계서: 후임자에게 업무에 대한 정보를 전달하기 위해 작성하는 문서로, 가장 적절한 선택입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc sức khỏe", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "퇴직", "term_vi": "Nghỉ việc", "def_ko": "그만두는 것", "def_vi": "Nghỉ lại"}, {"term_ko": "휴직", "term_vi": "Nghỉ phép", "def_ko": "일시적으로 업무를 중단하는 것", "def_vi": "Dừng công việc tạm thời"}, {"term_ko": "업무", "term_vi": "Công việc", "def_ko": "일을 하는 것", "def_vi": "Làm việc"}, {"term_ko": "인수인계", "term_vi": "Chuyển giao công việc", "def_ko": "다음 사람에게 업무를 전달하는 것", "def_vi": "Đưa công việc cho người khác"}, {"term_ko": "기록", "term_vi": "Ghi chép", "def_ko": "내용을 적어두는 것", "def_vi": "Ghi nhớ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1147, '9', '식사섭취, 배설, 목욕 등의 상태 및 제공 내용을 기록하는 요양보호 기록지는?', '["욕구사정", "방문일지", "상담일지", "상태기록지", "인수인계서"]'::jsonb, 4, '요양보호 기록지의 종류와 기능을 이해하고 있는지를 확인하기 위함입니다.', NULL, '{"1": "욕구사정: 개인의 필요와 욕구를 평가하는 도구로, 기록지는 아닙니다.\n[정답]", "4": "상태기록지: 식사섭취, 배설, 목욕 등의 상태 및 제공 내용을 기록하는 문서입니다.", "2": "방문일지: 방문한 날짜와 시간, 활동 내용을 기록합니다.", "3": "상담일지: 상담 내용과 결과를 기록하는 문서입니다.", "5": "인수인계서: 요양보호사 간의 정보 전달 문서입니다."}'::jsonb, '[{"term_ko": "식사섭취", "term_vi": "Sự tiêu thụ thực phẩm", "def_ko": "음식이나 음료를 섭취하는 것", "def_vi": "Ăn uống hoặc uống đồ uống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1146, '9', '요양보호사의 재각급여제공 내용을 국민건강보험공단에 실시간으로 전송하고 이를 급여비용 청구와 자동으로 연계하는 관리체계는?', '["보건복지포털", "사회복지통합관리망", "요양시설관리시스템", "재가급여전자관리시스템", "건강보험급여청구시스템"]'::jsonb, 4, '요양보호사의 재각급여 제공 관련 관리체계를 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "보건복지부가 제공하는 정보 시스템으로 전송 기능과는 거리가 있습니다.\n[정답]", "4": "재가급여 전자관리 시스템은 재각급여 제공 내용을 실시간으로 전송하고 급여비용 청구와 연결하는 시스템입니다.", "2": "사회복지통합관리망은 다양한 사회복지 관련 정보를 통합 관리하지만 이 문제와는 연관성이 낮습니다.", "3": "요양시설 관리 시스템은 시설 관리에 중점을 두고 있고, 재각급여와 관련이 없습니다.", "5": "건강보험 급여청구 시스템은 건강보험 관련 청구를 처리하지만 재각급여의 실시간 전송과는 연결되지 않습니다."}'::jsonb, '[{"term_ko": "재각급여", "term_vi": "Trợ cấp lại", "def_ko": "다시 제공되는 요양급여", "def_vi": "Phúc lợi chăm sóc được cung cấp lại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1145, '9', '요양보호사가 대상자에게 제공한 서비스의 내용과 시간, 특이사항을 기록하는 것은?', '["상담일지", "상태기록지", "사고보고서", "인수인계서", "장기요양급여 제공기록지"]'::jsonb, 5, '대상자에게 제공한 서비스의 기록 관리 방법에 대한 이해를 점검하는 문제입니다.', NULL, '{"1": "상담일지: 상담 내용을 기록하는 문서로, 서비스 제공 기록과는 다릅니다.\n[정답]", "5": "장기요양급여 제공기록지: 요양보호사가 제공한 서비스 내용, 시간 및 특이사항을 기록하는 공식 문서입니다.", "2": "상태기록지: 대상자의 건강 상태를 기록하는 문서입니다.", "3": "사고보고서: 사고 발생 시 작성하는 문서로, 서비스 기록과는 차이가 있습니다.", "4": "인수인계서: 서비스 인계 시 작성하는 서류로, 제공 기록과는 목적이 다릅니다."}'::jsonb, '[{"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "서비스(한국어)", "def_vi": "Dịch vụ(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1144, '9', '요양보호사가 제공한 서비스 내용을 기록하는 목적은?', '["동료를 평가하고 감독하기 위해서", "업무에 대한 책임감을 높이기 위해서", "대상자의 비밀을 동료와 공유하기 위해서", "법적 책임을 회피하기 위해서", "서비스를 제한하고 대상자를 평가하기 위해서"]'::jsonb, 2, '요양보호사가 제공한 서비스의 기록 목적을 이해하고 선택지를 분석할 수 있는 능력을 평가하고자 함.', NULL, '{"1": "동료를 평가하고 감독하기 위해서는 서비스 내용 기록이 아닌 다른 방법이 필요하다. \n[정답]", "2": "업무에 대한 책임감을 높이기 위한 것이며, 기록은 서비스 제공에 있어 중요한 증거가 된다.", "3": "대상자의 비밀은 다른 동료와 공유해서는 안 된다.", "4": "법적 책임을 회피하기 위한 것이 아니라, 법적 책임을 명확히 하기 위한 기록이라 할 수 있다.", "5": "서비스를 제한하고 대상자를 평가하기 위한 목적이 아니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌보미", "def_vi": "Người chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1143, '9', '요양보호 기록의 목적으로 옳은 것은?', '["요양보호사의 능력을 평가하기 위해서", "요양보호사의 책임성을 줄이기 위해서", "요양보호사의 단점을 발견하기 위해서", "요양보호서비스의 표준화에 기여하기 위해서", "요양보호사의 근무 태도를 비교하기 위해서"]'::jsonb, 4, '요양보호 기록이 어떤 목적을 가지는지를 이해하는 것은 중요하다. 이러한 기록은 요양보호 서비스의 질을 향상시키고 표준화하는 데 기여한다.', NULL, '{"1": "요양보호사의 능력을 평가하기 위해서", "2": "요양보호사의 책임성을 줄이기 위해서", "3": "요양보호사의 단점을 발견하기 위해서\n[정답]", "4": "요양보호서비스의 표준화에 기여하기 위해서", "5": "요양보호사의 근무 태도를 비교하기 위해서"}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "Chăm sóc người già", "def_ko": "노인을 돌보는 활동", "def_vi": "Hoạt động chăm sóc cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1142, '9', '요양보호 업무기록의 중요성으로 옳은 것은?', '["기록하는 습관을 유지할 수 있다.", "대상자의 사생활을 관리할 수 있다.", "보호자와의 유대관계를 형성한다.", "관련 전문가에게 중요한 정보를 제공한다.", "대상자에 대한 주관적인 판단에 도움이 된다."]'::jsonb, 4, '요양보호 업무기록의 중요성을 이해하고, 올바른 선택지를 고를 수 있도록 유도하는 것이 의도입니다.', NULL, '{"1": "기록하는 습관을 유지할 수 있지만, 이는 중요성의 핵심이 아닙니다.\n[정답]", "4": "관련 전문가에게 중요한 정보를 제공하는 것이 요양보호 업무기록의 가장 중요한 역할 중 하나입니다.", "2": "대상자의 사생활 관리와 연관이 있지만, 주로 업무기록의 중요성과 관련되지 않습니다.", "3": "보호자와의 유대관계 형성은 중요하지만, 업무기록의 중요한 목적은 아닙니다.", "5": "대상자에 대한 주관적인 판단은 업무기록의 목적이 아닙니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "Chăm sóc người cao tuổi", "def_ko": "노인을 돌보는 일", "def_vi": "Công việc chăm sóc cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1141, '9', '요양보호 기록의 목적으로 옳은 것은?', '["시설장에게 잘 보이기 위해서", "주관적인 의견을 기록하기 위해서", "대상자의 건강을 진단하기 위해서", "서비스의 연속성을 유지하기 위해서", "근무 평가에 따른 수당을 더 받기 위해서"]'::jsonb, 4, '요양보호 기록의 목적을 이해하고 올바른 선택지를 찾는 것.', NULL, '{"1": "시설장에게 잘 보이기 위해서는 기록의 목적이 아니다.\n[정답]", "4": "서비스의 연속성을 유지하기 위해서 기록은 필수적이다.", "3": "건강 진단은 전문 의료인이 수행해야 한다.", "2": "주관적인 의견은 표기하지 않아야 한다.", "5": "근무 평가에 따른 수당은 기록과 직접적 연관이 없다."}'::jsonb, '[{"term_ko": "요양보호 기록", "term_vi": "Ghi chép chăm sóc người cao tuổi", "def_ko": "노인 돌봄과 관련된 문서 작성", "def_vi": "Việc viết tài liệu liên quan đến chăm sóc người cao tuổi"}, {"term_ko": "시설장", "term_vi": "Giám đốc cơ sở", "def_ko": "시설의 책임자", "def_vi": "Người chịu trách nhiệm về cơ sở"}, {"term_ko": "주관적", "term_vi": "Chủ quan", "def_ko": "개인의 의견이나 느낌", "def_vi": "Ý kiến hoặc cảm nhận cá nhân"}, {"term_ko": "서비스 연속성", "term_vi": "Tính liên tục của dịch vụ", "def_ko": "서비스의 지속적인 제공", "def_vi": "Việc cung cấp dịch vụ liên tục"}, {"term_ko": "건강 진단", "term_vi": "Chẩn đoán sức khỏe", "def_ko": "건강 상태를 평가하는 과정", "def_vi": "Quá trình đánh giá tình trạng sức khỏe"}, {"term_ko": "근무 평가", "term_vi": "Đánh giá công việc", "def_ko": "업무 수행에 대한 평가", "def_vi": "Đánh giá về việc thực hiện công việc"}, {"term_ko": "수당", "term_vi": "Phụ cấp", "def_ko": "추가 보상", "def_vi": "Thưởng thêm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1140, '8', '거동이 불편하거나 인지기능이 저하된 시설 대상자의 여가활동을 돕기 위한 방법으로 옳은 것은?', '["어렵지 않고 흥미로운 프로그램으로 배정한다.", "가족의 의견을 중심으로 여가활동을 지원한다.", "요양보호사의 상황에 따라 프로그램을 배정한다.", "움직임이 빠르고 신속한 프로그램을 배정한다.", "대상자의 경제적 수준을 고려하여 집단 프로그램으로 배정한다."]'::jsonb, 1, '여가활동을 돕기 위해 적합한 방법을 이해하고 선택하는 능력을 평가하고자 함.', NULL, '{"1": "어렵지 않고 흥미로운 프로그램으로 배정한다. - 대상자가 참여하기 쉽고 기분이 좋아지는 활동을 제공하는 것이 중요하다.\n[정답]", "2": "가족의 의견을 중심으로 여가활동을 지원한다. - 가족의 의견이 중요하지만, 항상 개별 대상자의 선호가 우선되어야 한다.", "3": "요양보호사의 상황에 따라 프로그램을 배정한다. - 요양보호사의 상황보다는 대상자의 특성을 우선적으로 고려해야 한다.", "4": "움직임이 빠르고 신속한 프로그램을 배정한다. - 거동이 불편한 대상자에게는 부적합한 선택이다.", "5": "대상자의 경제적 수준을 고려하여 집단 프로그램으로 배정한다. - 경제적 수준은 고려해야 하지만, 대상자의 선호와 신체적 한계를 더 중요하게 생각해야 한다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Di chuyển", "def_ko": "움직임(행동)", "def_vi": "di chuyển"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1139, '8', '다음 대화 중 요양보호사가 대상자에게 추천한 여가활동 유형은?대상자: 건강했을 때 농사를 지었는데 힘들어도 보람이 있어서 좋았는데 지금은 심심해. 요양보호사: 그러셨어요! 상추를 가꾸어 보시는 건 어떠세요.', '["소일 활동", "운동 활동", "가족 중심 활동", "사교 오락 활동", "자기계발 활동"]'::jsonb, 1, '대상자가 여가활동으로 무엇을 추천받았는지를 묻고 있다.', NULL, '{"1": "상추를 가꾸는 것은 흙을 다루는 활동이며, 흙과의 접촉을 통해 심리적 안정감을 제공한다. 이는 소일 활동에 해당한다.\n[정답]", "2": "운동 활동은 신체 단련이 목표인데, 농사를 지으면서 그 자체가 운동으로 배치되기 어렵다.", "3": "가족 중심 활동은 가족과의 시간을 중시하는 활동을 의미하여 관련이 없다.", "4": "사교 오락 활동은 친구나 타인과의 교류가 중심인 여가 활동이다.", "5": "자기계발 활동은 개인적인 성장이나 학습에 중점을 두는 활동으로, 농사를 한다는 것과는 무관하다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간에 수행하는 활동", "def_vi": "Hoạt động thực hiện trong thời gian rảnh rỗi"}, {"term_ko": "소일 활동", "term_vi": "Hoạt động liên quan đến đất", "def_ko": "자연과 함께하는 활동", "def_vi": "Hoạt động như tiếp xúc với đất"}, {"term_ko": "운동", "term_vi": "Thể dục", "def_ko": "신체를 사용하는 활동", "def_vi": "Hoạt động sử dụng cơ thể"}, {"term_ko": "가족", "term_vi": "Gia đình", "def_ko": "친척", "def_vi": "Người thân"}, {"term_ko": "사교", "term_vi": "Xã hội", "def_ko": "친구나 지인과의 교류", "def_vi": "Giao lưu với bạn bè"}, {"term_ko": "자기계발", "term_vi": "Phát triển bản thân", "def_ko": "개인의 성장 활동", "def_vi": "Hoạt động liên quan đến sự phát triển cá nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1138, '8', '대상자의 신진대사 촉진에 도움이 되는 산책에 해당하는 여가활동 유형은?', '["자기계발 활동", "사교 오락 활동", "가족 중심 활동", "운동 활동", "소일 활동"]'::jsonb, 4, '신진대사를 촉진하는 여가활동의 유형을 이해하고 구별하기 위함입니다.', NULL, '{"1": "자기계발 활동: 개인의 능력 개발과 관련된 활동으로 신진대사 촉진과는 직접적인 연관이 없습니다.\n[정답]", "4": "운동 활동: 신진대사를 촉진하는 중요한 방법으로 산책은 운동의 일종입니다.", "2": "사교 오락 활동: 사람들과의 사회적 상호작용을 포함하지만 신진대사와의 연관성은 낮습니다.", "3": "가족 중심 활동: 가족 간의 유대감을 강화하는 활동이나 신진대사 촉진과는 다소 거리가 있습니다.", "5": "소일 활동: 시간을 보내기 위한 활동으로 신진대사와 크게 관련이 없습니다."}'::jsonb, '[{"term_ko": "신진대사", "term_vi": "Chuyển hóa", "def_ko": "생명체의 물질대사 과정", "def_vi": "Quá trình trao đổi chất"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1137, '8', '김씨 할아버지는 아내와 사별 후 1년 동안 다른 사람 만나는 것을 꺼리고 있다. 이때 추천할 수 있는 여가활동은?', '["신문 보기", "그림 그리기", "친목 활동", "책 읽기", "텔레비전 시청하기"]'::jsonb, 3, '여가활동을 통해 사회적 상호작용과 정서적 지지의 중요성을 강조하기 위함입니다.', NULL, '{"1": "신문 보기는 정보 습득은 가능하지만 외부와의 상호작용이 적습니다.", "2": "그림 그리기는 개인적인 취미 활동으로 사회적 상호작용이 부족합니다.\n[정답]", "3": "친목 활동은 타인과의 관계를 형성하고 정서적 지지를 받을 수 있는 좋은 방법입니다.", "4": "책 읽기는 개인적인 활동으로 외부와의 소통이 없습니다.", "5": "텔레비전 시청하기는 수동적인 활동으로 사회적 상호작용을 제공하지 않습니다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간에 하는 활동(한국어)", "def_vi": "Hoạt động trong thời gian rảnh rỗi(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1136, '8', '김씨 할아버지는 아내와 사별 후 1년 동안 다른 사람 만나는 것을 꺼리고 있다. 이때 추천할 수 있는 여가활동은?', '["신문 보기", "그림 그리기", "친목 활동", "책 읽기", "텔레비전 시청하기"]'::jsonb, 3, '여가활동을 통해 정서적 안정을 찾고, 사회적 상호작용을 늘릴 수 있는 방법을 제시하기 위함입니다.', NULL, '{"1": "신문 보기는 개인적인 활동으로 고립감을 느낄 수 있습니다.\n[정답]", "3": "친목 활동은 사람들과의 교류를 통해 정서적 지지를 받을 수 있는 좋은 방법입니다.", "2": "그림 그리기는 개인적인 취미로 사회적 교류가 적습니다.", "4": "책 읽기는 개인적인 활동으로, 다른 사람과의 상호작용을 유도하지 않습니다.", "5": "텔레비전 시청은 소극적인 활동으로 대인관계 형성이 어렵습니다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간을 활용한 활동", "def_vi": "Hoạt động trong thời gian rảnh rỗi"}, {"term_ko": "사별", "term_vi": "Mất mát", "def_ko": "사랑하는 사람을 잃다", "def_vi": "Mất người thân"}, {"term_ko": "추천", "term_vi": "Gợi ý", "def_ko": "제안하다", "def_vi": "Đề xuất"}, {"term_ko": "친목", "term_vi": "Giao lưu", "def_ko": "사람들과의 교류", "def_vi": "Sự tương tác với mọi người"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1135, '8', '은퇴를 한 노부부가 친목회 회원들과 가끔 음악회나 전시회를 가곤한다. 해당하는 여가활동 유형은?', '["종교 참여 활동", "사교 오락 활동", "운동 활동", "소일 활동", "자기계발 활동"]'::jsonb, 2, '여가활동의 유형을 알고 구분할 수 있는 능력을 평가하려는 의도입니다.', NULL, '{"1": "종교 참여 활동: 종교적인 모임이나 의식에 참여하는 활동입니다.\n[정답]", "2": "사교 오락 활동: 사람들이 모여 즐겁게 대화하고 오락을 즐기는 활동입니다.", "3": "운동 활동: 신체 활동을 통해 건강을 유지하거나 증진하는 활동입니다.", "4": "소일 활동: 여가시간을 보내는 간단한 활동입니다.", "5": "자기계발 활동: 개인의 기술이나 지식을 향상시키기 위한 활동입니다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "사교", "def_ko": "여가시간에 하는 활동(활동 giải trí)", "def_vi": "사람들과의 친목과 교류(quan hệ xã hội)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1134, '8', '다음 대화에서 요양보호사가 제안한 여가활동 유형은?대상자: 옛날에는 사물놀이에서 장구도 배우고 재밌었는데, 지금은 나이가 들어 아무것도 안 하니까 재미가 없어. 요양보호사: 그러면 다시 한번 장구를 배워보시면 어떨가요?', '["소일 활동", "자기계발 활동", "운동 활동", "가족중심 활동", "사교오락 활동"]'::jsonb, 2, '대상자가 예전의 여가활동 경험을 회상하며, 요양보호사가 제안할 수 있는 활동 유형을 파악하기 위함입니다.', NULL, '{"1": "소일 활동: 일상적인 일을 하며 시간을 보내는 활동입니다. 이 문제에서는 해당되지 않습니다.\n[정답]", "2": "자기계발 활동: 장구를 배우는 것은 개인의 기술을 향상시키는 활동으로 자기계발 활동에 해당합니다.", "3": "운동 활동: 신체적인 활동을 포함하지만, 장구 배우기는 운동의 범주에 포함되지 않습니다.", "4": "가족중심 활동: 가족과 함께하는 활동은 아니므로 해당되지 않습니다.", "5": "사교오락 활동: 친구들과의 여가활동에 해당하지만, 이 경우 특정 기술을 배우는 것이므로 주제와 다릅니다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간에 하는 활동(한국어)", "def_vi": "Hoạt động trong thời gian rảnh(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1133, '8', '보행이 불편한 대상자의 자기계발을 위한 여가활동으로 적합한 것은?', '["텃밭 가꾸기", "손자녀 돌보기", "산책 하기", "외식나들이", "서예교실"]'::jsonb, 5, '대상자가 보행이 불편한 상황에서도 자기계발을 하기 위한 적절한 여가활동을 선택하도록 돕기 위함입니다.', NULL, '{"1": "텃밭 가꾸기는 신체적인 활동이 많이 필요하여 보행이 불편한 대상자에게는 적합하지 않습니다.\n[정답]", "5": "서예교실은 정적인 활동으로 보행이 불편한 대상자도 참여할 수 있어 자기계발에 적합합니다.", "2": "손자녀 돌보기는 신체적 부담이 클 수 있어 적합하지 않습니다.", "3": "산책하기는 보행이 불편한 대상자에게 힘든 활동입니다.", "4": "외식나들이는 보행이 불편한 상황에서 어려움이 있을 수 있습니다."}'::jsonb, '[{"term_ko": "보행", "term_vi": "Đi bộ", "def_ko": "걷기(한국어)", "def_vi": "Đi lại(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1132, '8', '서예. 책 읽기를 좋아하는 노인대상자의 여가활동 유형은?', '["운동 활동", "자기계발 활동", "사교오락 활동", "종교참여 활동", "가족중심 활동"]'::jsonb, 2, '여가활동 유형 중 노인 대상자가 선호할 수 있는 활동을 구분하고 이해하기 위함입니다.', NULL, '{"1": "운동 활동: 신체적 건강을 위한 활동이나 운동은 노인이 선호하지 않을 수 있습니다.\n[정답]", "2": "자기계발 활동: 책 읽기는 지식과 능력을 개발할 수 있는 활동으로, 노인이 선호할 수 있는 여가활동입니다.", "3": "사교오락 활동: 타인과의 관계를 중요시하지만, 개인적인 독서와는 거리가 있습니다.", "4": "종교참여 활동: 종교적 활동은 개인적일 수 있지만 일반적으로 책 읽기에 해당하지 않습니다.", "5": "가족중심 활동: 가족과의 시간도 중요하지만 책 읽기와는 관련이 적습니다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간에 하는 활동(한국어)", "def_vi": "Hoạt động trong thời gian rảnh(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1131, '8', '노인의 여가활동 중 사교오락 활동에 해당하는 것은?', '["TV 보기", "책 읽기", "음악회", "텃밭 가꾸기", "악기연주"]'::jsonb, 3, '노인의 여가활동에서 사교오락 활동을 구분할 수 있는 능력을 평가하고자 하는 문제입니다.', NULL, '{"1": "TV 보기는 혼자서 즐기는 활동으로 사교오락 활동이 아닙니다.", "2": "책 읽기는 개인적인 활동으로 사교오락 활동이 아닙니다.\n[정답]", "3": "음악회는 타인과의 교류가 있는 사교오락 활동입니다.", "4": "텃밭 가꾸기는 개인적인 취미 활동으로 사교오락 활동이 아닙니다.", "5": "악기연주는 개인적으로 할 수도 있지만, 타인과 함께 할 경우 사교오락이 될 수 있습니다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가에 사용하는 활동(한국어)", "def_vi": "Các hoạt động sử dụng thời gian rảnh"}, {"term_ko": "사교오락", "term_vi": "Giải trí xã hội", "def_ko": "사람들과의 교류가 있는 오락 활동(한국어)", "def_vi": "Hoạt động giải trí có sự giao lưu với người khác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1130, '8', '다음과 같은 방법으로 의사소통을 해야 하는 치매 대상자의 상황은?• 휴지를 주워와서 모을 때는 본인이 하고 싶어 하는 대로 두기 • 주워 온 물건에 대해 다시 이야기하지 않기 • 대상자가 할 수 있는 일로 주의 전환하기', '["수집증", "무감동", "불안", "섭식장애", "초조행동"]'::jsonb, 1, '치매 대상자의 경우 의사소통 방법에 대한 이해를 돕기 위한 문제입니다.', NULL, '{"1": "수집증은 물건을 모으는 행동으로, 해당 상황에 부합합니다.\n[정답]", "2": "무감동은 감정 표현이 없는 상태지만, 주어진 상황과는 관련이 없습니다.", "3": "불안은 불안감을 느끼는 상태로, 제시된 방법과 연관성이 떨어집니다.", "4": "섭식장애는 식습관의 문제가 초점이므로 상황에 적합하지 않습니다.", "5": "초조행동은 불안정한 감정을 나타내지만, 특정한 수집과 관련성은 부족합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억과 사고에 영향을 미치는 신경퇴행성 질환", "def_vi": "Bệnh thoái hoá thần kinh ảnh hưởng đến trí nhớ và tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1129, '8', '치매 대상자가 우울한 상황에서 의사소통 방법으로 옳은 것은?', '["활동에 참여하도록 강요한다.", "잘못은 직접적으로지적한다.", "우울한 생각을 계속하면 모른 척 외면한다.", "좋아하고 즐거워하는 활동을 하게 한다.", "어ㅕ운 일을 맡겨 성취감을 맛보게 한다."]'::jsonb, 4, '환자가 우울한 상황에서 의사소통 방법을 이해하고, 적절한 대처 방안을 고려하도록 유도하는 문제입니다.', NULL, '{"1": "활동에 참여하도록 강요한다. - 강요는 환자의 기분을 더 우울하게 만들 수 있습니다.\n[정답]", "4": "좋아하고 즐거워하는 활동을 하게 한다. - 환자의 기분을 좋게 하는 긍정적인 접근입니다.", "2": "잘못은 직접적으로 지적한다. - 부정적인 피드백은 우울감을 증대시킬 수 있습니다.", "3": "우울한 생각을 계속하면 모른 척 외면한다. - 외면은 환자의 감정을 무시하는 행동입니다.", "5": "어려운 일을 맡겨 성취감을 맛보게 한다. - 지나치게 어려운 일은 부담을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억 및 인지 기능의 지속적인 저하", "def_vi": "Sự suy giảm liên tục của trí nhớ và chức năng nhận thức"}, {"term_ko": "우울", "term_vi": "Trầm cảm", "def_ko": "슬픔과 절망의 감정", "def_vi": "Cảm xúc buồn và tuyệt vọng"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보나 감정을 주고받는 과정", "def_vi": "Quá trình trao đổi thông tin hoặc cảm xúc"}, {"term_ko": "활동", "term_vi": "Hoạt động", "def_ko": "어떤 행동이나 일", "def_vi": "Một hành động hoặc công việc"}, {"term_ko": "성취감", "term_vi": "Cảm giác thành công", "def_ko": "달성의 기쁨", "def_vi": "Niềm vui khi đạt được"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1128, '8', '인지능력 저하, 우울증, 무관심 등이 원인이 되어 나타나는 치매대상자의 상황으로 다음과 같은 방법으로 의사소통해야 하는 경우는?• 대답하지 않더라도 이름을 부르거나 화를 내지 않기 • 좋아하는 활동 확인하기 • 사소한 말과 행동에도 관심 기울이기', '["무감동", "불안", "배회", "공격성", "초조행동"]'::jsonb, 1, '인지능력 저하, 우울증, 무관심 등의 증상이 있는 치매대상자의 의사소통 방법을 파악하기 위한 문제입니다.', NULL, '{"1": "무감동: 감정 표현이 결여되어 있는 상태를 의미하며, 해당 상황에서 의사소통 방법이 적합합니다.\n[정답]", "2": "불안: 불안은 다른 문제와 연관되어 있으며, 이 경우 적절한 의사소통 방법과는 거리가 있습니다.", "3": "배회: 치매 환자에게서 흔히 나타나는 행동이나, 의사소통에 대한 질문과는 관련이 적습니다.", "4": "공격성: 공격성은 의사소통의 방식이 아닌 행동상의 문제로, 의사소통 방법과 무관합니다.", "5": "초조행동: 초조행동 역시 의사소통과 관련이 적습니다."}'::jsonb, '[{"term_ko": "인지능력", "term_vi": "Năng lực nhận thức", "def_ko": "능력을 이해하고 판단하는 힘", "def_vi": "Khả năng hiểu và phán đoán"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1127, '8', '치매 대상자가 눈이 내리는 창밖을 보면서 다음과 같이 말한다. 이때 대상자의 지남력 증진에 도움이 되는 요양보호사의 반응으로 적절한 것은?대상자: 빨리 도토리 주우러 가자. 남들이 다 줍기 전에.. 요양보호사: ( )', '["\"밖에 나가고 싶으세요?\"", "\"미끄러워 위험하니 다음에 가요.\"", "\"배고프신가 봐요. 맛있는 거 드릴게요.\"", "\"아무도 주워가지 않으니 걱정마세요.\"", "\"지금은 한겨울이에요. 도토리는 강르에 줍잖아요.\""]'::jsonb, 5, '대상자의 지남력을 증진시키기 위한 요양보호사의 적절한 반응을 묻는 문제입니다.', NULL, '{"1": "''밖에 나가고 싶으세요?''는 대상자의 말을 단순히 반영할 뿐, 지남력 증진에는 도움이 되지 않습니다.\n[정답]", "5": "''지금은 한겨울이에요. 도토리는 강르에 줍잖아요.''는 계절적 정보를 제공하여 대상자의 지남력 증진에 기여합니다.", "2": "''미끄러워 위험하니 다음에 가요.''는 부정적인 반응으로 지남력 증진에 도움이 되지 않습니다.", "3": "''배고프신가 봐요. 맛있는 거 드릴게요.''는 대상자의 표현과 관련이 없어 지남력 증진에 기여하지 않습니다.", "4": "''아무도 주워가지 않으니 걱정마세요.''는 대상자를 안심시키지만, 지남력 증진에는 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억과 사고 기능의 감소로 인한 질병", "def_vi": "Bệnh giảm chức năng trí nhớ và tư duy"}, {"term_ko": "지남력", "term_vi": null, "def_ko": "시간, 장소, 사람에 대한 인식 능력", "def_vi": null}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인이나 환자를 돕고 케어하는 직업", "def_vi": "Nghề giúp đỡ và chăm sóc người cao niên hoặc bệnh nhân"}, {"term_ko": "도토리", "term_vi": "Quả sồi", "def_ko": "나무에서 떨어지는 열매", "def_vi": "Quả rơi từ cây"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1126, '8', '치매로 인한 장애 대상자와 의사소통하는 방법은?', '["주변사람들에게 치매로 인한 장애를 비밀로 한다.", "상식에 어긋나는 말을 할 경우 지적한다.", "시간, 장소, 사람 등을 인식시킨다.", "한 번에 많은 내용의 이야기를 한다.", "요양보호사의 속도에 맞추어 대화한다."]'::jsonb, 3, '치매에 걸린 대상자와의 효과적인 의사소통 방법을 이해하고 이에 대한 올바른 대처 방법을 선택하는 것이 문제의 목적입니다.', NULL, '{"1": "주변사람들에게 치매로 인한 장애를 비밀로 하여도 대상자의 의사소통에는 도움이 되지 않으므로 부적절하다.", "2": "상식에 어긋나는 말을 지적하는 것은 대상자의 자존감을 해칠 수 있으므로 좋은 방법이 아니다.\n[정답]", "3": "시간, 장소, 사람 등을 인식시킴으로써 대상자가 상황을 이해할 수 있도록 돕는 것은 효과적인 의사소통 방법이다.", "4": "한 번에 많은 내용을 이야기하는 것은 오히려 혼란을 줄 수 있으므로 지양해야 한다.", "5": "요양보호사의 속도에 맞추어 대화하는 것은 대상자의 이해 능력을 고려하지 않은 방법이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Chứng mất trí", "def_ko": "기억을 잃는 질병", "def_vi": "Bệnh mất trí nhớ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1125, '8', '치매로 인한 장애가 있는 대상자와 의사소통 방법으로 옳은 것은?', '["환경적 자극을 위해 변화를 자주 준다.", "대상자의 뒤에서 천천히 다가가 말을 건넨다.", "자신감을 느끼도록 매번 새로운 정보를 준다.", "대상자의 언어적 표현보다 심적 안정에 맞춘다.", "대상자의 사소한 말과 행동은 그냥 넘긴다."]'::jsonb, 4, '치매 환자와의 효과적인 의사소통 방법을 이해하고 적용하는 것이 중요하다.', NULL, '{"1": "환경적 자극을 변화에 주는 것은 치매 환자에게 혼란을 줄 수 있다.\n[정답]", "2": "대상자의 뒤에서 다가가는 것은 오히려 불안감을 줄 수 있어 좋은 방법이 아니다.", "3": "매번 새로운 정보를 주는 것은 오히려 환자의 혼란을 가중시킬 수 있다.", "4": "대상자의 언어적 표현보다 심적 안정에 맞추는 것이 중요하다.", "5": "사소한 말과 행동을 무시하는 것은 환자의 자존감을 해칠 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고능력이 저하되는 뇌의 질병", "def_vi": "Bệnh liên quan đến việc giảm khả năng nhớ và tư duy của não"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "사람들 간에 정보를 교환하는 과정", "def_vi": "Quá trình trao đổi thông tin giữa mọi người"}, {"term_ko": "심적 안정", "term_vi": "An toàn tâm lý", "def_ko": "정서적으로 안정된 상태", "def_vi": "Trạng thái tâm lý ổn định"}, {"term_ko": "자존감", "term_vi": "Lòng tự trọng", "def_ko": "자신의 가치나 중요성을 느끼는 것", "def_vi": "Cảm giác về giá trị hoặc tầm quan trọng của bản thân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1124, '8', '치매로 인한 장애 대상자와 의사소통 하는 방법으로 옳은 것은?', '["''할 수 없는 것''을 집중적으로 찾아 준다.", "대상자의 뒤에서 천천히 다가가 말을 건넨다.", "자신감을 느끼도록 매번 새로운 정보를 준다.", "대상자의 언어적 표현보다 심적 안정에 맞춘다.", "대상자의 사소한 말과 행동은 그냥 넘긴다."]'::jsonb, 2, '치매로 인한 장애대상자와 효과적으로 의사소통하는 방법을 이해하고 평가하는 것이 목적입니다.', NULL, '{"1": "''할 수 없는 것''을 집중적으로 찾아 주는 것은 부정적인 언어로 의사소통을 하게 되어 대상자의 자존감을 떨어뜨릴 수 있습니다.\n[정답]", "2": "대상자의 뒤에서 천천히 다가가 말을 건네는 방법은 상대방에게 안전하고 편안한 느낌을 주며 의사소통을 원활하게 합니다.", "3": "매번 새로운 정보를 주는 것은 혼란을 초래할 수 있으며, 대상자의 이해력을 고려하는 것이 중요합니다.", "4": "언어적 표현보다 심적 안정을 우선시하는 것은 의사소통의 중요한 요소지만, 대상자의 의사 표현도 존중해야 합니다.", "5": "대상자의 사소한 말과 행동을 그냥 넘기는 것은 대상자의 감정을 무시하는 행동이 될 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Chứng sa sút trí tuệ", "def_ko": "기억력과 사고능력의 저하", "def_vi": "Sự giảm sút trí nhớ và khả năng tư duy"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "사람들 간의 정보를 주고받는 행위", "def_vi": "Hành vi trao đổi thông tin giữa mọi người"}, {"term_ko": "자존감", "term_vi": "Lòng tự trọng", "def_ko": "자신에 대한 믿음", "def_vi": "Niềm tin về bản thân"}, {"term_ko": "혼란", "term_vi": "Sự hỗn loạn", "def_ko": "명확하지 않은 상태", "def_vi": "Tình trạng không rõ ràng"}, {"term_ko": "안정", "term_vi": "Ổn định", "def_ko": "위험이 없고 편안한 상태", "def_vi": "Tình trạng không có nguy cơ và thoải mái"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1123, '8', '뇌졸중으로 알아듣기는 하나 말이 어눌한 대상자와의 의사소통 방법으로 옳은 것은?', '["대상자 옆에 앉아서 대화한다.", "사람이 많은 곳에서 대화한다.", "대상자의 말에 짐작하여 대답한다.", "답변이 끝나기 전에 다음 질문을 한다.", "대상자가 의사표현을 잘했을 경우 긍정적 공감을 표현해준다."]'::jsonb, 5, '뇌졸중 환자와의 효과적인 의사소통 방법을 이해하고 있어야 함을 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "대상자 옆에 앉아서 대화하는 것은 좋은 의사소통 방법입니다. 그러나 반드시 올바른 방법은 아닙니다.\n[정답]", "5": "대상자가 의사표현을 잘했을 경우 긍정적 공감을 표현해 주는 것은 환자의 자존감을 높이고 의사소통을 원활하게 해줄 수 있는 방법입니다.", "3": "대상자의 말을 짐작하여 대답하는 것은 잘못된 의사소통 방법입니다.", "4": "답변이 끝나기 전에 다음 질문을 하는 것은 상대방의 말을 듣지 않는 태도로 비춰질 수 있습니다.", "2": "사람이 많은 곳에서 대화하는 것은 집중을 방해할 수 있으므로 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈액 공급이 중단되어 생기는 질환", "def_vi": "Bệnh xảy ra khi cung cấp máu cho não bị ngừng lại"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "서로 정보를 주고받는 과정", "def_vi": "Quá trình trao đổi thông tin giữa hai hoặc nhiều người"}, {"term_ko": "긍정적", "term_vi": "Tích cực", "def_ko": "좋거나 긍정적인 반응을 보이는 것", "def_vi": "Biểu hiện phản ứng tốt hoặc tích cực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1122, '8', '알아듣기는 해도 말로 표현이 어려운 대상자와 의사소통 하는 방법은?', '["음악을 틀어 편안하게 해준다.", "귀에 대고 천천히 또박또박 말한다.", "그림판, 문자판을 이용하여 표현하게 한다.", "날짜, 달력, 시계 등을 자주 인식시킨다.", "몸짓, 얼굴표정 등으로 이야기 전달을 돕는다."]'::jsonb, 3, '대상자와의 의사소통 전략을 이해하고 적용하기 위함입니다.', NULL, '{"1": "음악을 틀어 편안하게 해주는 것은 분위기를 좋게 할 수 있지만, 의사소통을 직접적으로 향상시키지는 않습니다.\n[정답]", "3": "그림판, 문자판을 이용하여 표현하게 하는 것은 비언어적 의사소통에 효과적이며, 상대방이 자신의 생각이나 감정을 전달하는 데 도움을 줍니다.", "2": "귀에 대고 천천히 또박또박 말하는 것은 듣는 데 도움이 될 수 있지만, 말로 표현하기 어려운 경우에는 효과적이지 않습니다.", "4": "날짜, 달력, 시계 등을 자주 인식시키는 것은 인지적 도움을 주지만, 의사소통에는 직접적인 도움이 되지 않습니다.", "5": "몸짓, 얼굴표정 등으로 이야기 전달을 돕는 것은 비언어적 의사소통에 도움을 줄 수 있지만, 직접적으로 표현하게 하는 방법은 아닙니다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통(한국어)", "def_vi": "sự thông tin qua lại(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1121, '8', '시각장애 대상자와 이야기하는 방법으로 옳은 것은?', '["대상자와 반걸음 떨어진 뒤에서 이야기한다.", "전달하기 어려운 형태나 사물은 만져보게 한다.", "지시대명사를 사용하여 사물의 위치를 설명한다.", "몸짓과 얼굴표정을 사용하여 대화한다.", "보행 시에는 대상자의 바로 뒤에 서서 돕는다."]'::jsonb, 2, '시각장애인의 의사소통 방법을 이해하고 올바른 대화 방식에 대한 인식 평가.', NULL, '{"1": "대화 시 적정한 거리에서 이야기하는 것이 중요하나 반걸음 떨어진 뒤에서 이야기하는 것은 적절하지 않다.\n[정답]", "2": "전달하기 어려운 형태나 사물은 만져보게 하는 것이 시각장애인에게 더 알기 쉽게 의사소통할 수 있다.", "3": "지시대명사를 사용하여 사물의 위치를 설명하는 것은 시각장애인에게 혼동을 줄 수 있다.", "4": "몸짓과 얼굴표정을 사용하여 대화하는 것은 시각장애인에게 적합하지 않으며, 언어적 소통이 필요하다.", "5": "보행 시에는 대상자의 주변을 항상 확인하며 돕는 것이 중요하지만, 바로 뒤에 서는 것은 바람직하지 않다."}'::jsonb, '[{"term_ko": "시각장애", "term_vi": "Khuyết tật thị giác", "def_ko": "시력을 잃거나 시력이 제한된 상태", "def_vi": "Tình trạng mất hoặc hạn chế khả năng nhìn"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보를 주고받는 행위", "def_vi": "Hành động trao đổi thông tin"}, {"term_ko": "지시대명사", "term_vi": "Đại từ chỉ định", "def_ko": "특정 대상을 지칭하는 대명사", "def_vi": "Đại từ chỉ định đối tượng cụ thể"}, {"term_ko": "전달", "term_vi": "Truyền đạt", "def_ko": "정보를 주는 것", "def_vi": "Việc cung cấp thông tin"}, {"term_ko": "형태", "term_vi": "Hình thức", "def_ko": "형태, 구조", "def_vi": "Hình dạng, cấu trúc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1120, '8', '처음으로 시설에 입소한 시각장애 대상자에게 설명하는 방법으로 옳은 것은?', '["사물의 위치를 시계방향으로 설명한다.", "요양보호사를 중심으로 오른쪽, 왼쪽을 설명한다.", "대상자와 눈이 마주쳤을 때 대화를 시도한다.", "여기, 이쪽 등으로 정확히 방향을 제시해 준다.", "말을 건네기 전에 먼저 신체 접촉을 한다."]'::jsonb, 1, '시각장애 대상자에게 정보를 효과적으로 전달하는 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "사물의 위치를 시계방향으로 설명한다. [정답] 이는 시각장애인이 공간을 이해하는 데 도움을 줄 수 있습니다.", "2": "요양보호사를 중심으로 오른쪽, 왼쪽을 설명한다. 이는 시각장애인에게 방향 감각을 혼동시킬 수 있습니다.", "3": "대상자와 눈이 마주쳤을 때 대화를 시도한다. 시각장애인에게는 눈맞춤이 의미가 없으므로 부적절합니다.", "4": "여기, 이쪽 등으로 정확히 방향을 제시해 준다. 이는 불명확한 지시로 대상자의 이해를 방해할 수 있습니다.", "5": "말을 건네기 전에 먼저 신체 접촉을 한다. 이는 개인의 공간을 침해하고 불안감을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "시각장애", "term_vi": "Khiếm thị", "def_ko": "시력에 장애가 있는 상태", "def_vi": "Tình trạng không có khả năng nhìn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1119, '8', '노인성 난청이 있는 대상자와 의사소통하는 방법으로 옳은 것은?', '["신체 접촉을 하지 않는다.", "조명이 어두운 실내에서 대화한다.", "대상자의 등 뒤에서 큰소리로 말한다.", "보청기의 전원 스위치가 작동하는지 확인한다.", "의사소통을 위한 정보제공 시간을 짧게 한다."]'::jsonb, 4, '노인성 난청이 있는 대상자와 원활한 의사소통 방법을 이해하고 평가하기 위함입니다.', NULL, '{"1": "신체 접촉을 하지 않는 것은 의사소통 시 비효율적입니다.\n[정답]", "4": "보청기의 전원 스위치가 작동하는지 확인하는 것은 필수 적인 조치입니다.", "2": "조명이 어두운 실내에서 대화하는 것은 부적절합니다.", "3": "대상자의 등 뒤에서 큰소리로 말하는 것은 어려움을 가중시킵니다.", "5": "의사소통을 위한 정보제공 시간을 짧게 하는 것은 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "노인성 난청", "term_vi": "Nghe kém ở người lớn tuổi", "def_ko": "노인을 위한 청각 장애", "def_vi": "Khuyết tật thính giác dành cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1118, '8', '노인성 난청 대상자와 대화하는 방법으로 옳은 것은?', '["굳은 표정으로 차분하게 말한다.", "보청기 입력은 낮게 출력은 높게 한다.", "정보제공 시간을 짧게 한다.", "말의 의미를 이해할 때까지 반복해서 설명한다.", "대상자의 옆에서 큰 소리로 이야기 한다."]'::jsonb, 4, '노인성 난청 대상자와 효과적으로 의사소통하는 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "굳은 표정은 대화의 원활함을 방해할 수 있습니다.\n[정답]", "4": "반복해서 설명하면 대상자가 말을 이해하는 데 도움이 됩니다.", "2": "보청기의 사용법에 대해 정확한 정보가 필요합니다. 일반적으로 입력과 출력의 조절은 전문가의 도움이 필요합니다.", "3": "정보 제공 시간은 충분해야 대상자가 내용을 소화할 수 있습니다.", "5": "대상자의 옆에서 큰 소리로 이야기하면 듣는 데 오히려 방해가 됩니다."}'::jsonb, '[{"term_ko": "노인성 난청", "term_vi": "Mất thính lực tuổi già", "def_ko": "나이가 들어감에 따라 발생하는 청각 장애", "def_vi": "Khiếm thính do tuổi tác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1117, '8', '노인성 난청을 앓고 있는 대상자와 올바른 의사소통 방법은?', '["뒤에서 크게 말한다.", "빠른 속도로 말한다.", "고음으로 정확하게 말한다.", "얼굴표정과 몸짓을 사용하여 말한다.", "입을 작게 벌리며 말한다."]'::jsonb, 4, '노인성 난청을 앓고 있는 대상자와의 의사소통에서 효과적인 방법을 찾기 위해 문제를 출제하였다.', NULL, '{"1": "뒤에서 크게 말하는 것은 상대방에게 접촉이 없고 불필요한 소음을 유발할 수 있어 바람직하지 않다.", "2": "빠른 속도로 말하는 것은 이해를 돕기보다는 오히려 혼란을 줄 수 있다.", "3": "고음으로 말하는 것은 난청의 원인인 고주파 소리를 더욱 어렵게 만들 수 있다.\n[정답]", "4": "얼굴표정과 몸짓을 사용하여 말함으로써 비언어적 커뮤니케이션을 통해 의사소통의 효과를 높일 수 있다.", "5": "입을 작게 벌리며 말하는 것은 발음을 듣기 어렵게 만들 수 있다."}'::jsonb, '[{"term_ko": "노인성", "term_vi": "난청", "def_ko": "노인에 관련된, tuổi già", "def_vi": "청력을 잃거나 감소하는 것, mất thính lực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1116, '8', '노인성 난청이 있는 대상자와 의사소통으로 옳은 것은?', '["아주 큰 목소리로 말한다.", "말을 되풀이 하지 않는다.", "보청기의 입력은 낮게, 출력은 크게 조절한다.", "말할 때 어깨를 두드리지 않는다.", "눈짓으로 신호를 주면서 말한다."]'::jsonb, 5, '노인성 난청이 있는 대상자와의 효과적인 의사소통 방법을 이해하고 평가하는 것.', NULL, '{"1": "아주 큰 목소리로 말하는 것은 난청 있는 대상자가 불편해할 수 있다.\n[정답]", "5": "눈짓으로 신호를 주면서 말하는 것은 시각적, 청각적 자극을 동시에 제공해 의사소통을 원활하게 해준다.", "2": "말을 반복하지 않는 것은 대상자가 혼란스러워할 수 있다.", "3": "보청기의 입력과 출력을 조절할 때, 입력은 높이고 출력을 낮추는 것이 일반적이다.", "4": "말할 때 어깨를 두드리지 않는 것이 좋다, 그러나 상황에 따라 다를 수 있다."}'::jsonb, '[{"term_ko": "노인성 난청", "term_vi": "Điếc tuổi già", "def_ko": "노인에 의해 발생하는 청력 손실", "def_vi": "Mất thính lực do tuổi tác"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "두 사람 이상이 서로의 생각이나 감정을 전달하는 과정", "def_vi": "Quá trình truyền đạt suy nghĩ hoặc cảm xúc giữa hai hoặc nhiều người"}, {"term_ko": "보청기", "term_vi": "Máy trợ thính", "def_ko": "청력을 보완하기 위해 사용하는 장치", "def_vi": "Thiết bị dùng để hỗ trợ thính lực"}, {"term_ko": "눈짓", "term_vi": "Ánh mắt", "def_ko": "눈으로 하는 신호", "def_vi": "Tín hiệu bằng mắt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1115, '8', '대상자 가족과의 의사소통 방법으로 옳은 것은?', '["대상자에 대한 느낌을 솔직하게 전달한다.", "대상자의 이상 상태를 가족에게 알리지 않는다.", "대상자의 부정적인 행동을 직설적으로 말한다.", "의료진으로부터 받은 정보를 가족에게 전달하지 않는다.", "대상자에 대한 정보는 수시로 주고받는다."]'::jsonb, 5, '대상자 가족과의 효과적인 의사소통 방법을 이해하고 판단하는지 평가하기 위함입니다.', NULL, '{"1": "대상자에 대한 느낌을 솔직하게 전달하는 것은 중요하지만, 모든 경우에 적절한 방법은 아닙니다.\n[정답]", "5": "대상자에 대한 정보는 수시로 주고받아야 가족이 상황을 잘 이해하고 지원할 수 있습니다.", "2": "대상자의 이상 상태를 알리지 않는 것은 가족의 알 권리를 침해할 수 있습니다.", "3": "대상자의 부정적인 행동을 직설적으로 말하는 것은 가족에게 불필요한 불안을 줄 수 있습니다.", "4": "의료진으로부터 받은 정보를 가족에게 전달하지 않는 것은 비밀보장 원칙과는 관련이 있지만, 가족의 참여와 이해를 높이는 데 방해가 됩니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "환자, 대상자", "def_vi": "Bệnh nhân"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통, 의사전달", "def_vi": "Truyền đạt thông điệp"}, {"term_ko": "정보", "term_vi": "Thông tin", "def_ko": "알림, 데이터", "def_vi": "Dữ liệu, thông tin"}, {"term_ko": "부정적인", "term_vi": "Tiêu cực", "def_ko": "나쁜, 부정적", "def_vi": "Xấu, tiêu cực"}, {"term_ko": "이상 상태", "term_vi": "Tình trạng bất thường", "def_ko": "문제 있는 상태", "def_vi": "Tình trạng có vấn đề"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1114, '8', '다음 말벗하기에서 밑줄 친 부분에 해당하는 내용은?대상자: 비가 와서 그런지 팔 다리가 쑤시고 아파... 요양보호사: 몸이 많이 무거우시죠? 제가 따뜻한 물로 마사지해 드릴게요.', '["적극적 청취", "증상완화 보조", "정보의 제공", "감정의 제공", "존중과 관심"]'::jsonb, 2, '요양보호사가 대상자의 감정이나 신체적 불편함을 이해하고 그에 대한 적절한 반응을 제시하는 상황을 평가하고자 하는 의도이다.', NULL, '{"1": "적극적 청취: 대상자의 말을 잘 듣고 반응하는 것을 의미하지만, 이 경우 요양보호사 행동은 마사지 제공으로 이어지므로 해당되지 않음.\n[정답]", "2": "증상완화 보조: 요양보호사가 대상자의 팔 다리 통증을 완화하기 위해 마사지하려는 행동은 증상완화 보조에 해당하므로 정답임.", "3": "정보의 제공: 대상자에게 특별한 정보나 지식을 제공하는 것이 아니라 단순히 마사지하겠다는 내용이므로 해당되지 않음.", "4": "감정의 제공: 감정에 대한 언급이 없고, 구체적으로 대처하는 내용이 없으므로 해당되지 않음.", "5": "존중과 관심: 대상자의 말을 듣고 반응하는 것은 맞지만, 마사지 행위로 직접적 행위를 언급하는 것이므로 해당되지 않음."}'::jsonb, '[{"term_ko": "말벗하기", "term_vi": null, "def_ko": "대화하기", "def_vi": null}, {"term_ko": "요양보호사", "term_vi": null, "def_ko": "노인을 돌보는 전문가", "def_vi": null}, {"term_ko": "마사지", "term_vi": "Xoa bóp", "def_ko": "근육 이완을 위한 손으로 하는 치료", "def_vi": "Phương pháp điều trị thư giãn cơ"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병이나 부상의 신호", "def_vi": "Dấu hiệu bệnh tật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1113, '8', '대상자와 대화 중 밑줄 친 부분에 해당하는 것은?대상자: 영감이 돌아가시기 전까지 매일 잠자리를 살펴주었는데... 요양보호사: 할아버지를 한번 뵙고 싶어요. 사진을 좀 보여주세요.', '["정보의 제공", "존중과 관심", "적극적 청취", "증상완화 보조", "감정 공감"]'::jsonb, 3, '대상자와의 대화에서 요양보호사가 어떻게 반응하는지를 평가하려는 의도입니다.', NULL, '{"1": "정보의 제공: 요양보호사가 정보를 제공한 것이 아니라면 해당되지 않습니다.\n[정답]", "2": "존중과 관심: 요양보호사가 할아버지에 대한 관심을 표현한 것과는 차이가 있습니다.", "3": "적극적 청취: 요양보호사가 대화에 적극적으로 귀 기울이는 모습이 보입니다.", "4": "증상완화 보조: 증상 완화와는 관련이 없습니다.", "5": "감정 공감: 감정을 공감하는 부분이 있지만 이는 대화의 전반적인 맥락으로 보아야 합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối diện", "def_ko": "환자나 고객", "def_vi": "Bệnh nhân hoặc khách hàng"}, {"term_ko": "영감", "term_vi": "Ông", "def_ko": "할아버지", "def_vi": "Ông ông"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "요양을 돕는 사람", "def_vi": "Người giúp đỡ trong việc chăm sóc"}, {"term_ko": "적극적", "term_vi": "Tích cực", "def_ko": "능동적인", "def_vi": "Chủ động"}, {"term_ko": "청취", "term_vi": "Nghe", "def_ko": "듣기", "def_vi": "Nghe"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1112, '8', '당ㅁ 말벗하기에서 밑줄 친 부분에 해당하는 대화 내용은?대상자: 영감이 돌아가신 후엔 도둑이 들까 겁도 나고...늘 문단속을 해주었거든... 요양보호사: 할아버지가 자상한 분이셨네요.', '["감정 공감", "적극적 청취", "정보의 제공", "증상완화 보조", "존중과 관심"]'::jsonb, 1, '대화에서 요양보호사가 대상자의 감정을 이해하고 공감하는지를 평가하는 것입니다.', NULL, '{"1": "감정 공감: 대상자의 감정에 공감하며 대화하는 방식입니다.\n[정답]", "2": "적극적 청취: 대상자가 말하는 내용을 주의 깊게 듣고 반응하는 것입니다.", "3": "정보의 제공: 필요한 정보를 제공하는 것입니다.", "4": "증상완화 보조: 환자의 증상을 완화하는 보조적인 역할입니다.", "5": "존중과 관심: 대상자를 존중하고 그에 대한 관심을 표현하는 것입니다."}'::jsonb, '[{"term_ko": "감정", "term_vi": "Cảm xúc", "def_ko": "감정(한국어)", "def_vi": "Cảm xúc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1111, '8', '다음 대상자와 대화 중 요양보호사의 반응에 해당되는 것은?대상자: 손자 생일 선물을 사 주기로 약속했어요. 나를 마트에 데려가 주세요. 요양보호사: 손자가 아주 좋아하겠어요.', '["적극적 청취", "감정 공감", "수용", "결정", "존중과 관심"]'::jsonb, 2, '요양보호사가 대상자의 감정에 공감하는 반응을 이해하고 선택하게 하려는 의도입니다.', NULL, '{"1": "적극적 청취: 상대방의 말을 경청하며 이해하는 것이나, 감정에 대한 공감이 아님.\n[정답]", "2": "감정 공감: 대상자의 감정에 공감하여 반응한 사례.", "3": "수용: 상대방의 생각이나 감정을 있는 그대로 받아들이는 것으로, 예시와는 다름.", "4": "결정: 특정 행동을 선택하는 것, 이번 상황과는 관련이 없음.", "5": "존중과 관심: 대상자에 대한 존중이 필요한 상황이지만, 감정 공감과는 다름."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자 또는 고객", "def_vi": "Bệnh nhân hoặc khách hàng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1110, '8', '김 할아버지는 열이 나는 데도 손자 생일 선물을 사준다고 외출을 고집하신다. 대상자에게 존중과 관심을 표현하는 대답으로 옳은 것은?', '["해열제를 먼저 드세요.", "열이 있으니 외출하시면 안돼요.", "퇴근 후에 아들에게 사오라고 하세요.", "선물보다 용돈으로 주세요.", "열이 좀 있으시네요. 제가 대신 다녀올까요?"]'::jsonb, 5, '대상자의 상태를 고려하면서도 존중과 관심을 표현하는 대답을 찾는 것이다.', NULL, '{"1": "해열제를 먼저 드세요. - 대상자의 상태를 충분히 존중하지 않은 답변이다.", "2": "열이 있으니 외출하시면 안돼요. - 걱정하는 마음은 있지만 비판적인 태도가 포함되어 있다.", "3": "퇴근 후에 아들에게 사오라고 하세요. - 대상자의 욕구를 무시하는 답변이다.", "4": "선물보다 용돈으로 주세요. - 대상자의 선택을 제한하는 대답이다.\n[정답]", "5": "열이 좀 있으시네요. 제가 대신 다녀올까요? - 대상자의 상태를 인식하고, 존중하며 제안하는 올바른 대답이다."}'::jsonb, '[{"term_ko": "열", "term_vi": "Sốt", "def_ko": "열(열)", "def_vi": "Nhiệt độ cao"}, {"term_ko": "손자", "term_vi": "Cháu trai", "def_ko": "손자(아들)", "def_vi": "Con trai của con"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1109, '8', '효과적인 의사소통을 위한 요양보호사의 공감적 반응으로 옳은 것은?대상자: 애들이 왔다 간 지 너무 오래됐어. 다른 사람들은 손주들까지 데리고 자주 오던데... 요양보호사: ( )', '["\"자녀분들이 무심하네요. 제가 전화해 볼게요.\"", "\"연세가 많으시니 이것저것 서운한 게 당연해요.\"", "\"그동안 아무 말씀 없으시더니 왜 그러세요.\"", "\"자녀분들이 많이 보고 싶으신가봐요.\"", "\"가족이 외국에 살아서 아예 안 오시는 분도 있어요.\""]'::jsonb, 4, '요양보호사가 대상자의 감정과 상황에 공감하며 적절한 반응을 선택하는 것을 평가하기 위함입니다.', NULL, '{"1": "자녀를 비난하는 듯한 표현으로 공감적 반응이 아닙니다.\n[정답]", "4": "대상자의 감정에 공감하고, 그들을 생각해주는 따뜻한 반응입니다.", "2": "나이와 서운함을 연결지어 대상자의 기분을 경시하는 것으로 비공감적입니다.", "3": "질문 형식으로 대상자의 기분을 모르는 듯한 반응입니다.", "5": "다른 상황을 제시하여 상황을 축소하는 느낌을 주므로 공감적이지 않습니다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통(한국어)", "def_vi": "sự trao đổi thông tin(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1108, '8', '치매 대상자가 몸에 난 점을 보고 벌레가 나를 문다. 며 소란을 피운다. 요양보호사의 반응으로 옳은 것은?', '["\"어디 벌레가 있어요?\"", "\"잘 보세요. 점이잖아요!\"", "\"벌레는 저도 있어요. 소란피우지 마세요.\"", "\"점이 벌레처럼 보여서 무서우셨군요.\"", "\"어르신, 스스로 잡아보세요.\""]'::jsonb, 4, '치매 대상자의 비정상적인 행동에 대해 요양보호사가 어떻게 적절히 반응해야 하는지를 평가하기 위함입니다.', NULL, '{"1": "대상자의 불안감을 더욱 부각시키는 부적절한 반응입니다.\n[정답]", "4": "대상자의 감정을 이해하고 안심시킬 수 있는 적절한 반응입니다.", "2": "치매 대상자의 인지를 무시하는 반응으로 올바르지 않습니다.", "3": "치매 대상자가 걱정하는 것을 무시하는 반응입니다.", "5": "대상자의 상태를 더욱 악화시킬 수 있는 반응입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억과 사고에 영향을 미치는 질환", "def_vi": "Bệnh làm ảnh hưởng đến trí nhớ và tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1107, '8', '대상자에게 좋은 ''말벗''이 되기 위한 요양보호사의 태도로 옳은 것은?', '["대상자와 의존관계를 형성한다.", "친해지면 가끔 반말을 한다.", "대상자의 기분이나 감정에 주의를 기울인다.", "대상자의 삶을 옳고 그름으로 판단한다.", "대상자에 대한 좋고 싫은 감정을 솔직하게 표현한다."]'::jsonb, 3, '''말벗''이라는 개념에 대한 이해와 요양보호사가 가져야 할 태도를 묻는 문제이다.', NULL, '{"1": "대상자와 의존관계를 형성하는 것은 좋지 않은 태도이다.", "2": "친해지더라도 반말을 하는 것은 적절하지 않다.\n[정답]", "3": "대상자의 기분이나 감정에 주의를 기울이는 것은 중요한 태도이다.", "4": "대상자의 삶을 판단하는 것은 비윤리적인 태도이다.", "5": "대상자의 감정을 솔직하게 표현하는 것은 바람직하지 않다."}'::jsonb, '[{"term_ko": "말벗", "term_vi": "Người bạn đồng hành", "def_ko": "대화를 나누고 서로에게 정서적인 지지를 주는 친구", "def_vi": "Người bạn lắng nghe và hỗ trợ tinh thần cho nhau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1106, '8', '대상자와 효과적인 말벗하기를 위한 방법으로 옳은 것은?', '["대상자와 의존관계를 형성한다.", "사적인 대화를 많이 한다.", "대상자의 삶을 ''옳고 그름''으로 판단한다.", "대상자의 삶을 주관적으로 판단한다.", "대상자의 심리적 상태를 충분히 이해한다."]'::jsonb, 5, '대상자와의 효과적인 의사소통 방법을 이해시키기 위한 문제입니다.', NULL, '{"1": "대상자와 의존관계를 형성하는 것은 부적절한 접근 방법입니다.\n[정답]", "5": "대상자의 심리적 상태를 충분히 이해하는 것이 효과적인 말벗하기를 위한 기본입니다.", "2": "사적인 대화를 많이 하는 것은 개인적 경계를 침범할 수 있습니다.", "3": "대상자의 삶을 ''옳고 그름''으로 판단하는 것은 비판적 사고를 조장할 수 있습니다.", "4": "대상자의 삶을 주관적으로 판단하는 것도 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "Người nhận chăm sóc hoặc bệnh nhân"}, {"term_ko": "의존관계", "term_vi": "Mối quan hệ phụ thuộc", "def_ko": "누군가에게 의존하는 상태", "def_vi": "Tình trạng phụ thuộc vào ai đó"}, {"term_ko": "사적인 대화", "term_vi": "Cuộc trò chuyện riêng tư", "def_ko": "개인적인 대화", "def_vi": "Cuộc trò chuyện cá nhân"}, {"term_ko": "주관적 판단", "term_vi": "Đánh giá chủ quan", "def_ko": "개인적인 의견에 의거한 판단", "def_vi": "Đánh giá dựa trên ý kiến cá nhân"}, {"term_ko": "심리적 상태", "term_vi": "Tình trạng tâm lý", "def_ko": "감정이나 정신의 상태", "def_vi": "Trạng thái cảm xúc hoặc tâm thần"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1105, '8', '의사소통 시 침묵의 긍정적인 효과는?', '["서로의 마음이 통하여 호감과 상호신뢰가 생긴다.", "상대방의 입장에서 이해하고자 노력한다.", "자신의 느낌과 생각을 효과적으로 표현한다.", "요양보호사와 대상자 모두에게 생각을 정리할 시간을 준다.", "상대방의 표현을 있는 그대로 받아들인다."]'::jsonb, 5, '의사소통에서 침묵의 긍정적인 효과를 이해하고, 그로 인해 나타나는 효과를 선택하게 한다.', NULL, '{"1": "서로의 마음이 통하여 호감과 상호신뢰가 생길 수 있지만, 침묵과는 직접적인 관련이 없다.", "2": "상대방의 입장에서 이해하고자 노력하는 것은 중요하나, 침묵의 효과라고 보기는 어렵다.", "3": "자신의 느낌과 생각을 효과적으로 표현하는 것은 말이 필요하다.\n[정답]", "4": "요양보호사와 대상자 모두에게 생각을 정리할 시간을 주며, 이는 의사소통의 효과적인 부분이다.", "5": "상대방의 표현을 있는 그대로 받아들이는 것은 침묵의 효과와 관련이 없다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통(한국어)", "def_vi": "Sự trao đổi thông tin giữa các bên."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1104, '8', '대상자가 옷 입기를 거부할 때 나-전달법으로 옳은 것은?', '["\"저한테 불만이 많으신가 봐요.\"", "\"왜 옷을 안 입으세요?\"", "\"어르신이 옷을 갈아입지 않으려고 하니 제가 힘드네요.\"", "\"옷을 입지 않으시면 외출하지 않을거예요.\"", "\"마음에 안 드는 것이 있으면 말씀하세요.\""]'::jsonb, 3, '대상자의 의사 표현을 존중하며 옷 입기를 거부하는 이유를 이해하려는 의도를 나타냅니다.', NULL, '{"1": "''저한테 불만이 많으신가 봐요.'' - 대상자의 감정을 판단하는 발언으로 거부감을 줄 수 있습니다.", "2": "''왜 옷을 안 입으세요?'' - 직접적인 질문이지만, 상대의 기분을 고려하지 않은 방식입니다.\n[정답]", "3": "''어르신이 옷을 갈아입지 않으려고 하니 제가 힘드네요.'' - 나-전달법을 적절히 사용하여 상대의 행동이 자신의 감정에 어떤 영향을 미치는지를 표현하고 있습니다.", "4": "''옷을 입지 않으시면 외출하지 않을거예요.'' - 위협적인 언급으로서 부정적인 반응을 유발할 수 있습니다.", "5": "''마음에 안 드는 것이 있으면 말씀하세요.'' - 상대방의 감정을 존중하는 예의는 있지만, 구체적인 행동의 변화를 유도하지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 고객", "def_vi": "Bệnh nhân, khách hàng"}, {"term_ko": "거부", "term_vi": "Từ chối", "def_ko": "거절하다, 수용하지 않음", "def_vi": "từ chối, không chấp nhận"}, {"term_ko": "옷", "term_vi": "Áo", "def_ko": "의복", "def_vi": "quần áo"}, {"term_ko": "나-전달법", "term_vi": "Phương pháp truyền đạt cảm xúc của bản thân", "def_ko": "자신의 감정을 전달하는 법", "def_vi": "Phương pháp truyền đạt cảm xúc của bản thân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1103, '8', '대상자가 식사를 거부할 때 나-전달법으로 옳은 것은?', '["\"제게 불만이 많으신가요?\"", "\"어르신이 식사를 안 하려고 하니 걱정이 되네요.\"", "\"반찬이 마음에 안 드세요?\"", "\"배가 고파지면 말씀하세요.\"", "\"식사를 안 하면 오후에 간식이 없어요.\""]'::jsonb, 2, '대상자가 식사를 거부하는 상황에서 효과적인 의사소통 방법을 평가하기 위함입니다.', NULL, '{"1": "대상자의 감정을 직접적으로 물어보는 것은 효과적인 접근 방식이 아닙니다.\n[정답]", "2": "대상자의 식사 거부에 대한 걱정을 표현함으로써, 공감을 나타내고 소통의 기회를 마련합니다.", "3": "반찬에 대한 직접적인 질문은 대상자의 심리적 상태를 고려하지 않은 접근입니다.", "4": "행동을 강요하는 메시지는 대상자의 거부감을 더욱 악화시킬 수 있습니다.", "5": "조건부 행동을 제시하는 것은 부정적인 효과를 미칠 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "도움을 받는 사람", "def_vi": "Người nhận sự giúp đỡ"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn uống"}, {"term_ko": "거부", "term_vi": "Từ chối", "def_ko": "받아들이지 않음", "def_vi": "Không chấp nhận"}, {"term_ko": "전달법", "term_vi": "Phương pháp giao tiếp", "def_ko": "소통 방법", "def_vi": "Cách thức giao tiếp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1102, '8', '대상자와 요양보화의 대화 중 ''나-전달법''으로 옳은 것은?', '["식사를 안 하시면 어르신만 손해예요.", "입맛이 없어도 억지로라도 드셔야죠.", "점심때까지 배고파도 참으셔야겠네요.", "식사를 안 하시면 제가 더 힘들어요.", "소고기무국 좋아하시는데 식사를 안 하시니 걱정이 돼요."]'::jsonb, 5, '''나-전달법''을 이해하고 실생활에서 사용할 수 있는지 평가하기 위한 문제입니다.', NULL, '{"1": "''어르신만 손해예요.''는 나의 주장을 강조하는 표현입니다.\n[정답]", "5": "''소고기무국 좋아하시는데 식사를 안 하시니 걱정이 돼요.''는 나의 감정과 걱정을 전하는 표현입니다.", "2": "''억지로라도 드셔야죠.''는 상대방의 선택을 제한하는 언급입니다.", "3": "''참으셔야겠네요.''는 상대방의 행동을 강요하는 측면이 있습니다.", "4": "''제가 더 힘들어요.''는 나의 기분을 강조하지만 상대방의 입장을 고려하지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "대상자(한국어)", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "요양보호", "term_vi": "Chăm sóc", "def_ko": "돌봄(한국어)", "def_vi": "Chăm sóc"}, {"term_ko": "전달법", "term_vi": "Phương pháp truyền đạt", "def_ko": "전달 방법(한국어)", "def_vi": "Phương thức giao tiếp"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "식사(한국어)", "def_vi": "Bữa ăn"}, {"term_ko": "걱정", "term_vi": "Lo lắng", "def_ko": "걱정(한국어)", "def_vi": "Sự lo lắng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1101, '8', '동료 요양보호사가 반복적으로 사적인 부탁을 할 때 ''나-전달법'' 의사소통 방법은?', '["\"그건 규칙에 어긋나는 일이어서 안돼요.\"", "\"미안하지만 다른 분에게 부탁하는 게 좋겠어요.\"", "\"이번에만 해 드릴테니 다음부터는 부탁하지 마세요.\"", "\"한두 번도 아니고 다른 사람을 너무 힘들게 하시네요.\"", "\"자꾸 이러면 내 생활에 지장이 있고 함께 일하기 불편해요.\""]'::jsonb, 5, '''나-전달법'' 의사소통 방법을 이해하고 적용하는 능력을 평가하기 위함입니다.', NULL, '{"1": "상대방의 행동을 단순히 지적하는 방법으로, ''나-전달법''에 적합하지 않습니다.", "2": "상황을 피하는 방식으로, 보다 효과적인 의사소통 방법이 아닙니다.\n[정답]", "3": "자신의 감정이나 상황을 명확히 전달하는 방법입니다.", "4": "비난하는 방식으로, 건설적인 의사소통이 아닙니다.", "5": "자신의 영향과 감정을 명확히 전달하는 ''나-전달법''에 적합한 방법입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 돌보는 전문가", "def_vi": "chuyên gia chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1100, '8', '다음 상황에서 나- 전달법 의사소통으로 옳은 것은?대상자와 관련된 중요한 전화를 기다리고 있는데 동료 요양보호사가 사적인 전화 통화를 계속하고 있다.', '["언제까지 기다려야 하나요.", "사적인 통화는 휴대폰으로 하세요.", "전화 예의가 없으시네요.", "중요한 전화를 받지 못할까 봐 조바심도 나고 걱정이 돼요.", "통화를 할 때는 용건만 간단히 하세요."]'::jsonb, 4, '상대방에게 전달하고자 하는 감정이나 상황을 적절하게 표현하는 커뮤니케이션 능력을 평가하고자 하는 문제입니다.', NULL, '{"1": "언제까지 기다려야 하나요. - 이는 상대방에게 불만을 표출하는 방식으로, 부정적인 인상을 줄 수 있습니다.", "2": "사적인 통화는 휴대폰으로 하세요. - 강압적인 표현으로 해석 될 수 있습니다.\n[정답]", "3": "전화 예의가 없으시네요. - 이는 부정적인 피드백이므로 적절하지 않은 표현입니다.", "4": "중요한 전화를 받지 못할까 봐 조바심도 나고 걱정이 돼요. - 이는 자신의 감정을 솔직하게 표현함으로써 상대방의 이해를 도울 수 있는 올바른 커뮤니케이션입니다.", "5": "통화를 할 때는 용건만 간단히 하세요. - 이를 요청하는 것은 다소 무례하게 들릴 수 있습니다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통하는 방법", "def_vi": "Phương pháp giao tiếp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1099, '8', '대상자와 효과적으로 말하는 방법으로 옳은 것은?', '["자신의 감정을 숨긴다.", "의사전달을 분명하게 한다.", "부족하고 자신감 없는 태도를 보인다.", "모든 일에 전문가임을 주장한다.", "지나간 나쁜 내용을 상기시킨다."]'::jsonb, 2, '대상자와의 효과적인 의사소통 방법을 이해하고 평가하는 것에 대한 질문입니다.', NULL, '{"1": "자신의 감정을 숨기는 것은 신뢰를 구축하는 데 도움이 되지 않습니다.\n[정답]", "2": "의사전달을 분명하게 하는 것은 대상자와의 효과적인 소통에 필수적입니다.", "3": "부족하고 자신감 없는 태도는 상대방에게 부정적인 인식을 줄 수 있습니다.", "4": "모든 일에 전문가임을 주장하는 것은 오히려 상대방을 불편하게 할 수 있습니다.", "5": "지나간 나쁜 내용을 상기시키는 것은 불필요한 긴장을 유발합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người hưởng lợi", "def_ko": "환자 또는 돌봄 받는 사람", "def_vi": "Người bệnh hoặc người được chăm sóc"}, {"term_ko": "효과적", "term_vi": "Hiệu quả", "def_ko": "효과적인, 효과를 내는", "def_vi": "Có tác dụng hoặc hiệu quả"}, {"term_ko": "의사전달", "term_vi": "Truyền đạt thông tin", "def_ko": "정보를 전달하는 것", "def_vi": "Việc truyền đạt thông tin"}, {"term_ko": "신뢰", "term_vi": "Tin tưởng", "def_ko": "믿음", "def_vi": "Lòng tin"}, {"term_ko": "태도", "term_vi": "Thái độ", "def_ko": "행동이나 마음가짐", "def_vi": "Hành vi hoặc thái độ"}, {"term_ko": "전문가", "term_vi": "Chuyên gia", "def_ko": "특정 분야에서 지속적인 연구와 훈련을 받은 사람", "def_vi": "Người đã nghiên cứu và đào tạo liên tục trong một lĩnh vực cụ thể"}, {"term_ko": "상기시키다", "term_vi": "Nhắc lại", "def_ko": "기억나게 하다", "def_vi": "Ghi nhớ hoặc nhớ lại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1098, '8', '대상자와 공감적 대화로 옳은 것은?대상자: 어제 밤에 잠을 통 못 잤어. 낮잠을 자지 말아야겠어. 요양보호사: ( )', '["\"오늘 기분이 좋아 보이시네요.\"", "\"낮에 저랑 산책해요.\"", "\"네, 그렇게 해보시겠어요?\"", "\"무슨 고민이 있으세요?\"", "\"나이가 들면 잠이 없어진대요.\""]'::jsonb, 3, '대상자의 감정이나 상황을 이해하고 적절한 반응을 하는 공감적 의사소통의 중요성을 강조하기 위함입니다.', NULL, '{"1": "상대방의 기분에 대한 잘못된 판단으로 공감을 잘못 표현함.\n[정답]", "3": "대상자의 의사를 존중하며 긍정적인 방안을 제시함.", "2": "단순한 제안으로서 감정적 지지 부족.", "4": "대상자의 상태에 대한 불필요한 질문을 던짐.", "5": "일반적인 정보로서 대상자의 감정에 대한 공감 부족."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "환자나 보살핌이 필요한 사람", "def_vi": "Người bệnh hoặc người cần được chăm sóc"}, {"term_ko": "공감적", "term_vi": "Đồng cảm", "def_ko": "감정이나 상황을 이해하고 공유하는 것", "def_vi": "Hiểu và chia sẻ cảm xúc hoặc tình huống"}, {"term_ko": "대화", "term_vi": "Cuộc trò chuyện", "def_ko": "말이나 의사소통의 방식", "def_vi": "Cách giao tiếp hoặc nói chuyện"}, {"term_ko": "제안", "term_vi": "Đề xuất", "def_ko": "어떤 행동이나 결정을 제안하는 것", "def_vi": "Đưa ra một hành động hoặc quyết định"}, {"term_ko": "의사", "term_vi": "Bác sĩ", "def_ko": "전문가로서 진단을 내리거나 치료하는 사람", "def_vi": "Người chuyên môn đưa ra chẩn đoán hoặc điều trị"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1097, '8', '다음 대화 중 요양보호사의 공감적 반응으로 옳은 것은?대상자: 아이고 다리가 너무 아파, 꼼짝을 못하겠어. 갈수록 더 아픈 것 같아. 요양보호사: ( )', '["\"연세가 많으시니 아픈 것은 당연하지요.\"", "\"진통제를 좀 드릴까요.\"", "\"그동안 잘 참으셨잖아요. 조금만 더 참으세요.\"", "\"아프시니까 많이 힘드시죠.\"", "\"옆집 어르신도 많이 아프신가 봐요. 기운내세요.\""]'::jsonb, 4, '대화 속에서 요양보호사의 공감적 반응을 판단하는 것이며, 환자의 감정에 대해 이해하고 공감하는 태도를 알아보는 문제입니다.', NULL, '{"1": "환자의 감정을 무시하고 단순한 사실을 언급하여 공감하지 않음.\n[정답]", "4": "환자의 아픔을 인정하고 힘들다는 점에 공감함.", "3": "애써 환자를 위로하려는 의도는 있으나, 감정을 충분히 이해하지 못한 반응임.", "2": "의학적 제안으로, 감정적 지지를 제공하지 않음.", "5": "다른 사람의 사례를 들어 환자의 감정을 담아내지 않음."}'::jsonb, '[{"term_ko": "공감", "term_vi": "Đồng cảm", "def_ko": "이해하고 느끼는 것", "def_vi": "Hiểu và cảm nhận"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1096, '8', '다음 대화 중 요양보호사의 공감적 대화로 옳은 것은?대상자: 전에 요양보호사는 일 그만 두었다요? 그 분이 일을 참 잘했었는데... 요양보호사: ( )', '["그런 식으로 말씀하시지 마세요. 부탁드립니다.", "전에 하시던 분이 참 잘하셨나봐요. 저도 열심히 할게요.", "제가 마음에 안 드시면 다른 분 소개시켜 드릴까요?", "그러게 말씀하시니 기분이 안 좋네요. 서로 적응하면 나아질거예요.", "일 그만 둔 사람을 왜 찾으세요? 섭섭하네요."]'::jsonb, 2, '요양보호사가 공감적인 태도로 대화하는 것이 중요함을 이해하고 확인하기 위함입니다.', NULL, '{"1": "그런 식으로 말씀하시지 마세요. 부탁드립니다.", "2": "[정답] 전에 하시던 분이 참 잘하셨나봐요. 저도 열심히 할게요.", "3": "제가 마음에 안 드시면 다른 분 소개시켜 드릴까요?", "4": "그러게 말씀하시니 기분이 안 좋네요. 서로 적응하면 나아질거예요.", "5": "일 그만 둔 사람을 왜 찾으세요? 섭섭하네요."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자나 노인 등을 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân hoặc người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1095, '8', '다음 대화 중 요양보호사의 공감적 반응으로 옳은 것은?대상자: 나를 어린애 취급하는 것 같은데 성인으로 대해주세요. 양치질 해라, 머리 빗어라 명령하고 안하면 신경질 내잖아요. 요양보호사: ( )', '["신경질 낸 적 없거든요.", "그런 식으로 말하지 마세요.", "저도 성인으로 대하고 싶거든요.", "일일이 간섭하고 성가시게 해서 기분이 상하셨군요.", "어르신이 어린애처럼 스스로 못 챙기시잖아요."]'::jsonb, 4, '요양보호사로서 대상자의 감정과 불만을 이해하고 공감하는 능력을 평가하는 문제입니다.', NULL, '{"1": "신경질 낸 적 없거든요. (대상자의 감정을 무시하고 반박하는 태도입니다.)", "2": "그런 식으로 말하지 마세요. (비난적인 태도로 공감을 하지 못합니다.)", "3": "저도 성인으로 대하고 싶거든요. (자신의 입장을 나타내며 공감을 하지 않습니다.)\n[정답]", "4": "일일이 간섭하고 성가시게 해서 기분이 상하셨군요. (대상자의 기분을 공감하고 이해하는 반응입니다.)", "5": "어르신이 어린애처럼 스스로 못 챙기시잖아요. (부정적인 태도로 공감하지 않습니다.)"}'::jsonb, '[{"term_ko": "공감적 반응", "term_vi": "Phản ứng đồng cảm", "def_ko": "이해하고 동감하는 반응", "def_vi": "Phản ứng thể hiện sự hiểu biết và chia sẻ cảm xúc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1094, '8', '대상자와 대화할 때 경청을 방해하는 경우는?', '["충분히 듣지 않은 상태에서 조언한다.", "흥분하지 않고, 비판적 태도를 버린다.", "상대방이 말하는 의미를 잘 파악하고 이해한다.", "상대방이 말하는 동안 경청하고 있다는 것을 표현한다.", "상대방의 말을 가로채거나 이야기를 가로막지 않는다."]'::jsonb, 1, '대상자와의 의사소통에서 경청의 중요성을 이해하고 실천하는 능력을 평가하기 위함입니다.', NULL, '{"1": "충분히 듣지 않은 상태에서 조언한다. - 경청을 방해하는 대표적인 행동입니다. [정답]", "2": "흥분하지 않고, 비판적 태도를 버린다. - 경청에 도움이 되는 태도입니다.", "3": "상대방이 말하는 의미를 잘 파악하고 이해한다. - 경청의 중요한 요소입니다.", "4": "상대방이 말하는 동안 경청하고 있다는 것을 표현한다. - 경청을 증진시키는 방법입니다.", "5": "상대방의 말을 가로채거나 이야기를 가로막지 않는다. - 올바른 경청 태도입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "Người bệnh hoặc người nhận sự chăm sóc"}, {"term_ko": "경청", "term_vi": "Lắng nghe", "def_ko": "주의 깊게 듣는 것", "def_vi": "Nghe một cách chú ý"}, {"term_ko": "조언", "term_vi": "Lời khuyên", "def_ko": "다른 사람에게 일어날 수 있는 방법이나 해결책을 제시하는 것", "def_vi": "Đưa ra phương pháp hoặc giải pháp cho người khác"}, {"term_ko": "비판적", "term_vi": "Phê bình", "def_ko": "부정적이고 평가하는 태도", "def_vi": "Thái độ tiêu cực và đánh giá"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1093, '8', '대상자와 의사소통 시 효과적인 방법으로 옳은 것은?', '["듣고 싶지 않은 말은 걸러낸다.", "듣는 중간에 계속해서 조언한다.", "원하는 바를 우회적으로 돌려서 이야기한다.", "대상자의 말과 표정이 일치하는지 확인한다.", "요양보호사의 경험을 근거로 문제해결 방법을 조언한다."]'::jsonb, 4, '대상자와의 효과적인 의사소통 방법을 이해하고 적용할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "듣고 싶지 않은 말을 걸러내는 것은 효과적인 의사소통이 아닙니다.", "2": "듣는 중간에 계속해서 조언을 하는 것은 상대방의 말을 충분히 듣지 못하게 만들 수 있습니다.", "3": "원하는 바를 우회적으로 돌려서 이야기하는 것은 대화의 명확성을 떨어뜨릴 수 있습니다.\n[정답]", "4": "대상자의 말과 표정이 일치하는지 확인하는 것은 의사소통의 정확성을 높이는 좋은 방법입니다.", "5": "요양보호사의 경험을 근거로 문제해결 방법을 조언하는 것은 때로 도움이 될 수 있지만, 대상자가 느끼는 감정이나 요구를 우선적으로 고려해야 합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "환자 또는 수혜자", "def_vi": "Bệnh nhân hoặc người thụ hưởng"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통 또는 대화", "def_vi": "Sự giao tiếp hoặc trao đổi"}, {"term_ko": "표정", "term_vi": "Biểu cảm", "def_ko": "얼굴의 감정 표현", "def_vi": "Sự bày tỏ cảm xúc trên khuôn mặt"}, {"term_ko": "조언", "term_vi": "Lời khuyên", "def_ko": "의견이나 제안", "def_vi": "Ý kiến hoặc đề xuất"}, {"term_ko": "우회적", "term_vi": "Gián tiếp", "def_ko": "직접적이지 않은", "def_vi": "Không trực tiếp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1091, '8', '대상자와 효과적으로 의사소통하는 방법은?', '["의견이 맞지 않을 때는 대화 주제를 바꾼다.", "상황에 맞지 않는 말은 지적해 준다.", "대상자의 표정을 관찰하며 듣는다.", "ㄷ대상자가 말하는 동안 미리 대답을 준비한다.", "대상자의 말을 요양보호사의 경험에 비추어 판단한다."]'::jsonb, 3, '대상자와의 의사소통 방법을 이해하고, 실제 상황에 맞는 대응 방식을 판단하게 하기 위함입니다.', NULL, '{"1": "의견이 맞지 않을 때는 대화 주제를 바꾼다: 이는 효과적인 의사소통이 아닌 회피적 행동입니다.\n[정답]", "3": "대상자의 표정을 관찰하며 듣는다: 비언어적 신호를 이해하고 반응하는 것은 의사소통의 핵심입니다.", "2": "상황에 맞지 않는 말은 지적해 준다: 직접적인 지적은 대화의 흐름을 방해할 수 있습니다.", "4": "대상자가 말하는 동안 미리 대답을 준비한다: 이는 상대방의 말을 충분히 듣지 못하는 결과를 초래합니다.", "5": "대상자의 말을 요양보호사의 경험에 비추어 판단한다: 개인적인 경험으로 판단하는 것은 대상자의 고유한 상황을 왜곡할 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자나 클라이언트", "def_vi": "Bệnh nhân hoặc khách hàng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1090, '8', '대상자와 친밀한 관계를 형성하는 데 도움이 되는 의사소통 방법은?', '["듣기 전에 대답할 말을 미리 준비한다.", "논쟁에서는 다른 사람과 비교하면서 설득한다.", "ㅇ요양보호사는 국가자격을 지닌 전문가임을 강조한다.", "의견이 다를 때에는 대상자의 주장을 먼저 들어준다.", "대상자가 침묵할 때에는 요양보호사가 주도적으로 이야기한다."]'::jsonb, 4, '대상자와의 친밀한 관계 형성을 위한 적절한 의사소통 방법을 이해하고 선택하는 것이다.', NULL, '{"1": "듣기 전에 대답할 말을 미리 준비하는 것은 상대방의 의견을 존중하지 않는 태도이다.\n[정답]", "4": "의견이 다를 때에는 대상자의 주장을 먼저 들어주는 것이 친밀한 관계를 형성하는 데 도움이 된다.", "2": "논쟁에서는 다른 사람과 비교하면서 설득하는 것은 관계를 악화시킬 수 있다.", "3": "요양보호사가 국가자격을 지닌 전문가임을 강조하는 것은 관계 형성과는 거리가 있다.", "5": "대상자가 침묵할 때 요양보호사가 주도적으로 이야기하는 것은 상대방의 필요를 무시하는 태도이다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "보호받는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보를 전달하는 과정", "def_vi": "Quá trình truyền đạt thông tin"}, {"term_ko": "친밀한", "term_vi": "Thân thiết", "def_ko": "가까운, 친근한", "def_vi": "Gần gũi, thân thuộc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1089, '8', '비언어적 의사소통 중 바람직한 태도는?', '["입술을 깨물거나 꼭 다문 입", "대상자보다 높거나 낮은 눈높이", "따뜻하고 배려하는 표정", "손가락으로 지적하기", "큰소리로 말하기"]'::jsonb, 3, '비언어적 의사소통에서 바람직한 태도를 평가하기 위한 문제입니다.', NULL, '{"1": "입술을 깨물거나 꼭 다문 입: 긴장이나 불안감을 나타내는 부정적인 비언어적 신호입니다.\n[정답]", "3": "따뜻하고 배려하는 표정: 상대방에게 긍정적인 감정을 전달하며, 비언어적 의사소통에서 매우 중요한 태도입니다.", "2": "대상자보다 높거나 낮은 눈높이: 눈높이가 맞지 않으면 비언어적 의사소통의 효과가 떨어질 수 있습니다.", "4": "손가락으로 지적하기: 공격적이거나 불쾌감을 줄 수 있는 행동입니다.", "5": "큰소리로 말하기: 비언어적 의사소통의 맥락에서 부적절한 태도로 간주됩니다."}'::jsonb, '[{"term_ko": "비언어적 의사소통", "term_vi": "Giao tiếp không bằng lời nói", "def_ko": "언어가 아닌 방법으로 의사소통하는 것", "def_vi": "Cách giao tiếp không sử dụng ngôn ngữ"}, {"term_ko": "바람직한", "term_vi": "Đáng mong đợi", "def_ko": "좋은 품질이나 상태를 가진", "def_vi": "Có chất lượng hoặc trạng thái tốt"}, {"term_ko": "태도", "term_vi": "Thái độ", "def_ko": "어떤 행동이나 사고방식", "def_vi": "Một hành vi hoặc cách suy nghĩ"}, {"term_ko": "표정", "term_vi": "Biểu cảm", "def_ko": "얼굴의 감정이나 상태", "def_vi": "Cảm xúc hoặc trạng thái của khuôn mặt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1088, '8', '대상자와 의사소통 시 올바른 자세는?', '["팔짱끼기", "잦은 하품", "눈썹 치켜뜨기", "대상자와 같은 눈높이", "지나친 머리 끄덕임"]'::jsonb, 4, '대상자와의 올바른 의사소통 방식을 이해하고 평가하기 위함입니다.', NULL, '{"1": "팔짱끼기는 비협조적인 태도로 해석될 수 있습니다.\n[정답]", "4": "대상자와 같은 눈높이는 신뢰감을 주고 의사소통에 효과적입니다.", "3": "눈썹 치켜뜨기는 놀란 듯한 인상을 줄 수 있습니다.", "2": "잦은 하품은 피로감을 나타내어 적절하지 않습니다.", "5": "지나친 머리 끄덕임은 동의의 의미로 이해되겠지만, 과도할 경우 무례하게 여겨질 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "Bệnh nhân hoặc người nhận sự chăm sóc"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통", "def_vi": "Giao tiếp"}, {"term_ko": "눈높이", "term_vi": "Tầm nhìn", "def_ko": "동일한 시선의 높이", "def_vi": "Chiều cao của tầm nhìn"}, {"term_ko": "팔짱", "term_vi": "Khoanh tay", "def_ko": "두 팔을 서로 교차하여 감다", "def_vi": "Bắt chéo hai tay"}, {"term_ko": "하품", "term_vi": "Ngáp", "def_ko": "피로감으로 입을 벌리고 숨을 내쉬는 행위", "def_vi": "Hành động há miệng và thở ra do mệt mỏi"}, {"term_ko": "치켜뜨다", "term_vi": "Nâng mày", "def_ko": "눈썹을 위로 들어 올리다", "def_vi": "Nâng lông mày lên"}, {"term_ko": "지나치다", "term_vi": "Quá mức", "def_ko": "과도하거나 너무 많다", "def_vi": "Quá nhiều hoặc quá mức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1087, '8', '비언어적 의사소통 시 요양보호사의 자세로 옳은 것은?', '["너무 긴 침묵", "희미한 미소", "시선을 한 곳에 고정하기", "습관적인 머리 끄덕임", "대상자를 향해 약간 기울인 자세"]'::jsonb, 5, '비언어적 의사소통에서 요양보호사의 올바른 자세를 이해하고 평가하기 위함입니다.', NULL, '{"1": "너무 긴 침묵은 대화의 흐름을 방해할 수 있습니다.", "2": "희미한 미소는 상대방에게 비인격적인 인상을 줄 수 있습니다.", "3": "시선을 한 곳에 고정하는 것은 상대방과의 소통을 어렵게 합니다.", "4": "습관적인 머리 끄덕임은 진정한 이해를 나타내지 않을 수 있습니다.\n[정답]", "5": "대상자를 향해 약간 기울인 자세는 관심과 참여를 나타내어 비언어적 소통에 긍정적입니다."}'::jsonb, '[{"term_ko": "비언어적", "term_vi": "Giao tiếp phi ngôn ngữ", "def_ko": "말로 하지 않고 전달되는 의사소통", "def_vi": "Giao tiếp không bằng lời nói"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1086, '8', '다음 중 언어적 의사소통 표현으로 옳은 것은?', '["자세", "말의 내용", "눈맞춤", "옷차림", "얼굴표정"]'::jsonb, 2, '언어적 의사소통의 정의와 예시를 이해하고, 그에 따른 표현 방법을 구별할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "자세: 비언어적 표현이며 의사소통에 영향을 줄 수 있지만 언어적 의사소통과는 관계없음.\n[정답]", "2": "말의 내용: 언어적 의사소통을 표현하는 가장 직접적인 수단이며, 텍스트나 언어로 전달되는 의미를 담고 있음.", "3": "눈맞춤: 비언어적 의사소통에 해당하며 상대방과의 연결감을 주는 방법입니다.", "4": "옷차림: 개인의 스타일 표현으로, 의사소통을 돕기보다는 주로 비언어적 신호로 작용함.", "5": "얼굴표정: 비언어적 의사소통의 일종으로 감정이나 반응을 전달하는 수단입니다."}'::jsonb, '[{"term_ko": "언어적 의사소통", "term_vi": "Giao tiếp bằng ngôn ngữ", "def_ko": "말이나 글을 통해 의사를 전달하는 과정", "def_vi": "Quá trình truyền đạt ý kiến thông qua lời nói hoặc văn bản"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1085, '8', '대화를 할 때 영향을 미치는 요소 중 가장 중요한 것은?', '["억양", "표현력", "얼굴표정", "말의 내용", "말의 속도"]'::jsonb, 3, '대화를 할 때 영향을 미치는 중요한 요소를 이해하고 판단하는 능력을 평가하려는 의도입니다.', NULL, '{"1": "억양은 대화의 감정을 전달할 수 있지만, 가장 중요한 요소는 아닙니다.\n[정답]", "3": "얼굴표정은 비언어적 의사소통의 중요한 부분으로, 대화에 큰 영향을 미칩니다.", "2": "표현력도 중요하지만, 얼굴표정보다 덜 중요합니다.", "4": "말의 내용은 필수적이지만, 비언어적 요소인 얼굴표정에 비해 중요도가 낮습니다.", "5": "말의 속도도 대화에 영향을 주지만, 얼굴표정이 더 중요합니다."}'::jsonb, '[{"term_ko": "대화", "term_vi": "Cuộc trò chuyện", "def_ko": "대화를 나누는 것", "def_vi": "Hành động giao tiếp với nhau"}, {"term_ko": "영향", "term_vi": "Ảnh hưởng", "def_ko": "어떤 것이 다른 것에 미치는 작용", "def_vi": "Tác động của một cái gì đó lên cái khác"}, {"term_ko": "요소", "term_vi": "Yếu tố", "def_ko": "구성하는 부분", "def_vi": "Phần cấu thành"}, {"term_ko": "얻다", "term_vi": "Đạt được", "def_ko": "어떤 것을 가지게 되다", "def_vi": "Có được điều gì đó"}, {"term_ko": "표정", "term_vi": "Biểu cảm", "def_ko": "얼굴의 모습", "def_vi": "Diện mạo của khuôn mặt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1084, '8', '업무수행 과정에서 요굳회는 의사소통의 필요성으로 옳은 것은?', '["요양보호사의 업무를 평가하기 위해서", "요양보호사의 활동을 입증하기 위해서", "요양보호사의 전문성을 향상하기 위해서", "요양보호사의 책임성을 제고하기 위해서", "신뢰관계를 형성하여 좋은 관계를 유지하기 위해서"]'::jsonb, 5, '업무 수행 과정에서 의사소통이 중요한 이유를 이해하도록 요구하는 문제입니다.', NULL, '{"1": "요양보호사의 업무를 평가하기 위해서\n→ 이 선택지는 평가의 필요성을 언급하고 있지만, 의사소통의 필요성과는 다소 관련이 낮습니다.\n[정답]", "5": "신뢰관계를 형성하여 좋은 관계를 유지하기 위해서\n→ 의사소통은 신뢰관계를 구축하고 유지하는 데 필수적인 요소입니다. 따라서 올바른 답변입니다.", "2": "요양보호사의 활동을 입증하기 위해서\n→ 활동의 입증은 의사소통의 필요성과 직접적으로 연결되지 않습니다.", "3": "요양보호사의 전문성을 향상하기 위해서\n→ 전문성 향상은 교육이나 경험을 통해 이루어지며, 의사소통과의 관련성이 떨어집니다.", "4": "요양보호사의 책임성을 제고하기 위해서\n→ 책임성 제고와 의사소통 필요성은 연결될 수 있으나, 신뢰관계 형성의 중요성이 더 크다고 볼 수 있습니다."}'::jsonb, '[{"term_ko": "업무", "term_vi": "Công việc", "def_ko": "일, 작업", "def_vi": "Công việc, nhiệm vụ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1083, '7', '한랭 질환인 저체온증에 대한 설명으로 옳은 것은?', '["젖은 옷을 입은 채 담요로 감싼다.", "피부 및 피하조직이 손ㅅ상되어 무감각해진다.", "손가락, 발가락이 단단해지며 누런 회색으로 변한다.", "의식이 있으면 따뜻한 음료와 초콜릿을 섭취하게 한다.", "따뜻한 장소로 이동 후, 호전이 없으면 119에 신고한다."]'::jsonb, 4, '저체온증에 대한 정확한 대처 방법을 이해하고 있는지를 묻는 문제이다.', NULL, '{"1": "젖은 옷을 입은 채 담요로 감싸면 오히려 체온이 떨어질 수 있으므로 잘못된 방법이다.\n[정답]", "4": "의식이 있으면 따뜻한 음료와 초콜릿을 섭취하게 하는 것이 적절한 응급 처치 방법이다.", "2": "피부 및 피하조직이 손상되어 무감각해지는 것은 저체온증의 증상일 수 있으나 직접적인 대처 방법은 아니다.", "3": "손가락, 발가락이 단단해지고 변색되는 것은 저체온증의 증상으로 맞지만, 이를 대처하는 방법으로 적절하지 않다.", "5": "따뜻한 장소로 이동 후, 호전이 없으면 119에 신고하는 것이 좋지만, 이 단계에서 따뜻한 음료를 주는 것이 먼저이다."}'::jsonb, '[{"term_ko": "저체온증", "term_vi": "Hạ thân nhiệt", "def_ko": "기온이 체온보다 낮아져 나타나는 질환", "def_vi": "Bệnh xảy ra khi nhiệt độ cơ thể thấp hơn nhiệt độ bình thường"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "주변 상황을 인식하고 있는 상태", "def_vi": "Trạng thái nhận thức được xung quanh"}, {"term_ko": "온도", "term_vi": "Nhiệt độ", "def_ko": "열의 정도", "def_vi": "Mức độ của nhiệt"}, {"term_ko": "음료", "term_vi": "Đồ uống", "def_ko": "마실 수 있는 액체", "def_vi": "Chất lỏng có thể uống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1082, '7', '한랭관련 질환에 대한 설명으로 옳은 것은?', '["동상은 주로 가슴과 배, 등 부위에 생긴다.", "저체온증인 경우 옷을 벗은 상태로 있는다.", "동상부위는 차가운 물에 담가준다.", "저체온증은 착란, 어눌한 말투, 기억상실 증상이 나타난다.", "겨울에는 혈관이 이완되고 혈압이 저하되어 뇌졸중이 발생한다."]'::jsonb, 4, '한랭관련 질환에 대한 이해도를 평가하고자 하는 의도입니다.', NULL, '{"1": "동상은 주로 손, 발, 코와 같은 노출된 부위에 발생합니다, 따라서 잘못된 설명입니다.\n[정답]", "4": "저체온증에서는 착란, 어눌한 말투, 기억상실 등의 증상이 나타나므로 옳은 설명입니다.", "2": "저체온증인 경우 옷을 벗으면 상황이 더욱 악화될 수 있습니다, 잘못된 설명입니다.", "3": "동상 부위는 따뜻한 물에 담가야 하며 차가운 물은 피해야 합니다, 잘못된 설명입니다.", "5": "겨울철에는 혈관이 수축되고 혈압이 상승하여 뇌졸중 위험이 증가합니다, 잘못된 설명입니다."}'::jsonb, '[{"term_ko": "동상", "term_vi": "Bệnh đông lạnh", "def_ko": "동상", "def_vi": "Bệnh đông lạnh"}, {"term_ko": "저체온증", "term_vi": "Hạ thân nhiệt", "def_ko": "저체온증", "def_vi": "Hạ thân nhiệt"}, {"term_ko": "착란", "term_vi": "Rối loạn ý thức", "def_ko": "혼란", "def_vi": "Rối loạn ý thức"}, {"term_ko": "어눌한", "term_vi": "Lời nói khó khăn", "def_ko": "둔한", "def_vi": "Lời nói khó khăn"}, {"term_ko": "기억상실", "term_vi": "Mất trí nhớ", "def_ko": "기억상실", "def_vi": "Mất trí nhớ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1081, '7', '겨울철 뇌졸중 예방을 위한 안전수칙으로 옳은 것은?', '["실내 운동보다 실외 운동을 한다.", "술을 마신 다음 날 아침에 운동을 한다.", "운동시간은 낮보다 새벽 시간을 이용한다.", "따뜻한 곳에서 바로 차가운 곳으로 나간다.", "외출 시 방한복과 모자를 착용한다."]'::jsonb, 5, '겨울철 뇌졸중 예방에 필요한 안전수칙을 평가하기 위한 문제입니다.', NULL, '{"1": "실내 운동보다 실외 운동은 기온에 따라 위험할 수 있기 때문에 옳지 않습니다.\n[정답]", "5": "외출 시 방한복과 모자를 착용하는 것은 체온 유지에 도움이 되어 뇌졸중 예방에 효과적입니다.", "2": "술을 마신 다음 날 아침에 운동은 몸에 무리가 갈 수 있어 적절하지 않습니다.", "3": "운동시간을 새벽에 하는 것은 기온이 낮아 위험할 수 있어 권장되지 않습니다.", "4": "따뜻한 곳에서 바로 차가운 곳으로 나가는 것은 체온 조절에 문제가 생길 수 있습니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌에 혈액이 공급되지 않아 발생하는 질병", "def_vi": "Bệnh xảy ra khi máu không được cung cấp cho não"}, {"term_ko": "안전수칙", "term_vi": "Quy tắc an toàn", "def_ko": "사고를 예방하기 위한 규칙", "def_vi": "Quy tắc để ngăn ngừa tai nạn"}, {"term_ko": "방한복", "term_vi": "Đồ ấm", "def_ko": "겨울철에 체온을 유지하는 옷", "def_vi": "Trang phục giữ nhiệt độ cơ thể vào mùa đông"}, {"term_ko": "모자", "term_vi": "Mũ", "def_ko": "머리를 덮는 의복", "def_vi": "Đồ che đầu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1080, '7', '노인의 겨울철 안전수칙으로 옳은 것은?', '["실내운동과 적절한 영양섭취를 한다.", "심혈관질환 댓상자는 야외활동을 늘린다.", "밖에 나갈 때는 여러 겹의 두꺼운 옷을 입는다.", "동상부위는 헤어드라이어로 열을 가해 녹인다.", "저체온증으로 의식이 없으면 따뜻한 커피를 먹인다."]'::jsonb, 1, '노인의 겨울철 안전에 대한 정보 이해 및 적용 확인.', NULL, '{"1": "노인은 실내에서 운동과 영양섭취를 통해 건강을 유지해야 한다. \n[정답]", "2": "심혈관질환 환자는 야외활동을 조심해야 하며, 무리한 활동은 피해야 한다.", "3": "여러 겹의 얇은 옷을 입는 것이 보온에 더 효과적이며, 두꺼운 옷은 동작을 제한할 수 있다.", "4": "동상 부위는 반드시 따뜻한 물에 담그거나 의료진과 상담을 해야 하며, 헤어드라이어는 사용할 수 없다.", "5": "저체온증으로 의식이 없을 경우, 음식을 섭취하는 것이 위험하며 즉시 응급처치를 받아야 한다."}'::jsonb, '[{"term_ko": "겨울철", "term_vi": "안전수칙", "def_ko": "겨울(한국어) - mùa đông(베트남어)", "def_vi": "안전 규칙(한국어) - quy tắc an toàn(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1079, '7', '대상자가 겨울철에 실내에서 차가운 바깥응로 나갈 때 가장 주의해야 할 증상은?', '["맥박 저하", "혈압 상승", "호흡수 감소", "심박동수 저하", "체온 상승"]'::jsonb, 2, '겨울철 실내에서 차가운 바깥으로 나갈 때 주의해야 할 증상을 확인하는 문제입니다.', NULL, '{"1": "맥박 저하는 일반적으로 추위와 관련이 적습니다.\n[정답]", "2": "혈압 상승은 차가운 환경에서 발생할 수 있는 주요 증상입니다.", "3": "호흡수 감소는 상황에 따라 다르지만 주된 증상은 아닙니다.", "4": "심박동수 저하는 일반적으로 긴장이나 스트레스 상황에서 발생합니다.", "5": "체온 상승은 차가운 환경에서는 발생하지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1078, '7', '열탈진(일사병)이 발생한 경ㅇ우 응급조치로 옳은 것은?', '["119에 즉시 신고한다.", "따뜻한 물로 목욕을 시킨다.", "경련이 일어난 근육을 마사지한다.", "스포츠 음료나 주스 등을 마시게 한다.", "따뜻한 음료와 초콜릿을 제공한다."]'::jsonb, 4, '열탈진(일사병) 발생 시 적절한 응급조치를 묻는 문제입니다.', NULL, '{"1": "119에 신고하는 것은 좋지만 즉시 상황이 위급한 경우가 아니면 우선적인 조치가 아닙니다.\n[정답]", "4": "스포츠 음료나 주스는 수분과 전해질을 보충해 주어 탈진 회복에 도움이 됩니다.", "2": "따뜻한 물로 목욕시키는 것은 오히려 더 위험할 수 있습니다.", "3": "경련이 일어난 근육을 마사지하는 것은 올바른 조치가 아닙니다.", "5": "따뜻한 음료와 초콜릿을 주는 것은 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "열탈진", "term_vi": "Cơn sốc nhiệt", "def_ko": "열에 의해 발생하는 신체의 이상 상태", "def_vi": "Tình trạng bất thường của cơ thể do nhiệt độ cao"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1077, '7', '다음과 같은 방법으로 응급조치를 시행해야 하는 온열질환은?• 서늘한 곳에서 휴식 • 스포츠 음료나 주스 등을 마심 • 경련이 일어난 근육을 마사지', '["열발진", "열성부종", "열경련", "열사병", "열실신"]'::jsonb, 3, '응급조치가 필요한 온열질환을 구별하는 것.', NULL, '{"1": "열발진: 피부에 발진이 있는 상태로, 주로 발한의 영향을 받아 발생하며 응급조치가 필요하지 않음.\n[정답]", "3": "열경련: 근육이 경련을 일으키고 탈수로 인해 발생하며, 서늘한 곳에서의 휴식과 수분 보충이 필요함.", "2": "열성부종: 부종이 발생하는 온열질환으로, 일반적으로 긴급한 처치가 필요하지 않음.", "4": "열사병: 심각한 온열질환으로, 즉각적인 응급 처치가 필요하지만 본 문제의 응급조치에는 맞지 않음.", "5": "열실신: 기절하는 상태이지만, 문제에서 제시한 조치와는 관련이 없음."}'::jsonb, '[{"term_ko": "응급조치", "term_vi": "Biện pháp khẩn cấp", "def_ko": "긴급한 상황에서 행하는 처치", "def_vi": "Các biện pháp thực hiện trong tình huống khẩn cấp"}, {"term_ko": "온열질환", "term_vi": "Bệnh lý do nhiệt", "def_ko": "열로 인한 질환", "def_vi": "Bệnh vì nhiệt độ cao"}, {"term_ko": "열경련", "term_vi": "Chuột rút nhiệt", "def_ko": "근육 경련이 발생한 상태", "def_vi": "Tình trạng cơ bị co thắt"}, {"term_ko": "탈수", "term_vi": "Mất nước", "def_ko": "체액 결핍 상태", "def_vi": "Tình trạng thiếu nước cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1076, '7', '열사병으로 대상자가 의식이 없을 때 대처 방법으로 옳은 것은?', '["시원한 음료를 마시게 한다.", "이불 등으로 몸을 감싸 땀을 흘리게 한다.", "시원한 장소로 옮긴 후 살포제를 사용한다.", "기다렸다가 의식이 회복되면 병원 진료를 받는다.", "옷을 시원한 물로 적시고 몸에 선풍기 바람을 쇠어준다."]'::jsonb, 5, '열사병에 대한 응급처치 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "시원한 음료를 마시게 하는 것은 의식이 있는 경우에 가능한 방법입니다. 여기서는 대상자가 의식이 없으므로 부적절합니다.\n[정답]", "5": "옷을 시원한 물로 적시고 몸에 선풍기 바람을 쏴주는 것은 열사병의 주요 응급처치 방법 중 하나로 올바른 대처입니다.", "2": "이불 등으로 몸을 감싸서 땀을 흘리게 하는 것은 열사병을 악화시킬 수 있으므로 적절하지 않습니다.", "3": "시원한 장소로 옮긴 후 살포제를 사용하는 것은 의식이 없는 상태에서 신중하게 접근해야 하며, 부적절할 수 있습니다.", "4": "기다렸다가 의식이 회복되면 병원 진료를 받는 것은 즉각적인 응급처치를 제공하지 않는 것이므로 잘못된 방법입니다."}'::jsonb, '[{"term_ko": "열사병", "term_vi": "Bệnh say nắng", "def_ko": "과도한 더위에 노출되어 발생하는 질환", "def_vi": "căn bệnh xảy ra do phơi nhiễm nhiệt độ quá cao"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "자신이 존재하는 것을 인지하는 상태", "def_vi": "trạng thái nhận thức về sự tồn tại của bản thân"}, {"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "즉각적인 치료를 제공하는 과정", "def_vi": "quá trình cung cấp sự trợ giúp ngay lập tức"}, {"term_ko": "선풍기", "term_vi": "Quạt", "def_ko": "바람을 발생시키는 기구", "def_vi": "thiết bị tạo ra gió"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1075, '7', '여름철 폭염 대응 안전수칙으로 옳은 것은?', '["야외 활동을 권장한다.", "평소보다 물을 적게 마신다.", "두통이 있을 때는 가볍게 운동을 한다.", "현기증, 메스꺼움이 있을 때는 뜨거운 차를 마신다.", "외출할 때는 챙이 넓은 모자와 물을 휴대한다."]'::jsonb, 5, '여름철 폭염에 대한올바른 대처 방법을 이해하고 선택하는 능력을 평가하고자 함', NULL, '{"1": "여름철 폭염에선 야외 활동을 피해야 하므로 틀린 선택이다.\n[정답]", "5": "여름철 더위에 대비해 챙이 넓은 모자와 물을 휴대하는 것이 중요하다.", "2": "여름철에는 수분 보충이 필요하므로 물을 적게 마시는 것은 바람직하지 않다.", "3": "두통이 있을 때는 운동하기 보다는 휴식이 권장된다.", "4": "현기증 및 메스꺼움을 느낄 때는 뜨거운 차를 마시는 것 대신 시원한 환경을 유지해야 한다."}'::jsonb, '[{"term_ko": "폭염", "term_vi": "Nóng", "def_ko": "무더위(한국어)", "def_vi": "Nắng nóng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1074, '7', '여름철 폭염 시 대상자가 외출 후 현기증과 매스꺼움, 두통을 호소 할 때 대처방법은?', '["낮잠을 자게 한다.", "따뜻한 물로 목욕 시킨다.", "평소보다 식사를 많이 하게 한다.", "시원한 물이나 음료를 천천히 마시게 한다.", "문을 닫고 선풍기를 틀어준다."]'::jsonb, 4, '여름철 폭염 시 대상자의 건강 상태를 이해하고 적절한 대처 방법을 선택하도록 유도하는 문제입니다.', NULL, '{"1": "낮잠을 자게 한다: 낮잠은 휴식을 제공할 수 있지만, 현기증과 매스꺼움에는 즉각적인 도움이 되지 않습니다.\n[정답]", "4": "시원한 물이나 음료를 천천히 마시게 한다: 탈수와 열로 인한 증상을 완화시키고, 수분 보충에 효과적입니다.", "2": "따뜻한 물로 목욕 시킨다: 따뜻한 물은 오히려 열을 가중시켜 증상을 악화시킬 수 있습니다.", "3": "평소보다 식사를 많이 하게 한다: 식사는 필요하지만, 매스꺼움을 느낄 때는 과식이 오히려 불편함을 초래할 수 있습니다.", "5": "문을 닫고 선풍기를 틀어준다: 선풍기가 도움이 될 수 있지만, 시원한 음료 섭취가 더욱 중요합니다."}'::jsonb, '[{"term_ko": "폭염", "term_vi": "Nóng bức", "def_ko": "엄청 더움(한국어)", "def_vi": "rất nóng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1072, '7', '파상풍, 디프테리아 예방접종 주기로 옳은 것은?', '["6개월", "1년", "3년", "5년", "10년"]'::jsonb, 5, '파상풍과 디프테리아 예방접종의 주기를 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "6개월 간격으로 접종하지 않습니다.", "2": "1년 후 접종이 필요하지 않습니다.", "3": "3년 간격으로 접종하지 않습니다.", "4": "5년 간격으로 접종하는 것이 아닙니다.\n[정답]", "5": "10년마다 예방접종을 보강해야 합니다."}'::jsonb, '[{"term_ko": "파상풍", "term_vi": "Bệnh uốn ván", "def_ko": "병의 이름(한국어)", "def_vi": "Tên bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1071, '7', '노인 대상자에게 매년 1회 접종하도록 권유해야 하는 예방접종은?', '["파상풍", "디프테리아", "폐렴구균", "인플루엔자", "유행성 이하선염"]'::jsonb, 4, '노인 대상자에게 필요한 예방접종에 대한 이해를 확인하기 위함입니다.', NULL, '{"1": "파상풍은 정기적으로 접종해야 하지만 매년 1회 접종 대상은 아닙니다.", "2": "디프테리아도 정기적으로 접종해야 하지만 주기적으로 맞아야 합니다.\n[정답]", "3": "폐렴구균 예방접종은 노인에게 매년 접종이 권장됩니다.", "4": "인플루엔자 예방접종은 매년 1회 접종이 권장됩니다.", "5": "유행성 이하선염은 노인에게 주로 권장되는 예방접종이 아닙니다."}'::jsonb, '[{"term_ko": "예방접종", "term_vi": "대상자", "def_ko": "접종 예방", "def_vi": "người được áp dụng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1070, '7', '노인에게 권장되는 예방접종에 대한 설명으로 옳은 것은?', '["결핵 - 10년마다 1회", "인플루엔자 - 3년마다 1회", "파상풍 - 5년마다 1회", "폐렴구균 - 매년 1회", "대상포진 - 60세 이상 1회"]'::jsonb, 5, '노인에게 필요한 예방접종에 대한 정확한 정보를 제공하기 위함입니다.', NULL, '{"1": "결핵 예방접종은 일반적으로 권장되지 않으며, 10년마다 1회는 잘못된 정보입니다.\n[정답]", "5": "대상포진 예방접종은 60세 이상에게 1회 권장됩니다.", "2": "인플루엔자 예방접종은 매년 1회가 권장되며, 3년마다 1회는 잘못된 정보입니다.", "3": "파상풍 예방접종은 10년마다 1회가 권장되며, 5년마다 1회는 잘못된 정보입니다.", "4": "폐렴구균 예방접종은 고위험군에서 웬만하면 5년마다 1회가 권장됩니다."}'::jsonb, '[{"term_ko": "예방접종", "term_vi": "노인", "def_ko": "예방접종(주사) - tiêm chủng", "def_vi": "노인 - người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1069, '7', '음주를 하고 있는 대상자가 절주 습관을 갖도록 돕는 방법은?', '["공복에 술을 마시게 한다.", "매일 식사와 함게 소량의 술을 마시게 한다.", "절주에 대한 결심을 주변 사람에게 알리게 한다.", "권유받은 경우에만 술을 마시게 한다.", "암 예방을 위해 하루 2잔 이내로 마시게 한다."]'::jsonb, 3, '음주 습관 개선을 위한 적절한 방법을 이해하고 적용할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "공복에 술을 마시게 하면 건강에 해롭고 절주에 도움이 되지 않습니다.", "2": "매일 식사와 함께 소량의 술을 마시는 것은 오히려 음주 습관을 악화시킬 수 있습니다.\n[정답]", "3": "절주에 대한 결심을 주변 사람에게 알리게 하면 사회적 지지가 이루어져 절주를 유지하는 데 도움을 줍니다.", "4": "권유받은 경우에만 술을 마시게 하는 것은 자율적인 절주 습관 형성에 도움이 되지 않습니다.", "5": "암 예방을 위해 하루 2잔 이내로 마시게 하는 것은 절주가 아닌 지침일 뿐입니다."}'::jsonb, '[{"term_ko": "음주", "term_vi": "Uống rượu", "def_ko": "술을 마시는 행동", "def_vi": "Hành động uống rượu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1068, '7', '절주를 돕는 방법으로 옳은 것은?', '["큰 잔에 술을 마시게 한다.", "음주일지를 작성하여 점검하게 한다.", "여러 종류의 술을 섞어 마시게 한다.", "알코올 도수가 높은 술로 마시게 한다.", "집 안의 잘 보이는 곳에 술을 전시하게 한다."]'::jsonb, 2, '절주를 돕는 방법을 이해하고 적용하는 능력을 평가하고자 함', NULL, '{"1": "큰 잔에 술을 마시게 한다는 것은 오히려 음주를 장려하는 방법이다.\n[정답]", "2": "음주일지를 작성하여 점검하게 하는 것은 음주 습관을 스스로 인식하게 도와 절주를 돕는 방법이다.", "3": "여러 종류의 술을 섞어 마시게 하는 것은 건강에 해롭고 음주 통제를 어렵게 만든다.", "4": "알코올 도수가 높은 술로 마시게 하는 것은 절주와는 반대되는 행동이다.", "5": "집 안의 잘 보이는 곳에 술을 전시하게 하는 것은 음주를 부추기는 환경을 조성하는 것이다."}'::jsonb, '[{"term_ko": "절주", "term_vi": "Kiểm soát uống rượu", "def_ko": "술을 줄이거나 마시지 않는 것", "def_vi": "Giảm hoặc không uống rượu"}, {"term_ko": "음주일지", "term_vi": "Nhật ký uống rượu", "def_ko": "음주 습관을 기록하는 일지", "def_vi": "Nhật ký ghi lại thói quen uống rượu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1067, '7', '흡연과 금연에 관한 설명으로 옳은 것은?', '["간접흡연 시 폐활량이 증가한다.", "금연 시기를 놓치면 금연 효과가 없다.", "일시적 금연은 폐기능을 악화시킨다.", "간접흡연은 질병을 유발할 수 있다.", "금연 시 혈중 일산화탄소 수치가 증가한다."]'::jsonb, 4, '흡연과 금연에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "간접흡연은 폐활량에 긍정적인 영향을 미치지 않습니다. 오히려 감소할 수 있습니다.\n[정답]", "4": "간접흡연은 다양한 질병을 유발할 수 있습니다. 이는 여러 연구에서도 입증된 바 있습니다.", "2": "금연 시기를 놓치더라도 금연하면 효과는 발생합니다.", "3": "일시적 금연이 폐기능을 악화시키는 것은 아닙니다. 일반적으로 금연은 폐기능 개선에 긍정적입니다.", "5": "금연 시 혈중 일산화탄소 수치는 감소합니다."}'::jsonb, '[{"term_ko": "흡연", "term_vi": "Hút thuốc", "def_ko": "담배를 피우는 것", "def_vi": "Hút thuốc lá"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1066, '7', '금연 후 나타나는 변화로 옳은 것은?', '["기대수명이 감소한다.", "혈압이 정상으로 돌아온다.", "손상된 폐기능이 악화된다.", "성기능과 정자 수가 감소한다.", "혈중 산소량이 정상보다 감소한다."]'::jsonb, 2, '금연 후 신체에서 나타나는 긍정적인 변화를 이해하고 있는지 평가하기 위함입니다.', NULL, '{"1": "기대수명이 감소한다. - 금연은 기대수명을 증가시킵니다.\n[정답]", "2": "혈압이 정상으로 돌아온다. - 금연 후 혈압이 정상적으로 회복됩니다.", "3": "손상된 폐기능이 악화된다. - 금연 후 폐기능이 개선됩니다.", "4": "성기능과 정자 수가 감소한다. - 금연은 성기능 및 정자 수를 증가시킵니다.", "5": "혈중 산소량이 정상보다 감소한다. - 금연 후 혈중 산소량이 증가합니다."}'::jsonb, '[{"term_ko": "금연", "term_vi": "Bỏ thuốc lá", "def_ko": "담배를 끊는 것", "def_vi": "Ngưng hút thuốc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1065, '7', '금연으로 기대할 수 있는 변화로 옳은 것은?', '["후각과 미각이 무뎌진다.", "혈압이 정상보다 높아진다.", "심장병 발병 위험이 증가한다.", "폐암으로 사망할 확률이 증가한다.", "혈중 일산화탄소량이 정상으로 회복된다."]'::jsonb, 5, '금연 후 신체의 변화를 이해하고 이를 통해 금연의 긍정적인 영향을 인식하는 것이다.', NULL, '{"1": "후각과 미각이 무뎌진다. 이는 금연 후 개선되는 부분이다.\n[정답]", "5": "혈중 일산화탄소량이 정상으로 회복된다. 금연 후 혈중 수치는 회복된다.", "2": "혈압이 정상보다 높아진다. 금연은 혈압을 정상으로 낮춘다.", "3": "심장병 발병 위험이 증가한다. 금연은 심장병 위험을 감소시킨다.", "4": "폐암으로 사망할 확률이 증가한다. 금연은 폐암 위험을 줄인다."}'::jsonb, '[{"term_ko": "금연", "term_vi": "Bỏ thuốc lá", "def_ko": "담배를 끊는 것", "def_vi": "Ngừng hút thuốc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1064, '7', '노인의 흡연에 대한 설명으로 옳은 것은?', '["흡연은 체중감소 효과가 있다.", "흡연은 우울증, 불면증을 개선한다.", "흡연은 혈액순환에 도움이 된다.", "하루 1~2개비가 적정 흡연량이다.", "오랫동안 흡연하였어도 금연하면 건강을 증진할 수 있다."]'::jsonb, 5, '노인의 흡연이 건강에 미치는 영향을 정리하고, 금연의 이점에 대해 이해하도록 하는 것.', NULL, '{"1": "흡연은 체중감소 효과가 있지만, 이는 건강에 해로운 영향을 미친다.", "2": "흡연은 우울증과 불면증을 악화시킬 수 있다.", "3": "흡연은 혈액순환에 부정적인 영향을 미친다.", "4": "하루 1~2개비는 여전히 건강에 나쁜 영향을 미칠 수 있다.\n[정답]", "5": "오랫동안 흡연하였어도 금연하면 건강을 개선할 수 있는 여러 연구 결과가 있다."}'::jsonb, '[{"term_ko": "흡연", "term_vi": "Hút thuốc", "def_ko": "담배를 피우는 것", "def_vi": "Hút thuốc lá"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1063, '7', '다음 중 약물복용 방법으로 옳은 것은?', '["철분제는 우유와 함께 복용한다.", "고혈압 약은 자몽주스와 함께 복용한다.", "인슐린은 식사 전 입으로 복용한다.", "기관지확장제는 머리를 숙인 채 흡입한다.", "분할선이 있는 약은 쪼개어 복용할 수 있다."]'::jsonb, 5, '약물 복용 방법에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "철분제는 우유와 함께 복용 시 흡수에 방해가 됩니다.\n[정답]", "5": "분할선이 있는 약은 쪼개어 복용할 수 있어, 복용량 조절에 도움이 됩니다.", "2": "고혈압 약과 자몽주스는 상호작용이 있어 함께 복용하면 안 됩니다.", "3": "인슐린은 주사제로 사용되며, 식사 전 입으로 복용하지 않습니다.", "4": "기관지확장제는 일반적으로 제대로된 자세로 흡입해야 합니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "thuốc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1062, '7', '노인이 복용한 후 낙상 사고의 부작용이 발생할 수 있는 약물로 옳은 것은?', '["소염진통제", "스테로이드제", "당뇨병 약제", "항응고제", "수면제 등 신경정신계 약물"]'::jsonb, 5, '노인이 복용한 약물이 낙상 사고에 미치는 영향을 이해하는 문제입니다.', NULL, '{"1": "소염진통제는 주로 통증 완화를 위해 사용되며 낙상과 직접적인 관련이 없습니다.\n[정답]", "5": "수면제 등 신경정신계 약물은 졸림과 집중력 저하를 유발하여 낙상 사고의 위험을 증가시킵니다.", "2": "스테로이드제는 면역 반응을 억제하지만 낙상과 직접적인 연관성은 낮습니다.", "3": "당뇨병 약제는 혈당 조절을 위해 사용되며 일반적으로 낙상과는 무관합니다.", "4": "항응고제는 출혈 위험을 증가시킬 수 있지만, 낙상 사고를 직접 유발하지는 않습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người già", "def_ko": "나이 많은 사람", "def_vi": "Người lớn tuổi"}, {"term_ko": "낙상", "term_vi": "Ngã", "def_ko": "넘어져서 떨어지는 것", "def_vi": "Ngã xuống"}, {"term_ko": "소염진통제", "term_vi": "Thuốc giảm đau chống viêm", "def_ko": "통증을 줄이는 약물", "def_vi": "Thuốc giảm đau"}, {"term_ko": "스테로이드제", "term_vi": "Thuốc steroid", "def_ko": "면역 반응을 억제하는 약물", "def_vi": "Thuốc ức chế miễn dịch"}, {"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "혈당 조절 장애", "def_vi": "Rối loạn kiểm soát đường huyết"}, {"term_ko": "항응고제", "term_vi": "Thuốc chống đông máu", "def_ko": "출혈 예방 약물", "def_vi": "Thuốc ngăn ngừa chảy máu"}, {"term_ko": "수면제", "term_vi": "Thuốc an thần", "def_ko": "잠을 유도하는 약물", "def_vi": "Thuốc gây buồn ngủ"}, {"term_ko": "신경정신계", "term_vi": "Hệ thần kinh tâm thần", "def_ko": "정신 건강과 관련된 약물", "def_vi": "Liên quan đến sức khỏe tâm thần"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1061, '7', '약물과 약물의 흡수를 돕는 식품이 바르게 연결된 것은?', '["칼슘제 - 우유", "와파린 - 시금치", "고혈압약 - 인삼, 홍삼", "철분제 - 오렌지주스", "항생제 - 프로바이오틱스"]'::jsonb, 4, '약물과 음식의 상호작용에 대한 이해를 점검하기 위한 문제입니다.', NULL, '{"1": "칼슘제를 우유와 함께 복용할 경우 흡수에 방해가 될 수 있습니다.\n[정답]", "4": "철분제는 오렌지주스와 함께 복용해야 흡수력이 높아집니다.", "2": "와파린과 시금치는 비타민 K의 영향을 줄 수 있습니다.", "3": "고혈압약과 인삼, 홍삼은 상호작용에 주의해야 합니다.", "5": "항생제와 프로바이오틱스는 보통 함께 복용할 경우 효과가 줄어들 수 있습니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "thuốc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1060, '7', '재가 방문 시 편의점에서 구입 가능한 비상약으로 옳은 것은?', '["수면제", "항생제", "해열진통제", "혈압약", "기관지확장제"]'::jsonb, 3, '비상약의 종류와 구입 가능성에 대한 이해를 평가하기 위해 출제되었다.', NULL, '{"1": "수면제는 일반 약국에서 구입이 가능하지만, 편의점에서는 구입할 수 없다.", "2": "항생제는 의사의 처방이 필요한 약물이다.\n[정답]", "3": "해열진통제는 일반적으로 편의점에서도 쉽게 구입할 수 있는 비상약이다.", "4": "혈압약은 처방이 필요하며 일반 약국에서만 구입할 수 있다.", "5": "기관지확장제도 처방약으로 분류되어 일반적인 접촉에서 구입할 수 없다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Tại gia", "def_ko": "가정에서의 의미", "def_vi": "Nghĩa là ở nhà"}, {"term_ko": "편의점", "term_vi": "Cửa hàng tiện lợi", "def_ko": "쉽게 접근할 수 있는 상점", "def_vi": "Cửa hàng dễ dàng tiếp cận"}, {"term_ko": "비상약", "term_vi": "Thuốc khẩn cấp", "def_ko": "긴급하게 필요한 약", "def_vi": "Thuốc cần thiết trong trường hợp khẩn cấp"}, {"term_ko": "해열진통제", "term_vi": "Thuốc hạ sốt và giảm đau", "def_ko": "열을 낮추고 통증을 완화하는 약물", "def_vi": "Thuốc giảm nhiệt độ và giảm đau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1059, '7', '올바른 약물복용을 위한 관리방법으로 옳은 것은?', '["전날에 복용하지 않은 경우 2회 분량을 한꺼번에 복용한다.", "효과가 없을 때에는 정해진 양보다 많이 먹는다.", "증상이 좋아지면 처방약 복용을 중단한다.", "약물과 건강기능식품을 함께 복용 시 의사와 상의 없이 먹어도 된다.", "다른 병원이나 약국을 방문할 경우 이전 처방전을 보여준다."]'::jsonb, 5, '약물 복용에 대한 올바른 관리 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "전날에 복용하지 않은 경우 2회 분량을 한꺼번에 복용하는 것은 잘못된 방법입니다. 약물은 정해진 복용량에 따라 복용해야 합니다.\n[정답]", "5": "다른 병원이나 약국을 방문할 경우 이전 처방전을 보여주는 것이 올바른 관리 방법입니다. 이는 안전한 약물 복용을 위해 필요합니다.", "2": "효과가 없을 때 정해진 양보다 많이 먹는 것은 오히려 위험할 수 있습니다.", "3": "증상이 좋아지면 처방약 복용을 중단해서는 안 되며, 의사의 지시를 따라야 합니다.", "4": "약물과 건강기능식품을 함께 복용할 때는 반드시 의사와 상의해야 합니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "Thuốc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1058, '7', '노인들의 약물관리 방법으로 옳은 것은?', '["술을 마신 후에도 반드시 약을 복용한다.", "위장 장애가 있을 때에느 약 용량을 줄인다.", "약을 중단하기 전 의사와 먼저 상담한다.", "약을 증상에 맞게 본인이 혼합해서 먹어도 된다.", "새로운 약을 처방받은 경우 이전 약을 먼저 먹는다."]'::jsonb, 3, '노인들의 약물 관리 및 안전한 복용 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "술을 마신 후에 약을 복용하면 상호작용이 발생할 수 있어 위험합니다.\n[정답]", "3": "약을 중단하기 전에는 반드시 의사와 상담해야 안전합니다.", "2": "위장 장애가 있을 때는 즉시 의사와 상담해야 하며, 용량을 조정할 수 있습니다.", "4": "약은 반드시 의사의 처방에 따라서 복용해야 하며, 혼합해서 복용하는 것은 위험합니다.", "5": "새로운 약을 처방받은 경우, 기존 약과의 상호작용을 피하기 위해 반드시 먼저 의사와 상담해야 합니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1057, '7', '대상자가 두통이 있을 때마다 약을 복용하려 할 때 대처방법은?', '["삼키기 힘든 장용 코팅제는 쪼개서 복용하게 한다.", "한번에 많은 양을 사두고 필요 시 복용하게 한다.", "증상에 따라 약 용량을 조절하여 복용하게 한다.", "비처방 약이라도 의사와 사담 후 복용하게 한다.", "증상이 비슷한 다른 대상자의 약을 복용하게 한다."]'::jsonb, 4, '대상자가 두통이 있을 때의 안전한 약 복용 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "삼키기 힘든 장용 코팅제는 쪼개서 복용하게 한다. 잘못된 방법입니다. 장용 코팅제는 쪼개면 효과가 감소할 수 있습니다.\n[정답]", "2": "한 번에 많은 양을 사두고 필요 시 복용하게 한다. 이는 안전하지 않으며, 과다 복용의 위험이 있습니다.", "3": "증상에 따라 약 용량을 조절하여 복용하게 한다. 이는 의사가 지시한 경우에만 가능합니다.", "4": "비처방 약이라도 의사와 사담 후 복용하게 한다. 의사와 상담 후에 약을 복용하는 것은 안전한 방법입니다.", "5": "증상이 비슷한 다른 대상자의 약을 복용하게 한다. 이는 매우 위험하며, 안전하지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1056, '7', '노인에게 약물중독이 많이 발생하는 주된 이유는?', '["약물의 흡수능력 증가", "심장의 수축력 증가", "간의 대사능력 증가", "위장의 위산분비 증가", "신장의 혈류량 감소"]'::jsonb, 5, '노인이 약물중독에 걸리기 쉬운 이유를 묻고 있습니다.', NULL, '{"1": "약물의 흡수능력이 증가하면 약물이 더 쉽게 체내에 흡수될 수 있지만, 이것이 주된 원인은 아닙니다.", "2": "심장의 수축력이 증가하는 것은 일반적으로 약물중독의 원인과 관련이 없습니다.", "3": "간의 대사능력이 증가하면 약물이 더 빨리 대사되어야 하지만, 노인의 경우 대사능력이 감소하는 경향이 있습니다.", "4": "위장의 위산분비가 증가하는 것은 약물 흡수에 영향을 미칠 수 있지만, 주된 원인은 아닙니다.\n[정답]", "5": "신장의 혈류량 감소는 노인에서 흔히 발생하며, 신장의 기능 저하로 이어져 약물 배설이 원활하지 않아 약물중독의 위험을 증가시킵니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "Thuốc"}, {"term_ko": "중독", "term_vi": "Ngộ độc", "def_ko": "해로운 물질이 몸에 들어가 고통을 주는 상태(한국어)", "def_vi": "Tình trạng có chất độc xâm nhập vào cơ thể gây đau đớn"}, {"term_ko": "흡수능력", "term_vi": "Khả năng hấp thụ", "def_ko": "어떤 것이 흡수할 수 있는 능력(한국어)", "def_vi": "Khả năng mà một cái gì đó có thể được hấp thụ"}, {"term_ko": "신장", "term_vi": "Thận", "def_ko": "피가 여과되는 장기(한국어)", "def_vi": "Cơ quan lọc máu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1055, '7', '노인에게 약물중독이 많이 발생하는 주된 이유는?', '["약물의 흡수능력 증가", "심장의 수축력 증가", "간의 대사능력 증가", "위장의 위산분비 증가", "신장의 혈류량 감소"]'::jsonb, 5, '노인들의 약물중독 원인을 이해하고, 중앙신경계와 대사과정이 노인에게 미치는 영향을 알리는 것.', NULL, '{"1": "약물의 흡수능력 증가: 노인에서는 약물 흡수가 평소보다 감소하는 경향이 있다.", "2": "심장의 수축력 증가: 노인에서는 심장 수축력이 감소하여 혈액순환이 불량해진다.", "3": "간의 대사능력 증가: 노인의 간 대사능력은 보통 감소하며, 이는 약물의 작용 지속시간을 늘릴 수 있다.\n[정답]", "5": "신장의 혈류량 감소: 노인의 경우 신장 기능이 저하되어 약물의 배설이 원활하지 못하고, 이로 인해 약물중독이 발생할 수 있다.", "4": "위장의 위산분비 증가: 노인은 위산 분비가 줄어드는 경향이 있다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "중독", "def_ko": "약(한국어)/thuốc(베트남어)", "def_vi": "타락(한국어)/ngộ độc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1054, '7', '뇌졸증 대상자가 성생활에 대해 고민할 때 요양보호사의 대처방법은?', '["\"성생활은 건강에 도움이 안 돼요.\"", "\"성생활로 뇌졸증이 악화되지 않아요.\"", "\"윤활제를 사용하면 성기능이 감소돼요.\"", "\"항고혈압제를 드시면 성기능이 좋아져요.\"", "\"체위변화를 위한 기구는 전혀 도움이 되지 않아요.\""]'::jsonb, 2, '뇌졸증 환자의 성생활에 대한 올바른 정보를 제공하기 위한 요양보호사의 대처 방법을 묻는 문제입니다.', NULL, '{"1": "\"성생활은 건강에 도움이 안 돼요.\" - 성생활은 건강에 여러모로 긍정적인 영향을 줄 수 있습니다. 잘못된 정보입니다.\n[정답]", "2": "\"성생활로 뇌졸증이 악화되지 않아요.\" - 이 문장은 뇌졸증 환자가 성생활을 해도 건강에 나쁜 영향을 주지 않는다는 올바른 정보입니다.", "3": "\"윤활제를 사용하면 성기능이 감소돼요.\" - 윤활제는 오히려 도움이 되는 경우가 많습니다. 잘못된 정보입니다.", "4": "\"항고혈압제를 드시면 성기능이 좋아져요.\" - 항고혈압제가 모두 성기능에 긍정적인 영향을 주는 것은 아닙니다. 일반적인 진술이 아닙니다.", "5": "\"체위변화를 위한 기구는 전혀 도움이 되지 않아요.\" - 체위변화를 돕는 기구는 성생활에 도움이 될 수 있습니다. 잘못된 정보입니다."}'::jsonb, '[{"term_ko": "뇌졸증", "term_vi": "Đột quỵ", "def_ko": "뇌혈관이 막혀서 생기는 질병", "def_vi": "Bệnh do tắc nghẽn mạch máu não"}, {"term_ko": "성생활", "term_vi": "Đời sống tình dục", "def_ko": "성적 활동", "def_vi": "Hoạt động tình dục"}, {"term_ko": "윤활제", "term_vi": "Chất bôi trơn", "def_ko": "성적 활동을 돕기 위해 사용하는 용액", "def_vi": "Chất lỏng sử dụng để hỗ trợ hoạt động tình dục"}, {"term_ko": "항고혈압제", "term_vi": "Thuốc hạ huyết áp", "def_ko": "고혈압을 치료하는 약물", "def_vi": "Thuốc điều trị cao huyết áp"}, {"term_ko": "체위변화", "term_vi": "Thay đổi tư thế", "def_ko": "성적 활동 시 자세를 바꾸는 것", "def_vi": "Việc thay đổi tư thế trong hoạt động tình dục"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1053, '7', '노인의 성기능을 감소시키는 요인과 관계가 없는 대상자는?', '["이뇨제를 복용하는 대상자", "고혈압 약을 복용중인 대상자", "관절염을 치료중인 대상자", "전립선 절제술을 받은 대상자", "당뇨병이 있는 대상자"]'::jsonb, 4, '노인의 성기능 감소에 영향을 미치는 요인과의 관계를 파악하기 위한 문제이다.', NULL, '{"1": "이뇨제는 성기능에 영향을 미칠 수 있는 약물이다.\n[정답]", "4": "전립선 절제술은 성기능에 영향을 줄 수 있지만, 이 질문에서는 관계가 없는 것으로 간주된다.", "2": "고혈압 약물은 성기능에 부정적인 영향을 줄 수 있다.", "3": "관절염 치료를 위한 약물도 성기능에 영향을 미칠 수 있다.", "5": "당뇨병은 성기능 감소와 관련이 있다."}'::jsonb, '[{"term_ko": "성기능", "term_vi": "Chức năng tình dục", "def_ko": "성에 관련된 신체적 능력", "def_vi": "Khả năng liên quan đến cơ thể về tình dục"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1052, '7', '노인의 성적 변화에 대한 설명으로 옳은 것은?', '["항염즈성 약물을 복용하면 성적 욕구가 증가한다.", "과도한 알코올 섭취는 오르가슴을 빨리 느끼게 한다.", "유방절제술을 한 노인은 성기능이 감소한다.", "질 분비물이 증가하여 성교 시 통증이 없다.", "자궁척출술은 성기능에 영향을 주지 않는다."]'::jsonb, 5, '노인의 성적 변화에 대한 정확한 이해를 확인하기 위한 문제입니다.', NULL, '{"1": "항염증성 약물이 성적 욕구에 미치는 영향은 개별 차이가 크며 일반적으로 증가시키지 않습니다.", "2": "과도한 알코올 섭취는 성적 반응을 저하시킬 수 있습니다.\n[정답]", "3": "유방절제술을 한 노인은 성기능이 감소할 수 있습니다. 이는 심리적 요인과 생리적 요인 모두가 관련될 수 있습니다.", "4": "질 분비물의 양은 개인차가 있으며, 증가한다고 하더라도 성교 시 통증 없이 진행되기 어려울 수 있습니다.", "5": "자궁적출술을 한 경우에도 성기능이 영향을 받을 수 있습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "고령자(한국어)", "def_vi": "Người lớn tuổi"}, {"term_ko": "성적 변화", "term_vi": "Sự thay đổi tình dục", "def_ko": "성적 상황이나 반응의 변화(한국어)", "def_vi": "Sự thay đổi về tình trạng tình dục hoặc phản ứng"}, {"term_ko": "성적 욕구", "term_vi": "Ham muốn tình dục", "def_ko": "성적 충동이나 욕망(한국어)", "def_vi": "Sự thèm muốn tình dục"}, {"term_ko": "유방절제술", "term_vi": "Phẫu thuật cắt bỏ vú", "def_ko": "유방을 제거하는 수술(한국어)", "def_vi": "Phẫu thuật loại bỏ ngực"}, {"term_ko": "자궁적출술", "term_vi": "Phẫu thuật cắt bỏ tử cung", "def_ko": "자궁을 제거하는 수술(한국어)", "def_vi": "Phẫu thuật loại bỏ tử cung"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1051, '7', '대상자의 질환이 성생활에 미치는 영향으로 올바르게 연결된 것은?', '["뇌졸증 - 성기능 감소", "당뇨병 - 발기부전", "심근경색- 성 욕구 감소", "알코올 중독 - 성기능 증가", "전립선 절제술 - 성 욕구 감소"]'::jsonb, 2, '대상자의 질환이 성생활에 미치는 영향에 대한 이해를 평가하고자 함.', NULL, '{"1": "뇌졸증은 신경계에 영향을 주어 성기능을 감소시킬 수 있으나, 연결이 정확하지 않음.\n[정답]", "2": "당뇨병은 혈액순환 및 신경 손상으로 발기부전을 유발할 수 있어 올바른 연결이다.", "3": "심근경색은 심장 건강의 문제로 성욕에 영향을 줄 수 있으나 항상 감소한다고 할 수 없음.", "4": "알코올 중독은 성기능을 감소시킬 가능성이 높으며, 기능 증가와는 연결되지 않음.", "5": "전립선 절제술은 성욕 감소를 유발하는 경우가 일반적이지만, 전립선의 상태나 개인에 따라서 다를 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "질환", "def_ko": "환자, đối tượng", "def_vi": "병, bệnh lý"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1050, '7', '무더운 여름밤에 잠을 못 이루고 뒤척이는 치매 대상자를 돕는 방법은?', '["시원한 홍차를 제공한다.", "시원하고 얇은 이불을 덮어 준다.", "포만감을 느끼도록 간식을 제공한다.", "낮잠으로 수면을 보충하도록 돕는다.", "숙면을 위해 수면제를 복용하게 한다."]'::jsonb, 2, '치매 환자의 숙면을 도와주기 위한 적절한 방법을 찾는 것.', NULL, '{"1": "시원한 홍차는 카페인이 포함되어 있어 수면에 도움을 주지 않는다.\n[정답]", "2": "시원하고 얇은 이불을 덮어 주면 열을 식히고 편안함을 제공하여 숙면을 돕는다.", "3": "포만감을 주는 간식은 오히려 불편함으로 이어질 수 있다.", "4": "낮잠을 잘 경우, 밤에 잠을 이루기 더욱 어려워질 수 있으므로 적절하지 않다.", "5": "수면제는 부작용이 있을 수 있어 치매 환자에게 사용하기 위험하다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고 능력이 저하되는 질환", "def_vi": "Bệnh giảm sút trí nhớ và khả năng tư duy"}, {"term_ko": "숙면", "term_vi": "Giấc ngủ ngon", "def_ko": "깊고 편안한 잠", "def_vi": "Giấc ngủ sâu và thoải mái"}, {"term_ko": "이불", "term_vi": "Chăn", "def_ko": "침대 위에 덮는 천", "def_vi": "Vải phủ lên giường"}, {"term_ko": "포만감", "term_vi": "Cảm giác no", "def_ko": "배부른 느낌", "def_vi": "Cảm giác no bụng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1049, '7', '공복감으로 잠을 이루지 못하는 수면장애 대상자를 돕는 방법은?', '["따뜻한 홍차나 녹차를 제공한다.", "실내온도를 서늘하게 유지한다.", "수면제를 복용하게 한다.", "저녁 식사를 많이 권한다.", "따뜻한 우유를 제공한다."]'::jsonb, 5, '수면장애를 겪는 대상자에게 도움을 줄 수 있는 방법을 묻고 있다.', NULL, '{"1": "따뜻한 홍차나 녹차는 카페인이 있어 수면에 방해가 될 수 있다.\n[정답]", "5": "따뜻한 우유는 수면 유도에 도움이 될 수 있는 효과가 있다.", "3": "수면제를 복용하게 하는 것은 만성적으로 의존성을 초래할 수 있다.", "2": "실내온도를 서늘하게 유지하는 것은 수면에 도움이 되나, 식사와 관련이 없다.", "4": "저녁 식사를 많이 권하는 것은 오히려 수면에 부정적인 영향을 미칠 수 있다."}'::jsonb, '[{"term_ko": "공복감", "term_vi": "Cảm giác đói", "def_ko": "허기가 느껴지는 상태", "def_vi": "trạng thái cảm thấy đói"}, {"term_ko": "수면장애", "term_vi": "Rối loạn giấc ngủ", "def_ko": "수면에 문제가 있는 상태", "def_vi": "trạng thái có vấn đề về giấc ngủ"}, {"term_ko": "제공하다", "term_vi": "Cung cấp", "def_ko": "어떤 것을 주거나 제공하는 것", "def_vi": "hành động đưa hoặc cung cấp một cái gì đó"}, {"term_ko": "저녁 식사", "term_vi": "Bữa tối", "def_ko": "저녁에 먹는 식사", "def_vi": "bữa ăn vào buổi tối"}, {"term_ko": "의존성", "term_vi": "Sự phụ thuộc", "def_ko": "사용이 반복되며 그에 따라 영향을 받는 상태", "def_vi": "trạng thái bị ảnh hưởng bởi việc sử dụng lặp đi lặp lại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1048, '7', '공복감으로 잠을 이루지 못하는 수면장애 대상자를 돕는 방법은?', '["따뜻한 홍차나 녹차를 제공한다.", "실내온도를 서늘하게 유지한다.", "수면제를 복용하게 한다.", "저녁 식사를 많이 권한다.", "따뜻한 우유를 제공한다."]'::jsonb, 5, '공복감이 수면에 미치는 영향을 이해하고, 이에 대한 적절한 대처 방법을 평가하기 위함입니다.', NULL, '{"1": "따뜻한 홍차나 녹차는 카페인을 포함할 수 있어 수면을 방해할 수 있습니다.\n[정답]", "5": "따뜻한 우유는 트립토판과 칼슘을 포함해 수면을 촉진시킬 수 있습니다.", "2": "실내온도를 서늘하게 유지하는 것도 도움이 될 수 있지만, 공복감 해결에는 직접적인 원인이 아닙니다.", "3": "수면제를 복용하게 하는 것은 의존성을 유발할 수 있어 장기적인 해결책이 아닙니다.", "4": "저녁 식사를 많이 권하는 것은 오히려 불편함을 초래하여 수면을 방해할 수 있습니다."}'::jsonb, '[{"term_ko": "공복감", "term_vi": "Cảm giác đói", "def_ko": "배가 고픈 느낌", "def_vi": "Cảm giác bụng đói"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1047, '7', '밤에 잠을 쉽게 이루지 못하는 대상자의 잘못된 생활 습관은?', '["낮잠을 자지 않는다.", "낮 시간에 산책이나 운동을 한다.", "저녁 운동 후 시원한 녹차를 마신다.", "침실의 온도를 적절하게 유지한다.", "매일 일정한 시간에 일어나고 일정한 시간에 잠을 잔다."]'::jsonb, 3, '주간 활동과 수면의 관계를 이해하고, 잘못된 생활습관을 파악하게 하려는 의도입니다.', NULL, '{"1": "낮잠을 자지 않는 것은 밤에 잠을 이루는 데 도움이 됩니다.", "2": "낮 시간에 산책이나 운동을 하는 것은 자연스러운 피로를 유도하여 수면에 좋습니다.\n[정답]", "3": "저녁 운동 후 시원한 녹차를 마시는 것은 카페인의 영향을 줄 수 있어 수면에 방해가 될 수 있습니다.", "4": "침실의 온도를 적절하게 유지하는 것은 수면의 질을 높이는 데 중요합니다.", "5": "매일 일정한 시간에 일어나고 잠자리에 드는 것은 생체 리듬을 유지하는 데 도움이 됩니다."}'::jsonb, '[{"term_ko": "잠", "term_vi": "Giấc ngủ", "def_ko": "잠(한국어)", "def_vi": "ngủ"}, {"term_ko": "생활습관", "term_vi": "Thói quen sinh hoạt", "def_ko": "생활습관(한국어)", "def_vi": "thói quen sinh hoạt"}, {"term_ko": "온도", "term_vi": "Nhiệt độ", "def_ko": "온도(한국어)", "def_vi": "nhiệt độ"}, {"term_ko": "운동", "term_vi": "Tập thể dục", "def_ko": "운동(한국어)", "def_vi": "tập thể dục"}, {"term_ko": "녹차", "term_vi": "Trà xanh", "def_ko": "녹차(한국어)", "def_vi": "trà xanh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1046, '7', '잠들기 어려운 대상자의 수면을 돕는 방법으로 옳은 것은?', '["잠자기 전에 술을 마신다.", "매일 아침 일정한 시간에 일어난다.", "잠들기 전까지 텔레비전을 본다.", "취침 전 집중할 수 있는 일을 한다.", "공복감으로 잠이 안 오는 경우 따뜻한 녹차를 마신다."]'::jsonb, 2, '수면을 돕기 위한 적절한 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "술은 수면 유도에 도움이 될 수 있으나, 수면의 질을 저하시킬 수 있습니다.\n[정답]", "2": "일정한 시간에 일어나는 것은 생체리듬을 조절하는 데 유리합니다.", "3": "취침 전 텔레비전 시청은 수면을 방해할 수 있는 요소입니다.", "4": "취침 전 집중할 수 있는 일은 오히려 정신을 더 활발하게 해 수면을 방해합니다.", "5": "따뜻한 녹차는 이완에 도움이 되지만 카페인이 포함되어 있어 자극이 될 수 있습니다."}'::jsonb, '[{"term_ko": "수면", "term_vi": "Giấc ngủ", "def_ko": "잠(한국어)", "def_vi": "Ngủ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1045, '7', '노화로 인한 수면 양상상의 변화로 옳은 것은?', '["수면시간이 늘어난다.", "쉽게 잠이 든다.", "수면 중에 자주 깬다.", "수면의 질이 향상된다.", "낮잠을 거의 자지 않는다."]'::jsonb, 3, '노화에 따른 수면의 변화와 관련된 지식을 점검하고자 하는 의도입니다.', NULL, '{"1": "노화가 진행됨에 따라 수면 시간은 보통 줄어드는 경향이 있습니다.", "2": "노인은 쉽게 잠이 드는 경향이 있지만, 이 역시 개인차가 클 수 있습니다.\n[정답]", "3": "노화로 인해 수면 중 자주 깰 확률이 높아지는 것이 일반적입니다.", "4": "노화에 따른 수면의 질은 보통 저하되는 경우가 많습니다.", "5": "낮잠을 자는 빈도는 개인마다 다르지만, 노인은 종종 낮잠을 자기도 합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 많은 상태", "def_vi": "Tình trạng có tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1044, '7', '노인 대상자의 운동관리 방법으로 옳은 것은?', '["개인의 신체 능력에 맞는 운동을 한다.", "강도가 높은 운동으로 폐활량을 늘린다.", "준비 운동은 2~3분 이내로 짧게 한다.", "빠른 동작의 운동으로 관절이 굳는 것을 예방한다.", "운동효과를 높이기 위해 운동 중간에 휴식은 생략한다."]'::jsonb, 1, '노인 대상자의 운동 관리 방법을 평가하기 위한 질문입니다.', NULL, '{"1": "개인의 신체 능력에 맞는 운동을 한다. [정답] 이는 안전하고 효과적인 운동 관리 방법입니다.", "2": "강도가 높은 운동으로 폐활량을 늘린다. 이는 노인의 신체 상태에 무리가 될 수 있습니다.", "3": "준비 운동은 2~3분 이내로 짧게 한다. 준비 운동은 충분한 시간이 필요합니다.", "4": "빠른 동작의 운동으로 관절이 굳는 것을 예방한다. 이는 오히려 부상을 초래할 수 있습니다.", "5": "운동효과를 높이기 위해 운동 중간에 휴식은 생략한다. 이는 오히려 건강에 해롭습니다."}'::jsonb, '[{"term_ko": "운동관리", "term_vi": "노인", "def_ko": "관리 luyện tập", "def_vi": "người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1043, '7', '만성질환을 예방하기 위한 노인의 운동방법으로 옳은 것은?', '["최대 심박동수의 80% 수준으로 운동을 시작한다.", "이른 아침이나 밤시간 대에 운동을 한다.", "고강도로 시작하여 저강도 운동으로 마무리 한다.", "현재 복용 중인 약물을 확인한 후 운동하게 한다.", "운동을 모두 마친 후에 휴식시간을 갖는다."]'::jsonb, 4, '노인의 운동 방법과 관련하여 올바른 내용을 선택하도록 하는 문제입니다.', NULL, '{"1": "최대 심박동수의 80% 수준으로 운동을 시작하는 것은 너무 강한 운동일 수 있어 노인에게 적절하지 않습니다.\n[정답]", "4": "현재 복용 중인 약물을 확인한 후 운동하도록 하는 것은 안전한 운동을 위해 필수적입니다.", "2": "이른 아침이나 밤시간 대에 운동하는 것은 개인의 상황에 따라 다를 수 있으나, 좋은 운동 시간은 아닐 수 있습니다.", "3": "고강도로 시작하여 저강도 운동으로 마무리하는 것은 잘못된 접근으로, 노인의 운동 강도는 천천히 조절해야 합니다.", "5": "운동 후에 휴식 시간을 가지는 것은 중요하지만, 운동 방법으로 보기에서는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "만성질환", "term_vi": "Bệnh mãn tính", "def_ko": "만성질환(한국어)", "def_vi": "Bệnh lâu dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1042, '7', '노인 대상자의 운동관리 방법으로 옳은 것은?', '["빠르게 방향을 바꾸는 운동으로 민첩성을 키운다.", "저강도 운동으로 시작하여 서서히 증가시킨다.", "땀복을 입어 운동효과를 높인다.", "마무리 운동은 생략한다.", "휴식ㅇ은 운동을 마친 후 갖는다."]'::jsonb, 2, '노인 대상자의 안전하고 효과적인 운동 관리 방법을 이해하고 있는지를 평가하려는 의도입니다.', NULL, '{"1": "빠르게 방향을 바꾸는 운동은 노인에게 부상의 위험이 높으므로 적합하지 않습니다.\n[정답]", "2": "저강도 운동으로 시작하여 서서히 증가시키는 방법이 가장 안전하고 효과적인 운동 관리 방법입니다.", "3": "땀복을 입는 것은 운동 효과를 높이지 않으며, 오히려 체온 조절에 문제를 일으킬 수 있습니다.", "4": "마무리 운동은 부상의 예방을 위해 반드시 필요합니다.", "5": "휴식은 운동 중에도 필요하며, 운동 후 적절한 휴식을 취하는 것이 중요합니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1041, '7', '노인이 운동을 할 때 힘이 드는 이유는?', '["심장근육의 수축력 증가", "균형 및 조정 능력 증가", "폐활량의 감소", "심근의 두께 감소", "근육피로도 감소"]'::jsonb, 3, '노인이 운동을 할 때 힘이 드는 이유를 이해하는 것.', NULL, '{"1": "심장근육의 수축력이 증가하면 운동 시 더 많은 힘을 낼 수 있어야 한다. 그러나 노인의 경우 오히려 체력 저하가 나타날 수 있다.\n[정답]", "3": "폐활량의 감소는 노인이 운동할 때 힘이 드는 주된 원인 중 하나로, 노화에 따른 폐기능이 저하되기 때문이다.", "2": "균형 및 조정 능력의 증가가 아니라 감소가 나타나기 때문에 운동 시 힘이 더욱 들어지게 된다.", "4": "심근의 두께는 나이에 따라 감소할 수 있지만, 운동력이 줄어드는 주된 요인은 아니다.", "5": "근육 피로도는 노인에게서 증가하는 경향이 있으며, 운동이 더욱 힘들게 느껴지게 하는 요인이다."}'::jsonb, '[{"term_ko": "운동", "term_vi": "Vận động", "def_ko": "뜻(한국어)", "def_vi": "Nghĩa(베트남어)"}, {"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "뜻(한국어)", "def_vi": "Nghĩa(베트남어)"}, {"term_ko": "폐활량", "term_vi": "Dung tích phổi", "def_ko": "뜻(한국어)", "def_vi": "Nghĩa(베트남어)"}, {"term_ko": "심장근육", "term_vi": "Cơ tim", "def_ko": "뜻(한국어)", "def_vi": "Nghĩa(베트남어)"}, {"term_ko": "근육", "term_vi": "Cơ bắp", "def_ko": "뜻(한국어)", "def_vi": "Nghĩa(베트남어)"}, {"term_ko": "체력", "term_vi": "Thể lực", "def_ko": "뜻(한국어)", "def_vi": "Nghĩa(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1040, '7', '노인이 운동을 할 때 힘이 드는 이유는?', '["관절의 운동 범위 증가", "낙상에 대한 두려움 증가", "폐조직의 탄력성 증가", "골밀도 증가", "자극에 대한 반응 증가"]'::jsonb, 2, '노인이 운동을 할 때 힘들어하는 이유를 이해하는 것.', NULL, '{"1": "관절의 운동 범위가 증가했을 때 오히려 운동이 수월해질 수 있다.\n[정답]", "2": "낙상에 대한 두려움이 증가하면 운동을 할 때 힘이 들게 된다.", "3": "폐조직의 탄력성이 증가하는 것은 오히려 도움이 될 수 있다.", "4": "골밀도가 증가하면 힘이 들지 않을 수 있다.", "5": "자극에 대한 반응이 증가하는 것은 운동이 쉬워질 수 있는 요인이다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người già", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1039, '7', '한국인을 위한 식생활 지침으로 옳은 것은?', '["수분섭취를 제한한다.", "간헐적으로 단식을 한다.", "많은 양의 음식을 한꺼번에 준비한다.", "신선한 채소와 과일을 매일 섭취한다.", "단순당이 많은 음식을 선택하여 섭취한다."]'::jsonb, 4, '한국인의 올바른 식생활 습관을 평가하기 위한 질문이다.', NULL, '{"1": "수분섭취를 제한하는 것은 건강에 좋지 않다.\n[정답]", "4": "신선한 채소와 과일을 매일 섭취하는 것은 균형 잡힌 영양을 위한 중요한 요소이다.", "2": "간헐적으로 단식을 하는 것은 개인의 삶의 방식에 따라 다르지만 일반적으로 권장되지 않는다.", "3": "많은 양의 음식을 한꺼번에 준비하는 것은 비효율적이며 균형 잡힌 식사를 방해할 수 있다.", "5": "단순당이 많은 음식을 선택하여 섭취하는 것은 건강에 해롭다."}'::jsonb, '[{"term_ko": "식생활", "term_vi": "지침", "def_ko": "식사의 방식, eating habits", "def_vi": "지시사항, guideline"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1038, '7', '노인에게 영양 문제가 발생하는 요인으로 옳은 것은?', '["나트륨은 기준 이하 부족하게 섭취한다.", "전체 섭취량 중 탄수화물의 비중이 높다.", "비타민 A, C, D를 필요량보다 많이 섭취한다.", "75세 이상 고령자 중 에너지 과다 섭취가 많다.", "소득 수준이 낮은 경우 영양소를 과다 섭취한다."]'::jsonb, 2, '노인의 영양 문제와 관련된 요인을 이해하고 파악하는 것.', NULL, '{"1": "나트륨의 부족한 섭취는 영양 문제의 한 가지 요인이지만, 나트륨의 과다 섭취가 더 많이 문제될 수 있다.\n[정답]", "2": "노인의 경우 탄수화물의 비중이 높아 영양 불균형이 발생할 수 있다.", "3": "비타민 A, C, D를 과다 섭취하는 것은 잘못된 내용으로 영양 문제와는 무관하다.", "4": "75세 이상 고령자의 경우 에너지 과다 섭취는 일반적이지 않다.", "5": "소득 수준이 낮으면 영양소의 섭취가 부족해지는 경우가 많아서 과다 섭취는 잘못된 정보이다."}'::jsonb, '[{"term_ko": "영양", "term_vi": "Dinh dưỡng", "def_ko": "영양(한국어)", "def_vi": "dinh dưỡng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1037, '7', '노인에게 탈수 증상이 쉽게 나타나는 원인은?', '["갈증반응 감소", "타액분비 감소", "염분섭취 증가", "칼슘흡수 증가", "위 소화액 분비 감소"]'::jsonb, 1, '노인에서 탈수 증상이 나타나는 이유를 이해하고, 이를 통해 적절한 예방 및 관리를 할 수 있도록 돕기 위함입니다.', NULL, '{"1": "갈증반응이 감소하여 노인이 탈수 증상이 안 나타나기 쉽다.\n[정답]", "2": "타액 분비 감소가 탈수와 관련이 있지만, 갈증 반응 감소가 더 직접적인 원인이다.", "3": "염분 섭취 증가는 탈수를 유발할 수 있으나, 노인에게 주로 발생하는 갈증 반응 감소가 더 큰 영향을 미친다.", "4": "칼슘 흡수 증가와 탈수의 직접적인 연관은 없다.", "5": "위 소화액 분비 감소는 소화 기능에 영향을 미치지만 탈수와의 직접적인 연관은 미미하다."}'::jsonb, '[{"term_ko": "탈수", "term_vi": "Mất nước", "def_ko": "수분 부족(한국어)", "def_vi": "Thiếu nước"}, {"term_ko": "갈증", "term_vi": "Khát", "def_ko": "물이 마르고 싶어지는 느낌(한국어)", "def_vi": "Cảm giác muốn uống nước"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "반응 또는 응답(한국어)", "def_vi": "Phản ứng hoặc phản hồi"}, {"term_ko": "타액", "term_vi": "Nước bọt", "def_ko": "입에서 나오는 침(한국어)", "def_vi": "Nước trong miệng"}, {"term_ko": "염분", "term_vi": "Muối", "def_ko": "소금과 같은 물질(한국어)", "def_vi": "Chất giống như muối"}, {"term_ko": "칼슘", "term_vi": "Canxi", "def_ko": "뼈에 주요한 무기질(한국어)", "def_vi": "Khoáng chất quan trọng trong xương"}, {"term_ko": "소화액", "term_vi": "Dịch tiêu hóa", "def_ko": "음식을 소화하는 데 필요한 액체(한국어)", "def_vi": "Dịch cần thiết để tiêu hóa thức ăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1036, '6', '영양 문제 발생 위험이 가장 높은 대상자는?', '["보청기를 사용하는 대상자", "배변 활동이 양호한 대상자", "인지기능이 저하된 대상자", "잇몸에 맞는 의치를 낀 대상자", "시력 교정용 안경을 쓴 대상자"]'::jsonb, 3, '대상자의 영양 문제 발생 위험을 평가할 수 있는 능력을 측정하려는 의도입니다.', NULL, '{"1": "보청기를 사용하는 대상자는 영양 문제와 관련이 적습니다.\n[정답]", "3": "인지기능이 저하된 대상자는 식사에 대한 인식이 부족해 영양 문제 발생 위험이 높습니다.", "2": "배변 활동이 양호한 대상자는 영양 문제와 관련이 없습니다.", "4": "잇몸에 맞는 의치를 낀 대상자는 식사를 할 수 있어 영양 문제가 적습니다.", "5": "시력 교정용 안경을 쓴 대상자는 영양 문제와 관련이 적습니다."}'::jsonb, '[{"term_ko": "영양", "term_vi": "Dinh dưỡng", "def_ko": "음식과 그 성분에 대한 정보", "def_vi": "Thông tin về thực phẩm và thành phần của chúng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1035, '7', '노인에게 영양 관련 문제가 발생할 가능성이 높은 이유는?', '["위장 운동 증가", "미각과 후각기능 저하", "소화 및 흡수기능 증가", "인지기능의 증가", "칼슘의 섭취 및 흡수 증가"]'::jsonb, 2, '노인이 겪는 영양 관련 문제의 원인을 이해하고 평가하는 것.', NULL, '{"1": "위장 운동은 보통 저하되므로 영양 문제가 발생하기 쉬움.\n[정답]", "2": "미각과 후각 기능이 저하되면서 음식의 맛을 느끼지 못하고 식욕이 감소할 수 있음.", "3": "소화 및 흡수 기능은 대개 감소함.", "4": "인지 기능이 감소하면 식사 패턴도 변화하게 됨.", "5": "칼슘의 섭취 및 흡수는 나이가 들수록 감소하는 경향이 있음."}'::jsonb, '[{"term_ko": "영양", "term_vi": "Dinh dưỡng", "def_ko": "영양(한국어)", "def_vi": "Dinh dưỡng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1034, '6', '파킨슨병을 치료 및 관리하는 방법으로 옳은 것은?', '["근육 스트레칭을 삼간다.", "관절 운동을 삼간다.", "약물요법을 지속한다.", "단백질 섭취량을 줄인다.", "두뇌활동을 규칙적으로 한다."]'::jsonb, 3, '파킨슨병 치료 및 관리에 대한 올바른 방법을 묻는 문제입니다.', NULL, '{"1": "근육 스트레칭을 삼간다: 근육 스트레칭은 긴장을 풀어주고 운동 기능을 개선하는 데 도움이 됩니다.", "2": "관절 운동을 삼간다: 관절 운동은 유연성을 유지하는 데 중요합니다.\n[정답]", "3": "약물요법을 지속한다: 약물요법은 파킨슨병 관리에 필수적입니다.", "4": "단백질 섭취량을 줄인다: 단백질 섭취는 뇌 건강에 필요합니다.", "5": "두뇌활동을 규칙적으로 한다: 두뇌 활동은 인지 기능 유지를 돕습니다."}'::jsonb, '[{"term_ko": "파킨슨병", "term_vi": "Bệnh Parkinson", "def_ko": "신경계 질환의 일종", "def_vi": "Một loại bệnh về hệ thần kinh"}, {"term_ko": "약물요법", "term_vi": "Liệu pháp thuốc", "def_ko": "약을 사용하는 치료법", "def_vi": "Phương pháp điều trị bằng thuốc"}, {"term_ko": "근육 스트레칭", "term_vi": "Kéo giãn cơ", "def_ko": "근육을 늘리기 위한 운동", "def_vi": "Bài tập để kéo dãn cơ"}, {"term_ko": "관절 운동", "term_vi": "Vận động khớp", "def_ko": "관절을 유연하게 하기 위한 운동", "def_vi": "Bài tập để duy trì độ linh hoạt của khớp"}, {"term_ko": "두뇌활동", "term_vi": "Hoạt động não bộ", "def_ko": "뇌의 기능을 사용하는 모든 활동", "def_vi": "Tất cả các hoạt động sử dụng chức năng của não"}, {"term_ko": "단백질", "term_vi": "Protein", "def_ko": "몸에 필요한 영양소의 일종", "def_vi": "Một loại dinh dưỡng cần thiết cho cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1033, '6', '파킨슨병의 증상으로 옳은 것은?', '["곧은 자세", "행동 빨라짐", "인지능력 증가", "자세 불안정", "얼굴 표정의 변화"]'::jsonb, 4, '파킨슨병의 주요 증상을 이해하고 있는지를 확인하기 위한 문제입니다.', NULL, '{"1": "곧은 자세는 파킨슨병의 증상 중 하나가 아닙니다.\n[정답]", "4": "자세 불안정은 파킨슨병의 전형적인 증상입니다.", "2": "행동 빨라짐은 파킨슨병과 관련이 없습니다.", "3": "인지능력 증가도 파킨슨병의 증상이 아닙니다.", "5": "얼굴 표정의 변화는 발생할 수 있지만, 자세 불안정이 더 전형적입니다."}'::jsonb, '[{"term_ko": "파킨슨병", "term_vi": "Bệnh Parkinson", "def_ko": "신경계 질환으로 운동 기능에 영향을 주는 질병", "def_vi": "Bệnh liên quan đến hệ thần kinh ảnh hưởng đến chức năng vận động"}, {"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "신체의 위치나 상태", "def_vi": "Vị trí hoặc trạng thái của cơ thể"}, {"term_ko": "불안정", "term_vi": "Không ổn định", "def_ko": "안정되지 않음, 불안정한 상태", "def_vi": "Trạng thái không ổn định"}, {"term_ko": "행동", "term_vi": "Hành động", "def_ko": "사람의 의도된 동작", "def_vi": "Hành vi hoặc động tác có ý định của một người"}, {"term_ko": "인지능력", "term_vi": "Khả năng nhận thức", "def_ko": "사고, 이해 및 학습하는 능력", "def_vi": "Khả năng suy nghĩ, hiểu và học hỏi"}, {"term_ko": "표정", "term_vi": "Biểu cảm", "def_ko": "얼굴의 감정을 나타내는 모습", "def_vi": "Diện mạo thể hiện cảm xúc trên khuôn mặt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1032, '6', '파킨슨병에 관한 설명으로 옳은 것은?', '["고혈압이 주된 발병 원인이다.", "도파민이 과잉 분비되어 발생한다.", "안정 시 떨림과 근육경직이 나타난다.", "손상된 쪽 뇌의 반대편 신체에 마비가 온다.", "뇌혈관이 좁아져 혈액의 흐름에 장애가 생겨 발생한다."]'::jsonb, 3, '파킨슨병에 대한 기본적인 이해를 묻는 문제입니다.', NULL, '{"1": "고혈압은 파킨슨병의 주된 발병 원인이 아닙니다.\n[정답]", "3": "파킨슨병은 안정 시 떨림과 근육경직이 나타나는 특징이 있습니다.", "2": "도파민은 부족해져서 발생하는 질병입니다.", "4": "마비는 손상된 쪽 뇌의 같은 편 신체에 주로 나타납니다.", "5": "뇌혈관의 질환은 다른 형태의 신경 질환을 유발할 수 있습니다."}'::jsonb, '[{"term_ko": "파킨슨병", "term_vi": "Bệnh Parkinson", "def_ko": "병의 이름(한국어)", "def_vi": "Tên của bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1031, '6', '도파민 부족으로 동작이 느려지고 안정 시 떨림이 발생하는 질병은?', '["섬망", "고혈압", "파킨슨병", "혈관성 치매", "알츠하이머병"]'::jsonb, 3, '도파민과 관련된 신경계 질환에 대한 이해를 확인하고자 함', NULL, '{"1": "섬망은 주로 정신적인 혼란과 관련된 증상이다.", "2": "고혈압은 혈압 상승과 관련된 상태로 도파민과 직접적인 관련이 없다.\n[정답]", "3": "파킨슨병은 도파민 부족으로 인한 동작의 느려짐과 안정 시 떨림이 발생하는 질병이다.", "4": "혈관성 치매는 뇌혈관 문제로 인한 인지장애고 도파민 부족과는 관련이 적다.", "5": "알츠하이머병은 기억력과 인지 기능에 영향을 주지만 도파민 부족과는 연관성이 낮다."}'::jsonb, '[{"term_ko": "도파민", "term_vi": "Dopamine", "def_ko": "신경전달물질의 일종", "def_vi": "Một loại chất truyền dẫn thần kinh"}, {"term_ko": "동작", "term_vi": "Hành động", "def_ko": "행동을 취하는 것", "def_vi": "Hành động mà ai đó thực hiện"}, {"term_ko": "떨림", "term_vi": "Run", "def_ko": "손이나 몸이 불규칙하게 움직이는 것", "def_vi": "Di chuyển không đều của tay hoặc cơ thể"}, {"term_ko": "질병", "term_vi": "Căn bệnh", "def_ko": "건강에 문제가 있는 상태", "def_vi": "Tình trạng có vấn đề sức khỏe"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1030, '6', '다음과 같은 전구증상이 나타날 때 의심할 수 있는 질환은?• 두통 및 구토, 시각장애 (복시, 시야장애)가 발생한다.• 일어서려고 하면 자꾸 한쪽으로 넘어진다.• 한쪽 팔다리가 마비되거나 감각이 이상하다.•말할 때 발음이 분명치 않거나, 말을 잘 못한다.', '["난청", "빈혈", "고혈압", "뇌졸증", "폐렴"]'::jsonb, 4, '질환에 대한 증상을 통해 정확한 진단을 하는 것이 중요하다는 것을 강조하고자 하는 문제이다.', NULL, '{"1": "난청: 주로 청각과 관련된 증상으로, 구토 및 시각장애와는 관련이 적다.", "2": "빈혈: 피로감이 주요 증상이며, 언어 장애와 관련성이 없다.\n[정답]", "3": "고혈압: 증상으로 보여진 두통과 관련이 있을 수 있으나, 다른 신경학적 증상은 포함되지 않는다.", "4": "뇌졸증: 뇌혈관에 문제가 생겨 발생하며, 제시된 모든 증상이 관련이 있다.", "5": "폐렴: 호흡기 관련 문제로 신경학적 증상과는 거리가 있다."}'::jsonb, '[{"term_ko": "전구증상", "term_vi": "Triệu chứng tiền triệu", "def_ko": "증상이 나타나기 전에 보이는 증상", "def_vi": "Những triệu chứng xuất hiện trước khi có triệu chứng chính"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1029, '6', '현기증, 팔다리 저림, 뒷ㅗㄹ 통증 등의 전구증상이 나타나는 질환은?', '["알츠하이머병", "뇌졸중", "파킨슨병", "섬망", "치매"]'::jsonb, 2, '환자에게 나타날 수 있는 전구증상에 대한 이해를 평가하는 문제입니다.', NULL, '{"1": "알츠하이머병은 주로 기억력 감소와 인지 기능 저하로 나타납니다.\n[정답]", "2": "뇌졸중은 현기증, 팔다리 저림, 통증 등의 전구증상이 나타날 수 있습니다.", "3": "파킨슨병은 운동 장애 및 경직 증상이 주를 이룹니다.", "4": "섬망은 급성 혼돈 상태로, 전구증상과는 다릅니다.", "5": "치매는 인지 기능 저하가 나타나나, 전구증상으로는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "현기증", "term_vi": "Chóng mặt", "def_ko": "어지럼증(한국어)", "def_vi": "Chóng mặt(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1028, '6', '대상자가 음식이나 물을 삼키기 힘들어 하는 증상은?', '["삼킴장애", "오심", "운동 실조증", "다뇨증", "다갈증"]'::jsonb, 1, '대상자가 음식을 삼키기 힘들어 하는 증상을 확인하기 위한 질문입니다.', NULL, '{"1": "삼킴장애: 음식이나 물을 삼키는 데 어려움을 겪는 증상입니다.\n[정답]", "2": "오심: 구역질이 나는 증상으로 삼키기와는 관련이 없습니다.", "3": "운동 실조증: 운동 조정의 문제가 있는 상태로 삼키기와 관계가 없습니다.", "4": "다뇨증: 소변을 많이 보는 상태로 삼킴과는 관련이 없습니다.", "5": "다갈증: 극심한 갈증을 느끼는 상태로 삼키기와는 관계가 없습니다."}'::jsonb, '[{"term_ko": "삼킴장애", "term_vi": "Rối loạn nuốt", "def_ko": "음식이나 물을 삼키는 데 어려움을 겪는 증상", "def_vi": "Triệu chứng gặp khó khăn khi nuốt thức ăn hoặc nước"}, {"term_ko": "오심", "term_vi": "Buồn nôn", "def_ko": "구역질이 나는 증상", "def_vi": "Triệu chứng cảm thấy buồn nôn"}, {"term_ko": "운동 실조증", "term_vi": "Rối loạn phối hợp vận động", "def_ko": "운동 조정의 문제가 있는 상태", "def_vi": "Tình trạng không phối hợp trong vận động"}, {"term_ko": "다뇨증", "term_vi": "Tiểu nhiều", "def_ko": "소변을 많이 보는 상태", "def_vi": "Trạng thái đi tiểu nhiều"}, {"term_ko": "다갈증", "term_vi": "Khát nước dữ dội", "def_ko": "극심한 갈증을 느끼는 상태", "def_vi": "Trạng thái cảm thấy khát nước dữ dội"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1027, '6', '뇌에 혈액을 공급하는 혈관이 막히거나 터졌을 때 나타나는 질환의 증상은?', '["허리 통증", "기침과 객담", "언어장애, 삼킴장애,", "가려움증", "피부 발적"]'::jsonb, 3, '뇌혈관에 문제가 생겼을 때 나타나는 증상을 이해하고 있는지를 확인하기 위한 문제이다.', NULL, '{"1": "허리 통증은 뇌와 관련이 없다.\n[정답]", "3": "언어장애와 삼킴장애는 뇌에 혈액이 공급되지 않아 발생할 수 있는 증상이다.", "2": "기침과 객담은 호흡기 관련 증상이다.", "4": "가려움증은 피부 관련 문제로 뇌와 직접적인 관련이 없다.", "5": "피부 발적도 피부 문제로 뇌와는 관련이 없다."}'::jsonb, '[{"term_ko": "뇌", "term_vi": "혈액", "def_ko": "뇌(한국어) / Não: não", "def_vi": "혈액(한국어) / Máu: máu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1026, '6', '뇌졸중에 대한 설명으로 옳은 것은?', '["도파민의 부족으로 발생한다.", "좌뇌가 손상되면 좌측마비가 발생한다.", "측두엽이 손사되면 술 취한 사람처럼 비틀거린다.", "안정 시 떨림, 무표정한 얼굴이 특징적으로 나타난다.", "한 개의 무렟가 둘로 보이는 전구 증상이 나타난다."]'::jsonb, 5, '뇌졸중의 원인과 증상에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "도파민의 부족은 파킨슨병과 관련이 있으며, 뇌졸중과는 관계가 없습니다.\n[정답]", "5": "한 개의 물체가 둘로 보이는 전구 증상은 뇌졸중의 일부 증상으로 나타날 수 있습니다.", "2": "좌뇌가 손상되면 우측마비가 발생합니다. 좌뇌는 신체 오른쪽을 관장합니다.", "3": "측두엽 손상은 비틀거림을 일으킬 수 있지만, 주로 발음이나 기억력에 영향을 미칩니다.", "4": "안정 시 떨림과 무표정한 얼굴은 파킨슨병의 증상입니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈액 공급이 차단되는 상태", "def_vi": "Tình trạng mất cung cấp máu đến não"}, {"term_ko": "좌뇌", "term_vi": "Bán cầu não trái", "def_ko": "뇌의 왼쪽 반구", "def_vi": "Bán cầu bên trái của não"}, {"term_ko": "마비", "term_vi": "Liệt", "def_ko": "신체의 일부가 움직이지 않는 상태", "def_vi": "Tình trạng không thể vận động một phần cơ thể"}, {"term_ko": "전구", "term_vi": "Đèn báo", "def_ko": "물체의 모양을 왜곡하게 만드는 증상", "def_vi": "Triệu chứng làm biến dạng hình dạng của vật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1025, '6', '뇌졸중 증상 중 운동 실조증에 대한 설명으로 옳은 것은?', '["복시 (한 개의 물체를 보는데 두 개로 보임)", "물건을 잡으려고 할 때 정확하게 잡을 수는 있음", "발음이 어눌해 짐", "음식이나 물을 삼키기 힘들어짐", "술 취한 사람처럼 비틀거리고 한쪽으로 자꾸 쓰러지려함"]'::jsonb, 5, '운동 실조증에 대한 이해를 확인하기 위해 출제된 문제입니다.', NULL, '{"1": "복시는 운동 실조증의 증상이 아닙니다.\n[정답]", "5": "운동 실조증은 비틀거림과 쓰러짐이 특징입니다.", "2": "물건을 정확히 잡지 못하는 것이 운동 실조증의 증상입니다.", "3": "발음이 어눌해지는 것은 언어 장애와 관련됩니다.", "4": "음식이나 물을 삼키기 힘든 것은 연하곤란과 관련됩니다."}'::jsonb, '[{"term_ko": "운동 실조증", "term_vi": "Rối loạn phối hợp vận động", "def_ko": "몸의 움직임을 조절하지 못하는 증상", "def_vi": "triệu chứng không thể điều chỉnh chuyển động của cơ thể"}, {"term_ko": "복시", "term_vi": "Đôi thị", "def_ko": "한 개의 물체를 두 개로 보이는 것", "def_vi": "nhìn thấy một vật thể thành hai"}, {"term_ko": "발음", "term_vi": "Phát âm", "def_ko": "말을 하는 방법", "def_vi": "phương pháp nói"}, {"term_ko": "음식", "term_vi": "Thức ăn", "def_ko": "먹는 것", "def_vi": "món ăn"}, {"term_ko": "삼키기", "term_vi": "Nuốt", "def_ko": "입으로 물리적 물체를 목으로 넘기는 행위", "def_vi": "hành động đưa vật thể vào cổ họng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1024, '6', '소뇌가 손상되어 뇌졸중이 발생했을 때 나타나는 특징적인 증상은?', '["묽은 혈변", "전신성 수포", "관절 부위 통증", "몸의 균형감각 상실", "가슴이 조이는 흉통"]'::jsonb, 4, '소뇌의 기능과 뇌졸중의 증상에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "묽은 혈변은 소화기 계통의 문제로 발생하며, 소뇌와는 관련이 없습니다.", "2": "전신성 수포는 피부 질환과 관련된 증상입니다.", "3": "관절 부위 통증은 소뇌 손상과는 무관합니다.\n[정답]", "4": "몸의 균형감각 상실은 소뇌의 주요 기능 중 하나이며, 손상 시 나타납니다.", "5": "가슴이 조이는 흉통은 심혈관계의 문제로 소뇌와는 직접적인 연관이 없습니다."}'::jsonb, '[{"term_ko": "소뇌", "term_vi": "Tiểu não", "def_ko": "뇌의 일부로 운동协调과 균형을 담당하는 부분", "def_vi": "Phần của não chịu trách nhiệm điều phối vận động và cân bằng"}, {"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈류가 막혀 발생하는 질병", "def_vi": "Bệnh xảy ra khi lưu lượng máu đến não bị tắc nghẽn"}, {"term_ko": "균형감각", "term_vi": "Cảm giác cân bằng", "def_ko": "몸의 균형을 유지하는 감각", "def_vi": "Cảm giác duy trì sự cân bằng của cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1023, '6', '뇌졸중으로 오른쪽 뇌가 손상되었을 때 나타날 수 있는 증상은?', '["왼쪽 팔의 소양증", "왼쪽 다리의 마비", "오른쪽 팔의 감각 저하", "오른쪽 다리의 얼얼한 느낌", "전신마비와 함께 의식 저하"]'::jsonb, 2, '뇌졸중으로 인한 오른쪽 뇌의 손상 시 나타날 수 있는 주요 증상을 이해하는 것이다.', NULL, '{"1": "왼쪽 팔이 간지럽거나 소양증이 나타날 수 있지만 이는 뇌졸중의 전형적인 증상은 아니다.\n[정답]", "2": "뇌졸중으로 오른쪽 뇌가 손상되면 왼쪽 몸의 마비가 나타날 수 있다.", "3": "오른쪽 팔의 감각 저하는 오른쪽 뇌 손상과 관련이 없고 왼쪽 몸의 증상과 관련이 있다.", "4": "오른쪽 다리의 얼얼한 느낌은 오른쪽 뇌 손상과는 관련없다.", "5": "전신마비와 의식 저하는 일반적인 증상이지만, 이는 뇌졸중의 구체적인 증상으로는 적합하지 않다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈액 공급이 차단되어 생기는 질병", "def_vi": "Bệnh xảy ra khi cung cấp máu cho não bị ngăn chặn"}, {"term_ko": "손상", "term_vi": "Tổn thương", "def_ko": "피해를 입거나 해를 입음", "def_vi": "Bị thiệt hại hoặc bị hại"}, {"term_ko": "마비", "term_vi": "Liệt", "def_ko": "신체의 일부 기능을 잃는 것", "def_vi": "Mất chức năng của một phần cơ thể"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병이나 상태에 따라 나타나는 질병의 특징", "def_vi": "Đặc điểm của bệnh hoặc tình trạng theo bệnh tật"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "깨어 있는 능력", "def_vi": "Khả năng tỉnh táo"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1022, '6', '다음의 지시에 따른 대상자의 반응으로 예측할 수 있는 질환은?• "말해 보세요." - 발음이 정확한지 확인한다.• "웃어 보세요." - 입의 좌우 모양이 대칭인지 확인한다.• "걸어 보세요." - 비틀거리고 한쪽으로 쓰러지는지 확인한다.', '["고혈압", "심부전", "뇌졸중", "동맥경화증", "기립성 저혈압"]'::jsonb, 3, '대상자의 반응을 통해 예측할 수 있는 질환을 확인하는 것.', NULL, '{"1": "고혈압은 주로 혈압과 관련된 증상으로 이 문제와 직접적 연관이 없다.", "2": "심부전은 호흡곤란, 부종 등의 증상이 주로 나타나며, 이 지시와는 관련이 없다.\n[정답]", "3": "뇌졸중은 발음, 얼굴의 비대칭, 균형 감각 저하와 같은 증상이 나타나며, 문제의 지시에 가장 적합하다.", "4": "동맥경화증은 주요 심혈관계 질환으로서 이 문제와 관련된 증상과는 차이가 있다.", "5": "기립성 저혈압은 서 있을 때 발생하는 혈압 강하와 주로 관련된 증상으로, 제시된 지시와 일치하지 않는다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 검사를 받는 사람", "def_vi": "Người bệnh hoặc người được kiểm tra"}, {"term_ko": "발음", "term_vi": "Phát âm", "def_ko": "소리를 내는 방식", "def_vi": "Cách phát ra âm thanh"}, {"term_ko": "모양", "term_vi": "Hình dạng", "def_ko": "형태", "def_vi": "Hình thức"}, {"term_ko": "비대칭", "term_vi": "Không đối xứng", "def_ko": "대칭이 아닐 때", "def_vi": "Khi không đối xứng"}, {"term_ko": "비틀거리다", "term_vi": "Chao đảo", "def_ko": "엉망으로 걷다", "def_vi": "Đi lạc thường"}, {"term_ko": "쓰러지다", "term_vi": "Ngã", "def_ko": "넘어지다", "def_vi": "Bị ngã"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1021, '6', '치매 대상자에게 발생할 수 있는 다음과 같은 증상의 질환은?', '["요실금", "섬망", "변실금", "영양실조", "경련"]'::jsonb, 2, '치매 대상자에게 주로 발생할 수 있는 증상을 이해하는 것.', NULL, '{"1": "요실금은 노인성 질환으로 발생할 수 있지만 치매와는 직접적인 관련이 적다.\n[정답]", "2": "섬망은 치매 환자에게 자주 발생하는 상태로, 인지 기능의 급격한 변화가 특징이다.", "3": "변실금은 일부 치매 환자에게 나타날 수 있으나 일반적으로 섬망과 관련된 증상이다.", "4": "영양실조는 다양한 원인으로 발생하지만, 치매 환자에 의해 간접적으로 영향받을 수 있다.", "5": "경련은 갑작스러운 신경학적 상태로, 일시적인 문제일 수 있지만 치매와는 직접적인 연관이 없다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억과 사고 기능에 문제가 생기는 질환", "def_vi": "Bệnh có vấn đề với trí nhớ và tư duy"}, {"term_ko": "섬망", "term_vi": "Rối loạn ý thức", "def_ko": "급성 혼란 상태", "def_vi": "Trạng thái rối loạn cấp tính"}, {"term_ko": "요실금", "term_vi": "Tiểu không kiểm soát", "def_ko": "소변을 제어하지 못하는 상태", "def_vi": "Tình trạng không kiểm soát được tiểu tiện"}, {"term_ko": "영양실조", "term_vi": "Suy dinh dưỡng", "def_ko": "영양소 부족으로 인한 상태", "def_vi": "Tình trạng thiếu chất dinh dưỡng"}, {"term_ko": "경련", "term_vi": "Co giật", "def_ko": "비정상적인 근육 수축", "def_vi": "Co thắt cơ bất thường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1020, '6', '치매의 말기 증상으로 옳은 것은?', '["배회와 같은 정신행동증상이 심해진다.", "시간 이외에 공간도 헷갈리기 시작한다.", "새로 외우는 것이 거의 불가능하다.", "남의 말을 이해하는데 어려움이 생긴다.", "가족의 얼굴을 알아보지 못한다."]'::jsonb, 5, '치매의 말기 증상을 파악하기 위한 질문입니다.', NULL, '{"1": "배회와 같은 정신행동증상이 심해질 수 있으나, 이는 말기의 전반적인 특징이 아닐 수 있습니다.\n[정답]", "5": "가족의 얼굴을 알아보지 못하는 것은 치매의 말기 증상 중 하나입니다.", "2": "시간 이외에 공간도 헷갈리는 증상은 중기 증상일 수 있습니다.", "3": "새로 외우는 것이 거의 불가능한 것은 전반적으로 나타나지만 말기 증상으로 한정할 수 없습니다.", "4": "남의 말을 이해하는 데 어려움이 생기는 것은 초기와 중기의 특징일 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고 능력이 저하되는 질환", "def_vi": "Bệnh giảm khả năng nhớ và suy nghĩ"}, {"term_ko": "배회", "term_vi": "Đi lang thang", "def_ko": "일정한 경로 없이 돌아다니는 행동", "def_vi": "Hành động đi không theo lộ trình nhất định"}, {"term_ko": "정신행동증상", "term_vi": "Triệu chứng hành vi tinh thần", "def_ko": "정신적 행동의 변화", "def_vi": "Thay đổi hành vi tâm lý"}, {"term_ko": "가족", "term_vi": "Gia đình", "def_ko": "혈연으로 연결된 사람들", "def_vi": "Những người có mối liên hệ huyết thống"}, {"term_ko": "얼굴", "term_vi": "Khuôn mặt", "def_ko": "사람의 얼굴", "def_vi": "Khuôn mặt của con người"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1019, '6', '중기 치매 증상으로 옳은 것은?', '["새로운 것을 외우는 것이 어렵다.", "환각, 망상 등의 정신행동증상이 심해진다.", "우울이나 짜증의 증상이 나타나기 시작한다.", "말을 할 때 적절한 단어가 떠오르지 않는다.", "간혹 시간이 헷갈릴 때가 있다."]'::jsonb, 2, '중기 치매의 주요 증상을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "새로운 것을 외우는 것이 어렵다. 중기 치매의 초기 증상일 수 있으나, 명확한 특징은 아닙니다.\n[정답]", "2": "환각, 망상 등의 정신행동증상이 심해진다. 이 증상은 중기 치매에서 흔히 나타나는 증상입니다.", "3": "우울이나 짜증의 증상이 나타나기 시작한다. 이 역시 초기 단계에서 흔히 나타날 수 있습니다.", "4": "말을 할 때 적절한 단어가 떠오르지 않는다. 이는 진행되는 중기나 말기 치매에서 흔하게 나타나는 증상입니다.", "5": "간혹 시간이 헷갈릴 때가 있다. 일반적인 노화 과정에서도 있을 수 있는 증상입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Chứng mất trí nhớ", "def_ko": "기억 또는 사고 능력을 잃어가는 상태(한국어)", "def_vi": "Trạng thái mất khả năng ghi nhớ hoặc tư duy"}, {"term_ko": "중기", "term_vi": "Giai đoạn giữa", "def_ko": "진행 중인 상태(한국어)", "def_vi": "Trạng thái đang diễn ra"}, {"term_ko": "환각", "term_vi": "Ảo giác", "def_ko": "현실과 다른 감각 인식(한국어)", "def_vi": "Nhận thức giác quan khác với thực tế"}, {"term_ko": "망상", "term_vi": "Hoang tưởng", "def_ko": "사실과 다른 믿음이나 생각(한국어)", "def_vi": "Niềm tin hoặc suy nghĩ khác với sự thật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1018, '6', '치매의 초기 증상으로 옳은 것은?', '["시간과 공간이 헷갈린다.", "과거의 기억을 떠올리기 어렵다.", "남의 말을 이해하는데 어려움이 있다.", "간혹 시간이 헷갈릴 때가 있다.", "의사소통이 거의 불가능하다."]'::jsonb, 4, '치매의 초기 증상에 대한 이해를 테스트하는 문제입니다.', NULL, '{"1": "치매 초기에도 시간과 공간 혼동은 나타날 수 있지만, 일부 환자에서만 발생합니다.\n[정답]", "4": "간혹 시간이 헷갈릴 때가 있다는 것은 치매 초기의 일반적인 증상으로, 다양한 사람에게 일어날 수 있습니다.", "2": "과거의 기억을 떠올리기 어렵다는 것은 치매가 어느 정도 진행된 후 나타나는 증상입니다.", "3": "남의 말을 이해하는 능력이 감소하는 것은 치매의 중기 이상의 증상으로 주로 나타납니다.", "5": "의사소통이 거의 불가능하다는 것은 치매의 말기 증상으로, 초기와는 거리가 멉니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고 능력의 감소로 일상 생활에 지장을 주는 신경 퇴행성 질환", "def_vi": "Bệnh thoái hóa thần kinh gây ra sự suy giảm trí nhớ và khả năng suy nghĩ, ảnh hưởng đến cuộc sống hàng ngày"}, {"term_ko": "초기", "term_vi": "Giai đoạn đầu", "def_ko": "사건이 발생하는 시점", "def_vi": "Thời điểm xảy ra sự kiện"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병이나 이상이 나타나는 징후", "def_vi": "Dấu hiệu của bệnh tật hoặc tình trạng bất thường"}, {"term_ko": "기억", "term_vi": "Ký ức", "def_ko": "정보나 경험을 저장하고 회상하는 능력", "def_vi": "Khả năng lưu trữ và hồi tưởng thông tin hoặc kinh nghiệm"}, {"term_ko": "이해", "term_vi": "Hiểu", "def_ko": "상황이나 의미를 명확히 알다", "def_vi": "Biết rõ bối cảnh hoặc ý nghĩa"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통하는 행위", "def_vi": "Hành động giao tiếp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1017, '6', '치매에 관한 설명으로 옳은 것은?', '["시공간을 파악하는 능력은 정상이다.", "뇌의 정상적인 노화 현상이다.", "혈관성 치매 비율이 가장 높다.", "최근 일보다 먼 과거의 일을 잘 기억해 내지 못한다.", "감각 및 운동기관은 정상인데 실행능력기능이 저하된다."]'::jsonb, 5, '치매에 대한 기본적인 이해와 특정 유형의 치매 증상에 대한 인식을 평가하기 위한 문제입니다.', NULL, '{"1": "시공간을 파악하는 능력은 치매 환자들에게 종종 저하됩니다. 따라서 잘못된 설명입니다.", "2": "치매는 단순한 노화 현상이 아닙니다. 퇴행성 및 비퇴행성 뇌 질환입니다. 따라서 잘못된 설명입니다.\n[정답]", "3": "여러 유형의 치매 중 혈관성 치매 비율은 많지만, 알츠하이머형 치매의 비율이 가장 높습니다. 따라서 잘못된 설명입니다.", "4": "치매 환자들은 최근의 일을 기억하기 어려워하고 먼 과거의 일을 더 잘 기억하는 경향이 있습니다. 따라서 잘못된 설명입니다.", "5": "감각 및 운동기관은 정상일 수 있으나, 실행 능력은 저하되는 것이 치매의 주요 증상 중 하나입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "일종의 퇴행성 뇌 질환이자 기억력과 사고력을 저하시키는 상태", "def_vi": "Một loại bệnh thoái hóa não làm suy giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "시공간", "term_vi": null, "def_ko": "시간과 공간", "def_vi": null}, {"term_ko": "혈관성", "term_vi": null, "def_ko": "혈관과 관련된", "def_vi": null}, {"term_ko": "실행능력", "term_vi": null, "def_ko": "일을 계획하고 수행하는 능력", "def_vi": null}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1016, '6', '치매 대상자의 지남력 저하로 인해 나타나는 증상은?', '["물건을 둔 장소를 기억하지 못한다.", "전화 통화 내용을 기억하지 못한다.", "날짜, 요일, 시간을 착각한다.", "대화 중 적절한 단어가 떠오르지 않는다.", "시간이 지나 곰곰이 생각하면 기억이 난다."]'::jsonb, 3, '치매 대상자의 지남력 저하와 관련된 증상을 파악하기 위한 문제입니다.', NULL, '{"1": "물건을 둔 장소를 기억하지 못한다는 것은 주의력, 기억력의 문제를 나타내지만 지남력 저하와는 다소 차이가 있습니다.\n[정답]", "2": "날짜, 요일, 시간을 착각한다는 것은 지남력 저하의 대표적인 증상입니다.", "3": "전화 통화 내용을 기억하지 못하는 것은 단기 기억의 문제로, 지남력과는 다른 증상입니다.", "4": "대화 중 적절한 단어가 떠오르지 않는 것은 언어적 표현의 저하로, 지남력 저하와는 관련이 없습니다.", "5": "시간이 지나 곰곰이 생각하면 기억이 난다는 것은 치매와 관련된 일반적인 기억상실과는 다릅니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력과 판단력의 저하로 인해 발생하는 질병", "def_vi": "Bệnh lý do suy giảm trí nhớ và khả năng phán đoán"}, {"term_ko": "지남력", "term_vi": "Khả năng định hướng", "def_ko": "시간, 장소, 자기를 인식하는 능력", "def_vi": "Khả năng nhận biết thời gian, địa điểm và bản thân"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "특정 질병이나 상태의 징후", "def_vi": "Dấu hiệu của một bệnh hoặc tình trạng cụ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1015, '6', '정상적으로 생활하던 사람이 다양한 원인에 의한 인지기능 장애로, 일상생활을 수행할 수 없게 되는 질환은?', '["뇌졸증", "치매", "고혈압", "당뇨병", "동맥경화"]'::jsonb, 2, '정신적 또는 인지적 기능의 저하가 일상생활에 미치는 영향을 이해하고 관련 질환을 식별하는 것이다.', NULL, '{"1": "뇌졸증은 뇌에 혈액 공급이 중단되어 발생하며, 후유증으로 인지기능 장애가 올 수 있지만 반드시 일상생활을 수행하지 못하게 하지는 않는다.\n[정답]", "2": "치매는 인지기능의 전반적인 저하로 인해 일상생활 수행이 어려워지는 질환이다.", "3": "고혈압은 혈압 상승으로 심혈관계에 영향을 미치나, 인지기능 자체를 직접적으로 제한하지 않는다.", "4": "당뇨병은 주로 혈당 조절과 관련된 질환이며 인지기능 저하와는 직접적으로 관련이 없다.", "5": "동맥경화는 혈관의 경화로 심혈관계 질환의 원인이 될 수 있지만, 인지기능 장애를 유발하는 주된 원인은 아니다."}'::jsonb, '[{"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "정신적 기능(한국어)", "def_vi": "Chức năng tinh thần"}, {"term_ko": "장애", "term_vi": "Khuyết tật", "def_ko": "기능의 제한(한국어)", "def_vi": "Sự hạn chế chức năng"}, {"term_ko": "일상생활", "term_vi": "Cuộc sống hàng ngày", "def_ko": "일상적인 활동(한국어)", "def_vi": "Hoạt động hàng ngày"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병, 질병(한국어)", "def_vi": "Bệnh tật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1014, '5', '다음 설명에 해당하는 질환으로 옳은 것은?종아리 둘레 길이를 재어 간단히 측정할 수 있다. 근력 감소, 보행 능력의 감소를 나타내는 노쇠의 핵심 증상이다.', '["욕창", "낙상", "식욕부진", "근감소증", "수면장애"]'::jsonb, 4, '주어진 설명이 무엇을 의미하는지를 파악하여 올바른 질환을 선택하도록 유도하는 문제입니다.', NULL, '{"1": "욕창: 피부의 상처로, 종아리 둘레와는 관련이 없습니다.", "2": "낙상: 넘어지는 사고로, 근력 감소와 보행 능력의 감소는 관련이 있으나 주된 증상은 아닙니다.", "3": "식욕부진: 식욕의 감소로, 종아리 둘레와는 관련이 없습니다.\n[정답]", "4": "근감소증: 근력 감소, 보행 능력의 감소와 직접 관련이 있습니다.", "5": "수면장애: 수면의 질 문제로, 종아리 둘레와는 관련이 없습니다."}'::jsonb, '[{"term_ko": "종아리", "term_vi": "Bắp chân", "def_ko": "종아리(한국어)", "def_vi": "Bắp chân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1013, '5', '노인증후군의 특징으로 옳은 것은?', '["면역력이 강한 노인들에게 많이 생긴다.", "노인증후군은 노쇠의 과정을 거쳐 회복된다.", "질병의 다발성으로 인한 기능 저하로 발생한다.", "기존의 질병으로 주된 증상을 특정할 수 있다.", "노인의 식욕부진, 변비 등의 증상과는 관계없다."]'::jsonb, 3, '노인증후군의 특징을 이해하고 있는지를 확인하기 위한 문제입니다.', NULL, '{"1": "면역력과는 관련이 적으며, 오히려 면역력이 약한 노인에게 많이 나타납니다.\n[정답]", "3": "질병의 다발성이 기능 저하를 초래하여 노인증후군을 발생시킵니다.", "2": "노인증후군은 회복이 빠르지 않으며, 오히려 증상이 지속되는 경우가 많습니다.", "4": "기존 질병이 있는 경우가 많지만 주된 증상을 특정할 수 없는 경우가 많습니다.", "5": "노인의 식욕부진, 변비 등은 노인증후군의 주요 증상과 밀접한 관계가 있습니다."}'::jsonb, '[{"term_ko": "노인증후군", "term_vi": "Hội chứng người già", "def_ko": "노인에서 나타나는 다양한 증상들의 집합", "def_vi": "Tập hợp các triệu chứng khác nhau xuất hiện ở người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1012, '5', '노인증후군에 대한 설명으로 옳은 것은?', '["의학적 요인에 의해서만 발현된다.", "서로 연관성이 있는 기관에만 발생한다.", "주된 증상이 특정한 병적 상태로 설명된다.", "건강한 노인들에게서 흔히 나타나는 문제이다.", "다약제 복용으로 인한 약물-약물 상호작용이 원인이다."]'::jsonb, 5, '노인증후군에 대한 정확한 이해와 관련된 지식을 평가하기 위해 출제되었습니다.', NULL, '{"1": "노인증후군은 다양한 요인에 의해 발생하므로 의학적 요인만으로 발현되지 않습니다.", "2": "여러 기관의 상호작용으로 발생할 수 있으며, 특정 기관에만 국한되지 않습니다.", "3": "증상은 특정한 병적 상태와 관련이 없을 수 있습니다.\n[정답]", "4": "건강한 노인들에게는 노인증후군이 통상적이지 않으며, 여러 위험 요소가 있지만 건강한 노인에게 자주 나타나지는 않습니다.", "5": "다약제 복용은 노인에서 흔한 문제이며, 약물-약물 상호작용이 노인증후군의 원인 중 하나입니다."}'::jsonb, '[{"term_ko": "노인증후군", "term_vi": "Hội chứng người già", "def_ko": "노인에서 여러 증상이 동시에 나타나는 상태", "def_vi": "Tình trạng có nhiều triệu chứng đồng thời ở người già"}, {"term_ko": "의학적", "term_vi": "Y tế", "def_ko": "의료에 관련된", "def_vi": "Liên quan đến y tế"}, {"term_ko": "병적 상태", "term_vi": "Tình trạng bệnh lý", "def_ko": "특정 병으로 인한 상태", "def_vi": "Tình trạng do bệnh cụ thể gây ra"}, {"term_ko": "건강한", "term_vi": "Khỏe mạnh", "def_ko": "질병이나 문제가 없는 상태", "def_vi": "Tình trạng không có bệnh hoặc vấn đề"}, {"term_ko": "다약제", "term_vi": "Đa dược", "def_ko": "여러 가지 약을 동시에 복용하는 것", "def_vi": "Sử dụng nhiều loại thuốc cùng lúc"}, {"term_ko": "약물-약물 상호작용", "term_vi": "Tương tác thuốc-thuốc", "def_ko": "두 가지 이상의 약물이 서로 영향을 미치는 것", "def_vi": "Ảnh hưởng của hai hoặc nhiều loại thuốc lẫn nhau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1011, '5', '섬망이 있는 치매 대상자가 늦은 밤에 흥부나여 소리 지르며 난동을 피울 때 돕기 방법은?', '["방을 밝고 따뜻하게 해준다.", "흥분이 가라앉을 때까지 그냥 둔다.", "왜 그러는지 이유를 물어본다.", "다른 대상자들 앞에서 야단을 친다.", "진정제를 투약하여 잠을 재운다."]'::jsonb, 1, '섬망이 있는 치매 환자의 행동을 관리하는 방법을 묻는 질문입니다.', NULL, '{"1": "방을 밝고 따뜻하게 해주는 것은 안정감을 주어 환자의 상태를 개선하는 데 효과적입니다.\n[정답]", "2": "흥분이 가라앉을 때까지 그냥 두는 것은 오히려 문제를 악화시킬 수 있습니다.", "3": "왜 그러는지 이유를 물어보는 것은 환자가 정서적으로 불안정할 수 있어 도움이 되지 않습니다.", "4": "다른 대상자들 앞에서 야단을 치는 것은 환자에게 부정적인 영향을 미치고 더욱 혼란을 초래할 수 있습니다.", "5": "진정제를 투약하는 것은 의사의 지시에 따라 필요할 수 있지만, 상시적으로 사용하는 것은 권장되지 않습니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Mê sảng", "def_ko": "정신 혼란 상태", "def_vi": "Tình trạng rối loạn tâm thần"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1010, '5', '섬망 대상자가 초조해 하는 경우 돕는 방법은?', '["가족사진을 치운다.", "가족 방문 횟수를 줄인다.", "대상자의 물건을 다른 곳으로 치운다.", "단호하고 부드러운 목소리로 말한다.", "대상자와 시선을 마주치지 않는다."]'::jsonb, 4, '섬망 상태에 있는 대상자를 효과적으로 도와주기 위한 방법을 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "가족사진을 치우는 것은 대상자의 안정을 도울 수 없으며 오히려 불안감을 증가시킬 수 있습니다.", "2": "가족의 방문 횟수를 줄이는 것은 대상자의 외로움을 느끼게 할 수 있습니다.", "3": "대상자의 물건을 다른 곳으로 치우는 것은 대상자의 혼란을 가중시킬 수 있습니다.\n[정답]", "4": "단호하고 부드러운 목소리로 말하면 대상자에게 안정감을 줄 수 있습니다.", "5": "대상자와 시선을 마주치지 않는 것은 소통을 방해하고 불안감을 증대시킬 수 있습니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Delirium", "def_ko": "의식트래블 및 인지 기능 장애", "def_vi": "Rối loạn ý thức và chức năng nhận thức"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "요양 서비스의 제공을 받는 사람", "def_vi": "Người nhận dịch vụ chăm sóc"}, {"term_ko": "초조하다", "term_vi": "Lo lắng", "def_ko": "불안감이나 긴장 상태에 있다", "def_vi": "Ở trong trạng thái lo âu hoặc căng thẳng"}, {"term_ko": "단호하다", "term_vi": "Kiên quyết", "def_ko": "의견이 확고하다", "def_vi": "Có ý kiến vững vàng"}, {"term_ko": "부드럽다", "term_vi": "Mềm mại", "def_ko": "말이나 행동이 부드럽고 온화하다", "def_vi": "Nói hoặc hành động nhẹ nhàng và hòa nhã"}, {"term_ko": "목소리", "term_vi": "Giọng nói", "def_ko": "사람의 목소리", "def_vi": "Giọng nói của con người"}, {"term_ko": "시선", "term_vi": "Ánh nhìn", "def_ko": "눈의 방향", "def_vi": "Hướng nhìn của đôi mắt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1009, '5', '섬망 치료를 위한 비약물요법 중 개인의 정체성을 유지하는 방법은?', '["혼자 있게 한다.", "새로운 친구를 사귀게 한다.", "가족이 자주 방문하게 한다.", "밤에는 불을 끄고 어둡게 한다.", "많은 사람들을 접촉하게 한다."]'::jsonb, 3, '섬망 치료에 있어 개인의 정체성을 유지하는 방법을 이해하고 적용할 수 있는지를 묻는 질문입니다.', NULL, '{"1": "혼자 있게 한다는 것은 오히려 개인의 정체성을 상실하게 할 수 있습니다.\n[정답]", "3": "가족이 자주 방문하게 하는 것은 개인의 정체성을 유지하는 데 긍정적인 영향을 미칩니다.", "2": "새로운 친구를 사귀는 것은 도움이 될 수 있으나, 개인의 정체성을 중요시하는 데 있어 가족의 역할이 더 큽니다.", "4": "밤에 불을 끄고 어둡게 하는 것은 섬망 증상을 악화시킬 수 있습니다.", "5": "많은 사람들과 접촉하게 하는 것은 혼란을 초래할 수 있으므로 개인의 정체성을 저해할 수 있습니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Rối loạn", "def_ko": "혼란 상태(한국어)", "def_vi": "Tình trạng lẫn lộn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1008, '5', '섬망 증상이 있는 대상자의 지남력을 유지하는 방법은?', '["환경에 변화를 준다.", "달력, 시계 등을 없앤다.", "텔레비전을 크게 틀어 놓는다.", "낮 동안 커튼을 쳐서 빛을 차단한다.", "식사를 제공할 때 시간을 알려준다."]'::jsonb, 5, '섬망 증상이 있는 대상자의 지남력을 유지하는 효과적인 방법을 고르는 것입니다.', NULL, '{"1": "환경에 변화를 주는 것은 오히려 혼란을 초래할 수 있습니다.\n[정답]", "5": "식사 제공 시 시간을 알려주는 것은 지남력 향상에 도움이 됩니다.", "3": "텔레비전을 크게 틀어 놓는 것은 집중을 방해할 수 있습니다.", "4": "낮 동안 커튼을 쳐서 빛을 차단하는 것은 불규칙한 환경을 만들 수 있습니다.", "2": "달력, 시계 등을 없애는 것은 지남력 유지에 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Sảng khoái", "def_ko": "혼란 또는 인지 기능의 장애", "def_vi": "Sự nhầm lẫn hoặc rối loạn chức năng nhận thức"}, {"term_ko": "지남력", "term_vi": "Phương hướng", "def_ko": "사람이나 장소에 대한 인식과 기억", "def_vi": "Nhận thức và ghi nhớ về người hoặc địa điểm"}, {"term_ko": "달력", "term_vi": "Lịch", "def_ko": "날짜를 표시하는 도구", "def_vi": "Công cụ đánh dấu ngày"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식 섭취", "def_vi": "Tiêu thụ thực phẩm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1007, '5', '섬망 증상이 있는 대상자의 지남력을 유지하는 방법은?', '["환경에 변화를 준다.", "달력, 시계 등을 없앤다.", "텔레비전을 크게 틀어 놓는다.", "낮 동안 커튼을 쳐서 빛을 차단한다.", "식사를 제공할 때 시간을 알려준다."]'::jsonb, 5, '섬망 증상이 있는 대상자의 지남력을 유지하기 위한 방법을 묻는 문제입니다.', NULL, '{"1": "환경을 변화시키면 혼란을 가중시킬 수 있어 오히려 지남력 유지에 도움이 되지 않는다.\n[정답]", "5": "식사를 제공할 때 시간을 알려주면 대상자가 시간이 이해되고 지남력을 유지하는 데 도움이 된다.", "2": "달력과 시계는 시간을 알려주는 도구로 지남력 유지에 필요하다.", "3": "텔레비전 소음은 혼란을 초래할 수 있으며 도움이 되지 않는다.", "4": "낮 동안의 빛을 차단하면 일주기 리듬에 문제가 생겨 지남력 유지에 방해가 된다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Mê sảng", "def_ko": "정신 혼란 상태", "def_vi": "Trạng thái rối loạn tinh thần"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1006, '5', '섬망에 대한 설명으로 옳은 것은?', '["만성질환이다.", "신체 생리적 변화는 적다.", "주의력이 감소한다.", "증상의 기복이 약하다.", "수면양상이 규칙적이다."]'::jsonb, 3, '섬망에 대한 정확한 이해를 요구하는 문제입니다.', NULL, '{"1": "섬망은 급성 질환으로 만성질환이 아닙니다.\n[정답]", "3": "섬망은 주의력이 감소하는 특징을 가지고 있습니다.", "2": "섬망에서는 신체 생리적 변화가 뚜렷하게 나타날 수 있습니다.", "4": "섬망의 증상은 기복이 심합니다.", "5": "섬망 환자의 수면양상은 불규칙적입니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Delirium", "def_ko": "혼란스러운 정신 상태", "def_vi": "Trạng thái tinh thần hỗn loạn"}, {"term_ko": "주의력", "term_vi": "Sự chú ý", "def_ko": "주의를 기울이는 능력", "def_vi": "Khả năng tập trung"}, {"term_ko": "만성질환", "term_vi": "Bệnh mãn tính", "def_ko": "장기적인 질환", "def_vi": "Bệnh kéo dài"}, {"term_ko": "생리적", "term_vi": "Sinh lý", "def_ko": "생리와 관련된", "def_vi": "Liên quan đến sinh lý"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병이나 상태의 외부적인 표시", "def_vi": "Dấu hiệu bên ngoài của bệnh hoặc trạng thái"}, {"term_ko": "기복", "term_vi": "Biến động", "def_ko": "변동이 심함", "def_vi": "Biến đổi lớn"}, {"term_ko": "수면양상", "term_vi": "Mô hình giấc ngủ", "def_ko": "수면의 패턴", "def_vi": "Mô thức giấc ngủ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1005, '5', '섬망의 증상에 대한 설명으로 옳은 것은?', '["서서히 나타난다.", "회복이 불가능하다.", "의식에 변화가 없다.", "단독으로만 발생한다.", "호전과 악화가 반복된다."]'::jsonb, 5, '섬망의 증상에 대한 올바른 정보를 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "섬망의 증상은 급작스럽게 나타날 수 있습니다.\n[정답]", "5": "섬망은 증상이 호전과 악화를 반복하는 특징이 있습니다.", "2": "섬망은 회복이 가능할 수 있습니다.", "3": "섬망은 의식 변화가 있으므로 이 보기의 설명은 틀립니다.", "4": "섬망은 다양한 원인으로 발생할 수 있으며, 단독으로 발생하지 않습니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Mê sảng", "def_ko": "의식의 변화가 있는 상태", "def_vi": "Trạng thái có sự thay đổi ý thức"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병의 징후", "def_vi": "Dấu hiệu của bệnh"}, {"term_ko": "호전", "term_vi": "Cải thiện", "def_ko": "증상이 나아짐", "def_vi": "Sự phục hồi triệu chứng"}, {"term_ko": "악화", "term_vi": "Xấu đi", "def_ko": "증상이 나빠짐", "def_vi": "Sự xấu đi của triệu chứng"}, {"term_ko": "회복", "term_vi": "Hồi phục", "def_ko": "건강이 회복되는 것", "def_vi": "Việc phục hồi sức khỏe"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1004, '5', '의식장애로 인해 수 시간 내지 수일에 걸쳐 급격하게 발생하여, 증상의 기복이 심하고 인지장애, 정서불안 증세를 보이는 질환은?', '["섬망", "치매", "뇌졸증", "우울증", "파킨슨병"]'::jsonb, 1, '의식장애와 관련된 질환에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "섬망은 의식장애가 급격하게 발생하며 증상의 기복이 심한 특징이 있습니다.\n[정답]", "2": "치매는 일반적으로 진행성이며 급격하게 발생하지 않습니다.", "3": "뇌졸증은 급성 질환이지만, 증상의 기복이 섬망에 비해 덜 심합니다.", "4": "우울증은 정서적 불안을 동伴하지만, 의식장애와는 다릅니다.", "5": "파킨슨병은 주로 운동장애와 관련된 질환입니다."}'::jsonb, '[{"term_ko": "의식장애", "term_vi": "Rối loạn ý thức", "def_ko": "의식을 잃거나 변형된 상태", "def_vi": "Trạng thái thay đổi hoặc mất ý thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1003, '5', '우울증 대상자를 돕는 방법으로 옳은 것은?', '["곧 괜찮아질 것이라고 위로한다.", "햇볕을 쬐며 걷기운동을 하게 한다.", "사회적 활동을 줄이고 혼자 있게 한다.", "항우울제 용량을 늘려야 한다고 말한다.", "감정 표현을 자제시키고 스스로 극복하게 한다."]'::jsonb, 2, '우울증 환자에게 도움을 줄 수 있는 올바른 방법을 묻는 질문입니다.', NULL, '{"1": "곧 괜찮아질 것이라는 위로는 실제 환자의 상태를 무시하는 것으로 도움이 되지 않습니다.\n[정답]", "2": "햇볕을 쬐며 걷기 운동은 기분을 좋게 하고 우울증을 완화하는 데 도움이 됩니다.", "3": "사회적 활동을 줄이고 혼자 있게 하는 것은 우울증을 악화시킬 수 있습니다.", "4": "항우울제 용량을 늘려야 한다는 권장은 의료 전문가가 해야 할 일입니다.", "5": "감정 표현을 자제시키고 스스로 극복하게 하는 것은 환자에게 부정적인 영향을 미칠 수 있습니다."}'::jsonb, '[{"term_ko": "우울증", "term_vi": "Trầm cảm", "def_ko": "정신적 질병의 일종으로 기분 저하가 주 증상", "def_vi": "Một loại bệnh tâm thần với triệu chứng chính là tâm trạng xuống."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1002, '5', '우울증 발생 가능성이 높은 대상자의 상황은?', '["가족과 함께 살고 이다.", "타인에 대한 관심이 증가한다.", "낮에 햇빛을 쐬며 운동을 한다.", "최근 갑상샘기능저하증을 진단받았다.", "식욕과 체중이 변화 없이 유지되고 있다."]'::jsonb, 4, '우울증의 발생 위험과 관련된 신체적 요인을 이해하고 평가하는 것이 중요하다.', NULL, '{"1": "가족과 함께 사는 것은 정서적 지지로 우울증 발생 가능성을 낮춘다.", "2": "타인에 대한 관심 증가도 긍정적인 변화로 우울증 위험을 낮춘다.", "3": "햇빛을 쬐고 운동을 하는 것은 정신 건강에 긍정적 영향을 미쳐 우울증 발생 가능성을 줄인다.\n[정답]", "4": "갑상샘기능저하증은 우울증과 관련이 있는 신체적 요인으로, 우울증 발생 가능성을 높인다.", "5": "식욕과 체중 변화가 없다는 것은 우울증의 증상이 아닐 수도 있다."}'::jsonb, '[{"term_ko": "우울증", "term_vi": "갑상샘기능저하증", "def_ko": "우울증(Trầm cảm)", "def_vi": "갑상선의 기능 저하( Suy giáp)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1001, '5', '노인에게 나타나는 우울증 특성은?', '["인지기능은 그대로 유지된다.", "무기력과 흥분이 교대로 나타난다.", "본인 스스로 우울증을 자각하기 쉽다.", "주변 사람들이 우울증임을 쉽게 발견한다.", "두통, 소화불량 등 신체 증상을 호소한다."]'::jsonb, 5, '노인 우울증의 특성을 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "인지기능은 유지되지만, 우울증을 앓고 있는 경우 인지능력에 영향을 줄 수 있습니다.\n[정답]", "5": "두통, 소화불량 등 신체 증상을 호소하는 것은 노인 우울증의 일반적인 증상입니다.", "2": "무기력과 흥분이 함께 나타나는 것도 있지만, 이는 일반적인 양상은 아닙니다.", "3": "본인 스스로 자각하기 어려운 경우가 많습니다.", "4": "주변 사람들이 발견하기 어려울 수 있습니다."}'::jsonb, '[{"term_ko": "우울증", "term_vi": "Trầm cảm", "def_ko": "기분이 낮아지며, 흥미나 즐거움이 감소하는 상태", "def_vi": "Tình trạng cảm xúc giảm sút, mất hứng thú hoặc niềm vui"}, {"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "사고, 기억, 인식의 능력", "def_vi": "Khả năng suy nghĩ, ghi nhớ và nhận thức"}, {"term_ko": "신체 증상", "term_vi": "Triệu chứng cơ thể", "def_ko": "병이나 고통으로 인해 나타나는 신체적 징후", "def_vi": "Dấu hiệu vật lý do bệnh tật hoặc đau đớn gây ra"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1000, '5', '대상자가 말수가 줄고 매사에 관심이 없으며, 식욕부진과 함게 수면양상이 변할 때 의심되는 질환은?', '["섬망", "우울증", "치매", "환각", "망상"]'::jsonb, 2, '대상자가 나타내는 증상들 중 우울증과 관련된 내용을 파악하는 것이 중요하다.', NULL, '{"1": "섬망은 주로 혼란과 인지 장애를 동반하므로 이 상황과는 다르다.\n[정답]", "2": "우울증은 말수가 줄고, 관심이 없으며, 식욕부진과 수면 양상 변화가 있는 전형적인 증상이다.", "3": "치매는 인지 기능 저하가 중심이며, 이 경우와는 다르게 진행된다.", "4": "환각은 현실과 다른 감각적 경험을 의미하며, 여기서만의 증상으로는 우울증이라고 보기 어렵다.", "5": "망상은 비현실적인 믿음을 포함하나, 대상자의 증상이 구체적으로 우울증 쪽으로 기울어진다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "어떤 사건의 피해자나 관찰자의 사람", "def_vi": "Người chịu ảnh hưởng của sự kiện hoặc quan sát"}, {"term_ko": "말수", "term_vi": "Lượng lời nói", "def_ko": "대화의 양이나 빈도", "def_vi": "Số lượng hoặc tần suất nói"}, {"term_ko": "관심", "term_vi": "Sự quan tâm", "def_ko": "어떤 일에 대한 주의나 흥미", "def_vi": "Sự chú ý hoặc hứng thú với một điều gì đó"}, {"term_ko": "식욕부진", "term_vi": "Giảm cảm giác thèm ăn", "def_ko": "음식에 대한 욕구 감소", "def_vi": "Giảm nhu cầu ăn uống"}, {"term_ko": "수면양상", "term_vi": "Mô hình giấc ngủ", "def_ko": "수면의 특징이나 패턴", "def_vi": "Đặc điểm hoặc cách thức của giấc ngủ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (999, '5', '당뇨병 관리에 관한 설명으로 옳은 것은?', '["격렬한 운동으로 열량을 소비한다.", "혈당 조절을 위해 공복 시에만 운동한다.", "발의 상처 유무를 주의 깊게 관찰한다.", "혈당 조절을 위해 탄수화물 섭취를 금한다.", "운동량이 많은 날은 인슐린 투여량을 늘린다."]'::jsonb, 3, '당뇨병 관리에 대한 올바른 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "격렬한 운동은 당뇨병 환자에게 위험할 수 있으며, 적절한 운동을 권장합니다.\n[정답]", "3": "당뇨병 환자는 발에 상처가 생기기 쉬우므로 정기적으로 관찰하고 관리해야 합니다.", "2": "공복 시에만 운동하는 것은 혈당 조절에 도움이 되지 않습니다.", "4": "탄수화물은 에너지 공급원으로 필요하며, 적절한 섭취가 중요합니다.", "5": "운동량이 많은 날은 인슐린 투여량 조절이 필요하지만 무조건 늘리는 것은 아닙니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "당을 제대로 조절하지 못해 발생하는 질병", "def_vi": "Bệnh do không kiểm soát được lượng đường"}, {"term_ko": "격렬한 운동", "term_vi": "Tập thể dục mạnh", "def_ko": "신체적으로 힘든 활동", "def_vi": "Hoạt động thể chất căng thẳng"}, {"term_ko": "혈당", "term_vi": "Lượng đường trong máu", "def_ko": "혈액 속에 있는 포도당의 양", "def_vi": "Lượng glucose trong máu"}, {"term_ko": "탄수화물", "term_vi": "Carbohydrate", "def_ko": "질병을 예방하고 치료하는 데 중요한 영양소", "def_vi": "Chất dinh dưỡng quan trọng trong việc phòng ngừa và điều trị bệnh"}, {"term_ko": "인슐린", "term_vi": "Insulin", "def_ko": "혈당을 조절하는 호르몬", "def_vi": "Hormone điều chỉnh lượng đường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (998, '5', '당뇨병 대상자의 발 관리 방법으로 옳은 것은?', '["발톱의 양 끝을 둥글게 자른다.", "뜨거운 물로 발을 자주 씻게 한다.", "손톱깎이로 굳은살과 티눈을 잘라낸다.", "발가락이 노출되지 않게 양말을 신는다.", "발을 씻은 후에 물기는 남겨 습기를 유지한다."]'::jsonb, 4, '당뇨병 환자의 발 관리 방법에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "발톱의 양 끝을 둥글게 자르는 것은 권장되지 않습니다. 발톱은 일자로 자르는 것이 안전합니다.\n[정답]", "4": "발가락이 노출되지 않게 양말을 신는 것은 발을 보호하고 체온을 유지하는데 도움이 됩니다.", "2": "뜨거운 물로 발을 씻는 것은 피부에 손상을 줄 수 있어 바람직하지 않습니다.", "3": "굳은살과 티눈을 손톱깎이로 자르는 것은 감염의 위험이 있으며 전문가에게 맡기는 것이 안전합니다.", "5": "발을 씻은 후 습기를 남기는 것은 세균의 성장에 기여할 수 있어 피해야 합니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "병적 상태로 혈당 조절이 어려운 질환", "def_vi": "Tình trạng bệnh viện không kiểm soát được đường huyết"}, {"term_ko": "발 관리", "term_vi": "Chăm sóc chân", "def_ko": "발의 건강과 위생을 유지하는 방법", "def_vi": "Cách duy trì sức khỏe và vệ sinh của bàn chân"}, {"term_ko": "발톱", "term_vi": "Móng chân", "def_ko": "발끝에 위치한 단단한 표면", "def_vi": "Bề mặt cứng nằm ở đầu ngón chân"}, {"term_ko": "양말", "term_vi": "Tất", "def_ko": "발을 감싸는 의류", "def_vi": "Thời trang bao bọc bàn chân"}, {"term_ko": "굳은살", "term_vi": "Da chết", "def_ko": "피부가 두꺼워진 부분", "def_vi": "Vùng da dày lên"}, {"term_ko": "티눈", "term_vi": "Mụn nước", "def_ko": "발에 생기는 고통스러운 감염", "def_vi": "Nhiễm trùng gây đau ở chân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (997, '5', '당뇨병 대상자에게 권장하는 운동요법으로 옳은 것은?', '["하루에 10분 이내로 운동한다.", "식사 후 30분~60분 경에 운동을 시작한다.", "공복에 운동할 때는 혈당강하제를 갖고 다닌다.", "혈당이 300mg/dl 이상 시 바로 운동을 시작한다.", "약물복용 중에는 치료효과를 얻기 위해 운동을 삼간다."]'::jsonb, 2, '당뇨병 관리에 적합한 운동요법을 이해하고 있는지를 평가하려는 문제입니다.', NULL, '{"1": "하루에 10분 이내로 운동하는 것은 권장되지 않습니다. 운동은 최소 30분 이상이 효과적입니다.\n[정답]", "2": "식사 후 30분~60분 경에 운동을 시작하는 것이 혈당 조절에 좋습니다.", "3": "공복에 운동할 때는 혈당강하제를 갖고 다녀야 하지만, 항상 복용하는 것이 아니라 필요시 사용해야 합니다.", "4": "혈당이 300mg/dl 이상일 때는 운동을 피해야 합니다.", "5": "약물복용 중에도 적절한 운동은 치료효과에 긍정적 영향을 미칩니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "병명(한국어)", "def_vi": "Tên bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (996, '5', '저혈당 증상이 보이는 대상자에게 응급처치를 하지 않았을 때 발생할 수 있는 합병증은?', '["위염", "간 손상", "뇌 손상", "요도염", "방광염"]'::jsonb, 3, '저혈당 증상을 보이는 대상자에게 적절한 응급처치를 하지 않았을 경우 어떤 합병증이 발생할 수 있는지를 묻고 있다.', NULL, '{"1": "위염: 저혈당과 직접적인 관계가 없는 질환이다.\n[정답]", "3": "뇌 손상: 저혈당 상태가 지속되면 뇌에 필요한 포도당이 부족해져 뇌 손상이 발생할 수 있다.", "2": "간 손상: 저혈당과는 관련이 적으며, 주로 간의 대사 기능과 관련이 있다.", "4": "요도염: 저혈당과는 직접적인 연관성이 없다.", "5": "방광염: 방광의 염증으로 저혈당과는 관련이 없다."}'::jsonb, '[{"term_ko": "저혈당", "term_vi": "Hạ đường huyết", "def_ko": "혈당이 정상보다 낮은 상태", "def_vi": "Trạng thái đường huyết thấp hơn bình thường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (995, '5', '당뇨병을 관리하는 방법으로 옳은 것은?', '["맨발로 운동화를 신고 운동한다.", "인슐린주사약을 입으로 복용한다.", "감염이 이는 경우 저혈당에 대비한다.", "일주일에 1회, 최소 30분 이상 운동한다.", "활동량이 증가할 경우 저혈당에 대비한다."]'::jsonb, 5, '당뇨병 관리에 대한 이해를 측정하기 위해 의도된 문제입니다.', NULL, '{"1": "맨발로 운동하면 발에 상처가 생길 위험이 증가합니다.\n[정답]", "5": "활동량이 증가할 경우 저혈당에 대비하는 것은 매우 중요합니다.", "2": "인슐린 주사는 반드시 주사 형태로 투여해야 하며, 입으로 복용할 수 없습니다.", "3": "감염 발생 시 저혈당 대비는 중요하지만, 처음부터 저혈당에 대비하기보다는 상황에 따라 대처해야 합니다.", "4": "운동은 중요하지만 주 1회는 부족하며, 적어도 매일 또는 주 3회 이상 권장됩니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "병명(한국어)", "def_vi": "bệnh lý liên quan đến việc cao đường huyết"}, {"term_ko": "인슐린", "term_vi": "Insulin", "def_ko": "호르몬(한국어)", "def_vi": "hormone điều tiết đường huyết"}, {"term_ko": "저혈당", "term_vi": "Hạ đường huyết", "def_ko": "혈당이 낮은 상태(한국어)", "def_vi": "tình trạng đường huyết thấp"}, {"term_ko": "운동", "term_vi": "Tập thể dục", "def_ko": "신체활동(한국어)", "def_vi": "hoạt động thể chất"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "질병의 원인(한국어)", "def_vi": "nguyên nhân gây bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (994, '5', '인슐린 주사를 맞고 식사를 하지 않은 당뇨병 대상자에게 나타날 수 있는 증상은?', '["식은땀", "소화불량", "체온 상승", "식욕 증가", "소변량 증가"]'::jsonb, 1, '당뇨병과 인슐린의 관계, 인슐린 주사 후 부족한 식사로 인한 저혈당 증상을 이해하기 위함입니다.', NULL, '{"1": "식은땀: 저혈당 시 나타나는 일반적인 증상 중 하나입니다.\n[정답]", "2": "소화불량: 저혈당과는 관련이 적은 증상입니다.", "3": "체온 상승: 저혈당과는 관련이 없습니다.", "4": "식욕 증가: 저혈당 시 보통 반대되는 증상입니다.", "5": "소변량 증가: 당뇨병의 증상 중 하나이나, 저혈당과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "인슐린", "term_vi": "Insulin", "def_ko": "혈당 조절 호르몬", "def_vi": "Hormone điều tiết đường huyết"}, {"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "혈당 조절에 문제가 있는 질환", "def_vi": "Bệnh có vấn đề trong việc điều chỉnh đường huyết"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병이나 상태의 표시", "def_vi": "Những điều hiển thị của bệnh tật hoặc tình trạng"}, {"term_ko": "저혈당", "term_vi": "Hạ đường huyết", "def_ko": "혈당이 비정상적으로 낮은 상태", "def_vi": "Tình trạng đường huyết bất thường thấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (993, '5', '당뇨병의 원인으로 옳은 것은?', '["규칙적인 식사", "고섬유질 음식섭취", "규칙적인 운동", "표준체중", "유전적 요인"]'::jsonb, 5, '당뇨병의 원인을 질문하는 문제로, 다양한 요인이 무엇인지 이해하고 있는지를 평가하려는 의도입니다.', NULL, '{"1": "규칙적인 식사는 건강에 좋지만, 당뇨병의 직접적인 원인은 아닙니다.", "2": "고섬유질 음식섭취는 당뇨병 관리에 도움이 되지만, 원인은 아닙니다.", "3": "규칙적인 운동은 당뇨병 예방에 중요하지만, 원인은 아닙니다.", "4": "표준체중 또한 당뇨병 예방에 중요하나, 직접적인 원인은 아닙니다.\n[정답]", "5": "유전적 요인은 당뇨병 발생에 중요한 역할을 하는 원인 중 하나입니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "병의 상태", "def_vi": "Tình trạng bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (992, '5', '당뇨병의 대표적인 증상으로 옳은 것은?', '["수분 섭취량 감소", "식사량 감소", "질 감염의 감소", "말초 부종 증가", "소변 배설량 증가"]'::jsonb, 5, '당뇨병에 대한 이해와 관련 증상을 파악하기 위한 문제입니다.', NULL, '{"1": "수분 섭취량 감소는 당뇨병의 증상과 관련이 없습니다.", "2": "식사량 감소는 일반적으로 당뇨병의 증상으로 나타나지 않습니다.", "3": "질 감염의 감소는 당뇨병과는 반대되는 내용입니다.", "4": "말초 부종 증가도 당뇨병의 대표적인 증상이 아닙니다.\n[정답]", "5": "소변 배설량 증가는 당뇨병의 대표적인 증상 중 하나입니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "증상", "def_ko": "뜻(한국어) - Bệnh tiểu đường: 뜻(베트남어)", "def_vi": "뜻(한국어) - Triệu chứng: 뜻(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (991, '5', '인슐린이 분비되지 않거나 부족할 경우에 나타나는 질환의 증상으로 옳은 것은?', '["체중 증가", "질 분비물 감소", "식욕 감소", "상처 치유 지연", "성기능 증가"]'::jsonb, 4, '인슐린 부족으로 인한 질환의 증상을 이해하고 확인하는 문제입니다.', NULL, '{"1": "체중 증가는 인슐린 저항성과 관련이 있을 수 있지만, 인슐린 분비 부족의 직접적인 증상은 아닙니다.", "2": "질 분비물 감소는 일반적으로 인슐린과 관계가 없는 증상입니다.", "3": "식욕 감소는 인슐린의 부족으로는 보통 나타나지 않습니다.\n[정답]", "4": "상처 치유 지연은 인슐린 부족으로 인해 발생할 수 있는 증상입니다.", "5": "성기능 증가는 인슐린 부족과 관련이 없습니다."}'::jsonb, '[{"term_ko": "인슐린", "term_vi": "Insulin", "def_ko": "호르몬의 일종, 혈당을 조절하는 역할", "def_vi": "Một loại hormone, có vai trò điều chỉnh lượng đường trong máu"}, {"term_ko": "체중 증가", "term_vi": "Tăng cân", "def_ko": "몸의 무게가 늘어나는 것", "def_vi": "Sự tăng trọng lượng cơ thể"}, {"term_ko": "상처 치유", "term_vi": "Lành vết thương", "def_ko": "부상이 회복되는 과정", "def_vi": "Quá trình phục hồi vết thương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (990, '5', '노화로 인한 내분비계 특성 중 인슐린이 부족한 대상자에게 나타나는 증상으로 옳은 것은?', '["공복혈당 상승", "시력 향상", "체중 증가", "갈증 감소", "성 욕구 증가"]'::jsonb, 1, '노화와 내분비계와 관련하여 인슐린 부족으로 인한 증상을 이해하는 것.', NULL, '{"1": "공복혈당이 상승하는 것은 인슐린 부족으로 인해 당 대사가 제대로 이루어지지 않아 발생한다.\n[정답]", "2": "시력 향상은 인슐린 부족과 관련이 없다.", "3": "체중 증가는 인슐린 부족 시 발생할 수 있으나, 일반적으로 감소가 더 흔하다.", "4": "갈증 감소는 일반적으로 인슐린 부족과 맞지 않으며 오히려 갈증이 증가할 수 있다.", "5": "성 욕구 증가는 인슐린 부족과 관련이 없다."}'::jsonb, '[{"term_ko": "내분비계", "term_vi": "Hệ nội tiết", "def_ko": "내분비 시스템", "def_vi": "Hệ thống tiết hormone"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (989, '5', '노화에 따른 내분비계 특성으로 옳은 것은?', '["포도당 대사능력이 감소된다.", "인슐린에 대한 민감성 증가로 저혈당이 된다.", "갑상선의 크기가 커진다.", "갑상선 호르몬의 분비량이 증가한다.", "기초대사율이 증가한다."]'::jsonb, 1, '노화에 따른 내분비계의 변화를 이해하고, 그에 따른 신체적 특성을 파악하기 위한 문제입니다.', NULL, '{"1": "노화 과정에서 포도당 대사능력이 감소하는 것은 일반적으로 맞는 사실입니다.\n[정답]", "2": "노화와 관련하여 인슐린에 대한 민감성은 감소하는 경향이 있습니다.", "3": "노화가 진행됨에 따라 갑상선의 크기가 줄어드는 경향이 더 많이 관찰됩니다.", "4": "노화에 따라 갑상선 호르몬의 분비량은 보통 감소하는 경향이 있습니다.", "5": "기초대사율은 노화 과정에서 감소하는 경향이 있습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "노화(한국어)", "def_vi": "lão hóa"}, {"term_ko": "내분비계", "term_vi": "Hệ nội tiết", "def_ko": "내분비계(한국어)", "def_vi": "hệ thống tiết hormone"}, {"term_ko": "포도당", "term_vi": "Glucose", "def_ko": "포도당(한국어)", "def_vi": "glucose"}, {"term_ko": "인슐린", "term_vi": "Insulin", "def_ko": "인슐린(한국어)", "def_vi": "insulin"}, {"term_ko": "민감성", "term_vi": "Độ nhạy", "def_ko": "민감성(한국어)", "def_vi": "độ nhạy"}, {"term_ko": "갑상선", "term_vi": "Tuyến giáp", "def_ko": "갑상선(한국어)", "def_vi": "tuyến giáp"}, {"term_ko": "호르몬", "term_vi": "Hormone", "def_ko": "호르몬(한국어)", "def_vi": "hormone"}, {"term_ko": "기초대사율", "term_vi": "Tỷ lệ trao đổi cơ bản", "def_ko": "기초대사율(한국어)", "def_vi": "tỷ lệ trao đổi cơ bản"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (988, '5', '노화로 인한 내분비계 변화로 옳은 것은?', '["뇌하수체가 커진다.", "인슐린 분비량이 늘어난다.", "에스트로겐 분비가 감소한다.", "포도당 대사능력이 좋아진다.", "콜레스테롤 수치가 감소한다."]'::jsonb, 3, '노화와 관련된 내분비계의 변화를 이해하고, 올바른 정보를 판단하도록 유도하는 문제입니다.', NULL, '{"1": "뇌하수체의 크기 변화는 노화에 따라 고정적이지 않으며, 반드시 커지는 것은 아닙니다.\n[정답]", "3": "노화가 진행됨에 따라 에스트로겐의 분비는 감소하게 됩니다.", "2": "인슐린 분비량은 노화와 함께 감소하거나 일정하게 유지되는 경향이 있습니다.", "4": "노화에 따라 포도당 대사능력은 저하되는 경우가 많습니다.", "5": "콜레스테롤 수치는 노화에 따라 증가할 수 있으며, 반드시 감소하는 것은 아닙니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 들어감", "def_vi": "Sự già đi"}, {"term_ko": "내분비계", "term_vi": "Hệ nội tiết", "def_ko": "호르몬을 분비하는 기관의 집합", "def_vi": "Tập hợp các cơ quan tiết hormone"}, {"term_ko": "에스트로겐", "term_vi": "Estrogen", "def_ko": "여성의 성호르몬", "def_vi": "Hormone giới tính nữ"}, {"term_ko": "인슐린", "term_vi": "Insulin", "def_ko": "혈당 조절 호르몬", "def_vi": "Hormone điều chỉnh đường huyết"}, {"term_ko": "콜레스테롤", "term_vi": "Cholesterol", "def_ko": "지방의 일종", "def_vi": "Một loại chất béo"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (987, '5', '노인성 난청이 있는 대상자와 의사소통하는 방법 중 옳은 것은?', '["옆에서 귀에 대고 큰 소리로 말한다.", "소음이 있는 곳에서 대화한다.", "얼굴을 보면서 천천히 또박또박 말한다.", "보청기를 사용 시 고음의 큰 소리가 효과적이다.", "청력을 복구시키기 위해 약물치료를 한다."]'::jsonb, 3, '노인성 난청을 가진 환자와 효과적으로 의사소통하는 방법을 이해하는 것이 중요하다.', NULL, '{"1": "옆에서 귀에 대고 큰 소리로 말하는 것은 불필요한 소음을 유발할 수 있다.\n[정답]", "3": "얼굴을 보면서 천천히 또박또박 말하면 환자가 입 모양을 보고 이해하기 쉽다.", "2": "소음이 있는 곳에서 대화하면 의사소통이 어려워진다.", "4": "보청기를 사용할 때 고음의 큰 소리는 오히려 역효과를 줄 수 있다.", "5": "청력을 복구하기 위한 약물치료는 일반적으로 가능하지 않다."}'::jsonb, '[{"term_ko": "노인성 난청", "term_vi": "Điếc tuổi già", "def_ko": "나이가 들어서 발생하는 청각 손실", "def_vi": "Mất thính giác do tuổi cao"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보를 주고받는 방법", "def_vi": "Cách truyền đạt thông tin"}, {"term_ko": "보청기", "term_vi": "Máy trợ thính", "def_ko": "청각 보조 기구", "def_vi": "Thiết bị hỗ trợ nghe"}, {"term_ko": "소음", "term_vi": "Tiếng ồn", "def_ko": "방해가 되는 소리", "def_vi": "Âm thanh gây cản trở"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (986, '5', '노인성 난청의 중심으로 옳은 것은?', '["고음에서의 난청", "음의 전달 능력 증가", "평형감각의 증가", "언어 구분능력 증가", "소리에 대한 민감성 증가"]'::jsonb, 1, '노인성 난청에 대한 이해를 평가하고, 노인이 경험하는 청각적 특성을 알고 있는지를 확인하고자 한다.', NULL, '{"1": "고음에서의 난청은 노인성 난청에서 일반적으로 나타나는 특징이다.\n[정답]", "2": "음의 전달 능력이 감소하기 때문에 소리의 전달 능력은 증가하지 않는다.", "3": "노인성 난청은 평형감각의 감소를 동반하는 경우가 많다.", "4": "언어 구분 능력은 저하되며, 노인들은 소리의 구분이 어려운 경우가 많다.", "5": "노인성 난청에서는 소리에 대한 민감성이 감소한다."}'::jsonb, '[{"term_ko": "노인성 난청", "term_vi": "Khiếm thính người già", "def_ko": "노인에서 발생하는 청각 장애", "def_vi": "Khiếm thính xảy ra ở người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (985, '5', '노화에 따른 고막, 내이의 퇴행성 변화에 의해 청력이 감소되는 질환은?', '["이석증", "중이염", "노인성 난청", "내이염", "이명"]'::jsonb, 3, '노화에 따른 일반적인 청력 저하의 원인과 관련된 질환에 대한 이해를 평가하고자 함.', NULL, '{"1": "이석증은 귀의 균형 문제와 관련된 질환으로 청력 저하와는 관련이 적다.\n[정답]", "3": "노인성 난청은 노화로 인한 청력 감소를 의미하며, 가장 일반적인 노인들의 청력 장애이다.", "2": "중이염은 주로 염증으로 인한 청력 저하와 관련이 있다.", "4": "내이염은 내이에 염증이 생겨 청력에 영향을 줄 수 있으나 노화와의 직접적인 연관은 적다.", "5": "이명은 소리가 없는데도 귓속에서 소리가 나는 증상으로, 주로 소음 등의 여러 원인으로 발생한다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이 들어감(한국어)", "def_vi": "Sự tăng tuổi"}, {"term_ko": "고막", "term_vi": "Màng nhĩ", "def_ko": "귀 내부의 막(한국어)", "def_vi": "Màng trong tai"}, {"term_ko": "퇴행성", "term_vi": "Thoái hóa", "def_ko": "점진적으로 나빠지는(한국어)", "def_vi": "Xấu đi dần dần"}, {"term_ko": "청력", "term_vi": "Thính lực", "def_ko": "소리를 듣는 능력(한국어)", "def_vi": "Khả năng nghe"}, {"term_ko": "난청", "term_vi": "Điếc", "def_ko": "듣는 능력이 떨어지는 상태(한국어)", "def_vi": "Tình trạng mà khả năng nghe giảm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (984, '5', '고혈압이나 당뇨병 등의 합병증으로 올 수 있는 안과질환은?', '["녹내장", "백내장", "결막염", "망막염", "각막염"]'::jsonb, 2, '고혈압이나 당뇨병과 같은 만성 질환이 안과 질환에 미치는 영향을 질문하는 의도입니다.', NULL, '{"1": "녹내장은 고혈압에 의해 악화될 수 있지만, 직접적인 합병증으로 보기 어렵습니다.\n[정답]", "2": "백내장은 당뇨병과 관련하여 발생할 수 있는 합병증 중 하나입니다.", "3": "결막염은 일반적인 안과 질환으로 만성 질환과 직접적인 연관이 적습니다.", "4": "망막염은 여러 원인으로 발생하지만 고혈압이나 당뇨병의 직접적인 합병증으로 보기 어렵습니다.", "5": "각막염 또한 일반적인 염증으로 만성 질환과의 관련성이 낮습니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "Huyết áp cao", "def_ko": "혈압이 비정상적으로 높은 상태", "def_vi": "Trạng thái áp lực máu bất thường cao"}, {"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "인슐린의 문제로 발생하는 만성 질환", "def_vi": "Bệnh mãn tính do vấn đề về insulin"}, {"term_ko": "합병증", "term_vi": "Biến chứng", "def_ko": "주 질병에서 발생하는 추가적인 문제", "def_vi": "Vấn đề thêm phát sinh từ bệnh chính"}, {"term_ko": "안과질환", "term_vi": "Bệnh mắt", "def_ko": "눈에 관련된 질병", "def_vi": "Bệnh liên quan đến mắt"}, {"term_ko": "녹내장", "term_vi": "Glaucoma", "def_ko": "시신경이 손상되는 질환", "def_vi": "Bệnh tổn thương dây thần kinh thị giác"}, {"term_ko": "백내장", "term_vi": "Đục thủy tinh thể", "def_ko": "수정체가 혼탁해지는 질환", "def_vi": "Bệnh làm mờ thủy tinh thể"}, {"term_ko": "결막염", "term_vi": "Viêm kết mạc", "def_ko": "눈의 결막에 염증이 생긴 상태", "def_vi": "Tình trạng viêm kết mạc mắt"}, {"term_ko": "망막염", "term_vi": "Viêm võng mạc", "def_ko": "망막에 염증이 생기는 질환", "def_vi": "Bệnh gây viêm võng mạc"}, {"term_ko": "각막염", "term_vi": "Viêm giác mạc", "def_ko": "각막에 염증이 생기는 질환", "def_vi": "Bệnh gây viêm giác mạc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (983, '5', '백내장 진단을 받은 대상자에게 나타나는 증상은?', '["좁은 시야", "안구 통증", "어두움 적응장애", "색깔변화 인식장애", "동공의 백색 혼탁"]'::jsonb, 5, '백내장에 관한 기본적인 이해와 증상 인식', NULL, '{"1": "좁은 시야는 일반적으로 녹내장 등의 다른 시각 질환에서 나타나는 증상입니다.", "2": "안구 통증은 백내장과 직접적으로 연결되지 않은 증상입니다.", "3": "어두움 적응장애는 백내장의 증상 중 하나일 수 있지만, 주된 증상은 아닙니다.", "4": "색깔변화 인식장애도 백내장의 증상 중 하나이지만, 주로 백내장으로 인해 가장 두드러지게 나타나는 증상은 아닙니다.\n[정답]", "5": "동공의 백색 혼탁은 백내장을 정확하게 나타내는 주요 증상입니다."}'::jsonb, '[{"term_ko": "백내장", "term_vi": "Đục thủy tinh thể", "def_ko": "안구의 수정체가 혼탁해져 시력이 저하되는 질환", "def_vi": "Bệnh làm mờ mắt do thủy tinh thể bị đục"}, {"term_ko": "동공", "term_vi": "Đồng tử", "def_ko": "안구의 중심부로 빛이 들어오는 구멍", "def_vi": "Lỗ ở giữa mắt cho phép ánh sáng đi vào"}, {"term_ko": "혼탁", "term_vi": "Mờ đục", "def_ko": "명확하지 않거나 흐린 상태", "def_vi": "Trạng thái không rõ ràng hoặc mờ"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병이나 상태가 나타나는 신체적 또는 심리적 이상", "def_vi": "Sự bất thường về thể chất hoặc tinh thần thể hiện cho bệnh hoặc tình trạng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (982, '5', '수정체가 혼탁해져서 뿌옇게 보일 때 나타나는 증상은?', '["두통, 구역질", "눈 이물감", "안구통증", "밝은 불빛에서의 눈부심", "실명"]'::jsonb, 4, '수정체가 혼탁해져서 시각적 변화가 생기는 증상에 대한 이해를 평가하고자 함.', NULL, '{"1": "두통과 구역질은 일반적인 증상이 아닌 혼탁한 수정체와 직접적인 연관이 없음.\n[정답]", "4": "밝은 불빛에서의 눈부심은 수정체 혼탁의 대표적인 증상이다.", "3": "안구통증은 따라올 수 있지만 혼탁과 직접적인 관련은 적다.", "2": "눈 이물감은 증상 중 하나이나 혼탁한 수정체와 명확히 연결되지 않는다.", "5": "실명은 최악의 결과로 추가 증상이 동반되어야 한다."}'::jsonb, '[{"term_ko": "수정체", "term_vi": "Thủy tinh thể", "def_ko": "렌즈(한국어)", "def_vi": "Thấu kính trong mắt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (981, '5', '눈동자에 하얗게 백태가 껴서 잘 안보이게 되는 백내장의 발생 부위는?', '["공막", "각막", "홍채", "황반", "수정체"]'::jsonb, 5, '백내장에 대한 이해를 평가하기 위한 질문입니다.', NULL, '{"1": "공막: 눈의 흰자위를 형성하는 구조로, 백내장이 발생하지 않습니다.\n[정답]", "2": "수정체: 백내장은 수정체에 발생하여 시력을 저하시킵니다.", "3": "홍채: 눈의 색깔을 결정하는 부분이며, 백내장과 직접적인 관련이 없습니다.", "4": "황반: 망막의 중심 부분으로, 백내장과는 관계가 없습니다.", "5": "각막: 눈의 전면에 위치한 투명한 막으로, 백내장과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "백내장", "term_vi": "Đục thủy tinh thể", "def_ko": "수정체가 혼탁해져 시력이 저하되는 질환", "def_vi": "Bệnh làm đục thủy tinh thể gây giảm thị lực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (980, '5', '수정체가 혼탁해져서 빛이 들어가지 못하여 뿌옇게 보이는 질환은?', '["녹내장", "백내장", "결막염", "망막증", "황반변성"]'::jsonb, 2, '수정체의 상태와 관련된 질환을 구분할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "녹내장은 시신경에 손상을 주는 질환으로, 수정체 혼탁과는 관련이 없습니다.\n[정답]", "2": "백내장은 수정체가 혼탁해져서 빛이 통과하지 못해 뿌옇게 보이는 질환입니다.", "3": "결막염은 눈의 결막에 염증이 생기는 질환으로, 수정체와는 관계가 없습니다.", "4": "망막증은 망막에 문제가 생기는 질환으로, 수정체의 혼탁과는 무관합니다.", "5": "황반변성은 망막의 중심부에 영향을 미치는 질환이지 수정체와는 관계가 없습니다."}'::jsonb, '[{"term_ko": "수정체", "term_vi": "Thể thủy tinh", "def_ko": "렌즈(한국어)", "def_vi": "Thủy tinh thể"}, {"term_ko": "혼탁", "term_vi": "Đục", "def_ko": "흐리다(한국어)", "def_vi": "Mờ"}, {"term_ko": "빛", "term_vi": "Ánh sáng", "def_ko": "빛(한국어)", "def_vi": "Ánh sáng"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "질병(한국어)", "def_vi": "Bệnh"}, {"term_ko": "뿌옇게", "term_vi": "Mờ", "def_ko": "흐림(한국어)", "def_vi": "Mờ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (979, '5', '녹내장 대상자의 일상생활 습관으로 옳은 것은?', '["낮 시간에 일광욕을 한다.", "무거운 물건 드는 것을 피한다.", "매일 윗몸일으키기 운동을 한다.", "장시간 고개를 숙이고 책을 본다.", "목이 꽉 조이도록 넥타이를 세게 맨다."]'::jsonb, 2, '녹내장 환자가 일상생활에서 주의해야 할 습관에 대해 묻고 있습니다.', NULL, '{"1": "낮 시간에 일광욕을 한다. - 녹내장 환자는 햇빛이 직접 눈에 들어오는 것을 피하는 것이 좋습니다.\n[정답]", "2": "무거운 물건 드는 것을 피한다. - 무거운 물건을 들면 안압이 상승할 수 있으므로 피하는 것이 바람직합니다.", "3": "매일 윗몸일으키기 운동을 한다. - 윗몸일으키기는 안압을 상승시킬 수 있어 주의해야 합니다.", "4": "장시간 고개를 숙이고 책을 본다. - 고개를 숙이면 안압이 높아질 수 있습니다.", "5": "목이 꽉 조이도록 넥타이를 세게 맨다. - 목을 조이면 혈류 순환에 영향을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "녹내장", "term_vi": "Glaucoma", "def_ko": "안압이 상승하여 시신경 손상으로 이어지는 질환", "def_vi": "Bệnh tăng áp lực mắt"}, {"term_ko": "일상생활", "term_vi": "Sinh hoạt hàng ngày", "def_ko": "매일 반복되는 생활 습관", "def_vi": "Thói quen lặp đi lặp lại hàng ngày"}, {"term_ko": "안압", "term_vi": "Áp lực mắt", "def_ko": "눈 안의 압력", "def_vi": "Áp lực trong mắt"}, {"term_ko": "무거운", "term_vi": "Nặng", "def_ko": "많은 무게를 가진", "def_vi": "Có trọng lượng lớn"}, {"term_ko": "운동", "term_vi": "Tập thể dục", "def_ko": "신체를 움직여 활동하는 것", "def_vi": "Hoạt động cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (978, '5', '다음과 같은 질환을 진단받은 대상자에게 나타나는 증상은?안압의 상승으로 시신경이 손상되어 시력이 점차 약해진다.', '["좁은 시야", "동공의 백색 혼탁", "밝은 불빛에서의 눈부심", "통증 없이 흐린 시력", "불빛 주위에 무지개가 보임"]'::jsonb, 1, '안압이 상승하여 시신경 손상으로 인해 발생하는 증상을 이해하고, 이를 바탕으로 올바른 선택지를 고르도록 유도하는 문제입니다.', NULL, '{"1": "좁은 시야는 시신경 손상으로 나타날 수 있는 증상입니다.\n[정답]", "2": "동공의 백색 혼탁은 시신경 손상과는 관련이 적습니다.", "3": "밝은 불빛에서의 눈부심은 일반적으로 시신경 손상과 관계가 없습니다.", "4": "통증 없이 흐린 시력은 특정 질환에서 나타날 수 있지만, 이 경우 시신경 손상과는 연결되지 않습니다.", "5": "불빛 주위에 무지개가 보이는 증상은 다른 시각 질환과 관련이 있습니다."}'::jsonb, '[{"term_ko": "안압", "term_vi": "Áp lực nội nhãn", "def_ko": "눈 안의 압력", "def_vi": "Áp lực bên trong mắt"}, {"term_ko": "시신경", "term_vi": "Dây thần kinh thị giác", "def_ko": "눈의 신경", "def_vi": "Dây thần kinh của mắt"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병에서 나타나는 표시", "def_vi": "Dấu hiệu xuất hiện trong bệnh tật"}, {"term_ko": "좁은 시야", "term_vi": "Tầm nhìn hẹp", "def_ko": "시야가 제한적인 상태", "def_vi": "Tình trạng nhìn hạn chế"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔", "def_vi": "Cảm giác khó chịu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (977, '5', '다음 증상은 어떠한 질환에 대한 설명인가?좁은 시야, 눈 이물감 뿌옇게 혼탁한 각막, 안구통증, 두통', '["백내장", "녹내장", "결막염", "안구건조증", "다래끼"]'::jsonb, 2, '환자의 증상을 기반으로 해당 질환을 이해하도록 유도하는 문제입니다.', NULL, '{"1": "백내장은 시야가 뿌옇게 보이는 증상을 포함하지만, 주로 시야의 포착과는 관련이 없습니다.\n[정답]", "2": "녹내장은 좁은 시야와 함께 안구통증 등의 증상으로 설명되며, 문제에서 언급된 모든 증상과 잘 연관됩니다.", "3": "결막염은 주로 눈의 충혈과 가려움증과 관련이 있으며, 제시된 증상과는 관련이 적습니다.", "4": "안구건조증은 통증과 불편함은 있지만, 좁은 시야와 관련이 없습니다.", "5": "다래끼는 눈꺼풀에 생기는 염증으로, 위의 증상들과 맞지 않습니다."}'::jsonb, '[{"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증세(한국어)", "def_vi": "triệu chứng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (976, '5', '다음은 노화에 따른 후각, 촉각의 특성이다. 옳은 것은?', '["후각세포가 증가한다.", "후각의 변화가 없다.", "촉각에 의한 접촉감을 쉽게 느낀다.", "통증을 호소하는 정도는 감소한다.", "통증에 둔감한 반응을 보인다."]'::jsonb, 5, '노화에 따른 후각과 촉각의 변화를 이해하고, 이에 대한 올바른 지식을 확인하기 위함입니다.', NULL, '{"1": "후각세포는 노화와 함께 감소합니다.\n[정답]", "5": "노화가 진행되면 통증에 둔감해지는 경향이 있습니다.", "2": "노화로 인해 후각의 변화가 발생합니다.", "3": "촉각에 의한 접촉감이 둔화됩니다.", "4": "통증을 호소하는 정도는 오히려 증가할 수 있습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 많아지는 과정", "def_vi": "Quá trình trở nên lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (975, '5', '노화에 따른 미각의 변화로 옳은 것은?', '["혀의 미뢰개수 증가", "맛의 감지능력 증가", "구강건조 증상 증가", "단맛 감지기능 증가", "구강 점막의 재생 능력 증가"]'::jsonb, 3, '노화가 미각에 미치는 영향을 이해하고 관련된 증상을 파악하는 것을 목표로 한다.', NULL, '{"1": "혀의 미뢰 개수는 노화와 함께 감소한다.\n[정답]", "3": "구강 건조 증상은 노화와 함께 흔히 발생하는 증상이다.", "2": "맛의 감지 능력은 나이가 들면서 감소하는 경향이 있다.", "4": "노화에 따라 단맛 감지 기능은 감소하는 것이 일반적이다.", "5": "구강 점막의 재생 능력도 노화에 따라 감소한다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "미각", "def_ko": "늙음; tuổi tác", "def_vi": "vị giác; vị giác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (974, '5', '노화에 따른 청각의 변화로 옳은 것은?', '["귓바퀴의 연골이 위축된다.", "외이도의 건조증이 감소한다.", "이관이 내측으로 커진다.", "고막이 두꺼워지고 음의 전달 능력이 감소된다.", "노인성 난청은 여성에게 흔하게 나타난다."]'::jsonb, 4, '노화에 따른 청각의 변화에 대한 기본적인 이해를 평가하고자 함.', NULL, '{"1": "귓바퀴의 연골은 노화에 따라 위축되지만 이는 전반적인 변화 중 하나임.\n[정답]", "4": "고막은 노화와 관련하여 두꺼워지고 음의 전달 능력이 감소하는 경향이 있음.", "2": "외이도의 건조증은 노화에 따라 증가하는 경향이 있음.", "3": "이관이 내측으로 커지지 않음.", "5": "노인성 난청은 남성에게 더 흔하게 나타남."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이로 인한 변화", "def_vi": "sự thay đổi do tuổi tác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (973, '5', '노화에 따른 감각기계 변화로 옳은 것은?', '["평형감각이 향상된다.", "통증에 대한 민감성이 증가한다.", "같은 계열의 여러 색을 잘 구별한다.", "노인성 난청이 발생하여 고음을 잘 들을 수 있다.", "동공 지름 감소로 빛을 받아들이지 못해 밝은 곳을 좋아한다."]'::jsonb, 5, '노화와 관련된 감각기계의 변화에 대해 이해하고 있는지를 평가하려는 의도이다.', NULL, '{"1": "평형감각이 향상된다: 노화로 인해 평형감각은 오히려 감소한다.\n[정답]", "5": "동공 지름 감소로 빛을 받아들이지 못해 밝은 곳을 좋아한다: 노화에 따라 동공의 반응이 감소하여 밝은 곳을 선호하게 된다.", "2": "통증에 대한 민감성이 증가한다: 일반적으로 노화로 인해 통증에 대한 민감성이 감소한다.", "3": "같은 계열의 여러 색을 잘 구별한다: 노화로 인해 색 채도가 떨어지며 구별하기 어려운 경우가 많다.", "4": "노인성 난청이 발생하여 고음을 잘 들을 수 있다: 노화에 따라 고음이 잘 들리지 않는 경우가 많다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙어가는 과정", "def_vi": "Quá trình trở nên già"}, {"term_ko": "감각기계", "term_vi": "Hệ thống cảm giác", "def_ko": "감각을 담당하는 기관들", "def_vi": "Các cơ quan chịu trách nhiệm cảm giác"}, {"term_ko": "평형감각", "term_vi": "Cảm giác thăng bằng", "def_ko": "몸의 균형을 감지하는 능력", "def_vi": "Khả năng cảm nhận sự cân bằng của cơ thể"}, {"term_ko": "동공", "term_vi": "Đồng tử", "def_ko": "눈의 중앙에 있는 구멍", "def_vi": "Lỗ ở giữa mắt"}, {"term_ko": "고음", "term_vi": "Âm cao", "def_ko": "높은 주파수의 소리", "def_vi": "Âm thanh có tần số cao"}, {"term_ko": "밝은 곳", "term_vi": "Nơi sáng", "def_ko": "빛이 많이 있는 장소", "def_vi": "Nơi có nhiều ánh sáng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (972, '5', '수정체의 황화현상으로 색의 식별 능력이 떨어진 노인이 구별하기 어려운 색은?', '["빨간색, 노란색", "보라색, 남색", "빨간색, 초록색", "노란색, 남색", "흰색, 회색"]'::jsonb, 2, '노인의 색 인식 능력 저하와 관련된 문제로, 수정체의 황화현상에 따른 색 인식의 어려움을 확인하기 위함입니다.', NULL, '{"1": "빨간색과 노란색은 일반적으로 인식하기 비교적 쉬운 색상입니다.\n[정답]", "2": "보라색과 남색은 특히 노인에게는 인식이 더 어려운 색상입니다.", "3": "빨간색과 초록색은 많은 경우 구별 능력이 유지됩니다.", "4": "노란색과 남색은 평균적으로 잘 구별됩니다.", "5": "흰색과 회색은 밝은 톤이어서 인식에 어려움이 덜합니다."}'::jsonb, '[{"term_ko": "수정체", "term_vi": "Thể thủy tinh", "def_ko": "눈 속의투명한 부분이자 초점을 맞추는 역할을 하는 부분", "def_vi": "Phần trong suốt của mắt có chức năng điều chỉnh tiêu cự."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (971, '5', '노화에 따른 시각의 특성으로 옳은 것은?', '["각막반사의 증가", "눈부심의 감소", "빛 순응의 어려움 증가", "눈물의 양 증가", "가까운 물체에 초점을 맞추는 능력 증가"]'::jsonb, 3, '노화에 따른 시각 변화의 특징을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "각막반사는 노화와 관계없이 유지되므로 옳지 않습니다.", "2": "눈부심은 노화가 진행됨에 따라 증가하므로 옳지 않습니다.\n[정답]", "3": "노화에 따라 빛 순응의 어려움이 증가하는 것이 맞습니다.", "4": "나이가 들면서 눈물의 양은 보통 줄어들어 옳지 않습니다.", "5": "가까운 물체에 초점을 맞추는 능력은 감소하므로 옳지 않습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 많아지는 현상", "def_vi": "Hiện tượng già đi"}, {"term_ko": "시각", "term_vi": "Thị giác", "def_ko": "눈으로 사물을 보는 능력", "def_vi": "Khả năng nhìn thấy sự vật bằng mắt"}, {"term_ko": "각막", "term_vi": "Giác mạc", "def_ko": "눈의 가장 바깥층", "def_vi": "Lớp ngoài cùng của mắt"}, {"term_ko": "눈부심", "term_vi": "Ánh sáng chói", "def_ko": "밝은 빛에 의해 불편함을 느끼는 상태", "def_vi": "Tình trạng cảm thấy khó chịu do ánh sáng chói"}, {"term_ko": "빛 순응", "term_vi": "Thích nghi với ánh sáng", "def_ko": "밝은 환경과 어두운 환경 간의 시각적 적응", "def_vi": "Khả năng thích ứng giữa môi trường sáng và tối"}, {"term_ko": "눈물", "term_vi": "Nước mắt", "def_ko": "눈에서 나오는 액체", "def_vi": "Dịch tiết ra từ mắt"}, {"term_ko": "초점", "term_vi": "Tiêu điểm", "def_ko": "이미지가 맺히는 지점", "def_vi": "Điểm mà hình ảnh được hình thành"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (970, '5', '노화에 따른 신경계의 특성으로 옳은 것은?', '["감각이 예민해진다.", "정서조절이 안정된다.", "균형을 유지하는 능력이 증가한다.", "신경세포의 기능이 증가한다.", "단기 기억이 감퇴한다."]'::jsonb, 5, '노화가 신경계에 미치는 영향을 이해하고, 노화에 따른 변화의 특성을 확인하는 지식을 평가하기 위함입니다.', NULL, '{"1": "감각이 예민해진다. - 노화에 따라 감각 기능은 일반적으로 감소합니다.", "2": "정서조절이 안정된다. - 노화로 인해 정서 표현이나 조절이 다소 변화할 수 있습니다.", "3": "균형을 유지하는 능력이 증가한다. - 노화에 따라 균형 능력은 오히려 감소하는 경향이 있습니다.", "4": "신경세포의 기능이 증가한다. - 노화에 따라 신경세포의 기능은 감소합니다.\n[정답]", "5": "단기 기억이 감퇴한다. - 노화의 일반적인 특성 중 하나로, 단기 기억력이 감퇴하는 것이 사실입니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 들어감", "def_vi": "Quy trình già đi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (969, '5', '장기간의 자외선 노출과 강력한 스테로이드 연고 도포에 의해 출혈이 생기며, 노인학대로 올해받을 수 있는 피부계 질환은?', '["간찰진", "우정문신", "노인성 자반", "지루성 피부염", "기저귀 피부염"]'::jsonb, 3, '노인에게 발생할 수 있는 피부 질환을 중점적으로 이해하도록 유도하는 문제입니다.', NULL, '{"1": "간찰진: 주로 마찰에 의해 발생하는 피부질환이지만, 문제의 원인과 관련성이 약합니다.\n[정답]", "3": "노인성 자반: 노인에게 흔히 발생하며 장기간의 자외선 노출과 스테로이드 연고 사용으로 출혈이 생길 수 있습니다.", "2": "우정문신: 이와 직접적인 연관성이 없는 것으로 고려됩니다.", "4": "지루성 피부염: 주로 지루선 분비물과 관련된 피부질환으로, 문제의 의도와는 거리가 있습니다.", "5": "기저귀 피부염: 주로 아기에게 나타나는 피부질환으로 노인과는 연관성이 없습니다."}'::jsonb, '[{"term_ko": "장기간", "term_vi": "Thời gian dài", "def_ko": "오랜 시간", "def_vi": "Thời gian kéo dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (968, '5', '피부가 접히는 부분에 발생하는 붉은 변화로 마찰, 열, 습윤, 짓무름, 공기순환 부족에 의하여 발생하는 피부계 질환은?', '["간찰진", "우정문신", "노인성 자반", "기저귀 피부염", "지루성 피부염"]'::jsonb, 1, '피부계 질환에 대한 이해를 묻는 문제이다.', NULL, '{"1": "간찰진: 피부가 접히는 부분에서 마찰로 인해 발생하는 피부질환이다.\n[정답]", "2": "우정문신: 피부에 문신을 하는 것으로, 피부 질환과 관련이 없다.", "3": "노인성 자반: 노인에게 발생하는 자반으로, 피부 접힘과는 관련 없다.", "4": "기저귀 피부염: 기저귀 착용으로 인해 발생하는 염증으로 특정한 구간에서만 발생한다.", "5": "지루성 피부염: 피지선의 활동과 관련된 피부질환으로 접히는 부분과는 다른 원인이다."}'::jsonb, '[{"term_ko": "간찰진", "term_vi": "간찰 진", "def_ko": "접히는 피부에서 발생하는 질환(한국어)", "def_vi": "Bệnh lý da xuất hiện ở phần tiếp giáp do ma sát"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "염증의 상태(한국어)", "def_vi": "Trạng thái viêm"}, {"term_ko": "자반", "term_vi": "Bầm tím", "def_ko": "피부에 발생하는 자반 증세(한국어)", "def_vi": "Triệu chứng bầm tím xuất hiện trên da"}, {"term_ko": "지루성", "term_vi": "Bã nhờn", "def_ko": "피지선과 관련된(한국어)", "def_vi": "Liên quan đến tuyến bã nhờn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (967, '5', '피부질환에 대한 설명이 올바르게 연결된 것은?', '["우정문신 - 과도한 자극, 자외선 노출 등에 주의한다.", "간찰진 - 피부가 접히는 부위에 발생하며 감염에 의해 악화된다.", "노인성 자반 - 통풍을 시키고 항진균제나 스테로이드 연고를 바른다.", "지루성 피부염 - 마찰, 열, 습윤에 의하며 통풍과 국소항생제를 바른다.", "피지선의 활동이 많은 부위에 발생하며 흰색 인설이 동반된다."]'::jsonb, 2, '피부질환에 대한 올바른 내용을 알고 있는지를 평가하려는 의도가 있다.', NULL, '{"1": "우정문신 - 과도한 자극, 자외선 노출 등에 주의한다. 이 설명은 우정문신의 관리에 대한 설명이나, 피부질환의 정의와 관련이 없다.\n[정답]", "2": "간찰진 - 피부가 접히는 부위에 발생하며 감염에 의해 악화된다. 간찰진은 발병 부위와 원인을 잘 설명하고 있다.", "3": "노인성 자반 - 통풍을 시키고 항진균제나 스테로이드 연고를 바른다. 노인성 자반에 대한 잘못된 치료 방법으로 설명이 부적절하다.", "4": "지루성 피부염 - 마찰, 열, 습윤에 의하며 통풍과 국소항생제를 바른다. 지루성 피부염에 대한 올바른 설명이 아니다.", "5": "피지선의 활동이 많은 부위에 발생하며 흰색 인설이 동반된다. 이 설명은 정확하지 않다."}'::jsonb, '[{"term_ko": "피부질환", "term_vi": "Bệnh da", "def_ko": "병 về da", "def_vi": "Bệnh về da"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (966, '5', '머릿니에 대한 설명으로 옳은 것은?', '["피부 속에 굴을 뚫어 피부병을 유발한다.", "다른 사람에게 옮기지 않는다.", "빗과 브러쉬는 흐르는 물에 씻어 사용한다.", "모자, 수건 등을 함께 사용해도 된다.", "침구와 옷을 뜨거운 물로 세탁하고 말린다."]'::jsonb, 5, '머릿니의 특성과 전파 방식을 이해하고, 적절한 처리 방법을 알기 위함입니다.', NULL, '{"1": "피부 속에 굴을 뚫어 피부병을 유발한다. - 머릿니는 피부를 뚫고 들어가지는 않지만 가려움증을 유발할 수 있습니다.\n[정답]", "5": "침구와 옷을 뜨거운 물로 세탁하고 말린다. - 머릿니의 전파를 막기 위해서는 이러한 소독이 필요합니다.", "3": "빗과 브러쉬는 흐르는 물에 씻어 사용한다. - 흐르는 물에 씻는 것만으로는 머릿니 완전히 제거할 수 없습니다.", "4": "모자, 수건 등을 함께 사용해도 된다. - 머릿니는 전염성이 있으므로 함께 사용하면 안 됩니다.", "2": "다른 사람에게 옮기지 않는다. - 머릿니는 접촉을 통해 감염될 수 있습니다."}'::jsonb, '[{"term_ko": "머릿니", "term_vi": "Chấy", "def_ko": "두피에 기생하는 작은 곤충", "def_vi": "Côn trùng nhỏ sống trên da đầu"}, {"term_ko": "침구", "term_vi": "Ga trải giường", "def_ko": "잠을 잘 때 사용하는 이불이나 시트", "def_vi": "Vải bọc giường"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "더러움을 없애기 위해 세척하는 것", "def_vi": "Làm sạch để loại bỏ bụi bẩn"}, {"term_ko": "전파", "term_vi": "Lây lan", "def_ko": "한 곳에서 다른 곳으로 이동하는 것", "def_vi": "Di chuyển từ nơi này sang nơi khác"}, {"term_ko": "소독", "term_vi": "Khử trùng", "def_ko": "세균이나 병원균을 죽이는 것", "def_vi": "Giết vi khuẩn hoặc virus"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (965, '5', '다음의 방법으로 관리해야 하는 감염성 질환은?• 처방받은 연고를 밤에 바르고 다음 날 아침에 씻어 낸다.• 사용한 침구류는 뜨거운 물에 세탁 후 3일 이상 사용하지 않는다.• 대상자는 물론 동거 가족이나 요양보호사도 동시에 치료를 받는다.', '["옴", "대상포진", "두드러기", "피부건조증", "알레르기성 피부염"]'::jsonb, 1, '감염성 질환의 관리 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "옴은 피부에 기생하는 진드기로 인해 발생하며, 감염된 사람과의 접촉이나 오염된 침구류를 통해 전파됩니다. 따라서 관리 방법으로 처방받은 연고를 바르고, 침구를 세탁하며, 동거 가족과 함께 치료받는 것이 필수적입니다.\n[정답]", "2": "대상포진은 바이러스에 의해 발생하지만, 위의 관리 방법과는 맞지 않습니다.", "3": "두드러기는 알레르기 반응으로 발생하며, 위의 관리 방법과 관련이 없습니다.", "4": "피부건조증은 일반적인 피부 상태로 특별한 감염성 관리가 필요하지 않습니다.", "5": "알레르기성 피부염은 알레르기로 인해 발생되는 것이며, 감염성 질환이 아닙니다."}'::jsonb, '[{"term_ko": "감염성 질환", "term_vi": "Bệnh truyền nhiễm", "def_ko": "전염 bệnh", "def_vi": "Bệnh lây lan"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (964, '5', '밤에 가려움증이 심해지고 알레르기 증세와 비슷하며 사람에서 사람으로 직접 감염되는 피부계 질환은?', '["옴", "수두", "건조증", "대상포진", "아토피 피부염"]'::jsonb, 1, '피부계 질환 중에서 특정 증세와 감염 경로에 대한 이해를 평가하고자 함.', NULL, '{"1": "옴: 가려움증이 심하며 사람 간 전염되는 피부 질환.\n[정답]", "2": "수두: 가려움증이 있으나 전염 경로가 사람 간 직적 전염이 아닌 공기를 통한 감염이다.", "3": "건조증: 가려움증이 있을 수 있으나 전염성이 없다.", "4": "대상포진: 신경과 관련된 피부 질환으로 감염성이 있으나 나이 든 사람에게 주로 발병한다.", "5": "아토피 피부염: 알레르기 증세를 동반하나 직접적인 감염 전파는 없다."}'::jsonb, '[{"term_ko": "가려움증", "term_vi": "Ngứa", "def_ko": "가려움(한국어)", "def_vi": "Cảm giác ngứa"}, {"term_ko": "알레르기", "term_vi": "Dị ứng", "def_ko": "알레르기(한국어)", "def_vi": "Dị ứng"}, {"term_ko": "피부계", "term_vi": "Hệ da", "def_ko": "피부 관련(한국어)", "def_vi": "Hệ thống liên quan đến da"}, {"term_ko": "감염", "term_vi": "Lây nhiễm", "def_ko": "전염(한국어)", "def_vi": "Lây truyền"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병(한국어)", "def_vi": "Bệnh tật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (963, '5', '다음 중 대상포진에 대한 설명으로 옳은 것은?', '["세균에 의해 감염되는 질환이다.", "가려움이 없는 수포가 발생한다.", "치료 후 신경통이 사라질 때까지 격리한다.", "과거 풍진을 앓았던 사람에게 주로 발생한다.", "작열감을 동반한 수포가 띠 모양으로 나타난다."]'::jsonb, 5, '대상포진의 주요 증상과 발생 원인에 대한 이해를 평가하는 문제입니다.', NULL, '{"1": "세균에 의해 감염되는 질환이 아니다. 대상포진은 바이러스에 의해 발생한다.\n[정답]", "5": "작열감을 동반한 수포가 띠 모양으로 나타나는 것이 특징이다.", "2": "대상포진에 가려움이 없는 수포가 발생하는 것이 아니다. 일반적으로 통증이 동반된다.", "3": "치료 후 신경통이 사라질 때까지 격리할 필요는 없다. 일반적으로 증상이 가벼운 경우 격리할 필요가 없다.", "4": "대상포진은 과거 수두를 앓았던 사람에게 주로 발생한다."}'::jsonb, '[{"term_ko": "대상포진", "term_vi": "Zona", "def_ko": "질병 이름(한국어)", "def_vi": "tên bệnh"}, {"term_ko": "가려움", "term_vi": "Ngứa", "def_ko": "가렵다(한국어)", "def_vi": "ngứa"}, {"term_ko": "수포", "term_vi": "Bọng nước", "def_ko": "물집(한국어)", "def_vi": "bọng nước"}, {"term_ko": "작열감", "term_vi": "Cảm giác nóng rát", "def_ko": "열감(한국어)", "def_vi": "cảm giác nóng rát"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (962, '5', '대상포진에 관한 설명으로 옳은 것은?', '["1~2주면 통증이 없어진다.", "수포가 건조되지 않게 관리한다.", "장기간 스테로이드를 복용해야 한다.", "가려움증이 있는 부위에 온찜질을 적용한다.", "과거에 수두를 앓았던 사람에게서 주로 발생한다."]'::jsonb, 5, '대상포진의 기초 지식과 증상에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "대상포진의 통증은 개인에 따라 다르며, 1~2주 만에 완전히 없어지지 않을 수 있습니다.\n[정답]", "5": "과거에 수두를 앓았던 사람에게서 주로 발생하는 질환입니다.", "2": "수포가 건조되지 않게 관리하는 것은 필요하지 않습니다. 오히려 자연히 건조되도록 하는 것이 중요합니다.", "3": "장기간 스테로이드를 복용하는 것은 대상포진 치료에 적합하지 않습니다.", "4": "가려움증이 있는 부위에 온찜질을 적용하는 것은 오히려 더 자극할 수 있으므로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "대상포진", "term_vi": "Bệnh zona", "def_ko": "수두 바이러스가 재활성화되어 나타나는 질환", "def_vi": "Bệnh xảy ra do virus thủy đậu tái hoạt động"}, {"term_ko": "부위", "term_vi": "Vùng", "def_ko": "특정한 장소", "def_vi": "Địa điểm cụ thể"}, {"term_ko": "수포", "term_vi": "Mụn nước", "def_ko": "물집", "def_vi": "Bọng nước"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔", "def_vi": "Cảm giác đau"}, {"term_ko": "스테로이드", "term_vi": "Steroid", "def_ko": "스테로이드 약물", "def_vi": "Thuốc steroid"}, {"term_ko": "가려움증", "term_vi": "Ngứa", "def_ko": "가려운 느낌", "def_vi": "Cảm giác ngứa"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (961, '5', '노인 대상자가 대상포진에 걸릴 위험성이 높은 원인은?', '["과체중", "피부 건조", "면역력 저하", "혈액순환 장애", "신장기능 저하"]'::jsonb, 3, '노인 대상자의 건강 문제와 관련된 질병 발생 원인을 이해하는 것이다.', NULL, '{"1": "과체중은 여러 건강 문제를 일으킬 수 있지만, 대상포진과의 직접적인 관계는 부족하다.", "2": "피부 건조는 노인에게 흔한 문제이나, 대상포진의 발생 위험과는 무관하다.\n[정답]", "3": "면역력 저하는 노인의 주요 문제이며, 이는 대상포진 발생과 밀접한 관련이 있다.", "4": "혈액순환 장애는 여러 문제를 초래할 수 있지만, 대상포진과의 직접적인 관련은 적다.", "5": "신장기능 저하 역시 노인에게 흔하지만, 대상포진 발생 위험과는 관련이 적다."}'::jsonb, '[{"term_ko": "대상포진", "term_vi": "Bệnh zona", "def_ko": "질병 이름(한국어)", "def_vi": "tên bệnh(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (960, '5', '다음과 같은 증상이 나타나는 질환은?피부와 점막에 있는 감각신경말단 부위의 수포, 통증, 작열감, 가려움', '["욕창", "습진", "건조증", "대상포진", "아토피 피부염"]'::jsonb, 4, '해당 증상에 대한 주의를 환기하고, 관련 질환에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "욕창: 피부가 눌려서 혈액순환이 나빠져 생기는 손상으로, 수포나 작열감과는 차이가 있습니다.", "2": "습진: 가려움증을 동반하지만, 특정 감각신경말단 부위의 수포는 나타나지 않습니다.", "3": "건조증: 수분 부족으로 인한 증상으로, 통증이나 작열감이 동반되기 어려운 경우가 많습니다.\n[정답]", "4": "대상포진: 수포와 함께 통증, 작열감, 가려움이 특징으로, 감각신경 말단에 영향을 미칩니다.", "5": "아토피 피부염: 두드러기처럼 보일 수 있으나, 통증과 작열감이 주된 증상이 아닙니다."}'::jsonb, '[{"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증후(한국어)", "def_vi": "triệu chứng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (959, '5', '피부 건조증이 있는 대상자의 목욕을 돕는 방법으로 옳은 것은?', '["뜨거운 물로 깨끗이 씻어준다.", "때를 불린 뒤 밀어준다.", "자극이 강한 비누를 사용한다.", "목욕 후 수건으로 문지르듯 물기를 닦는다.", "목욕 후 물기가 완전히 마르기 전에 보습제를 바른다."]'::jsonb, 5, '피부 건조증이 있는 대상자에게 적절한 욕탕 방법을 묻고 있습니다.', NULL, '{"1": "뜨거운 물은 피부를 더욱 건조하게 만들 수 있습니다.", "2": "때를 불린 뒤 밀어주는 것은 피부 자극을 줄 수 있는 방법이 아닙니다.", "3": "자극이 강한 비누는 피부 건조증에 도움이 되지 않습니다.", "4": "물기를 문지르듯 닦는 것은 피부에 추가적인 자극을 줄 수 있습니다.\n[정답]", "5": "목욕 후 물기가 완전히 마르기 전에 보습제를 바르는 것은 피부 건조증 관리에 효과적입니다."}'::jsonb, '[{"term_ko": "피부", "term_vi": "Da", "def_ko": "피부(한국어)", "def_vi": "Da(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (958, '5', '노인에게 흔한 피부건조증을 예방하는 방법으로 옳은 것은?', '["수분섭취를 제한한다.", "목욕 후 물기는 그대로 둔다.", "실내습도는 30~40%를 유지한다.", "수시로 때를 문질러 닦는다.", "순한 비누와 보습제를 사용한다."]'::jsonb, 5, '노인의 피부건조증 예방에 대한 기본적인 이해를 평가하기 위함입니다.', NULL, '{"1": "수분 섭취를 제한하는 것은 피부건조증을 악화시킬 수 있습니다.\n[정답]", "5": "순한 비누와 보습제를 사용하면 피부 보호막이 유지되어 피부건조증 예방에 효과적입니다.", "2": "목욕 후 물기를 그대로 두는 것은 피부를 더욱 건조하게 만들 수 있습니다.", "3": "실내습도를 30~40%로 유지하면 다소 도움이 될 수 있지만, 적정 습도는 40~60%가 이상적입니다.", "4": "수시로 때를 문질러 닦는 것은 피부를 손상시킬 수 있습니다."}'::jsonb, '[{"term_ko": "피부건조증", "term_vi": "Bệnh khô da", "def_ko": "피부가 건조해지는 증상", "def_vi": "Triệu chứng da trở nên khô"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 씻는 행위", "def_vi": "Hành động rửa cơ thể"}, {"term_ko": "수분섭취", "term_vi": "Sự tiêu thụ nước", "def_ko": "물을 섭취하는 것", "def_vi": "Việc uống nước"}, {"term_ko": "보습제", "term_vi": "Kem dưỡng ẩm", "def_ko": "피부에 수분을 공급하는 제품", "def_vi": "Sản phẩm cung cấp độ ẩm cho da"}, {"term_ko": "실내습도", "term_vi": "Độ ẩm trong nhà", "def_ko": "실내의 습기 정도", "def_vi": "Mức độ ẩm trong nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (957, '5', '노인 대상자의 피부 건조를 예방하는 방법으로 옳은 것은?', '["겨울철에 제습기를 사용한다.", "알코올이 함유된 피부 보습제를 사용한다.", "뜨거운 물로 매일 샤워한다.", "때를 밀어 피부를 청결하게 한다.", "목욕 후 문지르지 않고 두드려 말린다."]'::jsonb, 5, '노인 대상자의 피부 보호와 관리의 중요성을 이해하고, 피부 건조 예방에 효과적인 방법을 선택하는 것이다.', NULL, '{"1": "겨울철에 제습기를 사용하면 오히려 습도가 낮아져 피부 건조를 악화시킬 수 있다.\n[정답]", "5": "목욕 후 문지르지 않고 두드려 말리면 피부가 수분을 유지하면서도 자극을 최소화할 수 있다.", "2": "알코올이 함유된 피부 보습제는 피부를 더 건조하게 만들 수 있으므로 사용해서는 안 된다.", "3": "뜨거운 물로 매일 샤워하는 것은 피부의 자연 유분을 제거하여 피부 건조를 초래할 수 있다.", "4": "때를 밀어 피부를 청결하게 할 경우 피부 장벽이 손상될 위험이 있다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người lớn tuổi"}, {"term_ko": "피부", "term_vi": "Da", "def_ko": "피부(한국어)", "def_vi": "Da"}, {"term_ko": "건조", "term_vi": "Khô", "def_ko": "건조하다(한국어)", "def_vi": "Khô"}, {"term_ko": "보습제", "term_vi": "Sản phẩm dưỡng ẩm", "def_ko": "보습제(한국어)", "def_vi": "Sản phẩm dưỡng ẩm"}, {"term_ko": "문지르다", "term_vi": "Chà", "def_ko": "문지르다(한국어)", "def_vi": "Chà"}, {"term_ko": "두드리다", "term_vi": "Vỗ", "def_ko": "두드리다(한국어)", "def_vi": "Vỗ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (956, '5', '습도가 낮은 겨울에 피부가 건조해지며 거칠어지고 손과 다리에 가려움증이 발생하는 질환은?', '["옴", "욕창", "건조증", "대상포진", "수두"]'::jsonb, 3, '피부 건강과 관련된 질환에 대한 이해를 테스트하기 위함입니다.', NULL, '{"1": "옴은 기생충에 의한 피부염으로 가려움증이 발생하지만, 주로 전염병의 성격이 강합니다.\n[정답]", "3": "건조증은 겨울철 습도가 낮을 때 피부가 건조해지고 거칠어지는 것을 설명합니다.", "2": "욕창은 장기간 압력이 가해져 피부나 조직이 손상된 상태입니다.", "4": "대상포진은 수두 바이러스에 의해 발생하는 피부 발진이며 주로 신경과 관련이 있습니다.", "5": "수두는 바이러스 감염으로 발생하는 질환으로 가려움증을 동반한 수포가 생깁니다."}'::jsonb, '[{"term_ko": "습도", "term_vi": "Độ ẩm", "def_ko": "습기(수분) 상태", "def_vi": "Trạng thái độ ẩm"}, {"term_ko": "피부", "term_vi": "Da", "def_ko": "인체의 외부 층", "def_vi": "Lớp bên ngoài của cơ thể"}, {"term_ko": "건조증", "term_vi": "Khô da", "def_ko": "수분이 부족하여 피부가 건조한 상태", "def_vi": "Tình trạng da khô do thiếu nước"}, {"term_ko": "가려움증", "term_vi": "Ngứa", "def_ko": "피부가 가렵도록 느끼는 증상", "def_vi": "Triệu chứng cảm thấy ngứa da"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (955, '5', '욕창의 치료 및 예방을 위해 우선적으로 공급해야 하는 영양소는?', '["칼슘", "욕창", "건조증", "대상포진", "수두"]'::jsonb, 3, '욕창 치료 및 예방을 위해서 어떤 영양소가 중요한지를 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "칼슘은 뼈 건강에 중요한 미네랄이지만 욕창 예방과는 직접적인 연관이 없습니다.\n[정답]", "2": "욕창 자체는 질병명이며 영양소가 아닙니다.", "3": "건조증은 피부 상태를 나타내지만 욕창 예방에 필요한 영양소는 아닙니다.", "4": "대상포진은 신경계의 바이러스 감염으로, 욕창 예방과는 관련이 없습니다.", "5": "수두는 바이러스 질환으로, 욕창과는 상관이 없습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부의 손상을 초래하는 상태", "def_vi": "Tình trạng gây tổn thương cho da"}, {"term_ko": "칼슘", "term_vi": "Canxi", "def_ko": "뼈 건강에 필요한 미네랄", "def_vi": "Khoáng chất cần thiết cho sức khỏe xương"}, {"term_ko": "건조증", "term_vi": "Khô da", "def_ko": "피부가 마르고 갈라지는 상태", "def_vi": "Trạng thái da khô và nứt nẻ"}, {"term_ko": "대상포진", "term_vi": "Zona", "def_ko": "신경계의 바이러스 감염", "def_vi": "Nhiễm virus ảnh hưởng đến hệ thần kinh"}, {"term_ko": "수두", "term_vi": "Thủy đậu", "def_ko": "바이러스 질환", "def_vi": "Bệnh nhiễm virus"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (954, '5', '요양보호사의 다음 행동 중 대상자에게 욕창 발생이 우려되는 경우는?', '["천골 부위에 도넛모양의 베개를 대어준다.", "기저귀가 뭉치지 않게 펴서 채워준다.", "목욕 후에 피부를 완전히 말려준다.", "무릎 사이에 베개를 끼운다.", "체위를 자주 변경해준다."]'::jsonb, 1, '대상자의 피부 건강 및 욕창 예방에 관한 이해도를 평가하기 위함입니다.', NULL, '{"1": "천골 부위에 도넛모양의 베개를 대어주는 것은 압력을 분산시켜 욕창을 유발할 수 있습니다. 이는 오히려 욕창 발생 위험을 높입니다.\n[정답]", "2": "기저귀가 뭉치지 않게 펴서 채워주는 것은 피부 마찰을 줄여 욕창을 예방할 수 있는 행동입니다.", "3": "목욕 후에 피부를 완전히 말려주는 것은 피부를 건강하게 유지하는 좋은 방법입니다.", "4": "무릎 사이에 베개를 끼우는 것은 압력을 줄이는 데 도움을 줄 수 있습니다.", "5": "체위를 자주 변경해주는 것은 욕창 예방의 핵심적인 방법입니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "압력이나 마찰로 인해 피부가 상처나는 것", "def_vi": "Vết thương trên da do áp lực hoặc ma sát"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (953, '5', '욕창 예방 방법으로 천골부위에 도넛 모양의 베개를 사용하지 않는 이유는?', '["옷 갈아 입히기가 어렵다.", "천골 부위에 혈액순환이 저하된다.", "피부가 건조해진다.", "체위변경이 어렵다.", "배설물 처리가 어렵다."]'::jsonb, 2, '욕창 예방 방법에 대한 기본 이해와 적용을 묻는 문제입니다.', NULL, '{"1": "옷 갈아 입히기가 어려운 것은 주요 원인이 아닙니다.\n[정답]", "2": "천골 부위에 혈액순환이 저하되어 욕창을 유발할 수 있습니다.", "3": "피부가 건조해지는 것과 직접적인 연관은 없습니다.", "4": "체위변경이 어렵다는 것은 맞지만, 혈액순환 문제보다 덜 중요한 이유입니다.", "5": "배설물 처리가 어려운 것은 이 문제와 직접적인 관련이 없습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét do tì đè", "def_ko": "상처가 생기기 쉬운 부위의 피부가 손상되는 상태", "def_vi": "Tình trạng tổn thương da ở vùng dễ bị thương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (952, '5', '장기간 누워 있는 대상자의 욕창 예방으로 옳은 ㅓㅅ은?', '["두꺼운 이불을 덮어준다.", "피부를 주무르듯이 마사지 한다.", "침대 시트의 주름을 펴준다.", "특정부위에 압력이 가해지도록 눕혀 둔다.", "의자보다는 침대에서 자주 자세를 바꾸어준다."]'::jsonb, 3, '장기간 누워 있는 대상자에게 욕창 예방을 위한 올바른 방법을 묻고 있다.', NULL, '{"1": "두꺼운 이불을 덮어주는 것은 오히려 압력을 증가시켜 욕창 예방에 도움이 되지 않는다.\n[정답]", "3": "침대 시트의 주름을 펴주는 것은 피부에 가해지는 압력을 줄여 욕창 예방에 효과적이다.", "2": "피부를 주무르듯이 마사지하는 것은 피부를 자극할 수 있어 권장되지 않는다.", "4": "특정부위에 압력이 가해지도록 눕혀 두는 것은 욕창을 유발할 수 있다.", "5": "의자보다는 침대에서 자주 자세를 바꾸어 주는 것이 아니라 의자에서 자주 자세를 바꾸어 주는 것이 좋다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부에 상처가 생기는 것(한국어)", "def_vi": "Vết thương hình thành trên da(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (951, '5', '욕창을 예방하는 방법으로 옳은 것은?', '["뜨거운 물주머니를 대준다.", "격일로 피부 상태를 점검한다.", "파우더를 사용하여 피부를 건조하게 한다.", "피부 건조시 찬바람과 뜨거운 바람을 번갈아 사용한다.", "무릎 사이에는 베개를 끼워준다."]'::jsonb, 5, '욕창 예방 방법에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "뜨거운 물주머니를 대주는 것은 피부에 화상을 입힐 수 있어 위험합니다.\n[정답]", "5": "무릎 사이에 베개를 끼워줌으로써 압력을 분산시켜 욕창을 예방할 수 있습니다.", "2": "격일로 피부 상태를 점검하는 것은 바람직하지만, 빈도가 낮아 효과적인 예방이 어려울 수 있습니다.", "3": "파우더를 사용하여 피부를 건조하게 하는 것은 오히려 피부를 더욱 손상시킬 수 있습니다.", "4": "피부 건조시 차가운 바람과 뜨거운 바람을 번갈아 사용하는 것은 피부에 자극이 될 수 있습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Vết loét", "def_ko": "피부에 생긴 궤양(상처)", "def_vi": "Vết thương trên da"}, {"term_ko": "예방", "term_vi": "Ngăn ngừa", "def_ko": "미리 방지하는 것", "def_vi": "Phòng ngừa"}, {"term_ko": "피부", "term_vi": "Da", "def_ko": "인체의 보호 외피", "def_vi": "Lớp bọc bảo vệ cơ thể"}, {"term_ko": "압력", "term_vi": "Áp lực", "def_ko": "물체가 다른 물체에 가하는 힘", "def_vi": "Lực mà một vật tác động lên vật khác"}, {"term_ko": "상태", "term_vi": "Tình trạng", "def_ko": "어떤 형편이나 상황", "def_vi": "Tình huống hay trạng thái"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (950, '5', '욕창이 있는 대상자를 돌보는 방법으로 옳은 것은?', '["얼음 주머니를 대준다.", "천골부위에 도넛 모양의 베개를 사용한다.", "젖은 침대 시트는 바로 교체한다.", "오염물질이 묻은 경우 찬물로 씻고 건조시킨다.", "의자에서는 두 시간마다 자세를 바꾸어준다."]'::jsonb, 3, '욕창이 있는 환자를 돌보는 방법에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "얼음 주머니를 대주는 것은 혈류를 줄여서 조직 손상을 초래할 수 있습니다.\n[정답]", "2": "천골부위에 도넛 모양의 베개를 사용하면 압력을 분산시켜 욕창 예방에 도움이 됩니다.", "3": "젖은 침대 시트는 바로 교체해야 합니다.", "4": "오염물질이 묻은 경우 찬물로 씻고 건조시키는 것보다는 미지근한 물로 씻는 것이 좋습니다.", "5": "의자에서는 두 시간마다 자세를 바꿔주는 것이 맞습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "상처 질환(한국어)", "def_vi": "Bệnh lý vết thương(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (949, '5', '욕창이 있는 대상자를 돕는 방법으로 옳은 것은?', '["대상자가 원하지 않으면 체위변경을 하지 않는다.", "침대에서는 두 시간 마다 체위변경을 한다.", "매트리스와 베개는 딱딱한 것이 좋다.", "지서용 비누로 깨끗이 씻겨준다.", "단추가 달린 바지를 입힌다."]'::jsonb, 2, '욕창 관리에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "대상자가 원하지 않더라도 체위변경은 필수적입니다. 체위변경은 욕창 예방을 위한 중요한 방법입니다.\n[정답]", "2": "욕창을 예방하기 위해 두 시간마다 체위를 변경하는 것이 바람직합니다.", "3": "매트리스와 베개는 부드러운 것이 좋습니다. 딱딱한 것은 오히려 욕창을 유발할 수 있습니다.", "4": "지서용 비누는 피부에 자극을 줄 수 있으므로 부드러운 비누를 사용하는 것이 좋습니다.", "5": "통증을 유발할 수 있는 의복은 피하는 것이 좋습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Vết loét", "def_ko": "피부에 생기는 궤양", "def_vi": "Vết thương xuất hiện trên da"}, {"term_ko": "체위변경", "term_vi": "Thay đổi tư thế", "def_ko": "환자의 자세를 바꾸는 것", "def_vi": "Thay đổi vị trí của bệnh nhân"}, {"term_ko": "매트리스", "term_vi": "Nệm", "def_ko": "침대에 사용하는 쿠션", "def_vi": "Đệm sử dụng trên giường"}, {"term_ko": "부드러운", "term_vi": "Mềm mại", "def_ko": "단단하지 않은, 유연한", "def_vi": "Không cứng, linh hoạt"}, {"term_ko": "지서용 비누", "term_vi": "Xà phòng dùng cho da", "def_ko": "피부에 사용되는 비누", "def_vi": "Xà phòng sử dụng cho da"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (948, '5', '거동이 불편한 대상자의 체위변경을 돕는 방법은?', '["욕창이 있으면 체위변경 횟수를 늘린다.", "딱딱하고 표면이 거친 쿠션을 받쳐 준다.", "파우더를 사용하여 피부가 습하지 않게 한다.", "대상자의 옷을 잡아당겨 체위를 변경한다.", "의자에서는 2시간마다 체위를 바꾸어 준다."]'::jsonb, 1, '체위변경과 관련된 올바른 방법을 이해하고 있는지를 확인하기 위함입니다.', NULL, '{"1": "욕창이 있으면 체위변경 횟수를 늘린다. [정답] 욕창 예방을 위해 체위를 자주 변경하는 것이 중요합니다.", "2": "딱딱하고 표면이 거친 쿠션을 받쳐 준다. 체위변경 시 부드러운 쿠션이 필요합니다.", "3": "파우더를 사용하여 피부가 습하지 않게 한다. 피부를 건조하게 유지하는 것은 중요하지만 바르는 방법에 대한 지식이 필요합니다.", "4": "대상자의 옷을 잡아당겨 체위를 변경한다. 대상자의 피부에 자극을 줄 수 있습니다.", "5": "의자에서는 2시간마다 체위를 바꾸어 준다. 의자에서의 체위변경은 자주 필요하지만, 2시간이라는 시간은 기계적일 수 있습니다."}'::jsonb, '[{"term_ko": "체위변경", "term_vi": "Thay đổi tư thế", "def_ko": "몸의 자세를 바꾸는 것", "def_vi": "Thay đổi vị trí của cơ thể"}, {"term_ko": "욕창", "term_vi": "Loét tì đè", "def_ko": "피부에 생기는 상처", "def_vi": "Vết thương trên da"}, {"term_ko": "쿠션", "term_vi": "Đệm", "def_ko": "편안함을 제공하는 물질", "def_vi": "Vật liệu tạo cảm giác thoải mái"}, {"term_ko": "의자", "term_vi": "Ghế", "def_ko": "앉는 가구", "def_vi": "Đồ nội thất dành để ngồi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (947, '5', '대상자의 기저귀를 교환할 때 둔부를 가볍게 두드려 마사지하는 이유는?', '["변의 자극", "욕창 예방", "근육 이완", "장운동 촉진", "심리적 안정"]'::jsonb, 2, '대상자가 기저귀를 교환할 때 둔부를 마사지하는 이유를 이해하도록 유도하는 문제입니다.', NULL, '{"1": "변의 자극: 마사지를 하는 주요 목적이 아닙니다.\n[정답]", "2": "욕창 예방: 마사지가 혈액순환을 촉진하여 욕창 예방에 도움을 줍니다.", "3": "근육 이완: 마사지로 인해 근육이 이완될 수 있으나, 주된 목적은 아닙니다.", "4": "장운동 촉진: 마사지가 장운동에 도움을 줄 수 있지만 이 경우는 우선순위가 아닙니다.", "5": "심리적 안정: 마사지를 통해 심리적 안정감을 줄 수는 있지만, 질문의 주제와는 관련성이 적습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "Tã"}, {"term_ko": "둔부", "term_vi": "Mông", "def_ko": "엉덩이(한국어)", "def_vi": "Mông"}, {"term_ko": "마사지", "term_vi": "Xoa bóp", "def_ko": "마사지(한국어)", "def_vi": "Xoa bóp"}, {"term_ko": "욕창", "term_vi": "Loét tì đè", "def_ko": "욕창(한국어)", "def_vi": "Loét tì đè"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (946, '5', '욕창으로 인해 대상자에게 피부 발적과 수포가 생겼을 경우 돕는 방법으로 옳은 것은?', '["피부를 주무르며 마사지한다.", "발적 부위를 미지근한 물로 닦아주고 건조시킨다.", "하루에 두 번 체위변경을 한다.", "몸에 꽉 끼는 옷을 입힌다.", "욕창 예방을 위해 도넛 모양의 베개를 대준다."]'::jsonb, 2, '욕창 관리와 관련하여 올바른 간호 방법을 평가하고자 함.', NULL, '{"1": "피부를 주무르며 마사지하는 것은 오히려 피부 손상을 초래할 수 있다.\n[정답]", "2": "발적 부위를 미지근한 물로 닦아주고 건조시키는 것은 피부 상태를 개선하고, 감염 예방에 도움이 된다.", "3": "하루에 두 번 체위변경을 하는 것은 욕창 예방에는 중요하지만, 대상자의 상태에 따라 빈도가 달라질 수 있다.", "4": "몸에 꽉 끼는 옷은 혈액 순환을 저해할 수 있어 피해야 한다.", "5": "도넛 모양의 베개는 도와줄 수 있지만, 상황에 따라 적절하지 않을 수 있다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét do tỳ đè", "def_ko": "피부가 손상되어 생기는 상처", "def_vi": "Vết thương do tổn thương da"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (945, '5', '와상 상태에 있는 대상자의 피부가 약간 붉게 변하였을 때 대처방법으로 옳은 것은?', '["욕창 주위를 마사지하고 가볍게 두드린다.", "뜨거운 물수건으로 찜질한다.", "차가운 바람으로 건조시킨다.", "춥지 않으면 1~2시간 햇볕을 쪼인다.", "물티슈로 수시로 닦아준다."]'::jsonb, 1, '와상 상태에 있는 대상자의 피부 상태 관리에 대한 이해를 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "욕창 주위를 마사지하고 가볍게 두드린다. - 피부의 혈액 순환을 도와 피부 상태를 개선할 수 있습니다.\n[정답]", "2": "뜨거운 물수건으로 찜질한다. - 화상의 위험이 있어 적절하지 않은 방법입니다.", "3": "차가운 바람으로 건조시킨다. - 피부를 더욱 손상시킬 수 있으므로 피해야 합니다.", "4": "춥지 않으면 1~2시간 햇볕을 쪼인다. - 피부에 부담을 주어 상태를 악화시킬 수 있습니다.", "5": "물티슈로 수시로 닦아준다. - 피부에 자극을 줄 수 있으므로 주의해야 합니다."}'::jsonb, '[{"term_ko": "와상 상태", "term_vi": "Trạng thái nằm liệt", "def_ko": "누워 있는 상태(한국어)", "def_vi": "Tình trạng nằm không di chuyển"}, {"term_ko": "욕창", "term_vi": "Loét do tì đè", "def_ko": "피부가 눌려서 상처가 생기는 질환(한국어)", "def_vi": "Bệnh xảy ra khi da bị ép"}, {"term_ko": "마사지", "term_vi": "Mát xa", "def_ko": "눌러서 혈액 순환을 촉진하는 방법(한국어)", "def_vi": "Phương pháp thúc đẩy tuần hoàn máu bằng cách ấn"}, {"term_ko": "자극", "term_vi": "Kích thích", "def_ko": "반응을 일으키는 것(한국어)", "def_vi": "Điều gây ra phản ứng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (944, '5', '욕창의 단계별 증상 중 다음 내용에 해당하는 것은?피하조직과 근막, 근육, 뼈나 관절을 포함한 심부조직에 손상이 있다.', '["1단계", "2단계", "3단계", "4단계", "5단계"]'::jsonb, 4, '욕창의 단계별 증상에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "1단계: 피부의 발적, 통증 등의 증상이 나타나는 경미한 단계입니다.", "2": "2단계: 표피와 진피 손상이 나타나며, 통증이 있습니다.\n[정답]", "3": "3단계: 피하조직 손상이 있고, 단단한 껍질이 형성되며, 외부가 드러날 수 있습니다.", "4": "4단계: 심부조직 손상이 있으며, 피하조직과 근막, 근육, 뼈나 관절 등까지 포함됩니다.", "5": "5단계: 이러한 정의는 없으며, 최대 4단계까지만 존재합니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부의 손상(한국어)", "def_vi": "Tổn thương da"}, {"term_ko": "단계", "term_vi": "Giai đoạn", "def_ko": "수준(한국어)", "def_vi": "Cấp độ"}, {"term_ko": "피하조직", "term_vi": "Mô dưới da", "def_ko": "조직(한국어)", "def_vi": "Mô"}, {"term_ko": "근막", "term_vi": "Vải cơ", "def_ko": "근육을 싸고 있는 막(한국어)", "def_vi": "Màng cơ"}, {"term_ko": "근육", "term_vi": "Cơ", "def_ko": "신체의 근력 조직(한국어)", "def_vi": "Cơ"}, {"term_ko": "뼈", "term_vi": "Xương", "def_ko": "신체를 구성하는 단단한 조직(한국어)", "def_vi": "Xương"}, {"term_ko": "관절", "term_vi": "Khớp", "def_ko": "뼈가 만나서 이루는 부분(한국어)", "def_vi": "Khớp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (943, '5', '욕창 발생 위험이 가장 높은 대상자는?', '["산책을 즐기는 과체중 대상자", "체중부하운동이 어려운 관절염 대상자", "지팡이를 짚고 걷는 파킨슨병 대상자", "체위 변겨이 어려운 척수 장애 대상자", "보조기구를 이용하여 산책하는 편마비 대상자"]'::jsonb, 4, '욕창 발생 위험이 높은 대상을 파악하고 구체적인 판단 능력을 요구하는 문제입니다.', NULL, '{"1": "산책을 즐기는 과체중 대상자는 활동량이 많아 욕창 발생 위험이 상대적으로 낮습니다.\n[정답]", "4": "체위 변겨이 어려운 척수 장애 대상자는 움직임이 제한되어 욕창이 발생할 위험이 가장 높습니다.", "2": "체중부하운동이 어려운 관절염 대상자는 활동이 제한되지만 상태에 따라 다릅니다.", "3": "지팡이를 짚고 걷는 파킨슨병 대상자는 어느 정도 움직일 수 있어 욕창 위험이 낮을 수 있습니다.", "5": "보조기구를 이용하여 산책하는 편마비 대상자는 이동이 가능하여 욕창 위험이 상대적으로 적습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Đau đớn", "def_ko": "피부와 조직의 손상으로 인한 통증 및 궤양", "def_vi": "Đau và loét do tổn thương da và mô"}, {"term_ko": "체중부하운동", "term_vi": "Vận động tải trọng", "def_ko": "움직임을 위한 체중을 지지하는 운동", "def_vi": "Bài tập hỗ trợ trọng lượng cho chuyển động"}, {"term_ko": "체위", "term_vi": "Tư thế", "def_ko": "자세, 위치", "def_vi": "Tư thế, vị trí"}, {"term_ko": "척수 장애", "term_vi": "Khuyết tật cột sống", "def_ko": "척수와 관련된 신경 기능 문제", "def_vi": "Vấn đề chức năng thần kinh liên quan đến cột sống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (942, '5', '거동이 불편한 대상자에게 욕창이 발생할 가능성이 가장 높은 경우는?', '["충분한 영양섭취를 하고 있다.", "낮잠을 자지 않는다.", "요실금 및 변실금이 있다.", "취침 시 자주 뒤척인다.", "변비가 이어 물을 많이 마신다."]'::jsonb, 3, '요양보호사가 욕창 예방을 위해 알아야 할 내용을 확인하는 것입니다.', NULL, '{"1": "충분한 영양섭취를 하고 있다: 영양 섭취가 좋으면께 욕창 발생 위험이 감소합니다.\n[정답]", "3": "요실금 및 변실금이 있다: 이러한 상태는 체중이 같은 부위에 지속적으로 압력이 가해져 욕창이 발생할 가능성을 높입니다.", "2": "낮잠을 자지 않는다: 낮잠과 욕창 발생은 직접적인 연관이 없습니다.", "4": "취침 시 자주 뒤척인다: 자주 자세를 변화시키면 욕창 발생 위험이 낮아집니다.", "5": "변비가 이어 물을 많이 마신다: 변비와 물 섭취는 욕창 발생과 직접적인 관련이 없습니다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Hành động", "def_ko": "움직이다(한국어)", "def_vi": "Di chuyển"}, {"term_ko": "불편", "term_vi": "Không thoải mái", "def_ko": "불편하다(한국어)", "def_vi": "Không thuận tiện"}, {"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부에 생기는 상처(한국어)", "def_vi": "Vết thương trên da"}, {"term_ko": "요실금", "term_vi": "Tiểu són", "def_ko": "소변을 잘 못 가리는 상태(한국어)", "def_vi": "Tình trạng không kiểm soát được tiểu tiện"}, {"term_ko": "변실금", "term_vi": "Tiêu chảy", "def_ko": "대변을 잘 못 가리는 상태(한국어)", "def_vi": "Tình trạng không kiểm soát được đại tiện"}, {"term_ko": "취침", "term_vi": "Ngủ", "def_ko": "잠을 자는 것(한국어)", "def_vi": "Thời gian ngủ"}, {"term_ko": "뒤척이다", "term_vi": "Lăn lộn", "def_ko": "자는 중에 몸을 움직이다(한국어)", "def_vi": "Di chuyển trong khi ngủ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (941, '5', '거동이 불편한 대상자에게 욕창이 발생할 가능성이 가장 높은 경우는?', '["피하지방이 많은 대상자", "부적절한 영양으로 근육이 위축된 대상자", "정상 체중을 유지하고 있는 대상자", "변비가 있는 대상자", "요의, 변의가 있는 대상자"]'::jsonb, 2, '거동이 불편한 대상자에게 욕창이 발생할 가능성이 높은 상황을 이해하고 평가하는 것이다.', NULL, '{"1": "피하지방이 많은 대상자는 피부가 보호되는 경향이 있어 욕창 발생 가능성이 낮다.\n[정답]", "2": "부적절한 영양으로 근육이 위축된 대상자는 피부 보호 기능이 약화되어 욕창 발생 가능성이 높다.", "3": "정상 체중을 유지하는 대상자는 욕창 발생 가능성이 낮다.", "4": "변비가 있는 대상자는 욕창과 직접적인 관계가 적다.", "5": "요의, 변의가 있는 대상자는 욕창 발생에 큰 영향을 미치지 않다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Hành động", "def_ko": "움직임(한국어)", "def_vi": "hành động(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (940, '5', '병상에 오랫동안 누워 있는 ㅐ상자의 피부가 혈액을 공급받지 못해서 괴사되는 질환은?', '["건조증", "욕창", "수두", "대상포진", "아토피 피부염"]'::jsonb, 2, '환자의 피부에 발생할 수 있는 문제를 이해하고 있는지를 테스트하기 위한 의도입니다.', NULL, '{"1": "건조증: 피부가 건조해지는 상태로, 혈액 공급 부족과는 관련이 없습니다.\n[정답]", "2": "욕창: 병상에 오래 누워 있을 때 피부가 괴사되는 질환으로, 혈액 공급이 부족하여 발생합니다.", "3": "수두: 바이러스성 질환으로 피부 괴사와는 다른 문제입니다.", "4": "대상포진: 신경계 질환과 관련이 있는 피부 질환입니다.", "5": "아토피 피부염: 알레르기 반응으로 인해 발생하는 피부 질환입니다."}'::jsonb, '[{"term_ko": "병상", "term_vi": "Giường bệnh", "def_ko": "침대(한국어)", "def_vi": "Giường mà bệnh nhân nằm"}, {"term_ko": "피부", "term_vi": "Da", "def_ko": "피부(한국어)", "def_vi": "Da của cơ thể"}, {"term_ko": "괴사", "term_vi": "Hoại tử", "def_ko": "죽어 있는 세포(한국어)", "def_vi": "Tình trạng tế bào chết do thiếu máu"}, {"term_ko": "혈액", "term_vi": "Máu", "def_ko": "피(한국어)", "def_vi": "Chất lỏng trong cơ thể"}, {"term_ko": "공급", "term_vi": "Cung cấp", "def_ko": "제공하다(한국어)", "def_vi": "Vận chuyển hoặc gửi đến"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (939, '5', '노화에 따른 피부의 특성으로 옳은 것은?', '["표피가 두꺼워진다.", "각질층의 수분함량이 증가한다.", "피하지방의 증가로 기온에 둔감해진다.", "모근의 멜라닌생성 세포가 증가한다.", "상처가 잘 낫지 않으면 궤양이 생기기 쉽다."]'::jsonb, 5, '노화가 피부에 미치는 영향을 이해하고, 그 특성을 평가하는 문제입니다.', NULL, '{"1": "표피는 일반적으로 노화에 따라 얇아집니다.\n[정답]", "5": "노화로 인해 피부의 치유 능력이 감소하여 상처가 잘 낫지 않으면 궤양이 생기기 쉽습니다.", "2": "각질층의 수분함량은 노화로 인해 감소합니다.", "3": "피하지방은 노화로 인해 감소하며, 기온에 둔감해지는 것은 피하지방의 감소 때문입니다.", "4": "모근의 멜라닌 생성 세포는 노화와 함께 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "노인(한국어)", "def_vi": "người già(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (938, '5', '대상자에게 관찰되는 피부계 변화 중 보고해야 하는 상황은?', '["머리카락이 가늘어졌다.", "손등에 노인성 반점이 생겼다.", "피부에 발적과 가려움증이 있다.", "손톱, 발톱이 딱딱하고 두꺼워졌다.", "눈가에 주름이 생기고, 피부의 탄력성이 떨어졌다."]'::jsonb, 3, '대상자의 피부 상태 변화 중 어떤 상황이 의료진에게 즉시 보고해야 하는지를 평가하는 것이다.', NULL, '{"1": "머리카락이 가늘어지는 것은 일반적인 노화 과정으로, 보고할 필요가 없다.", "2": "손등에 노인성 반점이 생기는 것은 노화의 일환으로, 보고하지 않아도 된다.\n[정답]", "3": "피부에 발적과 가려움증이 있는 경우는 염증이나 알레르기 반응의 가능성이 있어 즉시 보고해야 한다.", "4": "손톱, 발톱이 딱딱하고 두꺼워지는 것은 일반적인 노화 현상으로, 특별한 문제가 없으면 보고할 필요가 없다.", "5": "눈가에 주름이 생기고 피부의 탄력성이 떨어지는 것은 노화로 인한 자연스러운 변화로, 보고할 필요가 없다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자 또는 돌보는 사람", "def_vi": "Bệnh nhân hoặc người được chăm sóc"}, {"term_ko": "피부계", "term_vi": "Hệ thống da", "def_ko": "피부 및 그 기능에 관계된 시스템", "def_vi": "Hệ thống liên quan đến da và chức năng của nó"}, {"term_ko": "변화", "term_vi": "Biến đổi", "def_ko": "변화", "def_vi": "Sự thay đổi"}, {"term_ko": "발적", "term_vi": "Đỏ da", "def_ko": "피부의 붉은 반점", "def_vi": "Vết đỏ trên da"}, {"term_ko": "가려움증", "term_vi": "Ngứa", "def_ko": "피부가 간질거리는 느낌", "def_vi": "Cảm giác da bị ngứa"}, {"term_ko": "노인성 반점", "term_vi": "Đốm tuổi", "def_ko": "나이가 들어서 생기는 피부의 색소 변화", "def_vi": "Sự thay đổi sắc tố trên da do tuổi tác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (937, '5', '전립선비대증 대상자의 방광염 예방을 돕는 방법로 옳은 것은?', '["유치도뇨관을 삽입한다.", "골반근육강화운동을 하게 한다.", "소변을 참을 수 있을 때까지 참는다.", "낮에는 시간을 정해 규칙적으로 배뇨하게 한다.", "식이섬유가 풍부한 음식을 섭취하게 한다."]'::jsonb, 4, '전립선비대증 대상자의 방광염 예방을 위한 올바른 방법을 묻는 문제이다.', NULL, '{"1": "유치도뇨관을 삽입하는 것은 일반적으로 방광염 예방이 아닌 치료적인 방법이다.\n[정답]", "2": "골반근육강화운동은 방광의 기능을 개선할 수 있지만 직접적인 예방 방법은 아니다.", "3": "소변을 참는 것은 방광에 부담을 줄 수 있어 예방에 도움이 되지 않는다.", "4": "낮에는 시간을 정해 규칙적으로 배뇨하게 하는 것이 방광염 예방에 효과적이다.", "5": "식이섬유가 풍부한 음식은 장 건강에는 좋은 영향을 미치겠지만 방광염 예방과 직접적인 관련은 적다."}'::jsonb, '[{"term_ko": "전립선비대증", "term_vi": "Bệnh phì đại tiền liệt tuyến", "def_ko": "전립선이 비대해져서 발생하는 질환", "def_vi": "Bệnh lý gia tăng kích thước tuyến tiền liệt"}, {"term_ko": "방광염", "term_vi": "Viêm bàng quang", "def_ko": "방광의 염증", "def_vi": "Viêm nhiễm của bàng quang"}, {"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "소변을 배출하는 도구", "def_vi": "Thiết bị để dẫn lưu nước tiểu"}, {"term_ko": "배뇨", "term_vi": "Đi tiểu", "def_ko": "소변을 보는 행위", "def_vi": "Hành động đi tiểu"}, {"term_ko": "식이섬유", "term_vi": "Chất xơ", "def_ko": "소화관에서 게르마에 기여하는 식품 성분", "def_vi": "Thành phần thực phẩm giúp tiêu hóa"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (936, '5', '전립선비대증을 치료하는 방법으로 옳은 것은?', '["도뇨관을 이용하여 정기적으로 소변을 빼준다.", "고지방과 고콜레스테롤 음식을 섭취한다.", "약화된 근육을 강화하기 위해 체중을 늘린다.", "소변량을 증가시키기 위해 맥주를 마신다.", "심하면 약물 치료와 방사선 치료를 시작한다."]'::jsonb, 1, '전립선비대증의 치료 방법에 대한 올바른 이해를 확인하기 위함입니다.', NULL, '{"1": "도뇨관을 이용하여 정기적으로 소변을 빼주는 것은 전립선비대증의 일반적인 치료 방법 중 하나입니다.\n[정답]", "2": "고지방과 고콜레스테롤 음식은 오히려 건강에 좋지 않으므로 치료 방법이 아닙니다.", "3": "약화된 근육을 강화하기 위해 체중을 늘리는 것은 전립선비대증과 관련된 방법이 아닙니다.", "4": "소변량을 증가시키기 위해 맥주를 마시는 것은 전립선비대증에 도움이 되지 않습니다.", "5": "심하면 약물 치료와 방사선 치료를 고려할 수 있으나, 이 방법은 일반적인 치료 방법이 아닙니다."}'::jsonb, '[{"term_ko": "전립선비대증", "term_vi": "Bệnh phì đại tuyến tiền liệt", "def_ko": "과도한 전립선 성장으로 인한 증상", "def_vi": "Tình trạng tăng trưởng quá mức của tuyến tiền liệt"}, {"term_ko": "도뇨관", "term_vi": "Ống thông", "def_ko": "소변을 빼내기 위해 사용하는 관", "def_vi": "Ống sử dụng để xả nước tiểu"}, {"term_ko": "약물 치료", "term_vi": "Điều trị bằng thuốc", "def_ko": "의약품을 사용하여 질병을 치료하는 것", "def_vi": "Sử dụng thuốc để điều trị bệnh"}, {"term_ko": "방사선 치료", "term_vi": "Điều trị bằng xạ trị", "def_ko": "방사선을 이용하여 질병을 치료하는 것", "def_vi": "Sử dụng tia xạ để điều trị bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (935, '5', '전립선비대증이 있는 대상자에게 나타나는 증상으로 옳은 것은?', '["소변량이 많아졌어요.", "소변에서 냄새가 나요.", "소변 줄기가 굵어졌어요.", "소변에 거품이 섞여 나와요.", "소변을 보았는데도 시원하지가 않아요."]'::jsonb, 5, '전립선비대증 관련 증상을 이해하고, 주어진 보기에 대한 출처 확인이 필요합니다.', NULL, '{"1": "전립선비대증에서는 소변량이 많아지지 않는 경우가 많습니다.", "2": "소변에서 냄새가 나는 것은 비대증과 관련이 없습니다.", "3": "소변 줄기가 굵어지지 않으며 오히려 약해질 수 있습니다.\n[정답]", "5": "소변을 보았는데도 시원하지가 않은 느낌은 전립선비대증의 대표적인 증상입니다.", "4": "소변에 거품이 섞여 나오는 것은 다른 문제로 여겨질 수 있습니다."}'::jsonb, '[{"term_ko": "전립선비대증", "term_vi": "소변", "def_ko": "전립선이 비대해지는 질환 (Phì đại tuyến tiền liệt)", "def_vi": "체내에서 배출되는 액체 (Nước tiểu)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (934, '5', '전립선비대증 증상으로 옳은 것은?', '["단백뇨가 있다.", "배뇨 후 시원하다.", "소변에서 피가 섞여 나온다.", "요도가 넓어져서 소변을 자주 본다.", "배뇨 후 2시간 이내에 다시 소변이 마렵다."]'::jsonb, 5, '전립선비대증과 관련된 주요 증상을 이해하고 있는지를 확인하기 위한 문제입니다.', NULL, '{"1": "단백뇨는 전립선비대증의 증상이 아닙니다.\n[정답]", "5": "배뇨 후 2시간 이내에 다시 소변이 마렵다는 전립선비대증의 전형적인 증상입니다.", "2": "배뇨 후 시원하다는 증상은 일반적으로 전립선비대증과 관련이 없습니다.", "3": "소변에서 피가 섞여 나오는 것은 다른 비뇨기계 질환과 관련이 있을 수 있습니다.", "4": "요도가 넓어져서 소변을 자주 본다는 것은 전립선비대증의 증상과는 반대 개념입니다."}'::jsonb, '[{"term_ko": "전립선비대증", "term_vi": "Phì đại tuyến tiền liệt", "def_ko": "전립선이 비대해져서 생기는 증상", "def_vi": "Triệu chứng do tuyến tiền liệt phình to gây ra"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (933, '5', '배뇨 후 잔뇨감이 있고 소변 줄기가 가늘어지며 힘을 주어야 소변이 나오는 질환은?', '["요실금", "요도염", "요로결석", "신장염", "전립선비대증"]'::jsonb, 5, '소변 관련 질환을 이해하고 구별하도록 하는 문제입니다.', NULL, '{"1": "요실금: 소변을 의도하지 않게 흘리는 상태로, 본 문제와 관련이 없습니다.\n[정답]", "5": "전립선비대증: 배뇨 후 잔뇨감과 소변 줄기가 가늘어지는 증상이 보이며, 힘을 주어야 소변이 나옵니다.", "2": "요도염: 요도에 염증이 생겨 소변에 통증이 있을 수 있지만, 본 문제의 증상과는 다릅니다.", "3": "요로결석: 통증을 동반할 수 있는 질환이지만 잔뇨감과 줄기가 가늘어지는 증상과는 차이가 있습니다.", "4": "신장염: 신장의 염증으로, 배뇨 문제와는 다른 증상이 주로 나타납니다."}'::jsonb, '[{"term_ko": "배뇨", "term_vi": "Đi tiểu", "def_ko": "소변을 보는 행위", "def_vi": "Hành động đi tiểu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (932, '5', '전립성비대증 발생과 관련된 요인으로 옳은 것은?', '["요로감염", "복압상승", "남성호르몬 불균형", "방광의 저장능력 감소", "골반 근육 조절능력의 약화"]'::jsonb, 3, '전립성비대증의 발생 원인과 관련된 요인을 파악하게 하기 위함입니다.', NULL, '{"1": "요로감염은 전립성비대증의 직접적인 원인이 아닙니다.\n[정답]", "2": "복압상승은 전립선에 압력을 가할 수 있지만, 전립성 비대증의 주요 원인은 아닙니다.", "3": "남성호르몬 불균형은 전립성비대증의 발생과 밀접한 관련이 있습니다.", "4": "방광의 저장능력 감소는 전립성비대증의 증상으로 나타날 수 있지만, 발생 원인은 아닙니다.", "5": "골반 근육 조절능력의 약화는 비대증의 결과일 수 있으나, 발생 원인은 아닙니다."}'::jsonb, '[{"term_ko": "전립선", "term_vi": "비대증", "def_ko": "남성의 생식기관 중 하나 - Tuyến tiền liệt: Một trong những cơ quan sinh sản của nam giới", "def_vi": "비정상적으로 커지는 상태 - Phì đại: Tình trạng lớn một cách bất thường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (931, '5', '복압성 요실금이 있는 대상자를 돕는 방법은?', '["복부를 꽉 조이는 옷을 입힌다.", "매시간 화장실을 가도록 한다.", "비만 관리를 한다.", "규칙적으로 줄넘기를 하게 한다.", "식이섬유소가 적은 음식을 제공한다."]'::jsonb, 3, '복압성 요실금의 관리 및 치료 방법을 이해하고 그에 대한 적절한 대응 방법을 묻는 문제입니다.', NULL, '{"1": "복부를 꽉 조이는 옷을 입히면 요실금 증상이 악화될 수 있습니다.\n[정답]", "3": "비만 관리는 복압성 요실금 증상을 경감시킬 수 있는 방법입니다.", "2": "매시간 화장실에 가도록 하는 것은 효과적일 수 있지만 장기적인 관리 방법으로는 적절하지 않을 수 있습니다.", "4": "규칙적으로 줄넘기를 하는 것은 오히려 증상을 악화시킬 수 있습니다.", "5": "식이섬유소가 적은 음식은 변비를 유발할 수 있어 요실금에 좋지 않습니다."}'::jsonb, '[{"term_ko": "복압성", "term_vi": "Áp lực", "def_ko": "압력에 의해 발생하는", "def_vi": "chịu đựng một cái gì đó"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (920, '5', '절박성 요실금이 있는 대상자를 돕는 방법으로 옳은 것은?', '["수분 섭취를 제한한다.", "낮에는 기저귀를 채워 준다.", "웃음치료에 참여하게 한다.", "따뜻한 커피를 자주 마시게 한다.", "골반근육강화 운동을 하게한다."]'::jsonb, 5, '골다공증을 예방하거나 관리하는 방법을 묻는 질문입니다.', NULL, '{"1": "온열요법은 골절 예방과 관련이 없습니다.\n[정답]", "2": "체중부하운동은 뼈를 강화하고 골절 예방에 도움이 됩니다.", "3": "자외선 차단제는 골다공증과 무관합니다.", "4": "혈전예방 약물은 골절 예방과 관련이 없습니다.", "5": "에스트로겐 섭취 제한은 필요하지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈의 밀도가 낮아져 약해지는 상태", "def_vi": "Tình trạng xương trở nên yếu do mật độ thấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (929, '5', '복압성 요실금 대상자를 돕는 방법으로 옳은 것은?', '["체중을 늘린다.", "변비를 예방한다.", "유치도뇨관을 삽입한다.", "야간에는 수분 섭취를 금지한다.", "장기간 소변을 참았다가 배뇨하도록 한다."]'::jsonb, 2, '복압성 요실금의 관리와 예방 방법을 이해하고 있는지를 확인하기 위한 문제입니다.', NULL, '{"1": "체중을 늘리는 것은 복압성 요실금을 악화시킬 수 있습니다.\n[정답]", "2": "변비 예방은 복압성 요실금 환자에게 중요한 관리 방법입니다.", "3": "유치도뇨관은 필요하지 않은 경우에는 삽입하지 않아야 합니다.", "4": "야간에 수분 섭취를 제한하는 것은 수분 부족을 초래할 수 있습니다.", "5": "장기간 소변을 참는 것은 방광 기능에 문제를 일으킬 수 있습니다."}'::jsonb, '[{"term_ko": "복압성", "term_vi": "Tiểu không kiểm soát do áp lực", "def_ko": "압력이 가해지는 상태", "def_vi": "Tình trạng không kiểm soát tiểu tiện do áp lực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (928, '5', '노화로 인한 요실금의 원인이 되는 것은?', '["잔뇨량 감소", "신장 기능의 향상", "요도 기능 향상", "방광의 저장능력 감소", "골반 근육 조절능력의 향상"]'::jsonb, 4, '요실금의 원인에 대한 이해를 확인하기 위함입니다.', NULL, '{"1": "잔뇨량 감소는 요실금을 유발하는 요인이 아닙니다.\n[정답]", "4": "방광의 저장능력 감소는 노화에 따라 발생하는 일반적인 증상으로 요실금을 유발할 수 있습니다.", "2": "신장 기능의 향상은 요실금과 관련이 없습니다.", "3": "요도 기능 향상은 요실금으로 이어지지 않습니다.", "5": "골반 근육 조절능력의 향상은 오히려 요실금 예방에 도움이 됩니다."}'::jsonb, '[{"term_ko": "요실금", "term_vi": "Tiểu không kiểm soát", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "방광", "term_vi": "Bàng quang", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "저장능력", "term_vi": "Khả năng chứa", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "골반", "term_vi": "Khung chậu", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "근육", "term_vi": "Cơ", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (927, '5', '대상자가 기침, 웃음, 재채기를 할 때 복부 내 압려그이 증가로 인해 소변이 배출되는 증상이 나타나는 것은?', '["혼합성 요실금", "복압성 요실금", "절박성 요실금", "역류성 요실금", "반사성 요실금"]'::jsonb, 2, '환자에게 발생할 수 있는 다양한 요실금의 유형에 대해 이해하고 이를 구분하는 능력을 평가하려는 의도입니다.', NULL, '{"1": "혼합성 요실금은 여러 요인으로 발생하는 요실금을 의미합니다.\n[정답]", "2": "복압성 요실금은 기침, 웃음, 재채기 등으로 복압이 증가해 소변이 배출되는 현상을 말합니다.", "3": "절박성 요실금은 갑작스러운 배뇨 욕구로 인해 발생하는 요실금을 의미합니다.", "4": "역류성 요실금은 방광의 기능 저하로 인해 발생하는 요실금입니다.", "5": "반사성 요실금은 신경 손상으로 인해 배뇨의 반사가 제대로 이루어지지 않아 발생합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (926, '5', '자신의 의지와 상관없이 소변이 밖으로 흘러나오는 증상을 무엇이라 하는가?', '["변실금", "요실금", "요도염", "방광염", "신장염"]'::jsonb, 2, '소변이 의사와 관계없이 흘러나오는 증상의 이름을 묻는 문제입니다.', NULL, '{"1": "변실금: 대변이 의사와 관계없이 흘러나오는 증상입니다.\n[정답]", "2": "요실금: 자신의 의지와 상관없이 소변이 흘러나오는 증상입니다.", "3": "요도염: 요도의 염증으로, 소변을 흘리는 증상은 포함되지 않습니다.", "4": "방광염: 방광의 염증이지만, 소변이 흘러나오는 직접적인 증상은 아닙니다.", "5": "신장염: 신장의 염증이지만, 요실금과는 다른 증상입니다."}'::jsonb, '[{"term_ko": "요실금", "term_vi": "Tiểu không tự chủ", "def_ko": "의사와 상관없이 소변이 흘러나오는 증상", "def_vi": "Triệu chứng mà nước tiểu chảy ra ngoài mà không theo ý muốn"}, {"term_ko": "변실금", "term_vi": "Biểu hiện đi ngoài", "def_ko": "대변이 의사와 관계없이 흘러나오는 증상", "def_vi": "Thành phần của đại tiện chảy ra ngoài mà không theo ý muốn"}, {"term_ko": "요도염", "term_vi": "Viêm niệu đạo", "def_ko": "요도의 염증", "def_vi": "Tình trạng viêm niệu đạo"}, {"term_ko": "방광염", "term_vi": "Viêm bàng quang", "def_ko": "방광의 염증", "def_vi": "Tình trạng viêm bàng quang"}, {"term_ko": "신장염", "term_vi": "Viêm thận", "def_ko": "신장의 염증", "def_vi": "Tình trạng viêm thận"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (925, '5', '여성노인의 생식기계 변화로 옳은 것은?', '["성적 욕구 감소", "성교 시 통증 감소", "에스트로겐 분비 증가", "질의 수축력 증가", "질의 윤활작용 감소"]'::jsonb, 5, '여성 노인의 생식기계 변화에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "성적 욕구 감소는 일반적으로 나타나는 현상입니다.\n[정답]", "5": "질의 윤활작용 감소는 노화 과정에서 흔히 발생하는 문제입니다.", "2": "성교 시 통증 감소는 반대의 경우가 일반적입니다.", "3": "에스트로겐 분비는 감소하는 경향이 있습니다.", "4": "질의 수축력은 나이가 들면서 감소하는 경향이 있습니다."}'::jsonb, '[{"term_ko": "여성노인", "term_vi": "Phụ nữ già", "def_ko": "나이가 많은 여성", "def_vi": "Phụ nữ lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (924, '5', '노화에 따른 여성 노인의 생식기계 변화는?', '["난소 크기 감소", "질염 발생 감소", "질의 길이 증가", "질벽의 두께 증가", "여성호르몬 분비 증가"]'::jsonb, 1, '노화가 여성 노인의 생식기계에 미치는 영향을 이해하는 것.', NULL, '{"1": "노화에 따라 난소의 크기가 감소하는 것이 일반적이다.\n[정답]", "2": "질염 발생은 오히려 증가하는 경향이 있다.", "3": "질의 길이는 노화에 따라 감소하는 경향이 있다.", "4": "질벽의 두께는 감소할 수 있다.", "5": "여성호르몬 분비는 일반적으로 감소한다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙어감(한국어)", "def_vi": "Sự già đi(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (923, '5', '골다공증으로 고관절 골절의 위험이 높은 대상자의 잘못된 행동은?', '["거실에 널려 있는 물건을 모두 치운다.", "규칙적으로 하지근력 강화운동을 한다.", "연어, 고등어, 달걀을 자주 섭취한다.", "저체중 상태를 유지하기 위해 다이어트를 한다.", "안경 도수가 맞지 않아 안경을 새로 맞춘다."]'::jsonb, 4, '골다공증으로 고관절 골절의 위험이 높은 대상자의 행위 중 잘못된 행동을 물어보는 문제입니다.', NULL, '{"1": "거실에 있는 물건을 치우는 것은 안전사고를 예방하므로 좋은 행동입니다.\n[정답]", "4": "저체중 상태를 유지하기 위한 다이어트는 영양 섭취 부족을 초래할 수 있어 위험합니다.", "2": "하지근력 강화운동은 골절 예방에 도움이 되는 좋은 행동입니다.", "3": "연어, 고등어, 달걀은 칼슘과 비타민D의 섭취에 도움이 되어 건강에 좋습니다.", "5": "안경 도수를 맞춰 시력을 개선하는 것은 안전에 도움을 줍니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈가 약해지는 질병", "def_vi": "Bệnh làm xương yếu đi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (922, '5', '다음 중 고관절 골절을 유발하는 질환은?', '["퇴행성 관절염", "류마티스 관절염", "추간판 탈출증", "골다공증", "척추관 협착증"]'::jsonb, 4, '고관절 골절을 유발하는 주요 질환을 평가하고 식별하는 것이다.', NULL, '{"1": "퇴행성 관절염은 관절의 마모와 노화를 초래하지만 고관절 골절과는 직접적인 관계가 없다.\n[정답]", "4": "골다공증은 뼈의 밀도가 감소하여 골절 위험이 증가하며, 고관절 골절의 주 원인 중 하나이다.", "2": "류마티스 관절염은 주로 관절의 염증을 유발하여 관절 기능 장애를 초래하지만 고관절 골절을 직접적으로 유발하지는 않는다.", "3": "추간판 탈출증은 주로 허리와 관련된 문제로, 고관절 골절을 유발하는 것과는 관련이 없다.", "5": "척추관 협착증은 주로 척추에서 발생하는 질환으로 고관절 골절과는 직접적인 관계가 없다."}'::jsonb, '[{"term_ko": "고관절", "term_vi": "Khớp háng", "def_ko": "엉덩이 관절", "def_vi": "Khớp giữa xương chậu và xương đùi"}, {"term_ko": "골절", "term_vi": "Gãy xương", "def_ko": "뼈가 부러지는 것", "def_vi": "Hiện tượng xương bị gãy"}, {"term_ko": "퇴행성", "term_vi": "Thoái hóa", "def_ko": "나이가 들어감에 따라 퇴화하는 것", "def_vi": "Quá trình mất chức năng hoặc giảm hiệu suất theo thời gian"}, {"term_ko": "관절염", "term_vi": "Viêm khớp", "def_ko": "관절에 발생하는 염증 또는 질환", "def_vi": "Bệnh viêm ở khớp"}, {"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈의 밀도가 감소하는 질환", "def_vi": "Bệnh làm giảm mật độ xương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (921, '5', '낙상으로 인해 서혜부와 대퇴부에 통증이 있고 움직임에 제한이 있는 질환은?', '["퇴행성 관절염", "류마티스 관절염", "고관절 골절", "골다공증", "외상성 관절염"]'::jsonb, 3, '서혜부와 대퇴부에 통증을 유발하는 주요 질환을 파악하기 위해 출제된 문제입니다. 이와 관련된 지식이 필요합니다.', NULL, '{"1": "퇴행성 관절염은 노화나 반복적인 사용으로 인해 관절이 퇴화되면서 발생하는 질환입니다.", "2": "류마티스 관절염은 주로 면역계의 이상으로 인해 발생하는 염증성 질환입니다.\n[정답]", "3": "고관절 골절은 사고나 낙상 등에 의해 고관절이 부러진 상태로, 서혜부와 대퇴부에 통증 및 움직임에 제한이 발생합니다.", "4": "골다공증은 뼈의 밀도가 감소하여 쉽게 골절되는 상태를 나타내지만, 직접적인 통증이나 움직임 제한을 유발하지 않습니다.", "5": "외상성 관절염은 외부의 충격으로 인해 발생하는 관절의 염증을 의미하지만, 고관절 골절 경우와는 다릅니다."}'::jsonb, '[{"term_ko": "낙상", "term_vi": "Ngã", "def_ko": "넘어지다(한국어)", "def_vi": "Ngã"}, {"term_ko": "서혜부", "term_vi": "Vùng bẹn", "def_ko": "서혜부(한국어)", "def_vi": "Vùng bẹn"}, {"term_ko": "대퇴부", "term_vi": "Đùi", "def_ko": "허벅지(한국어)", "def_vi": "Đùi"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔(한국어)", "def_vi": "Đau"}, {"term_ko": "움직임", "term_vi": "Vận động", "def_ko": "운동(한국어)", "def_vi": "Vận động"}, {"term_ko": "제한", "term_vi": "Hạn chế", "def_ko": "제한하다(한국어)", "def_vi": "Hạn chế"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병(한국어)", "def_vi": "Bệnh"}, {"term_ko": "골절", "term_vi": "Gãy", "def_ko": "부러지다(한국어)", "def_vi": "Gãy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (920, '5', '골다공증으로 인한 골절을 예방할 수 있는 방법은?', '["온열요법을 실시한다.", "체중부하운동을 한다.", "자외선 차단제를 바른다.", "혈전예방 약물을 복용한다.", "에스트로겐 섭취를 제한한다."]'::jsonb, 2, '골다공증을 예방하거나 관리하는 방법을 묻는 질문입니다.', NULL, '{"1": "온열요법은 골절 예방과 관련이 없습니다.\n[정답]", "2": "체중부하운동은 뼈를 강화하고 골절 예방에 도움이 됩니다.", "3": "자외선 차단제는 골다공증과 무관합니다.", "4": "혈전예방 약물은 골절 예방과 관련이 없습니다.", "5": "에스트로겐 섭취 제한은 필요하지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈의 밀도가 낮아져 약해지는 상태", "def_vi": "Tình trạng xương trở nên yếu do mật độ thấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (919, '5', '골다공증 예방에 도움을 주는 영양소는?', '["비타민A", "비타민B", "비타민C", "비타민D", "비타민E"]'::jsonb, 4, '골다공증 예방에 도움이 되는 영양소를 익히기 위한 문제입니다.', NULL, '{"1": "비타민A는 주로 시력과 면역기능에 도움을 줍니다.", "2": "비타민B는 에너지 대사와 관련된 비타민 그룹입니다.", "3": "비타민C는 항산화 작용과 면역력 강화에 중요합니다.\n[정답]", "4": "비타민D는 칼슘 흡수를 도와 골다공증 예방에 중요합니다.", "5": "비타민E는 항산화 작용을 하는 비타민입니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈의 밀도가 낮아지는 질병(한국어)", "def_vi": "Bệnh giảm mật độ xương"}, {"term_ko": "영양소", "term_vi": "Dưỡng chất", "def_ko": "신체에 필요한 영양 성분(한국어)", "def_vi": "Thành phần dinh dưỡng cần thiết cho cơ thể"}, {"term_ko": "비타민", "term_vi": "Vitamin", "def_ko": "인체에 필수적인 유기 화합물(한국어)", "def_vi": "Hợp chất hữu cơ cần thiết cho cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (918, '5', '골다공증 예방을 위한 비타민 D의 섭취에 도움이 되는 것은?', '["매일 30분씩 햇볕을 쬐며 걷는다.", "충분한 숙면을 취한다.", "비타민A를 섭취한다.", "카페인이 많은 커피를 섭취한다.", "실외 운동보다는 실내 운동을 강화한다."]'::jsonb, 1, '골다공증 예방과 비타민 D 섭취의 관계를 평가하는 것입니다.', NULL, '{"1": "햇볕을 쬐는 것은 비타민 D의 자연 생성에 도움을 줍니다.\n[정답]", "2": "충분한 숙면은 건강에 필요하지만 비타민 D와는 직접적인 연관이 없습니다.", "3": "비타민 A는 비타민 D와는 다른 역할을 하며, 비타민 D의 섭취에 도움을 주지 않습니다.", "4": "카페인이 많은 커피는 칼슘 흡수를 방해할 수 있어 골다공증 예방에 부정적입니다.", "5": "실내 운동보다 실외 운동이 비타민 D 합성에 더 효과적입니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Bệnh loãng xương", "def_ko": "뼈의 밀도가 낮아져 약해지는 질환", "def_vi": "Một căn bệnh mà mật độ xương giảm và làm xương trở nên yếu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (917, '5', '골다공증과 관련된 설명으로 옳은 것은?', '["뼈세포가 증가하여 골밀도가 높아진다.", "서혜부와 대퇴부에 통증이 온다", "칼슘섭취를 제한한다.", "햇볕에 노출되는 것을 피한다.", "비타민 D가 함유된 음식을 섭취한다."]'::jsonb, 5, '골다공증에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "뼈세포가 증가하면 오히려 골밀도가 낮아질 수 있습니다. \n[정답]", "5": "비타민 D는 칼슘 흡수에 중요한 역할을 하므로, 이를 포함한 식사를 하는 것이 중요합니다.", "2": "서혜부와 대퇴부의 통증은 골다공증의 직접적인 증상이 아닙니다.", "3": "칼슘 섭취는 골다공증 예방에 중요하므로 제한해서는 안 됩니다.", "4": "햇볕에 노출되는 것은 비타민 D 합성에 필요하므로 피해야 합니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈가 약해지고 쉽게 부러지는 병", "def_vi": "Bệnh làm xương yếu và dễ gãy"}, {"term_ko": "골밀도", "term_vi": "Mật độ xương", "def_ko": "뼈의 밀도", "def_vi": "Độ dày của xương"}, {"term_ko": "비타민 D", "term_vi": "Vitamin D", "def_ko": "칼슘 흡수에 중요한 비타민", "def_vi": "Vitamin quan trọng cho sự hấp thụ canxi"}, {"term_ko": "칼슘", "term_vi": "Canxi", "def_ko": "뼈를 형성하는 중요한 미네랄", "def_vi": "Khoáng chất quan trọng cho sự hình thành xương"}, {"term_ko": "햇볕", "term_vi": "Ánh nắng mặt trời", "def_ko": "태양의 빛", "def_vi": "Ánh sáng mặt trời"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (916, '5', '뼈세포가 상실되고 골밀도가 낮아져 골절이 발생하기 쉬운 질환은?', '["고관절 골절", "골다공증", "퇴행성 관절염", "대퇴골 골절", "척추 디스크"]'::jsonb, 2, '뼈세포가 상실되고 골밀도가 낮아지는 질환에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "고관절 골절: 골절에 대한 내용으로 관련성을 찾기 어려움.\n[정답]", "2": "골다공증: 뼈의 밀도가 감소하고 골절의 위험을 증가시키는 질환.", "3": "퇴행성 관절염: 관절의 연골이 닳아 없어지는 질환으로 골밀도와 관계 없음.", "4": "대퇴골 골절: 특정 부위의 골절로, 골밀도 문제의 직접적인 언급 없음.", "5": "척추 디스크: 디스크 문제로 골밀도와는 관계가 없음."}'::jsonb, '[{"term_ko": "뼈세포", "term_vi": "Tế bào xương", "def_ko": "뼈를 구성하는 세포", "def_vi": "Các tế bào cấu thành xương"}, {"term_ko": "골밀도", "term_vi": "Mật độ xương", "def_ko": "뼈의 밀도", "def_vi": "Độ đặc của xương"}, {"term_ko": "골절", "term_vi": "Gãy xương", "def_ko": "뼈가 부서짐", "def_vi": "Sự gãy của xương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (915, '5', '퇴행성 관절염이 있는 대상자에게 적합한 운동으로 옳은 것은?', '["등산", "수영", "배드민턴", "계단 오르내리기", "장거리 걷기"]'::jsonb, 2, '퇴행성 관절염 환자에게 적합한 운동을 찾기 위한 질문입니다.', NULL, '{"1": "등산은 무릅에 부담이 되어 좋지 않습니다.\n[정답]", "2": "수영은 관절의 부담을 덜어주면서 전신 운동이 가능하여 좋습니다.", "3": "배드민턴은 빠른 움직임이 필요해 관절에 무리가 갈 수 있습니다.", "4": "계단 오르내리기는 관절에 큰 부담을 준다.", "5": "장거리 걷기는 무릎에 부담이 커질 수 있습니다."}'::jsonb, '[{"term_ko": "퇴행성 관절염", "term_vi": "Viêm khớp thoái hóa", "def_ko": "관절의 소모성 질환", "def_vi": "Bệnh lý hao mòn khớp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (914, '5', '퇴행성 관절염을 예방하는 방법으로 옳은 것은?', '["체중 줄이기", "계단 오르내리기", "무거운 것 들기", "등산 하기", "장거리 걷기"]'::jsonb, 1, '퇴행성 관절염 예방에 관한 기본적인 지식을 평가하고자 함.', NULL, '{"1": "체중을 줄이면 관절에 가해지는 부담을 줄어들게 하여 퇴행성 관절염을 예방할 수 있다.\n[정답]", "2": "계단 오르내리기는 무릎 관절에 부담을 심하게 주어 퇴행성 관절염을 유발할 수 있다.", "3": "무거운 것을 드는 것은 관절에 부하를 주어 위험하다.", "4": "등산은 무릎에 부담을 주어 관절염을 악화시킬 수 있다.", "5": "장거리 걷기는 관절에 과도한 스트레스를 줄 수 있어 주의가 필요하다."}'::jsonb, '[{"term_ko": "퇴행성", "term_vi": "Thoái hóa", "def_ko": "노화나 외상 등으로 인하여 나타나는 질병", "def_vi": "Bệnh xuất hiện do lão hóa hoặc chấn thương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (913, '5', '다음과 같은 증상이 나타나는 노인성 질환으로 옳은 것은?• 연골이 닳아서 없어지는 상태이다.• 아침에 일어나면 관절이 뻣뻣해진다.• 운동 시 악화되고 안정 시 호전된다.', '["퇴행성 관절염", "류마티스 관절염", "골다공증", "고관절 골절", "골연화증"]'::jsonb, 1, '노인성 질환의 증상에 따른 정확한 질환을 파악하는 것.', NULL, '{"1": "퇴행성 관절염은 연골이 닳아 없어지는 상태로 아침에 뻣뻣함과 운동 시 악화되는 증상이 나타난다.\n[정답]", "2": "류마티스 관절염은 관절의 염증으로 전신 증상이 동반되며, 증상 양상이 다르다.", "3": "골다공증은 뼈의 밀도가 감소하여 쉽게 골절되는 병으로 관절의 증상과는 다르다.", "4": "고관절 골절은 외부의 힘에 의해 발생하는 손상으로 노인에서 흔히 발생하지만 위의 증상과는 관련이 없다.", "5": "골연화증은 뼈의 질감이 부드러워지는 병으로, 관절 문제와는 관련이 없다."}'::jsonb, '[{"term_ko": "노인성 질환", "term_vi": "Bệnh tuổi già", "def_ko": "노인에서 발생하는 질병", "def_vi": "Bệnh lý phát sinh ở người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (912, '5', '노화에 따른 근골격계 변화로 옳은 것은?', '["추간판이 얇아진다.", "항가골이 단단해진다.", "근육의 피로도가 감소한다.", "인대의 탄력성이 증가한다.", "팔, 다리의 지방이 증가한다."]'::jsonb, 1, '노화에 따른 근골격계의 변화를 이해하고 옳은 내용을 찾는 것이 문제의 주요 의도입니다.', NULL, '{"1": "노화로 인해 추간판이 얇아지는 것은 일반적인 변화입니다. \n[정답]", "2": "항가골이 단단해지는 것은 사실이 아닙니다. 노화에 따라 항가골의 밀도가 감소할 수 있습니다.", "3": "근육의 피로도는 오히려 증가하는 경향이 있습니다.", "4": "인대의 탄력성은 노화와 함께 감소합니다.", "5": "팔, 다리의 지방은 노화에 따라 증가할 수 있습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "근골격계", "def_ko": "늙음, Lão hóa", "def_vi": "근육과 뼈로 이루어진 계통, Hệ cơ xương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (911, '5', '노화에 따른 근골격계 변화로 옳은 것은?', '["뼈의 질량 증가", "근긴장도 증가", "관절운동의 제한", "어깨가 넓어지고 골반이 작아짐", "엉덩이와 허리의 피하지방 감소"]'::jsonb, 3, '노화에 따른 근골격계의 변화를 이해하고, 그에 맞는 변화를 식별하는 능력을 평가하기 위함입니다.', NULL, '{"1": "뼈의 질량은 보통 노화에 따라 감소합니다.", "2": "근긴장도는 노화와 함께 감소하는 경향이 있습니다.\n[정답]", "3": "노화가 진행됨에 따라 관절의 운동 범위가 줄어드는 현상이 관찰됩니다.", "4": "어깨가 넓어지기보다는 노화로 인해 수축하는 경향이 있습니다.", "5": "엉덩이와 허리의 피하지방은 대개 증가하는 경향이 있습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙어가는 것", "def_vi": "Quá trình già đi"}, {"term_ko": "근골격계", "term_vi": "Hệ cơ xương", "def_ko": "근육과 뼈의 시스템", "def_vi": "Hệ thống cơ và xương"}, {"term_ko": "관절", "term_vi": "Khớp", "def_ko": "두 개 이상의 뼈가 만나는 곳", "def_vi": "Nơi hai hoặc nhiều xương gặp nhau"}, {"term_ko": "운동", "term_vi": "Vận động", "def_ko": "신체의 움직임", "def_vi": "Sự di chuyển của cơ thể"}, {"term_ko": "근긴장도", "term_vi": "Độ căng cơ", "def_ko": "근육의 긴장감", "def_vi": "Độ căng của cơ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (910, '5', '심장질환 대상자가 복도를 걷다가 갑자기 어지럼증을 호소할 때 우선적으로 해야 할 행동은?', '["따뜻한 설탕물을 준다.", "식사를 했는지 확인한다.", "바로 그 자리에 주저앉힌다.", "스트레스받은 일이 있는지 물어본다.", "즉시 도움을 요청하러 시설장에게 간다."]'::jsonb, 3, '심장질환 대상자가 갑작스러운 어지럼증을 호소할 때 신속하게 대처하는 방법을 평가하기 위함입니다.', NULL, '{"1": "따뜻한 설탕물을 주는 것은 저혈당을 의심할 때 도움이 될 수 있으나, 이 경우에는 즉각적인 대처가 필요합니다.\n[정답]", "3": "바로 그 자리에 주저앉히는 것이 안전하며, 이는 어지럼증으로 인해 넘어질 위험을 줄입니다.", "2": "식사를 했는지 확인하는 것은 중요하지만, 즉각적인 응급조치가 필요합니다.", "4": "스트레스를 물어보는 것도 중요하지만, 어지럼증의 즉각적인 원인 파악보다 우선하여 안전하게 대처해야 합니다.", "5": "도움을 요청하러 가는 것은 적절한 행동이지만, 환자의 안전이 우선시되어야 하므로 즉시 도움을 요청하기 전에 환자를 안전하게 해야 합니다."}'::jsonb, '[{"term_ko": "심장질환", "term_vi": "Bệnh tim", "def_ko": "심장과 관련된 질병", "def_vi": "Bệnh liên quan đến tim"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (909, '5', '노인 대상자에게 흔히 나타나는 빈혈의 원인은?', '["칼슘 부족", "비타민A 부족", "비타민 D 부족", "철분 부족", "단백질 부족"]'::jsonb, 4, '노인 대상자에게 나타나는 빈혈의 원인을 이해하고 평가하는 것.', NULL, '{"1": "칼슘이 부족해도 빈혈은 발생할 수 있지만, 주원인은 아님.\n[정답]", "4": "철분 부족은 빈혈의 가장 일반적인 원인 중 하나로, 특히 노인에게서 흔히 나타남.", "2": "비타민 A 부족은 시력 저하 등의 문제를 일으킬 수 있으나 빈혈과는 직접적인 관계가 적음.", "3": "비타민 D 부족은 뼈 건강에 중요한 요소이나 빈혈과는 관련이 없음.", "5": "단백질 부족은 여러 건강 문제를 초래할 수 있으나 빈혈의 직접적인 원인은 아님."}'::jsonb, '[{"term_ko": "빈혈", "term_vi": "Thiếu máu", "def_ko": "혈액 내 헤모글로빈 농도가 낮아지는 상태", "def_vi": "Tình trạng giảm mức độ hemoglobin trong máu"}, {"term_ko": "철분", "term_vi": "Sắt", "def_ko": "혈액 생성에 중요한 미네랄", "def_vi": "Khoáng chất quan trọng cho sự tạo máu"}, {"term_ko": "칼슘", "term_vi": "Canxi", "def_ko": "뼈 건강에 필요한 미네랄", "def_vi": "Khoáng chất cần thiết cho sức khỏe xương"}, {"term_ko": "비타민", "term_vi": "Vitamin", "def_ko": "신체 기능을 지원하는 유기 화합물", "def_vi": "Hợp chất hữu cơ hỗ trợ chức năng cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (908, '5', '빈혈로 철분제를 복용하고 있는 대상자가 어지럼증을 호소할 때 우선적으로 해야 할 일은?', '["영양주사를 맞힌다.", "햇볕을 쬐며 산책을 한다.", "낮잠을 자도록 돕는다.", "처방된 철분제를 복용했는지 확인한다.", "고지방식이로 영양을 공급한다."]'::jsonb, 4, '빈혈로 철분제를 복용 중인 환자가 어지럼증을 느낄 때 적절한 대처법을 알기 위함입니다.', NULL, '{"1": "영양주사를 맞히는 것은 필요하지 않습니다.", "2": "햇볕을 쬐며 산책하는 것은 어지럼증에 도움이 되지 않을 수 있습니다.", "3": "낮잠을 자도록 돕는 것은 일시적인 해결책이 될 수 있습니다.\n[정답]", "4": "처방된 철분제를 복용했는지 확인하는 것이 가장 중요합니다.", "5": "고지방식이로 영양을 공급하는 것은 비효율적입니다."}'::jsonb, '[{"term_ko": "빈혈", "term_vi": "Thiếu máu", "def_ko": "적혈구 또는 헤모글로빈 부족으로 인한 상태", "def_vi": "Tình trạng thiếu hồng cầu hoặc hemoglobin"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (907, '5', '심부전증 대상자를 돕는 방법으로 옳은 것은?', '["매일 체중을 측정한다.", "식사량을 늘려 제공한다.", "탄력스타킹을 항상 신게 한다.", "온, 냉탕을 오가며 목욕하게 한다.", "계단오르기 운동을 규칙적으로 하게 한다."]'::jsonb, 1, '심부전증 대상자에게 적절한 관리 방법을 물어보는 문제입니다.', NULL, '{"1": "심부전증 환자는 체중의 변화를 지속적으로 관찰해야 합니다. 체중 증가가 부종의 지표가 될 수 있기 때문입니다.\n[정답]", "2": "심부전증 환자는 식사량을 늘리는 것이 아니라 적절한 양의 식사를 하여 나트륨 섭취를 줄여야 합니다.", "3": "탄력스타킹을 착용하는 것은 부종을 방지하는 데 도움이 되지만, 항상 신게 할 필요는 없습니다.", "4": "온, 냉탕을 오가며 목욕하는 것은 심부전 환자에게 위험할 수 있습니다.", "5": "계단오르기 운동은 심부전증 관리에는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "심부전증", "term_vi": "対象者", "def_ko": "질병의 일종 - 心衰", "def_vi": "환자 - Đối tượng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (906, '5', '혈액 내에 적혈구나 헤모글로빈이 부족하여 몸에 필요한 산소를 충분히 공급하지 못하는 질병은?', '["기흉", "빈혈", "심부전", "협심증", "혈전색전증"]'::jsonb, 2, '혈액 내 적혈구나 헤모글로빈의 부족으로 인해 충분한 산소 공급이 이루어지지 않는 질병을 확인하고자 하는 문제임.', NULL, '{"1": "기흉: 폐와 흉막 사이에 공기가 찬 상태로 호흡곤란을 일으킬 수 있다.\n[정답]", "2": "빈혈: 적혈구나 헤모글로빈이 부족하여 몸에 필요한 산소를 충분히 공급하지 못하는 질병이다.", "3": "심부전: 심장이 제대로 기능하지 못해 몸의 여러 기관에 산소 공급이 부족할 수 있다.", "4": "협심증: 심장에 혈액이 충분히 공급되지 않아 가슴 통증이 발생하는 질환이다.", "5": "혈전색전증: 혈전에 의해 혈관이 막히는 현상으로, 특정 부위의 혈액 공급을 차단한다."}'::jsonb, '[{"term_ko": "혈액", "term_vi": "Máu", "def_ko": "피(한국어)", "def_vi": "máu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (905, '5', '심부전증을 예방하는 방법으로 옳은 것은?', '["고혈압을 치료한다.", "흡연을 한다.", "고염식이를 섭취한다.", "물을 많이 마신다.", "과식을 한다."]'::jsonb, 1, '심부전증 예방과 관련된 올바른 생활습관을 이해하는 것이 중요합니다.', NULL, '{"1": "고혈압은 심부전증의 위험 요소 중 하나이므로 치료는 예방에 도움이 됩니다.\n[정답]", "2": "흡연은 심혈관 질환의 위험을 증가시켜 심부전증 예방에 도움이 되지 않습니다.", "3": "고염식이는 고혈압 및 심부전에 악영향을 미치므로 피해야 합니다.", "4": "물을 많이 마시는 것이 심부전 예방에 직접적으로 도움이 되지는 않습니다.", "5": "과식은 비만과 관련되어 심부전증 위험을 증가시킵니다."}'::jsonb, '[{"term_ko": "심부전증", "term_vi": "Suy tim", "def_ko": "심장이 혈액을 충분히 펌프질하지 못하는 상태(한국어)", "def_vi": "Tình trạng tim không bơm đủ máu(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (904, '5', '다음 증상과 관련이 깊은 질환은?심장의 수축력 저하로 신체에 적절한 산소와 영양분을 공급받지 못하여 허약감, 피로, 호흡곤란을 느끼게 되며 걷기, 계단 오르기, 쇼핑하기 등 일상 생활에 어려움이 나타난다.', '["관절염", "고혈압", "심부전", "폐결핵", "동맥경화증"]'::jsonb, 3, '심장의 기능 저하와 관련된 질환에 대한 이해를 요구하는 문제입니다.', NULL, '{"1": "관절염은 주로 관절에 염증이 생기는 질환으로, 해당 증상과는 관련이 없습니다.\n[정답]", "3": "심부전은 심장의 수축력이 저하되어 적절한 혈액 공급이 이루어지지 않아 허약감, 피로, 호흡곤란 등의 증상을 유발합니다.", "2": "고혈압은 혈압 상승으로 인한 문제로, 직접적인 수축력 저하와는 관련이 없습니다.", "4": "폐결흉은 폐 관련 질환으로 호흡기 증상이 주로 나타나며, 심부전과는 차이가 있습니다.", "5": "동맥경화증은 혈관의 경화로 여러 가지 심혈관계에 영향을 미칠 수 있지만, 주된 증상은 아닙니다."}'::jsonb, '[{"term_ko": "심장", "term_vi": "Tim", "def_ko": "심장(한국어)", "def_vi": "trái tim"}, {"term_ko": "수축력", "term_vi": "Sức co bóp", "def_ko": "혈액을 내보내는 힘(한국어)", "def_vi": "sức mạnh bơm máu"}, {"term_ko": "허약감", "term_vi": "Cảm giác yếu đuối", "def_ko": "힘이 없음(한국어)", "def_vi": "cảm giác không có sức"}, {"term_ko": "호흡곤란", "term_vi": "Khó thở", "def_ko": "숨쉬기 힘든 상태(한국어)", "def_vi": "tình trạng khó thở"}, {"term_ko": "일상 생활", "term_vi": "Cuộc sống hàng ngày", "def_ko": "매일 하는 활동(한국어)", "def_vi": "hoạt động hàng ngày"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (903, '5', '심부전의 증상으로 옳은 것은?가. 좌식호흡 나. 식욕상실 다. 의식혼돈, 현기증 라. 언어장애', '["가,라", "가, 나, 라", "나, 라", "가, 다, 라", "가, 나, 다"]'::jsonb, 5, '심부전의 증상에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "가: 좌식호흡은 심부전의 증상으로 보지 않으며, 라: 언어장애는 일반적으로 심부전과는 관련이 없습니다.", "2": "가: 좌식호흡은 심부전의 증상이 아니고, 나: 식욕상실은 심부전의 일반적인 증상입니다.\n[정답]", "5": "가: 좌식호흡은 심부전의 증상이 아니며, 나: 식욕상실과 다: 의식혼돈, 현기증은 심부전의 중요한 증상으로 포함됩니다.", "3": "나: 식욕상실은 맞지만, 라: 언어장애는 심부전과 관계가 없습니다.", "4": "가: 좌식호흡은 심부전 증상이 아니므로 틀립니다."}'::jsonb, '[{"term_ko": "심부전", "term_vi": "Suy tim", "def_ko": "심장이 제 기능을 하지 못하는 상태", "def_vi": "Tình trạng tim không hoạt động bình thường"}, {"term_ko": "좌식호흡", "term_vi": "Thở ngồi", "def_ko": "앉아서 호흡을 하는 것", "def_vi": "Thở trong tư thế ngồi"}, {"term_ko": "식욕상실", "term_vi": "Mất cảm giác thèm ăn", "def_ko": "음식에 대한 욕구가 줄어드는 것", "def_vi": "Giảm sự thèm ăn"}, {"term_ko": "의식혼돈", "term_vi": "Rối loạn ý thức", "def_ko": "인지 기능의 장애", "def_vi": "Sự rối loạn về nhận thức"}, {"term_ko": "현기증", "term_vi": "Chóng mặt", "def_ko": "어지럼증을 느끼는 것", "def_vi": "Cảm giác choáng váng"}, {"term_ko": "언어장애", "term_vi": "Rối loạn ngôn ngữ", "def_ko": "말하는 데 어려움이 있는 것", "def_vi": "Khó khăn trong giao tiếp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (902, '5', '심장의 수축력이 저하되어 저산소증이 올 때 나타나는 증상은?', '["의식혼돈", "부종", "흉객혈통", "객혈", "언어장애"]'::jsonb, 1, '심장의 수축력이 저하되어 저산소증이 발생할 때 나타나는 증상을 이해하고 구별하기 위함입니다.', NULL, '{"1": "의식혼돈: 저산소증으로 인해 뇌에 충분한 산소 공급이 이루어지지 않아 혼돈 상태를 유발할 수 있습니다.\n[정답]", "2": "부종: 심장 기능 저하로 수분이 체내에 축적되며 부종이 발생할 수 있으나 주된 증상과는 거리가 있습니다.", "3": "흉객혈통: Кордиум 관상동맥의 질환으로 인한 통증이지만 저산소증과 직접적 연관은 없습니다.", "4": "객혈: 폐혈관의 문제일 가능성이 있지만 저산소증과는 명확하게 연결되지 않습니다.", "5": "언어장애: 뇌의 산소 부족으로 언어에 문제가 생길 수 있으나 이는 다른 요인과의 관련성이 크기 때문에 주된 증상으로 보기 어렵습니다."}'::jsonb, '[{"term_ko": "심장", "term_vi": "Trái tim", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "수축력", "term_vi": "Sức co bóp", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "저산소증", "term_vi": "Thiếu oxy", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "혼돈", "term_vi": "Lẫn lộn", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (901, '5', '동맥경화증이 있는 대상자에게 적합한 음식은?', '["새우튀김", "제육볶음", "토마토", "부대찌개", "오징어 젓갈"]'::jsonb, 3, '동맥경화증 환자에게 적합한 식단을 이해하고 올바른 선택을 할 수 있는지 평가하기 위함입니다.', NULL, '{"1": "새우튀김은 기름에 튀겨져 있는 고열량 음식으로 적합하지 않습니다.", "2": "제육볶음은 지방이 많아 동맥경화증 환자에게 좋지 않습니다.\n[정답]", "3": "토마토는 항산화 물질이 풍부하고 심혈관 건강에 도움을 줍니다.", "4": "부대찌개는 여러 재료가 들어가고 기름기가 많아 부적합합니다.", "5": "오징어 젓갈은 나트륨 함량이 높아 좋지 않은 선택입니다."}'::jsonb, '[{"term_ko": "동맥경화증", "term_vi": "Xơ vữa động mạch", "def_ko": "혈관의 벽에 지방, 콜레스테롤 등이 쌓이는 병증", "def_vi": "Bệnh lý tích tụ chất béo, cholesterol vào thành mạch"}, {"term_ko": "적합한", "term_vi": "Phù hợp", "def_ko": "적절한, 맞는", "def_vi": "Thích hợp, đúng"}, {"term_ko": "음식", "term_vi": "Thực phẩm", "def_ko": "식사나 간식으로 먹는 것", "def_vi": "Món ăn, món ngon"}, {"term_ko": "토마토", "term_vi": "Cà chua", "def_ko": "한 종류의 채소, 붉은색", "def_vi": "Một loại rau củ, màu đỏ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (900, '5', '동맥경화증의 원인으로 옳은 것은?', '["저염식이 섭취", "규칙적인 운동", "저지방식이 섭취", "당뇨병, 고지혈증, 고혈압", "가족적 소인은 없다."]'::jsonb, 4, '동맥경화증의 주요 원인에 대한 이해를 확립하기 위한 문제입니다.', NULL, '{"1": "저염식이 섭취는 동맥경화증을 예방하는데 도움이 될 수 있습니다.", "2": "규칙적인 운동도 심혈관 건강에 좋습니다.\n[정답]", "4": "당뇨병, 고지혈증, 고혈압은 동맥경화증의 주요한 위험 인자입니다.", "3": "저지방식이 섭취는 동맥경화증을 예방하는데 기여할 수 있습니다.", "5": "가족적 소인은 동맥경화증에 영향을 미칠 수 있습니다."}'::jsonb, '[{"term_ko": "동맥경화증", "term_vi": "Xơ vữa động mạch", "def_ko": "혈관 벽에 지방, 콜레스테롤 등이 축적되어 혈관이 좁아지는 질환", "def_vi": "Bệnh mà ở thành mạch máu tích tụ mỡ, cholesterol làm hẹp lòng mạch"}, {"term_ko": "원인", "term_vi": "Nguyên nhân", "def_ko": "어떤 일이 일어나는 이유", "def_vi": "Lý do xảy ra một sự việc"}, {"term_ko": "당뇨병", "term_vi": "Bệnh đái tháo đường", "def_ko": "인체의 혈당 수치 조절이 어려운 질병", "def_vi": "Bệnh mà cơ thể khó kiểm soát mức đường huyết"}, {"term_ko": "고지혈증", "term_vi": "Rối loạn lipid máu", "def_ko": "혈액 중의 지질 성분이 비정상적으로 높은 상태", "def_vi": "Tình trạng lipid trong máu quá cao bất thường"}, {"term_ko": "고혈압", "term_vi": "Tăng huyết áp", "def_ko": "혈압이 비정상적으로 높은 상태", "def_vi": "Tình trạng huyết áp cao bất thường"}, {"term_ko": "가족적", "term_vi": "Di truyền", "def_ko": "가족과 관련된", "def_vi": "Liên quan đến gia đình"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (899, '5', '관상동맥이 동맥경화로 좁아져 심장근육에 충분한 산소공급을 하지 못할 때 발생하는 통증은?', '["복통", "요통", "흉통", "관절통", "신경통"]'::jsonb, 3, '관상동맥이 동맥경화로 인해 심장근육에 충분한 산소를 공급하지 못하는 상황을 이해하고, 이로 인해 나타나는 통증의 유형을 묻는 문제입니다.', NULL, '{"1": "복통은 위장관 계통의 문제로 발생하는 통증입니다.", "2": "요통은 허리나 주변 부위의 통증으로, 심장과 관련이 없습니다.\n[정답]", "3": "흉통은 심장에 공급되는 혈액이나 산소의 부족으로 인해 발생하는 통증입니다.", "4": "관절통은 관절에서 발생하는 통증으로 심장과 관련이 없습니다.", "5": "신경통은 신경의 손상이나 자극으로 인해 발생하는 통증입니다."}'::jsonb, '[{"term_ko": "관상동맥", "term_vi": "Động mạch vành", "def_ko": "심장의 혈액을 공급하는 동맥", "def_vi": "Động mạch cung cấp máu cho tim"}, {"term_ko": "동맥경화", "term_vi": "Xơ vữa động mạch", "def_ko": "동맥에 지방, 콜레스테롤이 쌓이는 상태", "def_vi": "Tình trạng tích tụ mỡ, cholesterol trong động mạch"}, {"term_ko": "산소", "term_vi": "Oxy", "def_ko": "생명 유지에 필수적인 기체", "def_vi": "Khí thiết yếu cho sự sống"}, {"term_ko": "심장근육", "term_vi": "Cơ tim", "def_ko": "심장 벽을 구성하여 심장의 수축을 담당하는 근육", "def_vi": "Cơ cấu tạo nên thành tim, chịu trách nhiệm co bóp của tim"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "불쾌한 감각이나 느낌", "def_vi": "Cảm giác hay cảm xúc khó chịu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (898, '5', '고혈압 대상자의 관리 방법으로 옳은 것은?', '["체중을 서서히 늘린다.", "복부 비만이라도 표준체중이면 정상이다.", "일주일에 3~5회, 30분 이상 땀이 날 정도로 운동한다.", "포화지방이 많은 음식을 섭취하여 혈압을 조절한다.", "혈압을 낮추기 위해 하루 15g 이상 염분을 섭취한다."]'::jsonb, 3, '고혈압 대상자의 올바른 관리 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "체중을 서서히 늘리는 것은 고혈압 관리에 도움이 되지 않습니다.\n[정답]", "3": "일주일에 3~5회, 30분 이상 땀이 날 정도로 운동하는 것은 고혈압 관리에 효과적입니다.", "2": "복부 비만이라도 표준체중이면 정상이라는 것은 잘못된 정보입니다.", "4": "포화지방이 많은 음식을 섭취하여 혈압을 조절한다는 것은 사실과 다릅니다.", "5": "날마다 15g 이상의 염분 섭취는 혈압을 높일 수 있으므로 피해야 합니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "운동", "def_ko": "높은 혈압(압 suất máu cao)", "def_vi": "신체 활동(hoạt động thể chất)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (897, '5', '뒷머리가 뻐근하게 아프고 어지럽거나 흐리게 보이며 이른 아침에 두통 증상이 나타나는 질환은?', '["동맥경화증", "고혈압", "심부전", "빈혈", "뇌졸증"]'::jsonb, 2, '두통 증상과 관련된 질환을 묻는 문제입니다.', NULL, '{"1": "동맥경화증은 혈관의 경직과 관련된 질환으로 두통과는 직접적으로 연관이 없습니다.\n[정답]", "2": "고혈압은 두통의 일반적인 원인 중 하나로 이른 아침에 나타나는 경우가 많습니다.", "3": "심부전은 심장과 관련된 문제로 두통이 주요 증상이지 않습니다.", "4": "빈혈은 일반적으로 졸림, 피로감 등의 증세가 더 두드러집니다.", "5": "뇌졸증은 심각한 신경학적 증상으로 두통은 나타날 수 있지만, 문제에서 설명한 증상과는 걸맞지 않습니다."}'::jsonb, '[{"term_ko": "두통", "term_vi": "Đau đầu", "def_ko": "통증(한국어)", "def_vi": "Đau trong đầu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (896, '5', '고혈압 대상자의 혈압약 복용 방법으로 옳은 것은?', '["혈압이 조절되면 약 복용을 중단한다.", "체중이 감소하면 복용량을 줄인다.", "혈압이 높아지면 복용량을 늘린다.", "투약 후에도 고혈압이 지속되면 의사와 상의한다.", "몸이 약해지므로 장기간 투약하지 않는다."]'::jsonb, 4, '고혈압 관리에 대한 올바른 약물 복용 방법을 이해하고 있는지 확인하기 위함입니다.', NULL, '{"1": "혈압이 조절되었다고 해서 약 복용을 중단해서는 안 됩니다. 약물은 지속적으로 복용해야 합니다.\n[정답]", "4": "고혈압이 지속될 경우 반드시 의사와 상의해야 하며, 이는 안전한 치료를 위해 중요합니다.", "2": "체중 감소가 약물 복용량에 직접적인 영향을 주는 것은 아닙니다.", "3": "혈압이 높아졌다고 해서 복용량을 즉시 늘리는 것은 불필요할 수 있으며, 의사의 지시에 따라야 합니다.", "5": "고혈압 관리에 있어 장기간 투약은 필수적이며, 환자의 상태에 따라 의사가 결정합니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "Tăng huyết áp", "def_ko": "고혈압(한국어)", "def_vi": "Huyết áp cao"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (895, '5', '고혈압 대상자가 장기간 약물 복용 후 정상적인 혈압을 유지할 때 돕는 방법은?', '["운동으로만 관리한다.", "증상이 없으면 약 복용을 중단한다.", "금식인 경우에는 혈압약을 먹지 않는다.", "두통이 있을 때만 약을 복용한다.", "혈압이 조절되어도 처방된 혈압약은 계속 복용한다."]'::jsonb, 5, '고혈압 관리에 대한 올바른 약물 복용의 중요성을 확인하기 위함입니다.', NULL, '{"1": "운동으로만 관리한다: 고혈압 관리에는 운동이 중요하지만, 약물 치료도 필요하다.\n[정답]", "5": "혈압이 조절되어도 처방된 혈압약은 계속 복용한다: 약물의 지속적인 복용은 혈압 조절에 필수적이다.", "2": "증상이 없으면 약 복용을 중단한다: 증상이 없어도 혈압 조절을 위해 약물 복용이 필요하다.", "3": "금식인 경우에는 혈압약을 먹지 않는다: 금식 중에도 의료진의 지시에 따라 약을 복용해야 할 수 있다.", "4": "두통이 있을 때만 약을 복용한다: 두통 외에도 약물을 정기적으로 복용하는 것이 중요하다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "약물", "def_ko": "높은 혈압(압 suất của máu)", "def_vi": "약 또는 thuốc chữa bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (894, '5', '다음 중 고혈압에 관련된 설명으로 옳은 것은?', '["혈관이 좁아지면 혈압은 낮아진다.", "혈압은 측정 시간과 자세에 따라 다르다.", "이완기 혈압은 심장이 혈액을 내보낼 때의 압력이다.", "본태성 고혈압은 원인 질병이 치료되면 정상화된다.", "대부분의 고혈압은 다른 질병의 합병증으로 발생한다."]'::jsonb, 2, '고혈압에 대한 기본적인 이해를 평가하고, 관련된 정보의 정확성을 확인하기 위함입니다.', NULL, '{"1": "혈관이 좁아지면 혈압이 높아지는 것이 일반적입니다. 이는 혈액이 흐르는 경로가 좁아지기 때문에 압력이 증가하는 원리입니다.\n[정답]", "2": "혈압은 측정 시간과 자세에 따라 변동할 수 있으며, 이는 정상적인 생리적 현상입니다.", "3": "이완기 혈압은 심장이 이완될 때 혈관 내 압력을 의미합니다. 따라서 심장이 혈액을 내보낼 때의 압력은 수축기 혈압입니다.", "4": "본태성 고혈압은 원인질환이 없는 고혈압으로, 원인 치료에 따라 항상 정상으로 돌아오지 않습니다.", "5": "대부분의 고혈압은 본태성 고혈압이며, 안타깝게도 다른 질병의 합병증으로 발생하기보다는 독립적으로 존재하는 경우가 많습니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "혈관", "def_ko": "높은 혈압(압 suất máu cao)", "def_vi": "몸의 혈액을 전달하는 구조(mạch máu)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (893, '5', '오랫동안 심혈관 질환을 앓고 있는 대상자에게 발생할 수 있는 문제는?', '["우울증으로 인한 자해", "감각이상으로 인한 괴사", "골격이상으로 인한 골절", "청각이상으로 인한 교통사고", "기립성 저혈압으로 인한 낙상"]'::jsonb, 5, '심혈관 질환이 있는 대상자에게 나타날 수 있는 합병증 및 관련 문제를 이해하고 있는지 평가하기 위함입니다.', NULL, '{"1": "우울증은 심혈관 질환 환자에게 흔하게 발생할 수 있으나, 자해와는 직접적인 관련이 적습니다.\n[정답]", "5": "기립성 저혈압은 심혈관 질환 환자에게 자주 나타나는 문제로, 이는 낙상의 위험을 증가시킵니다.", "2": "감각이상으로 인한 괴사는 심혈관 질환의 직접적인 합병증은 아닙니다.", "3": "골격이상은 일반적인 심혈관 질환과는 관련이 적습니다.", "4": "청각이상은 심혈관과 직접적인 관련성이 적으며, 교통사고와의 연관성도 낮습니다."}'::jsonb, '[{"term_ko": "심혈관 질환", "term_vi": "Bệnh tim mạch", "def_ko": "심장과 혈관의 질환", "def_vi": "Bệnh liên quan đến tim và mạch máu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (892, '5', '노화에 따른 심혈관계 특성으로 옳은 것은?', '["최대 심박출량 증가", "최대 심박동수 증가", "심장의 탄력성 감소", "심장으로의 혈액순환 증가", "정맥의 탄력 증가"]'::jsonb, 5, '노화과정에서의 심혈관계 변화를 이해하고 확인하는 것.', NULL, '{"1": "최대 심박출량은 보통 감소한다.", "2": "최대 심박동수는 나이가 들면서 감소한다.\n[정답]", "3": "심장의 탄력성은 감소한다.", "4": "심장으로의 혈액순환은 일반적으로 감소한다.", "5": "정맥의 탄력은 보통 감소한다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이 들다", "def_vi": "Trở nên già"}, {"term_ko": "심혈관계", "term_vi": "Hệ tim mạch", "def_ko": "심장과 혈관으로 이루어진 계통", "def_vi": "Hệ thống bao gồm tim và mạch máu"}, {"term_ko": "심박출량", "term_vi": "Lưu lượng bơm máu", "def_ko": "심장에서 혈액이 흘러나오는 양", "def_vi": "Lượng máu chảy ra từ tim"}, {"term_ko": "심박동수", "term_vi": "Tần số nhịp tim", "def_ko": "심장이 뛰는 횟수", "def_vi": "Số lần tim đập"}, {"term_ko": "탄력성", "term_vi": "Độ đàn hồi", "def_ko": "늘어나는 성질", "def_vi": "Đặc tính co dãn"}, {"term_ko": "혈액순환", "term_vi": "Tuần hoàn máu", "def_ko": "심장과 혈관을 통해 혈액이 흐르는 과정", "def_vi": "Quá trình máu chảy qua tim và mạch máu"}, {"term_ko": "정맥", "term_vi": "Tĩnh mạch", "def_ko": "심장으로 혈액을 가져오는 혈관", "def_vi": "Mạch máu đưa máu về tim"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (891, '5', '노화에 따른 심혈관계 특성으로 옳은 것은?', '["말초혈관의 저항 감소", "하지정맥류 발생 감소", "기립성 저혈압 발생 감소", "심장 근육의 탄력성 증가", "정맥의 약화로 하지 부종 발생"]'::jsonb, 5, '노화에 따른 심혈관계의 변화를 이해하고, 그 특성에 대해 올바른 선택지를 고르는 것.', NULL, '{"1": "말초혈관의 저항은 노화로 인해 증가한다.\n[정답]", "5": "정맥의 약화로 인해 하지 부종이 발생할 수 있다.", "2": "하지정맥류의 발생은 오히려 증가한다.", "3": "기립성 저혈압의 발생도 증가한다.", "4": "심장 근육의 탄력성은 감소한다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이의 증가(한국어)", "def_vi": "Sự gia tăng tuổi tác(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (890, '5', '폐결핵 의심 대상자와 접촉했을 때 요양보호사의 대처 방법으로 옳은 것은?', '["결핵약을 즉시 복용한다.", "2~3일간 요양보호 서비스를 중단한다.", "사용하는 침구류는 강한 산이나 알칼리로 소독한다.", "2주~1개월 이후 반드시 X-ray 검진을 받아본다.", "대상자는 물론 가족과 요양보호사도 동시에 치료 받는다."]'::jsonb, 4, '폐결핵 의심 대상자를 접촉한 후 요양보호사가 어떻게 대처해야 하는지 이해시키기 위함입니다.', NULL, '{"1": "결핵약은 의사의 처방에 따라 복용해야 하므로 즉시 복용하는 것은 옳지 않습니다.\n[정답]", "4": "폐결핵 접촉 후 2주에서 1개월 이내에 X-ray 검사로 확인하는 것이 필요합니다.", "2": "요양보호 서비스 중단은 필요하지 않습니다.", "3": "침구류 소독은 필요하지만 적절한 방법이 아닙니다.", "5": "가족과 요양보호사도 치료받는 것은 권장되지만 반드시 동시에 치료를 받을 필요는 없습니다."}'::jsonb, '[{"term_ko": "폐결핵", "term_vi": "Bệnh lao phổi", "def_ko": "폐에서 발생하는 결핵", "def_vi": "Lao xảy ra trong phổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (889, '5', '다음 중 폐결핵에 대한 설명으로 옳은 것은?', '["바이러스성 만성질환이다.", "약물 복용이 끝ㅌ날 때까지 격리치료한다.", "약물 투여로 인한 위장장애, 피부 발진 등 부작용이 생긴다.", "대체로 오전에 열이 오르고, 오후에 열이 내린다.", "치료기간 중 증상이 없으면 약 복용을 중단한다"]'::jsonb, 3, '폐결핵에 대한 정확한 이해를 평가하기 위함입니다.', NULL, '{"1": "폐결핵은 세균성 질환으로, 바이러스성 만성질환이 아닙니다.\n[정답]", "3": "약물 투여로 인해 위장장애와 피부 발진 등의 부작용이 발생할 수 있습니다.", "2": "약물 복용이 끝날 때까지 격리 치료가 필요하지만, 일반적으로 격리 치료의 규정은 치료 단계에 따라 다릅니다.", "4": "폐결핵로 인한 열은 대개 오후에 더 심해지는 경향이 있습니다.", "5": "치료기간 중 증상이 없더라도 의사 지시에 따라 약 복용을 지속해야 합니다."}'::jsonb, '[{"term_ko": "폐결핵", "term_vi": "Bệnh lao phổi", "def_ko": "폐에서 발생하는 결핵 질환", "def_vi": "Bệnh lao xảy ra ở phổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (888, '5', '폐결핵에 대한 설명으로 옳은 것은?', '["항결핵제 중 한 가지 약물만 복용한다.", "주기적으로 간 기능 검사와 객담 검사를 실시한다.", "치료기간은 1주일이다.", "증상이 좋아지면 약의 양을 줄인다.", "결핵은 감염성이 매우 낮다."]'::jsonb, 2, '폐결핵에 대한 올바른 치료 및 관리 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "항결핵제는 여러 가지 약물을 조합하여 복용해야 합니다.\n[정답]", "2": "주기적으로 간 기능 검사와 객담 검사를 실시하는 것이 중요합니다.", "3": "치료기간은 보통 6개월 이상 걸립니다.", "4": "증상이 좋아지더라도 약을 조기 중단하면 효과가 떨어질 수 있으므로 주의해야 합니다.", "5": "결핵은 전염성이 높은 질병입니다."}'::jsonb, '[{"term_ko": "폐결핵", "term_vi": "Bệnh lao phổi", "def_ko": "폐에 생기는 결핵균 감염", "def_vi": "Nhiễm trùng do vi khuẩn lao ở phổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (887, '5', '다음 증상이 나타나는 질환은?• 오후에 고열이 있다가 늦은 밤에 식은땀과 함께 열이 내린다.• 피로감, 식욕부진, 체중감소• 호흡곤란과 흉막염이 나타난다.', '["폐렴", "천식", "폐결핵", "간염", "만성기관지염"]'::jsonb, 3, '환자의 증상으로부터 질환을 추론하는 것을 목적으로 함.', NULL, '{"1": "폐렴: 주로 고열과 기침 등의 증상이 나타나지만 식은땀과 체중 감소가 주 증상이 아님.\n[정답]", "3": "폐결핵: 오후에 고열과 식은땀, 체중 감소 등 전형적인 증상을 나타내며, 흉막염이 동반될 수 있음.", "2": "천식: 호흡곤란이 나타나지만 열과 체중 감소는 일반적이지 않음.", "4": "간염: 일반적으로 식욕부진과 피로가 있으나 고열과 식은땀은 주 증상이 아님.", "5": "만성기관지염: 호흡곤란이 있으나 고열과 함께 식은땀, 체중 감소는 동반되지 않음."}'::jsonb, '[{"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증상(한국어)", "def_vi": "triệu chứng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (886, '5', '폐결핵 발병 원인으로 옳은 것은?', '["결핵균의 호흡기 감염", "영양상태 양호", "면역력 증가", "혈액을 통한 감염", "미생물에 의한 피부 감염"]'::jsonb, 1, '폐결핵의 발병 원인을 이해하고, 올바른 선택지를 고르는 능력을 검증하기 위한 문제입니다.', NULL, '{"1": "결핵균인 Mycobacterium tuberculosis가 호흡기를 통해 감염되며, 폐결핵의 주요 원인입니다.\n[정답]", "2": "영양상태가 양호하면 면역력이 높아져 결핵 발병 위험이 낮아집니다.", "3": "면역력 증가는 결핵 발병에 영향을 미치는 요인이 아니므로 옳지 않습니다.", "4": "혈액을 통한 감염은 폐결핵의 일반적인 전파 경로가 아닙니다.", "5": "미생물에 의한 피부 감염은 폐결핵과 관련이 없습니다."}'::jsonb, '[{"term_ko": "폐결핵", "term_vi": "Bệnh lao phổi", "def_ko": "폐에 발생하는 결핵", "def_vi": "Lao xảy ra ở phổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (884, '5', '다음 증상이 나타나는 질환으로 옳은 것은?• 숨을 내쉴 때 쌕쌔거리는 호흡음• 만성 염증성 질환으로 기관지 벽의 부종과 기도 협착• 꽃가루, 집먼지진드기, 찬 공기 노출 시 기도의 과민반응', '["천식", "결핵", "후두염", "폐수종", "흉막염"]'::jsonb, 1, '호흡기 질환의 증상과 특징을 이해하고, 주어진 증상에 맞는 질환을 선택하도록 하여 요양보호사의 기초적인 진단 능력을 평가하기 위함입니다.', NULL, '{"1": "천식: 주어진 증상과 관련된 주요 특징을 모두 포함하고 있으며, 특히 쌕쌕거리는 호흡음과 기도의 과민반응이 특징입니다.\n[정답]", "2": "결핵: 주로 기침과 가래가 특징이며, 주어진 증상들과는 관련성이 낮습니다.", "3": "후두염: 주로 후두의 염증으로 인한 증상이며, 쌕쌕거리는 호흡음이 일반적이지 않습니다.", "4": "폐수종: 폐에 액체가 고이는 상태로, 호흡곤란을 유발하지만 주어진 증상과는 다릅니다.", "5": "흉막염: 흉막의 염증으로 호흡 시 통증이 주 증상인데, 주어진 증상들과 맞지 않습니다."}'::jsonb, '[{"term_ko": "호흡음", "term_vi": "Chứng âm thở", "def_ko": "소리(소리)", "def_vi": "Âm thanh của hơi thở"}, {"term_ko": "만성", "term_vi": "Mạn tính", "def_ko": "오랜 시간 동안 지속되는(kinh niên)", "def_vi": "Kéo dài lâu"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "신체가 감염이나 손상에 반응하여 발생하는 상태(viêm)", "def_vi": "Trạng thái phát sinh khi cơ thể phản ứng với nhiễm trùng hoặc tổn伤"}, {"term_ko": "부종", "term_vi": "Phù", "def_ko": "부풀어 오르다(swelling)", "def_vi": "Sưng lên"}, {"term_ko": "기도", "term_vi": "Đường thở", "def_ko": "호흡에 사용하는 통로(đường hô hấp)", "def_vi": "Cửa đường hô hấp"}, {"term_ko": "과민반응", "term_vi": "Phản ứng quá mẫn", "def_ko": "지나치게 민감하게 반응하는 상태(phản ứng quá mẫn)", "def_vi": "Trạng thái phản ứng quá mức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (883, '5', '천식 대상자의 기도 경련을 유발하거나 악화시키는 요인은?', '["찬 공기 노출", "복식 호흡", "독감 예방접종", "가벼운 실내운동", "뜨거운 물로 침구류 세탁"]'::jsonb, 1, '천식 환자에서 기도 경련을 유발하거나 악화시키는 원인을 이해하고 확인하는 것입니다.', NULL, '{"1": "찬 공기에 노출되면 기도가 수축되어 천식 증상이 악화될 수 있습니다.\n[정답]", "2": "복식 호흡은 천식 피해자의 기도를 이완시킬 수 있습니다.", "3": "독감 예방접종은 천식 발작과 직접적인 연관이 없습니다.", "4": "가벼운 실내 운동은 천식 환자에게 도움이 될 수 있습니다.", "5": "뜨거운 물로 침구류 세탁은 천식에 영향을 미치지 않습니다."}'::jsonb, '[{"term_ko": "천식", "term_vi": "Hen suyễn", "def_ko": "알레르기나 환경적 요인으로 인해 기도가 좁아지는 질환", "def_vi": "Bệnh khiến đường thở bị thu hẹp do dị ứng hoặc yếu tố môi trường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (882, '5', '기도의 만성 염증성 질환으로 숨을 내쉴 때 쌕쌕거리는 호흡음이 나는 호흡기 질환은?', '["폐렴", "천식", "폐결핵", "만성기관지염", "협심증"]'::jsonb, 2, '기침과 호흡음에 관한 이해를 평가하고자 하는 문제입니다.', NULL, '{"1": "폐렴은 폐에 염증이 생기는 질환으로, 쌕쌕거리는 소리와는 직접적인 연관이 적습니다.\n[정답]", "2": "천식은 기도의 만성 염증성 질환으로, 숨을 내쉴 때 쌕쌕거리는 호흡음이 특징입니다.", "3": "폐결핵은 결핵균에 의한 폐렴의 일종으로, 쌕쌕거림과는 다릅니다.", "4": "만성기관지염은 기도의 만성 염증이지만, 주로 기침과 가래가 특징입니다.", "5": "협심증은 심장의 문제로, 호흡기 질환이 아닙니다."}'::jsonb, '[{"term_ko": "기도", "term_vi": "염증", "def_ko": "기도(상기도와 하기도를 포함) / Đường hô hấp: Đường hô hấp (bao gồm đường hô hấp trên và dưới)", "def_vi": "염증(병리적 상태) / Viêm: Tình trạng bệnh lý"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (881, '5', '폐렴을 치료하는 방법으로 옳은 것은?', '["치내 혈액의 산소 농도를 적절하게 유지한다.", "수분 섭취를 제한한다.", "실내 습도를 높게 유지한다.", "항생제 사용을 금한다.", "주기적으로 객담 검사를 실시한다."]'::jsonb, 1, '폐렴은 호흡기 질환 중 하나로, 올바른 치료 방법을 이해하는 것이 중요하다.', NULL, '{"1": "치내 혈액의 산소 농도를 적절하게 유지하는 것은 폐렴 치료에서 중요한 요소이다.\n[정답]", "2": "수분 섭취를 제한하는 것은 오히려 건강에 해로울 수 있다.", "3": "실내 습도를 높게 유지하는 것은 일부 환자에게 도움이 될 수 있지만, 항상 필요한 것은 아니다.", "4": "항생제 사용을 금하는 것은 오히려 폐렴 치료에 부정적인 영향을 미친다.", "5": "주기적으로 객담 검사를 실시하는 것은 중요하지만, 치료 방법으로 보기에는 적합하지 않다."}'::jsonb, '[{"term_ko": "폐렴", "term_vi": "치료", "def_ko": "폐의 염증(viêm phổi)", "def_vi": "질병 또는 증상을 완화하거나 없애기 위한 방법(điều trị)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (880, '5', '음식물이나 이물질이 기도 내로 넘어가 기관지나 폐에 염증을 일으키는 질환은?', '["식도염", "폐렴", "위경련", "폐기종", "천식"]'::jsonb, 2, '음식물이나 이물질이 기도 내로 넘어가는 상황에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "식도염: 식도가 염증으로 인해 발생하는 질환으로, 기도의 염증과는 관련이 없습니다.\n[정답]", "2": "폐렴: 폐에 염증이 발생하는 질환으로, 음식물이나 이물질이 기도 내로 넘어가면서 발생할 수 있습니다.", "3": "위경련: 위의 근육 경련으로, 기도와는 관계가 없습니다.", "4": "폐기종: 폐 내의 공기주머니가 파괴되는 질환으로, 염증과는 다릅니다.", "5": "천식: 기도가 좁아지면서 나타나는 반응으로, 음식물이나 이물질의 침입과 직접적인 관계가 없습니다."}'::jsonb, '[{"term_ko": "기관지", "term_vi": "Phế quản", "def_ko": "기도의 가지 부분", "def_vi": "Phần nhánh của đường thở"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "조직이 부풀고 아픈 상태", "def_vi": "Trạng thái tổ chức sưng và đau"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병이나 질병", "def_vi": "Bệnh tật hoặc tình trạng bệnh lý"}, {"term_ko": "기타", "term_vi": "Khác", "def_ko": "기타라는 것을 포함한 여러 상태", "def_vi": "Bao gồm nhiều tình trạng khác nhau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (879, '5', '세균, 바이러스에 의한 폐 조직의 염증으로 호흡곤란, 가래, 기침이 나타나는 질병은?', '["폐렴", "폐암", "천식", "폐결핵", "만성기관지염"]'::jsonb, 1, '세균이나 바이러스 감염으로 인한 폐에 발생하는 염증과 그로 인한 증상을 이해하고 있는지 확인하려고 하는 문제입니다.', NULL, '{"1": "폐렴은 세균이나 바이러스에 의해 폐의 염증이 발생하며, 호흡곤란, 가래, 기침 등의 증상이 나타납니다.\n[정답]", "2": "폐암은 폐에 발생하는 악성 종양으로, 주로 기침, 체중 감소 등의 증상을 보이지만 염증은 아닙니다.", "3": "천식은 알레르기 등을 원인으로 하는 염증성 질환이지만, 세균이나 바이러스에 의한 것은 아닙니다.", "4": "폐결핵은 결핵균에 의한 감염병으로 폐에 염증을 일으키지만, 주로 점진적인 증상이 나타납니다.", "5": "만성기관지염은 장기간의 기관지 염증으로 인한 기침, 가래가 특징이나, 감염에 의한 것이 아닙니다."}'::jsonb, '[{"term_ko": "세균", "term_vi": "Vi khuẩn", "def_ko": "박테리아(한국어)", "def_vi": "vi sinh vật đơn bào gây bệnh"}, {"term_ko": "바이러스", "term_vi": "Virus", "def_ko": "바이러스(한국어)", "def_vi": "tác nhân gây bệnh nhỏ hơn vi khuẩn"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "염증(한국어)", "def_vi": "phản ứng của cơ thể với tổn thương"}, {"term_ko": "호흡곤란", "term_vi": "Khó thở", "def_ko": "호흡 곤란(한국어)", "def_vi": "tình trạng không thể thở bình thường"}, {"term_ko": "가래", "term_vi": "Đờm", "def_ko": "가래(한국어)", "def_vi": "chất nhầy trong đường hô hấp"}, {"term_ko": "기침", "term_vi": "Ho", "def_ko": "기침(한국어)", "def_vi": "hành động đẩy không khí ra khỏi phổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (878, '5', '만성 기관지염으로 기도가 좁아진 대상자를 돕는 방법으로 옳은 것은?', '["자극적인 음식을 섭취한다.", "차가운 물을 자주 마시게 한다.", "탈취제를 사용하여 실내 공기를 정화한다.", "전염성이 강하므로 마스크를 착용하게 한다.", "갑작스러운 온도 변화에 노출되지 않게 한다."]'::jsonb, 5, '만성 기관지염 환자의 기도를 원활하게 돕는 방법을 묻고 있다.', NULL, '{"1": "자극적인 음식은 기도를 더 자극하여 증상을 악화시킬 수 있다.\n[정답]", "5": "갑작스러운 온도 변화는 기관지에 부담을 줄 수 있으므로 노출되지 않게 해야 한다.", "2": "차가운 물은 기도를 수축시킬 수 있어 바람직하지 않다.", "3": "탈취제는 화학 성분이 포함되어 있어 호흡기에 좋지 않을 수 있다.", "4": "전염성이 강하다는 것은 정확하지 않으며, 기본적인 예방 조치가 필요하지만 마스크 착용이 주된 방법은 아니다."}'::jsonb, '[{"term_ko": "만성 기관지염", "term_vi": "기도", "def_ko": "만성 bronchitis", "def_vi": "đường thở"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (877, '5', '만성기관지염으로 기도가 좁아진 경우 치료 및 예방법으로 옳은 것은?', '["찬 공기에 노출한다.", "뜨거운 음식을 섭취한다.", "흡연자는 금연을 한다.", "차가운 음식을 섭취한다.", "기침을 자제한다."]'::jsonb, 3, '만성기관지염의 치료와 예방에 대한 올바른 이해를 요구함.', NULL, '{"1": "찬 공기에 노출하면 기도가 더욱 좁아질 수 있으므로 옳지 않다.\n[정답]", "3": "흡연은 만성기관지염을 악화시키기 때문에 금연이 필수적이다.", "2": "뜨거운 음식은 기도에 자극을 줄 수 있어 주의해야 한다.", "4": "차가운 음식 역시 기도를 자극할 수 있으므로 바람직하지 않다.", "5": "기침은 기도에서 이물질을 배출하는 중요한 반사작용이므로 자제하는 것이 좋지 않다."}'::jsonb, '[{"term_ko": "만성기관지염", "term_vi": "Bệnh phế quản mãn tính", "def_ko": "만성적으로 기도의 염증이 생기는 질환", "def_vi": "Bệnh viêm mãn tính ở đường thở"}, {"term_ko": "기도", "term_vi": "Đường thở", "def_ko": "호흡하는 경로", "def_vi": "Đường dẫn khí"}, {"term_ko": "흡연", "term_vi": "Hút thuốc", "def_ko": "담배를 피우는 행위", "def_vi": "Hành động hút thuốc"}, {"term_ko": "금연", "term_vi": "Bỏ thuốc", "def_ko": "담배를 끊는 것", "def_vi": "Ngừng hút thuốc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (876, '5', '만성기관지염을 앓고 있는 대상자의 증상을 완화시키는 방법으로 옳은 것은?', '["해열진통제를 투여한다.", "차고 매ㅐ운 음식을 먹게 한다.", "공기 정화를 위해 방향제를 뿌린다.", "호흡곤란 시에는 뜨거운 차를 마시게 한다.", "심호흡과 기침을 하여 기관지 내 가래를 배출한다."]'::jsonb, 5, '만성기관지염에 대한 이해와 적절한 증상 완화 방법을 찾는 것이다.', NULL, '{"1": "해열진통제는 주로 통증 조절을 위해 사용되며, 만성기관지염의 증상 완화와는 크게 관련이 없다.\n[정답]", "5": "심호흡과 기침은 기관지 내 가래를 배출하는 데 효과적이며, 만성기관지염 환자에게 도움이 된다.", "2": "차고 매운 음식은 기관지를 자극할 수 있어 권장되지 않는다.", "3": "방향제는 공기를 정화하기보다는 오히려 기관지에 자극을 줄 수 있다.", "4": "뜨거운 차는 호흡곤란 개선에 직접적인 도움이 되지 않고, 오히려 자극을 줄 수 있다."}'::jsonb, '[{"term_ko": "만성기관지염", "term_vi": "Viêm phế quản mãn tính", "def_ko": "만성 기침, 가래, 호흡곤란 등의 증상을 동반하는 질병", "def_vi": "Bệnh có triệu chứng như ho mãn tính, đờm và khó thở"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증세 및 시그널", "def_vi": "Biểu hiện và tín hiệu"}, {"term_ko": "가래", "term_vi": "Đờm", "def_ko": "호흡기에서 배출되는 점액", "def_vi": "Chất nhầy được loại bỏ khỏi đường hô hấp"}, {"term_ko": "심호흡", "term_vi": "Hít thở sâu", "def_ko": "깊은 호흡", "def_vi": "Thở sâu"}, {"term_ko": "기침", "term_vi": "Ho", "def_ko": "호흡기가 자극받을 때 발생하는 반사 작용", "def_vi": "Phản ứng xảy ra khi đường hô hấp bị kích thích"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (875, '5', '다음 증상이 나타나는 질환은?• 체중 감소, 잦은 호흡기 감염• 점진적으로 호흡곤란이 심화• 이른 아침에 발생하는 가래 끓는 기침', '["만성기관지염", "폐렴", "폐결핵", "천식", "심부전"]'::jsonb, 1, '이 문제는 호흡기 관련 질환의 증상과 특징을 이해하고 구분할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "만성기관지염은 지속적인 기침과 가래가 동반되며 체중 감소와 잦은 호흡기 감염이 나타날 수 있습니다.\n[정답]", "2": "폐렴은 급성 호흡기 감염으로 일반적으로 기침과 가래가 발생하지만 체중 감소와 잦은 감염은 만성적으로 나타나기 어렵습니다.", "3": "폐결핵은 체중 감소와 기침이 있지만, 주로 밤에 땀을 흘리는 증상이 더 두드러집니다.", "4": "천식은 발작적 호흡곤란이 특징이며, 가래는 드물게 나타납니다.", "5": "심부전은 호흡곤란을 유발할 수 있으나, 주로 체중 증가 및 부종이 동반됩니다."}'::jsonb, '[{"term_ko": "체중", "term_vi": "Cân nặng", "def_ko": "몸의 무게", "def_vi": "Trọng lượng cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (874, '5', '고열과 함께 기침 등 호흡기 증상을 일으키는 인플루엔자에 대한 설명으로 옳은 것은?', '["혈액으로 감염되는 질병이다.", "치료제로 항바이러스제를 사용한다.", "증상 발현 이후에는 전파 위험이 없다.", "감염자와 접촉한 사람은 증상 유무에 관계없이 치료한다.", "감염 후 회복 중에 발열과 누런 가래가 생기는 것은 정상이다."]'::jsonb, 2, '인플루엔자에 대한 기본적인 이해와 치료 방법을 평가하기 위함입니다.', NULL, '{"1": "인플루엔자는 호흡기 감염으로 혈액으로 전파되지 않습니다.\n[정답]", "2": "인플루엔자의 치료에는 항바이러스제가 사용됩니다.", "3": "증상 발현 이후에도 전파 위험이 존재합니다.", "4": "감염자와 접촉한 사람들은 증상이 나타나지 않아도 예방 차원에서 치료할 수 있습니다.", "5": "회복 중에 발열과 누런 가래가 발생할 수 있지만, 이는 일반적인 경우에 해당하지 않습니다."}'::jsonb, '[{"term_ko": "고열", "term_vi": "Sốt cao", "def_ko": "고온(한국어)", "def_vi": "Nhiệt độ cơ thể tăng cao"}, {"term_ko": "기침", "term_vi": "Ho", "def_ko": "기침(한국어)", "def_vi": "Hắt hơi"}, {"term_ko": "호흡기", "term_vi": "Đường hô hấp", "def_ko": "호흡기(한국어)", "def_vi": "Đường thở"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증상(한국어)", "def_vi": "Triệu chứng"}, {"term_ko": "인플루엔자", "term_vi": "Cúm", "def_ko": "인플루엔자(한국어)", "def_vi": "Cúm"}, {"term_ko": "치료제", "term_vi": "Thuốc điều trị", "def_ko": "치료제(한국어)", "def_vi": "Thuốc điều trị"}, {"term_ko": "항바이러스제", "term_vi": "Thuốc kháng virus", "def_ko": "항바이러스제(한국어)", "def_vi": "Thuốc kháng virus"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염(한국어)", "def_vi": "Nhiễm trùng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (873, '5', '노화에 따라 일반적으로 나타나는 호흡기계 변화는?', '["호흡기계 감염 감소", "폐활량 증가", "호흡근육 근력 감소", "기관지 내 분비물 감소", "신체조직 내 수분 함유량 증가"]'::jsonb, 3, '노화에 따른 신체의 변화, 특히 호흡기계 기능의 감소를 이해하고 평가하는 것.', NULL, '{"1": "노화에 따라 호흡기계 감염이 증가하는 편이다.\n[정답]", "3": "노화에 따라 호흡근육의 근력이 감소하는 것이 일반적이다.", "2": "노화로 인해 폐활량은 감소하는 경향이 있다.", "4": "노화에 따라 기관지의 분비물은 증가할 수 있다.", "5": "신체조직 내 수분 함유량은 노화에 따라 감소하는 경우가 많다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이의 증가에 따라 신체적, 정신적 기능이 저하되는 과정", "def_vi": "Quá trình suy giảm chức năng cơ thể và tâm lý theo sự gia tăng độ tuổi"}, {"term_ko": "호흡기계", "term_vi": "Hệ hô hấp", "def_ko": "숨을 쉴 때 사용되는 기관과 구조", "def_vi": "Các cơ quan và cấu trúc tham gia vào việc thở"}, {"term_ko": "폐활량", "term_vi": "Dung tích phổi", "def_ko": "폐가 한 번의 호흡으로 흡입 또는 내보낼 수 있는 공기의 총량", "def_vi": "Tổng lượng không khí mà phổi có thể hít vào hoặc thở ra trong một nhịp"}, {"term_ko": "호흡근육", "term_vi": "Cơ hô hấp", "def_ko": "호흡을 담당하는 근육들", "def_vi": "Các cơ chịu trách nhiệm cho việc thở"}, {"term_ko": "기관지", "term_vi": "Phế quản", "def_ko": "폐로 공기를 운반하는 통로", "def_vi": "Đường dẫn không khí vào phổi"}, {"term_ko": "신체조직", "term_vi": "Mô cơ thể", "def_ko": "신체를 구성하는 조직", "def_vi": "Các mô cấu thành cơ thể"}, {"term_ko": "수분 함유량", "term_vi": "Nồng độ nước", "def_ko": "물이 포함된 양", "def_vi": "Lượng nước có trong mô"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (872, '5', '노화에 따른 호흡기계의 특성으로 옳은 것은?', '["폐순환량 감소", "폐포의 탄력성 증가", "호흡근육의 근력 강화", "기침반사 증가", "섬모운동 증가"]'::jsonb, 1, '노화가 호흡기계에 미치는 영향을 이해하고, 관련된 특성을 파악하기 위함입니다.', NULL, '{"1": "노화로 인해 폐순환량이 감소하는 것은 맞는 설명입니다. 이는 노화로 인해 호흡기계의 구조와 기능이 변화하기 때문입니다.\n[정답]", "2": "노화가 진행됨에 따라 폐포의 탄력성은 감소하는 경향이 있습니다.", "3": "노화에 따라 호흡근육의 근력은 약화될 수 있습니다.", "4": "기침반사는 노화로 인해 감소하는 경우가 많습니다.", "5": "섬모운동은 노화에 따라 일반적으로 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙음, 나이듦(성장과 시간의 경과로 인한 변화)", "def_vi": "Sự già hóa, quá trình thay đổi do tuổi tác"}, {"term_ko": "호흡기계", "term_vi": "Hệ hô hấp", "def_ko": "호흡과 연관된 기관들의 집합체", "def_vi": "Tập hợp các cơ quan liên quan đến hô hấp"}, {"term_ko": "폐순환량", "term_vi": "Lượng tuần hoàn phổi", "def_ko": "폐로 가는 혈액의 양", "def_vi": "Lượng máu chảy đến phổi"}, {"term_ko": "폐포", "term_vi": "Phế nang", "def_ko": "호흡의 기본 단위", "def_vi": "Đơn vị cơ bản của hô hấp"}, {"term_ko": "탄력성", "term_vi": "Tính đàn hồi", "def_ko": "원래 형태로 돌아가려는 성질", "def_vi": "Tính chất trở về hình dạng ban đầu"}, {"term_ko": "호흡근육", "term_vi": "Cơ bắp hô hấp", "def_ko": "호흡에 관여하는 근육", "def_vi": "Cơ bắp tham gia vào hô hấp"}, {"term_ko": "기침", "term_vi": "Ho", "def_ko": "호흡기에 자극이 있을 때 나타나는 반응", "def_vi": "Phản ứng khi có kích thích ở đường hô hấp"}, {"term_ko": "반사", "term_vi": "Phản xạ", "def_ko": "자극에 대한 자동적인 반응", "def_vi": "Phản ứng tự động đối với kích thích"}, {"term_ko": "섬모", "term_vi": "Lông niệu", "def_ko": "세포에 붙어있는 미세한 털", "def_vi": "Sợi tóc mịn gắn vào tế bào"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (871, '5', '변비 대상자를 돕는 방법으로 옳은 것은?', '["복부 마사지를 해준다.", "변비약을 주기적으로 권한다.", "하제 사용을 많이 한다.", "수분 섭취를 줄인다.", "음식 섭취량을 줄인다."]'::jsonb, 1, '변비를 관리하고 개선하는 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "복부 마사지는 장의 움직임을 촉진시켜 변비 완화에 도움을 줍니다.\n[정답]", "2": "변비약을 주기적으로 사용하는 것은 의사의 처방에 따라야 하며, 자주 권하는 것은 적절치 않습니다.", "3": "하제 사용은 장기간 사용 시 의존성을 초래할 수 있습니다.", "4": "수분 섭취는 오히려 증가시켜야 하며, 줄이는 것은 바람직하지 않습니다.", "5": "음식 섭취량을 줄이는 것은 변비를 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "대변을 보기 어렵거나 귀찮은 상태", "def_vi": "Tình trạng khó khăn hoặc phiền phức khi đi đại tiện"}, {"term_ko": "마사지를 하다", "term_vi": "Xoa bóp", "def_ko": "신체의 특정 부위를 문지르거나 눌러서 자극을 주는 것", "def_vi": "Sự chà xát hoặc ấn vào một phần cụ thể của cơ thể để kích thích"}, {"term_ko": "하제", "term_vi": "Thuốc nhuận tràng", "def_ko": "대변을 부드럽게 하는 약물", "def_vi": "Thuốc làm mềm phân"}, {"term_ko": "수분", "term_vi": "Nước", "def_ko": "체내의 물 성분", "def_vi": "Thành phần nước trong cơ thể"}, {"term_ko": "음식", "term_vi": "Thức ăn", "def_ko": "섭취하는 모든 물질", "def_vi": "Tất cả các chất được tiêu thụ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (870, '5', '변비의 원인이 되는 요인으로 옳은 것은?', '["신체활동 증가", "충분한 수분 섭취", "마약성 진통제 복용", "복부 근육의 힘 강화", "규칙적인 배변 습관"]'::jsonb, 3, '변비의 원인으로 옳은 항목을 파악하는 것이다.', NULL, '{"1": "신체활동이 증가하면 장 운동이 원활해져 변비 예방에 도움을 준다.", "2": "충분한 수분 섭취는 변을 부드럽게 하여 변비를 예방한다.\n[정답]", "3": "마약성 진통제 복용은 장의 기능을 억제하여 변비를 유발할 수 있다.", "4": "복부 근육의 힘 강화는 변비 예방에 도움이 된다.", "5": "규칙적인 배변 습관은 변비를 예방하는 중요한 방법이다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "대변이 딱딱해지고 배변이 어려운 상태", "def_vi": "Tình trạng phân cứng và khó đi vệ sinh"}, {"term_ko": "신체활동", "term_vi": "Hoạt động thể chất", "def_ko": "운동이나 활동을 통해 신체를 움직이는 것", "def_vi": "Điều gì đó mà cơ thể được vận động hoặc chuyển động"}, {"term_ko": "마약성 진통제", "term_vi": "Thuốc giảm đau có chứa narcotic", "def_ko": "마약에 해당하는 진통제", "def_vi": "Thuốc giảm đau thuộc loại thuốc phiện"}, {"term_ko": "배변 습관", "term_vi": "Thói quen đi vệ sinh", "def_ko": "대변을 보는 방식이나 패턴", "def_vi": "Cách thức hoặc thói quen đi vệ sinh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (869, '5', '변비를 유발하는 식사로 옳은 것은?', '["우유 섭취", "저잔여식이 섭취", "수분이 많은 음식 섭취", "섬유질이 많은 음식 섭취", "유산균이 많이 포함된 음식 섭취"]'::jsonb, 2, '변비 유발 요인을 이해하고, 영향을 미치는 식사를 판단하게 하기 위함입니다.', NULL, '{"1": "우유는 변비를 완화시킬 수 있는 성분이 있는 음식입니다.\n[정답]", "2": "저잔여식이는 변비를 유발할 수 있는 식사입니다.", "3": "수분이 많은 음식 섭취는 변비를 예방하는 데 도움이 됩니다.", "4": "섬유질이 많은 음식은 변비를 해결하는 데 효과적입니다.", "5": "유산균이 많이 포함된 음식은 장에 긍정적인 영향을 주어 변비를 완화할 수 있습니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "변의 배출이 어려운 상태(한국어)", "def_vi": "Trạng thái khó tiêu hóa phân"}, {"term_ko": "저잔여식이", "term_vi": "Chế độ ăn ít cặn", "def_ko": "섬유소가 적은 식사(한국어)", "def_vi": "Bữa ăn ít chất xơ"}, {"term_ko": "유산균", "term_vi": "Probiotic", "def_ko": "장 건강에 좋은 균(한국어)", "def_vi": "Vi khuẩn có lợi cho sức khỏe đường ruột"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (868, '5', '노인에게 변비가 많은 이유로 옳은 것은?', '["과도한 하제 남용", "충분한 수분섭취", "저작능력 증가", "음식물 섭취량 증가", "장근육의 긴장도 증가"]'::jsonb, 1, '노인의 변비 원인을 이해하고, 이에 대한 정확한 인식을 돕기 위한 문제입니다.', NULL, '{"1": "과도한 하제 남용은 변비를 유발할 수 있습니다. 노인들은 약물에 의한 의존성이 있을 수 있으며, 이는 변비를 악화시킵니다.\n[정답]", "2": "충분한 수분섭취는 오히려 변비 예방에 도움이 됩니다. 노인에게 물 섭취가 부족할 경우 변비가 발생할 수 있습니다.", "3": "저작능력 증가가 변비와 관련이 없으며, 이는 오히려 음식 섭취를 촉진합니다.", "4": "음식물 섭취량 증가가 변비를 유발하는 것은 아니며, 적절한 식사가 장 건강에 유익합니다.", "5": "장근육의 긴장도 증가가 변비와 직접적인 관계가 없습니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "배변이 어려운 상태(한국어)", "def_vi": "Tình trạng khó đi đại tiện (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (867, '5', '변비의 발생 원인으로 옳은 것은?', '["규칙적인 운동", "섬유질이 많은 음식 섭취", "수분섭취 부족", "장운동 증가", "복부 근육의 힘 증가"]'::jsonb, 3, '변비의 원인에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "규칙적인 운동은 장의 운동을 촉진시켜 변비를 예방합니다.", "2": "섬유질이 많은 음식 섭취는 장의 건강을 돕고 변비 예방에 도움을 줍니다.\n[정답]", "3": "수분섭취 부족은 변비의 주요 원인 중 하나입니다. 수분이 부족하면 대변이 단단해져 배출이 어려워집니다.", "4": "장운동 증가는 변비를 완화하는 요인입니다.", "5": "복부 근육의 힘 증가는 변비 예방에 도움이 됩니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "배변이 어려운 상태", "def_vi": "Tình trạng khó đi tiêu"}, {"term_ko": "운동", "term_vi": "Tập thể dục", "def_ko": "신체 활동", "def_vi": "Hoạt động thể chất"}, {"term_ko": "수분", "term_vi": "Nước", "def_ko": "몸에 필요한 물", "def_vi": "Nước cần thiết cho cơ thể"}, {"term_ko": "섬유질", "term_vi": "Chất xơ", "def_ko": "식이섬유", "def_vi": "Chất xơ trong thực phẩm"}, {"term_ko": "장운동", "term_vi": "Hoạt động của ruột", "def_ko": "장의 움직임", "def_vi": "Sự di chuyển của ruột"}, {"term_ko": "복부", "term_vi": "Bụng", "def_ko": "배 부분", "def_vi": "Phần bụng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (866, '5', '잦은 설사로 탈수가 예상되는 대상자에게 우선적으로 돕는 방법은?', '["우유 섭취량을 늘린다.", "식사를 충분히 제공한다.", "물을 충분히 마시게 한다.", "수시로 지사제를 복용시킨다.", "장운동을 증가시키는 음식을 먹게 한다."]'::jsonb, 3, '설사는 탈수를 유발할 수 있으므로, 적절한 수분 보충 방법을 묻는 문제이다.', NULL, '{"1": "우유는 수분을 제공할 수 있지만, 설사 시에는 유제품이 기저에 영향을 줄 수 있다.\n[정답]", "3": "물은 탈수 예방에 가장 기초적인 방법이며, 우선적으로 공급해야 한다.", "2": "식사가 충분하더라도 수분이 부족하면 탈수를 막기 어렵다.", "4": "지사제를 사용하기보다는 수분을 보충하는 것이 우선이다.", "5": "장운동을 증가시키는 음식은 오히려 설사를 악화시킬 수 있다."}'::jsonb, '[{"term_ko": "설사", "term_vi": "Tiêu chảy", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (865, '5', '대상자가 수차례 설사 후에 피부가 건조하고 힘이 없다고 할 때 돕는 방법으로 옳은 것은?', '["지사제를 바로 공급한다.", "녹차나 커피를 제공한다.", "음식량을 늘리낟.", "고지방식을 제공한다.", "몸을 따뜻하게 하고 수분섭취를 해준다."]'::jsonb, 5, '대상자의 설사로 인한 탈수와 건조한 피부를 고려한 적절한 처치를 묻고 있다.', NULL, '{"1": "지사제를 바로 공급하는 것은 지양해야 한다. 장의 자연스러운 회복을 방해할 수 있다.\n[정답]", "5": "몸을 따뜻하게 하고 수분 섭취를 해주는 것이 가장 적절하다. 체온 유지와 수분 보충은 회복에 도움이 된다.", "3": "음식량을 늘리는 것은 GI 트랙에 부담을 줄 수 있다.", "4": "고지방식은 소화에 어려움을 줄 수 있어 피해야 한다.", "2": "녹차나 커피는 이뇨작용을 증가시켜 탈수 상태를 악화할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (864, '5', '대상자가 설사를 할 때 제공하는 음식으로 옳은 것은?', '["우유", "비빔밥, 콜라", "흰죽, 보리차", "사과, 복숭아", "제육볶음, 현미밥"]'::jsonb, 3, '설사를 할 때 적절한 음식을 제공하는 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "우유는 소화가 어려워 설사를 악화시킬 수 있습니다.\n[정답]", "3": "흰죽과 보리차는 소화가 잘되고 수분 보충에 도움이 됩니다.", "2": "비빔밥과 콜라는 기름지고 자극적이어서 피해야 합니다.", "4": "사과와 복숭아는 섬유질이 많아 소화에 부담을 줄 수 있습니다.", "5": "제육볶음과 현미밥은 기름지고 소화가 어려운 음식입니다."}'::jsonb, '[{"term_ko": "설사", "term_vi": "Tiêu chảy", "def_ko": "증상(한국어)", "def_vi": "triệu chứng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (863, '5', '설사의 발생 원인으로 옳은 것은?', '["뜨거운 음식물 섭취", "균형 잡힌 식사", "식물성 식이섬유 섭취", "하제 등 약물의 남용", "소화기능의 증가"]'::jsonb, 4, '설사의 원인에 대한 이해를 평가하기 위해 출제되었습니다.', NULL, '{"1": "뜨거운 음식물 섭취는 일반적으로 설사를 유발하지 않습니다.\n[정답]", "4": "하제 등 약물의 남용은 설사의 일반적인 원인입니다.", "2": "균형 잡힌 식사는 설사를 예방하는 데 도움이 됩니다.", "3": "식물성 식이섬유 섭취는 소화를 돕지만 설사를 유발하지 않습니다.", "5": "소화기능의 증가는 설사와 관련이 없습니다."}'::jsonb, '[{"term_ko": "설사", "term_vi": "Tiêu chảy", "def_ko": "설사는 화장실을 자주 가고 물 같은 변을 보는 증상입니다.", "def_vi": "Là triệu chứng đi vệ sinh thường xuyên và có phân lỏng."}, {"term_ko": "하제", "term_vi": "Thuốc nhuận tràng", "def_ko": "대변의 배출을 촉진하는 약물입니다.", "def_vi": "Là loại thuốc thúc đẩy việc thải phân."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (862, '5', '대장암 환자의 식이요법으로 옳은 것은?', '["간식을 수시로 섭취한다.", "통곡물로 만든 음식을 섭취한다.", "동물성 식품을 많이 섭취한다.", "염장식품을 섭취한다.", "생채소, 생과일 섭취를 제한한다."]'::jsonb, 2, '대장암 환자에게 적절한 식이요법을 구별하는 것', NULL, '{"1": "대장암 환자는 간식을 자주 섭취하는 것이 건강에 좋지 않다.\n[정답]", "2": "통곡물로 만든 음식은 식이섬유가 풍부하여 대장 건강에 도움이 된다.", "3": "동물성 식품은 지방이 높아 대장암 환자에게 좋지 않다.", "4": "염장식품은 발암물질이 포함될 수 있어 피하는 것이 좋다.", "5": "생채소와 생과일은 대장 건강에 이로운 식품이므로 섭취를 제한해서는 안 된다."}'::jsonb, '[{"term_ko": "식이요법", "term_vi": "Chế độ ăn uống", "def_ko": "식사 치료법(한국어)", "def_vi": "Phương pháp điều trị bằng ăn uống"}, {"term_ko": "대장암", "term_vi": "Ung thư đại tràng", "def_ko": "대장에 생기는 암(한국어)", "def_vi": "Ung thư xảy ra ở đại tràng"}, {"term_ko": "통곡물", "term_vi": "Ngũ cốc nguyên hạt", "def_ko": "곡물을 정제하지 않은 것(한국어)", "def_vi": "Ngũ cốc không được tinh chế"}, {"term_ko": "식이섬유", "term_vi": "Chất xơ", "def_ko": "소화되지 않는 섬유소(한국어)", "def_vi": "Chất không tiêu hóa được"}, {"term_ko": "발암물질", "term_vi": "Chất gây ung thư", "def_ko": "암을 유발하는 물질(한국어)", "def_vi": "Chất gây ra bệnh ung thư"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (861, '5', '대장암 환자의 식이요법으로 옳은 것은?', '["정제된 곡물을 섭취한다.", "훈연된 동물성 식품을 섭취한다.", "고칼로리 음식을 섭취한다.", "하루에 6~8잔의 생수를 마신다.", "입맛을 돋우는 자극적인 음식을 섭취한다."]'::jsonb, 4, '대장암 환자에게 적절한 식이요법을 이해하고, 올바른 선택을 할 수 있는지를 평가하고자 한다.', NULL, '{"1": "정제된 곡물은 섬유소가 적어 식이요법에 적합하지 않다.\n[정답]", "4": "하루에 6~8잔의 생수는 수분 섭취를 돕고 장 건강에 좋다.", "2": "훈연된 동물성 식품은 발암물질이 포함될 수 있어 대장암 환자에게 바람직하지 않다.", "3": "고칼로리 음식은 비만을 유발할 수 있어 추천되지 않는다.", "5": "자극적인 음식은 대장에 부담을 줄 수 있어 피해야 한다."}'::jsonb, '[{"term_ko": "대장암", "term_vi": "Ung thư đại tràng", "def_ko": "대장에 발생하는 암", "def_vi": "Ung thư xảy ra ở đại tràng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (860, '5', '대장암 대상자의 식이요법으로 옳은 것은?', '["생채소, 생과일을 충분히 섭취한다.", "육류는 훈연하여 섭취한다.", "간식으로 튀김류를 자주 섭취한다.", "차가운 아이스크림으로 식욕을 돋운다.", "흰죽을 야식으로 섭취한다."]'::jsonb, 1, '대장암 대상자의 식이요법에 대한 이해도를 평가하고자 하는 의도입니다.', NULL, '{"1": "대장암 환자에게는 식이섬유가 풍부한 생채소와 생과일을 섭취하는 것이 좋다.\n[정답]", "2": "육류는 훈연하여 섭취하는 것이 건강에 해로울 수 있다.", "3": "튀김류는 지방이 많아 좋지 않은 선택이다.", "4": "차가운 아이스크림은 대장에 자극을 줄 수 있어 피해야 한다.", "5": "흰죽은 소화가 잘되지만, 충분한 영양소를 포함하지 않아 단독 섭취는 좋지 않다."}'::jsonb, '[{"term_ko": "대장암", "term_vi": "식이요법", "def_ko": "결 colon cancer", "def_vi": "chế độ ăn uống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (859, '5', '대장암 환자에게 적합한 음식은?', '["현미밥", "라면", "육개장", "명란젓", "피자"]'::jsonb, 1, '대장암 환자에게 적합한 식단을 이해하고 그에 따른 적절한 음식을 선택하는 능력을 평가하고자 함.', NULL, '{"1": "현미밥은 식이섬유가 풍부하여 대장 건강에 도움을 줄 수 있어 대장암 환자에게 적합하다.\n[정답]", "2": "라면은 염분과 첨가물이 많아 대장암 환자에게 좋지 않다.", "3": "육개장은 기름과 염분이 높아 대장암 환자에게 부적합할 수 있다.", "4": "명란젓 역시 염분이 높아 대장암 환자에게 추천되지 않는다.", "5": "피자는 고지방, 고열량 음식으로 대장암 환자에게는 좋지 않다."}'::jsonb, '[{"term_ko": "대장암", "term_vi": "Ung thư đại tràng", "def_ko": "대장에 생기는 암", "def_vi": "Ung thư xảy ra ở đại tràng"}, {"term_ko": "식이섬유", "term_vi": "Chất xơ", "def_ko": "소화할 수 없는 식물성 영양소", "def_vi": "Chất dinh dưỡng thực vật không tiêu hóa được"}, {"term_ko": "염분", "term_vi": "Natri", "def_ko": "소금의 성분", "def_vi": "Thành phần của muối"}, {"term_ko": "고지방", "term_vi": "Chất béo cao", "def_ko": "지방이 많은", "def_vi": "Nhiều chất béo"}, {"term_ko": "고열량", "term_vi": "Nhiều calo", "def_ko": "칼로리가 많은", "def_vi": "Nhiều năng lượng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (858, '5', '대상자가 최근 체중감소와 설사, 변비, 점액이 섞인 혈변을 자주 호소할 때 의심되는 질환은?', '["위암", "췌장암", "대장암", "위염", "신부전"]'::jsonb, 3, '환자의 증상으로 미루어 볼 때 어떤 질병이 의심되는지 평가하도록 하는 문제입니다.', NULL, '{"1": "위암은 소화기계의 악성 종양으로 체중 감소가 있을 수 있지만 혈변과 같은 특정 증상은 없습니다.\n[정답]", "2": "췌장암은 소화기계에 영향을 미칠 수 있으나 주된 증상은 아닙니다.", "3": "대장암은 체중 감소, 설사, 변비, 혈변 등과 연관이 있으므로 해당 증상에 가장 적합합니다.", "4": "위염은 위에서 염증이 발생하는 것으로, 혈변이 자주 나타나지 않습니다.", "5": "신부전은 주로 소변에 영향을 주며 체중 변화가 있을 수 있지만, 위의 증상과는 관계가 적습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (857, '5', '위암 환자가 섭취하는 음식으로 옳은 것은?', '["육개장", "녹황색 채소", "치킨", "카레", "베이컨"]'::jsonb, 2, '위암 환자에게 적합한 식단을 묻는 질문입니다. 위암 환자는 소화가 잘 되고 영양소가 풍부한 음식을 섭취해야 합니다.', NULL, '{"1": "육개장은 기름지고 자극적인 음식으로 위암 환자에게 적합하지 않습니다.\n[정답]", "2": "녹황색 채소는 비타민과 미네랄이 풍부하여 위암 환자에게 좋습니다.", "3": "치킨은 기름지고, 조리법에 따라 위암 환자에게 부적합할 수 있습니다.", "4": "카레는 자극적인 향신료가 포함되어 있어 위암 환자에게 좋지 않습니다.", "5": "베이컨은 고지방식으로 소화가 어렵고 위암 환자에게 적합하지 않습니다."}'::jsonb, '[{"term_ko": "위암", "term_vi": "Ung thư dạ dày", "def_ko": "위에서 발생하는 암", "def_vi": "Ung thư xảy ra ở dạ dày"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (856, '5', '위암에 대한 설명으로 옳은 것은?', '["체중증가가 나타난다.", "증상만으로 조기진단이 가능하다.", "위암은 가족력이 없다.", "단백질 섭취를 피한다.", "치료 후 5년간은 정기검진으로 재발여부를 확인한다."]'::jsonb, 5, '위암에 대한 기본적인 이해와 관련된 사항을 평가하고자 함.', NULL, '{"1": "위암 환자는 일반적으로 체중 감소가 나타난다.\n[정답]", "5": "치료 후 5년간은 정기검진으로 재발여부를 확인하는 것이 중요하다.", "2": "위암은 증상만으로 조기진단하기 어렵다.", "3": "위암은 가족력이 있을 수 있으며, 가족력은 위험 인자 중 하나다.", "4": "단백질 섭취는 환자의 영양 상태를 고려하여 적절히 조절해야 한다."}'::jsonb, '[{"term_ko": "위암", "term_vi": "Ung thư dạ dày", "def_ko": "위장에서 발생하는 악성 종양", "def_vi": "Khối u ác tính phát sinh trong dạ dày"}, {"term_ko": "체중", "term_vi": "Cân nặng", "def_ko": "몸의 무게", "def_vi": "Khối lượng cơ thể"}, {"term_ko": "정기검진", "term_vi": "Khám định kỳ", "def_ko": "정해진 주기로 건강 상태를 확인하는 검사", "def_vi": "Kiểm tra tình trạng sức khỏe theo một lịch trình nhất định"}, {"term_ko": "가족력", "term_vi": "Tiền sử gia đình", "def_ko": "가족 내에서 발생한 질병의 이력", "def_vi": "Lịch sử bệnh tật trong gia đình"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (855, '5', '질병이 서서히 진행되어 증상이 잘 나타나지 않으며 체중감소와 오심, 출혈, 구토나 복부 종양 덩어리가 나타나는 질환은?', '["식도암", "위암", "간암", "대장암", "폐암"]'::jsonb, 2, '질병의 진행 과정과 증상에 대한 이해를 확인하기 위함', NULL, '{"1": "식도에 생기는 악성 종양으로, 초기에는 증상이 없고 진행될수록 연하곤란과 통증이 나타날 수 있다.\n[정답]", "2": "위에서 발생하는 암으로, 초기에는 증상이 거의 없으며 체중 감소와 오심, 구토가 점진적으로 나타난다.", "3": "간에서 발생하는 암이며, 초기에는 증상이 миним한 경우가 많지만, 황달이나 복통 등의 증상이 나올 수 있다.", "4": "대장에서 발생하는 암으로, 초기에는 무증상이 많고 이후 변화가 나타날 수 있다.", "5": "폐에서 생기는 암으로, 초기에는 기침이나 호흡곤란이 나타나며 진행이 되면 다양한 증상이 발생할 수 있다."}'::jsonb, '[{"term_ko": "질병", "term_vi": "Bệnh", "def_ko": "병(한국어)", "def_vi": "bệnh tật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (854, '5', '위궤양 대상자를 돕는 방법으로 옳은 것은?', '["훈연한 음식을 먹게 한다.", "흡연자이면 금연하게 한다.", "잠자리에 들기 전에 녹차를 마시게 한다.", "검은색 대변을 보더라도 정상이라고 안심시킨다.", "비스테로이드성 소염진통제를 자주 복용하게 한다."]'::jsonb, 2, '위궤양에 대한 올바른 대처 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "훈연한 음식은 위에 자극을 줄 수 있으므로 좋지 않습니다.\n[정답]", "2": "흡연은 위궤양에 악영향을 미치므로 금연이 필요합니다.", "3": "잠자리에 들기 전에 녹차를 마시는 것은 위에 자극을 줄 수 있습니다.", "4": "검은색 대변은 위장 출혈을 의미할 수 있어 안심시키는 것이 옳지 않습니다.", "5": "비스테로이드성 소염진통제는 위궤양을 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "위궤양", "term_vi": "Loét dạ dày", "def_ko": "위의 점막에 생기는 염증성 병변", "def_vi": "Vết thương viêm trên niêm mạc dạ dày"}, {"term_ko": "흡연", "term_vi": "Hút thuốc", "def_ko": "담배를 피우는 행위", "def_vi": "Hành động hút thuốc lá"}, {"term_ko": "비스테로이드성 소염진통제", "term_vi": "Thuốc giảm đau chống viêm không steroid", "def_ko": "소염 및 진통 효과가 있는 약물", "def_vi": "Thuốc có tác dụng giảm đau và chống viêm"}, {"term_ko": "검은색 대변", "term_vi": "Phân có màu đen", "def_ko": "소화관 출혈을 의미할 수 있는 징후", "def_vi": "Dấu hiệu có thể chỉ ra chảy máu tiêu hóa"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (853, '5', '헬리코박터균 감염이 원인이 되어 속쓰림과 상복부 불편감이 나타나는 질환은?', '["췌장염", "협심증", "담석증", "위궤양", "대장암"]'::jsonb, 4, '헬리코박터균 감염과 관련된 질환을 이해하고 있는지를 묻는 문제입니다.', NULL, '{"1": "췌장염은 췌장에서 염증이 발생하는 질환으로, 헬리코박터균과는 관련이 없습니다.", "2": "협심증은 심장과 관련된 질환으로, 소화기계와는 관련이 없습니다.", "3": "담석증은 담낭에 결석이 생긴 질환으로, 헬리코박터균 감염과는 관련이 없습니다.\n[정답]", "4": "위궤양은 헬리코박터균 감염으로 인해 발생할 수 있는 질환입니다.", "5": "대장암은 대장에서 발생하는 암으로, 헬리코박터균과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "헬리코박터균", "term_vi": "Vi khuẩn Helicobacter", "def_ko": "위염, 위궤양 유발 원인균", "def_vi": "Vi khuẩn gây viêm dạ dày, loét dạ dày"}, {"term_ko": "속쓰림", "term_vi": "Đau dạ dày", "def_ko": "위에서 불편한 느낌", "def_vi": "Cảm giác không thoải mái ở dạ dày"}, {"term_ko": "상복부", "term_vi": "Thượng vị", "def_ko": "배의 상단 부분", "def_vi": "Phần trên của bụng"}, {"term_ko": "불편감", "term_vi": "Cảm giác khó chịu", "def_ko": "괴로운 느낌", "def_vi": "Cảm giác không thoải mái"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (852, '5', '다음과 같은 증상이 나타나는 질환은?• 새벽 1~2시에 발생하는 속쓰림과 상복부 불편감 • 심한 경우 위 출혈, 위 천공, 위 협착', '["위암", "위염", "위궤앙", "식도암", "대장암"]'::jsonb, 3, '환자가 겪고 있는 증상을 통해 어떤 질환인지 파악하는 문제입니다.', NULL, '{"1": "위암: 주로 진행된 상태에서 증상이 나타나므로 이 증상과는 일치하지 않습니다.\n[정답]", "3": "위궤양: 새벽에 발생하는 속쓰림과 복부 불편감, 위 출혈 등과 관련이 있습니다.", "2": "위염: 속쓰림이 있지만, 심한 경우는 이 증상에 비해 덜 위험합니다.", "4": "식도암: 증상은 다르게 나타나므로 부합하지 않습니다.", "5": "대장암: 상복부 불편감보다는 하복부 증상이 주로 발생합니다."}'::jsonb, '[{"term_ko": "속쓰림", "term_vi": "Đau dạ dày", "def_ko": "쓰넣음(한국어)", "def_vi": "Đau dạ dày(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (851, '5', '위염으로 명치 부위의 통증과 구토 증상이 있을 때 도움이 되는 방법은?', '["차가운 음료를 마신다.", "양손으로 상복부를 밀어 올린다.", "처방받은 제산제 복용을 중단한다.", "배고프지 않도록 식사를 자주 한다.", "하루 정도 금식하여 위의 부담을 덜어준다."]'::jsonb, 5, '위염으로 인해 명치 부위의 통증과 구토 증상의 완화 방법에 대한 이해를 평가하고자 함.', NULL, '{"1": "차가운 음료를 마신 경우 위염 증상이 악화될 수 있으므로 좋지 않다.\n[정답]", "5": "하루 정도 금식하여 위의 부담을 덜어주는 것이 위염 증상 완화에 도움이 된다.", "2": "양손으로 상복부를 밀어 올리는 방법은 통증을 유발할 수 있어 피해야 한다.", "3": "처방받은 제산제 복용을 중단하는 것은 증상을 악화시킬 수 있다.", "4": "배고프지 않도록 식사를 자주 하는 것은 위에 부담을 줄 수 있어 바람직하지 않다."}'::jsonb, '[{"term_ko": "위염", "term_vi": "Viêm dạ dày", "def_ko": "위의 염증", "def_vi": "Viêm của dạ dày"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (850, '5', '위염의 치료 및 예방법으로 옳은 것은?', '["금식 시 수분 섭취를 줄인다.", "자극적인 음식을 섭취한다.", "금식 후 뜨거운 음식을 섭취한다.", "제산제, 진정제 등의 약물을 사용한다.", "활발하게 신체를 움직여서 위장운동을 촉진한다."]'::jsonb, 4, '위염의 치료와 예방에 대한 올바른 정보를 확인하기 위한 문제입니다.', NULL, '{"1": "금식을 하더라도 수분 섭취는 충분히 해야 합니다.", "2": "자극적인 음식은 위염을 악화시킬 수 있습니다.", "3": "금식 후 뜨거운 음식은 위에 자극을 줄 수 있습니다.\n[정답]", "4": "제산제와 진정제는 위염 치료에 도움을 줍니다.", "5": "과도한 신체 활동은 위장에 부담을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "위염", "term_vi": "Viêm dạ dày", "def_ko": "위의 염증", "def_vi": "Sự viêm của dạ dày"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (849, '5', '배가 고프기 시작할 때 발생하는 명치 부위와 심한 통증과 식사 후 위가 무겁거나 부푼듯한 느낌을 주는 질환은?', '["위궤양", "당뇨병", "변비", "위염", "대장암"]'::jsonb, 4, '명치 부위의 통증과 식사 후 불편한 증상에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "위궤양은 특정한 복통과 관련이 있지만 통증의 위치와 느낌이 다릅니다.\n[정답]", "4": "위염은 명치 부위의 통증과 식사 후 무겁거나 부풀어 오른 느낌과 관련이 있습니다.", "3": "변비는 주로 배변과 관련된 문제로 통증 위치와는 거리가 있습니다.", "2": "당뇨병은 위의 증상과는 관련이 적습니다.", "5": "대장암도 통증의 위치와 다르며, 이 문제의 증상과는 맞지 않습니다."}'::jsonb, '[{"term_ko": "명치", "term_vi": "Thượng vị", "def_ko": "위쪽 복부의 중앙 부분", "def_vi": "Phần giữa trên bụng"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔, 아프다", "def_vi": "Cảm giác không thoải mái"}, {"term_ko": "무겁다", "term_vi": "Nặng", "def_ko": "재기거나 무겁게 느끼는 것", "def_vi": "Cảm thấy nặng nề"}, {"term_ko": "부풀다", "term_vi": "Sưng phồng", "def_ko": "부풀어 오른 느낌", "def_vi": "Cảm giác đầy bụng"}, {"term_ko": "위염", "term_vi": "Viêm dạ dày", "def_ko": "위의 염증", "def_vi": "Viêm ở dạ dày"}, {"term_ko": "위궤양", "term_vi": "Loét dạ dày", "def_ko": "위의 상처", "def_vi": "Vết thương trong dạ dày"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (848, '5', '노화에 따라 일반적으로 나타나는 소화기계 변화는?', '["타액 분비 증가", "위액의 산도 증가", "지방의 흡수력 증가", "쓴맛, 신맛의 미각 감소", "약물 대사능력 감소"]'::jsonb, 5, '노화에 따른 소화기계의 변화를 이해하고, 일반적인 특징을 알고 있는지를 확인하기 위함입니다.', NULL, '{"1": "타액 분비 증가는 노화와 관련이 없습니다.\n[정답]", "5": "약물 대사능력이 감소하는 것은 노화로 인해 나타나는 일반적인 변화입니다.", "2": "위액의 산도는 일반적으로 노화에 따라 감소합니다.", "3": "지방의 흡수력은 노화에 따라 감소합니다.", "4": "미각은 노화에 따라 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이로 인해 신체 기능이 저하되는 과정", "def_vi": "Quá trình giảm chức năng cơ thể do tuổi tác"}, {"term_ko": "타액", "term_vi": "Nước bọt", "def_ko": "입에서 나오는 소화액", "def_vi": "Dịch tiêu hóa được tiết ra từ miệng"}, {"term_ko": "위액", "term_vi": "Dịch vị", "def_ko": "위에서 나오는 소화액", "def_vi": "Dịch tiêu hóa được tiết ra từ dạ dày"}, {"term_ko": "미각", "term_vi": "Khả năng nếm vị", "def_ko": "맛을 느끼는 능력", "def_vi": "Khả năng cảm nhận mùi vị"}, {"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "치료를 위해 사용하는 물질", "def_vi": "Chất được sử dụng để điều trị"}, {"term_ko": "대사", "term_vi": "Chuyển hóa", "def_ko": "체내에서 물질이 변환되는 과정", "def_vi": "Quá trình chuyển đổi chất trong cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (847, '5', '노화에 따른 소화기계의 변화로 옳은 것은?', '["당내성 감소", "대장연동운동 증가", "단맛, 짠맛 감각 증가", "췌장의 소화효소 분비 증가", "항문 괄약근 긴장도 증가"]'::jsonb, 1, '노화가 소화기계에 미치는 영향을 이해하고, 그 변화에 대해 올바른 지식을 갖추도록 하는 것이 목적입니다.', NULL, '{"1": "당내성 감소는 노화에 따른 소화기계의 변화로 맞습니다.\n[정답]", "2": "대장연동운동 증가는 노화의 결과가 아닙니다.", "3": "단맛, 짠맛 감각은 노화로 인해 감소합니다.", "4": "췌장의 소화효소 분비는 노화에 따라 감소합니다.", "5": "항문 괄약근 긴장도는 노화와 함께 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이 들어감", "def_vi": "Sự già đi"}, {"term_ko": "소화기계", "term_vi": "Hệ tiêu hóa", "def_ko": "음식물을 소화하는 시스템", "def_vi": "Hệ thống tiêu hóa thức ăn"}, {"term_ko": "당내성", "term_vi": "Khả năng dung nạp đường", "def_ko": "당분을 처리하는 능력", "def_vi": "Khả năng xử lý đường"}, {"term_ko": "대장연동운동", "term_vi": "Vận động đại tràng", "def_ko": "대장의 운동 활동", "def_vi": "Hoạt động vận động của đại tràng"}, {"term_ko": "췌장", "term_vi": "Tụy", "def_ko": "소화 효소를 생성하는 기관", "def_vi": "Cơ quan sản xuất enzyme tiêu hóa"}, {"term_ko": "항문 괄약근", "term_vi": "Cơ vòng hậu môn", "def_ko": "항문을 제어하는 근육", "def_vi": "Cơ kiểm soát hậu môn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (846, '5', '노화에 따른 소화기계의 변화로 옳은 것은?', '["맛을 느끼는 세포수가 증가한다.", "후각기능은 변함이 없고, 미각은 둔화된다.", "타액과 위액분비가 상승하여 소화가 잘 된다.", "의치의 사용으로 음식을 잘 씹게 된다.", "소화능력의 저하로 변비, 설사, 구토 등이 생긴다."]'::jsonb, 5, '노화에 따른 소화기계의 변화를 이해하고 관련된 증상을 아는 것이 중요하다.', NULL, '{"1": "맛을 느끼는 세포수가 증가하지 않고, 오히려 감소한다.\n[정답]", "5": "소화능력이 저하되어 변비, 설사, 구토 등의 증상이 발생할 수 있다.", "2": "후각기능도 대체로 둔화되며, 미각이 둔화되는 경우가 흔하다.", "3": "타액과 위액 분비는 일반적으로 감소하여 소화가 더 어려워진다.", "4": "의치 사용이 모든 사람에게 음식을 잘 씹게 하는 것은 아니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "노인 또는 나이가 많음", "def_vi": "Người già hoặc nhiều tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (845, '5', '노화에 따른 소화기계 특성으로 옳은 것은?', '["대장의 활동성 증가", "미각과 후각 기능 둔감", "타액과 위액분비 증가", "직장벽의 탄력성 증가", "지방의 흡수력 증가"]'::jsonb, 2, '노화 과정에서 소화기계의 변화를 이해하고 식별하는 것이다.', NULL, '{"1": "대장의 활동성 증가: 노화가 진행되면서 대장의 활동성은 일반적으로 감소한다. \n[정답]", "2": "미각과 후각 기능 둔감: 노화로 인해 미각과 후각의 기능이 둔감해지는 것이 일반적이다.", "3": "타액과 위액분비 증가: 노화가 진행되면 타액과 위액의 분비가 감소한다.", "4": "직장벽의 탄력성 증가: 노화로 인하여 직장벽의 탄력성은 감소한다.", "5": "지방의 흡수력 증가: 노화는 지방의 흡수력을 감소시킨다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙음(한국어)", "def_vi": "Già đi(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (844, '5', '다음 중 소화된 음식물의 수분을 흡수하여 대변 형태로 굳게 만드는 역할을 하는 소화기계 기관은?', '["췌장", "소장", "ㄷ대장", "위", "십이지장"]'::jsonb, 3, '소화기계에서 대변의 형태와 수분 흡수의 역할을 이해하고 있는지를 묻는 문제입니다.', NULL, '{"1": "췌장은 소화 효소를 분비하여 음식을 소화하는 역할을 합니다.\n[정답]", "3": "대장은 소화된 음식물의 수분을 흡수하여 대변 형태로 굳게 만드는 주된 기관입니다.", "2": "소장은 영양소를 흡수하는 주요한 기관입니다.", "4": "위는 음식을 저장하고 소화하는 역할을 합니다.", "5": "십이지장은 소화 효소와 담즙이 섞여 음식을 분해하는 곳입니다."}'::jsonb, '[{"term_ko": "소화기계", "term_vi": "대변", "def_ko": "소화기관의 집합체(소 hệ tiêu hóa)", "def_vi": "체내에서 소화된 음식물의 찌꺼기(phân)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (843, '5', '노인성 질환의 특징으로 옳은 것은?', '["급성질환으로 회복이 느리다.", "만성질환으로 치료가 빠르다.", "혈액순환 저하로 욕창이 잘 발생한다.", "질환의 원인은 명확하나 치료가 어렵다.", "한 가지 질병이 단독으로 발생한다."]'::jsonb, 3, '노인성 질환에 대한 올바른 이해를 평가하고자 함.', NULL, '{"1": "노인성 질환은 급성 질환이 아니므로, 이 보기는 부정확하다.\n[정답]", "3": "혈액순환 저하로 욕창이 잘 발생하는 것은 노인성 질환의 특징이다.", "2": "만성질환은 치료가 느리므로, 이 보기도 부정확하다.", "4": "질환의 원인이 명확할지라도 치료가 어려운 경우가 많아 이 보기도 부정확하다.", "5": "노인성 질환은 여러 가지 질병이 동시에 발생할 수 있으므로 이 보기도 부정확하다."}'::jsonb, '[{"term_ko": "노인성", "term_vi": "Bệnh lý người cao tuổi", "def_ko": "노인이 앓는 병", "def_vi": "Bệnh mà người cao tuổi mắc phải"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (842, '5', '노인성 질환의 특성에 대한 설명으로 옳은 것은?', '["가벼운 질환에도 의식장애가 발생한다.", "초기 진단과 예후 예측이 용이하다.", "원인이 병확한 만성 퇴행성 질병이다.", "증상이 뚜렷하여 기존 질병명으로 구분된다.", "신장의 배설 능력 저하로 약물의 배설이 빠르다."]'::jsonb, 1, '노인성 질환의 특성을 이해하고, 여러 설명 중에서 올바른 것을 찾는 것이다.', NULL, '{"1": "가벼운 질환에도 의식장애가 발생할 수 있다. 이는 노인에서 뇌 기능이 저하되어 있을 가능성이 증가하기 때문이다.\n[정답]", "2": "초기 진단과 예후 예측이 용이하다고 할 수 없다. 노인성 질환은 특성상 증상이 복잡하고 비특이적이기 때문이다.", "3": "노인성 질환은 반드시 만성 퇴행성 질병이라는 잘못된 인식이다. 다양한 원인에 의해 발생할 수 있다.", "4": "증상이 뚜렷하여 기존 질병명으로 구분된다고 보기 어려운 경우가 많다.", "5": "신장의 배설 능력 저하로 약물의 배설이 느려진다. 이는 노인에서 흔한 상황이다."}'::jsonb, '[{"term_ko": "노인성 질환", "term_vi": "Bệnh tuổi già", "def_ko": "고령자에게 흔한 질병", "def_vi": "Bệnh phổ biến ở người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (841, '5', '노인이 약물에 쉽게 중독되는 이유로 옳은 것은?', '["혈액순환 증가", "간의 대사능력 증가", "약물의 흡수능력 증가", "신장의 배설능력 감소", "위장의 위산분비 증가"]'::jsonb, 4, '노인이 약물에 쉽게 중독되는 이유에 대한 이해를 평가하고자 하는 의도입니다.', NULL, '{"1": "혈액순환이 증가하면 약물의 분포가 빨라질 수 있으나, 노인의 경우 일반적으로 혈액순환이 감소합니다.\n[정답]", "4": "신장의 배설능력이 감소하면 약물이 체내에 더 오래 남아있게 되어 중독 위험이 증가합니다.", "2": "간의 대사능력이 증가하는 것은 노인의 특성과 맞지 않으며, 대신 일반적으로 감소합니다.", "3": "약물의 흡수능력이 증가하는 것도 노인에서 일반적으로 나타나지 않으며, 노화로 인해 흡수 능력이 저하될 수 있습니다.", "5": "위장의 위산 분비가 증가하면 약물의 흡수가 더 잘 될 수 있지만, 노인에서는 위산 분비가 감소하는 경우가 많습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}, {"term_ko": "중독", "term_vi": "Ngộ độc", "def_ko": "독성이 있어 몸에 해로운 상태", "def_vi": "Tình trạng độc hại cho cơ thể"}, {"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "치료를 위해 사용하는 화학물질", "def_vi": "Chất hóa học sử dụng để chữa bệnh"}, {"term_ko": "신장", "term_vi": "Thận", "def_ko": "배설 기능을 하는 장기", "def_vi": "Cơ quan thực hiện chức năng bài tiết"}, {"term_ko": "대사", "term_vi": "Chuyển hóa", "def_ko": "체내 물질이 변화하는 과정", "def_vi": "Quá trình thay đổi chất trong cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (840, '5', '다음 중 노인성 질환의 특성으로 옳은 것은?', '["질환의 경과가 빠른 급성질환이 대부분이다.", "젊은 사람보다 약물에 둔감하게 반응한다.", "질환이 빈번히 발생하여 회복이 빠르다.", "노화과정과 구분이 어려워 정확한 진단이 어렵다.", "골격근의 수축력 증가로 관절운동이 용이하다."]'::jsonb, 4, '노인성 질환의 일반적인 특성을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "급성질환은 일반적으로 노인성 질환에 해당하지 않습니다. 노인성 질환은 만성적입니다.\n[정답]", "4": "노인성 질환은 노화 과정과 밀접한 관련이 있어 진단이 어렵습니다.", "3": "노인성 질환은 빈번히 발생하지만 회복이 느린 경향이 있습니다.", "2": "노인의 약물 반응은 젊은 사람에 비해 변화가 있을 수 있으나 둔감하다고 일반화할 수 없습니다.", "5": "노화로 골격근의 수축력이 감소하는 경우가 많아 관절 운동이 용이하지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "노인성", "term_vi": "Người cao tuổi", "def_ko": "노화로 인한", "def_vi": "Do quá trình lão hóa"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (839, '5', '노인성 질환의 특성으로 옳은 것은?', '["노인성 질환은 경과가 짤다.", "합병증이 동반되지 않는다.", "질환이 치유되면 자립생활이 가능하다.", "전형적인 증상이 빈번하게 나타난다.", "다른 질병을 동반하기 쉽다."]'::jsonb, 5, '노인성 질환의 특성을 이해하고, 잘못된 정보와 올바른 정보를 구별할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "노인성 질환은 보통 경과가 길다.\n[정답]", "5": "노인성 질환은 다른 질병을 동반하기 쉬운 경향이 있다.", "2": "노인성 질환은 합병증이 동반되기 쉽다.", "3": "대부분의 경우 자립생활이 어려울 수 있다.", "4": "전형적인 증상이 항상 나타나는 것은 아니다."}'::jsonb, '[{"term_ko": "노인성", "term_vi": "Người già", "def_ko": "나이가 많은", "def_vi": "Người lớn tuổi"}, {"term_ko": "합병증", "term_vi": "Biến chứng", "def_ko": "다른 질병이나 상태에서 생기는 문제", "def_vi": "Vấn đề phát sinh từ bệnh hoặc tình trạng khác"}, {"term_ko": "자립생활", "term_vi": "Sống tự lập", "def_ko": "독립적으로 생활하는 것", "def_vi": "Sống độc lập"}, {"term_ko": "특성", "term_vi": "Đặc điểm", "def_ko": "특징", "def_vi": "Đặc trưng"}, {"term_ko": "경과", "term_vi": "Quá trình", "def_ko": "병이 진행되는 과정", "def_vi": "Tiến trình"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (838, '5', '노인성 질환의 특성으로 옳은 것은?', '["정상적인 노화과정과 구분이 쉬다.", "재발되는 경우는 드물다.", "질환에 대한 민감도가 낮다.", "수분과 전해질의 균형이 깨지기 쉽다.", "약 성분이 체외로 빨리 배출되어 치료가 어렵다."]'::jsonb, 4, '노인성 질환의 특성에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "정상적인 노화과정과 구분이 쉽지 않습니다.\n[정답]", "4": "노인의 경우 수분과 전해질의 균형이 깨지기 쉽습니다.", "2": "재발되는 경우가 많습니다.", "3": "오히려 질환에 대한 민감도가 높습니다.", "5": "약 성분이 체내에 오래 남아 효과적으로 치료할 수 있습니다."}'::jsonb, '[{"term_ko": "노인성", "term_vi": "질환", "def_ko": "노인과 관련된, bệnh liên quan đến người già", "def_vi": "병, bệnh lý"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (837, '4', '다음 내용에 해당하는 직무스트레스 해소 방법은?업무 중 상사로부터 꾸지람을 들었을 때"나에게 관심이 있어 야단치는 거야."라고 자신의 상황을 긍정적으로 생각한다.', '["호흡법", "인정요법", "심상훈련", "인지수정", "긴장이완기법"]'::jsonb, 4, '업무 스트레스 해소 방법 중 인지적 접근 방식을 이해하도록 하는 의도입니다.', NULL, '{"1": "호흡법: 긴장을 완화하고 집중력을 높이기 위한 방법입니다.", "2": "인정요법: 개인의 감정이나 행동을 수용하는 방법입니다.\n[정답]", "3": "인지수정: 부정적인 사고를 긍정적으로 전환하는 기법으로, 문제에서 제시된 상황을 긍정적으로 해석하는 것을 포함합니다.", "4": "긴장이완기법: 신체의 긴장을 풀어주는 방법입니다."}'::jsonb, '[{"term_ko": "직무스트레스", "term_vi": "Stress công việc", "def_ko": "업무 스트레스(압박감, 부담감)", "def_vi": "áp lực, gánh nặng trong công việc"}, {"term_ko": "긍정적", "term_vi": "Tích cực", "def_ko": "긍정적인, 좋은", "def_vi": "tốt"}, {"term_ko": "상사", "term_vi": "Cấp trên", "def_ko": "직장의 상위 관계자", "def_vi": "người cấp cao trong công việc"}, {"term_ko": "상황", "term_vi": "Tình huống", "def_ko": "특정한 경우나 상황", "def_vi": "trường hợp hay hoàn cảnh cụ thể"}, {"term_ko": "인지", "term_vi": "Nhận thức", "def_ko": "인지, 인식", "def_vi": "sự nhận biết"}, {"term_ko": "해소", "term_vi": "Giải quyết", "def_ko": "문제를 해결하거나 없애다", "def_vi": "giải quyết hoặc loại bỏ vấn đề"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (836, '4', '다음 설명에 해당하는 직무스트레스 대처 방법은?•과거 편안했던 기억을 떠올린다. •복식호흡을 천천히 하면서 "편해", "쉬어" 등의 단어를 천천히 속으로 반복한다.', '["호흡법", "인정요법", "심상훈련", "인지수정", "긴장이완기법"]'::jsonb, 3, '직무스트레스 대처 방법에 대한 이해를 확인하기 위함입니다.', NULL, '{"1": "호흡법: 호흡을 조절하여 스트레스를 줄이는 방법입니다.\n[정답]", "3": "심상훈련: 과거의 편안한 기억을 떠올리고 긍정적인 단어를 반복하여 마음을 편안하게 만드는 기법입니다.", "2": "인정요법: 자신의 감정을 인식하고 수용하는 방법입니다.", "4": "인지수정: 부정적인 사고를 긍정적인 사고로 바꾸는 방법입니다.", "5": "긴장이완기법: 근육의 긴장을 풀어주는 기법입니다."}'::jsonb, '[{"term_ko": "직무스트레스", "term_vi": "Căng thẳng nghề nghiệp", "def_ko": "직장에서의 스트레스", "def_vi": "Căng thẳng trong công việc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (835, '4', '직무스트레스를 예방하기 위한 활동으로 옳은 것은?', '["근로계약 시 근로시간을 유연하게 정한다.", "업무 효율을 위해 동료 간의 만남을 자제한다.", "업무 성과를 위해 근무 중 휴게시간을 반납한다.", "정기회의와 면담을 통해 의사소통 체계를 확보한다.", "업무지침은 상황에 따라 근로자가 판단하고 변경한다."]'::jsonb, 4, '직무스트레스를 예방하는 활동 중의 하나를 묻고 있다.', NULL, '{"1": "근로계약 시 근로시간을 유연하게 정하는 것은 직무스트레스를 줄일 수 있지만, 직접적인 예방 활동이라고 보기는 어렵다.\n[정답]", "4": "정기회의와 면담을 통해 의사소통 체계를 확보하는 것은 직원 간의 의견 교환과 스트레스 관리에 매우 중요한 활동이다.", "3": "업무 성과를 위해 근무 중 휴게시간을 반납하는 것은 오히려 직무스트레스를 악화시킬 가능성이 있다.", "2": "업무 효율을 위해 동료 간의 만남을 자제하는 것은 소통의 단절을 초래할 수 있어 부정적 영향을 미칠 수 있다.", "5": "업무지침의 판단과 변경은 근로자의 주관적인 판단에 의존하게 되어 혼란을 초래할 수 있으므로 적절하지 않다."}'::jsonb, '[{"term_ko": "직무스트레스", "term_vi": "Stress nghề nghiệp", "def_ko": "직장에서 느끼는 스트레스", "def_vi": "Căng thẳng nghề nghiệp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (834, '4', '다음 사례에 해당하느 요양보호사의 직무스트레스 유발 요인은?치매대상자가 커피잔이 없어졌다면서, 요양보호사가 의심스럽다고 아들에게 말한다. "커피잔이 예쁘고 좋은 걸 알고 훔쳐갔어. 손버릇이 아주 나빠." 치매증상을 이해하고 최선을 다하려고 하지만, 도둑 취급당하는 것 같아 자존심도 상하고 기분이 나쁘다.', '["직무요구", "조직체계", "노동강도", "역할모호", "감정노동"]'::jsonb, 5, '요양보호사가 직면하는 직무스트레스의 유발 요인을 확인하기 위한 문제입니다.', NULL, '{"1": "직무요구: 업무의 양이나 질이 높은 경우를 말하며, 해당 사례와는 관련이 없습니다.", "2": "조직체계: 조직에서의 위치나 권한에 따른 문제로, 이번 사례와 직접적인 연관이 없습니다.", "3": "노동강도: 육체적 혹은 정신적 노동의 강함에 대한 것으로, 이 경우와는 관계가 적습니다.", "4": "역할모호: 역할의 경계나 기대가 불확실한 경우를 의미하나, 이 사례는 그와는 거리가 있습니다.\n[정답]", "5": "감정노동: 감정 노동은 타인의 감정을 관리해야 하는 일을 의미하며, 요양보호사가 도둑 취급을 당하는 느낌을 받아 스트레스를 받는 상황이 이에 해당합니다."}'::jsonb, '[{"term_ko": "직무스트레스", "term_vi": "Căng thẳng công việc", "def_ko": "업무에서 오는 스트레스(한국어)", "def_vi": "Căng thẳng đến từ công việc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (833, '4', '다음 내용에 해당하는 요양보호사의 직무스트레스 유발 요인은?대상자:"점심에 딸들이 온다는데, 식사 좀 맛있게 준비해 줘요. 애들 갈 때 싸서 보낼 반찬도 넉넉하게 만들어 줘요." 요양보호사:"(......)', '["조직체계", "직무요구", "역할모호", "노동강도", "성희롱"]'::jsonb, 3, '요양보호사의 직무스트레스 요인에 대해 이해하고 있는지를 평가하기 위한 문제이다.', NULL, '{"1": "조직체계: 요양보호사가 속한 조직의 구조와 운영 방식이 직무 스트레스에 미치는 영향이다.", "2": "직무요구: 요양보호사에게 요구되는 직무의 양과 질을 나타낸다.\n[정답]", "3": "역할모호: 요양보호사가 맡은 역할과 책임이 불명확할 때 발생하는 스트레스를 의미한다.", "4": "노동강도: 직무를 수행하는 데 필요한 육체적 힘의 정도를 나타낸다.", "5": "성희롱: 직장 내 성적인 괴롭힘으로 인한 스트레스 요인이다."}'::jsonb, '[{"term_ko": "직무스트레스", "term_vi": "Căng thẳng công việc", "def_ko": "업무에서 느끼는 스트레스", "def_vi": "Stress mà nhân viên gặp phải trong công việc"}, {"term_ko": "조직체계", "term_vi": "Hệ thống tổ chức", "def_ko": "조직의 구조와 운영 방식", "def_vi": "Cấu trúc và cách thức hoạt động của tổ chức"}, {"term_ko": "직무요구", "term_vi": "Yêu cầu công việc", "def_ko": "업무의 양과 질", "def_vi": "Khối lượng và chất lượng công việc"}, {"term_ko": "역할모호", "term_vi": "Mơ hồ về vai trò", "def_ko": "역할과 책임의 불확실성", "def_vi": "Sự không rõ ràng về vai trò và trách nhiệm"}, {"term_ko": "노동강도", "term_vi": "Cường độ lao động", "def_ko": "직무에 필요한 육체적 힘의 정도", "def_vi": "Mức độ sức lực cần thiết để thực hiện nhiệm vụ"}, {"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적인 괴롭힘", "def_vi": "Hành vi quấy rối tình dục"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (832, '4', '재가요양보호사가 경험하는 직무스트레스에 대한 설명으로 옳은 것은?', '["역할모호 - 업무범위 밖의 가사노동 요구", "감정노동 - 가족을 대신하여 보호자 역할 수행", "성희롱 - 대상자의 자유로운 의사표현의 권리 존중", "직무요구 - 생활이 어려운 대상자의 생업 지원의 부담감", "조직체계 - 체계적인 관리감독에 따른 근로조건의 일관성"]'::jsonb, 1, '재가요양보호사가 직무 중 경험하는 스트레스를 이해하고 관련된 용어를 구별하는 것.', NULL, '{"1": "역할모호 - 업무범위 밖의 가사노동 요구는 재가요양보호사가 직무 구분이 명확하지 않을 때 겪는 스트레스를 설명한다.\n[정답]", "2": "감정노동 - 가족을 대신하여 보호자 역할 수행은 재가요양보호사가 정서적 노동을 하고 있다는 것을 나타낸다. 그러나 직무스트레스의 직접적인 원인은 아니다.", "3": "성희롱 - 대상자의 자유로운 의사표현의 권리 존중은 성희롱을 구분하는 내용이며, 스트레스의 원인으로 보기 어렵다.", "4": "직무요구 - 생활이 어려운 대상자의 생업 지원의 부담감은 직무의 요구를 설명하지만, 이는 스트레스의 원인보다는 응답자의 직무 내 외적인 요구를 나타낸다.", "5": "조직체계 - 체계적인 관리감독에 따른 근로조건의 일관성은 스트레스보다는 조직의 안정성을 의미한다."}'::jsonb, '[{"term_ko": "역할모호", "term_vi": "Vai trò mơ hồ", "def_ko": "역할의 경계가 불명확함(한국어)", "def_vi": "Ranh giới vai trò không rõ ràng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (831, '4', '옴에 감염된 대상자를 안전하게 돕는 방법으로 옳은 것은?', '["공용 체온계를 사용한다.", "맨손으로 가려운 곳을 긁어 준다.", "감염 부위를 만져 보아 열감을 확인한다.", "내의와 침구는 뜨거운 물로 10~20분간 세탁한다.", "대상자와 접촉하여 증상이 나타나면 장갑과 가운을 착용한다."]'::jsonb, 4, '옴 감염에 대한 안전한 처리 방법을 이해하고 있는지를 묻는 문제입니다.', NULL, '{"1": "공용 체온계를 사용하면 감염이 확산될 수 있으므로 안전하지 않습니다.\n[정답]", "4": "내의와 침구를 뜨거운 물로 10~20분간 세탁하면 감염균을 효과적으로 제거할 수 있습니다.", "2": "맨손으로 가려운 곳을 긁어 주는 것은 감염을 악화시킬 수 있어 위험합니다.", "3": "감염 부위를 만져 보아 열감을 확인하는 것은 불필요하며, 손상된 피부를 건드리는 것은 위험할 수 있습니다.", "5": "대상자와 접촉하여 증상이 나타나면 장갑과 가운을 착용하는 것은 사후 조치로 적절하지만, 사전에 예방하는 것이 더 중요합니다."}'::jsonb, '[{"term_ko": "옴", "term_vi": "Ghẻ", "def_ko": "피부에 발생하는 기생충 감염", "def_vi": "Nhiễm ký sinh trùng trên da"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "병원체가 체내에 침투하여 발생하는 질병", "def_vi": "Bệnh xảy ra khi vi khuẩn xâm nhập vào cơ thể"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "오염물질을 제거하기 위한 처리", "def_vi": "Xử lý để loại bỏ chất bẩn"}, {"term_ko": "장갑", "term_vi": "Găng tay", "def_ko": "손을 보호하기 위한 기구", "def_vi": "Dụng cụ bảo vệ tay"}, {"term_ko": "가운", "term_vi": "Áo choàng", "def_ko": "의료진이 착용하는 보호복", "def_vi": "Trang phục bảo vệ của nhân viên y tế"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (830, '4', '옴에 대한 설명으로 옳은 것은?', '["밤보다 낮에 가려움이 더 심하다.", "2~3주 지나면 자연적으로 없어진다.", "다른 사람에게 옮기지 않는다.", "면역이 저하된 노인에게 주로 발생한다.", "약은 밤에 바르고 다음날 아침에 씻어낸다."]'::jsonb, 5, '옴에 대한 기본적인 이해와 관련된 증상 및 치료 방법을 파악하기 위한 문제입니다.', NULL, '{"1": "낮에 가려움이 심한 것이 아니라, 주로 밤에 가려움이 심해지는 질환입니다.\n[정답]", "2": "일반적으로 옴은 자연적으로 사라지지 않고, 치료가 필요합니다.", "3": "옴은 쉽게 전염되므로 다른 사람에게 옮길 수 있습니다.", "4": "면역이 저하된 노인뿐만 아니라, 모든 연령대에서 발생할 수 있습니다.", "5": "옴 약물은 일반적으로 밤에 바르고 다음날 씻어내는 방법이 효과적입니다."}'::jsonb, '[{"term_ko": "옴", "term_vi": "Ghẻ", "def_ko": "피부질환으로 가려움증을 유발하는 병", "def_vi": "Bệnh da gây ngứa"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (829, '4', '옴에 감염된 편마비 대상자를 돌볼 때 요양보호사의 대처방법은?', '["마스크를 착용한다.", "얼굴을 포함한 전신에 연고를 발라준다.", "2~3일간 요양보호 업무를 중단한다.", "내의 및 침구류를 세탁 후 바로 사용한다.", "세탁이 어려운 것은 3일간 햇볕을 쬐거나 다리미로 다린다."]'::jsonb, 5, '옴에 감염된 편마비 대상자를 돌볼 때 요양보호사가 알아야 할 대처방법을 평가하기 위한 문제입니다.', NULL, '{"1": "마스크를 착용하는 것은 일반적인 감염 예방의 방법이지만, 옴은 피부 접촉을 통해 전파되므로 마스크 착용만으로는 충분하지 않습니다.\n[정답]", "5": "세탁이 어려운 것은 3일간 햇볕을 쬐거나 다리미로 다려 소독하는 방법은 옴의 전파를 예방하는데 효과적입니다.", "2": "얼굴을 포함한 전신에 연고를 발라주는 것은 감염 치료에 필요하지만, 요양보호사로서의 대처방법으로는 적절하지 않습니다.", "3": "2~3일간 요양보호 업무를 중단하는 것은 감염이 확인된 후 필요할 수 있으나, 반드시 필요한 대처 방법은 아닙니다.", "4": "내의 및 침구류를 세탁 후 바로 사용하하는 것은 감염 전파의 위험이 있습니다."}'::jsonb, '[{"term_ko": "옴", "term_vi": "Ghẻ", "def_ko": "피부 질환으로 발생하는 병", "def_vi": "Bệnh về da do ký sinh trùng gây ra"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (828, '4', '요양보호사가 옴에 감염된 대상자에게 서비스를 실행한 후 겨드랑이에 물집이 생기고 가려움증이 있을 때 치료방법으로 옳은 것은?', '["24시간 이내에 예방접종을 한다.", "겨드랑이와 팔이 접히는 부분에만 약을 바른다.", "엑스레이를 찍어 감염여부를 확인한다.", "자연 치유되므로 그냥 나둔다.", "요양보호사와 동거하는 가족까지 동시에 치료를 받는다."]'::jsonb, 5, '요양보호사가 옴에 감염된 대상자에게 적절한 치료 방법을 선택할 수 있는지를 묻는 문제입니다.', NULL, '{"1": "예방접종은 옴 감염에 대해 즉각적인 치료 효과가 없습니다.\n[정답]", "5": "옴은 전염성이 강하므로, 요양보호사와 동거하는 가족도 함께 치료를 받아야 합니다.", "2": "겨드랑이와 팔 접히는 부분에만 약을 바르는 것은 부족한 대처법입니다.", "3": "엑스레이는 옴 감염을 확인하는 방법이 아닙니다.", "4": "자연 치료를 기대하는 것은 적절한 치료 방법이 아닙니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람이란 뜻", "def_vi": "Người chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (827, '4', '다음 내용에 해당하는 감염성 질환은?•오염된 음식, 물 등을 섭취할 때 감염된다. •구토, 메스꺼움,오한,복통, 설사 증상이 있다. •감염력이 강하고 전염성이 높다.', '["옴", "결핵", "독감", "머릿니", "노로바이러스 장염"]'::jsonb, 5, '(감염성 질환의 전파 경로 및 증상에 대한 이해를 평가하고자 함)', NULL, '{"1": "옴: 피부에 기생하는 기생충에 의해 발생하는 질환으로, 이 문제의 증상과 전파 방식이 다름.", "2": "결핵: 호흡기를 통해 전파되는 세균 감염이며, 문제의 전파 경로와는 관련이 없음.", "3": "독감: 바이러스에 의해 발생하지만, 주로 호흡기로 전파되며 문제의 전파 경로와 맞지 않음.\n[정답]", "5": "노로바이러스 장염: 오염된 음식이나 물을 통해 감염되며, 구토, 메스꺼움, 복통, 설사 등의 증상을 동반하고 전염성이 강함.", "4": "머릿니: 피부 접촉을 통해 전파되지만, 문제의 증상과는 일치하지 않음."}'::jsonb, '[{"term_ko": "감염성", "term_vi": "Nhiễm trùng", "def_ko": "감염을 일으키는 성질(한국어)", "def_vi": "Tính chất gây nhiễm trùng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (826, '4', '요양보호사가 대상자로부터 감염되지 않도록 주의해야 하는 직업성 감염 질환은?', '["옴", "천식", "기관지염", "알레르기성 비염", "갑상선기능 저하증"]'::jsonb, 1, '요양보호사가 직업적으로 감염의 위험에 노출될 수 있는 질환을 인식하도록 하기 위함입니다.', NULL, '{"1": "옴은 피부 접촉을 통해 전파되는 감염병입니다.\n[정답]", "2": "천식은 알레르기나 환경적 요인에 의해 발생하는 호흡기 질환입니다.", "3": "기관지염은 주로 바이러스나 박테리아에 의해 발생하는 염증입니다.", "4": "알레르기성 비염은 알레르기 반응으로 인한 비염으로 전염성이 없습니다.", "5": "갑상선기능 저하증은 호르몬 분비 문제로 발생하며, 전염성이 없습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 돌보는 전문가", "def_vi": "Người chuyên chăm sóc bệnh nhân"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "병원균이 몸에 침투하여 생기는 질병", "def_vi": "Bệnh do vi khuẩn xâm nhập vào cơ thể"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병이나 증세", "def_vi": "Bệnh tật hoặc triệu chứng"}, {"term_ko": "천식", "term_vi": "Hen suyễn", "def_ko": "호흡기 질환", "def_vi": "Bệnh đường hô hấp"}, {"term_ko": "기관지염", "term_vi": "Viêm phế quản", "def_ko": "호흡기 염증", "def_vi": "Viêm đường hô hấp"}, {"term_ko": "알레르기성 비염", "term_vi": "Viêm mũi dị ứng", "def_ko": "비염의 일종", "def_vi": "Một loại viêm mũi"}, {"term_ko": "갑상선기능 저하증", "term_vi": "Suy giáp", "def_ko": "갑상선의 기능 저하", "def_vi": "Giảm chức năng tuyến giáp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (825, '4', '요양보호사가 업무 중 고열과 인후통 증상으로 독감이 의심될 때 우선적으로 해야 할 일은?', '["요양보호 업무를 중단한다.", "독감 예방접종을 한다.", "사용하던 물품을 소독한다.", "가글액으로 입안을 헹군다.", "해열진통제를 복용한다."]'::jsonb, 1, '요양보호사가 독감과 같은 전염병 의심 증상이 나타날 때 어떤 행동을 우선적으로 취해야 하는지 평가하는 문제입니다.', NULL, '{"1": "요양보호사가 전염병 증상을 보일 때에는 다른 환자에게 전염을 예방하기 위해 업무를 중단해야 합니다.\n[정답]", "2": "예방접종은 사전 예방 조치이지, 증상이 나타난 경우에는 시급하지 않습니다.", "3": "소독은 중요하지만, 가장 우선적으로 해야 할 행동은 아닙니다.", "4": "가글은 증상 완화를 위한 조치이나, 우선시되어야 할 사항은 아닙니다.", "5": "해열진통제 복용도 필요할 수 있으나, 업무 중단이 우선되어야 합니다."}'::jsonb, '[{"term_ko": "고열", "term_vi": "Sốt cao", "def_ko": "높은 체온", "def_vi": "Nhiệt độ cơ thể cao"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (824, '4', '요양보호서비스 제공 시 감염을 예방하는 방법으로 옳은 것은?', '["독감이 걸린 대상자는 즉시 서비스를 중단한다.", "장염에 감염된 경우 손을 잘 씻고 음식조리를 한다.", "독감이 유행하기 시작하면 예방접종을 한다.", "결핵대상자가 사용한 침구류는 일광소독 한다.", "요양보호사가 잠복결핵 상태인 경우 업무를 중단한다."]'::jsonb, 4, '요양보호서비스 제공 시 감염 예방의 중요성을 이해하고, 올바른 예방 방법을 선택하도록 유도하는 문제입니다.', NULL, '{"1": "독감이 걸린 대상자는 즉시 서비스를 중단하는 것은 지나친 조치입니다. 대신 감염 예방을 위한 다른 방법을 취해야 합니다.\n[정답]", "4": "결핵대상자가 사용한 침구류는 일광소독 하는 것이 올바른 감염 예방 방법입니다.", "2": "장염에 감염된 경우 손을 잘 씻고 음식조리를 하는 것은 필요하지만, 감염 예방을 위한 방법으로는 적합하지 않습니다.", "3": "독감이 유행하기 시작하면 예방접종을 하는 것이 권장되지만, 질문의 의도에는 직접적인 감염 예방 방법이 아닙니다.", "5": "요양보호사가 잠복결핵 상태인 경우 업무를 중단하는 것이 적절할 수 있지만, 모든 경우에 해당하는 것은 아닙니다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염(한국어)", "def_vi": "Nhiễm trùng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (823, '4', '요양보호사의 직업성 감염질환 중 결핵에 대한 설명으로 옳은 것은?', '["결핵은 폐에만 침범하는 감염성 질환이다.", "식욕증가와 함께 체중이 늘어난다.", "2주 이상의 기침과 피가 섞인 가래가 나온다.", "감염 대상자와 접촉 시에는 즉시 격리치료를 받는다.", "결핵은 유전되는 질환이다."]'::jsonb, 3, '결핵에 대한 정확한 이해를 평가하고자 하는 문제입니다.', NULL, '{"1": "결핵은 폐에만 침범하는 감염성 질환이 아니며, 다른 장기에도 영향을 미칠 수 있습니다.\n[정답]", "3": "2주 이상의 기침과 피가 섞인 가래는 결핵의 전형적인 증상입니다.", "2": "결핵 환자는 보통 체중이 줄어들며 식욕도 감소합니다.", "4": "감염 대상자와 접촉 시 즉시 격리치료를 받기보다는 적절한 조치를 취하고 관찰하는 것이 중요합니다.", "5": "결핵은 유전되는 질환이 아닙니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌보는 사람", "def_vi": "Người chăm sóc cho người khác"}, {"term_ko": "결핵", "term_vi": "Bệnh lao", "def_ko": "폐렴 바이러스에 의해 발생하는 감염 질환", "def_vi": "Bệnh gây ra bởi virus phổi"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "병원균이 침투하여 생기는 질병", "def_vi": "Bệnh do vi khuẩn xâm nhập gây ra"}, {"term_ko": "기침", "term_vi": "Ho", "def_ko": "숨을 쉴 때 공기가 목구멍에서 나오는 과정", "def_vi": "Hành động phát ra âm thanh trong quá trình thở"}, {"term_ko": "가래", "term_vi": "Đờm", "def_ko": "기침을 할 때 나오는 진한 분비물", "def_vi": "Chất nhầy tiết ra khi ho"}, {"term_ko": "격리", "term_vi": "Cách ly", "def_ko": "분리하여 치료하는 절차", "def_vi": "Quy trình tách riêng để điều trị"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (822, '4', '결핵이 의심되는 환자를 돌볼 시 감염을 예방하는 방법으로 옳은 것은?', '["항생제 복용", "보호장구 착용", "침구류 그늘에서 말리기", "수액으로 영양보충", "대상자가 입었던 옷 소각"]'::jsonb, 3, '결핵 환자를 돌보는 과정에서 감염 예방에 대한 올바른 방법을 확인하는 것입니다.', NULL, '{"1": "항생제 복용은 치료에 도움이 되지만 감염 예방과는 관련이 적습니다.\n[정답]", "2": "보호장구 착용은 감염을 예방하는 방법 중 하나입니다.", "3": "침구류 그늘에서 말리기는 위생적으로 처리가치 않지만, 감염 예방으로 직접적인 효과는 없습니다.", "4": "수액으로 영양보충은 직접적인 감염 예방과는 관련이 없습니다.", "5": "대상자가 입었던 옷 소각은 과도한 조치이며 필요하지 않습니다."}'::jsonb, '[{"term_ko": "결핵", "term_vi": "Bệnh lao", "def_ko": "병균에 의한 폐 질환", "def_vi": "Bệnh do vi khuẩn gây ra ở phổi"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "질병이나 바이러스가 신체에 침투하는 것", "def_vi": "Sự xâm nhập của bệnh hoặc virus vào cơ thể"}, {"term_ko": "항생제", "term_vi": "Kháng sinh", "def_ko": "세균 감염을 치료하는 약물", "def_vi": "Thuốc điều trị nhiễm trùng do vi khuẩn"}, {"term_ko": "보호장구", "term_vi": "Trang bị bảo hộ", "def_ko": "의료진이 감염을 예방하기 위해 착용하는 장비", "def_vi": "Thiết bị được nhân viên y tế sử dụng để phòng ngừa nhiễm trùng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (821, '4', '요양보호사의 감염예방 방법으로 옳은 것은?', '["가능하면 손톱을 길게 유지한다.", "분비물 접촉 후에는 휴지로 손을 닦는다.", "주기적으로 스테로이드 약물을 복용한다.", "감염질환이 의심될 때에만 건강검진을 받는다.", "임신한 경우 풍진, 수두 감염 대상자와 접촉을 피한다."]'::jsonb, 5, '요양보호사가 감염 예방을 위해 알아야 할 올바른 방법을 묻는 문제입니다.', NULL, '{"1": "가능하면 손톱을 짧게 관리해야 합니다. 손톱이 길면 세균이 쌓이기 쉽습니다.\n[정답]", "5": "임신한 경우 풍진, 수두 감염 대상자와의 접촉을 피해야 합니다. 감염으로 인한 위험을 예방할 수 있습니다.", "2": "분비물 접촉 후에는 반드시 손을 씻어야 합니다. 휴지로 닦는 것은 불완전합니다.", "3": "주기적으로 스테로이드 약물을 복용하는 것은 면역력을 저하시킬 수 있기 때문에 권장되지 않습니다.", "4": "감염 질환이 의심될 때는 정기적으로 건강검진을 받아야 합니다. 검진을 지연하는 것은 좋지 않습니다."}'::jsonb, '[{"term_ko": "감염예방", "term_vi": "Phòng ngừa nhiễm trùng", "def_ko": "감염을 예방하는 방법", "def_vi": "Các phương pháp ngăn ngừa nhiễm trùng"}, {"term_ko": "손톱", "term_vi": "Móng tay", "def_ko": "손가락 끝의 단단한 부분", "def_vi": "Phần cứng ở đầu ngón tay"}, {"term_ko": "분비물", "term_vi": "Chất tiết", "def_ko": "몸에서 나오는 물질", "def_vi": "Chất từ cơ thể tiết ra"}, {"term_ko": "스테로이드", "term_vi": "Steroid", "def_ko": "호르몬의 일종", "def_vi": "Một loại hormone"}, {"term_ko": "핵검진", "term_vi": "Kiểm tra sức khỏe", "def_ko": "건강을 확인하는 절차", "def_vi": "Quy trình xác nhận sức khỏe"}, {"term_ko": "풍진", "term_vi": "Rubella", "def_ko": "바이러스 감염", "def_vi": "Nhiễm virus"}, {"term_ko": "수두", "term_vi": "Thủy đậu", "def_ko": "바이러스 감염", "def_vi": "Nhiễm virus"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (820, '4', '요양보호사의 근골격계 손상을 예방하기 위한 스트레치 방법으로 옳은 것은?', '["통증을 느낄 때까지 한다.", "같은 동작을 2~3회 반복한다.", "동작을 빠르고 신속하게 한다.", "스트레칭 된 자세로 10~15초 정도 유지한다.", "동작과 동작 사이를 쉬지 않고 계속 한다."]'::jsonb, 4, '요양보호사가 근골격계 손상을 예방하기 위해 올바른 스트레칭 방법을 이해하고 적용하는 능력을 평가하고자 하는 것이다.', NULL, '{"1": "통증을 느낄 때까지 하는 것은 부상의 위험이 크므로 올바르지 않다.\n[정답]", "4": "스트레칭 된 자세로 10~15초 정도 유지하는 것은 근육의 이완을 도와주어 안전한 스트레칭 방법이다.", "2": "같은 동작을 2~3회 반복하는 것은 일반적인 스트레칭 방법이나, 너무 반복할 경우 부상의 위험이 높아질 수 있다.", "3": "동작을 빠르고 신속하게 하는 것은 스트레칭의 목적에 맞지 않다.", "5": "동작과 동작 사이를 쉬지 않고 계속하는 것은 근육의 회복 시간을 방해할 수 있다."}'::jsonb, '[{"term_ko": "근골격계", "term_vi": "Hệ cơ xương", "def_ko": "신체의 뼈와 근육 시스템", "def_vi": "Hệ thống xương và cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (819, '4', '요양보호사가 전신 스트레칭을 할 때 올바른 방법은?', '["동작을 최대한 빠르고 강하게 한다.", "스트레칭된 자세로 30초이상 유지한다.", "상 하 좌 우 균형있게 교대로 스트레칭한다.", "통증이 느껴질 때까지 동작을 반복한다.", "호흡을 최대한 참고 스트레칭 한다."]'::jsonb, 3, '요양보호사가 전신 스트레칭을 하는 올바른 방법에 대해 묻고 있습니다.', NULL, '{"1": "동작을 최대한 빠르고 강하게 하면 부상을 초래할 수 있습니다.\n[정답]", "3": "상하좌우 균형 있게 교대로 스트레칭하는 것이 올바른 방법입니다.", "2": "스트레칭된 자세를 30초 이상 유지하는 것은 좋지만 교대로 하는 것이 중요합니다.", "4": "통증이 느껴질 때까지 동작을 반복하는 것은 위험합니다.", "5": "호흡을 최대한 참고 스트레칭하는 것은 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "전신 스트레칭", "term_vi": "Kéo dài toàn thân", "def_ko": "전신을 늘이고 기르는 동작", "def_vi": "Động tác kéo dài toàn bộ cơ thể"}, {"term_ko": "상하좌우", "term_vi": null, "def_ko": "위아래 그리고 좌우", "def_vi": null}, {"term_ko": "균형", "term_vi": "Cân bằng", "def_ko": "같은 정도로 나누어짐", "def_vi": "Chia đều mức độ"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔", "def_vi": "Cảm giác đau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (818, '4', '노인 대상자가 만성관절염으로 어깨와 무릎에 통증을 호소할 때 돕는 방법으로 옳은 것은?', '["냉찜질을 한다.", "온찜질을 한다.", "진통제를 준다.", "심호흡을 하게 한다.", "운동의 강도를 높인다."]'::jsonb, 2, '노인 대상자의 만성관절염에 대한 이해 및 적절한 대처 방법을 묻는 문제입니다.', NULL, '{"1": "냉찜질은 초기 통증이나 염증이 있는 경우 사용하지만 만성관절염에는 적절하지 않습니다.\n[정답]", "2": "온찜질은 혈액순환을 촉진하고 통증 완화에 도움을 주므로 적절한 방법입니다.", "3": "진통제는 통증 완화에 도움이 될 수 있으나 의사의 처방이 필요합니다.", "4": "심호흡은 긴장을 완화할 수 있으나 통증의 직접적인 완화에는 효과적이지 않습니다.", "5": "운동의 강도를 높이는 것은 오히려 통증을 악화시킬 수 있으므로 권장되지 않습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (817, '4', '침대의 자세를 조절하기 위해서 반복적으로 레버를 돌리다가 손목에 통증과 부종이 생길 경우 초기 대처 방법은?', '["손목 부위에 압박 붕대를 감아준다.", "손목을 가볍게 털어 준다.", "스테로이드 약물을 주입한다.", "손목 부위에 온찜질을 한다.", "심장보다 손상부위를 낮게 내린다."]'::jsonb, 1, '손목에 통증과 부종이 발생했을 때 적절한 초기 대처 방법을 이해하는 것.', NULL, '{"1": "손목 부위에 압박 붕대를 감아준다: 손목의 부종을 줄이고 통증을 완화하는 데 도움이 된다.\n[정답]", "2": "손목을 가볍게 털어 준다: 통증을 가중시킬 수 있는 방법이다. 효과적이지 않다.", "3": "스테로이드 약물을 주입한다: 급성 상황에서 초기 대처로는 적합하지 않다.", "4": "손목 부위에 온찜질을 한다: 초기에는 찜질보다 냉찜질이 더 효과적이다.", "5": "심장보다 손상부위를 낮게 내린다: 부종을 악화시킬 수 있으므로 바람직하지 않다."}'::jsonb, '[{"term_ko": "손목", "term_vi": "Cổ tay", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (816, '4', '요양보호사가 물건을 들어 올릴 때 허리를 보호하는 자세로 옳은 것은?', '["무릎을 펴고 무게중심을 높인다.", "몸의 무게중심을 낮추고 지지면을 좁힌다.", "물건을 최대한 몸 가까이 위치하여 들어올린다.", "물건을 든 상태에서 허리를 돌려 방향을 전환한다.", "양손으로 물건을 들어 올릴 때는 허리를 구부리고 들어올린다."]'::jsonb, 3, '요양보호사가 올바른 자세로 물건을 들어야 하는 이유를 이해하고, 허리의 보호 방법을 알고 있는지를 묻는 문제입니다.', NULL, '{"1": "무릎을 펴고 무게중심을 높이면 허리에 무리가 갈 수 있습니다.\n[정답]", "3": "물건을 최대한 몸 가까이 위치하여 들어올리면 허리 부담이 줄어듭니다.", "2": "몸의 무게중심을 낮추고 지지면을 좁히면 불안정해질 수 있습니다.", "4": "물건을 든 상태에서 허리를 돌리면 허리 부상을 초래할 수 있습니다.", "5": "양손으로 물건을 들어 올릴 때 허리를 구부리면 허리를 다칠 위험이 있습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 전문 직업", "def_vi": "Nghề chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (815, '4', '요양보호사가 무거운 물건을 들어 올릴 때 허리를 보호하는 자세로 옳은 것은?', '["무릎을 굽히고 지지면을 넓힌다.", "허리를 구부리고 들어올린다.", "물건을 든 상태에서 허리를 돌려 방향을 전환한다.", "물체는 몸에서 멀리 놓고 들어올린다.", "순간적인 허리힘을 이용해서 들어올린다."]'::jsonb, 1, '무거운 물건을 안전하게 들어 올리는 방법에 대한 이해를 평가하기 위해 출제됨.', NULL, '{"1": "무릎을 굽히고 지지면을 넓히는 것은 허리를 보호하는 올바른 자세입니다.\n[정답]", "2": "허리를 구부리고 들어올리는 것은 허리에 부담을 줄 수 있어 잘못된 자세입니다.", "3": "물건을 든 상태에서 허리를 돌리는 것은 허리에 과부하를 줄 수 있어 위험합니다.", "4": "물체를 몸에서 멀리 놓고 들어올리는 것은 힘을 더 주게 되어 허리에 부담이 될 수 있습니다.", "5": "순간적인 허리힘을 이용해 들어올리는 것은 부상을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자의 신체적, 정서적 지지를 제공하는 직업", "def_vi": "Người hỗ trợ về thể chất và tinh thần cho bệnh nhân"}, {"term_ko": "허리", "term_vi": "Lưng", "def_ko": "몸의 중심 부위", "def_vi": "Vùng trung tâm của cơ thể"}, {"term_ko": "물건", "term_vi": "Vật", "def_ko": "물질이나 물체", "def_vi": "Vật chất hoặc đồ vật"}, {"term_ko": "지지면", "term_vi": "Mặt tiếp xúc", "def_ko": "무언가를 지지하는 표면", "def_vi": "Bề mặt hỗ trợ một cái gì đó"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (814, '4', '허리를 오랫동안 반복적으로 구부려서 생기는 디스크를 예방하기 위한 스트레칭 방법은?', '["한 손으로 반대쪽 팔꿈치를 감싸 지그시 눌러준다.", "엎드려 누운 자세에서 위로 다리를 들어 올린다.", "등 뒤에서 수건의 양끝을 잡고 지그시 잡아당긴다.", "두 손을 뒤로하여 깍지 끼고 뒤로 밀어준다.", "양측의 손등을 맞대고 미는 동작을 유지한다."]'::jsonb, 2, '허리 디스크 예방을 위한 효과적인 스트레칭 방법을 이해하고 있는지를 묻는 문제입니다.', NULL, '{"1": "한 손으로 반대쪽 팔꿈치를 감싸 지그시 눌러주는 자세는 허리 스트레칭에 바람직하지 않습니다.\n[정답]", "2": "엎드려 누운 자세에서 위로 다리를 들어 올리는 것은 허리 근육을 효과적으로 늘려주어 디스크 예방에 도움이 됩니다.", "3": "등 뒤에서 수건의 양끝을 잡고 지그시 잡아당기는 방법은 일반적인 허리 통증 완화에는 좋지만, 디스크 예방에는 적합하지 않습니다.", "4": "두 손을 뒤로하여 깍지 끼고 뒤로 밀어주면 허리 근육에 긴장이 생길 수 있어 조심해야 합니다.", "5": "양측의 손등을 맞대고 미는 동작은 자세 교정에 도움이 되나, 디스크 예방 스트레칭에는 그다지 효과적이지 않습니다."}'::jsonb, '[{"term_ko": "허리", "term_vi": "Lưng", "def_ko": "허리(한국어)", "def_vi": "Vùng lưng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (813, '4', '수근관 증후군의 증상에 대한 설명으로 옳은 것은?', '["손목을 손바닥 방향으로 굽히면 통증이 감소된다.", "가운데 손가락의 운동 기능장애가 심하다.", "새끼손가락과 연결된 손바닥 감각이 둔해진다.", "손을 털면 저림과 통증이 완화될 수 있다.", "밤에 통증이 완화되고, 낮에는 심해진다."]'::jsonb, 4, '수근관 증후군의 증상에 대한 정확한 이해를 평가하기 위함입니다.', NULL, '{"1": "손목을 손바닥 방향으로 굽히면 통증이 감소되지 않고 오히려 악화될 수 있습니다.\n[정답]", "2": "가운데 손가락의 운동 기능장애는 있을 수 있으나, 가장 심한 경우는 아닙니다.", "3": "새끼손가락은 수근관 증후군의 주요 증상과 관련이 없습니다.", "4": "손을 털면 저림과 통증이 완화될 수 있습니다.", "5": "수근관 증후군은 밤에 통증이 증가하고 낮에 완화되는 경우가 많습니다."}'::jsonb, '[{"term_ko": "수근관", "term_vi": "Ống cổ tay", "def_ko": "손목의 중간을 지나는 관", "def_vi": "Ống giữa cổ tay"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (812, '4', '요양보호사에게 발생되는 근골격계 질환의 위험요인은?', '["반복적으로 같은 동작을 하는 경우", "안정된 자세에서 작업하는 경우", "힘이 적게 드는 일을 하는 경우", "가벼운 물건을 들어 올릴 경우", "적당한 힘을 가하는 경우"]'::jsonb, 1, '요양보호사가 업무 중 겪을 수 있는 근골격계 질환의 위험 요인을 이해하고 확인하는 것.', NULL, '{"1": "반복적으로 같은 동작을 하는 경우는 근골격계 질환의 주요 위험 요인으로, 지속적인 스트레스를 유발할 수 있다.\n[정답]", "2": "안정된 자세에서 작업하는 경우는 위험 요인으로 작용하지 않으며, 오히려 건강한 자세를 지원할 수 있다.", "3": "힘이 적게 드는 일을 하는 경우에는 위험도가 낮아 근골격계 질환과 관련이 없다.", "4": "가벼운 물건을 들어 올릴 경우에도 일반적으로 안전한 활동으로 간주된다.", "5": "적당한 힘을 가하는 경우는 근골격계에 부담을 줄이지 않기 때문에 위험 요인이 아니다."}'::jsonb, '[{"term_ko": "근골격계", "term_vi": "Hệ cơ xương", "def_ko": "신체의 뼈와 근육 시스템", "def_vi": "Hệ thống xương và cơ bắp của cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (811, '4', '치매 대상자가 옷을 입은 채 거실에 서서 대변을 보고 있다. 대상자의 딸이 정말 큰일이네, 치매 증상이 점점 심해지셔서...라고 말할 때 요양보호사의 대처방법은?', '["방으로 데리고 가서 기저귀를 채운다.", "동료 요양보호사에게 업무를 인계한다.", "뒷처리를 해준 후 증상을 기록한다.", "하던 일을 계속하며 개입하지 않는다.", "재가서비스가 어려우므로 시설 입소를 권유한다."]'::jsonb, 3, '치매 환자의 상황에 대한 적절한 대처를 묻는 문제입니다.', NULL, '{"1": "방으로 데리고 가서 기저귀를 채우는 것은 임시방편일 뿐, 근본적인 해결이 아닙니다.\n[정답]", "3": "뒷처리를 해준 후 증상을 기록하는 것은 환자의 안전과 기록 관리 측면에서 적절한 대처입니다.", "2": "동료 요양보호사에게 업무를 인계하는 것은 상황에 따라 필요할 수 있으나, 즉각적인 대처가 요구되는 상황에서는 적절하지 않습니다.", "4": "하던 일을 계속하며 개입하지 않는 것은 환자의 안전과 건강을 고려했을 때 잘못된 접근입니다.", "5": "재가서비스가 어려우므로 시설 입소를 권유하는 것은 심각한 상황에서의 대처보다는 장기적인 해결책을 제안하는 것으로, 즉각적인 대처로는 부적합합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고력에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và khả năng tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (810, '4', '평소 알고 지내던 요양보호사가 서로의 어머니에게 교차서비스를 제공하는 것으로 처리하여 급여를 더 받자고 할 때 대처방법은?', '["어머니의 의견을 물어보고 알려주겠다고 한다.", "제안을 들어줄 만한 다른 요양보호사를 소개한다.", "마찰이 생길 수 있으니 대응하지 않는다.", "윤리원칙에 어긋난다고 말하며 거부한다.", "어머니에게 교차서비스에 대해 미리 설명한다."]'::jsonb, 4, '요양보호사 간의 윤리적 갈등 및 부정행위에 대한 적절한 대처 방안을 이해하고 있는지를 평가하고자 하는 문제입니다.', NULL, '{"1": "어머니의 의견을 물어보는 것은 문제가 될 수 있는 행위를 조장할 수 있습니다.\n[정답]", "4": "윤리원칙에 어긋난다는 점을 강조하며 명확히 거부하는 것이 가장 바람직합니다.", "2": "다른 요양보호사를 소개하는 것은 문제를 악화시킬 수 있습니다.", "3": "마찰을 피하는 것이 아니라 적절한 대응이 필요합니다.", "5": "교차서비스에 대해 설명하는 것은 상황을 오해하게 만들 수 있습니다."}'::jsonb, '[{"term_ko": "교차서비스", "term_vi": "Dịch vụ chéo", "def_ko": "서로 다른 서비스를 제공하는 것", "def_vi": "Cung cấp dịch vụ khác nhau cho nhau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (809, '4', '대상자의 보호자가 사용했던 기저귀의 재사용을 강요할 때 대처방법은?', '["재사용이 해로운 이유는 설명하고 새 기저귀를 사용한다.", "소변이 덜 묻은 기저귀는 말려서 재사용한다.", "보호자의 요구 사항을 기록한 후 재사용한다.", "보호자가 방문하는 날에만 재사용한다.", "요양보호사의 사비로 기저귀를 구매하여 사용한다."]'::jsonb, 1, '대상자의 보호자가 사용했던 기저귀의 재사용을 강요하는 상황에서 요양보호사가 어떻게 대처해야 하는지를 묻고 있습니다.', NULL, '{"1": "재사용이 해로운 이유는 설명하고 새 기저귀를 사용한다. \n[정답] 재사용이 인체에 미치는 해로운 영향을 보호자에게 설명하여, 새로운 기저귀 사용을 권장하는 것이 올바른 대처입니다.", "2": "소변이 덜 묻은 기저귀는 말려서 재사용한다. \n재사용은 감염의 위험이 있어 적절하지 않습니다.", "3": "보호자의 요구 사항을 기록한 후 재사용한다. \n요양보호사는 보호자의 요구 사항보다 안전이 우선입니다.", "4": "보호자가 방문하는 날에만 재사용한다. \n보호자의 방문 여부와 관계없이 안전한 방법을 따라야 합니다.", "5": "요양보호사의 사비로 기저귀를 구매하여 사용한다. \n요양보호사의 사비로 기저귀를 구매하는 것은 바람직하지 않으며, 기관의 기준에 따라야 합니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "기저귀(한국어)", "def_vi": "Bỉm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (808, '4', '대상자로부터 본인부담금 면제를 강요 받은 경우 대처방법은?', '["형편이 어려우면 요양보호사가 대신 납부한다.", "불법행위이므로 할 수 없다고 말한다.", "면제해주고 그만큼 서비스 시간을 줄인다.", "수수료를 받고 면제받을 수 있도록 해준다.", "면제받을 수 있는 다른 기관을 소개해준다."]'::jsonb, 2, '대상자가 요양보호사에게 부당한 요구를 할 경우 적절한 대처 방법을 이해하고 있는지를 확인하기 위함입니다.', NULL, '{"1": "형편이 어려운 경우에도 요양보호사가 그 대신 납부하는 것은 정당하지 않기 때문에 잘못된 선택입니다.\n[정답]", "2": "불법행위이므로 할 수 없다고 말하는 것이 정답입니다. 요양보호사는 부당한 요구를 거절해야 합니다.", "3": "면제해주고 서비스 시간을 줄이는 것은 합법적이지 않으며, 고객의 요구를 잘못 수용하는 것입니다.", "4": "수수료를 받고 면제받을 수 있도록 해주는 것은 명백한 불법행위입니다.", "5": "면제받을 수 있는 다른 기관을 소개해주는 것도 합법적인 방법이 아닙니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "수혜자(한국어)", "def_vi": "Người nhận dịch vụ chăm sóc (베트남어)"}, {"term_ko": "본인부담금", "term_vi": "Chi phí cá nhân", "def_ko": "개인 부담금(한국어)", "def_vi": "Chi phí mà cá nhân phải chi trả(베트남어)"}, {"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "보건 의료 종사자(한국어)", "def_vi": "Người làm trong lĩnh vực chăm sóc sức khỏe (베트남어)"}, {"term_ko": "불법", "term_vi": "Bất hợp pháp", "def_ko": "법에 어긋나는 것(한국어)", "def_vi": "Không đúng theo pháp luật (베트남어)"}, {"term_ko": "면제", "term_vi": "Miễn phí", "def_ko": "면책(한국어)", "def_vi": "Miễn trừ phí tổn (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (807, '4', '시설에서 목욕서비스를 제공하던 중 대상자가 갑자기 가슴을 만지는 경우 대처방법은?', '["화를 내며 목욕을 중단한다.", "대상자에게 정신적 피해보상을 요구한다.", "단호히 거부하고 대상자의 가족과 시설장에게 알리겠다고 말한다.", "대상자의 사생활 보호를 위해 비밀로 한다.", "치매라서 그러는 거라ㅗ 이해하며 넘어간다."]'::jsonb, 3, '대상자가 목욕 중에 부적절한 행동을 했을 때, 적절한 대처 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "화를 내며 목욕을 중단하는 것은 상황을 악화시킬 수 있습니다.\n[정답]", "3": "단호히 거부하고 대상자의 가족과 시설장에게 알리겠다고 말하는 것이 적절한 대처 방법입니다.", "2": "정신적 피해 보상을 요구하는 것은 적절하지 않습니다.", "4": "비밀로 하는 것은 대상자의 권리를 침해할 우려가 있습니다.", "5": "이해한다는 태도는 문제의 심각성을 간과하는 것입니다."}'::jsonb, '[{"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "씻는 일", "def_vi": "Hoạt động rửa sạch"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (806, '4', '시설에서 대상자가 넘어져 쓰러졌을 때 먼저 해야 할 것으로 옳은 것은?', '["보호자에게 연락한다.", "동료 요양보호사에게 연락한다.", "시설장에게 보고한다.", "침대로 옮긴 후 안정을 시킨다.", "병원으로 이송시킨다."]'::jsonb, 3, '대상자가 넘어졌을 때 올바른 대처 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "보호자에게 연락하는 것은 나중에 해야 하는 일입니다.\n[정답]", "3": "시설장에게 보고하는 것이 가장 먼저 해야 할 일입니다.", "2": "동료 요양보호사에게 연락하는 것도 중요하지만 우선적으로 시설장에게 보고해야 합니다.", "4": "침대로 옮기는 것은 상황에 따라 다를 수 있으므로 먼저 보고가 필요합니다.", "5": "병원으로 이송하는 것은 상황이 심각할 경우에 필요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (805, '4', '다음 사례에서 요양보호사가 지키지 못한 직업적 태도는?대상자 딸: "엄마, 요양보호사 선생님 어디 가셨어요?" 대상자: "점심밥 차려주고 잠깐만 나갔다 온다 했은데, 나간 지 한시간이 됐는데 안 오네..."', '["대상자의 권리를 보호한다.", "대상자의 상태 변화를 세심하게 관찰한다.", "요양보호 업무 중 근무지를 비우지 않는다.", "요양보호사의 판단만으로 서비스를 제공하지 않는다.", "성실한 태도로 책임감을 갖고 업무 활동을 한다."]'::jsonb, 3, '요양보호사가 수행해야 할 직업적 태도와 책임감에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "대상자의 권리를 보호하는 것은 요양보호사가 반드시 지켜야 하는 태도입니다.", "2": "대상자의 상태 변화를 세심하게 관찰하는 것은 중요한 업무입니다.\n[정답]", "3": "요양보호 업무 중 근무지를 비우지 않는 것은 기본적인 직업 태도로서, 규정을 지키지 않은 경우입니다.", "4": "요양보호사의 판단만으로 서비스를 제공하지 않는 것은 적절한 태도입니다.", "5": "성실한 태도로 책임감을 갖고 업무 활동을 하는 것은 필수적입니다."}'::jsonb, '[{"term_ko": "직업적 태도", "term_vi": "Thái độ nghề nghiệp", "def_ko": "직업적으로 가져야 할 자세", "def_vi": "Thái độ cần có trong công việc"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "돌봄을 받는 사람", "def_vi": "Người nhận chăm sóc"}, {"term_ko": "상태 변화", "term_vi": "Sự thay đổi tình trạng", "def_ko": "상태의 변화", "def_vi": "Sự thay đổi về tình trạng sức khỏe"}, {"term_ko": "근무지", "term_vi": "Nơi làm việc", "def_ko": "근무하는 장소", "def_vi": "Địa điểm làm việc"}, {"term_ko": "판단", "term_vi": "Phán đoán", "def_ko": "결정 내리기", "def_vi": "Ra quyết định"}, {"term_ko": "책임감", "term_vi": "Cảm giác trách nhiệm", "def_ko": "책임 의식", "def_vi": "Ý thức về bổn phận"}, {"term_ko": "성실", "term_vi": "Chân thành", "def_ko": "진정성 있는 태도", "def_vi": "Thái độ chân thành"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (804, '4', '요양보호사의 윤리적 태도로 올바른 것은?', '["사고발생 시 즉시 시설장 및 관리책임자에게 보고한다.", "대상자의 비밀은 필요 시에만 보호한다.", "서비스 내용이 확실하지 않을 시 기록을 뺀다.", "대상자가 학대받는 상황에는 관여하지 않는다.", "서비스 시간 변경 요청 시 조정할 수 없다고 말한다."]'::jsonb, 1, '요양보호사의 윤리적 태도에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "사고발생 시 즉시 시설장 및 관리책임자에게 보고한다. [정답] 사고 발생 시 즉시 보고하는 것은 윤리적 책임을 다하는 것입니다.", "2": "대상자의 비밀은 필요 시에만 보호한다. 비밀 보호는 항상 중요합니다.", "3": "서비스 내용이 확실하지 않을 시 기록을 뺀다. 정확한 기록이 중요하며, 빼는 것은 잘못된 행동입니다.", "4": "대상자가 학대받는 상황에는 관여하지 않는다. 학대 상황에 대해 관여해야 하는 의무가 있습니다.", "5": "서비스 시간 변경 요청 시 조정할 수 없다고 말한다. 상황에 따라 조정할 수 있어야 합니다."}'::jsonb, '[{"term_ko": "윤리적 태도", "term_vi": "Thái độ đạo đức", "def_ko": "도덕적 관점에서의 행동 방식", "def_vi": "Cách cư xử từ quan điểm đạo đức"}, {"term_ko": "보고하다", "term_vi": "Báo cáo", "def_ko": "알리다", "def_vi": "Thông báo"}, {"term_ko": "비밀", "term_vi": "Bí mật", "def_ko": "은밀한 정보", "def_vi": "Thông tin kín"}, {"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "폭행 혹은 일부러 해치다", "def_vi": "Hành vi bạo lực hoặc cố ý làm hại"}, {"term_ko": "조정하다", "term_vi": "Điều chỉnh", "def_ko": "배치 또는 수정하다", "def_vi": "Sắp xếp hoặc sửa đổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (803, '4', '요양보호 업무 중 법적 소송에 휘말리지 않기 위한 방법으로 옳은 것은?', '["서비스내용과 방법이 확실하지 않으면 상식선에서 판단한다.", "서비스계획 수립 시 대상자의 요구는 배제한다.", "대상자의 상태 변화를 세심하게 관찰하여 기록한다.", "시설장이나 간호사에게 보고한 내용은 따로 기록하지 않는다.", "대상자가 학대 받고 있다고 의심되면 동료와 의논하여 해결한다."]'::jsonb, 3, '법적 소송에 휘말리지 않기 위한 요양보호사의 적절한 업무 수행 방법을 묻는 문제입니다.', NULL, '{"1": "서비스의 내용을 확실히 하지 않으면 상식적으로 판단하는 것은 올바른 방법이 아닙니다.\n[정답]", "3": "대상자의 상태 변화를 세심하게 관찰하고 기록하는 것은 법적 문제를 예방하는 중요한 방법입니다.", "2": "서비스 계획에 대상자의 요구를 배제하는 것은 바람직하지 않습니다.", "4": "보고한 내용은 별도로 기록해야 법적 소송에 대비할 수 있습니다.", "5": "학대 의심 시, 동료와 의논하는 것은 필요하지만 반드시 보고하고 기록해야 합니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "업무", "def_ko": "돌보는 것 (chăm sóc)", "def_vi": "일 (công việc)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (802, '4', '법적, 윤리적 태도를 위한 요양보호사의 태도로 옳은 것은?', '["장기요양등급을 받을 수 있도록 유인한다.", "서비스 제공은 정해진 원칙과 절차에 따른다.", "제공된 요양보호서비스는 중요한 내용만 기록한다.", "서비스 제공 시 대상자의 자기결정권을 제한한다.", "사고발생 시 대상자의 보호를 위해 발설하지 않는다."]'::jsonb, 2, '법적, 윤리적 태도가 요구되는 요양보호사의 역할을 이해하고, 옳은 태도를 찾기 위한 문제이다.', NULL, '{"1": "장기요양등급을 받을 수 있도록 유인하는 것은 윤리적으로 바람직하지 않다.\n[정답]", "2": "서비스 제공은 정해진 원칙과 절차에 따라 이루어져야 한다.", "3": "제공된 요양보호서비스는 모든 중요한 내용을 기록해야 한다.", "4": "서비스 제공 시 대상자의 자기결정권은 존중되어야 하며 제한되어서는 안 된다.", "5": "사고 발생 시 대상자의 보호를 위해서도 정보를 공유해야 할 필요가 있다."}'::jsonb, '[{"term_ko": "법적", "term_vi": "윤리적", "def_ko": "법(luật)", "def_vi": "đạo đức(đạo đức)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (801, '4', '요양보호사가 갖추어야 할 직업윤리로 옳은 것은?', '["서비스 내용과 방법은 요양보호사가 결정한다.", "대상자 개인의 선호보다 기관의 지침을 중시한다.", "대상자의 신체, 정신적 변화가 있을 경우 즉시 보고한다.", "업무수행 상 발생한 문제는 요양보호사 스스로 판단하여 해결한다.", "노인학대가 확실한 경우에만 보고한다."]'::jsonb, 3, '요양보호사가 갖추어야 할 직업윤리에 대한 이해를 점검하고자 하는 문제입니다.', NULL, '{"1": "서비스 내용과 방법은 요양보호사가 결정하는 것이 아니라, 대상자와의 상의 후 결정해야 합니다.", "2": "기관의 지침도 중요하지만, 대상자의 개인적인 선호와 욕구가 더 우선해야 합니다.\n[정답]", "3": "대상자의 신체 및 정신적 변화는 즉시 보고해야 하며, 이는 필수적인 직업윤리입니다.", "4": "업무수행 중 발생한 문제는 팀원과 함께 해결해야 하며, 요양보호사 혼자 판단해서는 안 됩니다.", "5": "노인학대는 항상 보고해야 하며, 확실한 경우에만 제한해서 보고하는 것이 아닙니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업에서 지켜야 할 도리(한국어)", "def_vi": "Những nguyên tắc cần tuân thủ trong công việc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (800, '4', '요양보호사의 윤리적 태도로 옳은 것은?', '["대상자와 같은 종교를 믿으면 더욱 친절하게 대한다.", "업무에 협조하지 않을 경우 서비스를 종결한다.", "서비스 중 급한 용무는 대상자에게 양해를 구하고 다녀온다.", "제공 된 요양보호 서비스 내용을 정확히 기록한다.", "대상자에게 복지용구를 대여하거나 구입을 권유한다."]'::jsonb, 4, '요양보호사는 윤리적 태도로 서비스 제공 중 업무 태도를 평가하고자 하는 의도를 가지고 있습니다.', NULL, '{"1": "대상자와 같은 종교를 믿는 것이 윤리적 태도와는 무관하여 잘못된 행동입니다.\n[정답]", "4": "제공 된 요양보호 서비스 내용을 정확히 기록하는 것은 윤리적이며 필수적인 태도입니다.", "2": "업무에 협조하지 않을 경우 서비스를 종결하는 것은 비윤리적인 행위로 간주될 수 있습니다.", "3": "서비스 중 급한 용무는 대상자에게 양해를 구하고 다녀오는 것은 좋지만, 우선적으로 서비스의 연속성을 고려해야 합니다.", "5": "대상자에게 복지용구를 대여하거나 구입을 권유하는 것은 직무 범위를 벗어날 수 있습니다."}'::jsonb, '[{"term_ko": "윤리적", "term_vi": "Đạo đức", "def_ko": "도덕적으로 올바른 것", "def_vi": "Điều đúng về mặt đạo đức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (799, '4', '대상자의 가족이 본인부담금 할인을 요구할 때 대처방법은?', '["기관장에게 알리고 본인부담금을 할인해 준다.", "비용 감면 대신 서비스 시간을 늘려 준다.", "본인부담금을 먼저 받고 나중에 일정액을 돌려 준다.", "다른 대상자를 소개해 주면 할인해 준다고 말한다.", "노인장기요양보험법 위반으로 불법이라고 명확하게 말한다."]'::jsonb, 5, '대상자의 가족이 본인부담금 할인 요구에 대한 적절한 대처 방안을 묻는 문제이다.', NULL, '{"1": "기관장에게 알리고 본인부담금을 할인해 준다: 기관장은 본인부담금을 할인할 권한이 없으므로 잘못된 대처다.\n[정답]", "5": "노인장기요양보험법 위반으로 불법이라고 명확하게 말한다: 법적 근거에 따라 명확하게 설명해 주는 것이 올바른 대처법이다.", "2": "비용 감면 대신 서비스 시간을 늘려 준다: 서비스의 양과 질을 바꾸는 것은 적절한 해결이 아니다.", "3": "본인부담금을 먼저 받고 나중에 일정액을 돌려 준다: 이런 방식은 불법적이므로 적절하지 않다.", "4": "다른 대상자를 소개해 주면 할인해 준다고 말한다: 이는 비윤리적인 행위이며 허용되지 않는다."}'::jsonb, '[{"term_ko": "본인부담금", "term_vi": "Tiền đồng góp", "def_ko": "본인이 부담해야 하는 비용", "def_vi": "Số tiền mà người bệnh phải chi trả"}, {"term_ko": "할인", "term_vi": "Giảm giá", "def_ko": "금액을 줄이는 것", "def_vi": "Cắt giảm số tiền"}, {"term_ko": "법", "term_vi": "Luật", "def_ko": "규칙이나 규정을 정하는 것", "def_vi": "Quy tắc hoặc quy định"}, {"term_ko": "위반", "term_vi": "Vi phạm", "def_ko": "규칙을 어기는 것", "def_vi": "Vi phạm quy tắc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (798, '4', '대상자가 수고했다며 돈 봉투를 주려고 할 때 올바른 대처방법은?', '["\"돈은 받으면 안 돼요. 마음만 받을게요.\"", "\"저를 어떻게 보고 이런 행동을 하시는 거예요.\"", "\"제가 갖고 있다가 다음에 음료수 사다 드릴게요.\"", "\"마침 센터에 부족한 물건이 있었는데 이걸로 살게요.\"", "\"감사합니다.\"라고 받고 다음 날 대상자에게 돌려준다."]'::jsonb, 1, '대상자와의 관계를 유지하고 윤리적 기준을 지키는 상황에서의 올바른 대처 방법을 묻는 문제입니다.', NULL, '{"1": "대상자가 제안한 금전적인 선물을 받지 않고 마음만 받겠다고 표현함으로써 윤리적 기준을 지키는 올바른 대처입니다.\n[정답]", "2": "부정적인 반응을 보이는 것으로, 상대방의 감정을 상하게 할 수 있습니다.", "3": "돈을 일시적으로 보류하겠다는 제안은 윤리적으로 바람직하지 않습니다.", "4": "부적절한 상황에서 금전을 사용하겠다는 것은 전문가로서의 태도가 아닙니다.", "5": "금전을 받고 나중에 돌려주는 것은 올바른 대처가 아닙니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "도움을 받는 사람", "def_vi": "Người nhận sự giúp đỡ"}, {"term_ko": "버튼", "term_vi": "Cách đúng", "def_ko": "맞는 방법", "def_vi": "Phương pháp đúng"}, {"term_ko": "윤리적", "term_vi": "Đạo đức", "def_ko": "도덕적인", "def_vi": "Có liên quan đến đạo đức"}, {"term_ko": "금전", "term_vi": "Tiền tệ", "def_ko": "돈", "def_vi": "Tiền"}, {"term_ko": "선물", "term_vi": "Quà tặng", "def_ko": "주는 것", "def_vi": "Món tặng"}, {"term_ko": "대처", "term_vi": "Đối phó", "def_ko": "대응하다", "def_vi": "Phản ứng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (797, '4', '요양보호사가 법적, 윤리적 책임을 다하기 위해 지켜야 할 사항으로 옳은 것은?', '["대상자의 복지용구를 저렴한 비용으로 구입해 준다.", "서비스 방법이 확실하지 않을 때는 동료와 의논한다.", "사고 발생 시에는 보호자에게 비밀로 한다.", "서비스 시간 변경을 요청할 때에는 관리책임자에게 보고한다.", "대상자의 질병 악화가 판단될 때에는 입원시킨다."]'::jsonb, 4, '요양보호사가 법적, 윤리적 책임을 다하기 위해 지켜야 할 사항을 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "대상자의 복지용구를 저렴한 비용으로 구입해 주는 것이 법적 책임을 다하는 방법이 아니다.\n[정답]", "2": "서비스 방법이 확실하지 않을 때는 동료와 의논하는 것은 법적, 윤리적 책임을 다하는 방법이다.", "3": "사고 발생 시 보호자에게 비밀로 하는 것은 윤리적으로 올바르지 않다.", "4": "서비스 시간 변경을 요청할 때 관리책임자에게 보고하는 것은 필수적인 절차이다.", "5": "대상자의 질병 악화가 판단될 때 입원시키는 것은 의료 전문가의 판단이 필요하다."}'::jsonb, '[{"term_ko": "법적", "term_vi": "Pháp lý", "def_ko": "법률에 관한", "def_vi": "Liên quan đến pháp luật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (796, '4', '다음 중 요양보호사의 올바른 윤리적 태도는?', '["방문 시 대상자가 없으면 기관에 연락하여 확인한다.", "방문 시 대상자가 없으면 바로 귀가한다.", "추가 서비스를 요구할 때는 요양보호사가 임의대로 들어준다.", "사정이 어려운 대상자의 본인부담금을 할인해 준다.", "다른 요양보호사에게 자신의 근무를 대신 요구한다."]'::jsonb, 1, '요양보호사가 준수해야 할 윤리적 원칙과 태도를 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "올바른 윤리적 태도로, 대상자가 없을 때 기관에 확인하는 것은 책임감 있는 행동입니다.\n[정답]", "2": "대상을 확인하지 않고 귀가하는 것은 비윤리적입니다.", "3": "요양보호사는 임의로 추가 서비스를 제공할 수 없습니다. 이는 윤리에 어긋나는 행동입니다.", "4": "대상자의 본인부담금을 임의로 할인하는 것은 적절하지 않습니다.", "5": "자신의 근무를 다른 사람에게 부탁하는 것은 전문성을 저하할 수 있습니다."}'::jsonb, '[{"term_ko": "윤리적", "term_vi": "Đạo đức", "def_ko": "도덕적 원칙에 따른", "def_vi": "Theo nguyên tắc đạo đức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (795, '4', '대상자와 상호신뢰를 형성할 수 있는 요양보호사의 윤리적 태도는?', '["상황에 맞게 적당한 신체접촉을 한다.", "친근하게 반말을 사용한다.", "대상자를 내려다보면서 시선을 맞춘다.", "추가서비스는 요양보호사가 별도로 계약을 한다.", "방문 시 대상자가 없으면 가사 일을 하면서 기다린다."]'::jsonb, 1, '대상자와의 신뢰 관계를 형성하기 위한 요양보호사의 태도를 평가하는 문제입니다.', NULL, '{"1": "상황에 맞게 적당한 신체접촉을 한다. - 요양보호사와 대상자 간의 신뢰를 형성하는 데 중요한 요소입니다.\n[정답]", "2": "친근하게 반말을 사용한다. - 반말 사용은 상황에 따라 부적절할 수 있어 신뢰를 저해할 수 있습니다.", "3": "대상자를 내려다보면서 시선을 맞춘다. - 내려다보는 것은 대인 관계에서 부정적인 인상을 줄 수 있습니다.", "4": "추가서비스는 요양보호사가 별도로 계약을 한다. - 정식 계약 없이 제공되는 서비스는 신뢰를 떨어뜨릴 수 있습니다.", "5": "방문 시 대상자가 없으면 가사 일을 하면서 기다린다. - 대상자의 공간을 존중하는 태도가 필요합니다."}'::jsonb, '[{"term_ko": "상호신뢰", "term_vi": "Niềm tin lẫn nhau", "def_ko": "서로 믿고 의지하는 것", "def_vi": "Sự tin tưởng và dựa vào nhau"}, {"term_ko": "윤리적 태도", "term_vi": "Thái độ đạo đức", "def_ko": "도덕적으로 바람직한 행동", "def_vi": "Hành động đúng đắn về mặt đạo đức"}, {"term_ko": "신체접촉", "term_vi": "Tiếp xúc cơ thể", "def_ko": "몸을 직접 만지는 행동", "def_vi": "Hành động chạm vào cơ thể"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "요양 서비스를 받는 사람", "def_vi": "Người nhận dịch vụ chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (794, '4', '요양보호사의 윤리적 태도로 옳은 것은?', '["서비스 제공 시 시설장의 의사결정을 우선한다.", "타 직종과의 협력보다 업무의 신속성을 중시한다.", "보수교육을 통해 전문적 지식과 기술을 연마한다.", "대상자의 등급에 따라 서비스할 대상자를 선택한다.", "대상자가 실수하면 질책하여 재발을 방지한다."]'::jsonb, 3, '요양보호사의 윤리적 태도를 이해하고, 올바른 행동 기준을 알고 있는지를 평가하기 위함입니다.', NULL, '{"1": "서비스 제공 시 시설장의 의사결정을 우선하는 것은 윤리적으로 바람직하지 않습니다.\n[정답]", "3": "보수교육을 통해 전문적 지식과 기술을 연마하는 것은 윤리적 태도의 중요한 부분입니다.", "2": "타 직종과의 협력보다 업무의 신속성을 중시하는 것은 비윤리적입니다.", "4": "대상자의 등급에 따라 서비스할 대상을 선택하는 것은 윤리적이지 않습니다.", "5": "대상자가 실수하면 질책하는 것은 비윤리적이며, 올바른 교육과 지원이 필요합니다."}'::jsonb, '[{"term_ko": "윤리적", "term_vi": "Đạo đức", "def_ko": "도덕과 관련된", "def_vi": "Liên quan đến đạo đức"}, {"term_ko": "전문적", "term_vi": "Chuyên môn", "def_ko": "전문적인, 전문화된", "def_vi": "Chuyên nghiệp, chuyên sâu"}, {"term_ko": "보수교육", "term_vi": "Đào tạo lại", "def_ko": "재교육을 받는 과정", "def_vi": "Quá trình học lại"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스를 받을 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "질책", "term_vi": "Khiển trách", "def_ko": "비난이나 타박을 하는 것", "def_vi": "Hành động chỉ trích hoặc chê trách"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (793, '4', '다음 설명에 해당하는 요양보호사의 윤리적 태도는?• 직무수행 시 필요한 전문적 지식과 기술을 습득한다. • 교육훈련 프로그램에 적극적으로 참여한다.', '["겸손한 태도", "상호 협조적인 태도", "자기를 계발하려는 태도", "친절하고 예의바른 태도", "인격체를 존중하는 태도"]'::jsonb, 3, '요양보호사로서의 윤리적 태도를 이해하고, 관련된 태도를 선택하도록 유도하는 문제입니다.', NULL, '{"1": "겸손한 태도: 겸손함은 중요하지만, 전문적 지식 습득과 관련이 없습니다.\n[정답]", "3": "자기를 계발하려는 태도: 전문적 지식과 기술 습득, 교육 훈련 참여의 핵심을 나타냅니다.", "2": "상호 협조적인 태도: 협력은 중요하지만, 자아 개발과는 다소 차이 있습니다.", "4": "친절하고 예의바른 태도: 인간관계에서 중요한 요소지만, 직무수행에 초점을 맞춘 태도가 아닙니다.", "5": "인격체를 존중하는 태도: 존중은 중요하나, 여기서는 전문성 개발과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "윤리적", "term_vi": "태도", "def_ko": "도덕적, đạo đức", "def_vi": "태도, thái độ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (792, '4', '방문요양서비스를 제공하는 요양보호사의 윤리적 태도로 옳은 것은?', '["대상자의 권리를 지켜주고 존중한다.", "요양보호사의 편의를 위해 일회용 제품을 사용한다.", "대상자가 없어도 방에 들어가서 요양보호사의 할 일을 하고 나온다.", "서비스 우선순위를 요양보호사가 주관적으로 결정한다.", "대상자의 욕구보다 요양보호사의 편의를 중시한다."]'::jsonb, 1, '방문요양서비스를 제공하는 요양보호사로서의 윤리적 태도를 이해하고 평가하는 것.', NULL, '{"1": "대상자의 권리를 지켜주고 존중하는 것은 윤리적 태도로 반드시 필요한 자세입니다.\n[정답]", "2": "요양보호사의 편리를 위해 일회용 제품을 사용하는 것은 윤리적이지 않습니다.", "3": "대상자가 없어도 방에 들어가는 것은 개인의 사생활을 침해할 수 있으므로 부적절합니다.", "4": "서비스 우선순위를 주관적으로 결정하는 것은 윤리적 기준을 어기는 행동입니다.", "5": "대상자의 욕구보다 요양보호사의 편의를 중시하는 것은 부적절한 태도입니다."}'::jsonb, '[{"term_ko": "방문요양서비스", "term_vi": "Dịch vụ chăm sóc tại nhà", "def_ko": "집에 가서 지원하는 요양 서비스", "def_vi": "Dịch vụ hỗ trợ tại nhà"}, {"term_ko": "윤리적", "term_vi": "Đạo đức", "def_ko": "도덕적 원칙과 기준에 따른", "def_vi": "Theo nguyên tắc và tiêu chuẩn đạo đức"}, {"term_ko": "대상자", "term_vi": "Người nhận trợ giúp", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "편리", "term_vi": "Tiện lợi", "def_ko": "불편함이 없는 상태", "def_vi": "Trạng thái không có phiền phức"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "필요한 바람", "def_vi": "Mong muốn cần thiết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (791, '4', '시설에서 동료 요양보호사가 무의식 상태인 대상자를 때리는 것을 보았을 때 요양보호사의 올바른 행동은?', '["동료 요양보호사에게 주의를 준다.", "그냥 모른 척 넘어간다.", "보호자에게 알린다.", "시설정이나 간호사에게 즉시 보고한다.", "동료 요양보호사에게 대상자의 상태를 이해시킨다."]'::jsonb, 4, '무의식 상태인 대상자에 대한 적절한 대처를 묻는 질문입니다. 동료 요양보호사가 부적절한 행동을 할 때, 요양보호사는 이를 신속하게 보고하여 문제를 해결해야 합니다.', NULL, '{"1": "동료 요양보호사에게 주의를 줄 경우, 상황이 개선되지 않을 수 있으며, 대상자에게 더 큰 위험을 초래할 수 있습니다.\n[정답]", "4": "시설장이나 간호사에게 즉시 보고해야 합니다. 이는 대상자의 안전을 최우선으로 해야 하는 요양보호사의 의무입니다.", "3": "보호자에게 알린다고 해도 즉각적인 조치가 아니며, 보고가 늦어질 수 있습니다.", "2": "그냥 모른 척 넘어가는 것은 결코 용납될 수 없는 행동입니다.", "5": "동료에게 이해시킨다고 해서 문제의 행동이 멈출 것이라는 보장이 없습니다."}'::jsonb, '[{"term_ko": "무의식 상태", "term_vi": "Trạng thái không nhận thức", "def_ko": "의식이 없는 상태", "def_vi": "Tình trạng không có ý thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (789, '4', '다음의 사례에서 요양보호사의 대처 방법으로 옳은 것은?요양보호사 김씨는 장기요양 2등급을 받은 할머니에게 요양서비스를 제공하고 있었다. 그러던 중 배우자인 할아버지가 치매 진단을 받고 장기요양 3등급을 받게 되었다. 보호자가 오전에는 할머니를 돌봐주고 오후에는 할아버지를 돌봐달라고 요청했다.', '["다른 요양보호사를 소개시켜 준다.", "남자분은 불편하다고 정중히 거절한다.", "조용히 서비스를 중단한다.", "서비스료를 추가로 받는다.", "시설장에게 보고한다."]'::jsonb, 5, '요양보호사가 가족 구성원의 변화에 적절히 대처하는 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "다른 요양보호사를 소개시켜 준다. - 이는 전문적이지 않은 대처로 적절하지 않습니다.\n[정답]", "5": "시설장에게 보고한다. - 상황 변화를 정확하게 전달하고 지침을 받는 것이 중요합니다.", "3": "조용히 서비스를 중단한다. - 이는 고객에게 불편을 주고 다른 문제를 초래할 수 있습니다.", "4": "서비스료를 추가로 받는다. - 서비스 제공자와 고객 간의 신뢰를 상실할 수 있는 행동입니다.", "2": "남자분은 불편하다고 정중히 거절한다. - 이는 상황을 해결하는 방법이 아닙니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌봄 제공자", "def_vi": "Người cung cấp dịch vụ chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (788, '4', '다음 중 요양보호사의 직업윤리 원칙으로 올바른 것은?', '["대상자에게 복지용구 구매를 알선한다.", "대상자의 요구 시 별도의 서비스 계약을 한다.", "대상자의 요청이 있으면 타 기관에 의뢰한다.", "요양보호사와 대상자가 대등한 관계임을 인식한다.", "대상자의 권리보다는 시설의 운영 규칙을 우선시 한다."]'::jsonb, 4, '요양보호사의 직업윤리에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "복지용구 구매를 알선하는 것은 직업윤리에 어긋납니다.\n[정답]", "4": "요양보호사와 대상자는 대등한 관계임을 인식해야 합니다.", "2": "별도의 서비스 계약은 요양보호사의 윤리에 맞지 않습니다.", "3": "타 기관에 의뢰하는 것은 필요할 수 있지만, 윤리적 기준에 따라야 합니다.", "5": "대상자의 권리는 항상 우선시 되어야 하므로 잘못된 내용입니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업에서 지켜야 할 윤리적 원칙", "def_vi": "Nguyên tắc đạo đức cần tuân theo trong nghề"}, {"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "요양 서비스를 받는 사람", "def_vi": "Người nhận dịch vụ chăm sóc"}, {"term_ko": "복지용구", "term_vi": "Dụng cụ hỗ trợ", "def_ko": "복지 서비스를 위한 도구", "def_vi": "Công cụ cho dịch vụ phúc lợi"}, {"term_ko": "서비스 계약", "term_vi": "Hợp đồng dịch vụ", "def_ko": "제공되는 서비스에 대한 계약", "def_vi": "Hợp đồng cho dịch vụ được cung cấp"}, {"term_ko": "대등한 관계", "term_vi": "Quan hệ bình đẳng", "def_ko": "평등한 관계", "def_vi": "Mối quan hệ bình đẳng"}, {"term_ko": "운영 규칙", "term_vi": "Quy tắc hoạt động", "def_ko": "시설의 규칙", "def_vi": "Quy tắc của cơ sở"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (787, '4', '시설에서 요양보호사가 지켜야 할 직업윤리는?', '["대상자의 질병상태를 외부로 발설한다.", "지시 받지 않은 서비스는 경험에 따라 제공한다.", "서비스 제공 시 발생한 사고는 보고하지 않는다.", "업무와 관련하여 대상자의 가족, 의사, 간호사 등과 협력한다.", "법적인 소송에 휘말리지 않기 위해 신체접촉은 하지 않는다."]'::jsonb, 4, '요양보호사가 직업윤리와 관련하여 지켜야 할 중요한 내용에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "대상자의 질병상태를 외부로 발설하는 것은 개인정보 보호와 직업윤리에 위배됩니다.\n[정답]", "4": "업무와 관련하여 대상자의 가족, 의사, 간호사 등과 협력하는 것은 매우 중요하며, 직업윤리를 잘 지키는 행동입니다.", "2": "지시 받지 않은 서비스를 임의로 제공하는 것은 위험할 수 있으며, 윤리에 어긋납니다.", "3": "서비스 제공 시 발생한 사고는 반드시 보고해야 하며, 보고하지 않는 것은 직업 윤리에 반합니다.", "5": "법적인 소송을 피하기 위해서만 신체 접촉을 하지 않는 것은 직업 윤리의 본질을 이해하지 못한 것입니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "윤리 trong nghề nghiệp", "def_vi": "Đạo đức trong công việc"}, {"term_ko": "대상자", "term_vi": "Người dùng", "def_ko": "서비스 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "협력", "term_vi": "Hợp tác", "def_ko": "함께 일하다", "def_vi": "Làm việc cùng nhau"}, {"term_ko": "보고", "term_vi": "Báo cáo", "def_ko": "정보를 전달하다", "def_vi": "Truyền đạt thông tin"}, {"term_ko": "신체접촉", "term_vi": "Tiếp xúc cơ thể", "def_ko": "몸을 접촉하다", "def_vi": "Chạm vào cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (786, '4', '요양보호사의 직업윤리로 옳은 것은?', '["기관장으 지시는 선택하여 따른다.", "대상자의 자기결정을 최대한 존중한다.", "대상자의 개인정보를 동료 요양보호사와 공유한다.", "장기요양 1등급 대상자는 서비스 대상에서 제외한다.", "서비스제공기록지에 대상자와 보호자에게 제공한 내용을 기록한다."]'::jsonb, 2, '요양보호사의 직업윤리에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "기관장의 지시는 반드시 따라야 되는 것은 아니므로 옳지 않은 답변입니다.\n[정답]", "2": "요양보호사는 대상자의 자기결정을 최대한 존중해야 하므로 옳은 사항입니다.", "3": "대상자의 개인정보는 비밀이므로 동료와 공유하는 것은 옳지 않습니다.", "4": "서비스 제공의 기준에 따라 장기요양 1등급 대상자도 서비스의 대상이 될 수 있습니다.", "5": "서비스제공기록지는 반드시 기록해야 하지만, 내용이 아닌 다른 요소를 강조해야 하므로 완전한 답변이 아닙니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업에서 지켜야 할 윤리적 기준", "def_vi": "tiêu chuẩn đạo đức cần tuân thủ trong nghề nghiệp"}, {"term_ko": "자기결정", "term_vi": "Quyết định bản thân", "def_ko": "스스로 결정을 내리는 것", "def_vi": "tự mình đưa ra quyết định"}, {"term_ko": "개인정보", "term_vi": "Thông tin cá nhân", "def_ko": "개인의 사적인 정보", "def_vi": "thông tin riêng tư của cá nhân"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "도움을 주는 행위", "def_vi": "hành động giúp đỡ"}, {"term_ko": "기록지", "term_vi": "Sổ ghi chép", "def_ko": "사건이나 내용이 정리된 문서", "def_vi": "tài liệu ghi lại sự kiện hoặc nội dung"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (785, '4', '시설에서 요양보호사가 지켜야 할 직업윤리 원칙은?', '["대상자와 수직적인 관계를 강조한다.", "자신의 종교를 권유하기 위해 더 잘해준다.", "대상자의 방은 경제수준에 따라 배정한다.", "대상자보다 가족의 의견을 우선으로 반영한다.", "업무수행을 위해 복장 및 외모관리, 건강관리를 철저히 한다."]'::jsonb, 5, '요양보호사 직업윤리에 대해 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "대상자와 수직적인 관계를 강조하는 것은 직업윤리에 반하는 내용입니다.\n[정답]", "5": "업무수행을 위해 복장 및 외모관리, 건강관리를 철저히 하는 것은 직업윤리에 부합합니다.", "2": "자신의 종교를 권유하기 위해 더 잘해주는 것은 윤리적이지 않습니다.", "3": "대상자의 방을 경제수준에 따라 배정하는 것은 편견을 포함한 차별입니다.", "4": "대상자보다 가족의 의견을 우선으로 반영하는 것은 대상자의 권리를 침해할 수 있습니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업에 관련된 도덕적 원칙", "def_vi": "nguyên tắc đạo đức liên quan đến nghề nghiệp"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "도움을 필요한 사람", "def_vi": "người cần giúp đỡ"}, {"term_ko": "복장", "term_vi": "Trang phục", "def_ko": "입는 옷", "def_vi": "trang phục"}, {"term_ko": "외모", "term_vi": "Ngoại hình", "def_ko": "사람의 모습", "def_vi": "diện mạo của con người"}, {"term_ko": "건강관리", "term_vi": "Quản lý sức khỏe", "def_ko": "건강을 유지하기 위한 관리", "def_vi": "việc duy trì sức khỏe"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (784, '4', '요양보호사의 직업윤리원칙을 바르게 설명한 것은?', '["요양보호사의 자기결정을 최대한 존중한다.", "업무상 알게 된 대상자의 개인정보는 비밀을 유지한다.", "대상자의 성별, 연령, 종교에 따라 차별 서비스한다.", "대상자와 개인적으로 별도의 서비스 계약을 한다.", "모든 서비스는 가족의 요구대로 수행한다."]'::jsonb, 2, '요양보호사의 윤리적 책임과 원칙에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "요양보호사는 자기결정을 존중해야 하지만, 보기에 제시된 내용은 그 자체로 맞다 볼 수 없습니다.\n[정답]", "2": "요양보호사는 업무상 알게 된 개인정보를 비밀로 유지해야 하는 윤리 원칙이 있습니다.", "3": "성별, 연령, 종교에 따라 차별적으로 서비스하는 것은 윤리적으로 옳지 않습니다.", "4": "요양보호사는 대상자와 개인적으로 서비스 계약을 맺지 않아야 합니다.", "5": "모든 서비스는 가족의 요구에 무조건적으로 따를 수 없으며, 대상자의 의사를 존중해야 합니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업에서 지켜야 할 도리", "def_vi": "Nghĩa vụ phải tuân thủ trong nghề nghiệp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (783, '4', '가정을 방문하여 목욕 서비스를 제공하던 중 대상자가 뒤에서 가슴을 만지는 경우 대처방법으로 옳은 것은?', '["\"이러시면 안됩니다.\"라고 단호하게 말한다.", "\"왜 이러세요.\"라고 화를 내며 나가 버린다.", "\"할머니가 생각나세요?\"라고 위로해 준다.", "\"제가 좋으세요?\"라고 말하며 웃어 넘긴다.", "\"비밀로 해 드릴게요\"하고 한번은 넘어간다."]'::jsonb, 1, '대상자의 부적절한 행동에 대해 요양보호사가 어떻게 대처해야 하는지를 묻는 문제입니다.', NULL, '{"1": "대상자의 행동에 대해 단호하게 거부의사를 표현하는 것은 필요한 조치입니다.\n[정답]", "2": "화를 내며 나가 버리는 것은 상황을 악화시킬 수 있습니다.", "3": "위로하는 것은 긍정적이지만 부적절한 행동을 받아들이는 것으로 해석될 수 있습니다.", "4": "웃어 넘기는 것은 행동을 용인하는 것으로 받아들여질 수 있습니다.", "5": "이성과 이 규범을 무시하는 행동이므로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "목욕하다(욕조나 물에서 씻다)", "def_vi": "Làm sạch bằng nước"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "치료나 돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "부적절", "term_vi": "Không phù hợp", "def_ko": "적합하지 않은, 적절하지 않은", "def_vi": "Không thích hợp, không đúng mực"}, {"term_ko": "행동", "term_vi": "Hành vi", "def_ko": "어떤 방식으로 행동하거나 반응하는 것", "def_vi": "Cách mà ai đó hành động hoặc phản ứng"}, {"term_ko": "거부", "term_vi": "Từ chối", "def_ko": "받아들이지 않거나 반대하는 것", "def_vi": "Không chấp nhận hoặc phản đối"}, {"term_ko": "위로", "term_vi": "An ủi", "def_ko": "슬퍼하거나 힘든 사람을 다독이는 것", "def_vi": "Động viên người đang buồn hoặc khó khăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (782, '4', '요양보호사가 대상자에게 성희롱을 당했을 때 장기요양기관장의 대처방법은?', '["대상자에게 서비스 중단 조치를 취한다.", "대상자에게 성희롱 예방교육을 2년에 1번 이상 실시한다.", "기관장의 판단에 따라 요양보호사를 다른 업무에 배치한다.", "요양보호사의 심리치료와 법적 대응에 대한 상담을 직접 실시한다.", "요양보호사가 성적 수치심을 느끼지 않도록 피해 사실을 묵인한다."]'::jsonb, 1, '요양보호사가 직장에서 성희롱을 당했을 때, 관리자에게 요구되는 적절한 대응 방안을 이해하는 것이다.', NULL, '{"1": "요양보호사가 성희롱을 당했을 경우, 즉각적으로 대처가 필요하며 서비스 중단 조치는 적절한 대안이다.\n[정답]", "2": "성희롱 예방교육은 중요하지만, 당장에 대처 방법으로는 적절하지 않다.", "3": "요양보호사가 다른 업무로 배치되는 것은 상황에 따라 다를 수 있지만, 최소한의 조치가 필요하다.", "4": "상담은 전문적으로 이루어져야 하므로, 기관장이 직접 실시하는 것은 바람직하지 않다.", "5": "피해 사실을 묵인하는 것은 절대로 수용할 수 없는 잘못된 대처다."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적 괴롭힘(한국어)", "def_vi": "Hành vi quấy rối về tình dục"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "서비스(한국어)", "def_vi": "Dịch vụ"}, {"term_ko": "기관장", "term_vi": "Giám đốc", "def_ko": "장의(한국어)", "def_vi": "Người đứng đầu"}, {"term_ko": "심리치료", "term_vi": "Liệu pháp tâm lý", "def_ko": "심리 치료(한국어)", "def_vi": "Điều trị tâm lý"}, {"term_ko": "법적 대응", "term_vi": "Phản ứng pháp lý", "def_ko": "법적 조치(한국어)", "def_vi": "Phản ứng theo quy định pháp luật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (781, '4', '성희롱에 대한 요양보호사의 대처방법으로 옳은 것은?', '["대상자의 가족에게 비밀로 한다.", "단호히 거의의사를 표현한다.", "대상자으 행동을 넓은 마음으로 이해한다.", "가족에게 시정해 줄 것을 요구하며 감정적인 대응을 한다.", "시정 요구에도 상습적으로 계속할 경우에는 경찰서에 고소한다."]'::jsonb, 2, '성희롱에 대한 올바른 대처 방법을 알고 있는지를 확인하기 위한 문제입니다.', NULL, '{"1": "대상자의 가족에게 비밀로 하는 것은 적절하지 않습니다. 성희롱은 심각한 문제이므로 알리는 것이 필요합니다.\n[정답]", "2": "단호히 의사를 표현하는 것이 필요합니다. 감정적으로 대처하기보다 명확하게 의사를 전달해야 합니다.", "3": "대상자의 행동을 넓은 마음으로 이해하는 것은 잘못된 접근입니다. 성희롱은 결코 용납되어서는 안됩니다.", "4": "가족에게 시정해 줄 것을 요구하며 감정적인 대응을 하는 것은 비효율적이며 문제를 악화시킬 수 있습니다.", "5": "시정 요구에도 상습적으로 계속할 경우 경찰에 고소하는 것은 마지막 수단이며, 우선적으로 의사를 단호하게 표현해야 합니다."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적인 행동이나 언어로 인한 괴롭힘", "def_vi": "Hành vi hoặc ngôn ngữ mang tính chất tình dục gây phiền phức"}, {"term_ko": "대처", "term_vi": "Xử lý", "def_ko": "문제에 대한 대응 방법", "def_vi": "Phương pháp ứng phó với vấn đề"}, {"term_ko": "아름다운", "term_vi": "Đẹp", "def_ko": "좋거나 긍정적인 것", "def_vi": "Điều tốt hoặc tích cực"}, {"term_ko": "경찰서", "term_vi": "Đồn cảnh sát", "def_ko": "범죄를 신고하는 곳", "def_vi": "Nơi để báo cáo tội phạm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (780, '4', '다음 중 육체적 성희롱에 해당하는 행위는?', '["음란한 농담을 하며 외모를 평가함", "옆에 앉아 술을 따르라고 함", "음란한 편지, 사진을 전송함", "자신의 특정 신체부위를 만짐", "옆에 앉으며 허리를 잡아 당김"]'::jsonb, 5, '육체적 성희롱을 이해하고 그 사례를 구분하는 능력을 평가하기 위함입니다.', NULL, '{"1": "음란한 농담을 하며 외모를 평가하는 것은 언어적 성희롱에 해당합니다.\n[정답]", "2": "옆에 앉아 술을 따르라고 하는 것은 상대방의 의사에 반하는 요구로 해석될 수 있지만, 육체적 성희롱으로 보기 어렵습니다.", "3": "음란한 편지, 사진을 전송하는 것도 언어적 성희롱에 해당합니다.", "4": "자신의 특정 신체부위를 만진 경우는 육체적 성희롱이 아닙니다.", "5": "옆에 앉으며 허리를 잡아 당기는 행위는 명백한 육체적 성희롱에 해당합니다."}'::jsonb, '[{"term_ko": "육체적", "term_vi": "Thể xác", "def_ko": "신체에 관련된", "def_vi": "Liên quan đến cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (779, '4', '대상자가 요양보호사에게 언어적 성희롱을 하는 행위는?', '["음란한 사진을 보여준다.", "가슴과 엉덩이를 만진다.", "성적 사실관계를 묻거나 성적인 정보를 유포한다.", "특정 신체부위를 고의적으로 노출한다.", "뒤에서 껴안으며 신체 접촉을 한다."]'::jsonb, 3, '대상자와 요양보호사 간의 신뢰 관계와 안전을 위해 성희롱의 유형을 이해하고 구분하는 것이 중요함.', NULL, '{"1": "음란한 사진을 보여주는 것은 성희롱의 일종이나, 언어적인 성희롱이 아님.", "2": "가슴과 엉덩이를 만지는 것은 신체적 성희롱으로 언어적 성희롱과는 다름.\n[정답]", "3": "성적 사실관계를 묻거나 성적인 정보를 유포하는 것은 언어적 성희롱의 명백한 예시임.", "4": "특정 신체부위를 고의적으로 노출하는 것은 신체적 성희롱으로 분류됨.", "5": "뒤에서 껴안으며 신체 접촉을 하는 것은 언어가 아닌 신체적 성희롱에 해당함."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적으로 불쾌감을 주는 언행", "def_vi": "Hành vi ngôn ngữ hoặc thể chất gây ra sự khó chịu về mặt tình dục"}, {"term_ko": "언어적", "term_vi": "Bằng lời", "def_ko": "말로 표현되는", "def_vi": "Biểu hiện bằng lời nói"}, {"term_ko": "신체적", "term_vi": "Cơ thể", "def_ko": "신체에 관련된", "def_vi": "Liên quan đến cơ thể"}, {"term_ko": "사실관계", "term_vi": "Thực tế", "def_ko": "사실의 관계나 상황", "def_vi": "Mối quan hệ hoặc tình huống của sự thật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (778, '4', '요양보호사에게 업무상 부상이나 질병이 발생했을 때, 산업재해보상보험봅의 보장 내용으로 옳은 것은?', '["보험급여는 양도, 압류할 수 있다.", "사업장이 부도, 폐업한 경우 지급받을 수 없다.", "시설장이 잘못이 없으면 급여가 지급되지 않는다.", "보험급여는 세금이 부과되지 않는다.", "산업재해로 퇴직할 경우 보험급여는 중단된다."]'::jsonb, 4, '산업재해보상보험의 보장 내용을 이해하고 있는지를 평가하고자 함.', NULL, '{"1": "보험급여는 양도, 압류할 수 없다.\n[정답]", "2": "사업장이 부도, 폐업한 경우 지급받을 수 있다.", "3": "시설장이 잘못이 없으면 급여가 지급될 수 있다.", "4": "보험급여는 세금이 부과되지 않는다.", "5": "산업재해로 퇴직할 경우 보험급여는 중단되지 않는다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Y tá hỗ trợ", "def_ko": "환자를 돌보는 직업", "def_vi": "Nghề chăm sóc bệnh nhân"}, {"term_ko": "업무상", "term_vi": "Liên quan đến công việc", "def_ko": "업무에 의해 발생함", "def_vi": "Phát sinh từ công việc"}, {"term_ko": "부상", "term_vi": "Thương tích", "def_ko": "다치다", "def_vi": "Bị thương"}, {"term_ko": "질병", "term_vi": "Bệnh", "def_ko": "병", "def_vi": "Bệnh tật"}, {"term_ko": "산업재해", "term_vi": "Tai nạn lao động", "def_ko": "직업상의 사고", "def_vi": "Tai nạn nghề nghiệp"}, {"term_ko": "보상보험", "term_vi": "Bảo hiểm bồi thường", "def_ko": "보상을 위한 보험", "def_vi": "Bảo hiểm bồi thường"}, {"term_ko": "급여", "term_vi": "Tiền lương", "def_ko": "보수", "def_vi": "Tiền lương"}, {"term_ko": "세금", "term_vi": "Thuế", "def_ko": "국가에 바치는 금액", "def_vi": "Số tiền nộp cho nhà nước"}, {"term_ko": "중단", "term_vi": "Ngừng", "def_ko": "멈추다", "def_vi": "Dừng lại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (777, '4', '산업재해보상보험법의 설명으로 옳은 것은?', '["보험급여는 채권자가 압류할 수 있다.", "산업재해 인정을 받았다는 이유로 해고될 수 없다.", "사업주가 보험료를 꼭 납입해야 지급받을 수 있다.", "법으로 보장된 보험급여를 받을 권리는 1년이다.", "근무 중 본인의 실수로 인한 사고는 보상받을 수 없다."]'::jsonb, 2, '산업재해보상보험법에 대한 기본적인 이해를 확인하기 위한 문제입니다.', NULL, '{"1": "보험급여는 채권자가 압류할 수 없다. (보험급여는 채권자의 압류에서 보호받는다.)\n[정답]", "2": "산업재해 인정을 받았다는 이유로 해고될 수 없다. (산업재해를 인정받은 경우 해고가 금지된다.)", "3": "사업주가 보험료를 꼭 납입해야 지급받을 수 없다. (노동자는 산업재해로 인한 보상을 받을 수 있다.)", "4": "법으로 보장된 보험급여를 받을 권리는 3년이다. (보험급여를 청구할 수 있는 기간은 3년으로, 1년이 아니다.)", "5": "근무 중 본인의 실수로 인한 사고는 보상받을 수 있다. (업무 중 발생한 사고는 보상받을 수 있는 경우가 많다.)"}'::jsonb, '[{"term_ko": "산업재해보상보험법", "term_vi": "Luật bảo hiểm bồi thường tai nạn lao động", "def_ko": "산업재해에 대한 보상을 규정한 법률", "def_vi": "Luật quy định bồi thường cho tai nạn lao động"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (776, '4', '근로자의 업무상 재해를 신속하고 공정하게 보상하며, 재해근로자의 복지를 증진하기 위한 목적으로 제정된 법률은?', '["노인장기요양보험법", "국민연금법", "산업재해보상보험법", "고용보험법", "노인복지법"]'::jsonb, 3, '근로자의 재해 및 복지와 관련된 법률에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "노인장기요양보험법은 노인에 대한 장기 요양 서비스를 제공하기 위한 법률입니다.\n[정답]", "3": "산업재해보상보험법은 근로자의 업무상 재해에 대해 신속하고 공정한 보상을 제공하는 법률입니다.", "2": "국민연금법은 국민의 노후 보장을 위한 연금 제도를 규정한 법률입니다.", "4": "고용보험법은 실업급여 및 고용보험에 대한 내용을 포함한 법률입니다.", "5": "노인복지법은 노인의 복지 증진을 위한 법률입니다."}'::jsonb, '[{"term_ko": "업무상", "term_vi": "Tình huống lao động", "def_ko": "일과 관련된(한국어)", "def_vi": "liên quan đến công việc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (775, '4', '근로자의 기본적 생활을 보장, 향상하여 균형 있는 국민경제의 발전에 기여하는 것을 목적으로 제정된 법률은?', '["근로기준법", "산업안전보건법", "산업재해보상보험법", "건강보험법", "노인복지법"]'::jsonb, 1, '근로자의 기본적인 생활을 보장하고 향상시키기 위한 법률의 목적을 묻고 있습니다.', NULL, '{"1": "근로자의 근로조건을 정하고 보호하기 위한 법률로, 기본적인 생활 보장과 균형 있는 국민경제 발전에 기여합니다.\n[정답]", "2": "산업현장에서의 안전과 건강을 보장하기 위한 법률입니다.", "3": "산업 재해로 인한 피해를 보상하기 위한 법률입니다.", "4": "국민의 건강을 보장하기 위한 보험 제도입니다.", "5": "노인의 복지를 증진하기 위한 법률입니다."}'::jsonb, '[{"term_ko": "근로자", "term_vi": "Người lao động", "def_ko": "노동자(한국어)", "def_vi": "Người làm việc"}, {"term_ko": "기본적", "term_vi": "Cơ bản", "def_ko": "기본적인(한국어)", "def_vi": "Cơ sở, nền tảng"}, {"term_ko": "생활", "term_vi": "Cuộc sống", "def_ko": "삶(한국어)", "def_vi": "Đời sống"}, {"term_ko": "보장", "term_vi": "Đảm bảo", "def_ko": "보증하다(한국어)", "def_vi": "Bảo đảm"}, {"term_ko": "향상", "term_vi": "Nâng cao", "def_ko": "향상시키다(한국어)", "def_vi": "Tăng cường"}, {"term_ko": "균형", "term_vi": "Cân bằng", "def_ko": "균형(한국어)", "def_vi": "Cân bằng"}, {"term_ko": "국민경제", "term_vi": "Kinh tế quốc dân", "def_ko": "국가 경제(한국어)", "def_vi": "Kinh tế của quốc gia"}, {"term_ko": "사고", "term_vi": "Sự cố", "def_ko": "사고(한국어)", "def_vi": "Tai nạn"}, {"term_ko": "법률", "term_vi": "Luật", "def_ko": "법률(한국어)", "def_vi": "Bộ luật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (774, '4', '근로자의 기본적 생활을 보장, 향상하여 균형 있는 국민경제의 발전에 기여하는 것을 목적으로 제정된 법률은?', '["근로기준법", "산업안전보건법", "산업재해보상보험법", "건강보험법", "노인복지법"]'::jsonb, 1, '근로자의 기본적 생활을 보장하고 향상시키기 위한 법률을 묻는 문제입니다.', NULL, '{"1": "근로자의 권리와 근로 조건을 보장하는 법입니다.\n[정답]", "2": "산업 현장에서의 안전과 건강을 보장하는 법입니다.", "3": "산업 재해로 인한 피해를 보상하는 법입니다.", "4": "국민의 건강을 보장하는 법입니다.", "5": "노인의 복지를 증진하기 위한 법입니다."}'::jsonb, '[{"term_ko": "근로자", "term_vi": "Người lao động", "def_ko": "노동자(한국어)", "def_vi": "Người làm việc"}, {"term_ko": "기본적", "term_vi": "Cơ bản", "def_ko": "기본적인(한국어)", "def_vi": "Cơ sở"}, {"term_ko": "생활", "term_vi": "Cuộc sống", "def_ko": "생활(한국어)", "def_vi": "Cuộc sống"}, {"term_ko": "보장", "term_vi": "Đảm bảo", "def_ko": "보장하다(한국어)", "def_vi": "Đảm bảo"}, {"term_ko": "향상", "term_vi": "Nâng cao", "def_ko": "향상시키다(한국어)", "def_vi": "Nâng cao"}, {"term_ko": "균형", "term_vi": "Cân bằng", "def_ko": "균형(한국어)", "def_vi": "Cân bằng"}, {"term_ko": "국민경제", "term_vi": "Kinh tế quốc dân", "def_ko": "국민 경제(한국어)", "def_vi": "Kinh tế quốc dân"}, {"term_ko": "발전", "term_vi": "Phát triển", "def_ko": "발전(한국어)", "def_vi": "Phát triển"}, {"term_ko": "법률", "term_vi": "Luật pháp", "def_ko": "법률(한국어)", "def_vi": "Luật pháp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (773, '4', '요양보호사가 업무상 부당한 대우를 받았을 때 대처방법은?', '["시설을 퇴사한다.", "동료 요양보호사와 의논한다.", "노인보호전문기관에 법적자문을 요청한다.", "장기요양요원지원센터에 상담을 신청한다.", "산업재해보상보험법에 따른 피해구제 방법을 알아본다."]'::jsonb, 4, '요양보호사가 직장에서 부당한 대우를 받을 경우 적절히 대처할 수 있는 방법을 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "시설을 퇴사한다: 부당한 대우를 해결하기보다 회피하는 방법으로 바람직하지 않습니다.", "2": "동료 요양보호사와 의논한다: 동료와의 의논이 도움이 될 수 있지만, 공식적인 도움을 받는 것이 중요합니다.\n[정답]", "3": "노인보호전문기관에 법적자문을 요청한다: 전문기관의 상담을 통해 법적 대처 방법을 모색할 수 있습니다.", "4": "장기요양요원지원센터에 상담을 신청한다: 이곳은 요양보호사에게 필요한 상담과 지원을 제공하는 곳입니다.", "5": "산업재해보상보험법에 따른 피해구제 방법을 알아본다: 법적 구제 방법을 알지만, 상담 요청이 더 직접적인 해결책입니다."}'::jsonb, '[{"term_ko": "부당한", "term_vi": "대우", "def_ko": "부당한 (không công bằng)", "def_vi": "대우 (đối xử)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (772, '4', '요양보호사의 건강검진, 취업상담 지원 및 대체인력을 지원해주는 곳은?', '["노인정보센터", "노인인권센터", "재가노인복지센터", "노인일자리지원센터", "장기요양요원지원센터"]'::jsonb, 5, '요양보호사와 관련된 지원 기관의 기능에 대해 묻고 있습니다.', NULL, '{"1": "노인정보센터: 노인들에게 필요한 정보 제공을 주로 하는 센터입니다.", "2": "노인인권센터: 노인의 권리를 보호하고 인권을 신장하기 위한 목적으로 운영됩니다.", "3": "재가노인복지센터: 가정에서 거주하는 노인을 대상으로 서비스를 제공합니다.\n[정답]", "4": "노인일자리지원센터: 고용 중심으로 노인들을 지원하는 기관입니다.", "5": "장기요양요원지원센터: 요양보호사를 포함한 장기요양 인력에 대한 지원과 관련된 기관입니다."}'::jsonb, '[{"term_ko": "건강검진", "term_vi": "Khám sức khỏe", "def_ko": "건강 상태를 확인하기 위한 검사", "def_vi": "Kiểm tra tình trạng sức khỏe"}, {"term_ko": "취업상담", "term_vi": "Tư vấn việc làm", "def_ko": "구직자를 대상으로 한 상담", "def_vi": "Tư vấn cho người tìm việc"}, {"term_ko": "대체인력", "term_vi": "Nhân lực thay thế", "def_ko": "대신 일을 수행하는 인력", "def_vi": "Nhân lực thay thế công việc"}, {"term_ko": "노인", "term_vi": "Người già", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}, {"term_ko": "센터", "term_vi": "Trung tâm", "def_ko": "기관 또는 장소", "def_vi": "Cơ quan hoặc địa điểm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (771, '4', '다음 상황에서 요양보호사가 침해받을 권리는?기관장: "지원서를 보니 어르신을 돌보기에는 나이가 많아 일하기 힘들 것 같네요." 요양보호사: "........"', '["자유에 관한 권리", "평등에 관한 권리", "신체의 안전에 대한 권리", "휴식 및 여가를 누릴 권리", "노후소득을 보장 받을 권리"]'::jsonb, 2, '이 문제는 요양보호사로서의 권리와 관련된 상황을 평가하는 것입니다. 요양보호사가 자신의 권리를 보호받는 것의 중요성을 이해하도록 하고자 합니다.', NULL, '{"1": "자유에 관한 권리: 요양보호사도 개인의 자유를 갖고 있지만 이 상황에서는 권리 침해와 직접적인 관련이 없습니다.\n[정답]", "2": "평등에 관한 권리: 요양보호사는 나이로 인해 차별받지 않을 권리가 있으며, 이 상황에서 침해받은 권리는 평등에 관한 권리입니다.", "3": "신체의 안전에 대한 권리: 신체의 안전은 중요하지만 주어진 상황에서는 해당되지 않습니다.", "4": "휴식 및 여가를 누릴 권리: 이 보기는 현재 상황과 관련이 없습니다.", "5": "노후소득을 보장 받을 권리: 노후소득 보장은 중요하지만 이 사례와는 무관합니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc y tế", "def_ko": "환자를 돌보는 직업", "def_vi": "Nghề chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (770, '4', '다음 상황에서 요양보호사가 침해받을 권리는?치매대상자를 돌보느라 휴식시간 없이 일을 하고, 퇴근 시간 이후에도 수당 없이 초과근무를 하였다.', '["평등권", "자유권", "교육권", "노동권", "참정권"]'::jsonb, 4, '요양보호사가 직장에서 침해받을 수 있는 권리에 대해 이해하고, 어떤 권리가 관련되는지를 평가하기 위한 문제입니다.', NULL, '{"1": "평등권은 개인이 평등하게 대우받아야 함을 의미하므로 해당 문제와 무관합니다.", "2": "자유권은 기본적인 자유를 보장받는 권리로, 이 상황과는 관련이 없습니다.", "3": "교육권은 교육을 받을 권리로, 문제의 상황과 연관이 없습니다.\n[정답]", "4": "노동권은 근로자가 합리적이고 공정하게 일할 권리이며, 이 경우 요양보호사가 자신의 근무 조건에 대해 침해받고 있는 상황입니다.", "5": "참정권은 정치적 권리로, 이 문제와는 관련이 없습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인이나 환자를 돌보는 사람", "def_vi": "Người chăm sóc người già hoặc bệnh nhân"}, {"term_ko": "침해", "term_vi": "Xâm phạm", "def_ko": "권리를 방해하다", "def_vi": "Ngăn cản quyền"}, {"term_ko": "권리", "term_vi": "Quyền", "def_ko": "개인의 이익을 보장하는 법적 권한", "def_vi": "Quyền lợi pháp lý đảm bảo lợi ích cá nhân"}, {"term_ko": "노동권", "term_vi": "Quyền lao động", "def_ko": "근로자의 권리", "def_vi": "Quyền của người lao động"}, {"term_ko": "휴식시간", "term_vi": "Thời gian nghỉ ngơi", "def_ko": "일을 쉬는 시간", "def_vi": "Thời gian không làm việc"}, {"term_ko": "초과근무", "term_vi": "Làm thêm giờ", "def_ko": "정해진 시간을 초과하여 일하는 것", "def_vi": "Làm việc vượt quá thời gian quy định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (769, '3', '노인학대 예방을 위한 유관기관(A)와 역할 (B)를 바르게 연결한 것은?', '["법률기관 현장조사 시 동행 협조", "사법경찰 학대 판정을 위한 의학적 진단, 소견", "의료기관 이용자 대상 노인학대 예방교육", "노인보호전문기관 학대 사례의 신고접수", "노인 및 사회복지시설 학대 피해노인의 후견인 지정"]'::jsonb, 4, '노인학대 예방을 위해 각 유관기관의 역할을 올바르게 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "법률기관은 법적인 문제 해결을 위한 지원을 제공하나, 현장조사 시 동행 협조는 주로 사회복지기관의 역할입니다.\n[정답]", "2": "사법경찰은 사건의 수사를 담당하지만, 의학적 진단과 소견은 의료기관의 역할입니다.", "3": "의료기관은 노인학대 예방교육을 실시하는 것이 아니라, 환자의 의료적 필요를 충족하는 곳입니다.", "4": "노인보호전문기관은 노인학대 사례에 대한 신고접수를 담당합니다.", "5": "노인 및 사회복지시설에서의 후견인 지정은 법원 등의 절차를 통해 이루어집니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인에 대한 폭력 또는 학대", "def_vi": "Bạo lực hoặc lạm dụng đối với người cao tuổi"}, {"term_ko": "유관기관", "term_vi": "Cơ quan liên quan", "def_ko": "연관된 기관들", "def_vi": "Các tổ chức có liên quan"}, {"term_ko": "현장조사", "term_vi": "Khảo sát thực địa", "def_ko": "실제 사례 조사", "def_vi": "Điều tra thực tế"}, {"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "폭력이나 학대 행동", "def_vi": "Hành động bạo lực hoặc lạm dụng"}, {"term_ko": "신고접수", "term_vi": "Tiếp nhận báo cáo", "def_ko": "사건에 대한 보고를 받는 것", "def_vi": "Nhận báo cáo về sự việc"}, {"term_ko": "후견인", "term_vi": "Người giám hộ", "def_ko": "법적으로 대리인 역할을 하는 사람", "def_vi": "Người đại diện hợp pháp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (768, '3', '다음 중 직무상 노인학대 신고 의무자는?', '["이웃 주민", "요양 보호사", "집배원", "가족", "주민센터 일반 직원"]'::jsonb, 2, '노인학대 신고 의무자의 범위를 이해하고 있는지 확인하기 위해 출제되었습니다.', NULL, '{"1": "이웃 주민은 신고 의무자가 아닙니다.\n[정답]", "2": "요양 보호사는 직무상 노인학대에 대한 신고 의무가 있습니다.", "3": "집배원은 신고 의무자가 아닙니다.", "4": "가족은 신고를 할 수 있지만, 의무자는 아닙니다.", "5": "주민센터 일반 직원은 신고 의무자가 아닙니다."}'::jsonb, '[{"term_ko": "직무", "term_vi": "Nhiệm vụ", "def_ko": "의무/책임(한국어)", "def_vi": "nghĩa vụ/ trách nhiệm(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (767, '3', '방문목욕서비스를 제공하던 중 대상자의 몸 여러 군데에 멍들고 상처난 자국이 발견되었다. 요양보호사의 대처방법은?', '["시설에 입소할 것을 권유한다.", "대상자의 이야기를 들어주고 위로해 준다.", "함께 사는 가족들에게 연락하여 대상자의 상태를 알려준다.", "노인보호전문기관이나 경찰서에 신고한다.", "개인적인 일이므로 모른 척 한다."]'::jsonb, 4, '대상자의 안전과 건강을 중시하며 필요한 조치를 취하는 방법을 아는가?', NULL, '{"1": "시설에 입소할 것을 권유하는 것은 문제의 원인을 중재하지 않는다.\n[정답]", "2": "대상자의 이야기를 들어주고 위로해 주는 것은 중요하지만, 더 큰 문제에 대한 대처가 아니다.", "3": "함께 사는 가족들에게 연락하여 대상자의 상태를 알려주는 것은 필요할 수 있지만, 즉각적인 대처가 요구된다.", "4": "노인보호전문기관이나 경찰서에 신고하는 것이 적절한 조치이다.", "5": "개인적인 일이므로 모른 척 하는 것은 책임 회피가 된다."}'::jsonb, '[{"term_ko": "방문목욕서비스", "term_vi": "Dịch vụ tắm tại nhà", "def_ko": "환자의 집을 방문해 목욕 서비스를 제공하는 것", "def_vi": "Dịch vụ tắm cho bệnh nhân tại nhà"}, {"term_ko": "멍", "term_vi": "Vết bầm", "def_ko": "피부에 생긴 푸른 반점", "def_vi": "Vết bầm trên da"}, {"term_ko": "상처", "term_vi": "Vết thương", "def_ko": "피부의 손상", "def_vi": "Tổn thương trên da"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자의 요양과 간호를 돕는 직업", "def_vi": "Nghề giúp đỡ chăm sóc bệnh nhân"}, {"term_ko": "노인보호전문기관", "term_vi": "Cơ quan bảo vệ người cao tuổi", "def_ko": "노인을 보호하기 위한 기관", "def_vi": "Tổ chức bảo vệ người già"}, {"term_ko": "경찰서", "term_vi": "Đồn cảnh sát", "def_ko": "범죄를 수사하는 기관", "def_vi": "Cơ quan điều tra tội phạm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (766, '3', '월별 입소비용 미납 등 노인에 대한 특별한 보호조치 없이 가족이 연락을 두절하는 학대유형은?', '["신체적 학대", "정서적 학대", "경제적 학대", "유기", "방임"]'::jsonb, 4, '노인학대의 유형 중에서 가족의 유기와 관련된 개념을 이해하고 구별할 수 있는지를 평가하고자 함.', NULL, '{"1": "신체적 학대: 노인에게 신체적으로 강압을 가하는 경우로, 이 문제와는 관련이 없음.", "2": "정서적 학대: 노인의 감정이나 심리에 대한 학대로, 연락을 두절하는 행위와는 차이가 있음.\n[정답]", "3": "경제적 학대: 경제적인 자원을 제한하거나 착취하는 경우로, 이 문제와는 직접적인 관련이 없음.", "4": "유기: 가족이 노인을 돌보지 않고 연락을 끊는 경우로, 이 문제에 해당됨.", "5": "방임: 노인이 필요로 하는 기본적인 돌봄을 제공하지 않는 경우로, 유기와는 다름."}'::jsonb, '[{"term_ko": "입소비용", "term_vi": "학대", "def_ko": "비용 để vào viện", "def_vi": "lạm dụng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (765, '3', '다음에서 파악되는 노인학대의 유형으로 옳은 것은?• 집 안에 쓰레기가 쌓여 악취가 나는데도 대상자가 도움을 거부한다.• 대상자가 건강에 치명적인 약물이나 알코올 남용을 지속한다.', '["유기", "방임", "자기방임", "경제적 학대", "신체적 학대"]'::jsonb, 3, '노인학대의 다양한 유형을 이해하고 그에 대한 사례를 파악하는 것이 중요하다.', NULL, '{"1": "유기는 타인의 보호나 도움을 거부하는 상태를 의미한다. 이 경우는 해당되지 않는다.\n[정답]", "3": "자기방임은 스스로 자신의 안전이나 건강을 돌보지 않는 상태로, 해당 사례에 적합하다.", "2": "방임은 타인의 돌봄이 필요한 상황에서 그 돌봄이 이뤄지지 않는 상태를 의미한다.", "4": "경제적 학대는 피해자의 재정적 자원을 착취하는 행위를 뜻한다.", "5": "신체적 학대는 신체에 대한 폭력이나 상해를 가하는 것을 말한다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인을 대상으로 하는 학대", "def_vi": "Hành vi ngược đãi đối với người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (764, '3', '다음 사례에 해당하는 노인학대 유형은? 쪽방에서 생활하고 있는 대상자는 1개우러 전에 배우자와 사별한 후, 식사를 거부하고 약 복용을 중지한 채 홀로 지내고 있다. 그 결과 체중이 급격히 줄고 몸이 날로 쇠약해져 갔다.', '["방임", "유기", "자기방임", "착취", "신체적 학대"]'::jsonb, 3, '노인학대의 다양한 유형을 이해하고, 사례에 해당하는 유형을 구분하는 것이다.', NULL, '{"1": "방임: 필요한 기본적 요구를 충족하지 못한 경우로, 이 경우는 본인이 스스로 식사를 거부하고 약을 중지한 것으로 볼 수 있어 방임은 해당되지 않는다.\n[정답]", "3": "자기방임: 노인이 스스로 자신의 건강 관리를 소홀히 하는 경우로, 주어진 사례에서 대상자가 식사를 거부하고 약 복용을 중지한 것은 자기방임에 해당한다.", "2": "유기: 보호자나 가족이 노인을 방치한 경우로, 이 사례에서는 홀로 있더라도 방치가 아닌 자신의 행동으로 인한 것이므로 유기가 아니다.", "4": "착취: 경제적 혹은 신체적으로 착취당하는 상황으로, 이 사례와는 관련이 없다.", "5": "신체적 학대: 신체적으로 피해를 입는 경우로, 해당 사례와는 무관하다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인에게 가해지는 폭력이나 방임", "def_vi": "Bạo lực hoặc bỏ mặc đối với người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (763, '3', '노인학대의 유형과 학대행위가 바르게 연결된 것은?', '["신체적 학대 - 대화를 하지 않는다.", "방임- 안정된 주거공간을 제공하지 않고 떠돌게 한다.", "경제적 학대 - 의료적 처치와 생활비 제공을 중단한다.", "정서적 학대 - 노인이 자살을 시도한다.", "유기 - 거동이 불편한 노인의 간병을 소홀히 한다."]'::jsonb, 2, '노인학대의 다양한 유형과 그에 해당하는 학대행위를 이해하고, 올바르게 연결할 수 있는지를 평가하기 위한 문제이다.', NULL, '{"1": "신체적 학대는 주로 물리적으로 상해를 입히는 행위로 대화를 하지 않는 것은 해당하지 않는다.\n[정답]", "2": "방임은 안정된 주거공간을 제공하지 않는 것으로, 노인을 안전하게 지내지 못하게 하는 경우를 설명한다.", "3": "경제적 학대는 재정적인 지원을 중단하는 것이 맞지만, 금전적 착취가 더 일반적인 설명이다.", "4": "정서적 학대는 노인의 자살 시도와 관련된 심리적 고통과 관계가 있지만, 학대행위로 직접 연결하기는 어렵다.", "5": "유기는 노인을 방치하거나 돌보지 않는 행위로 설명할 수 있으며, 거동이 불편한 노인의 간병 소홀은 유기의 정의에 맞는다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인을 대상으로 한 학대", "def_vi": "Hành vi lạm dụng nhắm vào người cao tuổi"}, {"term_ko": "신체적", "term_vi": "Thể chất", "def_ko": "신체적으로 관련된", "def_vi": "Liên quan đến cơ thể"}, {"term_ko": "방임", "term_vi": "Bỏ bê", "def_ko": "필요한 보호를 하지 않는 행위", "def_vi": "Hành vi không bảo vệ cần thiết"}, {"term_ko": "정서적", "term_vi": "Cảm xúc", "def_ko": "감정적으로 관련된", "def_vi": "Liên quan đến cảm xúc"}, {"term_ko": "유기", "term_vi": "Bỏ mặc", "def_ko": "책임을 다하지 않는 행위", "def_vi": "Hành vi không hoàn thành trách nhiệm"}, {"term_ko": "경제적", "term_vi": "Kinh tế", "def_ko": "재정적으로 관련된", "def_vi": "Liên quan đến tài chính"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (762, '3', '다음 사례에 해당하는 노인학대 유형은?어머니가 화장실에서 넘어져 엉덩이의 통증을 호소하며 며칠 동안 누워있는데 아들은 병원에 모시고 갈 생각은 하지 않고, 방안에 방치하였다.', '["방임", "유기", "자기방임", "착취", "신체적 학대"]'::jsonb, 1, '노인학대의 다양한 유형을 이해하고 사례를 통해 적절한 유형을 식별하는 것이다.', NULL, '{"1": "방임: 필요한 도움이나 치료를 제공하지 않는 경우로, 이 사례는 아들이 어머니를 방치했으므로 방임에 해당한다.\n[정답]", "2": "유기: 의도적으로 환자를 버리는 경우로, 이 사례는 아들이 어머니를 버린 것과는 다른 상황이다.", "3": "자기방임: 스스로 자신의 신체나 건강을 돌보지 않는 경우로, 어머니가 의식적으로 그렇게 한 것은 아니다.", "4": "착취: 다른 사람에게 경제적 이득을 취하기 위해 사용하는 경우로, 이 사례와는 관련이 없다.", "5": "신체적 학대: 신체적으로 상해를 가하는 경우로, 이 사례는 방치와 관련되어 있다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "고령자의 권리를 침해하거나 건강을 해치는 행위", "def_vi": "Hành vi xâm phạm quyền lợi hoặc làm tổn hại sức khỏe của người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (761, '3', '다음 내용에 해당하는 노인학대 유형은?• 안경이 깨져있다.• 더럽고 찢어진 옷을 입고 있다.• 오물로 이불이 더럽고, 욕창이 있다.', '["방임", "유기", "신체적 학대", "경제적 학대", "정서적 학대"]'::jsonb, 1, '노인학대의 유형을 이해하고 구분하는 능력을 평가하기 위한 문제입니다.', NULL, '{"1": "방임: 노인이 기본적인 돌봄과 보호를 받지 못하는 상태를 의미합니다. 제시된 내용은 노인이 옷이나 안경이 불량하며, 욕창이 있는 상황이므로 방임에 해당합니다.\n[정답]", "2": "유기: 노인을 방치하거나 돌보지 않는 상황을 의미하지만, 이 문제에서는 물리적 방임이 강조되었으므로 정답이 아닙니다.", "3": "신체적 학대: 신체적 상해를 입히는 행위이나, 이 경우는 방임 문제입니다.", "4": "경제적 학대: 노인의 재산을 착취하거나 재정적 지원을 하지 않는 것을 의미하지만, 이 문제에서는 해당하지 않습니다.", "5": "정서적 학대: 정신적 고통을 주는 행위이지만, 여기서는 신체적 상황이 주제입니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người già", "def_ko": "늙은 사람에게 가해지는 배려 부족 또는 폭력", "def_vi": "Hành vi thiếu chăm sóc hoặc bạo lực đối với người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (760, '3', '부양 의무자로서 책임이나 의무를 거부 또는 포기하여 노인에게 의식주 및 의료를 적절하게 제공하지 않는 행위의 학대 유형은?', '["방임", "유기", "자기방임", "착취", "신체적 학대"]'::jsonb, 1, '노인복지법에서의 부양 의무자에 대한 이해와 관련된 학대 유형을 묻고 있다.', NULL, '{"1": "방임: 부양 의무자가 책임이나 의무를 거부하여 노인에게 적절한 도움을 제공하지 않는 경우를 의미한다. \n[정답]", "2": "유기: 부양 의무자가 노인을 돌보지 않고 방치하는 경우를 뜻한다.", "3": "자기방임: 노인이 자신의 건강이나 안전을 스스로 무시하는 경우이다.", "4": "착취: 노인을 경제적이나 신체적으로 이용하여 이득을 취하는 경우를 말한다.", "5": "신체적 학대: 노인에게 신체적 상해를 가하는 행위를 의미한다."}'::jsonb, '[{"term_ko": "부양 의무자", "term_vi": "Người nuôi dưỡng", "def_ko": "가족이나 친척이 노인을 돕고 돌봐야 하는 책임이 있는 사람", "def_vi": "Người có trách nhiệm giúp đỡ và chăm sóc người cao tuổi trong gia đình"}, {"term_ko": "방임", "term_vi": "Bỏ bê", "def_ko": "필요를 무시하고 돌보지 않음", "def_vi": "Không quan tâm và bỏ mặc nhu cầu"}, {"term_ko": "유기", "term_vi": "Bỏ rơi", "def_ko": "돌보지 않고 방치함", "def_vi": "Bỏ mặc không chăm sóc"}, {"term_ko": "착취", "term_vi": "Khai thác", "def_ko": "부당하게 이용하는 것", "def_vi": "Sử dụng một cách không công bằng"}, {"term_ko": "신체적 학대", "term_vi": "Lạm dụng thể xác", "def_ko": "신체적으로 피해를 주는 것", "def_vi": "Gây hại về mặt thể chất"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (759, '3', '아들이 사업의 실패로 대상자의 통장을 몰래 빼돌려 허락 없이 돈을 인출하여 세금과 공과금이 체납되었다. 어떤 유형의 학대인가?', '["경제적 학대", "정서적 학대", "성적 학대", "유기", "방임"]'::jsonb, 1, '대상자가 겪고 있는 학대의 유형을 파악하는 것.', NULL, '{"1": "경제적 학대는 대상자의 재산이나 재정에 악영향을 주는 행위로, 이 경우 아들이 몰래 돈을 인출한 것이 해당된다.\n[정답]", "2": "정서적 학대는 감정적 상처를 주는 행위로, 문제의 경우와는 무관하다.", "3": "성적 학대는 성적 행위에 관련된 학대로, 이 경우와는 무관하다.", "4": "유기는 대상자를 아예 돌보지 않는 것을 의미하며, 이 상황과는 다르다.", "5": "방임은 필요한 돌봄을 제공하지 않는 것으로, 이번 경우에서는 아들이 직접 개입했기 때문에 해당하지 않는다."}'::jsonb, '[{"term_ko": "경제적", "term_vi": "Kinh tế", "def_ko": "재정과 관련된", "def_vi": "Liên quan đến tài chính"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (758, '3', '노인의 의사에 반하여 성적 수치심 유발 행위 및 성희롱, 성추행을 강제적으로 행할 경우에 해당하는 학대 유형은?', '["신체적 학대", "정서적 학대", "성적 학대", "경제적 학대", "방임"]'::jsonb, 3, '노인의 권리와 관련된 성적 학대의 개념을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "신체적 학대: 신체적 손상을 주는 행위로, 이 문제와는 관련이 없습니다.", "2": "정서적 학대: 감정적 고통을 주는 행위로, 성적 행위와는 다른 차원의 문제입니다.\n[정답]", "3": "성적 학대: 노인의 의사에 반하여 성적 수치심을 유발하는 행위는 성적 학대에 해당합니다.", "4": "경제적 학대: 재정적으로 착취하는 행위로, 성적 관련 행위와는 무관합니다.", "5": "방임: 필요한 돌봄을 제공하지 않는 것을 의미하며, 이 문제와는 관련이 없습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (757, '3', '다음 사례에 해당하는 노인학대 유형은?늦은 저녁식사를 하고 쇼파에 앉아 쉬고 있는 시어머니께 "에이, 꼴도 보기 싫은데 빨리 방에나 들어가지 왜 거기 앉아 있는 거야. 죽치고 앉아 있지 말고 빨리 들어가요." 라고 소리를 질렀다.', '["정서적 학대", "신체적 학대", "경제적 학대", "방임", "유기"]'::jsonb, 1, '이 문제는 노인학대의 유형을 이해하고 구분할 수 있는지를 평가하기 위해 출제되었습니다. 주어진 사례에서 나타나는 행동이 어떤 형태의 학대로 분류될 수 있는지를 파악하는 것이 핵심입니다.', NULL, '{"1": "상대방의 감정을 상하게 하고, 심리적 고통을 주는 언행을 직면했으므로 정서적 학대입니다.\n[정답]", "2": "신체적 접촉이나 폭력이 관여되지 않았기 때문에 신체적 학대가 아닙니다.", "3": "경제적 착취나 재산에 대한 위협이 없으므로 경제적 학대가 아닙니다.", "4": "충분한 돌봄이 부족하지 않기 때문에 방임이 아닙니다.", "5": "유기하고 방치하는 것이 아니므로 유기가 아닙니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인이 당하는 학대", "def_vi": "Hành vi lạm dụng đối với người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (756, '3', '다음 내용에서 파아갈 수 있는 노인학대 유형은?• 대상자만 따로 식사하게 한다.• 대상자의 이성교제를 방해한다.• 대상자의 말과 행동에 반응하지 않는다.', '["유기", "방임", "신체적 학대", "정서적 학대", "경제적 학대"]'::jsonb, 4, '노인학대의 유형을 이해하고 범주화하는 능력을 평가하기 위함입니다.', NULL, '{"1": "유기는 누군가를 돌보지 않고 방치하는 것으로, 이 경우에 해당하지 않습니다.", "2": "방임은 필요한 돌봄을 제공하지 않는 것을 의미하지만, 이 시나리오에서 직접적으로 나타나지 않습니다.\n[정답]", "3": "신체적 학대는 물리적인 폭력을 포함하나 본 사례에는 해당하지 않습니다.", "4": "정서적 학대는 상대방의 감정을 해치거나 사회적 관계를 혼란스럽게 만드는 것으로, 본 사례의 내용은 여기에 적합합니다.", "5": "경제적 학대는 재정적 자원을 착취하는 것으로, 이 내용과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인을 대상으로 하는 다양한 형태의 학대", "def_vi": "Các hình thức lạm dụng đa dạng đối với người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (755, '3', '노인학대 행위(A)와 유형 (B)이 바르게 연결된 것은?', '["창피를 준다. 성적 학대", "외출을 못하게 한다. 신체적 학대", "가출을 해도 찾지 않는다. 자기방임", "치료를 못 받게 한다. 경제적 학대", "대상자의 말을 무시한다. 유기"]'::jsonb, 2, '노인학대의 다양한 유형과 그에 대응하는 행위를 이해하고 있는지를 평가할 의도이다.', NULL, '{"1": "창피를 준다. 성적 학대", "2": "외출을 못하게 한다. 신체적 학대\n[정답]", "3": "가출을 해도 찾지 않는다. 자기방임", "4": "치료를 못 받게 한다. 경제적 학대", "5": "대상자의 말을 무시한다. 유기"}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인을 대상으로 한 폭력이나 학대", "def_vi": "Bạo lực hoặc lạm dụng đối với người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (754, '3', '가족이 일방적으로 수도와 전기를 단절하여 대상자의 생존을 위협하는 노인학대 유형은?', '["유기", "자기방임", "정서적 학대", "언어적 학대", "신체적 학대"]'::jsonb, 5, '노인학대의 다양한 유형을 이해하고 구별하는 능력을 평가하기 위한 문제입니다.', NULL, '{"1": "유기는 피할 수 있는 환경에서 의도적으로 방치하는 것으로, 생명에 위협적이지는 않지만 정서적으로 영향을 줄 수 있습니다.\n[정답]", "5": "신체적 학대는 생존을 위협할 수 있는 행위로, 수도와 전기를 차단하는 것은 명백한 신체적 학대의 사례입니다.", "2": "자기방임은 노인이 자기 자신을 돌보지 않는 경우로, 가족의 의도와는 무관합니다.", "3": "정서적 학대는 언어적 공격이나 심리적 압박을 포함하지만, 생명을 직접적으로 위협하지는 않습니다.", "4": "언어적 학대는 신체적 피해를 주지는 않지만, 정신적으로 상처를 남길 수 있습니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인을 대상으로 한 학대", "def_vi": "Hành vi lạm dụng nhắm vào người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (753, '3', '물리적인 힘이나 도구를 이용하여 노인에게 신체적 손상, 고통, 장애 등을 유발하는 노인학대의 유형은?', '["정서적 학대", "신체적 학대", "경제적 학대", "방임", "유기"]'::jsonb, 2, '노인학대의 유형에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "정서적 학대: 노인에게 정서적 고통이나 심리적 스트레스를 주는 형태입니다.\n[정답]", "2": "신체적 학대: 물리적인 힘이나 도구를 사용하여 노인에게 신체적 손상이나 고통을 유발하는 학대입니다.", "3": "경제적 학대: 노인의 재산이나 재정을 착취하는 형태의 학대입니다.", "4": "방임: 필요한 돌봄이나 도움이 제공되지 않는 경우를 의미합니다.", "5": "유기: 노인이 돌보지 않아 혼자 남겨지는 상황입니다."}'::jsonb, '[{"term_ko": "신체적", "term_vi": "Thể xác", "def_ko": "신체(몸)와 관련된", "def_vi": "liên quan đến cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (752, '3', '노인학대를 발생시킬 수 있는 요인은?', '["노인부양 의식 강화", "노인의 의존성 증가", "가족관계 갈등 해소", "가족부양 부담 감소", "노인의 사회적 관계망 확대"]'::jsonb, 2, '노인학대를 유발할 수 있는 요인을 이해하고 평가하기 위함입니다.', NULL, '{"1": "노인부양 의식 강화를 통해 노인에 대한 이해와 배려가 증진되어 학대를 줄일 수 있습니다.\n[정답]", "2": "노인의 의존성이 증가하면 가족의 부담감이 커져 노인학대를 촉발할 수 있습니다.", "3": "가족관계 갈등 해소는 노인학대와 관련이 없으며 오히려 긍정적인 결과를 가져올 수 있습니다.", "4": "가족부양 부담 감소는 노인학대와는 반대의 개념으로, 노인에 대한 도움이 줄어들게 할 수 있습니다.", "5": "노인의 사회적 관계망 확대는 노인이 더 많은 지원을 받을 수 있게 하여 학대를 방지하는 데 기여할 수 있습니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인에 대한 신체적, 정서적, 재정적 학대", "def_vi": "Lạm dụng về thể chất, tinh thần, tài chính đối với người cao tuổi"}, {"term_ko": "의존성", "term_vi": "Sự phụ thuộc", "def_ko": "다른 사람에게 의존하는 상태", "def_vi": "Trạng thái phụ thuộc vào người khác"}, {"term_ko": "가족부양", "term_vi": "Chăm sóc gia đình", "def_ko": "가족이 노인이나 아픈 가족을 돌보는 일", "def_vi": "Sự chăm sóc người cao tuổi hoặc thành viên gia đình bị bệnh"}, {"term_ko": "사회적 관계망", "term_vi": "Mạng lưới xã hội", "def_ko": "사람들 간의 관계와 연결망", "def_vi": "Mối quan hệ và kết nối giữa mọi người"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (751, '3', '다음 중 퇴소 단계에서 노인에게 보장되어야할 권리로 옳은 것은?', '["노인의 퇴소 결정을 번복하고자 회유한다.", "퇴소가 불가피한 경우 그 사유를 통보하지 않는다.", "보호자의 방임, 종사자와의 불화 시 퇴소를 권유한다.", "노인의 의사에 반하는 전원 또는 퇴소 조치를 한다.", "퇴소 이후에도 지역사회 내 서비스를 연계하여 제공한다."]'::jsonb, 5, '퇴소 단계에서 노인이 보장받아야 할 권리를 파악하는 것이다.', NULL, '{"1": "노인의 퇴소 결정을 번복하고자 회유하는 것은 노인의 권리를 침해하는 행동이다.", "2": "퇴소가 불가피한 경우 그 사유를 통보하지 않는 것은 투명한 소통을 하지 않는 것이므로 옳지 않다.", "3": "보호자의 방임, 종사자와의 불화 시 퇴소를 권유하는 것은 노인의 자율성을 인정하지 않는 내용이다.", "4": "노인의 의사에 반하는 전원 또는 퇴소 조치를 하는 것은 절대적으로 금지되어 있는 행위이다.\n[정답]", "5": "퇴소 이후에도 지역사회 내 서비스를 연계하여 제공하는 것은 노인의 권리를 보장하는 바람직한 행동이다."}'::jsonb, '[{"term_ko": "퇴소", "term_vi": "Xuất viện", "def_ko": "병원이나 요양시설에서 나가는 것", "def_vi": "Ra khỏi bệnh viện hoặc cơ sở chăm sóc"}, {"term_ko": "보장", "term_vi": "Đảm bảo", "def_ko": "안전하게 지켜주는 것", "def_vi": "Đảm bảo an toàn"}, {"term_ko": "의사", "term_vi": "Ý chí", "def_ko": "원하는 것, 뜻", "def_vi": "Mong muốn, ý kiến"}, {"term_ko": "전원", "term_vi": "Chuyển viện", "def_ko": "다른 곳으로 옮기는 것", "def_vi": "Chuyển đến nơi khác"}, {"term_ko": "지역사회", "term_vi": "Cộng đồng", "def_ko": "살고 있는 지역의 주민", "def_vi": "Cư dân của khu vực sống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (750, '3', '다음 사례에서 시설 생활노인의 권리 침해에 해당하는 것은?(박씨 할머니는 정기적으로 병원진료를 받아왔다.) 요양보호사: 어르신 오늘 진료를 늦게까지 했나 봐요? 식사 시간이 지났으니 그냥 찬밥을 드셔야 겠네요. 박씨 할머니: 밥도 차가운데, 국이라도 따뜻하게 데워주지...', '["존엄한 존재로 대우받을 권리", "안전한 생활환경을 제공받을 권리", "신체구속을 받지 않을 권리", "개인적 견해를 표현하고 해결을 요구할 권리", "차별 및 노인학대를 받지 않을 권리"]'::jsonb, 4, '시설 생활노인의 권리가 무엇인지 이해하고, 해당 사례에서 침해된 권리를 파악하는 것이 중요함.', NULL, '{"1": "어르신의 존재를 존중받아야 한다는 권리로, 이 경우 침해되지 않음.", "2": "안전한 환경에서 생활해야 한다는 권리로, 이 경우 침해되지 않음.", "3": "신체적 구속이 없어야 한다는 권리로, 이 경우 침해되지 않음.\n[정답]", "4": "자신의 의견을 표현하고 이를 해결할 것을 요구할 수 있어야 하나, 이를 제대로 존중받지 못한 상황임.", "5": "차별 또는 학대를 받지 않아야 할 권리로, 이 경우 명확히 침해된 상황은 아님."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (749, '3', '다음에서 설명하는 시설 생활노인의 권리보호를 위한 윤리강령은?• 보안장치가 마련된 사물함을 개인에게 제공한다.• 개인의 금전 및 물품을 타인에게 양도, 처분해서는 안 된다.', '["신체구속을 받지 않을 권리", "충분한 정보를 제공 받을 권리", "사생활과 비밀보장에 대한 권리", "개인의 재산과 소유물을 스스로 관리할 권리", "개인적 견해를 표현하고 해결을 요구할 권리"]'::jsonb, 4, '시설 생활노인의 권리보호를 위한 윤리강령에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "신체적 자유침해를 막기 위한 권리로, 해당 문제와는 관련이 없습니다.", "2": "충분한 정보에 대한 권리는 중요한 사항이나 이에 대한 직접적인 내용은 포함되어 있지 않습니다.", "3": "사생활의 보호와 비밀 보장은 기본적인 윤리적 권리지만, 문제의 핵심은 개인의 재산 관리에 대한 것입니다.\n[정답]", "4": "개인의 재산과 소유물을 스스로 관리할 권리는 문제에서 언급된 내용과 일치합니다.", "5": "개인적 견해를 표현하는 권리는 중요하나, 문제의 맥락과는 상관이 없습니다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "시설(한국어)", "def_vi": "cơ sở(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (748, '3', '다음 내용에 해당하는 시설 생활노인의 권리보호를 위한 윤리강령은?• 시설 내 자발적 모임이나 의사소통에 제재를 가하지 않는다.• 노인의 면회, 외출, 외박을 최대한 보장한다.• 노인의 정치적 이념과 종교적 신념을 인정한다.', '["존엄한 조냊로 대우받을 권리", "사생활과 비밀보장에 대한 권리", "질 높은 생활서비스를 받을 권리", "안락하고 안전한 생활환경을 제공받을 권리", "시설 내, 외부 활동 및 사회적 관계에 참여할 권리"]'::jsonb, 5, '노인의 권리를 보호하기 위한 윤리강령의 내용을 이해하고, 해당 권리가 무엇인지 알고 있는지를 평가하기 위함입니다.', NULL, '{"1": "존엄한 대우를 받을 권리는 중요한 요소이나 이번 문제의 내용과는 직접적인 연관이 없습니다.", "2": "사생활과 비밀보장에 대한 권리도 중요하나, 주어진 내용에 명시된 사항과는 관련성이 부족합니다.", "3": "질 높은 생활서비스를 받을 권리는 시설 노인의 중요한 권리 중 하나지만, 직접적으로 문제의 내용과 연결되지 않습니다.", "4": "안락하고 안전한 생활환경을 제공받을 권리는 노인이 요구하는 기본적인 권리이나, 이번 문제의 구체적인 내용과 상관없습니다.\n[정답]", "5": "시설 내, 외부 활동 및 사회적 관계에 참여할 권리는 주어진 내용과 가장 밀접한 관련이 있습니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền (Tiếng Việt)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (747, '3', '다음 사례에서 해당하는 시설 생활노인의 권리보호를 위한 윤리강령은?이씨 할머니는 머리를 만지면서 "아무리 나이를 먹었고 시설에서 남의 도움으로 생활하고 있다지만 저 사람한테 파마를 하면 머리카락이 많이 상해. 약이 안 좋은가봐. 못돼 먹은 봉사자야."라며 화를 내신다.', '["차별 및 노인학대를 받지 않을 권리", "질 높은 생활서비스를 받을 권리", "사생활과 비밀 보장에 대한 권리", "개인적 견해를 표현하고 해결을 요구할 권리", "안락하고 안전한 생활환경을 제공받을 권리"]'::jsonb, 2, '이 문제는 시설 생활노인이 자신의 권리를 표현하고 요구하는 상황에서 어떤 윤리 강령이 적용되는지를 묻고 있습니다.', NULL, '{"1": "차별 및 노인학대를 받지 않을 권리: 맞지만, 이 사례의 핵심은 서비스 질에 대한 표현입니다.\n[정답]", "2": "질 높은 생활서비스를 받을 권리: 이씨 할머니의 불만은 제공받는 서비스의 질에 관한 것으로, 이는 권리 보호와 관련이 깊습니다.", "3": "사생활과 비밀 보장에 대한 권리: 관련이 없으며, 이 사례와는 거리가 있습니다.", "4": "개인적 견해를 표현하고 해결을 요구할 권리: 개인의 불만이 표현되었지만, 여기서는 서비스 질이 주제입니다.", "5": "안락하고 안전한 생활환경을 제공받을 권리: 환경은 언급되었지만, 핵심은 생활서비스의 질입니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (746, '3', '다음 설명에서 시설 생활노인에게 보장되는 권리로 옳은 것은?•대상자의 선호와 건강 상태에 따라 개별화된 식단을 제공한다.•잔존능력을 유지하고 기력 향상을 위한 재활 프로그램을 제공한다.•요양보호사의 능력 개발을 위한 직무훈련을 실시한다.', '["질 높은 생활서비스 및 보건의료서비스를 받을 권리", "존엄한 존재로 대우받을 권리", "사생활과 비밀 보장에 대한 권리", "개인적 견해를 표현하고 해결을 요구할 권리", "안락하고 안전한 생활환경을 제공받을 권리"]'::jsonb, 1, '시설 생활노인에게 보장되는 권리를 확인하는 목적의 문제입니다.', NULL, '{"1": "질 높은 생활서비스 및 보건의료서비스를 받을 권리는 시설 생활노인에게 보장된 기본적인 권리입니다.\n[정답]", "2": "존엄한 존재로 대우받을 권리는 존엄성을 강조하는 권리이나, 이번 문제에서 요구하는 구체적인 설명과 맞지 않습니다.", "3": "사생활과 비밀 보장에 대한 권리는 중요한 권리지만, 개별화된 서비스에 대한 직접적인 내용과는 다릅니다.", "4": "개인적 견해를 표현하고 해결을 요구할 권리는 중요하나, 이번 질문의 범위와는 약간 차이가 있습니다.", "5": "안락하고 안전한 생활환경을 제공받을 권리는 필요한 권리이나, 문제의 질문과는 다소 다른 맥락입니다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "시설(한국어)", "def_vi": "Cơ sở"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (745, '3', '다음 사례에서 요양원이 위반한 시설 생활노인의 권리보호를 위한 윤리강령은?', '["개별화된 서비스를 제공받고 선택할 수 있는 권리", "존엄한 존재로 대우받을 권리", "신체구속을 받지 않을 권리", "사생활 및 비밀보장에 대한 권리", "차별 및 노인학대를 받지 않을 권리"]'::jsonb, 3, '요양원에서의 노인의 권리보호와 관련된 윤리강령을 이해하고 적용할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "개별화된 서비스의 제공은 노인의 선택권을 존중하는 권리입니다.\n[정답]", "3": "신체구속을 받지 않을 권리는 노인의 기본적인 자유와 관련된 중요한 윤리적 사항입니다.", "2": "존엄한 존재로 대우받을 권리는 노인의 인격을 존중하는 것을 의미합니다.", "4": "사생활 및 비밀보장에 대한 권리는 프라이버시와 관련된 것입니다.", "5": "차별 및 노인학대를 받지 않을 권리는 노인의 인권 보호와 관련 있습니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền lợi(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (744, '3', '다음 사례에서 시설대상자가 보장받아야 할 기본 권리는?"저 노인네는 자식들이 자주 와서 직원들한테 선물도 하고 그래서 그런지 말 한마디를 해도 고분고분하게 해. 똑같이 음식을 흘려도 나한테만 더 화를 내서 기분이 좋지 않아."', '["신체구속을 받지 않을 권리", "질 높은 생활서비스를 받을 권리", "충분한 정보를 제공받을 권리", "사생활과 비밀 보장에 대한 권리", "차별 및 노인학대를 받지 않을 권리"]'::jsonb, 5, '시설대상자가 보장받아야 할 기본 권리를 인식하게 하기 위함입니다.', NULL, '{"1": "신체구속을 받을 권리는 시설이 아니라 개인의 자유를 보호하는 개념입니다.\n[정답]", "5": "차별 및 노인학대를 받지 않을 권리는 기본적인 인권으로, 사례의 상황에서 가장 중요한 권리입니다.", "2": "질 높은 생활서비스를 받을 권리는 기본 생활에 관한 권리의를 포함하지만, 본 사례와는 먼 내용입니다.", "3": "충분한 정보를 제공받을 권리는 정보에 대한 접근을 의미하나, 본 사례에서 주된 이슈는 차별입니다.", "4": "사생활과 비밀 보장에 대한 권리는 중요하지만, 사례의 본질적인 문제는 차별과 노인학대입니다."}'::jsonb, '[{"term_ko": "시설대상자", "term_vi": "Người cao tuổi trong cơ sở", "def_ko": "시설에서 생활하는 노인", "def_vi": "Người sống trong cơ sở"}, {"term_ko": "차별", "term_vi": "Phân biệt", "def_ko": "특정 집단이나 개인이 불합리하게 대우받는 것", "def_vi": "Việc được đối xử không công bằng với một nhóm hoặc cá nhân"}, {"term_ko": "노인학대", "term_vi": "Lạm dụng tuổi già", "def_ko": "노인에 대한 신체적, 정신적 학대", "def_vi": "Bạo lực thể chất hoặc tâm lý đối với người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (743, '3', '다음 설명에 해당하는 시설 생활노인 권리보호를 위한 윤리강령은?노인의 권리가 침해될 우려가 있거나, 침해받은 경우 이의 회복과 구제를 위한 적극적 조치를 강구해야 한다.', '["사생활과 비밀 보장에 대한 권리", "질 높은 생활서비스를 받을 권리", "존엄한 존재로 대우받을 권리", "신체구속을 받지 않을 권리", "개인적 견해를 표현하고 해결을 요구할 권리"]'::jsonb, 3, '노인의 권리 보호에 관한 윤리강령을 이해하고 판단하는 것.', NULL, '{"1": "사생활과 비밀 보장에 대한 권리는 노인의 개인 정보와 사생활이 보호되어야 함을 의미하지만, 질문의 주안점과는 거리가 있음.\n[정답]", "2": "존엄한 존재로 대우받을 권리는 노인이 인격적으로 존중받아야 함을 강조하며, 직접적으로 권리 보호의 필요성을 나타내는 표현이다.", "3": "질 높은 생활서비스를 받을 권리는 노인의 생활 수준을 보장받는 것과 관련이 있지만 직접적인 윤리강령을 설명하지는 않음.", "4": "신체구속을 받지 않을 권리는 노인의 신체적 자유를 강조하지만, 질문의 내용과는 연결되지 않음.", "5": "개인적 견해를 표현하고 해결을 요구할 권리는 중요한 권리이지만, 윤리강령의 주제와는 잘 어울리지 않는다."}'::jsonb, '[{"term_ko": "윤리강령", "term_vi": "Quy tắc đạo đức", "def_ko": "도덕적 원칙을 규정한 규칙", "def_vi": "quy tắc quy định nguyên tắc đạo đức"}, {"term_ko": "사생활", "term_vi": "Đời sống riêng tư", "def_ko": "개인의 비밀", "def_vi": "bí mật cá nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (742, '3', '노인이나 가족이 건강상태와 치료, 돌봄, 제반 서비스에 관한 정보와 기록을 요구할 때 허용해야 하며, 타인에게 정보를 제공해서는 안된다.''고 규정한 시설 생활노인의 윤리강령은?', '["존엄한 존재로 대우받을 권리", "사생활과 비밀 보장에 대한 권리", "개별화된 서비스를 제공받고 선택할 수 있는 권리", "개인적 견해를 표현하고 해결을 요구할 권리", "차별 및 노인학대를 받지 않을 권리"]'::jsonb, 2, '노인과 그 가족이 필요한 정보를 요구할 권리를 이해하고, 이와 관련된 윤리강령의 내용을 평가하기 위함입니다.', NULL, '{"1": "존엄한 존재로 대우받을 권리는 노인의 가치와 존엄성을 강조합니다.\n[정답]", "2": "사생활과 비밀 보장에 대한 권리는 정보 보호의 중요성을 명확히 합니다.", "3": "개별화된 서비스를 제공받고 선택할 수 있는 권리는 개인 맞춤형 서비스를 의미합니다.", "4": "개인적 견해를 표현하고 해결을 요구할 권리는 의견 표출의 자유를 포함합니다.", "5": "차별 및 노인학대를 받지 않을 권리는 기본적인 인권 보장을 나타냅니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "늙은 사람", "def_vi": "Người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (741, '3', '다음은 시설 생활노인의 어떤 권리를 위반한 내용인가?나씨 할머니는 외부에서 시설 방문을 왔다면서 자기들 맘대로 사진을 찍거나 방에 불쑥불쑥 들어와 구경하고 나가는 것을 보면 매우 불쾌하다고 하신다.', '["질 높은 생활서비스를 받을 권리", "안전한 생활을 제공받을 권리", "신체구속을 받지 않을 권리", "사생활과 비밀보장에 대한 권리", "개인적 견해를 표현하고 해결을 요구할 권리"]'::jsonb, 4, '노인의 권리와 관련된 이해도를 확인하기 위한 문제입니다.', NULL, '{"1": "질 높은 생활서비스를 받을 권리는 노인이 기본적으로 누려야 할 권리이지만, 이 문제에서는 해당되지 않습니다.", "2": "안전한 생활을 제공받을 권리는 중요하지만, 이 경우와 직접적인 연관이 없습니다.", "3": "신체구속을 받지 않을 권리는 타인의 간섭 여부와는 관련이 적습니다.\n[정답]", "4": "사생활과 비밀보장에 대한 권리는 해당 노인이 외부인의 불쾌감을 느끼는 이유와 직접적인 관련이 있습니다.", "5": "개인적 견해를 표현하고 해결을 요구할 권리는 노인이 의견을 표현하는 것을 다루지만, 사례의 핵심은 사생활입니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền lợi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (740, '3', '다음과 같은 사례에서 요양보호사의 대처방법으로 옳은 것은?송씨 할아버지는 평생을 온돌에서 생활하셨는데, 시설에서 무조건 침대를 쓰라고 한다면서, 떨어질까 겁도 나고 불편해서 잠이 안 온다고 투덜거리신다.', '["며칠 지나면 다른 분들처럼 곧 적응되실 거예요.", "참으셔야죠. 자꾸 그러시면 저희가 돌보기 힘들어요.", "저도 어쩔 수가 없네요. 다른 시설을 알아봐 드릴까요?", "불편하시죠? 온돌방이 있는지 알아볼게요.", "어르신, 여기서는 무조건 침대생활을 해야 돼요."]'::jsonb, 4, '요양보호사가 환자의 감정을 이해하고 존중하는 대처 방법을 평가하기 위한 문제입니다.', NULL, '{"1": "며칠 지나면 적응된다며 환자의 불안과 불편을 무시하는 접근입니다.\n[정답]", "4": "환자의 불편함을 인정하고 해결책을 모색하는 긍정적인 접근입니다.", "3": "다른 시설을 알아보겠다는 말은 현 상황을 부정적으로 인식하게 만듭니다.", "5": "무조건 침대생활을 해야 한다는 강압적 태도는 환자의 감정을 상해할 수 있습니다.", "2": "참으셔야 한다고 말하는 것은 환자의 기분을 고려하지 않은 접근입니다."}'::jsonb, '[{"term_ko": "대처방법", "term_vi": "Cách giải quyết", "def_ko": "처리 방법(한국어)", "def_vi": "Phương pháp xử lý"}, {"term_ko": "불편", "term_vi": "Khó chịu", "def_ko": "불편함(한국어)", "def_vi": "Sự khó chịu"}, {"term_ko": "온돌", "term_vi": "Sàn sưởi", "def_ko": "온돌 시스템(한국어)", "def_vi": "Hệ thống sưởi sàn"}, {"term_ko": "적응", "term_vi": "Thích nghi", "def_ko": "적응하다(한국어)", "def_vi": "Thích nghi"}, {"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "시설(한국어)", "def_vi": "Cơ sở"}, {"term_ko": "어르신", "term_vi": "Người lớn tuổi", "def_ko": "노인(한국어)", "def_vi": "Người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (739, '3', '다음 내용에서 어르신이 요구할 수 있는 권리는?(거울을 보며 머리를 만지면서) "아무리 늙고 병들었다고 해도 머리를 이렇게 남자같이 짧게 깎아 놨어!"라고 말하며 요양보호사에게 화를 내신다.', '["신체구속을 받지 않을 권리", "충분한 정보를 제공받을 권리", "사생활과 비밀 보장에 대한 권리", "개별화된 서비스를 제공받고 선택할 수 있는 권리", "안락하고 안전한 생활환경을 제공받을 권리"]'::jsonb, 4, '어르신들이 요양서비스를 받을 때, 자신이 원하는 모습이나 서비스를 선택할 수 있는 권리가 중요함을 확인하기 위한 문제임.', NULL, '{"1": "신체구속을 받지 않을 권리: 어르신이 원하지 않는 신체적인 제약을 받지 않을 권리입니다.", "2": "충분한 정보를 제공받을 권리: 필요한 정보를받아 자신의 상황에 대해 이해할 수 있는 권리입니다.", "3": "사생활과 비밀 보장에 대한 권리: 개인의 사생활과 비밀이 보장되어야 함을 나타냅니다.\n[정답]", "4": "개별화된 서비스를 제공받고 선택할 수 있는 권리: 어르신이 원하는 대로 자신의 머리 스타일을 선택할 수 있는 권리입니다.", "5": "안락하고 안전한 생활환경을 제공받을 권리: 안전하고 편안한 환경에서 생활할 권리를 의미합니다."}'::jsonb, '[{"term_ko": "어르신", "term_vi": "Người cao tuổi", "def_ko": "노인", "def_vi": "Người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (738, '2', '다음 중 요양보호사의 역할이 바르게 연결된 것은?', '["옹호자 - 숙련된 기술로 대상자의 불편함을 경감하기 위해 돕는다.", "관찰자 - 대상자가 능력을 최대한 발휘하여 스스로 할 수 있도록 격려한다.", "동기 유발자 - 호흡곤란, 피부 발진이 생기는지 살펴본다.", "정보 전달자 - 대상자의 신체, 심리적 상태변화를 의료진에게 전달한다.", "말벗과 상담자 - 소외되고 차별받는 대상자의 입장에서 편들어 주고 지켜준다."]'::jsonb, 4, '요양보호사의 다양한 역할 중 바른 연결을 찾기 위한 문제입니다.', NULL, '{"1": "옹호자는 대상자의 불편함을 경감하기 위해 도와주는 역할이 아닙니다. 이는 ''말벗과 상담자''의 역할에 가깝습니다.\n[정답]", "4": "정보 전달자는 대상자의 신체 및 심리적 상태 변화를 의료진에게 전달하는 중요한 역할을 수행합니다.", "3": "동기 유발자는 건강 상태를 관찰하는 역할이 아니며, 주로 대상자의 의욕을 높이는 역할입니다.", "2": "관찰자는 주로 대상자가 능력을 최대한 발휘하도록 격려하는 역할이 아닙니다. 이는 ''동기 유발자''의 역할에 해당합니다.", "5": "말벗과 상담자는 소외된 대상을 편들어 주기보다 의사소통과 정서적 지지를 제공합니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "요양 서비스를 제공하는 사람", "def_vi": "Người cung cấp dịch vụ chăm sóc"}, {"term_ko": "역할", "term_vi": "Vai trò", "def_ko": "맡은 기능이나 일", "def_vi": "Chức năng đảm nhận"}, {"term_ko": "옹호자", "term_vi": "Người bảo vệ", "def_ko": "권리를 지키고 보호하는 사람", "def_vi": "Người bảo vệ và bảo vệ quyền lợi"}, {"term_ko": "정보 전달자", "term_vi": "Người truyền thông", "def_ko": "정보를 전달하는 사람", "def_vi": "Người chuyển tải thông tin"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (737, '2', '소외되고 차별 받는 대상자를 위해 편들어 주고 지켜주는 요양보호사의 역할은?', '["옹호자", "관찰자", "숙련된 수발자", "동기 유발자", "정보 전달자"]'::jsonb, 1, '요양보호사의 역할 중 소외되거나 차별받는 대상자를 위해 그들을 지지하고 보호하는 방식에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "옹호자: 소외된 대상자를 위해 그들의 권리를 지키고 지지하는 역할을 하므로 정답입니다.\n[정답]", "2": "관찰자: 단순히 관찰하는 사람으로서의 역할을 나타내며 옹호와는 거리가 멉니다.", "3": "숙련된 수발자: 기술적 지원이 주요 역할이지 대상자를 지키는 것은 아닙니다.", "4": "동기 유발자: 격려하거나 동기를 부여하는 역할에 해당하지만 보호의 개념은 포함되지 않습니다.", "5": "정보 전달자: 정보를 제공하는 역할이지 직접적인 보호와는 관련이 없습니다."}'::jsonb, '[{"term_ko": "옹호자", "term_vi": "Người bảo vệ", "def_ko": "권리를 지키고 지원하는 사람", "def_vi": "Người bảo vệ quyền lợi và hỗ trợ"}, {"term_ko": "관찰자", "term_vi": "Người quan sát", "def_ko": "단순히 지켜보는 사람", "def_vi": "Người chỉ theo dõi"}, {"term_ko": "숙련된 수발자", "term_vi": "Người chăm sóc có tay nghề", "def_ko": "기술적으로 지원하는 사람", "def_vi": "Người cung cấp sự hỗ trợ kỹ thuật"}, {"term_ko": "동기 유발자", "term_vi": "Người khuyến khích động lực", "def_ko": "격려하고 동기를 주는 사람", "def_vi": "Người tạo động lực"}, {"term_ko": "정보 전달자", "term_vi": "Người cung cấp thông tin", "def_ko": "정보를 제공하는 사람", "def_vi": "Người cung cấp thông tin"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (736, '2', '다음 사례에서 요양보호사의 수행역할로 옳은 것은?편마비 환자가 잔존기능을 최대한 발휘할 수 있도록 요양보호사가 지지를 하였더니, 환자 스스로 식사와 옷 입기를 할 수 있게 되었다.', '["관찰자", "옹호자", "중재자", "동기 유발자", "정보 전달자"]'::jsonb, 4, '요양보호사가 제공해야 하는 지원의 종류와 역할을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "관찰자: 요양보호사로서 환자의 상태를 관찰하는 역할을 하며, 직접적인 지원은 포함되지 않습니다.\n[정답]", "2": "옹호자: 환자의 권리와 요구를 지지하고 보호하는 역할이지만, 사례에서는 동기 부여가 주된 내용입니다.", "3": "중재자: 문제 해결을 위한 조정자 역할이나 이번 사례와는 직접적인 관련이 없습니다.", "4": "동기 유발자: 환자가 스스로 능동적으로 활동하도록 동기를 부여하는 역할로, 사례와 잘 맞습니다.", "5": "정보 전달자: 필요한 정보를 제공하는 역할로, 이번 사례에서는 주로 동기 부여에 중점을 두고 있습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "직접적인 돌봄을 제공하는 사람", "def_vi": "Người trực tiếp cung cấp sự chăm sóc"}, {"term_ko": "편마비", "term_vi": "Liệt nửa", "def_ko": "한쪽 몸의 기능이 저하된 상태", "def_vi": "Tình trạng giảm chức năng của một bên cơ thể"}, {"term_ko": "잔존기능", "term_vi": "Chức năng còn lại", "def_ko": "남아있는 기능", "def_vi": "Chức năng còn tồn tại"}, {"term_ko": "지지", "term_vi": "Hỗ trợ", "def_ko": "지원, 도움", "def_vi": "Sự hỗ trợ"}, {"term_ko": "동기 유발자", "term_vi": "Người khơi dậy động lực", "def_ko": "스스로 행동하도록 하는 사람", "def_vi": "Người khuyến khích tự hành động"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (735, '2', '다음 중 요양보호사의 역할로 옳은 것은?신체활동지원서비스나 일상생활지우너서비스 등을 제공하는 것에 그치지 않고 대상자가 능력을 최대한 발휘하도록 지지한다.', '["정보 전달자", "관찰자", "동기 유발자", "옹호자", "말벗과 상담자"]'::jsonb, 3, '요양보호사의 역할에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "정보 전달자는 정보와 지식을 제공하는 역할을 합니다.\n[정답]", "3": "동기 유발자는 대상자가 스스로의 능력을 최대한 발휘하도록 격려하고 지지하는 역할을 합니다.", "2": "관찰자는 대상자의 상태를 주의 깊게 살피고 기록하는 역할입니다.", "4": "옹호자는 대상자의 권리와 이익을 보호하기 위해 노력하는 역할입니다.", "5": "말벗과 상담자는 정서적 지지를 제공하는 역할을 합니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인을 포함한 환자를 보살피는 전문 직업", "def_vi": "Nghề chăm sóc bệnh nhân, bao gồm cả người già"}, {"term_ko": "역할", "term_vi": "Vai trò", "def_ko": "어떤 일을 수행하는 직무나 기능", "def_vi": "Nhiệm vụ hoặc chức năng thực hiện một công việc"}, {"term_ko": "동기", "term_vi": "Động lực", "def_ko": "어떤 일을 하도록 이끄는 내적 요인", "def_vi": "Yếu tố bên trong thúc đẩy một hoạt động"}, {"term_ko": "지지", "term_vi": "Hỗ trợ", "def_ko": "도움을 주는 것, 또는 지지하는 행동", "def_vi": "Hành động giúp đỡ ai đó"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (734, '2', '대상자와 관게를 형성하고 서비스를 제공하여 대상자의 신체적, 정신적, 심리적 안위를 도모하는 요양보호사의 역할은?', '["정보 전달자", "관찰자", "숙련된 수발자", "말벗과 상담자", "동기 유발자"]'::jsonb, 4, '요양보호사의 역할을 이해하고 관련된 개념을 확인하는 것입니다.', NULL, '{"1": "정보 전달자는 주로 정보를 제공하는 역할을 합니다.\n[정답]", "4": "말벗과 상담자는 대상자와 관계를 형성하며 그들의 심리적 안위를 도모하는 데 중점을 둡니다.", "2": "관찰자는 대상자의 상태를 관찰하고 기록하는 역할을 합니다.", "3": "숙련된 수발자는 신체적 도움이 필요한 경우 직접적인 돌봄을 제공하는 역할을 합니다.", "5": "동기 유발자는 대상자의 동기를 높이려는 역할을 수행합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자, 수혜자", "def_vi": "Bệnh nhân, người nhận dịch vụ"}, {"term_ko": "관계", "term_vi": "Mối quan hệ", "def_ko": "상호작용, 소통", "def_vi": "Tương tác, giao tiếp"}, {"term_ko": "안위", "term_vi": "An nguy", "def_ko": "안전과 행복", "def_vi": "An toàn và hạnh phúc"}, {"term_ko": "상담자", "term_vi": "Người tư vấn", "def_ko": "조언을 주는 사람", "def_vi": "Người cho lời khuyên"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (733, '2', '맥박, 호흡, 체온, 혈압 등의 건강상태와 심리적인 변화까지 관찰하여 증상을 완화하고, 합병증을 예방하는 요양보호사의 역할은?', '["정보 전달자 역할", "관찰자 역할", "숙련된 수발자 역할", "동기 유발자 역할", "옹호자 역할"]'::jsonb, 2, '요양보호사의 역할 중 건강상태와 심리적인 변화를 관찰하는 것을 강조하기 위함입니다.', NULL, '{"1": "정보 전달자 역할: 정보를 전달하는 역할이지만, 관찰의 중요성을 포함하지 않습니다.\n[정답]", "2": "관찰자 역할: 건강상태와 심리적인 변화를 관찰하여 증상을 완화하고 합병증을 예방하는 역할입니다.", "3": "숙련된 수발자 역할: 수발의 숙련도를 강조하지만 관찰 역할은 포함되어 있지 않습니다.", "4": "동기 유발자 역할: 환자의 동기를 유발하려는 역할은 관찰과는 관련이 없습니다.", "5": "옹호자 역할: 환자의 권리를 옹호하는 역할이나 관찰 기능은 아닙니다."}'::jsonb, '[{"term_ko": "맥박", "term_vi": "Mạch", "def_ko": "맥박(한국어)", "def_vi": "Mạch đập(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (732, '2', '다음 내용에 해당하는 요양보호사의 역할로 옳은 것은?대상자의 신체, 심리에 관한 정보를 가족, 시설장, 의료진에게 전달하며 필요 시 지시사항을 대상자와 가족에게 전달한다.', '["정보 전달자 역할", "관찰자 역할", "숙련된 수발자 역할", "말벗과 상담자 역할", "동기 유발자 역할"]'::jsonb, 1, '요양보호사의 역할 중에서 적절한 정보를 전달하는 기능에 대한 이해를 요구하는 문제입니다.', NULL, '{"1": "정보 전달자 역할: 대상자의 신체, 심리에 관한 정보를 전달하는 역할을 정확히 설명합니다.\n[정답]", "2": "관찰자 역할: 대상자의 상태를 관찰하는 역할이지만, 정보 전달과는 직접 관련이 없습니다.", "3": "숙련된 수발자 역할: 신체적 돌봄을 강조하는 역할로 정보 전달과는 관련이 없습니다.", "4": "말벗과 상담자 역할: 정서적 지지를 제공하지만 정보 전달과는 다릅니다.", "5": "동기 유발자 역할: 대상자를 격려하고 동기를 부여하지만 정보 전달에는 해당하지 않습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 직업", "def_vi": "Nghề chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (731, '2', '다음 중 요양보호사의 역할로 옳은 것은?숙련된 요양보호서비스에 대한 지식과 기술로 필요한서비스를 지원하여 대상자를 도와준다.', '["정보 전달자", "관찰자", "숙련된 수발자", "상담자", "동기 유발자"]'::jsonb, 3, '요양보호사의 역할에 대한 이해를 평가하고자 함.', NULL, '{"1": "정보 전달자는 정보를 제공하는 역할이나, 요양보호사의 주 역할이 아니다.\n[정답]", "3": "숙련된 수발자는 요양보호사의 핵심 역할로, 숙련된 기술로 환자를 지원하는 것이 중요하다.", "2": "관찰자는 환자의 상태를 관찰하는 역할이지만, 수발자의 역할이 더 강조된다.", "4": "상담자는 주로 심리적 지원을 제공하는 역할이지만, 이는 요양보호사의 보조적인 역할이다.", "5": "동기 유발자는 환자의 동기를 부여하는 역할이나, 요양보호사의 주요 책임은 아니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (730, '2', '요양보호사 자격 취소 사유에 해당되지 않는 것은?', '["자격증을 대여, 양도 또는 위조, 변조한 경우", "노인에 대한 금지행위를 위반하여 처벌받은 경우", "영리를 목적으로 요양서비스를 알선, 유인한 경우", "거짓이나 부정한 방법으로 자격증을 취득한 경우", "대상자의 욕구에 맞는 장기요양서비스를 제공한 경우"]'::jsonb, 5, '요양보호사 자격 취소 사유에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "자격증을 대여, 양도 또는 위조, 변조한 경우는 자격 취소 사유입니다.\n[정답]", "5": "대상자의 욕구에 맞는 장기요양서비스를 제공한 경우는 자격 취소 사유에 해당하지 않습니다.", "2": "노인에 대한 금지행위를 위반하여 처벌받은 경우는 자격 취소 사유입니다.", "3": "영리를 목적으로 요양서비스를 알선, 유인한 경우는 자격 취소 사유입니다.", "4": "거짓이나 부정한 방법으로 자격증을 취득한 경우는 자격 취소 사유입니다."}'::jsonb, '[{"term_ko": "자격증", "term_vi": "Chứng chỉ", "def_ko": "증명서(한국어)", "def_vi": "Giấy chứng nhận"}, {"term_ko": "대여", "term_vi": "Cho thuê", "def_ko": "빌려주는 것(한국어)", "def_vi": "Cho mượn"}, {"term_ko": "양도", "term_vi": "Chuyển nhượng", "def_ko": "양도하는 것(한국어)", "def_vi": "Chuyển nhượng"}, {"term_ko": "위조", "term_vi": "Làm giả", "def_ko": "가짜로 만드는 것(한국어)", "def_vi": "Làm giả"}, {"term_ko": "변조", "term_vi": "Sửa đổi", "def_ko": "수정하는 것(한국어)", "def_vi": "Sửa đổi"}, {"term_ko": "금지행위", "term_vi": "Hành vi cấm", "def_ko": "금지된 행동(한국어)", "def_vi": "Hành vi bị cấm"}, {"term_ko": "처벌", "term_vi": "Xử phạt", "def_ko": "벌을 받는 것(한국어)", "def_vi": "Bị xử phạt"}, {"term_ko": "영리", "term_vi": "Lợi nhuận", "def_ko": "이익을 추구하는 것(한국어)", "def_vi": "Tìm kiếm lợi nhuận"}, {"term_ko": "알선", "term_vi": "Môi giới", "def_ko": "중개하는 것(한국어)", "def_vi": "Đảm bảo"}, {"term_ko": "유인", "term_vi": "Dụ dỗ", "def_ko": "끌어모으는 것(한국어)", "def_vi": "Thu hút"}, {"term_ko": "거짓", "term_vi": "Giả", "def_ko": "사실이 아닌 것(한국어)", "def_vi": "Giả"}, {"term_ko": "부정한", "term_vi": "Bất hợp pháp", "def_ko": "불법적인(한국어)", "def_vi": "Bất hợp pháp"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "필요한 것(한국어)", "def_vi": "Nhu cầu"}, {"term_ko": "장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "긴 기간의 관리 서비스(한국어)", "def_vi": "Dịch vụ chăm sóc dài hạn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (729, '2', '노인장기요양보험법 상 요양보호사가 1년 동안 장기요양급여를 제공 할 수 없는 경우는?', '["업무 수행능력이 저하되었다.", "업무상의 어려움을 시설장에게 전달하였다.", "동료와 경험을 공유하며 서로 지지해 주었다.", "대상자의 요구로 시간을 초과하여 서비스를 제공하였다.", "부정한 방법으로 장기요양급여비용을 청구하는 행위에 가담하였다."]'::jsonb, 5, '요양보호사가 장기요양급여를 제공할 수 없는 상황을 이해하고 파악하는 것을 의도함.', NULL, '{"1": "업무 수행능력이 저하되었다. - 요양보호사의 능력 저하가 서비스 제공 여부에 영향을 미칠 수 있지만 장기요양급여 중단 사유는 아님.\n[정답]", "5": "부정한 방법으로 장기요양급여비용을 청구하는 행위에 가담하였다. - 이는 법적인 문제로, 장기요양급여 제공을 받을 수 없게 되는 명백한 사유임.", "2": "업무상의 어려움을 시설장에게 전달하였다. - 어려움이 있을 때는 공유하는 것이 바람직하며, 문제를 해결할 수 있는 방향으로 나아가는 행동임.", "3": "동료와 경험을 공유하며 서로 지지해 주었다. - 동료 간의 지지와 협력은 서비스 품질을 높이는 긍정적인 행동임.", "4": "대상자의 요구로 시간을 초과하여 서비스를 제공하였다. - 대상자의 요구에 따른 추가 서비스 제공은 긍정적인 행동이며, 서비스 제공에 문제가 되지 않음."}'::jsonb, '[{"term_ko": "장기요양보험법", "term_vi": "Luật bảo hiểm chăm sóc dài hạn", "def_ko": "장기요양보험에 관한 법률", "def_vi": "Luật liên quan đến bảo hiểm chăm sóc dài hạn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (728, '2', '다음 중 요양보호사의 금지행위에 해당하는 것으로 옳은 것은?가. 노인학대 신고 나. 수급자 유인 알선행위 다. 부당수급 관련 행위 라. 개인정보 비밀유지 마. 급여제공자료 거짓 작성 바. 본인부담금 면제 및 감경', '["가,나,다,라", "가,나,다,마", "나,다,마,바", "나,다,라,마", "나,다,라,바"]'::jsonb, 3, '요양보호사의 금지행위를 이해하고 이를 식별하는 능력을 평가하기 위해 출제된 문제이다.', NULL, '{"1": "노인학대 신고는 법적 의무로, 금지행위가 아니다.\n[정답]", "2": "수급자 유인 알선행위는 금지행위에 해당한다.", "3": "부당수급 관련 행위는 금지행위에 해당한다.", "4": "개인정보 비밀유지는 요양보호사로서 지켜야 할 의무이다.", "5": "급여제공자료 거짓 작성은 금지행위에 해당한다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인과 장애인을 돌봐주는 전문직", "def_vi": "Nghề chuyên chăm sóc người cao tuổi và người khuyết tật"}, {"term_ko": "금지행위", "term_vi": "Hành vi bị cấm", "def_ko": "법적으로 금지된 행동", "def_vi": "Hành động bị cấm theo luật pháp"}, {"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "고령자에 대한 폭력이나 학대", "def_vi": "Bạo lực hoặc ngược đãi đối với người cao tuổi"}, {"term_ko": "부당수급", "term_vi": "Nhận phúc lợi không chính đáng", "def_ko": "불법적인 방법으로 이익을 취하는 것", "def_vi": "Có lợi ích theo cách bất hợp pháp"}, {"term_ko": "개인정보", "term_vi": "Thông tin cá nhân", "def_ko": "개인의 사생활에 관한 정보", "def_vi": "Thông tin liên quan đến đời sống riêng tư của cá nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (727, '2', '시설에서 응급상황 발생하였을 때 대처방법으로 옳은 것은?', '["대상자를 가급적 빨리 옮긴다.", "나이가 많은 대상자부터 처치한다.", "긴급을 요하는 대상자 순으로 처치한다.", "대상자를 발견한 순서대로 처치한다.", "대상자에게 손상을 입힌 화학약품은 즉시 버린다."]'::jsonb, 3, '응급상황에서의 올바른 대처 방법에 대한 이해를 확인하기 위함입니다.', NULL, '{"1": "대상자를 가급적 빨리 옮기는 것은 위험할 수 있습니다. 응급처치는 상황에 따라 다르게 진행되어야 합니다.\n[정답]", "3": "긴급을 요하는 대상자 순으로 처치하는 것이 최선의 방법입니다.", "2": "나이가 많은 대상자부터 처치하는 것은 옳지 않은 판단입니다.", "4": "대상자를 발견한 순서대로 처치하는 것은 비효율적입니다.", "5": "손상을 입힌 화학약품은 안전한 방법으로 처리해야 하며 즉시 버리는 것은 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "응급상황", "term_vi": "Tình huống khẩn cấp", "def_ko": "긴급한 상황(한국어)", "def_vi": "Tình huống gấp gáp(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (726, '2', '요양보호사의 요양업무 수행 내용으로 옳은 것은?', '["작업치료", "외상 처치", "관절운동범위 평가", "복지용구 이용도움", "유치도뇨관 삽입"]'::jsonb, 4, '요양보호사의 요양업무 수행 내용에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "작업치료는 주로 치료사에 의해 수행됩니다.\n[정답]", "4": "복지용구 이용도움은 요양보호사의 중요한 업무입니다.", "2": "외상 처치는 기본적으로 전문의료진의 역할입니다.", "3": "관절운동범위 평가는 재활 전문직에 의한 평가입니다.", "5": "유치도뇨관 삽입은 전문적인 의료행위에 해당합니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "요양업무", "term_vi": "Nhiệm vụ chăm sóc", "def_ko": "환자를 돌보는 업무", "def_vi": "Nhiệm vụ chăm sóc bệnh nhân"}, {"term_ko": "복지용구", "term_vi": "Thiết bị phúc lợi", "def_ko": "필요한 복지 장비", "def_vi": "Thiết bị cần thiết cho phúc lợi"}, {"term_ko": "작업치료", "term_vi": "Liệu pháp nghề nghiệp", "def_ko": "특정 작업을 통해 치료하는 방법", "def_vi": "Phương pháp điều trị thông qua công việc"}, {"term_ko": "외상 처치", "term_vi": "Xử lý tổn thương", "def_ko": "부상의 치료", "def_vi": "Việc điều trị cho các vết thương"}, {"term_ko": "관절운동범위", "term_vi": "Phạm vi chuyển động khớp", "def_ko": "관절의 운동 범위", "def_vi": "Phạm vi hoạt động của khớp"}, {"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "소변을 배출하기 위한 관", "def_vi": "Ống dùng để thải nước tiểu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (725, '2', '요양보호사가 제공할 수 있는 서비스로 옳은 것은?', '["드레싱", "도뇨처치", "투약 및 주사", "비위관 삽입", "관절구축 예방"]'::jsonb, 5, '요양보호사가 제공할 수 있는 서비스에 대한 이해를 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "드레싱: 요양보호사가 수행할 수 없는 전문적인 간호행위입니다.\n[정답]", "5": "관절구축 예방: 요양보호사가 제공할 수 있는 서비스 중 하나로, 환자의 운동과 관절 유지를 도와줍니다.", "2": "도뇨처치: 의료인이 수행해야 하는 전문적인 처치입니다.", "3": "투약 및 주사: 요양보호사의 업무 범위를 넘어서는 행위입니다.", "4": "비위관 삽입: 전문적인 의료 기술이 필요한 행위로 요양보호사가 수행할 수 없습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "dịch vụ chăm sóc", "def_ko": "돌봄 제공자", "def_vi": "dịch vụ chăm sóc mà người chăm sóc có thể cung cấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (724, '2', '요양보호사는 모든 의료행위를 하지 않아야한다. 다음 중 의료행위에 속하는 것들을 고르시오.가.도뇨 나.흡인 다.관장 라.욕창관리 마.경구약 및 외용약투약', '["가.나.다.마", "가.다.마", "나.라.마", "나.다.라.마", "가.나.다.라"]'::jsonb, 5, '요양보호사가 수행하지 않아야 할 의료행위를 이해하고 구분하기 위함입니다.', NULL, '{"1": "도뇨와 흡인, 관장은 의료행위에 해당하지만, 욕창관리와 경구약 및 외용약투약은 비의료행위입니다.\n[정답]", "5": "도뇨, 흡인, 관장, 욕창관리 전부가 의료행위에 속합니다.", "2": "의료행위에 해당하는 도뇨, 관장을 포함하나, 욕창관리는 비의료행위입니다.", "3": "흡인을 포함하고 있으나, 도뇨와 관장은 의료행위입니다.", "4": "흡인, 관장, 욕창관리가 포함돼 의료행위에 해당합니다."}'::jsonb, '[{"term_ko": "의료행위", "term_vi": "Hành động y tế", "def_ko": "환자에 대한 진료와 치료를 수행하는 행위", "def_vi": "Hành động điều trị và chăm sóc bệnh nhân."}, {"term_ko": "도뇨", "term_vi": "Thông tiểu", "def_ko": "방광 내 소변을 비워내기 위한 의료행위", "def_vi": "Hành động y tế để làm rỗng bàng quang."}, {"term_ko": "흡인", "term_vi": "Hút", "def_ko": "기도에서 분비물을 제거하는 의료행위", "def_vi": "Hành động y tế để loại bỏ dịch trong đường hô hấp."}, {"term_ko": "관장", "term_vi": "Thụt", "def_ko": "배변을 유도하기 위한 의료행위", "def_vi": "Hành động y tế để kích thích đại tiện."}, {"term_ko": "욕창관리", "term_vi": "Chăm sóc loét", "def_ko": "욕창으로 인한 상처를 예방하고 관리하는 비의료행위", "def_vi": "Hành động không phải y tế để phòng ngừa và kiểm soát vết thương do loét."}, {"term_ko": "경구약", "term_vi": "Thuốc uống", "def_ko": "입으로 복용하는 약물", "def_vi": "Thuốc dùng qua đường miệng."}, {"term_ko": "외용약", "term_vi": "Thuốc bôi", "def_ko": "피부에 바르는 약물", "def_vi": "Thuốc dùng cho da."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (723, '2', '요양보호서비스 제공 시 요양보호사가 지켜야 할 원칙으로 옳은 것은?', '["서비스 제공 전 대상자의 성격, 습관 등 상태를 파악한다.", "대상자의 보호자에게도 서비스를 제공한다.", "대상자를 수동적인 존재로 간주한다.", "대상자의 미미한 상태변화는 기록을 생략한다.", "대상자의 상태가 달라지면 요양보호사가 서비스를 조정한다."]'::jsonb, 1, '요양보호서비스 제공 시 요양보호사가 지켜야 할 원칙을 이해하고 있는지를 평가하고자 하였다.', NULL, '{"1": "서비스 제공 전 대상자의 성격, 습관 등 상태를 파악한다. 이 원칙은 요양보호사가 대상자의 개인적 특성을 이해하여 적절한 서비스를 제공하기 위해 반드시 지켜야 하는 사항이다.\n[정답]", "2": "대상자의 보호자에게도 서비스를 제공한다. 보호자에게 서비스 제공은 원칙이 아니다. 대상자가 중심이 되어야 한다.", "3": "대상자를 수동적인 존재로 간주한다. 이는 옳지 않으며, 대상자는 적극적인 참여가 필요하다.", "4": "대상자의 미미한 상태변화는 기록을 생략한다. 모든 상태변화는 기록되어야 한다.", "5": "대상자의 상태가 달라지면 요양보호사가 서비스를 조정한다. 서비스 조정은 필요한 사항이지만 이 보기 자체가 서비스 제공 원칙이 아니다."}'::jsonb, '[{"term_ko": "요양보호서비스", "term_vi": "Dịch vụ chăm sóc", "def_ko": "돌봄 서비스", "def_vi": "Dịch vụ chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (722, '2', '요양보호사가 서비스 제공 시 지켜야 할 기본원칙으로 옳은 것은?', '["대상자의 잔존능력을 최대한 활용한다.", "치매 대상자는 보호자 동의 없이 서비스를 제공한다.", "서비스를 제공하기 전에 보호자의 특성을 확인한다.", "서비스 제공 중 응급상황이 발생하면 알아서 처치한다.", "대상자의 사생활에 대해 자유롭게 이야기한다."]'::jsonb, 1, '요양보호사가 서비스를 제공할 때 준수해야 할 기본적인 원칙을 이해하고 있는지를 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "대상자의 잔존능력을 최대한 활용하는 것은 요양보호사가 반드시 지켜야 할 기본 원칙이므로 올바른 진술입니다.\n[정답]", "2": "치매 대상자는 보호자 동의 없이 서비스를 제공하면 안 되므로 잘못된 진술입니다.", "3": "서비스 제공 전에 보호자의 특성을 확인하는 것은 중요하지만, 기본 원칙으로 명시되지 않았습니다.", "4": "서비스 제공 중 응급상황이 발생하면 보호자와 상의하여 적절히 대처해야 하므로 잘못된 진술입니다.", "5": "대상자의 사생활에 대해 자유롭게 이야기하는 것은 프라이버시를 존중하지 않는 행위로 잘못된 진술입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 보호하고 돌보는 직업", "def_vi": "Nghề bảo vệ và chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (721, '2', '요양보호서비스 제공의 기본원칙으로 옳은 것은?', '["요양보호사 중심으로 서비스를 제공한다.", "대상자의 상태를 관찰하면서 서비스를 제공한다.", "중요한 서비스는 설명 없이 제공한다.", "서비스를 변경할 때에는 요양보호사가 혼자서 결정한다.", "응급 상황 시 우선순위에 따라 의료 행위를 한다."]'::jsonb, 2, '요양보호서비스 제공의 기본적인 원칙을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "요양보호사는 대상자의 상태를 고려하여 서비스를 제공해야 하므로 요양보호사 중심으로 서비스를 제공하는 것은 옳지 않습니다.\n[정답]", "2": "대상자의 상태를 관찰하면서 서비스를 제공하는 것은 요양보호서비스의 기본 원칙 중 하나입니다.", "3": "중요한 서비스는 반드시 대상자에게 설명한 후 제공해야 합니다.", "4": "서비스 변경은 팀원 간의 협의 후 결정해야 하며, 요양보호사가 혼자서 결정하는 것은 올바르지 않습니다.", "5": "응급 상황에서도 절차에 따라 진행해야 하며, 의료 행위는 전문 인력에게 맡겨야 합니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌보는 사람", "def_vi": "Người chăm sóc cho người khác"}, {"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "서비스의 주체", "def_vi": "Người chủ trì dịch vụ"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "제공되는 돌봄", "def_vi": "Chăm sóc được cung cấp"}, {"term_ko": "응급 상황", "term_vi": "Tình huống khẩn cấp", "def_ko": "즉각적인 조치가 필요한 기급한 상황", "def_vi": "Tình huống cần hành động ngay lập tức"}, {"term_ko": "상태", "term_vi": "Tình trạng", "def_ko": "건강이나 처치 상황", "def_vi": "Tình hình sức khỏe hoặc chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (720, '2', '요양보호서비스 원칙에 대한 설명으로 옳은 것은?', '["대상자로부터 많지 않은 물질적 보상은 받아도 된다.", "치매 대상자에게 발생하는 돌발 상황은 가족들과 의논하여 처리한다.", "변비인 대상자가 관장을 요구하면 지체 없이 도움을 주어야한다.", "대상자의 가족과 의견이 상충될 때는 마찰을 피하고 요구를 들어 준다.", "대상자 외 가족의 세탁, 청소, 식사준비 등은 업무범위가 아니므로 해서는 안 된다."]'::jsonb, 5, '요양보호서비스의 원칙에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "대상자로부터 전혀 물질적 보상을 받지 않는 것이 원칙입니다.\n[정답]", "5": "대상자 외 가족의 업무는 요양보호사의 범위가 아닙니다.", "2": "가족과 상의하여 처리하는 것이 아니라 요양보호사가 직접 책임지고 처리해야 합니다.", "3": "변비인 대상자에게는 관장을 하는 것이 적절하지 않을 수 있습니다.", "4": "가족과의 의견이 상충할 경우, 대상자의 복지를 우선적으로 고려해야 합니다."}'::jsonb, '[{"term_ko": "요양보호서비스", "term_vi": "Dịch vụ chăm sóc", "def_ko": "돌봄을 제공하는 서비스", "def_vi": "Dịch vụ cung cấp sự chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (719, '2', '권리와 책임에 따른 급여제공 시 ㅇ양보호사의 준수 사항으로 옳은 것은?', '["제공인력이 변경되면 급여제공을 보류한다.", "매년 건강검진을 받고 건강관리를 철저히 한다.", "사고예방을 위해 개인적인 판단을 우선시한다.", "급여제공내용과 상태변화를 월별로 기록한다.", "학대나 기관의 부당행위에는 개입하지 않는다."]'::jsonb, 2, '요양보호사의 권리와 책임에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "제공인력이 변경되면 급여제공을 보류한다: 잘못된 내용입니다.\n[정답]", "2": "매년 건강검진을 받고 건강관리를 철저히 한다: 요양보호사는 정기적인 건강검진을 통해 자신의 건강을 관리해야 합니다.", "3": "사고예방을 위해 개인적인 판단을 우선시한다: 개인적인 판단이 아니라 전문가의 지침을 따라야 합니다.", "4": "급여제공내용과 상태변화를 월별로 기록한다: 기록은 중요하지만 월별 기록이 아닌 상황에 따라 필요할 때 기록해야 합니다.", "5": "학대나 기관의 부당행위에는 개입하지 않는다: 요양보호사는 그러한 상황에 개입하고 보고해야 합니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권한(한국어)", "def_vi": "quyền hạn(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (718, '2', '급여제공 계획과 기준에 근거한 급여제공 시 요양보호사의 준수사항으로 옳은 것은?', '["상황에 따라 보호자에게 필요한 급여를 제공한다.", "응급 상황이 발생하면, 임의로 판단하여 처리한다.", "수급자의 부당한 요구는 대가를 받고 들어준다.", "급여제공내용과 방법은 동료 요양보호사의 경험을 따른다.", "기관의 운영규정, 근로계약 내용, 급여제공기준을 숙지한다."]'::jsonb, 5, '급여제공 시 요양보호사가 준수해야 하는 사항을 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "상황에 따라 보호자에게 필요한 급여를 제공한다. (잘못된 내용입니다. 요양보호사는 정해진 기준에 따라 급여를 제공해야 합니다.)\n[정답]", "5": "기관의 운영규정, 근로계약 내용, 급여제공기준을 숙지한다. (정확한 내용으로, 요양보호사는 이러한 사항을 반드시 숙지해야 합니다.)", "3": "수급자의 부당한 요구는 대가를 받고 들어준다. (부당한 요구는 들어줄 수 없습니다.)", "4": "급여제공내용과 방법은 동료 요양보호사의 경험을 따른다. (개인의 경험에 의존하기보다는 기준에 따라야 합니다.)", "2": "응급 상황이 발생하면, 임의로 판단하여 처리한다. (임의로 판단하기보다는 정해진 절차에 따라야 합니다.)"}'::jsonb, '[{"term_ko": "급여제공", "term_vi": "Cung cấp dịch vụ", "def_ko": "제공하는 서비스", "def_vi": "Dịch vụ được cung cấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (717, '2', '요양보호사가 준수해야 할 수급자 중심의 급여제공으로 옳은 것은?', '["수급자의 경제적 능력을 파악하여 급여낸용을 변경한다.", "제공할 급여내용을 수급자의 요구대로 임의로 계약한다.", "수급자의 상태에 따라 급여시간을 자유롭게 조절한다.", "수급자의 개별적인 욕구를 반영하여 급여를 제공한다.", "급여제공기록지를 사전에 작성하여 수급자에게 확인을 받는다."]'::jsonb, 4, '수급자 중심의 급여 제공 원칙에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "수급자의 경제적 능력을 반영하여 급여내용은 변경될 수 있지만, 이는 수급자의 동의를 필요로 합니다.\n[정답]", "4": "수급자의 개별적인 욕구를 반영하여 급여를 제공하는 것이 핵심 원칙입니다.", "2": "제공할 급여내용은 수급자의 요구에 따라 임의로 계약할 수 없습니다.", "3": "수급자의 상태에 따라 급여시간은 조절하지만, 무작위로 조절할 수 없습니다.", "5": "급여제공기록지는 수급자의 확인을 받기 전에 작성하는 것이 일반적입니다."}'::jsonb, '[{"term_ko": "수급자", "term_vi": "Người thụ hưởng", "def_ko": "서비스 수혜자(한국어)", "def_vi": "Người nhận dịch vụ(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (716, '2', '다음 상황에서 요양보호사의 대처 방법으로 옳은 것은?대상자:며느리가 들어온 후 아들과도 사이가 멀어졌어. 친척들한테 말해도 며느리편만 들어서 속상해. 요양보호사: ( )', '["신경쓰지 말라고 말한다.", "옳고 그름에 대해 판단하여 말해준다.", "자신의 경험에 비추어 이해를 시킨다.", "이야기를 들어주되 가족관계에 관여하지 않는다.", "아들에게 대상자의 마음 상태를 알려준다."]'::jsonb, 4, '요양보호사가 대상자의 감정을 이해하고 보호하는 방법을 평가하기 위함입니다.', NULL, '{"1": "신경쓰지 말라고 말하는 것은 대상자의 감정을 무시하는 것으로 부적절합니다.\n[정답]", "2": "옳고 그름에 대해 판단하여 말해주는 것은 주관적인 판단을 포함하므로 바람직하지 않습니다.", "3": "자신의 경험에 비추어 이해를 시키는 것은 이야기의 상황에 따라 적절할 수 있으나, 보편적으로 대상자의 입장을 들어주는 것이 우선입니다.", "4": "이야기를 들어주되 가족관계에 관여하지 않는 것은 대상자의 감정 지지를 제공하면서도 중립성을 유지할 수 있어서 가장 적절한 대처입니다.", "5": "아들에게 대상자의 마음 상태를 알려주는 것은 가족 간의 갈등을 유발할 수 있으므로 신중해야 합니다."}'::jsonb, '[{"term_ko": "대처", "term_vi": "Cách đối phó", "def_ko": "대처하는 것(한국어)", "def_vi": "cách xử lý tình huống"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스를 받는 사람(한국어)", "def_vi": "người nhận dịch vụ"}, {"term_ko": "며느리", "term_vi": "Dâu", "def_ko": "아들의 아내(한국어)", "def_vi": "vợ của con trai"}, {"term_ko": "가족관계", "term_vi": "Mối quan hệ gia đình", "def_ko": "가족 사이의 관계(한국어)", "def_vi": "mối quan hệ giữa các thành viên trong gia đình"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (715, '2', '대상자가 서비스 시간에 자주 전화하여 일너저런 푸념을 할 때 요양보호사의 대처방법은?', '["업무시간 외에는 전화를 받지 않는다.", "대상자를 이해하며 전화를 받아 끝까지 들어준다.", "상황을 파악한 후 개인적으로 해결해 준다.", "이야기를 들어주고 추가 서비스료를 받는다.", "서비스 시간 외에는 통화가 어려움을 이해시킨다."]'::jsonb, 5, '대상자가 서비스 시간을 벗어난 후에도 자주 연락하여 푸념을 할 경우 요양보호사가 어떻게 대처해야 하는지를 평가하는 문제입니다.', NULL, '{"1": "서비스 시간 외에 전화를 받지 않는 것은 고객과의 신뢰를 구축하는 데 부정적 영향을 미칠 수 있습니다.", "2": "대상자를 이해하며 전화 통화를 끝까지 듣는 것은 바람직하지만, 모든 전화에 응대하는 것은 적절하지 않습니다.", "3": "상황 파악 후 개인적으로 해결하는 것은 요양보호사의 역할을 넘어서는 행동입니다.", "4": "이야기를 들어주고 추가 서비스료를 받는 것은 윤리적이지 않으며 바람직하지 않습니다.\n[정답]", "5": "서비스 시간 외에는 통화가 어려움을 이해시킨다. 이는 요양보호사로서의 적절한 대처법입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "환자, 돌보아야 할 사람", "def_vi": "Bệnh nhân, người được chăm sóc"}, {"term_ko": "서비스 시간", "term_vi": "Thời gian dịch vụ", "def_ko": "제공되는 서비스의 시간", "def_vi": "Thời gian mà dịch vụ được cung cấp"}, {"term_ko": "전화", "term_vi": "Điện thoại", "def_ko": "전화 통화", "def_vi": "Cuộc gọi điện thoại"}, {"term_ko": "푸념", "term_vi": "Phàn nàn", "def_ko": "불만 사항 등을 이야기하다", "def_vi": "Nói về các vấn đề, sự không hài lòng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (714, '2', '대상자가 요양보호사에게 약 사러 가는 길에 아들 운동화도 사다달라고 부탁을 할 때 대처 방법은?', '["다음에 올 때 운동화를 사다 주겠다고 말한다.", "대상자가 직접 관리책임자에게 요청하게 한다.", "관리책임자에게 보고 한 후 운동화를 사다준다.", "가족에게 대상자의 약과 아들 운동화를 사오게 한다.", "가족의 물품은 사다줄 수 없다고 설명한다."]'::jsonb, 5, '대상자의 요구 사항과 요양보호사의 역할을 이해하고, 윤리적으로 올바른 대처 방법을 찾는 것이 목적이다.', NULL, '{"1": "다음에 올 때 운동화를 사다 주겠다고 말한다. 이는 약속을 어길 수 있는 가능성을 내포하므로 바람직하지 않다.\n[정답]", "5": "가족의 물품은 사다줄 수 없다고 설명한다. 이는 요양보호사의 역할과 책임을 명확히 하고 윤리적 기준을 준수하는 방법이다.", "3": "관리책임자에게 보고 한 후 운동화를 사다준다. 이는 불필요한 절차로 시간이 지체될 수 있다.", "4": "가족에게 대상자의 약과 아들 운동화를 사오게 한다. 이는 가족에게 추가적인 부담을 줄 수 있다.", "2": "대상자가 직접 관리책임자에게 요청하게 한다. 이는 대상자의 자율성을 존중하지만 명확한 대처가 되지 않는다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자나 요양을 받는 사람", "def_vi": "Bệnh nhân hoặc người nhận chăm sóc"}, {"term_ko": "운동화", "term_vi": "Giày thể thao", "def_ko": "신발의 한 종류", "def_vi": "Một loại giày"}, {"term_ko": "관리책임자", "term_vi": "Người quản lý", "def_ko": "요양시설을 관리하는 사람", "def_vi": "Người quản lý cơ sở chăm sóc"}, {"term_ko": "부담", "term_vi": "Gánh nặng", "def_ko": "짐이나 걱정", "def_vi": "Gánh nặng hoặc lo lắng"}, {"term_ko": "윤리적", "term_vi": "Đạo đức", "def_ko": "도덕적으로 올바른", "def_vi": "Đúng về mặt đạo đức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (713, '2', '거동이 불편한 대상자가 은행에 가서 고액의 돈을 인출해 달라고 부탁했을 때 요양보호사의 올바른 대처 방법은?', '["동료 요양보호사와 함께 간다.", "요양보호사 혼자 가서 인출해 온다.", "대상자의 가족과 함께 가서 인출한다.", "고액의 은행 업무는 본인과 함께 가야 한다고 설득한다.", "고액의 돈은 인출할 수 없다고 정중하게 거절한다."]'::jsonb, 3, '거동이 불편한 대상자가 원하는 조치를 취할 수 있도록 안전하게 지원하는 방법을 묻는 질문입니다.', NULL, '{"1": "동료 요양보호사와 함께 가는 것은 좋지만, 고액 인출은 대상자 본인의 동행이 필요합니다.\n[정답]", "3": "대상자의 가족과 함께 가서 인출하는 것이 안전하고 법적으로 올바른 방법입니다.", "2": "요양보호사 혼자 가서 인출하는 것은 대상자의 안전을 보장할 수 없습니다.", "4": "고액의 은행 업무는 본인과 함께 가야 한다고 설득하는 것은 어려운 상황에서는 적절하지 않습니다.", "5": "고액의 돈은 인출할 수 없다고 정중하게 거절하는 것은 대상자의 요청을 무시하는 행동입니다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Hành động", "def_ko": "움직임(한국어)", "def_vi": "hành động(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (712, '2', '냉장고에 음식이 상한 것을 발견했을 때 요양보호사의 대처방법으로 옳은 것은?', '["버리고 나서 대상자에게 설명한다.", "먹을 수 있도록 가열해 둔다.", "상한 부분만 버리고 냉장고에 넣는다.", "냉동실에 넣고 얼린다.", "대상자에게 알리고 즉시 폐기한다."]'::jsonb, 5, '냉장고에 상한 음식이 있을 경우 요양보호사가 취해야 할 적절한 대처 방법을 평가하기 위함입니다.', NULL, '{"1": "잘못된 대응입니다. 상한 음식을 버린 후 설명할 필요 없으며, 바로 조치를 취해야 합니다.\n[정답]", "5": "상한 음식을 발견했을 경우, 즉시 폐기하고 대상자에게 알려야 안전합니다.", "3": "상한 부분만 버리고 냉장고에 넣는 것은 안전하지 않습니다.", "2": "가열하여 먹을 수 있도록 하는 것은 더 위험한 방법입니다.", "4": "냉동실에 넣고 얼리는 것도 적절하지 않습니다."}'::jsonb, '[{"term_ko": "음식", "term_vi": "Thực phẩm", "def_ko": "음식(한국어)", "def_vi": "Thức ăn(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (711, '2', '치매 대상자가 입맛이 없다면서 식사를 거부할 때 대처방법은?', '["식욕촉진제를 준다.", "음식을 강제로 떠 먹인다.", "평소 좋아하는 음식을 제공한다.", "식사할 때까지 옆에서 기다린다.", "음식을 먹을 때까지 치우지 않는다."]'::jsonb, 3, '치매 대상을 대할 때의 적절한 식사 대처 방법을 이해하도록 하기 위함입니다.', NULL, '{"1": "식욕촉진제를 주는 것은 단기적인 해결책일 뿐입니다. 따라서, 효과적이지 않을 수 있습니다.\n[정답]", "3": "평소 좋아하는 음식을 제공하는 것은 대상자의 식욕을 자극할 수 있는 좋은 방법입니다.", "2": "음식을 강제로 떠 먹이는 것은 대상자에게 스트레스를 주고 식사에 대한 거부감을 더욱 키울 수 있습니다.", "4": "식사할 때까지 옆에서 기다리는 것은 비효율적이며 식사하지 않을 수 있습니다.", "5": "음식을 먹을 때까지 치우지 않는 것은 오히려 위생적이지 않고, 불필요한 스트레스를 유발할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고력의 저하 등을 특징으로 하는 질환", "def_vi": "Bệnh đặc trưng bởi giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "식욕", "term_vi": "Sự thèm ăn", "def_ko": "음식을 먹고 싶어 하는 욕구", "def_vi": "Mong muốn ăn uống"}, {"term_ko": "강제", "term_vi": "Ép buộc", "def_ko": "어떤 일을 하도록 강요하는 것", "def_vi": "Bắt buộc làm một việc gì đó"}, {"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "도움이나 서비스를 받을 사람", "def_vi": "Người nhận sự giúp đỡ hoặc dịch vụ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (710, '2', '혼자 사는 재가대상자가 명절음식을 만들어 달라고 요구할 때 요양보호사의 대처방법으로 옳은 것은?', '["별도의 비용을 지불하면 가능하다고 한다.", "대상자의 병이 다 나으면 만들어 준다고 한다.", "관리 책임자에게 허락받고 만들어주겠다고 한다.", "원칙상 안 되지만 특별히 만들어 준다고 한다.", "명절음식 차리기 등은 요양서비스 업무 범위가 아니라고 설명한다."]'::jsonb, 5, '요양보호사가 재가대상자의 요구에 어떻게 올바르게 대처해야 하는지를 평가하고자 하는 문제입니다.', NULL, '{"1": "별도의 비용을 지불하면 가능하다고 한다: 요양서비스는 일반적으로 정해진 범위 내에서 제공되므로 추가 비용을 요구하는 것은 부적절합니다.\n[정답]", "5": "명절음식 차리기 등은 요양서비스 업무 범위가 아니라고 설명한다: 요양보호사는 정해진 서비스 범위 내에서만 업무를 수행해야 하므로 가장 적절한 대처입니다.", "2": "대상자의 병이 다 나으면 만들어 준다고 한다: 이 또한 기본적인 서비스 범위를 벗어난 답변입니다.", "3": "관리 책임자에게 허락받고 만들어주겠다고 한다: 이를 따르더라도 요양서비스의 범위를 넘어섭니다.", "4": "원칙상 안 되지만 특별히 만들어 준다고 한다: 원칙을 무시하고 행동하는 것은 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận sự chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (709, '2', '변비인 대상자가 관장을 해달라고 요구할 때 대처방법으로 옳은 것은?', '["즉시 관장을 해준다.", "변비약을 구입하여 제공한다.", "못 들은 척 하고 다른 일을 한다.", "의료행위에 해당되므로 스스로 해결하게 한다.", "의부를 배꼽 주위에서 시계방향으로 마사지한다."]'::jsonb, 5, '대상자가 변비로 고통받고 있을 때 이를 해결하기 위한 적절한 대처 방법을 묻고 있다.', NULL, '{"1": "즉시 관장을 해주는 것은 전문가가 아닌 요양보호사가 할 수 없는 의료행위이다.\n[정답]", "5": "의부를 배꼽 주위에서 시계방향으로 마사지하는 것은 변비 완화에 도움을 줄 수 있는 비의료적 접근이다.", "3": "못 들은 척 하고 다른 일을 하는 것은 대상자의 요구를 무시하는 행동으로 올바르지 않다.", "4": "의료행위에 해당되므로 스스로 해결하게 하는 것은 적절한 대처가 아니다.", "2": "변비약을 구입하여 제공하는 것은 요양보호사의 역할에 해당하지 않는다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "배변이 어려운 상태", "def_vi": "Tình trạng khó đi đại tiện"}, {"term_ko": "관장", "term_vi": "Thụt tháo", "def_ko": "항문으로 약물이나 수액을 집어넣는 행위", "def_vi": "Hành động đưa thuốc hoặc dung dịch vào hậu môn"}, {"term_ko": "의료행위", "term_vi": "Hành động y tế", "def_ko": "의료목적으로 하는 모든 행위", "def_vi": "Tất cả các hành động nhằm mục đích y tế"}, {"term_ko": "마사지", "term_vi": "Mát-xa", "def_ko": "주물러서 자극을 주는 행위", "def_vi": "Hành động xoa bóp để kích thích"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (708, '2', '대상자가 기저귀를 차고 있는 상황에서 기저귀 안으로 손을 자주 넣을 때 올바른 대처방법은?', '["기저귀를 꽉 조여준다.", "음부의 피부 상태를 확인한다.", "화장실로 데려가 변기에 앉힌다.", "상하의가 붙은 옷을 입힌다.", "무의식적으로 하는 행동이므로 그냥 둔다."]'::jsonb, 2, '대상자가 기저귀를 착용하고 있을 때 손을 자주 넣는 행동의 원인을 파악하고 올바른 대처를 고민하게 하는 문제입니다.', NULL, '{"1": "기저귀를 너무 꽉 조이면 오히려 불편함을 줄 수 있습니다.\n[정답]", "2": "기저귀 안에 손을 넣는 이유 중 하나는 피부 상태에 문제가 있을 수 있어서 확인하는 것이 중요합니다.", "3": "기저귀 착용자의 상태에 따라 화장실에 데려가는 방법이 필요할 수 있지만, 현재 문제의 본질은 피부 확인입니다.", "4": "상하의가 붙은 옷은 오히려 불편하게 하여 행동을 유발할 수 있습니다.", "5": "무의식적인 행동이라고 하더라도 필요한 경우에는 대처가 필요합니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "기저귀(한국어)", "def_vi": "Bỉm(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (707, '2', '밤에 추워서 화장실에 가기 싫다며 기저귀를 사용하려는 대상자를 돕는 방법은?', '["이동변기를 사용한다.", "원하는 대로 기저귀를 사용한다.", "휠체어를 타고 가도록 한다.", "식사와 수분섭취를 줄인다.", "배설 욕구를 참았다가 화장실에 가게 한다."]'::jsonb, 1, '대상자의 불편함을 고려하여 적절한 방법으로 배설을 도와주는 방안을 묻고 있다.', NULL, '{"1": "이동변기를 사용한다. 적절한 방법으로 대상자가 편리하게 화장실을 이용하게 도와준다.\n[정답]", "2": "원하는 대로 기저귀를 사용한다. 기저귀 사용이 아닌 보다 적절한 배설 방법을 제시해야 한다.", "3": "휠체어를 타고 가도록 한다. 이동이 어렵다면 휠체어를 이용하는 방법이지만, 효과적이지 않을 수 있다.", "4": "식사와 수분섭취를 줄인다. 이 방법은 건강에 해로운 영향을 미칠 수 있다.", "5": "배설 욕구를 참았다가 화장실에 가게 한다. 욕구를 참게 하는 것은 불필요한 스트레스를 줄 수 있다."}'::jsonb, '[{"term_ko": "밤", "term_vi": "Đêm", "def_ko": "밤(한국어)", "def_vi": "đêm"}, {"term_ko": "추워서", "term_vi": "Lạnh", "def_ko": "추위로 인해(한국어)", "def_vi": "do lạnh"}, {"term_ko": "화장실", "term_vi": "Nhà vệ sinh", "def_ko": "화장실(한국어)", "def_vi": "nhà vệ sinh"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "tã"}, {"term_ko": "이동변기", "term_vi": "Bô di động", "def_ko": "이동변기(한국어)", "def_vi": "bô di động"}, {"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "휠체어(한국어)", "def_vi": "xe lăn"}, {"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "배설(한국어)", "def_vi": "bài tiết"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "욕구(한국어)", "def_vi": "nhu cầu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (706, '2', '치매 대상자가 목욕 도중 큰 소리로 욕을 하며 목욕을 그만하겠다고 할 때 대처방법으로 옳은 것은?', '["정해진 시간에 목욕을 마쳐야 한다고 말한다.", "욕하지 못하게 큰 소리로 꾸짖는다.", "무시하고 신속하게 목욕을 마친다.", "잠시 자리를 피해 혼자 있게 한다.", "안전을 위해 무리하게 목욕을 시키지 않는다."]'::jsonb, 5, '치매 환자의 행동 관리에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "정해진 시간에 목욕을 마쳐야 한다고 말하는 것은 치매 환자의 불안감을 증가시킬 수 있습니다.", "2": "욕하지 못하게 큰 소리로 꾸짖는 것은 환자의 기분을 더욱 나쁘게 만들 수 있습니다.", "3": "무시하고 신속하게 목욕을 마치는 것은 환자의 권리를 침해할 수 있습니다.", "4": "잠시 자리를 피해 혼자 있게 하는 것은 고립감을 유발할 수 있습니다.\n[정답]", "5": "안전을 위해 무리하게 목욕을 시키지 않는 것이 가장 바람직한 대처 방법입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 및 사고에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và khả năng suy nghĩ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (705, '2', '방문요양 시 대상자가 매번 목욕을 시켜 달라고 옷을 벗고 알몸으로 기다릴 때 요양보호사의 대처방법은?', '["서비스 제공을 중단한다.", "이웃에게 알려 도움을 청한다.", "같이 TV를 보자고 한다.", "임의로 목욕서비스를 실시한다.", "목욕 서비스가 없음을 설명하고 옷을 입도록 단호하게 말한다."]'::jsonb, 5, '대상자가 요구하는 서비스에 대해 요양보호사가 어떻게 대처해야 할지를 알고 있는지를 평가하는 문제입니다.', NULL, '{"1": "서비스 제공을 중단하는 것은 원인을 해결하지 못하는 방법입니다.", "2": "이웃에게 도움을 청하는 것은 적절한 대처가 아닙니다.", "3": "같이 TV를 보자고 하는 것은 목표에 부합하지 않는 대응입니다.", "4": "임의로 목욕서비스를 실시하는 것은 대상자의 의사와 상반되는 행동입니다.\n[정답]", "5": "목욕 서비스가 없음을 설명하고 옷을 입도록 단호하게 말하는 것이 적절한 대응 방법입니다."}'::jsonb, '[{"term_ko": "방문요양", "term_vi": "Chăm sóc tại nhà", "def_ko": "대상자의 집을 방문하여 요양 서비스를 제공하는 것", "def_vi": "Cung cấp dịch vụ chăm sóc tại nhà cho đối tượng"}, {"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "서비스나 치료를 받는 사람", "def_vi": "Người nhận dịch vụ hoặc điều trị"}, {"term_ko": "대처방법", "term_vi": "Cách xử lý", "def_ko": "문제에 대한 대응 방안", "def_vi": "Giải pháp đối phó với vấn đề"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 씻는 행위", "def_vi": "Hành động rửa cơ thể"}, {"term_ko": "단호하게", "term_vi": "Kiên quyết", "def_ko": "확고하고 강한 태도로", "def_vi": "Với thái độ vững vàng và mạnh mẽ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (704, '2', '대상자가 혈압이 높은데도 목욕을 하겠다고 하는 경우 대처방법은?', '["혈압약을 복용한 후 목욕을 한다.", "대상자의 가족에게 허락받고 목욕을 시킨다.", "샤워보다는 통 목욕으로 한다.", "목욕시간은 1시간 이내로 한다.", "혈압이 높을 때 목욕을 하면 위험함을 설명한다."]'::jsonb, 5, '대상자의 안전을 고려한 목욕 시 주의사항을 묻는 문제입니다.', NULL, '{"1": "혈압약을 복용한 후 목욕을 하게 되면 혈압이 더 낮아질 수 있어 위험할 수 있습니다.\n[정답]", "5": "혈압이 높을 때 목욕을 하면 위험할 수 있음을 설명하여 개인의 안전을 확보하는 것이 중요합니다.", "3": "통 목욕보다 샤워가 혈압에 덜 영향을 미칠 수 있으나, 대처 방법으로 적절하지 않습니다.", "4": "목욕 시간은 일반적으로 20-30분 이내로 제한하는 것이 바람직합니다.", "2": "가족에게 허락받고 목욕하게 되면 문제를 해결할 수 없으니 적절하지 않습니다."}'::jsonb, '[{"term_ko": "혈압", "term_vi": "Huyết áp", "def_ko": "혈액이 혈관벽에 미치는 압력(압 lực)", "def_vi": "Áp lực của máu tác động lên thành mạch"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (703, '2', '치매 대상자가 속옷을 갈아입으려고 하지 않을 때 올바른 대처 방법은?', '["갈아입지 않으려는 이유를 알아본다.", "목욕을 한다며 강제로 갈아 입힌다.", "갈아입지 않으면 밥을 주지 않는다고 말한다.", "속옷을 사다 주고 혼자 갈아입으라고 한다.", "자년에게 갈아 입히라고 말한다."]'::jsonb, 1, '치매 대상자의 올바른 대처 방법을 이해하고 있는지를 평가하기 위함이다.', NULL, '{"1": "갈아입지 않으려는 이유를 알아본다. [정답] 치매 대상자의 심리적, 정서적 이유를 이해하고, 그에 맞는 대처를 할 수 있어야 한다.", "2": "목욕을 한다며 강제로 갈아 입힌다. 강제적인 방법은 치매 환자의 불안감을 초래할 수 있다.", "3": "갈아입지 않으면 밥을 주지 않는다고 말한다. 이러한 방식은 환자에게 스트레스를 줄 수 있으며 부적절하다.", "4": "속옷을 사다 주고 혼자 갈아입으라고 한다. 환자의 자존감을 해칠 수 있으며 올바른 대처가 아니다.", "5": "자녀에게 갈아 입히라고 말한다. 이러한 방법은 기본적인 돌봄 책임을 다하지 않는 것이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억상실증(한국어)", "def_vi": "Bệnh không nhớ điều gì"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (702, '2', '회음부 세척 시 대상자가 부끄러워하며 도움을 거부할 때 대처방법은?', '["청결을 위해 무시하고 씻긴다.", "보호자에게 연락하여 도움을 요청한다.", "대상자가 도움을 요청할 때까지 기다린다.", "대상자의 거부의사를 존중하여 다음으로 미룬다.", "편안한 환경을 조성하고 세척의 필요성을 이해시킨다."]'::jsonb, 5, '회음부 세척과 관련하여 대상자의 의사를 존중하고, 적절한 대처 방법을 선택하는 능력을 평가하는 문제입니다.', NULL, '{"1": "청결을 위해 무시하고 씻기는 것은 대상자의 의사를 존중하지 않는 행동입니다.\n[정답]", "5": "편안한 환경을 조성하고 세척의 필요성을 이해시키는 것이 올바른 접근법입니다.", "3": "대상자가 도움을 요청할 때까지 기다리는 것은 시간이 소요될 수 있습니다.", "4": "대상자의 거부의사를 존중하되, 다음으로 미루는 것은 문제 상황을 해결하지 못합니다.", "2": "보호자에게 연락하여 도움을 요청하는 것은 상황을 개선하기 위한 방법이지만, 먼저 대상자의 의사를 존중해야 합니다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": "Cơ quan sinh dục", "def_ko": "생식기와 항문 사이의 부분", "def_vi": "Phần giữa cơ quan sinh dục và hậu môn"}, {"term_ko": "세척", "term_vi": "Rửa", "def_ko": "깨끗하게 하다", "def_vi": "Làm sạch"}, {"term_ko": "부끄러워하다", "term_vi": "Xấu hổ", "def_ko": "쑥스러워하다", "def_vi": "Ngại ngùng"}, {"term_ko": "거부하다", "term_vi": "Từ chối", "def_ko": "거절하다", "def_vi": "Từ chối"}, {"term_ko": "대처방법", "term_vi": "Phương pháp ứng phó", "def_ko": "해결 방법", "def_vi": "Cách giải quyết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (701, '2', '치매 대상자가 식사 후에 양치질을 거부할 때 돕는 방법은?', '["심하게 거부하면 그냥 둔다.", "입안을 물로 헹궈준다.", "간식을 주지 않는다고 말한다.", "치약과 칫솔을 손에 쥐어주고 기다린다.", "동료에게 도움을 요청하여 강제로 시도한다."]'::jsonb, 2, '치매 대상자의 구강 위생 관리 방법을 이해하고, 적절한 대응 방법을 찾도록 하는 것입니다.', NULL, '{"1": "심하게 거부할 경우, 강제로 시도하기보다 대상자의 의사를 존중하는 것이 중요합니다.\n[정답]", "2": "입안을 물로 헹구어주면 간접적으로 구강 위생을 도울 수 있습니다.", "3": "간식을 주지 않는다고 말하는 것은 부적절한 대응입니다.", "4": "치약과 칫솔을 손에 쥐어주고 기다리는 것은 비효율적입니다.", "5": "동료에게 도움을 요청하여 강제로 시도하는 것은 환자에게 스트레스를 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이 상실되고 사고 능력이 저하되는 증상", "def_vi": "Tình trạng mất khả năng nhớ và suy giảm khả năng suy nghĩ"}, {"term_ko": "양치질", "term_vi": "Đánh răng", "def_ko": "이빨을 닦는 행위", "def_vi": "Hành động chải răng"}, {"term_ko": "구강", "term_vi": "Miệng", "def_ko": "입안의 구역", "def_vi": "Khu vực trong miệng"}, {"term_ko": "거부", "term_vi": "Từ chối", "def_ko": "어떤 것을 원하지 않거나 받지 않다", "def_vi": "Không muốn hoặc không chấp nhận điều gì"}, {"term_ko": "간접적으로", "term_vi": "Gián tiếp", "def_ko": "직접 효과가 아닌 방법을 통해", "def_vi": "Thông qua phương pháp không hiệu quả trực tiếp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (700, '2', '요양보호사가 제공하는 정서지원, 의사소통에 해당하는 것은?', '["양치 지켜보기", "산책 시 부축", "손발톱 깎기", "화장하기", "편지대필"]'::jsonb, 5, '정서적 지원과 의사소통의 중요성을 이해하기 위한 문제입니다.', NULL, '{"1": "양치 지켜보기는 신체적 도움을 주는 행위입니다.", "2": "산책 시 부축은 이동에 대한 지원으로, 정서적 지원과는 직접적 연관이 없습니다.", "3": "손발톱 깎기는 신체적 관리에 해당합니다.", "4": "화장하기는 개인 위생과 미용 관련 행위입니다.\n[정답]", "5": "편지대필은 정서적 소통을 통해 환자의 감정을 지원하는 행동입니다."}'::jsonb, '[{"term_ko": "정서지원", "term_vi": "Hỗ trợ cảm xúc", "def_ko": "감정을 지원하는 것", "def_vi": "Hỗ trợ cảm xúc cho người bệnh"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통하는 것", "def_vi": "Sự giao tiếp"}, {"term_ko": "편지대필", "term_vi": "Viết thư thay mặt", "def_ko": "편지를 대신 써주는 것", "def_vi": "Viết thư cho người khác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (699, '2', '대상자에게 제공하는 가사 및 일상생활지원에 해당되는 것은?', '["좋아하는 시를 읽어준다.", "대상자와 함께 보건소 방문을 한다.", "기념일을 달력에 표기하도록 도와준다.", "전화로 생활상의 문제를 상담한다.", "대상자가 앉았다 일어서는 행동을 도와준다."]'::jsonb, 2, '대상자에게 제공하는 가사 및 일상생활 지원의 내용을 이해하고 판단할 수 있는 능력을 평가하고자 함.', NULL, '{"1": "좋아하는 시를 읽어주는 것은 정서적 지원의 일환으로, 가사 및 일상생활 지원에 해당하지 않음.\n[정답]", "2": "대상자와 함께 보건소 방문을 하는 것은 일상생활 지원의 일환으로, 필요한 의료적 지원을 받을 수 있도록 돕는 활동임.", "3": "기념일을 달력에 표기하도록 도와주는 것은 관리적 지원에 해당하지만, 일상생활 지원에는 포함되지 않음.", "4": "전화로 생활상의 문제를 상담하는 것은 정서적 지원에 해당하며, 직접적인 일상생활 지원이 아님.", "5": "대상자가 앉았다 일어서는 행동을 도와주는 것은 신체적 지원으로, 일상생활 지원에 해당하지 않음."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người cần chăm sóc", "def_ko": "환자 또는 요양을 받는 사람", "def_vi": "Bệnh nhân hoặc người được chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (698, '2', '개인활동이 곤라한 재가 대상자에게 제공할 수 있는 서비스는?', '["정원 잡초 뽑기", "시장 다녀오기", "가족식사 준비하기", "애완견 산책 다녀오기", "명절음식 만들기"]'::jsonb, 2, '재가 대상자의 개인활동 지원과 관련된 서비스를 이해하고 적용할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "정원 잡초 뽑기는 개인의 정원 관리에 해당하는 활동으로, 재가 대상자에게 제공하기에는 적절하지 않습니다.\n[정답]", "2": "시장 다녀오기는 재가 대상자가 필요로 하는 기본적인 외출 활동으로, 적합한 서비스입니다.", "3": "가족식사 준비하기는 가족이 함께할 때 고려할 수 있는 사항이며, 재가 대상자에게는 직접적인 서비스가 아닙니다.", "4": "애완견 산책 다녀오기는 재가 대상자가 아니라 애완견의 필요에 해당하므로 적합하지 않습니다.", "5": "명절음식 만들기는 특별한 경우를 제외하고는 재가 대상자에게 필요한 서비스가 아닙니다."}'::jsonb, '[{"term_ko": "개인활동", "term_vi": "Hoạt động cá nhân", "def_ko": "개인의 일상적인 활동", "def_vi": "Các hoạt động hàng ngày của cá nhân"}, {"term_ko": "재가 대상자", "term_vi": "Đối tượng chăm sóc tại nhà", "def_ko": "재가에서 돌보아야 하는 사람", "def_vi": "Người cần được chăm sóc ở nhà"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "제공되는 도움", "def_vi": "Sự giúp đỡ được cung cấp"}, {"term_ko": "시장", "term_vi": "Chợ", "def_ko": "물건을 사는 곳", "def_vi": "Nơi mua sắm"}, {"term_ko": "가족식사", "term_vi": "Bữa ăn gia đình", "def_ko": "가족이 함께하는 식사", "def_vi": "Bữa ăn cùng gia đình"}, {"term_ko": "명절음식", "term_vi": "Món ăn ngày lễ", "def_ko": "특별한 날에 만드는 음식", "def_vi": "Món ăn được chế biến vào dịp lễ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (697, '2', '대상자에게 제공되는 일상생활지원 내용으로 옳은 것은?', '["대상자 배우자의 바지를 다려 주었다.", "대상자 가족의 행정업무를 도와 주었다.", "대상자 손주의 유치원 등원을 도와 주었다.", "대상자가 먹고 싶어 하는 전복죽을 끓여 주었다.", "병문안을 온 친척의 점심을 차려 주었다."]'::jsonb, 4, '대상자에게 제공되는 일상생활지원의 내용을 이해하고 확인하는 것입니다.', NULL, '{"1": "잘못됨: 대상자 배우자의 바지를 다리는 것은 일상생활지원에 해당되지 않습니다.", "2": "잘못됨: 가족의 행정업무 지원은 요양보호사가 제공하는 일상생활지원 범주에 포함되지 않습니다.", "3": "잘못됨: 손주의 유치원 등원 도와 주는 것은 대상자가 아닌 다른 사람을 지원하는 것입니다.\n[정답]", "4": "맞음: 대상자가 먹고 싶어 하는 음식을 제공하는 것은 일상생활지원의 일환입니다.", "5": "잘못됨: 병문안을 온 친척의 점심을 차려 주는 것은 대상자가 아닌 다른 사람을 지원하는 것입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "지원을 받는 사람", "def_vi": "Người nhận hỗ trợ"}, {"term_ko": "일상생활지원", "term_vi": "Hỗ trợ sinh hoạt hàng ngày", "def_ko": "일상적인 생활을 지원하는 것", "def_vi": "Hỗ trợ cho cuộc sống hàng ngày"}, {"term_ko": "음식", "term_vi": "Thức ăn", "def_ko": "먹을 것을 의미", "def_vi": "Thức ăn có nghĩa là món ăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (696, '2', '다음 내용에 해당하는 표준서비스는?음식물 조리, 청소 및 주변정돈, 의복세탁 및 관리', '["신체활동지원", "가사 및 일상생활지원", "방문목욕", "정서지원, 의사소통", "건강 및 간호관리"]'::jsonb, 2, '표준서비스에 대한 이해와 이를 구별하는 능력을 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "신체적인 도움을 제공하는 서비스입니다.\n[정답]", "2": "음식물 조리, 청소 및 주변정돈, 의복세탁 및 관리와 관련된 서비스입니다.", "3": "개인의 위생을 위한 목욕 서비스입니다.", "4": "정서적 안정과 의사소통을 위한 지원 서비스입니다.", "5": "건강 상태 체크와 간호 관련 서비스입니다."}'::jsonb, '[{"term_ko": "표준서비스", "term_vi": "Dịch vụ tiêu chuẩn", "def_ko": "표준적인 서비스나 지원의 형태", "def_vi": "Hình thức dịch vụ hoặc hỗ trợ tiêu chuẩn"}, {"term_ko": "음식물 조리", "term_vi": "Chuẩn bị thức ăn", "def_ko": "음식을 준비하고 만드는 것", "def_vi": "Việc chuẩn bị và nấu ăn"}, {"term_ko": "청소", "term_vi": "Dọn dẹp", "def_ko": "환경을 정리하고 깨끗하게 하는 것", "def_vi": "Làm sạch và sắp xếp môi trường"}, {"term_ko": "주변정돈", "term_vi": "Quản lý môi trường xung quanh", "def_ko": "주변을 정리하는 것", "def_vi": "Việc sắp xếp và duy trì môi trường xung quanh"}, {"term_ko": "의복세탁", "term_vi": "Giặt quần áo", "def_ko": "옷을 세탁하는 것", "def_vi": "Hành động giặt giũ quần áo"}, {"term_ko": "관리", "term_vi": "Quản lý", "def_ko": "무엇인가를 잘 유지하고 감독하는 것", "def_vi": "Hành động duy trì và giám sát cái gì đó"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (695, '2', '재가 요양보호서비스 중 신체활동지원에 해당하는 것은?', '["식재료 구매", "몸 단장", "세탁물 빨기", "생활상담", "외출 시 동행"]'::jsonb, 2, '재가 요양보호서비스에서 신체활동지원을 이해하고 구분하는 것이 중요하다.', NULL, '{"1": "식재료 구매는 신체활동이 아닌 생활 지원에 해당한다.\n[정답]", "2": "몸 단장은 개인의 신체적 활동에 해당하여 신체활동지원에 포함된다.", "3": "세탁물 빨기는 신체적 활동보다는 생활지원에 가까운 서비스이다.", "4": "생활상담은 상담 서비스로 신체활동지원에 포함되지 않는다.", "5": "외출 시 동행은 활동 지원이지만 신체활동지원이라는 범주에 포함되지 않는다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Chăm sóc tại nhà", "def_ko": "가정에서 서비스를 제공받는 요양", "def_vi": "Dịch vụ nhận được tại nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (694, '2', '요양보호사의 업무 중 올바르게 짝지어진 것은?', '["신체활동지원 - 말벗, 격려, 위로, 생활상담", "정서지원, 의사소통 - 화장실 이동 보조, 몸 단장 하기", "기능회복훈련 - 몸 씻기 도움, 목욕 기계 조작", "가사 및 일상생활지원 - 약 타기, 병원 동행, 관공서 업무대행", "방문목욕 - 취사, 청소, 세탁"]'::jsonb, 4, '요양보호사의 다양한 업무를 이해하고 올바르게 짝지어진 항목을 선택하는 것이 중요하다.', NULL, '{"1": "신체활동지원 - 말벗, 격려, 위로, 생활상담 (잘못된 조합)\n[정답]", "2": "정서지원, 의사소통 - 화장실 이동 보조, 몸단장 하기 (잘못된 조합)", "3": "기능회복훈련 - 몸 씻기 도움, 목욕 기계 조작 (잘못된 조합)", "4": "가사 및 일상생활지원 - 약 타기, 병원 동행, 관공서 업무대행 (올바른 조합)", "5": "방문목욕 - 취사, 청소, 세탁 (잘못된 조합)"}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인을 돕는 전문가", "def_vi": "Chuyên gia giúp đỡ người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (693, '2', '노인장기요양보험 표준서비스 내용 중 ''인지행동 변화 관리''에 해당하는 것으로 옳은 것은?', '["신체활동지원", "정서지원, 의사소통", "가사 및 일상생활지원", "방문목욕", "인지지원"]'::jsonb, 5, '노인장기요양보험의 다양한 서비스 중 인지행동 변화 관리와 관련된 서비스를 구분하고 이해할 수 있도록 하는 것이다.', NULL, '{"1": "신체활동지원은 신체적 기능을 지원하는 서비스이다.\n[정답]", "5": "인지지원은 인지기능 향상을 위한 서비스로, 인지행동 변화 관리에 포함된다.", "2": "정서지원, 의사소통은 정서적 안정을 위한 지원이지만 인지행동 변화 관리와는 다르다.", "3": "가사 및 일상생활지원은 일상 활동을 돕는 서비스로, 인지 관련 서비스가 아니다.", "4": "방문목욕은 신체 위생 관리를 지원하는 서비스이다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기 요양 서비스 제공 정책", "def_vi": "Chính sách cung cấp dịch vụ chăm sóc dài hạn cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (692, '2', '노인장기요양보험 표준서비스 내용 중 기능회복훈련의 내용으로 옳은 것은?', '["이동 도움", "식사 도움", "화장실 이용 돕기", "작업치료", "체위변경"]'::jsonb, 4, '기능회복훈련에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "이동 도움: 기능회복훈련의 일부일 수 있지만 직접적인 내용은 아닙니다.", "2": "식사 도움: 활동 지원의 일환으로 기능회복 접근이 아닌, 기본적인 돌봄입니다.", "3": "화장실 이용 돕기: 기본적인 일상 생활 지원이라 기능회복훈련의 핵심이라고 할 수 없습니다.\n[정답]", "4": "작업치료: 기능회복훈련의 중요한 부분으로, 재활을 돕기 위한 치료입니다.", "5": "체위변경: 기본적 돌봄 활동으로 기능회복훈련의 중심은 아닙니다."}'::jsonb, '[{"term_ko": "기능회복훈련", "term_vi": "Đào tạo phục hồi chức năng", "def_ko": "재활 훈련(한국어)", "def_vi": "Huấn luyện phục hồi chức năng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (691, '2', '노인장기요양보험 표준서비스 중 건강 및 간호관리에 해당하는 것은?', '["몸단장", "의사소통 도움", "관찰 및 측정", "목욕 기계 조작", "일상생활 동작훈련"]'::jsonb, 3, '노인장기요양보험의 표준서비스에서 건강 및 간호관리와 관련된 내용을 확인하기 위한 문제입니다.', NULL, '{"1": "몸단장: 개인 위생과 관련이 있지만, 건강 및 간호관리와 직접적인 연관은 없습니다.\n[정답]", "3": "관찰 및 측정: 건강 상태를 관찰하고 측정하는 것이 간호관리의 핵심입니다.", "2": "의사소통 도움: 의사소통은 중요하지만 간호관리의 구체적인 요소는 아닙니다.", "4": "목욕 기계 조작: 목욕 서비스를 제공하는 것이지만 건강 관리와는 연결되지 않습니다.", "5": "일상생활 동작훈련: 기본적인 일상 생활 지원일 뿐 건강 및 간호관리와는 다른 범주입니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "고령자 장기 요양 시설에서 제공되는 보험", "def_vi": "Bảo hiểm cung cấp dịch vụ chăm sóc lâu dài cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (690, '2', '노인장기요양보험 표준서비스 중 가사 및 일상생활지원에 속하는 것은?', '["머리 감기기", "복약 도움", "함께 은행가기", "배뇨, 배변 도움", "신체기능의 유지, 증진"]'::jsonb, 3, '노인장기요양보험에서 제공하는 표준서비스 중 가사 및 일상생활지원의 내용을 확인하는 문제입니다.', NULL, '{"1": "머리 감기기는 개인 위생 관리로, 가사 및 일상생활지원에 해당되지만 주된 서비스는 아닙니다.\n[정답]", "3": "함께 은행 가기는 외부 활동을 지원하는 것으로 가사 및 일상생활지원에 포함됩니다.", "2": "복약 도움은 의료 지원의 일환으로 가사 서비스에는 포함되지 않습니다.", "4": "배뇨, 배변 도움은 신체적 지원이며 가사 서비스가 아닙니다.", "5": "신체기능의 유지, 증진은 재활 또는 의료적 지원과 관련된 내용입니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기 요양 서비스 제공을 위한 보험", "def_vi": "Bảo hiểm cung cấp dịch vụ chăm sóc dài hạn cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (689, '2', '노인장기요양보험 표준서비스 중 가사 및 일상생활지원에 해당하는 것은?', '["머리 감기기", "복약 도움", "함께 은행가기", "배뇨, 배변 도움", "신체기능의 유지, 증진"]'::jsonb, 5, '노인장기요양보험의 가사 및 일상생활 지원 서비스의 범위를 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "머리 감기기: 개인 위생에 해당하지만, 가사 및 일상 생활 지원의 직접적 범위는 아닙니다.", "2": "복약 도움: 약물 관리에 해당하며, 가사 지원과는 거리가 있습니다.", "3": "함께 은행가기: 사회적 활동 지원으로 분류되지만, 가사 및 일상생활 지원에는 포함되지 않습니다.\n[정답]", "4": "배뇨, 배변 도움: 이것은 개인의 일상생활을 지원하는 안전한 서비스 범위에 적합한 항목입니다.", "5": "신체기능의 유지, 증진: 이것은 노인의 신체적 활동과 관련된 지원으로 가사 및 일상생활 지원의 일부로 볼 수 있습니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기요양 보호 보험", "def_vi": "Bảo hiểm cho những người cao tuổi gặp khó khăn trong hoạt động hàng ngày"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (688, '2', '노인장기요양보험 표준서비스 중 신체활동지원에 해당하는 것은?', '["구강청결 도움", "생활상담 지원", "의사소통 도움", "인지자극 활동", "기본동작 훈련"]'::jsonb, 1, '신체활동지원이 무엇인지 파악하기 위한 문제입니다.', NULL, '{"1": "구강청결 도움은 신체활동지원에 해당하여 중요합니다.\n[정답]", "2": "생활상담 지원은 신체활동지원과는 관련이 없습니다.", "3": "의사소통 도움은 신체활동지원이 아닙니다.", "4": "인지자극 활동은 신체활동지원과는 관련이 없습니다.", "5": "기본동작 훈련은 신체활동지원의 일환으로 간주되지 않습니다."}'::jsonb, '[{"term_ko": "신체활동지원", "term_vi": "Hỗ trợ hoạt động thể chất", "def_ko": "신체 활동을 지원하는 서비스", "def_vi": "Dịch vụ hỗ trợ hoạt động thể chất"}, {"term_ko": "구강청결", "term_vi": "Làm sạch miệng", "def_ko": "입 안을 깨끗하게 하는 것", "def_vi": "Làm sạch bên trong miệng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (687, '2', '인간의 욕구 5단계 중 가장 높은 단계로서 삶의 보람, 자기만족을 느끼는 단계는?', '["생리적 욕구", "안전의 욕구", "사랑, 소속의 욕구", "존경의 욕구", "자아실현의 욕구"]'::jsonb, 5, '인간의 욕구에 대한 이해를 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "생리적 욕구는 생존을 위한 기본적인 필요입니다.", "2": "안전의 욕구는 신체적, 정서적 안전을 추구하는 것입니다.", "3": "사랑, 소속의 욕구는 인간관계의 형성에 대한 욕구입니다.\n[정답]", "4": "존경의 욕구는 타인으로부터 존중받고 인정받고 싶어하는 욕구입니다.", "5": "자아실현의 욕구는 개인의 잠재력을 최대한 발휘하고 삶의 의미를 찾는 단계입니다."}'::jsonb, '[{"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "필요(한국어)", "def_vi": "Nhu cầu(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (686, '2', '매슬로의 욕구단계 중, 요양보호서비스 제공 시 우선적으로 해결해주어야 하는 욕구는?', '["음식을 섭취할 욕구", "자아실현을 할 욕구", "가족에게 사랑받을 욕구", "타인으로부터 존중받을 욕구", "위험으로부터 안전하게 보호받을 욕구"]'::jsonb, 1, '매슬로의 욕구단계 이론을 통해 요양보호서비스에서 중점을 두어야 할 기본적인 욕구를 파악하기 위함이다.', NULL, '{"1": "매슬로의 이론에 따르면 생리적 욕구는 가장 기본적이고 우선적으로 충족되어야 하는 욕구이다.\n[정답]", "2": "자아실현 욕구는 보다 높은 차원의 욕구로 후순위에 해당된다.", "3": "사랑받고자 하는 욕구는 생리적 욕구 다음으로 중요하지만 식사의 필요 보다는 뒤에 위치한다.", "4": "존중받고자 하는 욕구는 개인의 자아와 관련이 있으나 생존을 위한 기본 욕구보다 우선할 수 없다.", "5": "위험으로부터의 안전은 중요하지만 매슬로의 이론에서는 생리적 욕구보다 후순위로 여겨진다."}'::jsonb, '[{"term_ko": "매슬로", "term_vi": "Maslow", "def_ko": "심리학자, 욕구 이론의 창시자", "def_vi": "Nhà tâm lý học, người sáng lập lý thuyết nhu cầu"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "원하는 상태", "def_vi": "Trạng thái mong muốn"}, {"term_ko": "생리적", "term_vi": "Sinh lý", "def_ko": "인체의 기본적인 생존 관련", "def_vi": "Liên quan đến sự tồn tại cơ bản của cơ thể"}, {"term_ko": "자아실현", "term_vi": "Tự thể hiện", "def_ko": "개인의 잠재력 발휘", "def_vi": "Khả năng tối đa hóa tiềm năng của cá nhân"}, {"term_ko": "사랑받다", "term_vi": "Được yêu thương", "def_ko": "애정을 받다", "def_vi": "Nhận được tình yêu"}, {"term_ko": "존중", "term_vi": "Tôn trọng", "def_ko": "타인을 존중하는 것", "def_vi": "Việc tôn trọng người khác"}, {"term_ko": "위험", "term_vi": "Nguy cơ", "def_ko": "위험한 상황", "def_vi": "Tình huống nguy hiểm"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "보호받는 상태", "def_vi": "Trạng thái được bảo vệ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (685, '2', '매슬로의 인간 욕구 5단계 중 식사, 배설, 수면은 어느 단계에 해당하는가?', '["안전의 욕구", "사랑과 소속의 욕구", "자아실현의 욕구", "생리적 욕구", "존경의 욕구"]'::jsonb, 4, '매슬로의 욕구 단계 이론에 대한 이해와 적용을 평가하기 위함입니다.', NULL, '{"1": "안전의 욕구: 인간이 생존에 위협을 느끼지 않도록 보호받고자 하는 욕구입니다.\n[정답]", "4": "생리적 욕구: 기본적인 생존을 위한 욕구로, 식사, 배설, 수면 등이 포함됩니다.", "3": "자아실현의 욕구: 자신의 잠재력을 최대한 발휘하고자 하는 욕구입니다.", "2": "사랑과 소속의 욕구: 인간관계 속에서 사랑받고 소속감을 느끼고자 하는 욕구입니다.", "5": "존경의 욕구: 타인의 존경을 받고, 자존감을 높이고자 하는 욕구입니다."}'::jsonb, '[{"term_ko": "매슬로", "term_vi": "Maslow", "def_ko": "미국의 심리학자로, 욕구 이론으로 유명함", "def_vi": "Nhà tâm lý học Mỹ, nổi tiếng với lý thuyết nhu cầu"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "사람의 필요나 원하는 것", "def_vi": "Những điều cần thiết hoặc mong muốn của con người"}, {"term_ko": "생리적", "term_vi": "Sinh lý", "def_ko": "생명 유지에 필요한 것과 관련된", "def_vi": "Liên quan đến những điều cần thiết cho sự sống"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험으로부터 보호받고자 하는 상태", "def_vi": "Trạng thái muốn được bảo vệ khỏi nguy hiểm"}, {"term_ko": "사랑", "term_vi": "Yêu", "def_ko": "긍정적인 감정의 표현", "def_vi": "Sự thể hiện cảm xúc tích cực"}, {"term_ko": "소속", "term_vi": "Tham gia", "def_ko": "어떤 그룹에 포함되거나 관계가 있는 상태", "def_vi": "Trạng thái được bao gồm trong một nhóm hoặc có mối quan hệ"}, {"term_ko": "자아실현", "term_vi": "Tự hiện thực hóa", "def_ko": "개인의 잠재력을 충분히 발휘하는 것", "def_vi": "Việc phát huy tối đa tiềm năng của một cá nhân"}, {"term_ko": "존경", "term_vi": "Tôn trọng", "def_ko": "타인으로부터 인정받는 것", "def_vi": "Được công nhận bởi người khác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (684, '2', '노인장기요양보험제도에서 대상자에게 제공하는 요양보호서비스의 목적으로 옳은 것은?', '["신체기능 증진 및 삶의 질 향상", "안전의 욕구 충족", "자아실현의 욕구 충족", "생리적 욕구 충족", "자아존중의 욕구 충족"]'::jsonb, 1, '노인장기요양보험제도에서 제공하는 서비스의 목적을 이해하고 구분하기 위함입니다.', NULL, '{"1": "신체기능 증진 및 삶의 질 향상은 요양보호서비스의 주요 목적 중 하나입니다.\n[정답]", "2": "안전의 욕구 충족은 요양보호서비스의 하나의 측면이지만 주된 목적은 아닙니다.", "3": "자아실현의 욕구 충족은 요양보호 서비스의 직접적인 목적이라기보다는 장기적인 목표일 수 있습니다.", "4": "생리적 욕구 충족은 기본적인 요구를 포함하지만, 요양보호서비스의 모든 목적을 포괄하지 않습니다.", "5": "자아존중의 욕구 충족도 중요하지만, 제공 서비스의 주요 목적이라 보기 어려운 하나입니다."}'::jsonb, '[{"term_ko": "노인장기요양보험제도", "term_vi": "Chế độ bảo hiểm chăm sóc dài hạn cho người già", "def_ko": "노인을 위한 장기 요양 서비스 제공 시스템", "def_vi": "Hệ thống cung cấp dịch vụ chăm sóc dài hạn cho người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (683, '2', '장기요양서비스 제공 계획을 수립하기 전에 대상자의 신체적 상황, 정신심리 상태, 사회 환경까지 파악하는 평가 방법은?', '["업무평가", "상태평가", "욕구평가", "종합평가", "자가평가"]'::jsonb, 3, '장기요양서비스를 제공하기 위해서는 대상자의 전반적인 상황을 이해해야 한다는 점을 강조하고 있다.', NULL, '{"1": "업무평가는 특정 업무의 수행 능력이나 진행 상황을 평가하는 방법이다.", "2": "상태평가는 대체로 건강 상태를 중점적으로 평가하는 방법이다.\n[정답]", "3": "욕구평가는 대상자의 신체적, 정신적, 사회적 요구를 파악하기 위한 평가 방법이다.", "4": "종합평가는 여러 가지 요소를 아우르는 전체적인 평가를 의미한다.", "5": "자가평가는 본인이 스스로 자신의 상태를 평가하는 방법이다."}'::jsonb, '[{"term_ko": "장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기간 동안 지속되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc kéo dài trong thời gian dài"}, {"term_ko": "신체적", "term_vi": "Thể chất", "def_ko": "신체와 관련된, 신체적 특성", "def_vi": "Liên quan đến cơ thể, đặc điểm thể chất"}, {"term_ko": "정신심리", "term_vi": "Tâm lý", "def_ko": "정신적이고 심리적인 것과 관련된", "def_vi": "Liên quan đến tâm trí và tâm lý"}, {"term_ko": "사회 환경", "term_vi": "Môi trường xã hội", "def_ko": "사회적 맥락", "def_vi": "Bối cảnh xã hội"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "필요, 요구", "def_vi": "Cần thiết, yêu cầu"}, {"term_ko": "평가", "term_vi": "Đánh giá", "def_ko": "측정하거나 판단하는 과정", "def_vi": "Quá trình đo lường hoặc đánh giá"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (682, '2', '장기요양서비스 이용절차 단계 중 대상자 및 가족에게 만족스러운 서비스가 제공되고 있는지를 점검하는 것은?', '["서비스 신청접수 및 방문상담", "서비스 제공 계획 수립", "서비스 이용 계획 체결", "서비스 제공", "모니터링 실시"]'::jsonb, 5, '장기요양서비스의 이용 절차 중 점검 및 평가의 중요성을 묻는 문제입니다.', NULL, '{"1": "서비스 신청접수 및 방문상담: 서비스 제공을 위한 초기 단계입니다.", "2": "서비스 제공 계획 수립: 서비스 제공을 위한 계획을 만드는 과정입니다.", "3": "서비스 이용 계획 체결: 이용 계획을 공식적으로 체결하는 단계입니다.", "4": "서비스 제공: 실제 서비스를 제공하는 단계입니다.\n[정답]", "5": "모니터링 실시: 서비스 제공 후 대상자와 가족의 만족도를 점검하는 단계입니다."}'::jsonb, '[{"term_ko": "장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기적인 간호와 요양이 필요한 사람을 위한 서비스", "def_vi": "Dịch vụ dành cho những người cần chăm sóc và điều dưỡng lâu dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (681, '2', '개인별장기요양이용계획서에 기록되지 않는 것은?', '["인정유효기간", "월 한도액", "수급자 희망급여", "급여의 종류와 횟수", "수급자의 월 수입액"]'::jsonb, 5, '개인별 장기 요양 이용 계획서에서 기록해야 할 사항에 대한 이해를 평가하는 문제입니다.', NULL, '{"1": "인정유효기간은 장기 요양 서비스 제공에 필요한 기간을 나타내기 때문에 기록되어야 합니다.\n[정답]", "5": "수급자의 월 수입액은 개인별 장기 요양 이용 계획서에 기록되지 않습니다.", "2": "월 한도액은 서비스 이용 시 상한선을 나타내므로 기록되어야 합니다.", "3": "수급자 희망급여는 수급자가 원하는 서비스를 나타내므로 기록되어야 합니다.", "4": "급여의 종류와 횟수는 어떤 서비스를 얼마나 받을지를 나타내므로 기록되어야 합니다."}'::jsonb, '[{"term_ko": "개인별", "term_vi": null, "def_ko": "개인에 대한", "def_vi": null}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (680, '2', '대상자의 등급에 따른 한도액과 본인부담률, 급여의 종류와 횟수 등 대상자와 가족들이 적절히 장기요양서비스를 이용할 수 있도록 돕기 위한 안내서는?', '["장기요양인정서", "개인별장기요양이용계획서", "장기요양평가서", "국민건강보험증", "모니터링기록지"]'::jsonb, 2, '대상자가 장기요양서비스를 적절히 이용할 수 있도록 하기 위한 안내서를 묻는 문제입니다.', NULL, '{"1": "장기요양인정서는 장기요양급여를 받을 수 있는 자격을 인증하는 문서입니다.\n[정답]", "2": "개인별장기요양이용계획서는 장기요양 서비스 이용을 위한 세부 계획을 제시하며, 대상자와 가족이 필요한 정보를 얻을 수 있습니다.", "3": "장기요양평가서는 대상자의 건강 상태나 필요를 평가하는 문서입니다.", "4": "국민건강보험증은 건강보험의 자격을 증명하는 카드로, 장기요양서비스와는 직접적인 연관이 없습니다.", "5": "모니터링기록지는 서비스 제공 후의 상태를 기록하는 문서입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người hưởng lợi", "def_ko": "환자 또는 수혜자", "def_vi": "bệnh nhân hoặc người nhận hỗ trợ"}, {"term_ko": "장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기 요양지원 서비스", "def_vi": "dịch vụ hỗ trợ chăm sóc dài hạn"}, {"term_ko": "본인부담률", "term_vi": "Tỷ lệ tự chi trả", "def_ko": "본인이 부담해야 하는 비용 비율", "def_vi": "tỷ lệ chi phí mà người hưởng lợi phải chi trả"}, {"term_ko": "한도액", "term_vi": "Giới hạn số tiền", "def_ko": "최대 금액", "def_vi": "số tiền tối đa"}, {"term_ko": "안내서", "term_vi": "Tài liệu hướng dẫn", "def_ko": "사용 설명서", "def_vi": "tài liệu chỉ dẫn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (679, '2', '장기요양인정 등급판정결과에 이의가 있는 경우 통보를 받은 날로부터 며칠 내에 공단에 증명서류를 제출하는가?', '["15일", "30일", "45일", "60일", "90일"]'::jsonb, 5, '장기요양인정에 대한 이의 제기 절차에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "15일은 이의 제기 기간이 아닙니다.\n[정답]", "5": "90일 내에 공단에 증명서류를 제출해야 합니다.", "2": "30일은 이의 제기 기간이 아닙니다.", "3": "45일은 틀린 정보입니다.", "4": "60일 또한 이의 제기에 대한 규정이 아닙니다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Công nhận chăm sóc dài hạn", "def_ko": "장기간 요양이 필요한 사람에 대한 공식적인 인정", "def_vi": "Sự công nhận chính thức cho những người cần chăm sóc lâu dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (678, '2', '다음 ( ) 안에 들어갈 내용은?장기요양보험료를 ( ) 이상 납부하지 아니하면 장기요양급요를 받을 수 없다.', '["1회", "2회", "3회", "4회", "5회"]'::jsonb, 4, '장기요양보험료 납부 기준을 확인하기 위한 문제이다.', NULL, '{"1": "1회 이상 납부는 장기요양급여를 받을 수 있는 조건이 아니다.\n[정답]", "4": "4회 이상 납부해야 장기요양급여를 받을 수 있다.", "2": "2회 이상 납부는 기준에 미달한다.", "3": "3회 이상 납부 역시 기준에 미달한다.", "5": "5회 이상 납부하면 조건을 초과한 것이므로 부적절하다."}'::jsonb, '[{"term_ko": "장기요양보험료", "term_vi": "Bảo hiểm chăm sóc dài hạn", "def_ko": "장기요양 서비스를 위한 보험료", "def_vi": "Phí bảo hiểm cho dịch vụ chăm sóc dài hạn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (677, '2', '장기요양인정의 갱신신청을 하고자 할 경우 올바른 신청 기간은?', '["유효기간이 만료되기 60일 전부터 30일 전까지", "유효기간이 만료된 후 30일 전부터 60일 까지", "유효기간이 만료된 후 30일 전부터 90일 까지", "유효기간이 만료되기 90일 전부터 60일 전까지", "유효기간이 만료되기 90일 전부터 30일 전까지"]'::jsonb, 5, '장기요양인정의 갱신신청에 대한 정확한 기간을 이해하고 있는지 평가하기 위함입니다.', NULL, '{"1": "유효기간이 만료되기 60일 전부터 30일 전까지는 틀린 정보입니다. 갱신 신청은 만료 전 90일 이내에 해야 합니다.\n[정답]", "5": "유효기간이 만료되기 90일 전부터 30일 전까지가 맞습니다. 이 기간 내에 신청해야 갱신이 가능합니다.", "2": "유효기간이 만료된 후 30일 전부터 60일 까지는 잘못된 정보입니다. 만료 후에는 갱신이 불가능합니다.", "3": "유효기간이 만료된 후 30일 전부터 90일 까지도 틀린 정보입니다.", "4": "유효기간이 만료되기 90일 전부터 60일 전까지는 잘못된 내용입니다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Công nhận chăm sóc lâu dài", "def_ko": "장기요양 서비스 제공을 위해 필요한 인증", "def_vi": "Chứng nhận cần thiết để cung cấp dịch vụ chăm sóc lâu dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (676, '2', '장기요양인정서에 기재하는 내용으로 옳은 것은?', '["이용가능 한도액", "장기요양급여의 종류 및 내용", "수급자 희망급여", "수급자의 주요 기능상태", "본인부담금"]'::jsonb, 2, '장기요양인정서에 포함되는 주요 정보를 이해하고 판단하는 능력을 평가하기 위함입니다.', NULL, '{"1": "이용가능 한도액은 장기요양급여의 재정적 측면에 해당하지만, 장기요양인정서에는 기재되지 않습니다.\n[정답]", "2": "장기요양급여의 종류 및 내용은 장기요양인정서에 필수적으로 기재되어야 하는 내용입니다.", "3": "수급자 희망급여는 신청서와 관련이 있지만, 인정을 받는 서류에는 포함되지 않습니다.", "4": "수급자의 주요 기능상태는 보통 평가에 포함되지만, 인정을 받는 구조에는 기재되지 않습니다.", "5": "본인부담금은 장기요양 급여와 관련된 내용이지만, 장기요양인정서에는 포함되지 않습니다."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기적 지원이 필요한 노인이나 장애인을 위한 요양 서비스", "def_vi": "Dịch vụ chăm sóc cho người già hoặc người khuyết tật cần hỗ trợ lâu dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (675, '2', '등급 판정 후 수급자가 서비스르 제공받을 때 제시해야 하는 것은?', '["모니터링기록지", "국민건강보험증", "장기요양인정서", "장기요양평가서", "장기요양이용계획서"]'::jsonb, 3, '서비스 이용을 위한 필요 서류를 알고 있는지를 평가하고자 함.', NULL, '{"1": "모니터링기록지는 서비스 제공 후 상태를 체크하는 용도이므로, 서비스 제공 전에 제시할 필요는 없음.\n[정답] (③) 장기요양인정서는 서비스 제공을 받기 위해 필수적으로 제시해야 하는 서류임.", "2": "국민건강보험증은 일반적인 의료 서비스에 필요하지만, 장기요양 서비스에는 직접적으로 무관함.", "4": "장기요양평가서는 평가 과정에서 작성되나, 서비스 제공 시 제시해야 하는 서류는 아님.", "5": "장기요양이용계획서는 서비스 제공 계획을 설명하는 문서이나, 공식적으로 제시해야 하는 서류는 아닌 경우가 많음."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기적인 돌봄 서비스", "def_vi": "Dịch vụ chăm sóc lâu dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (674, '2', '장기요양등급, 유효기간 등 수급자가 장기요양서비스를 제공받을 때 필요한 안내사항이 기재되어 있는 것은?', '["모니터링기록표", "장기요양인정서", "방문간호지시서", "요양보호기록지", "개인별장기요양이용계획서"]'::jsonb, 2, '장기요양서비스를 받는 수급자가 알아야 할 중요한 안내사항을 파악하는 것이다.', NULL, '{"1": "모니터링기록표: 수급자의 상태를 지속적으로 기록하는 표로, 안내사항과는 다소 관련이 없다.\n[정답]", "2": "장기요양인정서: 수급자가 어떤 장기요양서비스를 받을 수 있는지를 명시한 공식 문서로, 안내사항을 포함하고 있다.", "3": "방문간호지시서: 방문간호사가 수급자에게 필요한 치료내용에 대한 지시사항으로, 안내사항과는 다소 관련이 없다.", "4": "요양보호기록지: 요양보호사가 수급자의 일일 상태를 기록하는 지표로, 안내사항이 기재되지는 않는다.", "5": "개인별장기요양이용계획서: 수급자의 이용계획을 담은 문서이나, 직접적인 안내사항이 포함되지는 않는다."}'::jsonb, '[{"term_ko": "장기요양등급", "term_vi": "장기요양서비스", "def_ko": "등급 phân loại dịch vụ chăm sóc dài hạn", "def_vi": "dịch vụ chăm sóc dài hạn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (673, '2', '등급판정을 받은 장기요양인정자의 서비스이용 신청 절차로 옳은 것은?가. 서비스신청 접수 및 받문 상담 나. 서비스제공 다. 서비스제공 계획 수립 라. 서비스이용 계약 체결 마. 모니터링 실시', '["가 - 나 - 다 - 라 - 마 - 바", "나 - 가 - 다 - 마 - 라 - 바", "다 - 가 - 나 - 라 - 마 - 바", "가 - 다 - 라 - 나 - 마 - 바", "라 - 가 - 나 - 다 - 마 - 바"]'::jsonb, 4, '장기요양인정자가 서비스를 이용하기 위한 절차를 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "서비스 신청이 접수되어야 제반 상담이 이루어질 수 있지만, 순서가 잘못되어 있습니다.", "2": "서비스 제공은 그 후에 진행될 주체적 활동이므로 올바른 순서가 아닙니다.", "3": "모든 단계가 후속 조치에 대한 착각이 있습니다.  \n[정답]", "4": "서비스 신청 접수 후 상담이 실시되고, 이후 서비스 제공 계획이 수립되며, 계약 체결 후 모니터링이 이루어지는 순서가 맞습니다.", "5": "계약 체결이 신청 접수보다 먼저 이루어질 수는 없습니다."}'::jsonb, '[{"term_ko": "등급", "term_vi": "Cấp độ", "def_ko": "수준(한국어)", "def_vi": "Mức độ(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (672, '2', '다음 설명 중 ( ) 안에 들어갈 내용으로 옳은 것은?', '["15% 20%", "15% 10%", "20% 15%", "10% 7.5%", "7.5% 10%"]'::jsonb, 3, '(특정 비율을 알고 있는지를 묻는 문제)', NULL, '{"1": "15%와 20%의 비율은 질문과 관련이 없음.\n[정답]", "3": "20%와 15%의 비율은 질문에 적합한 설명입니다.", "2": "15%와 10%의 비율은 부적합합니다.", "4": "10%와 7.5%의 비율은 질문과 맞지 않습니다.", "5": "7.5%와 10%의 비율 역시 부적합합니다."}'::jsonb, '[{"term_ko": "비율", "term_vi": "Tỷ lệ", "def_ko": "뜻(한국어)", "def_vi": "nghĩa(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (671, '2', '장기요양보험의 재원조달에 대한 설명으로 옳은 것은?', '["공단은 장기요양보험료와 건강보험료를 별도로 징수한다.", "국가는 보험료 예상 수입액의 80%를 부담한다.", "재원은 장기요양보험료, 국가지원, 본인부담금으로 구성된다.", "저소득층, 의료급여 수급권자 등은 본인부담금의 20%를 경감해 준다.", "비급여 항목은 전액 국가가 부담한다."]'::jsonb, 3, '장기요양보험의 재원 조달 구조에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "공단은 장기요양보험료와 건강보험료를 별도로 징수한다. (장기요양보험료와 건강보험료는 통합 징수됩니다.)\n[정답]", "3": "재원은 장기요양보험료, 국가지원, 본인부담금으로 구성된다. (정확한 설명입니다.)", "2": "국가는 보험료 예상 수입액의 80%를 부담한다. (국가의 부담 비율은 다릅니다.)", "4": "저소득층, 의료급여 수급권자 등은 본인부담금의 20%를 경감해 준다. (정확한 경감 비율이 아닙니다.)", "5": "비급여 항목은 전액 국가가 부담한다. (비급여 항목은 개인이 부담합니다.)"}'::jsonb, '[{"term_ko": "장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn", "def_ko": "장기적인 요양 필요를 위한 보험", "def_vi": "Bảo hiểm cho nhu cầu chăm sóc lâu dài"}, {"term_ko": "재원", "term_vi": "Nguồn tài chính", "def_ko": "자금을 조달하는 방법", "def_vi": "Phương pháp thu tài chính"}, {"term_ko": "국가지원", "term_vi": "Hỗ trợ của nhà nước", "def_ko": "국가에서 지원하는 금액", "def_vi": "Số tiền hỗ trợ từ nhà nước"}, {"term_ko": "본인부담금", "term_vi": "Tiền tự chi trả", "def_ko": "개인이 부담해야 하는 금액", "def_vi": "Số tiền cá nhân phải chi trả"}, {"term_ko": "비급여", "term_vi": "Không được hưởng bảo hiểm", "def_ko": "보험 적용이 안 되는 항목", "def_vi": "Các hạng mục không nằm trong bảo hiểm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (670, '2', '다음 중 노인장기요양보험제도에 대한 설명으로 옳은 것은?', '["장기요양기고나은 장기요양급여를 제공한 후 국민건강보험공단에 비용을 청구한다.", "국민건강보험공단은 급여비용을 연 1회 장기요양기관에 지급한다.", "시설급여는 15%, 재가급여는 20%를 본인이 부담한다.", "유효기간 갱신 시 직전등급과 같은 2등급일 경우 유효기간 4년이다.", "국민기초생활수급권자는 본인이 50%를 부담한다."]'::jsonb, 1, '노인장기요양보험제도의 기본 개념과 운영 방식을 이해하고 있는지를 평가하려는 의도입니다.', NULL, '{"1": "장기요양기관에서 장기요양급여를 제공한 후 국민건강보험공단에 비용을 청구하게 되며, 이는 맞는 설명입니다.\n[정답]", "2": "국민건강보험공단은 급여비용을 연 1회가 아닌 매월 장기요양기관에 지급합니다.", "3": "시설급여와 재가급여에 대한 본인 부담률은 다르지만, 시설급여 15%, 재가급여 20%는 틀린 정보입니다.", "4": "유효기간 갱신 시 직전등급이 2등급일 경우 4년이 아닌 3년입니다.", "5": "국민기초생활수급권자는 본인 부담이 발생하지 않으며, 0%로 부담하는 것이 맞습니다."}'::jsonb, '[{"term_ko": "노인장기요양보험제도", "term_vi": "Chế độ bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "고령자를 위한 장기요양 지원 프로그램", "def_vi": "Chương trình hỗ trợ chăm sóc dài hạn cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (669, '2', '다음 중 방문목욕을 제공하는 장기요양요원으로 옳은 것은?', '["간호사", "사회복지사", "간호조무사", "요양보호사", "물리치료사"]'::jsonb, 4, '방문목욕을 제공할 수 있는 장기요양요원의 범위를 확인하기 위함입니다.', NULL, '{"1": "간호사는 전문적인 의료 서비스를 제공하지만 방문목욕은 포함되지 않습니다.\n[정답]", "4": "요양보호사는 방문목욕을 포함하여 여러 가지 요양서비스를 제공할 수 있는 자격을 가지고 있습니다.", "2": "사회복지사는 주로 상담 및 지원 서비스를 제공하며, 신체적인 목욕 서비스는 담당하지 않습니다.", "3": "간호조무사는 간호사 보조 업무를 수행하지만 방문목욕은 주된 업무가 아닙니다.", "5": "물리치료사는 재활 치료를 수행하지만 직접적인 목욕 서비스를 제공하지 않습니다."}'::jsonb, '[{"term_ko": "방문목욕", "term_vi": "Tắm tại nhà", "def_ko": "가정에서 이루어지는 목욕 서비스", "def_vi": "Dịch vụ tắm thực hiện tại nhà"}, {"term_ko": "장기요양요원", "term_vi": "Nhân viên chăm sóc dài hạn", "def_ko": "장기적으로 요양 서비스를 제공하는 사람", "def_vi": "Người cung cấp dịch vụ chăm sóc lâu dài"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "요양과 돌봄을 전문으로 하는 직원", "def_vi": "Nhân viên chuyên về chăm sóc và hỗ trợ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (668, '2', '수급자가 장기요양기관이 아닌 노인요양시설 등의 기관 도는 시설에서 장기요양급여를 받은 경우 수급자에게 지급되는 현금급여는?', '["가족요양비", "특례요양비", "요양병원 간병비", "방문요양비", "장해급여비"]'::jsonb, 2, '장기요양급여의 현금급여 종류를 이해하고 있는지를 평가하기 위함이다.', NULL, '{"1": "가족요양비: 가족이 수급자를 돌보는 경우 지급되는 비용이다.\n[정답]", "2": "특례요양비: 장기요양기관이 아닌 시설에서 제공되는 요양급여에 대한 지급으로, 노인요양시설 등에서 받는 경우 적용된다.", "3": "요양병원 간병비: 요양병원에서 간병 서비스를 제공받을 때 소요되는 비용이다.", "4": "방문요양비: 방문 요양 서비스를 제공받을 때 지급되는 비용이다.", "5": "장해급여비: 장애인에 대한 특별한 지원금을 의미한다."}'::jsonb, '[{"term_ko": "수급자", "term_vi": "Người thụ hưởng", "def_ko": "요양급여를 받는 사람", "def_vi": "Người nhận trợ cấp chăm sóc"}, {"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기적인 요양 서비스를 제공하는 기관", "def_vi": "Nơi cung cấp dịch vụ chăm sóc dài hạn"}, {"term_ko": "현금급여", "term_vi": "Trợ cấp tiền mặt", "def_ko": "현금 형태로 지급되는 지원금", "def_vi": "Khoản hỗ trợ tiền mặt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (667, '2', '장기요양기관이 없는 외딴 섬에 살고 있는 대상자가 며느리로부터 방문요양에 상당하는 장기요양급여를 받았다. 이때 지급되는 특별현금급여는?', '["재가급여", "시설급여", "가족요양비", "특례요양비", "요양병원 간병비"]'::jsonb, 3, '장기요양급여의 종류와 지급 기준을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "재가급여는 장기요양기관이 아닌 개인에게 지급되는 요양 서비스입니다.\n[정답]", "3": "가족요양비는 가족이 직접 요양을 제공하는 경우 지급되는 특별현금급여입니다.", "2": "시설급여는 기관에 입소해 요양을 받는 경우에 해당합니다.", "4": "특례요양비는 특정 조건에 따라 지급되는 요양비입니다.", "5": "요양병원 간병비는 병원에서 발생하는 간병비와 관련이 있습니다."}'::jsonb, '[{"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기적으로 요양 서비스를 제공하는 기관", "def_vi": "Cơ sở cung cấp dịch vụ chăm sóc dài hạn"}, {"term_ko": "방문요양", "term_vi": "Chăm sóc tại nhà", "def_ko": "가정에서 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc được cung cấp tại nhà"}, {"term_ko": "특별현금급여", "term_vi": "Trợ cấp tiền mặt đặc biệt", "def_ko": "특별한 조건에서 지급되는 현금 지원", "def_vi": "Hỗ trợ tiền mặt được trả trong các trường hợp đặc biệt"}, {"term_ko": "가족요양비", "term_vi": "Chi phí chăm sóc gia đình", "def_ko": "가족이 제공하는 요양에 대한 지급", "def_vi": "Khoản thanh toán cho việc chăm sóc của gia đình"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (666, '2', '수급자의 일상생활, 신체활동 지원에 필요한 복지용구를 제공하는 장기요양급여는?', '["가족요양급여", "단기보호 급여", "방문요양 급여", "주, 야간보호 급여", "기타 재가급여"]'::jsonb, 5, '수급자의 일상생활을 지원하기 위한 복지용구에 대한 이해도를 평가하고자 함.', NULL, '{"1": "가족요양급여: 가족이 수급자를 돌보는 경우에 제공되는 급여로, 복지용구에 대한 직접적인 지원이 아님.\n[정답]", "5": "기타 재가급여: 수급자의 일상생활과 신체활동을 지원하기 위해 필요한 복지용구를 제공하는 장기요양급여를 포함하는 개념.", "3": "방문요양 급여: 직접적인 방문을 통해 서비스를 제공하지만 복지용구와는 관련이 적음.", "4": "주, 야간보호 급여: 주간 또는 야간에 보호 서비스를 제공하는 것으로 복지용구의 제공과는 직접적으로 연결되지 않음.", "2": "단기보호 급여: 제한된 기간 동안 보호하는 프로그램으로, 장기요양급여의 일환일 수 있으나 복지용구 지원과는 거리가 있음."}'::jsonb, '[{"term_ko": "수급자", "term_vi": "Người thụ hưởng", "def_ko": "요양이나 재활 서비스를 받는 사람", "def_vi": "Người nhận dịch vụ chăm sóc hoặc phục hồi chức năng"}, {"term_ko": "복지용구", "term_vi": "Dụng cụ phúc lợi", "def_ko": "신체활동을 돕기 위한 도구", "def_vi": "Công cụ hỗ trợ hoạt động thể chất"}, {"term_ko": "장기요양급여", "term_vi": "Trợ cấp chăm sóc dài hạn", "def_ko": "장기간 동안 제공되는 요양 관련 서비스", "def_vi": "Dịch vụ chăm sóc dài hạn"}, {"term_ko": "일상생활", "term_vi": "Sinh hoạt hàng ngày", "def_ko": "매일의 기본 활동", "def_vi": "Các hoạt động cơ bản hàng ngày"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (665, '2', '요양보호사가 할 수 없는 업무는 무엇인가?', '["방문목욕", "신체활동지원", "방문간호", "정서지원, 의사소통", "가사 및 일상생활지원"]'::jsonb, 3, '요양보호사가 수행할 수 없는 업무를 파악하는 것.', NULL, '{"1": "방문목욕은 요양보호사가 수행할 수 있는 업무이다.", "2": "신체활동지원은 요양보호사의 주요 업무 중 하나이다.\n[정답]", "3": "방문간호는 의료 행위로, 요양보호사가 수행할 수 없는 업무이다.", "4": "정서지원 및 의사소통은 요양보호사가 수행할 수 있는 업무이다.", "5": "가사 및 일상생활지원도 요양보호사의 업무에 포함된다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 전문 직업인", "def_vi": "Người chuyên chăm sóc bệnh nhân"}, {"term_ko": "업무", "term_vi": "Công việc", "def_ko": "직무, 사무", "def_vi": "Nhiệm vụ"}, {"term_ko": "방문목욕", "term_vi": "Tắm tại nhà", "def_ko": "집에서 목욕을 도와주는 서비스", "def_vi": "Dịch vụ giúp tắm tại nhà"}, {"term_ko": "신체활동지원", "term_vi": "Hỗ trợ hoạt động cơ thể", "def_ko": "신체 활동을 돕는 것", "def_vi": "Giúp đỡ các hoạt động thể chất"}, {"term_ko": "방문간호", "term_vi": "Chăm sóc tại nhà", "def_ko": "환자의 집에서 전문 간호를 제공하는 것", "def_vi": "Cung cấp dịch vụ chăm sóc sức khỏe tại nhà"}, {"term_ko": "정서지원", "term_vi": "Hỗ trợ cảm xúc", "def_ko": "감정적인 지지를 제공하는 것", "def_vi": "Cung cấp sự hỗ trợ về cảm xúc"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "의사전달과 관련된 활동", "def_vi": "Hoạt động liên quan đến giao tiếp"}, {"term_ko": "가사", "term_vi": "Công việc nhà", "def_ko": "집안일과 관련된 활동", "def_vi": "Các hoạt động liên quan đến công việc gia đình"}, {"term_ko": "일상생활지원", "term_vi": "Hỗ trợ sinh hoạt hàng ngày", "def_ko": "일상 생활에서 필요한 지원", "def_vi": "Sự hỗ trợ cần thiết trong cuộc sống hàng ngày"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (664, '2', '대상자의 가정을 방문하여 신체활동과 가사활동 등의 서비스를 제공하는 재가급여를 무엇이라 하는가?', '["방문요양", "방문목욕", "방문간호", "단기보호", "주-야간보호"]'::jsonb, 1, '재가급여의 개념과 종류에 대한 이해를 평가하기 위한 문제이다.', NULL, '{"1": "방문요양: 가정에서 신체활동과 가사활동 등의 서비스를 제공하는 재가급여의 대표적인 형태이다.\n[정답]", "2": "방문목욕: 목욕 서비스를 전문적으로 제공하는 형태로, 신체활동의 일부일 수 있으나 재가급여 전체를 포괄하지 않는다.", "3": "방문간호: 간호 서비스를 제공하는 형태로, 물리적인 신체활동과 가사활동을 포함하지 않는다.", "4": "단기보호: 일정 기간 동안 보호를 필요로 하는 대상자를 위한 서비스로, 재가급여의 범위를 벗어난다.", "5": "주-야간보호: 정해진 시간 동안의 보호 서비스를 제공하나, 주로 시설 내에서 제공된다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자 혹은 보호를 받는 사람", "def_vi": "Bệnh nhân hoặc người được bảo trợ"}, {"term_ko": "신체활동", "term_vi": "Hoạt động thân thể", "def_ko": "신체의 움직임과 관련된 활동", "def_vi": "Các hoạt động liên quan đến sự di chuyển của cơ thể"}, {"term_ko": "가사활동", "term_vi": "Hoạt động gia đình", "def_ko": "집안일을 포함하는 활동", "def_vi": "Các hoạt động bao gồm công việc trong gia đình"}, {"term_ko": "재가급여", "term_vi": "Dịch vụ chăm sóc tại nhà", "def_ko": "가정에서 제공되는 사회복지 서비스", "def_vi": "Dịch vụ phúc lợi xã hội cung cấp tại nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (663, '2', '대상자를 하루 중 일정 시간 동안 장기요양기관에 보호하여 신체활동 지원 등을 제공하는 장기요양급여는?', '["주-야간보호", "단기보호", "특례요양급여", "가족요양급여", "요양병원 간병급여"]'::jsonb, 1, '장기요양기관에서 제공되는 다양한 서비스의 종류를 이해하고 있는지를 묻는 문제입니다.', NULL, '{"1": "주-야간보호는 대상자가 하루 중 일정 시간에 보호를 받을 수 있는 장기요양급여입니다.\n[정답]", "2": "단기보호는 일정 기간 동안 일시적으로 제공되는 서비스입니다.", "3": "특례요양급여는 특별한 경우에 제공되는 요양급여입니다.", "4": "가족요양급여는 가족이 보호자의 역할을 수행하는 경우의 급여입니다.", "5": "요양병원 간병급여는 병원에서 간병을 제공받는 것과 관련된 급여입니다."}'::jsonb, '[{"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기간 요양 서비스를 제공하는 기관", "def_vi": "Tổ chức cung cấp dịch vụ chăm sóc dài hạn"}, {"term_ko": "신체활동", "term_vi": "Hoạt động thể chất", "def_ko": "신체의 움직임과 활동", "def_vi": "Sự chuyển động và hoạt động của cơ thể"}, {"term_ko": "주-야간보호", "term_vi": "Chăm sóc ngày và đêm", "def_ko": "낮과 밤에 제공되는 보호 서비스", "def_vi": "Dịch vụ bảo vệ cả ban ngày và ban đêm"}, {"term_ko": "단기보호", "term_vi": "Chăm sóc ngắn hạn", "def_ko": "짧은 기간 동안 제공되는 보호 서비스", "def_vi": "Dịch vụ bảo vệ được cung cấp trong thời gian ngắn"}, {"term_ko": "가족요양급여", "term_vi": "Trợ cấp chăm sóc gia đình", "def_ko": "가족이 제공하는 요양 서비스", "def_vi": "Dịch vụ chăm sóc do gia đình cung cấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (662, '2', '다음 재가급여의 내용 중 옳은 것은?', '["방문요양: 재가 대상자의 기능 유지를 위한 복지용구를 제공한다.", "방문간호; 수급자를 방문하여 신체활동 및 가사활동을 지원한다.", "방문목욕: 수급자의 가정 등을 방문하여 목욕을 제공한다.", "단기보호: 장기요양기관에 장기간 입소하여 보호한다.", "주-야간보호: 일정기간 동안 장기요양기관에 보호하여 신체활동을 지원한다."]'::jsonb, 3, '재가급여의 각 종류에 대한 정확한 이해 여부를 평가하고자 함.', NULL, '{"1": "방문요양: 복지용구 제공은 포함되지 않으며, 주로 신체활동 지원을 목적으로 함.\n[정답]", "3": "방문목욕: 수급자의 가정에 방문하여 목욕을 제공하는 것이 옳음.", "2": "방문간호: 신체활동 지원이 아닌 의료적 간호 서비스를 제공함.", "4": "단기보호: 장기간이 아닌 단기간의 보호 서비스임.", "5": "주-야간보호: 주-야간 보호는 일정 기간 동안 보호하는 것이 아닌, 주간/야간에 제공되는 보호 서비스임."}'::jsonb, '[{"term_ko": "재가급여", "term_vi": "Dịch vụ hỗ trợ tại nhà", "def_ko": "가정에서 제공되는 복지 서비스", "def_vi": "Dịch vụ phúc lợi được cung cấp tại nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (661, '2', '장기요양급여 중 시설급여의 장점으로 옳은 것은?', '["개인중심의 생활을 할 수 있다.", "사생활이 보호된다.", "친숙한 환경에서 지낼 수 있다.", "종합적인 서비스를 받을 수 있다.", "재가급여보다 본인부담금이 저렴하다."]'::jsonb, 4, '장기요양급여 중 시설급여의 이점을 이해하고, 그 중 올바른 선택지를 찾는 것이 목표이다.', NULL, '{"1": "개인중심의 생활을 할 수 있다. - 시설급여는 주로 관리와 돌봄이 필요할 때 제공되므로 개인중심의 생활이 제한될 수 있다.\n[정답]", "4": "종합적인 서비스를 받을 수 있다. - 시설급여는 다양한 서비스를 통합적으로 제공하여, 복합적인 필요에 대응하는 것이 장점이다.", "3": "친숙한 환경에서 지낼 수 있다. - 시설급여는 종종 낯선 환경을 제공하므로 친숙하지 않을 수 있다.", "5": "재가급여보다 본인부담금이 저렴하다. - 본인부담금은 경우에 따라 다르므로 반드시 저렴하다고 할 수 없다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Bồi dưỡng dài hạn", "def_ko": "장기적으로 요양이 필요한 사람에게 제공되는 복지 급여", "def_vi": "Trợ cấp phúc lợi cung cấp cho những người cần chăm sóc dài hạn"}, {"term_ko": "시설급여", "term_vi": "Chăm sóc tại cơ sở", "def_ko": "시설에서 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc tại cơ sở"}, {"term_ko": "종합적인", "term_vi": "Tổng hợp", "def_ko": "여러 가지를 포괄하는", "def_vi": "Bao gồm nhiều điều"}, {"term_ko": "본인부담금", "term_vi": "Chi phí tự trả", "def_ko": "의료 서비스를 이용할 때 개인이 직접 부담해야 하는 비용", "def_vi": "Số tiền mà cá nhân phải tự chi trả khi sử dụng dịch vụ y tế"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (660, '2', '장기요양급여 중 재가급여의 장점으로 옳은 것은?', '["의료, 간호, 요양서비스가 단편적으로 진행되기 쉽다.", "긴급한 상황에 대한 신속한 대응이 어렵다.", "평소 생활했던 친숙한 환경에서 지낼 수 있다.", "개인중심의 생활이 어렵다.", "의료, 간호, 요양서비스를 종합적으로 제공 받을 수 있다."]'::jsonb, 3, '재가급여가 제공되는 장점에 대한 이해를 확인하고자 하는 의도입니다.', NULL, '{"1": "재가급여는 의료, 간호, 요양서비스가 통합적으로 제공되므로 단편적으로 진행되지 않습니다.", "2": "재가급여는 가정에서 이루어지기 때문에 긴급한 상황에 신속히 대응하기 어렵습니다.\n[정답]", "3": "재가급여는 환자가 평소 생활하던 환경에서 서비스를 받을 수 있어 정신적 안정을 제공합니다.", "4": "재가급여는 개인중심의 생활을 가능하게 합니다.", "5": "재가급여는 의료, 간호, 요양서비스를 통합적으로 제공하지 않는 경우도 있습니다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기간 요양이 필요한 환자에게 제공되는 서비스", "def_vi": "Dịch vụ dành cho bệnh nhân cần chăm sóc lâu dài"}, {"term_ko": "재가급여", "term_vi": "Chăm sóc tại nhà", "def_ko": "집에서 이루어지는 요양 서비스", "def_vi": "Dịch vụ chăm sóc diễn ra tại nhà"}, {"term_ko": "의료", "term_vi": "Y tế", "def_ko": "치료와 관련된 서비스", "def_vi": "Dịch vụ liên quan đến chăm sóc sức khỏe"}, {"term_ko": "간호", "term_vi": "Điều dưỡng", "def_ko": "환자의 상태를 살피고 간호하는 서비스", "def_vi": "Dịch vụ chăm sóc và theo dõi tình trạng bệnh nhân"}, {"term_ko": "요양서비스", "term_vi": "Dịch vụ chăm sóc", "def_ko": "진료 이외의 서비스", "def_vi": "Dịch vụ không thuộc điều trị"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (659, '2', '다음의 서비스를 포함하는 장기요양급여 종류는?•방문간호 •단기보호 •주-야간보호', '["재가급여", "시설급여", "간병급여", "퇴직급여", "요양급여"]'::jsonb, 1, '장기요양급여의 유형에 대한 지식을 평가하기 위함입니다.', NULL, '{"1": "재가급여는 방문간호, 단기보호, 주-야간보호 등과 같은 서비스를 포함합니다.\n[정답]", "2": "시설급여는 시설에서 제공하는 요양 서비스를 포함하지만, 문제의 서비스와는 관련이 없습니다.", "3": "간병급여는 주로 간병인을 통한 개별적인 간호 서비스를 의미하며, 방문간호 등은 포함되지 않습니다.", "4": "퇴직급여는 근로자가 퇴직 후 받는 급여로, 요양급여와는 차별적입니다.", "5": "요양급여는 일반적으로 요양을 제공받기 위한 총체적인 개념으로, 특정 서비스의 종류가 아닙니다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Trợ cấp dài hạn", "def_ko": "장기적인 요양 서비스를 제공하는 기초 서비스", "def_vi": "Dịch vụ chăm sóc dài hạn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (658, '2', '노인장기요양보험제도의 설명으로 옳은 것은?', '["고용노동부 장관이 관장한다.", "보험급여에는 재가급여, 시설급여, 특별현금급여가 있다.", "독거노인은 장기요양인정등급이 없어도 수급자가 된다,", "신청일로부터 20일 이내에 등급판정을 완료한다.", "장기요양인정 여부 및 등급은 방문조사자가 최종 판정한다."]'::jsonb, 2, '노인장기요양보험제도에 대한 이해도를 평가하고자 하는 문제입니다.', NULL, '{"1": "고용노동부가 아닌 보건복지부가 관장합니다.\n[정답]", "2": "재가급여, 시설급여, 특별현금급여가 포함됩니다.", "3": "독거노인은 장기요양인정등급을 받아야 수급자가 됩니다.", "4": "신청일로부터 20일 이내에 등급판정이 완료되는 것은 아닙니다.", "5": "방문조사자의 판단만으로는 최종 판정이 이루어지지 않습니다."}'::jsonb, '[{"term_ko": "노인장기요양보험제도", "term_vi": "Hệ thống bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인의 장기요양에 대한 보험 제도", "def_vi": "Hệ thống bảo hiểm cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (657, '2', '2022년 9월에 1등급 판정을 받고, 2024년 9월에 다시 1등급을 받은 대상자의 장기요양인정 유효기간은 몇 년인가?', '["1년", "2년", "3년", "4년", "5년"]'::jsonb, 4, '장기요양인정 유효기간에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "1년: 1등급 판정을 받은 시점에서 1년의 유효기간은 불가능합니다.\n[정답]", "4": "4년: 2022년 9월에 1등급을 받고, 2024년 9월에 다시 1등급을 받으면 유효기간은 4년입니다.", "3": "3년: 3년은 해당 사항이 아닙니다.", "2": "2년: 2년도 기간이 아닙니다.", "5": "5년: 5년은 과도한 기간으로 잘못된 답변입니다."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기간 동안 요양이 필요한 상태", "def_vi": "Tình trạng cần chăm sóc trong thời gian dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (656, '2', '장기요양인정 신청을 하여 최초로 등급판정을 받았을 때, 장기요양 인정 최소 유효기간은?', '["6개월 이상", "1년 이상", "2년 이상", "3년 이상", "5년 이상"]'::jsonb, 3, '장기요양인정 신청과 관련된 최소 유효기간에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "6개월은 장기요양인정의 최소 유효기간이 아닙니다.", "2": "1년도 최소 유효기간에 해당하지 않습니다.\n[정답]", "3": "최초로 등급판정을 받을 경우, 최소 유효기간은 2년 이상입니다.", "4": "3년은 장기요양 인정의 최소 유효기간이 아닙니다.", "5": "5년은 과도한 기간으로, 장기요양 인정의 최소 기간이 아닙니다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Công nhận chăm sóc dài hạn", "def_ko": "장기요양을 필요로 하는 사람에게 주어지는 공식적인 인정", "def_vi": "Sự công nhận chính thức dành cho những người cần chăm sóc dài hạn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (655, '2', '장기요양인정 점수가 45점 미만인 경증치매 어르신이 받을 수 있는 장기요양 등급은?', '["1등급", "2등급", "3등급", "4등급", "인지지원등급"]'::jsonb, 5, '장기요양인정 점수에 따라 경증치매 어르신이 받을 수 있는 장기요양 등급을 묻고 있습니다.', NULL, '{"1": "1등급은 높은 지원이 필요한 경우 부여됩니다.", "2": "2등급은 중간 정도의 지원이 필요할 때 할당됩니다.", "3": "3등급은 경증의 지원이 필요할 경우 주어집니다.", "4": "4등급은 매우 낮은 점수의 경우에는 부여되지 않습니다.\n[정답]", "5": "인지지원등급은 경증치매 어르신이 받을 수 있는 등급입니다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Xác nhận chăm sóc dài hạn", "def_ko": "장기적 요양서비스를 받을 수 있는 자격", "def_vi": "Đủ điều kiện nhận dịch vụ chăm sóc dài hạn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (654, '2', '인지지능 장애로 치매 진단을 확인받고 장기요양인정점수가 45점 이상 51점 미만인 경우 해당되는 장기요양등급은?', '["1등급", "2등급", "3등급", "4등급", "5등급"]'::jsonb, 5, '치매 환자의 장기요양등급을 이해하고 있는지를 확인하기 위한 문제입니다.', NULL, '{"1": "1등급은 95점 이상인 경우에 해당하므로 틀립니다.", "2": "2등급은 61점 이상 70점 미만인 경우에 해당하므로 틀립니다.", "3": "3등급은 46점 이상 60점 미만인 경우에 해당하므로 틀립니다.\n[정답]", "4": "4등급은 41점 이상 45점 미만인 경우에 해당하므로 틀립니다.", "5": "5등급은 45점 이상 51점 미만인 경우에 해당하므로 정답입니다."}'::jsonb, '[{"term_ko": "인지지능", "term_vi": "Năng lực nhận thức", "def_ko": "인지능력이나 사고 능력(한국어)", "def_vi": "Khả năng tư duy và nhận thức"}, {"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기적인 요양과 치료를 뜻함(한국어)", "def_vi": "Điều trị và chăm sóc lâu dài"}, {"term_ko": "등급", "term_vi": "Cấp độ", "def_ko": "단계나 수준(한국어)", "def_vi": "Cấp bậc hay mức độ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (653, '2', '장기요양 4등급에 대한 설명으로 옳은 것은?', '["일상생활에서 전적으로 다른 사람의 도움이 필요하다.", "자립이나 생활관리 능력 저하로 일정부분 도움이 필요하다.", "휠체어를 이용하여 일상생활을 유지한다.", "스스로 움직일 수 없는 와상 상태이다.", "낮에도 주로 침대에서 생활하는 경우가 많다."]'::jsonb, 2, '장기요양 4등급의 기준 및 설명을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "일상생활에서 전적으로 다른 사람의 도움이 필요한 경우는 5등급에 해당합니다.\n[정답]", "2": "자립이나 생활관리 능력 저하로 일정부분 도움이 필요하다. 이는 4등급의 적절한 설명입니다.", "3": "휠체어를 이용해도 자립적인 움직임이 가능한 경우는 3등급에 해당할 수 있습니다.", "4": "스스로 움직일 수 없는 와상 상태는 5등급의 설명입니다.", "5": "낮에 침대에서 주로 생활하는 경우는 5등급에 해당하며, 4등급은 일정 부분 도움을 필요로 합니다."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기간 요양이 필요한 상태(한국어)", "def_vi": "Tình trạng cần chăm sóc trong thời gian dài"}, {"term_ko": "등급", "term_vi": "Cấp độ", "def_ko": "평가 기준에 의한 단계(한국어)", "def_vi": "Bậc theo tiêu chí đánh giá"}, {"term_ko": "일상생활", "term_vi": "Cuộc sống hàng ngày", "def_ko": "매일 하는 기본적인 활동(한국어)", "def_vi": "Các hoạt động cơ bản thực hiện hàng ngày"}, {"term_ko": "자립", "term_vi": "Tự lập", "def_ko": "스스로 생활할 수 있는 능력(한국어)", "def_vi": "Khả năng sống tự mình"}, {"term_ko": "생활관리", "term_vi": "Quản lý cuộc sống", "def_ko": "일상적인 생활을 관리하는 것(한국어)", "def_vi": "Quản lý cuộc sống hàng ngày"}, {"term_ko": "와상", "term_vi": "Nằm bất động", "def_ko": "누워서만 생활하는 상태(한국어)", "def_vi": "Trạng thái chỉ nằm không thể di chuyển"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (652, '2', '대상자가 장기요양등급 판정 결과로 55점을 받았을 경우 해당되는 장기요양등급은?', '["1등급", "2등급", "3등급", "4등급", "5등급"]'::jsonb, 4, '대상자의 장기요양등급을 판별하는 기준을 이해하고 있는지를 평가하려는 의도입니다.', NULL, '{"1": "1등급은 90점 이상으로 주어지며 해당되지 않습니다.", "2": "2등급은 75점 이상으로 주어지므로 해당되지 않습니다.", "3": "3등급은 60점 이상으로 해당되지 않습니다.\n[정답]", "4": "4등급은 55점으로 해당 등급입니다.", "5": "5등급은 50점 이하로 주어지므로 해당되지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자 또는 수혜자", "def_vi": "Bệnh nhân hoặc người thụ hưởng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (651, '2', '장기요양 점수가 61점이며 일상생활에서 부분적으로 다른 사람의 도움이 필요한 대상자의 등급은?', '["1등급", "2등급", "3등급", "4등급", "5등급"]'::jsonb, 3, '장기요양 점수에 따른 등급 판별을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "1등급은 점수가 90점 이상인 대상자에게 해당합니다.\n[정답]", "3": "3등급은 점수가 60점에서 79점 사이인 대상자에게 해당하며, 일상생활에서 부분적인 도움이 필요합니다.", "2": "2등급은 점수가 80점에서 89점 사이인 경우에 해당합니다.", "4": "4등급은 점수가 40점에서 59점 사이인 경우입니다.", "5": "5등급은 점수가 39점 이하인 경우입니다."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기간의 요양이 필요한 상태", "def_vi": "Trạng thái cần chăm sóc lâu dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (650, '2', '장기요양등급 판정 시 다음 설명에 해당하는 대상자의 등급은?• 일상생활에서 부분적으로 다른 사람의 도움을 받아야 외출이 가능하다. • 휠체어를 통해 이동한다. • 장기요양인정점수가 65점이다.', '["1등급", "2등급", "3등급", "4등급", "5등급"]'::jsonb, 3, '장기요양등급 판정 기준에 따른 대상자의 상태를 확인하는 문제입니다.', NULL, '{"1": "1등급은 일상생활 전반에 걸쳐 전적인 도움이 필요한 경우에 해당합니다.", "2": "2등급은 하루에 5시간 미만으로 도움을 받는 경우에 해당합니다.\n[정답]", "3": "3등급은 부분적으로 다른 사람의 도움이 필요한 경우, 외출이 가능하지만 휠체어를 통해 이동하는 경우에 해당합니다.", "4": "4등급은 대체로 독립적인 생활이 가능한 상태에서 필요시 약간의 도움이 필요할 경우입니다.", "5": "5등급은 완전한 자립이 가능한 상황에 해당합니다."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc lâu dài", "def_ko": "장기간동안 요양이 필요한 상태", "def_vi": "Tình trạng cần chăm sóc trong thời gian dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (649, '2', '일상생활에서 상당 부분 다른 사람의 도움이 필요하며, 장기요양인정 점수가 75점인 대상자에게 해당되는 장기요양등급은?', '["1등급", "2등급", "3등급", "4등급", "5등급"]'::jsonb, 2, '장기요양 등급 판별 기준에 대한 이해를 확인하기 위함입니다.', NULL, '{"1": "1등급은 95점 이상일 때 해당됩니다.\n[정답]", "2": "2등급은 75점에서 94점 사이일 때 해당됩니다.", "3": "3등급은 60점에서 74점 사이일 때 해당됩니다.", "4": "4등급은 50점에서 59점 사이일 때 해당됩니다.", "5": "5등급은 49점 이하일 때 해당됩니다."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기간에 걸쳐 필요한 요양 및 간호 서비스를 제공하는 것", "def_vi": "Cung cấp dịch vụ chăm sóc và y tế cần thiết trong thời gian dài"}, {"term_ko": "등급", "term_vi": "Cấp độ", "def_ko": "수준이나 품질을 나타내는 기준", "def_vi": "Tiêu chí để thể hiện mức độ hoặc chất lượng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (648, '2', '장기요양인정 점수가 95점 이상이며, 스스로 움직일 수 없는 와병 상태로 모든 활동에서 전적으로 다른 사람의 도움이 필요한 대상자의 등급은?', '["1등급", "2등급", "3등급", "4등급", "5등급"]'::jsonb, 1, '장기요양인정 기준을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "1등급은 장기요양인정 점수가 95점 이상이며, 모든 활동에서 전적으로 다른 사람의 도움이 필요한 상태입니다.\n[정답]", "2": "2등급은 75점 이상 95점 미만이며, 부분적인 도움을 필요로 하는 상태입니다.", "3": "3등급은 60점 이상 75점 미만으로, 독립적인 활동이 가능한 경우도 포함됩니다.", "4": "4등급은 48점 이상 60점 미만인 경우입니다.", "5": "5등급은 48점 미만인 경우로, 가장 낮은 등급입니다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Công nhận chăm sóc lâu dài", "def_ko": "장기적인 요양이 필요하다고 인정받은 상태", "def_vi": "Tình trạng được công nhận cần chăm sóc lâu dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (647, '2', '다음 노인장기요양보험제도에 대한 설명 중 올바른 것은?', '["장기요양인정점수가 75점이면 장기요양 3등급을 받는다.", "장기요양인정점수가 52점이면 장기요양 4등급을 받는다.", "장기요양기관이 현저히 부족한 지역은 특례요양비를 지급한다.", "장기요양인정 유효기간은 최소 6개월이다.", "65세 이상의 노인만을 대상자로 한다."]'::jsonb, 2, '노인장기요양보험제도에 대한 기본적인 이해도를 평가하기 위함입니다.', NULL, '{"1": "장기요양인정점수는 75점일 경우 2등급에 해당합니다.\n[정답]", "2": "장기요양인정점수가 52점이면 장기요양 4등급을 받습니다.", "3": "장기요양기관이 부족한 지역에서 특례요양비가 지급되는 것은 맞지 않습니다.", "4": "장기요양인정 유효기간은 최소 12개월입니다.", "5": "65세 이상의 노인뿐만 아니라 65세 미만의 장애인도 대상자가 될 수 있습니다."}'::jsonb, '[{"term_ko": "노인장기요양보험제도", "term_vi": "Chế độ bảo hiểm chăm sóc dài hạn cho người già", "def_ko": "노인을 위한 장기요양 보험 제도", "def_vi": "Chế độ bảo hiểm phục vụ người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (646, '2', '노인장기요양보험 인정 절차에 관한 설명으로 옳은 것은?', '["의사소견서를 첨부하여 장기요양기관에 장기요양인정을 신청한다.", "국민건강보험공단은 조사결과서를 등급판정위원회에 제출한다.", "보건복지부는 1차 판정 결과를 심의하여 장기요양 등급을 최종 판정한다.", "지자체는 장기요양인정서를 국민건강보험공단에 제출한다.", "장기요양인정 점수에 따라 10등급으로 나뉜다."]'::jsonb, 2, '노인장기요양보험의 인정 절차에 대한 이해도를 평가하고자 하는 목적이 있다.', NULL, '{"1": "장기요양인정 신청은 의사소견서를 첨부해야 하나, 신청 주체는 장기요양기관이 아닌 개인이나 가족이다.\n[정답]", "2": "국민건강보험공단은 조사결과서를 등급판정위원회에 제출하는 절차가 맞다.", "3": "보건복지부는 등급판정 결과를 심의하지만 최종 등급 판정은 국민건강보험공단이 한다.", "4": "장기요양인정서는 국민건강보험공단에 제출하는 것이 아니라 해당 개인에게 발급된다.", "5": "장기요양인정 점수에 따라 등급은 1~5등급으로 나뉘고, 10등급은 존재하지 않는다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "장기요양보험", "def_ko": "노인이란 나이가 든 사람, 특히 65세 이상의 사람을 말한다.(người già)", "def_vi": "장기적인 요양과 돌봄을 위한 보험 제도.(bảo hiểm chăm sóc dài hạn)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (645, '2', '다음 중 노인장기요양인정 신청 및 판정절차로 옳은 것은?', '["65세 미만 노인성 질병 대상자는 의사소견서를 첨부하여 공단에 신청한다.", "방문조사는 교육을 이수한 장기요양기관 직원이 한다.", "개인별장기요양이용계획서는 공단이 장기요양기관에 제공한다.", "장기요양인정 신청은 본인만 가능하다.", "장기요양인정 점수가 60점이면 장기요양 4등급을 받는다."]'::jsonb, 1, '노인장기요양인정의 올바른 신청 및 판정절차를 이해하고 있는지를 평가하려는 문제입니다.', NULL, '{"1": "65세 미만 노인성 질병 대상자는 의사소견서를 첨부하여 공단에 신청한다. [정답] 이는 정확한 절차로, 65세 미만 한국 노인성 질병에 대한 신청이 올바르게 반영됩니다.", "2": "방문조사는 교육을 이수한 장기요양기관 직원이 한다. 이는 사실이지만, 방문조사는 공단에서 검증하는 과정관리가 필요한 절차입니다.", "3": "개인별장기요양이용계획서는 공단이 장기요양기관에 제공한다. 개인별 계획서는 장기요양기관이 제출해야 합니다.", "4": "장기요양인정 신청은 본인만 가능하다. 이는 잘못된 정보로, 대리 신청도 가능합니다.", "5": "장기요양인정 점수가 60점이면 장기요양 4등급을 받는다. 이는 사실이 아닌 정보로, 60점은 3등급 해당입니다."}'::jsonb, '[{"term_ko": "노인장기요양", "term_vi": "Đánh giá dài hạn người cao tuổi", "def_ko": "노인장기요양", "def_vi": "Chăm sóc dài hạn cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (644, '2', '등급 판정기준에 따라 심의에 필요한 자료를 검토하여 장기요양등급을 최종 판정하는 곳은?', '["장기요양위원회", "국민연금위원회", "등급판정위원회", "장애판정위원회", "건강보험심사평가원"]'::jsonb, 3, '장기요양등급 판정의 주체와 절차를 이해하기 위함입니다.', NULL, '{"1": "장기요양위원회는 정책 결정 기관으로 심의에 참여하나 최종 판정은 하지 않습니다.\n[정답]", "3": "등급판정위원회는 심의에 필요한 자료를 바탕으로 장기요양등급을 최종 판정합니다.", "2": "국민연금위원회는 국민연금 관련 업무를 담당합니다.", "4": "장애판정위원회는 장애인 판정을 담당하는 기관입니다.", "5": "건강보험심사평가원은 건강보험 관련 업무를 하지만 장기요양등급 판정과는 무관합니다."}'::jsonb, '[{"term_ko": "등급", "term_vi": "Cấp độ", "def_ko": "등급(한국어)", "def_vi": "Cấp độ(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (643, '2', '장기요양인정 신청 시 가정에 방문하여 신청인의 심신상태를 조사하는 기관은?', '["보건소", "주민 센터", "근로복지공단", "고용보험공단", "국민건강보험공단"]'::jsonb, 5, '이 문제는 장기요양인정 신청과 관련된 기관의 역할을 이해하고 있는지를 확인하기 위한 의도입니다.', NULL, '{"1": "보건소는 기본적인 보건 서비스를 제공하지만, 장기요양인정 신청과 직접적으로 관련이 없습니다.", "2": "주민 센터는 지역 주민의 복지 서비스를 지원하지만, 심신상태 조사는 하지 않습니다.", "3": "근로복지공단은 근로자와 관련된 복지 업무를 담당합니다.", "4": "고용보험공단은 고용보험 관련 업무를 담당하며 장기요양인정과는 관련이 없습니다.\n[정답]", "5": "국민건강보험공단은 장기요양인정 신청 시 가정에 방문하여 신청인의 심신상태를 조사하는 기관입니다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Đăng ký chăm sóc dài hạn", "def_ko": "장기 요양 서비스를 받기 위한 공식 인가", "def_vi": "Giấy phép chính thức để nhận dịch vụ chăm sóc dài hạn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (642, '2', '다음은 장기요양인정 신청 및 판정 절차이다. ( ) 속에 들어갈 내용으로 옳은 것은?신청 → ( A ) → 장기요양인정 점수산정 → ( B ) → 등급판정위원회 개최 → 등급판정', '["방문상담 계약체결", "계약체결 의사소견서 제출", "의사소견서 제출 방문조사", "방문조사 의사소견서 제출", "의사소견서 제출 계약체결"]'::jsonb, 4, '장기요양인정 신청 및 판정 절차에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "방문상담 계약체결: 이 과정은 신청 후의 절차가 아닙니다.\n[정답]", "2": "계약체결 의사소견서 제출: 의사소견서 제출은 방문조사가 완료된 후 이루어져야 합니다.", "3": "의사소견서 제출 방문조사: 순서가 잘못되었습니다.", "4": "방문조사 의사소견서 제출: 올바른 순서입니다. 신청 후 방문조사를 시행하고 이후 의사소견서를 제출하게 됩니다.", "5": "의사소견서 제출 계약체결: 이 과정 역시 절차를 잘못 이해한 것입니다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Nhận dạng chăm sóc dài hạn", "def_ko": "장기적인 요양이 필요한지를 판별하는 공식적인 인정", "def_vi": "Sự công nhận chính thức việc có cần chăm sóc dài hạn hay không"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (641, '2', '65세 미만자가 앓고 있는 질병 중 장기요양급여 대상자로 인정받을 수 있는 질환은?', '["파킨슨병", "심부전증", "고혈압", "퇴행성 관절염", "당뇨병"]'::jsonb, 1, '65세 미만의 장기요양급여 대상 질환에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "파킨슨병은 신경계 질환으로, 장기요양급여 대상입니다.\n[정답]", "2": "심부전증은 장기요양급여 대상에는 포함되지 않습니다.", "3": "고혈압은 일반적으로 장기요양급여 대상이 아닙니다.", "4": "퇴행성 관절염은 장기요양급여 대상이 아닙니다.", "5": "당뇨병은 장기요양급여 대상이 아닙니다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기 요양 서비스를 위해 제공되는 지원금", "def_vi": "Tiền hỗ trợ được cấp cho dịch vụ chăm sóc dài hạn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (640, '2', '등급판정위원회의 심의 결과 노인장기요양보험 급열를 받을 수 있는 대상자는?', '["팔이 골절된 60세 남자", "당뇨약을 복용하는 60세 남자", "혈압약을 복용하는 50세 여자", "혈관성 치매를 진단받은 50세 남자", "결핵으로 신체활동이 제한적인 60세 여자"]'::jsonb, 4, '노인장기요양보험의 대상자를 파악하는 능력을 평가하기 위한 질문입니다.', NULL, '{"1": "팔이 골절된 60세 남자는 요양보험의 대상자가 아닙니다.", "2": "당뇨약을 복용하는 60세 남자도 단순한 질병으로 요양보험 대상이 아닙니다.", "3": "혈압약을 복용하는 50세 여자 역시 요양보험 대상자가 아닙니다.\n[정답]", "4": "혈관성 치매를 진단받은 50세 남자는 요양보험의 대상자가 됩니다.", "5": "결핵으로 신체활동이 제한적인 60세 여자도 요양보험의 대상자가 아닙니다."}'::jsonb, '[{"term_ko": "급여", "term_vi": "Trợ cấp", "def_ko": "지급받는 돈(한국어)", "def_vi": "tiền trợ cấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (639, '2', '다음 중 장기요양급여 대상자로 인정 가능한 경우로 옳은 것은?', '["관절염을 앓고 있는 64세 남성", "혼자서 걸을 수 없는 50세 말기 암 여자", "파킨슨병으로 일상생활이 어려운 55세 남자", "난청이 있고 일상 생활이 가능한 80세 독거노인", "뇌출혈로 쓰러져 병원에서 치료중인 70세 남자"]'::jsonb, 3, '장기요양급여 대상자의 적격성을 판단하는 것.', NULL, '{"1": "관절염만으로는 장기요양급여 대상자가 되지 않음.\n[정답]", "2": "혼자서 걷지 못하는 경우는 장기요양급여 인정.", "3": "파킨슨병으로 일상생활이 어려운 경우는 장기요양급여 인정.", "4": "난청은 장기요양급여 기준에 해당하지 않음.", "5": "병원에서 치료 중인 경우는 장기요양급여 대상이 아님."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Trợ cấp chăm sóc dài hạn", "def_ko": "장기간 동안 필요한 요양 및 돌봄 서비스", "def_vi": "Dịch vụ chăm sóc và điều dưỡng cần thiết lâu dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (638, '2', '노인장기요양보험 기본 구조 및 절차에서 국민건강보험공단이 하는 일은?', '["요양서비스 재공", "등급판정", "서비스비용 청구", "서비스 신청 및 계약", "장기요양기관의 시설설립인가"]'::jsonb, 2, '노인장기요양보험의 구조와 절차에서 국민건강보험공단의 역할을 이해하는 것.', NULL, '{"1": "요양서비스를 제공하는 기관의 역할에 해당하는 내용입니다.\n[정답]", "2": "국민건강보험공단이 장기요양 등급을 판별하는 역할을 수행합니다.", "3": "서비스 비용 청구는 요양기관이 담당하는 부분입니다.", "4": "서비스 신청 및 계약 또한 요양기관의 역할에 해당합니다.", "5": "장기요양기관의 시설설립 인가는 지방자치단체가 담당합니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기 요양 서비스를 제공하는 보험 제도", "def_vi": "Hệ thống bảo hiểm cung cấp dịch vụ chăm sóc dài hạn cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (637, '2', '노인장기요양보험의 가입자로부터 보험료를 받아 계약조건에 따라 보험급여를 지급하는 기관은?', '["근로복지공단", "국민건강보험공단", "국민연금공단", "공무원연금공단", "고용보험공단"]'::jsonb, 2, '노인장기요양보험의 기본적인 구조와 관련 기관을 이해하고 있는지를 평가하는 질문입니다.', NULL, '{"1": "근로복지공단은 근로자에 대한 재해 보상 및 복지 서비스를 제공합니다.\n[정답]", "2": "국민건강보험공단은 노인장기요양보험의 가입자로부터 보험료를 받아 보험급여를 지급하는 주 기관입니다.", "3": "국민연금공단은 연금 보험 관련 업무를 담당합니다.", "4": "공무원연금공단은 공무원에 대한 연금 서비스만을 담당합니다.", "5": "고용보험공단은 실업급여 및 고용 관련 사업을 지원합니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "가입자", "def_ko": "노老 dài hạn tuyệt đối", "def_vi": "người tham gia"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (636, '2', '노인장기요양보험제도의 목적으로 옳은 것은?', '["안정적 노후를 위한 소득보장", "최저생활 보장으로 자활의욕 고취", "업무상 재해 보상을 통한 사회복귀를 촉진", "일상생활이 어려운 노인의 가사 및 신체활동 지원", "입원 중인 중증 노인의 의료비를 보장하여 가족의 부담 경감"]'::jsonb, 4, '노인장기요양보험제도의 목적을 이해하고, 올바른 보기를 선택하는 것이 요구된다.', NULL, '{"1": "안정적 노후를 위한 소득보장은 노인장기요양보험의 주된 목적이 아니다.\n[정답]", "2": "일상생활이 어려운 노인의 가사 및 신체활동 지원은 노인장기요양보험의 주요 목적 중 하나이다.", "3": "업무상 재해 보상을 통한 사회복귀는 다른 법적 제도에 해당한다.", "4": "입원 중인 중증 노인의 의료비를 보장하여 가족의 부담 경감은 건강보험에서 다루는 내용이다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (635, '2', '일상생활을 혼자하기 어려운 노인에게 신체활동 또는 가사활동 등을 지원하여 노후의 건강증진 및 생활안정을 도모하고 가족의 부담을 덜어주기 위한 사회보험제도는?', '["고용보험", "노인장기요양보험", "국민연금", "산업재해보상보험", "국민건강보험"]'::jsonb, 2, '노인의 일상 생활을 지원하고 가족의 부담을 덜어주는 제도를 이해하도록 하는 문제입니다.', NULL, '{"1": "고용보험: 근로자의 고용 안정을 위한 보험으로, 노인과 직접적인 관련이 없습니다.\n[정답]", "2": "노인장기요양보험: 노인의 신체활동 및 가사활동을 지원하고 건강 증진을 도모하기 위한 제도입니다.", "3": "국민연금: 노후 소득을 지원하는 제도로, 일상생활 지원과는 관련이 없습니다.", "4": "산업재해보상보험: 업무와 관련된 재해를 보상하는 보험으로, 노인 복지와는 연결되지 않습니다.", "5": "국민건강보험: 국민의 건강을 지키기 위한 보험이지만, 노인 지원에 특화된 제도는 아닙니다."}'::jsonb, '[{"term_ko": "신체활동", "term_vi": "가사활동", "def_ko": "신체를 움직이며 하는 활동(활동 thể chất)", "def_vi": "집안일이나 가정에서 하는 일(hoạt động gia đình)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (634, '2', '심신이 허약한 노인과 장애노인을 단기간 입소시켜 노인복지를 증진하는 서비스는?', '["방문목욕서비스", "방문요양서비스", "주-야간보호서비스", "단기보호서비스", "방문간호서비스"]'::jsonb, 4, '노인복지에 관련된 서비스 종류를 이해하고 있는지를 평가하고자 함.', NULL, '{"1": "방문목욕서비스: 집에서 목욕을 도와주는 서비스로, 단기간 입소와는 관련이 없음.", "2": "방문요양서비스: 요양보호사가 집으로 방문하여 간호, 요양을 하는 서비스이지만, 단기간 입소는 포함되지 않음.\n[정답]", "3": "주-야간보호서비스: 낮 동안 또는 밤 동안 노인을 보호하는 서비스이나, 단기간 입소가 핵심이 아님.", "4": "단기보호서비스: 심신이 허약한 노인과 장애노인을 위해 단기간 입소하여 복지를 증진하는 적합한 서비스.", "5": "방문간호서비스: 의료적 필요를 가진 환자에게 간호사를 파견하는 서비스지만, 단기 입소와는 관련이 없음."}'::jsonb, '[{"term_ko": "심신", "term_vi": null, "def_ko": "마음과 몸", "def_vi": null}, {"term_ko": "허약", "term_vi": null, "def_ko": "약함", "def_vi": null}, {"term_ko": "노인", "term_vi": null, "def_ko": "나이 많은 사람", "def_vi": null}, {"term_ko": "장애", "term_vi": null, "def_ko": "신체적, 정신적 기능에 장애가 있는 상태", "def_vi": null}, {"term_ko": "단기간", "term_vi": null, "def_ko": "짧은 시간", "def_vi": null}, {"term_ko": "입소", "term_vi": null, "def_ko": "시설에 들어가다", "def_vi": null}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (633, '2', '방문요양, 방문목욕, 주-야간 보호서비스는 노인복지시설 유형 중 어느 것에 해당 하는가?', '["노인의료복지시설", "재가노인복지시설", "노인주거복지시설", "노인여가복지시설", "노인일자리지원기관"]'::jsonb, 2, '노인복지시설의 유형에 대한 이해도를 평가하는 문제입니다.', NULL, '{"1": "노인의료복지시설은 주로 의료 서비스를 제공하는 시설입니다.\n[정답]", "2": "재가노인복지시설은 가정에서 서비스를 제공하는 시설로, 방문요양, 방문목욕 등이 포함됩니다.", "3": "노인주거복지시설은 노인이 거주하며 생활 지원을 받는 시설입니다.", "4": "노인여가복지시설은 노인의 여가 활동을 지원하는 시설입니다.", "5": "노인일자리지원기관은 노인의 일자리 제공 및 지원을 하는 기관입니다."}'::jsonb, '[{"term_ko": "방문요양", "term_vi": "Chăm sóc tại nhà", "def_ko": "가정에서의 요양 서비스 제공", "def_vi": "Dịch vụ chăm sóc tại nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (632, '2', '노인의 교양 취미생활 및 사회 참여활동 등에 대한 각종 정보와 노인의 복지 증진에 필요한 서비스를 제공하는 노인여가복지시설은?', '["양로시설", "노인복지관", "경로당", "노인교실", "노인복지주택"]'::jsonb, 2, '노인의 복지와 사회 참여를 지원하는 시설에 대한 이해를 평가하고자 함.', NULL, '{"1": "양로시설: 노인의 주거를 제공하는 시설이나 주로 요양 서비스에 중점을 둠.\n[정답]", "2": "노인복지관: 노인의 교양, 취미생활 및 복지 증진을 위한 정보와 서비스를 제공하는 전천후의 시설임.", "3": "경로당: 노인들의 지역 사회 내 모임을 위한 공간이지만, 활동성과 서비스가 노인복지관에 비해 제한적임.", "4": "노인교실: 노인 교육을 주제로 한 특화 시설이나 복지 증진과는 거리가 있음.", "5": "노인복지주택: 고령자의 주거 안정성을 지원하지만, 사회 참여 활동보다는 주거지위 중심의 시설임."}'::jsonb, '[{"term_ko": "교양", "term_vi": "Giáo dục", "def_ko": "문화 및 지식의 향상(한국어)", "def_vi": "Sự nâng cao văn hóa và tri thức (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (631, '2', '치매, 중픙 등으로 심신에 상당한 장애가 있는 노인에게 가정과 같은 주거여건과 급식, 요양, 일상생활 서비스 등을 제공하는 입소자 9인 이내의 노인의료복지시설은?', '["양로시설", "노인복지관", "노인복지주택", "노인요양시설", "노인요양공동생활가정"]'::jsonb, 5, '치매나 중증 장애가 있는 노인을 위한 적절한 복지시설의 종류를 이해하고 있는지 평가하기 위함입니다.', NULL, '{"1": "양로시설: 노인이 생활하는 시설이나 급식, 요양 서비스를 제공하지 않습니다.\n[정답]", "5": "노인요양공동생활가정: 노인의 심신에 장애가 있는 경우 가정과 같은 환경에서 서비스를 제공하는 시설입니다.", "2": "노인복지관: 다양한 노인 복지 프로그램이 제공되지만 입소 시설은 아닙니다.", "3": "노인복지주택: 독립적인 주거 형태로, 요양 서비스를 포함하지 않습니다.", "4": "노인요양시설: 입소자 수가 더 많고, 설치 기준이 다릅니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억이나 사고의 기능이 저하되는 질병", "def_vi": "Bệnh làm giảm khả năng nhớ và suy nghĩ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (630, '2', '노인의료복지시설 유형에 해당하는 것은?', '["노인요양공동생활가정", "양로시설", "노인복지관", "경로당", "노인복지주택"]'::jsonb, 1, '노인의료복지시설의 유형을 이해하고 구별할 수 있는 능력을 평가하기 위함입니다.', NULL, '{"1": "노인요양공동생활가정은 의료 및 돌봄 서비스를 제공하는 노인의료복지시설의 한 형태입니다.\n[정답]", "2": "양로시설은 노인들이 거주하는 시설이지만, 의료적인 서비스를 주로 제공하는 곳은 아닙니다.", "3": "노인복지관은 노인 복지 서비스를 제공하는 곳으로, 주로 여가 및 사회 활동을 지원합니다.", "4": "경로당은 지역 사회에서 노인들이 모여 활동하는 공간으로, 의료복지시설은 아닙니다.", "5": "노인복지주택은 자립적인 생활을 지원하는 주거 형태로, 의료 서비스는 중심이 아닙니다."}'::jsonb, '[{"term_ko": "노인요양공동생활가정", "term_vi": "Nhà chung sống cho người cao tuổi", "def_ko": "노인의료복지시설의 한 형태", "def_vi": "Một hình thức cơ sở y tế và phúc lợi dành cho người cao tuổi"}, {"term_ko": "양로시설", "term_vi": "Cơ sở dưỡng lão", "def_ko": "노인들이 거주하는 시설", "def_vi": "Nơi cư trú cho người cao tuổi"}, {"term_ko": "노인복지관", "term_vi": "Trung tâm phúc lợi cho người cao tuổi", "def_ko": "노인 복지 서비스를 제공하는 곳", "def_vi": "Nơi cung cấp dịch vụ phúc lợi cho người cao tuổi"}, {"term_ko": "경로당", "term_vi": "Nhà cộng đồng cho người cao tuổi", "def_ko": "노인들이 모여 활동하는 공간", "def_vi": "Không gian nơi người cao tuổi tụ tập"}, {"term_ko": "노인복지주택", "term_vi": "Nhà ở phúc lợi cho người cao tuổi", "def_ko": "자립적인 생활을 지원하는 주거 형태", "def_vi": "Hình thức cư trú hỗ trợ cho cuộc sống tự lập"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (629, '2', '치매 중픙 등 노인성 질환 등으로 심신에 상당한 장애가 발생하여 도움이 필요한 노인을 입소시켜 급식, 요양 등을 제공하는 노인복지 시설은?', '["양로시설", "노인공동생활가정", "노인복지관", "노인전문병원", "노인요양시설"]'::jsonb, 5, '노인성 질환으로 도움이 필요한 노인을 위한 적절한 시설을 선택하도록 유도하는 문제입니다.', NULL, '{"1": "양로시설: 주로 노인의 생활을 위한 시설로, 간호 등의 전문적인 요양 서비스는 제공하지 않습니다.\n[정답]", "5": "노인요양시설: 치매 및 노인성 질환이 있는 노인을 위해 급식, 요양 등을 제공하는 전문 시설입니다.", "3": "노인복지관: 노인의 사회적 활동과 복지를 지원하는 기관으로, 요양 서비스를 제공하지 않습니다.", "4": "노인전문병원: 노인의 질병 치료를 전문으로 하는 병원으로, 장기 요양 시설이 아닙니다.", "2": "노인공동생활가정: 여러 노인이 함께 생활하지만 노인성 질환이 심한 환자를 위한 시설은 아닙니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력 저하 및 인지능력 감소로 이어지는 질병(한국어)", "def_vi": "Bệnh lý dẫn đến suy giảm trí nhớ và khả năng nhận thức (베트남어)"}, {"term_ko": "노인성", "term_vi": "Bị lão hóa", "def_ko": "노화로 인해 발생하는 질병이나 상태(한국어)", "def_vi": "Bệnh hoặc trạng thái phát sinh do lão hóa (베트남어)"}, {"term_ko": "입소", "term_vi": "Nhập viện", "def_ko": "시설에 들어가 거주하는 것(한국어)", "def_vi": "Vào sinh sống tại cơ sở (베트남어)"}, {"term_ko": "급식", "term_vi": "Cung cấp bữa ăn", "def_ko": "식사를 제공하는 것(한국어)", "def_vi": "Việc cung cấp thức ăn (베트남어)"}, {"term_ko": "요양", "term_vi": "Chăm sóc sức khỏe", "def_ko": "건강을 돌보는 일(한국어)", "def_vi": "Việc chăm sóc sức khỏe (베트남어)"}, {"term_ko": "노인복지 시설", "term_vi": "Cơ sở phúc lợi người cao tuổi", "def_ko": "노인을 위한 복지 서비스 제공 시설(한국어)", "def_vi": "Cơ sở cung cấp dịch vụ phúc lợi cho người cao tuổi (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (628, '2', '다음 설명에 해당하는 노인복지시설은?• 양로시설 • 노인복지주택 • 노인공동생활가정', '["노인의료복지시설", "노인주거복지시설", "노인여가복지시설", "재가노인복지시설", "노인보호전문기관"]'::jsonb, 2, '노인복지시설의 종류에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "노인의료복지시설은 의료 서비스를 제공하는 시설입니다.\n[정답]", "2": "노인주거복지시설은 노인들이 거주할 수 있도록 마련된 주거 공간입니다.", "3": "노인여가복지시설은 노인의 여가 활동을 지원하는 시설입니다.", "4": "재가노인복지시설은 홈케어 서비스를 제공하는 시설입니다.", "5": "노인보호전문기관은 노인 학대 예방 및 상담을 처리하는 기관입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người già"}, {"term_ko": "복지시설", "term_vi": "Cơ sở phúc lợi", "def_ko": "복지시설(한국어)", "def_vi": "Cơ sở phúc lợi"}, {"term_ko": "양로시설", "term_vi": "Cơ sở dưỡng lão", "def_ko": "양로시설(한국어)", "def_vi": "Cơ sở dưỡng lão"}, {"term_ko": "노인복지주택", "term_vi": "Nhà ở phúc lợi cho người cao tuổi", "def_ko": "노인복지주택(한국어)", "def_vi": "Nhà ở phúc lợi cho người già"}, {"term_ko": "노인공동생활가정", "term_vi": "Nhà sống chung cho người cao tuổi", "def_ko": "노인공동생활가정(한국어)", "def_vi": "Nhà sống chung cho người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (626, '2', '노인복지사업의 유형 중 노인 사회활동 및 여가활동 지원사업에 해당하는 것은?', '["노인 건강진단", "경로당 지원사업", "노인실명 예방 사업", "결식 우려 노인 무료급식 지원", "노인 무릎인공관절 수술 지원"]'::jsonb, 2, '노인복지사업 중 사회활동 및 여가를 지원하는 사업 유형을 묻고 있습니다.', NULL, '{"1": "노인 건강진단은 건강관리에 해당하므로 제외됩니다.\n[정답]", "2": "경로당 지원사업은 노인의 사회활동과 여가활동을 지원하는 사업입니다.", "3": "노인실명 예방 사업은 건강 관련 지원으로 관련이 없습니다.", "4": "결식 우려 노인 무료급식 지원은 식사가 필요한 노인을 지원하는 사업입니다.", "5": "노인 무릎인공관절 수술 지원은 의료 지원으로 사회활동 및 여가활동과는 관계가 없습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người lớn tuổi"}, {"term_ko": "복지사업", "term_vi": "Dự án phúc lợi", "def_ko": "사업의 지원과 서비스", "def_vi": "Dự án hỗ trợ và dịch vụ"}, {"term_ko": "사회활동", "term_vi": "Hoạt động xã hội", "def_ko": "사회에서의 활동", "def_vi": "Hoạt động trong xã hội"}, {"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간을 이용한 활동", "def_vi": "Hoạt động trong thời gian rảnh"}, {"term_ko": "경로당", "term_vi": "Nhà văn hóa", "def_ko": "노인을 위한 쉼터", "def_vi": "Nơi nghỉ ngơi cho người cao tuổi"}, {"term_ko": "무료급식", "term_vi": "Bữa ăn miễn phí", "def_ko": "무료로 음식을 제공하는 것", "def_vi": "Cung cấp bữa ăn miễn phí"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (625, '2', '다음과 같은 내용의 사업을 실시하는 기관은?• 치매 조기검진, 치매환자 등록 및 관리 • 1:1로 매칭하여 필요한 서비스 연계', '["치매안심센터", "노인요양시설", "노인종합복지관", "노인보호전문기관", "노인의료나눔재단"]'::jsonb, 1, '치매 환자에 대한 조기 검진 및 관리 서비스 제공 기관을 묻는 문제입니다.', NULL, '{"1": "치매 환자에 맞춤형 서비스와 관리를 제공하는 기관입니다. [정답]", "2": "노인들의 주거 및 생활 지원이 주된 기능을 하는 시설입니다.", "3": "노인 복지 관련 다양한 프로그램을 제공하지만, 치매 관련 서비스는 제한적입니다.", "4": "노인 학대 및 보호를 위한 전문 기관으로, 주로 보호적인 역할을 합니다.", "5": "노인의료나눔재단은 의료 서비스 관련 재단으로, 직접적인 치매 관리 기관은 아닙니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "치매(한국어)", "def_vi": "Chứng mất trí nhớ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (624, 'unknown', '학대 받은 노인을 일정기간 보호하며 숙식과 기본적인 의료비를 지원하는 기관은?', '["정신요양시설", "주간보호센터", "노인학대신고센터", "정신건강복지센터", "학대피해노인 전용쉼터"]'::jsonb, 5, '노인을 학대받는 이들의 보호 및 지원을 위한 기관에 대한 이해를 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "정신요양시설: 정신장애인의 치료와 재활을 위한 시설이므로 정답이 아닙니다.\n[정답]", "5": "학대피해노인 전용쉼터: 학대받은 노인을 일정기간 보호하며 숙식과 기본적인 의료비를 지원하는 기관입니다.", "2": "주간보호센터: 낮 시간 동안 노인을 돌보는 시설이므로 정답이 아닙니다.", "3": "노인학대신고센터: 신고와 상담을 위한 기관이지 직접적인 보호를 제공하지 않으므로 정답이 아닙니다.", "4": "정신건강복지센터: 정신 건강 문제를 지원하는 기관이므로 정답이 아닙니다."}'::jsonb, '[{"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "폭력이나 학대의 행동(한국어)", "def_vi": "Hành vi bạo lực hoặc lạm dụng"}, {"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람(한국어)", "def_vi": "Người lớn tuổi"}, {"term_ko": "지원", "term_vi": "Hỗ trợ", "def_ko": "돕거나 지원하는 것(한국어)", "def_vi": "Sự giúp đỡ"}, {"term_ko": "숙식", "term_vi": "Chỗ ở và ăn uống", "def_ko": "잠자고 먹는 것(한국어)", "def_vi": "Nơi ngủ nghỉ và ăn uống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (623, '2', '다음 설명에 해당하는 업무를 담당하는 기관은?• 노인학대 사례의 신고접수 • 신고 된 시설학대 사례에 대한 개입 • 학대사례에 대한 사례관리 절차 지원', '["사법경찰", "노인보호전문기관", "법률기관", "의료기관", "보건복지부"]'::jsonb, 2, '노인학대에 대한 대응 기관에 대한 이해를 확인하고자 함', NULL, '{"1": "사법경찰은 범죄 사건 수사 및 법 집행 관련 업무를 수행하므로 해당되지 않음.\n[정답]", "2": "노인보호전문기관은 노인학대 관련 신고 접수 및 개입, 사례관리를 주 업무로 담당함.", "3": "법률기관은 법률적 상담 및 지원을 담당하지만 노인학대의 직접적 개입과는 관련이 없음.", "4": "의료기관은 의료적 치료를 제공하지만 학대 사례 관리와는 무관함.", "5": "보건복지부는 정책 수립과 감독 역할을 하지만 직접적으로 사례를 관리하지는 않음."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "고령자에게 가해지는 신체적, 정신적 학대", "def_vi": "Sự lạm dụng về thể chất và tinh thần đối với người cao tuổi"}, {"term_ko": "신고접수", "term_vi": "Tiếp nhận báo cáo", "def_ko": "사건에 대한 신고를 접수하는 것", "def_vi": "Nhận thông báo về vụ việc"}, {"term_ko": "사례관리", "term_vi": "Quản lý hồ sơ", "def_ko": "사건을 관리하는 절차", "def_vi": "Quy trình quản lý các vụ việc"}, {"term_ko": "개입", "term_vi": "Can thiệp", "def_ko": "사건에 직접 개입하는 것", "def_vi": "Can thiệp trực tiếp vào vụ việc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (622, '2', '등급판정위원회의 심의 결과 등급판정을 받지 못한 대상자가 이용할 수 있는 서비스는?', '["노인요양시설", "노인복지관", "단기보호", "방문목욕", "방문간호"]'::jsonb, 2, NULL, NULL, NULL, NULL);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (621, '2', '일상생활을 영위하기 어려운 노인에게 적절한 돌봄서비스를 제공하여 안정적인 노후생활을 보장하고 노인의 기능, 건강의 악화 예방을 목적으로 하는 노인 복지사업은?', '["노인맞춤돌봄서비스", "노인일자리 지원서비스", "독거노인 공동생활홈 서비스", "독거노인 응급안전안심서비스", "결식 우려 노인 무료급식 지원서비스"]'::jsonb, 1, '노인 복지사업의 주요 목적과 적절한 돌봄서비스를 이해하고 식별할 수 있는지를 평가하고자 함.', NULL, '{"1": "노인맞춤돌봄서비스는 노인의 기능, 건강 악화 예방에 중점을 두고 있어 정답이다.\n[정답]", "2": "노인일자리 지원서비스는 일자리에 관련된 서비스로 노인 돌봄 서비스가 아니다.", "3": "독거노인 공동생활홈 서비스는 공동생활을 지원하는 서비스일 뿐 돌봄 서비스 직접 제공과는 거리가 있다.", "4": "독거노인 응급안전안심서비스는 응급 상황 처리를 위한 서비스로, 목적이 다르다.", "5": "결식 우려 노인 무료급식 지원서비스는 식사 지원에 관련된 서비스로 노인 돌봄 서비스와는 차별화된다."}'::jsonb, '[{"term_ko": "일상생활", "term_vi": "돌봄서비스", "def_ko": "일상 cuộc sống", "def_vi": "dịch vụ chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (620, '2', '노인의 경륜을 사회에 재투자할 수 있도록 노인의 적극적 사회참여 및 노인의 인적자원 활용을 극대화하기 위한 사업은?', '["노인자원봉사", "노인보호전문기관", "노인 건강진단사업", "치매공공후견사업", "노인일자리 및 사회활동 지원사업"]'::jsonb, 1, '노인의 사회참여와 인적자원 활용을 통해 사회에 기여할 수 있는 방법을 묻고 있다.', NULL, '{"1": "노인이 자원봉사 활동을 통해 사회에 기여하는 방안이다.\n[정답]", "2": "노인을 보호하고 지원하는 기관으로 자원봉사와는 직접적으로는 관련이 없다.", "3": "노인의 건강 상태를 진단하는 것이며 사회참여와는 거리가 있다.", "4": "치매환자를 위한 공공후견사업으로 사회참여와는 다소 무관하다.", "5": "노인의 일자리와 사회활동을 지원하여 사회참여를 촉진하는 사업이다."}'::jsonb, '[{"term_ko": "경륜", "term_vi": "사회참여", "def_ko": "경험(경험)", "def_vi": "참여 xã hội(사회를 포함한 활동에 참여하다)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (619, '2', '다음 설명에 해당하는 노인복지 원칙은?• 노인의 잠재력을 개발할 수 있는 기회가 있어야 한다.• 사회의 교육적, 문화적, 정신적 자원과 여가서비스를 이용할 수 있어야 한다.', '["독립의 원칙", "참여의 원칙", "보호의 원칙", "존엄의 원칙", "자아실현의 원칙"]'::jsonb, 5, '노인복지의 원칙 중 노인의 잠재력 개발과 관련된 원칙을 묻고 있다.', NULL, '{"1": "독립의 원칙: 노인이 자율적으로 생활할 수 있도록 지원하는 원칙이다.\n[정답]", "5": "자아실현의 원칙: 노인이 자신의 잠재력을 최대한 발휘하고 자아를 실현할 수 있도록 기회를 제공하는 원칙이다.", "2": "참여의 원칙: 노인이 사회 활동에 참여할 수 있는 기회를 강조하는 원칙이다.", "3": "보호의 원칙: 노인을 안전하게 보호하는 것이 주된 목표인 원칙이다.", "4": "존엄의 원칙: 노인의 존엄성을 존중하고 보호하는 원칙이다."}'::jsonb, '[{"term_ko": "잠재력", "term_vi": "Tiềm năng", "def_ko": "가능성(한국어)", "def_vi": "Khả năng"}, {"term_ko": "기회", "term_vi": "Cơ hội", "def_ko": "기회(한국어)", "def_vi": "Cơ hội"}, {"term_ko": "자원", "term_vi": "Tài nguyên", "def_ko": "자원(한국어)", "def_vi": "Tài nguyên"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "서비스(한국어)", "def_vi": "Dịch vụ"}, {"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "원칙(한국어)", "def_vi": "Nguyên tắc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (618, '2', '의사결정능력 부족으로 어려움을 겪는 치매노인에게 지원하는 공공후견사업에 대한 내용으로 옳은 것은?', '["사업주체는 노인의료나눔제단이다.", "노인의 건강 유지, 증진을 위한 사업이다.", "사업대상은 일반 노인, 치매노인 및 가족이다.", "후견심판 청구 절차 및 비용을 지원한다.", "공공후견인 활동비는 지원하지 않는다."]'::jsonb, 4, '공공후견사업에 대한 이해도를 평가하고, 치매노인에 대한 지원 방법을 알고 있는지를 확인하기 위함입니다.', NULL, '{"1": "사업주체는 노인의료나눔제단이 아니라 공공기관입니다.\n[정답]", "4": "후견심판 청구 절차 및 비용을 지원하는 것이 공공후견사업의 중요한 내용입니다.", "2": "사업은 건강 유지, 증진을 목표로 하지만, 주로 후견 지원을 중점적으로 다룹니다.", "3": "치매노인 및 그 가족을 포함하나, 일반 노인 포함 여부는 다소 다를 수 있습니다.", "5": "공공후견인 활동비는 지원하지 않습니다."}'::jsonb, '[{"term_ko": "의사결정능력", "term_vi": "Năng lực quyết định", "def_ko": "결정을 내리는 능력", "def_vi": "Khả năng đưa ra quyết định"}, {"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력 및 인지 능력이 저하되는 질병", "def_vi": "Bệnh giảm trí nhớ và khả năng nhận thức"}, {"term_ko": "공공후견사업", "term_vi": "Dự án bảo trợ công cộng", "def_ko": "공공기관이 주관하는 후견지원 사업", "def_vi": "Dự án hỗ trợ bảo trợ do cơ quan công cộng tổ chức"}, {"term_ko": "후견심판", "term_vi": "Quyết định của tòa án giám hộ", "def_ko": "법원의 판단에 따라 후견인을 지정하는 절차", "def_vi": "Quy trình xác định người giám hộ theo phán quyết của tòa án"}, {"term_ko": "비용", "term_vi": "Chi phí", "def_ko": "지출하는 금액", "def_vi": "Số tiền chi tiêu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (617, '2', '국제연합(유엔)이 채택한 노인을 위한 원칙에 관한 설명으로 옳은 것은?', '["가능한 시설 거주를 권장한다.", "경제적 능력에 따라 대우한다.", "젊은 세대와 분리된 노인문화를 형성한다.", "교육과 문화 서비스 제공은 최소화한다.", "시설에서도 기본적인 자유를 누려야 한다."]'::jsonb, 5, '국제연합(유엔)의 노인 정책을 이해하고, 올바른 원칙에 대한 지식을 평가하고자 하는 의도로 출제되었다.', NULL, '{"1": "가능한 시설 거주를 권장한다: 유엔의 원칙에서는 가능한 한 노인이 자택에서 생활할 수 있도록 권장한다.\n[정답]", "5": "시설에서도 기본적인 자유를 누려야 한다: 노인은 시설 내에서도 자신의 삶에 대한 기본적인 선택과 자유를 누릴 권리가 있다.", "3": "젊은 세대와 분리된 노인문화를 형성한다: 유엔의 원칙은 노인이 젊은 세대와의 통합을 강조한다.", "4": "교육과 문화 서비스 제공은 최소화한다: 원칙에서는 교육과 문화 서비스의 중요성을 강조한다.", "2": "경제적 능력에 따라 대우한다: 유엔의 원칙은 모든 노인이 동등하게 대우받아야 한다고 강조한다."}'::jsonb, '[{"term_ko": "국제연합", "term_vi": "Tổ chức Liên hợp quốc", "def_ko": "유엔(United Nations)", "def_vi": "Liên Hợp Quốc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (616, '2', '다음에서 설명하는 노인을 위한 유엔의 원칙은?• 노인은 착취와 육체적, 정신적 학대로부터 자유로워야 한다.• 노인은 장애나 여타 지위에 상관없이 공정하게 대우받아야 한다.', '["독립의 원칙", "참여의 원칙", "보호의 원칙", "존엄의 원칙", "평등의 원칙"]'::jsonb, 4, '유엔이 제정한 노인을 위한 원칙을 이해하고 구별하는 것이다.', NULL, '{"1": "독립의 원칙: 노인이 자율적으로 생활할 수 있도록 지원하는 원칙이다.", "2": "참여의 원칙: 노인이 사회 활동에 적극적으로 참여할 수 있도록 하는 원칙이다.\n[정답]", "3": "보호의 원칙: 노인이 착취와 학대에 대한 보호를 받아야 한다는 내용을 포함한다.", "4": "존엄의 원칙: 노인의 존엄성을 지키는 것과 관련된 원칙이다.", "5": "평등의 원칙: 모든 노인이 공정하게 대우받아야 한다는 의미를 담고 있으나, 질문의 맥락은 아니다."}'::jsonb, '[{"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "원리, 규칙(한국어)", "def_vi": "Nguyên lý, quy tắc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (615, '2', '교사로 은퇴한 노인이 지역아동센터에서 교육봉사 단체를 조직하여 활동하는 노인복지 원칙은?', '["독립의 원칙", "참여의 원칙", "보호의 원칙", "존엄의 원칙", "평등의 원칙"]'::jsonb, 2, '노인복지의 원칙을 이해하고, 그에 따른 사례를 파악하도록 유도하는 문제입니다.', NULL, '{"1": "독립의 원칙: 노인이 스스로 생활할 수 있도록 지원하는 원칙\n[정답]", "2": "참여의 원칙: 노인이 사회활동에 적극적으로 참여할 수 있도록 장려하는 원칙", "3": "보호의 원칙: 노인을 보호하고 안전하게 지킬 수 있도록 하는 원칙", "4": "존엄의 원칙: 노인의 존엄성이 유지되도록 존중하는 원칙", "5": "평등의 원칙: 모든 노인이 동등한 권리를 가지고 대우받아야 한다는 원칙"}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (614, '2', '노인은 ''일할 수 있는 기회를 갖거나 다른 소득을 얻을 수 있어야 한다.''는 노인을 위한 유엔원칙은?', '["독립의 원칙", "참여의 원칙", "보호의 원칙", "존엄의 원칙", "자아실현의 원칙"]'::jsonb, 1, '노인을 위한 유엔 원칙 중에서 ''일할 수 있는 기회를 갖거나 다른 소득을 얻을 수 있어야 한다.''라는 내용을 이해하고 올바른 원칙을 찾도록 하는 문제입니다.', NULL, '{"1": "독립의 원칙: 노인이 자주적이고 독립적으로 생활할 수 있도록 하는 원칙입니다.\n[정답]", "2": "참여의 원칙: 노인이 사회에 참여할 수 있도록 하는 원칙이라는 점에서 가장 알맞습니다.", "3": "보호의 원칙: 노인을 보호하는 내용에 관련된 원칙입니다.", "4": "존엄의 원칙: 노인의 존엄성을 유지하는 것에 관련된 원칙입니다.", "5": "자아실현의 원칙: 개인의 잠재력을 실현하도록 하는 원칙입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "고령의 사람", "def_vi": "Người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (613, '2', '다음 설명에 해당되는 사회복지제도는?• 목적: 노인의 노후소득 보장 및 생활안정 지원• 대상: 만 65세 이상 소득인정액 기준 70% 수준 이하의 노인• 재원: 국가와 지방자치단체에 의해 조성', '["주택연금", "국민연금", "기초연금", "퇴직연금", "고용보험"]'::jsonb, 3, '사회복지제도의 기능과 대상에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "주택연금은 주택을 담보로 현금을 지급받는 제도입니다.", "2": "국민연금은 모든 국민이 일정 금액을 납부하고 노후에 지급받는 연금입니다.\n[정답]", "3": "기초연금은 65세 이상의 저소득 노인에게 지급되며, 노후소득 보장 및 생활안정을 지원합니다.", "4": "퇴직연금은 근로자가 퇴직할 때 지급받는 연금입니다.", "5": "고용보험은 실직 시 소득을 지원하는 제도입니다."}'::jsonb, '[{"term_ko": "사회복지제도", "term_vi": "Chế độ phúc lợi xã hội", "def_ko": "복지 사회 체계", "def_vi": "Hệ thống phúc lợi xã hội"}, {"term_ko": "노후소득", "term_vi": "Thu nhập hưu trí", "def_ko": "노인의 퇴직 후 소득", "def_vi": "Thu nhập sau khi nghỉ hưu"}, {"term_ko": "소득인정액", "term_vi": "Mức thu nhập công nhận", "def_ko": "소득 기준", "def_vi": "Tiêu chí thu nhập"}, {"term_ko": "생활안정", "term_vi": "Ổn định cuộc sống", "def_ko": "경제적 안정", "def_vi": "Ổn định kinh tế"}, {"term_ko": "국가", "term_vi": "Nhà nước", "def_ko": "국가", "def_vi": "Nhà nước"}, {"term_ko": "지방자치단체", "term_vi": "Chính quyền địa phương", "def_ko": "지역 자치 단체", "def_vi": "Chính quyền địa phương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (612, '2', '다음 중 사회보험의 종류와 내용이 올바르게 짝지어진 것은?', '["고용보험 - 근로자의 업무상 재해를 보상, 재활 및 사회복귀를 촉진", "국민연금보험 - 생활이 어려운 사람에게 필요한 급여를 제공하여 최저 생활을 보장", "국민건강보험 - 노령, 장애 ,사망에 대하여 연금을 지급하여 생활안정과 복지를 증진", "산업재해보상보험 - 근로자가 실업한 경우 생활안정, 구직활동을 위해 급여를 지급", "노인장기요양보험 - 고령, 노인성 질병으로 일상생활이 어려운 노인에게 급여를 제공"]'::jsonb, 5, '사회보험의 종류와 내용을 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "고용보험은 실업급여와 구직활동 지원을 목적으로 합니다. 이 설명은 맞지 않습니다.\n[정답]", "5": "노인장기요양보험은 고령, 노인성 질병으로 일상생활이 어려운 노인에게 급여를 제공하는 보험입니다.", "2": "국민연금보험은 노령연금, 장애연금, 유족연금을 지급하여 최저 생활을 보장합니다. 이 설명은 맞지 않습니다.", "3": "국민건강보험은 건강보험으로 여러 의료비를 지원합니다. 노령, 장애, 사망에 대한 연금을 지급하지 않습니다. 이 설명은 맞지 않습니다.", "4": "산업재해보상보험은 근로자의 업무상 재해에 대해 보상하며, 실업 시의 급여 지급과는 관련이 없습니다. 이 설명은 맞지 않습니다."}'::jsonb, '[{"term_ko": "사회보험", "term_vi": "Bảo hiểm xã hội", "def_ko": "사회적 위험에 대비하기 위한 보험 제도", "def_vi": "Hệ thống bảo hiểm để đối phó với các rủi ro xã hội"}, {"term_ko": "고용보험", "term_vi": "Bảo hiểm thất nghiệp", "def_ko": "실업 등으로 인해 소득이 중단된 근로자에게 제공되는 보험", "def_vi": "Bảo hiểm cung cấp cho người lao động khi thu nhập bị gián đoạn do thất nghiệp"}, {"term_ko": "국민연금", "term_vi": "Quỹ hưu trí quốc dân", "def_ko": "국민의 노후 생활을 보장하기 위한 연금 제도", "def_vi": "Hệ thống lương hưu nhằm đảm bảo cuộc sống cho công dân trong thời gian nghỉ hưu"}, {"term_ko": "국민건강보험", "term_vi": "Bảo hiểm sức khỏe quốc dân", "def_ko": "국민의 건강 관리를 위한 보험 제도", "def_vi": "Hệ thống bảo hiểm nhằm quản lý sức khỏe của người dân"}, {"term_ko": "산업재해보상보험", "term_vi": "Bảo hiểm bồi thường tai nạn lao động", "def_ko": "근로자가 업무 중 재해를 당했을 때 보상해주는 보험", "def_vi": "Bảo hiểm bồi thường cho người lao động khi gặp tai nạn trong công việc"}, {"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "장기 요양이 필요한 노인에게 서비스를 제공하는 보험", "def_vi": "Bảo hiểm cung cấp dịch vụ cho người cao tuổi cần chăm sóc dài hạn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (611, '2', '요양보호사가 실직했을 때 생활에 필요한 급여를 제공하는 사회보험은?', '["고용보험", "국민건강보험", "국민연금보험", "산업재해보상보험", "노인장기요양보험"]'::jsonb, 1, '요양보호사의 사회보험에 대한 이해를 확인하기 위함입니다.', NULL, '{"1": "고용보험은 실직 시 생활에 필요한 급여를 제공하는 보험입니다.\n[정답]", "2": "국민건강보험은 의료 서비스를 제공받기 위한 보험입니다.", "3": "국민연금보험은 노후 소득을 보장하는 보험입니다.", "4": "산업재해보상보험은 산업재해로 인한 보상을 위한 보험입니다.", "5": "노인장기요양보험은 노인에 대한 장기요양 서비스를 제공하는 보험입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자 또는 노인 등을 돌보는 직업", "def_vi": "Người chăm sóc bệnh nhân hoặc người cao tuổi"}, {"term_ko": "실직", "term_vi": "Mất việc", "def_ko": "일자리를 잃는 것", "def_vi": "Bị mất công việc"}, {"term_ko": "급여", "term_vi": "Trợ cấp", "def_ko": "삶에 필요한 돈", "def_vi": "Tiền cần thiết cho cuộc sống"}, {"term_ko": "사회보험", "term_vi": "Bảo hiểm xã hội", "def_ko": "사회적 위험을 대비한 보험", "def_vi": "Bảo hiểm cho các rủi ro xã hội"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (610, '1', '대상자가 최소한의 움직임도 하지 않고 오랜 시간 침상에 누워만 있을 때 발생할 수 있는 상황은?', '["순환기가 안정되어 심장 기능이 좋아진다.", "근력이 저하되어 보행 능력이 상실된다.", "호흡이 안정되어 폐활량에 도움이 된다.", "골격근이 강화되고 근력이 상승한다.", "관절이 보호되어 낙상 위험이 줄어든다."]'::jsonb, 2, '대상자가 오랜 시간 침상에 누워있을 때 발생할 수 있는 문제를 이해하는 것이다.', NULL, '{"1": "순환기가 안정되어 심장 기능이 좋아질 수 없다. 이는 장기적인 부동 상태에서 심장 기능이 감소할 위험이 있다.\n[정답]", "2": "근력이 저하되어 보행 능력이 상실될 수 있다. 이는 오랜 시간 부동으로 인해 발생하는 일반적인 상식이다.", "3": "호흡이 안정되어 폐활량에 도움이 되지 않는다. 오히려 침대에 오래 눕게 되면 폐활량이 감소할 수 있다.", "4": "골격근이 강화되고 근력이 상승하지 않는다. 지속적인 부동은 근육의 위축을 초래한다.", "5": "관절이 보호되어 낙상 위험이 줄어드는 것이 아니다. 오히려 장기간의 부동은 관절 경직을 초래할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (609, '1', '요양보호 실천의 4가지 원칙 중 말하기 방법으로 옳은 것은?', '["긍정형과 부정형 문장을 섞어서 또박또박 말한다.", "대상자가 반응이 없으면 말을 걸지 않는다.", "잠에서 덜 깨었을 때 말을 걸기 시작한다.", "말을 이해하지 못하면 서비스만 제공한다.", "이야기를 한 후 최소 3초 이상 기다린다."]'::jsonb, 5, '요양보호 실천에서의 효과적인 의사소통 방법을 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "긍정형과 부정형 문장을 섞어서 또박또박 말하는 것은 적절하지 않습니다.\n[정답]", "5": "이야기를 한 후 최소 3초 이상 기다리는 것이 올바른 의사소통 방법입니다.", "2": "대상자가 반응이 없으면 말을 걸지 않는 것은 비효율적인 방법입니다.", "3": "잠에서 덜 깨었을 때 말을 걸기 시작하는 것은 상대방의 상태에 따라 다를 수 있습니다.", "4": "말을 이해하지 못하면 서비스만 제공하는 것은 영양보호의 질을 떨어뜨릴 수 있습니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "원칙", "def_ko": "돌봄 (chăm sóc)", "def_vi": "원리 (nguyên tắc)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (608, '1', '요양보호 실천의 4가지 원칙과 내용이 옳은 것은?', '["대면하기 : 위에서 내려다보며 옆에서 힐끗 본다.", "말하기 : 대상자가 졸고 있을 때 말을 건다.", "접촉하기 : 손가락에 힘을 주어 꽉 잡는다.", "말하기 : 봐야 할 것을 눈높이에서 보여주며 말을 한다.", "일어서게 하기 : 도움을 주어 혼자 움직이지 않게 한다."]'::jsonb, 4, '요양보호 실천의 기본 원칙과 내용을 평가하기 위한 문제입니다.', NULL, '{"1": "대면하기는 적절하지 않으며, 위에서 내려다보며 옆에서 힐끗 보는 것은 바람직하지 않습니다.", "2": "졸고 있는 대상자에게 말을 건다면 상대방의 상태를 고려하지 않은 행동입니다.", "3": "손가락에 힘을 주어 꽉 잡는 것은 오히려 불편함을 줄 수 있으므로 적절하지 않습니다.\n[정답]", "4": "눈높이에서 봐야 할 것을 보여주며 말을 걸면 대상자와의 소통이 원활해집니다.", "5": "도움을 줄 때는 혼자 행동하지 못하게 하는 것이 아니라 혼자서도 할 수 있도록 돕는 것이 중요합니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "Chăm sóc", "def_ko": "돌봄과 지원을 필요로 하는 사람을 도와주는 직업", "def_vi": "Nghề giúp đỡ những người cần sự chăm sóc và hỗ trợ"}, {"term_ko": "대면하기", "term_vi": "Gặp gỡ", "def_ko": "시선이나 신체를 직접 맞대는 것", "def_vi": "Sự tiếp xúc trực tiếp bằng ánh mắt hoặc cơ thể"}, {"term_ko": "접촉하기", "term_vi": "Tiếp xúc", "def_ko": "서로의 신체를 만지는 것", "def_vi": "Sờ vào cơ thể của nhau"}, {"term_ko": "혼자", "term_vi": "Một mình", "def_ko": "외롭고 따로 있는 상태", "def_vi": "Trạng thái đơn độc và tách biệt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (607, '1', '억제대 사용 시 대상자에게 발생할 수 있는 상황으로 옳은 것은?', '["혈액순환에 도움이 된다.", "폐활량이 좋아진다.", "골격근의 근력 유지에 도움이 된다.", "자세변환이 힘들어 욕창이 잘 생긴다.", "뼈와 관절을 보호하고 골다공증에 도움이 된다."]'::jsonb, 4, '억제대 사용 시 어떤 부작용이나 상황이 발생할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "억제대는 혈액순환에 긍정적인 영향을 주지 않습니다.", "2": "폐활량이 개선되지 않습니다.", "3": "골격근의 근력 유지와 관련이 없습니다. \n[정답]", "4": "억제대 사용 시 자세변환이 어려워져 욕창 발생 위험이 증가합니다.", "5": "뼈와 관절 보호에 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "억제대", "term_vi": "Dây kiềm chế", "def_ko": "제한, 제어하기 위해 사용되는 장치", "def_vi": "Thiết bị được sử dụng để hạn chế và kiểm soát"}, {"term_ko": "혈액순환", "term_vi": "Tuần hoàn máu", "def_ko": "혈액이 신체를 순환하는 과정", "def_vi": "Quá trình máu lưu thông trong cơ thể"}, {"term_ko": "폐활량", "term_vi": "Khả năng hô hấp", "def_ko": "폐에서 호흡할 수 있는 공기의 양", "def_vi": "Lượng không khí có thể hít vào và thở ra từ phổi"}, {"term_ko": "골격근", "term_vi": "Cơ xương", "def_ko": "신체를 움직이는 데 필요하는 주요 근육", "def_vi": "Các cơ chính cần thiết để di chuyển cơ thể"}, {"term_ko": "욕창", "term_vi": "Loét do nằm lâu", "def_ko": "누워 있는 환자에게 생길 수 있는 피부손상", "def_vi": "Tổn thương da có thể xảy ra ở bệnh nhân nằm lâu"}, {"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈가 약해지기 쉽고 부서지기 쉬운 상태", "def_vi": "Tình trạng xương trở nên yếu và dễ vỡ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (606, '1', '노인부양 문제를 개선하기 위한 방안으로 옳은 것은?', '["노인돌봄정책을 축소한다.", "장기요양등급판정 항목을 늘린다.", "사회보험제도를 통해 세대통합을 증진한다.", "소득재분배를 위해 기초연금을 축소시킨다.", "국가 주도의 획일적인 노인복지서비스를 제공한다."]'::jsonb, 3, '노인부양 문제에 대한 해결책을 이해하고 평가하는 능력을 측정하고자 함.', NULL, '{"1": "노인돌봄정책을 축소하는 것은 부정적인 영향을 초래할 수 있다.\n[정답]", "3": "사회보험제도를 통해 세대통합을 증진하는 것은 노인의 삶의 질을 개선할 수 있는 긍정적인 방안이다.", "2": "장기요양등급판정 항목을 늘리는 것은 복잡성을 증가시킬 수 있다.", "4": "기초연금을 축소하는 것은 노인의 경제적 어려움을 가중시킬 수 있다.", "5": "국가 주도의 획일적인 노인복지서비스는 개인의 필요를 충족하지 못할 수 있다."}'::jsonb, '[{"term_ko": "노인부양", "term_vi": "Chăm sóc người cao tuổi", "def_ko": "늙은이들을 돌보는 것", "def_vi": "Việc chăm sóc cho người già"}, {"term_ko": "장기요양등급판정", "term_vi": "Đánh giá mức độ chăm sóc dài hạn", "def_ko": "장기요양 서비스의 필요성을 평가하는 것", "def_vi": "Đánh giá nhu cầu dịch vụ chăm sóc dài hạn"}, {"term_ko": "세대통합", "term_vi": "Hội nhập thế hệ", "def_ko": "서로 다른 세대 간의 관계를 증진하는 것", "def_vi": "Tăng cường mối quan hệ giữa các thế hệ"}, {"term_ko": "소득재분배", "term_vi": "Tái phân phối thu nhập", "def_ko": "소득의 불균형 해소를 위한 정책", "def_vi": "Chính sách nhằm giải quyết sự bất bình đẳng thu nhập"}, {"term_ko": "기초연금", "term_vi": "Trợ cấp hưu trí cơ bản", "def_ko": "노인이 받을 수 있는 기본적인 연금", "def_vi": "Khoản trợ cấp hưu trí cơ bản mà người cao tuổi có thể nhận được"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (605, '1', '노인부양 문제의 해결을 위해 노인의 개인적 대처방법으로 옳은 것은?', '["노인요양보험 확대", "사회 교육프로그램 참여", "양질의 노인일자리 개발", "노인복지정책 강화", "노인요양시설 확대"]'::jsonb, 2, '노인의 개인적 대처방법에 대한 이해를 요구함.', NULL, '{"1": "노인요양보험 확대는 정부의 정책 변화에 해당하며 개인적 대처와는 관련이 없다.\n[정답]", "2": "사회 교육프로그램 참여는 노인이 자신의 사회적 역할을 강화하는 방법으로 개인적 대처에 적합하다.", "3": "양질의 노인일자리 개발은 주로 정부와 관련된 문제로 개인 대처와 거리가 있다.", "4": "노인복지정책 강화는 정부 차원의 문제이며 개인적 대처와는 관련이 적다.", "5": "노인요양시설 확대는 사회적 지원 문제에 해당하며 개인적 대처가 아니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인을 뜻하는 말", "def_vi": "Người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (604, '1', '요양보호사가 대상자를 대하는 원칙 중 옳은 것은?', '["무엇이든 강제로 한다.", "사고방지를 위해 억제대를 하게 한다.", "움직임이 불편한 대상자는 겨드랑이를 잡아 올린다.", "화장실을 걸어서 이동하려고 하면 걸을 수 있게 해준다.", "대답이 없는 대상자에게는 말을 건네지 않는다."]'::jsonb, 4, '요양보호사가 대상자에게 준수해야 할 원칙에 대해 질문하고 있습니다.', NULL, '{"1": "강제로 하는 것은 대상자의 인권을 침해하는 행동입니다.\n[정답]", "4": "대상자가 스스로 이동할 수 있도록 도와주는 것이 바람직합니다.", "2": "억제대 사용은 최소화해야 하며, 필요할 경우에도 대상자의 동의를 우선시해야 합니다.", "3": "겨드랑이는 민감한 부위로, 잘못된 방법으로 올리면 부상을 초래할 수 있습니다.", "5": "대답이 없는 경우에도 지속적으로 말을 건네는 것이 중요합니다."}'::jsonb, '[{"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "원칙(한국어)", "def_vi": "nguyên tắc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (603, '1', '인간다움 케어에서 대상자가 기분 좋게 느끼도록 돌봄을 시행하는 단계로 옳은 것은?', '["케어의 준비 단계", "만남의 준비 단계", "감정의 고정 단계", "지각의 연결 단계", "재회의 약속 단계"]'::jsonb, 4, '대상자가 기분 좋게 느끼도록 하는 돌봄의 단계에 대한 이해를 평가하고자 한다.', NULL, '{"1": "케어의 준비 단계: 돌봄을 위한 사전 준비 단계로, 이는 감정이나 기분을 조성하는 단계가 아니다.\n[정답]", "2": "만남의 준비 단계: 대상자와의 만남에서 서로의 감정을 이해하고 연결하는 단계로, 인간다움을 느끼도록 하는 데 중요한 역할을 한다.", "3": "감정의 고정 단계: 감정이 고정되거나 고착되는 것이 아니라, 지속적으로 변화하는 것이 바람직하다.", "4": "지각의 연결 단계: 대상자의 기분을 좋게 만드는 데 중요한 단계이다. 감정과 기억이 연결되어 긍정적인 경험으로 이어진다.", "5": "재회의 약속 단계: 이후의 만남을 약속하는 단계로, 현재의 돌봄과는 직접적인 연관이 없다."}'::jsonb, '[{"term_ko": "인간다움", "term_vi": "Nhân tính", "def_ko": "인간성(한국어)", "def_vi": "Nhân văn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (602, '1', '대상자를 대하는 실천 원칙으로 5가지 단계의 순서로 옳은 것은?가. 케어의 준비 나. 만남의 준비 다. 감정의 고정 라. 지각의 연결 마.재회의 약속', '["가 → 나 → 다 → 라 → 마", "나 → 가 → 라 → 다 → 마", "나 → 다 → 마 → 라 → 가", "다 → 가 → 라 → 나 → 마", "라 → 가 → 디 → 마 → 나"]'::jsonb, 2, '대상자를 대하는 실천 원칙의 단계적 접근을 이해하고 정리하기 위함입니다.', NULL, '{"1": "케어의 준비가 먼저 이루어져야 하지만, 그 다음 단계는 만남의 준비가 앞서야 합니다. 따라서, 이 순서는 옳지 않습니다.\n[정답]", "2": "만남의 준비 후에 케어의 준비가 이어지고, 그 다음 감정의 고정, 지각의 연결, 재회의 약속 순으로 진행됩니다. 이 순서가 올바릅니다.", "3": "만남의 준비를 먼저 하고, 감정의 고정이 이루어지되, 이 순서는 바올바로 진행되지 못합니다.", "4": "감정의 고정을 가장 먼저 진행하는 것은 정해진 원칙에 맞지 않으므로 올바르지 않습니다.", "5": "지각의 연결이 먼저 오는 것도 옳지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (601, '1', '노인부양 문제의 해결 방안으로 옳은 것은?', '["재가노인은 요양보호사가 24시간 서비스를 담당한다.", "비공식적 돌봄인력인 간호사, 사회복지사가 참여한다.", "공식적 돌봄인력인 가족의 역할이 필수적이다.", "가족의 역할을 요양보호사로 대체한다.", "가족의 돌봄을 요양보호사가 함께 지원한다."]'::jsonb, 5, '노인 부양 문제의 해결에 대한 이해를 평가하기 위한 질문입니다.', NULL, '{"1": "재가노인이 24시간 요양보호사 서비스를 받는 것은 일반적이지 않으며, 재가노인은 가족 등의 지원이 필요합니다.\n[정답]", "5": "가족의 돌봄을 요양보호사가 함께 지원하는 것은 협력적인 돌봄 모델로 적절합니다.", "3": "가족의 역할이 중요하지만, 공식적 돌봄인력만으로는 부족한 상황이 많습니다.", "4": "가족 역할을 대체는 비효율적이며, 가족의 참여가 중요합니다.", "2": "비공식적 돌봄인력의 참여도 필요하지만, 요양보호사와의 협력이 더 중요합니다."}'::jsonb, '[{"term_ko": "재가노인", "term_vi": "Người cao tuổi tại gia", "def_ko": "집에서 돌봄을 받는 노인", "def_vi": "Người cao tuổi nhận sự chăm sóc tại nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (600, '1', '노인부양 문제의 해결방안으로 옳은 것은?', '["장남이 부양하는 것이 최선책이다.", "자녀에게 일방적인 부양을 강조한다.", "정서적 부양보다 경제적 부양을 중요시한다.", "몸이 불편해지면 바로 노인요양시설에 입소시킨다.", "사회와 가족이 협력하는 공적·사적 부양이 모두 필요하다."]'::jsonb, 5, '노인 부양에 대한 올바른 접근 방식을 이해하도록 하기 위함입니다.', NULL, '{"1": "장남이 부양하는 것이 최선책이라는 고정관념은 현대 사회에서 다양성을 무시합니다.", "2": "자녀에게 일방적인 부양을 강조하는 것은 비효율적이며, 가족 간의 갈등을 유발할 수 있습니다.", "3": "정서적 부양보다 경제적 부양을 중요시하는 것은 노인의 정서적 안정에 부정적인 영향을 미칠 수 있습니다.", "4": "몸이 불편해지면 바로 노인요양시설에 입소시키는 것은 가족과의 관계를 단절할 수 있습니다.\n[정답]", "5": "사회와 가족이 협력하는 공적·사적 부양이 모두 필요하다는 것이 현대적 해결 방안입니다."}'::jsonb, '[{"term_ko": "노인부양", "term_vi": "Chăm sóc người cao tuổi", "def_ko": "노인을 돌보는 것", "def_vi": "Chăm sóc cho người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (599, '1', '현대사회의 가족관계 변화로 옳은 것은?', '["세대 간 갈등이 완화되고 있다.", "독거노인의 비율이 낮아지고 있다.", "노인부양 의식이 점차 높아지고 있다.", "자녀의 독립으로 빈둥지증후군을 경험한다.", "조부모는 손자녀와 관계를 형성하는데 어려움을 겪는다."]'::jsonb, 4, '현대 사회의 가족 관계 변화와 그로 인해 나타나는 다양한 현상들을 이해하고 있는지를 평가하고자 하는 문제이다.', NULL, '{"1": "세대 간 갈등이 완화되고 있다. - 현대 사회에서는 세대 간 갈등이 여전히 존재하고 있다.\n[정답]", "2": "자녀의 독립으로 빈둥지증후군을 경험한다. - 자녀가 독립해 나가면 부모가 느끼는 외로움이나 공허함을 빈둥지증후군이라고 한다.", "3": "노인부양 의식이 점차 높아지고 있다. - 실제로는 부양의식이 약해지고 있는 경향이 많다.", "4": "독거노인의 비율이 낮아지고 있다. - 독거노인의 비율은 오히려 높아지고 있는 추세이다.", "5": "조부모는 손자녀와 관계를 형성하는데 어려움을 겪는다. - 조부모와 손자녀 간의 관계는 일반적으로 긍정적인 측면이 많다."}'::jsonb, '[{"term_ko": "가족관계", "term_vi": "Mối quan hệ gia đình", "def_ko": "가족 간의 유대 및 관계", "def_vi": "Sự gắn bó và mối quan hệ giữa các thành viên trong gia đình"}, {"term_ko": "세대", "term_vi": "Thế hệ", "def_ko": "세대, 시대", "def_vi": "Thế hệ, kỷ nguyên"}, {"term_ko": "갈등", "term_vi": "Xung đột", "def_ko": "갈등, 충돌", "def_vi": "Mâu thuẫn, xung đột"}, {"term_ko": "독거노인", "term_vi": "Người già sống một mình", "def_ko": "혼자 사는 노인", "def_vi": "Người cao tuổi sống độc lập"}, {"term_ko": "빈둥지증후군", "term_vi": "Hội chứng tổ trống", "def_ko": "자녀가 독립한 후 부모가 느끼는 심리적 증상", "def_vi": "Triệu chứng tâm lý mà cha mẹ cảm thấy khi con cái độc lập"}, {"term_ko": "조부모", "term_vi": "Ông bà", "def_ko": "손자녀를 가진 할아버지와 할머니", "def_vi": "Ông bà, ông với cháu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (598, '1', '노인이 되면 나타나는 대표적인 4가지 고통 중 옳은 것은?', '["무병장수", "직업", "무위", "여유", "저임금"]'::jsonb, 3, '노인이 겪는 일반적인 고통을 이해하고 구별하기 위한 문제입니다.', NULL, '{"1": "무병장수: 노인이 되면 건강 문제가 발생할 가능성이 높아지므로, 이는 옳지 않습니다.\n[정답]", "3": "무위: 노인이 되어 다양한 활동을 하지 못하고 무위 상태가 되는 경우가 많습니다.", "2": "직업: 노인이 되어도 일할 수 있는 경우가 있지만, 일반적으로는 은퇴 후 직업을 잃는 경우가 많지요.", "4": "여유: 노인이 되면 여유를 느끼는 경우도 있지만, 많은 고통을 함께 경험하는 경우가 많습니다.", "5": "저임금: 이는 경제적 문제와 관련된 것으로 노인의 고통을 직접적으로 나타내지는 않습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (597, '1', '노인 부모가 자녀와 근거리에 살면서 부양을 받는 가족 형태는?', '["핵가족", "수정확대가족", "대가족", "다문화가족", "한부모가족"]'::jsonb, 2, '노인 부모가 자녀와 가까이 살면서 받는 부양 형태를 이해하는 것이 목적입니다.', NULL, '{"1": "핵가족: 부모와 자녀로 구성된 작은 가족 단위입니다.\n[정답]", "2": "수정확대가족: 부모와 자녀가 함께 살고, 노인 부모도 근처에 살며 가족의 부양을 받는 형태입니다.", "3": "대가족: 여러 세대가 함께 살거나 여러 가족이 모여 구성된 가족입니다.", "4": "다문화가족: 다양한 문화적 배경을 가진 사람들이 이루는 가족입니다.", "5": "한부모가족: 한쪽 부모만 있는 가족을 의미합니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người già", "def_ko": "고령자(한국어)", "def_vi": "Người lớn tuổi"}, {"term_ko": "부모", "term_vi": "Bố mẹ", "def_ko": "부모님(한국어)", "def_vi": "Cha mẹ"}, {"term_ko": "부양", "term_vi": "Nuôi dưỡng", "def_ko": "지원(한국어)", "def_vi": "Chăm sóc"}, {"term_ko": "가족", "term_vi": "Gia đình", "def_ko": "가족(한국어)", "def_vi": "Gia đình"}, {"term_ko": "근거리", "term_vi": "Khoảng cách gần", "def_ko": "가까운 거리(한국어)", "def_vi": "Khoảng cách gần"}, {"term_ko": "형태", "term_vi": "Hình thức", "def_ko": "형식(한국어)", "def_vi": "Hình thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (596, '1', '노인이 적응하기 어렵고, 심한 고독감을 느끼게 되는 상황은?', '["전원생활", "자녀의 취업", "손자 손녀의 출생", "친한 친구의 죽음", "노인일자리사업 참여"]'::jsonb, 4, '노인이 심한 고독감을 느끼게 되는 상황을 이해하고, 고독감에서의 주요 원인을 찾도록 돕기 위함입니다.', NULL, '{"1": "전원생활은 노인이 자연 속에서 생활하는 것으로, 고독감과 관련이 적을 수 있습니다.\n[정답]", "4": "친한 친구의 죽음은 노인이 느끼는 심각한 고독감의 원인이 될 수 있습니다.", "2": "자녀의 취업은 긍정적인 요소로 작용할 수 있습니다.", "3": "손자 손녀의 출생은 노인에게 기쁨을 줄 수 있습니다.", "5": "노인일자리사업 참여는 활동적일 수 있어 고독감과는 거리가 있을 수 있습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người già", "def_ko": "노인 또는 늙은 사람", "def_vi": "Người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (595, '1', '노인이 죽음이라는 현실을 보다 잘 인식할 수 있는 계기가 되는 상황은?', '["배우자 사별", "경제적 빈곤감", "유대감 상실", "자녀의 결혼", "은퇴"]'::jsonb, 4, '노인이 죽음이라는 현실을 더 잘 인식할 수 있는 상황을 묻고 있습니다.', NULL, '{"1": "배우자 사별은 큰 슬픔을 느끼게 하여 죽음을 인식하게 만들 수 있지만, 주로 개인의 슬픔에 국한됩니다.\n[정답]", "4": "자녀의 결혼은 삶의 새로운 단계로 접어들면서 노인의 생애에 대한 성찰을 하게 만들고, 죽음이라는 현실을 더 잘 인식하게 만들 수 있습니다.", "2": "경제적 빈곤감은 삶의 질을 저하시킬 수 있지만, 직접적으로 죽음을 인식하게 만드는 요인은 아닙니다.", "3": "유대감 상실은 외로움을 느끼게 할 수 있지만, 죽음 인식과는 다소 관련성이 적습니다.", "5": "은퇴는 새로운 생활의 시작으로 느껴질 수 있어 죽음을 인식하는 요인과는 거리가 있습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (594, '1', '배우자 사별에 대한 적응단계 중 노인이 처음으로 경험하는 정서적 반응은?', '["소외감", "불안감", "상실감", "정체감", "자아존중감"]'::jsonb, 3, '배우자 사별 후 노인이 겪는 정서적 반응의 단계를 이해하고 있는지를 확인하기 위한 문제입니다.', NULL, '{"1": "소외감: 친구나 가족과의 관계에서 느끼는 고립감을 의미합니다.", "2": "불안감: 사별 후 미래에 대한 불안이나 두려움을 느끼는 것입니다.\n[정답]", "3": "상실감: 배우자의 사별로 인한 가장 처음 느껴지는 정서적 반응이며, 잃어버린 것에 대한 아픔입니다.", "4": "정체감: 노후에 자신의 존재 의미를 찾는 것입니다.", "5": "자아존중감: 자신의 가치와 존엄성을 인식하는 것입니다."}'::jsonb, '[{"term_ko": "배우자", "term_vi": "Người phối ngẫu", "def_ko": "결혼한 사람", "def_vi": "Người đã kết hôn"}, {"term_ko": "사별", "term_vi": "Mất người yêu", "def_ko": "사랑하는 사람을 잃다", "def_vi": "Mất người mà mình yêu quý"}, {"term_ko": "상실감", "term_vi": "Cảm giác mất mát", "def_ko": "잃은 것에 대한 슬픔", "def_vi": "Nỗi buồn về những gì đã mất"}, {"term_ko": "정서적", "term_vi": "Tình cảm", "def_ko": "감정에 관련된", "def_vi": "Liên quan đến cảm xúc"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "어떤 행동이나 태도를 보이는 것", "def_vi": "Hành động hoặc thái độ thể hiện"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (593, '1', '현대 사회에서 나타나는 노년기의 가족관계 변화 중 옳은 것은?', '["부부간의 관계가 동반자로 전환된다.", "성 역할의 구분이 명확해지고 있다.", "노년기 부부간 관계의 중요성이 감소되고 있다.", "부모에 비해 손자녀에 대한 책임감이 강해진다.", "노년기에 이르면서 형제자매와의 경쟁심이나 갈등이 심해진다."]'::jsonb, 1, '노년기 가족관계의 변화를 이해하고, 현실적인 선택지를 평가하는 능력을 묻는 문제입니다.', NULL, '{"1": "부부는 보다 동반자로서의 관계를 중시하게 됩니다.\n[정답]", "2": "성 역할의 구분은 노년기에 상대적으로 명확해질 수 없으며 부부간의 역할이 변화합니다.", "3": "노년기 부부간의 관계는 오히려 중요성이 증가하는 경향이 있습니다.", "4": "손자녀에 대한 책임감은 부부의 관계와 다르게 나타날 수 있습니다.", "5": "형제자매간의 갈등은 노년기에 일반적이지 않고, 오히려 서로의 지원이 중요하게 여겨집니다."}'::jsonb, '[{"term_ko": "노년기", "term_vi": "Giai đoạn tuổi già", "def_ko": "일생의 마지막 단계", "def_vi": "Giai đoạn cuối của cuộc đời"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (592, '1', '현대사회의 노인과 가족관계에 대한 설명으로 옳은 것은?', '["조부모들이 손자손녀와의 동거 관계를 불편해한다.", "기혼 자녀와의 동거가 줄면서 혼자 사는 노인이 늘고 있다.", "고부갈등이 늘어나고 장서갈등은 줄어든다.", "자녀가 직접 노인 부모를 봉양하는 일이 증가하고 있다.", "배우자와 사별 후 남성노인이 여성노인보다 더 오래 산다."]'::jsonb, 2, '현대 사회에서 노인과 가족관계의 변화를 이해하고, 노인의 생활양식과 사회적 관계를 파악하기 위함이다.', NULL, '{"1": "조부모와 손자손녀의 동거 관계에 대한 일반적인 불편함은 없다. \n[정답]", "2": "기혼 자녀와의 동거가 줄어들고 혼자 사는 노인의 수가 증가하고 있다는 사실은 현재 사회의 중요한 변화 중 하나이다.", "3": "고부갈등이 늘어나고 장서갈등이 줄어들 것이라는 주장은 통계적으로 뒷받침되지 않는다.", "4": "자녀가 직접 노인 부모를 봉양하는 일은 최근 감소하고 있다는 연구 결과가 많다.", "5": "배우자와 사별 후 남성 노인이 여성 노인보다 더 오래 산다는 통계는 존재하지 않는다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "elderly (한국어)", "def_vi": "elderly (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (591, '1', '생애주기 중 노인의 특성에 대한 이해로 옳은 것은?', '["노인의 특성은 선입견을 갖고 일반화시킨다.", "노인과의 만남은 일회적 접촉으로 충분하다.", "반복적 만남을 통해 노인의 특성을 파악한다.", "통합은 지나온 삶을 부정적으로 인식하는 것이다.", "절망은 과거와 현재 상황을 받아들이고 통합하는 상태이다."]'::jsonb, 3, '노인에 대한 올바른 이해를 돕기 위한 문제입니다.', NULL, '{"1": "노인의 특성을 일반화하는 것은 선입견을 낳을 수 있습니다.", "2": "노인과의 만남은 일회적이지 않고 반복적이어야 합니다.\n[정답]", "3": "반복적 만남을 통해 노인의 특성을 파악하는 것이 중요합니다.", "4": "통합은 지나온 삶을 부정적으로 인식하지 않습니다.", "5": "절망은 과거와 현재의 상황을 통합하는 것이 아닙니다."}'::jsonb, '[{"term_ko": "생애주기", "term_vi": "Vòng đời", "def_ko": "인생의 각 단계", "def_vi": "Các giai đoạn trong cuộc đời"}, {"term_ko": "특성", "term_vi": "Đặc điểm", "def_ko": "특징, 성질", "def_vi": "Tính chất, đặc tính"}, {"term_ko": "선입견", "term_vi": "Định kiến", "def_ko": "선입관, 편견", "def_vi": "Định kiến, ý kiến đã hình thành trước"}, {"term_ko": "통합", "term_vi": "Tích hợp", "def_ko": "하나로 합쳐짐", "def_vi": "Sự kết hợp, hợp nhất"}, {"term_ko": "절망", "term_vi": "Tuyệt vọng", "def_ko": "희망이 없음", "def_vi": "Không còn hy vọng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (590, '1', '에릭 에릭슨의 인간발달 단계 중 노년기에 경험하는 위기와 변화는?', '["근면성과 열등감", "친밀감과 고립감", "신뢰감과 불신감", "자아통합성과 절망감", "정체감과 역활혼돈"]'::jsonb, 4, '에릭 에릭슨의 인간발달 이론 중 노년기에서의 위기와 변화를 묻는 문제입니다.', NULL, '{"1": "근면성과 열등감은 아동기에 해당하는 주제입니다.", "2": "친밀감과 고립감은 청년기에 관련된 개념입니다.", "3": "신뢰감과 불신감은 유아기에 해당합니다.\n[정답]", "4": "자아통합성과 절망감은 노년기의 주요 주제로, 자신이 인생을 어떻게 평가하느냐에 대한 문제입니다.", "5": "정체감과 역할혼돈은 청소년기에 해당하는 개념입니다."}'::jsonb, '[{"term_ko": "인간발달", "term_vi": "Phát triển con người", "def_ko": "사람의 성장 과정(한국어)", "def_vi": "Quá trình lớn lên của con người(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (589, '1', '노인의 사회적 역할 변화로 인한 사회적 특성으로 옳은 것은?', '["퇴직으로 여유로운 생활을 한다.", "사회적 관계가 늘어나면서 유대감이 강화된다.", "사회적 역할이 상실되고 가정에서의 역할이 많아진다.", "역할 변화를 받아들이며 정서적 안정을 느끼게 된다.", "복합적이고 만성적인 질환으로 사회적 관계가 위축된다."]'::jsonb, 5, '노인의 사회적 역할 변화에 따른 사회적 특성을 이해하고, 그에 대한 올바른 인식을 평가하기 위해 출제된 문제이다.', NULL, '{"1": "퇴직 후 여유로운 생활을 하는 것은 일반적이지만, 모든 노인이 그렇게 느끼는 것은 아니다.\n[정답]", "5": "만성적인 질환으로 인해 사회적 관계가 위축되는 것이 노인의 일반적인 특성 중 하나이다.", "2": "사회적 관계가 늘어나기보다 약화되는 경향이 있다.", "3": "사회적 역할의 상실은 많아지지만, 가정에서의 역할 변화는 개인마다 다르다.", "4": "정서적 안정을 느끼는 것이 아니라 어려움을 겪는 경우가 많다."}'::jsonb, '[{"term_ko": "사회적 역할", "term_vi": "Vai trò xã hội", "def_ko": "사람의 사회 내에서의 기능과 위치", "def_vi": "Chức năng và vị trí của một người trong xã hội"}, {"term_ko": "사회적 관계", "term_vi": "Mối quan hệ xã hội", "def_ko": "사람들 간의 연결과 상호작용", "def_vi": "Sự kết nối và tương tác giữa mọi người"}, {"term_ko": "정서적 안정", "term_vi": "Sự ổn định cảm xúc", "def_ko": "감정의 안정된 상태", "def_vi": "Trạng thái cảm xúc ổn định"}, {"term_ko": "만성적 질환", "term_vi": "Bệnh mãn tính", "def_ko": "장기간 지속되는 질병", "def_vi": "Bệnh kéo dài trong thời gian dài"}, {"term_ko": "유대감", "term_vi": "Cảm giác gắn bó", "def_ko": "사람들 간의 끈끈한 관계", "def_vi": "Mối quan hệ chặt chẽ giữa mọi người"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (588, '1', '노화로 인한 노인의 심리적 변화로 옳은 것은?', '["유연성 증가", "외향성 증가", "조심성 증가", "독립성 증가", "의존성 증가"]'::jsonb, 5, '노화와 관련된 심리적 변화를 이해하고, 그 중에서 노인의 일반적인 특징을 파악하는 것입니다.', NULL, '{"1": "유연성 증가: 노화가 진행됨에 따라 유연성이 줄어드는 경향이 있습니다.", "2": "외향성 증가: 대개 내향적인 성향이 강화될 수 있습니다.", "3": "조심성 증가: 조심성이 증가하는 경우도 있으나, 이는 개인 차이에 따라 다를 수 있습니다.\n[정답]", "4": "독립성 증가: 나이가 들수록 독립적인 생활을 하려는 경향이 약해질 수 있습니다.", "5": "의존성 증가: 노화로 인해 신체적, 정서적인 의존성이 증가하는 경우가 많습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙어감(한국어)", "def_vi": "sự già đi(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (587, '1', '다음 설명에 해당하는 노인의 심리적 특성은?• 자신이 이 세상에 다녀갔다는 흔적을 후세에 남기고자 한다.• 자신이 가치 있는 삶을 살았다는 것을 인정받고자 한다.', '["의존성의 증가", "유산을 남기려는 경향", "내향성의 증가", "친근한 사물에 대한 애착심", "생에 대한 회고의 경향"]'::jsonb, 2, '노인이 가지는 심리적 특성을 이해하고 평가하기 위함입니다.', NULL, '{"1": "노인의 의존성이 증가하는 것은 심리적 특성 중 하나지만, 여기서는 후세에 대한 유산 남기기와 관련이 없습니다.\n[정답]", "2": "노인이 자신의 존재 가치를 인정받고자 하는 것은 유산을 남기려는 경향입니다.", "3": "내향성의 증가는 일반적인 심리적 경향일 수 있지만, 문제의 맥락에서는 부적합합니다.", "4": "친근한 사물에 대한 애착은 심리적 특성이지만, 직접적으로 유산 남기기와 연결되지 않습니다.", "5": "생에 대한 회고의 경향은 노인의 특성 중 하나이나, 유산을 남기려는 경향과는 다릅니다."}'::jsonb, '[{"term_ko": "심리적 특성", "term_vi": "Đặc điểm tâm lý", "def_ko": "인간의 정신과 감정의 특징", "def_vi": "Những đặc trưng về tâm trí và cảm xúc của con người"}, {"term_ko": "유산", "term_vi": "Di sản", "def_ko": "후세에 남기는 재산이나 가치", "def_vi": "Tài sản hoặc giá trị để lại cho thế hệ sau"}, {"term_ko": "가치", "term_vi": "Giá trị", "def_ko": "소중한 것", "def_vi": "Những điều quý giá"}, {"term_ko": "존재", "term_vi": "Sự tồn tại", "def_ko": "살아 있음", "def_vi": "Sự sống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (586, '1', '다음 내용은 노인의 심리적 특성 중 어떤 것을 고려한 것인가?요양시설에서 대상자의 가족에게 집에서 쓰던 물건이나 가족사진을 가져오게 하여 정서적 안정감을 유지하도록 돕는다.', '["의존성", "애착심", "경직성", "조심성", "내향성"]'::jsonb, 2, '노인의 심리적 특성 중 애착심을 고려한 내용을 묻고 있다.', NULL, '{"1": "의존성: 노인이 다른 사람에게 의존하는 경향을 의미한다.\n[정답]", "2": "애착심: 대상자가 사랑하는 사람이나 익숙한 사물에 대해 가지는 정서적 유대를 뜻한다.", "3": "경직성: 변경이나 새로운 것에 대한 저항을 나타낸다.", "4": "조심성: 신중함이나 위험을 피하려는 성향을 나타낸다.", "5": "내향성: 낯선 환경에서 스스로를 방어하며 외부와의 접촉을 피하는 성향을 의미한다."}'::jsonb, '[{"term_ko": "심리적", "term_vi": "Tâm lý", "def_ko": "심리적인 것과 관련된", "def_vi": "Liên quan đến tâm lý"}, {"term_ko": "특성", "term_vi": "Đặc điểm", "def_ko": "특징", "def_vi": "Đặc trưng"}, {"term_ko": "정서적", "term_vi": "Tình cảm", "def_ko": "감정과 관련된", "def_vi": "Liên quan đến cảm xúc"}, {"term_ko": "안정감", "term_vi": "Cảm giác ổn định", "def_ko": "안전하고 편안한 느낌", "def_vi": "Cảm giác an toàn và thoải mái"}, {"term_ko": "애착심", "term_vi": "Tình cảm gắn bó", "def_ko": "사랑하는 사람에 대한 감정적인 유대", "def_vi": "Sự gắn bó tình cảm với người yêu thích"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (585, '1', '다음 설명에 해당하는 노인의 심리적 특성은?• 자신의 지나온 일생의 여러 요인들을 떠올려 본다.• 실패와 좌절에 담담해 진다.•다가오는 죽음을 평온한 마음으로 받아들인다.', '["우울증 경향의 증가", "내향성의 증가", "유산을 남기려는 경향", "생에 대한 회고의 경향", "친근한 사물에 대한 애착심"]'::jsonb, 4, '노인의 심리적 특성을 이해하고 그에 따른 행동 패턴을 파악하기 위한 문제이다.', NULL, '{"1": "우울증 경향의 증가는 노인의 행동 특성을 나타내지만, 질문에 주어진 설명과는 관련이 없다.", "2": "내향성의 증가는 특정한 행동 특성을 의미하지만, 설명된 내용과 직접적으로 연결되지 않는다.\n[정답]", "3": "생에 대한 회고의 경향은 과거의 경험을 되새기는 노인의 행동을 잘 나타내며 최종 선택지로 적합하다.", "4": "친근한 사물에 대한 애착심은 노인들의 일반적인 심리 감정이지만, 설명된 특성과는 관련이 적다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (584, '1', '자신에게 익숙한 습관적인 태도나 방법을 고수하고 매사에 융통성이 없어지며 새로운 변화를 싫어한다. 노인의 심리적 특성은?', '["애착심 증가", "경직성 증가", "의존성 증가", "내향성 증가", "조심성 증가"]'::jsonb, 2, '노인의 심리적 특성을 이해하고, 변화를 싫어하는 경향을 파악하는 것이 주된 의도입니다.', NULL, '{"1": "애착심 증가: 노인이 친밀한 관계를 필요로 한다는 의미인데, 변화에 대한 저항과는 관련이 적습니다.\n[정답]", "2": "경직성 증가: 새로운 상황에 적응하지 않고 고집스러운 태도를 유지하는 것과 관련됩니다.", "3": "의존성 증가: 노인이 외부의 도움에 의존하게 되는 것을 의미하지만, 융통성과는 관련이 없습니다.", "4": "내향성 증가: 대인관계의 변화와 상관이 있으며, 경직성과는 다른 개념입니다.", "5": "조심성 증가: 변화에 대한 두려움을 포함하지만, 경직성과는 다르게 행동할 수 있는 여지가 있습니다."}'::jsonb, '[{"term_ko": "습관", "term_vi": "Thói quen", "def_ko": "습관(듣기)", "def_vi": "Thói quen"}, {"term_ko": "태도", "term_vi": "Thái độ", "def_ko": "태도(듣기)", "def_vi": "Thái độ"}, {"term_ko": "융통성", "term_vi": "Tính linh hoạt", "def_ko": "융통성(듣기)", "def_vi": "Tính linh hoạt"}, {"term_ko": "변화", "term_vi": "Thay đổi", "def_ko": "변화(듣기)", "def_vi": "Thay đổi"}, {"term_ko": "경직성", "term_vi": "Tính cứng nhắc", "def_ko": "경직성(듣기)", "def_vi": "Tính cứng nhắc"}, {"term_ko": "심리적", "term_vi": "Tâm lý", "def_ko": "심리적(듣기)", "def_vi": "Tâm lý"}, {"term_ko": "특성", "term_vi": "Đặc điểm", "def_ko": "특성(듣기)", "def_vi": "Đặc điểm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (583, '1', '일의 결과를 중시하고, 질문이나 문제에 대해 대답을 할지 망설이거나 하지 못하며, 매사에 신중해지는 노인의 심리적 특성은?', '["조심성의 증가", "내향성의 증가", "경직성의 증가", "우울증 경향의 증가", "친근한 사물에 대한 애착심 증가"]'::jsonb, 1, '노인의 심리적 특성을 이해하는 것이 목적입니다.', NULL, '{"1": "조심성이 증가하면 질문이나 문제에 대한 망설임이 발생할 수 있습니다.\n[정답]", "2": "내향성 증가와는 관련이 적습니다.", "3": "경직성의 증가는 특정 상황에 국한되지 않습니다.", "4": "우울증 경향은 별개의 심리적 특성입니다.", "5": "친근한 사물에 대한 애착심 증가와는 관계가 없습니다."}'::jsonb, '[{"term_ko": "일의 결과", "term_vi": "신중", "def_ko": "결과 của công việc", "def_vi": "cẩn trọng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (582, '1', '사회적 활동이 감소하고 타인과 만나는 것을 점차 기피하는 경향이 나타나는 노인의 심리적 특성은?', '["조심성의 증가", "우울증 경향의 증가", "내향성의 증가", "경직성의 증가", "의존성의 증가"]'::jsonb, 3, '노인의 심리적 특성을 이해하고, 사회적 활동과 대인관계에 대한 인식을 평가하는 것이 목적입니다.', NULL, '{"1": "조심성이 증가하면 외부 환경에 대한 경계가 커지지만, 노인들이 만남을 기피하는 것과는 다소 동떨어진 개념입니다.\n[정답]", "2": "우울증 경향이 증가하는 것은 심리적 에너지의 감소와 관련이 있지만, 내향성의 증가와 직접 연결되지는 않습니다.", "3": "내향성의 증가는 사회적 활동을 감소시키고 타인과의 만남을 기피하게 만듭니다.", "4": "경직성의 증가는 정신적 유연성을 잃는 것을 의미하지만, 사회적 기피와는 거리가 있습니다.", "5": "의존성의 증가는 외부에 대한 의존성을 높이지만, 내향성과는 다른 방향입니다."}'::jsonb, '[{"term_ko": "사회적 활동", "term_vi": "Hoạt động xã hội", "def_ko": "사람들 간의 상호작용과 교류", "def_vi": "Tương tác và giao lưu giữa mọi người"}, {"term_ko": "우울증", "term_vi": "Trầm cảm", "def_ko": "기분이 지속적으로 저하되는 정신 질환", "def_vi": "Bệnh tâm thần có tâm trạng liên tục bị giảm"}, {"term_ko": "내향성", "term_vi": "Hướng nội", "def_ko": "자신의 감정을 내면적으로 표현하는 성향", "def_vi": "Xu hướng biểu hiện cảm xúc bên trong"}, {"term_ko": "경직성", "term_vi": "Tính cứng nhắc", "def_ko": "유연함을 상실한 상태", "def_vi": "Trạng thái mất đi sự linh hoạt"}, {"term_ko": "의존성", "term_vi": "Tính phụ thuộc", "def_ko": "다른 사람에게 의지하는 성향", "def_vi": "Xu hướng dựa vào người khác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (581, '1', '우울증 경향이 있는 노인에게 나타나는 특성은?', '["자신감이 증가한다.", "숙면을 취한다.", "식욕이 증가한다.", "기억력이 저하된다.", "대인관계가 활발해진다."]'::jsonb, 4, '우울증 경향이 있는 노인의 특정 행동이나 심리적 특성을 파악하는 것.', NULL, '{"1": "자신감이 증가하는 것은 우울증의 특징이 아니다.", "2": "숙면을 취하는 것은 우울증 환자에게서 흔하지 않다.", "3": "식욕이 증가하는 것은 우울증과 관련이 적다.\n[정답]", "4": "기억력이 저하되는 것은 우울증 환자에게 자주 나타나는 현상이다.", "5": "대인관계가 활발해지는 것은 우울증과 반대되는 경향이다."}'::jsonb, '[{"term_ko": "우울증", "term_vi": "Trầm cảm", "def_ko": "정신적 질병으로 기분이 우울하고 기능이 저하됨", "def_vi": "Bệnh tâm lý khiến tâm trạng u ám và chức năng giảm sút"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (580, '1', '다음에서 설명하는 노인의 심리적인 특성은?•불면증, 식욕부진 •기억력 저하, 체중감소 •흥미와 의욕상실', '["조심성의 증가", "우울증 경향의 증가", "경직성의 증가", "내향성의 증가", "의존성의 증가"]'::jsonb, 2, '노인의 심리적 특성과 관련된 증상을 이해하고, 해당 증상이 무엇을 의미하는지를 묻는 질문입니다.', NULL, '{"1": "조심성의 증가: 노인에서 나타나는 심리적 특성이지만 질문의 증상과는 맞지 않음.\n[정답]", "2": "우울증 경향의 증가: 불면증, 식욕부진, 기억력 저하 등의 증상은 우울증의 특징들로 볼 수 있어 정답.", "3": "경직성의 증가: 성격의 구조적 변화와 관련있지만 질문의 증상과는 무관함.", "4": "내향성의 증가: 심리적 특성이지만 직접적인 관련성은 낮음.", "5": "의존성의 증가: 노인의 특성 중 하나이나 질문의 조건에선 적합하지 않음."}'::jsonb, '[{"term_ko": "불면증", "term_vi": "Mất ngủ", "def_ko": "잠을 충분히 자지 못하는 상태(한국어)", "def_vi": "Trạng thái không thể ngủ đủ"}, {"term_ko": "식욕부진", "term_vi": "Suy giảm cảm giác thèm ăn", "def_ko": "음식에 대한 욕구가 감소한 상태(한국어)", "def_vi": "Trạng thái giảm nhu cầu về thực phẩm"}, {"term_ko": "기억력 저하", "term_vi": "Giảm trí nhớ", "def_ko": "기억하는 능력이 떨어지는 상태(한국어)", "def_vi": "Trạng thái giảm khả năng ghi nhớ"}, {"term_ko": "체중감소", "term_vi": "Giảm cân", "def_ko": "몸무게가 줄어드는 현상(한국어)", "def_vi": "Hiện tượng trọng lượng cơ thể giảm"}, {"term_ko": "흥미", "term_vi": "Sự quan tâm", "def_ko": "어떤 것에 대해 관심을 가지는 것(한국어)", "def_vi": "Có sự quan tâm đến điều gì đó"}, {"term_ko": "의욕", "term_vi": "Ý chí", "def_ko": "어떤 일을 하려는 의향이나 열망(한국어)", "def_vi": "Sự mong muốn hoặc khát vọng làm một việc gì đó"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (579, '1', '노인의 공통적인 신체적 특성으로 옳은 것은?', '["신체 조직의 적응력이 빠르다.", "질병이 발생할 경우 급격하게 상황이 악화된다.", "인간의 노력으로 노화의 진행을 막을 수 있다.", "잔존능력의 증가로 일상생활에 어려움은 없다.", "회복이 가능한 만성질환이 대부분이다."]'::jsonb, 2, '노인의 신체적 특성을 이해하고 올바른 정보를 선택하게 하기 위함입니다.', NULL, '{"1": "신체 조직의 적응력이 빠르지 않으므로 틀립니다.\n[정답]", "2": "질병이 발생할 경우 급격하게 상황이 악화되므로 옳은 설명입니다.", "3": "노화의 진행은 완전히 막을 수 없습니다.", "4": "잔존 능력이 증가하지 않으므로 일상생활에 어려움이 있을 수 있습니다.", "5": "대부분의 만성질환은 회복이 어려운 경우가 많습니다."}'::jsonb, '[{"term_ko": "신체", "term_vi": "Cơ thể", "def_ko": "몸(한국어)", "def_vi": "cơ thể(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (578, '1', '노인의 신체적 특성으로 옳은 것은?', '["면역능력이 향상된다.", "회복능력이 향상된다.", "노화가 비가역적으로 진행된다.", "신체기관의 잔존능력이 향상된다.", "일상생활 수행능력이 향상된다."]'::jsonb, 3, '노인의 신체적 특성과 노화에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "면역능력은 노화와 함께 감소한다.", "2": "회복능력 역시 노화로 인해 저하된다. \n[정답]", "3": "노화는 비가역적인 과정으로 진행된다.", "4": "신체기관의 잔존능력은 노화에 따라 감소할 수 있다.", "5": "일상생활 수행능력은 보통 노화와 함께 저하된다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người già", "def_ko": "나이가 많은 사람", "def_vi": "Người có tuổi"}, {"term_ko": "신체적", "term_vi": "Thể chất", "def_ko": "몸과 관련된", "def_vi": "Liên quan đến cơ thể"}, {"term_ko": "특성", "term_vi": "Đặc điểm", "def_ko": "특징", "def_vi": "Đặc điểm"}, {"term_ko": "면역능력", "term_vi": "Khả năng miễn dịch", "def_ko": "면역 기능", "def_vi": "Chức năng miễn dịch"}, {"term_ko": "회복능력", "term_vi": "Khả năng hồi phục", "def_ko": "회복 능력", "def_vi": "Khả năng hồi phục"}, {"term_ko": "비가역적", "term_vi": "Không thể đảo ngược", "def_ko": "되돌릴 수 없는", "def_vi": "Không thể đảo ngược"}, {"term_ko": "신체기관", "term_vi": "Cơ quan trong cơ thể", "def_ko": "몸의 기관", "def_vi": "Các cơ quan trong cơ thể"}, {"term_ko": "잔존능력", "term_vi": "Khả năng còn lại", "def_ko": "남아 있는 능력", "def_vi": "Khả năng tồn tại"}, {"term_ko": "일상생활", "term_vi": "Sinh hoạt hàng ngày", "def_ko": "일상적인 활동", "def_vi": "Các hoạt động hàng ngày"}, {"term_ko": "수행능력", "term_vi": "Khả năng thực hiện", "def_ko": "수행 능력", "def_vi": "Khả năng thực hiện"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (577, '1', '건강한 노화를 위한 방법으로 옳은 것은?', '["체면을 위해 애정 표현은 삼간다.", "뇌에 자극을 주는 활동을 한다.", "사생활을 위해 대인관계를 자제한다.", "만성질환을 민간요법으로 지속적으로 관리한다.", "신체적 노화를 늦추기 위해 매시간 고강도 운동을 한다."]'::jsonb, 2, '건강한 노화를 위한 방법을 이해하고 선택할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "체면을 위해 애정 표현은 삼간다는 노화와 관련이 없는 부정적인 태도를 나타냅니다.\n[정답]", "2": "뇌에 자극을 주는 활동은 노화 방지와 인지 기능 향상에 도움이 됩니다.", "3": "사생활을 위해 대인관계를 자제하는 것은 건강한 사회적 관계를 맺는 데 방해가 됩니다.", "4": "만성질환을 민간요법으로 관리하는 것은 전문적인 치료에 비해 신뢰성이 떨어질 수 있습니다.", "5": "신체적 노화를 늦추기 위해 매시간 고강도 운동을 하는 것은 오히려 신체에 무리를 줄 수 있습니다."}'::jsonb, '[{"term_ko": "건강한", "term_vi": "Khỏe mạnh", "def_ko": "건강한(한국어)", "def_vi": "khỏe mạnh(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (576, '1', '노년기를 건강하게 보내기 위한 방법으로 옳은 것은?', '["야외 활동을 점차 줄인다.", "기억력 유지를 위해 단조로운 생활을 한다.", "만성질환의 유무를 정기적으로 확인한다.", "건강을 위해 자신에게 맞지 않는 음식도 먹도록 한다.", "여가활동, 지역사회 참여 등 생산적 활동을 자제한다."]'::jsonb, 3, '노년기를 건강하게 보내기 위한 올바른 방법을 묻는 문제입니다.', NULL, '{"1": "야외 활동을 점차 줄이는 것은 건강에 좋지 않다.", "2": "기억력 유지를 위해 단조로운 생활을 하는 것은 좋지 않다.\n[정답]", "3": "만성질환의 유무를 정기적으로 확인하는 것은 건강 유지에 필수적이다.", "4": "건강을 위해 자신에게 맞지 않는 음식을 먹는 것은 해롭다.", "5": "여가활동과 지역사회 참여는 노년기의 생산적 활동으로 권장된다."}'::jsonb, '[{"term_ko": "노년기", "term_vi": "Thời kỳ cao niên", "def_ko": "노인의 생애 단계", "def_vi": "Giai đoạn sống của người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (575, '1', '국가가 ''노인의 날''을 지정하여 해마다 기념하는, 노인을 위한 보상 유형은?', '["정치적 보상", "신체적 보상", "경제적 보상", "문화유산의 전수", "지적, 정신적 보상"]'::jsonb, 1, '국가가 노인을 위해 어떤 형태의 보상을 제공하는지 이해하는 것이 목적이다.', NULL, '{"1": "정치적 보상: 노인을 위한 정치적 권리 및 참여 기회를 포함한다.\n[정답]", "2": "신체적 보상: 노인의 건강 및 신체적 지원을 제공하는 것을 의미하지만, 이 문제의 정답은 아니다.", "3": "경제적 보상: 노인의 경제적 지원을 의미하나, ''노인의 날''의 취지와는 관련이 적다.", "4": "문화유산의 전수: 노인에게 문화유산을 계승하는 것을 의미하며 보상 유형이 아니다.", "5": "지적, 정신적 보상: 지적 및 정신적 지원을 포함하지만, 국가의 공식적인 보상 형태로서는 부적합하다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người có tuổi cao"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (574, 'mock', '중이염을 앓고 있는 대상자에게 귀약을 투여할 때 귓바퀴를 잡아당기는 방향은?', '["(가)", "(나)", "(다)", "(라)", "(마)"]'::jsonb, 2, '중이염 환자에게 귀약을 투여하는 과정에서 정확한 방법을 이해하고 있는지를 평가하기 위함이다.', NULL, '{"1": "잘못된 방향이다. 올바른 투여 방법이 아니다.\n[정답]", "2": "중이염 환자에게 귀약을 투여할 때는 귓바퀴를 위로 잡아당기는 것이 올바른 방법이다.", "3": "잘못된 방향이다. 올바른 투여 방법이 아니다.", "4": "잘못된 방향이다. 올바른 투여 방법이 아니다.", "5": "잘못된 방향이다. 올바른 투여 방법이 아니다."}'::jsonb, '[{"term_ko": "중이염", "term_vi": "Viêm tai giữa", "def_ko": "귀의 염증", "def_vi": "Viêm ở tai"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (573, 'mock', '다음 그림에서 대상자에게 안연고를 투여하는 위치와 방향이 옳은 것은?', '["(가)", "(나)", "(다)", "(라)", "(마)"]'::jsonb, 4, '대상자에게 안연고를 올바른 위치와 방향으로 투여하는 방법에 대한 이해를 평가하고자 하는 문제입니다.', NULL, '{"1": "(해당 방향이 잘못된 경우)", "2": "(해당 위치가 부적절한 경우)", "3": "(안연고 투여의 원리에 맞지 않는 경우)\n[정답] (라) (대상자에게 안연고를 적절한 위치와 방향으로 투여하는 방법)", "5": "(해당 방법이 잘못된 경우)"}'::jsonb, '[{"term_ko": "안연고", "term_vi": "Thuốc mỡ mắt", "def_ko": "눈에 사용하는 약물 형태", "def_vi": "Hình thức thuốc dùng cho mắt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (572, 'mock', '다음 그림 중 안약을 투여할 때 올바른 위치는?', '["(가)", "(나)", "(다)", "(라)", "(마)"]'::jsonb, 5, '안약 투여 시 올바른 위치를 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "(가) 안약을 투여할 위치가 아닙니다.\n[정답]", "5": "(마) 안약을 투여할 올바른 위치입니다.", "2": "(나) 안약을 투여할 위치가 아닙니다.", "3": "(다) 안약을 투여할 위치가 아닙니다.", "4": "(라) 안약을 투여할 위치가 아닙니다."}'::jsonb, '[{"term_ko": "안약", "term_vi": "Thuốc nhỏ mắt", "def_ko": "눈에 넣는 약", "def_vi": "Thuốc dùng cho mắt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (571, 'mock', '다음 중 물약을 사용하기 위해 병뚜껑을 열어 내려놓는 방법으로 옳은 것은?', '["(가)", "(나)", "(다)", "(라)", "(마)"]'::jsonb, 1, '병뚜껑을 올바르게 여는 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "병뚜껑을 열어 놓는 방법이 올바른 방식입니다.\n[정답]", "2": "잘못된 방법입니다.", "3": "잘못된 방법입니다.", "4": "잘못된 방법입니다.", "5": "잘못된 방법입니다."}'::jsonb, '[{"term_ko": "물약", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "Thuốc"}, {"term_ko": "병뚜껑", "term_vi": "Nắp chai", "def_ko": "병에 덮는 뚜껑(한국어)", "def_vi": "Nắp đậy của chai"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (570, 'mock', '가파른 내리막길에서 휠체어를 타고 있는 대상자의 이동을 돕는 방법은?', '["휠체어를 뒤로 돌려 지그재그로 내려간다.", "휠체어를 뒤로 돌려 앞바퀴를 들고 내려간다.", "휠체어를 앞으로 하여 똑바로 내려간다.", "휠체어를 앞으로 하여 지그재그로 내려간다.", "휠체어를 앞으로 하여 앞바퀴를 들고 내려간다."]'::jsonb, 1, '가파른 내리막길에서 휠체어를 안전하게 이동시키는 방법을 이해하고 대처할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "휠체어를 뒤로 돌려 지그재그로 내려가면 이동이 안전합니다.\n[정답]", "2": "휠체어를 뒤로 돌려 앞바퀴를 들고 내려가는 방법은 안전하지 않습니다.", "3": "휠체어를 앞으로 하여 똑바로 내려가는 방법은 위험할 수 있습니다.", "4": "휠체어를 앞으로 하여 지그재그로 내려가는 방법은 안전하지 않습니다.", "5": "휠체어를 앞으로 하여 앞바퀴를 들고 내려가는 방법은 매우 위험합니다."}'::jsonb, '[{"term_ko": "가파른", "term_vi": "Dốc", "def_ko": "경사가 심한", "def_vi": "độ dốc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (569, 'mock', '다음과 같이 반좌위 상태인 대상자를 침대 위쪽으로 이동시키는 방법은?', '["침대 시트를 잡아 당긴다.", "양 팔을 잡아 당긴다.", "겨드랑이 밑을 잡아 당긴다.", "발 아래에서 위로 밀어 올린다.", "침대 양 쪽에 서서 어깨와 등, 둔부와 대퇴를 받쳐 올려준다."]'::jsonb, 5, '대상자의 반좌위 상태에서의 안전하고 효율적인 이동 방법을 이해하고 있는지를 묻기 위한 문제입니다.', NULL, '{"1": "침대 시트를 잡아 당기는 것은 대상자를 이동시키는 데 안전하지 않은 방법입니다.\n[정답]", "2": "침대 양쪽에 서서 대상자의 어깨와 등, 둔부와 대퇴를 받쳐 올려주는 방법이 가장 안전하고 효과적입니다.", "3": "겨드랑이 밑을 잡아 당기는 것은 안전하지 않으며, 대상자에게 불편함을 줄 수 있습니다.", "4": "발 아래에서 위로 밀어 올리는 것은 부상의 위험이 있습니다.", "5": "양 팔을 잡아 당기는 것은 힘이 과도하게 들어 가므로 좋지 않습니다."}'::jsonb, '[{"term_ko": "반좌위", "term_vi": "Nửa nằm nửa ngồi", "def_ko": "반 앉은 자세", "def_vi": "Tư thế nửa nằm nửa ngồi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (568, 'mock', '그림과 같이 엎드린 대상자를 베개와 타월로 지지하는 이유는?', '["허리와 넙다리의 긴장 완화", "폐기능의 촉진", "척추 측만증 완화", "무릎관절 구축 예방", "혈액 순환 증진"]'::jsonb, 1, '대상자를 엎드린 자세로 지지하는 방법의 의도를 이해하기 위함이다.', NULL, '{"1": "허리와 넙다리의 긴장 완화: 엎드린 자세는 허리와 넙다리의 긴장을 완화시켜 주며, 따라서 지지하는 것이 필요하다.\n[정답]", "2": "폐기능의 촉진: 엎드린 자세가 폐 기능에 긍정적인 영향을 줄 수 있지만, 본 질문의 주요 목적과는 다르다.", "3": "척추 측만증 완화: 엎드린 자세는 척추 측만증을 완화할 수 있지만 직접적인 지지 방법은 아니다.", "4": "무릎관절 구축 예방: 엎드린 자세가 직접적인 영향을 미치지 않음.", "5": "혈액 순환 증진: 혈액 순환은 일반적으로 모든 자세에서 증가할 수 있으나, 이 질문의 특정 초점에는 해당하지 않는다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자 또는 도움이 필요한 사람", "def_vi": "Bệnh nhân hoặc người cần trợ giúp"}, {"term_ko": "베개", "term_vi": "Gối", "def_ko": "머리를 받치는 기구", "def_vi": "Vật dụng kê đầu"}, {"term_ko": "타월", "term_vi": "Khăn tắm", "def_ko": "개인 위생을 위한 천", "def_vi": "Vải dùng cho vệ sinh cá nhân"}, {"term_ko": "허리", "term_vi": "Lưng", "def_ko": "신체의 중간 부분", "def_vi": "Phần giữa cơ thể"}, {"term_ko": "넙다리", "term_vi": "Đùi", "def_ko": "허벅지", "def_vi": "Phần đùi"}, {"term_ko": "척추", "term_vi": "Cột sống", "def_ko": "등뼈", "def_vi": "Xương sống"}, {"term_ko": "측만증", "term_vi": "Cột sống lệch", "def_ko": "척추의 비정상 곡선", "def_vi": "Đường cong bất thường của cột sống"}, {"term_ko": "혈액", "term_vi": "Máu", "def_ko": "체내의 액체", "def_vi": "Chất lỏng trong cơ thể"}, {"term_ko": "순환", "term_vi": "Tuần hoàn", "def_ko": "회전 또는 흐름", "def_vi": "Quá trình lưu thông"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (566, 'mock', '장기간의 와상 상태에서 기저귀를 사용하는 대상자에게 욕창이 가장 잘 생기는 부위는?', '["(가)", "(나)", "(다)", "(라)", "(마)"]'::jsonb, 4, '장기간 와상 상태로 있는 대상자의 욕창 발생 부위를 파악하는 능력을 평가하고자 한다.', NULL, '{"1": "(가) 이 부위는 욕창 발생에 크게 영향을 미치지 않는다.\n[정답]", "4": "(라) 이 부위는 피부 압력으로 인해 욕창이 발생할 가능성이 높다.", "3": "(다) 이 부위의 욕창 위험은 낮다.", "5": "(마) 이 부위의 욕창 위험은 중간 정도이다."}'::jsonb, '[{"term_ko": "와상", "term_vi": "Nằm lâu", "def_ko": "침대에 눕거나 움직이지 못하는 상태", "def_vi": "Trạng thái nằm lâu không thể di chuyển"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (565, 'mock', '오른쪽 다리가 약한 대상자가 보행기를 사용하여 이동하는 순서는?', '["왼쪽 다리와 보행기 → 오른쪽 다리", "왼쪽 다리 → 오른쪽 다리 → 보행기", "오른쪽 다리와 보행기 → 왼쪽 다리", "오른쪽 다리 → 보행기 → 왼쪽 다리", "보행기 → 왼쪽 다리 → 오른쪽 다리"]'::jsonb, 3, '대상자의 보행을 도와주는 기구인 보행기를 사용할 때의 올바른 사용 순서를 이해하고 있는지를 평가하고자 함.', NULL, '{"1": "왼쪽 다리와 보행기를 사용하는 것은 보행기 사용법에 맞지 않음.\n[정답]", "3": "오른쪽 다리와 보행기를 먼저 사용한 후 왼쪽 다리를 이동하는 것은 약한 다리에 대한 올바른 지지 방법임.", "2": "이 방법은 보행기 사용 시 균형을 잃을 위험이 있음.", "4": "오른쪽 다리와 보행기를 먼저 이동하고 나면 균형 유지가 어려워질 수 있음.", "5": "처음에 보행기를 사용하는 것은 잘못된 순서임."}'::jsonb, '[{"term_ko": "다리", "term_vi": "Chân", "def_ko": "다리(한국어)", "def_vi": "Chân"}, {"term_ko": "보행기", "term_vi": "Khung đi bộ", "def_ko": "보행기(한국어)", "def_vi": "Khung đi bộ"}, {"term_ko": "대상자", "term_vi": "Người dùng", "def_ko": "대상자(한국어)", "def_vi": "Người dùng"}, {"term_ko": "이동", "term_vi": "Di chuyển", "def_ko": "이동(한국어)", "def_vi": "Di chuyển"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (562, 'mock', '다음 그림과 같이 정맥주사를 맞고 있는 왼쪽 편마비 대상자에게 단추있는 옷을 입히는 순서로 옳은 것은?', '["수액주머니 → 오른쪽 팔 → 왼쪽 팔", "오른쪽 팔 → 수액주머니 → 왼쪽 팔", "오른쪽 팔 → 왼쪽 팔 → 수액주머니", "왼쪽 팔 → 수액주머니 → 오른쪽 팔", "왼쪽 팔 → 오른쪽 팔 → 수액주머니"]'::jsonb, 4, '정맥주사를 맞고 있는 편마비 대상자에게 옷을 입히는 방법을 정확히 알고 적용하는 것의 중요성을 평가하기 위한 문제입니다.', NULL, '{"1": "수액주머니를 먼저 입히면 연결이 끊길 수 있습니다.\n[정답]", "4": "왼쪽 팔을 먼저 입히면 편마비로 인한 불편함을 최소화할 수 있습니다.", "2": "오른쪽 팔부터 시작하는 것은 편마비 대상자에게 적절하지 않습니다.", "3": "수액주머니를 나중에 입히면 연결 상태에 문제가 생길 수 있습니다.", "5": "왼쪽 팔을 먼저 하면서 수액주머니를 나중에 입히는 것은 잘못된 순서입니다."}'::jsonb, '[{"term_ko": "정맥주사", "term_vi": "Truyền nước biển", "def_ko": "정맥에 주입하는 약물 또는 수액", "def_vi": "Dịch truyền vào tĩnh mạch"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (561, 'mock', '왼쪽 편마비 대상자가 지팡이를 이용하여 버스를 탈 때 순서로 옳은 것은?', '["지팡이 - 오른발 - 왼발", "지팡이 - 왼발 - 오른발", "왼발 - 지팡이 - 오른발", "오른발 -지팡이 - 왼발", "왼발 - 오른발 - 지팡이"]'::jsonb, 1, '대상자가 버스를 탈 때 편마비 증상을 고려하여 올바른 방법을 선택하도록 하기 위함입니다.', NULL, '{"1": "오른발로 지팡이를 지지하고 앞으로 나아가면서 왼발로 버스에 승차하는 방법이 가장 올바릅니다.\n[정답]", "2": "왼발로 먼저 나아가면 균형을 잃을 수 있습니다.", "3": "왼발 먼저 나아가는 것도 부적절한 방법입니다.", "4": "오른발로 먼저 나아가면 지팡이의 역할을 제대로 할 수 없습니다.", "5": "지팡이의 위치가 부적절하여 안정성이 떨어집니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 신체가 마비된 상태", "def_vi": "Trạng thái tê liệt một bên cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (557, 'mock', '다음 그림과 같이 휠체어를 자동차의 트렁크로 옮기는 방법으로 옳은 것은?', '["몸에서 멀리하여 들어 올린다.", "허리의 회전을 이용하여 옮긴다.", "허리를 굽혔다 펴면서 들어 올린다.", "무릎을 굽혀 자세를 낮춰서 들어 올린다.", "다리를 모아 지지면을 좁혀 들어 올린다."]'::jsonb, 4, '휠체어를 안전하게 옮기는 방법에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "몸에서 멀리하여 들어 올리는 것은 허리의 부상을 유발할 수 있습니다.\n[정답]", "4": "무릎을 굽혀 자세를 낮춰서 들어 올리는 방법이 가장 안전하고 올바른 방법입니다.", "3": "허리를 굽혔다 펴면서 들어 올리는 방법은 허리에 부담을 줄 수 있습니다.", "2": "허리의 회전을 이용하여 옮기는 것은 잘못된 방법입니다.", "5": "다리를 모아 지지면을 좁혀 들어 올리는 것은 안정성을 저해할 수 있습니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": null, "def_ko": "휠체어", "def_vi": null}, {"term_ko": "트렁크", "term_vi": "Cốp xe", "def_ko": "자동차 후면의 짐을 실는 공간", "def_vi": "không gian để chứa đồ ở phía sau ô tô"}, {"term_ko": "무릎", "term_vi": "Đầu gối", "def_ko": "우리의 관절 중 하나", "def_vi": "một trong những khớp của chúng ta"}, {"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "무엇인가를 하고 있는 상태", "def_vi": "trạng thái khi làm một việc gì đó"}, {"term_ko": "부상", "term_vi": "Chấn thương", "def_ko": "다치거나 아프게 되는 것", "def_vi": "việc bị chấn thương hoặc đau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (554, 'mock', '왼쪽 편마비 대상자를 바닥에서 휠체어로 이동시킬 때 휠체어 놓는 위치로 옳은 것은?', '["(가)", "(나)", "(다)", "(라)", "(마)"]'::jsonb, 1, '왼쪽 편마비 대상자를 휠체어로 안전하게 이동시키기 위한 올바른 휠체어 위치를 파악하는 것이다.', NULL, '{"1": "올바른 위치로, 편마비 측과 가까운 방향에 놓여 있어야 하므로 적합하다.\n[정답]", "2": "휠체어가 대상자에게 너무 멀리 놓여 있어 이동에 어려움이 있을 수 있다.", "3": "휠체어가 너무 높은 위치에 놓여 있어 이동 시 불편할 수 있다.", "4": "휠체어가 담넘는 위치에 놓여 있어 안전하지 않다.", "5": "휠체어가 불안정한 위치에 놓여 있어 대상자를 이동하기 위험하다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸의 마비(한국어)", "def_vi": "Liệt một bên cơ thể(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (553, 'mock', '대상자가 침대 아래쪽으로 미끄러져 내려가 있을 때 위쪽으로 이동시키는 순서는?', '["가 - 나 - 다 - 라", "나 - 라 - 가 - 다", "나 - 다 - 가 - 라", "나 - 가 - 다 - 라", "다 - 나 - 가 - 라"]'::jsonb, 3, '침대에서 환자를 안전하게 이동시키는 방법을 이해하는 것.', NULL, '{"1": "가: 올바른 세팅이 아님.", "2": "나: 환자를 먼저 안정적으로 잡지 못함.\n[정답]", "3": "나: 먼저 환자의 머리를 안정시킨 후, 다리 쪽을 들어올리고, 가: 환자의 몸을 중앙으로 이동하며, 라: 마지막으로 몸을 고정하는 단계로 이동.", "4": "가: 올바른 순서가 아님.", "5": "다: 이동 순서에서 불필요한 단계가 포함됨."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (552, 'mock', '휠체어를 잡는 순으로 옳은 것은?', '["나 - 가 - 다 - 라", "나 - 라 - 가 - 다", "나 - 다 - 가 - 라", "나 - 다 - 라 - 가", "나 - 가 - 라 - 다"]'::jsonb, 3, '휠체어를 안전하게 사용하는 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "나 - 가 - 다 - 라: 순서가 잘못되었습니다.\n[정답]", "3": "나 - 다 - 가 - 라: 올바른 순서입니다.", "2": "나 - 라 - 가 - 다: 순서가 잘못되었습니다.", "4": "나 - 다 - 라 - 가: 순서가 잘못되었습니다.", "5": "나 - 가 - 라 - 다: 순서가 잘못되었습니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "이동 수단인 휠체어", "def_vi": "Xe trợ giúp di chuyển"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (551, 'mock', '그림과 같이 오른쪽 편마비 대상자가 지팡이를 이용하여 경사로를 내려갈 때 이동 순서는?', '["지팡이 → 오른쪽 다리 → 왼쪽 다리", "지팡이 → 왼쪽 다리 → 오른쪽 다리", "왼쪽 다리 → 지팡이 → 오른쪽 다리", "오른쪽 다리 → 지팡이 → 왼쪽 다리", "왼쪽 다리 → 오른쪽 다리 → 지팡이"]'::jsonb, 1, '편마비 환자가 지팡이를 사용하여 안전하게 경사로를 내려가는 방법을 이해하고 적용하는 능력을 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "지팡이로 몸을 지탱한 후 오른쪽 다리를 내리고, 마지막으로 왼쪽 다리를 내리는 순서입니다. 이는 안전하게 내려가는 방법입니다.\n[정답]", "2": "왼쪽 다리를 먼저 내리는 경우, 편마비 대상자가 더욱 불안해질 수 있습니다.", "3": "왼쪽 다리 다음에 지팡이를 내리는 것은 잘못된 순서입니다.", "4": "오른쪽 다리부터 내리는 것은 비슷한 위험을 초래할 수 있습니다.", "5": "이 순서는 편마비 대상을 제대로 고려하지 않으므로 부적절합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 팔과 다리가 마비된 상태", "def_vi": "Tình trạng tê liệt một bên tay và chân"}, {"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "보행 보조기구", "def_vi": "Thiết bị hỗ trợ đi lại"}, {"term_ko": "경사로", "term_vi": "Dốc", "def_ko": "기울어진 도로", "def_vi": "Đường nghiêng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (547, 'mock', '그림과 같이 반좌위를 하고 있는 대상자가 미끄러져 내려가지 않고 편안하도록 돕는 방법은?', '["발바닥에 베개를 대어 준다.", "머리 쪽 침대를 조금 더 올려 준다.", "목과 어깨 밑에 베개를 받쳐 준다.", "다리 쪽의 침대르 살짝 올려 준다.", "등 뒤에 베개를 A자 형태로 받쳐 준다."]'::jsonb, 4, '대상자가 반좌위를 유지하면서 미끄러지지 않도록 돕는 방법에 대한 이해를 확인하는 문제입니다.', NULL, '{"1": "발바닥에 베개를 대어 준다: 발바닥에 베개를 두는 것은 반좌위를 유지하는 데 도움이 되지 않습니다.\n[정답]", "2": "머리 쪽 침대를 조금 더 올려 준다: 머리 쪽을 올리면 몸이 안정되지만 미끄러짐 방지에는 효과적이지 않습니다.", "3": "목과 어깨 밑에 베개를 받쳐 준다: 이 방법은 반좌위를 유지하는 데 적합하지 않으며 불편할 수 있습니다.", "4": "다리 쪽의 침대를 살짝 올려 준다: 다리 쪽을 올리면 중심이 안정되어 미끄러지지 않도록 도와줍니다.", "5": "등 뒤에 베개를 A자 형태로 받쳐 준다: 이 방법은 지원을 제공하지만 반좌위를 유지하는 데 한계가 있습니다."}'::jsonb, '[{"term_ko": "반좌위", "term_vi": "Tư thế nửa nằm", "def_ko": "반 누운 자세", "def_vi": "Tư thế nằm nghiêng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (544, 'mock', '다음 그림과 같이 휠체어에 앉아있는 대상자를 자동차에 태울 때 순서로 옳은 것은?', '["나 - 가 - 다 - 라", "나 - 가 - 라 - 다", "나 - 다 - 가 - 라", "나 - 다 - 라 - 가", "나 - 라 - 다 - 가"]'::jsonb, 5, '휠체어 사용자의 안전한 자동차 탑승 방법을 평가하기 위한 문제입니다.', NULL, '{"1": "나 - 가 - 다 - 라: 순서가 비효율적이며 안전하지 않습니다.\n[정답]", "5": "나 - 라 - 다 - 가: 휠체어 사용자가 안전하게 차량에 탑승하는 정답 순서입니다.", "2": "나 - 가 - 라 - 다: 올바른 순서가 아닙니다.", "3": "나 - 다 - 가 - 라: 비효율적인 순서입니다.", "4": "나 - 다 - 라 - 가: 안전하지 않은 순서입니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "자동차", "def_ko": "휠체어(휠체어)", "def_vi": "자동차(ô tô)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (543, 'mock', '그림과 같은 방법으로 휠체어를 이동해야 하는 상황은?', '["오르막길을 올라갈 때", "내리막길을 내려갈 때", "울퉁불퉁한 길을 갈 때", "엘리베이터를 타고 내릴 때", "평지를 이동할 때"]'::jsonb, 3, '휠체어 이동 시의 주의사항과 방법에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "오르막길을 올라갈 때는 휠체어를 뒤에서 밀어주어야 하므로 주의가 필요합니다.\n[정답]", "2": "내리막길에는 속도를 충분히 조절해야 하므로 주의가 필요합니다.", "3": "울퉁불퉁한 길을 갈 때는 휠체어에 진동이 가해지므로 더욱 주의가 요구됩니다.", "4": "엘리베이터를 타고 내릴 때는 안전한 이동이 필요합니다.", "5": "평지를 이동할 때는 비교적 안전하나 기본적인 주의가 필요합니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "휠체어(한국어)", "def_vi": "Xe lăn (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (541, 'mock', '다음 그림에 해당하는 세탁방법은?', '["30℃ 물에 중성세제 사용, 약하게 손세탁 가능", "30℃ 물에 중성세제 사용, 세탁기 사용 불가", "30℃ 물에 세제 종류 제한 없음", "중성세제 사용, 삶을 수 있음", "물세탁 안 됨"]'::jsonb, 1, '(세탁 방법과 관련된 그림을 이해하고, 그에 맞는 세탁 방법을 선택하도록 하는 문제입니다)', NULL, '{"1": "30℃ 물에 중성세제를 사용하여 약하게 손세탁이 가능한 방법입니다. [정답]", "2": "30℃ 물에 중성세제를 사용하나 세탁기 사용이 불가능하다는 의미로, 그림에 적합하지 않습니다.", "3": "30℃ 물에는 세제 종류의 제한이 없지만, 그림의 세탁 방법을 고려할 때 이 방법은 적합하지 않습니다.", "4": "중성세제를 사용하고 삶을 수 있는 방법은 일반적으로 부드러운 세탁 조건을 요구하는 그림의 내용과 맞지 않습니다.", "5": "물세탁이 불가능한 경우는 그림과 일치하지 않습니다."}'::jsonb, '[{"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "세탁(한국어)", "def_vi": "Giặt(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (540, 'mock', '다음 그림과 같이 방바닥에 누워있는 대상자를 일으켜 앉힌 후, 휠체어로 옮기는 순서로 옳은 것은?', '["가 - 나 - 라 - 다", "가 - 라 - 나 - 다", "나 - 가 - 다 - 라", "다 - 라 - 나 - 가", "라 - 다 - 가 - 나"]'::jsonb, 5, '대상자를 안전하게 휠체어로 옮기기 위한 올바른 방법과 순서를 익히기 위한 문제입니다.', NULL, '{"1": "가 - 나 - 라 - 다: 이 순서는 대상자를 안전하게 세울 수 없습니다.\n[정답]", "5": "라 - 다 - 가 - 나: 올바른 순서로 대상자를 세우고 휠체어로 옮기는 방법입니다.", "3": "나 - 가 - 다 - 라: 위험한 방법으로, 대상자를 안전하게 옮길 수 없습니다.", "4": "다 - 라 - 나 - 가: 비효율적인 방법으로 안전하지 않습니다.", "2": "가 - 라 - 나 - 다: 짜임새가 없는 순서입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "방바닥", "term_vi": "Sàn nhà", "def_ko": "바닥이 있는 곳(한국어)", "def_vi": "Nơi có sàn"}, {"term_ko": "퀼체어", "term_vi": "Xe lăn", "def_ko": "휠체어(한국어)", "def_vi": "Xe lăn"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "다치지 않음(한국어)", "def_vi": "Không bị thương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (539, 'mock', '그림과 같이 대상자가 누워서 엉덩이를 들어 올리는 운동을 하는 이유는?', '["침대 위에서 이동이나 보행 시 신체안정에 도움이 된다.", "장시간 와상상태 시 욕창을 예방한다.", "어지러움, 오심, 구토 등의 증상을 완화시킨다.", "폐기능을 강화하여 호흡에 도움을 준다.", "관절의 굳어짐을 예방한다."]'::jsonb, 1, '대상자가 엉덩이를 들어 올리는 운동의 목적을 이해하고 올바른 이유를 선택하기 위함입니다.', NULL, '{"1": "침대 위에서 이동이나 보행 시 신체안정에 도움이 된다.\n[정답]", "2": "장시간 와상상태 시 욕창을 예방한다.", "3": "어지러움, 오심, 구토 등의 증상을 완화시킨다.", "4": "폐기능을 강화하여 호흡에 도움을 준다.", "5": "관절의 굳어짐을 예방한다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "사람(한국어)", "def_vi": "Người được chăm sóc"}, {"term_ko": "운동", "term_vi": "Bài tập", "def_ko": "신체활동(한국어)", "def_vi": "Hoạt động thể chất"}, {"term_ko": "엉덩이", "term_vi": "Mông", "def_ko": "엉덩이 부위(한국어)", "def_vi": "Vùng mông"}, {"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부손상(한국어)", "def_vi": "Tổn thương da"}, {"term_ko": "폐기능", "term_vi": "Chức năng phổi", "def_ko": "호흡 기능(한국어)", "def_vi": "Chức năng hô hấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (537, 'mock', '그림과 같이 대상자가 오른쪽으로 쏠려있을 때 침대 중앙으로 이동시키는 방법으로 옳은 것은?', '["어깨와 둔부를 밀어서 이동시킨다.", "팔과 다리를 잡고 당겨 이동시킨다.", "상반신과 하반신을 나누어서 이동시킨다.", "몸통 밑을 받쳐 한 번에 이동시킨다.", "머리와 허리를 잡고 당겨 이동시킨다."]'::jsonb, 3, '대상자를 침대 중앙으로 안전하게 이동시키는 방법에 대한 이해를 평가하고자 함.', NULL, '{"1": "어깨와 둔부를 밀어서 이동시키는 것은 안전하지 않고, 근골격계에 부담을 줄 수 있다.\n[정답]", "3": "상반신과 하반신을 나누어서 이동시키는 방법은 안전하고 효과적으로 이동할 수 있다.", "2": "팔과 다리를 잡고 당겨 이동시키면 약한 부위에 무리가 갈 수 있다.", "4": "몸통 밑을 받쳐 한 번에 이동시키는 것은 불안정할 수 있고, 잘못하면 부상 위험이 있다.", "5": "머리와 허리를 잡고 당겨 이동시키는 것은 잘못된 움직임으로 인해 부상 위험이 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Bệnh nhân", "def_ko": "환자", "def_vi": "Người được chăm sóc"}, {"term_ko": "이동", "term_vi": "Di chuyển", "def_ko": "이동하다", "def_vi": "Chuyển động"}, {"term_ko": "어깨", "term_vi": "Vai", "def_ko": "어깨", "def_vi": "Vai"}, {"term_ko": "둔부", "term_vi": "Hông", "def_ko": "엉덩이", "def_vi": "Hông"}, {"term_ko": "상반신", "term_vi": "Thân trên", "def_ko": "상체", "def_vi": "Phần thân trên"}, {"term_ko": "하반신", "term_vi": "Thân dưới", "def_ko": "하체", "def_vi": "Phần thân dưới"}, {"term_ko": "몸통", "term_vi": "Thân", "def_ko": "몸", "def_vi": "Thân"}, {"term_ko": "허리", "term_vi": "Lưng", "def_ko": "허리", "def_vi": "Lưng"}, {"term_ko": "부상", "term_vi": "Chấn thương", "def_ko": "부상", "def_vi": "Chấn thương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (530, 'mock', '보행보조차(실버카)의 안전한 사용을 위해 반드시 점검해야 하는 부분은?', '["(가)", "(나)", "(다)", "(라)", "(마)"]'::jsonb, 3, '보행보조차의 안전성을 점검하는 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "(가)", "2": "(나)\n[정답]", "3": "보행보조차의 바퀴가 정상적으로 작동하는지 확인해야 합니다.", "4": "(라)", "5": "(마)"}'::jsonb, '[{"term_ko": "보행보조차", "term_vi": "Xe đi bộ hỗ trợ", "def_ko": "보행을 도와주는 기구", "def_vi": "Thiết bị hỗ trợ đi bộ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (529, 'mock', '그림과 같은 표시 방법에 따라 건조해야 하는 세탁물은?', '["꽃무늬 블라우스", "하얀색 면 티셔츠", "이불 커버", "노란색 울 스웨터", "빨간색 니트"]'::jsonb, 1, '세탁물의 소재와 건조 방법에 따른 올바른 선택을 유도하는 문제입니다.', NULL, '{"1": "꽃무늬 블라우스는 일반적으로 통풍이 잘 되는 그늘에서 건조해야 합니다.\n[정답]", "2": "하얀색 면 티셔츠는 직사광선을 피하고 건조할 수 있습니다.", "3": "이불 커버는 널고 건조하는 것이 적합합니다.", "4": "노란색 울 스웨터는 세탁 후 평평하게 눕혀서 건조해야 합니다.", "5": "빨간색 니트는 서늘한 그늘에서 짠 후 조심스럽게 건조해야 합니다."}'::jsonb, '[{"term_ko": "세탁물", "term_vi": "Đồ giặt", "def_ko": "세탁하기 위한 물품", "def_vi": "Các vật phẩm cần giặt"}, {"term_ko": "건조", "term_vi": "Sấy khô", "def_ko": "물이나 습기를 제거하여 마르는 것", "def_vi": "Việc loại bỏ nước hoặc độ ẩm để vật phẩm khô"}, {"term_ko": "블라우스", "term_vi": "Blouse", "def_ko": "여성용 상의", "def_vi": "Áo nữ"}, {"term_ko": "티셔츠", "term_vi": "Áo phông", "def_ko": "일반적인 상의 형태", "def_vi": "Kiểu áo thông dụng"}, {"term_ko": "이불", "term_vi": "Chăn", "def_ko": "수면용 커버", "def_vi": "Vỏ chăn dùng để ngủ"}, {"term_ko": "울", "term_vi": "Len", "def_ko": "양모로 만들어진 섬유", "def_vi": "Sợi làm bằng lông cừu"}, {"term_ko": "스웨터", "term_vi": "Áo len", "def_ko": "따뜻하게 입는 니트 의류", "def_vi": "Trang phục dệt kim để giữ ấm"}, {"term_ko": "니트", "term_vi": "Vải dệt kim", "def_ko": "뜨개질로 만들어진 의류", "def_vi": "Vải được làm bằng cách đan"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (526, 'mock', '그림과 같이 대상자가 침대 아래쪽에 누워있을 때 침대 위쪽으로 이동시키는 방법으로 옳은 것은?', '["다리 쪽의 침대를 올려준다.", "침대 시트를 잡아서 끌어 올린다.", "양쪽 팔을 잡고 당겨 올린다.", "대상자가 협조를 할 수 있는 경우 침대 머리쪽 난간을 잡게 한다.", "대상자가 협조를 할 수 없는 경우 두 사람이 나란히 서서 올린다."]'::jsonb, 4, '대상자를 효과적으로 침대 위쪽으로 이동시키기 위한 안전한 방법을 이해하기 위한 문제입니다.', NULL, '{"1": "다리 쪽의 침대를 올려주는 것은 그리 안전한 방법이 아닙니다.\n[정답]", "4": "대상자가 협조를 할 수 있는 경우 침대 머리쪽 난간을 잡게 하는 것이 안전하고 효과적입니다.", "2": "침대 시트를 잡아서 끌어 올리는 것은 대상자에게 불편함을 줄 수 있습니다.", "3": "양쪽 팔을 잡고 당겨 올리는 것은 대상자의 안전에 위협이 될 수 있습니다.", "5": "대상자가 협조를 할 수 없는 경우 두 사람이 나란히 서서 올려주는 것은 더욱 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Bệnh nhân", "def_ko": "환자, 병자", "def_vi": "Người bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (521, '15', '주어진 사례를 읽고 치매에 걸린 아내를 돌보는 주보호자인 남편에 대한 요양보호사의 반응으로 옳은 것은?"아내는 갈수록 상태가 더 나빠지는 것 같아요. 내가 잘 돌보지 못해서 나날이 나빠지는 것만 같아 힘이 들어요. 나도 잘하고 싶은데 이게 잘하는 건지 못하는 건지 몰라 매번 답답해요. 이러다 아내가 어디로 없어지거나 더 상태가 나빠질까 봐 걱정이네요."', '["\"다른 가족분은 안 계시나요? 혼자서 돌보시기 힘드시겠어요.\"", "\"제가 바빠서요, 말씀은 나중에 다시 듣겠습니다.\"", "\"다른 집들도 다 똑같은 것 같아요. 너무 힘들어하지 마세요.\"", "\"더 잘 돌봐드리고 싶은데, 아내분이 더 나빠질까 봐 걱정이 되시나 봐요.\"", "\"더 도와드릴 부분이 있는지 시설장님께 말씀드려볼게요.\""]'::jsonb, 4, '주보호자인 남편의 심리적 부담과 걱정에 대한 올바른 반응을 찾는 것입니다.', NULL, '{"1": "다른 가족이 없다는 것을 언급하며 공감을 나타내는 것이 맞지만, 남편의 감정을 깊게 이해하지 못함.\n[정답]", "4": "남편의 걱정을 공감하고 그에 따른 감정의 상태를 잘 보여주는 적절한 반응입니다.", "2": "상대방의 말을 듣지 않겠다고 말하는 것은 매우 부적절합니다.", "3": "다른 집과 비교하는 것은 남편의 감정을 무시하는 것이나 마찬가지입니다.", "5": "도움을 주겠다는 의도는 좋지만, 남편의 감정을 먼저 이해해야 합니다."}'::jsonb, '[{"term_ko": "주보호자", "term_vi": "Người chăm sóc chính", "def_ko": "환자를 곁에서 가장 많이 도와주는 사람", "def_vi": "Người giúp đỡ bệnh nhân nhiều nhất ở bên cạnh"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억 상실증", "def_vi": "Rối loạn trí nhớ"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "대응", "def_vi": "Đối phó"}, {"term_ko": "심리적", "term_vi": "Tâm lý", "def_ko": "정신적인", "def_vi": "Tâm lý"}, {"term_ko": "부담", "term_vi": "Gánh nặng", "def_ko": "짐", "def_vi": "Gánh nặng"}, {"term_ko": "걱정", "term_vi": "Lo lắng", "def_ko": "염려", "def_vi": "Lo lắng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (520, '15', '주어진 사례를 읽고 치매 시아버지를 돌보는 며느리에 대한 요양보호사의 반응으로 옳은 것은?"시아버지를 돌보지 않겠다는 것은 아니지만 고맙다는 말 한마디도 안 하고 집에 올 때마다 방으로 들어가 버리는 남편이나 자기는 하나도 챙기지 않는다며 투정하는 딸 때문에 스트레스가 이만저만이 아니에요. 난 모든 것을 열심히 하려고 하는데, 주위에서는 내가 집에서 노는 줄 알아요."', '["\"남편들이 다 그렇지요, 많이 속상하시겠어요.\"", "\"아...그러시군요. 네네...\"하며 하던 일을 계속한다.", "\"제가 남편분께 한번 말씀드려볼까요.\"", "\"남편분이 따뜻한 말 한마디 해주시면 좋겠는데 그렇지 않아서 서운하시군요.\"", "\"따님이 아직 어려서 엄마가 힘든 걸 모르네요. 속상하시겠어요.\""]'::jsonb, 4, '요양보호사가 치매환자 가족의 스트레스와 감정을 이해하고 지지하는 방법을 평가하는 것이다.', NULL, '{"1": "남편에 대한 일반적인 편견을 표현한 것으로, 적절한 반응이 아니다.\n[정답]", "4": "남편의 행동에 대한 이해를 보이며, 감정을 공감하는 적절한 반응이다.", "2": "환자가 이야기하는 중에도 대화에 관심을 두지 않은 반응이다.", "3": "상황 해결을 위한 조력을 제안하지만, 우선적으로 감정을 이해해주지 않아서 부적절하다.", "5": "딸의 문제를 언급하며, 주어진 상황의 본질을 간과한 반응이다."}'::jsonb, '[{"term_ko": "주어진", "term_vi": "Được đưa ra", "def_ko": "주어진 상태에 있는, 주어짐", "def_vi": "Ở trạng thái đã đưa ra, được cung cấp"}, {"term_ko": "시아버지", "term_vi": "Bố chồng", "def_ko": "남편의 아버지", "def_vi": "Bố của chồng"}, {"term_ko": "투정", "term_vi": "Lếu láo", "def_ko": "불만을 말하고 소란을 피우는 것", "def_vi": "Nói những điều không đúng và gây rối"}, {"term_ko": "스트레스", "term_vi": "Căng thẳng", "def_ko": "심리적 압박 상태", "def_vi": "Trạng thái áp lực tâm lý"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "어떤 상황에 대한 응답", "def_vi": "Phản ứng với một tình huống nào đó"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (519, '15', '주어진 내용을 읽고 치매 대상자에 대한 요양보호사의 돕기 방법으로 옳은 것은?• 치매 어르신에게 인사를 해도 멍하니 반응이 없다. • 이야기를 해도 대꾸가 없다. • 그냥 가만히 의자에 앉아만 있다. • 텔레비전 시청도, 산책도 아무런 소용이 없다.', '["갑자기 뒤에서 안으며 이름을 부른다.", "대답을 하지 않으면 큰소리로 물어본다.", "과거에 좋아했던 활동을 하도록 유도한다.", "반응이 없으면 화를 내어 관심을 갖도록 한다.", "방으로 들어가 편히 쉬게 한다."]'::jsonb, 3, '치매 대상자에게 적절한 요양보호사의 대처 방법을 이해하고 평가하기 위한 문제입니다.', NULL, '{"1": "갑자기 뒤에서 안으며 이름을 부른다. 치매 환자는 갑작스러운 접근에 놀라거나 불안해할 수 있으므로 적절하지 않습니다.\n[정답]", "3": "과거에 좋아했던 활동을 하도록 유도한다. 이는 치매 환자의 기억과 정서에 긍정적인 영향을 줄 수 있는 방법입니다.", "2": "대답을 하지 않으면 큰소리로 물어본다. 이는 불안감을 유발하고 환자의 스트레스를 증가시킬 수 있습니다.", "4": "반응이 없으면 화를 내어 관심을 갖도록 한다. 이는 환자에게 상처를 줄 수 있고, 도움이 되지 않습니다.", "5": "방으로 들어가 편히 쉬게 한다. 이는 환자가 원할 때 선택적으로 제공될 수 있으나, 적극적인 상호작용이 필요할 때에는 적절하지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력 및 인지 기능이 감소하는 질환", "def_vi": "Một bệnh làm giảm trí nhớ và khả năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (518, '15', '주어진 사례를 읽고 요양보호사의 돕기 방법으로 옳은 것은?보호자는 치매 대상자를 욕실로 데려가 옷을 갈아입히거나 샤워기로 물을 뿌릴 때마다 설명 없이 끌고 가거나 옷을 벗기려 한다. 이럴 때마다 노인은 화를 내며 손을 뿌리치고 보호자를 밀치며 목욕을 거부하고 있다.', '["인지기능이 저하된 치매 대상자는 충분한 설명을 이해하기 어렵다.", "협조가 어려울 때는 강압적인 행동으로 목욕을 마무리한다.", "목욕을 하는 이유와 과정을 설명하고 목욕 후 좋아하는 일을 하자며 유도한다.", "목욕물의 온도, 옷 갈아입을 준비하기는 스스로 하도록 격려한다.", "목욕을 자주 할 수 없으므로 가능한 오랜 시간 동안 목욕한다."]'::jsonb, 3, '요양보호사가 치매 대상자와 효과적으로 의사소통하고 협조를 이끌어내기 위해 필요한 접근 방식을 이해하고 적용하는지를 평가하고자 함.', NULL, '{"1": "인지기능이 저하된 치매 대상자는 충분한 설명을 이해하기 어렵다. 이는 사실일 수 있지만, 이것만으로 목욕을 강요할 수는 없다.\n[정답]", "3": "목욕을 하는 이유와 과정을 설명하고 목욕 후 좋아하는 일을 하자며 유도한다. 이런 접근이 노인의 협조를 이끌어내는 데 효과적이다.", "2": "협조가 어려울 때는 강압적인 행동으로 목욕을 마무리한다. 이는 노인을 더 불안하게 만들고 상황을 악화시킬 수 있다.", "4": "목욕물의 온도, 옷 갈아입을 준비하기는 스스로 하도록 격려한다. 이는 긍정적인 방법이지만, 노인이 이미 불안해하고 있는 상황에서는 적절치 않다.", "5": "목욕을 자주 할 수 없으므로 가능한 오랜 시간 동안 목욕한다. 이는 오히려 노인의 스트레스를 증가시킬 수 있다."}'::jsonb, '[{"term_ko": "주요 관점", "term_vi": "Chính yếu tố", "def_ko": "요양보호사가 장애인을 돕기 위한 접근 방법", "def_vi": "Cách tiếp cận mà nhân viên chăm sóc cần thiết để hỗ trợ người khuyết tật"}, {"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "노인이 정보를 처리하고 이해하는 능력", "def_vi": "Khả năng tiếp nhận và hiểu thông tin của người già"}, {"term_ko": "협조", "term_vi": "Hợp tác", "def_ko": "노인이 목욕을 기꺼이 함께 하도록 하는 것", "def_vi": "Khi người cao tuổi sẵn sàng tham gia vào việc tắm"}, {"term_ko": "강압적", "term_vi": "Ép buộc", "def_ko": "강제로 푸는 태도", "def_vi": "Thái độ cưỡng chế"}, {"term_ko": "불안", "term_vi": "Lo âu", "def_ko": "노인이 느끼는 스트레스", "def_vi": "Căng thẳng mà người cao tuổi cảm thấy"}, {"term_ko": "스트레스", "term_vi": "Căng thẳng", "def_ko": "노인의 심리적 부담", "def_vi": "Gánh nặng tâm lý của người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (517, '15', '주어진 사례를 읽고 요양보호사가 치매 대상자의 일상생활 돕기 방법으로 옳은 것은?• 치매 대상자인 80세 여성은 식사를 할 때 한 가지 반찬만 주로 먹으며 수저를 사용하지 않고 손으로 음식을 집어 먹으려 한다. 요양보호사가 수저로 먹으라고 하면 알았다고 한 후 몇 번 서툴게 수저로 먹지만 금방 다시 손으로 음식을 집는다. • 식사 후 물을 컵에 따라주면 손으로 잡아 입에 대긴 하지만 제대로 마시지 못하고 대부분 흘린다. 요양보호사의 도움을 받아 물을 다 마시고 나면 컵을 테이블에 놓지 못하고 바닥에 떨어뜨린다.', '["숟가락을 사용하여 음식을 떠서 입안에 넣어준다.", "수저를 손에 쥐어 \"수저로 드셔야지요\" 하며 부드럽게 말한다.", "젓가락으로 음식을 집어 입안에 넣어준다.", "스스로 컵을 사용한 후 탁자 위에 놓을 수 있도록 격려한다.", "물을 많이 흘리므로 컵 사용을 제한한다."]'::jsonb, 2, '요양보호사가 치매 대상자를 어떻게 지원해야 하는지를 이해하도록 하는 문제입니다.', NULL, '{"1": "숟가락을 사용하게 하는 것은 전문가의 지원 없이 갑자기 수저만 사용하도록 강요하는 것으로, 치매 대상자에게 적합하지 않습니다.\n[정답]", "2": "수저를 손에 쥐어 주며 부드럽게 말하는 것은 대상자의 자존감을 지키면서 식사 습관을 개선할 수 있도록 돕는 좋은 방법입니다.", "3": "젓가락은 사용이 어려울 수 있어 치매 대상자에게 적합하지 않습니다.", "4": "스스로 컵을 사용하도록 격려하는 것은 좋으나, 현재로서는 그 대상자가 컵을 놓지 못하는 상황이므로 아직은 적합하지 않습니다.", "5": "물을 많이 흘리는 것은 사실이지만 컵 사용을 제한하면 자립성을 더욱 감소시킬 수 있습니다."}'::jsonb, '[{"term_ko": "주요", "term_vi": "대상자", "def_ko": "주요한 (quan trọng)", "def_vi": "환자 (bệnh nhân)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (516, '14', '심폐소생술을 할 때 자동심장 충격기를 사용하는 순서로 옳은 것은?', '["패드부착 → 심장충격 시행 → 전원 켜기 → 심장리듬분석 → 가슴압박", "패드부착 → 심장리듬분석 → 심장충격 시행 → 전원 켜기 → 가슴압박", "전원켜기 → 패드부착 → 심장리듬분석 → 심장충격 시행 → 가슴압박", "전원켜기 → 패드부착 → 심장충격 시행 → 심장리듬분석 → 가슴압박", "심장충격 시행 → 전원 켜기 → 패드부착 → 심장리듬분석 → 가슴압박"]'::jsonb, 3, '심폐소생술 과정에서 자동심장 충격기를 사용하는 올바른 순서를 묻는 문제이다.', NULL, '{"1": "올바른 순서가 아니다. 전원이 꺼져 있는 자동심장 충격기를 먼저 켜야 한다.\n[정답]", "3": "전원켜기 → 패드부착 → 심장리듬분석 → 심장충격 시행 → 가슴압박이 올바른 순서이다.", "2": "전원을 켜기 전에 심장리듬을 분석하는 것은 잘못된 순서이다.", "4": "심장리듬 분석 전에 충격을 시행해서는 안 된다.", "5": "먼저 심장충격을 시행하는 것은 잘못된 순서이다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "생명을 위급한 환자에게 제공하는 응급처치", "def_vi": "Chăm sóc khẩn cấp cung cấp cho bệnh nhân nguy cấp"}, {"term_ko": "자동심장충격기", "term_vi": "Máy khử rung tim tự động", "def_ko": "심장 리듬 이상 시 전기 충격을 주는 장비", "def_vi": "Thiết bị cung cấp sốc điện khi có bất thường nhịp tim"}, {"term_ko": "패드부착", "term_vi": "Gắn miếng dán", "def_ko": "전극 패드를 환자 몸에 붙이는 행동", "def_vi": "Hành động gắn miếng dán điện cực lên cơ thể bệnh nhân"}, {"term_ko": "가슴압박", "term_vi": "Áp lực lồng ngực", "def_ko": "심장 기능을 외부에서 압박하여 수행하는 행동", "def_vi": "Hành động nén tim từ bên ngoài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (514, '14', '자동심장 충격기 사용법으로 옳은 것은?', '["의료인만 사용한다.", "패드 1은 왼쪽 젖꼭지 아래 중간 겨드랑이선, 패드 2는 오른쪽 빗장뼈아래 부착한다.", "심장리듬 분석중이라는 음성이 나오면 가슴 압박을 시행한다.", "심장충격 버튼을 누르기 전 모두 물러나게 하고 버튼을 누른다.", "자동심장 충격기는 2초 간격으로 심장리듬을 분석한다."]'::jsonb, 4, '자동심장 충격기(AED)의 올바른 사용법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "자동심장 충격기는 의료인 외에도 일반인도 사용할 수 있습니다. \n[정답]", "2": "패드는 지정된 위치에 부착해야 하지만 설명이 다소 잘못되어 있습니다.", "3": "심장리듬 분석 중에는 가슴 압박을 하지 않아야 합니다.", "4": "모든 사람들이 물러난 후 버튼을 눌러야 하며, 정답입니다.", "5": "자동심장 충격기는 2분마다 심장리듬을 분석하는 것으로 일반적입니다."}'::jsonb, '[{"term_ko": "자동심장 충격기", "term_vi": "Máy sốc tim tự động", "def_ko": "자동 외부 제세동기 (AED)", "def_vi": "Máy tán nội bộ tự động"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (511, '14', '의식을 잃고 쓰러져 있는 대상자에게 심폐소생술을 시행하는 방법으로 옳은 것은?', '["분당 60회 속도로 가슴압박을 한다.", "쓰러진 대상자의 호흡을 1분 이내로 관찰한다.", "양팔을 쭉 편 상태로 체중을 실어 가슴을 압박한다.", "대상자의 가슴이 약 2cm 눌릴 수 있게 살짝 압박한다.", "반응확인 → 가슴압박 → 도움요청 → 호흡확인 순으로 실시한다."]'::jsonb, 3, '심폐소생술에 대한 올바른 시행 방법을 묻는 문제입니다.', NULL, '{"1": "분당 60회 속도로 가슴압박을 한다는 것은 너무 느린 속도로, 올바른 가슴 압박 속도는 분당 100-120회입니다.\n[정답]", "3": "양팔을 쭉 편 상태로 체중을 실어 가슴을 압박하는 것이 올바른 방법입니다.", "2": "쓰러진 대상자의 호흡을 1분 이내로 관찰하는 것은 부적절하며, 심폐소생술을 즉시 시작해야 합니다.", "4": "대상자의 가슴이 약 2cm 눌릴 수 있게 살짝 압박하는 것은 충분한 압박이 아닙니다.", "5": "반응확인 → 가슴압박 → 도움요청 → 호흡확인 순서 또한 잘못된 순서입니다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장 및 호흡이 멈춘 사람에게 응급처치를 하는 방법", "def_vi": "Phương pháp cấp cứu đối với người ngừng tim và ngừng thở"}, {"term_ko": "가슴압박", "term_vi": "Bơm ngực", "def_ko": "심장을 압박하여 혈액을 순환시키는 동작", "def_vi": "Hành động ấn để làm tuần hoàn máu"}, {"term_ko": "체중", "term_vi": "Trọng lượng cơ thể", "def_ko": "자신의 몸의 무게", "def_vi": "Cân nặng của cơ thể"}, {"term_ko": "호흡", "term_vi": "Hơi thở", "def_ko": "공기를 들이마시고 내쉬는 과정", "def_vi": "Quá trình hít vào và thở ra"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "치료를 받는 사람", "def_vi": "Người đang được điều trị"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (510, '14', '심폐소생술 시 가슴압박 시행 방법으로 옳은 것은?', '["분당 100~120회 속도로 압박한다.", "가슴이 3cm 눌릴 수 있게 한다.", "매번 압박의 위치를 바꾼다.", "양팔을 굽은 상태로 한다.", "흉골 아래 명치부분을 압박한다."]'::jsonb, 1, '심폐소생술에 대한 기본적인 이해와 압박 방법에 대한 지식을 평가하고자 함.', NULL, '{"1": "분당 100~120회 속도로 압박하는 것이 심폐소생술의 기본 원칙이다.\n[정답]", "2": "가슴이 3cm 눌릴 수 있게 하는 것은 좋지 않다. 왜냐하면, 충분한 압박 깊이가 요구된다.", "3": "매번 압박의 위치를 바꾸는 것은 오히려 효율성을 떨어뜨린다.", "4": "양팔이 굽은 상태일 경우 압박의 힘이 감소하므로 바른 방법이 아니다.", "5": "흉골 아래 명치부분을 압박하는 것은 잘못된 방법이다."}'::jsonb, '[{"term_ko": "심폐소생술", "term_vi": "Hồi sinh tim phổi", "def_ko": "심장을 다시 시작하게 하는 응급 절차", "def_vi": "Quy trình cấp cứu để khởi động lại tim."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (509, '14', '심정지 대상자에게 심폐소생술을 시행하는 순서로 옳은 것은?', '["반응확인 → 가슴압박 → 도움요청 → 호흡확인 → 회복자세", "반응확인 → 도움요청 → 호흡확인 → 가슴압박 → 회복자세", "반응확인 → 도움요청 → 회복자세 → 호흡확인 → 가슴압박", "반응확인 → 회복자세 → 도움요청 → 가슴압박 → 호흡확인", "반응확인 → 회복자세 → 호흡확인 → 도움요청 → 가슴압박"]'::jsonb, 2, '심정지 환자에게 심폐소생술(CPR)을 올바른 순서로 시행하는 방법을 평가하기 위함입니다.', NULL, '{"1": "반응확인 후 가슴압박은 잘못된 순서입니다.\n[정답]", "2": "반응확인 후 도움 요청, 호흡 확인 후 가슴압박이 올바른 순서입니다.", "3": "회복자세는 심정지 환자에게 시행하지 않고 가슴압박이 먼저입니다.", "4": "회복자세는 심정지 시 필요하지 않으며, 올바른 순서가 아닙니다.", "5": "호흡확인이 제대로 이루어진 후 가슴압박을 시행해야 합니다."}'::jsonb, '[{"term_ko": "심정지", "term_vi": "Ngừng tim", "def_ko": "심장이 뛰지 않는 상태", "def_vi": "Trạng thái tim không đập"}, {"term_ko": "심폐소생술", "term_vi": "Hồi sinh tim phổi", "def_ko": "심장과 호흡을 재개하기 위한 응급처치", "def_vi": "Biện pháp khẩn cấp để phục hồi tim và hô hấp"}, {"term_ko": "가슴압박", "term_vi": "Bơm ngực", "def_ko": "심장을 압박하여 혈액을 순환시키는 행위", "def_vi": "Hành động ấn vào ngực để lưu thông máu"}, {"term_ko": "회복자세", "term_vi": "Tư thế hồi phục", "def_ko": "환자를 안정적으로 지탱하도록 돕는 자세", "def_vi": "Tư thế hỗ trợ ổn định cho bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (508, '14', '심정지 대상자에게 심폐소생술을 하는 일차적인 목적으로 옳은 것은?', '["쇼크 예방", "뇌 손상 최소화", "면역 기능 향상", "신장 기능 향상", "근골격 손상 회복"]'::jsonb, 2, '심정지 대상자에 대한 심폐소생술의 주된 목적을 이해하고 평가하는 것.', NULL, '{"1": "쇼크 예방: 심정지 상황에서는 쇼크 예방이 중요하지만, 심폐소생술의 주된 목적은 아님.\n[정답]", "2": "뇌 손상 최소화: 심폐소생술의 일차적인 목적은 뇌 손상을 최소화하는 것이다. 심정지 상태에서 뇌는 산소 공급이 중단되어 심각한 손상을 받을 수 있으므로, 이 목적이 가장 중요하다.", "3": "면역 기능 향상: 심폐소생술과는 관련이 없으며, 심정지와 면역 기능 향상은 직접적인 관련이 없다.", "4": "신장 기능 향상: 신장 기능 향상과 관련이 없으며, 심정지 상황에서는 생명을 구하는 것이 우선이다.", "5": "근골격 손상 회복: 근골격 손상 회복은 심정지와는 관련이 없으며, 심폐소생술의 목표와는 거리가 있다."}'::jsonb, '[{"term_ko": "심정지", "term_vi": "Ngừng tim", "def_ko": "생명이 멈추는 상태", "def_vi": "Tình trạng ngừng sự sống"}, {"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장이 멈춘 환자를 살리기 위한 응급처치", "def_vi": "Thủ tục cứu sống bệnh nhân khi tim ngừng đập"}, {"term_ko": "뇌", "term_vi": "Não", "def_ko": "인체의 중요한 기관", "def_vi": "Cơ quan quan trọng của cơ thể"}, {"term_ko": "손상", "term_vi": "Tổn thương", "def_ko": "상처나 피해", "def_vi": "Vết thương hoặc thiệt hại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (507, '14', '대상자가 넘어져 발목에 통증이 있고 골절이 의심될 때 응급처치 방법으로 옳은 것은?', '["발목을 압박한다.", "다리에 온찜질을 한다.", "압박붕대를 꽉 조이게 감아준다.", "발목을 절대로 움직이지 않게 한다.", "부축하여 병원에 진료를 보러 간다."]'::jsonb, 4, '대상자가 발목 부상으로 골절이 의심될 때 적절한 응급처치 방법을 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "발목을 압박한다: 이러한 방법은 부상의 악화를 초래할 수 있으므로 부적절합니다.\n[정답]", "4": "발목을 절대로 움직이지 않게 한다: 골절이 의심될 때는 움직임을 최소화하여 추가적인 손상을 방지해야 합니다.", "2": "다리에 온찜질을 한다: 온찜질은 부록에 영향을 줄 수 있어 부적절한 응급처치입니다.", "3": "압박붕대를 꽉 조이게 감아준다: 너무 세게 감으면 혈액 순환 문제를 일으킬 수 있습니다.", "5": "부축하여 병원에 진료를 보러 간다: 증상이 악화될 수 있으므로 부상 부위를 보호한 채로 이동하는 것이 더 중요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bị thương", "def_ko": "피해자", "def_vi": "Người bị thương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (506, '14', '대상자가 산책 중 넘어져 움직이기 어려울 정도로 심한 손목 통증을 호소할 때 응급처치 방법으로 옳은 것은?', '["손목을 움직여보게 한다.", "온찜질을 한다.", "붕대를 압박하여 감아준다.", "손목부위를 마사지한다.", "팔찌를 미리 벗겨낸다."]'::jsonb, 5, '응급처치 방법에 대한 이해와 올바른 대처 방안을 평가하기 위함입니다.', NULL, '{"1": "손목을 움직이면 통증이 더 심해질 수 있으므로 올바른 응급처치가 아닙니다.\n[정답]", "5": "팔찌와 같은 액세서리는 swelling (부종) 시 혈류를 압박할 수 있으므로 미리 벗겨주는 것이 중요합니다.", "3": "붕대를 압박하여 감는 것은 잘못된 방법이며, 손목이 부풀어 오를 수 있습니다.", "2": "온찜질은 부상 직후에 적용해선 안 되는 방법입니다.", "4": "손목부위를 마사지하는 것은 부상을 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "응급 시에 하는 치료", "def_vi": "Điều trị khi có tình huống khẩn cấp"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔", "def_vi": "Nỗi đau"}, {"term_ko": "부종", "term_vi": "Sưng", "def_ko": "몸의 일부분이 부풀어 오름", "def_vi": "Phần nào đó trên cơ thể bị sưng lên"}, {"term_ko": "마사지", "term_vi": "Massage", "def_ko": "근육을 풀기 위한 동작", "def_vi": "Hành động để thư giãn cơ bắp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (505, '14', '정수기를 사용하던 대상자가 뜨거운 물에 손을 데었을 때 대처방법으로 옳은 것은?', '["손가락의 반지를 빼준다.", "얼음물에 15분 이상 담근다.", "화상부위에 치약을 발라준다.", "화상이 어느 정도인지 모를 때는 멸균드레싱을 한다.", "경미한 화상의 후기고령자는 집에서 치료한다."]'::jsonb, 1, '화상에 대한 적절한 응급처치 방법을 묻고 있다.', NULL, '{"1": "손가락의 반지를 빼주는 것은 부종을 방지하기 위함이다.\n[정답]", "2": "얼음물에 15분 이상 담그는 것은 과도한 냉각으로 인한 손상 위험이 있다.", "3": "치약을 바르는 것은 화상에 도움이 되지 않으며 오히려 감염을 유발할 수 있다.", "4": "화상의 정도를 파악하기 전 멸균드레싱을 하는 것은 전문적인 판단이 필요하다.", "5": "후기고령자의 경우, 반드시 병원 치료가 필요하다."}'::jsonb, '[{"term_ko": "정수기", "term_vi": "손", "def_ko": "정수기(한국어) / máy lọc nước: nghĩa tiếng Việt", "def_vi": "손(한국어) / tay: nghĩa tiếng Việt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (504, '14', '대상자가 식사 도중 뜨거운 국을 소등에 쏟았을 때 응급처치 방법으로 옳은 것은?', '["흐르는 수돗물에 환부를 직접 씻는다.", "15분 이상 찬물에 담근다.", "팔찌, 귀고리는 그대로 둔다.", "핸드크림을 발라 열기를 내보낸다.", "2도 화상에는 얼음으로 문지른다."]'::jsonb, 2, '응급처치에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "흐르는 수돗물에 환부를 직접 씻는 것은 위험할 수 있으므로 옳지 않습니다.\n[정답]", "2": "15분 이상 찬물에 담그는 것이 2도 화상에 대한 적절한 응급처치입니다.", "3": "팔찌, 귀고리는 빼는 것이 좋습니다.", "4": "핸드크림을 발라서는 안 됩니다.", "5": "2도 화상에는 얼음을 직접 문지르면 위험합니다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "긴급 상황에서 즉시 취하는 조치를 의미합니다.", "def_vi": "Các biện pháp khẩn cấp được thực hiện ngay lập tức trong tình huống khẩn cấp."}, {"term_ko": "화상", "term_vi": "Bỏng", "def_ko": "열에 의해 피부가 손상되는 것을 의미합니다.", "def_vi": "Là sự tổn thương da do nhiệt."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (503, '14', '치매 대상자가 알 수 없는 약물을 먹고 의식이 없을 때 응급대처 방법으로 옳은 것은?', '["즉시 가족에게 사실을 알린다.", "우유를 먹여 구토하게 한다.", "천장을 바라보는 자세로 눕히고 고개를 옆으로 돌린다.", "복용한 것으로 의심되는 용기는 시설장에게 전달한다.", "의식이 돌아올 때까지 어깨를 두드린다."]'::jsonb, 3, '치매 대상자가 알 수 없는 약물을 복용하여 의식이 없을 때, 적절한 응급 대처 방법을 알고 있는지를 묻는 문제입니다.', NULL, '{"1": "즉시 가족에게 사실을 알리는 것은 중요하지만 응급처치의 적절한 순서가 아닙니다.\n[정답]", "3": "천장을 바라보는 자세로 눕히고 고개를 옆으로 돌리는 것은 기도를 확보하고 질식을 방지하기 위한 올바른 응급처치입니다.", "2": "우유를 먹여 구토하게 하는 것은 위험할 수 있으므로 피해야 합니다.", "4": "복용한 것으로 의심되는 용기를 시설장에게 전달하는 것은 중요한 절차이나, 응급처치와는 직접적인 연관이 없습니다.", "5": "의식이 돌아올 때까지 어깨를 두드리는 것은 효과적이지 않으며, 오히려 추가적인 위험을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억이나 인지 능력이 저하되는 질환", "def_vi": "Bệnh lý giảm khả năng ghi nhớ hoặc nhận thức"}, {"term_ko": "알 수 없는", "term_vi": "Không rõ", "def_ko": "신원이나 상태가 명확하지 않은", "def_vi": "Không xác định được danh tính hoặc tình trạng"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "자아나 환경을 인식하는 상태", "def_vi": "Trạng thái nhận thức về bản thân hoặc môi trường"}, {"term_ko": "응급처치", "term_vi": "Xử lý khẩn cấp", "def_ko": "즉각적인 치료 또는 도움을 제공하는 것", "def_vi": "Cung cấp sự điều trị hoặc giúp đỡ ngay lập tức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (502, '14', '대상자가 약물 중독으로 쓰러졌을 때 대처방법으로 옳은 것은?', '["겉으로 드러난 증상이 없다면 지켜본다.", "복용하고 남은 약을 119대원에게 전달한다.", "손가락을 넣어 구토를 유발한다.", "의식이 없더라도 물을 조금씩 먹인다.", "입에서 거품이 나오면 깨끗이 닦아준다."]'::jsonb, 2, '대상자가 약물 중독 상태에서 적절하게 대처하는 방법을 묻는 문제입니다.', NULL, '{"1": "겉으로 드러난 증상이 없다면 지켜보는 것은 위험할 수 있습니다. 상황에 따라 즉시 조치를 취해야 합니다.\n[정답]", "2": "복용하고 남은 약을 119대원에게 전달하는 것은 중요한 정보 제공으로, 향후 치료에 도움이 됩니다.", "3": "손가락을 넣어 구토를 유발하는 행위는 상황에 따라 위험할 수 있으므로 지양해야 합니다.", "4": "의식이 없더라도 물을 먹이는 것은 호흡기로 물이 들어갈 위험이 있으므로 안전하지 않습니다.", "5": "입에서 거품이 나더라도 수동적으로 닦아주는 것은 불필요하며, 적절한 응급조치가 필요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (501, '14', '프로그램에 참여하던 대상자가 쓰러져 경련을 할 때 응급처치 방법으로 옳은 것은?', '["손가락으로 입을 벌려 약을 먹인다.", "안전을 위해 조용한 방으로 옮긴다.", "대상자의 머리 아래에 딱딱한 것을 대어준다.", "경련이 멈출 때까지 양쪽 어꺠를 꽉 잡아준다.", "고개를 가만히 옆으로 돌려준다."]'::jsonb, 5, '경련을 하는 환자에게 올바른 응급처치 방법을 묻는 문제이다.', NULL, '{"1": "손가락으로 입을 벌려 약을 먹인다: 이는 매우 위험한 방법으로, 환자가 기도 폐쇄가 발생할 수 있다.\n[정답]", "2": "안전을 위해 조용한 방으로 옮긴다: 조용한 환경을 제공하는 것은 좋지만, 근처에서 안전하게 경련이 멈추길 기다려야 한다.", "3": "대상자의 머리 아래에 딱딱한 것을 대어준다: 부상의 위험이 있으므로 적절하지 않다.", "4": "경련이 멈출 때까지 양쪽 어깨를 꽉 잡아준다: 이는 환자에게 추가적인 부상을 초래할 수 있다.", "5": "고개를 가만히 옆으로 돌려준다: 이는 환자의 기도가 확보되고 안전하게 경련이 멈추도록 도와줄 수 있는 방법이다."}'::jsonb, '[{"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "emergency treatment", "def_vi": "điều trị khẩn cấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (500, '14', '대상자가 날카로운 물체에 찔려 팔에 출혈이 있을 때 응급처치 방법으로 옳은 것은?', '["맨손으로 지혈하고 수돗물에 닦는다.", "멸균거즈를 이용하여 상처를 압박한다.", "대상자를 절대 안정시키고 움직이지 않게 한다.", "상처부위에 냉찜질을 한다.", "압박붕대를 이용하여 꽉 조이게 한다."]'::jsonb, 5, '대상자가 날카로운 물체에 찔려 출혈이 발생했을 때, 적절한 응급처치를 묻고 있습니다.', NULL, '{"1": "맨손으로 지혈하고 수돗물에 닦는 것은 비위생적이며 상처에 감염의 위험이 있습니다.\n[정답]", "2": "멸균거즈를 이용하여 상처를 압박하면 출혈을 효과적으로 지혈할 수 있습니다.", "3": "대상자를 안정시키고 움직이지 않게 하는 것이 중요하지만 응급처치 방법이 아닙니다.", "4": "냉찜질은 부기에는 도움이 될 수 있으나 출혈을 멈추는 데는 직접적인 효과가 없습니다.", "5": "압박붕대를 이용하여 꽉 조이게 하는 것은 적절한 방법이지만, 멸균거즈를 우선 사용하는 것이 중요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (499, '14', '급성 저혈압 증상에 관한 설명으로 옳은 것은?', '["혈압이 과도하게 높아져 혈액순환이 이루어지지 못한다.", "피부색이 하얗거나 파랗다.", "손발이 따뜻하다.", "호흡수가 감소한다.", "맥박수가 감소한다."]'::jsonb, 2, '급성 저혈압에 대한 정확한 이해와 관련 증상을 확인하기 위함입니다.', NULL, '{"1": "급성 저혈압에선 혈압이 낮아 혈액순환이 원활하지 않다.\n[정답]", "2": "급성 저혈압 환자는 피부색이 창백하거나 청색증을 보인다.", "3": "손발은 차갑고, 따뜻하지 않다.", "4": "호흡수가 일반적으로 증가한다.", "5": "맥박수는 보통 증가한다."}'::jsonb, '[{"term_ko": "급성 저혈압", "term_vi": "증상", "def_ko": "급성 hạ huyết áp", "def_vi": "triệu chứng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (497, '14', '인절미를 먹던 대상자가 목을 움켜잡고 괴로운 표정을 지을 때 응급처치 방법으로 옳은 것은?', '["대상자의 뒷목을 주먹으로 두드린다.", "물을 먹여 이물질이 내려가도록 한다.", "손가락을 입에 넣어 구토를 유발한다.", "음식물이 보이면 젓가락으로 꺼낸다.", "대상자를 등 뒤에서 안아 상복부를 후상방향으로 힘차게 밀어 올린다."]'::jsonb, 5, '목에 이물질이 걸렸을 때의 올바른 응급처치 방법을 이해하고 적용하는 능력을 평가하기 위함입니다.', NULL, '{"1": "대상자의 뒷목을 주먹으로 두드리는 것은 비효율적이며 위험할 수 있습니다. \n[정답]", "5": "대상자를 등 뒤에서 안아 상복부를 후상방향으로 힘차게 밀어 올리면 기도를 확보하는 효과가 있습니다.", "2": "물을 먹이는 것은 이물질을 더욱 밀어넣을 수 있어 위험합니다.", "3": "손가락을 입에 넣어 구토를 유발하는 방법은 위험하며 바람직하지 않습니다.", "4": "음식물이 보일 때 젓가락으로 꺼내는 것은 추가적인 상해를 발생시킬 수 있습니다."}'::jsonb, '[{"term_ko": "목", "term_vi": "Cổ", "def_ko": "목(한국어)", "def_vi": "Cổ họng (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (496, '14', '올바른 손씻기 방법으로 옳은 것은?', '["요양보호사는 정해진 시간에 손을 씻는다.", "흐르는 물로만 손을 씻는다.", "근무 중 반지나 팔찌를 착용하지 않는다.", "손톱은 길고 뾰족하게 다듬는다.", "대상자의 집을 떠난 후 씻는다."]'::jsonb, 3, '올바른 손씻기 방법에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "요양보호사는 정해진 시간에 손을 씻는 것은 중요하지만, 손씻기는 상황에 따라 필요할 때 해야 합니다.\n[정답]", "3": "근무 중 반지나 팔찌를 착용하지 않는 것이 올바른 손씻기 방법이며 감염 예방을 위한 중요한 수칙입니다.", "2": "흐르는 물로만 손을 씻는 것은 권장되지 않으며, 비누와 함께 씻는 것이 중요합니다.", "4": "손톱을 길고 뾰족하게 다듬는 것은 오히려 세균이 쌓이기 쉬우므로 권장되지 않습니다.", "5": "대상자의 집을 떠난 후 손을 씻는 것은 올바른 방법이지만, 그 전에 손을 씻는 것이 더 중요합니다."}'::jsonb, '[{"term_ko": "손씻기", "term_vi": "Rửa tay", "def_ko": "손을 깨끗하게 하는 방법", "def_vi": "Phương pháp làm sạch tay"}, {"term_ko": "근무", "term_vi": "Làm việc", "def_ko": "일하거나 활동하는 것", "def_vi": "Làm hoặc hoạt động"}, {"term_ko": "반지", "term_vi": "Nhẫn", "def_ko": "손가락에 끼는 장식구", "def_vi": "Đồ trang sức đeo trên ngón tay"}, {"term_ko": "팔찌", "term_vi": "Vòng tay", "def_ko": "손목에 착용하는 장식구", "def_vi": "Đồ trang sức đeo trên cổ tay"}, {"term_ko": "세균", "term_vi": "Vi khuẩn", "def_ko": "병원균", "def_vi": "Mầm bệnh"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "질병을 유발하는 과정", "def_vi": "Quá trình gây bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (495, '14', '대상자를 도울 때 감염이 전파될 수 있는 상황으로 옳은 것은?', '["장갑을 착용하고 분비물을 처리하였다.", "배설물이 묻은 의류를 분리하여 세탁하였다.", "분비물에 오염된 일회용 장갑을 깨끗이 씻어 재사용하였다.", "일회용 방수가운을 입고 대상자의 분비물을 처리하였다.", "혈액이 묻은 물품을 찬물로 씻어낸 후 더운 물로 헹구었다."]'::jsonb, 3, '대상자의 감염 예방과 관련된 상황에서 올바른 행동을 묻는 문제이다.', NULL, '{"1": "장갑을 착용하고 분비물을 처리하는 것은 감염 전파를 예방하는 행동으로 바른 방법이다.", "2": "배설물이 묻은 의류를 분리하여 세탁하는 것은 감염 전파를 예방하는 올바른 방법이다.\n[정답]", "3": "분비물에 오염된 일회용 장갑을 깨끗이 씻어 재사용하는 것은 감염 전파 위험이 높아지므로 잘못된 행동이다.", "4": "일회용 방수가운을 입고 대상자의 분비물을 처리하는 것은 감염을 예방하는 방법이다.", "5": "혈액이 묻은 물품을 찬물로 씻어낸 후 더운 물로 헹구는 것은 감염 전파에 도움이 되지 않으므로 잘못된 방법이다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm", "def_ko": "전염병이 퍼지는 것", "def_vi": "sự lây truyền của bệnh truyền nhiễm"}, {"term_ko": "장갑", "term_vi": "Găng tay", "def_ko": "보호를 위해 착용하는 장비", "def_vi": "thiết bị bảo vệ được đeo"}, {"term_ko": "분비물", "term_vi": "Dịch tiết", "def_ko": "신체에서 나오는 액체", "def_vi": "chất lỏng tiết ra từ cơ thể"}, {"term_ko": "일회용", "term_vi": "Dùng một lần", "def_ko": "한 번 사용하고 버리는 것", "def_vi": "dùng một lần và vứt đi"}, {"term_ko": "방수가운", "term_vi": "Áo chống thấm", "def_ko": "물을 막는 장비", "def_vi": "thiết bị ngăn nước"}, {"term_ko": "혈액", "term_vi": "Máu", "def_ko": "신체의 액체", "def_vi": "chất lỏng trong cơ thể"}, {"term_ko": "배설물", "term_vi": "Phân", "def_ko": "몸에서 나오는 노폐물", "def_vi": "chất thải từ cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (494, '14', '전기 콘센트에 감전되어 쓰러진 대상자를 돕기 위한 우선순위로 옳은 것은?', '["119에 신고한다.", "호흡과 맥박을 확인한다.", "누전기 이상 여부를 확인한다.", "119가 올 때까지 지켜본다.", "전류가 차단될 때까지 접촉하지 않는다."]'::jsonb, 5, '대상자가 전기 콘센트에 감전된 상황에서 우선적으로 해야 할 행동을 평가하고 이해하기 위함이다.', NULL, '{"1": "119에 신고하는 것은 중요하나, 우선순위가 아니다.\n[정답]", "5": "전류가 차단될 때까지 접촉하지 않는 것이 가장 우선적으로 해야 할 행동이다.", "2": "호흡과 맥박을 확인하는 것은 감전 후 상태를 확인하기 위해 필요하지만, 안전이 확보된 후 해야 한다.", "3": "누전기 이상 여부를 확인하는 것은 나중에 할 일이며, 우선적으로 전류를 차단해야 한다.", "4": "119가 올 때까지 지켜보는 것은 도움이 된다 하더라도 우선적인 조치는 아니다."}'::jsonb, '[{"term_ko": "전기", "term_vi": "Điện", "def_ko": "전기의 힘(한국어)", "def_vi": "Sức mạnh của điện"}, {"term_ko": "콘센트", "term_vi": "Ổ điện", "def_ko": "전기 기구가 연결되는 소켓(한국어)", "def_vi": "Ổ cắm cho thiết bị điện"}, {"term_ko": "감전", "term_vi": "Điện giật", "def_ko": "전기로 인해 생기는 부상(한국어)", "def_vi": "Chấn thương do điện"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (493, '14', '태풍 예보를 듣고 대비하는 방법으로 옳은 것은?', '["주유되어 있는 자동차의 연료를 비운다.", "오염에 대비해 욕조에 물을 미리 받아둔다.", "지하 주차장에 주차한다.", "전기 차단기를 내린다.", "통신 기기는 꺼 놓는다."]'::jsonb, 2, '태풍 예보에 대비하여 어떤 방법이 옳은지 판단하는 것이다.', NULL, '{"1": "주유된 차량의 연료를 비우는 것은 태풍에 대비하는 방법으로 옳지 않다.\n[정답]", "2": "오염에 대비해 욕조에 물을 미리 받아두는 것은 재난 발생 시 유용하게 사용될 수 있다.", "3": "지하 주차장에 주차하는 것은 안전을 보장하지 않으므로 바람직하지 않다.", "4": "전기 차단기를 내리는 것은 오히려 불필요한 조치가 될 수 있다.", "5": "통신 기기를 꺼 놓는 것은 연락이 불가능해질 수 있어 위험할 수 있다."}'::jsonb, '[{"term_ko": "태풍", "term_vi": "Bão", "def_ko": "폭풍 nhiệt대 지역에서 발생하는 강한 바람과 비가 동반된 기상현상", "def_vi": "Hiện tượng khí tượng mạnh với gió và mưa xảy ra ở vùng nhiệt đới"}, {"term_ko": "대비", "term_vi": "Chuẩn bị", "def_ko": "미리 준비함", "def_vi": "Sẵn sàng trước"}, {"term_ko": "욕조", "term_vi": "Bồn tắm", "def_ko": "욕실에서 사용하는 큰 통", "def_vi": "Bể tắm lớn dùng trong phòng tắm"}, {"term_ko": "오염", "term_vi": "Ô nhiễm", "def_ko": "더럽혀짐, 영향을 받음", "def_vi": "Bị bẩn, bị ảnh hưởng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (492, '14', '지진 발생 시 대처방법으로 옳은 것은?', '["신속히 엘리베이터로 이동한다.", "건물 바로 밑에서 주위를 살핀다.", "운동장이나 공원 등은 피한다.", "탁자 아래로 들어가 몸을 보호한다.", "전기와 가스를 차단하고 출구를 차단한다."]'::jsonb, 4, '지진 발생 시 안전한 대처 방법을 알고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "신속히 엘리베이터로 이동하는 것은 위험합니다. 지진 시 엘리베이터 사용은 피해야 합니다.\n[정답]", "4": "탁자 아래로 들어가 몸을 보호하는 것이 올바른 대처 방법입니다. 이는 낙하물로부터 몸을 보호할 수 있습니다.", "2": "건물 바로 밑에서 주위를 살핀다는 것은 안전하지 않으며, 보호를 받지 못할 가능성이 높습니다.", "3": "운동장이나 공원은 개방된 공간이지만, 움직이지 말고 안전한 장소에서 대기하는 것이 좋습니다.", "5": "전기와 가스를 차단하는 것은 중요하지만, 출구를 차단하는 것은 문제가 많습니다."}'::jsonb, '[{"term_ko": "지진", "term_vi": "신속히", "def_ko": "지진(động đất)", "def_vi": "빠르게(nhanh chóng)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (491, '14', '홍수로 인해 수해가 발생했을 때 대처방법은?', '["양초에 불을 붙여 실내를 밝게 한다.", "물이 집 안으로 밀려들어오는 경우 모래주머니로 막는다.", "밀려온 물이 집 안에서 빠진 직후 전기차단기를 올린다.", "홍수로 밀려온 물에 몸이 젖은 경우 수건으로 닦는다.", "집 안의 물이 빠지고 나면 라이터를 사용하여 불을 켠다."]'::jsonb, 2, '재난 상황에서의 올바른 대처 방법을 이해하고 평가하기 위함입니다.', NULL, '{"1": "양초에 불을 붙이는 것은 화재를 유발할 수 있으므로 위험합니다.\n[정답]", "2": "물이 집 안으로 밀려들어오는 경우 모래주머니로 막는 것이 올바른 대처 방법입니다.", "3": "밀려온 물이 집 안에서 빠진 직후 전기차단기를 올리는 것은 전기 사고를 유발할 수 있어 위험합니다.", "4": "홍수로 밀려온 물에 몸이 젖은 경우 수건으로 닦는 것은 상황 대처와는 관련이 없습니다.", "5": "집 안의 물이 빠지고 나면 라이터를 사용하여 불을 켠다는 것은 매우 위험한 행동입니다."}'::jsonb, '[{"term_ko": "홍수", "term_vi": "대처", "def_ko": "침수(홍 lũ)", "def_vi": "대응(ứng phó)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (490, '14', '시설에서 화재가 발생했을 때 대처방법으로 옳은 것은?', '["승강기를 이용하여 대피한다.", "최대한 허리를 세워 움직인다.", "실내에 불이 나면 전화를 걸어 알린다.", "아래층으로 이동할 수 없다면 옥상으로 이동한다.", "방향을 알기 힘들 때에는 양쪽 손으로 벽을 번갈아 짚으며 나간다."]'::jsonb, 4, '화재 발생 시 대처 방법에 대한 이해를 확인하기 위함입니다.', NULL, '{"1": "승강기는 화재 시 사용할 수 없으므로 잘못된 답변입니다.\n[정답]", "4": "상황에 따라 옥상으로 이동하는 것이 안전할 수 있습니다.", "2": "허리를 세우는 것보다 더 낮은 자세로 이동하는 것이 안전합니다.", "3": "실내에 불이 난 경우 즉시 대피하는 것이 중요하며 전화를 걸 시간이 없습니다.", "5": "벽을 짚고 나가는 것은 좋은 방법이지만, 이 경우 방향을 알기 힘들다고 하여 지체할 필요는 없습니다."}'::jsonb, '[{"term_ko": "화재", "term_vi": "Hỏa hoạn", "def_ko": "불이 나는 현상", "def_vi": "Hiện tượng lửa bùng lên"}, {"term_ko": "승강기", "term_vi": "Thang máy", "def_ko": "건물 내부에서 이동할 때 사용하는 기계", "def_vi": "Thiết bị sử dụng để di chuyển trong tòa nhà"}, {"term_ko": "대피", "term_vi": "Tản ra", "def_ko": "안전한 장소로 이동하는 것", "def_vi": "Di chuyển đến nơi an toàn"}, {"term_ko": "옥상", "term_vi": "Mái nhà", "def_ko": "건물의 가장 높은 부분", "def_vi": "Phần cao nhất của tòa nhà"}, {"term_ko": "전화", "term_vi": "Điện thoại", "def_ko": "소통에서 사용하는 장비", "def_vi": "Thiết bị liên lạc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (489, '14', '실내에서 화재가 발생했을 때 소화기를 사용하는 순서로 옳은 것은?(그림) #311', '["가 → 나 → 다 → 라", "가 → 다 → 나 → 라", "나 → 가 → 라 → 다", "나 → 다 → 가 → 라", "라 → 나 → 가 → 다"]'::jsonb, 5, '실내 화재 발생 시 소화기 사용 방법에 대한 이해도를 평가하고자 함.', NULL, '{"1": "먼저 점검 후 처치하는 순서로 맞지 않음.\n[정답]", "5": "화재에 대처하는 올바른 순서가 포함되어 있음.", "3": "적절한 대응 방법이 아님.", "4": "순서가 잘못되어 효과적인 소화가 불가능함.", "2": "올바른 소화 순서가 아님."}'::jsonb, '[{"term_ko": "실내", "term_vi": "화재", "def_ko": "실내(한국어) / Trong nhà(베트남어)", "def_vi": "화재(한국어) / Hỏa hoạn(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (488, '14', '가스레인지 불을 끄는 것을 자주 잃어버리는 대상자를 위한 돕기 방법으로 옳은 것은?', '["휴대용 가스레인지를 사용한다.", "배달음식 메뉴로 식단표를 작성한다.", "휴대전화기를 보면서 조리한다.", "음식을 조리하는 중에 주방을 떠나지 않는다.", "미리 얼려둔 음식을 전자레인지에 해동한다."]'::jsonb, 4, '대상자가 가스레인지 불을 끄는 것을 잊어버리는 경우, 어떻게 도와줄 수 있는지를 묻는 문제입니다.', NULL, '{"1": "휴대용 가스레인지를 사용한다. - 이 방법은 불을 잊어버리는 것과 관련이 없어 적절하지 않습니다.\n[정답]", "4": "음식을 조리하는 중에 주방을 떠나지 않는다. - 주방에 계속 머무는 것이 불을 끄는 것을 잊지 않도록 도와줍니다.", "3": "휴대전화기를 보면서 조리한다. - 음식을 조리하는 것에 집중하지 못하게 하며, 위험할 수 있습니다.", "2": "배달음식 메뉴로 식단표를 작성한다. - 조리와 관련이 없으므로 오답입니다.", "5": "미리 얼려둔 음식을 전자레인지에 해동한다. - 이 방법은 전혀 관련이 없습니다."}'::jsonb, '[{"term_ko": "가스레인지", "term_vi": "Bếp gas", "def_ko": "가스를 연료로 사용하는 조리 기구", "def_vi": "Thiết bị nấu ăn sử dụng khí gas"}, {"term_ko": "불", "term_vi": "Lửa", "def_ko": "타오르는 상태", "def_vi": "Tình trạng đang cháy"}, {"term_ko": "배달음식", "term_vi": "Thức ăn giao hàng", "def_ko": "음식을 집으로 배달해 주는 서비스", "def_vi": "Dịch vụ giao thức ăn đến nhà"}, {"term_ko": "조리", "term_vi": "Nấu ăn", "def_ko": "음식을 준비하고 요리하는 것", "def_vi": "Chuẩn bị và nấu thức ăn"}, {"term_ko": "주방", "term_vi": "Nhà bếp", "def_ko": "음식을 조리하고 준비하는 공간", "def_vi": "Không gian để nấu và chuẩn bị thức ăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (487, '14', '의학적 위기상황에 대한 대처 방법으로 옳은 것은?', '["가장 먼저 기관장에게 보고한다.", "대상자의 의식이 돌아올 때까지 기다린다.", "대상자의 호흡불안정, 심한 통증이 있다면 119에 신고한다.", "뚜렷한 위기징후가 없더라도 반드시 119에 신고한다.", "상황이 종료되면 요양보호사의 주관적 느낌도 기록한다."]'::jsonb, 3, '의학적 위기상황에 대한 요양보호사의 대처 방법을 이해하고 판단하는 능력을 평가하기 위함입니다.', NULL, '{"1": "기관장에게 보고하는 것은 중요하지만, 응급 상황에서는 환자의 상태를 먼저 파악해야 합니다.\n[정답]", "3": "호흡 불안정이나 심한 통증을 느끼는 경우에는 즉시 119에 신고해야 합니다.", "2": "의식이 돌아올 때까지 기다리는 것은 필요한 응급조치를 지연시킬 수 있습니다.", "4": "뚜렷한 위기징후가 없더라도 신고하는 것은 오히려 자원의 낭비로 이어질 수 있습니다.", "5": "요양보호사의 주관적 느낌을 기록하는 것은 중요하지만, 우선적인 조치는 아닙니다."}'::jsonb, '[{"term_ko": "의학적", "term_vi": "Y học", "def_ko": "의학의 관련된", "def_vi": "liên quan đến y học"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (486, '13', '사전연명의료의향서에 관한 설명으로 옳은 것은?', '["본인 의사에 상관없이 대리작성이 가능하다.", "사전연명의료의향서 등록기관에 등록해야만 효력이 있다.", "연명의료 중단은 의사의 도움에 의한 적극적 안락사와 같다.", "효력이 발생하여 연명의료가 중단되어도 심폐소생술은 실시된다.", "의료행위와 영양분, 산소의 단순 공급은 보류하거나 중단할 수 있다."]'::jsonb, 2, '사전연명의료의향서의 개념과 법적 효력에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "본인 의사에 반하여 대리작성을 할 수 없습니다.\n[정답]", "2": "사전연명의료의향서는 등록기관에 등록해야 효력이 발생합니다.", "3": "연명의료 중단은 의사의 도움으로 이루어진 안락사와는 다릅니다.", "4": "효력이 발생하여 연명의료가 중단된 경우에도 심폐소생술은 실시되지 않습니다.", "5": "의료행위 및 영양분, 산소의 공급은 상황에 따라 중단할 수 있습니다."}'::jsonb, '[{"term_ko": "사전연명의료의향서", "term_vi": "Văn bản ý kiến về y tế trước khi tử vong", "def_ko": "죽기 전에 의사 결정을 미리 기록한 문서", "def_vi": "Tài liệu ghi lại quyết định y tế trước khi chết"}, {"term_ko": "대리작성", "term_vi": "Viết thay", "def_ko": "다른 사람을 대신하여 작성하다", "def_vi": "Viết thay cho người khác"}, {"term_ko": "효력", "term_vi": "Hiệu lực", "def_ko": "법적으로 효력이 있다", "def_vi": "Có hiệu lực pháp lý"}, {"term_ko": "연명의료", "term_vi": "Điều trị y tế kéo dài sự sống", "def_ko": "생명을 연장하기 위한 의료행위", "def_vi": "Hành vi y tế để gia tăng sự sống"}, {"term_ko": "심폐소생술", "term_vi": "Hồi sức tim phổi", "def_ko": "심장과 호흡을 재개시키기 위한 의료행위", "def_vi": "Hành động y tế để hồi phục tim và hô hấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (485, '13', '사전연명의료의향서를 등록한 대상자가 임종을 앞두고 있을 때 제공 받을 수 있는 것은?', '["산소 공급", "혈액 투석", "항암제 투여", "기관지확장제 투여", "심폐소생술"]'::jsonb, 1, '사전연명의료의향서 등록 후의 환자 관리에 대한 이해 여부를 묻는 문제입니다.', NULL, '{"1": "산소 공급은 임종 환자에게 제공할 수 있는 기본적인 치료입니다.\n[정답]", "2": "혈액 투석은 임종 환자에게 권장되지 않습니다.", "3": "항암제 투여는 통상적인 경우엔 적합하지 않으며 비특정 치료입니다.", "4": "기관지확장제 투여는 필요한 경우일 수 있으나, 임종 시기에는 우선순위가 낮습니다.", "5": "심폐소생술은 사전연명의료의향서 등록 시 대부분의 환자가 원하지 않는 치료입니다."}'::jsonb, '[{"term_ko": "사전연명의료의향서", "term_vi": "Di chúc y tế trước", "def_ko": "환자의 의사를 사전에 문서화한 것", "def_vi": "Tài liệu ghi lại ý chí của bệnh nhân trước đó"}, {"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "생의 마지막 단계", "def_vi": "Giai đoạn cuối cùng của cuộc sống"}, {"term_ko": "치료", "term_vi": "Điều trị", "def_ko": "환자의 치료 방법", "def_vi": "Phương pháp điều trị cho bệnh nhân"}, {"term_ko": "공급", "term_vi": "Cung cấp", "def_ko": "드리는 것, 제공하는 것", "def_vi": "Cung cấp, đưa cho"}, {"term_ko": "산소", "term_vi": "Oxy", "def_ko": "생명에 필요한 기체", "def_vi": "Khí cần thiết cho sự sống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (484, '13', '말기환자 또는 19세 이상의 성인이 치료효과 없이 임종과정의 기간만을 연장하는 의학적 시술에 대한 본인의 의사에 대해 명시하는 서류로 옳은 것은?', '["호스피스", "호스피스 이용동의서", "사전연명의료의향서", "임종 관리서", "통증완화 동의서"]'::jsonb, 3, '말기환자의 의사결정에 관련된 법적 서류에 대한 명확한 이해를 촉구하기 위함입니다.', NULL, '{"1": "호스피스는 환자가 말기 상태에서 삶의 질을 향상시키기 위한 돌봄 서비스입니다.\n[정답]", "3": "사전연명의료의향서는 환자가 치료효과 없이 임종과정의 기간만을 연장하지 않겠다는 본인의 의사를 명시하는 서류입니다.", "2": "호스피스 이용동의서는 호스피스 서비스를 이용하기 위한 동의를 기록한 문서입니다.", "4": "임종 관리서는 임종기간 동안의 관리에 대한 내용을 담고 있습니다.", "5": "통증완화 동의서는 통증 완화를 위한 치료에 관한 내용입니다."}'::jsonb, '[{"term_ko": "말기환자", "term_vi": "Bệnh nhân giai đoạn cuối", "def_ko": "말기 상태의 환자", "def_vi": "Bệnh nhân ở giai đoạn điều trị cuối"}, {"term_ko": "의사", "term_vi": "Ý chí", "def_ko": "본인의 의사", "def_vi": "Ý kiến của bản thân"}, {"term_ko": "서류", "term_vi": "Tài liệu", "def_ko": "법적 문서", "def_vi": "Tài liệu pháp lý"}, {"term_ko": "사전연명의료의향서", "term_vi": "Tuyên bố mong muốn điều trị trước khi mất", "def_ko": "사전의료의향에 대한 문서", "def_vi": "Tài liệu về ý chí điều trị trước khi mất"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (483, '13', '임종 대상자의 가족을 돕는 방법으로 옳은 것은?', '["요양보호사만 대상자와 있을 수 있게 한다.", "대상자가 의사소통이 있을 때 사진촬영 등을 금한다.", "분노 반응을 보이는 가족에게는 적대적으로 대한다.", "가족이 스스로 감정을 표현하도록 지지한다.", "1개월 이상의 애도반응은 자연스러운 일임을 알려준다."]'::jsonb, 4, '임종 대상자의 가족을 지원하고 그들의 감정을 이해하는 방법을 파악하기 위한 문제입니다.', NULL, '{"1": "요양보호사만 대상자와 있을 수 있게 하는 것은 가족의 정서적 지지를 받지 못하게 할 수 있습니다. \n[정답]", "4": "가족이 스스로 감정을 표현하도록 지지하는 것은 그들의 심리적 안정을 돕고 필수적입니다.", "2": "대상자가 의사소통이 있을 때 사진 촬영 등을 금하는 것은 비생산적이며, 상호작용의 기회를 줄이게 됩니다.", "3": "분노 반응을 보이는 가족에게 적대적으로 대하는 것은 감정을 상처 주고 더욱 부정적인 상황으로 이어질 수 있습니다.", "5": "1개월 이상의 애도반응은 사람마다 다를 수 있으므로, 그것이 자연스럽다고 단정짓는 것은 적절하지 않습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음을 맞이하는 단계", "def_vi": "Giai đoạn mà con người sắp đến lúc qua đời"}, {"term_ko": "가족", "term_vi": "Gia đình", "def_ko": "당사자의 친족", "def_vi": "Người thân của đối tượng"}, {"term_ko": "감정", "term_vi": "Cảm xúc", "def_ko": "심리적 반응", "def_vi": "Phản ứng tâm lý"}, {"term_ko": "지지", "term_vi": "Hỗ trợ", "def_ko": "도움이 되거나 힘을 주는 것", "def_vi": "Giúp đỡ hoặc mang lại sức mạnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (482, '13', '임종을 앞둔 대상자가 음식을 섭취하는 데 어려움이 있을 때 돕기 방법으로 옳은 것은?', '["억지로라도 먹을 수 있게 한다.", "오심, 구토가 있다면 소화제를 준다.", "대상자가 좋아하는 따뜻한 차를 준비하여 준다.", "구토가 심할 경우 주스 얼린 것 등을 입안에 넣어준다.", "위관영양으로 음식을 대체하도록 한다."]'::jsonb, 4, '임종을 앞둔 대상자에 대한 영양 관리의 중요성을 평가하기 위함이다.', NULL, '{"1": "억지로 먹게 하면 스트레스를 유발할 수 있다.\n[정답]", "2": "오심과 구토의 원인을 치료하는 것이 우선이다.", "3": "따뜻한 차는 도움이 될 수 있지만, 모든 환자에게 적합하지 않다.", "4": "구토가 심할 경우 주스를 얼린 후 입안에 넣어주면 구토 완화에 도움이 된다.", "5": "위관영양은 마지막 단계에서 고려해야 할 방법이다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "죽음에 가까운 상태", "def_vi": "Tình trạng gần chết"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "치료를 받는 사람", "def_vi": "Người nhận điều trị"}, {"term_ko": "오심", "term_vi": "Buồn nôn", "def_ko": "구역질의 느낌", "def_vi": "Cảm giác buồn nôn"}, {"term_ko": "구토", "term_vi": "Nôn", "def_ko": "음식을 토하는 행위", "def_vi": "Hành động nôn thức ăn"}, {"term_ko": "위관영양", "term_vi": "Dinh dưỡng qua ống", "def_ko": "위를 통해 영양분을 공급하는 방법", "def_vi": "Phương pháp cung cấp dinh dưỡng qua ống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (481, '13', '임종을 앞둔 대상자가 심리적으로 불안해 할 때 돕기 방법으로 옳은 것은?', '["만나고 싶어 하는 사람을 만나게 해준다.", "곧 회복할 수 있다며 격려하고 지지한다.", "조용히 혼자 있는 시간을 준다.", "요양보호사의 희망하는 종교의식을 알아본다.", "장례절차는 가족의 의견을 반영한다."]'::jsonb, 1, '임종을 앞둔 대상자의 심리적 안정을 도와주는 방법을 찾기 위함입니다.', NULL, '{"1": "만나고 싶어 하는 사람을 만나게 해준다. 당연히 그들의 심리적 안정에 도움이 됩니다.\n[정답]", "2": "곧 회복할 수 있다며 격려하고 지지한다. 현실적이지 않은 위로는 오히려 불안감을 증가시킬 수 있습니다.", "3": "조용히 혼자 있는 시간을 준다. 대상자의 상황에 따라 불안감이 증가할 수 있습니다.", "4": "요양보호사의 희망하는 종교의식을 알아본다. 이는 대상자의 심리적 안정과는 관련이 없습니다.", "5": "장례절차는 가족의 의견을 반영한다. 이는 지원의 내용이 아닙니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "삶의 마지막 단계", "def_vi": "Giai đoạn cuối cùng của cuộc sống"}, {"term_ko": "심리적", "term_vi": "Tâm lý", "def_ko": "마음의 상태와 감정", "def_vi": "Tình trạng tâm trí và cảm xúc"}, {"term_ko": "불안", "term_vi": "Lo âu", "def_ko": "마음의 괴로움", "def_vi": "Sự lo lắng"}, {"term_ko": "격려", "term_vi": "Khích lệ", "def_ko": "힘을 줌", "def_vi": "Tạo động lực"}, {"term_ko": "지지", "term_vi": "Hỗ trợ", "def_ko": "지원하다", "def_vi": "Giúp đỡ"}, {"term_ko": "종교", "term_vi": "Tôn giáo", "def_ko": "신념 체계", "def_vi": "Hệ thống niềm tin"}, {"term_ko": "장례", "term_vi": "Tang lễ", "def_ko": "사망한 사람을 위한 의식", "def_vi": "Nghi thức cho người đã mất"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (480, '13', '임종을 앞둔 대상자를 도울 때 마지막까지 남아 있는 감각을 고려하여 돕는 방법으로 옳은 것은?', '["손을 잡아 준다.", "조명을 밝게 켜둔다.", "가족사진을 보여준다.", "좋아하는 음악을 들려준다.", "즐겨 쓰던 아로마 향을 맡게 한다."]'::jsonb, 4, '임종을 앞둔 대상자의 마지막 감각을 고려하여 어떤 방법으로 도와야 하는지를 묻는 문제입니다.', NULL, '{"1": "손을 잡아 주는 것은 감정적인 지지를 제공하지만, 감각적 방법으로는 부족하다.\n[정답]", "4": "좋아하는 음악을 들려주는 것은 청각적 자극을 제공하여 안정감을 줄 수 있다.", "2": "조명을 밝게 켜두는 것은 오히려 불안감을 줄 수 있으므로 적절하지 않다.", "3": "가족사진을 보여주는 것은 시각적 자극이지만, 임종 시점에서는 기억이나 인식을 하기 어려운 경우가 많다.", "5": "즐겨 쓰던 아로마 향을 맡게 하는 것은 추가적인 감각적 자극을 제공할 수 있지만, 음악에 비해 효과성이 떨어질 수 있다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối", "def_ko": "끝, 죽음의 과정", "def_vi": "Kết thúc, quá trình chết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (479, '13', '임종이 임박한 대상자의 신체적 변화로 옳은 것은?', '["동공이 축소된다.", "소변량이 증가한다.", "잠자는 시간이 짧아진다.", "손과 발에서 열감이 느껴진다.", "무호흡과 깊고 빠른 호흡이 교대로 나타난다."]'::jsonb, 5, '임종이 임박한 대상자의 신체적 변화를 파악하기 위해서이다.', NULL, '{"1": "동공이 확장되는 것이 일반적이다.\n[정답]", "5": "무호흡과 깊고 빠른 호흡이 교대로 나타나는 현상은 임종에 가까운 생리적 변화로 관찰된다.", "2": "소변량은 감소하는 경향이 있다.", "3": "임종 직전에는 수면 상태가 길어질 수 있다.", "4": "손과 발은 차가워지는 것이 일반적이다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음에 가까워짐", "def_vi": "Gần đến cái chết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (478, '13', '임조에 대한 요양보호사의 상담기술 방법으로 옳은 것은?', '["임종 경험 유무에 상관없이 획일적인 상담을 지원한다.", "보호자의 임종에서 마주하는 감정표현을 자제시킨다.", "평소 신뢰하는 종교 지도자와 만남을 주선한다.", "죽음을 앞둔 모든 사람은 죽음에 대해 ''좋은 죽음''이라고 생각한다.", "대상자와 가족이 임종에 이르는 다음 단계에로의 진입에 강요한다."]'::jsonb, 3, '요양보호사가 임종 상황에서 어떤 상담 기술을 사용하는 것이 적절한지 확인하기 위한 문제입니다.', NULL, '{"1": "임종 경험 유무에 상관없이 획일적인 상담은 맞지 않습니다. 상담은 개인의 상황에 맞춰야 합니다.\n[정답]", "3": "평소 신뢰하는 종교 지도자와 만남을 주선하는 것은 적절한 상담 기술입니다.", "2": "보호자의 임종에서 마주하는 감정표현을 자제시키는 것은 비정상적인 접근입니다.", "4": "죽음을 앞둔 모든 사람이 ''좋은 죽음''이라고 생각하는 것은 일반화의 오류입니다.", "5": "대상자와 가족이 임종에 이르는 다음 단계에로의 진입을 강요하는 것은 부적절한 방법입니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Thời điểm hưu", "def_ko": "죽음을 맞이하는 시기", "def_vi": "Thời điểm đối diện với cái chết"}, {"term_ko": "상담", "term_vi": "Tư vấn", "def_ko": "조언 또는 도움을 주는 행위", "def_vi": "Hành động tư vấn hoặc trợ giúp"}, {"term_ko": "감정", "term_vi": "Cảm xúc", "def_ko": "감정이나 느낌", "def_vi": "Cảm giác và cảm xúc"}, {"term_ko": "종교", "term_vi": "Tôn giáo", "def_ko": "신앙이나 교리", "def_vi": "Tín ngưỡng hoặc giáo lý"}, {"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "서비스나 도움을 받는 사람", "def_vi": "Người nhận dịch vụ hoặc trợ giúp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (477, '13', '임종을 맞이하는 대상자의 임종 적응단계의 순서로 옳은 것은?가.분노 나.부정 다.우울 라.타협 마.수용', '["가 - 나 - 다 - 라 - 마", "나 - 가 - 다 - 라 - 마", "나 - 가 - 라 - 다 - 마", "다 - 가 - 나 - 라 - 마", "다 - 나 - 가 - 라 - 마"]'::jsonb, 3, '임종을 맞이하는 대상자가 겪는 임종 적응단계의 올바른 순서를 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "가 - 나 - 다 - 라 - 마: 이 순서는 임종 적응단계를 올바르게 반영하지 않습니다.\n[정답]", "2": "나 - 가 - 라 - 다 - 마: 이 순서가 임종 적응단계의 올바른 순서입니다.", "3": "나 - 가 - 다 - 라 - 마: 이 순서에서도 임종 적응단계를 올바르게 반영하지 않습니다.", "4": "다 - 가 - 나 - 라 - 마: 이 순서는 임종 적응단계를 올바르게 반영하지 않습니다.", "5": "다 - 나 - 가 - 라 - 마: 이 순서에서도 임종 적응단계를 올바르게 반영하지 않습니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음의 순간", "def_vi": "Khoảnh khắc của cái chết"}, {"term_ko": "적응단계", "term_vi": "Giai đoạn thích nghi", "def_ko": "상황에 적응하는 단계", "def_vi": "Giai đoạn thích ứng với tình huống"}, {"term_ko": "수용", "term_vi": "Chấp nhận", "def_ko": "받아들이는 것", "def_vi": "Sự chấp nhận"}, {"term_ko": "분노", "term_vi": "Tức giận", "def_ko": "화를 내는 것", "def_vi": "Cảm xúc tức giận"}, {"term_ko": "부정", "term_vi": "Phủ nhận", "def_ko": "인정하지 않는 것", "def_vi": "Không chấp nhận"}, {"term_ko": "우울", "term_vi": "Trầm cảm", "def_ko": "슬프고 우울한 상태", "def_vi": "Trạng thái buồn và suy sụp"}, {"term_ko": "타협", "term_vi": "Thỏa hiệp", "def_ko": "중간 지점을 찾는 것", "def_vi": "Tìm kiếm điểm trung gian"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (476, '13', '다음에 해당하는 임종적응 단계로 옳은 것은?• 평화로운 마음 속에서 마지막 정리의 시간을 보내기도 한다. • 재산관리, 상속 관련 상담이 포함된다. • 가족들과 종교적 예식을 준비하는 경우도 있다.', '["부정", "분노", "타협", "우울", "수용"]'::jsonb, 5, '임종적응 단계에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "부정: 개인이 죽음을 인정하지 않으려는 단계입니다.", "2": "분노: 자신의 상황에 대한 분노와 불만을 표현하는 단계입니다.", "3": "타협: 죽음을 피하기 위해 거래하거나 조건을 제시하는 단계입니다.", "4": "우울: 자신의 상황을 받아들이기 어려워 슬픔에 잠기는 단계입니다.\n[정답]", "5": "수용: 죽음을 자연스럽게 받아들이고 마지막 정리를 하는 단계입니다."}'::jsonb, '[{"term_ko": "임종적응", "term_vi": "Giai đoạn thích nghi với cái chết", "def_ko": "죽음을 받아들이는 과정", "def_vi": "Quá trình chấp nhận cái chết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (475, '13', '대상자가 자신이 더 이상 회복 가능성이 없다고 생각하게 되면서 침울해지는 임종의 적응단계로 옳은 것은?', '["부정", "분노", "타협", "우울", "수용"]'::jsonb, 4, '대상자가 임종을 앞두고 회복 가능성을 상실한 상태에서 겪는 감정 상태를 이해하기 위한 문제입니다.', NULL, '{"1": "부정: 처음에는 사실을 부정하는 단계입니다.\n[정답]", "4": "우울: 회복할 수 없다는 인식을 하게 될 때 자연스럽게 느끼는 슬픔과 침울함의 단계입니다.", "2": "분노: 대개 자신이나 주변에 대한 분노를 느끼는 단계입니다.", "3": "타협: 증상이 악화되거나 상태가 심각해질 때, 다른 방법을 찾으려는 시도입니다.", "5": "수용: 마지막 단계로, 사실을 받아들이고 평화를 찾는 단계입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 병자를", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (474, '13', '임종을 앞둔 대상자가 다음과 같이 말할 때의 임종적응 단계로 옳은 것은?대상자: 내게 이런 일이 벌어졌어. 그렇지만 우리 아이가 결혼할 때까지만 살게 해주세요.', '["부정", "분노", "타협", "우울", "수용"]'::jsonb, 3, '대상자의 임종적응 단계를 확인하고 구분하는 것.', NULL, '{"1": "부정: 자신의 상태를 인정하지 않으려는 감정 단계이다.\n[정답]", "3": "타협: 상대방이나 상황을 고려하여 조건을 제시하며 수용하려는 단계이다.", "2": "분노: 상황에 대한 분노와 불만을 표현하는 단계이다.", "4": "우울: 미래에 대한 무력감을 느끼고 슬픔에 잠기는 단계이다.", "5": "수용: 자신의 운명을 받아들이고 평온하게 임종을 준비하는 단계이다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음을 맞이하는 과정", "def_vi": "Quá trình chuẩn bị cho cái chết"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "치료를 받는 사람", "def_vi": "Người nhận điều trị"}, {"term_ko": "부정", "term_vi": "Phủ định", "def_ko": "상황을 인정하지 않으려는 감정", "def_vi": "Cảm xúc không chấp nhận hoàn cảnh"}, {"term_ko": "분노", "term_vi": "Phẫn nộ", "def_ko": "화내는 감정", "def_vi": "Cảm xúc giận dữ"}, {"term_ko": "타협", "term_vi": "Thỏa thuận", "def_ko": "조건을 제시하는 것", "def_vi": "Đưa ra điều kiện"}, {"term_ko": "우울", "term_vi": "Trầm cảm", "def_ko": "슬픔에 잠기는 상태", "def_vi": "Trạng thái buồn bã"}, {"term_ko": "수용", "term_vi": "Chấp nhận", "def_ko": "받아들이는 과정", "def_vi": "Quá trình chấp nhận"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (473, '13', '다음 내용을 읽고 임종의 적응단계로 옳은 것은?이씨는 "나는 아니야. 왜 하팔이면 나야, 왜 지금이야."라고 화를 내며 어디에서나 누구에게나 불만스러운 면만을 찾으려고 한다.', '["부정", "분노", "타협", "우울", "수용"]'::jsonb, 2, '정신적 준비 과정 중 환자가 겪는 다양한 감정 단계의 이해를 요구하는 문제입니다.', NULL, '{"1": "부정: 환자가 상황을 인정하지 않으려는 단계입니다.\n[정답]", "2": "분노: 환자가 상황에 대해 화를 내고 불만을 표현하는 단계입니다.", "3": "타협: 환자가 현재 상황을 받아들이기 위해 타협하려는 단계입니다.", "4": "우울: 환자가 상황을 심각하게 받아들이고 슬픔을 느끼는 단계입니다.", "5": "수용: 환자가 상황을 받아들이고 평화롭게 있는 단계입니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "죽음을 맞이하는 시기", "def_vi": "Thời điểm đối mặt với cái chết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (472, '13', '다음에 해당하는 임종적응 단계로 옳은 것은?• 충격적으로 반응하며 이를 사실로 받아들이려 하지 않는다. • 다시 회복할 수 있다는 비현실적인 믿음을 갖는다.', '["부정", "분노", "타협", "우울", "수용"]'::jsonb, 1, '임종적응 단계에 대한 이해를 평가하는 문제입니다.', NULL, '{"1": "''부정'' 단계는 충격적으로 반응하며 사실로 받아들이지 않으려는 특성이 있습니다.\n[정답]", "2": "''분노'' 단계는 상황에 대한 반발감이나 분노가 나타나는 것입니다.", "3": "''타협'' 단계는 회복의 가능성을 믿고 이를 통해 개인의 감정을 조절하려고 시도하는 과정입니다.", "4": "''우울'' 단계는 슬픔과 무력감을 느끼는 상태를 말합니다.", "5": "''수용'' 단계는 상황을 받아들이고 평온한 마음을 갖는 단계를 의미합니다."}'::jsonb, '[{"term_ko": "임종", "term_vi": "Giai đoạn cuối đời", "def_ko": "말기(한국어)", "def_vi": "Giai đoạn cuối của cuộc sống"}, {"term_ko": "적응", "term_vi": "Thích ứng", "def_ko": "적합해지다(한국어)", "def_vi": "Để phù hợp"}, {"term_ko": "충격", "term_vi": "Sốc", "def_ko": "갑작스러운 감정(한국어)", "def_vi": "Cảm xúc bất ngờ"}, {"term_ko": "부정", "term_vi": "Phủ nhận", "def_ko": "사실을 받아들이지 않음(한국어)", "def_vi": "Không chấp nhận sự thật"}, {"term_ko": "분노", "term_vi": "Nổi giận", "def_ko": "화난 상태(한국어)", "def_vi": "Tình trạng tức giận"}, {"term_ko": "타협", "term_vi": "Thương lượng", "def_ko": "서로의 의견을 조정하는 것(한국어)", "def_vi": "Điều chỉnh ý kiến của nhau"}, {"term_ko": "우울", "term_vi": "Trầm cảm", "def_ko": "슬퍼하는 상태(한국어)", "def_vi": "Tình trạng buồn bã"}, {"term_ko": "수용", "term_vi": "Chấp nhận", "def_ko": "받아들이는 것(한국어)", "def_vi": "Sự chấp nhận"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (471, '12', '중증 인지기능 장애 대상자 활동으로 스트레스를 해소하고, 사람들과의 관계를 통해 사회적 상호작용이 증가하는 활동 내용으로 옳은 것은?', '["얼굴 삼행시 짓기", "물건 보며 회상하기", "악기 연주하기", "날짜 계산하기", "뇌 건강 일기 쓰기"]'::jsonb, 3, '중증 인지기능 장애 대상자가 스트레스를 해소하고 사회적 상호작용을 증가시킬 수 있는 활동을 찾는 것.', NULL, '{"1": "얼굴 삼행시 짓기는 언어적 상호작용을 요구하지만, 관계 형성에는 한계가 있을 수 있다.\n[정답]", "3": "악기 연주하기는 다른 사람과 함께 하는 활동으로, 사회적 상호작용을 증진시키고 스트레스 해소에 도움이 된다.", "2": "물건 보며 회상하기는 개인적인 회상 활동으로 사회적 상호작용을 제한할 수 있다.", "4": "날짜 계산하기는 인지적인 활동이나, 사회적 상호작용과는 거리가 먼 개인적인 작업이다.", "5": "뇌 건강 일기 쓰기는 개인의 내면적인 활동으로, 사회적 상호작용을 증진시키는데 직접적인 도움을 주지 않는다."}'::jsonb, '[{"term_ko": "중증", "term_vi": "Nghiêm trọng", "def_ko": "심각한 상태", "def_vi": "Tình trạng nặng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (470, '12', '중증 인지기능 장애 대상자와 프로그램 진행 시 주의사항으로 옳은 것은?', '["간단한 일상생활도 모두 도움을 준다.", "아침잠이 많은 대상자라도 일찍 깨워 운동하게 한다.", "주방일을 해본 적 없는 대상자에게 요리활동을 제안한다.", "대상자의 익숙한 물건을 버리고 인테리어를 새로 한다.", "배변 실수를 하여도 따뜻한 말로 위로해준다."]'::jsonb, 5, '중증 인지기능 장애 대상자와의 프로그램 진행 시 유의할 점을 묻고 있다.', NULL, '{"1": "간단한 일상생활도 도움을 주지만, 모든 것을 대신해주어서는 안 된다.\n[정답]", "5": "배변 실수를 하더라도 따뜻한 말로 위로하는 것이 중요하다.", "2": "아침잠이 많은 대상자는 억지로 일찍 깨우기보다는 자연스럽게 일어나도록 유도해야 한다.", "3": "주방일을 해본 적 없는 대상자에게는 적합한 활동을 제안해야 하며, 요리활동은 신중하게 접근해야 한다.", "4": "대상자의 익숙한 물건을 버리는 것은 불안감을 유발할 수 있으며, 변경이 필요하더라도 점진적으로 진행해야 한다."}'::jsonb, '[{"term_ko": "중증", "term_vi": "Nghiêm trọng", "def_ko": "심각하다(한국어)", "def_vi": "Nghiêm trọng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (469, '12', '다음과 같이 책이나 신문을 읽다가 숫자와 음이 같은 글자가 나오면 낭독을 하다가 손동작으로 숫자를 함께 표시하는 활동의 목표로 옳은 것은?문제 1. 아래 신문 기사를 읽다가 숫자와 음이 같은 글자가 나오면 손가락으로 숫자를 나타내세요.문제 2. 집에 있는 신문 기사나 책을 읽으며 해당 동작을 취해보세요.(그림)#290', '["집행 기능", "공감능력", "계산능력", "실행능력", "주의집중력"]'::jsonb, 5, '본 문제는 숫자와 해당 글자가 나타날 때 이를 동시에 인지하고 표현하는 능력을 평가하고자 합니다. 이를 통해 주의집중력이 얼마나 잘 발휘되는지를 확인하고자 하는 의도입니다.', NULL, '{"1": "집행 기능: 계획, 조직, 실행의 기능으로 본 문제와는 관계가 적습니다.", "2": "공감능력: 다른 사람의 감정을 이해하고 공감하는 능력으로 본 문제와 관련이 없습니다.", "3": "계산능력: 숫자를 계산하는 능력으로 이 문제의 핵심은 아닙니다.\n[정답]", "4": "실행능력: 의도한 동작(손 동작)을 실현하는 데 필요한 능력입니다.", "5": "주의집중력: 주어진 과제를 수행하기 위해 집중하는 능력이므로 이 문제의 정답입니다."}'::jsonb, '[{"term_ko": "집행 기능", "term_vi": "Chức năng điều hành", "def_ko": "계획, 조직, 실행의 기능(한국어)", "def_vi": "Chức năng lập kế hoạch, tổ chức và thực hiện(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (468, '12', '신문, 드라마, 새로 만난 주변인의 이름을 다음과 같은 네모 안에 기입하고 첫 글자로 삼행시를 짓는 활동 목표로 옳은 것은?문제 예시홍:길:동:', '["창의력", "공감능력", "계산능력", "실행능력", "억제력"]'::jsonb, 1, '활동 목표가 무엇인지 파악하도록 유도하는 문제입니다.', NULL, '{"1": "창의력: 삼행시를 짓는 활동은 창의력을 요구합니다.\n[정답]", "2": "공감능력: 공감능력과는 관련이 적습니다.", "3": "계산능력: 계산능력은 해당 활동과 무관합니다.", "4": "실행능력: 실행능력의 요소가 포함되지만, 주된 목적은 아니므로 부적합합니다.", "5": "억제력: 억제력과 관계가 없습니다."}'::jsonb, '[{"term_ko": "창의력", "term_vi": "Sáng tạo", "def_ko": "창의적으로 생각하고 새로운 것을 만들어내는 능력(한국어)", "def_vi": "Khả năng tư duy sáng tạo và tạo ra cái mới(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (465, '12', '치매 대상자의 인지자극을 위해 다음과 같은 문제를 내었을 때 향상될 수 있는 것은?(그림)#289• 오늘 날짜를 양력으로 적어보세요, ( )월 ( )일•연도, 양력 날짜, 음력 날짜를 해당란에 적고 덧셈, 곱셈을 표기된 대로 하세요.', '["지남력, 의사표현", "계산력, 기억력", "주의집중력, 억제력", "독립성, 활동수행능력", "언어의 유창성, 자발성"]'::jsonb, 2, '치매 대상자의 인지 능력을 향상시키기 위한 방법을 이해하는 것.', NULL, '{"1": "지남력과 의사표현이 향상될 수 있으나, 이 문제의 중점은 수학적 과제에 있다.\n[정답]", "2": "계산력과 기억력은 주어진 문제를 통해 직접적으로 향상될 수 있다.", "3": "주의집중력과 억제력도 중요하지만, 이 문제에서는 특정 수학적 과제가 더 강조된다.", "4": "독립성과 활동수행능력은 간접적으로 영향을 받을 수 있지만 주된 목표는 아니다.", "5": "언어의 유창성은 이 활동과 직접적인 연관이 없다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력, 사고, 의사소통에 영향을 주는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ, suy nghĩ, và giao tiếp."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (464, '12', '치매 대상자를 위한 인지자극 훈련에 관한 설명으로 옳은 것은?', '["가족의 수발 부담을 증가시킨다.", "치매의 진행을 늦추는 약물요법에 해당된다.", "''맨손체조하기''는 지남력을 향상시킨다.", "인지자극훈련 대상자는 혼자서 움직일 수 있어야 한다.", "인지기능에 대한 기본적인 인식이 있는 숙련된 요양보호사가 담당한다."]'::jsonb, 5, '인지자극 훈련의 목표와 대상에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "가족의 수발 부담을 증가시키는 것이 아니라, 오히려 경감시키는 것이 목적입니다.", "2": "약물요법이 아닙니다. 인지자극 훈련은 비약리적 접근입니다.", "3": "맨손체조는 몸의 운동능력에 도움을 주지만, 지남력을 향상시키는 것과는 직접적인 관련이 없습니다.", "4": "인지자극훈련을 받는 대상자는 움직일 수 있는 능력뿐만 아니라 지원과 관리가 필요합니다.\n[정답]", "5": "인지기능에 대한 인식과 이해가 있는 숙련된 요양보호사가 이 과정을 담당해야 합니다."}'::jsonb, '[{"term_ko": "인지자극 훈련", "term_vi": "치매", "def_ko": "기억 và khả năng nhận thức", "def_vi": "bệnh suy giảm trí nhớ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (463, '12', '단기 기억을 향상하기 위한 프로그램으로 적절한 것은?', '["뇌건강 일기 쓰기", "악기 연주하기", "선 따라 그리기", "물건 값 계산하기", "좋아하는 음식 말하기"]'::jsonb, 1, '(단기 기억 향상을 위한 방법을 이해하고 파악하는 것)', NULL, '{"1": "뇌의 기능을 자극하고 사고를 정리하는데 도움이 된다.\n[정답]", "2": "악기를 연주하는 것은 단기 기억뿐만 아니라 전반적인 집중력을 향상시킬 수 있다.", "3": "선을 따라 그리기는 집중력을 요구하지만 단기 기억에는 적합하지 않다.", "4": "물건 값을 계산하는 것은 실생활에 유용하지만 단기 기억을 향상시키는 데는 한계가 있다.", "5": "좋아하는 음식을 말하는 것은 대화의 일부일 수 있지만 단기 기억 향상에는 기여하지 않는다."}'::jsonb, '[{"term_ko": "단기 기억", "term_vi": "Trí nhớ ngắn hạn", "def_ko": "짧은 기간 동안 정보를 기억하는 능력", "def_vi": "Khả năng ghi nhớ thông tin trong thời gian ngắn"}, {"term_ko": "프로그램", "term_vi": "Chương trình", "def_ko": "특정 목표를 위해 체계적으로 구성된 활동", "def_vi": "Hoạt động được tổ chức có hệ thống để đạt được mục tiêu cụ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (462, '12', '빗소리, 개굴 울음소리 등 청각적 자극을 활용한 인지자극 훈련으로 기대할 수 있는 효과로 옳은 것은?', '["집행기능 향상", "지남력 자극", "친화력 확대", "공감능력 향상", "계산능력 향상"]'::jsonb, 2, '청각적 자극을 이용한 인지자극 훈련의 효과를 이해하는 것이 목적이다.', NULL, '{"1": "집행기능 향상은 다양한 인지 훈련의 결과로 나타날 수 있지만, 청각적 자극과의 직접적인 연관성은 낮다.\n[정답]", "2": "지남력 자극은 환경 인식을 증가시키고 방향 감각을 향상시키는 데 도움이 된다.", "3": "친화력 확대는 주로 사회적 상호작용에 따른 결과로, 청각적 자극과는 관련이 적다.", "4": "공감능력 향상은 대인 관계에 영향을 미치는 측면으로, 청각적 자극이 직접적인 영향을 주는 것은 아니다.", "5": "계산능력 향상은 주로 수리적 사고와 관련이 있으며, 청각적 자극과의 직접적인 연결이 없다."}'::jsonb, '[{"term_ko": "청각적 자극", "term_vi": "Kích thích thính giác", "def_ko": "귀로 감지할 수 있는 자극", "def_vi": "Các kích thích có thể được phát hiện bằng tai"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (461, '12', '요양보호사가 치매말기 대상자에게 어르신, 점심 드셨어요?라고 했을 때 대상자의 반응으로 옳은 것은?', '["\"거기에 언제 갈 거야?\"라며 대화의 주제가 바뀐다.", "\"어제 먹었어.\"라며 올바른 시제 사용이 어렵다.", "\"그거 있잖아.아니, 그것 말이야.\"라며 올바른 지칭을 사용하지 못한다.", "\"응, 많이 먹었어요.\"라며 인사를 건넨다.", "\"점심 드셨어요?\"라고 하면 앵무새처럼 따라 한다."]'::jsonb, 5, '치매말기 대상자의 반응 특성과 대화의 진행 방식을 이해하는 것이 중요하다.', NULL, '{"1": "대상자가 주제를 바꾸는 것은 치매의 일반적인 반응이다.\n[정답]", "5": "치매환자가 이전에 들었던 질문을 어투를 따라서 반복하는 경향이 있다.", "2": "치매환자는 종종 시제를 혼동할 수 있다.", "3": "올바른 지칭을 사용하지 못하는 것은 치매환자의 일반적인 특징이다.", "4": "간혹 치매환자는 긍정적인 반응을 보이기도 하지만, 정확한 대답은 아닐 수 있다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 전문직", "def_vi": "Nghề chăm sóc bệnh nhân"}, {"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 인지 기능의 저하", "def_vi": "Sự suy giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "대답이나 행동", "def_vi": "Trả lời hoặc hành động"}, {"term_ko": "어르신", "term_vi": "Người lớn tuổi", "def_ko": "존경하는 어른", "def_vi": "Ông bà, người lớn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (460, '12', '치매 대상자가 의사표현을 하도록 돕는 방법으로 옳은 것은?', '["큰소리로 톤을 높여 말한다.", "\"이것은 해도 되고, 저것은 안 된다\"라고 표현한다.", "\"아! 그 사람이요? 네? 왜요?\"라고 질문한다.", "대상자의 주의를 끌 때 요양보호사의 소개는 생략한다.", "친근함을 위해 고향 사투리 말을 걸어본다."]'::jsonb, 5, '치매 대상자가 의사표현을 할 수 있도록 도와주는 방법에 대한 이해를 평가하려는 의도로 출제되었다.', NULL, '{"1": "큰소리로 톤을 높여 말하는 것은 대상자가 불안감을 느낄 수 있어 좋지 않다.\n[정답]", "5": "친근함을 위해 고향 사투리 말을 건네는 것은 대상자가 편안함을 느끼고 의사표현을 더 잘 할 수 있도록 도와줄 수 있다.", "2": "''이것은 해도 되고, 저것은 안 된다''라고 표현하는 것은 선택의 제한을 둘 수 있어 바람직하지 않다.", "3": "''아! 그 사람이요? 네? 왜요?''라는 질문은 대화를 흐트러뜨릴 수 있다.", "4": "대상자의 주의를 끌 때 요양보호사의 소개는 상황에 따라 필요할 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력, 사고력 및 기능이 저하되는 상태", "def_vi": "Tình trạng suy giảm trí nhớ, khả năng tư duy và chức năng"}, {"term_ko": "의사표현", "term_vi": "Thể hiện ý kiến", "def_ko": "자신의 생각이나 감정을 전달하는 것", "def_vi": "Truyền đạt suy nghĩ hoặc cảm xúc của bản thân"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스의 혜택을 받는 사람", "def_vi": "Người nhận lợi ích từ dịch vụ"}, {"term_ko": "주변", "term_vi": "Môi trường xung quanh", "def_ko": "가까운 환경", "def_vi": "Môi trường gần gũi"}, {"term_ko": "친근함", "term_vi": "Sự thân thiện", "def_ko": "관계가 가까워서 편안한 느낌", "def_vi": "Cảm giác thoải mái vì mối quan hệ gần gũi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (459, '12', '치매 대상자와의 의사소통 기본 원칙으로 옳은 것은?', '["눈을 맞추고 미소를 지으며 이야기한다.", "어린아이 대하듯 친근하게 말한다.", "\"왜\"라는 질문을 하여 대화를 지속시킨다.", "TV를 켜고 화면에 나오는 내용으로 대화한다.", "목소리의 톤을 높여 집중하게 한다."]'::jsonb, 1, '치매 대상자와의 효과적인 의사소통 방식을 이해하고 적용할 수 있는지를 평가하고자 하는 문제입니다.', NULL, '{"1": "눈을 맞추고 미소를 지으며 이야기하는 것은 치매 환자의 정서적 안정감과 관계 형성에 중요합니다.\n[정답]", "2": "어린아이 대하듯 친근하게 말하는 것은 부적절할 수 있으며, 존중이 필요합니다.", "3": "\"왜\"라는 질문을 자주 하는 것은 혼란을 줄 수 있습니다.", "4": "TV를 켜고 대화하는 것은 분산 집중을 유발할 수 있으므로 바람직하지 않습니다.", "5": "목소리의 톤을 높이는 것이 오히려 스트레스를 줄 수 있으므로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (458, '12', '시설 치매 대상자가 담당 요양보호사를 애인이라고 하면서 다음과 같은 행동을 할 때 돕는 방법으로 옳은 것은?• 담당 요양보호사가 다른 대상자를 돌보지 못하게 한다.• 담당 요양보호사가 올 때마다 가슴을 만진다.', '["보호자에게 알리고 퇴소절차를 밟는다.", "성희롱이라고 하면서 성폭력 상담소에 신고한다.", "담당 요양보호사의 변경을 요청하겠다고 경고한다.", "어르신을 돌보는 전문가라고 권위적으로 말한다.", "치매 대상자에게 나타나는 증상이라고 이해하고 모른 척한다."]'::jsonb, 3, '치매 환자의 행동 문제에 대한 적절한 대처 방법을 물어보는 문제입니다.', NULL, '{"1": "보호자에게 알리고 퇴소절차를 밟는 것은 상황을 더 악화시킬 수 있습니다.\n[정답]", "2": "성희롱이라고 하면서 성폭력 상담소에 신고하는 것은 문제를 해결하기보다는 복잡하게 만듭니다.", "3": "담당 요양보호사의 변경을 요청하겠다고 경고하는 것은 최선의 대처 방법으로, 상황을 개선할 수 있습니다.", "4": "어르신을 돌보는 전문가라고 권위적으로 말하는 것은 상황을 더욱 긴장하게 만들 수 있습니다.", "5": "치매 대상자에게 나타나는 증상이라고 이해하고 모른 척하는 것은 문제를 방치하는 것입니다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Người chăm sóc", "def_ko": "시설(시설물)", "def_vi": "Có chăm sóc cho người trong một cơ sở"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (457, '12', '기저귀를 차고 있는 치매 대상자가 기저귀 안으로 손을 자주 넣어 성기에 상처를 낼 때 돕는 방법으로 옳은 것은?', '["손톱을 짧게 깎고, 청결을 유지한다.", "부끄러운 행동이라고 비난한다.", "하의를 벗겨 시원하게 해준다.", "상·하의가 붙은 옷으로 갈아입힌다", "서비스를 중단하겠다고 말한다."]'::jsonb, 1, '치매 대상자의 기저귀 사용에 따른 안전한 돌봄 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "손톱을 짧게 깎고, 청결을 유지함으로써 상처를 방지할 수 있습니다.\n[정답]", "2": "부끄러운 행동이라고 비난하는 것은 대상자의 자존감을 해칠 수 있어 바람직하지 않습니다.", "3": "하의를 벗겨 시원하게 해주는 것은 상황에 따라 불편할 수 있습니다.", "4": "상·하의가 붙은 옷으로 갈아입히는 것은 불편함을 줄이기 위한 방법이지만, 기저귀 착용 문제에 대처하기에는 적합하지 않습니다.", "5": "서비스를 중단하겠다고 말하는 것은 극단적인 대응으로, 문제 해결에 도움을 주지 않습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "아기 또는 노인이 비뇨를 하거나 대변을 눌러도 옷이 더럽혀지지 않도록 해주는 제품", "def_vi": "Sản phẩm giúp cho trẻ em hoặc người già không làm bẩn quần áo khi đi tiểu hoặc đại tiện"}, {"term_ko": "성기", "term_vi": "Cơ quan sinh dục", "def_ko": "남성 또는 여성의 생식 기관", "def_vi": "Cơ quan sinh sản của nam hoặc nữ"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억을 잃거나 혼란스러운 상태", "def_vi": "Tình trạng mất trí nhớ hoặc gây nhầm lẫn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (456, '12', '치매 대상자가 바지를 내리고 성기를 노출하고 있을 때 돕는 방법으로 옳은 것은?', '["\"창피한 것도 모르세요?\"", "\"이러시면 퇴소조치를 하겠어요.\"", "\"제가 옷을 다시 입혀드릴게요.\"", "\"어린아이처럼 행동하지 마세요!\"", "\"지금 저에게 성희롱하는 거예요!\""]'::jsonb, 3, '치매 대상자의 성적 행동에 대한 적절한 대응 방법을 묻는 질문입니다.', NULL, '{"1": "''창피한 것도 모르세요?''는 대상자의 행동을 비하하는 표현으로, 적절하지 않습니다.\n[정답]", "3": "''제가 옷을 다시 입혀드릴게요.''는 대상자의 존엄성을 존중하며 상황을 적절히 처리하는 방법입니다.", "2": "''이러시면 퇴소조치를 하겠어요.''는 협박으로, 부적절한 반응입니다.", "4": "''어린아이처럼 행동하지 마세요!''는 대상자를 비하하며 문제가 해결되지 않습니다.", "5": "''지금 저에게 성희롱하는 거예요!''는 상황을 악화시킬 수 있는 발언입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 인지 기능이 저하되는 질병", "def_vi": "Sự suy giảm trí nhớ và chức năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (455, '12', '치매 대상자가 프로그램 활동 중 자주 옷을 벗는 행동을 할 때 돕는 방법으로 옳은 것은?', '["편안한 옷으로 갈아입게 한다.", "벗은 상태에서 활동하게 한다.", "성희롱으로 신고하겠다고 말한다.", "스스로 옷을 입을 때까지 기다린다.", "시설장과 의논하여 가족에게 퇴소를 권고한다."]'::jsonb, 1, '치매 대상자의 행동 관리와 적절한 대처 방법을 이해하고 확인하기 위해서입니다.', NULL, '{"1": "편안한 옷으로 갈아입게 함으로써 치매 대상자가 상황에 편안하게 적응할 수 있도록 도와주는 것이 올바른 방법입니다.\n[정답]", "2": "벗은 상태에서 활동하게 하는 것은 적절하지 않습니다. 치매 대상자를 존중하고 안전하게 보낼 수 있는 환경을 조성해야 합니다.", "3": "성희롱으로 신고하겠다고 말하는 것은 치매 대상자의 행동에 대한 이해가 부족한 모습이며, 적절한 대처가 아닙니다.", "4": "스스로 옷을 입도록 기다리는 것은 상황을 악화시킬 수 있으며, 더 이상적이지 않습니다.", "5": "가족에게 퇴소를 권고하는 것은 문제의 근본적인 해결이 아니라 상황을 회피하는 방법입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Quên", "def_ko": "기억력과 인지능력의 저하(치 Dementia)", "def_vi": "Sự suy giảm trí nhớ và khả năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (454, '12', '시설 대상자가 하루 종일 콩 고르기를 하다가 해질녘이 되면 오늘은 이만 하고 돌아가겠습니다. 하면서 밖으로 나가려고 할 때 돕기 방법으로 옳은 것은?', '["자녀분이 데리러 올 거라고 기다리라고 한다.", "여기가 집이라며 집에 갈 수 없다고 설득한다.", "조명을 소등하여 밤이라는 것을 알린다.", "할 일이 더 있으니 갈수 없다고 말한다.", "반찬거리를 사오자며 함께 산책을 나간다."]'::jsonb, 5, '대상자가 적절한 상호작용을 통해 지원을 받을 수 있는 방법을 파악하는 것입니다.', NULL, '{"1": "자녀분이 데리러 올 거라고 기다리라고 한다. - 대상자의 의사를 존중하지 않는 방식입니다.\n[정답]", "5": "반찬거리를 사오자며 함께 산책을 나간다. - 대상자가 활동을 지속할 수 있도록 유도하며 외부로 나가는 대신 긍정적인 활동을 제안합니다.", "3": "조명을 소등하여 밤이라는 것을 알린다. - 대상자의 인지적 혼란을 초래할 수 있습니다.", "4": "할 일이 더 있으니 갈 수 없다고 말한다. - 강제적인 대처로 대상자의 감정을 해칠 수 있습니다.", "2": "여기가 집이라며 집에 갈 수 없다고 설득한다. - 잘못된 정보 제공으로 대상자를 혼란스럽게 할 수 있습니다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "시설(한국어)", "def_vi": "Cơ sở"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (453, '12', '치매 대상자가 해질녘이 되면 불안하고 우울증상을 보일 때 돕는 방법으로 옳은 것은?', '["낮 동안 충분한 수면을 취하게 한다.", "텔레비전을 끄고 소음을 차단한다.", "조용히 혼자 있도록 배려한다.", "복잡한 소일거리를 제공한다.", "따뜻한 음료수를 제공한다."]'::jsonb, 5, '치매 환자의 정서적 안정과 불안감 감소를 위한 적절한 대처 방법을 알아보는 것이다.', NULL, '{"1": "낮 동안 충분한 수면을 취하게 한다. -> 낮 동안 수면을 취하는 것이 아닌 저녁 시간에 안정감을 주는 방법이 필요하다.\n[정답]", "5": "따뜻한 음료수를 제공한다. -> 따뜻한 음료는 정서적 안정에 도움을 줄 수 있다.", "3": "조용히 혼자 있도록 배려한다. -> 혼자 있도록 할 경우 불안감이 증가할 수 있다.", "4": "복잡한 소일거리를 제공한다. -> 복잡한 활동은 오히려 스트레스를 유발할 수 있다.", "2": "텔레비전을 끄고 소음을 차단한다. -> 소음 차단은 필요할 수 있으나, 정서적 지원이 더 중요하다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고력의 감소로 일상 생활에 지장을 주는 질환", "def_vi": "Bệnh gây ảnh hưởng đến trí nhớ và khả năng tư duy của người bệnh"}, {"term_ko": "불안", "term_vi": "Lo âu", "def_ko": "정서적으로 고통받는 상태", "def_vi": "Trạng thái tinh thần khó chịu"}, {"term_ko": "우울증상", "term_vi": "Triệu chứng trầm cảm", "def_ko": "슬픔과 무기력 등을 나타내는 증상", "def_vi": "Các triệu chứng thể hiện sự buồn bã và không có động lực"}, {"term_ko": "정서적 안정", "term_vi": "Sự ổn định cảm xúc", "def_ko": "정신적인 편안함", "def_vi": "Sự thư giãn về tinh thần"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (452, '12', '치매 대상자가 갑자기 분통을 터뜨리며 요양보호사에게 침을 뱉고, 주먹으로 치며 신체적인 폭력을 가할 때 돕는 방법으로 옳은 것은?', '["갑자기 화가 난 이유를 물어본다.", "입을 막아 침을 뱉지 못하게 한다.", "행동이 멈출 때까지 그 자리를 피한다.", "진정될 때까지 신체적으로 구속시킨다.", "화가 난 것을 이해한다고 말하며 진정시킨다."]'::jsonb, 5, '치매 대상자의 돌발적 행동에 대처하는 방법을 이해하고, 적절한 대처법을 선택하는 능력을 평가하고자 함.', NULL, '{"1": "갑자기 화가 난 이유를 물어보는 것은 상황을 악화시킬 수 있기 때문에 부적절하다.\n[정답]", "5": "화가 난 것을 이해한다고 말하며 진정시킨다. 이는 대상자의 감정을 인정하고, 안정감을 주기 위한 적절한 방법이다.", "3": "행동이 멈출 때까지 그 자리를 피하는 것은 문제를 회피하는 것으로, 바람직하지 않다.", "4": "신체적으로 구속시키는 것은 폭력을 유발할 수 있고, 대상자의 불안감을 더욱 키울 수 있다.", "2": "입을 막는 것은 대상자의 권리를 침해할 수 있으므로 피해야 한다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 및 인지 기능의 저하", "def_vi": "Suy giảm chức năng nhớ và nhận thức"}, {"term_ko": "신체적인 폭력", "term_vi": "Bạo lực thể chất", "def_ko": "신체에 대한 공격적인 행동", "def_vi": "Hành vi tấn công vào cơ thể"}, {"term_ko": "진정시키다", "term_vi": "Làm dịu", "def_ko": "안정시키다", "def_vi": "Trấn an"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (451, '12', '시설 치매 어르신이 같은 방을 사용하는 노인에게 저 사람은 남의 집에 세들어 살면서 방세도 내지 않는다. 라고 큰소리로 불만을 말할 때 돕는 방법으로 옳은 것은?', '["누가 그런 말을 했는지 물어본다.", "다 같이 지내는 시설임을 수시로 알려준다.", "요양보호사가 방세확인서를 임의로 만들어 보여준다.", "상대 노인에게 귓속말로 신경 쓰지 않아도 된다고 말해준다.", "고향에 관한 대화를 나누어 관심을 돌린다."]'::jsonb, 2, '시설에서 치매 어르신의 행동이나 발언에 대한 적절한 대처 방법을 이해하고 선택하는 것이 중요하다.', NULL, '{"1": "누가 그런 말을 했는지 물어보는 것은 상황을 더 혼란스럽게 할 수 있다.\n[정답]", "2": "시설에서 함께 지내는 것임을 상기시킴으로써 불만의 원인을 완화할 수 있다.", "3": "방세확인서를 임의로 만들어 보여주는 것은 믿음을 줄이지 않을 수 있다.", "4": "고령자에게 귀속말로 이야기하는 것은 오히려 상황을 악화시킬 수 있다.", "5": "고향에 관한 대화를 나누는 것은 좋지만, 이는 불만에 대한 직접적인 대처가 아니다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "공간(한국어)", "def_vi": "Nơi chốn"}, {"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억 상실증(한국어)", "def_vi": "Rối loạn trí nhớ"}, {"term_ko": "어르신", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người già"}, {"term_ko": "방세", "term_vi": "Tiền thuê phòng", "def_ko": "방세(한국어)", "def_vi": "Chi phí thuê phòng"}, {"term_ko": "귓속말", "term_vi": "Nói thì thầm", "def_ko": "작은 소리로 말하다(한국어)", "def_vi": "Nói nhỏ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (450, '12', '치매 대상자가 아무도 없는 방 안을 보며 우리 손주가 벌써 왔네? 맛있는 거 가져올게. 라고 할 때 돕는 방법으로 옳은 것은?', '["\"방 안에 아무도 없어요.\"라며 방문을 닫는다.", "\"손주가 많이 보고 싶군요.\"라며 어깨를 안아준다.", "\"방 안에 사람이 있는지를 눈을 크게 뜨고 보세요\"라고 말한다.", "\"기력이 없으셔서 헛것이 보이나 봐요.\"라며 보호자에게 연락한다.", "\"손주는 지금 학교에 가서 없어요.\"라며 하던 일을 계속한다."]'::jsonb, 2, '치매 대상자와의 의사소통 및 정서적 지원 방법을 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "치매 대상자가 현실을 인식할 수 있도록 돕는 것이 아니라 그들을 혼란스럽게 할 수 있습니다.\n[정답]", "2": "대상자의 감정을 인정하고 지지해 주는 방법입니다.", "3": "치매 대상자에게는 적극적인 지시보다 부드러운 대화가 효과적입니다.", "4": "기력 부족을 판단하기보다 정서적 지지를 우선해야 합니다.", "5": "대상자의 관심사를 무시하는 것이기 때문에 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 인지 기능이 감퇴된 상태", "def_vi": "Trạng thái suy giảm trí nhớ và khả năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (446, '12', '다음 상황을 읽고 요양보호사의 적절한 반응으로 옳은 것은?• 치매 대상자 : 누가 날 죽이려고 내 밥에 독약을 넣었어! 안 먹어. 저리 치워!• 요양보호사 : ________________________________________________', '["\"왜 독약을 넣었다고 생각하세요?\"", "\"정말요?누가 넣었는지 아세요?\"", "\"경찰에 신고해서 누가 그랬는지 알아볼게요\"", "\"아무도 안 넣었으니 걱정 말고 드세요.\"", "\"제가 먼저 먹어볼 테니 저와 같이 드셔요.\""]'::jsonb, 5, '요양보호사가 치매 환자의 불안과 두려움을 이해하고, 신뢰를 구축하기 위한 적절한 대처 방안을 선택하는 것이 중요하다.', NULL, '{"1": "환자의 불안을 더욱 키울 수 있는 질문이며, 상황을 진지하게 받아들이지 않는 인상이다.\n[정답]", "5": "요양보호사가 먼저 음식을 먹어보임으로써 환자의 불안감을 덜어주고 신뢰를 쌓을 수 있는 방법이다.", "2": "불안을 유발할 수 있는 질문으로, 환자의 정서적 안정에 도움이 되지 않는다.", "3": "즉각적인 신고는 상황을 악화시킬 수 있으며, 환자를 더욱 불안하게 만들 수 있다.", "4": "불안감을 무시하고 대처하는 방식으로, 환자의 감정을 존중하지 않는 것이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억이나 사고에 문제가 생기는 질병", "def_vi": "bệnh có vấn đề về trí nhớ hoặc suy nghĩ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (445, '12', '치매 대상자가 자신의 목걸이를 누군가 훔쳐갔다고 말하며 딸을 의심할 때 요양보호사의 적절한 반응으로 옳은 것은?', '["\"어르신, 따님이 목걸이를 왜 훔쳐갔을까요?\"", "\"어르신, 귀한 목걸이를 잃어버려서 많이 속상하시겠어요.\"", "\"어르신, 다른 데다 두시고 잊어버리신 것 아니에요?\"", "\"어르신, 또 엉뚱한 사람 의심하고 그러세요.\"", "동료 요양보호사에게 귓속말을 하며 하소연을 한다."]'::jsonb, 2, '치매 환자의 의심과 감정을 이해하고 적절히 대응하는 방법을 평가하기 위한 질문입니다.', NULL, '{"1": "어르신의 감정을 무시하는 질문입니다.\n[정답]", "2": "어르신의 기분을 공감하고 위로하는 적절한 반응입니다.", "3": "어르신의 불안감을 덜어주기보다는 오히려 불안하게 만드는 질문입니다.", "4": "어르신의 감정을 깎아내리고 불쾌감을 줄 수 있는 반응입니다.", "5": "동료에게 불만을 토로하는 것은 프로페셔널하지 못한 행동입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고 능력이 감소하는 질환", "def_vi": "Bệnh giảm khả năng ghi nhớ và suy nghĩ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (444, '12', '다음과 같은 상황에서 요양보호사의 돕는 방법으로 옳은 것은?시설치매 대상자가 사망한 남편의 이름을 부르며 허공에 손짓을 하며 "여보, 나 여기 있어요!"라며 하고 있다.', '["남편이 무슨 옷을 입었는지 물어본다.", "남편은 오래전에 돌아가셨다고 말해준다.", "\"지금은 밤이니 내일 오실 거에요.\"라며 말한다.", "낮에 사온 과일이 맛있는지 먹어보자고 한다.", "병세가 심해서 헛것이 보이는 것이라고 설명한다."]'::jsonb, 4, '환자가 대상자의 감정 상태를 이해하고 적절하게 반응하도록 돕는 방법을 묻고 있다.', NULL, '{"1": "남편의 옷차림에 대한 질문은 현재 상황과 관련이 없고 대상자를 혼란스럽게 할 수 있다.\n[정답]", "2": "남편이 돌아가셨다는 사실은 대상자에게 상처를 줄 수 있기에 적절하지 않다.", "3": "현재 상황을 무시하면서 내일 올 것이라는 말은 상황을 더욱 어렵게 만들 수 있다.", "4": "환자의 감정을 존중하고 긍정적으로 반응하는 것은 요양보호사가 가지고 있어야 할 중요한 태도다.", "5": "병세를 설명하는 것으로는 환자의 감정을 고려하지 않은 답변이 된다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인을 돌보는 사람", "def_vi": "Người chăm sóc người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (443, '12', '다음과 같은 상황에서 요양보호사의 적절한 반응으로 옳은 것은?• 치매 대상자 : 나만 빼고 너희끼리 고기 구워 먹었지? 나도 얼른 구워 줘!• 요양보호사 : ________________________________________________', '["\"무슨 고기 냄새가 난다고 그러세요?\"", "\"조금 전에 고기반찬 드셨잖아요.\"", "\"고기가 드시고 싶으세요? 같이 사러 가요\"", "\"어르신은 치아가 나빠서 못 드세요.\"", "\"무슨 말씀이세요? 아무도 고기 먹지 않았어요.\""]'::jsonb, 3, '요양보호사가 치매 대상자와의 효과적인 소통 방법을 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "요양보호사가 치매 대상자의 감정을 무시하는 반응입니다.\n[정답]", "3": "치매 대상자의 요구를 인정하고, 긍정적인 방향으로 대화를 이끌어가는 반응입니다.", "2": "과거의 기억을 언급하며 대상자를 혼란스럽게 할 수 있습니다.", "4": "치아 문제를 언급함으로써 대상을 불편하게 만드는 대답입니다.", "5": "대상자의 말을 무시하는 반응이며, 부정적인 인터랙션을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억이나 인지 능력을 상실하는 질병", "def_vi": "Bệnh mất trí nhớ"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "사람의 행동에 대한 대답", "def_vi": "Đáp lại hành động của người khác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (442, '12', '내가 살던 집이 아니라며 자주 집 주변을 돌아다니는 치매 대상자를 돕는 방법으로 옳은 것은?', '["집 주소와 보호자의 전화번호를 외우게 한다.", "텔레비전을 크게 틀어주어 집중하게 한다.", "대상자의 신분증을 보호자가 소지하게 한다.", "외출할 때 입을 겉옷을 문 입구에 걸어준다.", "주소, 전화번호가 적인 이름표를 옷에 꿰매어준다."]'::jsonb, 5, '치매 대상자를 돕기 위한 올바른 방법을 묻는 질문이다.', NULL, '{"1": "집 주소와 보호자의 전화번호를 외우게 한다. - 치매 환자는 기억력이 떨어지므로 외우는 것이 어렵다.\n[정답]", "5": "주소, 전화번호가 적인 이름표를 옷에 꿰매어준다. - 이 방법은 대상자가 스스로 정보에 접근할 수 있게 도와주므로 유용하다.", "3": "대상자의 신분증을 보호자가 소지하게 한다. - 신분증을 소지하는 것만으로는 치매 환자의 불안감을 해소할 수 없다.", "4": "외출할 때 입을 겉옷을 문 입구에 걸어준다. - 환자의 혼란을 일으킬 수 있는 방법이다.", "2": "텔레비전을 크게 틀어주어 집중하게 한다. - 집중력이 떨어진 환자에게 효과적인 방법이 아니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이 쇠퇴해 일상생활에 어려움을 겪는 상태", "def_vi": "Tình trạng suy giảm trí nhớ gây khó khăn trong sinh hoạt hàng ngày"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "도움을 받는 사람", "def_vi": "Người nhận sự giúp đỡ"}, {"term_ko": "보호자", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "신분증", "term_vi": "Thẻ căn cước", "def_ko": "개인 정보를 확인할 수 있는 증명서", "def_vi": "Giấy xác nhận thông tin cá nhân"}, {"term_ko": "주소", "term_vi": "Địa chỉ", "def_ko": "거주하는 장소를 나타내는 정보", "def_vi": "Thông tin về nơi cư trú"}, {"term_ko": "전화번호", "term_vi": "Số điện thoại", "def_ko": "전화로 연락할 수 있는 번호", "def_vi": "Số để liên lạc qua điện thoại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (441, '12', '야간에 집 안에서 목적 없이 이곳저곳 배회하는 치매 대상자를 돕는 방법으로 옳은 것은?', '["취침 전에 따뜻한 녹차를 제공한다.", "현관문을 열어 공기를 환기시킨다.", "함께 자리에 누워 고향에 관한 이야기를 한다.", "배회 동선을 차단하여 낙상 위험을 줄인다.", "거실을 어둡게 하여 방에서 나오는 것을 방지한다."]'::jsonb, 3, '치매 대상자에게 적절한 수면 환경을 조성하기 위해 어떤 방법이 효과적인지를 묻는 문제이다.', NULL, '{"1": "취침 전에 따뜻한 녹차를 제공하는 것은 수면에 도움이 될 수 있으나, 카페인이 포함되어 있을 경우 오히려 수면을 방해할 수 있다.\n[정답]", "3": "함께 자리에 누워 고향에 관한 이야기를 하는 것은 치매 대상자의 정서적 안정감과 기억 회상에 도움이 된다.", "2": "현관문을 열어 공기를 환기시키는 것은 이렇다 할 효과가 없으며 안전에도 문제가 될 수 있다.", "4": "배회 동선을 차단하여 낙상 위험을 줄이는 것은 필요할 수 있으나, 치매 대상자의 자유를 과도하게 제한할 수 있다.", "5": "거실을 어둡게 하여 방에서 나오는 것을 방지하는 것은 대상자를 불안하게 만들 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 사고 기능이 저하되는 질환", "def_vi": "Bệnh làm giảm khả năng nhớ và suy nghĩ"}, {"term_ko": "수면", "term_vi": "Giấc ngủ", "def_ko": "일정 시간 동안 의식이 없는 상태", "def_vi": "Trạng thái không có ý thức trong một khoảng thời gian"}, {"term_ko": "정서적", "term_vi": "Tình cảm", "def_ko": "감정과 관련된", "def_vi": "Liên quan đến cảm xúc"}, {"term_ko": "안정감", "term_vi": "Cảm giác an toàn", "def_ko": "불안이 없는 상태", "def_vi": "Trạng thái không có sự lo lắng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (440, '12', '프로그램에 참여하던 치매 대상자가 갑자기 일어나서 서성이며 안절부절못할 때 돕는 방법으로 옳은 것은?', '["대·소변이 보고 싶은지 물어본다.", "소등하여 실내를 어둡게 한다.", "그대로 놔둔 채 프로그램을 진행한다.", "조용한 방으로 데려가 혼자 있게 한다.", "프로그램에 집중하라고 권유한다."]'::jsonb, 1, '치매 대상자의 행동 변화에 대한 적절한 대처 방안을 묻는 문제입니다.', NULL, '{"1": "대·소변이 보고 싶은지 물어본다. (치매 대상자가 불안해할 때, 신체적 욕구를 확인하는 것이 중요합니다.)\n[정답]", "2": "소등하여 실내를 어둡게 한다. (어두운 환경은 더 불안감을 조성할 수 있습니다.)", "3": "그대로 놔둔 채 프로그램을 진행한다. (대상자의 안전과 안정을 우선시해야 합니다.)", "4": "조용한 방으로 데려가 혼자 있게 한다. (대상자가 더 불안해할 수 있으므로 혼자 두지 말아야 합니다.)", "5": "프로그램에 집중하라고 권유한다. (대상자가 안절부절 못 할 때는 집중하기 어려울 수 있습니다.)"}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "뇌의 기능 저하로 인한 인지능력 감소, 나이를 먹는 것과 관련됨", "def_vi": "Giảm khả năng nhận thức do suy giảm chức năng não, liên quan đến tuổi tác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (439, '12', '낮 동안 계속 졸고, 밤에는 거실을 서성거리는 치매 대상자를 돕는 방법으로 옳은 것은?', '["낮 동안 좋아하는 커피를 제공한다.", "낮잠으로 부족한 잠을 보충한다.", "산책과 가튼 야외활동을 하게 한다.", "저녁 식사 후 고강도 근력운동을 하게 한다.", "잠들기 전까지 좋아하는 드라마를 보게 한다."]'::jsonb, 3, '치매 대상자의 낮 동안의 졸림과 밤의 불안정한 행동을 해결하기 위한 적절한 방법을 찾는 것이다.', NULL, '{"1": "커피는 카페인이 포함되어 있어 졸음을 유발할 수 있다.\n[정답]", "3": "야외활동은 신체 활동을 통해 낮 동안의 졸림을 줄이고, 야간에 안정된 수면을 도울 수 있다.", "2": "낮잠을 보충하는 것은 문제를 해결하기보다는 수면 리듬을 더 흐트러뜨릴 수 있다.", "4": "고강도 근력운동은 밤에 긴장을 유발할 수 있으므로 추천하지 않는다.", "5": "좋아하는 드라마는 수면 유도보다는 오히려 각성 상태를 유지하게 할 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억과 인지 기능의 장애", "def_vi": "Rối loạn trí nhớ và chức năng nhận thức"}, {"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "산책", "term_vi": "Đi dạo", "def_ko": "신체적 활동의 일환으로 걷기", "def_vi": "Hình thức hoạt động thể chất đi bộ"}, {"term_ko": "고강도", "term_vi": "Cường độ cao", "def_ko": "강도가 높은", "def_vi": "Mức độ cao"}, {"term_ko": "근력운동", "term_vi": "Tập thể dục cường độ cao", "def_ko": "근육을 강화하는 운동", "def_vi": "Tập luyện để tăng cường cơ bắp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (438, '12', '치매 대상자의 수면장애 증상으로 옳은 것은?', '["밤낮 없이 일어서서 돌아다닌다.", "초저녁에 자고 새벽에 일어난다.", "밤낮으로 자다 깨다를 반복한다.", "밤에 잠을 자고 낮 동안에 활동이 많아진다.", "2~3일간 잠을 자지 않고 2~3일 뒤에 계속 잠을 잔다."]'::jsonb, 5, '치매 환자의 수면장애 증상 파악', NULL, '{"1": "야경증의 전형적인 증상으로 볼 수 있으나, 잠을 자지 않는 것이 아님\n[정답]", "5": "치매 환자는 주기적으로 수면 패턴의 변화가 있으며, 2~3일째 잠을 자지 않다가 그 뒤에 많은 시간 잠을 자는 경우도 있다.", "3": "경우에 따라 나타날 수 있지만, 전형적인 증상은 아님", "4": "일반적으로 치매 환자는 밤에 활동이 적고 낮에 더 활동적인 경우가 많다.", "2": "치매에 해당하는 전형적인 수면 패턴은 아님"}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고력이 상실되는 질환", "def_vi": "Bệnh mất khả năng nhớ và tư duy"}, {"term_ko": "수면장애", "term_vi": "Rối loạn giấc ngủ", "def_ko": "수면의 질과 양에 문제가 발생하는 증상", "def_vi": "Triệu chứng liên quan đến chất lượng và số lượng giấc ngủ"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "환자의 상태를 나타내는 신호", "def_vi": "Dấu hiệu biểu thị tình trạng của bệnh nhân"}, {"term_ko": "전형적인", "term_vi": "Điển hình", "def_ko": "대표적인", "def_vi": "Đại diện"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (437, '12', '치매 대상자가 식사를 거부할 때 돕는 방법으로 옳은 것은?', '["꾸짖거나 잔소리를 하여 음식을 먹게 한다.", "대상자 몸의 상태를 충분히 살펴본다.", "가볍게 먹을 수 있는 컵밥 등을 준비해준다.", "다른일에 지나치게 몰두하고 있다면 그대로 둔다.", "기분전환을 할 수 있도록 산책 후 식사하게 한다."]'::jsonb, 2, '치매 대상자의 식사 거부 원인을 이해하고 적절한 도움을 제공하는 방법을 인식하도록 한다.', NULL, '{"1": "꾸짖거나 잔소리를 하여 음식을 먹게 한다는 것은 대상자의 심리적 상태를 악화시킬 수 있다. \n[정답]", "2": "대상자 몸의 상태를 충분히 살펴보는 것은 올바른 접근법이다.", "3": "가볍게 먹을 수 있는 컵밥 등을 준비해주는 것도 좋은 방법이지만, 신체 상태를 우선적으로 고려해야 한다.", "4": "다른일에 지나치게 몰두하고 있다면 그대로 둬서는 안 된다. 대상자가 식사를 해야 하므로 주의를 환기시켜야 한다.", "5": "기분전환을 할 수 있도록 산책 후 식사하게 하는 것은 좋은 방법이다. 그러나 우선은 몸 상태 체크가 필요하다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억 및 사고에 영향을 주는 질환", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và suy nghĩ"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "치료 또는 돌봄을 받는 사람", "def_vi": "Người nhận điều trị hoặc chăm sóc"}, {"term_ko": "음식", "term_vi": "Thức ăn", "def_ko": "사람의 생명을 유지하는 물질", "def_vi": "Chất duy trì sự sống của con người"}, {"term_ko": "양식", "term_vi": "Cách ăn", "def_ko": "먹는 방법", "def_vi": "Cách thức ăn"}, {"term_ko": "심리적", "term_vi": "Tâm lý", "def_ko": "정신적인 상태와 관련된", "def_vi": "Liên quan đến trạng thái tinh thần"}, {"term_ko": "신체", "term_vi": "Cơ thể", "def_ko": "사람의 신체적 상태", "def_vi": "Tình trạng thể chất của con người"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (436, '12', '치매 대상자가 제공된 음식을 못 먹고 쳐다 보고만 있을 때 돕는 방법으로 옳은 것은?', '["요양보호사가 직접 입에 넣어준다.", "계속 거부하면 음식을 치운다고 말한다.", "식사하는 방법을 순서대로 가르쳐준다.", "식사를 거르면 건강에 해롭다고 설명한다.", "스스로 먹을 때까지 음식을 그대로 둔다."]'::jsonb, 3, '치매 대상자의 식사 지원 방법에 대한 이해를 묻고 있습니다.', NULL, '{"1": "요양보호사가 직접 입에 넣어주는 것은 대상자의 자존감을 해칠 수 있습니다.\n[정답]", "3": "식사하는 방법을 순서대로 가르쳐주는 것은 올바른 지원 방법입니다.", "2": "계속 거부하면 음식을 치운다고 말하는 것은 강압적일 수 있습니다.", "4": "식사를 거르면 건강에 해롭다고 설명하는 것은 대상자가 받아들이기 어려울 수 있습니다.", "5": "스스로 먹을 때까지 음식을 그대로 둬서는 적절한 지원이 아닙니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력 및 사고 능력이 감소하는 질병", "def_vi": "Bệnh làm giảm khả năng ghi nhớ và tư duy"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "지원", "term_vi": "Hỗ trợ", "def_ko": "도움을 주는 행동", "def_vi": "Hành động giúp đỡ"}, {"term_ko": "자존감", "term_vi": "Lòng tự trọng", "def_ko": "자신의 가치를 아는 감정", "def_vi": "Cảm giác biết giá trị bản thân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (435, '12', '치매 대상자가 방금 식사한 것을 잊어버리고 밥을 또 달라고 할 때 돕는 방법으로 옳은 것은?', '["요구할 때마다 좋아하는 음식을 준다.", "먹고 난 빈 식기를 그대로 둔다.", "다음 식사 시간까지 기다리라고 한다.", "자꾸 먹으면 살이 찐다고 설득한다.", "다른 요양보호사를 데려와 확인시켜준다."]'::jsonb, 2, '치매 환자의 식사 인지 문제에 대한 해결 방안을 묻고 있다.', NULL, '{"1": "요구할 때마다 좋아하는 음식을 준다. - 이 방법은 치매 환자에게 혼란을 줄 수 있다.\n[정답]", "2": "먹고 난 빈 식기를 그대로 둔다. - 빈 식기를 두는 것은 이미 식사가 이루어졌음을 명확히 인식하게 도와준다.", "3": "다음 식사 시간까지 기다리라고 한다. - 이 방법은 환자에게 스트레스를 줄 수 있다.", "4": "자꾸 먹으면 살이 찐다고 설득한다. - 치매 환자는 이러한 논리를 이해하기 어려울 수 있다.", "5": "다른 요양보호사를 데려와 확인시켜준다. - 이 방법은 환자에게 혼란을 줄 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 인지 기능이 저하되는 질환", "def_vi": "Là căn bệnh suy giảm trí nhớ và khả năng nhận thức"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 섭취하는 행위", "def_vi": "Hành động tiêu thụ thực phẩm"}, {"term_ko": "빈", "term_vi": "Trống", "def_ko": "내용물이 없는 상태", "def_vi": "Tình trạng không có nội dung"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인을 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (434, '12', '치매 대상자가 비누를 입에 넣으려 하며 빼앗기지 않으려고 할 때 돕는 방법으로 옳은 것은?', '["비누를 쥔 손을 꼬집어 빼앗는다.", "먹으면 안 된다고 설득한다.", "대상자가 좋아하는 호떡을 주며 비누와 바꾼다.", "비누라고 설명하면 냄새를 맡아 보게 한다.", "음식물인지 아닌지 잘 구분해 보라고 말한다."]'::jsonb, 3, '치매 대상자의 안전을 고려한 대처 방법을 이해하는 것이다.', NULL, '{"1": "비누를 쥔 손을 꼬집어 빼앗는다. - 폭력적인 방법으로 해서는 안 된다.\n[정답]", "3": "대상자가 좋아하는 호떡을 주며 비누와 바꾼다. - 대상자의 기분을 고려한 긍정적인 접근 방법이다.", "2": "먹으면 안 된다고 설득한다. - 설득이 잘 안 되는 경우가 많으므로 효과적이지 않다.", "4": "비누라고 설명하면 냄새를 맡아 보게 한다. - 설명은 효과적이지 않을 수 있다.", "5": "음식물인지 아닌지 잘 구분해 보라고 말한다. - 혼란을 줄 수 있는 방법이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 사고 능력이 감소하는 질환", "def_vi": "Bệnh mà khả năng ghi nhớ và tư duy giảm sút"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "도움을 필요로 하는 사람", "def_vi": "Người cần sự giúp đỡ"}, {"term_ko": "비누", "term_vi": "Xà phòng", "def_ko": "세정제로 사용되는 물질", "def_vi": "Chất được sử dụng để tẩy rửa"}, {"term_ko": "호떡", "term_vi": "Bánh hồ tịch", "def_ko": "한국의 전통 간식", "def_vi": "Đặc sản truyền thống của Hàn Quốc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (433, '12', '치매 대상자가 밤에 자지 않고 베개 솜을 뜯어 먹고 있을 때 돕는 방법으로 옳은 것은?', '["손모아장갑을 끼고 자게 한다.", "처방받은 수면제를 먹여 재운다.", "솜을 먹으면 안 된다고 설명한다.", "가족에게 새 베개를 사오게 한다.", "솜 대신 두꺼운 수건을 넣어둔다."]'::jsonb, 5, '치매 환자가 안전하게 수면을 취하도록 돕기 위한 방법을 평가하는 문제입니다.', NULL, '{"1": "손모아장갑을 끼고 자게 한다. - 안전을 고려했지만, 실제로 수면을 취하게 하는 방법이 아닙니다.\n[정답]", "5": "솜 대신 두꺼운 수건을 넣어둔다. - 치매 대상자가 베개 솜을 뜯어먹지 않도록 안전한 대체물을 제공하는 방법입니다.", "3": "솜을 먹으면 안 된다고 설명한다. - 치매 환자는 이해하기 어려워 설명이 효과적이지 않을 수 있습니다.", "4": "가족에게 새 베개를 사오게 한다. - 단순히 새로운 베개를 제공하는 것은 문제 해결에 직접적인 도움이 되지 않습니다.", "2": "처방받은 수면제를 먹여 재운다. - 약물 사용은 의사 처방이 필요하며, 수면제를 사용하는 것이 적절하지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억력과 인지 기능에 영향을 미치는 질병", "def_vi": "Bệnh ảnh hưởng đến trí nhớ và chức năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (432, '12', '과식하는 치매 대상자의 일상생활을 돕는 방법으로 옳은 것은?', '["칼로리가 높은 음식을 제공한다.", "체중계의 체중을 직접 확인시킨다.", "금방 식사했음을 반복해서 알려준다.", "기분을 다른 곳으로 돌릴 수 있도록 산책을 유도한다.", "포만감이 오래 가도록 한꺼번에 많은 음식을 제공한다."]'::jsonb, 4, '치매 대상자의 일상생활을 어떻게 지원해야 하는지를 질문하고 있다.', NULL, '{"1": "칼로리가 높은 음식을 제공하면 과식을 조장할 수 있다.\n[정답]", "4": "기분을 다른 곳으로 돌릴 수 있도록 산책을 유도하는 것은 치매 대상자가 과식하지 않도록 도와줄 수 있다.", "2": "체중계의 체중을 직접 확인시켜도 치매 대상자가 인지하지 못할 수 있다.", "3": "금방 식사했음을 반복해서 알려주는 것은 혼동을 줄 수 있다.", "5": "포만감이 오래 가도록 한꺼번에 많은 음식을 제공하는 것은 오히려 문제를 심화시킬 수 있다."}'::jsonb, '[{"term_ko": "과식", "term_vi": "Ăn quá nhiều", "def_ko": "많이 먹는 것", "def_vi": "Ăn quá nhiều"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (431, '12', '치매 대상자가 자신이 즐겨 입는 꽃무늬 원피스를 접었다 폈다 하느라 잠을 자지 않을 때 돕는 방법으로 옳은 것은?', '["처방받은 수면제 제공한다.", "원피스를 입고 자자며 다독인다.", "그런 행동을 하는 이유를 묻는다.", "세탁해 주겠다며 원피스를 가져간다.", "수건으로 바꾸어 주고 계속하게 한다."]'::jsonb, 2, '치매 대상자의 행동을 이해하고 적절한 반응을 할 수 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "처방받은 수면제 제공은 약물 의존을 초래할 수 있어 권장되지 않습니다.\n[정답]", "2": "원피스를 입고 자자며 다독이는 방법은 치매 대상자의 안정과 위안이 될 수 있습니다.", "3": "그런 행동을 하는 이유를 물어보는 것은 불안감을 증가시킬 수 있습니다.", "4": "세탁해 주겠다며 원피스를 가져가는 것은 대상자의 정서적 불안을 유발할 수 있습니다.", "5": "수건으로 바꾸어 주고 계속하게 하는 것은 원피스에 대한 집착을 더욱 심화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 인지기능의 저하가 나타나는 질환", "def_vi": "Bệnh suy giảm trí nhớ và chức năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (430, '12', '시설 치매 대상자가 요양보호사를 따라다니며 다음과 같이 반복적으로 질문할 때 요양보호사의 적절한 반응으로 옳은 것은?• 대상자 : 내가 고향에 갈 날이 얼마나 남았어요?• 요양보호사 : ________________________________________________', '["\"어르신은 며칠 남으신 것 같으세요?\"", "\"저와 달력을 보면서 확인해 봐요.\"", "\"아까도 알려드렸잖아요. 몇 번째에요?\"", "\"고향에 가셔도 아는 분이 없을 거에요.\"", "\"저는 어르신과 같이 있고 싶은데 고향에 가고 싶으시군요.\""]'::jsonb, 2, '치매 환자와의 효과적인 의사소통 방식을 평가하기 위한 문제입니다.', NULL, '{"1": "''어르신은 며칠 남으신 것 같으세요?''는 환자의 질문에 대한 답변이 아니라 되묻기 때문에 적절하지 않습니다.\n[정답]", "2": "''저와 달력을 보면서 확인해 봐요.''는 환자에게 시각적인 도움을 주어 기억을 도와주는 좋은 반응입니다.", "3": "''아까도 알려드렸잖아요. 몇 번째에요?''는 환자를 혼란스럽게 할 수 있는 반응입니다.", "4": "''고향에 가셔도 아는 분이 없을 거에요.''는 부정적인 반응으로서 적절하지 않습니다.", "5": "''저는 어르신과 같이 있고 싶은데 고향에 가고 싶으시군요.''는 요양보호사의 감정을 드러내지만, 환자의 질문에 대한 직접적인 답변은 아닙니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억과 사고에 능력이 줄어드는 질환", "def_vi": "Bệnh làm giảm khả năng ghi nhớ và suy nghĩ"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc người già", "def_ko": "노인을 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc người cao tuổi"}, {"term_ko": "고향", "term_vi": "Quê hương", "def_ko": "태어난 곳, 자란 곳", "def_vi": "Nơi sinh ra, nơi lớn lên"}, {"term_ko": "달력", "term_vi": "Lịch", "def_ko": "날짜를 기록한 종이", "def_vi": "Giấy ghi lại ngày tháng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (429, '12', '먼저 사망한 아들이 있는 치매 대상자가 오늘따라 아들이 왜 이렇게 안 오지?라며 반복적으로 물으며 밖으로 나가려고 할 때 돕기 방법으로 옳은 것은?', '["아들을 기다리는 이유를 물어본다.", "조용해질 때까지 하던 일을 모른 척한다.", "아들이 먼저 사망했다는 사실을 알려준다.", "좋아하는 가요 프로그램을 함께 보자고 한다.", "아들이 내일이면 올 거라며 기다리지 말라고 설득한다."]'::jsonb, 4, NULL, NULL, NULL, NULL);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (428, '12', '재가 치매 대상자의 부엌을 안전하게 관리하는 방법으로 옳은 것은?', '["채소 모양의 자석은 냉장고에 붙인다.", "유리그릇은 보관장에 넣고 자물쇠로 채워둔다.", "부엌과 거실이 구분되도록 문턱을 설치한다.", "노출된 온수파이프는 주방용 랩으로 감싸둔다.", "음식물이 담긴 쓰레기봉투는 부엌 안쪽에 둔다."]'::jsonb, 2, '부엌의 안전한 관리 방안을 알아보는 질문이다.', NULL, '{"1": "채소 모양의 자석은 장식용일 뿐, 안전과는 관련이 없다.\n[정답]", "2": "유리그릇은 위험할 수 있으므로 안전하게 잠구는 것이 옳다.", "3": "문턱을 설치하는 것은 안전성을 높일 수 있지만, 치매 대상자에게 불편할 수 있다.", "4": "노출된 온수파이프는 감싸는 것이 좋지만, 주방용 랩은 안전한 방법이 아닐 수 있다.", "5": "음식물이 담긴 쓰레기봉투는 부엌 밖에 두어야 한다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Chăm sóc tại nhà", "def_ko": "가정에서 요양 보호를 받는 것", "def_vi": "Nhận sự chăm sóc trong gia đình"}, {"term_ko": "치매", "term_vi": "Chứng mất trí", "def_ko": "기억력과 인지기능이 감소하는 질병", "def_vi": "Bệnh giảm trí nhớ và khả năng nhận thức"}, {"term_ko": "부엌", "term_vi": "Nhà bếp", "def_ko": "음식 준비와 조리를 하는 장소", "def_vi": "Nơi chuẩn bị và nấu nướng thực phẩm"}, {"term_ko": "자물쇠", "term_vi": "Khóa", "def_ko": "잠기는 장치", "def_vi": "Thiết bị đóng lại"}, {"term_ko": "온수파이프", "term_vi": "Ống nước nóng", "def_ko": "핫워터 파이프", "def_vi": "Ống nước nóng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (427, '12', '거울만 보면 욕설을 하는 치매 대상자를 돕는 방법으로 옳은 것은?', '["대상자와 함께 거울을 보며 욕을 한다.", "집안의 거울에 덮개를 씌워 놓는다.", "무슨 이야기를 하는지 자세하게 들어본다.", "거울 속에 있는 사람이 누구인지 물어본다.", "흥분이 가라앉을 때까지 기다렸다가 욕하는 이유를 물어본다."]'::jsonb, 2, '치매 대상자가 거울을 보고 욕설을 하는 상황에서 어떻게 대처할지를 묻는 문제입니다.', NULL, '{"1": "대상자와 함께 거울을 보며 욕을 한다: 이 방법은 적절하지 않습니다. 대상자의 행동을 부추기는 결과를 초래할 수 있습니다.\n[정답]", "2": "집안의 거울에 덮개를 씌워 놓는다: 이 방법은 대상자가 거울을 보지 않게 하여 욕설을 방지하는 효과가 있습니다.", "3": "무슨 이야기를 하는지 자세하게 들어본다: 이야기를 듣는 것은 중요하지만, 욕설에 대한 즉각적인 대처에는 도움이 되지 않습니다.", "4": "거울 속에 있는 사람이 누구인지 물어본다: 대상자의 불안감을 조정할 수 있지만, 더 이상 욕설을 하는 것을 막는 것은 아닙니다.", "5": "흥분이 가라앉을 때까지 기다렸다가 욕하는 이유를 물어본다: 이 방법은 상황을 진정시키는 데는 시간이 걸릴 수 있습니다."}'::jsonb, '[{"term_ko": "거울", "term_vi": "대상자", "def_ko": "거울(giấy gương)", "def_vi": "대상자(bệnh nhân)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (426, '12', '시설치매 대상자를 위해 화장실의 환경을 안전하게 조성하는 방법으로 옳은 것은?', '["화장실 가는 복도에 화분을 둔다.", "대상자의 눈높이에 맞추어 ''화장실''표시를 한다.", "프라이버시를 위해 화장실 안에 잠금장치를 설치한다.", "펌프식 세정제보다 고형의 비누를 이용한다.", "세면대 위에 큰 거울을 설치하여 자신의 모습을 보게 한다."]'::jsonb, 2, '시설치매 대상자의 화장실 사용을 안전하게 하기 위한 방법을 파악하는 것입니다.', NULL, '{"1": "화분은 장애물로 작용할 수 있어 안전에 좋지 않습니다.\n[정답]", "2": "눈높이에 맞춘 표시는 대상자가 화장실을 쉽게 인식하는 데 도움이 됩니다.", "3": "잠금장치는 설치할 수 있지만, 긴급 상황에서의 접근을 방해할 수 있으므로 신중해야 합니다.", "4": "고형 비누는 세정에 있어 더욱 위생적이지 않을 수 있으며, 펌프식 세정제가 더 안전합니다.", "5": "큰 거울은 혼란을 줄 수 있어 권장되지 않습니다."}'::jsonb, '[{"term_ko": "시설치매", "term_vi": "Bệnh nhân mất trí", "def_ko": "시설에서 치료받는 치매환자", "def_vi": "bệnh nhân được điều trị tại cơ sở"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (425, '12', '치매 대상자의 안전을 고려하여 방을 관리하는 방법으로 옳은 것은?', '["침대 밑 방바닥에 두꺼운 요를 깔아둔다.", "큰 유리창을 투명하게 하여 밖이 잘 보이게 한다.", "통일감을 주기 위해 난간과 출입구를 같은 색으로 한다.", "다른 사람의 눈에 잘 뛰지 않는 방으로 배정한다.", "난방을 위해 대상자 옆에 난로를 켜둔다."]'::jsonb, 1, '치매 대상자가 안전하게 지낼 수 있는 환경을 조성하는 방법을 묻고 있다.', NULL, '{"1": "방바닥에 두꺼운 요를 깔아두면 넘어짐 사고를 예방할 수 있다.\n[정답]", "2": "큰 유리창을 투명하게 하면 외부를 잘 볼 수 있지만, 외부의 소음이나 자극으로 인해 오히려 불안감을 초래할 수 있다.", "3": "난간과 출입구를 같은 색으로 하는 것은 통일감을 줄 수 있으나, 치매 대상자가 혼란스러울 수 있다.", "4": "다른 사람의 눈에 잘 뛰지 않는 방에 배정하는 것은 고립감을 느끼게 할 수 있어 바람직하지 않다.", "5": "난로를 켜두면 화재의 위험이 있어 안전하지 않다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고 기능의 저하로 인한 질병", "def_vi": "Bệnh gây suy giảm trí nhớ và chức năng tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (424, '12', '치매 대상자의 운동을 돕는 방법으로 옳은 것은?', '["걷는 시간을 서서히 늘린다.", "운동 시간을 매일 다르게 한다.", "산책로는 자주 바꾸어 지루하지 않게 한다.", "다리 운동에서 목 운동으로 진행하게 한다.", "팔다리 관절을 빠르게 움직이며 운동하게 한다."]'::jsonb, 1, '치매 대상자의 운동 치료에 효과적인 방법을 발굴하기 위한 문제입니다.', NULL, '{"1": "걷는 시간을 서서히 늘리는 것은 적절한 방법으로, 치매 대상자가 안전하게 운동을 지속할 수 있도록 돕습니다.\n[정답]", "2": "운동 시간을 매일 다르게 하는 것은 일관성을 줄이므로 바람직하지 않습니다.", "3": "산책로를 자주 바꾸면 대상자가 혼란스러울 수 있어 그다지 좋지 않습니다.", "4": "다리 운동에서 목 운동으로 진행하는 것은 적절한 연결이 아닙니다.", "5": "팔다리 관절을 빠르게 움직이는 것은 치매 대상자에게 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력과 인지 능력이 감소하는 질병", "def_vi": "Bệnh suy giảm trí nhớ và khả năng nhận thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (423, '12', '치매 대상자의 옷 입기를 돕는 방법으로 옳은 것은?', '["색깔이 요란하고 장식이 많은 옷을 선택한다.", "시간이 걸리면 요양보호사가 입혀준다.", "옷 입기를 거부하면 목욕 시간을 이용하여 갈아입힌다.", "단추가 많이 달린 옷을 제공한다.", "자신의 옷이 아니라고 하면 다른 옷을 구입한다."]'::jsonb, 3, '치매 대상자의 옷 입기와 관련하여 적절한 접근법을 이해하는 것이 중요하다.', NULL, '{"1": "색깔이 요란하고 장식이 많은 옷을 선택하는 것은 치매 환자에게 혼란을 줄 수 있어 바람직하지 않다.\n[정답]", "2": "시간이 걸리면 요양보호사가 입혀주는 것은 자율성을 침해할 수 있다.", "3": "옷 입기를 거부하면 목욕 시간을 이용하여 갈아입히는 것은 치매 대상자의 스트레스를 최소화할 수 있는 방법이다.", "4": "단추가 많이 달린 옷은 치매 환자가 입기 힘들 수 있다.", "5": "자신의 옷이 아니라고 하면 다른 옷을 구입하는 것은 개인의 정체성과 감정을 고려하지 않는 방법이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억 및 사고 기능의 저하로 인한 질병", "def_vi": "Bệnh do suy giảm chức năng trí nhớ và tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (422, '12', '목욕을 시키기 위해 치매 대상자의 옷을 벗기려 하자 거칠게 거부할 때 돕는 방법으로 옳은 것은?', '["욕실 내 혼자 머무르게 한다.", "행동을 신속하게 제지한다.", "목욕하기 싫은 이유를 물어본다.", "여러 요양보호사와 함께 목욕을 시킨다.", "목욕을 중지하고 조용한 방에서 쉬게 한다."]'::jsonb, 5, '치매 대상자의 특성을 이해하고, 그들의 감정을 고려하여 목욕을 시키기 위한 적절한 방법을 선택하는 것이 중요하다.', NULL, '{"1": "욕실 내 혼자 머무르게 한다는 것은 치매 대상자의 불안감을 증가시킬 수 있다.\n[정답]", "5": "목욕을 중지하고 조용한 방에서 쉬게 하는 것은 대상자의 스트레스를 줄이고 향후 목욕 시간을 다시 시도할 수 있는 여지를 제공한다.", "2": "행동을 신속하게 제지하는 것은 상황을 악화시킬 수 있다.", "3": "목욕하기 싫은 이유를 물어보는 것은 필요하지만, 이 상황에서는 적절하지 않다.", "4": "여러 요양보호사와 함께 목욕을 시키는 것은 혼란스러움을 야기할 수 있다."}'::jsonb, '[{"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "씻는 것(한국어)", "def_vi": "Rửa"}, {"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억 및 인지 기능의 저하(한국어)", "def_vi": "Sự suy giảm chức năng ghi nhớ và nhận thức"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "치료나 보호를 받는 사람(한국어)", "def_vi": "Người được điều trị hoặc chăm sóc"}, {"term_ko": "거부", "term_vi": "Từ chối", "def_ko": "원하지 않는다고 말하거나 행동하는 것(한국어)", "def_vi": "Nói hoặc hành động nói rằng không muốn"}, {"term_ko": "스트레스", "term_vi": "Căng thẳng", "def_ko": "긴장이나 압박감을 느끼는 상태(한국어)", "def_vi": "Trạng thái cảm thấy căng thẳng hoặc áp lực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (421, '12', '치매 대상자를 목욕시키는 방법으로 옳은 것은?', '["목욕을 싫어해도 개인위생을 위해 억지로 시킨다.", "부드럽게 유도하거나 시간을 미루어 다시 시도한다.", "나이가 들면 피부의 탄력을 잃기 때문에 통목욕을 자주 한다.", "개인위생을 위해 목욕 시간은 1시간 이상 꼼꼼히 한다.", "지루하지 않게 목욕 과정을 길고 복잡하게 한다."]'::jsonb, 2, '치매 대상자를 대상으로 한 목욕 방법에 대한 이해도를 확인하기 위함입니다.', NULL, '{"1": "목욕을 억지로 시키는 것은 부정적인 경험을 줄 수 있습니다.\n[정답]", "2": "부드럽게 유도하거나 시간을 미루는 것은 치매 환자의 심리적 안정을 돕습니다.", "3": "피부의 탄력과 목욕 빈도는 나이와 관계없이 개별적으로 다룬다.", "4": "목욕 시간은 개인의 상태에 맞추어 적절히 조정해야 합니다.", "5": "긴 목욕 과정은 오히려 환자에게 스트레스를 유발할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억과 사고 기능의 감소로 인한 상태", "def_vi": "Một trạng thái giảm khả năng ghi nhớ và tư duy"}, {"term_ko": "부드럽게", "term_vi": "Nhẹ nhàng", "def_ko": "부드러운 방법으로", "def_vi": "Bằng cách nhẹ nhàng"}, {"term_ko": "유도하다", "term_vi": "Đưa ra hướng dẫn", "def_ko": "어떤 방향으로 이끌다", "def_vi": "Hướng dẫn một cách chủ động"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "청결을 위한 물과 비누 활용", "def_vi": "Sử dụng nước và xà phòng để giữ vệ sinh"}, {"term_ko": "개인위생", "term_vi": "Vệ sinh cá nhân", "def_ko": "개인의 청결 유지", "def_vi": "Duy trì sự sạch sẽ của cơ thể cá nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (420, '12', '치매 대상자의 부적절한 배설행동에 대한 돕기 방법으로 옳은 것은?', '["배변시간에는 대상자 혼자 있도록 한다.", "반복하여 화장실에 갈 경우 수분섭취량을 줄인다.", "대소변을 손으로 만지더라도 아무렇지 않은 것처럼 뒤처리를 한다.", "화장실과 먼 곳에 방을 배치한다.", "대소변처리가 쉽도록 화장실 환경을 바꾸어본다."]'::jsonb, 3, '치매 대상자에게 적절한 배설 도와주기와 그 방법을 이해하는 것.', NULL, '{"1": "대상자가 혼자 있도록 하면 안전 문제와 불안감을 초래할 수 있다.\n[정답]", "3": "대소변을 손으로 만지더라도 이를 수용하고 정상적인 반응으로 대처한다.", "2": "수분섭취량을 줄이는 것은 건강에 악영향을 미칠 수 있다.", "4": "화장실과 먼 거리에 방을 배치하면 접근성이 떨어진다.", "5": "화장실 환경을 개선하는 것은 긍정적인 영향을 미친다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억과 사고 능력이 저하되는 질환", "def_vi": "Bệnh giảm khả năng nhớ và suy nghĩ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (419, '12', '다음과 같은 상황이 있을 때 요양보호사의 돕는 방법으로 옳은 것은?', '["시설장에게 즉시 보고한다.", "상황을 기록하고 기저귀를 채운다.", "수치심을 유발하지 않게 모른 척한다.", "뒤처리 후 더러워진 옷을 갈아입힌다.", "재가서비스가 어려우므로 시설 입소를 권한다."]'::jsonb, 4, '요양보호사가 환자에게 적절하고 신속한 도움을 제공하는 방법에 대한 이해를 평가하려는 의도입니다.', NULL, '{"1": "상황에 따라 즉시 보고해야 할 경우도 있지만, 이 경우 환자의 긴급한 도움이 우선입니다.\n[정답]", "2": "단순히 상황을 기록하는 것으로는 환자에게 필요한 도움을 주지 못합니다.", "3": "수치심을 유발하지 않게 하는 것이 중요하지만, 모른 척하는 것은 환자에게 도움이 되지 않습니다.", "4": "뒤처리를 통해 청결을 유지하고 환자의 편안함을 보장하는 것이 중요한 대응입니다.", "5": "상황과 필요에 따라 결정해야 하며, 즉각적인 도움을 제공하는 것이 우선입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인을 돌보는 전문 직업", "def_vi": "Nghề chuyên chăm sóc người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (418, '12', '스스로 음식을 먹을 수 있는 치매 대상자의 식사를 돕는 방법으로 옳은 것은?', '["투명한 유리 제품에 음식을 보기 좋게 담는다.", "식전에 사탕을 제공하여 식욕을 돋운다.", "약간 무거운 숟가락을 쥐어준다.", "소금이나 간장은 식탁 위에 두고 사용하게 한다.", "식사 시간에 졸려 하더라도 제시간에 먹게 한다."]'::jsonb, 3, '치매 대상자의 자립적인 식사 능력을 지원하는 방법을 이해하고 적용하는 것이 중요하다.', NULL, '{"1": "투명한 유리 제품에 음식을 보기 좋게 담는 것은 시각적 자극을 제공해 도움이 될 수 있다. 그러나 직접적인 도움과는 관련이 없다.\n[정답]", "2": "식전에 사탕을 제공하여 식욕을 돋우는 것은 도움이 될 수 있지만 의도한 식사 도움의 방법이 아니다.", "3": "약간 무거운 숟가락을 쥐어주는 것은 그들이 스스로 음식을 먹는 데 필요한 힘을 제공하여 유용하다.", "4": "소금이나 간장은 식탁 위에 두고 사용하게 하는 것이 자율성을 부여하지만, 이 방법은 직접적으로 식사를 돕는 것이 아니다.", "5": "식사 시간에 졸려 하더라도 제시간에 먹게 하는 것은 식사의 규칙성을 제공하지만, 스스로 먹는 것을 돕는 것이 아니라 강요하는 행위가 될 수 있다."}'::jsonb, '[{"term_ko": "스스로", "term_vi": null, "def_ko": "스스로(자기 자신으로부터)", "def_vi": null}, {"term_ko": "음식", "term_vi": null, "def_ko": "음식(đồ ăn)", "def_vi": null}, {"term_ko": "치매", "term_vi": null, "def_ko": "치매(bệnh sa sút trí tuệ)", "def_vi": null}, {"term_ko": "대상자", "term_vi": null, "def_ko": "대상자(nhân vật)", "def_vi": null}, {"term_ko": "식사", "term_vi": null, "def_ko": "식사(bữa ăn)", "def_vi": null}, {"term_ko": "도움", "term_vi": null, "def_ko": "도움(hỗ trợ)", "def_vi": null}, {"term_ko": "방법", "term_vi": null, "def_ko": "방법(phương pháp)", "def_vi": null}, {"term_ko": "소금", "term_vi": null, "def_ko": "소금(muối)", "def_vi": null}, {"term_ko": "간장", "term_vi": null, "def_ko": "간장(xì dầu)", "def_vi": null}, {"term_ko": "졸리다", "term_vi": null, "def_ko": "졸리다(buồn ngủ)", "def_vi": null}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (417, '12', '치매 대상자의 식사를 돕는 방법은?', '["휴대전화로 영상을 보여주며 식사한다.", "음식을 부드럽게 조리하여 제공한다.", "간장을 이용해 스스로 간을 맞추게 한다.", "가벼운 숟가락과 젓가락을 사용하게 한다.", "처방된 비타민은 음식에 섞어서 먹게 한다."]'::jsonb, 2, '치매 대상자의 식사 지원 방법을 이해하고 평가하기 위함입니다.', NULL, '{"1": "휴대전화로 영상을 보여주는 것은 주의 집중을 해칠 수 있어 적절하지 않습니다.\n[정답]", "2": "음식을 부드럽게 조리하여 제공하는 것은 치매 환자의 씹는 능력을 고려한 좋은 방법입니다.", "3": "간장을 스스로 간을 맞추게 하는 것은 혼란을 초래할 수 있어 좋지 않습니다.", "4": "가벼운 숟가락과 젓가락을 사용하는 것은 도와줄 수 있으나, 직접적으로 식사 지원과는 관련이 적습니다.", "5": "처방된 비타민을 음식에 섞는 것은 알 수 없으므로 주의가 필요합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Chứng mất trí", "def_ko": "기억력과 사고 능력이 감소하는 상태", "def_vi": "Tình trạng giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn uống"}, {"term_ko": "부드럽게", "term_vi": "Mềm", "def_ko": "아프지 않게, 쉽게 씹을 수 있게 하는 것", "def_vi": "Không đau, dễ nhai"}, {"term_ko": "간장", "term_vi": "Nước tương", "def_ko": "한식에서 사용되는 간단한 양념", "def_vi": "Gia vị đơn giản trong ẩm thực Hàn Quốc"}, {"term_ko": "비타민", "term_vi": "Vitamin", "def_ko": "몸에 필요한 영양소", "def_vi": "Chất dinh dưỡng cần thiết cho cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (416, '12', '최근 시설에 입소한 치매 대상자가 자신의 방을 청소하겠다고 할 때 돕는 방법으로 옳은 것은?', '["청소기 사용법을 자세하게 설명한다.", "담당 청소 직원이 한다고 설명한다.", "무리하지 않는 범위 내에서 청소하게 한다.", "당분간 침상에서 절대 안정을 취하라고 말한다.", "청소는 낙상 위험이 있으므로 하지 말라고 한다."]'::jsonb, 3, '치매 대상자의 자율성을 존중하면서 안전성을 고려한 청소 지원 방법을 판단하는 문제이다.', NULL, '{"1": "청소기 사용법을 자세하게 설명하면 대상자가 혼란스러워할 수 있다.\n[정답]", "3": "무리하지 않는 범위 내에서 청소하게 함으로써 자율성을 존중하고 안전을 확보할 수 있다.", "2": "담당 청소 직원이 한다고 설명하면 대상자의 자율성을 침해할 수 있다.", "4": "당분간 침상에서 절대 안정을 취하라고 하면 청소를 할 수 없게 된다.", "5": "청소는 낙상 위험이 있으므로 하지 말라고 하면 대상자의 자율성을 부정하는 것이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고 능력에 문제가 생기는 질환", "def_vi": "Bệnh có vấn đề về trí nhớ và khả năng suy nghĩ"}, {"term_ko": "청소", "term_vi": "Dọn dẹp", "def_ko": "공간을 깨끗하게 만들기 위한 작업", "def_vi": "Hoạt động làm sạch không gian"}, {"term_ko": "자율성", "term_vi": "Tự chủ", "def_ko": "스스로 결정하고 행동할 수 있는 능력", "def_vi": "Khả năng tự quyết định và hành động"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태", "def_vi": "Trạng thái không có nguy hiểm"}, {"term_ko": "낙상", "term_vi": "Ngã", "def_ko": "넘어짐", "def_vi": "Rơi xuống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (415, '12', '치매 대상자의 일상생활 지원의 목적으로 옳은 것은?', '["대상자의 상태를 정확히 파악한다.", "정신기능 활동을 위해 새로운 학습활동을 한다.", "현재의 신체기능을 유지한다.", "새로운 환경을 조성한다.", "새로운 일을 배우는 능력을 기른다."]'::jsonb, 1, '치매 대상자의 일상생활 지원에서 가장 중요한 목적은 그들의 상태를 정확히 이해하고 지원하는 것이다.', NULL, '{"1": "대상자의 상태를 정확히 파악한다. [정답] 이는 치매 대상자가 필요한 지원을 적절하게 제공하기 위한 기초가 된다.", "2": "정신기능 활동을 위해 새로운 학습활동을 한다. 이는 치매 환자에게 도전이 될 수 있으나 기본적으로 상태 파악이 우선이다.", "3": "현재의 신체기능을 유지한다. 중요하지만, 상태 파악이 선행되어야 한다.", "4": "새로운 환경을 조성한다. 환경 변화는 스트레스를 유발할 수 있으므로 신중해야 한다.", "5": "새로운 일을 배우는 능력을 기른다. 이는 목표가 아닐 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력, 사고, 행동의 기능에 장애가 생기는 질병", "def_vi": "Bệnh làm suy giảm chức năng trí nhớ, tư duy, và hành vi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (414, '12', '처방약이 변경된 후 대상자가 초조한 듯 집안을 왔다 갔다 하고 있다. 요양보호사의 돕는 방법으로 옳은 것은?', '["약물의 용량을 늘려서 제공한다.", "이전에 복용하던 치매 약을 준다.", "증상을 메모하여 병원 갈 때 가지고 간다.", "대상자에게 부작용의 증상을 물어본다.", "약이 바뀌면 흔하게 나타나는 증상이라고 말한다."]'::jsonb, 3, '변경된 처방약으로 인한 대상자의 불안감을 이해하고, 요양보호사가 어떻게 돕는 것이 올바른지 평가하는 질문입니다.', NULL, '{"1": "약물의 용량을 늘리는 것은 잘못된 방법입니다.\n[정답]", "3": "증상을 메모하고 병원에 갈 때 가지고 가는 것은 의사와의 소통에 도움이 됩니다.", "2": "이전에 복용하던 약을 주는 것은 치료에 도움이 되지 않습니다.", "4": "대상자에게 부작용의 증상을 물어보는 것은 필요하지만, 질문을 통해 바로 해결하지는 못합니다.", "5": "번화한 증상이 흔하다고 말하는 것은 대상자의 불안감을 경감시키지 못할 수 있습니다."}'::jsonb, '[{"term_ko": "처방약", "term_vi": "Thuốc theo chỉ định", "def_ko": "의사의 지시에 따라 환자가 복용하는 약", "def_vi": "Thuốc mà bệnh nhân sử dụng theo chỉ dẫn của bác sĩ"}, {"term_ko": "초조한", "term_vi": "Lo âu", "def_ko": "불안하거나 긴장하거나 차분하지 않은 상태", "def_vi": "Tình trạng không yên tâm hoặc căng thẳng"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질환이나 상태의 나타남", "def_vi": "Biểu hiện của bệnh tật hoặc trạng thái"}, {"term_ko": "부작용", "term_vi": "Tác dụng phụ", "def_ko": "약물이나 치료에 의해 나타나는 원치 않는 증상", "def_vi": "Các triệu chứng không mong muốn xuất hiện do thuốc hoặc điều trị"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (413, '12', '치매 대상자의 약물 복용을 돕는 방법으로 옳은 것은?', '["인지개선제는 병의 완치를 위해 투여한다.", "약물을 복용한 후 침상에서 절대 안정시킨다.", "증상의 변화에 따라 약의 양을 조절한다.", "약물 부작용이 나타나면 메모하여 병원 진료 시 알린다.", "복용량을 줄이고자 할 때는 기관장의 허락을 받는다."]'::jsonb, 4, '치매 환자의 약물 관리와 복용의 중요성을 이해하도록 하기 위함입니다.', NULL, '{"1": "인지개선제는 병의 완치를 위해 투여하는 것이 아니라 증상을 완화하기 위해 사용됩니다.\n[정답]", "4": "약물 부작용이 나타나면 반드시 메모하여 병원 진료 시 의사에게 알리는 것이 중요합니다.", "2": "약물을 복용한 후 침상에서 절대 안정시키는 것은 비효율적이며, 오히려 활동을 권장할 수 있습니다.", "3": "증상의 변화에 따라 약의 양을 조절하는 것은 전문의의 판단이 필요하므로, 독단적으로 변경해서는 안 됩니다.", "5": "복용량을 줄이고자 할 때는 기관장의 허락을 받아야 하는 것이 아니라 전문의와 상담 후 결정해야 합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "질병(한국어)", "def_vi": "Bệnh gây mất trí nhớ(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (412, '12', '치매 대상자의 병원 방문을 도울 때 의사소통하는 방법으로 옳은 것은?', '["대상자 스스로가 치매 대상자임을 인식시킨다.", "요양보호사가 동행한다고 말해주며 안심시킨다.", "대상자가 병원 방문 이유를 알고 있는지 확인한다.", "병원에서 검사 후 진료를 받고 약을 탈 것이라고 설명한다.", "치매의 정도가 심해졌을 수도 있다고 분명하게 말해둔다."]'::jsonb, 2, '치매 대상자의 병원 방문에 도움을 주기 위한 효과적인 의사소통 방법을 평가하는 문제입니다.', NULL, '{"1": "대상자가 스스로 치매임을 인식하는 것은 어렵기 때문에 효과적이지 않습니다.\n[정답]", "2": "요양보호사가 동행한다고 말해주며 안심시키는 것이 가장 적절한 방법입니다.", "3": "병원 방문 이유를 확인하는 것은 중요하지만 긴장감이 높아질 수 있습니다.", "4": "병원에서 검사 후 진료 및 약을 탈 것이라고 설명하는 것은 필요하지만, 치매 대상자에게는 복잡할 수 있습니다.", "5": "치매의 정도가 심해질 수도 있다고 말하는 것은 불안감을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력과 인지 기능의 감소가 있는 상태", "def_vi": "Tình trạng suy giảm trí nhớ và chức năng nhận thức"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "치료를 받는 환자", "def_vi": "Bệnh nhân nhận điều trị"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인이나 장애인을 도와주는 사람", "def_vi": "Người hỗ trợ người già hoặc người khuyết tật"}, {"term_ko": "병원", "term_vi": "Bệnh viện", "def_ko": "환자가 치료를 받는 장소", "def_vi": "Nơi bệnh nhân nhận điều trị"}, {"term_ko": "정신적 지지", "term_vi": "Hỗ trợ tinh thần", "def_ko": "심리적인 도움", "def_vi": "Sự giúp đỡ về tâm lý"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (411, '11', '치매노인이 생활하는데 안전한 주거 환경으로 옳은 것은?', '["깔끔한 환경을 위해 공간 이름표 등을 제거하여 혼란을 줄인다.", "망상 및 배회를 줄이기 위해 창문이 없는 공간에서 생활한다.", "낙상예방을 위해 요양보호사들이 일상생활 활동을 대신한다.", "새소리, 음식 끓는 소리 등의 환경적 자극은 제한한다.", "불쾌한 악취 등의 냄새는 조정한다."]'::jsonb, 5, '치매노인의 안전한 주거 환경에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "공간 이름표 등을 제거하면 오히려 혼란을 초래할 수 있으며, 치매환자의 기억에 도움을 줄 수 있습니다.\n[정답]", "5": "불쾌한 악취 등의 냄새를 조정하는 것은 치매환자의 편안함과 안전을 위한 중요한 조치입니다.", "2": "창문이 없는 공간은 치매환자에게 오히려 불안과 혼란을 줄 수 있습니다.", "3": "요양보호사가 모든 활동을 대신하는 것은 환자의 자립성을 감소시킬 수 있습니다.", "4": "환경적 자극을 제한하는 것은 부적절하며, 적절한 자극은 좋습니다."}'::jsonb, '[{"term_ko": "주거 환경", "term_vi": "Môi trường sống", "def_ko": "생활 공간(한국어)", "def_vi": "Không gian sinh hoạt(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (410, '11', '재가대상자가 요구한 물건을 구매했더니 마음에 들지 않는다며 불평을 할 때 대처 방법으로 옳은 것은?', '["해결방안을 시설장과 상의하여 처리한다.", "비슷한 물건이니 그냥 쓰라고 설득한다.", "앞으로 물건 대행은 어렵겠다고 말한다.", "구매한 물건을 대상자와 함께 교환하러 간다.", "원하는 물건은 대상자가 직접 구매하게 한다."]'::jsonb, 4, '재가대상자가 만족하지 못하는 물건에 대한 불만을 어떻게 해결해야 하는지를 평가하기 위한 문제입니다.', NULL, '{"1": "해결방안을 시설장과 상의하여 처리한다.\n시설장과 상의하는 것은 좋은 방법이지만, 즉각적인 대처가 아니라서 직접적인 해결책이 아닙니다.\n[정답]", "4": "구매한 물건을 대상자와 함께 교환하러 간다.\n대상자의 불만을 해결하고, 그들의 의견을 존중하는 방법입니다.", "3": "앞으로 물건 대행은 어렵겠다고 말한다.\n대상자의 요청을 무시하는 것으로, 긍정적인 방법이 아닙니다.", "2": "비슷한 물건이니 그냥 쓰라고 설득한다.\n대상자의 만족도를 고려하지 않는 비효율적인 접근입니다.", "5": "원하는 물건은 대상자가 직접 구매하게 한다.\n대상자의 편의를 고려하지 않는 방법입니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người phục vụ tại nhà", "def_ko": "집에서 돌봄을 받는 대상자", "def_vi": "Người nhận sự chăm sóc tại nhà"}, {"term_ko": "불평", "term_vi": "Phàn nàn", "def_ko": "불만 또는 불만의 표현", "def_vi": "Sự không hài lòng hoặc biểu hiện sự không hài lòng"}, {"term_ko": "교환", "term_vi": "Đổi", "def_ko": "바꾸다", "def_vi": "Thay đổi đồ vật hoặc món hàng"}, {"term_ko": "해결", "term_vi": "Giải quyết", "def_ko": "문제를 없애다", "def_vi": "Loại bỏ vấn đề"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (409, '11', '재가대상자가 요양보호사의 차를 이용하여 외출하고자 할 때 대처방법으로 옳은 것은?', '["외출은 주말에만 할 수 있다고 말한다.", "외출하기 전에 주유비를 미리 청구한다.", "시설장에게 직접 허락을 받아달라고 한다.", "요양보호사의 차를 이용할 수 없다고 말한다.", "요양보호사의 차의 뒷자석에 대상자를 앉혀 이동한다."]'::jsonb, 4, '재가대상자가 요양보호사의 차량을 이용해 외출할 때의 적절한 대처 방법을 묻는 문제입니다.', NULL, '{"1": "외출은 주말에만 할 수 있다고 말한다: 적절하지 않은 답변입니다. 외출은 주말에만 제한되지 않습니다.\n[정답]", "2": "외출하기 전에 주유비를 미리 청구한다: 통상적으로 이런 방식은 사용되지 않아 적절하지 않습니다.", "3": "시설장에게 직접 허락을 받아달라고 한다: 불필요한 절차로, 적절한 방법이 아닙니다.", "4": "요양보호사의 차를 이용할 수 없다고 말한다: 이는 요양보호사가 외출에 대한 관리 책임이 있음을 나타내므로 적절합니다.", "5": "요양보호사의 차의 뒷자석에 대상자를 앉혀 이동한다: 안전을 고려했을 때 적절하지 않은 방법입니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người nhận dịch vụ chăm sóc tại nhà", "def_ko": "집에서 외부의 도움을 받는 사람", "def_vi": "Người nhận sự giúp đỡ từ bên ngoài tại nhà"}, {"term_ko": "외출", "term_vi": "Ra ngoài", "def_ko": "집을 떠나 나가는 것", "def_vi": "Rời khỏi nhà"}, {"term_ko": "주유비", "term_vi": "Chi phí xăng", "def_ko": "차량 연료비", "def_vi": "Chi phí cho nhiên liệu của xe"}, {"term_ko": "시설장", "term_vi": "Giám đốc cơ sở", "def_ko": "시설의 책임자", "def_vi": "Người đứng đầu cơ sở"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (408, '11', '대상자가 진료를 위해 병원을 방문하고자 할 때 동행하는 방법으로 옳은 것은?', '["요양보호사의 일정에 맞게 병원 예약을 정한다.", "보호자의 자가용을 운전하여 이동한다.", "대상자의 귀중품은 소지하고 가게 한다.", "대상자에게 필요한 경비를 미리 확인한다.", "외출 전에 하루 용량의 약을 복용하게 한다."]'::jsonb, 4, '대상자가 병원에 가는 경우에 필요한 사전 준비와 동행 방법을 이해하고 있는지 확인하고자 함.', NULL, '{"1": "요양보호사의 일정에 맞게 병원 예약을 정하는 것은 아니라는 점에서 부적절하다.\n[정답]", "4": "대상자에게 필요한 경비를 미리 확인하는 것은 병원 방문에 필수적인 준비 사항이므로 옳다.", "2": "보호자의 자가용을 운전하여 이동하는 것이 꼭 필요한 방법은 아니다.", "3": "대상자의 귀중품은 소지하고 가게 하는 것은 안전을 위해 피하는 것이 좋다.", "5": "외출 전에 하루 용량의 약을 복용하게 하는 것은 적절한 시점이 아닐 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (407, '11', '거동이 불편한 재가 서비스 대상자와 외출을 할 때 동행방법으로 옳은 것은?', '["보호자를 통해 이동보조 기구 및 장비를 점검시킨다.", "계단을 오를 때 몇 번씩 쉬면서 천천히 이동한다.", "차량 이용 시 요양보호사는 운전자 옆자리에 앉고, 대상자 스스로 오르내리게 격려한다.", "외출 후 돌아와 낮잠을 푹 자게 한다.", "만족스러웠는지 보호자에게 확인한다."]'::jsonb, 2, '재가 서비스 대상자의 안전한 외출 동행 방법을 이해하고 평가하기 위한 문제입니다.', NULL, '{"1": "보호자를 통해 이동보조 기구 및 장비를 점검하는 것은 중요하지만, 동행 방법으로는 적절하지 않습니다.\n[정답]", "2": "계단을 오를 때 몇 번씩 쉬면서 천천히 이동하는 것은 안전한 동행 방법입니다.", "3": "차량 이용 시 요양보호사가 운전자의 옆자리에 앉고, 대상자 스스로 오르내리게 격려하는 것은 바람직하지 않은 방법입니다.", "4": "외출 후 돌아와 낮잠을 푹 자게 하는 것은 건강 관리의 일환이지만, 동행 방법과는 관련이 없습니다.", "5": "만족스러웠는지 보호자에게 확인하는 것은 사후 평가에 해당하며, 동행 방법으로는 부적절합니다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "거 động", "def_ko": "움직임(한국어)", "def_vi": "di chuyển(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (406, '11', '다음과 같은 표시기호가 있는 의복의 다림질 방법으로 옳은 것은?(그림)#252', '["80~120˚C 이상의 온도로 다림질한다.", "80~120˚C의 물로 분무한 후 다림질한다.", "80~120˚C로 다림질한 후 펴서 보관한다.", "80~120˚C로 다림질한 후 완전히 말린다.", "원단 위에 천을 덮고 80~120˚C로 다림질한다."]'::jsonb, 5, '의복의 다림질 방법에 대한 이해도를 평가하려는 의도입니다.', NULL, '{"1": "80~120˚C 이상의 온도로 다림질하면 소재 손상이 일어날 수 있습니다.", "2": "물로 분무한 후 다림질하는 것은 적절한 방법이지만, 80~120˚C 범위에 해당하는 것이 아니라서 틀립니다.\n[정답]", "5": "원단 위에 천을 덮고 80~120˚C로 다림질하는 것이 올바른 방법입니다.", "3": "다림질한 후 펴서 보관하는 것은 잘못된 방법입니다.", "4": "다림질한 후 완전히 말리는 것은 필요 없고, 오히려 다림질과 동시에 수분이 남아 있어야 합니다."}'::jsonb, '[{"term_ko": "다림질", "term_vi": "Ủi", "def_ko": "옷을 펴게 하는 과정(한국어)", "def_vi": "quá trình làm phẳng quần áo(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (405, '11', '다음의 그림에 해당하는 설명으로 옳은 것은?(그림)#252', '["청바지 - 색이 바래지 않게 뒤집어서 건조", "색깔 있는 니트 - 통기성이 좋은 곳에서 채 반등에 펴서 건조", "노란색 나일론 블라우스 - 옷걸이에 걸어서 그늘에 건조", "흰색 면직물 - 햇볕에 건조", "합성섬유 - 뉘어서 그늘에 건조"]'::jsonb, 3, '이 문제는 의류의 건조 방법에 대한 이해를 평가하기 위한 것입니다.', NULL, '{"1": "청바지는 색이 바래지 않게 뒤집어서 건조해야 합니다.\n[정답]", "2": "색깔 있는 니트는 통기성이 좋은 곳에서 채 반듯이 펴서 건조해야 합니다.", "3": "노란색 나일론 블라우스는 옷걸이에 걸어서 그늘에 건조하는 것이 맞습니다.", "4": "흰색 면직물은 자외선에 의해 노란색으로 변할 수 있으므로 햇볕에 건조하면 안 됩니다.", "5": "합성섬유는 보통 뉘어서 그늘에서 건조하는 것이 좋습니다."}'::jsonb, '[{"term_ko": "청바지", "term_vi": "Quần bò", "def_ko": "찢어진 바지(바지)", "def_vi": "Quần có vết rách"}, {"term_ko": "색깔", "term_vi": "Màu sắc", "def_ko": "색(명사)", "def_vi": "Màu"}, {"term_ko": "니트", "term_vi": "Đồ len", "def_ko": "뜨개질한 옷(명사)", "def_vi": "Quần áo đan"}, {"term_ko": "통기성", "term_vi": "Tính thông gió", "def_ko": "공기가 통과하는 성질(명사)", "def_vi": "Tính chất cho không khí đi qua"}, {"term_ko": "흰색", "term_vi": "Màu trắng", "def_ko": "색상이 없는(형용사)", "def_vi": "Không có màu sắc"}, {"term_ko": "면직물", "term_vi": "Vải cotton", "def_ko": "면으로 된 직물(명사)", "def_vi": "Vải làm từ bông"}, {"term_ko": "합성섬유", "term_vi": "Sợi tổng hợp", "def_ko": "인공 섬유(명사)", "def_vi": "Sợi nhân tạo"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (404, '11', '방충제를 넣어 보관해야 하는 의류로 옳은 것은?', '["비닐 장갑(모자)", "나일론 양말", "합성섬유 바지", "모직 자켓", "폴리에스테르 티셔츠"]'::jsonb, 4, '어떤 의류가 방충제와 함께 보관해야 하는지를 이해시키기 위한 문제입니다.', NULL, '{"1": "비닐 장갑(모자)은 방충제가 필요하지 않습니다.\n[정답]", "4": "모직 자켓은 방충제를 넣어 보관해야 합니다.", "2": "나일론 양말은 방충제가 필요하지 않습니다.", "3": "합성섬유 바지는 방충제가 필요하지 않습니다.", "5": "폴리에스테르 티셔츠는 방충제가 필요하지 않습니다."}'::jsonb, '[{"term_ko": "방충제", "term_vi": "Thuốc chống côn trùng", "def_ko": "해충을 방지하는 약품", "def_vi": "Thuốc ngăn côn trùng"}, {"term_ko": "의류", "term_vi": "Trang phục", "def_ko": "입는 옷", "def_vi": "Quần áo"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (403, '11', '다음 그림의 세탁표시에 따른 세탁 방법을 옳게 설명한 것은?(그림)#251', '["약하게 짜면 안됨", "다림질을 약한 온도로 함", "드라이클리닝을 약하게 함", "산소계표백제를 적게 사용함", "세탁기에서는 단시간에 짜야함"]'::jsonb, 5, '세탁 방법을 올바르게 이해하고 있는지 평가하고자 함', NULL, '{"1": "약하게 짜면 안됨: 세탁표시의 요구사항을 충족하지 않음.\n[정답]", "2": "다림질을 약한 온도로 함: 세탁 후 다림질에 대한 요구사항이 아님.", "3": "드라이클리닝을 약하게 함: 드라이클리닝과 세탁 방법과는 무관함.", "4": "산소계표백제를 적게 사용함: 세탁표시와 관련된 내용 아님.", "5": "세탁기에서는 단시간에 짜야함: 세탁기 사용 시 짜는 것에 대한 정확한 설명."}'::jsonb, '[{"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "세금(한국어)", "def_vi": "Giặt giũ(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (402, '11', '세탁 후 관리하는 방법으로 옳은 것은?', '["다림질은 다리미가 앞으로 나갈 때는 앞부분에 힘을 준다.", "풀 먹인 천을 다릴 때는 분무기로 물을 뿌리고 다린다.", "거풍할 때는 건조하고 맑게 갠 날 바람이 잘 통하는 그늘에서 한다.", "실리카겔은 분홍색으로 변색되면 사용할 수 없다.", "방충제는 공기보다 무거우므로 보관용기의 아래 구석에 넣어둔다."]'::jsonb, 3, '세탁 후 관리 방법에 대한 기본적인 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "다림질은 다리미가 앞으로 나갈 때는 앞부분에 힘을 준다는 설명이 부정확합니다.\n[정답]", "2": "풀 먹인 천을 다릴 때는 분무기로 물을 뿌리고 다려야 효과적입니다.", "3": "거풍할 때는 건조하고 맑게 갠 날 바람이 잘 통하는 그늘에서 해야 합니다.", "4": "실리카겔은 분홍색으로 변색되면 사용할 수 없습니다.", "5": "방충제는 공기보다 가벼우므로 보관할 때 주의가 필요합니다."}'::jsonb, '[{"term_ko": "세탁", "term_vi": "관리", "def_ko": "세탁(giặt)", "def_vi": "관리(quan lý)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (401, '11', '대상자의 면 속옷을 삶을 때 세탁방법으로 옳은 것은?', '["면직물 속옷은 줄어들기 때문에 주의해야 한다.", "먼저 삶은 후 세탁한다.", "삶을 때는 뚜껑을 열고 삶는다.", "색이 빠질 우려가 있는 제품은 절대 삶지 않는다.", "비눗물에 세탁물이 반쯤 잠길 정도로 넣고 삶는다."]'::jsonb, 5, '세탁 방법에 대한 기본 지식을 평가하기 위함입니다.', NULL, '{"1": "면직물 속옷이 줄어든다는 점은 맞으나, 이 보기는 세탁 방법에 대한 질문이므로 정답이 아닙니다.\n[정답]", "5": "비눗물에서 반쯤 잠기도록 세탁하는 것이 올바른 방법입니다.", "2": "삶은 후 세탁하는 것은 일반적이지 않으므로 옳지 않습니다.", "3": "삶을 때 뚜껑을 열고 삶는 것은 안전하지 않으므로 적절하지 않습니다.", "4": "색이 빠질 우려가 있는 제품은 세탁법에 맞게 다르게 처리해야 하므로 잘못된 정보입니다."}'::jsonb, '[{"term_ko": "면", "term_vi": "Cotton", "def_ko": "면직물(한국어)", "def_vi": "Vải cotton"}, {"term_ko": "삶다", "term_vi": "Nấu", "def_ko": "끓이는 행위(한국어)", "def_vi": "Hành động đun sôi"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "세탁(한국어)", "def_vi": "Giặt"}, {"term_ko": "제품", "term_vi": "Sản phẩm", "def_ko": "제품(한국어)", "def_vi": "Sản phẩm"}, {"term_ko": "우려", "term_vi": "Lo lắng", "def_ko": "걱정하는 상태(한국어)", "def_vi": "Tình trạng lo lắng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (400, '11', '변실금으로 오염된 대상자의 속옷을 세탁하는 방법으로 옳은 것은?', '["뚜껑을 열고 삶는다.", "본 세탁 전에 애벌빨래를 한다.", "오염된 부위는 아세톤으로 세탁한다.", "얼룩을 제거하고 섬유유연제에 오래 담가 둔다.", "식초물에 여러 번 담갔다가 헹구어 건조한다."]'::jsonb, 2, '변실금으로 오염된 속옷을 세탁하는 방법에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "뚜껑을 열고 삶는 것은 위생적이지 않으며, 잘못된 접근입니다.\n[정답]", "2": "본 세탁 전에 애벌빨래를 하는 것이 가장 적절한 방법입니다.", "3": "아세톤으로 세탁하는 것은 적합하지 않습니다.", "4": "섬유유연제에 오래 담가 두는 것은 필요하지 않으며, 알맞지 않은 방법입니다.", "5": "식초물에 담갔다가 헹구는 방법은 하지만, 일반적으로 선호되는 방법은 아닙니다."}'::jsonb, '[{"term_ko": "변실금", "term_vi": "Tiêu chảy", "def_ko": "대변의 제어를 잃는 질환", "def_vi": "Mất kiểm soát phân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (399, '11', '대상자의 세탁물을 처리하는 방법으로 옳은 것은?', '["수선이 필요한 경우 세탁 후 수선한다.", "오염이 심한 세탁물은 드라이클리닝을 한다.", "립스틱은 클렌징 폼으로 얼룩을 살살 문질러 따뜻한 물에 헹군다.", "혈액얼룩은 더운물로 닦고 찬물에 헹군다.", "속옷은 뚜껑을 열고 삶는다."]'::jsonb, 3, '대상자의 세탁물을 안전하게 처리하는 방법에 대한 이해를 평가하고자 한다.', NULL, '{"1": "수선이 필요한 경우 세탁 후 수선하기 보다는, 수선이 이루어져야 할 경우 수선 후 세탁하는 것이 일반적이다.\n[정답]", "2": "드라이클리닝은 소량의 더러움을 제거하는 데 적합하지 않다.", "3": "립스틱 얼룩은 클렌징 폼으로 문질러 따뜻한 물에 헹구는 것이 적절한 방법이다.", "4": "혈액얼룩은 따뜻한 물이 아닌 찬물로 처리해야 얼룩이 퍼지지 않는다.", "5": "속옷은 삶을 때 뚜껑을 열어서는 안전하지 않으며, 닫아서 삶아야 한다."}'::jsonb, '[{"term_ko": "세탁물", "term_vi": "Đồ giặt", "def_ko": "세탁하기 위한 의류", "def_vi": "Quần áo cần được giặt"}, {"term_ko": "오염", "term_vi": "Ô nhiễm", "def_ko": "더러움", "def_vi": "Bẩn"}, {"term_ko": "드라이클리닝", "term_vi": "Giặt khô", "def_ko": "화학약품으로 세탁하는 방법", "def_vi": "Phương pháp giặt sử dụng hóa chất"}, {"term_ko": "얼룩", "term_vi": "Vết bẩn", "def_ko": "더러운 흔적", "def_vi": "Dấu vết bẩn"}, {"term_ko": "속옷", "term_vi": "Đồ lót", "def_ko": "몸에 직접 닿는 의류", "def_vi": "Quần áo tiếp xúc trực tiếp với cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (398, '11', '대상자의 침구류(A)와 선택 시 고려사항(B)으로 옳은 것은?', '["이불 따뜻하고 가벼우며 보습성이 있는 것", "이불 커버 거칠고 모직물로 된 것", "베개 목침처럼 딱딱한 베개", "시트 풀을 먹이고 재봉선이 있는 것", "매트리스 푹신하고 습기를 흡수하는 것"]'::jsonb, 1, '대상자의 침구류 선택 시 올바른 고려사항을 평가하기 위한 문제입니다.', NULL, '{"1": "이불이 따뜻하고 가벼우며 보습성이 있다는 것은 대상자의 편안함을 높여줍니다.\n[정답]", "2": "이불 커버가 거칠고 모직물로 된 것은 적절하지 않습니다.", "3": "딱딱한 베개는 목에 부담을 줄 수 있어 바람직하지 않습니다.", "4": "시트에 풀을 먹이고 재봉선이 있는 것은 오히려 불편할 수 있습니다.", "5": "푹신한 매트리스는 좋으나 너무 습기를 흡수하면 건강에 좋지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "침구류", "term_vi": "Đồ đạc trên giường", "def_ko": "침대에 사용하는 모든 종류의 패브릭", "def_vi": "Tất cả các loại vải sử dụng trên giường"}, {"term_ko": "보습성", "term_vi": "Tính giữ ẩm", "def_ko": "습기를 유지하는 성질", "def_vi": "Đặc tính duy trì độ ẩm"}, {"term_ko": "거칠다", "term_vi": "Thô ráp", "def_ko": "표면이 부드럽지 않고 거친 상태", "def_vi": "Tình trạng bề mặt không mịn màng"}, {"term_ko": "딱딱하다", "term_vi": "Cứng", "def_ko": "단단한 상태", "def_vi": "Tình trạng chắc chắn"}, {"term_ko": "풀", "term_vi": "Keo", "def_ko": "접착제를 의미", "def_vi": "Có nghĩa là chất dính"}, {"term_ko": "재봉선", "term_vi": "Đường may", "def_ko": "천을 꿰매어 연결하는 선", "def_vi": "Dấu hiệu kết nối vải lại với nhau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (397, '11', '대상자의 침구를 관리하는 방법으로 옳은 것은?', '["매트리스는 푹신한 소재를 선택한다.", "오리털 이불은 햇볕에 말린다.", "재봉선이 없는 시트를 사용한다.", "습기를 흡수하는 베갯속을 선택한다.", "침대 커버는 한 달에 한 번 세탁한다."]'::jsonb, 3, '대상자의 침구 관리에 대한 올바른 방법을 파악하는 것.', NULL, '{"1": "매트리스는 딱딱한 소재가 건강에 좋다.\n[정답]", "3": "재봉선이 없는 시트를 사용하면 세균 번식을 줄일 수 있다.", "2": "오리털 이불은 햇볕에 말리면 오히려 손상될 수 있다.", "4": "습기를 흡수하는 베갯속은 방지해주는 것이 좋다.", "5": "침대 커버는 1주일마다 세탁하는 것이 바람직하다."}'::jsonb, '[{"term_ko": "침구", "term_vi": "Bộ đồ giường", "def_ko": "침대와 관련된 모든 품목", "def_vi": "Tất cả các mặt hàng liên quan đến giường"}, {"term_ko": "매트리스", "term_vi": "Nệm", "def_ko": "침대의 뼈대", "def_vi": "Khung của giường"}, {"term_ko": "재봉선", "term_vi": "Đường khâu", "def_ko": "꿰매는 선", "def_vi": "Đường may"}, {"term_ko": "습기", "term_vi": "Độ ẩm", "def_ko": "물이 많은 상태", "def_vi": "Trạng thái có nhiều nước"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "세척하다", "def_vi": "Rửa"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (396, '11', '재가 대상자의 주방을 위생적으로 관리하는 방법으로 옳은 것은?', '["냉장고는 계절별로 청소한다.", "냉장고 청소는 손을 씻고 변색된 음식을 버린다.", "냉장고 선반은 젖은 행주로 닦는다.", "손의 보습을 위해 고무장갑은 습기를 유지한다.", "쓰레기통은 자주 세척하고 건조한 후 사용한다."]'::jsonb, 5, '재가 대상자의 주방 위생 관리에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "냉장고는 계절별로 청소해야 하나, 청소 빈도가 중요하다.\n[정답]", "5": "쓰레기통은 자주 세척하고 건조한 후 사용하는 것이 위생적으로 관리하는 올바른 방법이다.", "2": "냉장고 청소 시 손을 씻고 변색된 음식을 버리는 것은 중요하지만 전반적인 위생 관리 방법에 포함되지 않는다.", "3": "냉장고 선반은 젖은 행주로 닦는 것보다는 마른 행주로 닦는 것이 바람직하다.", "4": "고무장갑의 사용 목적은 보습이 아닌 위생적인 작업을 돕기 위한 것이다."}'::jsonb, '[{"term_ko": "주방", "term_vi": "Nhà bếp", "def_ko": "부엌", "def_vi": "Nơi nấu ăn"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결 상태", "def_vi": "Tình trạng sạch sẽ"}, {"term_ko": "청소", "term_vi": "Dọn dẹp", "def_ko": "더러운 것을 제거하는 행동", "def_vi": "Hành động loại bỏ sự bẩn"}, {"term_ko": "쓰레기통", "term_vi": "Thùng rác", "def_ko": "쓰레기를 담는 용기", "def_vi": "Bình chứa rác"}, {"term_ko": "세척", "term_vi": "Vệ sinh", "def_ko": "깨끗하게 하는 것", "def_vi": "Làm sạch"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (395, '11', '재가 대상자의 식기 및 주방을 위생적으로 관리하는 방법으로 옳은 것은?', '["기름기가 많은 그릇은 물로 세척한다.", "유통기한이 지난 음식은 빨리 조리한다.", "그물 모양 수세미보다 스펀지로 된 수세미를 사용한다.", "일반쓰레기와 음식물 쓰레기통을 함께 사용한다.", "삶을 수 없는 수세미는 소독제를 희석한 물에 담근다."]'::jsonb, 5, '식기 및 주방 위생 관리의 중요성을 이해하고 올바른 방법을 선택하는 능력을 평가하고자 함.', NULL, '{"1": "기름기가 많은 그릇은 물로 세척하면 기름이 잘 제거되지 않아 위생에 문제가 발생할 수 있다.", "2": "유통기한이 지난 음식은 빨리 조리해서도 먹으면 안 되며, 폐기해야 한다.", "3": "그물 모양 수세미는 표면이 거칠어서 위생적으로 좋지 않으므로 스펀지 수세미가 더 적합하다.\n[정답]", "4": "일반쓰레기와 음식물 쓰레기통은 분리해서 사용해야 위생적이다.", "5": "삶을 수 없는 수세미는 소독제를 희석한 물에 담가서 소독할 수 있다."}'::jsonb, '[{"term_ko": "재가 대상자", "term_vi": "Người nhận chăm sóc tại nhà", "def_ko": "가정에서 돌봄을 받는 사람", "def_vi": "Người được chăm sóc tại nhà"}, {"term_ko": "식기", "term_vi": "Chén dĩa", "def_ko": "식사 시 사용하는 그릇", "def_vi": "Đồ dùng ăn"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "건강을 위해 깨끗하게 관리하는 것", "def_vi": "Quản lý sạch sẽ cho sức khỏe"}, {"term_ko": "주방", "term_vi": "Nhà bếp", "def_ko": "음식을 준비하는 곳", "def_vi": "Nơi chuẩn bị thực phẩm"}, {"term_ko": "수세미", "term_vi": "Bọt biển", "def_ko": "그릇을 씻는 도구", "def_vi": "Dụng cụ rửa chén"}, {"term_ko": "유통기한", "term_vi": "Hạn sử dụng", "def_ko": "식품의 소비 기한", "def_vi": "Thời gian tiêu thụ thực phẩm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (394, '11', '수확한 뒤 상온에서 일정기간 보관했다가 먹으면 영양가가 더 좋아지는 과일로 옳은 것은?', '["토마토", "수박", "한라봉", "딸기", "블루베리"]'::jsonb, 1, '과일의 영양가 변화에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "수확 후 숙성이 진행되어 맛과 영양가가 증가합니다.\n[정답]", "2": "상온 보관 시 수분이 빠져나가 영양가가 감소할 수 있습니다.", "3": "수확 후 바로 소비하는 것이 좋습니다.", "4": "상온에서 보관해도 큰 변화가 없습니다.", "5": "다른 과일에 비해 숙성에 유리하지 않습니다."}'::jsonb, '[{"term_ko": "수확", "term_vi": "Thu hoạch", "def_ko": "수확하다(한국어)", "def_vi": "thu hoạch(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (393, '11', '대상자가 유효기간이 지난 영양제를 버리지 못하게 할 때 요양보호사의 대처방법으로 옳은 것은?', '["최대한 빨리 드시라고 말한다.", "냉동실에 보관하여 드시라고 한다.", "영양제 대신 다른 약을 넣어둔다.", "보호자가 지켜보는 앞에서 정리한다.", "가족에게 새로운 영양제 구입비용을 청구한다."]'::jsonb, 4, '대상자가 유효기간이 지난 영양제를 버리지 못하게 될 경우 요양보호사가 어떻게 대처해야 하는지를 묻는 문제입니다.', NULL, '{"1": "최대한 빨리 드시라고 말한다: 대상자의 안전을 고려하지 않은 비효율적인 방법입니다.\n[정답]", "4": "보호자가 지켜보는 앞에서 정리한다: 보호자의 동의와 지켜보는 상황에서 정리하는 것이 안전하고 바람직한 대처입니다.", "2": "냉동실에 보관하여 드시라고 한다: 잘못된 보관 방법입니다.", "3": "영양제 대신 다른 약을 넣어둔다: 안전하지 않으며 비윤리적인 방법입니다.", "5": "가족에게 새로운 영양제 구입비용을 청구한다: 문제가 해결되지 않고 불필요한 부담을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "유효기간", "term_vi": "Hạn sử dụng", "def_ko": "특정 제품이 안전하게 사용될 수 있는 기간", "def_vi": "Thời gian mà sản phẩm có thể sử dụng an toàn"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인을 돌보는 전문인", "def_vi": "Chuyên gia chăm sóc người già"}, {"term_ko": "보호자", "term_vi": "Người giám hộ", "def_ko": "환자를 담당하는 가족 또는 친척", "def_vi": "Gia đình hoặc người thân chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (392, '11', '재가대상자의 식사를 도울 때 식중독을 예방할 수 있는 방법으로 옳은 것은?', '["야채굴죽은 50˚c에서 조리한다.", "냉동식품은 실온에서 해동한다.", "달걀은 조리 직전에 씻어서 사용한다.", "채소는 물에 1분 정도 담갔다 먹는다.", "해동 후 남은 어패류는 다시 냉동한다."]'::jsonb, 3, '재가대상자의 식사 준비 과정에서 식중독을 예방하는 올바른 방법을 묻는 문제입니다.', NULL, '{"1": "야채굴죽은 50˚c에서 조리하면 낮은 온도에서 조리되므로 식중독을 유발할 수 있는 세균이 살지 않을 가능성이 큽니다.\n[정답]", "2": "냉동식품은 실온에서 해동하면 식중독 세균이 성장할 수 있는 위험이 있습니다.", "3": "달걀은 조리 직전에 씻어서 사용하면 외부 오염물을 제거할 수 있어서 안전하게 사용할 수 있습니다.", "4": "채소는 물에 1분 정도 담갔다 먹으면 충분히 세척되지 못할 수 있어 도리어 위험할 수 있습니다.", "5": "해동 후 남은 어패류는 다시 냉동하는 것은 품질 저하와 식중독 위험을 높일 수 있습니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người nhận dịch vụ tại nhà", "def_ko": "가정에서 요양받는 사람", "def_vi": "Người nhận dịch vụ chăm sóc sức khỏe tại nhà"}, {"term_ko": "식중독", "term_vi": "Ngộ độc thực phẩm", "def_ko": "식사나 음식을 통해 감염되는 질병", "def_vi": "Bệnh truyền qua thực phẩm"}, {"term_ko": "조리", "term_vi": "Nấu ăn", "def_ko": "음식 만드는 과정", "def_vi": "Quá trình chế biến thức ăn"}, {"term_ko": "세균", "term_vi": "Vi khuẩn", "def_ko": "미생물의 일종", "def_vi": "Một loại vi sinh vật"}, {"term_ko": "위험", "term_vi": "Nguy hiểm", "def_ko": "위험한 상황", "def_vi": "Tình huống nguy hiểm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (391, '11', '치아 손실이 있는 재가대상자의 식사를 조리하는 방법으로 옳은 것은?', '["삼치는 바싹 튀겨 소금을 뿌린다.", "오징어는 물을 붓고 오랫동안 삶는다.", "흰떡은 큼직하게 썰어 기름에 볶는다.", "양배추는 센 불로 익힌 후 약불로 줄여서 찐다.", "소고기는 납작하게 저며서 말려 육포로 만든다."]'::jsonb, 4, '치아 손실이 있는 재가대상자에게 적합한 식사 조리 방법을 이해하도록 하는 문제입니다.', NULL, '{"1": "삼치는 바싹 튀겨 소금을 뿌리면, 경도가 높아 씹기 힘들 수 있습니다.\n[정답]", "2": "오징어는 물을 붓고 오랫동안 삶으면 부드러워져 쉽게 먹을 수 있습니다.", "3": "흰떡은 큼직하게 썰어 기름에 볶으면 소화에 부담을 줄 수 있습니다.", "4": "양배추는 센 불로 익힌 후 약불로 줄여서 찌면 부드럽고 소화가 잘 됩니다.", "5": "소고기는 납작하게 저며서 말려 육포로 만들면 식사에 적합하지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "치아", "term_vi": "Răng", "def_ko": "이(한국어)", "def_vi": "Răng"}, {"term_ko": "손실", "term_vi": "Mất", "def_ko": "잃다(한국어)", "def_vi": "Thua lỗ"}, {"term_ko": "재가대상자", "term_vi": "Người chăm sóc tại nhà", "def_ko": "재가에서 관리받는 사람(한국어)", "def_vi": "Người nhận sự chăm sóc tại nhà"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "먹는 일(한국어)", "def_vi": "Bữa ăn"}, {"term_ko": "조리", "term_vi": "Nấu ăn", "def_ko": "음식을 만드는 일(한국어)", "def_vi": "Nấu ăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (390, '11', '삼킴장애 대상자의 식사 시 주의사항으로 옳은 것은?', '["떠먹는 요구르트보다 마시는 요구르트를 제공한다.", "밥을 국이나 물에 말아 먹인다.", "참외를 숫가락으로 긁어서 먹인다.", "채소는 레몬소스를 뿌려 먹인다.", "계란은 반숙보다 완숙으로 먹는다."]'::jsonb, 3, '삼킴장애가 있는 대상자에게 안전하고 효과적인 식사 방법을 질문하는 문제입니다.', NULL, '{"1": "떠먹는 요구르트보다 마시는 요구르트를 제공하는 것은 삼킴장애에 좋지 않습니다. 마시는 요구르트는 넘어질 위험이 높습니다.\n[정답]", "3": "참외를 숫가락으로 긁어서 먹이는 것은 안전한 방법입니다. 삼킴장애가 있는 분들에게 알맞은 식사를 제공합니다.", "2": "밥을 국이나 물에 말아 먹이는 것은 삼킴장애를 악화시킬 수 있습니다.", "4": "채소는 레몬소스를 뿌려 먹이지 않는 것이 좋습니다. 소스가 넘치는 위험이 있습니다.", "5": "계란은 반숙보다 완숙으로 먹이는 것이 일반적으로 안전하지만, 삼킴장애의 경우에는 과도한 조리 방법이 필요할 수 있습니다."}'::jsonb, '[{"term_ko": "삼킴장애", "term_vi": "Rối loạn nuốt", "def_ko": "음식이나 액체를 삼키는 데 어려움이 있는 상태", "def_vi": "Tình trạng khó khăn trong việc nuốt thức ăn hoặc chất lỏng"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태", "def_vi": "Tình trạng không có nguy cơ"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn uống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (389, '11', '고혈압 대상자에게 혈압을 낮추기 위해 제공할 수 있는 칼륨이 많이 함유된 식품으로 옳은 것은?', '["깻잎 장아찌", "조개젓", "강된장", "찐 감자", "마른 오징어"]'::jsonb, 4, '고혈압을 관리하기 위해 식이요법의 중요성을 이해하고, 칼륨이 많이 포함된 식품을 선택하는 능력을 평가하기 위함입니다.', NULL, '{"1": "깻잎 장아찌: 칼륨 함량이 낮고, 나트륨이 많이 포함되어 있기 때문에 고혈압에 적합하지 않습니다.\n[정답]", "4": "찐 감자: 칼륨이 풍부하여 혈압을 낮추는 데 도움이 됩니다.", "2": "조개젓: 나트륨 함량이 매우 높아 고혈압에는 좋지 않습니다.", "3": "강된장: 나트륨이 많아 고혈압에 적합하지 않습니다.", "5": "마른 오징어: 칼륨 함량이 낮고 나트륨이 많아 부적합합니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "Tăng huyết áp", "def_ko": "고혈압(한국어)", "def_vi": "Tăng huyết áp(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (388, '11', '당뇨병 대상자의 혈당 관리에 도움이 되는 혈당지수 낮은 식품으로 옳은 것은?', '["미역", "고구마", "수박", "흰 식빵", "떡"]'::jsonb, 1, '당뇨병 대상자의 식이 요법에서 혈당 관리에 도움을 줄 수 있는 식품을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "미역은 혈당 지수가 낮아 당뇨병 환자에게 좋은 식품입니다.\n[정답]", "2": "고구마는 혈당 지수가 상대적으로 낮지만, 미역보다 혈당 관리에 덜 효과적일 수 있습니다.", "3": "수박은 혈당 지수가 높은 편입니다.", "4": "흰 식빵은 혈당 지수가 높아 당뇨병 환자에게 피해야 할 식품입니다.", "5": "떡은 일반적으로 혈당 지수가 높아 당뇨병 환자에게 적합하지 않습니다."}'::jsonb, '[{"term_ko": "혈당 관리", "term_vi": "Quản lý đường huyết", "def_ko": "혈 đường 수치를 조절하는 것", "def_vi": "Điều chỉnh mức đường trong máu"}, {"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "만성 질환으로 인슐린의 분비나 작용이 부족.", "def_vi": "Bệnh mãn tính do thiếu hụt sự bài tiết hoặc tác động của insulin"}, {"term_ko": "혈당 지수", "term_vi": "Chỉ số đường huyết", "def_ko": "식품이 혈당에 끼치는 영향의 척도", "def_vi": "Thước đo ảnh hưởng của thực phẩm đến đường huyết"}, {"term_ko": "식품", "term_vi": "Thực phẩm", "def_ko": "음식, thực phẩm", "def_vi": "Thực phẩm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (387, '11', '대상자의 식사를 준비하기 위해 장을 볼 때 고려할 사항으로 옳은 것은?', '["한 번에 많은 양의 식품을 구입한다.", "장을 본 후 결과에 만족하는지를 확인한다.", "장보기 후 경비 결산은 시설장에게 한다.", "가족이 먹고 싶은 음식을 확인하여 구입한다.", "요양보호사 자신에게 필요한 물품을 함께 구입한다."]'::jsonb, 2, '대상자가 섭취할 식사를 준비하는 과정에서 고려해야 할 중요한 사항을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "한 번에 많은 양의 식품을 구입하는 것은 식품의 신선도를 떨어뜨릴 수 있으므로 바람직하지 않습니다.\n[정답]", "2": "장을 본 후 결과에 만족하는지를 확인하는 것은 올바른 행동입니다. 식품의 질이나 양을 체크해야 합니다.", "3": "장보기 후 경비 결산은 일반적으로 요양보호사가 아닌 다른 책임자가 해야 합니다.", "4": "가족이 먹고 싶은 음식을 확인하여 구입하는 것도 중요하지만, 대상자의 건강 상태를 우선 고려해야 합니다.", "5": "요양보호사 자신에게 필요한 물품을 함께 구입하는 것은 업무의 초점을 흐릴 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (386, '11', '재가 대상자의 식사를 준비하는 방법으로 옳은 것은?', '["음식이 뜨거울 때 간을 맞춘다.", "무, 버섯으로 만든 채수로 국물을 만든다.", "생선은 오래 굽고 육류는 기름에 튀긴다.", "엿과 설탕 같은 단당류로 음식을 조리한다.", "음식은 한꺼번에 만들어 두고 조금씩 제공한다."]'::jsonb, 2, '재가 대상자의 보다 안전하고 건강한 식사 준비 방법에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "음식이 뜨거울 때 간을 맞추면 균형 잡힌 맛을 내기 어렵다. \n[정답]", "2": "무와 버섯으로 만든 채수는 건강한 국물 대신으로 적합하다.", "3": "생선을 너무 오래 굽는 것은 질감을 떨어뜨리고 육류를 기름에 튀기는 것은 건강에 좋지 않다.", "4": "엿과 설탕처럼 단당류는 과다 섭취 시 건강에 문제를 일으킬 수 있다.", "5": "음식은 신선하게 제공하는 것이 좋으며, 미리 만들어야 할 경우 적절한 보관이 필요하다."}'::jsonb, '[{"term_ko": "재가 대상자", "term_vi": "Đối tượng chăm sóc tại nhà", "def_ko": "가정에서 요양을 받는 환자", "def_vi": "Người bệnh nhận sự chăm sóc tại nhà"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 준비하고 제공하는 행위", "def_vi": "Hành động chuẩn bị và phục vụ thức ăn"}, {"term_ko": "채수", "term_vi": "Nước dùng", "def_ko": "채소를 우려낸 물", "def_vi": "Nước được chiết xuất từ rau củ"}, {"term_ko": "단당류", "term_vi": "Đường đơn", "def_ko": "단순당으로 구성된 당분", "def_vi": "Loại đường cấu thành từ các đường đơn giản"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (385, '11', '식사를 준비하면서 재가대상자에게 설명한 것으로 옳은 것은?', '["\"반찬을 만들고 남은 재료는 제가 가져갈게요.\"", "\"야채 사고 남은 돈은 아들에게 주었어요.\"", "\"어르신은 편찮으시니까 죽만 드시는 것이 좋겠어요.\"", "\"냉장고에 있던 과일은 오래된 것 같아서 버렸어요.\"", "\"혈당이 높으니 어르신이 좋아하는 잡곡밥을 해드릴게요.\""]'::jsonb, 5, '재가대상자를 위한 식사 준비 시 적절한 설명을 선택하는 것이다.', NULL, '{"1": "식사 준비 과정에서 재료를 가져가는 것은 불필요한 소통이다.\n[정답]", "5": "어르신의 건강 상태에 맞춰 잡곡밥을 제공하는 것이 적절하다.", "2": "개인적인 사정을 언급하는 것은 전문적인 의사소통이 아니다.", "3": "어르신의 건강을 고려한 발언이지만, 메시지가 명확하지 않다.", "4": "과일 소실에 대한 무책임한 언급으로서 부적절하다."}'::jsonb, '[{"term_ko": "식사", "term_vi": "준비", "def_ko": "식사(한국어), bữa ăn(베트남어)", "def_vi": "준비(한국어), chuẩn bị(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (384, '10', '자세 변환용 쿠션을 선택할 때 고려해야 할 사항으로 옳은 것은?', '["부착된 지퍼가 노출되어 있어야 한다.", "내부 충진재가 커버 밖으로 나와 있어야 한다.", "견고하고 딱딱한 재질이어야 한다.", "커버는 분리되지 않아야 한다.", "변질되지 않는 것이어야 한다."]'::jsonb, 5, '자세 변환용 쿠션 선택 시 주의해야 할 사항을 이해하는지 확인하기 위함입니다.', NULL, '{"1": "부착된 지퍼가 노출되어 있는 것은 안전하지 않으므로 바람직하지 않습니다.\n[정답]", "5": "변질되지 않는 것이어야 하며, 이는 쿠션의 지속적인 사용을 위해 중요합니다.", "3": "견고하고 딱딱한 재질은 편안함을 제공하지 않을 수 있습니다.", "4": "커버가 분리되지 않는 것은 관리 측면에서 불편할 수 있습니다.", "2": "내부 충진재가 커버 밖으로 나와 있는 것은 안전 문제가 발생할 수 있습니다."}'::jsonb, '[{"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "태도(한국어)", "def_vi": "Thái độ(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (383, '10', '신체압력을 분산시켜 욕창을 예방하며 보온성, 통풍성이 용이한 것을 선택해야 하는 대여 복지용구로 옳은 것은?', '["침대형 휠체어", "욕창예방 매트리스", "욕창예방 방석", "전동 침대", "자세변환 쿠션"]'::jsonb, 2, '신체 압력을 분산시켜 욕창을 예방하는 방법을 묻고 있다.', NULL, '{"1": "침대형 휠체어는 이동성을 제공하지만 압력 분산 효과가 낮다.\n[정답]", "2": "욕창예방 매트리스는 압력을 잘 분산시켜 욕창 예방에 효과적이다.", "3": "욕창예방 방석은 특정 부위에 초점을 맞추지만 전체적인 보온성과 통풍성은 부족할 수 있다.", "4": "전동 침대는 기능성이 뛰어나나 압력 분산에 제한적이다.", "5": "자세변환 쿠션은 주로 자세를 바꾸는 데 사용되며 압력 분산 효과가 매트리스보다 낮다."}'::jsonb, '[{"term_ko": "신체압력", "term_vi": "Áp lực cơ thể", "def_ko": "압력이 신체에 미치는 영향", "def_vi": "Ảnh hưởng của áp lực lên cơ thể"}, {"term_ko": "욕창", "term_vi": "Loét do tì đè", "def_ko": "피부가 손상되는 질환", "def_vi": "Bệnh gây tổn thương da"}, {"term_ko": "예방", "term_vi": "Ngăn ngừa", "def_ko": "방지하거나 예방하는 것", "def_vi": "Ngăn chặn hoặc phòng ngừa"}, {"term_ko": "복지용구", "term_vi": "Thiết bị hỗ trợ", "def_ko": "장애인을 돕기 위한 도구", "def_vi": "Công cụ giúp người khuyết tật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (382, '10', '이동욕조 선정이나 사용 시 고려할 사항으로 옳은 것은?', '["배수구가 막혀져 있는 것을 사용한다.", "욕조 안이 미끄러워야 한다.", "공기 주입 및 조립이 복잡해야 한다.", "팽창상태에서 변형이 가능해야 한다.", "평평하고 이물질이 없는 장소에서 사용한다."]'::jsonb, 5, '이동욕조를 선택하거나 사용할 때 중요한 고려사항을 파악하는 것이다.', NULL, '{"1": "배수구가 막혀져 있는 것은 안전상 문제를 일으킬 수 있으므로 옳지 않다.", "2": "욕조 안이 미끄러우면 안전사고의 위험이 높아진다.", "3": "공기 주입 및 조립이 복잡하면 사용이 불편해진다.\n[정답]", "5": "평평하고 이물질이 없는 장소에서 사용하는 것이 안전에 중요하다.", "4": "팽창상태에서 변형이 가능해야 할 필요는 없다."}'::jsonb, '[{"term_ko": "이동욕조", "term_vi": "Bồn tắm di động", "def_ko": "이동이 가능한 욕조", "def_vi": "Bồn tắm có thể di chuyển"}, {"term_ko": "배수구", "term_vi": "Cống thoát nước", "def_ko": "물이 빠지는 구멍", "def_vi": "Lỗ để nước chảy ra"}, {"term_ko": "미끄러움", "term_vi": "Trơn trượt", "def_ko": "미끄러운 상태", "def_vi": "Trạng thái trơn trượt"}, {"term_ko": "이물질", "term_vi": "Chất lạ", "def_ko": "원하지 않는 물체", "def_vi": "Vật thể không mong muốn"}, {"term_ko": "평평하다", "term_vi": "Bằng phẳng", "def_ko": "고른 표면을 가지다", "def_vi": "Có bề mặt phẳng"}, {"term_ko": "변형", "term_vi": "Biến dạng", "def_ko": "형태가 바뀌다", "def_vi": "Thay đổi hình dạng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (381, '10', '목욕리프트 선정 시 고려사항으로 옳은 것은?', '["등받이가 각도가 고정된 것", "대상자의 무게를 지탱할 수 있는 것", "높낮이가 수동으로 조절되는 것", "철재로 만들어진 것", "요양보호사가 옮기기에 부담스러운 것"]'::jsonb, 2, '목욕리프트를 선택할 때 어떤 요소가 중요한지 인식하게 하려는 목적입니다.', NULL, '{"1": "등받이가 고정된 것은 사용에 불편함을 초래할 수 있습니다.\n[정답]", "2": "대상자의 무게를 지탱할 수 있는 것은 필수적인 요구 사항입니다.", "3": "높낮이가 수동으로 조절되는 것은 사용의 편의성을 저하시킬 수 있습니다.", "4": "철재로 만들어진 것은 내구성에 영향을 미칠 수 있지만, 반드시 필요한 조건은 아닙니다.", "5": "요양보호사가 옮기기에 부담스러운 것은 적절한 선택이 아닙니다."}'::jsonb, '[{"term_ko": "목욕리프트", "term_vi": "Xe nâng tắm", "def_ko": "욕실에서 환자를 들어 올리는데 사용하는 기기", "def_vi": "Thiết bị dùng để nâng người bệnh trong nhà tắm"}, {"term_ko": "고정", "term_vi": "Cố định", "def_ko": "고정된 상태를 유지하는 것", "def_vi": "Giữ nguyên trạng thái"}, {"term_ko": "무게", "term_vi": "Trọng lượng", "def_ko": "질량 혹은 중량", "def_vi": "Khối lượng hoặc cân nặng"}, {"term_ko": "지탱하다", "term_vi": "Gánh vác", "def_ko": "지탱하는 것, 지지하는 것", "def_vi": "Điều gì đó, hỗ trợ"}, {"term_ko": "부담스럽다", "term_vi": "Gánh nặng", "def_ko": "힘들고 불편하다", "def_vi": "Khó khăn và không thoải mái"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (380, '10', '거동이 불편한 대상자의 생활공간에 안전손잡이를 설치해야 하는 이유는?', '["근력과 지구력 증진", "심장과 폐기능 향상", "유연성과 신장성 향상", "스트레칭과 유산소 운동 증진", "자립심 향상과 신체 균형 유지"]'::jsonb, 5, '거동이 불편한 대상자가 안전하게 생활할 수 있도록 돕기 위한 이유를 묻고 있습니다.', NULL, '{"1": "근력과 지구력 증진은 안전손잡이 설치와 직접적인 관계가 없습니다.\n[정답]", "5": "자립심 향상과 신체 균형 유지는 안전손잡이를 설치함으로써 이룰 수 있는 중요한 효과입니다.", "2": "심장과 폐기능 향상은 주로 유산소 운동과 연관이 있습니다.", "3": "유연성과 신장성 향상은 운동의 결과일 수 있습니다.", "4": "스트레칭과 유산소 운동 증진은 다른 목적의 활동입니다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Hành động", "def_ko": "움직임(한국어)", "def_vi": "Hành động di chuyển"}, {"term_ko": "불편", "term_vi": "Khó khăn", "def_ko": "불편함(한국어)", "def_vi": "Tình trạng khó khăn"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자, 사용자(한국어)", "def_vi": "Người cần chăm sóc"}, {"term_ko": "생활공간", "term_vi": "Không gian sống", "def_ko": "생활 공간(한국어)", "def_vi": "Không gian sinh hoạt"}, {"term_ko": "안전손잡이", "term_vi": "Tay cầm an toàn", "def_ko": "안전하게 잡을 수 있는 기구(한국어)", "def_vi": "Dụng cụ cầm nắm an toàn"}, {"term_ko": "자립심", "term_vi": "Tự lập", "def_ko": "자립하는 마음(한국어)", "def_vi": "Tinh thần tự lập"}, {"term_ko": "신체", "term_vi": "Cơ thể", "def_ko": "몸(한국어)", "def_vi": "Cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (379, '10', '성인용 보행기 선정 시 고려해야 할 사항으로 옳은 것은?', '["고무받침은 매번 사용할 때마다 교환한다.", "접이식 보행기라면 펼친 후에 잠금 버튼을 확인한다.", "잘 미끄러지는 신발을 신는다.", "바퀴가 있는 경우 잠금장치를 풀고 일어난다.", "팔꿈치가 약 15˚구부러지도록 대상자 둔부 높이로 한다."]'::jsonb, 2, '성인용 보행기를 선정할 때 고려해야 할 안전 관련 사항을 이해하는지 평가하기 위함입니다.', NULL, '{"1": "고무받침은 매번 교환할 필요가 없습니다. 주기적으로 확인하고 교환해야 하지만 매번 사용할 때마다 교환할 필요는 없습니다.\n[정답]", "2": "접이식 보행기를 사용할 경우, 펼친 후에 잠금 버튼이 제대로 작동하는지 확인하는 것은 매우 중요합니다. 이는 안전사고를 예방하는 데 필수적입니다.", "3": "잘 미끄러지는 신발은 보행 안전에 도움이 되지 않습니다. 미끄러짐을 방지할 수 있는 적절한 신발이 필요합니다.", "4": "바퀴가 있는 경우, 잠금장치를 해제한 상태에서 일어나는 것은 위험합니다. 항상 잠금을 걸어야 합니다.", "5": "팔꿈치가 약 15˚ 구부러지도록 조정하는 것은 적절하지만, 대상자의 둔부 높이에 맞춰야 하며, 이를 주의 깊게 고려해야 합니다."}'::jsonb, '[{"term_ko": "성인용 보행기", "term_vi": "Xe đi bộ cho người lớn tuổi", "def_ko": "성인을 위한 보행 보조기구", "def_vi": "Thiết bị hỗ trợ đi lại cho người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (378, '10', '휠체어의 잠금장치 기능이 약할 때 점검해야 할 사항으로 옳은 것은?', '["팔걸이", "받침쇠", "바퀴 손잡이", "발 받침대", "타이어 공기압"]'::jsonb, 5, '휠체어의 잠금장치 기능과 관련된 점검 사항을 이해하고 있는지를 확인하기 위함입니다.', NULL, '{"1": "팔걸이는 잠금장치와 직접적인 관련이 없습니다.", "2": "받침쇠는 일반적으로 안정성을 높이는 역할을 하지만 잠금장치의 기능을 점검하는 데는 필요하지 않습니다.", "3": "바퀴 손잡이는 휠체어 조작에 중요한 요소이나 잠금장치와 관계는 적습니다.\n[정답]", "4": "발 받침대는 사용자의 안전을 위해 조정할 수 있으나 잠금장치의 점검과는 관계가 없습니다.", "5": "타이어 공기압은 휠체어의 안정성과 관련이 있으며, 잠금장치 기능이 약할 때 필수적으로 점검해야 할 사항입니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "휠체어(한국어)", "def_vi": "Xe lăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (377, '10', '복지용구 중에서 요실금 팬티를 사용하는 방법으로 옳은 것은?', '["요실금 팬티는 세탁하여 사용할 수 있다.", "실금량이 적을 때는 말려서 재사용한다.", "요실금 팬티 위에 일반 팬티를 덧입힌다.", "신체보다 한두 치수 큰 것으로 사용한다.", "외형이 보통 팬티와 달라 구분이 잘 된다."]'::jsonb, 1, '요실금 팬티의 올바른 사용법에 대한 이해를 확인하기 위함입니다.', NULL, '{"1": "요실금 팬티는 세탁하여 사용할 수 있다.\n[정답]", "2": "실금량이 적을 때는 말려서 재사용한다.", "3": "요실금 팬티 위에 일반 팬티를 덧입힌다.", "4": "신체보다 한두 치수 큰 것으로 사용한다.", "5": "외형이 보통 팬티와 달라 구분이 잘 된다."}'::jsonb, '[{"term_ko": "요실금", "term_vi": "Tiểu tiện không tự chủ", "def_ko": "의도하지 않은 소변의 유출", "def_vi": "Sự rò rỉ nước tiểu không có ý định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (376, '10', '간이변기의 재질로 적합한 것은?', '["세척 후 변형이 없어야 한다.", "물 세척이나 소독약으로 소독할 수 있는 재질이어야 한다.", "열탕으로 소독할 수 있도록 충분한 내열성이 있어야 한다.", "녹이 슬지 않고 미끄러지지 않는 재질이 좋다.", "표면에 도장이 되어 있어야 한다."]'::jsonb, 3, '간이변기의 재질에 대한 이해를 평가하기 위해 출제되었다.', NULL, '{"1": "간이변기는 세척 후 변형이 없어야 한다는 것은 중요하지만, 재질로 적합한지의 기준이 아니다.\n[정답]", "2": "물 세척이나 소독약으로 소독할 수 있는 재질이어야 한다는 것은 필요조건이지만, 내열성의 중요성을 간과할 수 없다.", "3": "열탕으로 소독할 수 있도록 충분한 내열성이 있어야 한다는 것이 가장 적합한 조건이다.", "4": "녹이 슬지 않고 미끄러지지 않는 재질이 좋지만, 이것이 재질의 직접적인 특성상 우선 순위는 아니다.", "5": "표면에 도장이 되어 있어야 한다는 조건은 필수 조건이 아니다."}'::jsonb, '[{"term_ko": "간이변기", "term_vi": "Bồn vệ sinh di động", "def_ko": "이동하는 화장실", "def_vi": "Nhà vệ sinh có thể di chuyển"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (375, '10', '노인장기요양보험 급여 복지용구 중 구입 가능한 품목으로 옳은 것은?', '["전동침대", "이동욕조", "수동휠체어", "배회감지기", "성인용 보행기"]'::jsonb, 5, '노인장기요양보험에서 지원하는 복지용구의 종류를 이해하고 실제 구입 가능한 품목을 구별할 수 있도록 하는 문제입니다.', NULL, '{"1": "전동침대는 노인장기요양보험 지원 품목이 아닙니다.", "2": "이동욕조는 노인장기요양보험 지원 품목이 아닙니다.", "3": "수동휠체어는 노인장기요양보험 지원 품목이 아닙니다.\n[정답]", "4": "배회감지기는 노인장기요양보험 지원 품목이 아닙니다.", "5": "성인용 보행기는 노인장기요양보험에서 구입 가능한 품목입니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기적인 요양 서비스 제공을 위한 보험", "def_vi": "Bảo hiểm cung cấp dịch vụ chăm sóc dài hạn cho người cao tuổi"}, {"term_ko": "복지용구", "term_vi": "Thiết bị hỗ trợ", "def_ko": "노인이나 장애인을 위한 행복과 편리함을 제공하는 기구", "def_vi": "Dụng cụ cung cấp tiện nghi và hạnh phúc cho người cao tuổi hoặc người khuyết tật"}, {"term_ko": "구입", "term_vi": "Mua sắm", "def_ko": "구매하다", "def_vi": "Mua hàng"}, {"term_ko": "품목", "term_vi": "Hạng mục", "def_ko": "물품의 종류", "def_vi": "Loại hàng hóa"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (374, '10', '다리가 모두 약한 대상자가 보행보조차를 사용하여 이동하는 방법으로 옳은 것은?', '["보행보조차 → 오른발 → 왼발", "오른쪽 발과 보행보조차 → 왼발", "보행보조차 → 오른발·왼발", "고무받침은 정해진 날짜에만 확인한다.", "팔꿈치가 약 15˚구부러지도록 손잡이를 엉덩이 높이로 조절한다."]'::jsonb, 1, '대상자가 보행보조차를 사용할 때 올바른 보행 방법을 이해하고 있는지를 확인하기 위한 문제입니다.', NULL, '{"1": "보행보조차를 먼저 놓고 그 다음에 오른발, 왼발의 순서로 이동하는 방법입니다. [정답]", "2": "오른발과 보행보조차를 함께 이동시키는 방법은 올바르지 않습니다.", "3": "보행보조차와 함께 양발을 동시에 움직이는 것은 올바른 보행 방법이 아닙니다.", "4": "고무받침은 늘 확인이 필요하며 정해진 날짜에만 확인하는 것은 틀린 내용입니다.", "5": "손잡이 높이는 개개인에 맞춰 조정해야 하며, 15˚ 구부리는 것은 적절하지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "다리", "term_vi": "Chân", "def_ko": "다리(한국어)", "def_vi": "chân(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (373, '10', '왼쪽 다리가 마비된 대상자가 지팡이를 짚고 계단을 내려갈 때 순서로 옳은 것은?', '["지팡이 → 왼쪽 다리 → 오른쪽 다리", "지팡이 → 오른쪽 다리 → 왼쪽 다리", "오른쪽 다리 → 지팡이 → 왼쪽 다리", "오른쪽 다리 → 왼쪽 다리 → 지팡이", "왼쪽 다리 → 지팡이 → 오른쪽 다리"]'::jsonb, 1, '대상자가 마비된 다리를 가진 경우 안전하게 이동하는 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "지팡이를 먼저 짚고 마비된 왼쪽 다리를 내린 후, 건강한 오른쪽 다리를 내리는 순서가 옳습니다.\n[정답]", "2": "지팡이와 오른쪽 다리를 먼저 내리는 것은 잘못된 순서입니다.", "3": "오른쪽 다리를 먼저 내리는 것은 마비된 쪽에 부상을 줄 수 있으므로 옳지 않습니다.", "4": "오른쪽 다리를 내린 후 왼쪽 다리를 내리는 순서는 반대가 되어 잘못된 순서입니다.", "5": "마비된 왼쪽 다리를 먼저 내리면 넘어질 위험이 큽니다."}'::jsonb, '[{"term_ko": "다리", "term_vi": "Chân", "def_ko": "다리(한국어)", "def_vi": "Chân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (372, '10', '왼쪽 편마비 대상자가 지팡이가 없을 때 계단을 내려가는 순서로 옳은 것은?', '["오른쪽 손으로 계단 손잡이 → 왼쪽 다리 → 오른쪽 다리", "오른쪽 손으로 계단 손잡이 → 오른쪽 다리 → 왼쪽 다리", "오른쪽 다리 → 오른쪽 손으로 계단 손잡이 → 왼쪽 다리", "오른쪽 다리 → 왼쪽 다리 → 오른쪽 손으로 계단 손잡이", "왼쪽 다리 → 오른쪽 손으로 계단 손잡이 → 오른쪽 다리"]'::jsonb, 1, '왼쪽 편마비 환자의 안전한 계단 하강 방법을 이해하고 알고 있는지를 평가하기 위함입니다.', NULL, '{"1": "오른쪽 손으로 계단 손잡이를 잡고, 왼쪽 다리를 먼저 내리고, 그 다음 오른쪽 다리를 내려야 합니다. 이는 편마비 환자가 균형을 유지하며 안전하게 내려갈 수 있는 방법입니다.\n[정답]", "2": "오른쪽 다리는 먼저 내리고, 왼발을 그 뒤에 일반적으로 내리는 수순은 올바르지 않습니다.", "3": "오른쪽 다리를 먼저 내리고 손잡이를 잡는 것은 불안정할 수 있으며 불편합니다.", "4": "오른쪽 다리부터 내리고 왼쪽 다리를 내려가는 것은 균형을 잃을 위험이 있습니다.", "5": "왼쪽 다리를 먼저 내리고 후에 손잡이를 잡는 것 역시 위험합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "왼쪽 또는 오른쪽 신체의 근육 기능이 약화된 상태", "def_vi": "trạng thái yếu cơ của một bên cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (371, '10', '오른쪽 편마비 대상자가 지팡이를 이용하여 계단을 오를 때 순서로 옳은 것은?', '["지팡이 → 왼쪽 다리 → 오른쪽 다리", "지팡이 → 오른쪽 다리 → 왼쪽 다리", "오른쪽 다리 → 지팡이 → 왼쪽 다리", "오른쪽 다리 → 왼쪽 다리 → 지팡이", "왼쪽 다리 → 지팡이 → 오른쪽 다리"]'::jsonb, 1, '오른쪽 편마비 대상자의 계단 오르내리기 방법에 대한 이해를 확인하기 위함.', NULL, '{"1": "지팡이를 사용하여 왼쪽 다리를 먼저 내디디고 오른쪽 다리를 뒤따라 오르는 올바른 순서이다.\n[정답]", "2": "오른쪽 다리로 이동하고 난 후 왼쪽 다리를 내디디는 방법은 부적절하다.", "3": "오른쪽 다리를 먼저 내디디는 것은 편마비 환자에게 위험하다.", "4": "오른쪽 다리는 뒤에 남기고 왼쪽 다리를 먼저 내디디는 순서는 잘못되었다.", "5": "왼쪽 다리를 먼저 내디디고 지팡이를 사용하는 것은 순서 상으로 올바르지 않다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽 몸이 마비된 상태", "def_vi": "Tình trạng bị liệt một nửa cơ thể"}, {"term_ko": "지팡이", "term_vi": "Gậy", "def_ko": "보행을 도와주는 도구", "def_vi": "Công cụ giúp đi lại"}, {"term_ko": "계단", "term_vi": "Cầu thang", "def_ko": "올라가는 구조물", "def_vi": "Cấu trúc để đi lên"}, {"term_ko": "대상자", "term_vi": "Người nhận trợ giúp", "def_ko": "도움을 받는 환자", "def_vi": "Bệnh nhân nhận giúp đỡ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (370, '10', '오른쪽 편마비 대상자가 지팡이가 없을 때 계단을 오르는 순서로 옳은 것은?', '["왼쪽 손으로 계단 손잡이 → 왼쪽 다리 → 오른쪽 다리", "왼쪽 손으로 계단 손잡이 → 오른쪽 다리 → 왼쪽 달 ㅣ", "오른쪽 다리 → 왼쪽 손으로 계단 손잡이 → 왼쪽 다리", "오른쪽 다리 → 왼쪽 다리 → 왼손으로 계단 손잡이", "왼쪽 다리 → 왼쪽 손으로 계단 손잡이 → 오른쪽 다리"]'::jsonb, 1, '편마비 환자의 안전한 이동 및 계단 오르기 방법에 대한 이해를 평가하고자 합니다.', NULL, '{"1": "왼쪽 손으로 계단 손잡이를 잡고, 왼쪽 다리로 먼저 올라가면 몸의 균형을 유지하며 이동할 수 있습니다.\n[정답]", "2": "오른쪽 다리로 올라가면 편마비 상태에서 균형을 잡기 어려워 위험할 수 있습니다.", "3": "오른쪽 다리로 먼저 오르면 이동의 안전성이 떨어집니다.", "4": "오른쪽 다리로 먼저 올라가면 중심이 불안정해질 수 있습니다.", "5": "왼쪽 다리가 아닌 오른쪽 다리를 먼저 올라가는 것은 안전하지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 신체의 마비 상태", "def_vi": "Tình trạng mất khả năng vận động một bên cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (369, '10', '오른쪽 편마비 대상자를 부축하며 걷는 방법으로 옳은 것은?', '["대상자 옆에서 팔로 양 어깨를 껴안듯 잡는다.", "대상자의 오른쪽 어깨를 감싸고, 오른손을 잡고 걷는다.", "서로 같은 편 발을 앞으로 내딛어 발을 맞춰 걷는다.", "대상자의 왼쪽 팔로 요양보호사의 허리를 감싸게 하여 이동한다.", "대상자는 오른쪽 다리를 먼저 내딛도록 한다."]'::jsonb, 5, '오른쪽 편마비 환자를 부축하는 올바른 방법을 찾기 위한 문제입니다.', NULL, '{"1": "대상자의 팔로 양 어깨를 껴안듯 잡는 것은 안정적이지 않습니다.\n[정답]", "5": "대상자는 오른쪽 다리를 먼저 내딛도록 하여 균형을 유지하도록 하는 방법이 올바릅니다.", "2": "오른쪽 어깨를 감싸고 오른손을 잡는 것은 안정성이 떨어집니다.", "3": "같은 편 발을 내딛는 것은 균형을 해칠 수 있습니다.", "4": "대상자의 왼쪽 팔로 허리를 감싸는 것은 불안정할 수 있습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bệnh liệt một bên", "def_ko": "한쪽 신체가 마비된 상태(편 liệt)", "def_vi": "Tình trạng bị liệt một bên cơ thể"}, {"term_ko": "부축", "term_vi": "Hỗ trợ", "def_ko": "걸을 때 도움을 주다", "def_vi": "Giúp đỡ khi đi lại"}, {"term_ko": "올바른", "term_vi": "Đúng", "def_ko": "정확한, 맞는", "def_vi": "Chính xác"}, {"term_ko": "균형", "term_vi": "Cân bằng", "def_ko": "안정된 상태 또는 비율", "def_vi": "Tình trạng ổn định hoặc tỷ lệ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (368, '10', '편마비 대상자를 자동차에서 휠체어로 옮기는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (367, '10', '대상자를 휠체어에서 자동차로 이동시키는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (366, '10', '대상자를 휠체어에서 이동변기로 이동하는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (365, '10', '오른쪽 편마비 대상자를 휠체어에서 방바닥으로 옮기는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (364, '10', '요양보호사 두 사람이 휠체어에 앉아있는 대상자로 침대로 이동할 때 각각 지지해야 하는 부위로 옳은 것은?', '["등과 허리 종아리와 발목", "등과 허리 대퇴(넙다리)와 발목", "겨드랑이와 팔 대퇴(넙다리)와 종아리", "겨드랑이와 가슴 종아리와 발목", "겨드랑이와 가슴 대퇴(넙다리)와 발목"]'::jsonb, 3, '대상자를 침대로 이동할 때, 적절한 지지 부위를 이해하고 선택할 수 있도록 하는 문제입니다.', NULL, '{"1": "등과 허리 종아리와 발목: 지지 부위가 적절하지 않음.\n[정답]", "2": "등과 허리 대퇴(넙다리)와 발목: 지지 부위가 일정하게 분포되어 있지만, 대퇴(넙다리)와 발목의 조합은 비효율적임.", "3": "겨드랑이와 팔 대퇴(넙다리)와 종아리: 겨드랑이와 팔로 안정적으로 지지할 수 있어 올바른 선택.", "4": "겨드랑이와 가슴 종아리와 발목: 효과적인 지지가 부족함.", "5": "겨드랑이와 가슴 대퇴(넙다리)와 발목: 허리와 대퇴(넙다리) 간의 균형이 위태로울 수 있음."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "요양보호를 담당하는 사람", "def_vi": "Người phụ trách chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (363, '10', '휠체어에 타고 있는 오른쪽 편마비 대상자를 침대로 옮기는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (362, '10', '침대에 걸터앉아 있는 오른쪽 편마비 대상자를 휠체어로 이동시키는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (361, '10', '바닥에 누워있는 대상자를 휠체어로 이동하는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (360, '10', '바닥이 울퉁불퉁한 길을 휠체어로 이동할 때 방법으로 옳은 것은?', '["휠체어를 뒤쪽으로 기울이고 앞바퀴를 들어올린다.", "앞바퀴를 들어올린 상태로 뒷바퀴를 천천히 뒤로 빼면서 앞바퀴를 조심히 내려놓는다.", "앞바퀴를 들어올려 뒤로 젖힌 상태에서 이동한다.", "가급적 자세를 낮추고 다리에 힘을 주어 밀고 올라간다.", "휠체어를 뒤로 돌려 뒷걸음으로 내려간다."]'::jsonb, 3, '휠체어 이동 시 바닥 상태에 따라 어떻게 안전하게 이동할 수 있는지를 평가하는 문제입니다.', NULL, '{"1": "휠체어를 뒤쪽으로 기울이면 불안정해지므로 위험할 수 있다.\n[정답]", "2": "앞바퀴를 들어올린 상태로 뒷바퀴를 천천히 빼는 것은 효과적이지만 올바른 방법은 아니므로 정답이 아니다.", "3": "앞바퀴를 들어올려 뒤로 젖힌 상태에서 이동하는 것은 안전한 방법으로 적절하다.", "4": "자세를 낮추고 힘을 주는 것은 하지만 휠체어의 안전한 이동과는 관련이 없다.", "5": "휠체어를 뒤로 돌려 뒷걸음으로 내려가는 것은 안전하지 않은 행동이다."}'::jsonb, '[{"term_ko": "바닥", "term_vi": "울퉁불퉁", "def_ko": "바닥(한국어) / mặt đất: mặt đất(베트남어)", "def_vi": "울퉁불퉁한(한국어) / gồ ghề: gồ ghề(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (359, '10', '대상자가 타고 있는 휠체어를 지그재그로 이동해야 하는 경우로 옳은 것은?', '["도로 턱을 넘을 때", "엘리베이터를 탈 때", "문턱을 내려갈 때", "울퉁불퉁한 길을 갈 때", "경사가 큰 경우 내리막길을 갈 때"]'::jsonb, 5, '휠체어를 안전하게 이동하는 방법에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "도로 턱을 넘을 때, 지그재그로 이동하는 것이 적절하지 않습니다.\n[정답]", "5": "경사가 큰 경우 내리막길을 갈 때, 지그재그로 이동하여 안정성을 확보해야 합니다.", "2": "엘리베이터를 탈 때, 지그재그로 이동할 필요가 없습니다.", "3": "문턱을 내려갈 때, 직진으로 내려가는 것이 더 효율적입니다.", "4": "울퉁불퉁한 길을 갈 때, 지그재그보다 직선 이동이 더 안전합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người sử dụng", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (358, '10', '휠체어로 문턱을 내려갈 때 휠체어 조작 방법으로 옳은 것은?', '["앞바퀴를 들고 앞으로 내려간다.", "뒤로 돌려 뒷걸음으로 한 번에 내려간다.", "바퀴 한쪽씩 지그재그로 앞으로 내려간다.", "뒤로 돌려 바퀴 한쪽씩 지그재그로 내려간다.", "뒤로 돌려 뒷바퀴를 내린 후 앞바퀴를 조심히 내려놓는다."]'::jsonb, 5, '휠체어를 안전하게 조작하는 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "앞바퀴를 들어내고 문턱을 내려가는 것은 안전하지 않습니다.\n[정답]", "5": "뒤로 돌려 뒷바퀴를 내린 후 앞바퀴를 조심히 내려놓는 것이 가장 안전한 방법입니다.", "2": "뒤로 돌려 뒷걸음으로 한 번에 내려가는 것은 위험할 수 있습니다.", "3": "바퀴 한쪽씩 지그재그로 앞으로 내려가는 방법은 불안정할 수 있습니다.", "4": "뒤로 돌려 바퀴 한쪽씩 지그재그로 내려가는 방법도 안전하지 않습니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "이동 보조 기구", "def_vi": "thiết bị hỗ trợ di chuyển"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (357, '10', '휠체어 기본 조작 시 접기 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (356, '10', '기본 체위에 따른 대상자의 적용 상황으로 옳은 것은?', '["앙와위 - 위관 영양을 할 때 자세", "반좌위 - 숨이 찰 때 자세", "복위 - 관장을 할 때 자세", "측위 - 휴식을할 때 자세", "바로 누워 무릎을 세운 자세 - 엉덩이에 욕창이 있을 때 자세"]'::jsonb, 2, '체위에 따른 대상자의 적합한 적용 상황을 이해하고 평가하는 능력을 점검하기 위한 문제입니다.', NULL, '{"1": "위관 영양을 할 때는 일반적으로 반좌위 자세가 추천되므로 잘못된 설명입니다.\n[정답]", "2": "숨이 찰 때는 반좌위 자세가 적합하여 옳은 설명입니다.", "3": "관장을 할 때는 양무릎 위 자세나 앙와위가 일반적으로 사용되므로 잘못된 설명입니다.", "4": "휴식을 할 때는 측위도 가능하지만 더 적합한 자세가 많아 잘못된 설명입니다.", "5": "욕창이 있을 때는 가능한 한 엉덩이에 압력이 가해지지 않는 자세가 필요하므로 잘못된 설명입니다."}'::jsonb, '[{"term_ko": "체위", "term_vi": "Vị trí cơ bản", "def_ko": "자세(한국어)", "def_vi": "Tư thế cơ bản(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (355, '10', '침대에 걸터앉아 있는 대상자를 일으켜 세우는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (354, '10', '대상자를 침대 끝으로 이동하여 걸터앉는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (353, '10', '침상에 누워있는 편마비대상자를 일으켜 앉히는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (352, '10', '침대에 누워있는 대상자를 옆으로 돌려 눕히는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (351, '10', '오른쪽 편마비 대상자가 왼쪽으로 쏠려 누워있을 때 침대 중앙으로 이동시키는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (350, '10', '협조할 수 없는 대상자가 침대 아래로 미끄러져 내려가 누워있을 때 두 명의 요양보호사가 올려 눕히는 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (349, '10', '대상자의 체위변경이나 이동을 도움 때 요양 보호사의 신체손상을 예방하는 방법으로 옳은 것은?', '["대상자와 멀리하여 지지면을 넓힌다.", "허리를 돌리지 않고 발을 움직여 방향을 바꾼다.", "양발을 모으고 다리에 체중을 싣는다.", "허리는 구부리고 무릎을 펴고 무게중심을 높인다.", "손을 이용한 작은 근육을 사용한다."]'::jsonb, 2, '요양 보호사가 체위변경이나 이동을 도와줄 때 신체 손상을 예방할 수 있는 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "대상자를 멀리 두는 것은 올바른 지지면을 확보하지 못하므로 신체 손상을 초래할 수 있습니다.\n[정답]", "2": "허리를 돌리지 않고 발을 움직여 방향을 바꾸는 것은 허리의 부하를 줄여 신체 손상을 예방하는 올바른 방법입니다.", "3": "양발을 모으고 다리에 체중을 싣는 것은 무게중심을 불안정하게 하여 부상의 위험이 있습니다.", "4": "허리를 구부리고 무릎을 펴면 무게중심이 높아져서 신체 손상 위험이 증가합니다.", "5": "손을 이용한 작은 근육을 사용하는 것은 힘의 전달이 비효율적이므로 신체 손상 예방에 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "체위변경", "term_vi": "이동", "def_ko": "자세 thay đổi", "def_vi": "di chuyển"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (348, '10', '수액을 맞고 있는 왼쪽 편마비대상자의 단추가 달린 옷을 벗기는 순서로 옳은 것은?', '["오른쪽 팔 → 수액 → 왼쪽 팔", "오른쪽 팔 → 왼쪽 팔 → 수액", "수액 → 오른쪽 팔 → 왼쪽 팔", "왼쪽 팔 → 오른쪽 팔 → 수액", "왼쪽 팔 → 수액 →오른쪽 팔"]'::jsonb, 1, '편마비대상자의 옷을 안전하고 효율적으로 벗기는 방법을 묻고 있다.', NULL, '{"1": "오른쪽 팔을 먼저 벗기고, 수액 주입을 한 후 왼쪽 팔을 벗기는 것이 안전하다.\n[정답]", "2": "왼쪽 팔을 먼저 벗기면 수액이 끊어질 위험이 있다.", "3": "수액을 먼저 제거하는 것은 위험하다.", "4": "왼쪽 팔이 마비되어 있어 오른쪽 팔이 먼저 벗겨져야 안전하다.", "5": "왼쪽 팔이 마비된 상태이므로 오른쪽 팔부터 벗겨야 한다."}'::jsonb, '[{"term_ko": "수액", "term_vi": "Dịch tĩnh mạch", "def_ko": "체액(한국어)", "def_vi": "Chất lỏng trong cơ thể"}, {"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 팔 및 다리에 마비가 있는 상태(한국어)", "def_vi": "Trạng thái bị liệt một bên cơ thể"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태(한국어)", "def_vi": "Trạng thái không có nguy hiểm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (347, '10', '누워있는 편마비 대상자의 하의를 갈아입힐 때 순서로 옳은 것은?
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (346, '10', '편마비 대상자에게 단추가 없는 상의를 입히는 순서로 옳은 것은?', '["마비된 팔 → 머리 → 건강한 팔", "마비된 팔 → 건강한 팔 → 머리", "머리 → 마비된 팔 → 건강한 팔", "건강한 팔 → 머리 → 마비된 팔", "건강한 팔 → 마비된 팔 → 머리"]'::jsonb, 1, '편마비 환자에게 옷을 입히는 올바른 순서를 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "마비된 팔 → 머리 → 건강한 팔: 편마비 환자에게 가장 적절한 옷 입히기 순서입니다. 옷을 입힐 때는 마비된 쪽의 팔부터 시작하여 머리를 지나 건강한 팔 순으로 입혀야 합니다.\n[정답]", "2": "마비된 팔 → 건강한 팔 → 머리: 이 순서는 옷을 입히는 과정에 적합하지 않습니다.", "3": "머리 → 마비된 팔 → 건강한 팔: 머리부터 시작하는 것은 잘못된 순서입니다.", "4": "건강한 팔 → 머리 → 마비된 팔: 건강한 팔 먼저 입히는 것은 바람직하지 않습니다.", "5": "건강한 팔 → 마비된 팔 → 머리: 후순위로 마비된 팔을 입히는 것은 잘못된 방법입니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bệnh liệt nửa người", "def_ko": "반쪽이 마비된 상태", "def_vi": "Tình trạng bị liệt một nửa cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (345, '10', '치매 대상자의 옷을 갈아입히는 방법으로 옳은 것은?', '["서있는 자세로 옷을 갈아입힌다.", "장식이 많은 옷으로 갈아입는다.", "스스로 옷을 갈아입도록 자리를 피해준다.", "갈아입기를 거부하면 목욕 시간을 이용한다.", "겉옷이 맨 위로 오게 하여 옷을 정리해둔다."]'::jsonb, 4, '치매 대상자의 옷을 갈아입히는 바른 방법에 대한 이해를 점검하기 위함입니다.', NULL, '{"1": "치매 대상자는 서 있는 자세보다 앉는 자세에서 더 안전하게 옷을 갈아입을 수 있습니다.", "2": "장식이 많은 옷은 혼란을 줄 수 있어 바람직하지 않습니다.\n[정답]", "3": "치매 환자가 스스로 옷을 갈아입을 수 있도록 자리를 피해주는 것이 적절합니다.", "4": "갈아입기를 거부할 경우, 목욕 시간을 이용해 자연스럽게 갈아입힐 수 있습니다.", "5": "겉옷이 위로 오게 정리하는 것은 실수할 가능성을 높여줍니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Sa sút trí tuệ", "def_ko": "기억력 및 사고력이 저하되는 질병", "def_vi": "Bệnh giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "옷", "term_vi": "Quần áo", "def_ko": "착용하는 의류", "def_vi": "Trang phục"}, {"term_ko": "갈아입다", "term_vi": "Thay", "def_ko": "옷을 교체하다", "def_vi": "Thay thế"}, {"term_ko": "거부하다", "term_vi": "Từ chối", "def_ko": "무엇인가를 하지 않겠다고 말하다", "def_vi": "Nói rằng không làm một việc gì đó"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 씻는 행위", "def_vi": "Hành động rửa sạch cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (344, '10', '침상목욕을 도울 때 신체부위(A)와 몸 닦기 방향(B)으로 옳은 것은?', '["팔 위팔에서 손목 쪽으로", "유방 목에서 배꼽 쪽으로", "복부 배꼽을 중심으로 시계 반대 방향으로", "다리 발끝에서 허벅지 쪽으로", "회음부 항문에서 요도 쪽으로"]'::jsonb, 4, '침상목욕을 도울 때 적절한 신체부위와 몸 닦기 방향을 알고 있는지를 평가하기 위함입니다.', NULL, '{"1": "팔 위팔에서 손목 쪽으로는 팔의 닦기 방향으로 적절하지 않습니다.\n[정답]", "2": "유방 목에서 배꼽 쪽으로는 위에서 아래로 내려가는 방향으로 적절하지 않습니다.", "3": "복부 배꼽을 중심으로 시계 반대 방향으로는 오히려 알맞지 않은 방향입니다.", "4": "다리 발끝에서 허벅지 쪽으로는 올바른 방향입니다.", "5": "회음부 항문에서 요도 쪽으로도 올바르지 않습니다."}'::jsonb, '[{"term_ko": "침상목욕", "term_vi": "Tắm trên giường", "def_ko": "침대에서 하는 목욕", "def_vi": "Tắm trên giường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (343, '10', '편마비 대상자의 통목욕 돕기 방법으로 옳은 것은?', '["욕조의 턱보다 의자 높이를 낮춘다.", "마비된 쪽 다리부터 욕조에 들어가게 한다.", "말초에서 중심방향으로 닦아준다.", "욕조에 있는 시간을 20~30분 정도로 한다.", "욕조에서 머리를 감긴 후 밖으로 나오게 한다."]'::jsonb, 3, '편마비 환자를 대상으로 한 적절한 통목욕 보조 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "욕조의 턱보다 의자 높이를 낮추는 것은 욕조에 안전하게 들어가기 위한 방법이지만, 통목욕에서는 일반적으로 마비된 쪽의 안전이 더 중요합니다.\n[정답]", "3": "말초에서 중심방향으로 닦아주는 것은 편마비 환자의 피부를 자극하지 않으면서 깨끗하게 유지할 수 있는 방법입니다.", "2": "마비된 쪽 다리부터 욕조에 들어가게 하는 것은 환자의 안전을 위협할 수 있으므로 바람직하지 않습니다.", "4": "욕조에 있는 시간을 20~30분 정도로 하는 것은 일반적인 목욕 기준이긴 하지만, 편마비 환자에게는 개인의 상태에 따라 조절이 필요합니다.", "5": "욕조에서 머리를 감긴 후 밖으로 나오게 하는 것은 안전 문제를 야기할 수 있으므로 주의가 필요합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸의 마비 상태", "def_vi": "Tình trạng tê liệt một bên cơ thể"}, {"term_ko": "통목욕", "term_vi": "Tắm ngâm", "def_ko": "전체 몸을 담그는 목욕", "def_vi": "Tắm trên toàn bộ cơ thể"}, {"term_ko": "말초", "term_vi": "Ngoại vi", "def_ko": "신체의 끝 부분", "def_vi": "Phần xa cơ thể"}, {"term_ko": "중심방향", "term_vi": "Hướng vào giữa", "def_ko": "몸의 중심으로 향하는 방향", "def_vi": "Hướng vào trung tâm cơ thể"}, {"term_ko": "욕조", "term_vi": "Bồn tắm", "def_ko": "목욕을 위한 큰 통", "def_vi": "Thùng tắm lớn"}, {"term_ko": "다리", "term_vi": "Chân", "def_ko": "신체의 아래쪽 부분", "def_vi": "Phần dưới của cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (342, '10', '목욕을 하는 동안 대상자의 체온이 떨어지지 않도록 돕는 방법으로 옳은 것은?', '["욕실 문을 열어 습기를 제거한다.", "목욕 중 몸에 따뜻한 물을 자주 뿌려준다.", "목욕 후 몸의 물기는 자연 건조 되게 한다.", "목욕물의 온도는 50˚C 이상이 되도록 한다.", "시원한 우유를 마셔 수분을 보충해준다."]'::jsonb, 2, '대상자의 체온을 유지하는 방법에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "욕실 문을 열면 외부 공기가 들어오고, 습기가 저절로 제거되지만, 이는 체온 유지에 도움이 되지 않습니다.\n[정답]", "2": "목욕 중 따뜻한 물을 몸에 자주 뿌리는 것은 체온이 떨어지지 않도록 돕는 방법입니다.", "3": "목욕 후 몸의 물기가 자연 건조되면 체온이 떨어질 수 있습니다.", "4": "목욕물의 온도는 너무 높으면 화상을 입을 수 있으며 안전하지 않습니다.", "5": "시원한 우유는 체온 유지에 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "체온", "term_vi": "Nhiệt độ cơ thể", "def_ko": "몸의 온도", "def_vi": "Nhiệt độ cơ thể"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 깨끗하게 하는 행위", "def_vi": "Hành động gội rửa cơ thể"}, {"term_ko": "물기", "term_vi": "Độ ẩm", "def_ko": "물의 존재", "def_vi": "Sự tồn tại của nước"}, {"term_ko": "자연", "term_vi": "Tự nhiên", "def_ko": "자연스럽게", "def_vi": "Tự nhiên"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (341, '10', '침상에서 세수하는 대상자를 돕는 방법으로 옳은 것은?', '["침대를 수평으로 하여 똑바로 눕힌다.", "코, 뺨, 눈, 귀, 목 순으로 닦는다.", "귀지 제거는 의료기관에서 시행한다.", "입술과 그 주변을 알코올 솜으로 닦아낸다.", "수건에 비누를 묻혀 눈의 안쪽에서 바깥쪽으로 닦아준다."]'::jsonb, 3, '대상자에게 안전하고 올바른 방법으로 세수하는 절차를 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "침대를 수평으로 하여 똑바로 눕히는 것은 안전상 좋으나, 세수와 관련된 방법이 아닙니다.\n[정답]", "3": "귀지 제거는 의료기관에서 시행하는 것이 맞으며, 가정에서 하지 않는 것이 안전합니다.", "2": "코, 뺨, 눈, 귀, 목 순으로 닦는 것은 일반적이지 않으며, 세수 순서가 바람직하지 않습니다.", "4": "입술과 그 주변을 알코올 솜으로 닦는 것은 적절하지 않을 수 있으며, 자극을 줄 수 있습니다.", "5": "수건에 비누를 묻혀 눈의 안쪽에서 바깥쪽으로 닦는 것은 잘못된 방법으로, 눈에 자극을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "giường ngủ"}, {"term_ko": "세수", "term_vi": "Rửa mặt", "def_ko": "얼굴을 씻다(한국어)", "def_vi": "rửa mặt"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "người bệnh"}, {"term_ko": "귀지", "term_vi": "Ráy tai", "def_ko": "귀에서 나오는 찌꺼기(한국어)", "def_vi": "chất nhờn trong tai"}, {"term_ko": "알코올", "term_vi": "Cồn", "def_ko": "알코올 (소독제)(한국어)", "def_vi": "chất khử trùng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (340, '10', '남서 대상자의 회음부 청결 돕기 방법으로 옳은 것은?', '["요로감염 예방을 위해 멸균장갑을 착용한다.", "둔부 밑에 변기를 넣은 다음 그 아래에 방수포를 깐다.", "차가운 물을 음부에 끼얹은 다음 비누로 닦는다.", "음경을 수건으로 잡고 피부가 겹치는 부분과 음낭의 뒷면을 닦는다.", "세안 후에 사용한 수건으로 음경을 잡고 닦는다."]'::jsonb, 4, '회음부 청결을 돕는 방법에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "요로감염 예방을 위해 멸균장갑을 착용하는 것은 중요하지만, 회음부 청결을 돕기 위해서는 반드시 필요한 조치는 아닙니다.\n[정답]", "2": "둔부 밑에 변기를 넣은 다음 그 아래에 방수포를 깔고, 청결을 유지하는 것이 좋은 방법입니다.", "3": "차가운 물을 음부에 끼얹는 것은 피부를 자극할 수 있으므로 바람직하지 않습니다.", "4": "음경을 수건으로 잡고 피부가 겹치는 부분과 음낭의 뒷면을 닦는 것이 가장 적절한 방법입니다.", "5": "세안 후에 사용한 수건으로 음경을 잡고 닦는 것은 위생적인 방법이 아닙니다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": "Vùng âm đạo", "def_ko": "생식기와 항문 사이의 부위", "def_vi": "Vùng giữa bộ phận sinh dục và hậu môn"}, {"term_ko": "요로감염", "term_vi": "Nhiễm trùng đường tiết niệu", "def_ko": "요로에서 발생하는 감염", "def_vi": "Nhiễm trùng xảy ra trong đường tiết niệu"}, {"term_ko": "멸균장갑", "term_vi": "Găng tay tiệt trùng", "def_ko": "감염을 예방하기 위한 장갑", "def_vi": "Găng tay dùng để ngăn ngừa nhiễm trùng"}, {"term_ko": "음경", "term_vi": "Dương vật", "def_ko": "남성의 성기", "def_vi": "Bộ phận sinh dục nam"}, {"term_ko": "음낭", "term_vi": "Bìu", "def_ko": "음경을 보호하는 피부 주머니", "def_vi": "Túi da bảo vệ dương vật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (339, '10', '여성 대상자의 회음부를 청결하게 하는 방법으로 옳은 것은?', '["대상자를 눕혀 무릎을 펴고 다리를 벌리게 한다.", "목욕담요를 마름모꼴로 하여 몸통과 다리를 덮어준다.", "항문 - 요도 - 질 순서로 뒤쪽에서 앞으로 닦는다.", "대상자가 수치심을 느낀다면 닦지 않는다.", "회음부에 분비물이 있으면 소독해준다."]'::jsonb, 2, '여성 대상자의 회음부 청결 관리에 대한 올바른 방법을 질문하는 것입니다.', NULL, '{"1": "대상자를 눕히고 무릎을 펴고 다리를 벌리게 하는 것은 청결 관리를 위한 적절한 자세가 아닙니다. \n[정답]", "2": "목욕담요를 마름모꼴로 하여 몸통과 다리를 덮어주면 프라이버시를 보호하면서 청결하게 관리할 수 있습니다.", "3": "항문 - 요도 - 질 순서로 닦는 것은 청결도와 관련하여 잘못된 방법입니다.", "4": "대상자가 수치심을 느낀다면 청결 관리 방법이 적절하지 않기 때문에 권장하지 않습니다.", "5": "회음부에 분비물이 있을 경우 소독하기보다는 적절한 세척이 필요합니다."}'::jsonb, '[{"term_ko": "회음부", "term_vi": null, "def_ko": "외부 생식기와 항문 사이의 부위", "def_vi": null}, {"term_ko": "청결", "term_vi": null, "def_ko": "깨끗함", "def_vi": null}, {"term_ko": "대상자", "term_vi": null, "def_ko": "돌봄을 받는 사람", "def_vi": null}, {"term_ko": "수치심", "term_vi": null, "def_ko": "부끄러움을 느끼는 감정", "def_vi": null}, {"term_ko": "분비물", "term_vi": null, "def_ko": "체내에서 만들어져 나오는 액체", "def_vi": null}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (338, '10', '대상자가 부끄럽다며 회음부 씻는 것을 거부할 때 대처 방법으로 옳은 것은?', '["대상자가 요청할 때 까지 기다린다.", "보호자에게 연락하여 도움을 청한다.", "대상자의 거부의사를 존중하고 세척하지 않는다.", "전용 물수건을 제공하여 스스로 씻을 수 있게 한다.", "청결을 위해 본인 의사와 관계없이 씻긴다."]'::jsonb, 4, '대상자가 회음부 씻기 거부 시 적절한 대처 방법을 묻는 질문입니다.', NULL, '{"1": "대상자가 요청할 때까지 기다리는 것은 세척을 미루는 것이므로 적절하지 않습니다.\n[정답]", "4": "전용 물수건을 제공하여 스스로 씻을 수 있게 하는 것은 대상자의 자율성을 존중하면서 청결을 유지할 수 있는 방법입니다.", "2": "보호자에게 연락하여 도움을 청하는 것은 주로 의료적 상황에서 필요하지만, 현재 상황에서는 적절하지 않습니다.", "3": "대상자의 거부 의사를 존중하는 것은 중요하지만, 세척이 필요한 경우에는 다른 방법이 필요합니다.", "5": "청결을 위해 본인의 의사와 관계없이 씻기는 것은 권리 침해가 될 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (337, '10', '대상자의 머리손질을 돕는 방법으로 옳은 것은?', '["손톱으로 두피를 마사지한다.", "빗질은 두피에서 모발 끝 쪽으로 한다.", "두피 손상이 있으면 연고를 발라준다.", "두피건강을 위해 잡아당기며 손질한다.", "엉킨 머리카락은 두발세정제를 발라 벗긴다."]'::jsonb, 2, '대상자의 머리손질에 대한 기본적인 방법과 올바른 절차를 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "손톱으로 두피를 마사지하는 것은 자극을 줄 수 있으므로 바람직하지 않습니다.\n[정답]", "2": "빗질은 두피에서 모발 끝 쪽으로 하는 것이 올바른 방법입니다.", "3": "두피 손상이 있는 경우에는 직접적으로 연고를 바르는 것이 아닌 의사의 처방이 필요합니다.", "4": "두피 건강을 위해서는 잡아당기지 않고 부드럽게 손질해야 합니다.", "5": "엉킨 머리카락은 두발세정제가 아닌 전용 헤어 제품 또는 전용 빗을 활용해야 합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người chăm sóc", "def_ko": "환자나 돌봐야 할 사람", "def_vi": "Bệnh nhân hoặc người cần được chăm sóc"}, {"term_ko": "머리손질", "term_vi": "Chăm sóc tóc", "def_ko": "머리를 씻거나 빗는 등의 행동", "def_vi": "Hành động như gội đầu hoặc chải tóc"}, {"term_ko": "두피", "term_vi": "Da đầu", "def_ko": "머리의 피부", "def_vi": "Da của đầu"}, {"term_ko": "모발", "term_vi": "Tóc", "def_ko": "머리카락", "def_vi": "Tóc"}, {"term_ko": "연고", "term_vi": "Thuốc bôi", "def_ko": "피부에 바르는 약제", "def_vi": "Dược phẩm bôi trên da"}, {"term_ko": "잡아당기다", "term_vi": "Kéo", "def_ko": "힘으로 끌어당기다", "def_vi": "Kéo hoặc lôi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (336, '10', '대상자의 손발 청결을 위한 관리 방법으로 옳은 것은?', '["보온을 위해 모직 양말을 신긴다.", "피부가 자극되도록 마사지한다.", "피부 건조 예방을 위해 오일을 발라준다.", "손톱은 일자, 발톱은 둥글게 잘라준다.", "안쪽으로 파고드는 발톱은 알코올로 소독해준다."]'::jsonb, 3, '대상자의 손발 청결을 위한 관리 방법을 평가하는 것.', NULL, '{"1": "양말을 신기는 것은 보온 효과가 있지만 청결 관리와는 직접적인 관련이 없다.\n[정답]", "3": "피부 건조 예방을 위해 오일을 발라주는 것은 손발 청결 유지에 도움을 준다.", "2": "자극적인 마사지는 피부에 해로울 수 있다.", "4": "손톱을 일자, 발톱을 둥글게 자르는 것은 일반적인 팁이지만, 청결과는 다소 거리가 있다.", "5": "발톱 소독은 필요할 수 있으나 알코올은 자극을 줄 수 있어 주의해야 한다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (335, '10', '드라이샴푸를 이용하여 머리를 감기는 방법으로 옳은 것은?', '["드라이샴푸를 모발에 발라 거품이 나도록 마사지한다.", "머리카락에 물을 적신 후 드라이샴푸를 충분히 바른다.", "드라이샴푸를 모발에 발라 두피에서 모발 끝으로 빗질을 한다.", "드라이샴푸를 모발에 바르고 샴푸로 헹구어낸다.", "드라이샴푸를 수건에 묻혀 모발을 닦아낸다."]'::jsonb, 1, '드라이샴푸 사용법에 대한 정확한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "드라이샴푸를 모발에 발라 거품이 나도록 마사지한다. [정답] 드라이샴푸는 일반적으로 모발에 직접 발라 마사지하여 기름기를 흡수하는 방식이므로 옳은 방법입니다.", "2": "머리카락에 물을 적신 후 드라이샴푸를 충분히 바른다. 물과 함께 사용하면 드라이샴푸의 효과가 감소할 수 있습니다.", "3": "드라이샴푸를 모발에 발라 두피에서 모발 끝으로 빗질을 한다. 빗질 후 남은 잔여물이 있을 수 있어 적절하지 않습니다.", "4": "드라이샴푸를 모발에 바르고 샴푸로 헹구어낸다. 드라이샴푸는 일반 샴푸처럼 헹구지 않고 사용해야 합니다.", "5": "드라이샴푸를 수건에 묻혀 모발을 닦아낸다. 이는 효과적인 사용법이 아닙니다."}'::jsonb, '[{"term_ko": "드라이샴푸", "term_vi": "Dầu gội khô", "def_ko": "샴푸 없이 사용 가능한 헤어 제품", "def_vi": "Sản phẩm chăm sóc tóc có thể sử dụng không cần gội"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (334, '10', '침상에 누워있는 대상자의 머리를 감기기 위한 준비로 옳은 것은?', '["샤워기 물은 요양보호사의 손등으로 확인한다.", "대상자의 눈과 귀에 수건을 올려 덮는다.", "대상자의 머리를 침대 모서리에 오게 한다.", "방수포를 머리 밑에서 목까지 깐다.", "수건으로 가슴부터 허리까지 감싼다."]'::jsonb, 3, '대상자의 머리를 세정하기 위한 올바른 준비 과정을 이해하는지 평가하기 위함입니다.', NULL, '{"1": "샤워기 물은 손등을 사용하여 확인하는 것은 적절하지 않습니다. 온도 확인은 신중하게 해야 합니다.\n[정답]", "2": "대상자의 눈과 귀를 수건으로 덮는 것은 중요한 보호 조치입니다.", "3": "대상자의 머리를 침대 모서리에 위치시키는 것은 안전한 방법입니다.", "4": "방수포를 깔아야 하지만, 목까지가 아니라 머리 아래에만 깔아야 합니다.", "5": "수건으로 가슴을 감싸는 것은 권장하지 않으며, 방법이 안전하지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자, 고객", "def_vi": "bệnh nhân, khách hàng"}, {"term_ko": "머리", "term_vi": "Đầu", "def_ko": "머리", "def_vi": "đầu"}, {"term_ko": "수건", "term_vi": "Khăn", "def_ko": "수건", "def_vi": "khăn"}, {"term_ko": "방수포", "term_vi": "Nilon", "def_ko": "방수포", "def_vi": "nilon"}, {"term_ko": "올바른", "term_vi": "Đúng", "def_ko": "올바른, 맞는", "def_vi": "đúng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (333, '10', '의치 세정제가 없을 때 대체할 수 있는 것으로 옳은 것은?', '["치약", "레몬즙", "주방세제", "표백제", "과탄화수소"]'::jsonb, 3, '의치 세정제의 대체품에 대한 이해를 평가하고자 함.', NULL, '{"1": "치약은 의치 세정용으로 적합하지 않음.\n[정답]", "2": "레몬즙은 산성으로 세척에 도움을 줄 수 있으나, 의치 세정제로 적합하지 않음.", "3": "주방세제는 기름기 제거에 효과적이며, 의치 세정제로도 사용 가능함.", "4": "표백제는 독성이 있어 사용하면 안됨.", "5": "과탄화수소는 산화제로 적합하지 않음."}'::jsonb, '[{"term_ko": "의치", "term_vi": "Răng giả", "def_ko": "틀니", "def_vi": "Hàm giả"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (332, '10', '대상자의 머리를 감기는 방법으로 옳은 것은?', '["두피를 손톱으로 마사지한다.", "공복과 식후를 피하여 감긴다.", "모발 끝에서 두피 쪽으로 빗질한다.", "머리카락을 비비며 물기를 말린다.", "두피에 상처가 있으면 연고를 발라준다."]'::jsonb, 2, '대상자의 머리 감기는 방법에 대한 올바른 지식을 확인하기 위한 문제입니다.', NULL, '{"1": "두피를 손톱으로 마사지하는 것은 상처를 유발할 수 있으므로 옳지 않습니다.\n[정답]", "2": "공복과 식후를 피하여 감기는 것이 일반적인 요양 방법으로, 대상자의 편안함을 고려한 올바른 방법입니다.", "3": "모발 끝에서 두피 쪽으로 빗질하면 엉킴이 발생할 수 있습니다.", "4": "머리카락을 비비며 물기를 말리는 것은 모발 손상의 원인이 될 수 있습니다.", "5": "두피에 상처가 있으면 연고를 바르는 것은 예외적인 조치가 필요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "머리", "term_vi": "Đầu", "def_ko": "머리(한국어)", "def_vi": "Đầu"}, {"term_ko": "두피", "term_vi": "Da đầu", "def_ko": "머리 피부(한국어)", "def_vi": "Da đầu"}, {"term_ko": "마사지", "term_vi": "Mát-xa", "def_ko": "마사지하다(한국어)", "def_vi": "Mát-xa"}, {"term_ko": "공복", "term_vi": "Đói", "def_ko": "공복 상태(한국어)", "def_vi": "Trạng thái đói"}, {"term_ko": "물기", "term_vi": "Nước", "def_ko": "물기가 있는 상태(한국어)", "def_vi": "Nước"}, {"term_ko": "상처", "term_vi": "Vết thương", "def_ko": "손상(한국어)", "def_vi": "Vết thương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (331, '10', '대상자의 의치를 관리하는 방법으로 옳은 것은?', '["하루 12시간 이상 의치를 빼놓는다.", "의치를 표백제에 담가 세척한다.", "의치를 뺄 때 아래쪽부터 천천히 뺀다.", "냉수가 담긴 보관용기에 담아 보관한다.", "취침 전 의치를 세척 후 다시 끼워준다."]'::jsonb, 4, '대상자의 의치 관리에 대한 기본적인 지식을 평가하기 위함입니다.', NULL, '{"1": "하루 12시간 이상 의치를 빼놓는 것은 치아 건강에 좋지 않으므로 부적절합니다.\n[정답]", "4": "냉수가 담긴 보관용기에 담아 보관하는 것은 의치를 안전하게 유지하는 방법입니다.", "2": "의치를 표백제에 담가 세척하면 의치 재료를 손상시킬 수 있습니다.", "3": "의치를 뺄 때 아래쪽부터 천천히 뺀다라는 방법은 잘못된 방법입니다.", "5": "취침 전 의치를 세척 후 다시 끼워주는 것은 비위생적일 수 있습니다."}'::jsonb, '[{"term_ko": "의치", "term_vi": "Dụng cụ răng giả", "def_ko": "틀니", "def_vi": "Hộp chứa dụng cụ này"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (330, '10', '칫솔질을 할 때 유의사항으로 옳은 것은?', '["치약을 칫솔위에 두툼하게 올린다.", "칫솔 각도는 90˚로 닦는다.", "치아에서 잇몸 쪽으로 닦는다.", "구토를 유발하므로 혀는 닦지 않는다.", "혈액응고 대상자는 치실을 사용하지 않는다."]'::jsonb, 5, '칫솔질을 할 때 주의해야 할 사항에 대한 이해를 평가하려는 문제입니다.', NULL, '{"1": "치약을 너무 많이 올리면 불필요한 낭비가 발생하고 효과적인 칫솔질을 방해합니다.\n[정답]", "5": "혈액응고 대상자는 치실을 사용하지 않아야 하며, 출혈 위험이 있으므로 주의해야 합니다.", "2": "칫솔 각도는 45˚로 기울여서 닦는 것이 올바릅니다.", "3": "칫솔질은 잇몸에서 치아 방향으로 하는 것이 바람직하지만, 이 방향으로만 닦으면 어려움이 있습니다.", "4": "혀는 구강 위생을 위해 브러시로 닦는 것이 좋습니다."}'::jsonb, '[{"term_ko": "칫솔질", "term_vi": "Đánh răng", "def_ko": "이는 닦다(한국어)", "def_vi": "Làm sạch răng miệng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (329, '10', '대상자의 구강청결을 돕는 방법으로 옳은 것은?', '["입안을 닦아 낼 때는 목젖까지 닦는다.", "일회용 스펀지에 치약을 묻혀 닦는다.", "대상자를 똑바로 눕힌 자세에서 닦는다.", "구강 점막에 염증이 있으면 구강청정제로 닦는다.", "위쪽 잇몸과 이를 닦은 후 아래쪽 잇몸과 이를 닦는다."]'::jsonb, 5, '대상자의 구강청결을 효과적으로 유지하기 위한 방법을 이해하고 있는지를 평가하기 위한 문제이다.', NULL, '{"1": "입안을 닦는 방법으로 목젖까지 닦는 것은 잘못된 방법이다. \n[정답]", "5": "위쪽 잇몸과 이를 닦은 후 아래쪽 잇몸과 이를 닦는 것이 올바른 순서이다.", "2": "일회용 스펀지의 사용은 필요에 따라 가능하지만 치약을 묻혀 닦는 것은 적절하지 않다.", "3": "구강청결은 환자가 편안한 자세에서 이루어져야 하므로 똑바로 눕힌 자세는 바람직하지 않다.", "4": "구강 점막에 염증이 있는 경우에는 구강청결제를 사용하지 않는 것이 좋다."}'::jsonb, '[{"term_ko": "구강청결", "term_vi": "Sát khuẩn miệng", "def_ko": "구강 위생 유지(한국어)", "def_vi": "Duy trì vệ sinh miệng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (328, '10', '장루보유 대상자의 관리 방법으로 옳은 것은?', '["복벽을 통해 체외로 소변을 배설시키는 소변통로다.", "주머니에서 냄새가 나면 비운다.", "주 1회 정도 주기로 교환한다.", "장루주머니의 불편감은 무시한다.", "무른 변을 예방하기 위해 수분섭취를 줄인다."]'::jsonb, 3, '장루보유 대상자의 관리 방법을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "복벽을 통해 체외로 소변을 배설시키는 소변통로는 장루와는 관련이 없습니다.\n[정답]", "3": "장루주머니는 일반적으로 주 1회 정도 주기로 교환하는 것이 바람직합니다.", "2": "주머니에서 냄새가 나면 즉시 비우는 것이 좋습니다.", "4": "장루주머니의 불편감은 무시하면 안 됩니다.", "5": "무른 변을 예방하기 위해서는 오히려 수분 섭취를 충분히 해야 합니다."}'::jsonb, '[{"term_ko": "장루", "term_vi": "Ống tiêu hóa", "def_ko": "장이 외부로 나오는 것(한국어)", "def_vi": "Đường tiêu hóa"}, {"term_ko": "주머니", "term_vi": "Túi", "def_ko": "수집하는 용기(한국어)", "def_vi": "Bình chứa"}, {"term_ko": "불편감", "term_vi": "Cảm giác khó chịu", "def_ko": "불편한 느낌(한국어)", "def_vi": "Cảm giác không thoải mái"}, {"term_ko": "변", "term_vi": "Phân", "def_ko": "배설물(한국어)", "def_vi": "Chất thải"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (327, '10', '요루보유 대상자의 관리 방법으로 옳은 것은?', '["요루 안으로 물이 들어가므로 통목욕을 금한다.", "통목욕 시에는 주머니의 소변을 비우고 주머니를 착용한다.", "주머니의 소변이 가득 차면 비운다.", "주머니의 소변이 새면 교환한다.", "샤워 시 물이 안으로 들어가므로 주머니를 떼지 않는다."]'::jsonb, 2, '요루보유 대상자의 관리 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "요루 안으로 물이 들어가므로 통목욕을 금한다. 이는 요루가 물에 닿으면 감염 위험이 있을 수 있기 때문에 일반적인 관리 방법입니다.\n[정답]", "2": "통목욕 시에는 주머니의 소변을 비우고 주머니를 착용한다. 이는 목욕 중 요루의 안전한 관리를 위해 권장되는 방법입니다.", "3": "주머니의 소변이 가득 차면 비운다. 일정 시간마다 비우는 것이 필요하지만, 통목욕 시 주머니를 비우는 것이 중요합니다.", "4": "주머니의 소변이 새면 교환한다. 이는 필요하지만 통목욕과 관련된 직접적인 지침은 아닙니다.", "5": "샤워 시 물이 안으로 들어가므로 주머니를 떼지 않는다. 확실히 주머니를 떼지 않는 것이 좋지만, 관리 방법에 대한 질문의 맥락에서 통목욕 시에는 주머니 비움이 우선입니다."}'::jsonb, '[{"term_ko": "요루", "term_vi": "Y tá", "def_ko": "인공적으로 만들어진 배뇨 경로", "def_vi": "Đường tiểu nhân tạo"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (326, '10', '유치도뇨관을 삽입하고 있는 대상자에게서 다음과 같은 상황이 관찰될 때 간호사에게 보고해야 하는 상황으로 옳은 것은?', '["연결관이 꼬여 있는 경우", "소변이 도뇨관 밖으로 새는 경우", "소변주머니가 가득 차있는 경우", "소변주머니를 들고 걸어 다니는 경우", "소변주머니의 배출구가 잠겨있는 경우"]'::jsonb, 2, '유치도뇨관을 삽입한 환자의 상태를 모니터링하며 문제 상황을 판단하고 대응할 수 있는지를 확인하기 위한 문제입니다.', NULL, '{"1": "연결관이 꼬여 있는 경우: 연결관이 꼬인 경우 관리를 필요로 하지만 즉각적인 보고가 필요하지 않습니다.\n[정답]", "2": "소변이 도뇨관 밖으로 새는 경우: 이는 즉각적인 문제로, 간호사에게 보고해야 합니다.", "3": "소변주머니가 가득 차있는 경우: 소변주머니의 내용물은 정기적으로 비워져야 하나, 즉각적인 보고 사안은 아닙니다.", "4": "소변주머니를 들고 걸어 다니는 경우: 이는 환자의 이동 방법으로, 문제가 아니라 주의가 필요합니다.", "5": "소변주머니의 배출구가 잠겨있는 경우: 이 또한 문제이나 즉각적인 보고가 필요하지 않습니다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "체내에 놓인 소변관", "def_vi": "Ống dẫn nước tiểu vào cơ thể"}, {"term_ko": "소변", "term_vi": "Nước tiểu", "def_ko": "체내의 노폐물로 포함된 액체", "def_vi": "Chất lỏng chứa chất thải trong cơ thể"}, {"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 저장하는 용기", "def_vi": "Bình chứa nước tiểu"}, {"term_ko": "배출구", "term_vi": "Cổng xả", "def_ko": "내용물을 내보내는 부분", "def_vi": "Phần xả ra ngoài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (325, '10', '유치도뇨관을 삽입하고 있는 대상자에게 요로감염이 발생할 수 있는 상황으로 옳은 것은?', '["매일 충분한 수분을 섭취하고 있다.", "소변주머니가 방광 위치보다 높게 두고 있다.", "소변의 양과 색깔을 2~3시간마다 확인한다.", "소변주머니가 침대 매트리스 아래쪽에 고정되어 있다.", "배출구가 잠그고 알코올 솜으로 소독 후 제자리에 꽂는다."]'::jsonb, 2, '유치도뇨관 삽입 환자에게 요로감염이 발생할 수 있는 상황을 파악하는 것이다.', NULL, '{"1": "매일 충분한 수분을 섭취하면 오히려 요로감염 예방에 도움이 된다.\n[정답]", "2": "소변주머니가 방광 위치보다 높게 두고 있으면 소변이 역류하여 감염 위험이 증가할 수 있다.", "3": "소변의 양과 색깔을 2~3시간마다 확인하는 것은 감염 예방에 도움이 된다.", "4": "소변주머니가 침대 매트리스 아래쪽에 고정되어 있으면 역류 가능성이 있어 감염 위험이 높아질 수 있다.", "5": "배출구를 잠그고 알코올 솜으로 소독 후 제자리에 꽂으면 감염 예방 조치를 취한 것으로 적절하다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "방광에 소변을 배출하기 위해 삽입하는 관", "def_vi": "Ống được đặt vào bàng quang để thải nước tiểu"}, {"term_ko": "요로감염", "term_vi": "Nhiễm trùng đường tiết niệu", "def_ko": "요로에 발생하는 감염", "def_vi": "Nhiễm trùng xảy ra trong đường tiết niệu"}, {"term_ko": "소변주머니", "term_vi": "Túi tiểu", "def_ko": "방광에서 나오는 소변을 저장하는 기기", "def_vi": "Thiết bị lưu trữ nước tiểu từ bàng quang"}, {"term_ko": "역류", "term_vi": "Chảy ngược", "def_ko": "소변이 뒤로 흐르는 현상", "def_vi": "Hiện tượng nước tiểu chảy ngược lại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (324, '10', '유치도뇨관을 삽입하고 있는 대상자가 아랫배에 가스가 찬 것처럼 불편해요.라고 호소할 때 대처방법으로 옳은 것은?', '["소화제를 제공한다.", "소변주머니를 비워준다.", "도뇨관이 꺾여있는지 확인한다.", "따뜻한 물주머니를 복부에 대어준다.", "침대 머리를 올려 반좌위를 취하게 한다."]'::jsonb, 3, '유치도뇨관 삽입 후 불편감을 호소하는 대상자에게 올바른 대처방법을 파악하는 것이 이 문제의 의도입니다.', NULL, '{"1": "소화제를 제공한다: 소화제는 가스 불편감에 직접적인 도움이 되지 않습니다.\n[정답]", "2": "소변주머니를 비워준다: 소변주머니를 비우면 편안해질 수 있지만 문제의 상황과는 직접적인 연관이 없습니다.", "3": "도뇨관이 꺾여있는지 확인한다: 도뇨관의 상태를 확인하는 것이 가장 적절한 대처입니다.", "4": "따뜻한 물주머니를 복부에 대어준다: 따뜻한 물주머니는 불편감 완화에 도움을 줄 수 있지만 근본적인 문제 해결에는 미치지 못합니다.", "5": "침대 머리를 올려 반좌위를 취하게 한다: 조금 더 편안함을 제공할 수 있지만, 도뇨관이 꺾인 경우에는 별로 의미가 없습니다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông niệu", "def_ko": "배뇨를 위한 관", "def_vi": "Ống sử dụng để tiểu tiện"}, {"term_ko": "소화제", "term_vi": "Thuốc tiêu hóa", "def_ko": "소화에 도움을 주는 약물", "def_vi": "Thuốc giúp tiêu hóa"}, {"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 받는 용기", "def_vi": "Bình chứa nước tiểu"}, {"term_ko": "도뇨관", "term_vi": "Ống thông", "def_ko": "소변을 배출하기 위해 삽입하는 관", "def_vi": "Ống được đặt để thải nước tiểu"}, {"term_ko": "꺾이다", "term_vi": "Gập lại", "def_ko": "접히다", "def_vi": "Bị gập"}, {"term_ko": "따뜻한", "term_vi": "Ấm", "def_ko": "따뜻한 상태", "def_vi": "Nóng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (323, '10', '유치도뇨관을 삽입하고 있는 대상자의 보행을 돕는 방법으로 옳은 것은?', '["유치도뇨관을 잠근 후 보행하게 한다.", "수분 섭취를 제한하면서 보행하게 한다.", "유치도뇨관을 새것으로 교체한 후 보행하게 한다.", "소변주머니를 아랫배보다 아래로 오도록 들고 보행하게 한다.", "하루 2~3시간만 보행하게 한다."]'::jsonb, 4, '유치도뇨관을 삽입한 대상자의 안전한 보행 방법을 이해하고 이를 통해 환자의 상태를 올바르게 관리할 수 있는지를 평가하고자 함.', NULL, '{"1": "유치도뇨관을 잠그면 소변이 배출되지 않아 문제를 일으킬 수 있다.\n[정답]", "4": "소변주머니를 아랫배보다 아래로 오도록 들고 보행하게 하면, 소변의 역류를 방지할 수 있어 안전하다.", "2": "수분 섭취를 제한하면 환자의 건강에 좋지 않다.", "3": "유치도뇨관을 새것으로 교체한 후에는 환자가 안정 상태여야 하며 즉시 보행하는 것은 바람직하지 않다.", "5": "보행 시간을 제한하는 것은 환자의 운동 능력의 향상에 방해가 될 수 있다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "소변을 정기적으로 배출하기 위해 삽입하는 도관", "def_vi": "Ống được đặt để thải nước tiểu định kỳ"}, {"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 저장하는 가방", "def_vi": "Túi chứa nước tiểu"}, {"term_ko": "보행", "term_vi": "Đi bộ", "def_ko": "걷는 행동", "def_vi": "Hành động đi lại"}, {"term_ko": "건강", "term_vi": "Sức khỏe", "def_ko": "신체적, 정신적으로 좋은 상태", "def_vi": "Tình trạng tốt về thể chất và tâm lý"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (322, '10', '협조가 불가능한 대상자의 기저귀를 갈아 주는 방법으로 옳은 것은?', '["소변이 조금 묻은 기저귀는 말려서 재사용한다.", "피부의 발적을 발견했을 때 연고를 발라준다", "옆으로 돌려 눕혀 기저귀를 교환한다.", "냄새가 나지 않도록 기저귀를 단단히 조여 채운다.", "기저귀를 두 개씩 겹쳐서 채운다."]'::jsonb, 3, '협조가 불가능한 대상자에게 기저귀를 교환하는 올바른 방법을 묻는 문제입니다.', NULL, '{"1": "기저귀는 일회용이며 재사용하면 감염의 위험이 있습니다.\n[정답]", "3": "옆으로 돌려 눕히는 방법은 기저귀 교환 시 안전하고 효과적인 방법입니다.", "2": "피부 발적을 발견했을 때 연고를 바르는 것은 필요하지만 기저귀 교환 전에 확인해야 하는 점입니다.", "4": "어른의 욕실에서 냄새를 방지하기 위해 기저귀를 단단히 조여 채우는 것은 오히려 불편함을 줄 수 있습니다.", "5": "기저귀를 두 개씩 겹쳐 채우는 것은 적절하지 않으며, 기저귀의 본래 목적을 해치는 행동입니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "tã(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (321, '10', '한쪽으로만 누워있는 대상자가 기저귀 밖으로 소변이 샐 때 대처방법으로 옳은 것은?', '["기저귀 안에 속 기저귀를 한 개 더 채워준다.", "기저귀 밑에 방수포를 깔아둔다.", "정해진 시간에 기저귀를 갈아준다.", "몸 한쪽에 베개를 대는 방식으로 체위를 자주 바꾸어준다.", "소변이 새는 쪽 기저귀 안에 물티슈를 넣어준다."]'::jsonb, 4, '대상자의 누워있는 상태에서 기저귀의 소변 누수 문제를 해결하기 위한 적절한 대처 방법을 묻는 문제입니다.', NULL, '{"1": "기저귀 안에 속 기저귀를 한 개 더 채워주는 것은 과도한 흡수 능력을 요하므로 적절하지 않습니다.\n[정답]", "4": "몸 한쪽에 베개를 대는 방식으로 체위를 자주 바꾸어주는 것은 누워 있는 상태에서의 압력을 분산시키므로 효과적입니다.", "2": "기저귀 밑에 방수포를 깔아두는 것은 누수에 대한 방어책이지만 본질적인 해결책이 아닙니다.", "3": "정해진 시간에 기저귀를 갈아주는 것은 일반적으로 필요하지만, 소변이 새는 상황에서는 즉각적인 대처가 필요합니다.", "5": "소변이 새는 쪽 기저귀 안에 물티슈를 넣는 것은 실질적인 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "기저귀(한국어)", "def_vi": "Bỉm(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (320, '10', '대상자의 기저귀를 교환하는 방법으로 옳은 것은?', '["창문을 닫고 탈취제나 방향제를 사용한다.", "기저귀를 정해진 시간에 교환한다.", "기저귀를 교환할 때마다 보호자에게 알린다.", "기저귀의 깨끗한 면이 보이도록 말아 넣는다.", "대상자가 허리를 들 수 없으면 엎드리게 하여 기저귀를 교환한다."]'::jsonb, 4, '대상자의 기저귀 교환 방법에 대한 올바른 절차 및 상식 이해를 평가하기 위함입니다.', NULL, '{"1": "창문을 닫고 탈취제나 방향제를 사용하는 것은 적절한 방법이 아닙니다. 기저귀 교환 시에는 환기가 필요합니다.\n[정답]", "4": "기저귀의 깨끗한 면이 보이도록 말아 넣는 것은 올바른 방법입니다. 이는 청결을 유지하는 데 도움이 됩니다.", "2": "기저귀를 정해진 시간에 교환하는 것이 좋지만, 대상자의 상태에 따라 필요할 때 교환하는 것이 중요합니다.", "3": "기저귀를 교환할 때마다 보호자에게 알리는 것은 필수 사항이 아닙니다.", "5": "대상자가 허리를 들 수 없는 경우에는 엎드리게 하기보다는 적절한 자세로 지지하여 교환하는 것이 안전합니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "bỉm"}, {"term_ko": "교환", "term_vi": "Thay", "def_ko": "교환(한국어)", "def_vi": "thay thế"}, {"term_ko": "탈취제", "term_vi": "Chất khử mùi", "def_ko": "탈취제(한국어)", "def_vi": "chất khử mùi"}, {"term_ko": "방향제", "term_vi": "Thuốc xịt thơm", "def_ko": "방향제(한국어)", "def_vi": "thuốc xịt tạo hương"}, {"term_ko": "대상자", "term_vi": "Bệnh nhân", "def_ko": "대상자(한국어)", "def_vi": "bệnh nhân"}, {"term_ko": "보호자", "term_vi": "Người thân", "def_ko": "보호자(한국어)", "def_vi": "người thân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (319, '10', '대상자의 기저귀 사용 돕기로 옳은 것은?', '["정해진 시간에 기저귀를 갈아준다.", "바지를 내린 후 면 덮개로 덮어준다.", "물수건으로 닦은 후 바로 기저귀를 채운다.", "피부상태 변화 및 상처를 살펴본다.", "회음부는 뒤에서 앞으로 닦는다."]'::jsonb, 4, '대상자의 기저귀 사용 시 주의해야 할 사항을 알고 있는지를 테스트하는 문제입니다.', NULL, '{"1": "정해진 시간에 기저귀를 갈아주는 것은 좋지만, 필요에 따라 수시로 갈아줘야 합니다.\n[정답]", "4": "피부상태 변화 및 상처를 살펴보는 것이 중요합니다.", "2": "바지를 내린 후 면 덮개로 덮어주는 것은 잘못된 방법입니다.", "3": "물수건으로 닦은 후 바로 기저귀를 채우는 것은 피부에 좋지 않습니다.", "5": "회음부를 닦는 방향은 앞에서 뒤로 닦는 것이 맞습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "tã(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (318, '10', '대상자가 몇 번의 실금을 했어도 기저귀를 바로 사용하지 않는 이유로 옳은 것은?', '["낙상의 위험이 높아지기 때문에", "움직임이 제한되기 때문에", "기저귀 사용 비용이 부담되기 때문에", "비뇨기계 감염이 발생할 수 있기 때문에", "스스로 배설하는 습관이 사라질 수 있기 때문에"]'::jsonb, 5, '대상자가 실금을 했다고 해서 즉시 기저귀를 사용하지 않는 이유를 이해하고, 이를 통해 적절한 요양 방법을 알고자 함.', NULL, '{"1": "낙상의 위험이 높아지기 때문에\n기저귀를 사용하면 화장실에 가는 빈도가 줄어 들어 낙상의 위험이 증가할 수 있다.\n[정답]", "5": "스스로 배설하는 습관이 사라질 수 있기 때문에\n기저귀 사용이 잦으면 자연스러운 배설 습관이 저하될 수 있다.", "3": "기저귀 사용 비용이 부담되기 때문에\n비용도 고려될 수 있으나, 주된 이유는 아니다.", "4": "비뇨기계 감염이 발생할 수 있기 때문에\n기저귀 사용으로 인해 감염 위험이 증가할 수 있으나, 주된 이유는 아니다.", "2": "움직임이 제한되기 때문에\n기저귀 사용 자체로 움직임이 크게 제한되지는 않는다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "환자, 수급자", "def_vi": "Bệnh nhân, người thụ hưởng"}, {"term_ko": "실금", "term_vi": "Rò rỉ", "def_ko": "배뇨 또는 배변 조절을 못함", "def_vi": "Không thể kiểm soát việc tiểu tiện hoặc đại tiện"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "아기나 성인이 사용하는 배변 용품", "def_vi": "Sản phẩm sử dụng cho trẻ em hoặc người lớn để đi vệ sinh"}, {"term_ko": "낙상", "term_vi": "Ngã", "def_ko": "높은 곳에서 떨어져 다치는 것", "def_vi": "Bị ngã từ một độ cao"}, {"term_ko": "비용", "term_vi": "Chi phí", "def_ko": "지출해야 하는 돈", "def_vi": "Tiền phải chi trả"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "질병에 의해 발생하는 병리적 상태", "def_vi": "Tình trạng bệnh lý do bệnh gây ra"}, {"term_ko": "습관", "term_vi": "Thói quen", "def_ko": "반복적으로 행하는 행동", "def_vi": "Hành động thực hiện một cách lặp đi lặp lại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (317, '10', '이동변기를 사용하여 배설하는 대상자를 돕는 방법으로 옳은 것은?', '["침대 양쪽 난간을 내리고 이동한다.", "변기 옆에 작은 매트를 깔아준다.", "움직이기 힘들어하면 안아서 변기에 앉힌다.", "두 발의 발가락 끝이 바닥에 닿게 변기에 앉힌다.", "배설 시 소리가 나지 않게 주변 환경을 조용하게 한다."]'::jsonb, 3, '이 문제는 이동변기를 사용하여 배설하는 과정에서 요양보호사가 알아야 할 안전하고 효율적인 방법을 묻고 있습니다.', NULL, '{"1": "침대 양쪽 난간을 내리고 이동한다. 이런 방법은 불안정할 수 있으므로 적절하지 않습니다.\n[정답]", "2": "변기 옆에 작은 매트를 깔아준다. 매트를 깔아줘도 도움이 되지만, 가장 중요한 것은 환자를 안전하게 앉히는 것입니다.", "3": "움직이기 힘들어하면 안아서 변기에 앉힌다. 이 방법은 안전성을 위해 주의해야 하며, 체중을 지탱할 수 있는 방법이 필요합니다.", "4": "두 발의 발가락 끝이 바닥에 닿게 변기에 앉힌다. 이 방식은 바람직하지 않습니다, 환자의 안전을 특히 우선시할 여지가 있습니다.", "5": "배설 시 소리가 나지 않게 주변 환경을 조용하게 한다. 이를 지켜야 하지만 가장 중요한 것은 환자를 안전하게 도와주는 것입니다."}'::jsonb, '[{"term_ko": "이동변기", "term_vi": "Bồn cầu di động", "def_ko": "이동할 수 있는 변기", "def_vi": "Toilet có thể di chuyển"}, {"term_ko": "배설", "term_vi": "Tiểu tiện", "def_ko": "소변이나 대변을 보는 것", "def_vi": "Đi tiểu hoặc đi đại tiện"}, {"term_ko": "매트", "term_vi": "Thảm", "def_ko": "바닥에 깔아놓는 것", "def_vi": "Vật trải sàn"}, {"term_ko": "주변 환경", "term_vi": "Môi trường xung quanh", "def_ko": "주위의 상황", "def_vi": "Tình huống xung quanh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (316, '10', '이동변기를 사용하여 배변중인 대상자가 배설을 어려워 할 때 돕는 방법으로 옳은 것은?', '["차가운 물을 마시게 한다.", "조용한 음악을 틀어준다.", "배변할 때까지 앉아 있게 한다.", "이동변기 대신 기저귀를 채워준다.", "항문 주위에 미지근한 물을 끼얹어준다."]'::jsonb, 5, '배변 중 어려움을 겪는 대상자의 상황에서 적절한 도움을 주는 방법을 이해하고 있는지를 평가하고자 함.', NULL, '{"1": "차가운 물은 배변에 도움이 되지 않는다.\n[정답]", "5": "항문 주위에 미지근한 물을 끼얹는 것은 배변을 도와줄 수 있는 방법이다.", "2": "조용한 음악은 긴장을 완화시킬 수 있지만 직접적인 도움은 아니다.", "3": "배변할 때까지 앉아 있게 하는 것은 심리적 압박을 줄 수 있다.", "4": "기저귀를 채우는 것은 의도하지 않은 방법이다."}'::jsonb, '[{"term_ko": "이동변기", "term_vi": "Bệ vệ sinh di động", "def_ko": "이동형 변기", "def_vi": "Nhà vệ sinh di động"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (315, '10', '대상자가 밤에는 추워서 화장실 가기 싫다며 기저귀 사용을 원할 때 대처방법으로 옳은 것은?', '["원하는 대로 기저귀를 사용한다.", "간이변기를 대어준다.", "겉옷을 준비하여 준다.", "이동식 변기를 옆에 둔다.", "대상자를 설득하여 화장실을 사용한다."]'::jsonb, 4, '대상자가 밤에 화장실을 가기 싫어하는 상황에서 어떤 대처방법이 적절한지를 묻는 문제입니다.', NULL, '{"1": "기저귀 사용은 대상자의 요청에 따라 수용할 수 있지만, 건강한 욕구를 위한 대처 방법이 아닙니다.\n[정답]", "2": "간이변기는 매우 유용한 도구로, 야간에 화장실 이용을 쉽게 도와줍니다.", "3": "겉옷을 준비해주는 것은 도움이 될 수 있지만, 화장실 이용의 결정을 직접적으로 바꾸지는 않습니다.", "4": "이동식 변기는 환자가 빠르게 접근할 수 있는 방법으로, 적절한 대처입니다.", "5": "대상자를 설득하는 것은 긍정적이지만, 대상자의 기저귀 사용 요청을 무시할 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (314, '10', '왼쪽 편마비 대상자의 이동변기 사용을 돕는 방법으로 옳은 것은?', '["이동변기를 침대 높이보다 낮게 한다.", "이동변기를 하루에 한 번 세척한다.", "이동변기를 대상자의 왼쪽에 놓는다.", "이동변기 앞에 미끄럼방지 매트를 깔아준다.", "소독약으로 세척할 수 있는 이동변기를 사용한다."]'::jsonb, 5, '이 문제는 편마비 환자의 이동변기 사용 시 주의해야 할 점과 올바른 방법을 이해하고 있는지를 평가하기 위한 것이다.', NULL, '{"1": "이동변기를 침대 높이보다 낮게 하면 오히려 불편할 수 있다.\n[정답]", "5": "소독약으로 세척할 수 있는 이동변기를 사용하면 위생적이다.", "3": "이동변기를 대상자의 왼쪽에 놓는 것은 편마비 환자에게 어려움을 줄 수 있다.", "4": "이동변기 앞에 미끄럼방지 매트를 깔아주면 좋지만, 반드시 필요한 것은 아니다.", "2": "이동변기를 하루에 한 번 세척하는 것은 위생 관리에 부족하다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽이 마비된 상태", "def_vi": "Tình trạng bị liệt một bên cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (313, '10', '간이변기를 사용하여 침상에서 배설하는 대상자를 돕는 방법으로 옳은 것은?', '["대상자의 두분 아래에 방수포를 깐다.", "조용한 환경에서 배설할 수 있게 한다.", "변기를 침대 난간과 30~45˚가 되게 붙인다.", "바지를 내린 후에 허리 아래 부분을 가려준다.", "대상자가 협조할 수 있으면 옆으로 돌려 눕혀 변기를 대어준다."]'::jsonb, 1, '대상자가 간이변기를 사용하는 상황에서 올바른 지원 방법을 이해하고 평가할 수 있는 능력을 점검하기 위해 출제되었습니다.', NULL, '{"1": "대상자의 두분 아래에 방수포를 깐다: 침대에 방수포를 깔아두는 것은 배설 시 청결과 편안함을 제공하기 때문에 적절한 방법입니다.\n[정답]", "2": "조용한 환경에서 배설할 수 있게 한다: 배설하는 동안 편안한 환경을 제공하는 것은 중요하지만, 본 질문에서 더 적절한 방법은 방수포를 깔는 것입니다.", "3": "변기를 침대 난간과 30~45˚가 되게 붙인다: 변기의 각도 조정은 필요할 수 있지만, 방수포 준비와 더 밀접한 관련이 없습니다.", "4": "바지를 내린 후에 허리 아래 부분을 가려준다: 사생활 보호는 중요하지만, 본 문제에서 제시된 정답에는 해당되지 않습니다.", "5": "대상자가 협조할 수 있으면 옆으로 돌려 눕혀 변기를 대어준다: 대상자가 협조할 경우 이러한 방법도 가능하지만, 방수포를 깔아야 할 필요성이 더 우선시 됩니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자 또는 고객", "def_vi": "Người bệnh hoặc khách hàng"}, {"term_ko": "방수포", "term_vi": "Tấm trải chống thấm", "def_ko": "물이 스며들지 않는 포", "def_vi": "Tấm trải không thấm nước"}, {"term_ko": "조용한", "term_vi": "Yên tĩnh", "def_ko": "소음이 없거나 평온한", "def_vi": "Không có tiếng ồn hoặc thanh bình"}, {"term_ko": "허리", "term_vi": "Eo", "def_ko": "허리 부분", "def_vi": "Vùng eo"}, {"term_ko": "협조", "term_vi": "Hợp tác", "def_ko": "서로 도와주다", "def_vi": "Giúp đỡ lẫn nhau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (312, '10', '거동이 불편한 대상자가 침상에서 자주 배변 실수를 할 때 돕는 방법으로 옳은 것은?', '["음식섭취량을 줄여준다.", "낮 동안에 기저귀를 채워준다.", "간이변기를 침대에 두고 사용하게 한다.", "대상자가 변의를 호소할 때 즉시 배설할 수 있도록 한다.", "기저귀를 깔고 하의를 벗긴 후 이불을 덮어준다."]'::jsonb, 4, '거동이 불편한 대상자가 배변 실수를 자주 하는 상황에서 적절한 도움을 제시하는 능력을 평가하고자 한다.', NULL, '{"1": "음식섭취량을 줄이면 배변 횟수를 감소시킬 수 있지만, 건강에 문제가 될 수 있다.\n[정답]", "2": "낮 동안에 기저귀를 채우는 것은 유용할 수 있지만, 대상자가 배변 욕구에 즉시 반응할 수 있도록 돕는 것이 중요하다.", "3": "간이변기를 침대에 두도록 하는 것은 좋은 방법이나, 사용 방법을 제대로 배워야 한다.", "4": "대상자가 변의를 호소할 때 즉시 배설할 수 있도록 하는 것이 가장 바람직한 도움이다.", "5": "기저귀를 깔고 하의를 벗기는 것은 현실적이지만, 필요한 상황에서 즉시 도움을 주는 것이 더 효과적이다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "불편", "def_ko": "행동, di chuyển", "def_vi": "không thoải mái"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (311, '10', '침대에 누워 지내는 대상자의 침상 배설을 돕는 방법으로 옳은 것은?', '["복부를 시계 방향으로 마사지한다.", "배변 후 물티슈로 닦고 바로 옷을 입힌다.", "앙와위로 눕혀 배변하기 쉬운 자세가 되게 한다.", "찬 수건으로 항문 주위를 닦아주어 변의를 자극한다.", "변의를 호소하면 한두 번 참게 한 후 변기를 대어준다."]'::jsonb, 1, '대상자의 배설 도움 방법을 이해하고 있는지 평가하기 위한 문제입니다.', NULL, '{"1": "복부를 시계 방향으로 마사지하는 것은 장의 운동을 돕고 배변을 유도하는 효과가 있습니다.\n[정답]", "2": "배변 후에 물티슈로 닦고 즉시 옷을 입히는 것은 청결을 고려하지 않은 방법입니다.", "3": "앙와위로 눕혀 배변하기 쉬운 자세를 제공하는 것은 배변을 돕지 않는 자세입니다.", "4": "찬 수건으로 항문 주위를 닦는 것은 불편하고 자극이 부족합니다.", "5": "변의를 호소한 대상자를 한두 번 참게 하는 것은 건강에 좋지 않습니다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "cái giường"}, {"term_ko": "배설", "term_vi": "Đi tiêu", "def_ko": "대변을 처리하다(한국어)", "def_vi": "đi vệ sinh"}, {"term_ko": "복부", "term_vi": "Bụng", "def_ko": "배(한국어)", "def_vi": "cái bụng"}, {"term_ko": "마사지", "term_vi": "Mát-xa", "def_ko": "마사지하다(한국어)", "def_vi": "xoa bóp"}, {"term_ko": "물티슈", "term_vi": "Khăn ướt", "def_ko": "물로 적신 티슈(한국어)", "def_vi": "khăn lau ướt"}, {"term_ko": "앙와위", "term_vi": "Nằm ngửa", "def_ko": "눕는 자세(한국어)", "def_vi": "nằm ở tư thế ngửa"}, {"term_ko": "변의", "term_vi": "Cảm giác muốn đi vệ sinh", "def_ko": "대변을 보고 싶다는 느낌(한국어)", "def_vi": "cảm giác muốn đi tiêu"}, {"term_ko": "항문", "term_vi": "Hậu môn", "def_ko": "항문(한국어)", "def_vi": "hậu môn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (310, '10', '요실금 대상자의 배뇨를 돕는 방법으로 옳은 것은?', '["배뇨후 치골상부를 눌러 방광을 완전히 비운다.", "주기적으로 도뇨관을 사용한다.", "식이섬유가 적은 음식을 제공한다.", "더운물주머니를 복부에 대주어 방광을 자극한다.", "활동을 제한하여 배뇨 횟수를 줄인다."]'::jsonb, 1, '요실금을 가진 대상자의 배뇨를 돕기 위한 올바른 방법을 묻는 문제입니다.', NULL, '{"1": "배뇨후 치골상부를 눌러 방광을 완전히 비운다. - 이는 방광을 비우는 올바른 방법으로, 요실금 대상자에게 적합합니다.\n[정답]", "2": "주기적으로 도뇨관을 사용한다. - 도뇨관 사용은 특정 상황에서 필요하지만 일반적인 방법은 아닙니다.", "3": "식이섬유가 적은 음식을 제공한다. - 식이섬유가 부족한 음식은 오히려 변비를 유발할 수 있습니다.", "4": "더운물주머니를 복부에 대주어 방광을 자극한다. - 방광 자극은 필요할 수 있지만, 이것이 적절한 배뇨 방법이라고 할 수 없습니다.", "5": "활동을 제한하여 배뇨 횟수를 줄인다. - 활동 제한은 건강에 좋지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "요실금", "term_vi": "Tiểu không tự chủ", "def_ko": "소변을 조절하지 못하는 상태", "def_vi": "Trạng thái không kiểm soát được nước tiểu"}, {"term_ko": "배뇨", "term_vi": "Tiểu tiện", "def_ko": "소변을 보는 행동", "def_vi": "Hành động đi tiểu"}, {"term_ko": "방광", "term_vi": "Bàng quang", "def_ko": "소변이 저장되는 기관", "def_vi": "Cơ quan chứa nước tiểu"}, {"term_ko": "치골", "term_vi": "Xương mu", "def_ko": "골반의 앞부분", "def_vi": "Phần phía trước của xương chậu"}, {"term_ko": "도뇨관", "term_vi": "Ống dẫn nước", "def_ko": "소변을 배출하기 위해 사용하는 튜브", "def_vi": "Ống sử dụng để dẫn nước tiểu"}, {"term_ko": "식이섬유", "term_vi": "Chất xơ", "def_ko": "장 건강에 도움이 되는 섬유소", "def_vi": "Chất giúp cải thiện sức khỏe đường ruột"}, {"term_ko": "제한하다", "term_vi": "Hạn chế", "def_ko": "활동이나 섭취량을 줄이다", "def_vi": "Giảm hoạt động hoặc lượng tiêu thụ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (309, '10', '휠체어를 사용하는 왼쪽 편마비 대상자의 화장실 이용을 돕는 방법으로 옳은 것은?', '["화장실 밖에 응급벨을 설치한다.", "대상자의 두 발이 바닥에 닿지 않게 앉힌다.", "배뇨 후 도움이 필요한 부분을 도와준다.", "화장실 앞에 화분을 놓아 화장실 위치를 표시한다.", "침대에서 휠체어로 옮길 때 대상자의 왼쪽에 휠체어를 놓는다."]'::jsonb, 3, '대상자의 화장실 이용을 안전하고 효율적으로 돕기 위한 방법을 묻는 문제입니다.', NULL, '{"1": "화장실 밖에 응급벨을 설치하는 것은 안전을 위한 조치이나, 화장실 이용 방법과는 직접적인 관련이 없습니다.\n[정답]", "2": "대상자의 두 발이 바닥에 닿지 않게 앉힌 것은 안전하게 화장실을 이용하기 위한 방법이 아닙니다.", "3": "배뇨 후 도움이 필요한 부분을 도와주는 것은 가장 적절한 방법입니다.", "4": "화장실 앞에 화분을 놓아 화장실 위치를 표시하는 것은 파악을 돕는 방법이지만, 대상자에게 직접적인 도움을 주지 않습니다.", "5": "침대에서 휠체어로 옮길 때 대상자의 왼쪽에 휠체어를 놓는 것은 편마비 환자를 도와주는 방법으로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "휠체어(장애인을 위한 의자형 수송기구)", "def_vi": "Ghế ngồi di chuyển cho người khuyết tật"}, {"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "신체의 한쪽이 마비된 상태", "def_vi": "Tình trạng bị liệt bên một nửa cơ thể"}, {"term_ko": "배뇨", "term_vi": "Đi tiểu", "def_ko": "소변을 보는 과정", "def_vi": "Quá trình đi vệ sinh"}, {"term_ko": "두 발", "term_vi": "Hai chân", "def_ko": "사람의 다리", "def_vi": "Chân của con người"}, {"term_ko": "응급벨", "term_vi": "Chuông khẩn cấp", "def_ko": "긴급 상황에서 호출하는 벨", "def_vi": "Chuông dùng để gọi trong trường hợp khẩn cấp"}, {"term_ko": "화분", "term_vi": "Chậu cây", "def_ko": "식물이나 꽃을 기르는 그릇", "def_vi": "Để trồng cây hoặc hoa"}, {"term_ko": "화장실", "term_vi": "Nhà vệ sinh", "def_ko": "소변이나 대변을 보는 방", "def_vi": "Phòng để đi vệ sinh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (308, '10', '휠체어로 이동하여 화장실을 사용하는 오른쪽 편마비 대상자를 돕는 방법은?', '["대상자의 오른쪽에 휠체어를 놓고 옮긴다.", "이동할 때는 휠체어 의자 끝에 걸터앉게 한다.", "휠체어 잠금장치를 풀고 발 받침대를 접은 후 변기에 옮긴다.", "대상자의 겨드랑이를 감싸 일으킨 후 몸을 회전시켜 변기에 앉힌다.", "배설이 끝날 때까지 화장실 문을 열어둔다."]'::jsonb, 4, '대상자의 편마비 상태에 맞는 안전하고 적절한 화장실 사용 방법을 물어보는 문제입니다.', NULL, '{"1": "대상자의 오른쪽에 휠체어를 놓고 옮긴다. - 오른쪽 편마비인 경우 왼쪽에서 도움을 주는 것이 더 안전하다.\n[정답]", "2": "이동할 때는 휠체어 의자 끝에 걸터앉게 한다. - 휠체어 끝에 걸터앉는 것은 안전하지 않다.", "3": "휠체어 잠금장치를 풀고 발 받침대를 접은 후 변기에 옮긴다. - 잠금장치는 반드시 해제해야 하지만 이 순서로 진행하는 것은 비효율적이다.", "4": "대상자의 겨드랑이를 감싸 일으킨 후 몸을 회전시켜 변기에 앉힌다. - 올바른 방법으로, 편마비 대상자를 안전하게 화장실에 옮기는 방법이다.", "5": "배설이 끝날 때까지 화장실 문을 열어둔다. - 개인정보 보호와 안전을 위해 문을 닫아야 한다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bán liệt", "def_ko": "한쪽 신체의 운동 기능이 소실된 상태", "def_vi": "Tình trạng mất chức năng vận động của một bên cơ thể"}, {"term_ko": "겨드랑이", "term_vi": "Nách", "def_ko": "팔과 몸통 사이의 부위", "def_vi": "Khu vực giữa tay và thân"}, {"term_ko": "화장실", "term_vi": "Nhà vệ sinh", "def_ko": "배설을 위한 공간", "def_vi": "Không gian để đi vệ sinh"}, {"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "이동을 위해 사용하는 의자", "def_vi": "Ghế ngồi di chuyển"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (307, '10', '침대에 누워 있던 대상자가 화장실에 간다며 일어나 앉더니 어지럽다고 할 때 대처 방법으로 옳은 것은?', '["따뜻한 차를 마시게 한다.", "똑바로 누워 다리를 높여준다.", "이동변기를 사용하게 한다.", "서둘러 화장실에 데려간다.", "잠시 침대에 앉아있게 하고 지켜본다."]'::jsonb, 5, '대상자가 어지럼증을 느낄 때, 안전하고 적절한 대처 방법을 묻는 문제입니다.', NULL, '{"1": "따뜻한 차를 마시는 것은 도움이 될 수 있지만, 즉각적인 대처 방법으로는 적합하지 않습니다.\n[정답]", "5": "잠시 침대에 앉아있게 하고 지켜보는 것이 가장 안전한 방법입니다.", "3": "이동변기를 사용하게 하는 것은 대상자가 어지럼증을 느끼는 상황에서는 적절치 않습니다.", "4": "서둘러 화장실에 데려가는 것은 더 위험할 수 있습니다.", "2": "똑바로 눕히고 다리를 높이는 것도 하지만, 바로 앉아있는 수가 더 안전합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "어지럽다", "def_ko": "환자, Người bệnh", "def_vi": "어지럽다, Chóng mặt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (306, '10', '대상자가 안전하게 화장실을 이용할 수 있도록 돕는 방법으로 옳은 것은?', '["화장실을 대상자의 방과 가까운 곳으로 정한다.", "화장실 표시는 입구 아래쪽에 한다.", "화장실 전등은 밤에는 소등을 한다.", "화장실 복도에 조형물을 두어 미관을 좋게 한다.", "화장실에 갈 때 신고 벗기 쉽게 슬리퍼를 이용한다."]'::jsonb, 1, '대상자가 화장실을 안전하게 이용할 수 있도록 돕는 방법을 묻는 문제입니다.', NULL, '{"1": "화장실을 대상자의 방과 가까운 곳으로 정하는 것은 대상자가 쉽게 접근할 수 있게 하여 안전하게 이용할 수 있도록 돕는 방법입니다.\n[정답]", "2": "화장실 표시는 입구 아래쪽에 하는 것이 아니라 쉽게 볼 수 있는 곳에 해야 합니다.", "3": "화장실 전등은 밤에 소등하는 것이 아니라 불을 켜두어야 안전합니다.", "4": "화장실 복도에 조형물이 있을 경우 오히려 방해가 될 수 있습니다.", "5": "신고 벗기 쉽게 슬리퍼는 편리함을 줄 수 있으나, 안전을 고려하면 통제된 신발을 권장합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자, 수혜자", "def_vi": "Bệnh nhân, người được hưởng lợi"}, {"term_ko": "화장실", "term_vi": "Nhà vệ sinh", "def_ko": "배변 및 세면을 하는 곳", "def_vi": "Nơi đi vệ sinh và rửa mặt"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험이 없는 상태", "def_vi": "Trạng thái không có nguy hiểm"}, {"term_ko": "근접", "term_vi": "Gần", "def_ko": "가까이 있음", "def_vi": "Ở gần"}, {"term_ko": "조형물", "term_vi": "Tượng", "def_ko": "미관을 위한 설계된 객체", "def_vi": "Đối tượng được thiết kế cho mục đích mỹ quan"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (305, '10', '대상자의 배설물을 관찰한 결과 시설장에게 보고해야 하는 경우로 옳은 것은?', '["소변이 투명하다.", "소변에 거품이 없다.", "소변이 엷은 노란색이다.", "대변에 점액질이 섞여 나온다.", "대변이 부드럽고 형태가 있다."]'::jsonb, 4, '대상자의 배설물 상태를 관찰하여 어떤 경우에 시설장에게 보고해야 하는지를 파악하는 것이 중요하다.', NULL, '{"1": "소변이 투명하다. - 정상적인 소변의 특징으로, 보고할 필요는 없다.", "2": "소변에 거품이 없다. - 정상적인 소변의 특징으로, 보고할 필요는 없다.", "3": "소변이 엷은 노란색이다. - 정상적인 소변의 색상으로, 보고할 필요는 없다.\n[정답]", "4": "대변에 점액질이 섞여 나온다. - 점액질이 섞인 대변은 이상징후로, 반드시 보고해야 한다.", "5": "대변이 부드럽고 형태가 있다. - 정상적인 대변의 상태로, 보고할 필요는 없다."}'::jsonb, '[{"term_ko": "배설물", "term_vi": "Chất thải", "def_ko": "분비물(소변, 대변)", "def_vi": "Chất dịch được bài tiết (nước tiểu, phân)"}, {"term_ko": "소변", "term_vi": "Nước tiểu", "def_ko": "체내에서 배설되는 액체", "def_vi": "Chất lỏng được bài tiết ra từ cơ thể"}, {"term_ko": "대변", "term_vi": "Phân", "def_ko": "장의 내용물이 체외로 배출된 형태", "def_vi": "Hình thức mà nội dung của ruột được thải ra ngoài cơ thể"}, {"term_ko": "점액질", "term_vi": "Chất nhầy", "def_ko": "점성이 있는 액체", "def_vi": "Chất lỏng có độ nhớt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (303, '10', '경관영양 시 비위관이 새고 있을 때 돕기 방법으로 옳은 것은?', '["역류가 되지 않는다면 그대로 둔다.", "왼쪽으로 눕혀 구토를 예방한다.", "요양보호사가 비위관을 제거한다.", "비위관을 잠그고 간호사에게 연락한다.", "청색증이 나타나는지 관찰한다."]'::jsonb, 4, '경관영양을 시행할 때 비위관의 문제를 인식하고 대처할 수 있는 능력을 평가하기 위해 출제되었다.', NULL, '{"1": "역류가 되지 않는다면 그대로 두는 것은 안전하지 않다.", "2": "왼쪽으로 눕히는 것만으로는 충분한 예방조치가 아니다.\n[정답]", "3": "요양보호사가 비위관을 제거하는 것은 적절하지 않으며, 전문적인 조치가 필요하다.", "4": "비위관을 잠그고 간호사에게 연락하는 것이 가장 적절한 대처 방법이다.", "5": "청색증 관찰은 중요하지만, 문제 해결의 직접적인 방법이 아니다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua ống", "def_ko": "영양을 공급하기 위한 의학적 방법", "def_vi": "Phương pháp cung cấp dinh dưỡng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (302, '10', '의식이 없는 대상자의 경관영양을 돕는 방법으로 옳은 것은?', '["영양액은 체온보다 낮은 온도로 준비한다.", "영양액 주머니를 침대 높이에 맞추어 건다.", "비위관이 빠지면 최대한 빨리 밀어 넣는다.", "영양액은 1분에 50mL 이상 주입되지 않도록 주의한다.", "구토 증상을 보이면 소화제와 함께 주입한다."]'::jsonb, 4, '의식이 없는 대상자에게 경관영양을 제공할 때의 올바른 방법에 대해 묻는 문제입니다.', NULL, '{"1": "영양액은 체온보다 낮은 온도로 준비하는 것은 올바르지 않습니다. 영양액은 체온과 유사한 온도로 준비해야 합니다.\n[정답]", "2": "영양액 주머니를 침대 높이에 맞추어 건다는 것은 일반적인 지침이나, 높이를 맞추는 것이 꼭 반드시 필요한 것은 아닙니다.", "3": "비위관이 빠지면 최대한 빨리 밀어 넣는 것은 위험할 수 있으므로 올바르지 않은 방법입니다.", "4": "영양액은 1분에 50mL 이상 주입되지 않도록 주의한다는 것이 올바른 방법입니다. 이는 부작용을 예방하기 위해 중요합니다.", "5": "구토 증상을 보이면 소화제와 함께 주입하는 것은 잘못된 방법입니다. 구토가 발생하면 즉시 주입을 중단하고 의사와 상담해야 합니다."}'::jsonb, '[{"term_ko": "의식", "term_vi": "경관영양", "def_ko": "의식을 가진 상태, 의식이 없다: không có ý thức", "def_vi": "위로 음식이 아닌 약품을 주입하는 방법, dinh dưỡng qua ống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (301, '10', '침상에 누워있는 오른쪽 편마비 대상자의 식사 돕기로 옳은 것은?', '["오른쪽 밑으로 하여 옆으로 눕힌다.", "왼쪽 허리를 베개로 받쳐 지지해준다.", "똑바로 누운 채 고개를 요양보호사 쪽으로 돌린다.", "숟가락 끝을 왼쪽 입술에 대고 음식물을 넣어준다.", "왼쪽 입안에 음식찌꺼기가 있는지 확인한다."]'::jsonb, 4, '대상자의 오른쪽 편마비 상태를 고려하여 식사 보조 시 올바른 방법을 묻는 문제입니다.', NULL, '{"1": "오른쪽 밑으로 하여 옆으로 눕히는 것은 편마비 환자에게 위험할 수 있습니다.\n[정답]", "4": "숟가락 끝을 왼쪽 입술에 대고 음식물을 넣어주는 방법이 가장 적절합니다.", "2": "왼쪽 허리를 베개로 받쳐 지지하는 것은 필요할 수 있지만, 직접적으로 식사 보조와 관련이 없습니다.", "3": "똑바로 누워 있는 상태는 편마비 환자의 안전과 관련하여 부적절할 수 있습니다.", "5": "왼쪽 입안에 음식찌꺼기가 있는지 확인하는 것은 중요하지만, 즉각적인 식사 보조와 직접적인 연결이 없습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽 몸의 기능이 저하된 상태", "def_vi": "Tình trạng giảm chức năng của một nửa cơ thể"}, {"term_ko": "베개", "term_vi": "Gối", "def_ko": "목이나 허리를 받쳐주는 도구", "def_vi": "Dụng cụ hỗ trợ cổ hoặc lưng"}, {"term_ko": "입술", "term_vi": "Môi", "def_ko": "음식물이 들어가는 구강의 일부", "def_vi": "Một phần của cơ thể dùng để ăn uống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (300, '10', '편마비 대상자의 식사 돕기 방법으로 옳은 것은?', '["건강한 쪽을 밑으로 하여 옆으로 눕힌다.", "숟가락에 밥과 반찬을 가득 올려 먹인다.", "숟가락 끝부분을 입술 중앙에 대고 음식을 넣어준다.", "음식을 완전히 삼키기 전에 음식을 넣어준다.", "식사가 끝난 직후 똑바로 누워 쉬게 한다."]'::jsonb, 1, '편마비 대상자의 안전한 식사 도와주기 방법을 평가하는 질문입니다.', NULL, '{"1": "건강한 쪽을 밑으로 하여 옆으로 눕힌다. - 편마비 환자가 안전하게 식사를 할 수 있도록 도와주는 방법입니다.\n[정답]", "2": "숟가락에 밥과 반찬을 가득 올려 먹인다. - 과도한 양은 삼키기 어려워 위험할 수 있습니다.", "3": "숟가락 끝부분을 입술 중앙에 대고 음식을 넣어준다. - 정확한 위치에서 음식을 넣는 것이 필요합니다.", "4": "음식을 완전히 삼키기 전에 음식을 넣어준다. - 이는 질식을 유발할 수 있어 위험합니다.", "5": "식사가 끝난 직후 똑바로 누워 쉬게 한다. - 식사 후 자세에 대한 안전 고려가 필요합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bán liệt", "def_ko": "절반이 마비된 상태", "def_vi": "Tình trạng bị liệt một nửa"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 섭취하는 행동", "def_vi": "Hành động tiêu thụ đồ ăn"}, {"term_ko": "술관", "term_vi": "Thìa", "def_ko": "음식을 먹기 위해 사용하는 도구", "def_vi": "Dụng cụ sử dụng để ăn uống"}, {"term_ko": "삼키다", "term_vi": "Nuốt", "def_ko": "음식을 목구멍으로 넘기는 행동", "def_vi": "Hành động đưa đồ ăn vào họng"}, {"term_ko": "안전", "term_vi": "An toàn", "def_ko": "위험 요소로부터 보호되는 상태", "def_vi": "Trạng thái được bảo vệ khỏi nguy hiểm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (299, '10', '사레예방 방법으로 옳은 것은?', '["식사 전 물이나 국물로 식도를 적신다.", "의자에 앉을 수 없는 대상자는 누운 자세를 취한다.", "천천히 드시게 하기 위해 음식 섭취 도중에 말을 건넨다.", "점도가 높은 떡 종류를 준비한다.", "목을 축일 수 있는 신맛이 강한 과일을 준비한다."]'::jsonb, 1, '사례 예방에 대한 기본 지식을 평가하고자 하는 문제입니다.', NULL, '{"1": "식사 전 물이나 국물로 식도를 적신다: 이는 식사 중 기도가 막히는 것을 예방하는 좋은 방법입니다.\n[정답]", "2": "의자에 앉을 수 없는 대상자는 누운 자세를 취한다: 누운 자세는 오히려 기도를 막을 수 있으므로 잘못된 방법입니다.", "3": "천천히 드시게 하기 위해 음식 섭취 도중에 말을 건넨다: 음식 섭취 도중에 말을 하는 것은 위험할 수 있습니다.", "4": "점도가 높은 떡 종류를 준비한다: 점도가 높은 음식은 삼키기 어려울 수 있어 위험할 수 있습니다.", "5": "목을 축일 수 있는 신맛이 강한 과일을 준비한다: 신맛이 강한 과일은 오히려 삼키기 어렵게 만들 수 있습니다."}'::jsonb, '[{"term_ko": "사례", "term_vi": "예방", "def_ko": "사례(사례)", "def_vi": "예방(ngăn ngừa)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (298, '10', '입맛이 없는 대상자의 식욕을 증진할 수 있는 방법으로 옳은 것은?', '["혼자서 조용히 식사하게 한다.", "음식의 형태를 알 수 없도록 갈아서 제공한다.", "감칠맛 나는 단 음식 위주로 준비한다.", "다양한 색깔의 반찬을 골고루 제공한다.", "신맛이 강한 음식을 주어 미각을 돋운다."]'::jsonb, 4, '대상자의 식욕 증진 방법을 이해하고, 적절한 방법을 선택할 수 있는 능력을 평가하고자 함.', NULL, '{"1": "혼자서 조용히 식사하게 하면 식욕이 더욱 감소할 수 있다.\n[정답]", "4": "다양한 색깔의 반찬을 제공하면 시각적으로 식욕을 자극할 수 있다.", "2": "음식의 형태를 알 수 없도록 갈아서 제공하면 식욕 저하를 초래할 수 있다.", "3": "감칠맛 나는 단 음식 위주로 준비하는 것은 영양 편중의 위험이 있다.", "5": "신맛이 강한 음식을 주면 일부 환자에게는 식욕을 돋울 수 있지만, 대부분에게는 불쾌감을 줄 수 있다."}'::jsonb, '[{"term_ko": "입맛", "term_vi": "Khẩu vị", "def_ko": "식욕(한국어)", "def_vi": "Sự thèm ăn(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (297, '10', '의자에 앉아 식탁에서 식사하는 대상자를 돕는 방법으로 옳은 것은?', '["등받이가 없는 의자에 앉게 한다.", "대상자를 의자에 걸터앉게 한다.", "식탁의 상판이 대상자의 배꼽 높이에 오게 한다.", "대상자의 발가락 끝이 바닥에 닿게 한다.", "의자를 식탁과 30˚~45˚각도가 되도록 하여 비스듬히 앉게 한다."]'::jsonb, 3, '대상자가 안전하고 편리하게 식사할 수 있는 자세를 확인하고 돕는 방법을 이해하도록 한다.', NULL, '{"1": "등받이가 없는 의자에 앉게 할 경우 안정성이 떨어진다.", "2": "대상자를 의자에 걸터앉게 하는 것은 올바르지 않은 방법이다.\n[정답]", "3": "식탁의 상판이 대상자의 배꼽 높이에 오게 하는 것이 가장 적절한 방법이다.", "4": "대상자의 발가락 끝이 바닥에 닿게 하는 것은 필요하지만 전제가 아니다.", "5": "의자를 식탁과 비스듬히 앉게 하는 것은 바람직하지 않다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자 또는 도움이 필요한 사람", "def_vi": "Bệnh nhân hoặc người cần sự giúp đỡ"}, {"term_ko": "식탁", "term_vi": "Bàn ăn", "def_ko": "식사를 하는 테이블", "def_vi": "Bàn dùng để ăn"}, {"term_ko": "배꼽", "term_vi": "Rốn", "def_ko": "몸의 중앙에 있는 부위", "def_vi": "Vùng trung tâm của cơ thể"}, {"term_ko": "발가락", "term_vi": "Ngón chân", "def_ko": "발의 끝 부분", "def_vi": "Phần đầu của chân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (296, '10', '음식물을 삼키는 데 어려움이 있는 대상자의 식사를 돕는 방법으로 옳은 것은?', '["식전 입맛을 돋게 하기 위해 레몬차를 제공한다.", "식사 중에 물을 자주 마시게 한다.", "수시로 말을 걸어 음식을 천천히 삼키게 한다.", "머리와 목을 약간 뒤로 젖혀 음식을 삼키게 한다.", "액체는 증점제를 첨가하여 점도를 높인다."]'::jsonb, 5, '대상자가 음식을 삼키는 데 어려움을 겪는 상황에서 올바른 식사 보조 방법을 이해하도록 하기 위함입니다.', NULL, '{"1": "식전 입맛을 돋게 하기 위해 레몬차를 제공하는 것은 삼키기 어려운 대상자에게 도움이 되지 않습니다.\n[정답]", "5": "액체는 증점제를 첨가하여 점도를 높이면 삼키기 쉽도록 도와줍니다.", "2": "식사 중에 물을 자주 마시게 하는 것은 삼키는 데 방해가 될 수 있습니다.", "3": "수시로 말을 걸면 대상자가 음식을 빨리 삼키게 되어 위험할 수 있습니다.", "4": "머리와 목을 뒤로 젖히면 기도가 막힐 수 있어 위험합니다."}'::jsonb, '[{"term_ko": "음식물", "term_vi": "Thức ăn", "def_ko": "음식", "def_vi": "Thức ăn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (295, '9', '월례회의의 주된 내용으로 옳은 것은?', '["대상자의 성향과 제공되는 서비스를 점검한다.", "대상자에 대한 건강, 사고 등에 대해 정보를 전달한다.", "대상자와 관계된 직종들의 역할 분담을 명확히 한다.", "대상자 가족의 복리후생, 애로사항을 듣는다.", "대상자에 대한 서비스 제공계획을 검토한다."]'::jsonb, 2, '월례회의의 주요 내용을 이해하고 확인하기 위한 질문입니다.', NULL, '{"1": "대상자의 성향과 제공되는 서비스를 점검하는 것은 회의의 일환일 수 있지만 주된 내용은 아닙니다.\n[정답]", "2": "대상자에 대한 건강, 사고 등에 대해 정보를 전달하는 것이 월례회의의 주된 내용입니다.", "3": "직종들의 역할 분담은 필요하지만 주된 내용으로 보기 어렵습니다.", "4": "대상자 가족의 애로사항을 듣는 것은 중요하지만 주된 내용은 아닙니다.", "5": "서비스 제공계획의 검토도 중요하지만 주된 내용으로 명시되지 않습니다."}'::jsonb, '[{"term_ko": "월례회의", "term_vi": "Cuộc họp hàng tháng", "def_ko": "매월 열리는 회의", "def_vi": "Cuộc họp diễn ra mỗi tháng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (294, '9', '다음 내용에 해당하는 회의로 옳은 것은?', '["운영회의", "월례회의", "사례회의", "연구회의", "운영회의"]'::jsonb, 2, '요양보호사의 업무와 관련된 회의의 종류를 이해하고 구별하기 위한 문제입니다.', NULL, '{"1": "운영회의: 운영 관련 사항을 다루는 회의지만, 이 내용과는 맞지 않습니다.\n[정답]", "2": "월례회의: 요양보호사의 업무와 관련된 준수사항 및 정보를 전달하는 회의입니다.", "3": "사례회의: 특정 사례에 대한 논의가 중심이 되며, 이 내용과는 부합하지 않습니다.", "4": "연구회의: 연구 목적의 회의로, 해당되지 않습니다.", "5": "운영회의: 중복된 보기이며, 정답이 아닙니다."}'::jsonb, '[{"term_ko": "업무", "term_vi": "Công việc", "def_ko": "일(한국어)", "def_vi": "Công việc"}, {"term_ko": "준수사항", "term_vi": "Điều cần tuân thủ", "def_ko": "지켜야 할 사항(한국어)", "def_vi": "Những điều cần tuân thủ"}, {"term_ko": "정보", "term_vi": "Thông tin", "def_ko": "알림(한국어)", "def_vi": "Thông báo"}, {"term_ko": "의견", "term_vi": "Ý kiến", "def_ko": "의견(한국어)", "def_vi": "Ý kiến"}, {"term_ko": "애로사항", "term_vi": "Khó khăn", "def_ko": "어려운 점(한국어)", "def_vi": "Những vấn đề khó khăn"}, {"term_ko": "조치", "term_vi": "Biện pháp", "def_ko": "조치를 취하다(한국어)", "def_vi": "Thực hiện biện pháp"}, {"term_ko": "보고하다", "term_vi": "Báo cáo", "def_ko": "알리다(한국어)", "def_vi": "Báo cáo"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (293, '9', '장기요양기관 사례관리에서 요양보호사의 역할로 옳은 것은?', '["요양보호의 주된 서비스 제공자는 보호자이다.", "사례관리에서 요양보호사는 제외된다.", "사회복지사가 수급자의 가정방문 시 요양보호사의 서비스는 중단된다.", "수급자가 병원에 입원하더라도 사후 관리업무에 협조한다.", "급여제공계획은 요양보호사가 단독으로 계획한다."]'::jsonb, 4, '요양보호사 역할에 대한 이해를 평가하는 문제입니다.', NULL, '{"1": "요양보호의 주된 서비스 제공자는 보호자가 아니라 요양보호사입니다.", "2": "사례관리에서 요양보호사는 제외되지 않고 중요한 역할을 맡습니다.", "3": "사회복지사가 방문하는 경우에도 요양보호사의 서비스가 중단되지 않습니다.\n[정답]", "4": "수급자가 병원에 입원하더라도 요양보호사는 사후 관리업무에 협조해야 합니다.", "5": "급여제공계획은 요양보호사 혼자서 계획할 수 없으며 협력해야 합니다."}'::jsonb, '[{"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기 요양 서비스를 제공하는 기관", "def_vi": "Cơ sở cung cấp dịch vụ chăm sóc dài hạn"}, {"term_ko": "사례관리", "term_vi": "Quản lý trường hợp", "def_ko": "개별 환자를 평가하고 관리하는 과정", "def_vi": "Quá trình đánh giá và quản lý bệnh nhân cá nhân"}, {"term_ko": "요양보호사", "term_vi": "Điều dưỡng viên chăm sóc", "def_ko": "환자를 돌보는 전문 인력", "def_vi": "Nhân viên chuyên trách chăm sóc bệnh nhân"}, {"term_ko": "수급자", "term_vi": "Người thụ hưởng", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "사회복지사", "term_vi": "Nhân viên xã hội", "def_ko": "사회복지 서비스를 제공하는 전문가", "def_vi": "Chuyên gia cung cấp dịch vụ phúc lợi xã hội"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (292, '9', '장기요양기관에서 실시하는 사례회의 목적으로 옳은 것은?', '["기관의 신규사업 홍보", "요양보호사의 직무평가", "노인 학대에 대한 정기교육", "서비스계획의 타당성 검토와 조정", "요양보호사 복리후생에 대한 의견 수렴"]'::jsonb, 4, '사례회의의 목적과 중요성을 이해하고 정확하게 기억하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "기관의 신규사업 홍보는 사례회의의 주요 목적이 아닙니다.\n[정답]", "2": "서비스계획의 타당성 검토와 조정은 사례회의의 중요한 목적입니다.", "3": "노인 학대에 대한 정기교육은 별도의 교육 프로그램에 해당합니다.", "4": "요양보호사 복리후생에 대한 의견 수렴은 사례회의의 목적과 관련이 없습니다."}'::jsonb, '[{"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기적인 요양 서비스를 제공하는 기관", "def_vi": "Cơ sở cung cấp dịch vụ chăm sóc dài hạn"}, {"term_ko": "사례회의", "term_vi": "Cuộc họp trường hợp", "def_ko": "특정 환자의 치료나 서비스 계획에 대해 논의하는 회의", "def_vi": "Cuộc họp thảo luận về kế hoạch điều trị hoặc dịch vụ cho bệnh nhân cụ thể"}, {"term_ko": "서비스계획", "term_vi": "Kế hoạch dịch vụ", "def_ko": "환자를 위한 서비스의 구체적인 계획", "def_vi": "Kế hoạch cụ thể cho dịch vụ cho bệnh nhân"}, {"term_ko": "타당성", "term_vi": "Tính khả thi", "def_ko": "실현 가능성", "def_vi": "Khả năng thực hiện"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자의 요양을 담당하는 사람", "def_vi": "Người chịu trách nhiệm chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (291, '9', '보고 내용이 복잡하거나 자료 보존이 필요할 때 사용하는 업무보고 형식으로 옳은 것은?', '["원격보고", "수시보고", "서면보고", "대면보고", "구두보고"]'::jsonb, 3, '업무보고 형식에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "원격보고: 원거리에서 이루어지는 보고 방식으로 자료 보존과는 거리가 있음.\n[정답]", "3": "서면보고: 복잡한 내용을 명확하게 전달하고 자료로 보존하기에 적합한 형태입니다.", "2": "수시보고: 필요할 때 즉시 이루어지지만 자료가 남지 않음.", "4": "대면보고: 직접 만나서 하는 보고 방식으로는 자료 보존이 어려움.", "5": "구두보고:口頭報告, 기록이 남지 않아 보존에 적합하지 않음."}'::jsonb, '[{"term_ko": "보고", "term_vi": "Báo cáo", "def_ko": "보고(한국어)", "def_vi": "báo cáo(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (290, '9', '상황이 급하거나 사안이 가벼울 때 활용할 수 있는 업무보고 형식으로 옳은 것은?', '["구두보고", "서면보고", "주간보고", "월례회의 보고", "정기업무보고"]'::jsonb, 1, '업무보고에 대한 다양한 형식 중, 특정 상황에서 적절한 형식을 묻는 문제입니다.', NULL, '{"1": "구두보고는 빠른 의사소통에 유리하며, 급한 상황에서 유용합니다.\n[정답]", "2": "서면보고는 종종 시간이 걸리고, 가벼운 사안에는 적합하지 않을 수 있습니다.", "3": "주간보고는 정기적인 업무 업데이트에 적합하지만, 급한 상황에 적합하지 않습니다.", "4": "월례회의 보고는 정기적인 회의에서 사용하는 형식으로, 긴급 상황에 부합하지 않습니다.", "5": "정기업무보고는 공식적인 문서로, 비상시에 사용하기에는 부적합합니다."}'::jsonb, '[{"term_ko": "구두보고", "term_vi": "Báo cáo bằng miệng", "def_ko": "말로 전달하는 보고", "def_vi": "Báo cáo được truyền đạt bằng lời"}, {"term_ko": "서면보고", "term_vi": "Báo cáo bằng văn bản", "def_ko": "문서로 작성된 보고", "def_vi": "Báo cáo được viết thành tài liệu"}, {"term_ko": "주간보고", "term_vi": "Báo cáo hàng tuần", "def_ko": "매주 정기적으로 제출하는 보고서", "def_vi": "Báo cáo được gửi định kỳ mỗi tuần"}, {"term_ko": "월례회의 보고", "term_vi": "Báo cáo cuộc họp hàng tháng", "def_ko": "매월 회의에서 보고하는 형식", "def_vi": "Hình thức báo cáo trong cuộc họp hàng tháng"}, {"term_ko": "정기업무보고", "term_vi": "Báo cáo công việc chính thức", "def_ko": "공식적인 보고서", "def_vi": "Tài liệu báo cáo chính thức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (289, '9', '재가방문 후 요양보호사가 시설장에게 신속하게 보고를 해야 하는 경우로 옳은 것은?', '["이불 빨래가 세탁실에 있다.", "유통기한이 임박한 유제품이 냉장고에 있다.", "화장실 등이 깜박거린다.", "대상자의 방문에 자물쇠가 설치되어 있다.", "대상자의 자녀가 오랜만에 방문하였다."]'::jsonb, 4, '재가방문 후 요양보호사가 시설장에게 보고해야 하는 상황을 이해하고 구별하는 능력을 평가하기 위함입니다.', NULL, '{"1": "이불 빨래가 세탁실에 있다는 사실은 큰 문제가 되지 않으므로 신속하게 보고할 필요가 없습니다.", "2": "유통기한이 임박한 유제품은 관리해야 할 사항이지만, 긴급한 상황이 아닙니다.", "3": "화장실 등이 깜박거리는 것은 점검이 필요할 수 있지만, 즉각적인 보고가 필요한 상황은 아닙니다.\n[정답]", "4": "대상자의 방문에 자물쇠가 설치되어 있다면, 이는 긴급히 조치를 취해야 하는 상황이므로 즉시 보고해야 합니다.", "5": "대상자의 자녀 방문은 일반적인 사항이기 때문에 긴급 보고가 아닙니다."}'::jsonb, '[{"term_ko": "재가방문", "term_vi": "Thăm nhà", "def_ko": "집에서의 요양 서비스 제공", "def_vi": "Cung cấp dịch vụ chăm sóc tại nhà"}, {"term_ko": "시설장", "term_vi": "Người quản lý", "def_ko": "시설의 관리자", "def_vi": "Người quản lý cơ sở"}, {"term_ko": "신속하게", "term_vi": "Nhanh chóng", "def_ko": "빠르게", "def_vi": "Nhanh chóng"}, {"term_ko": "보고", "term_vi": "Báo cáo", "def_ko": "보고하다", "def_vi": "Báo cáo"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "자물쇠", "term_vi": "Khóa", "def_ko": "khóa", "def_vi": "Khóa"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (288, '9', '요양보호 업무보고가 중요한 이유는?', '["서비스 비용의 결정", "대상자의 사적 정보 공유", "기관 중심의 서비스 제공", "요양보호서비스의 질 향상", "다른 장기요양기관과의 경쟁"]'::jsonb, 4, '요양보호 업무보고가 가지는 중요성을 이해하고, 그 중 서비스의 질 향상에 대한 인식을 평가하는 것이다.', NULL, '{"1": "서비스 비용은 요양보호 업무보고로 직접 결정되기 어렵다.\n[정답]", "4": "요양보호 업무보고는 서비스의 질을 높이는 데 중요한 역할을 한다.", "3": "기관 중심의 서비스 제공은 하나의 측면일 뿐이다.", "5": "경쟁도 존재하지만, 업무보고의 주된 목적은 아니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "Chăm sóc y tế", "def_ko": "돌보는 서비스(한국어)", "def_vi": "Dịch vụ chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (287, '9', '요양보호사가 기록한 내용으로 바르게 기록한 것은?', '["오늘 자장면을 많이 드셨다고 한다.", "소변을 시원하게 보았다고 한다.", "기분이 나쁜 것처럼 말하였다.", "1시부터 4시까지 낮잠을 주무심", "엉덩이에 욕창이 발생하였다."]'::jsonb, 4, '요양보호사가 환자에 대한 기록을 어떻게 바르게 작성해야 하는지 평가하는 문제입니다.', NULL, '{"1": "''많이 드셨다고 한다''는 주관적인 표현으로, 구체적인 수치를 제시하지 않아 부적절합니다.\n[정답]", "2": "''시원하게 보았다''는 비유적 표현이 포함되어 있어 애매한 보고입니다.", "3": "''나쁜 기분처럼 말하였다''는 감정의 주관적 해석으로 부적합합니다.", "4": "''낮잠을 주무심''은 구체적인 시간과 행동을 명확하게 기록하여 적절합니다.", "5": "''욕창이 발생하였다''는 의학적 용어는 적절하나 발생 시점이나 상태 설명이 부족합니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자 돌봄을 담당하는 사람", "def_vi": "Người phụ trách chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (286, '9', '요양보호 기록에 관한 설명으로 옳은 것은?', '["일주일 단위로 핵심 내용을 보고한다.", "공식화된 용어를 사용하여 기록한다.", "기록지는 열람하기 쉬운 곳에 비치한다.", "요양보호사가 느낀 점을 중심으로 기록한다.", "서비스는 내용을 우회적으로 표현하여 기록한다."]'::jsonb, 2, '요양보호 기록의 중요성과 올바른 기록 방법에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "일주일 단위로 핵심 내용을 보고하는 것은 일반적으로 필요하지 않습니다.\n[정답]", "2": "공식화된 용어를 사용하여 기록하는 것이 중요합니다.", "3": "기록지는 접근이 용이해야 하지만, ''열람하기 쉬운 곳''은 비밀 유지 측면에서 적절하지 않을 수 있습니다.", "4": "요양보호사가 느낀 점을 중심으로 기록하는 것은 주관적일 수 있습니다.", "5": "서비스 내용을 우회적으로 표현하여 기록하는 것은 명확성을 해칠 수 있습니다."}'::jsonb, '[{"term_ko": "요양보호 기록", "term_vi": "Ghi chép chăm sóc người cao tuổi", "def_ko": "환자를 돌보면서 기록하는 문서", "def_vi": "Tài liệu ghi lại quá trình chăm sóc bệnh nhân"}, {"term_ko": "공식화된 용어", "term_vi": "Thuật ngữ chính thức", "def_ko": "규칙적으로 사용하는 단어 등", "def_vi": "Từ ngữ sử dụng theo quy định"}, {"term_ko": "열람", "term_vi": "Xem xét", "def_ko": "열어보는 것", "def_vi": "Hành động xem, kiểm tra"}, {"term_ko": "주관적", "term_vi": "Chủ quan", "def_ko": "개인의 감정에 따른 것", "def_vi": "Điều gì đó dựa trên cảm xúc cá nhân"}, {"term_ko": "우회적", "term_vi": "Gián tiếp", "def_ko": "직접적이지 않은 방법", "def_vi": "Phương pháp không trực tiếp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (285, '9', '재가급여전자관리시스템 업무 절차 중 ☐ 안에 들어갈 순서로 옳은 것은?', '["사용자 등록 급여내용 전송", "사용자 등록 재가시설 등록", "서비스 내용 급여내용 전송", "서비스 내용 사용자 등록", "급여내용 전송 사용자 등록"]'::jsonb, 1, '재가급여전자관리시스템의 업무 절차를 이해하고 올바른 순서를 파악하는 것이 중요합니다.', NULL, '{"1": "사용자 등록 급여내용 전송\n[정답]", "2": "사용자 등록 재가시설 등록", "3": "서비스 내용 급여내용 전송", "4": "서비스 내용 사용자 등록", "5": "급여내용 전송 사용자 등록"}'::jsonb, '[{"term_ko": "재가급여", "term_vi": "Chăm sóc tại nhà", "def_ko": "가정에서 제공되는 요양 서비스", "def_vi": "Dịch vụ điều dưỡng được cung cấp tại nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (284, '9', '요양보호사가 기록하는 급여제공기록지에 주요 내용으로 옳은 것은?', '["상담내용 및 결과", "서비스의 목표, 내용, 횟수", "서비스의 제공 내용 및 시간", "사례회의 검토 내용", "대상자의 욕구 사정"]'::jsonb, 3, '요양보호사가 기록하는 급여제공기록지의 중요성을 이해하고, 어떤 내용이 포함되어야 하는지를 판단하게 하는 데 있다.', NULL, '{"1": "상담내용 및 결과: 상담 결과는 중요한 정보이지만, 급여제공기록지의 주요 내용은 아니다.\n[정답]", "2": "서비스의 목표, 내용, 횟수: 이 항목은 서비스 제공에 필요한 중요한 정보를 포함한다.", "3": "서비스의 제공 내용 및 시간: 급여제공기록지에서 가장 중요하게 기록되는 내용이다.", "4": "사례회의 검토 내용: 사례회의는 중요하지만, 직접적인 급여제공기록지의 일부분은 아니다.", "5": "대상자의 욕구 사정: 욕구 사정은 필요하지만, 급여제공기록지의 주요 내용에는 포함되지 않는다."}'::jsonb, '[{"term_ko": "급여", "term_vi": "Dịch vụ", "def_ko": "보상받는 서비스", "def_vi": "Dịch vụ nhận được"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (283, '9', '요양보호사의 재가급여제공 내용을 국민건강보험 공단에 실시간으로 전송하고 이를 급여비용 청구와 자동으로 연계하는 관리체계로 옳은 것은?', '["장기요양급여제공 기록관리 시스템", "스마트장기요양 시스템", "24시간 방문요양 시스템", "재가급여전자관리 시스템(RFID)", "급여제공계획 관리 시스템"]'::jsonb, 4, '요양보호사가 제공하는 재가급여의 관리체계를 이해하고 관련 시스템의 기능을 구별하는 것이 요구된다.', NULL, '{"1": "장기요양급여제공 기록관리 시스템: 요양급여 제공 기록을 관리하는 시스템으로, 실시간 전송 기능이 없다.\n[정답]", "2": "스마트장기요양 시스템: 최신 기술을 이용한 요양 시스템이나, 질문의 관리체계와는 다름.", "3": "24시간 방문요양 시스템: 방문요양 서비스 제공에 관한 시스템이지만, 실시간 전송과 연계 기능이 부족하다.", "4": "재가급여전자관리 시스템(RFID): 재가급여를 실시간으로 전송하고 청구와 연계되는 관리체계를 갖춘 시스템이다.", "5": "급여제공계획 관리 시스템: 급여 제공 계획을 관리하는 시스템으로, 실시간 전송과는 관련이 없다."}'::jsonb, '[{"term_ko": "재가급여", "term_vi": "Trợ cấp tại nhà", "def_ko": "가정에서 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc sức khỏe được cung cấp tại nhà"}, {"term_ko": "국민건강보험 공단", "term_vi": "Cơ quan bảo hiểm y tế quốc gia", "def_ko": "국민의 건강보험을 관리하는 기관", "def_vi": "Cơ quan quản lý bảo hiểm y tế cho công dân"}, {"term_ko": "실시간", "term_vi": "Thời gian thực", "def_ko": "즉시, 동시에", "def_vi": "Ngay lập tức, đồng thời"}, {"term_ko": "청구", "term_vi": "Yêu cầu thanh toán", "def_ko": "비용을 요구하는 행위", "def_vi": "Hành động yêu cầu chi phí"}, {"term_ko": "관리체계", "term_vi": "Hệ thống quản lý", "def_ko": "체계적으로 관리하는 시스템", "def_vi": "Hệ thống quản lý một cách có tổ chức"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (282, '9', '요양보호사의 업무내용을 기록하는 이유로 옳은 것은?', '["대상자의 개인정보를 공유할 수 있다.", "대상자의 책임성을 높일 수 있다.", "타 전문직과의 원활한 업무협조를 할 수 있다.", "요양보호사의 자질을 평가할 수 있다.", "대상자의 태도를 평가할 수 있다."]'::jsonb, 3, '요양보호사가 업무를 기록하는 이유를 이해하고 그 중요성을 파악하도록 하기 위함입니다.', NULL, '{"1": "개인정보를 공유할 수는 있지만, 이는 윤리적으로 문제가 될 수 있습니다.\n[정답]", "3": "기록을 통해 타 전문직과의 원활한 업무협조가 가능해집니다.", "2": "대상자의 책임성을 높이는 것은 기록과는 직접적인 연관이 없습니다.", "4": "기록은 요양보호사의 자질을 직접적으로 평가하기보다는 업무 수행을 평가하는 데 사용됩니다.", "5": "대상자의 태도는 기록으로 평가하기 어려운 주관적인 부분입니다."}'::jsonb, '[{"term_ko": "업무", "term_vi": "Nhiệm vụ", "def_ko": "일(한국어)", "def_vi": "Công việc(chăm sóc sức khỏe)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (281, '9', '요양보호사가 업무 내용을 기록하는 이유로 옳은 것은?', '["예산을 효율적으로 분배한다.", "대상자의 사생활을 파악한다.", "가족과의 의사송통을 제한한다.", "관련 전문가에게 정보를 제공한다.", "문제 발생 시 법적 책임을 회피할 수 있다."]'::jsonb, 4, '요양보호사가 업무 내용을 기록하는 이유를 이해하는지 평가하기 위함입니다.', NULL, '{"1": "예산을 효율적으로 분배한다는 것은 직접적인 관계가 없습니다.\n[정답]", "4": "관련 전문가에게 정보를 제공하는 것은 중요한 이유 중 하나입니다.", "3": "가족과의 의사소통을 제한하는 것은 바람직하지 않습니다.", "5": "문제 발생 시 법적 책임을 회피할 수 있다는 것은 기록의 주된 목적이 아닙니다.", "2": "대상자의 사생활을 파악하는 것은 업무 기록과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "업무", "term_vi": "Công việc", "def_ko": "일이나 과제", "def_vi": "Công việc hoặc nhiệm vụ"}, {"term_ko": "기록", "term_vi": "Ghi chép", "def_ko": "적어두다, 문서화하다", "def_vi": "Để ghi lại, tài liệu hóa"}, {"term_ko": "사생활", "term_vi": "Quyền riêng tư", "def_ko": "개인의 비공식적인 생활", "def_vi": "Cuộc sống không chính thức của cá nhân"}, {"term_ko": "전문가", "term_vi": "Chuyên gia", "def_ko": "특정 분야에서 지식과 경험이 있는 사람", "def_vi": "Người có kiến thức và kinh nghiệm trong một lĩnh vực cụ thể"}, {"term_ko": "법적 책임", "term_vi": "Trách nhiệm pháp lý", "def_ko": "법적으로 책임을 져야 하는 상태", "def_vi": "Tình trạng phải chịu trách nhiệm về mặt pháp lý"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (280, '1', '국가는 ''어버이날''을 지정하여 매년 기념하면서 모범 어르신을 선정하여 보상하는 유형으로 옳은 것은?', '["지적 보상", "경제적 보상", "정치적 보상", "자유적 보상", "문화유산의 전수"]'::jsonb, 3, '국가가 특정한 기념일을 제정하고 그에 따라 보상하는 방식에 대해 이해하고 있는지를 평가하고자 합니다.', NULL, '{"1": "지적 보상은 주로 지식이나 기술에 관련된 보상을 뜻하므로 틀립니다.\n[정답]", "2": "경제적 보상은 금전적인 보상을 의미하며, 어버이날 기념과 관련이 없습니다.", "3": "정치적 보상은 정치적 활동에 대한 대가를 의미하므로 부적합합니다.", "4": "자유적 보상은 자유를 기준으로 한 보상이기 때문에 맞지 않습니다.", "5": "문화유산의 전수는 전통이나 문화를 배우고 전하는 것으로, 질문의 맥락과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "국가", "term_vi": "Quốc gia", "def_ko": "나라의 정치적 조직", "def_vi": "Tổ chức chính trị của một đất nước"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (279, '1', '노화의 긍정적 측면으로 옳은 것은?', '["노화로 인해 일상적인 균형을 유지하기 힘들다.", "수준 높은 동기부여 직무를 수행하기 힘들다.", "즉각적인 의사소통을 하는 데 어려움이 없다.", "젊은 세대에 비해 중요한 정보를 추출하기 힘들다.", "젊은 세대에 비해 신중하고 조심스러워 실수가 적다."]'::jsonb, 5, '노화의 긍정적인 측면을 평가하고 이해하기 위한 질문입니다.', NULL, '{"1": "노화로 인해 일상적인 균형을 유지하기 힘들다는 부정적 측면입니다.", "2": "수준 높은 동기부여 직무를 수행하기 힘들다고 하는 것은 노화의 부정적인 면을 나타냅니다.", "3": "즉각적인 의사소통을 하는 데 어려움이 없다는 것은 긍정적 측면이 아닙니다.\n[정답]", "4": "젊은 세대에 비해 중요한 정보를 추출하기 힘들다는 것은 노화의 부정적인 면을 강조하는 것입니다.", "5": "젊은 세대에 비해 신중하고 조심스러워 실수가 적다는 것은 노화의 긍정적 측면을 나타냅니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "노화(성장과 발달 동안 발생하는 신체적, 정신적 변화의 자연적인 과정)", "def_vi": "Quá trình tự nhiên của sự thay đổi thể chất và tinh thần xảy ra trong suốt sự phát triển và trưởng thành"}, {"term_ko": "균형", "term_vi": "Cân bằng", "def_ko": "안정 상태", "def_vi": "Trạng thái ổn định"}, {"term_ko": "신중", "term_vi": "Thận trọng", "def_ko": "조심스러운 태도", "def_vi": "Thái độ cẩn thận"}, {"term_ko": "실수", "term_vi": "Lỗi", "def_ko": "잘못된 행동", "def_vi": "Hành động sai lầm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (278, '1', '노년기를 건강하게 보내기 위한 방법으로 옳은 것은?', '["사회 활동 참여를 제한한다.", "부부간 애정 표현을 삼간다.", "혼자 보내는 시간을 늘린다.", "뇌를 자극하는 독서 활동을 늘린다.", "영양보조식품 중심으로 식단을 구성한다."]'::jsonb, 4, '노년기를 건강하게 보내기 위한 방법에 대한 이해도를 평가합니다.', NULL, '{"1": "사회 활동 참여를 제한한다. 이는 건강한 노년기를 보내는 데 부정적 영향을 미칩니다.", "2": "부부간 애정 표현을 삼간다. 이것도 정서적 지원을 줄이는 행동입니다.", "3": "혼자 보내는 시간을 늘린다. 고립감을 증가시켜 건강에 좋지 않습니다.\n[정답]", "4": "뇌를 자극하는 독서 활동을 늘린다. 이는 뇌 건강에 긍정적인 영향을 줍니다.", "5": "영양보조식품 중심으로 식단을 구성한다. 이는 균형 잡힌 식사를 대체할 수 없습니다."}'::jsonb, '[{"term_ko": "노년기", "term_vi": "Thời kỳ cao niên", "def_ko": "노인의 시기", "def_vi": "Thời kỳ của người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (277, '1', '노년기의 신체적 특성으로 옳은 것은?', '["기초대사율이 증가한다.", "신체회복력이 향상된다.", "일상생활 수행능력이 향상된다.", "노화가 비가역적으로 진행된다.", "신체기관의 잔존능력이 향상된다."]'::jsonb, 4, '노년기의 신체적 특성을 이해하고 관련된 사실을 구별할 수 있는 능력을 평가하려는 의도입니다.', NULL, '{"1": "기초대사율은 노화에 따라 일반적으로 감소합니다.", "2": "신체회복력은 노화에 따라 감소합니다.", "3": "일상생활 수행능력은 노화로 인해 저하될 수 있습니다.\n[정답]", "4": "노화는 비가역적으로 진행되며, 이는 불가역적인 신체적 변화를 의미합니다.", "5": "신체기관의 잔존능력은 보통 저하되는 경향이 있습니다."}'::jsonb, '[{"term_ko": "노년기", "term_vi": null, "def_ko": "유년이 지난 후의 나이, 신체적 특성: 몸의 특성, 기초대사율: 기본적인 에너지 소비량, 신체회복력: 몸의 회복 능력, 비가역적: 되돌릴 수 없는, 잔존능력: 남아있는 능력", "def_vi": null}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (276, '1', '다음의 노인의 심리적 특성으로 옳은 것은?• 식욕부진, 체중 감소 등 신체적인 증상을 호소한다.• 주변 사람들에게 적대적으로 대하거나 비난하는 행동을 보인다.', '["우울증 경향의 증가", "내향성의 증가", "조심성의 증가", "경직성의 증가", "생에 대한 회고의 경향 증가"]'::jsonb, 1, '노인의 심리적 특성을 이해하고 이를 바탕으로 적절한 대처 방안을 고민하도록 한다.', NULL, '{"1": "우울증 경향의 증가: 노인이 식욕부진, 체중 감소 등의 신체적 증상을 보이는 경우 우울증의 징후일 수 있다.\n[정답]", "2": "내향성의 증가: 내향성이 증가하는 것은 항상 우울과 관련이 있는 것은 아니다.", "3": "조심성의 증가: 조심성 증가와 관련된 심리적 증상은 다른 경우에 해당한다.", "4": "경직성의 증가: 경직성의 증가는 특정한 인격 특성이며 우울증의 직접적인 징후가 아니다.", "5": "생에 대한 회고의 경향 증가: 생에 대한 회고는 노인의 일반적인 특성일 수 있지만 우울증과는 명확한 연관성이 없다."}'::jsonb, '[{"term_ko": "심리적", "term_vi": "Tâm lý", "def_ko": "정신적인", "def_vi": "liên quan đến tinh thần"}, {"term_ko": "신체적", "term_vi": "Thể chất", "def_ko": "신체와 관련된", "def_vi": "liên quan đến cơ thể"}, {"term_ko": "우울증", "term_vi": "Trầm cảm", "def_ko": "깊은 슬픔의 상태", "def_vi": "trạng thái buồn sâu sắc"}, {"term_ko": "식욕부진", "term_vi": "Giảm sự thèm ăn", "def_ko": "식욕이 감소함", "def_vi": "giảm sự đói"}, {"term_ko": "체중", "term_vi": "Cân nặng", "def_ko": "몸의 무게", "def_vi": "trọng lượng cơ thể"}, {"term_ko": "경향", "term_vi": "Xu hướng", "def_ko": "특정 방향으로의 성향", "def_vi": "sự thiên về một hướng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (275, '1', '결단이나 행동이 느려지고 매사에 신중해지는 노인의 심리적 배경으로 옳은 것은?', '["비가역성", "의존성", "조심성", "경직성", "내향성"]'::jsonb, 3, '노인의 심리적 특성과 관련된 행동 변화를 이해하고 올바른 개념을 선택하도록 유도하는 문제입니다.', NULL, '{"1": "비가역성: 노화로 인해 일어나는 어떤 변화는 되돌릴 수 없다는 의미입니다.", "2": "의존성: 노인이 신체적, 정서적으로 타인에게 의존하게 되는 경향을 나타냅니다.\n[정답]", "3": "조심성: 노화로 인해 신중해지고 결단력이 느려지는 경향을 설명합니다.", "4": "경직성: 사고나 행동이 융통성 없이 고정된 상태를 의미합니다.", "5": "내향성: 외부와의 상호작용보다 자신의 내면을 중시하는 성향을 뜻합니다."}'::jsonb, '[{"term_ko": "결단", "term_vi": "Quyết định", "def_ko": "결정하고 실행하는 것", "def_vi": "Quyết định và thực hiện"}, {"term_ko": "행동", "term_vi": "Hành động", "def_ko": "어떤 행동이나 작업을 수행하는 것", "def_vi": "Thực hiện một hành động hoặc công việc"}, {"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người có tuổi"}, {"term_ko": "심리적", "term_vi": "Tâm lý", "def_ko": "마음과 정신과 관련된", "def_vi": "Liên quan đến tâm trí và tinh thần"}, {"term_ko": "신중", "term_vi": "Thận trọng", "def_ko": "조심스럽고 고려하는 태도", "def_vi": "Thái độ cẩn thận và xem xét"}, {"term_ko": "의존성", "term_vi": "Tính phụ thuộc", "def_ko": "다른 사람에게 의지하는 상태", "def_vi": "Trạng thái phụ thuộc vào người khác"}, {"term_ko": "조심성", "term_vi": "Thận trọng", "def_ko": "신중함", "def_vi": "Tính cẩn trọng"}, {"term_ko": "경직성", "term_vi": "Tính cứng nhắc", "def_ko": "생각과 행동이 경직된 상태", "def_vi": "Trạng thái tư duy và hành động không linh hoạt"}, {"term_ko": "내향성", "term_vi": "Tính hướng nội", "def_ko": "외향적이지 않음", "def_vi": "Không hướng ngoại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (274, '1', '다음의 노인의 심리적 특성으로 옳은 것은?• 노인은 자신에게 익숙한 습관적인 태도나 방법을 고수한다.• 매사에 융통성이 없어지고, 새로운 변화를 싫어하며, 도전적인 일을 꺼리는 경향을 보인다.• 새로운 기구를 사용하거나 새로운 방식으로 일을 처리하는 데에 저항한다.', '["우울증 경향의 증가", "내향성의 증가", "조심성의 증가", "경직성의 증가", "의존성의 증가"]'::jsonb, 4, '노인의 심리적 특성을 이해하고, 그것이 어떤 행동 양상으로 나타나는지를 평가하는 것이 중요하다.', NULL, '{"1": "우울증 경향의 증가: 노인이 느끼는 심리적 특성이 반드시 우울증으로 연결되지는 않는다.", "2": "내향성의 증가: 노인이 내향적으로 변할 수 있지만, 이것이 주된 특징은 아니다.", "3": "조심성의 증가: 조심성은 중요하지만, 경직성이 더 나타나기 쉽다.\n[정답]", "4": "경직성의 증가: 노인이 새로운 변화를 싫어하고 고수하는 모습은 경직성을 나타낸다.", "5": "의존성의 증가: 의존성도 나타날 수 있지만, 경직성이 더 두드러진다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (273, '1', '노년기의 일반적인 특성으로 옳은 것은?', '["사고의 융통성이 증대된다.", "사회적 유대관계가 확대된다.", "삶에 대한 회고적 경향이 나타난다.", "역할 상실로 자기정체성이 강화된다.", "내향성의 감소로 매사에 신중해진다."]'::jsonb, 3, '노년기의 일반적인 특성을 이해하고 적용하는 능력을 평가하기 위해 출제된 문제이다.', NULL, '{"1": "사고의 융통성이 감소한다.\n[정답]", "3": "노년기는 회고적 경향이 나타나 삶을 돌아보게 된다.", "2": "사회적 유대관계는 축소되는 경향이 있다.", "4": "역할 상실이 일어나면 자기정체성이 흔들리는 경우가 많다.", "5": "내향성의 감소는 일반적으로 나타나지 않는다."}'::jsonb, '[{"term_ko": "노년기", "term_vi": "Người già", "def_ko": "나이가 많은 시기(한국어)", "def_vi": "Thời kỳ có tuổi cao"}, {"term_ko": "특성", "term_vi": "Đặc điểm", "def_ko": "특징(한국어)", "def_vi": "Tính chất, đặc điểm"}, {"term_ko": "사고", "term_vi": "Suy nghĩ", "def_ko": "사고(한국어)", "def_vi": "Suy nghĩ"}, {"term_ko": "융통성", "term_vi": "Linh hoạt", "def_ko": "유연함(한국어)", "def_vi": "Tính linh hoạt"}, {"term_ko": "사회적", "term_vi": "Xã hội", "def_ko": "사회와 관련된(한국어)", "def_vi": "Liên quan đến xã hội"}, {"term_ko": "유대관계", "term_vi": "Quan hệ", "def_ko": "연결관계(한국어)", "def_vi": "Mối quan hệ"}, {"term_ko": "회고적", "term_vi": "Hồi tưởng", "def_ko": "회고하는 것(한국어)", "def_vi": "Nhớ lại"}, {"term_ko": "경향", "term_vi": "Xu hướng", "def_ko": "경향(한국어)", "def_vi": "Xu hướng"}, {"term_ko": "자기정체성", "term_vi": "Bản sắc cá nhân", "def_ko": "자기 정체성(한국어)", "def_vi": "Danh tính cá nhân"}, {"term_ko": "내향성", "term_vi": "Hướng nội", "def_ko": "내향적인 성향(한국어)", "def_vi": "Tính hướng nội"}, {"term_ko": "신중", "term_vi": "Thận trọng", "def_ko": "신중함(한국어)", "def_vi": "Sự thận trọng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (272, '1', '노화에 따른 노년기 특성으로 옳은 것은?', '["유대감이 줄어든다.", "조심성이 감소한다.", "우울증 경향이 감소한다.", "정서적 의존성이 감소한다.", "친근한 사물에 대한 애착이 감소한다."]'::jsonb, 1, '노화에 따른 노년기의 정신적, 정서적 변화를 이해하고, 이와 관련된 특성을 파악하기 위함입니다.', NULL, '{"1": "노화가 진행됨에 따라 유대감이 줄어드는 경향이 있습니다.\n[정답]", "2": "일반적으로 조심성이 오히려 증가하는 경향이 있습니다.", "3": "우울증 경향이 증가하는 경우가 많습니다.", "4": "정서적 의존성은 증가할 수 있습니다.", "5": "친근한 사물에 대한 애착은 오히려 증가할 수 있습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙는 것(한국어)", "def_vi": "Sự già đi(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (271, '1', '에릭슨이 주장한 생애주기에서 노년기에 해당하는 특성으로 옳은 것은?', '["신뢰감 - 불신감", "자율성 - 의심", "정체감 - 고립감", "생산성 - 자아 침체", "자아통합 - 절망감"]'::jsonb, 5, '에릭슨의 생애주기 이론을 기반으로 노년기의 특징을 묻는 문제입니다.', NULL, '{"1": "신뢰감 - 불신감: 에릭슨의 초기 단계에서의 개념입니다.", "2": "자율성 - 의심: 유아기의 단계에서 해당하는 개념입니다.", "3": "정체감 - 고립감: 청소년기의 발달 단계에 해당합니다.", "4": "생산성 - 자아 침체: 중년기의 특징입니다.\n[정답]", "5": "자아통합 - 절망감: 노년기의 특징으로, 개인이 자신의 삶을 수용하고 일생을 통합적으로 이해하는 과정에서 느끼는 감정입니다."}'::jsonb, '[{"term_ko": "생애주기", "term_vi": "Giai đoạn cuộc đời", "def_ko": "인생의 다양한 단계", "def_vi": "Các giai đoạn khác nhau trong cuộc sống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (270, '1', '다음에서 설명하는 가족형태로 옳은 것은?• 노인 부모가 같은 아파트에 따로 거주하고 있고, 성인 자녀로부터 필요할 때 돌봄을 받고 있다.', '["핵가족", "조손가족", "다문화가족", "한부모가족", "수정확대가족"]'::jsonb, 5, '고령 부모가 독립적으로 거주하면서 성인 자녀의 돌봄을 받는 가족 형태를 이해하는지 평가하기 위한 문제입니다.', NULL, '{"1": "핵가족: 부모와 자녀로 구성된 기본적인 가족 형태입니다.", "2": "조손가족: 손주가 조부모와 함께 사는 형태입니다.", "3": "다문화가족: 서로 다른 문화적 배경을 가진 가족입니다.", "4": "한부모가족: 한 부모가 자녀를 양육하는 형태입니다.\n[정답]", "5": "수정확대가족: 부모, 자녀, 조부모 등이 함께 거주하거나 밀접하게 연결된 가족 형태입니다."}'::jsonb, '[{"term_ko": "가족형태", "term_vi": "Hình thức gia đình", "def_ko": "가족의 구성 구조", "def_vi": "Cấu trúc của gia đình"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (269, '1', '노년기 가족관계의 변화로 옳은 것은?', '["확대가족이 증가한다.", "고부 갈등이 해소된다.", "은퇴로 인해 부부관계가 수직적으로 변한다.", "조부모는 손자녀의 긍정적 자아 형성에 기여한다.", "배우자의 상실로 빈 둥지 증후군을 경험한다."]'::jsonb, 4, '노년기 가족관계의 변화와 그 영향을 이해하고 잘 알고 있는지 평가하기 위함입니다.', NULL, '{"1": "확대가족의 증가가 아니라 주로 핵가족이 증가하는 경향이 있습니다.\n[정답]", "4": "조부모는 손자녀의 긍정적 자아 형성에 기여하는 중요한 역할을 합니다.", "2": "고부 갈등은 종종 해소되지 않고 계속될 수 있습니다.", "3": "은퇴로 인해 부부관계는 흔히 수평적으로 변하는 경향이 있습니다.", "5": "배우자의 상실로 인해 빈 둥지 증후군을 경험할 수 있지만, 이 선택지는 전체적인 변화에 대한 직접적인 설명이 아닙니다."}'::jsonb, '[{"term_ko": "노년기", "term_vi": "Giai đoạn người già", "def_ko": "노인(성인) 시기(한국어)", "def_vi": "Giai đoạn của người già"}, {"term_ko": "가족관계", "term_vi": "Mối quan hệ gia đình", "def_ko": "가족 구성원 간의 관계(한국어)", "def_vi": "Mối quan hệ giữa các thành viên trong gia đình"}, {"term_ko": "확대가족", "term_vi": "Gia đình mở rộng", "def_ko": "조부모, 부모, 자녀가 함께 사는 가족(한국어)", "def_vi": "Gia đình có ông bà, cha mẹ và con cái sống cùng nhau"}, {"term_ko": "고부 갈등", "term_vi": "Xung đột mẹ chồng và nàng dâu", "def_ko": "시어머니와 며느리 간의 갈등(한국어)", "def_vi": "Sự xung đột giữa mẹ chồng và con dâu"}, {"term_ko": "빈 둥지 증후군", "term_vi": "Hội chứng tổ chim trống", "def_ko": "자녀가 성장하여 집을 떠난 후 부모가 느끼는 외로움(한국어)", "def_vi": "Cảm giác cô đơn của cha mẹ khi con cái lớn lên và rời bỏ tổ ấm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (268, '1', '노인부향 문제의 개선 방안으로 옳은 것은?', '["자녀에게 부양 부담을 부과한다.", "노인부양을 가족의 문제로 한정한다.", "소득 재분배를 위한 기초 연금을 축소한다.", "사회보험제도를 통해 세대통합을 증진한다.", "돌봄서비스에 대한 국각의 책임을 축소한다."]'::jsonb, 4, '노인부양 문제에 대한 올바른 개선 방안을 찾기 위한 문제입니다.', NULL, '{"1": "자녀에게 부양 부담을 부과하는 것은 가족의 부담을 가중시킬 뿐입니다.\n[정답]", "4": "사회보험제도를 통해 세대통합을 증진하는 것은 노인부양 문제의 해결에 긍정적인 역할을 할 수 있습니다.", "2": "노인부양을 가족의 문제로 한정하는 것은 사회적인 책임을 경시하는 결과를 초래할 수 있습니다.", "3": "소득 재분배를 위한 기초 연금을 축소하는 것은 노인들의 생활을 더욱 어렵게 만들 것입니다.", "5": "돌봄서비스에 대한 국가의 책임을 축소하는 것은 오히려 문제를 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "부양", "term_vi": "Chăm sóc", "def_ko": "돌봄이나 지원", "def_vi": "Sự trợ cấp hoặc hỗ trợ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (267, '1', '대상자 중심의 요양보호'' 의 원칙을 준수한 사례로 옳은 것은?', '["\"화장실에 가시면 어르신이나 저도 고생이니까 간이변기를 사용하시는 게 좋겠어요.\"", "\"걸으려면 힘들고 넘어지니까 그냥 휠체어 타세요. 제가 밀어 드릴게요.\"", "\"잠에서 깰 수 있으니 주무시는 동안에는 기저귀를 확인하지 않을게요.\"", "\"지금 목욕 안하면 다음 주까지 기다려야 해요. 그러니까 지금 얼른 하세요.\"", "\"안 묶으면 콧줄을 잡아 뽑으시니 억제대로 묶어 놓을 수밖에 없어요.\""]'::jsonb, 3, '대상자 중심의 요양보호 원칙에 맞는 행동을 구분하는 것이다.', NULL, '{"1": "\"어르신이나 저도 고생이니까 간이변기를 사용하시는 게 좋겠어요.\" - 어르신의 편안함을 고려하지 않은 발언이다.", "2": "\"걸으려면 힘들고 넘어지니까 그냥 휠체어 타세요. 제가 밀어 드릴게요.\" - 대상자의 자율성을 무시한 결정이다.\n[정답]", "3": "\"잠에서 깰 수 있으니 주무시는 동안에는 기저귀를 확인하지 않을게요.\" - 대상자의 수면을 존중한 행동이다.", "4": "\"지금 목욕 안하면 다음 주까지 기다려야 해요. 그러니까 지금 얼른 하세요.\" - 대상자의 선택을 강요하는 발언이다.", "5": "\"안 묶으면 콧줄을 잡아 뽑으시니 억제대로 묶어 놓을 수밖에 없어요.\" - 대상자의 인권을 침해하는 행동이다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 수혜자", "def_vi": "Bệnh nhân hoặc người thụ hưởng"}, {"term_ko": "요양보호", "term_vi": "Chăm sóc", "def_ko": "노인을 돌보는 일", "def_vi": "Công việc chăm sóc người cao tuổi"}, {"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "기본 규칙, 가이드라인", "def_vi": "Quy tắc cơ bản, hướng dẫn"}, {"term_ko": "자율성", "term_vi": "Tự chủ", "def_ko": "스스로 결정할 수 있는 능력", "def_vi": "Khả năng tự quyết định"}, {"term_ko": "선택", "term_vi": "Lựa chọn", "def_ko": "고르거나 결정하는 것", "def_vi": "Việc chọn hoặc quyết định"}, {"term_ko": "인권", "term_vi": "Quyền lợi", "def_ko": "인간의 기본 권리", "def_vi": "Quyền cơ bản của con người"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (266, '1', '대상자와 의사소통할 때 편안하게 대면하는 방법으로 옳은 것은?', '["대상자와 눈을 맞추고 나서 말을 건넨다.", "손가락으로 대상자의 손목을 잡음녀서 말한다.", "잠에서 덜 깬 대상자에게는 옆으로 조용히 다가간다.", "대상자가 벽 쪽으로 돌아누워 있으면 등 뒤에서 말한다.", "반응이 없는 대상자는 말을 건네지 않고 하던 일을 계속한다."]'::jsonb, 1, '대상자와 효과적으로 소통하는 방법을 이해하고 옳은 행동을 선택하도록 유도하기 위함입니다.', NULL, '{"1": "대상자와 눈을 맞추고 나서 말을 건넨다. 이는 상대방에게 존중을 표시하고 편안한 대화를 유도하는 방법입니다.\n[정답]", "2": "손가락으로 대상자의 손목을 잡으면서 말한다. 이는 불편함을 초래할 수 있는 행동입니다.", "3": "잠에서 덜 깬 대상자에게는 옆으로 조용히 다가간다. 이는 적절하나 직접적인 대면이 부족할 수 있습니다.", "4": "대상자가 벽 쪽으로 돌아누워 있으면 등 뒤에서 말한다. 이는 상대방이 불안감을 느낄 수 있습니다.", "5": "반응이 없는 대상자는 말을 건네지 않고 하던 일을 계속한다. 이는 대상자와의 의사소통을 소홀히 하는 행동입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (265, '2', '생활이 어려운 사람에게 필요한 급여를 제공하여 최저생활을 보장하고 자활을 돕는 것을 목적으로 하는 공적부조제도로 옳은 것은?', '["국민연금제도", "고용보험제도", "국민건강보험제도", "국민기초생활보장제도", "산업재해보상보험제도"]'::jsonb, 4, '공적부조제도를 이해하고 그것에 해당하는 제도를 구별하는 것의 중요성을 확인하기 위함입니다.', NULL, '{"1": "국민연금제도는 노후 소득 보장을 위한 제도입니다.\n[정답]", "4": "국민기초생활보장제도는 생활이 어려운 사람에게 급여를 제공하여 최저생활을 보장하고 자활을 돕는 제도입니다.", "2": "고용보험제도는 실직 시 소득을 보장하는 제도입니다.", "3": "국민건강보험제도는 건강 관리를 위한 보험입니다.", "5": "산업재해보상보험제도는 산업재해로 인한 피해를 보상하는 제도입니다."}'::jsonb, '[{"term_ko": "공적부조제도", "term_vi": "Chế độ hỗ trợ công cộng", "def_ko": "공적 재정으로 지원을 받는 제도", "def_vi": "Chế độ nhận hỗ trợ từ ngân sách công"}, {"term_ko": "급여", "term_vi": "Trợ cấp", "def_ko": "급여(보조금)", "def_vi": "Trợ cấp(tiền hỗ trợ)"}, {"term_ko": "자활", "term_vi": "Tự lập", "def_ko": "스스로 생활을 할 수 있는 상태", "def_vi": "Trạng thái có thể tự sống"}, {"term_ko": "최저생활", "term_vi": "Cuộc sống tối thiểu", "def_ko": "최하층에서의 생활", "def_vi": "Cuộc sống ở mức thấp nhất"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (264, '2', '국민의 질병 및 건강 증진에 대하여 보험급여를 제공함으로써 국민 보건 향상과 사회보장 증진에 기여하는 제도로 옳은 것은?', '["국민연금보험제도", "긴급복지지원제도", "국민건강보험제도", "산업재해보상보험제도", "국민기초생활보장제도"]'::jsonb, 3, '국민의 건강과 관련된 보험 제도를 이해하고, 각 제도의 목적을 구별하기 위함입니다.', NULL, '{"1": "국민연금보험제도는 노후 생활 안정과 관련된 제도입니다.\n[정답]", "3": "국민건강보험제도는 국민의 질병 및 건강 증진을 위한 보험 제도입니다.", "2": "긴급복지지원제도는 긴급한 생계 지원을 위한 제도입니다.", "4": "산업재해보상보험제도는 산업재해로 인한 피해 보상을 위한 제도입니다.", "5": "국민기초생활보장제도는 기초생활 유지 지원을 위한 제도입니다."}'::jsonb, '[{"term_ko": "국민", "term_vi": "Công dân", "def_ko": "국민(한국어)", "def_vi": "Công dân"}, {"term_ko": "질병", "term_vi": "Bệnh tật", "def_ko": "질병(한국어)", "def_vi": "Bệnh tật"}, {"term_ko": "건강", "term_vi": "Sức khỏe", "def_ko": "건강(한국어)", "def_vi": "Sức khỏe"}, {"term_ko": "증진", "term_vi": "Nâng cao", "def_ko": "증진(한국어)", "def_vi": "Nâng cao"}, {"term_ko": "보험", "term_vi": "Bảo hiểm", "def_ko": "보험(한국어)", "def_vi": "Bảo hiểm"}, {"term_ko": "제도", "term_vi": "Chế độ", "def_ko": "제도(한국어)", "def_vi": "Chế độ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (263, '2', '요양보호사가 실직했을 때 생활에 필요한 급여를 제공하는 사회보험으로 옳은 것은?', '["고용보험", "국민건강보험", "국민연금보험", "산업재해보상보험", "노인장기요양보험"]'::jsonb, 1, '사회보험에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "고용보험은 실직한 근로자에게 생활비를 지원하는 제도입니다.\n[정답]", "2": "국민건강보험은 건강을 유지하기 위한 보험으로, 실직과 관련이 없습니다.", "3": "국민연금보험은 노후를 대비한 제도입니다.", "4": "산업재해보상보험은 업무상 재해에 대한 보상을 제공합니다.", "5": "노인장기요양보험은 노인을 위한 장기 요양 서비스에 대한 보험입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "돌봄 및 지원을 제공하는 전문인력", "def_vi": "Người cung cấp sự hỗ trợ và chăm sóc"}, {"term_ko": "실직", "term_vi": "Thất nghiệp", "def_ko": "일자리를 잃다", "def_vi": "Mất việc"}, {"term_ko": "급여", "term_vi": "Trợ cấp", "def_ko": "보상금, 재정지원", "def_vi": "Tiền hỗ trợ"}, {"term_ko": "사회보험", "term_vi": "Bảo hiểm xã hội", "def_ko": "건강, 노후 등을 위해 정부가 제공하는 보험", "def_vi": "Bảo hiểm do chính phủ cung cấp cho sức khỏe và hưu trí"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (262, '2', '노인을 위한 유엔의 5원칙 중 ''독립의 원칙''의 원칙으로 옳은 것은?', '["가능한 오랫동안 가정에서 살 수 있어야 한다.", "노인들을 위한 사회운동을 하고 단체를 조직할 수 있어야 한다.", "자율과 보호를 높이는 사회적, 법률적인 서비스를 이용할 수 있어야 한다.", "노인의 잠재력을 계발할 수 있는 기회가 있어야 한다.", "존업과 안전 속에서 살 수 있어야 한다."]'::jsonb, 1, '노인의 독립적인 생활을 보장하는 원칙에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "가능한 오랫동안 가정에서 살 수 있어야 한다.\n[정답]", "2": "노인들을 위한 사회운동을 하고 단체를 조직할 수 있어야 한다.", "3": "자율과 보호를 높이는 사회적, 법률적인 서비스를 이용할 수 있어야 한다.", "4": "노인의 잠재력을 계발할 수 있는 기회가 있어야 한다.", "5": "존엄과 안전 속에서 살 수 있어야 한다."}'::jsonb, '[{"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "원칙(한국어)", "def_vi": "nguyên tắc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (261, '2', '다음 사례에서 노인이 실천한 노인복지 원칙으로 옳은 것은?• 교사로 은퇴한 노인이 지역아동센터 아동을 대상으로 한 교육봉사 단체를 조직하여 활동하고 있다.', '["독립의 원칙", "참여의 원칙", "보호의 원칙", "자아실현의 원칙", "존엄의 원칙"]'::jsonb, 2, '노인이 실천한 노인복지 원칙을 이해하고 적용할 수 있는지 평가하기 위함입니다.', NULL, '{"1": "독립의 원칙: 노인이 자립하여 생활할 수 있도록 지원하는 원칙입니다.\n[정답]", "2": "참여의 원칙: 노인이 사회와 지역사회에 적극적으로 참여하고 활동할 수 있도록 장려하는 원칙입니다.", "3": "보호의 원칙: 노인의 안전과 권리를 보호하는 원칙입니다.", "4": "자아실현의 원칙: 노인이 자신의 잠재력과 능력을 발휘하여 자아를 실현할 수 있도록 지원하는 원칙입니다.", "5": "존엄의 원칙: 노인이 존중받고 권리를 인정받으며 존엄성을 유지하는 원칙입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người lớn tuổi"}, {"term_ko": "복지", "term_vi": "Phúc lợi", "def_ko": "복지(한국어)", "def_vi": "Phúc lợi"}, {"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "원칙(한국어)", "def_vi": "Nguyên tắc"}, {"term_ko": "참여", "term_vi": "Tham gia", "def_ko": "참여(한국어)", "def_vi": "Tham gia"}, {"term_ko": "자립", "term_vi": "Tự lập", "def_ko": "자립(한국어)", "def_vi": "Tự lập"}, {"term_ko": "자아실현", "term_vi": "Tự thể hiện", "def_ko": "자아실현(한국어)", "def_vi": "Tự thực hiện"}, {"term_ko": "존엄", "term_vi": "Nhân phẩm", "def_ko": "존엄(한국어)", "def_vi": "Nhân phẩm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (260, '2', '다음에서 설명하는 노인복지 원칙으로 옳은 것은?• 노인의 자율과 보호를 높이는 사회적, 법률적인 서비스를 이용할 수 있어야 한다.', '["독립의 원칙", "평등의 원칙", "보호의 원칙", "참여의 원칙", "존엄의 원칙"]'::jsonb, 3, '노인복지의 원칙에 대해 이해하고 옳은 원칙을 선택하는 것입니다.', NULL, '{"1": "독립의 원칙: 노인은 독립적으로 생활할 수 있어야 하며, 이를 위해 지원을 받아야 합니다.\n[정답]", "3": "보호의 원칙: 노인의 자율과 보호를 동시에 고려하는 원칙으로, 안전과 권리를 보호받아야 합니다.", "2": "평등의 원칙: 모든 노인이 평등하게 대우받아야 한다는 원칙입니다.", "4": "참여의 원칙: 노인이 사회생활에 참여할 수 있도록 보장해야 하는 원칙입니다.", "5": "존엄의 원칙: 노인의 존엄성을 존중해야 한다는 원칙입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "고령자(한국어)", "def_vi": "Người già(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (259, '2', '다음에서 설명하는 노인복지 원칙으로 옳은 것은?• 노인의 잠재력을 계발할 수 있는 기회가 있어야 한다.• 사회의 교육적, 문화적, 정신적 자원과 여가서비스를 이용할 수 있어야 한다.', '["독립의 원칙", "평등의 원칙", "보호의 원칙", "존엄의 원칙", "자아실현의 원칙"]'::jsonb, 5, '노인복지 원칙에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "독립의 원칙: 노인이 스스로 결정하고 행동할 수 있는 것을 중요시하는 원칙입니다.", "2": "평등의 원칙: 모든 노인이 동등한 기회를 가져야 한다는 원칙입니다.", "3": "보호의 원칙: 노인을 외부로부터 보호해야 한다는 관점입니다.", "4": "존엄의 원칙: 노인의 존엄성을 존중하는 것을 강조합니다.\n[정답]", "5": "자아실현의 원칙: 노인이 자신의 잠재력을 개발하고 자아를 실현할 수 있는 기회를 제공해야 한다는 원칙입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노년기에 있는 사람", "def_vi": "Người trong độ tuổi cao niên"}, {"term_ko": "복지", "term_vi": "Phúc lợi", "def_ko": "사회적 서비스 제공", "def_vi": "Cung cấp dịch vụ xã hội"}, {"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "기본적인 이념", "def_vi": "Truyền thống cơ bản"}, {"term_ko": "잠재력", "term_vi": "Tiềm năng", "def_ko": "겉으로 드러나지 않은 능력", "def_vi": "Năng lực chưa được thể hiện"}, {"term_ko": "자아실현", "term_vi": "Tự thực hiện", "def_ko": "자신의 가능성을 최대한 발휘함", "def_vi": "Phát huy tối đa khả năng của bản thân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (258, '2', '치매 환자 및 가족들이 안심하고 살아가도록 전담 코디네이터를 1:1로 매칭하여 서비스를 연계하고 관리를 수행하는 기관으로 옳은 것은?', '["노인돌봄종합서비스", "노인보호 전문기관", "노인건강진단", "노인복지관", "치매안심센터"]'::jsonb, 5, '치매 환자와 그 가족들을 위한 전문적인 지원 기관에 대한 이해를 평가하고자 함.', NULL, '{"1": "노인돌봄종합서비스는 다양한 서비스를 제공하지만 1:1 매칭 서비스를 직접적으로 제공하지 않음.\n[정답]", "5": "치매안심센터는 치매 환자와 가족들을 위한 1:1 매칭 서비스를 제공하는 전문 기관임.", "3": "노인건강진단은 건강 검진을 목적으로 하는 것이므로 관련성이 없음.", "4": "노인복지관은 다양한 복지 서비스를 제공하지만 치매 전담 코디네이터와의 1:1 매칭과는 거리가 있음.", "2": "노인보호 전문기관은 노인 보호를 위한 기관으로, 치매 환자에 특화된 서비스는 아님."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억과 사고 능력의 감퇴를 유발하는 질환", "def_vi": "Bệnh gây giảm khả năng ghi nhớ và tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (257, '2', '노인의 인권보호 사업, 학대예방사업, 노인인식 개선, 노인자살 예방 교육 및 시설 내 노인권리보호, 피해노인에 대한 상담 및 보호를 담당하는 기관으로 옳은 것은?', '["보건소", "학대피해노인 전용쉼터", "노인보호 전문기관", "노인종합복지센터", "정신건강복지센터"]'::jsonb, 3, '노인의 권리를 보호하고 관련 사업을 담당하는 기관에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "보건소는 일반 건강 관리를 담당하는 기관으로, 노인 전용 인권 보호와는 거리가 있습니다.\n[정답]", "3": "노인보호 전문기관은 노인의 인권 보호, 학대 예방, 상담 및 보호를 전문으로 하는 기관입니다.", "2": "학대피해노인 전용쉼터는 피해 노인의 일시적인 안전을 위한 공간일 뿐, 종합적인 권리 보호를 책임지는 기관은 아닙니다.", "4": "노인종합복지센터는 다양한 복지 서비스를 제공하지만, 법적 권리 보호에 전문적이지 않습니다.", "5": "정신건강복지센터는 정신 건강 문제를 다루는 기관으로, 노인의 권리 보호 전담 기관은 아닙니다."}'::jsonb, '[{"term_ko": "인권", "term_vi": "Quyền con người", "def_ko": "권리를 보호받는 것(한국어)", "def_vi": "nhận được sự bảo vệ quyền lợi"}, {"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "부당한 대우(한국어)", "def_vi": "đối xử không công bằng"}, {"term_ko": "상담", "term_vi": "Tư vấn", "def_ko": "조언과 도움을 주는 것(한국어)", "def_vi": "cung cấp lời khuyên và sự giúp đỡ"}, {"term_ko": "전문기관", "term_vi": "Cơ quan chuyên môn", "def_ko": "특정 분야에 특화된 기관(한국어)", "def_vi": "cơ quan chuyên về một lĩnh vực cụ thể"}, {"term_ko": "예방", "term_vi": "Ngăn ngừa", "def_ko": "미리 막는 것(한국어)", "def_vi": "ngăn chặn trước"}, {"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람(한국어)", "def_vi": "người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (256, '2', '학대피해노인 보호와 숙식 제공 등의 쉼터 생활지원, 의료비 등을 지원해주는 사업으로 옳은 것은?', '["학대피해노인 전용쉼터", "정신요양시설", "정신건강 복지센터", "주간보호센터", "노인학대 신고센터"]'::jsonb, 1, '학대 피해 노인에 대한 보호 및 지원에 관한 내용을 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "학대 피해 노인을 보호하고 숙식 및 의료비를 제공하는 전용 쉼터입니다.\n[정답]", "2": "정신질환자를 위한 시설로, 노인학대와는 관련이 없습니다.", "3": "정신건강 관련 시설로, 학대피해 노인 지원과는 거리가 있습니다.", "4": "주간에 노인을 보호하고 돌보는 시설로, 학대 피해 노인을 위한 전용 쉼터는 아닙니다.", "5": "노인학대를 신고하는 곳으로 직접적인 보호 서비스는 제공하지 않습니다."}'::jsonb, '[{"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "폭력이나 고통을 주는 행위", "def_vi": "Hành động gây thương tích hoặc đau đớn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (255, '2', '노인장기요양보험제도의 목적으로 옳은 것은?', '["직업능력개발을 통한 고용 촉진", "최저생활 보장을 통한 자활의욕 고취", "안정적 노후를 위한 소득보장체계 마련", "업무상 재해 보상을 통한 사회복귀 지원", "일상생활을 혼자 수행하기 어려운 노인의 신체활동 또는 가사활동 지원"]'::jsonb, 5, '노인장기요양보험제도의 목적을 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "직업능력개발을 통한 고용 촉진은 해당 제도의 목적에 포함되지 않습니다.", "2": "최저생활 보장을 통한 자활의욕 고취는 주로 사회복지 정책의 목표입니다.\n[정답]", "3": "안정적 노후를 위한 소득보장체계 마련은 노인장기요양보험의 주요 목적은 아니지만 연결될 수 있습니다.", "4": "업무상 재해 보상을 통한 사회복귀 지원은 근로자의 안전과 관련된 제도입니다.", "5": "일상생활을 혼자 수행하기 어려운 노인의 신체활동 또는 가사활동 지원은 노인장기요양보험의 핵심 목적입니다."}'::jsonb, '[{"term_ko": "노인장기요양보험제도", "term_vi": "Hệ thống bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "신체활동", "term_vi": "Hoạt động thể chất", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "가사활동", "term_vi": "Hoạt động sinh hoạt", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "자활의욕", "term_vi": "Mong muốn tự lập", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (254, '2', '노인장기요양보험제도에 관한 설명으로 옳은 것은?', '["고용노동부장관이 관장한다.", "보험자는 국민건강보험공단이다.", "단기보호는 시설급여에 해당한다.", "장기요양등급은 1등급에서 10등급까지이다.", "대상자 가족의 일상생활 지원을 목적으로 한다."]'::jsonb, 2, '노인장기요양보험제도의 주요 내용을 이해하고 있는지를 평가하고자 하는 문제입니다.', NULL, '{"1": "고용노동부가 아니라 보건복지부가 관장합니다.\n[정답]", "2": "보험자는 국민건강보험공단으로 맞습니다.", "3": "단기보호는 시설급여가 아닌 재가급여입니다.", "4": "장기요양등급은 1등급에서 5등급까지 있습니다.", "5": "대상자 가족의 지원은 목적 중 하나지만 주된 목적은 대상자의 일상생활 지원입니다."}'::jsonb, '[{"term_ko": "노인장기요양보험제도", "term_vi": "Chế độ bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인들을 위한 장기 요양 보험 제도", "def_vi": "Chế độ bảo hiểm cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (253, '2', '노인장기요양서비스 전달체계에서 국민건강보험공단의 역할로 옳은 것은?', '["요양서비스 제공", "장기요양 등급판정", "서비스신청 및 계약", "서비스비용 청구", "장기요양기관의 설립인가"]'::jsonb, 2, '노인장기요양서비스의 전달체계에서 각 기관의 역할을 이해하는 것이 중요함을 강조하는 문제입니다.', NULL, NULL, '[{"term_ko": "노인장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기적인 요양 서비스", "def_vi": "Dịch vụ chăm sóc lâu dài cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (252, '2', '다음 중 노인장기요양급여의 대상자로 옳은 것은?', '["뇌경색으로 병원에 입원한 65세 남성", "결핵으로 일상생활이 어려운 50세 여성", "혈관성 치매로 일상생활이 어려운 70세 남성", "고혈압이 있고 일상생활이 가능한 65세 여성", "뇌졸증에서 회복되어 일상생활이 가능한 70세 남성"]'::jsonb, 3, '노인장기요양급여의 대상자를 파악하는 능력을 평가하기 위한 문제입니다.', NULL, '{"1": "뇌경색으로 입원했으나, 노인장기요양급여 대상자가 되기 어렵습니다.\n[정답]", "3": "혈관성 치매로 인해 일상생활이 어려워져 노인장기요양급여의 대상자가 됩니다.", "2": "결핵으로 일상생활이 어려운 경우는 노인장기요양급여의 대상이 아닙니다.", "4": "고혈압 상태지만 일상생활이 가능한 경우는 대상자가 아닙니다.", "5": "뇌졸증에서 회복하여 일상생활을 할 수 있는 경우에는 요양 급여의 대상자가 아닙니다."}'::jsonb, '[{"term_ko": "노인장기요양급여", "term_vi": "Chăm sóc sức khỏe dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기요양 서비스", "def_vi": "Dịch vụ chăm sóc dài hạn cho người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (251, '2', '노인장기요양인정 절차에 관한 설명으로 옳은 것은?', '["지방자치단체에 장기요양인정을 신청한다.", "신청자가 동의하면 사회복지전담공무원이 대신 신청할 수 있다.", "장기요양인정 방문조사는 등급판정위원회에서 실시한다.", "국민건강보험공단의 방문조사원이 장기요양등급을 2차로 판정한다.", "보건복지부는 1차 장기요양등급 판정 결과를 심의하여 최종 판정한다."]'::jsonb, 2, '노인장기요양인정 절차에 대한 이해도를 평가하고자 하였다.', NULL, '{"1": "지방자치단체에 장기요양인정을 신청하는 것이 맞지만, 이 보기는 지방자치단체를 직접 신청하는 과정이 아닌 ''대신'' 신청하는 부분에 초점을 맞추고 있다.\n[정답]", "2": "신청자가 동의하면 사회복지전담공무원이 대신 신청할 수 있다. 이는 관련 절차에서 정확한 설명이다.", "3": "장기요양인정 방문조사는 국민건강보험공단의 방문조사원이 진행한다.", "4": "2차 판단도 국민건강보험공단에서 실시하는 것으로, 등급판정위원회와는 다르다.", "5": "보건복지부는 장기요양등급 판정 결과를 심의하지만, 최종 판정은 국민건강보험공단에서 이루어진다."}'::jsonb, '[{"term_ko": "노인장기요양인정", "term_vi": "Công nhận chăm sóc dài hạn cho người cao tuổi", "def_ko": "고령자를 위한 장기적인 요양 서비스 인정", "def_vi": "Nhận dạng dịch vụ chăm sóc dài hạn cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (250, '2', '노인장기 요양보험 등급 인정에 관한 설명으로 옳은 것은?', '["장기요양인정은 지방자치단체에 신청한다.", "장기요양인정 점수에 따라 9등급으로 나뉜다.", "보건복지부는 1차 장기요양등급판정을 심의하여 최종 판정한다.", "노인성 질병 대상자는 의사소견서 없이 장기요양 등급을 판정받는다.", "국민건강보험공단은 장기요양인정표에 따라 작성된 조사결과서를 등급판정위원회에 제출한다."]'::jsonb, 5, '노인장기 요양보험의 등급 인정 절차와 관련된 내용을 이해하고 있는가를 평가하기 위함입니다.', NULL, '{"1": "장기요양인정은 지방자치단체에 신청한다. (내용이 일부 정확하나, 실제로는 국민건강보험공단을 통한 신청이 바람직함)\n[정답]", "5": "국민건강보험공단은 장기요양인정표에 따라 작성된 조사결과서를 등급판정위원회에 제출한다. (정확한 설명)", "2": "장기요양인정 점수에 따라 9등급으로 나뉜다. (정확한 내용이지만, 현재는 5개 등급으로 나눠짐)", "3": "보건복지부는 1차 장기요양등급판정을 심의하여 최종 판정한다. (정확하지 않음. 최종 판정은 중앙장기요양위원회가 담당)", "4": "노인성 질병 대상자는 의사소견서 없이 장기요양 등급을 판정받는다. (정확하지 않음. 의사소견서 필요)"}'::jsonb, '[{"term_ko": "노인장기 요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인의 요양 서비스를 제공하기 위한 보험 제도", "def_vi": "Hệ thống bảo hiểm cung cấp dịch vụ chăm sóc cho người cao tuổi"}, {"term_ko": "등급", "term_vi": "Cấp độ", "def_ko": "수준", "def_vi": "Mức độ"}, {"term_ko": "장기요양인정", "term_vi": "Công nhận chăm sóc dài hạn", "def_ko": "장기요양 서비스의 필요성을 공식적으로 인정받는 절차", "def_vi": "Quy trình công nhận sự cần thiết của dịch vụ chăm sóc dài hạn"}, {"term_ko": "조사결과서", "term_vi": "Bảng kết quả khảo sát", "def_ko": "조사 후 작성되는 결과 문서", "def_vi": "Tài liệu kết quả được biên soạn sau khi khảo sát"}, {"term_ko": "의사소견서", "term_vi": "Giấy xác nhận của bác sĩ", "def_ko": "의사가 작성한 환자의 건강 상태에 대한 의견서", "def_vi": "Tài liệu ý kiến về tình trạng sức khỏe của bệnh nhân do bác sĩ viết"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (249, '2', '장기요양인정 신청 및 판정 절차에 관한 설명으로 옳은 것은?', '["장기요양인정 신청서는 국민건강보험공단에 제출한다.", "대리인이 신청할 경우 시설장의 동의가 필요하다.", "교육을 이수한 장기요양기관의 직원이 방문조사를 한다.", "지방자치단체장이 장기요양인정 등급을 최종 판정한다.", "요양보호사가 대상자에게 장기요양인정서를 제공한다."]'::jsonb, 1, '장기요양인정 신청 및 판정 절차에 대한 이해를 평가하기 위해 출제되었다.', NULL, '{"1": "장기요양인정 신청서는 국민건강보험공단에 제출해야 한다. 이는 정확한 정보이다.\n[정답]", "2": "대리인이 신청할 경우, 시설장의 동의가 필요한 것은 아니다. 대리 신청이 가능하지만 동의는 필요하지 않다.", "3": "교육을 이수한 장기요양기관의 직원이 방문조사를 할 수 있으나, 반드시 그러해야하는 것은 아니다.", "4": "지방자치단체장이 장기요양인정 등급을 판정하는 것이 아니라, 국민건강보험공단이 최종 판정한다.", "5": "요양보호사는 장기요양인정서를 제공하지 않으며, 이는 주로 해당 기관이 담당한다."}'::jsonb, '[{"term_ko": "장기요양인정", "term_vi": "Công nhận chăm sóc dài hạn", "def_ko": "장기 요양이 필요한 사람들에 대한 공식적인 인정", "def_vi": "Công nhận chính thức cho những người cần chăm sóc dài hạn"}, {"term_ko": "국민건강보험공단", "term_vi": "Quỹ Bảo hiểm Y tế Quốc dân", "def_ko": "국민의 건강보험을 관리하는 기관", "def_vi": "Cơ quan quản lý bảo hiểm y tế của công dân"}, {"term_ko": "대리인", "term_vi": "Người đại diện", "def_ko": "대신하여 행동하는 사람", "def_vi": "Người hành động thay cho người khác"}, {"term_ko": "지방자치단체장", "term_vi": "Người đứng đầu chính quyền địa phương", "def_ko": "지역 정부의 책임자", "def_vi": "Người đứng đầu chính quyền tại địa phương"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "요양을 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (248, '2', '다음에서 설명하는 장기요양급여로 옳은 것은?• 하루 중 일정 시간 동안 대상자를 보호하면서 신체활동을 지원하고 심신기능 향상을 위한 교육 · 훈련을 제공함', '["방문요양", "방문목욕", "방문간호", "주 · 야간 보호", "노인요양시설"]'::jsonb, 4, '이 문제는 장기요양급여의 종류를 이해하고 올바르게 구분하는 데 목적이 있다.', NULL, '{"1": "방문요양: 개인의 가정에서 필요한 신체적 도움을 제공하는 서비스이다.", "2": "방문목욕: 가정에서의 목욕 지원 서비스를 뜻한다.", "3": "방문간호: 간호사가 가정에서 환자에게 필요한 간호를 제공하는 서비스이다.\n[정답]", "4": "주 · 야간 보호: 장기요양급여 중 하루 중 일정 시간 동안 대상자를 보호하며, 신체 활동 지원과 교육 훈련을 포함함.", "5": "노인요양시설: 노인을 위한 시설로 24시간 돌봄 서비스를 제공하는 곳이다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Trợ cấp chăm sóc dài hạn", "def_ko": "장기간 동안 제공되는 요양 서비스(한국어)", "def_vi": "Dịch vụ chăm sóc được cung cấp trong thời gian dài(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (247, '2', '수급자를 일정한 기간 동안 장기요양기관에 보호하여 신체활동지원 등을 제공하는 장기요양급여로 옳은 것은?', '["단기보호 서비스", "주 · 야간보호 서비스", "방문목욕 서비스", "방문간호 서비스", "방문요양 서비스"]'::jsonb, 1, '장기요양급여의 종류와 정의를 이해하고 올바르게 구분할 수 있는지 평가하는 문제입니다.', NULL, '{"1": "단기보호 서비스는 정기적으로 일정 기간 동안 제공되는 요양 서비스입니다.\n[정답]", "2": "주 · 야간보호 서비스는 낮과 밤에 각각 보호를 제공하는 서비스로, 장기 요양 기관에서 제공될 수 있습니다.", "3": "방문목욕 서비스는 가정에서 목욕을 지원하는 서비스입니다.", "4": "방문간호 서비스는 정기적인 간호 지원을 제공하는 서비스입니다.", "5": "방문요양 서비스는 가정에서 요양 보호 서비스를 제공하는 형태입니다."}'::jsonb, '[{"term_ko": "수급자", "term_vi": "Người thụ hưởng", "def_ko": "수혜자(한국어)", "def_vi": "Người nhận dịch vụ chăm sóc"}, {"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기요양 서비스 제공소(한국어)", "def_vi": "Nơi cung cấp dịch vụ chăm sóc dài hạn"}, {"term_ko": "신체활동", "term_vi": "Hoạt động thể chất", "def_ko": "신체의 동작 및 행동(한국어)", "def_vi": "Hành động và cử động của cơ thể"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "서비스(한국어)", "def_vi": "Dịch vụ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (246, '2', '재가대상자의 일상생활에 필요한 복지용구를 제공하는 급여로 옳은 것은?', '["기타재가급여", "주간보호급여", "방문요양급여", "방문목욕급여", "단기보호급여"]'::jsonb, 1, '재가대상자의 일상생활에 필요한 복지용구의 제공과 관련된 급여 유형을 이해하고 구분할 수 있도록 하는 것이 문제의 주요 의도입니다.', NULL, '{"1": "기타재가급여는 일상생활에 필요한 복지용구를 포함하여 다양한 급여를 지원하는 항목입니다.\n[정답]", "2": "주간보호급여는 낮 시간 동안의 보호와 서비스를 제공하는 급여입니다.", "3": "방문요양급여는 요양보호사가 가정에 방문하여 필요한 요양 서비스를 제공하는 급여입니다.", "4": "방문목욕급여는 요양보호사가 가정에서 목욕 서비스를 제공하는 급여입니다.", "5": "단기보호급여는 일시적으로 시설에서 보호를 받는 급여입니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người được chăm sóc tại nhà", "def_ko": "가정에서 요양이 필요한 대상자", "def_vi": "Người cần được chăm sóc tại nhà"}, {"term_ko": "복지용구", "term_vi": "Thiết bị hỗ trợ", "def_ko": "일상생활에 필요한 보조 도구", "def_vi": "Công cụ hỗ trợ cần thiết cho cuộc sống hàng ngày"}, {"term_ko": "급여", "term_vi": "Trợ cấp", "def_ko": "지원되는 서비스", "def_vi": "Dịch vụ được hỗ trợ"}, {"term_ko": "주간보호", "term_vi": "Dịch vụ bảo trợ vào ban ngày", "def_ko": "낮 시간 동안 보호하는 서비스", "def_vi": "Dịch vụ bảo vệ trong thời gian ban ngày"}, {"term_ko": "방문요양", "term_vi": "Chăm sóc tại nhà", "def_ko": "가정에서의 요양 서비스", "def_vi": "Dịch vụ chăm sóc tại nhà"}, {"term_ko": "방문목욕", "term_vi": "Tắm tại nhà", "def_ko": "가정에서의 목욕 서비스", "def_vi": "Dịch vụ tắm tại nhà"}, {"term_ko": "단기보호", "term_vi": "Bảo vệ ngắn hạn", "def_ko": "일시적인 보호 서비스", "def_vi": "Dịch vụ bảo vệ tạm thời"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (245, '2', '장기요양급여 중 재가급여의 장점으로 옳은 것은?', '["가족이 선호하는 서비스가 제공된다.", "응급상황에서 신속하게 대응할 수 있다.", "평소 친숙한 환경에서 서비스가 제공된다.", "종합적인 재활치료 서비스가 제공될 수 있다.", "건강검진을 통해 질병을 조기에 발견할 수 있다."]'::jsonb, 3, '재가급여의 장점을 이해하고 선택할 수 있는 능력을 평가하기 위한 문제입니다.', NULL, '{"1": "가족이 선호하는 서비스가 제공되지만, 특정 가족의 선호는 상황에 따라 다를 수 있습니다.\n[정답]", "3": "평소 친숙한 환경에서 서비스가 제공되어 환자가 안정감을 느낄 수 있습니다.", "2": "응급상황에서 신속한 대응은 재가급여의 장점이 아닙니다.", "4": "종합적인 재활치료 서비스는 주로 요양시설에서 제공되며, 재가급여는 한정적입니다.", "5": "건강검진은 별도의 프로그램에 의해 이루어지며 재가급여와는 직결되지 않습니다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기 요양이 필요한 환자를 위해 제공되는 급여", "def_vi": "Các phúc lợi được cung cấp cho bệnh nhân cần chăm sóc dài hạn."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (244, '2', '장기요양급여 중 시설급여에 해당하는 것으로 옳은 것은?', '["단기보호", "복지용구", "가족요양비", "주 · 야간 보호", "노인요양공동생활가정"]'::jsonb, 5, '장기요양급여의 종류와 해당되는 내용을 상대적으로 이해하고 판단하는 것이 목적이다.', NULL, '{"1": "단기보호는 시설급여에 포함되지 않는다.\n[정답]", "5": "노인요양공동생활가정은 시설급여에 해당한다.", "2": "복지용구는 장비를 제공하는 서비스로 시설급여가 아니다.", "3": "가족요양비는 가족이 요양을 제공하는 경우에 대한 지원으로 시설급여가 아니다.", "4": "주 · 야간 보호는 시설급여보다는 서비스의 일종이다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Trợ cấp chăm sóc dài hạn", "def_ko": "장기적인 요양을 제공하는 지원금", "def_vi": "Tiền hỗ trợ chăm sóc lâu dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (243, '2', '장기요양급여 시설급여의 장점으로 옳은 것은?', '["사생활이 보장된다.", "친숙한 환경에서 지낼 수 있다.", "개인 중심의 생활을 보장받을 수 있다.", "종합적인 서비스를 받을 수 있다.", "본인일부부담금이 재가 급여 보다 저렴하다."]'::jsonb, 4, '장기요양급여의 장점에 대한 이해를 평가하고자 하는 문제입니다.', NULL, '{"1": "사생활이 보장되지 않을 수 있습니다. 의료인력과 다른 입소자들과의 관계에서 개인의 사생활이 제한될 수 있습니다.", "2": "친숙한 환경에서 지내기 어려울 수 있으며, 병원처럼 낯선 환경일 수 있습니다.\n[정답]", "3": "개인 중심의 생활을 보장할 수 있으나, 실제로는 제약이 있을 수 있습니다.", "4": "종합적인 서비스를 받을 수 있어 다양한 필요에 맞춘 통합적인 관리가 가능합니다.", "5": "본인일부부담금은 경우에 따라 다를 수 있으며, 재가 급여보다 저렴한 경우가 많지만 항상 그렇지 않습니다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기간 동안 제공되는 의료 및 요양 서비스", "def_vi": "Dịch vụ y tế và chăm sóc được cung cấp trong thời gian dài"}, {"term_ko": "주거시설", "term_vi": "Cơ sở lưu trú", "def_ko": "주거용 건물 또는 시설", "def_vi": "Tòa nhà hoặc cơ sở sinh hoạt"}, {"term_ko": "사생활", "term_vi": "Quyền riêng tư", "def_ko": "개인의 개인적인 일상이나 공간", "def_vi": "Cuộc sống cá nhân hoặc không gian cá nhân"}, {"term_ko": "복지", "term_vi": "Phúc lợi", "def_ko": "사회가 국민에게 제공하는 지원 또는 서비스", "def_vi": "Các hỗ trợ hoặc dịch vụ mà xã hội cung cấp cho công dân"}, {"term_ko": "비용", "term_vi": "Chi phí", "def_ko": "재화나 서비스에 대한 금전적 지불", "def_vi": "Sự trả tiền cho hàng hóa hoặc dịch vụ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (242, '2', '가족요양비가 포함된 장기요양급여의 종류로 옳은 것은?', '["시설급여", "재가급여", "간병급여", "장애급여", "특별현금급여"]'::jsonb, 5, '가족요양비와 관련된 장기요양급여의 종류를 이해하고 있는지 평가하기 위한 문제입니다.', NULL, '{"1": "시설급여는 주로 시설에서 제공되는 요양 서비스를 말합니다.", "2": "재가급여는 가정에서 제공되는 요양 서비스를 포함합니다.", "3": "간병급여는 환자가 일상생활을 영위할 수 있도록 돕는 서비스입니다.", "4": "장애급여는 장애인을 위한 지원을 포함하고 있습니다.\n[정답]", "5": "특별현금급여는 가족요양비가 포함된 장기요양급여의 일종입니다."}'::jsonb, '[{"term_ko": "가족요양비", "term_vi": "Phí chăm sóc gia đình", "def_ko": "가족이 제공하는 요양에 대한 비용", "def_vi": "Chi phí cho việc chăm sóc của gia đình"}, {"term_ko": "장기요양급여", "term_vi": "Trợ cấp chăm sóc dài hạn", "def_ko": "장기간에 걸쳐 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc kéo dài"}, {"term_ko": "시설급여", "term_vi": "Trợ cấp cơ sở", "def_ko": "시설에서 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc tại cơ sở"}, {"term_ko": "재가급여", "term_vi": "Trợ cấp tại nhà", "def_ko": "가정에서 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc tại nhà"}, {"term_ko": "간병급여", "term_vi": "Trợ cấp chăm sóc", "def_ko": "환자의 일상생활 지원 서비스", "def_vi": "Dịch vụ hỗ trợ sinh hoạt hàng ngày của bệnh nhân"}, {"term_ko": "장애급여", "term_vi": "Trợ cấp cho người khuyết tật", "def_ko": "장애인을 위한 지원", "def_vi": "Hỗ trợ cho người khuyết tật"}, {"term_ko": "특별현금급여", "term_vi": "Trợ cấp tiền mặt đặc biệt", "def_ko": "가족요양비 포함 장기요양급여의 일종", "def_vi": "Một loại trợ cấp dài hạn bao gồm phí chăm sóc gia đình"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (241, '2', '장기요양기관의 비용 청구 및 재원에 관한 설명으로 옳은 것은?', '["국가는 보험료 예상 수입액의 20%를 부담한다.", "장기요양기관은 본인부담금을 보건복지부에 청구한다.", "장기요양보험료와 건강보험료는 통합회계로 관리한다.", "장기요양기관은 의료급여수습권자의 급여비용을 전액 부담한다.", "국민건강보험공단은 급여비용을 연 1회 장기요양기관에 지급한다."]'::jsonb, 1, '장기요양기관의 비용 청구 및 재원에 대한 이해를 측정하기 위한 문제입니다.', NULL, '{"1": "국가는 보험료 예상 수입액의 20%를 부담한다.\n[정답]", "2": "장기요양기관은 본인부담금을 보건복지부에 청구한다.", "3": "장기요양보험료와 건강보험료는 통합회계로 관리한다.", "4": "장기요양기관은 의료급여수습권자의 급여비용을 전액 부담한다.", "5": "국민건강보험공단은 급여비용을 연 1회 장기요양기관에 지급한다."}'::jsonb, '[{"term_ko": "장기요양기관", "term_vi": "Cơ sở điều dưỡng dài hạn", "def_ko": "장기적으로 요양 서비스를 제공하는 기관", "def_vi": "Cơ sở cung cấp dịch vụ chăm sóc lâu dài"}, {"term_ko": "비용", "term_vi": "Chi phí", "def_ko": "금액을 지불해야 하는 금액", "def_vi": "Số tiền phải trả"}, {"term_ko": "청구", "term_vi": "Yêu cầu", "def_ko": "청구서 또는 요구하는 것", "def_vi": "Đòi hỏi hoặc yêu cầu"}, {"term_ko": "본인부담금", "term_vi": "Khoản tự chi trả", "def_ko": "개인이 부담해야 할 금액", "def_vi": "Số tiền tự chi trả bởi cá nhân"}, {"term_ko": "급여비용", "term_vi": "Chi phí trợ cấp", "def_ko": "급여를 위한 비용", "def_vi": "Chi phí cho các khoản trợ cấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (240, '2', '노인장기요양보호험 급여 중 본인 부담금에 관한 설명으로 옳은 것은?', '["비급여 항목은 본인이 60% 부담한다.", "복지용구 비용은 본인이 8% 부담한다.", "재가급여 비용은 본인이 20% 부담한다.", "국민기초생활수습권자는 본인 부담금이 없다.", "의사소견서 발급 비용은 본인이 15% 부담한다."]'::jsonb, 4, '노인장기요양보험 급여와 본인 부담금에 대한 올바른 이해를 요구하는 문제입니다.', NULL, '{"1": "비급여 항목은 본인이 60% 부담하는 것이 아니라 본인이 전액 부담합니다.\n[정답]", "4": "국민기초생활수급자는 본인 부담금이 없으며, 이 점에서 올바른 설명입니다.", "2": "복지용구 비용은 본인이 8% 부담하는 것이 아니라 대부분 무료 지원을 받습니다.", "3": "재가급여 비용은 본인이 20% 부담하는 것이 맞지만, 번호 4가 정답입니다.", "5": "의사소견서 발급 비용은 본인이 15% 부담하는 것이 아니라 본인이 부담하지 않습니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인을 위한 장기요양 보호 서비스 보험", "def_vi": "Dịch vụ bảo hiểm cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (239, '2', '장기요양서비스 이용절차 중 ☐ 안에 들어갈 내용으로 옳은 것은?『서비스 신청 접수 및 방문 상담』 → 『서비스 제공 계획 수립』 → 『서비스 이용 계약 체결』 → 『 ☐ 』 → 『모니터링 실시 / 서비스 종료 혹은 계속』', '["서비스 방법 개발", "서비스 기관 안내", "서비스 제공", "서비스 개입 계획 설정", "공식, 비공식 자원 발급"]'::jsonb, 3, '장기요양서비스의 이용 절차를 이해하고 올바른 단계를 파악하는 것이 중요하다.', NULL, '{"1": "서비스 방법 개발: 이는 초기 계획 단계이므로 올바르지 않은 선택이다.", "2": "서비스 기관 안내: 서비스 제공 이전 과정에서 필요한 정보지만, 정확한 단계에 해당하지 않다.\n[정답]", "3": "서비스 제공: 서비스 계약 체결 후 실제로 서비스를 제공하는 단계로, 맞는 선택이다.", "4": "서비스 개입 계획 설정: 서비스 개입과 관련된 단계이나, 계약 후 단계에는 해당되지 않는다.", "5": "공식, 비공식 자원 발급: 자원 할당과 관련 있지만, 해당 절차에서의 올바른 단계가 아니다."}'::jsonb, '[{"term_ko": "장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "길게 지속되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc kéo dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (238, '2', '등급판정 이후 장기요양 서비스를 받고자 할 때 기관에 제출해야 하는 서류로 옳은 것은?', '["의사소견서", "급여제공계획서", "장기요양급여제공기록지", "장기요양인정서", "상태기록지"]'::jsonb, 4, '장기요양 서비스를 받기 위해 필요한 서류에 대한 이해를 확인하고자 하는 문제입니다.', NULL, '{"1": "의사소견서는 장기요양 서비스 이용 시 필요하지만, 제출해야 하는 서류는 아닙니다.\n[정답]", "4": "장기요양인정서는 장기요양 서비스를 받기 위해 반드시 제출해야 하는 서류입니다.", "2": "급여제공계획서는 서비스 제공에 필요한 문서이나, 단계적 제출이기 때문에 보통 후에 제출합니다.", "3": "장기요양급여제공기록지는 서비스 이용 후 기록하는 문서로, 초기 제출 서류가 아닙니다.", "5": "상태기록지는 환자의 상태를 기록하는 문서로, 서비스 신청 시 제출해야 하는 서류는 아닙니다."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기간에 걸쳐 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc kéo dài trong thời gian dài"}, {"term_ko": "서류", "term_vi": "Tài liệu", "def_ko": "문서", "def_vi": "Giấy tờ"}, {"term_ko": "제출", "term_vi": "Nộp", "def_ko": "제출하다", "def_vi": "Nộp"}, {"term_ko": "인정서", "term_vi": "Giấy chứng nhận", "def_ko": "증명이 되는 서류", "def_vi": "Tài liệu chứng nhận"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (237, '2', '등급판정을 받은 대상자에게 발급하는 장기요양 인정서에 기재되는 항목으로 옳은 것은?', '["월 한도액", "이용할 수 있는 급여의 종류와 내용", "본인부담 금액", "수급자희망급여", "서비스 목표"]'::jsonb, 2, '장기요양 인정서의 주요 항목을 이해하고 구별할 수 있는지를 평가함.', NULL, '{"1": "월 한도액: 장기요양급여의 월 한도액은 기재되지 않음.\n[정답]", "2": "이용할 수 있는 급여의 종류와 내용: 장기요양 인정서에 명시되는 항목이며, 수급자가 받을 수 있는 급여의 종류와 내용을 구체적으로 설명함.", "3": "본인부담 금액: 장기요양 인정서에 포함되지 않음.", "4": "수급자희망급여: 수급자가 희망하는 급여는 별도로 기재되므로 포함되지 않음.", "5": "서비스 목표: 장기요양 인정서에는 명시되지 않음."}'::jsonb, '[{"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기적인 요양 및 돌봄 서비스", "def_vi": "Dịch vụ chăm sóc và hỗ trợ kéo dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (236, '2', '장기요양서비스를 이용하고자 할 때 다음의 내용의 서식 유형으로 옳은 것은?• 대상자의 등급에 따른 이용 한도액과 본인 부담률, 급여의 종류와 횟수, 비용, 인정유효기간', '["장기요양 인정서", "개인별 장기요양 이용계획서", "상태기록지", "장기요양급여제공 기록지", "급여제공 계획서"]'::jsonb, 2, '장기요양서비스의 서식 유형에 대해 이해하고 있는지 묻는 문제입니다.', NULL, '{"1": "장기요양 인정서는 서비스를 이용하기 위한 기준을 정하는 서식입니다.\n[정답]", "2": "개인별 장기요양 이용계획서는 대상자의 맞춤형 이용 계획을 기록하는 서식으로, 등급에 따른 한도액 및 본인 부담률과 급여의 종류, 횟수, 비용, 인정유효기간 등을 포함합니다.", "3": "상태기록지는 환자의 상태를 기록하는 서식입니다.", "4": "장기요양급여제공 기록지는 서비스 제공 내역을 기록하는 서식입니다.", "5": "급여제공 계획서는 서비스 제공의 전반적인 계획을 서술한 문서입니다."}'::jsonb, '[{"term_ko": "장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기적으로 필요한 요양 서비스를 제공하는 시스템", "def_vi": "Hệ thống cung cấp dịch vụ chăm sóc cần thiết trong thời gian dài"}, {"term_ko": "서식", "term_vi": "Mẫu", "def_ko": "공식적인 문서 형태", "def_vi": "Dạng tài liệu chính thức"}, {"term_ko": "이용 계획서", "term_vi": "Kế hoạch sử dụng", "def_ko": "특정 목적을 위한 계획 문서", "def_vi": "Tài liệu kế hoạch cho mục đích cụ thể"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스나 혜택을 받는 사람", "def_vi": "Người nhận dịch vụ hoặc lợi ích"}, {"term_ko": "인정유효기간", "term_vi": "Thời gian hiệu lực công nhận", "def_ko": "서비스가 승인된 유효 기간", "def_vi": "Thời gian mà dịch vụ đã được phê duyệt"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (235, '2', '요양보호 업무의 목적으로 옳은 것은?', '["평생교육프로그램 개발 및 참여", "대상자의 신체기능 증진", "가족 중심의 서비스 제공", "대상자의 시설입소 홍보", "일자리 재창출을 위한 정보제공"]'::jsonb, 2, '요양보호 업무의 주요 목적을 이해하고 구별하는 것이다.', NULL, '{"1": "평생교육프로그램 개발 및 참여는 요양보호의 직접적인 목적이 아니다.\n[정답]", "2": "대상자의 신체기능 증진은 요양보호의 핵심 목적이다.", "3": "가족 중심의 서비스 제공도 중요한 요소지만 주된 목적은 아니다.", "4": "대상자의 시설입소 홍보는 부가적인 역할일 뿐이다.", "5": "일자리 재창출을 위한 정보제공도 업무의 직접적인 목적이 아니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "업무", "def_ko": "돌봄, chăm sóc", "def_vi": "일, công việc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (234, '2', '다음에 해당하는 노인장기요양보험 표준서비스 유형으로 옳은 것은?• 간식을 포함한 식사 돕기• 참대에서 휠체어로 옮겨 태우기', '["정서지원서비스", "신체활동지원서비스", "일상생활지원서비스", "개인활동지원서비스", "기능회복훈련서비스"]'::jsonb, 2, '노인장기요양보험의 서비스 유형에 대한 이해를 확인하기 위함입니다.', NULL, '{"1": "정서지원서비스: 정서적인 지지와 상담을 제공하는 서비스입니다.\n[정답]", "2": "신체활동지원서비스: 노인이 필요한 신체적인 활동을 도와주는 서비스로, 식사 돕기와 같은 신체적 지원이 포함됩니다.", "3": "일상생활지원서비스: 일상생활에서 필요한 기본적인 지원을 제공하는 서비스입니다.", "4": "개인활동지원서비스: 개인의 특성에 맞춰 지원하는 활동입니다.", "5": "기능회복훈련서비스: 기능 회복을 위한 훈련 프로그램을 제공하는 서비스입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (233, '2', '노인장기요양보험 표준서비스 중 가사 및 일상생활지원서비스에 해당되는 것으로 옳은 것은?', '["식사도움", "물품관리", "청소 및 정리정돈", "생활상담", "신체기능 유지"]'::jsonb, 3, '노인장기요양보험에서 제공하는 서비스 중에서 가사 및 일상생활 지원 서비스가 무엇인지 이해하도록 하는 문제입니다.', NULL, '{"1": "식사도움: 환자의 식사를 도와주는 서비스입니다.\n[정답]", "3": "청소 및 정리정돈: 가사 및 일상생활 지원에 해당되는 서비스입니다.", "2": "물품관리: 필요한 물품을 관리하는 서비스입니다.", "4": "생활상담: 생활에 대한 상담을 제공하는 서비스입니다.", "5": "신체기능 유지: 신체 기능을 유지하는 데 도움을 주는 서비스입니다."}'::jsonb, '[{"term_ko": "노인장기요양보험", "term_vi": "Bảo hiểm chăm sóc dài hạn cho người cao tuổi", "def_ko": "노인들을 위한 장기 요양 보험", "def_vi": "Bảo hiểm chi trả cho việc chăm sóc lâu dài"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (232, '2', '가사 및 일상생활지원 표준서비스 중 개인활동 지원 내용으로 옳은 것은?', '["화장실 이용 돕기", "외출 시 동행", "옷 갈아입히기", "식사 준비 및 정리", "청소 및 주변정돈"]'::jsonb, 2, '가사 및 일상생활지원 서비스의 유형을 이해하고, 개인활동 지원의 내용을 구별하는 것이다.', NULL, '{"1": "화장실 이용 돕기는 개인활동 지원의 일환이지만, 표준서비스 범위에는 포함되지 않는다.\n[정답]", "2": "외출 시 동행은 개인활동 지원에 해당하며, 표준서비스에 포함된다.", "3": "옷 갈아입히기는 개인활동 지원에 해당하지만, 이번 문제의 관점에서 벗어난다.", "4": "식사 준비 및 정리는 가사 지원 서비스에 해당한다.", "5": "청소 및 주변정돈은 일상생활 지원 서비스 중 가사 지원의 일부이다."}'::jsonb, '[{"term_ko": "가사", "term_vi": "Hỗ trợ sinh hoạt", "def_ko": "집안일(한국어)", "def_vi": "hỗ trợ sinh hoạt(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (231, '2', '정서지원 및 의사소통 도움 서비스 내용으로 옳은 것은?', '["입욕준비 및 목용을 도왔다.", "은행 외출 시 동행을 하였다.", "생활의 문제 상담을 하였다.", "욕창 예방을 위한 체위변경을 도왔다.", "장보기 및 식사준비를 도왔다."]'::jsonb, 3, '정서지원 및 의사소통에 필요한 서비스 내용을 파악하는 것이다.', NULL, '{"1": "입욕준비 및 목용을 도왔다. 이는 신체적 지원에 해당한다.\n[정답]", "3": "생활의 문제 상담을 하였다. 이는 정서적 지원 및 의사소통 도움에 해당한다.", "2": "은행 외출 시 동행을 하였다. 이는 이동 지원에 해당한다.", "4": "욕창 예방을 위한 체위변경을 도왔다. 이는 신체적 지원에 해당한다.", "5": "장보기 및 식사준비를 도왔다. 이는 생활 지원에 해당한다."}'::jsonb, '[{"term_ko": "정서지원", "term_vi": "Hỗ trợ cảm xúc", "def_ko": "감정적 지원( 한국어 )", "def_vi": "Hỗ trợ liên quan đến cảm xúc( 베트남어 )"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (230, '2', '치매 대상자가 같은 옷만 입으려고 할 때 대처 방법으로 옳은 것은?', '["거울을 보여 주며 더러워진 옷이라고 한다.", "옷을 갈아입어야 한다는 것을 설명한다.", "가족과 상의하여 동일한 유형의 옷을 추가로 구입한다.", "물을 엎질러 다른 옷을 입게 한다.", "좋아하는 음식을 주며 다른 옷을 입게 한다."]'::jsonb, 3, '치매 대상자에 대한 이해와 그들의 행동에 대한 대처 방법을 판단하기 위한 문제입니다.', NULL, '{"1": "거울을 보여 주며 더러워진 옷이라고 한다는 것은 대처 방법으로 적절하지 않습니다. 대상자가 혼란스러워할 수 있습니다.\n[정답]", "2": "옷을 갈아입어야 한다는 것을 설명하는 것은 인지 기능이 저하된 대상을 혼란스럽게 할 수 있으므로 효과적이지 않습니다.", "3": "가족과 상의하여 동일한 유형의 옷을 추가로 구입하는 것은 대상자의 정서적 안정에 도움이 되므로 적절한 대처 방법입니다.", "4": "물을 엎질러 다른 옷을 입게 하는 것은 의도적인 행동으로, 대상자에게 부정적인 경험을 줄 수 있습니다.", "5": "좋아하는 음식을 주며 다른 옷을 입게 하는 것은 이 방법이 아닌 다른 대처 방법일 수 있으므로 잘못된 접근입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력이나 판단력이 저하된 상태", "def_vi": "Trạng thái suy giảm trí nhớ hoặc phán đoán"}, {"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "돌봄이나 요양이 필요한 사람", "def_vi": "Người cần chăm sóc hoặc điều dưỡng"}, {"term_ko": "대처 방법", "term_vi": "Cách xử lý", "def_ko": "어떤 상황에서 대응하는 방법", "def_vi": "Phương pháp đối phó với tình huống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (229, '2', '대상자가 기저귀 안으로 자꾸 손을 넣을 때 요양보호사의 대처 방법으로 옳은 것은?', '["단호하게 하지 말라고 말한다.", "손을 억제대로 묶어 놓는다.", "음부에 습진이 있는지 확인한다.", "손톱을 짧게 깎아준다.", "음부를 청결히 한다."]'::jsonb, 3, '대상자가 기저귀 안으로 손을 넣는 행동의 원인을 파악하고 올바른 대처 방법을 찾는 것이다.', NULL, '{"1": "단호하게 하지 말라고 말하는 것은 문제가 지속될 수 있는 상황을 방치하는 것이다.\n[정답]", "3": "음부에 습진이 있는지 확인하는 것은 대상자의 피부 상태를 점검하기 위한 중요한 조치이다.", "2": "손을 억제대로 묶어 놓는 것은 대상자의 인권을 침해할 수 있는 부적절한 방법이다.", "4": "손톱을 짧게 깎아주는 것은 예방적인 조치지만, 현재 문제 해결과는 직접적인 관련이 없다.", "5": "음부를 청결히 하는 것은 중요하지만, 현재 손을 넣는 행동의 원인을 분석하는 것이 우선이다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "환자, 돌봄을 받는 사람", "def_vi": "Bệnh nhân, người được chăm sóc"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "아기나 성인 환자의 배변을 위한 용품", "def_vi": "Đồ dùng cho trẻ em hoặc bệnh nhân người lớn để đi vệ sinh"}, {"term_ko": "손을 넣다", "term_vi": "Đưa tay vào", "def_ko": "손을 특정한 장소에 넣는 행동", "def_vi": "Hành động đưa tay vào một vị trí cụ thể"}, {"term_ko": "습진", "term_vi": "Bệnh chàm", "def_ko": "피부 발진, 염증", "def_vi": "Nổi mẩn, viêm da"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (228, '2', '요양보호서비스 제공의 기본 원칙으로 옳은 것은?', '["요양보호사가 추가 서비스를 결정한다.", "대상자와의 심각한 갈등을 직접 해결한다.", "서비스 계획 시 대상자의 습관을 반영한다.", "대상자의 상태에 따라 처방약의 용량을 조절한다.", "대상자의 인지능력이 악화된 경우에는 서비스를 중단한다."]'::jsonb, 3, '요양보호서비스 제공에서의 기본 원칙을 이해하고 적용하는 능력을 평가하려는 의도를 가지고 있다.', NULL, '{"1": "요양보호사는 추가 서비스를 결정할 권한이 없다. 서비스 제공은 대상자의 요구에 기반하여 이루어져야 한다.\n[정답]", "3": "서비스 계획 시에는 항상 대상자의 습관과 선호를 반영해야 하며, 이는 개인 맞춤형 서비스를 제공하기 위해 중요하다.", "2": "대상자와의 심각한 갈등은 전문 상담을 통해 해결하는 것이 바람직하다.", "4": "처방약의 용량 조절은 의사의 권한이며, 요양보호사가 임의로 조절할 수 없다.", "5": "대상자의 인지능력이 악화되었다고 해서 즉시 서비스를 중단하는 것은 적절하지 않다. 상황에 따라 적절한 대처가 필요하다."}'::jsonb, '[{"term_ko": "요양보호서비스", "term_vi": "Dịch vụ chăm sóc", "def_ko": "돌봄 서비스를 제공하는 지원", "def_vi": "Dịch vụ hỗ trợ chăm sóc"}, {"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "갈등", "term_vi": "Xung đột", "def_ko": "의견이나 감정의 차이", "def_vi": "Sự khác biệt về quan điểm hoặc cảm xúc"}, {"term_ko": "습관", "term_vi": "Thói quen", "def_ko": "반복적으로 하는 행동", "def_vi": "Hành vi lặp lại"}, {"term_ko": "처방약", "term_vi": "Thuốc theo toa", "def_ko": "의사가 특정 환자에게 제공하는 약", "def_vi": "Thuốc được bác sĩ kê cho bệnh nhân"}, {"term_ko": "인지능력", "term_vi": "Năng lực nhận thức", "def_ko": "정보를 이해하고 처리하는 능력", "def_vi": "Khả năng hiểu và xử lý thông tin"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (227, '2', '요양보호서비스 제공 원칙으로 옳은 겻은?', '["대상자가 인지능력이 없는 경우 보호자의 동의를 받는다.", "서비스의 추가 및 변경 사항은 보호자와 의논한다.", "대상자가 관장을 원하면 시설장과 의논하여 제공한다.", "응급상황 발생 시 가족에게 우선 알린다.", "치매 대상자의 돌발상황 시 가족과 의논한다."]'::jsonb, 1, '요양보호서비스 제공에 있어서 어떤 원칙이 맞는지 판단하기 위한 문제입니다.', NULL, '{"1": "대상자가 인지능력이 없는 경우 보호자의 동의를 받는다.\n[정답]", "2": "서비스의 추가 및 변경 사항은 보호자와 의논한다.", "3": "대상자가 관장을 원하면 시설장과 의논하여 제공한다.", "4": "응급상황 발생 시 가족에게 우선 알린다.", "5": "치매 대상자의 돌발상황 시 가족과 의논한다."}'::jsonb, '[{"term_ko": "요양보호서비스", "term_vi": "원칙", "def_ko": "돌봄 서비스(서비스 chăm sóc)", "def_vi": "기본 법칙(nguyên tắc)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (226, '2', '방문요양 서비스 제공 시 요양보호사의 준수사항으로 옳은 것은?', '["서비스 제공 중 알게 된 비밀은 시설장에게 보고한다.", "제공되는 서비스에 대해 보호자에게 충분히 설명한다.", "대상자의 상태와 관계없이 서비스를 제공한다.", "체온, 맥박, 호흡, 혈압측정은 하지 않는다.", "대상자 부축 시 넘어져 부상을 입은 경우 시설장에게 즉시 보고한다."]'::jsonb, 5, '방문요양 서비스 제공 시 요양보호사가 지켜야 할 사항을 이해하고 있는지를 평가하기 위함이다.', NULL, '{"1": "서비스 제공 중 알게 된 비밀은 보호자에게 보고해야 하며, 시설장에게 직접 보고하는 것은 아닙니다.\n[정답]", "5": "대상자 부축 시 넘어져 부상을 입은 경우는 즉시 시설장에게 보고해야 합니다.", "3": "대상자의 상태에 따라 서비스 제공 여부가 달라져야 하므로, 관계없이 서비스를 제공하는 것은 틀립니다.", "4": "체온, 맥박, 호흡, 혈압 측정은 필수적인 건강 관리의 일환으로 수행해야 합니다.", "2": "제공되는 서비스에 대해 보호자에게 충분히 설명하는 것이 중요합니다."}'::jsonb, '[{"term_ko": "방문요양 서비스", "term_vi": "요양보호사", "def_ko": "방문 chăm sóc", "def_vi": "Người chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (225, '2', '요양보호서비스 제공원칙을 준수한 경우로 옳은 겻은?', '["대상자의 가래를 흡인한다.", "상황에 따라 서비스 비용을 청구한다.", "대상자의 선호보다 시설의 규칙을 우선시한다.", "응급 상황에서는 응급처치 우선순위에 따라 처치한다.", "대상자의 인지능력이 악화되면 서비스를 중단한다."]'::jsonb, 4, '요양보호서비스 제공원칙에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "가래 흡인은 특별한 상황에서만 필요한 조치이며, 일반적인 원칙에 어긋날 수 있습니다.\n[정답]", "2": "서비스 비용 청구는 상황에 따라 접근해야 하지만, 원칙적으로 대상자의 동의를 받아야 합니다.", "3": "시설의 규칙보다 대상자의 선호가 우선되어야 합니다.", "4": "응급 상황에서는 응급처치가 우선이므로, 옳은 선택입니다.", "5": "인지능력 저하 시 서비스 중단은 적절하지 않습니다."}'::jsonb, '[{"term_ko": "요양보호서비스", "term_vi": "Dịch vụ chăm sóc", "def_ko": "돌봄 서비스를 제공하는 것", "def_vi": "Cung cấp dịch vụ chăm sóc"}, {"term_ko": "제공원칙", "term_vi": "Nguyên tắc cung cấp", "def_ko": "서비스를 제공할 때 따르는 규칙", "def_vi": "Quy tắc khi cung cấp dịch vụ"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "가래", "term_vi": "Đờm", "def_ko": "폐에서 나오는 점액", "def_vi": "Chất nhầy từ phổi"}, {"term_ko": "응급 상황", "term_vi": "Tình huống khẩn cấp", "def_ko": "긴급 상황", "def_vi": "Tình huống cần giải quyết ngay"}, {"term_ko": "인지능력", "term_vi": "Khả năng nhận thức", "def_ko": "사고하거나 이해하는 능력", "def_vi": "Khả năng suy nghĩ hoặc hiểu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (224, '2', '다음의 사례 내용 중 요양보호사 금지 행위에 해당하는 것으로 옳은 것은?• 요양보호사에게 수급자의 본인부담금을 전가시키는 경우• 수급자에게 비급여 대상의 비용을 면제 · 할인하는 경우', '["노인학대 등의 금지 행위", "수급자 유인 알선 행위 금지", "본인부담금 면제 감경 금지", "부당수급 관련 행위 금지", "급여제공자료 거짓 작성 금지"]'::jsonb, 3, '요양보호사가 금지된 행위를 고르기 위한 문제입니다.', NULL, '{"1": "노인학대는 명백한 범죄행위로 요양보호사의 금지 행위에 해당합니다.", "2": "수급자 유인 알선 행위도 금지된 행위입니다.\n[정답]", "3": "본인부담금 면제 감경은 요양보호사가 하지 말아야 할 행위로 정확히 금지됩니다.", "4": "부당수급 관련 행위는 요양보호사의 활동과 관련하여 금지됩니다.", "5": "급여제공자료 거짓 작성도 요양보호사의 금지 행위입니다."}'::jsonb, '[{"term_ko": "금지", "term_vi": "Cấm", "def_ko": "금지하다(한국어)", "def_vi": "cấm(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (223, '2', '요양보호서비스에 대한 지식과 기술로 대상자의 불편함을 경감하는 요양보호사의 역할로 옳은 것은?', '["옹호자", "촉진자", "숙련된 수발자", "정보전달자", "동기유발자"]'::jsonb, 3, '요양보호사의 역할에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "옹호자는 환자의 권리를 지키고 보장하는 역할을 합니다.\n[정답]", "3": "숙련된 수발자는 대상자의 요구를 이해하고 적절한 도움을 제공하는 역할입니다.", "2": "촉진자는 사회적 상호작용을 촉진하는 역할을 합니다.", "4": "정보전달자는 필요한 정보를 전달하는 역할을 수행합니다.", "5": "동기유발자는 대상자를 격려하고 동기를 부여하는 역할입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌보는 사람", "def_vi": "Người chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (222, '2', '배우자의 사별로 우울증상을 겪는 대상자의 신체 · 심리적 정보를 가족과 의료진에게 알리는 요양보호사의 역할로 옳은 것은?', '["숙련된 수발자", "정보전달자", "관찰자", "말벗과 상담자", "동기유발자"]'::jsonb, 2, '요양보호사가 대상자의 신체 및 심리적 정보를 가족과 의료진에게 제대로 전달하는 것이 중요하다는 점을 강조하려는 의도입니다.', NULL, '{"1": "숙련된 수발자: 요양보호사는 숙련된 기술을 가지고 있지만, 정보 전달의 역할과는 직접적인 관련이 없습니다.\n[정답]", "2": "정보전달자: 요양보호사는 대상자의 상태를 가족과 의료진에게 효과적으로 전달해야 하는 역할을 가지고 있습니다.", "3": "관찰자: 관찰자는 상태 파악에 기여하지만, 정보 전달의 주된 역할은 아닙니다.", "4": "말벗과 상담자: 정서적 지원을 제공하는 역할이나 정보 전달과는 구분됩니다.", "5": "동기유발자: 동기를 유발하는 역할은 중요하지만, 정보 전달과는 직접적인 관련이 없습니다."}'::jsonb, '[{"term_ko": "사별", "term_vi": "Mất người thân", "def_ko": "사랑하는 사람을 잃는 것", "def_vi": "Mất đi người yêu thương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (221, '2', '요양보호서비스를 제공할 때 대상자의 상태 변화와 투약 여부를 파악하는 요양보호사의 역할로 옳은 것은?', '["옹호자", "관찰자", "중개자", "정보전달자", "동기유발자"]'::jsonb, 2, '대상자의 상태 변화와 투약 여부를 파악하는 요양보호사의 역할을 이해하고 확인하는 것.', NULL, '{"1": "옹호자는 환자의 권리를 보호하고 지지하는 역할을 한다.\n[정답]", "2": "관찰자는 대상자의 상태 변화를 주의 깊게 살펴보는 역할을 하며, 투약 여부를 파악하는 것이 중요한 임무이다.", "3": "중개자는 정보나 서비스를 이전하는 역할을 한다.", "4": "정보전달자는 다른 사람에게 정보를 전파하는 역할을 한다.", "5": "동기유발자는 환자의 동기를 유발하고 유도하는 역할을 한다."}'::jsonb, '[{"term_ko": "요양보호서비스", "term_vi": "Dịch vụ chăm sóc", "def_ko": "돌봄 서비스(한국어)", "def_vi": "Dịch vụ chăm sóc"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자를 의미(한국어)", "def_vi": "Có nghĩa là bệnh nhân"}, {"term_ko": "상태", "term_vi": "Trạng thái", "def_ko": "상태(한국어)", "def_vi": "Trạng thái"}, {"term_ko": "변화", "term_vi": "Biến đổi", "def_ko": "변화(한국어)", "def_vi": "Sự thay đổi"}, {"term_ko": "투약", "term_vi": "Dùng thuốc", "def_ko": "약물의 투여(한국어)", "def_vi": "Sự dùng thuốc"}, {"term_ko": "역할", "term_vi": "Vai trò", "def_ko": "역할(한국어)", "def_vi": "Vai trò"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (220, '2', '요양보호사가 동기 유발자로서 역할을 수행한 경우로 옳은 것은?', '["대상자의 투약여부를 면밀히 관찰한다.", "대상자의 심리적 문제를 가족에게 알린다.", "숙련된 기술로 질 높은 서비스를 제공한다.", "대상자 스스로 신체 활동을 하도록 격려한다.", "대상자의 말을 경청하며 신뢰관계를 형성한다."]'::jsonb, 4, '요양보호사가 대상자의 동기를 유발하는 역할을 수행하는 것을 이해하고, 이를 통해 적절한 선택지를 파악하는 것이다.', NULL, '{"1": "대상자의 투약여부를 면밀히 관찰하는 것은 동기 유발자 역할이 아니다.\n[정답]", "4": "대상자 스스로 신체 활동을 하도록 격려하는 것은 동기 유발자로서의 역할이다.", "3": "숙련된 기술로 질 높은 서비스를 제공하는 것은 중요하지만 동기 유발자 역할과는 관련이 없다.", "2": "대상자의 심리적 문제를 가족에게 알리는 것은 필요한 조치지만 동기 유발자 역할이라고 보기 어렵다.", "5": "대상자의 말을 경청하며 신뢰관계를 형성하는 것은 중요하지만 동기 유발과는 거리가 있다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보고 그들의 필요를 지원하는 전문가", "def_vi": "Chuyên gia chăm sóc và hỗ trợ nhu cầu của bệnh nhân"}, {"term_ko": "동기 유발자", "term_vi": "Người kích thích động lực", "def_ko": "대상자가 스스로 행동하도록 동기를 부여하는 역할", "def_vi": "Vai trò khuyến khích bệnh nhân tự thực hiện hành động"}, {"term_ko": "신체 활동", "term_vi": "Hoạt động thể chất", "def_ko": "움직임, 운동", "def_vi": "Sự di chuyển, tập thể dục"}, {"term_ko": "격려", "term_vi": "Khuyến khích", "def_ko": "자극, 응원", "def_vi": "Khích lệ, động viên"}, {"term_ko": "신뢰관계", "term_vi": "Mối quan hệ tin cậy", "def_ko": "서로 믿을 수 있는 관계", "def_vi": "Quan hệ giữa những người có thể tin tưởng lẫn nhau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (219, '2', '다음과 같은 상황에서 요양보호사가 수행하는 역할로 옳은 것은?• 대상자가 성희롱을 당했을 때 기관장에게 보고함 • 학대 의심 사례가 발생했을 때 경찰서에 신고함', '["촉진자", "옹호자", "교육자", "동기유발자", "숙련된 수발자"]'::jsonb, 2, '요양보호사가 대상자를 보호하고 지원하는 역할을 이해하도록 평가하기 위한 문제입니다.', NULL, '{"1": "촉진자는 단순히 어떤 행동을 유도하는 역할로, 요양보호사와는 관련이 적습니다.\n[정답]", "2": "옹호자는 대상자를 대변하고 보호하는 역할로, 문제 상황에서 적절한 조치를 취하는 요양보호사의 역할을 잘 나타냅니다.", "3": "교육자는 지식이나 기술을 가르치는 역할로, 본 문제와는 관련이 없습니다.", "4": "동기유발자는 개인의 행동을 자극하는 역할로, 이 문제의 상황과는 맞지 않습니다.", "5": "숙련된 수발자는 기초적인 돌봄 기술을 수행하는 역할이지만, 문제의 핵심인 보고 및 신고와는 다릅니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인이나 장애인을 돌보는 사람", "def_vi": "Người chăm sóc người già hoặc người khuyết tật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (218, '2', '요양보호사의 역할(A)과 관련된 내용(B)이 바르게 연결된 것으로 옳은 것은?', '["관찰자 필요한 서비스 연계 활동", "옹호자 차별받는 대상자 지지", "정보전달자 직접적인 서비스 제공", "동기 유발자 질병의 증상 확인", "숙련된 수발자 서비스 제공 게획 및 수립"]'::jsonb, 2, '요양보호사의 역할과 관련된 개념적 이해를 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "관찰자: 필요한 서비스 연계 활동은 요양보호사의 역할 중 하나이나 정확한 연결이 아님.\n[정답]", "2": "옹호자: 차별받는 대상자 지지는 요양보호사가 수행하는 핵심 역할 중 하나입니다.", "3": "정보전달자: 직접적인 서비스 제공은 다른 전문가의 역할에 가까움.", "4": "동기 유발자: 질병의 증상 확인은 요양보호사의 핵심 역할이 아님.", "5": "숙련된 수발자: 서비스 제공 계획 및 수립은 관리자의 역할에 가까움."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 요양하고 돌보는 전문인력", "def_vi": "Nhân lực chuyên chăm sóc và nuôi dưỡng bệnh nhân"}, {"term_ko": "역할", "term_vi": "Vai trò", "def_ko": "근무에서의 역할", "def_vi": "Vai trò trong công việc"}, {"term_ko": "관찰자", "term_vi": "Người quan sát", "def_ko": "상황이나 행동을 주의 깊게 살펴보는 사람", "def_vi": "Người chú ý đến tình huống hoặc hành vi"}, {"term_ko": "옹호자", "term_vi": "Người bảo vệ", "def_ko": "지원 및 변호를 하는 사람", "def_vi": "Người hỗ trợ và đại diện"}, {"term_ko": "정보전달자", "term_vi": "Người truyền đạt thông tin", "def_ko": "정보를 전달하는 사람", "def_vi": "Người truyền tải thông tin"}, {"term_ko": "동기 유발자", "term_vi": "Người khơi gợi động lực", "def_ko": "동기를 주는 사람", "def_vi": "Người tạo động lực"}, {"term_ko": "숙련된 수발자", "term_vi": "Người chăm sóc có kỹ năng", "def_ko": "전문가적인 돌봄을 하는 사람", "def_vi": "Người chăm sóc có chuyên môn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (217, '2', '다음 중 수급자가 요양보호사에게 요구해서는 안 되는 행위로 옳은 것은?', '["대상자를 위한 관공서 등 업무지원", "대상자 생일을 위한 미역국 끓이기", "대상자 아들 가게의 음식을 준비함.", "보호자가 어머님이 베란다에서 배변하는 것을 발견하여 문의함", "대상자가 은행의 고액 업무를 부탁함"]'::jsonb, 3, '수급자가 요양보호사에게 요구할 수 있는 행위와 요구해서는 안 되는 행위를 구분하기 위함입니다.', NULL, '{"1": "대상자를 위한 관공서 등 업무지원은 가능하므로 요구할 수 있습니다.\n[정답]", "3": "대상자 아들 가게의 음식을 준비하는 것은 개인적인 부탁으로 요구해서는 안 됩니다.", "2": "대상자 생일을 위한 미역국 끓이기는 요양 서비스를 포함할 수 있습니다.", "4": "보호자가 어머님이 베란다에서 배변하는 것을 발견하여 문의하는 것은 적절한 행위입니다.", "5": "대상자가 은행의 고액 업무를 부탁하는 것은 부적절한 요구입니다."}'::jsonb, '[{"term_ko": "수급자", "term_vi": "Người hưởng", "def_ko": "서비스를 받는 사람", "def_vi": "Người nhận dịch vụ"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "보호와 돌봄을 제공하는 사람", "def_vi": "Người cung cấp sự chăm sóc và bảo vệ"}, {"term_ko": "행위", "term_vi": "Hành vi", "def_ko": "행동", "def_vi": "Hành động"}, {"term_ko": "업무지원", "term_vi": "Hỗ trợ công việc", "def_ko": "업무에 대한 지원", "def_vi": "Hỗ trợ công việc"}, {"term_ko": "요구", "term_vi": "Yêu cầu", "def_ko": "요청", "def_vi": "Yêu cầu"}, {"term_ko": "부탁", "term_vi": "Nhờ", "def_ko": "부탁하다", "def_vi": "Nhờ cậy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (216, '2', '다음과 같은 요양보호사의 고충이 있을 경우 장기요양기관장의 적절한 조치로 옳은 것은?• 치매 대상자의 배우자는 요양보호사가 대상자를 제대로 돌보지 않아 치매 증상이 심해졌다며 심한 폭언을 하였다.', '["요양보호사의 고충 요청을 무시한다.", "조리업무로 업무를 전환한다.", "상담심리 지원 프로그램을 제공한다.", "대상자의 일부 부담금을 할인해준다.", "요양보호사에게 적성이 맞는지 상담을 한다."]'::jsonb, 3, '요양보호사가 겪는 고충을 이해하고, 적절한 지원 방안을 찾는 것이 중요하다.', NULL, '{"1": "요양보호사의 고충 요청을 무시한다는 것은 잘못된 대처 방법이다.\n[정답]", "3": "상담심리 지원 프로그램을 제공하는 것은 요양보호사의 정서적 지지를 위한 올바른 조치이다.", "2": "조리업무로 업무를 전환하는 것은 문제 해결에 도움이 되지 않는다.", "4": "대상자의 일부 부담금을 할인해주는 것은 요양보호사의 고충과는 무관한 조치이다.", "5": "요양보호사에게 적성이 맞는지 상담하는 것은 필요한 조치일 수 있지만, 현재 상황에 대한 즉각적인 지원이 아니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (215, '3', '김씨 할머니는 거울을 보며 에휴, 매번 머리 모양을 남자처럼 짧게 깎아놔...라며 투덜거리는 상황에서 대상자가 요구할 수 있는 권리로 옳은 것은?', '["개별화된 서비스를 제공받고 선택할 수 있는 권리", "안락하고 안전한 생활환경을 제공받을 권리", "존엄한 존재로 대우받을 권리", "건강한 생활을 위한 질 높은 생활서비스 및 보건의료서비스를 받을 권리", "시설운영과 서비스에 대한 개인적 견해를 표현학 해결을 요구할 권리"]'::jsonb, 1, '김씨 할머니가 거울을 보며 자신의 머리 모양에 대해 불만을 표현하며, 이 상황에서 대상자가 가지는 권리를 묻는 문제입니다.', NULL, '{"1": "개별화된 서비스를 제공받고 선택할 수 있는 권리: 개인의 필요와 선호에 따라 서비스를 선택할 수 있는 권리로, 대상자의 고유한 요구를 반영합니다.\n[정답]", "2": "안락하고 안전한 생활환경을 제공받을 권리: 기본적인 안전과 안락함을 보장받을 권리지만, 문제의 상황과는 직접적 관련이 적습니다.", "3": "존엄한 존재로 대우받을 권리: 존엄성은 중요하지만, 이 상황에서는 개인의 선택권이 더 부각됩니다.", "4": "건강한 생활을 위한 질 높은 생활서비스 및 보건의료서비스를 받을 권리: 건강과 관련된 권리로 의미가 있으나, 이 문제에서는 개인의 선택권이 주제입니다.", "5": "시설운영과 서비스에 대한 개인적 견해를 표현하고 해결을 요구할 권리: 개인의 의견과 요구를 표현할 수 있는 권리이나, 상황의 맥락을 봤을 때 더 적합한 선택은 아닙니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (214, '3', '다음과 같은 상황에서 대상자가 침해받은 권리로 옳은 것은?• 시설장 : (입소자가 가져온 짐을 보면서) 어르신, 전화로도 말씀드렸듯이 이 시설에서는 개인의 물품을 설치하거나 이용하는 것을 허용하지 않습니다. • 대상자 : ......', '["신체구속을 받지 않을 권리", "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리", "차별 및 노인학대를 받지 않을 권리", "사생활과 비밀보장에 대한 권리", "개별화된 서비스를 제공받고 선택할 수 있는 권리"]'::jsonb, 5, '시설에서 입소자의 권리에 대한 이해도를 평가하려는 문제입니다.', NULL, '{"1": "신체구속을 받지 않을 권리는 특정 상황에서 적용되는 것이므로, 이번 상황에 직접적인 관련이 없습니다.", "2": "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리는 중요하지만, 문제 상황에서는 개인 물품 설치에 대한 제한을 다루고 있습니다.", "3": "차별 및 노인학대를 받지 않을 권리는 일반적인 권리이지만, 여기에서는 특정한 조치와 관련된 권리를 묻고 있습니다.\n[정답]", "4": "사생활과 비밀보장에 대한 권리는 시설에서 개인 물품을 설치할 수 없다는 조치와 관련이 있으며, 사생활 보호와 맞물려 있습니다.", "5": "개별화된 서비스를 제공받고 선택할 수 있는 권리는 개인의 자유와 관계가 깊어서, 물품 설치 자유와 관련이 있습니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền lợi"}, {"term_ko": "사생활", "term_vi": "Cuộc sống riêng tư", "def_ko": "개인의 프라이버시(한국어)", "def_vi": "Cuộc sống riêng tư"}, {"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "시설(한국어)", "def_vi": "Cơ sở"}, {"term_ko": "개별화", "term_vi": "Cá nhân hóa", "def_ko": "맞춤형(한국어)", "def_vi": "Cá nhân hóa"}, {"term_ko": "선택", "term_vi": "Lựa chọn", "def_ko": "선택(한국어)", "def_vi": "Lựa chọn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (213, '3', '다음과 같은 사례에서 보장되어야 하는 대상자의 권리로 옳은 것은?• 대상자는 평소에 온돌에서 생활해 왔는데, 시설에 입소 후 침대생활을 해야 해서 쉽게 잠이 들지 않고 떨어질까 봐 불안하여 잠을 깊게 잘 수가 없다고 한다.', '["사생활과 비밀보장에 대한 권리", "신체구속을 받지 않을 권리", "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리", "차별 및 노인 학대를 받지 않을 권리", "안락하고 안전한 생활환경을 제공받을 권리"]'::jsonb, 5, '대상자의 권리와 관련된 사례를 통해 어떤 권리가 보장되어야 하는지를 평가하고자 하는 의도입니다.', NULL, '{"1": "사생활과 비밀보장에 대한 권리는 중요하지만, 현재 사례와 직접적인 관련은 적습니다.\n[정답]", "5": "안락하고 안전한 생활환경을 제공받을 권리 가 가장 적절한 선택입니다. 대상자가 편안한 수면을 취할 수 있는 환경이 필요하기 때문입니다.", "3": "정보 제공 권리도 중요하지만, 현재 사례의 핵심은 생활환경에 대한 것입니다.", "4": "차별과 노인 학대의 방지 또한 중요한 권리지만, 현재 사례와는 맞지 않습니다.", "2": "신체구속을 받지 않을 권리도 중요하지만, 이 사례에서는 다루지 않은 내용입니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền lợi của người dùng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (212, '3', '다음과 같은 사례에 해당되는 시설 대상자의 권리로 옳은 것은?• 편마비 대상자가 시설장에게 화장실에 비상벨이 없어 불편하다고 하였다.', '["신체구속을 받지 않을 권리", "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리", "사생활과 비밀보장에 대한 권리", "노인 스스로 입소를 결정하며, 공정한 입소 계약을 맺을 권리", "안락하고 안전한 생활환경을 제공받을 권리"]'::jsonb, 5, '대상자의 권리에 대한 이해를 확인하기 위함입니다.', NULL, '{"1": "신체구속을 받지 않을 권리는 중요하지만, 이 사례와는 관련이 없습니다.\n[정답]", "5": "안락하고 안전한 생활환경을 제공받을 권리는 편마비 대상자의 불편함과 직접적으로 관련이 있습니다.", "2": "시설 운영 전반에 관한 충분한 정보를 제공받을 권리는 일반적인 권리이나, 해당 사례와는 관계가 적습니다.", "3": "사생활과 비밀보장에 대한 권리는 중요하지만, 이번 사례와는 연결되지 않습니다.", "4": "노인 스스로 입소를 결정하며, 공정한 입소 계약을 맺을 권리는 대상자의 상황에 비추어 볼 때 이러한 권리는 이미 충족된 것으로 보입니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸의 감각이나 운동 기능이 상실된 상태(한국어)", "def_vi": "Tình trạng mất cảm giác hoặc chức năng vận động ở một bên cơ thể"}, {"term_ko": "비상벨", "term_vi": "Chuông báo động", "def_ko": "긴급 상황에서 사용되는 경고 장치(한국어)", "def_vi": "Thiết bị cảnh báo được sử dụng trong trường hợp khẩn cấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (211, '3', '다음 사례에 해당하는 시설노인을 위한 윤리강령의 원칙 중 침해받은 권리로 옳은 것은?• 어르신께서는 시설 실습을 나온 실습생들이 기념이라며 자기들 맘대로 사진을 찍거나 방에 불쑥불쑥 들어와 구경하고 나가는 것을 보면 매우 불쾌하다고 하신다.', '["안락하고 안전한 생활환경을 제공받을 권리", "사생활과 비밀보장에 대한 권리", "존엄한 존재로 대우받을 권리", "건강한 생활을 위한 질 높은 생활서비스 및 보건의료서비스를 받을 권리", "시설운영과 서비스에 대한 개인적 견해를 표현하고 해결을 요구할 권리"]'::jsonb, 2, '(시설노인의 권리에 대한 이해와 윤리 강령의 원칙을 평가하기 위함)', NULL, '{"1": "안락하고 안전한 생활환경은 중요하지만, 사진 촬영과 관련된 권리는 아닙니다.\n[정답]", "2": "사생활과 비밀보장에 대한 권리는 사진촬영과 사적인 공간 침해와 관련이 있습니다.", "3": "존엄한 존재로 대우받는 것도 중요하지만, 주어진 사례에서는 사생활의 침해가 더욱 명확합니다.", "4": "건강과 관련된 권리는 중요하나, 이번 문제의 사례와는 직접적인 연관이 없습니다.", "5": "개인적 견해 표현은 권리지만, 사례에서 중심이 되는 문제는 사생활의 침해입니다."}'::jsonb, '[{"term_ko": "시설노인", "term_vi": "Người lớn tuổi trong viện dưỡng lão", "def_ko": "시설에서 생활하는 노인", "def_vi": "Người sống trong cơ sở chăm sóc dài hạn"}, {"term_ko": "윤리강령", "term_vi": "Nguyên tắc đạo đức", "def_ko": "윤리 원칙을 규정한 문서", "def_vi": "Tài liệu quy định các nguyên tắc đạo đức"}, {"term_ko": "사생활", "term_vi": "Cá nhân", "def_ko": "개인의 사적 공간과 정보", "def_vi": "Không gian và thông tin cá nhân"}, {"term_ko": "권리", "term_vi": "Quyền", "def_ko": "개인의 기본적인 요구 또는 요청", "def_vi": "Nhu cầu hoặc yêu cầu cơ bản của cá nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (210, '3', '치매 대상자가 같은 방을 쓰는 동료 노인에게 소리치고, 발로 차고 동료 노인의 따귀를 때릴 때 대처 방법으로 옳은 것은?', '["치매 노인에게 왜 때리는지 이유를 물어본다.", "침해 당한 노인의 방을 옮겨 마주치지 않게 한다.", "치매 대상에게 퇴소시킬 수 있다고 경고한다.", "치매 대상자의 습성이라고 이해한다.", "치매 대상자의 가족에게 인권교육을 시킨다."]'::jsonb, 2, '치매 대상자의 행동에 대한 적절한 대처 방법을 이해하고 있는지를 평가하려는 의도입니다.', NULL, '{"1": "치매 노인은 상황을 인지하기 어려워 이유를 물어봐도 의미가 없을 수 있습니다.\n[정답]", "2": "침해 당한 노인의 방을 옮겨 마주치지 않게 하는 것이 가장 효과적인 대처 방법입니다.", "3": "퇴소 위협은 치매 환자에게는 오히려 부정적인 영향을 미칠 수 있습니다.", "4": "습성을 이해하는 것이 중요하지만, 이를 방치하면 문제를 해결할 수 없습니다.", "5": "가족에게 인권교육은 필요하지만, 상황 해결과는 직접적인 연관이 없습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "대상자", "def_ko": "기억력이나 사고 기능의 저하가 있는 뇌질환(병 lão hóa trí nhớ, bệnh Alzheimer)", "def_vi": "치료나 도움이 필요한 사람(người được điều trị)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (209, '3', '다음과 같은 상황에서 시설대상자가 침해받는 권리로 옳은 것은?• 다른 대상자에게 따귀를 맞은 사실에 대해 요양보호사가 아무런 개입을 하지 않았다. • 요양보호사가 치매 대상자에게 폭언을 하였다.', '["신체구속을 받지 않을 권리", "개별화된 서비스를 제공받고 선택할 수 있는 권리", "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리", "존엄한 존재로 대우받을 권리", "사생활과 비밀보장에 대한 권리"]'::jsonb, 4, '이 문제가 의도하는 바는 시설대상자가 어떤 권리들을 침해받고 있는지를 이해하고, 그 중에서 가장 적합한 답을 찾도록 하는 것이다.', NULL, '{"1": "신체구속을 받지 않을 권리: 질문에 언급된 상황은 신체구속과 관련이 없다.\n[정답]", "2": "개별화된 서비스를 제공받고 선택할 수 있는 권리: 요양보호사의 폭언으로 인해 대우받지 못하였다.", "3": "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리: 질문의 맥락과는 관련이 없다.", "4": "존엄한 존재로 대우받을 권리: 대상자가 폭언과 타인에게 따귀를 맞는 상황에서 이 권리가 침해된 것이므로 정답이다.", "5": "사생활과 비밀보장에 대한 권리: 질문과 관련이 없는 권리이다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền lợi", "def_ko": "권리(한국어)", "def_vi": "Quyền"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (208, '3', '다음의 시설대상자가 보장받아야 할 기본 권리로 옳은 것은?"우리 가족들이 잘 안 와서 그런지 똑같이 음식을 흘려도 나한테만 유난히 더 화를 내. 나를 괄시하는 거지."', '["신체구속을 받지 않을 권리", "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리", "개인 소유의 재산과 소유물을 스스로 관리할 권리", "사생활과 비밀보장에 대한 권리", "차별 및 노인학대를 받지 않을 권리"]'::jsonb, 5, '시설 대상자가 가지는 기본 권리에 대한 이해를 평가하기 위한 문제이다.', NULL, '{"1": "신체구속을 받지 않을 권리에 대한 설명은 맞지만, 이 사례에서는 강조되지 않는다.\n[정답]", "5": "차별 및 노인학대를 받지 않을 권리는 상황에 비추어 가장 적합하다.", "3": "개인 소유의 재산과 소유물을 스스로 관리할 권리는 중요하지만 이 문장에서 직접적으로 다루지 않는다.", "2": "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리는 필수적이지만, 사례와는 관계가 없다.", "4": "사생활과 비밀보장에 대한 권리는 중요하지만, 문맥에서는 차별 문제에 더 집중하고 있다."}'::jsonb, '[{"term_ko": "시설", "term_vi": "Cơ sở", "def_ko": "시설(한국어)", "def_vi": "Cơ sở"}, {"term_ko": "보장", "term_vi": "Bảo đảm", "def_ko": "보장(한국어)", "def_vi": "Bảo đảm"}, {"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền"}, {"term_ko": "차별", "term_vi": "Phân biệt", "def_ko": "차별(한국어)", "def_vi": "Phân biệt"}, {"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người cao tuổi"}, {"term_ko": "학대", "term_vi": "Bạo lực", "def_ko": "학대(한국어)", "def_vi": "Bạo lực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (207, '3', '다음 사례에 해당하는 시설생활노인의 보장받을 권리로 옳은 것은?• 거동이 불편한 김씨 할아버지는 산책 중에 넘어져 손목을 골절당한 경험이 있다. 이후부터 요양보호사는 자리를 비울 때마다 손과 발을 묶어 놓고 나가기 때문에 하루에도 몇 번씩 억제를 당하고 있다.', '["존엄한 존재로 대우받을 권리", "사생활과 비밀보장에 대한 권리", "신체구속을 받지 않을 권리", "안락하고 안전한 생활환경을 제공받을 권리", "건강한 생활을 위한 질 높은 생활서비스 및 보건의료서비스를 받을 권리"]'::jsonb, 3, '이 문제는 시설생활노인의 권리에 대한 이해를 평가하기 위한 것입니다. 사례에서 거동이 불편한 노인이 손과 발이 묶이는 상황은 신체구속에 해당하므로 이에 대한 권리가 무엇인지 묻고 있습니다.', NULL, '{"1": "존엄한 존재로 대우받을 권리는 기본적인 권리지만, 사례와 직접적인 연관이 없습니다.\n[정답]", "3": "신체구속을 받지 않을 권리는 노인의 권리 중 하나로 사례에서 명백히 위반되고 있습니다.", "2": "사생활과 비밀보장에 대한 권리는 중요하지만, 이 사례에서 논의하는 부분과는 관계가 없습니다.", "4": "안락하고 안전한 생활환경을 제공받을 권리는 기본적이지만, 문제의 핵심은 신체구속입니다.", "5": "건강한 생활을 위한 질 높은 생활서비스 및 보건의료서비스를 받을 권리는 관련있지만 이 사례의 본질과는 거리가 있습니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền"}, {"term_ko": "시설생활노인", "term_vi": "Người cao tuổi sống trong cơ sở", "def_ko": "시설에서 생활하는 노인(한국어)", "def_vi": "Người cao tuổi sống trong cơ sở"}, {"term_ko": "신체구속", "term_vi": "Hạn chế thể xác", "def_ko": "신체의 일부가 제한되는 것(한국어)", "def_vi": "Bị giới hạn một phần thân thể"}, {"term_ko": "안락", "term_vi": "An nhàn", "def_ko": "편안함(한국어)", "def_vi": "Sự thoải mái"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주위의 상황(한국어)", "def_vi": "Tình huống xung quanh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (206, '3', '다음의 내용과 같은 시설대상자의 기본 권리로 옳은 것은?• 개인의 선호와 건강 상태에 따른 개별화된 식단을 제공한다. • 잔존능력을 유지시키기 위해 재활프로그램을 제공한다. • 시설은 종사자에게 직무훈련과 교육기회를 충분히 부여한다.', '["존엄한 존재로 대우받을 권리", "사생활과 비밀보장에 대한 권리", "신체구속을 받지 않을 권리", "안락하고 안전한 생활환경을 제공받을 권리", "건강한 생활을 위한 질 높은 생활서비스 및 보건의료서비스를 받을 권리"]'::jsonb, 5, '시설대상자의 기본 권리를 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "존엄한 존재로 대우받을 권리는 기본적인 인권을 포함하지만, 직접적인 내용과는 관련이 없습니다.", "2": "사생활과 비밀보장에 대한 권리는 중요한 권리이나, 제시된 예시와 연관이 없습니다.", "3": "신체구속을 받지 않을 권리는 특정한 권리 중 하나로 관련성이 적습니다.\n[정답]", "4": "안락하고 안전한 생활환경을 제공받을 권리는 예시와 맞물려 있으며,", "5": "건강한 생활을 위한 질 높은 생활서비스 및 보건의료서비스를 받을 권리, 제시된 모든 내용과 일치합니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권리(한국어)", "def_vi": "Quyền(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (205, '3', '시설 내 · 외부 활동 및 사회적 관계에 참여할 권리에 침해 받은 것은?', '["노인의 정치적 이념을 존중한다.", "특정 인물에 투표하도록 영향력을 행사한다.", "노인의 종교적 신념을 인정한다.", "종교적 신념의 변화를 목적으로 영향력을 행사하지 않는다.", "노인의 문화적 다양성을 인정한다."]'::jsonb, 2, '노인의 권리에 관한 내용을 확인하고 이해하는 것.', NULL, '{"1": "노인의 정치적 이념을 존중하는 것은 권리를 보호하는 행동이다.\n[정답]", "2": "특정 인물에 투표하도록 영향력을 행사하는 것은 노인의 권리를 침해하는 행위이다.", "3": "노인의 종교적 신념을 인정하는 것은 권리를 보호하는 행동이다.", "4": "종교적 신념의 변화를 목적으로 영향력을 행사하지 않는 것은 권리를 지키는 일이다.", "5": "노인의 문화적 다양성을 인정하는 것은 권리를 존중하는 행동이다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "고령자(한국어)", "def_vi": "Người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (204, '3', '다음에 해당하는 시설생활노인의 보장받을 권리로 옳은 것은?• 노인의 이성교제를 금기시하거나 흥밋거리로 다루지 않아야 한다. • 노인의 성적 욕구를 인간의 기본욕구로서 선입견 없이 받아들여야 한다. • 흡연, 음주 등 특정 기호품 사용에 대해 시설환경 내에서 해결할 수 있는 방안을 마련한다.', '["신체구속을 받지 않을 권리", "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리", "사생활과 비밀보장에 대한 권리", "이성교제, 성생활, 기호품 사용에 관한 가지 결정의 권리", "시설운영과 서비스에 대한 개인적 견해를 표현하고 해결을 요구할 권리"]'::jsonb, 4, '시설생활노인의 권리와 관련된 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "신체구속을 받지 않을 권리는 노인의 신체적 자유를 보장하는 내용입니다.\n[정답]", "4": "이성교제, 성생활, 기호품 사용에 관한 결정 권리는 노인의 기본적인 인권을 존중하는 내용을 포함합니다.", "2": "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리는 노인의 정보 접근성을 의미합니다.", "3": "사생활과 비밀보장에 대한 권리는 노인의 개인적 사생활을 보호하는 내용을 담고 있습니다.", "5": "시설 운영과 서비스에 대한 개인적 견해를 표현하고 해결을 요구할 권리는 노인의 의견을 반영하는 내용을 포함합니다."}'::jsonb, '[{"term_ko": "시설생활노인", "term_vi": "Người già sống trong cơ sở", "def_ko": "시설에서 생활하는 노인", "def_vi": "Người già sống trong môi trường điều trị"}, {"term_ko": "신체구속", "term_vi": "Ràng buộc thể xác", "def_ko": "신체적으로 자유를 제한받는 것", "def_vi": "Bị hạn chế về mặt thể xác"}, {"term_ko": "이성교제", "term_vi": "Quan hệ tình cảm", "def_ko": "이성과의 관계 형성", "def_vi": "Hình thành mối quan hệ với người khác giới"}, {"term_ko": "성적 욕구", "term_vi": "Nhu cầu tình dục", "def_ko": "성에 관한 욕구", "def_vi": "Nhu cầu liên quan đến tình dục"}, {"term_ko": "기호품", "term_vi": "Sản phẩm sở thích", "def_ko": "개인이 선호하는 물품", "def_vi": "Các sản phẩm mà cá nhân ưa thích"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (203, '3', '시설에 대상자의 의견 수렴 건의함을 설치하지 않았을 때 대상자가 침해받을 수 있는 권리로 옳은 것은?', '["신체구속을 받지 않을 권리", "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리", "사생활과 비밀보장에 대한 권리", "노인 스스로 입소를 결정하며, 공정한 입소 계약을 맺을 권리", "시설운영과 서비스에 대한 개인적 견해를 표현하고 해결을 요구할 권리"]'::jsonb, 5, '대상자의 권리에 대한 이해를 확인하기 위함입니다.', NULL, '{"1": "신체구속을 받지 않을 권리는 기본적인 인권으로, 시설에 의견 수렴 건의함의 설치 여부와는 직접적인 관계가 없습니다.\n[정답]", "5": "시설운영과 서비스에 대한 개인적 견해를 표현하고 해결을 요구할 권리는 의견 수렴을 통해 보장되는 권리입니다.", "2": "시설 운영 전반에 관한 충분한 정보를 제공 받을 권리는 정보 제공의 의무에 해당하지만, 의견 수렴 건의함의 부재와는 직접적인 연관이 없습니다.", "3": "사생활과 비밀보장에 대한 권리는 개인의 프라이버시를 보호하는 것을 의미하며, 이 경우와 연관이 없습니다.", "4": "노인이 스스로 입소를 결정하며, 공정한 입소 계약을 맺을 권리는 입소 계약 관련 권리로, 의견 수렴 건의함과는 상관이 없습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người sử dụng dịch vụ", "def_ko": "환자, 서비스 이용자", "def_vi": "Người nhận chăm sóc, bệnh nhân"}, {"term_ko": "권리", "term_vi": "Quyền", "def_ko": "권한, 법적인 권리", "def_vi": "Quyền hợp pháp, quyền hạn"}, {"term_ko": "입소", "term_vi": "Nhập viện", "def_ko": "시설에 들어가는 것", "def_vi": "Vào cơ sở"}, {"term_ko": "의견", "term_vi": "Ý kiến", "def_ko": "생각, 의견", "def_vi": "Suy nghĩ, đề xuất"}, {"term_ko": "건의", "term_vi": "Đề xuất", "def_ko": "제안하는 것", "def_vi": "Đề nghị"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (202, '3', '노인학대의 발생요인에 해당하는 것으로 옳은 것은?', '["학력 수준의 증가", "가족관계 갈등 해소", "노인의 의존성 증가", "노인부양 의식 강화", "노인의 사회적 관계망 확대"]'::jsonb, 3, '노인학대의 발생 요인에 대해 이해하고 있는지를 묻는 문제입니다.', NULL, '{"1": "노인학대의 발생과는 상관이 없는 요인입니다.", "2": "가족관계 갈등 해소는 오히려 학대의 감소로 이어질 수 있습니다.\n[정답]", "3": "노인의 의존성이 증가하면 학대의 위험이 커질 수 있습니다.", "4": "노인부양 의식의 강화는 긍정적인 요인이지 학대를 유발하는 요인이 아닙니다.", "5": "노인의 사회적 관계망이 확대되면 오히려 보호받는 경우가 많습니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인에게 가해지는 신체적, 정신적, 정서적 폭력", "def_vi": "Bạo lực về thể chất, tâm lý, và tinh thần đối với người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (201, '3', '자식 내외가 노인부모의 기본 생존 유지에 필요한 장치, 식사, 약물 등으로부터 단절하였을 때 학대의 종류로 옳은 것은?', '["신체적 학대", "정서적 학대", "성적 학대", "경제적 학대", "방임"]'::jsonb, 1, '노인학대의 유형을 정확히 이해하고 구별하는 능력을 평가하기 위함입니다.', NULL, '{"1": "신체적 학대: 신체에 위한 상해나 고통을 가하는 행동입니다.\n[정답]", "2": "정서적 학대: 정신적 고통을 주는 행동이지만, 여기서는 생존 유지 단절에 해당하지 않습니다.", "3": "성적 학대: 환자의 의사에 반하는 성적 행위를 강요하는 것입니다.", "4": "경제적 학대: 재정적 자원의 이용에 대한 부적절한 처리가 해당하나, 생존 유지와는 거리가 있습니다.", "5": "방임: 필요한 돌봄을 제공하지 않는 상태로, 이 경우에 가장 적합한 유형입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (200, '3', '다음에 해당하는 노인학대 유형으로 옳은 것은?• 집 밖으로 나가지 못하게 통제한다. • 강제로 수감하거나 위협하여 일을 강요한다.', '["방임", "유기", "신체적 학대", "정서적 학대", "경제적 학대"]'::jsonb, 3, '노인학대의 유형에 대한 이해를 평가하고자 하는 문제입니다.', NULL, '{"1": "방임: 노인을 돌보지 않거나 필요한 도움을 제공하지 않는 경우를 말합니다.", "2": "유기: 노인을 단독으로 방치하여 위험에 처하게 하는 것을 의미합니다.\n[정답]", "3": "신체적 학대: 신체적 폭력이나 강압으로 신체에 피해를 주는 행위로, 질문에서 언급한 통제와 강압이 해당됩니다.", "4": "정서적 학대: 심리적 고통이나 두려움을 주는 행동을 포함합니다.", "5": "경제적 학대: 재정적 자원을 착취하거나 통제하는 것을 의미합니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "고의적으로 노인을 해치거나 방치하는 행위", "def_vi": "Hành động cố ý gây hại hoặc bỏ mặc người cao tuổi"}, {"term_ko": "강압", "term_vi": "Ép buộc", "def_ko": "무언가를 하도록 강제로 만드는 것", "def_vi": "Bắt ai đó làm điều gì đó"}, {"term_ko": "통제", "term_vi": "Kiểm soát", "def_ko": "자유롭게 행동하지 못하도록 제한하는 것", "def_vi": "Hạn chế hành động tự do"}, {"term_ko": "신체적", "term_vi": "Thân thể", "def_ko": "몸과 관련된", "def_vi": "Liên quan đến cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (199, '3', '노인의 이성 교제를 방해, 말과 행동을 무시하고 따로 식사하게 할 때 노인학대의 유형으로 옳은 것은?', '["신체적 학대", "정서적 학대", "성적 학대", "경제적 학대", "방임"]'::jsonb, 2, '노인의 이성 교제를 방해하고, 말과 행동을 무시하는 것은 노인에게 정서적 피해를 야기할 수 있음.', NULL, '{"1": "신체적 학대: 신체에 직접적인 피해를 주는 학대 형태입니다.\n[정답]", "2": "정서적 학대: 감정적으로 상처를 주거나 무시하는 행위로 노인에게 정서적 고통을 줌.", "3": "성적 학대: 성적인 행위에 대한 학대로, 노인의 동의 없이 이루어져서는 안 됩니다.", "4": "경제적 학대: 노인의 재산이나 수입을 부당하게 관리하는 행위입니다.", "5": "방임: 필요한 보호나 돌봄을 제공하지 않는 경우를 의미합니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "이성", "def_ko": "老人", "def_vi": "性别"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (198, '3', '다음 사례에 해당하는 학대 유형으로 옳은 것은?• 요양시설 방문객들이 자주 오는 주말임에도 요양보호사는 목욕탕 문을 열어 놓고 어르신을 알몸으로 목욕을 시키고 있었다.', '["신체적 학대", "정서적 학대", "성적 학대", "경제적 학대", "자기방임"]'::jsonb, 3, '해당 사례를 통해 요양보호사가 저지른 학대의 유형을 판단하게 한다.', NULL, '{"1": "신체적 학대는 신체에 대한 물리적 피해를 주는 행위로 이 경우와는 다르다.\n[정답]", "3": "성적 학대는 개인의 신체를 성적 목적에 이용하거나 노출시키는 행위로 여기서 어르신이 알몸으로 목욕하는 상황이 이에 해당한다.", "2": "정서적 학대는 감정적으로 상처를 주는 행위로, 이 사례에서는 해당되지 않는다.", "4": "경제적 학대는 재정적인 자산을 부당하게 이용하는 것이며 이 사례와 관계가 없다.", "5": "자기방임은 스스로 돌봄을 하지 않는 상태를 뜻하는데, 이 역시 해당되지 않는다."}'::jsonb, '[{"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "괴롭히거나 해치는 것(한국어)", "def_vi": "Hành động gây tổn hại hoặc làm phiền"}, {"term_ko": "요양시설", "term_vi": "Cơ sở chăm sóc", "def_ko": "노인을 돌보는 시설(한국어)", "def_vi": "Cơ sở chăm sóc người cao tuổi"}, {"term_ko": "알몸", "term_vi": "Khỏa thân", "def_ko": "옷을 입지 않은 상태(한국어)", "def_vi": "Trạng thái không mặc quần áo"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "물로 몸을 씻는 것(한국어)", "def_vi": "Hành động rửa cơ thể bằng nước"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (197, '3', '다음 사례에 해당하는 학대 유형으로 옳은 것은?• 대상자의 손자가 대상자가 받고 있는 국민기초생활보장 급여를 몰래 인출해가는 것을 요양보호사가 목격하였다.', '["유기", "자기방임", "경제적 학대", "정서적 학대", "신체적 학대"]'::jsonb, 3, '대상자가 경험하는 특정 유형의 학대를 확인하는 데 있다.', NULL, '{"1": "유기는 대상자를 방치하거나 돌보지 않는 행위를 의미한다.", "2": "자기방임은 대상자가 스스로 자신의 건강이나 안전을 돌보지 않는 경우이다.\n[정답]", "3": "경제적 학대는 대상자의 재산이나 소득을 불법적으로 착취하는 행위로, 여기서는 손자가 대상자의 급여를 몰래 인출한 사례를 설명한다.", "4": "정서적 학대는 정신적, 정서적 고통을 주는 행위로, 이 사례와는 관련이 없다.", "5": "신체적 학대는 대상을 신체적으로 해치는 경우로, 이 사례와 관계가 없다."}'::jsonb, '[{"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "학대(보호자 또는 가족이 피해자에게 가하는 해로운 행위)", "def_vi": "Hành vi có hại của người chăm sóc hoặc gia đình đối với nạn nhân"}, {"term_ko": "경제적", "term_vi": "Kinh tế", "def_ko": "경제적 (물질적 가치와 관련된)", "def_vi": "Liên quan đến giá trị vật chất"}, {"term_ko": "손자", "term_vi": "Cháu trai", "def_ko": "손자의 의미", "def_vi": "Con của con"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (196, '3', '다음이 내용에 해당하는 노인학대 유형으로 옳은 것은?• 치매 대상자가 고열 증세로 몸져누워 있지만 아들 내외는 치료비가 없다며 대상자를 병원에 데려가지 않고 며칠 동안 집을 비웠다.', '["신체적 학대", "정서적 학대", "경제적 학대", "방임", "유기"]'::jsonb, 4, '노인학대의 유형을 이해하고, 사례를 통해 올바른 답변을 선택하도록 유도하는 문제입니다.', NULL, '{"1": "신체적 학대: 신체에 직접적인 해를 가하는 행위로, 예시에는 해당하지 않습니다.", "2": "정서적 학대: 감정적으로 상처를 주는 행위나 언어적 폭력을 포함하나, 여기서는 해당하지 않습니다.", "3": "경제적 학대: 경제적 자원을 부당하게 유용하는 것이지만, 이 사례에서는 병원 치료를 거부하여 방임의 경우에 해당합니다.\n[정답]", "4": "방임: 치료가 필요한 상황에서 대상자를 방치하고 집을 비운 경우로 명백한 방임으로 판단됩니다.", "5": "유기: 의도적으로 부모나 노인을 버리는 행위로, 이 경우와는 다릅니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người già", "def_ko": "노인을 괴롭히는 행위", "def_vi": "Hành vi làm tổn hại đến người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (195, '3', '노인학대의 유형으로 옳은 것은?• 대상자의 건강이 악화됨에도 계속 술을 마신다. • 요양보호사가 집 안을 청소하려 해도 대상자가 거부한다.', '["신체적 학대", "정서적 학대", "자기방임", "방임", "유기"]'::jsonb, 3, '노인학대의 다양한 유형을 이해하고 적용하는 능력을 평가하기 위함입니다.', NULL, '{"1": "신체적 학대: 신체에 대한 직접적인 폭력을 의미합니다.", "2": "정서적 학대: 정신적 고통이나 괴롭힘을 포함합니다.\n[정답]", "3": "자기방임: 자신의 기본적인 필요를 스스로 충족시키지 못하는 상태를 의미합니다.", "4": "방임: 필요한 보호나 돌봄을 제공받지 못하는 상황입니다.", "5": "유기: 누군가를 책임지는 사람이 그을 방치하는 상태입니다."}'::jsonb, '[{"term_ko": "노인학대", "term_vi": "Lạm dụng người cao tuổi", "def_ko": "노인을 학대하거나 방치하는 행위", "def_vi": "Hành vi lạm dụng hoặc bỏ bê người già"}, {"term_ko": "자기방임", "term_vi": "Tự bỏ bê", "def_ko": "자신의 기본적인 필요를 스스로 충족하지 못함", "def_vi": "Không thể tự đáp ứng nhu cầu cơ bản"}, {"term_ko": "신체적", "term_vi": "Thể chất", "def_ko": "신체와 관련된", "def_vi": "Liên quan đến cơ thể"}, {"term_ko": "정서적", "term_vi": "Tình cảm", "def_ko": "정신적인 측면", "def_vi": "Khía cạnh tâm lý"}, {"term_ko": "방임", "term_vi": "Bỏ mặc", "def_ko": "보호가 부족한 상태", "def_vi": "Tình trạng thiếu bảo vệ"}, {"term_ko": "유기", "term_vi": "Bỏ rơi", "def_ko": "책임자에 의한 방치", "def_vi": "Bị bỏ mặc bởi người có trách nhiệm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (194, '3', '치매 대상자를 고의적으로 가출하게 하는 학대 유형으로 옳은 것은?', '["유기", "자기방임", "정서적 학대", "신체적 학대", "경제적 학대"]'::jsonb, 1, '치매 대상자에게 가해지는 학대 유형을 이해하고 구체적으로 알아보는 것이다.', NULL, '{"1": "유기: 보호자가 의도적으로 돌보지 않고 방치하는 행위이다.\n[정답]", "2": "자기방임: 대상자가 자신을 돌보지 않는 것을 의미한다.", "3": "정서적 학대: 언어적 폭력이나 정신적 고통을 주는 방식이다.", "4": "신체적 학대: 폭력을 행사하는 것을 포함한다.", "5": "경제적 학대: 금전적 이득을 취하기 위해 대상자를 착취하는 것이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억과 사고 능력이 감소하는 병", "def_vi": "Bệnh mà làm giảm khả năng ghi nhớ và suy nghĩ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (193, '3', '학대의 유형 (A)과 행위 (B)가 바르게 연결된 것으로 옳은 것은?', '["자기방임 가출해도 찾지 않는다.", "정서적 학대 치료를 받지 못하게 한다.", "신체적 학대 낯선 장소에 버린다.", "경제적 학대 유언장의 서명을 변조한다.", "유기 식사를 제공하지 않는다."]'::jsonb, 4, '이번 문제는 다양한 학대의 유형을 이해하고, 각 유형에 해당하는 행위를 정확하게 연결하는 능력을 평가하고자 합니다.', NULL, '{"1": "자기방임: 자기관리를 하지 못하는 경우로, 가출만으로는 학대와 연결되지 않음.\n[정답]", "2": "정서적 학대: 정신적인 고통을 주는 행위를 나타내며, 치료를 받지 못하게 하는 것은 정서적 학대의 예시입니다.", "3": "신체적 학대: 신체적 피해를 주는 행위를 말하며, 낯선 장소에 버리는 것은 다른 학대 유형에 더 적합합니다.", "4": "경제적 학대: 재정적인 피해를 주는 행위로, 유언장의 서명을 변조하는 것은 경제적 학대의 예시입니다.", "5": "유기: 돌보아야 할 사람을 방치하는 행위로, 식사를 제공하지 않는 것은 유기의 일종이지만, 정확한 연결은 아닙니다."}'::jsonb, '[{"term_ko": "학대", "term_vi": "Lạm dụng", "def_ko": "폭력, 신체적, 정서적, 경제적 해를 가하는 행위", "def_vi": "Hành vi gây tổn hại về thể chất, tinh thần hoặc tài chính"}, {"term_ko": "유기", "term_vi": "Bỏ rơi", "def_ko": "방치, 돌보지 않음", "def_vi": "Không chăm sóc, bỏ mặc"}, {"term_ko": "정서적", "term_vi": "Tâm lý", "def_ko": "정신적인, 감정의", "def_vi": "Tâm thần, cảm xúc"}, {"term_ko": "신체적", "term_vi": "Thể chất", "def_ko": "신체와 관련된, 육체적인", "def_vi": "Liên quan đến thể xác, cơ thể"}, {"term_ko": "경제적", "term_vi": "Kinh tế", "def_ko": "재정적, 자산의", "def_vi": "Liên quan đến tài chính, tài sản"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (192, '3', '방문요양 시 대상자 머리에 멍든 자국과 상처를 발견하였을 때 요양보호사의 대처 방법으로 옳은 것은?', '["방문간호사에게 보고한다.", "가족에게 말한다.", "시설장에게 보고한다.", "노인보호전문기관에 신고한다.", "동료 요양보호사와 의논한다."]'::jsonb, 4, '요양보호사가 방문요양 중 환자의 건강 상태에 이상 징후를 발견했을 때 올바른 대처 방법을 확인하는 것이 목적입니다.', NULL, '{"1": "방문간호사에게 보고한다는 방법은 중요하지만, 노인학대나 안전 문제를 신고하는 우선 조치는 아닙니다.", "2": "가족에게 말하는 것은 필요할 수 있지만, 적절한 신고 절차를 선행해야 합니다.", "3": "시설장에게 보고하는 것은 후속 조치로 필요한 경우가 있지만, 직접적인 신고는 아닙니다.\n[정답]", "4": "노인보호전문기관에 신고하는 것은 법적으로 요구되는 조치로, 신속하게 문제를 해결하기 위한 첫 번째 단계입니다.", "5": "동료 요양보호사와 의논하는 것은 유용할 수 있지만, 즉각적인 신고가 우선해야 합니다."}'::jsonb, '[{"term_ko": "방문요양", "term_vi": "Chăm sóc tại nhà", "def_ko": "집이나 시설에 가서 직접 돌보는 서비스", "def_vi": "Dịch vụ chăm sóc trực tiếp tại nhà hoặc cơ sở"}, {"term_ko": "멍든 자국", "term_vi": "Dấu hiệu bầm tím", "def_ko": "피부에 생긴 푸른자국", "def_vi": "Vết thương tim xanh hoặc bầm trên da"}, {"term_ko": "상처", "term_vi": "Vết thương", "def_ko": "피부가 다친 상태", "def_vi": "Tình trạng tổn thương da"}, {"term_ko": "신고", "term_vi": "Báo cáo", "def_ko": "공식적으로 알리는 것", "def_vi": "Việc thông báo chính thức"}, {"term_ko": "노인보호전문기관", "term_vi": "Trung tâm chuyên môn bảo vệ người cao tuổi", "def_ko": "노인 학대 및 안전 문제를 다루는 기관", "def_vi": "Cơ quan xử lý vấn đề bạo hành và an toàn cho người cao tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (191, '3', '노인 학대 문제를 해결하기 위한 유관기관 (A)과 역할 (B)을 바르게 연결한 것은?', '["의료기관 이용자 대상을 위한 학대 예방 교육", "경찰관서 학대판정을 위한 의학적 진단 및 치료", "노인보호 전문기관 학대사례 신고 접수", "법률기관 현장조사 시 동행", "노인 및 사회복지 시설 학대피해노인 후견인 지정"]'::jsonb, 3, '노인 학대 문제를 해결하는 데 관련된 기관과 각 기관의 역할을 이해하고 연결할 수 있는지를 평가하고자 함.', NULL, '{"1": "의료기관 이용자 대상을 위한 학대 예방 교육: 의료기관은 주로 치료와 예방을 담당하지만, 구체적인 예방 교육을 주로 수행하지는 않음.\n[정답]", "3": "노인보호 전문기관 학대사례 신고 접수: 노인보호 전문기관은 신고 및 상담을 위한 전문 기관으로, 학대 사례를 접수하는 역할을 수행함.", "2": "경찰관서 학대판정을 위한 의학적 진단 및 치료: 경찰관서는 범죄 처벌을 위한 역할을 수행하지만, 의학적 진단 및 치료는 의료기관의 역할임.", "4": "법률기관 현장조사 시 동행: 법률기관이 현장조사를 하는 업무가 있지만, 동행하는 것은 구체적인 역할이 아님.", "5": "노인 및 사회복지 시설 학대피해노인 후견인 지정: 후견인 지정은 사회복지 전반에서 중요한 역할이지만, 특정 기관의 역할로만 명확하게 정의되지는 않음."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "할머니/할아버지(한국어)", "def_vi": "Ông bà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (190, '4', '요양보호사 채용과정에서 기관장이 다음과 같이 말했을 때 요양보호사가 침해받은 권리에 해당하는 것은?"이력서를 보니 나이가 많으시네요. 아무래도 어르신을 돌보는 업무가 힘들것 같네요."', '["자유권", "참정권", "평등권", "신체적 안정 보장 권리", "휴식 및 여가 보장 권리"]'::jsonb, 3, '요양보호사 채용과정에서의 평등권 침해를 확인하는 문제입니다.', NULL, '{"1": "자유권은 개인의 기본적인 자유를 의미하며, 이 상황과는 관계가 없습니다.\n[정답]", "3": "평등권은 모든 사람들이 동등하게 대우받아야 함을 의미하며, 이 경우 나이에 따른 차별이 해당됩니다.", "2": "참정권은 투표와 관련된 권리이며, 여기서는 관련이 없습니다.", "4": "신체적 안정 보장 권리는 신체적 안전과 관련된 권리로, 이번 상황과는 다소 차이가 있습니다.", "5": "휴식 및 여가 보장 권리는 근로자의 권리로, 현재의 상황에서는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc bệnh nhân", "def_ko": "돌봄 서비스를 제공하는 사람", "def_vi": "Người cung cấp dịch vụ chăm sóc"}, {"term_ko": "채용", "term_vi": "Tuyển dụng", "def_ko": "새로운 직원을 뽑는 과정", "def_vi": "Quy trình chọn nhân viên mới"}, {"term_ko": "기관장", "term_vi": "Giám đốc cơ sở", "def_ko": "기관의 최고 책임자", "def_vi": "Người chịu trách nhiệm cao nhất của cơ sở"}, {"term_ko": "침해", "term_vi": "Xâm phạm", "def_ko": "권리나 자유를 방해하는 것", "def_vi": "Việc cản trở quyền hoặc tự do"}, {"term_ko": "평등권", "term_vi": "Quyền bình đẳng", "def_ko": "모든 사람에게 동등하게 권리를 보장하는 것", "def_vi": "Đảm bảo quyền lợi cho mọi người một cách công bằng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (189, '4', '다음 상황에서 요양보호사가 침해받은 권리로 옳은 것은?• 인지장애 어르신을 돌보느라 점심시간도 없이 일을 하고, 퇴근 시간 이후에도 초과수당 없이 근무를 하였다.', '["평등 관련 권리", "자유 관련 권리", "노동 관련 권리", "문화 관련 권리", "교육 관련 권리"]'::jsonb, 3, '요양보호사의 권리 침해 상황을 이해하고, 이를 바탕으로 올바른 권리 개념을 구분하도록 하는 데 그 의도가 있다.', NULL, '{"1": "평등 관련 권리는 개별적 차별을 금하는 기본적인 원칙이지만, 여기서는 적용되지 않는다.", "2": "자유 관련 권리는 선택의 자유를 포함하나, 주어진 상황에서는 업무 강제가 문제가 된다.\n[정답]", "3": "노동 관련 권리는 근로자의 근무 조건과 관련되며, 초과 근무와 초과수당의 문제에 해당하여 이 상황에 적절하다.", "4": "문화 관련 권리는 개인의 문화적 표현과 생활 방식을 보호하지만, 이 사례와는 관계가 없다.", "5": "교육 관련 권리는 학습 권리를 말하며, 여기서는 관련성이 없다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 직업", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "침해", "term_vi": "Xâm phạm", "def_ko": "권리가 침해당하는 것", "def_vi": "Bị xâm phạm quyền"}, {"term_ko": "퇴근", "term_vi": "Về nhà", "def_ko": "근무를 마치고 집으로 돌아감", "def_vi": "Về nhà sau khi làm việc"}, {"term_ko": "초과근무", "term_vi": "Làm thêm giờ", "def_ko": "정해진 근무 시간을 초과하여 일하는 것", "def_vi": "Làm việc quá giờ quy định"}, {"term_ko": "초과수당", "term_vi": "Trả thêm", "def_ko": "초과근무에 대해 추가로 지급되는 급여", "def_vi": "Tiền lương trả thêm cho giờ làm thêm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (188, '4', '다음 상황에서 요양보호사가 침해받은 권리로 옳은 것은?• 노인주거 시설에서 시설 내 종교활동이 있을 때마다 요양보호사들에게 종교 행사 활동 및 종교를 강요한다.', '["평등권", "자유권", "노동 관련 권리", "문화 관련 권리", "교육 관련 권리"]'::jsonb, 2, '요양보호사가 침해받는 권리와 관련된 내용을 이해하고, 올바른 선택지를 고르는지 확인하기 위한 문제이다.', NULL, '{"1": "평등권은 모든 사람이 차별 없이 대우받아야 한다는 권리이다.\n[정답]", "2": "자유권은 개인이 자유롭게 행동할 수 있는 권리로, 종교 활동 등에 강요받지 않아야 한다.", "3": "노동 관련 권리는 근로자가 직장에서 부당한 대우를 받지 않아야 한다는 권리이다.", "4": "문화 관련 권리는 개인의 문화적 권리를 보호하는 것이지만, 이 상황에서는 직접적인 관련이 없다.", "5": "교육 관련 권리는 교육을 받을 권리로, 이 상황과는 무관하다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "종교", "def_ko": "돌보기 간호사", "def_vi": "tôn giáo"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (187, '4', '요양보호사의 상담 및 대체인력 지원을 위한 사업을 하는 기관으로 옳은 것은?', '["근로복지공단", "산업안전 보건공단", "장기요양요원지원센터", "요양보호협회", "노인장기요양보험 공단"]'::jsonb, 3, '요양보호사와 관련된 상담 및 지원 기관을 이해하고 있는지를 묻는 문제입니다.', NULL, '{"1": "근로복지공단: 근로자의 권리 보호와 복지 향상을 위한 기관입니다. 요양보호사와는 직접적으로 연관이 없습니다.", "2": "산업안전 보건공단: 산업안전 및 보건관련 사업을 하는 기관입니다. 요양보호사와 관련된 지원은 아닙니다.\n[정답]", "3": "장기요양요원지원센터: 요양보호사 및 대체인력 지원을 위한 사업을 하는 기관입니다.", "4": "요양보호협회: 요양보호사들을 위한 협회이나, 지원 기관은 아닙니다.", "5": "노인장기요양보험 공단: 노인 장기요양에 관한 보험을 운영하는 기관으로, 직접적인 상담 지원과는 거리가 있습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (186, '4', '요양보호사의 근로계약서에 명시해야 할 내용으로 옳은 것은?', '["기관의 회계기준", "표준서비스의 분류", "임금의 구성 항목", "직원 채용의 과정", "장기요양 인정번호"]'::jsonb, 3, '요양보호사 근로계약에 포함되어야 할 필수적인 내용을 확인하기 위함입니다.', NULL, '{"1": "기관의 회계기준은 근로계약서의 필수 항목이 아닙니다.", "2": "표준서비스의 분류도 계약서에 명시되지 않습니다.\n[정답]", "3": "임금의 구성 항목은 근로계약서에 반드시 포함되어야 하는 내용입니다.", "4": "직원 채용의 과정은 계약서와 관련이 없습니다.", "5": "장기요양 인정번호 또한 계약서의 필수 사항이 아닙니다."}'::jsonb, '[{"term_ko": "근로계약서", "term_vi": "Hợp đồng lao động", "def_ko": "고용 계약 문서", "def_vi": "Tài liệu hợp đồng lao động"}, {"term_ko": "명시", "term_vi": "Chỉ định", "def_ko": "구체적으로 표시하다", "def_vi": "chỉ rõ"}, {"term_ko": "임금", "term_vi": "Tiền lương", "def_ko": "급여", "def_vi": "tiền công"}, {"term_ko": "구성 항목", "term_vi": "Mục cấu thành", "def_ko": "구성 요소", "def_vi": "thành phần"}, {"term_ko": "장기요양", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기 요양", "def_vi": "chăm sóc lâu dài"}, {"term_ko": "인정번호", "term_vi": "Số hiệu công nhận", "def_ko": "인증번호", "def_vi": "mã số chứng nhận"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (185, '4', '다음에 해당하는 요양보호사의 권리를 보장하는 법으로 옳은 것은?• 서비스 제공 중 요양보호사가 보호자에게 폭언 및 신체폭력의 위협을 받아 안전상의 이유로 업무를 중단하였을 때, 기관장은 요양보호사에게 해고를 하거나 그밖에 불리한 처우를 하여서는 안 된다.', '["노인복지법", "근로기준법", "산업안전보건법", "노인장기요양보험법", "산업재해보상보험법"]'::jsonb, 3, '요양보호사의 권리를 보장하는 법에 대한 이해를 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "노인복지법: 노인에 대한 기본적인 복지 서비스를 규정하는 법입니다.\n[정답]", "2": "근로기준법: 근로자의 기본적인 권리와 조건을 규정하는 법이나, 이 경우 특정 상황과 관련성 낮음입니다.", "3": "산업안전보건법: 근로자가 안전하게 근무할 수 있는 환경을 보장하기 위한 법입니다.", "4": "노인장기요양보험법: 노인 요양 서비스를 제공하는 제도에 대한 법령입니다.", "5": "산업재해보상보험법: 산업재해에 대한 보상을 규정하는 법입니다."}'::jsonb, '[{"term_ko": "권리", "term_vi": "요양보호사", "def_ko": "권리(한국어)  권 lợi: quyền lợi(베트남어)", "def_vi": "요양보호사(한국어)  Nhân viên chăm sóc: nhân viên chăm sóc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (184, '4', '『산업재해보상보험법』에 따른 근로자 보호의 내용으로 옳은 것은?', '["보험급여는 채권자가 압류할 수 있다.", "보험급여를 받을 권리는 2년간 유효하다.", "산업재해를 당했다는 이유로 해고할 수 없다.", "보험급여는 조세로 적용되어 세금을 부과한다.", "사업장이 폐업된 경우는 장애급여를 받지 못한다."]'::jsonb, 3, '산업재해보상보험법에 따른 근로자의 권리와 보호조치를 이해하고 있는지를 평가하는 문제입니다.', NULL, '{"1": "보험급여는 채권자가 압류할 수 없습니다.\n[정답]", "3": "산업재해를 당했다는 이유로 해고할 수 없습니다.", "2": "보험급여를 받을 권리는 2년간 유효하지 않고, 특정 조건에 따라 연장될 수 있습니다.", "4": "보험급여는 조세가 아닌 사회보험으로 적용되어 세금이 부과되지 않습니다.", "5": "사업장이 폐업된 경우에도 일정 조건 하에 장애급여를 받을 수 있습니다."}'::jsonb, '[{"term_ko": "산업재해", "term_vi": "Tai nạn nghề nghiệp", "def_ko": "사고 nghề nghiệp(한국어)", "def_vi": "Tai nạn xảy ra trong quá trình làm việc"}, {"term_ko": "보험급여", "term_vi": "Tiền bảo hiểm", "def_ko": "보험으로부터 지급받는 금전적 도움(한국어)", "def_vi": "Sự trợ giúp tài chính từ bảo hiểm"}, {"term_ko": "해고", "term_vi": "Sa thải", "def_ko": "근로칸에서 쫓겨나다(한국어)", "def_vi": "Bị đuổi việc"}, {"term_ko": "조세", "term_vi": "Thuế", "def_ko": "정부에 의해 부과되는 세금(한국어)", "def_vi": "Thuế áp dụng bởi chính phủ"}, {"term_ko": "장애급여", "term_vi": "Trợ cấp khuyết tật", "def_ko": "장애로 인해 지급되는 금융 지원(한국어)", "def_vi": "Hỗ trợ tài chính do khuyết tật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (183, '4', '다음 내용과 같은 성희롱 유형으로 옳은 것은?• 음탕하고 상스러운 이야기 • 옆에 앉아서 술을 따르라고 말함', '["언어적 성희롱", "시각적 성희롱", "사회적 성희롱", "육체적 성희롱", "물리적 성희롱"]'::jsonb, 1, '성희롱의 유형을 구분하는 능력을 평가하고자 함.', NULL, '{"1": "언어적 성희롱은 음탕하고 상스러운 이야기 등 언어를 통해 이루어지는 성희롱을 의미한다.\n[정답]", "2": "시각적 성희롱은 음란한 시각적 표현을 포함하는 성희롱이다.", "3": "사회적 성희롱은 사회적 관계를 이용한 성희롱을 의미한다.", "4": "육체적 성희롱은 신체적 접촉을 포함한다.", "5": "물리적 성희롱은 물리적인 힘이나 압력을 이용한 성희롱이다."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적으로 불쾌감을 주는 행동", "def_vi": "Hành động gây khó chịu về mặt tình dục"}, {"term_ko": "음탕", "term_vi": "Dâm đãng", "def_ko": "음란하고 추잡한", "def_vi": "Khiêu dâm và thô tục"}, {"term_ko": "상스러운", "term_vi": "Thô tục", "def_ko": "상징적이고 추잡한", "def_vi": "Mang tính biểu thị và khiếm nhã"}, {"term_ko": "언어적", "term_vi": "Bằng lời nói", "def_ko": "말을 통한", "def_vi": "Qua lời nói"}, {"term_ko": "시각적", "term_vi": "Bằng hình ảnh", "def_ko": "시각을 통한", "def_vi": "Qua hình ảnh"}, {"term_ko": "사회적", "term_vi": "Xã hội", "def_ko": "사회적 관계와 관련된", "def_vi": "Liên quan đến mối quan hệ xã hội"}, {"term_ko": "육체적", "term_vi": "Thân thể", "def_ko": "신체와 관련된", "def_vi": "Liên quan đến cơ thể"}, {"term_ko": "물리적", "term_vi": "Vật lý", "def_ko": "물리적인 힘과 관련된", "def_vi": "Liên quan đến sức mạnh vật lý"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (182, '4', '다음에 해당하는 성희롱 유형으로 옳은 것은?• 신체 일부를 밀착하거나 잡아당김 • 뒤에서 껴안기', '["시각적 성희롱", "언어적 성희롱", "육체적 성희롱", "사회적 성희롱", "위계적 성희롱"]'::jsonb, 3, '성희롱 유형에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "시각적 성희롱: 성적으로 부적절한 시각적 자극에 해당합니다.", "2": "언어적 성희롱: 성적 언어 표현이나 농담 등으로 상대방을 불쾌하게 하는 경우입니다.\n[정답]", "3": "육체적 성희롱: 타인의 신체를 밀착하거나 잡아당기는 등의 행동을 포함합니다.", "4": "사회적 성희롱: 직장 내 사회적 위치를 이용하여 성적 압박을 가하는 경우입니다.", "5": "위계적 성희롱: 권력 관계를 이용한 성희롱을 뜻합니다."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적인 행동이나 말로 불쾌감을 주는 것", "def_vi": "Hành động hoặc lời nói gây khó chịu về mặt tình dục"}, {"term_ko": "육체적", "term_vi": "Vật lý", "def_ko": "신체와 관련된", "def_vi": "Liên quan đến cơ thể"}, {"term_ko": "언어적", "term_vi": "Ngôn ngữ", "def_ko": "언어와 관련된", "def_vi": "Liên quan đến ngôn ngữ"}, {"term_ko": "위계", "term_vi": "Cấp bậc", "def_ko": "권력을 기반으로 한", "def_vi": "Dựa trên quyền lực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (181, '4', '대상자의 행위 중 시각적 성희롱에 해당하는 것으로 옳은 것은?', '["성적인 정보를 의도적으로 유포하기", "뒤에서 껴안기", "외모에 대한 성적인 평가", "음란한 내용의 편지 보내기", "옆에 앉으며 허리 잡아당기기"]'::jsonb, 4, '대상자의 행위 중 시각적 성희롱을 식별하는 능력을 평가하고자 하는 질문입니다.', NULL, '{"1": "성적인 정보를 의도적으로 유포하기는 전반적으로 성희롱에 해당하나, 시각적 성희롱에는 포함되지 않습니다.\n[정답]", "4": "음란한 내용의 편지 보내기는 명백한 시각적 성희롱으로 이해됩니다.", "2": "뒤에서 껴안기는 신체적 성희롱입니다.", "3": "외모에 대한 성적인 평가는 심리적 성희롱에 해당하지만, 시각적이지 않습니다.", "5": "옆에 앉으며 허리 잡아당기기는 신체적 성희롱입니다."}'::jsonb, '[{"term_ko": "행위", "term_vi": "Hành vi", "def_ko": "행동(한국어)", "def_vi": "hành động(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (180, '4', '성희롱 유형 (A)과 행위 (B)가 올바르게 연결된 것은?', '["언어적 성희롱 신체 일부를 잡아당김", "육체적 성희롱 성과 관련된 농담을 함", "육체적 성희롱 음란한 사진을 보여 줌", "시각적 성희롱 외모에 관한 성적인 비유를 함", "시각적 성희롱 성과 관련한 신체부위를 고의적으로 노출함"]'::jsonb, 5, '성희롱의 다양한 유형과 행동을 구분하여 올바르게 연결하는 능력을 평가하기 위함입니다.', NULL, '{"1": "언어적 성희롱은 주로 말이나 언어를 통해 이루어지는 것으로, 신체 일부를 잡아당기는 행위는 신체적 성희롱에 해당합니다.\n[정답]", "5": "시각적 성희롱은 성적으로 노출된 신체부위를 의도적으로 드러내는 행위로, 성과 관련한 신체부위를 고의적으로 노출하는 것은 올바른 연결입니다.", "3": "육체적 성희롱에서는 음란한 사진을 보여주는 경우가 해당하지만, 이는 시각적 성희롱의 예로 볼 수 있습니다.", "4": "외모에 관한 성적인 비유는 언어적 성희롱으로 분류됩니다.", "2": "성과 관련된 농담은 언어적 성희롱의 일종입니다."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적 수치를 느끼게 하는 행위", "def_vi": "Hành vi gây cảm giác xúc phạm tình dục"}, {"term_ko": "행위", "term_vi": "Hành động", "def_ko": "행동", "def_vi": "Hành vi"}, {"term_ko": "언어적", "term_vi": "Bằng lời", "def_ko": "말로", "def_vi": "Bằng ngôn ngữ"}, {"term_ko": "육체적", "term_vi": "Thân thể", "def_ko": "신체적", "def_vi": "Cơ thể"}, {"term_ko": "시각적", "term_vi": "Thị giác", "def_ko": "시각적", "def_vi": "Thị giác"}, {"term_ko": "외모", "term_vi": "Ngoại hình", "def_ko": "외관", "def_vi": "Hình thức"}, {"term_ko": "비유", "term_vi": "So sánh", "def_ko": "비유", "def_vi": "So sánh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (179, '4', '대상자로부터 요양보호사가 성희롱을 당했을 때 장기요양기관장의 대처 방법으로 옳은 것은?', '["대상자를 다른 요양기관으로 전원시킨다.", "대상자 가족에게 시정해줄 것을 요구한다.", "기관장이 판단하에 요양보호사를 조리 업무에 배치시킨다.", "대상자가 원하면 성희롱 예방교육을 제공한다.", "요양보호사에게 심리치료가 필요하다고 판단되면 기관장이 직접 치료한다."]'::jsonb, 2, '요양보호사와 대상자 간의 성희롱 사건 발생 시 기관장이 어떻게 대처해야 하는지를 묻는 문제입니다.', NULL, '{"1": "대상자를 다른 요양기관으로 전원시키는 것은 문제의 본질을 해결하지 못합니다.\n[정답]", "2": "대상자 가족에게 시정해줄 것을 요구하는 것은 올바른 대처 방법입니다.", "3": "기관장이 판단하에 요양보호사를 조리 업무에 배치하는 것은 적절하지 않습니다.", "4": "대상자가 원하면 성희롱 예방교육을 제공하는 것은 필요하지만, 이러한 상황에서는 즉각적인 조치가 우선입니다.", "5": "요양보호사에게 심리치료가 필요하다고 판단되면 기관장이 직접 치료하는 것은 부적절합니다."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적 언행으로 상대방을 괴롭히는 행위", "def_vi": "Hành vi làm phiền người khác bằng cách nói hoặc hành động liên quan đến tình dục"}, {"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "요양 서비스를 제공하는 곳", "def_vi": "Nơi cung cấp dịch vụ chăm sóc"}, {"term_ko": "대상자", "term_vi": "Người nhận dịch vụ", "def_ko": "요양 서비스를 받는 사람", "def_vi": "Người nhận dịch vụ chăm sóc"}, {"term_ko": "기관장", "term_vi": "Giám đốc", "def_ko": "기관의 책임자", "def_vi": "Người đứng đầu cơ sở"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (178, '4', '요양보호사가 상습적으로 성희롱을 당했을 때 대처 방법으로 옳은 것은?', '["대상자에게 1년에 한 번씩 성폭력 예방교육을 한다.", "몰래 녹취하거나 일자를 작성한다.", "요양보호사는 외부 전문기관에 문의 및 상담을 한다.", "보호자에게 연락하고 서비스를 중단한다.", "요양보호사의 업무를 주방보조로 변경한다."]'::jsonb, 3, '요양보호사가 성희롱을 당했을 때의 올바른 대처 방안을 묻는 문제입니다.', NULL, '{"1": "성폭력 예방교육은 중요하지만, 1년에 한 번씩 교육하는 것만으로는 대처할 수 없다.\n[정답]", "2": "몰래 녹취하거나 일자를 작성하는 것은 일부 상황에서 도움이 될 수 있지만, 전문기관에 상담하는 것이 가장 중요하다.", "3": "외부 전문기관에 문의 및 상담하는 것은 올바른 대처 방법이다.", "4": "보호자에게 연락하고 서비스를 중단하는 것은 상황에 따라 다르지만, 직접적인 해결에는 도움이 되지 않는다.", "5": "업무를 주방보조로 변경하는 것은 문제를 해결하는 방법이 아니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인을 돌보는 전문 직종", "def_vi": "Nghề chuyên chăm sóc người già"}, {"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "성적인 괴롭힘", "def_vi": "Hành vi gây khó chịu về mặt tình dục"}, {"term_ko": "상습적", "term_vi": "Thường xuyên", "def_ko": "반복적인", "def_vi": "Lặp lại"}, {"term_ko": "대처", "term_vi": "Xử lý", "def_ko": "대응하다", "def_vi": "Đối phó"}, {"term_ko": "전문기관", "term_vi": "Cơ quan chuyên môn", "def_ko": "전문적인 기관", "def_vi": "Tổ chức chuyên nghiệp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (177, '4', '시설에서 대상자가 다른 대상자를 성희롱하는 것을 발견하였을 때 대처 방법으로 옳은 것은?', '["큰 소리로 단호하게 꾸짖는다.", "대상자의 행동을 못 본 척한다.", "가족에게 알리고 퇴소시킨다.", "동료 요양보호사와 대처 방법을 의논한다.", "행이를 중단시키고 시설장에게 즉시 알린다."]'::jsonb, 5, '시설에서의 성희롱 사건 발생 시 적절한 대처 방법을 알고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "큰 소리로 단호하게 꾸짖는 것은 상황을 악화시킬 수 있으므로 부적절합니다.\n[정답]", "5": "행위를 중단시키고 시설장에게 즉시 알리는 것이 가장 적절한 대처 방법입니다.", "2": "대상자의 행동을 못 본 척하는 것은 문제를 방치하는 것이므로 바람직하지 않습니다.", "3": "가족에게 알리고 퇴소시키는 것은 상황을 바로잡는 것이 아닌, 피해자를 더 위험에 처할 수 있는 방법입니다.", "4": "동료 요양보호사와 대처 방법을 의논하는 것은 좋지만, 즉각적인 행동이 필요한 상황에서 지체되는 것은 문제입니다."}'::jsonb, '[{"term_ko": "성희롱", "term_vi": "Quấy rối tình dục", "def_ko": "부적절한 성적 언행(한국어)", "def_vi": "Những hành vi lời nói không thích hợp về tình dục(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (176, '4', '요양보호사의 윤리적 태도로 옳은 것은?', '["수급자 부재 시 들어가지 말고, 다음 방문일을 메모해둔다.", "보호자가 원하는 대로 서비스를 해준다.", "요양보호사와 같은 종교를 가진 대상자에게 더 잘해준다.", "업무상 알게 된 대상자의 비밀을 시설장과 공유한다.", "대상자의 동의 없이 오래된 물건은 버린다."]'::jsonb, 1, '요양보호사의 윤리적 태도에 대해 이해하고 올바른 태도를 선택하도록 유도하는 문제입니다.', NULL, '{"1": "수급자가 부재할 때 다음 방문일을 메모하는 것은 윤리적으로 올바른 행동입니다.\n[정답]", "2": "보호자의 요청이 무조건적으로 수용되는 것은 윤리적이지 않습니다.", "3": "특정 종교를 가진 대상자에게만 특별히 대하는 것은 공정하지 않으며 윤리적이지 않습니다.", "4": "업무상 알게 된 비밀은 대상자와의 신뢰를 저해하므로 비공유가 바람직합니다.", "5": "대상자의 동의 없이 물건을 버리는 것은 권리를 침해할 수 있습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌보는 사람", "def_vi": "Người chăm sóc cho người khác"}, {"term_ko": "윤리적", "term_vi": "Đạo đức", "def_ko": "도덕적인", "def_vi": "Liên quan đến đúng sai"}, {"term_ko": "수급자", "term_vi": "Người nhận dịch vụ", "def_ko": "서비스 받는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "비밀", "term_vi": "Bí mật", "def_ko": "은밀한 정보", "def_vi": "Thông tin riêng tư"}, {"term_ko": "동의", "term_vi": "Đồng ý", "def_ko": "허락", "def_vi": "Sự cho phép"}, {"term_ko": "물건", "term_vi": "Đồ vật", "def_ko": "사물", "def_vi": "Vật phẩm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (175, '4', '다음 상황에서 직업윤리를 준수한 요양보호사의 태도로 옳은 것은?• 서비스 제공 중 대상자의 전화통화 내용을 듣게 된 요양보호사는 배우자의 외도 사실을 알게 되었다.', '["대상자를 공감하며 위로한다.", "다른 대상자에게 이야기한다.", "동료 요양보호사에게 전달한다.", "대상자에게 외도 사유를 묻는다.", "비밀을 유지하고 내색하지 않는다."]'::jsonb, 5, '요양보호사로서 직업윤리를 유지하고 비밀을 지켜야 하는 상황을 이해하는 것.', NULL, '{"1": "대상자를 공감하며 위로하는 것은 긍정적이나, 개인적인 비밀을 알게 된 상황에서 적절하지 않다.\n[정답]", "5": "비밀을 유지하고 내색하지 않는 것이 올바른 직업윤리의 태도이다.", "2": "다른 대상자에게 이야기하는 것은 직업윤리에 반하는 행위이다.", "3": "동료 요양보호사에게 전달하는 것도 비밀을 누설하는 행위이므로 옳지 않다.", "4": "대상자에게 외도 사유를 묻는 것은 사생활 침해가 된다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업에서의 도덕적 원칙", "def_vi": "Nguyên tắc đạo đức trong công việc"}, {"term_ko": "비밀", "term_vi": "Bí mật", "def_ko": "타인에게 알려지지 않도록 숨기는 것", "def_vi": "Điều không được tiết lộ cho người khác"}, {"term_ko": "공감", "term_vi": "Đồng cảm", "def_ko": "감정을 이해하고 함께 느끼는 것", "def_vi": "Hiểu và cảm nhận cảm xúc của người khác"}, {"term_ko": "사생활", "term_vi": "Cuộc sống riêng tư", "def_ko": "개인의 사적인 생활", "def_vi": "Cuộc sống cá nhân của mỗi người"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (174, '4', '다음 사례에서 요양보호사가 준수한 직업윤리로 옳은 것은?• 방문요양 시 대상자가 손주의 간식을 만들어 달라고 부탁하였을 때, 급여내용에 없어 서비스를 제공할 수 없다고 정중히 거절함', '["협력하려는 태도", "자기계발을 하려는 태도", "인권을 옹호하려는 태도", "전문상담가로서의 태도", "규정에 따라 업무를 수행하려는 태도"]'::jsonb, 5, '요양보호사가 제공해야 하는 서비스를 이해하고, 직업윤리를 준수하는 태도를 평가하기 위함입니다.', NULL, '{"1": "협력하려는 태도: 요양보호사가 협력을 하는 것으로 오해할 수 있지만, 서비스 제공의 원칙을 따르는 것이 중요합니다.\n[정답]", "5": "규정에 따라 업무를 수행하려는 태도: 요양보호사가 제공할 수 있는 서비스의 범위를 이해하고 이를 준수해서 탈선을 막는 행동입니다.", "2": "자기계발을 하려는 태도: 요양보호사의 개인적인 성장과 개발은 중요하지만, 이 사례와는 관련이 없습니다.", "3": "인권을 옹호하려는 태도: 인권 존중은 중요한 가치이나, 이 사례의 주된 내용은 아닙니다.", "4": "전문상담가로서의 태도: 전문 상담가는 다른 역할을 수행하기 때문에 이 사례와 부합하지 않습니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업 생활에서 지켜야 할 기본적인 도리와 규범", "def_vi": "Những quy tắc và quy định cơ bản cần tuân theo trong công việc"}, {"term_ko": "규정", "term_vi": "Quy định", "def_ko": "특정한 기준이나 규칙", "def_vi": "Tiêu chuẩn hoặc quy tắc cụ thể"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "제공되는 지원이나 도움", "def_vi": "Hỗ trợ hoặc giúp đỡ được cung cấp"}, {"term_ko": "협력", "term_vi": "Hợp tác", "def_ko": "함께 일하는 것", "def_vi": "Làm việc cùng nhau"}, {"term_ko": "자기계발", "term_vi": "Phát triển bản thân", "def_ko": "자신의 능력을 개발하는 것", "def_vi": "Phát triển khả năng của bản thân"}, {"term_ko": "인권", "term_vi": "Nhân quyền", "def_ko": "사람으로서의 권리", "def_vi": "Quyền của con người"}, {"term_ko": "전문상담가", "term_vi": "Cố vấn chuyên nghiệp", "def_ko": "전문가로서 상담하는 사람", "def_vi": "Người tư vấn ở tư cách chuyên gia"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (173, '4', '대상자가 연말을 앞두고 요양보호사에게 감사의 의미로 상품권을 주고자 할 때 요양보호사의 대처 방법으로 옳은 것은?', '["\"정말 왜 이러세요!\"라고 정색하며 거절한다.", "\"고맙습니다.\"라고 하며 받은 후 다음 날 돌려준다.", "\"이런 것 받으면 안 됩니다. 마음만 받겠습니다.\"라고 정중히 거절한다.", "\"다음에 좋아하는 케이크를 사다 드릴게요.\"라며 받는다.", "\"마침 센터에서 기부행사가 있는데 잘됐네요.\"라며 받는다."]'::jsonb, 3, '사례를 통해 요양보호사가 윤리적 기준에 따라 대처하는 방법을 익히도록 하는 것이다.', NULL, '{"1": "정색하며 거절하는 것은 부적절한 태도이다.\n[정답]", "2": "상품권을 받은 후 다음 날 돌려주는 것은 마음을 상하게 할 수 있다.", "3": "''이런 것 받으면 안 됩니다. 마음만 받겠습니다.''라고 정중히 거절하는 것이 바람직하다.", "4": "''다음에 좋아하는 케이크를 사다 드릴게요.''라고 하면 부담스럽게 느낄 수 있다.", "5": "기부행사와 관련된 언급은 상황에 따라 부적절할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "환자나 고객", "def_vi": "bệnh nhân hoặc khách hàng"}, {"term_ko": "상품권", "term_vi": "Thẻ quà tặng", "def_ko": "상점에서 사용할 수 있는 카드 형식의 쿠폰", "def_vi": "thẻ coupon sử dụng tại cửa hàng"}, {"term_ko": "대처", "term_vi": "Đối phó", "def_ko": "대응 방법", "def_vi": "phương pháp ứng xử"}, {"term_ko": "정중히", "term_vi": "Lịch sự", "def_ko": "예의 바르게", "def_vi": "một cách tôn trọng"}, {"term_ko": "부담스럽다", "term_vi": "Cảm thấy áp lực", "def_ko": "부담을 주다", "def_vi": "gây áp lực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (172, '4', '시설에서 요양보호사가 지켜야 할 직업윤리로 옳은 것은?', '["타 직종과의 협력보다 업무의 신속성을 중시한다.", "서비스 제공 시 시설장의 의사결정을 우선한다.", "대상자가 실수를 하면 질책하여 재발을 방지한다.", "자신의 종료를 권유하기 위해 친절을 베푼다.", "보수교육을 통해 전문적 지식과 기술을 익힌다."]'::jsonb, 5, '시설에서 요양보호사가 가져야 할 올바른 직업윤리에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "타 직종과의 협력보다 업무의 신속성을 중시한다. 이 선택지는 직업윤리와 할당된 책임을 소홀히 할 수 있기 때문에 옳지 않습니다.\n[정답]", "5": "보수교육을 통해 전문적 지식과 기술을 익힌다. 이는 요양보호사가 직업적 윤리를 지키기 위해 필요한 중요한 요소입니다.", "2": "서비스 제공 시 시설장의 의사결정을 우선한다. 이는 협업보다 개인의 의사결정이 중요하여 바람직하지 않습니다.", "3": "대상자가 실수를 하면 질책하여 재발을 방지한다. 이는 긍정적인 피드백 대신 부정적인 접근으로 해결하려는 것이기 때문에 적절하지 않습니다.", "4": "자신의 종료를 권유하기 위해 친절을 베푼다. 이는 업무의 본질이 아닌 개인의 이익을 위해 친절을 베푸는 것이기 때문에 올바르지 않습니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업에서 지켜야 할 도리와 규범", "def_vi": "Nghĩa vụ và quy tắc cần tuân theo trong nghề nghiệp"}, {"term_ko": "보수교육", "term_vi": "Đào tạo bổ sung", "def_ko": "지속적인 교육을 통해 기술과 지식을 보완하는 것", "def_vi": "Bổ sung kỹ năng và kiến thức thông qua việc học liên tục"}, {"term_ko": "서비스 제공", "term_vi": "Cung cấp dịch vụ", "def_ko": "특정 고객에게 서비스를 제공하는 것", "def_vi": "Cung cấp dịch vụ cho khách hàng cụ thể"}, {"term_ko": "시설장", "term_vi": "Giám đốc cơ sở", "def_ko": "특정 시설의 관리자", "def_vi": "Người quản lý một cơ sở cụ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (171, '4', '요양보호사가 지켜야 할 직업윤리로 옳은 것은?', '["대상자와 상호 대등한 관계임을 인식한다.", "계획된 것보다 시간을 줄여 서비스를 제공한다.", "대상자의 성별에 따라 서비스 내용을 달리한다.", "대상자 부재 시에 서비스를 제공하고 메모를 남긴다.", "타 직종과의 협력보다 업무의 신속성을 중요시한다."]'::jsonb, 1, '요양보호사가 갖추어야 할 직업윤리에 대한 이해를 평가하기 위한 문제이다.', NULL, '{"1": "대상자와 상호 대등한 관계임을 인식하는 것은 요양보호사의 기본적 윤리이다.\n[정답]", "2": "계획된 것보다 시간을 줄여 서비스를 제공하는 것은 윤리에 어긋난다.", "3": "대상자의 성별에 따라 서비스 내용을 달리하는 것은 차별이 될 수 있다.", "4": "대상자 부재 시에 서비스를 제공하고 메모를 남기는 것은 신뢰성을 떨어뜨릴 수 있다.", "5": "타 직종과의 협력보다 업무의 신속성을 중요시하는 것은 협업의 중요성을 간과하는 것이다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "대상자", "def_ko": "직업에서 지켜야 할 도덕적 원칙(직 nghiệp đạo đức)", "def_vi": "서비스를 받는 사람(người nhận dịch vụ)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (170, '4', '요양보호사의 직업윤리 원칙으로 옳은 것은?', '["기관의 결정을 우선시한다.", "보호자의 판단대로 서비스를 제공한다.", "대상자와 수직적 관계를 유지한다.", "복지용구가 필요하다고 하면 대여해준다.", "제공된 서비스 내용은 정확히 기록한다."]'::jsonb, 5, '요양보호사로서의 직업윤리 원칙 중 올바른 선택을 찾도록 하는 문제입니다.', NULL, '{"1": "기관의 결정을 우선시하는 것은 직업윤리가 아닙니다.", "2": "보호자의 판단대로 서비스를 제공하는 것은 윤리적으로 문제가 될 수 있습니다.", "3": "대상자와 수직적 관계를 유지하는 것은 바람직하지 않습니다.\n[정답]", "4": "복지용구가 필요하다고 하면 대여해주는 것은 윤리적입니다.", "5": "제공된 서비스 내용은 정확히 기록해야 합니다."}'::jsonb, '[{"term_ko": "직업윤리", "term_vi": "Nguyên tắc đạo đức nghề nghiệp", "def_ko": "직업 활동에서 지켜야 할 도덕적 원칙", "def_vi": "Nguyên tắc đạo đức cần tuân thủ trong hoạt động nghề nghiệp"}, {"term_ko": "보호자", "term_vi": "Người bảo vệ", "def_ko": "환자의 보호자", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "복지용구", "term_vi": "Thiết bị phúc lợi", "def_ko": "복지 목적으로 사용하는 기구", "def_vi": "Công cụ sử dụng cho mục đích phúc lợi"}, {"term_ko": "수직적 관계", "term_vi": "Mối quan hệ theo chiều dọc", "def_ko": "위아래 관계", "def_vi": "Quan hệ lên xuống"}, {"term_ko": "정확히", "term_vi": "Chính xác", "def_ko": "틀림없이, 잘못되지 않게", "def_vi": "Không sai, không nhầm lẫn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (169, '4', '다음의 상황에서 요양보호사의 대처방법으로 옳은 것은?• 동료 요양보호사가 개인적인 일이 있을 때마다 서비스를 대신 제공해줄 것을 요청한다.', '["고민해 보겠다고 하며 대답을 피한다.", "직업윤리에 위배된다며 거절한다.", "다른 동료 요양보호사를 연결해준다.", "동료 요양보호사에게 별도의 수고비를 요구한다.", "개인 용무가 있을 때마다 서로의 부탁을 들어주고자 한다."]'::jsonb, 2, '요양보호사의 직업적 윤리와 동료 간의 책임에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "고민해 보겠다고 하며 대답을 피한다는 것은 회피하는 태도로, 적절하지 않습니다.\n[정답]", "2": "직업윤리에 위배된다며 거절하는 것이 올바른 대처입니다.", "3": "다른 동료 요양보호사를 연결해주는 것은 책임을 회피하는 것으로 판단됩니다.", "4": "동료 요양보호사에게 별도의 수고비를 요구하는 것은 비윤리적입니다.", "5": "개인 용무가 있을 때마다 서로의 부탁을 들어주겠다는 것은 비정상적인 상호 의존 관계를 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "대처방법", "term_vi": "Cách ứng phó", "def_ko": "대처 방식(한국어)", "def_vi": "Cách xử lý tình huống"}, {"term_ko": "직업윤리", "term_vi": "Đạo đức nghề nghiệp", "def_ko": "직업의 도리와 가치(한국어)", "def_vi": "Đạo đức trong công việc"}, {"term_ko": "동료", "term_vi": "Đồng nghiệp", "def_ko": "같은 직장에서 일하는 사람(한국어)", "def_vi": "Người làm cùng nghề"}, {"term_ko": "수고비", "term_vi": "Phí công sức", "def_ko": "추가 비용(한국어)", "def_vi": "Chi phí thêm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (168, '4', '재가서비스 중 치매 대상자의 증상이 악화되어 서서 대변을 보는 행동을 보일 때 대처방법으로 옳은 것은?', '["식사량을 줄이겠다고 한다.", "서비스를 중단하겠다고 말한다.", "방으로 데려가 기저귀를 채운다.", "변화된 증상을 관할하여 기록한다.", "재가서비스 제공이 어렵다며 시설 입소를 유도한다."]'::jsonb, 4, '치매 대상자의 증상 악화에 따른 적절한 대처 방법을 이해하고 평가하는 것이다.', NULL, '{"1": "식사량을 줄이는 것은 증상 악화를 초래할 수 있다.\n[정답]", "4": "변화된 증상을 관찰하여 기록하는 것은 중요하며, 적절한 대처 방법이다.", "2": "서비스를 중단하는 것은 문제 해결에 도움이 되지 않는다.", "3": "기저귀를 채우는 것은 일시적인 대처일 뿐, 문제의 본질을 해결하지 않는다.", "5": "시설 입소를 유도하는 것은 섣부른 판단일 수 있다."}'::jsonb, '[{"term_ko": "재가서비스", "term_vi": "치매", "def_ko": "가정에서 제공되는 서비스(dịch vụ tại nhà)", "def_vi": "기억력, 사고, 행동의 기능이 저하되는 질병(người bị mất trí nhớ)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (167, '4', '대상자가 본인부담금 할인을 요구할 때 요양보호사의 대처방법으로 옳은 것은?', '["\"네, 시설장님과 의논해보고 말씀드릴게요.\"", "\"그럴 리가요? 다시 알아보시고 말씀해주세요.\"", "\"다른 대상자를 소개해 주시면 싸게 해 드릴게요.\"", "\"고민해보고 내일 말씀드릴게요.\"", "\"불법이라서 저희 센터에서는 할 수 없습니다.\""]'::jsonb, 5, '대상자가 본인부담금 할인 요구 시 요양보호사가 어떻게 대처해야 하는지에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "''시설장님과 의논해보겠다''는 답변은 책임 회피처럼 보일 수 있습니다.\n[정답]", "5": "''불법이라서 저희 센터에서는 할 수 없습니다.'' 이는 합법적인 차원에서 잘 대처한 경우입니다.", "2": "''그럴 리가요? 다시 알아보시고 말씀해주세요.''는 오히려 대화를 단절할 수 있습니다.", "3": "''다른 대상자를 소개해 주시면 싸게 해 드릴게요.''는 윤리적으로 문제가 될 수 있습니다.", "4": "''고민해보고 내일 말씀드릴게요.''는 결정을 미루는 것으로 부적절합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "환자, 수혜자", "def_vi": "Bệnh nhân, đối tượng được chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (166, '4', '다음 상황에서 요양보호사의 대처방법으로 옳은 것은?• 대상자가 고장난 휠체어를 바꾸고 싶은데 형편이 어렵다고 호소한다.', '["직접 구매하여 가져다준다.", "휠체어를 대여해 주고 사례금을 받는다.", "이용할 수 있는 서비스를 안내해준다.", "다른 대상자가 사용 중인 휠체어를 가져다준다.", "평소 알고 있는 업체에서 구매하도록 권유한다."]'::jsonb, 3, '대상자의 상황에서 요양보호사가 어떻게 도와줄 수 있는지를 평가함.', NULL, '{"1": "직접 구매하여 가져다주는 것은 경제적 부담을 초래할 수 있다.\n[정답]", "3": "이용할 수 있는 서비스를 안내해주는 것은 대상자의 권리를 존중하며, 필요에 따라 적절한 지원을 제공하는 방법이다.", "2": "휠체어를 대여해 주고 사례금을 받는 것은 비윤리적이다.", "4": "다른 대상자가 사용 중인 휠체어를 가져다주는 것은 적법하지 않으며 대상자에게 피해를 줄 수 있다.", "5": "평소 알고 있는 업체에서 구매하도록 권유하는 것은 대상자에게 강요하는 것으로 여겨질 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": null, "def_ko": "환자, người bệnh", "def_vi": null}, {"term_ko": "호소", "term_vi": null, "def_ko": "불만을 표현하다, kêu ca", "def_vi": null}, {"term_ko": "형편", "term_vi": null, "def_ko": "경제적 상황, tình hình tài chính", "def_vi": null}, {"term_ko": "대여", "term_vi": null, "def_ko": "잠시 사용하는 것, cho mượn", "def_vi": null}, {"term_ko": "서비스", "term_vi": null, "def_ko": "제공되는 도움, dịch vụ", "def_vi": null}, {"term_ko": "업체", "term_vi": null, "def_ko": "회사, cơ sở", "def_vi": null}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (165, '4', '재가센터에서 함께 일하고 있는 요양보호사가 서로의 부모님에게 교차서비스를 제공하는 것으로 처리하여 급여를 더 받자고 제안할 때 대처 방법으로 옳은 것은?', '["마찰을 파하기 위해 대응하지 않는다.", "윤리원칙에 어긋난다고 말하며 거부한다.", "제안을 수용할 만한 다른 요양보호사를 소개한다.", "어머니에게 교차서비스를 미리 설명한다.", "교차 서비스에 대해 주변에 비밀로 해 줄 것을 부탁한다."]'::jsonb, 2, '요양보호사의 윤리적 책임과 대처 방안에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "마찰을 파하기 위해 대응하지 않는다. - 대응하지 않는 것은 비윤리적 제안을 묵인하는 것이므로 바람직하지 않습니다.\n[정답]", "2": "윤리원칙에 어긋난다고 말하며 거부한다. - 윤리적 원칙을 지키는 것이 중요하며, 이를 통해 올바른 판단을 할 수 있습니다.", "3": "제안을 수용할 만한 다른 요양보호사를 소개한다. - 이는 윤리적 문제를 해결하기보다는 회피하는 방법일 뿐입니다.", "4": "어머니에게 교차서비스를 미리 설명한다. - 제안 자체가 비윤리적이므로 설명하는 것은 상황을 악화시킬 수 있습니다.", "5": "교차 서비스에 대해 주변에 비밀로 해 줄 것을 부탁한다. - 비밀을 부탁하는 것은 윤리적으로 잘못된 행동입니다."}'::jsonb, '[{"term_ko": "재가센터", "term_vi": "Trung tâm chăm sóc tại nhà", "def_ko": "가정에서 서비스를 제공하는 센터", "def_vi": "Trung tâm cung cấp dịch vụ tại nhà"}, {"term_ko": "교차서비스", "term_vi": "Dịch vụ chéo", "def_ko": "서로 다른 고객에 대한 서비스 제공", "def_vi": "Cung cấp dịch vụ cho khách hàng khác nhau"}, {"term_ko": "윤리", "term_vi": "Đạo đức", "def_ko": "도덕적 원칙", "def_vi": "Nguyên tắc đạo đức"}, {"term_ko": "급여", "term_vi": "Tiền lương", "def_ko": "보수, 급여", "def_vi": "Thù lao, lương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (164, '4', '보호자가 기저귀 재사용을 강요할 때 대처 방법으로 옳은 것은?', '["가족이 방문하는 날만 재사용을 한다.", "재사용할 수 없는 이유를 설명한다.", "오염 정도가 적으면 말려서 사용한다.", "대상자에게 알리고 서비스를 중단한다.", "보호자의 요구사항을 기록한 후 재사용한다."]'::jsonb, 2, '보호자가 기저귀 재사용을 강요할 때 올바른 대처 방법을 묻는 문제입니다.', NULL, '{"1": "가족이 방문하는 날만 재사용을 한다. 이는 상황을 피하는 방안으로, 바람직하지 않습니다.\n[정답]", "2": "재사용할 수 없는 이유를 설명한다. 이는 보호자에게 이해를 돕고 바른 결정을 유도하는 올바른 방법입니다.", "3": "오염 정도가 적으면 말려서 사용한다. 이는 위생적이지 않으므로 바람직하지 않습니다.", "4": "대상자에게 알리고 서비스를 중단한다. 이는 가장 극단적인 조치로, 다른 대안이 있을 때는 피해야 합니다.", "5": "보호자의 요구사항을 기록한 후 재사용한다. 이는 환자의 건강과 안전을 해칠 수 있습니다."}'::jsonb, '[{"term_ko": "보호자", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "환자가 착용하는 위생 용품", "def_vi": "Dụng cụ vệ sinh mà bệnh nhân mặc"}, {"term_ko": "재사용", "term_vi": "Tái sử dụng", "def_ko": "한번 사용한 것을 다시 사용하는 것", "def_vi": "Sử dụng lại cái gì đó đã được sử dụng một lần"}, {"term_ko": "오염", "term_vi": "Ô nhiễm", "def_ko": "더러워진 상태", "def_vi": "Tình trạng bị bẩn"}, {"term_ko": "설명하다", "term_vi": "Giải thích", "def_ko": "이유를 말하는 것", "def_vi": "Nói lý do"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (163, '4', '요양보호사의 근골격계 질환 발생 가능성을 줄이는 작업 환경 조성 방법으로 옳은 것은?', '["무거운 물건을 들고 이동한다.", "문턱을 설치하여 공간을 구분한다.", "거실 중앙에 얇은 매트를 깐다.", "바닥에 물을 뿌려 습도를 유지한다.", "야간 근무 시 통로에 조명을 켜둔다."]'::jsonb, 5, '요양보호사 근골격계 질환 예방을 위한 안전한 작업 환경 조성을 묻는 문제입니다.', NULL, '{"1": "무거운 물건을 들고 이동하는 것은 근골격계 질환을 유발할 수 있습니다.", "2": "문턱을 설치하면 이동 시 걸림돌이 되어 오히려 위험합니다.", "3": "거실 중앙에 얇은 매트를 깔면 걸려 넘어질 위험이 있습니다.", "4": "바닥에 물을 뿌리면 미끄러짐 사고의 원인이 될 수 있습니다.\n[정답]", "5": "야간 근무 시 통로에 조명을 켜두면 안전성을 높여 근골격계 질환을 예방합니다."}'::jsonb, '[{"term_ko": "근골격계", "term_vi": "Hệ cơ xương", "def_ko": "근육과 뼈로 구성된 신체의 구조", "def_vi": "Cấu trúc cơ thể bao gồm cơ và xương"}, {"term_ko": "작업", "term_vi": "Công việc", "def_ko": "일이나 행동을 수행하는 것", "def_vi": "Thực hiện công việc hoặc hành động"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주변의 상태나 상황", "def_vi": "Tình trạng hoặc tình huống xung quanh"}, {"term_ko": "예방", "term_vi": "Phòng ngừa", "def_ko": "미리 조치를 취하여 사고를 막는 것", "def_vi": "Thực hiện các biện pháp để ngăn chặn tai nạn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (162, '4', '요양보호사에게 나타날 수 있는 수근관 증후군에 관한 설명으로 옳은 것은?', '["밤중에 통증이 감소된다.", "손목을 굴곡시키면 통증이 감소된다.", "손목에서 팔꿈치까지 강직이 나타난다.", "손을 털면 저림과 통증이 완화될 수 있다.", "새끼손가락과 연결된 손바닥 감각이 둔해진다."]'::jsonb, 4, '수근관 증후군에 대한 이해를 확인하기 위한 문제입니다.', NULL, '{"1": "밤중에 통증이 감소되는 것은 잘못된 설명입니다. 수근관 증후군은 주로 밤에 증상이 심해지는 경향이 있습니다.\n[정답]", "4": "손을 털면 저림과 통증이 완화될 수 있다는 것은 수근관 증후군의 전형적인 증상입니다.", "2": "손목을 굴곡시키면 통증이 감소되는 것은 일반적으로 정확하지 않습니다. 오히려 통증이 증가할 수 있습니다.", "3": "손목에서 팔꿈치까지 강직이 나타난다는 것은 다른 문제로, 수근관 증후군과는 관련이 없습니다.", "5": "새끼손가락과 연결된 손바닥 감각이 둔해지는 것은 주로 외측신경과 관련 있으며, 수근관 증후군과는 다릅니다."}'::jsonb, '[{"term_ko": "수근관 증후군", "term_vi": "Hội chứng ống cổ tay", "def_ko": "손목에서 발생하는 압박으로 인한 신경 증상", "def_vi": "Vấn đề về thần kinh do áp lực ở cổ tay"}, {"term_ko": "감각", "term_vi": "Cảm giác", "def_ko": "느끼는 것", "def_vi": "Cảm nhận"}, {"term_ko": "주로", "term_vi": "Chủ yếu", "def_ko": "주된 형태로", "def_vi": "Dựa chủ yếu"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔", "def_vi": "Đau đớn"}, {"term_ko": "저림", "term_vi": "Tê", "def_ko": "감각이 둔해지는 상태", "def_vi": "Trạng thái cảm giác bị tê"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (161, '4', '요통을 예방하면서 물건을 들어 올리는 방법으로 옳은 것은?', '["물건을 몸에서 멀리 둔다.", "두 발을 모아 지지면을 좁힌다.", "몸의 무게중심을 높인다.", "무릎을 굽혀 자세를 낮춘다.", "방향을 바꿀 때는 허리를 돌린다."]'::jsonb, 4, '요통을 예방하는 올바른 물건 들어올리기 방법을 묻는 질문입니다.', NULL, '{"1": "물건을 몸에서 멀리 두는 것은 요통을 유발할 수 있습니다.\n[정답]", "4": "무릎을 굽혀 자세를 낮추면 하체의 힘을 이용하여 안전하게 물건을 들어올릴 수 있습니다.", "2": "두 발을 모아 지지면을 좁히면 균형이 불안정해질 수 있습니다.", "3": "몸의 무게중심을 높이는 것은 무게 중심의 불균형을 초래할 수 있습니다.", "5": "방향을 바꿀 때는 허리를 돌리는 것이 아니라 몸 전체를 회전해야 합니다."}'::jsonb, '[{"term_ko": "요통", "term_vi": "Đau lưng", "def_ko": "허리 통증(한국어)", "def_vi": "Cơn đau ở thắt lưng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (160, '4', '대상자의 체위를 변경하다가 손목을 삐어 통증이 있을 때 초기 관리 방법으로 옳은 것은?', '["손목을 가볍게 움직여 준다.", "통증부위를 심장보다 낮게 한다.", "손목부위에 압박붕대를 적용한다.", "손상 직후 손목부위에 온찜질을 한다.", "손목을 털면서 굽혔다 폈다 하는 운동을 한다."]'::jsonb, 3, '신체 부상 발생 시 초기 관리 방법에 대한 이해를 확인하고자 하는 문제입니다.', NULL, '{"1": "손목을 가볍게 움직이는 것은 통증이 있을 때 오히려 상태를 악화시킬 수 있습니다.\n[정답]", "3": "손목부위에 압박붕대를 적용하는 것은 부상을 관리하는 올바른 방법입니다.", "2": "통증부위를 심장보다 낮게 두는 것은 혈액 순환에 도움이 될 수 있지만 즉각적으로 적용해야 할 방법은 아닙니다.", "4": "손상 직후 손목부위에 온찜질을 하는 것은 부상 초기에는 적절하지 않습니다.", "5": "손목을 털면서 운동을 하는 것은 추가적인 부상을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "체위", "term_vi": "Vị trí", "def_ko": "상태(한국어)", "def_vi": "Trạng thái"}, {"term_ko": "손목", "term_vi": "Cổ tay", "def_ko": "팔목(한국어)", "def_vi": "Cổ tay"}, {"term_ko": "압박붕대", "term_vi": "Băng bó áp lực", "def_ko": "압박다친 것(한국어)", "def_vi": "Băng bó làm giảm trọng lượng"}, {"term_ko": "온찜질", "term_vi": "Chườm ấm", "def_ko": "따뜻한 찜질(한국어)", "def_vi": "Chườm ấm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (159, '4', '요양보호사의 근골격계 예방을 위한 스트레칭 시 주의사항으로 옳은 것은?', '["빠르게 움직인다.", "통증을 느낄 때까지 한다.", "동작과 동작 사이에 쉬지 않는다.", "상하좌우 균형 있게 교대로 스트레칭 한다.", "동작 시 호흡은 멈춘다."]'::jsonb, 4, '요양보호사의 근골격계 예방을 위한 올바른 스트레칭 방법을 이해하고 적용하는 능력을 평가하고자 함.', NULL, '{"1": "빠르게 움직인다: 부상의 위험이 있으므로 옳지 않음.", "2": "통증을 느낄 때까지 한다: 통증은 스트레칭의 지표가 아니므로 옳지 않음.", "3": "동작과 동작 사이에 쉬지 않는다: 휴식이 필요하므로 옳지 않음.\n[정답]", "4": "상하좌우 균형 있게 교대로 스트레칭 한다: 균형 있는 스트레칭은 근골격계 예방에 효과적임.", "5": "동작 시 호흡은 멈춘다: 호흡은 계속해야 하므로 옳지 않음."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인이나 장애인을 돌보는 전문가", "def_vi": "chuyên gia chăm sóc người già hoặc người khuyết tật"}, {"term_ko": "근골격계", "term_vi": "Hệ cơ xương khớp", "def_ko": "뼈와 근육으로 이뤄진 몸의 계통", "def_vi": "hệ thống cơ và xương trong cơ thể"}, {"term_ko": "스트레칭", "term_vi": "Stretching", "def_ko": "근육을 늘리는 운동", "def_vi": "bài tập kéo giãn cơ"}, {"term_ko": "균형", "term_vi": "Cân bằng", "def_ko": "대칭을 이루는 상태", "def_vi": "trạng thái đối xứng"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "신체에 느끼는 아픔", "def_vi": "cảm giác khó chịu trong cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (158, '4', '서비스 제공 중 요양보호사가 고열과 인후통이 있어 독감이 의심될 때 대처방법으로 옳은 것은?', '["요양보호 서비스를 중단한다.", "독갑예방 접종을 한다.", "주민자치센터에 신고한다.", "가글액으로 입안을 헹군다.", "사용하던 물품을 소독한다."]'::jsonb, 1, '요양보호사가 서비스를 제공하는 중에 고열과 인후통이 있을 경우 적절한 대처 방법을 알고 있는지를 파악하고자 하는 의도입니다.', NULL, '{"1": "요양보호 서비스를 중단하는 것이 옳습니다. 증상이 있는 상태에서 서비스를 지속할 경우 다른 환자에게 감염을 전파할 위험이 있습니다.\n[정답]", "2": "독감 예방 접종은 일반적으로 질병이 발병하기 전에 실시해야 하며, 현재 상태에서는 접근 방법이 아닙니다.", "3": "주민자치센터에 신고하는 것은 필요하지 않습니다.", "4": "가글액으로 입안을 헹구는 것은 증상을 완화할 수 있지만, 전염병 상황에서 기본적으로 필요한 조치가 아닙니다.", "5": "사용하던 물품을 소독하는 것은 필요할 수 있지만, 가장 중요한 것은 본인의 상태를 먼저 점검하고 서비스를 중단하는 것입니다."}'::jsonb, '[{"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "서비스(한국어)", "def_vi": "dịch vụ(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (157, '4', '폐결핵에 관한 설명으로 옳은 것은?', '["바이러스성 감염질환이다.", "스테로이드 약물 복용으로 예방할 수 있다.", "약물 복용 중 주기적인 간 기능 검사가 필요하다.", "치료 기간 중 증상이 사라지면 약물 복용을 중단한다.", "오전에 고열이 나고 오후에 열이 내리는 증상이 반복된다."]'::jsonb, 3, '폐결핵에 대한 기본 지식과 증상 및 치료에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "폐결핵은 세균에 의한 감염질환으로, 바이러스성이 아닙니다.\n[정답]", "3": "폐결핵 치료 중 약물 복용 환자는 간 기능 검사를 주기적으로 해야 합니다.", "2": "스테로이드 약물은 폐결핵의 예방에 효과적이지 않습니다.", "4": "치료 중 증상이 사라진 경우에도 약물 복용을 중단해서는 안 됩니다.", "5": "폐결핵의 고열 증상은 주로 오후에 열이 나고 저녁에 해열되는 경향이 있습니다."}'::jsonb, '[{"term_ko": "폐결핵", "term_vi": "Bệnh lao phổi", "def_ko": "폐에 발생하는 결핵 감염", "def_vi": "Nhiễm trùng lao xảy ra trong phổi"}, {"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "치료를 위한 화학물질", "def_vi": "Chất hóa học dùng để điều trị"}, {"term_ko": "주기적", "term_vi": "Định kỳ", "def_ko": "정기적으로 반복되는", "def_vi": "Lặp lại một cách đều đặn"}, {"term_ko": "간 기능 검사", "term_vi": "Xét nghiệm chức năng gan", "def_ko": "간의 건강을 평가하는 검사", "def_vi": "Kiểm tra tình trạng sức khỏe của gan"}, {"term_ko": "예방", "term_vi": "Phòng ngừa", "def_ko": "증상을 미리 막는 것", "def_vi": "Ngăn chặn triệu chứng xảy ra trước đó"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (156, '4', '결핵 대상자와 접촉한 후 요양보호사의 대처방법으로 옳은 것은?', '["폐렴구균을 추가 접종한다.", "예방적 항생제를 복용한다.", "멸균소독가운과 멸균장갑을 착용한다.", "기침을 할 때는 손으로 가리고 한다.", "감염 여부를 확인하기 위해 검사를 한다."]'::jsonb, 5, '결핵 대상자와 접촉한 후 요양보호사의 적절한 대처 방법을 묻는 문제입니다.', NULL, '{"1": "폐렴구균과 결핵은 다른 감염병이므로 추가 접종은 해당하지 않습니다.\n[정답]", "5": "감염 여부를 확인하기 위해 검사를 하는 것이 적절한 대처 방법입니다.", "2": "예방적 항생제를 복용하는 것은 특정 상황에서만 필요하며 일반적인 대처 방법은 아닙니다.", "3": "멸균소독가운과 멸균장갑을 착용하는 것만으로는 충분하지 않습니다.", "4": "기침을 할 때 손으로 가리는 것은 비위생적이며 적절한 대처가 아닙니다."}'::jsonb, '[{"term_ko": "결핵", "term_vi": "Bệnh lao", "def_ko": "폐에 영향을 미치는 감염 질환", "def_vi": "Bệnh truyền nhiễm ảnh hưởng đến phổi"}, {"term_ko": "대처", "term_vi": "Xử lý", "def_ko": "상황에 맞게 대응하는 것", "def_vi": "Phản ứng theo tình huống"}, {"term_ko": "예방", "term_vi": "Phòng ngừa", "def_ko": "병이 생기는 것을 미리 막는 것", "def_vi": "Ngăn chặn bệnh tật xảy ra"}, {"term_ko": "검사", "term_vi": "Kiểm tra", "def_ko": "질병을 확인하기 위한 과정", "def_vi": "Quá trình xác nhận bệnh tật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (155, '4', '다음에서 설명하는 감염성 질환으로 옳은 것은?• 질환에 걸린 대상자의 구토물에 의한 감염 • 구토, 메스꺼움, 오한, 복통, 설사 증상이 있음', '["결핵", "독감", "노로바이러스 감염", "옴", "머릿니"]'::jsonb, 3, '감염성 질환에 대한 이해 및 관련 증상을 파악하기 위함입니다.', NULL, '{"1": "결핵은 주로 호흡기로 전파되는 질환으로, 여기서 설명하는 증상과는 차이가 있습니다.", "2": "독감은 호흡기 감염으로 구토, 메스꺼움, 설사가 흔하지 않습니다.\n[정답]", "3": "노로바이러스 감염은 구토 및 설사를 유발하며, 구토물에 의한 감염이 가능합니다.", "4": "옴은 피부 기생충으로 감염 증상이 다릅니다.", "5": "머릿니는 머리카락에 기생하는 기생충으로, 구토나 설사 증상이 없습니다."}'::jsonb, '[{"term_ko": "감염성 질환", "term_vi": "Bệnh truyền nhiễm", "def_ko": "감염으로 인해 발생하는 질병", "def_vi": "Bệnh xảy ra do nhiễm trùng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (154, '4', '옴에 감염된 대상자를 돕는 방법으로 옳은 것은?', '["공용 혈압계를 사용한다.", "맨손으로 도포용 약제를 발라준다.", "증상이 있는 부위만 약을 바른다.", "대상자가 사용한 침구류를 다른 대상자의 물품과 함께 세탁한다.", "대상자와 접촉한 사람은 증상 유무와 상관없이 함께 동시에 치료한다."]'::jsonb, 5, '옴에 감염된 대상자의 적절한 관리 방법을 이해하고 있는지 평가하려는 의도이다.', NULL, '{"1": "공용 혈압계를 사용하면 감염이 전파될 수 있다. 따라서 잘못된 방법이다.\n[정답]", "5": "대상자와 접촉한 사람은 증상 유무와 상관없이 함께 동시에 치료해야 감염을 예방할 수 있다.", "2": "맨손으로 도포용 약제를 바르면 감염이 전파될 수 있으므로 잘못된 방법이다.", "3": "증상이 있는 부위만 약을 바르는 것은 효과적이지 않으며, 전체적으로 치료해야 한다.", "4": "대상자가 사용한 침구류는 따로 세탁하여야 다른 대상자에게 전파되지 않는다."}'::jsonb, '[{"term_ko": "옴", "term_vi": "Ghẻ", "def_ko": "피부염의 일종", "def_vi": "Một loại viêm da"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (153, '4', '감염성 질환인 머릿니 관리법으로 옳은 것은?', '["요양보호사는 귀가 후 손을 씻어 감염을 예방한다.", "세탁물을 55도 이상에서 5분 이상 노출시켜 사멸시킨다.", "수건, 옷솔 등은 공동으로 사용한다.", "치료하기 전에 2일 동안 착용한 침구류는 햇빛에 말린다.", "대상자가 앉거나 누운 바닥은 빗자루를 이용하여 청소한다."]'::jsonb, 2, '감염성 질환인 머릿니의 올바른 관리 방법을 이해하고 적용하는 것이 중요하다.', NULL, '{"1": "요양보호사는 감염 예방을 위해 손을 씻는 것이 필수적이다. 그러나 이는 직접적인 관리법이 아니라 예방 조치이다.\n[정답]", "2": "세탁물을 55도 이상에서 5분 이상 노출시켜 사멸시키는 것은 머릿니를 관리하는 올바른 방법이다.", "3": "수건, 옷솔 등은 개인 위생을 위해 공동으로 사용해서는 안 된다.", "4": "치료 전에 2일 동안 착용한 침구류는 세탁 후 햇빛에 말리기보다 바로 세탁하는 것이 더 효과적이다.", "5": "대상자가 앉거나 누운 바닥은 청소가 필요하나, 빗자루로 청소하는 것은 물리적 방법으로 완전히 제거하기 어렵다."}'::jsonb, '[{"term_ko": "감염성 질환", "term_vi": "Bệnh truyền nhiễm", "def_ko": "전염병(한국어)", "def_vi": "Bệnh có thể lây lan"}, {"term_ko": "머릿니", "term_vi": "Chấy", "def_ko": "이(한국어)", "def_vi": "Rận tóc"}, {"term_ko": "관리법", "term_vi": "Phương pháp quản lý", "def_ko": "관리 방법(한국어)", "def_vi": "Cách quản lý"}, {"term_ko": "사멸", "term_vi": "Tiêu diệt", "def_ko": "죽이다(한국어)", "def_vi": "Diệt trừ"}, {"term_ko": "침구류", "term_vi": "Đồ bedding", "def_ko": "침대 시트 및 베개 커버 (한국어)", "def_vi": "Ga trải giường và gối"}, {"term_ko": "햇빛", "term_vi": "Ánh sáng mặt trời", "def_ko": "태양광선(한국어)", "def_vi": "Ánh sáng mặt trời"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (152, '4', '감염예방을 위한 요양보호사의 대처방법으로 옳은 것은?', '["대상자가 감염된 경우 보호 장구를 착용하지 않는다.", "임신한 요양보호사는 수두바이러스 질환 대상자와 접촉하지 않는다.", "독감에 걸린 요양보호사는 보호 장구 착용 후 서비스를 제공한다.", "옴에 걸린 대상자의 가족은 증상이 있을 때 치료 받는다.", "노로바이러스에 감염된 요양보호사는 2 ~ 3일간 음식조리 업무만 한다."]'::jsonb, 2, '요양보호사가 감염 예방을 위해 알아야 할 올바른 대처 방법을 묻고 있습니다.', NULL, '{"1": "대상자가 감염된 경우 보호 장구를 착용하지 않는 것은 잘못된 대처입니다.\n[정답]", "2": "임신한 요양보호사는 수두바이러스 질환 대상자와 접촉하지 않아야 합니다.", "3": "독감에 걸린 요양보호사는 보호 장구를 착용한 후에도 서비스 제공을 자제해야 합니다.", "4": "옴에 걸린 대상자의 가족은 증상이 있을 때 치료를 받는 것이 아닌 조기에 치료를 받아야 합니다.", "5": "노로바이러스에 감염된 요양보호사는 음식 조리 업무를 하지 말아야 하며, 격리 조치가 필요합니다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염(한국어)", "def_vi": "Nhiễm bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (151, '5', '노화에 따른 변화와 노인성 질환의 특성으로 옳은 것은?', '["질병의 경과가 짧다.", "질병의 초기진단이 쉽다.", "질병 발생의 원인이 명확하다.", "가벼운 질환에도 의식장애가 발생하기 쉽다.", "약성분이 체외로 빨리 배출되어 치료가 쉽다."]'::jsonb, 4, '노화에 따른 신체적, 정신적 변화와 노인성 질환의 특성을 이해하고 이를 바탕으로 올바른 답을 찾도록 하는 문제입니다.', NULL, '{"1": "질병의 경과가 짧지 않습니다.", "2": "질병의 초기 진단이 쉽지 않습니다.", "3": "질병 발생의 원인이 항상 명확하지 않습니다.\n[정답]", "4": "가벼운 질환에도 의식장애가 발생하기 쉽습니다.", "5": "약성분이 체외로 빨리 배출되지 않습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 들어감(한국어)", "def_vi": "Trở nên già"}, {"term_ko": "변화", "term_vi": "Thay đổi", "def_ko": "변화(한국어)", "def_vi": "Sự thay đổi"}, {"term_ko": "노인성", "term_vi": "Người cao tuổi", "def_ko": "노인에게 발생하는(한국어)", "def_vi": "Liên quan đến người già"}, {"term_ko": "질환", "term_vi": "Bệnh tật", "def_ko": "질병(한국어)", "def_vi": "Bệnh"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "의식(한국어)", "def_vi": "Ý thức"}, {"term_ko": "장애", "term_vi": "Khuyết tật", "def_ko": "방해, 문제(한국어)", "def_vi": "Sự cản trở"}, {"term_ko": "약성분", "term_vi": "Thành phần thuốc", "def_ko": "약의 성분(한국어)", "def_vi": "Thành phần của thuốc"}, {"term_ko": "체외", "term_vi": "Ngoài cơ thể", "def_ko": "체외로, 신체 밖으로(한국어)", "def_vi": "Ra ngoài cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (150, '5', '노인에게 약물중독의 위험이 증가하는 이유로 옳은 것은?', '["대상자의 운동성 증가", "심장 근육의 수축력 증가", "신경전달물질의 분비 증가", "신장의 배설능력 감소", "폐 조직의 탄력성 감소"]'::jsonb, 4, '노인에게 약물중독의 위험 증가에 대한 이해를 평가하고자 함.', NULL, '{"1": "대상자의 운동성이 증가하면 약물의 이용도 증가할 수 있으나 중독 위험과는 관련이 없음.", "2": "심장 근육의 수축력이 증가하면 혈액순환이 개선될 수 있지만 약물중독과는 무관함.", "3": "신경전달물질의 분비가 증가하면 오히려 약물의 효과가 줄어들 수 있어 중독 위험과는 관련이 없음.\n[정답]", "4": "신장의 배설능력이 감소하면 노인이 약물의 대사가 제대로 이루어지지 않아 약물중독의 위험이 증가함.", "5": "폐 조직의 탄력성이 감소하면 호흡기능이 저하되지만 이는 약물중독과는 직접적인 관련이 없음."}'::jsonb, '[{"term_ko": "약물중독", "term_vi": "Ngộ độc thuốc", "def_ko": "독성 약물이 체내에 과하게 축적되어 나타나는 증상", "def_vi": "Triệu chứng xuất hiện khi thuốc độc tích tụ quá mức trong cơ thể"}, {"term_ko": "운동성", "term_vi": "Vận động", "def_ko": "신체의 움직임 속도나 능력", "def_vi": "Tốc độ hoặc khả năng di chuyển của cơ thể"}, {"term_ko": "신장", "term_vi": "Thận", "def_ko": "체내 노폐물 및 수분을 여과하고 배설하는 장기", "def_vi": "Cơ quan lọc và bài tiết chất thải và nước trong cơ thể"}, {"term_ko": "배설능력", "term_vi": "Khả năng bài tiết", "def_ko": "체내 노폐물이나 약물을 배출하는 능력", "def_vi": "Khả năng thải trừ chất thải hoặc thuốc ra khỏi cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (149, '5', '노화현상으로 인한 소화기계 증상으로 옳은 것은?', '["후각기능의 증가", "쓴맛 감각의 증가", "당내성의 증가", "지방흡수력의 증가", "약물의 대사와 제거 능력의 증가"]'::jsonb, 2, '노화가 소화기계에 미치는 영향을 이해하고 올바른 증상을 선택하도록 유도하는 문제입니다.', NULL, '{"1": "후각기능의 증가: 노화로 인해 후각기능이 일반적으로 감소합니다.\n[정답]", "2": "쓴맛 감각의 증가: 노화에 따라 쓴맛 감각이 더 예민해지는 경우가 많습니다.", "3": "당내성의 증가: 노화와 관련하여 당내성은 감소하는 경향이 있습니다.", "4": "지방흡수력의 증가: 지방흡수력이 감소하는 것이 일반적입니다.", "5": "약물의 대사와 제거 능력의 증가: 노화로 인해 대사 및 제거 능력은 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 많아지는 것", "def_vi": "Trở nên già hơn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (148, '5', '노화로 간 기능이 변화되어 나타날 수 있는 결과로 옳은 것은?', '["당내성 증가", "타액 분비의 증가", "칼슘 흡수의 증가", "위산 분비 저하", "약물 대사 능력 저하"]'::jsonb, 5, '노화에 따른 간 기능의 변화를 이해하고 그 결과에 대한 지식을 평가하고자 함.', NULL, '{"1": "당내성 증가: 노화로 인해 일반적으로 인슐린 저항성이 증가하나, 분명한 결과라 볼 수 없음.", "2": "타액 분비의 증가: 노화에 따라 오히려 타액 분비는 감소하는 경향이 있음.\n[정답]", "3": "칼슘 흡수의 증가: 노화로 인해 칼슘 흡수는 감소하며, 이는 뼈에 영향을 준다.", "4": "위산 분비 저하: 노화로 위산 분비는 저하되며, 이는 소화에 영향을 준다.", "5": "약물 대사 능력 저하: 노화로 인해 간 기능이 저하되면서 약물 대사 능력이 감소함."}'::jsonb, '[{"term_ko": "노화", "term_vi": "간", "def_ko": "늙음 (lão hóa)", "def_vi": "간 (gan)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (147, '5', '위염증상을 완화하는 데 도움이 되는 방법으로 옳은 것은?', '["복부를 시계 방향으로 마사지한다.", "염장식품의 섭취를 격려한다.", "부드러운 유동식을 제공한다.", "음식을 뜨겁게 하여 제공한다.", "음식 섭취량을 늘리도록 한다."]'::jsonb, 3, '위염의 증상 완화 방법을 이해하고 적용할 수 있는지를 평가하고자 함.', NULL, '{"1": "복부를 시계 방향으로 마사지하는 것은 일반적인 진통 완화 방법이나, 위염 증상 완화와는 직접적인 연관이 없음.\n[정답]", "3": "부드러운 유동식을 제공하는 것은 위염 환자가 소화하기에 용이하며, 증상을 완화하는 데 도움이 된다.", "2": "염장식품의 섭취는 오히려 위염 증상을 악화시킬 수 있기 때문에 권장되지 않는다.", "4": "음식을 뜨겁게 하여 제공하는 것은 위에 자극이 될 수 있어 피해야 한다.", "5": "음식 섭취량을 늘리는 것은 위에 부담을 줄 수 있으므로, 위염 환자에게 바람직하지 않다."}'::jsonb, '[{"term_ko": "위염", "term_vi": "Viêm dạ dày", "def_ko": "위의 염증", "def_vi": "Viêm của dạ dày"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (146, '5', '위궤양 대상자를 돕는 방법으로 옳은 것은?', '["훈연한 음식을 먹게 한다.", "흡연자면 금연하게 한다.", "잠자리에 들기 전에 녹차를 마시게 한다.", "검은색 대변을 보더라도 정상이라고 안심시킨다.", "비스테로이드성 소염진통제를 자주 복용하게 한다."]'::jsonb, 2, '위궤양 환자에게 적절한 도움을 제공하는 방법을 알도록 하기 위함입니다.', NULL, '{"1": "훈연한 음식을 먹게 하는 것은 위염을 악화시킬 수 있습니다.\n[정답]", "2": "흡연자는 위궤양을 악화시킬 수 있으므로 금연하게 하는 것이 중요합니다.", "3": "녹차는 카페인이 포함되어 있어 잠자기 전에 마시는 것이 좋지 않습니다.", "4": "검은색 대변은 위장 출혈의 징후일 수 있으므로 안심시킬 것이 아니라 진료를 받아야 합니다.", "5": "비스테로이드성 소염진통제는 위 점막을 자극할 수 있으며, 위궤양 환자에게는 사용을 피해야 합니다."}'::jsonb, '[{"term_ko": "위궤양", "term_vi": "Loét dạ dày", "def_ko": "위의 점막에 생기는 염증", "def_vi": "Viêm màng nhầy của dạ dày"}, {"term_ko": "흡연", "term_vi": "Hút thuốc", "def_ko": "담배를 피우는 행위", "def_vi": "Hành động hút thuốc lá"}, {"term_ko": "금연", "term_vi": "Bỏ thuốc", "def_ko": "담배를 끊는 것", "def_vi": "Ngừng hút thuốc"}, {"term_ko": "대변", "term_vi": "Phân", "def_ko": "배설물", "def_vi": "Phân"}, {"term_ko": "비스테로이드성 소염진통제", "term_vi": "Thuốc giảm đau không steroid", "def_ko": "비스테로이드성 소염진통제를 포함한 약물", "def_vi": "Thuốc bao gồm cả thuốc giảm đau không steroid"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (145, '5', '대상자의 장습관의 변화, 선홍색의 혈액과 점액이 섞인 설사와 변비를 반복할 때 나타나는 소화기계 질환으로 옳은 것은?', '["위염", "위궤양", "변비", "대장암", "설사"]'::jsonb, 4, '대상자의 장습관 변화에 따른 소화기계 질환의 이해를 요구하는 문제입니다.', NULL, '{"1": "위염은 위 점막의 염증으로, 수반되는 증상이 다릅니다.", "2": "위궤양은 위 점막의 결손으로, 혈변이 관찰되는 경우가 드뭅니다.", "3": "변비는 정상적인 배변이 어려운 상태로, 혼합된 혈액과 점액이 나타나지 않습니다.\n[정답]", "4": "대장암은 장의 이상으로 장 습관 변화와 혈액이 섞인 설사를 동반할 수 있습니다.", "5": "설사는 여러 원인으로 발생할 수 있으나, 특정 질환과 직접적인 연관은 약합니다."}'::jsonb, '[{"term_ko": "장습관", "term_vi": "대장암", "def_ko": "배변의 습관(thói quen đại tiện)", "def_vi": "대장의 암(tumor ở đại tràng)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (144, '5', '대장암을 예방하기 위한 식이요법으로 옳은 것은?', '["지방함유량이 많은 음식을 제공한다.", "통곡식으로 만든 음식을 제공한다.", "고칼로리 음식을 제공한다.", "훈연된 동물성 식품을 제공한다.", "야식으로 가공된 음식을 제공한다."]'::jsonb, 2, '대장암 예방을 위한 식이요법에 대한 이해를 평가하기 위해 출제됨.', NULL, '{"1": "지방함유량이 많은 음식은 대장암 예방에 도움이 되지 않음.\n[정답]", "2": "통곡식으로 만든 음식은 섬유소가 많아 대장암 예방에 효과적임.", "3": "고칼로리 음식은 오히려 대장암 위험을 증가시킬 수 있음.", "4": "훈연된 동물성 식품은 발암 물질을 포함할 수 있어 피해야 함.", "5": "야식으로 가공된 음식은 건강에 좋지 않음."}'::jsonb, '[{"term_ko": "대장암", "term_vi": "Ung thư đại tràng", "def_ko": "큰 창자에서 발생하는 암", "def_vi": "Ung thư xảy ra trong ruột già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (143, '5', '설사를 하는 대상자를 돕기 위한 방법으로 옳은 것은?', '["시원한 탄산음료를 마시게 한다.", "물을 적게 마시게 한다.", "기생충이 원인일 경우 진정제를 투약한다.", "지사제를 사용한다.", "몸을 따뜻하게 하고 수분 섭취량을 늘린다."]'::jsonb, 5, '설사를 하는 대상자를 돕기 위한 적절한 방법을 찾는 것이다.', NULL, '{"1": "시원한 탄산음료는 위장에 부담을 줄 수 있다.", "2": "물을 적게 마시는 것은 탈수를 유발할 수 있다.", "3": "기생충이 원인일 경우 진정제는 효과적이지 않다.\n[정답]", "5": "몸을 따뜻하게 하고 수분 섭취량을 늘리는 것이 중요하다.", "4": "지사제는 원인에 따라 사용할 수 있으나, 모든 경우에 적합하지 않다."}'::jsonb, '[{"term_ko": "설사", "term_vi": "Tiêu chảy", "def_ko": "배탈(한국어)", "def_vi": "tiêu chảy(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (142, '5', '노인 변비의 유발 요인으로 옳은 것은?', '["식사량의 증가", "수분섭취의 증가", "배변반사의 증가", "마약성 진통제 사용", "고섬유질 음식 섭취의 증가"]'::jsonb, 4, '노인 변비의 유발 요인을 파악하고 관련 지식을 평가하고자 하는 의도입니다.', NULL, '{"1": "식사량의 증가: 일반적으로 식사량의 증가는 변비를 완화할 수 있습니다.", "2": "수분섭취의 증가: 수분은 장 내 수분량을 증가시켜 변비 예방에 도움을 줍니다.", "3": "배변반사의 증가: 배변반사가 증가하면 변이 원활하게 배출될 수 있습니다.\n[정답]", "4": "마약성 진통제 사용: 마약성 진통제는 장의 운동성을 저하시키고 변비를 유발할 수 있습니다.", "5": "고섬유질 음식 섭취의 증가: 고섬유질 음식은 일반적으로 변비를 예방하고 개선하는 데 좋습니다."}'::jsonb, '[{"term_ko": "변비", "term_vi": "Táo bón", "def_ko": "장의 운동이 느려져 배변이 어려운 상태", "def_vi": "Tình trạng khó khăn trong việc đại tiện do sự chậm lại của hoạt động ruột"}, {"term_ko": "수분", "term_vi": "Nước", "def_ko": "물", "def_vi": "Nước"}, {"term_ko": "배변반사", "term_vi": "Phản xạ đại tiện", "def_ko": "대변을 배출하려는 자연스러운 반응", "def_vi": "Phản ứng tự nhiên để thải phân"}, {"term_ko": "마약성 진통제", "term_vi": "Thuốc giảm đau gây nghiện", "def_ko": "통증을 완화하기 위해 사용하는 약물", "def_vi": "Thuốc được sử dụng để giảm đau"}, {"term_ko": "고섬유질", "term_vi": "Giàu chất xơ", "def_ko": "섬유소가 많은 식사", "def_vi": "Bữa ăn nhiều chất xơ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (141, '5', '시설대상자가 아침에 속이 쓰리다고 말할 때 요양보호사의 반응으로 옳은 것은?', '["\"위염이니 병원에 가야 해요\"", "\"위장약을 먹어야 할 것 같네요\"", "\"괜찮아요, 저는 아침마다 그래요.\"", "\"제가 현재 상태를 간호사에게 전할게요.\"", "\"위가 쉬어야 하니까 아침식사를 거르세요.\""]'::jsonb, 4, '시설대상자의 불편한 증상에 대한 요양보호사의 적절한 반응을 평가하기 위함입니다.', NULL, '{"1": "''위염이니 병원에 가야 해요''는 의료적 판단을 요양보호사가 바로 내리는 것은 부적절합니다.\n[정답]", "4": "''제가 현재 상태를 간호사에게 전할게요''는 적절한 대처로, 전문적인 판단을 간호사에게 맡기며 안전한 방법입니다.", "2": "''위장약을 먹어야 할 것 같네요''는 약물 권장으로, 의사의 처방이 필요한 부분입니다.", "3": "''괜찮아요, 저는 아침마다 그래요.''는 개인적인 경험을 토대로 문제를 간과하는 것입니다.", "5": "''위가 쉬어야 하니까 아침식사를 거르세요.''는 음식 섭취를 무조건 금하는 것이며, 상태에 따라 다를 수 있습니다."}'::jsonb, '[{"term_ko": "시설대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "시설에서 돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc tại cơ sở"}, {"term_ko": "위염", "term_vi": "Viêm dạ dày", "def_ko": "위장에 발생하는 염증", "def_vi": "Viêm trong dạ dày"}, {"term_ko": "간호사", "term_vi": "Y tá", "def_ko": "환자를 돌보는 의료 전문인", "def_vi": "Nhân viên chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (139, '5', '노화와 관련된 호흡기계 특성으로 옳은 것은?', '["폐순환량이 증가하여 숨 쉬기 편하다.", "기침반사가 증가하여 미세 물질을 걸러내기 쉽다.", "콧속 점막에 습기가 증가하여 공기 흡인이 쉽다.", "호흡근육이 약화되어 호흡 증가 시 피로해지기 쉽다.", "기관지 내 분비무리 감소하여 감염 발생 위험이 낮다."]'::jsonb, 4, '노화가 호흡기계에 미치는 영향을 이해하고 관련된 특성을 평가하기 위함입니다.', NULL, '{"1": "폐순환량이 증가하지 않으며, 노화로 인해 호흡이 편해지지 않습니다.\n[정답]", "4": "노화로 호흡근육이 약해져 호흡 시 피로해지기 쉽습니다.", "2": "기침반사는 감소하며, 미세 물질을 걸러내기 어려워집니다.", "3": "콧속 점막의 습기가 감소하여 공기 흡인에 어려움이 있습니다.", "5": "기관지 내 분비물 증가로 감염 발생 위험이 높아집니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙은 상태", "def_vi": "Trạng thái già"}, {"term_ko": "호흡기계", "term_vi": "Hệ hô hấp", "def_ko": "호흡을 담당하는 기관군", "def_vi": "Nhóm cơ quan chịu trách nhiệm hô hấp"}, {"term_ko": "피로", "term_vi": "Mệt mỏi", "def_ko": "에너지가 고갈된 상태", "def_vi": "Trạng thái mất năng lượng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (138, '5', '인플루엔자 바이러스에 의한 감염병으로 겨울철에 유행하는 질환으로 옳은 것은?', '["독감", "기관지염", "천식", "결핵", "폐렴"]'::jsonb, 1, '인플루엔자 바이러스가 유행하는 질환에 대한 이해를 테스트하기 위한 문제입니다.', NULL, '{"1": "독감은 인플루엔자 바이러스에 의한 대표적인 감염병으로 겨울철에 주로 발생합니다.\n[정답]", "2": "기관지염은 여러 가지 원인에 의해 발생하며 인플루엔자와는 다릅니다.", "3": "천식은 알레르기 반응에 의한 만성 질환으로 인플루엔자와는 관련이 없습니다.", "4": "결핵은 세균 감염에 의한 질환으로 인플루엔자와는 관계가 없습니다.", "5": "폐렴은 여러 감염원에 의해 발생할 수 있지만 인플루엔자와는 다릅니다."}'::jsonb, '[{"term_ko": "인플루엔자", "term_vi": "Virus Influenza", "def_ko": "독감(한국어)", "def_vi": "cúm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (137, '5', '인플루엔자 대상자를 돕는 방법으로 옳은 것은?', '["사람들이 많은 장소에 출입한다.", "외출할 때는 마스크를 쓰게 한다.", "치료제로 항생제를 복용하게 한다.", "운동 전에 기관지 확장제를 쓰게 한다.", "정기적으로 흉부방사선 검사를 받게 한다."]'::jsonb, 2, '인플루엔자에 대한 적절한 대응 방법을 평가하기 위한 문제입니다.', NULL, '{"1": "사람들이 많은 장소에 출입한다는 것은 감염 위험을 증가시키므로 옳지 않습니다.\n[정답]", "2": "외출할 때 마스크를 착용하게 하는 것은 감염 예방에 효과적입니다.", "3": "인플루엔자는 바이러스 감염이므로 항생제는 효과가 없습니다.", "4": "운동 전에 기관지 확장제를 사용해야 하는 경우는 특수 상황에서만 필요합니다.", "5": "정기적인 흉부 방사선 검사는 인플루엔자 예방과 관련이 없습니다."}'::jsonb, '[{"term_ko": "인플루엔자", "term_vi": "Cúm", "def_ko": "독감(한국어)", "def_vi": "Cảm lạnh"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Người bị bệnh"}, {"term_ko": "마스크", "term_vi": "Khẩu trang", "def_ko": "얼굴 가리개(한국어)", "def_vi": "Đồ che mặt"}, {"term_ko": "항생제", "term_vi": "Kháng sinh", "def_ko": "감염 치료제(한국어)", "def_vi": "Thuốc chữa nhiễm trùng"}, {"term_ko": "기관지", "term_vi": "Phế quản", "def_ko": "호흡기 계통의 일부(한국어)", "def_vi": "Một phần của hệ hô hấp"}, {"term_ko": "정기적", "term_vi": "Định kỳ", "def_ko": "일정한 간격으로(한국어)", "def_vi": "Ở khoảng cách quy định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (136, '5', '기관지의 만성적 염증으로 기도가 좁아져 숨쉬기 힘든 대상자를 돕는 방법으로 옳은 것은?', '["공기오염이 심한 곳에는 가습기를 설치한다.", "심호흡과 기침을 하여 기관지 내 가래를 배출한다.", "방향제를 사용하여 공기를 정화한다.", "습기가 많은 날씨에 외출을 즐긴다.", "기관지 확장제는 증상이 없을 때만 사용한다."]'::jsonb, 2, '기관지의 만성적 염증으로 인한 호흡 곤란을 겪는 대상자의 관리 방법을 이해하고 적용하는 것.', NULL, '{"1": "공기오염이 심한 곳에 가습기를 설치하는 것은 도움이 되지 않는다.\n[정답]", "2": "심호흡과 기침을 통해 기관지 내 가래를 배출하는 것이 중요하다.", "3": "방향제를 사용하는 것은 오히려 자극을 줄 수 있다.", "4": "습기가 많은 날씨에는 외출을 피하는 것이 좋다.", "5": "기관지 확장제는 증상이 있을 때 사용하는 것이 효과적이다."}'::jsonb, '[{"term_ko": "기관지", "term_vi": "Phế quản", "def_ko": "호흡기를 통해 공기가 통과하는 길", "def_vi": "Đường dẫn khí qua phổi"}, {"term_ko": "만성적", "term_vi": "Mãn tính", "def_ko": "오랜 시간 지속되는", "def_vi": "Kéo dài trong thời gian lâu"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "신체의 손상이나 감염에 의해 발생하는 반응", "def_vi": "Phản ứng xảy ra do tổn thương hoặc nhiễm trùng trong cơ thể"}, {"term_ko": "가래", "term_vi": "Đờm", "def_ko": "호흡기에서 배출되는 점액", "def_vi": "Chất nhầy được bài tiết từ đường hô hấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (135, '5', '세균, 바이러스에 의한 폐 조직의 염증으로 호흡곤란, 가래, 기침이 나타나는 질병으로 옳은 것은?', '["독감", "결핵", "천식", "만성기관지염", "폐렴"]'::jsonb, 5, '호흡기 질환에 대한 이해도를 평가하기 위함입니다.', NULL, '{"1": "독감: 인플루엔자 바이러스에 의해 발생하는 질병으로 다양한 증상이 나타날 수 있지만, 주로 발열과 근육통이 특징입니다.\n[정답]", "5": "폐렴: 세균이나 바이러스에 의해 폐 조직에 염증이 생기고, 기침, 가래, 호흡곤란이 주요 증상입니다.", "3": "천식: 주로 알레르기 요인에 의해 발작적으로 발생하는 호흡곤란입니다.", "4": "만성기관지염: 장기간 동안 지속적인 기침과 가래가 특징이며, 염증이 동반됩니다.", "2": "결핵: 결핵균에 의해 폐에 발생하는 만성 감염병으로, 기침, 체중 감소, 야간 발한 등의 증상이 나타납니다."}'::jsonb, '[{"term_ko": "세균", "term_vi": "바이러스", "def_ko": "bacteria", "def_vi": "virus"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (134, '5', '만성기관지염 대상자의 효과적인 가래 배출 방법으로 옳은 것은?', '["항생제를 투여한다.", "수분 섭취를 제한한다.", "심호흡과 기침을 하게 한다.", "똑바로 누워 안정을 취하게 한다.", "실내 공기를 서늘하게 유지한다."]'::jsonb, 3, '만성기관지염 환자에게 적절한 가래 배출 방법을 이해하고 있는지를 평가하기 위함이다.', NULL, '{"1": "항생제를 투여하여도 가래 배출에는 직접적인 도움이 되지 않는다.\n[정답]", "3": "심호흡과 기침을 통해 가래를 효과적으로 배출할 수 있다.", "2": "수분 섭취를 제한하면 오히려 가래가 더 끈적해질 수 있다.", "4": "똑바로 누워 안정을 취하는 것은 호흡을 방해할 수 있다.", "5": "실내 공기를 서늘하게 유지하면 기관지가 자극을 받을 수 있다."}'::jsonb, '[{"term_ko": "만성기관지염", "term_vi": "가래", "def_ko": "만 tính viêm phế quản", "def_vi": "đờm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (133, '5', '고양이를 쓰다듬던 대상자가 잠시 후 쌕쌕거리는 호흡음을 내쉬며 가슴이 답답하다고 호소할 때 의심되는 질환으로 옳은 것은?', '["결핵", "비염", "천식", "후두염", "흉막염"]'::jsonb, 3, '대상자가 호소하는 증상을 통해 호흡기 질환을 이해하고 올바른 진단을 선택하는 것이 중요하다.', NULL, '{"1": "결핵: 결핵은 주로 폐에 영향을 미치지만, 쌕쌕거리는 호흡음과 가슴 답답함과 직접적인 연관은 낮다.\n[정답]", "3": "천식: 천식은 쌕쌕거리는 호흡음과 가슴 답답감을 유발하는 주요 질환입니다.", "2": "비염: 비염은 주로 코와 관련된 증상으로 호흡음과 다소 거리가 있다.", "4": "후두염: 후두염은 목 소리 변화와 관련이 있으며, 일반적으로 호흡음을 이끌어내지 않는다.", "5": "흉막염: 흉막염은 가슴 통증을 유발할 수 있지만 쌕쌕거리는 호흡음과는 연관성이 작다."}'::jsonb, '[{"term_ko": "호흡음", "term_vi": "Âm thanh hô hấp", "def_ko": "소리(한국어)", "def_vi": "Âm thanh liên quan đến hơi thở(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (132, '5', '천식 대상자의 호흡곤란을 예방하는 방법으로 옳은 것은?', '["추운 날씨에 벽난로를 핀다.", "차고 건조한 공기로 환기시킨다.", "뜨거운 물로 침구류를 세탁한다.", "해마다 폐렴구균을 추가 접종한다.", "운동 시작 전에는 기관지 확장제 흡인을 금한다."]'::jsonb, 3, '천식 환자의 호흡곤란을 예방하기 위한 올바른 방법을 묻고 있다.', NULL, '{"1": "추운 날씨는 호흡곤란을 악화시킬 수 있어 벽난로를 피하는 것이 좋다.\n[정답]", "3": "뜨거운 물로 세탁한 침구는 먼지를 제거하고 알레르기 반응을 줄여 호흡곤란 예방에 효과적이다.", "2": "차고 건조한 공기로 환기시키는 것은 천식에 좋지 않다.", "4": "예방접종은 중요하지만, 폐렴구균 접종이 직접적으로 호흡곤란 예방에 기여하지는 않는다.", "5": "운동 전 기관지 확장제 흡인은 실제로 필요할 수 있다."}'::jsonb, '[{"term_ko": "천식", "term_vi": "Hen suyễn", "def_ko": "호흡기 질환의 일종", "def_vi": "Bệnh lý hô hấp"}, {"term_ko": "호흡곤란", "term_vi": "Khó thở", "def_ko": "숨쉬기 어려움", "def_vi": "Khó khăn trong việc thở"}, {"term_ko": "예방", "term_vi": "Phòng ngừa", "def_ko": "미리 방지함", "def_vi": "Ngăn chặn trước"}, {"term_ko": "접종", "term_vi": "Tiêm phòng", "def_ko": "백신을 맞는 것", "def_vi": "Tiêm vacxin"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (131, '5', '천식 대상자가 흡인용 기관지 확장제를 사용할 때의 순서로 옳은 것은?가. 흡인기의 뚜껑을 열고 흔든다. 나. 흡인기를 입으로 문다. 다. 10초간 숨을 참은 후 천천히 내쉰다. 라. 3~5초간 천천히 깊게 숨을 들이쉰다. 마. 입으로 숨을 들이쉬면서 흡인기를 누른다.', '["가 → 나 → 다 → 라 → 마", "가 → 나 → 마 → 라 → 다", "가 → 라 → 나 → 다 → 마", "가 → 다 → 나 → 라 → 마", "가 → 라 → 나 → 마 → 다"]'::jsonb, 2, '천식 환자가 흡인용 기관지 확장제를 올바르게 사용하는 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "흡인기의 뚜껑을 연 후 흔드는 것은 약물이 고르게 섞이도록 하기 위해서입니다.\n[정답]", "2": "흡인기를 입으로 물고 입안에 약물이 잘 퍼지도록 합니다.", "3": "숨을 참는 것은 약물이 폐에 더 잘 흡수되도록 합니다.", "4": "깊게 숨을 들이쉬며 약물을 폐로 밀어 넣는 과정입니다.", "5": "숨을 들이쉬면서 흡인기를 누르는 것이 올바른 사용법입니다."}'::jsonb, '[{"term_ko": "천식", "term_vi": "Hen suyễn", "def_ko": "호흡기 질환의 일종", "def_vi": "Một loại bệnh hô hấp"}, {"term_ko": "흡인", "term_vi": "Hít", "def_ko": "기구를 사용해 약물을 넣는 행위", "def_vi": "Hành động đưa thuốc vào cơ thể bằng thiết bị"}, {"term_ko": "기관지", "term_vi": "Phế quản", "def_ko": "호흡기를 구성하는 관", "def_vi": "Ống mạch khí trong hệ hô hấp"}, {"term_ko": "확장제", "term_vi": "Thuốc giãn", "def_ko": "기계적으로 확장시키는 물질", "def_vi": "Chất làm giãn nở một cách cơ học"}, {"term_ko": "환자", "term_vi": "Bệnh nhân", "def_ko": "치료가 필요한 사람", "def_vi": "Người cần điều trị"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (130, '5', '요양보호사 결핵이 의심되는 대상자와 접촉했을 때 대처방법으로 옳은 것은?', '["대상자를 병원에 입원시킨다.", "서비스를 중단한다.", "결핵 예방접종을 한다.", "1개월 이후 반드시 의료기관을 찾아 감염 여부를 확인한다.", "대상자에게 마스크와 장갑을 착용하게 한다."]'::jsonb, 4, '결핵에 대한 올바른 대처방법을 이해하고 적용할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "대상자를 병원에 입원시키는 것은 의료진의 판단이 필요하고, 요양보호사의 권한이 아닙니다.\n[정답]", "4": "1개월 이후 의료기관을 방문해 감염 여부를 확인하는 것이 가장 적절한 대처방법입니다.", "2": "서비스를 중단하는 것은 필요하지 않으며, 대처 방법이 아닙니다.", "3": "결핵 예방접종을 하는 것은 일반적인 상황에서 대처방법이 아닙니다.", "5": "대상자에게 마스크와 장갑을 착용하게 하는 것은 좋지만, 감염 여부를 판단하는 것은 의료기관에서 해야 합니다."}'::jsonb, '[{"term_ko": "결핵", "term_vi": "Bệnh lao", "def_ko": "병원체에 의해 발생하는 호흡기 질환", "def_vi": "Bệnh lý hô hấp do vi khuẩn gây ra"}, {"term_ko": "예방접종", "term_vi": "Tiêm phòng", "def_ko": "특정 질병을 예방하기 위해 접종하는 것", "def_vi": "Hành động tiêm để ngăn ngừa một bệnh cụ thể"}, {"term_ko": "의료기관", "term_vi": "Cơ sở y tế", "def_ko": "의료 서비스를 제공하는 조직", "def_vi": "Tổ chức cung cấp dịch vụ y tế"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (129, '5', '항결핵제 복용방법에 관한 설명으로 옳은 것은?', '["평생 동안 복용한다.", "증상이 없으면 복용량을 줄인다.", "약물복용이 끝날 때까지 격리한다.", "주기적으로 간기능 검사를 하면서 복용한다.", "항결핵제 중 한 가지 약물을 복용하는 것이 원칙이다."]'::jsonb, 4, '항결핵제에 대한 올바른 복용 방법을 파악하기 위한 문제입니다.', NULL, '{"1": "평생 동안 복용하지 않습니다. 치료 기간이 정해져 있습니다.\n[정답]", "2": "증상이 없더라도 규칙적으로 복용해야 합니다.", "3": "약물복용이 끝날 때까지 격리하지 않습니다. 격리는 필요하지 않습니다.", "4": "간기능 검사를 주기적으로 하면서 복용하는 것이 중요합니다.", "5": "일반적으로 복합 요법을 사용하며, 한 가지 약물만 복용하는 것이 원칙이 아닙니다."}'::jsonb, '[{"term_ko": "항결핵제", "term_vi": "Thuốc kháng lao", "def_ko": "결핵을 치료하는 약물", "def_vi": "Thuốc dùng để điều trị bệnh lao"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (128, '5', '노화에 따른 심혈관계 특성으로 옳은 것은?', '["최대 심박출량 감소", "심장근육 두께 감소", "심방동수 증가", "심장의 탄력성 증가", "심장으로의 혈액순환 증가"]'::jsonb, 1, '노화가 심혈관계에 미치는 영향과 특성에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "최대 심박출량 감소는 노화에 따른 일반적인 심혈관계 변화입니다.\n[정답]", "2": "심장근육 두께 감소는 노화와 관련이 있을 수 있지만, 일반적으로는 두꺼워질 수 있습니다.", "3": "심방동수 증가는 노화와 관련된 변화가 아닙니다.", "4": "심장의 탄력성 증가는 노화에 맞지 않는 설명입니다.", "5": "심장으로의 혈액순환 증가는 노화에 따른 변화가 아닙니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이에서 오는 변화", "def_vi": "Sự thay đổi do tuổi tác"}, {"term_ko": "심혈관계", "term_vi": "Hệ tim mạch", "def_ko": "심장 및 혈관 시스템", "def_vi": "Hệ thống tim và mạch máu"}, {"term_ko": "최대", "term_vi": "Tối đa", "def_ko": "최대치", "def_vi": "Giá trị tối đa"}, {"term_ko": "심박출량", "term_vi": "Khối lượng máu bơm ra", "def_ko": "심장이 박출하는 혈액의 양", "def_vi": "Lượng máu do tim bơm ra"}, {"term_ko": "심장근육", "term_vi": "Cơ tim", "def_ko": "심장 근육", "def_vi": "Cơ của tim"}, {"term_ko": "탄력성", "term_vi": "Tính đàn hồi", "def_ko": "신축성", "def_vi": "Khả năng đàn hồi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (127, '5', '고혈압에 관한 설명으로 옳은 것은?', '["혈관이 좁아져 혈압이 낮아진다.", "염장식품은 혈압조절에 도움이 된다.", "심장병이 본태성 고혈압의 원인이 된다.", "이완기 혈압은 심장에서 피를 짜낼 때 압력이다.", "처방된 혈압약은 혈압이 조절되어도 계속 복용한다."]'::jsonb, 5, '고혈압에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "혈관이 좁아지면 혈압이 오히려 높아진다.", "2": "염장식품은 나트륨이 많아 혈압을 높일 수 있으므로 도움이 되지 않는다.\n[정답]", "5": "처방된 혈압약은 증상이 개선되더라도 중단하지 않고 꾸준히 복용해야 한다.", "3": "심장병은 고혈압의 원인이 아니라 고혈압의 합병증일 수 있다.", "4": "이완기 혈압은 심장이 이완될 때의 압력으로, 피를 짜낼 때의 압력은 수축기 혈압이다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "Huyết áp cao", "def_ko": "높은 혈압(한국어)", "def_vi": "Huyết áp cao(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (126, '5', '고혈압 대상자의 약물 요법으로 옳은 것은?', '["복용하지 않은 약물은 다음날 2배 복용한다.", "증상이 없어도 혈압이 높으면 치료해야 한다.", "두통 등의 증상이 있을 때만 약을 복용한다.", "혈압 약을 오래 먹으면 몸이 허약해진다.", "혈압이 조절되면 그만 먹어도 된다."]'::jsonb, 2, '고혈압 관리 및 약물 요법에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "복용하지 않은 약물은 다음날 2배 복용하는 것은 잘못된 방법입니다. \n[정답]", "2": "혈압이 높으면 증상이 없더라도 치료가 필요합니다.", "3": "두통 등의 증상이 있을 때만 약을 복용하는 것은 고혈압 관리에 적절하지 않습니다.", "4": "혈압 약을 오래 먹어도 몸이 허약해진다는 것은 일반적으로 사실이 아닙니다.", "5": "혈압이 조절되면 약 복용을 중단하는 것은 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "Huyết áp cao", "def_ko": "높 혈압(한국어)", "def_vi": "Huyết áp cao(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (125, '5', '고혈압 대상자를 돕는 방법으로 옳은 것은?', '["저지방 유제품을 먹게 한다.", "격렬한 유산소 운동을 하게 한다.", "알코올 섭취로 열량을 보충하게 한다.", "매일 한 잔의 술로 스트레스를 줄이게 한다.", "혈압이 조절되면 약물 복용을 중단하고 운동을 하게 한다."]'::jsonb, 1, '고혈압 관리에 대한 올바른 방법을 이해하는지 평가하기 위함입니다.', NULL, '{"1": "저지방 유제품은 칼슘이 풍부하고 고혈압 관리에 도움이 됩니다.\n[정답]", "2": "격렬한 유산소 운동은 오히려 혈압을 높일 수 있어 위험합니다.", "3": "알코올 섭취는 고혈압에 부정적인 영향을 줄 수 있습니다.", "4": "매일 술을 마시는 것은 건강에 좋지 않으며 고혈압에 해로울 수 있습니다.", "5": "의사의 지시 없이는 약물 복용을 중단해서는 안 됩니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "유제품", "def_ko": "높은 혈압(압 suất máu cao)", "def_vi": "우유에서 만든 음식(sản phẩm từ sữa)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (124, '5', '동맥혈관 안쪽 벽에 지방이 축적되어 혈관 내부가 좁아지고 혈관벽이 굳어지는 증상으로 옳은 것은?', '["고혈압", "동맥경화증", "신부전", "심부전", "빈혈"]'::jsonb, 2, '동맥혈관의 건강 상태와 관련된 질환을 이해하고 구별하는 능력을 평가하고자 함.', NULL, '{"1": "고혈압은 혈압이 비정상적으로 높아진 상태로, 동맥경화증의 결과로 발생할 수 있다.\n[정답]", "2": "동맥경화증은 동맥혈관 안쪽 벽에 지방이 축적되어 혈관 내부가 좁아지고 혈관벽이 굳어지는 증상이다.", "3": "신부전은 신장의 기능이 감소하여 발생하는 상태로, 문제에서 설명하는 증상과는 관련이 없다.", "4": "심부전은 심장이 제대로 기능하지 못하는 상태로, 동맥경화증과는 다른 질환이다.", "5": "빈혈은 혈액 내의 적혈구나 헤모글로빈의 수가 적은 상태를 의미하며, 혈관 관련 증상과는 관련이 없다."}'::jsonb, '[{"term_ko": "동맥혈관", "term_vi": "Mạch máu động mạch", "def_ko": "동맥의 혈관", "def_vi": "Mạch máu của động mạch"}, {"term_ko": "지방", "term_vi": "Chất béo", "def_ko": "지방", "def_vi": "Chất béo"}, {"term_ko": "축적", "term_vi": "Tích tụ", "def_ko": "축적하다", "def_vi": "Tích tụ"}, {"term_ko": "좁아지다", "term_vi": "Hẹp lại", "def_ko": "좁아지다", "def_vi": "Hẹp lại"}, {"term_ko": "굳어지다", "term_vi": "Cứng lại", "def_ko": "굳어지다", "def_vi": "Cứng lại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (123, '5', '협심증, 심근경색 등 관상동백질환이 있을 때 나타나는 특징적인 증상으로 옳은 것은?', '["뇌혈관 출혈", "흉통", "반신불수", "기억력 저하", "불면증"]'::jsonb, 2, '관상동맥질환의 증상을 이해하고 있는지를 평가하기 위한 문제입니다.', NULL, '{"1": "뇌혈관 출혈은 관상동맥질환과 관련이 없습니다.\n[정답]", "2": "흉통은 협심증과 심근경색의 대표적인 증상입니다.", "3": "반신불수는 뇌혈관질환의 증상이지 관상동맥질환과 관련이 없습니다.", "4": "기억력 저하는 주로 신경학적 문제와 관련이 있습니다.", "5": "불면증은 정신적 문제와 관련이 있지만, 관상동맥질환의 증상으로는 일반적이지 않습니다."}'::jsonb, '[{"term_ko": "협심증", "term_vi": "Đau thắt ngực", "def_ko": "가슴 통증이 발생하는 질환", "def_vi": "Bệnh gây đau ngực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (122, '5', '심장의 수축력이 저하되어 나타나는 질환의 주요 증상으로 옳은 것은?', '["복위자세에서의 호흡", "식욕이 좋아짐", "명료한 의식", "지속적인 기침과 객담", "간헐적인 무릎 통증"]'::jsonb, 4, '심장의 수축력 저하와 관련된 주요 증상을 이해하고 있는지를 확인하는 문제입니다.', NULL, '{"1": "복위자세에서의 호흡은 심장의 수축력 저하와 직접적인 관련이 없습니다.\n[정답]", "4": "지속적인 기침과 객담은 심장 기능 저하로 인해 폐혈류가 감소하면서 발생할 수 있는 증상입니다.", "2": "식욕이 좋아짐은 심장 질환과 역행하는 증상으로 부정확합니다.", "3": "명료한 의식은 통상적으로 심장 질환과는 관련이 적습니다.", "5": "간헐적인 무릎 통증은 심장 질환과 관련이 없습니다."}'::jsonb, '[{"term_ko": "심장", "term_vi": "Tim", "def_ko": "심장의 의미(한국어)", "def_vi": "Tim"}, {"term_ko": "수축력", "term_vi": "Sức co bóp", "def_ko": "수축하는 힘(한국어)", "def_vi": "Sức co bóp"}, {"term_ko": "질환", "term_vi": "Bệnh tật", "def_ko": "병의 의미(한국어)", "def_vi": "Bệnh tật"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "나타나는 상태(한국어)", "def_vi": "Triệu chứng"}, {"term_ko": "호흡", "term_vi": "Hô hấp", "def_ko": "숨쉬는 과정(한국어)", "def_vi": "Hô hấp"}, {"term_ko": "기침", "term_vi": "Ho", "def_ko": "기침하는 행위(한국어)", "def_vi": "Ho"}, {"term_ko": "객담", "term_vi": "Đờm", "def_ko": "기침으로 나오는 가래(한국어)", "def_vi": "Đờm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (121, '5', '심부전 대상자를 돕는 방법으로 옳은 것은?', '["매일 체중을 측정한다.", "식사량을 늘려 제공한다.", "계단 오르기 운동을 격려한다.", "담배와 같은 기호품은 허용한다.", "온 · 냉탕을 오가며 목욕하게 한다."]'::jsonb, 1, '심부전 관리 및 간호 방법에 대한 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "체중은 심부전 환자의 수분 상태를 체크하는 중요한 지표입니다.\n[정답]", "2": "심부전 환자에게는 식사량을 늘려주는 것이 오히려 증상을 악화시킬 수 있습니다.", "3": "심부전 환자에게는 과도한 운동이 해롭기 때문에 계단 오르기 운동은 권장되지 않습니다.", "4": "담배와 같은 기호품은 심부전에 좋지 않으므로 허용되지 않습니다.", "5": "온 · 냉탕을 오가는 목욕은 심부전 환자에게 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "심부전", "term_vi": "Suy tim", "def_ko": "심장의 기능이 저하된 상태", "def_vi": "Tình trạng chức năng tim giảm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (120, '5', '적혈구 부족이 원인이 되어 산소운반능력이 저하되는 질환으로 옳은 것은?', '["고혈압", "빈혈", "심부전", "뇌경색", "동맥경화증"]'::jsonb, 2, '적혈구가 부족하게 되면 산소를 운반하는 능력이 감소하여 다양한 건강 문제를 일으킬 수 있습니다. 이에 따라 적혈구 부족으로 인해 나타날 수 있는 질환 중 빈혈을 찾는 것이 문제의 핵심입니다.', NULL, '{"1": "고혈압은 혈압이 상승하는 질환으로, 적혈구와 직접적인 연관이 없습니다.\n[정답]", "2": "빈혈은 적혈구의 부족으로 인해 발생하는 질환으로, 산소운반능력이 저하됩니다.", "3": "심부전은 심장이 제 기능을 하지 못하게 되는 상태로, 적혈구의 수와는 별개의 문제입니다.", "4": "뇌경색은 뇌의 혈류가 차단되어 발생하는 상태로, 적혈구 부족과는 직접적인 연관이 없습니다.", "5": "동맥경화증은 동맥의 경화에 의한 질환으로, 적혈구 수와는 상관이 없습니다."}'::jsonb, '[{"term_ko": "적혈구", "term_vi": "Hồng cầu", "def_ko": "혈액 내 산소를 운반하는 세포", "def_vi": "Tế bào mang oxy trong máu"}, {"term_ko": "빈혈", "term_vi": "Thiếu máu", "def_ko": "적혈구 수가 부족해지는 질환", "def_vi": "Bệnh do thiếu hụt số lượng hồng cầu"}, {"term_ko": "산소", "term_vi": "Oxy", "def_ko": "우리가 숨쉬면서 몸에 필요한 기체", "def_vi": "Khí cần thiết cho cơ thể mà chúng ta hít vào"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병이나 상태", "def_vi": "Tình trạng sức khỏe không bình thường"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (119, '5', '심장질환 대상자가 복도를 걷다가 어지럼증을 호소할 때 우선적으로 해야 할 행동으로 옳은 것은?', '["따뜻한 녹차를 마시게 한다.", "바로 그 자리에 앉힌다.", "손가락에 사혈을 한다.", "손으로 입을 가리고 숨을 빨리 쉬라고 한다.", "도움을 요청하러 동료 요양보호사에게 간다."]'::jsonb, 2, '심장질환 대상자가 어지럼증을 호소할 때 적절한 응급처치를 고르는 능력을 평가하기 위함입니다.', NULL, '{"1": "따뜻한 녹차를 마시게 한다: 이는 어지럼증 상황에서 적절한 응급처치가 아닙니다.\n[정답]", "2": "바로 그 자리에 앉힌다: 어지럼증을 호소하는 환자를 안전하게 앉혀 안정시키는 것이 최우선입니다.", "3": "손가락에 사혈을 한다: 응급처치에서 필요하지 않은 행동입니다.", "4": "손으로 입을 가리고 숨을 빨리 쉬라고 한다: 이는 오히려 상태를 악화시킬 수 있습니다.", "5": "도움을 요청하러 동료 요양보호사에게 간다: 상황을 즉시 처리해야 하므로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "심장질환", "term_vi": "Bệnh tim mạch", "def_ko": "심장과 관련된 질병", "def_vi": "Các bệnh liên quan đến tim"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (118, '5', '노화에 따른 근골격계 변화로 옳은 것은?', '["관절운동의 제한", "허리의 피하지방 감소", "뼈의 질량 증가", "추간판 두께 증가", "근육의 긴장도 증가"]'::jsonb, 1, '노화가 근골격계에 미치는 영향을 이해하고, 그 변화를 정확히 파악하도록 하는 것입니다.', NULL, '{"1": "노화에 따라 관절의 운동 범위가 줄어들게 됩니다.\n[정답]", "2": "노화와 함께 허리의 피하지방이 증가하는 경향이 있습니다.", "3": "노화로 인해 뼈의 질량은 감소하게 됩니다.", "4": "추간판의 두께는 일반적으로 나이가 들수록 줄어듭니다.", "5": "근육의 긴장도는 노화에 따라 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "노화(한국어)", "def_vi": "lão hóa"}, {"term_ko": "근골격계", "term_vi": "Hệ cơ xương", "def_ko": "근골격계(한국어)", "def_vi": "hệ cơ xương"}, {"term_ko": "관절", "term_vi": "Khớp", "def_ko": "관절(한국어)", "def_vi": "khớp"}, {"term_ko": "운동", "term_vi": "Vận động", "def_ko": "운동(한국어)", "def_vi": "vận động"}, {"term_ko": "허리", "term_vi": "Lưng", "def_ko": "허리(한국어)", "def_vi": "lưng"}, {"term_ko": "피하지방", "term_vi": "Mỡ dưới da", "def_ko": "피하지방(한국어)", "def_vi": "mỡ dưới da"}, {"term_ko": "뼈", "term_vi": "Xương", "def_ko": "뼈(한국어)", "def_vi": "xương"}, {"term_ko": "질량", "term_vi": "Khối lượng", "def_ko": "질량(한국어)", "def_vi": "khối lượng"}, {"term_ko": "추간판", "term_vi": "Đĩa đệm", "def_ko": "추간판(한국어)", "def_vi": "đĩa đệm"}, {"term_ko": "두께", "term_vi": "Độ dày", "def_ko": "두께(한국어)", "def_vi": "độ dày"}, {"term_ko": "근육", "term_vi": "Cơ", "def_ko": "근육(한국어)", "def_vi": "cơ"}, {"term_ko": "긴장도", "term_vi": "Độ căng", "def_ko": "긴장도(한국어)", "def_vi": "độ căng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (117, '5', '다음과 같은 증상을 보이는 질환으로 옳은 것은?• 관절연골의 마모와 관절조직의 퇴화 • 계단을 오르내릴 때 심한 무릎 통증', '["골수염", "골다공증", "골연화증", "고관절 골절", "퇴행성관절염"]'::jsonb, 5, '관절의 퇴화와 통증에 대한 질환을 묻는 문제입니다.', NULL, '{"1": "골수염: 주로 뼈의 감염으로 인한 염증으로 이 증상과는 관련이 없습니다.", "2": "골다공증: 뼈의 밀도가 감소하는 질환이지만, 관절 통증과 관련이 없습니다.", "3": "골연화증: 뼈가 약해지는 질환으로, 직접적인 관절증상과는 차이가 있습니다.", "4": "고관절 골절: 골절은 특정 상황에서 발생하지만, 만성적인 관절통은 설명하지 않습니다.\n[정답]", "5": "퇴행성관절염: 관절연골의 마모와 통증이 주 증상으로, 보기에서 설명한 내용과 일치합니다."}'::jsonb, '[{"term_ko": "관절", "term_vi": "연골", "def_ko": "관절(관 khớp)", "def_vi": "연골(giải phẫu: sụn)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (116, '5', '퇴행성관절염 예방 및 치료로 옳은 것은?', '["가능한 한 움직임을 삼간다.", "통증 부위에 냉찜질을 한다.", "규칙적인 수영을 한다.", "고칼슘 섭취를 한다.", "통증이 있다면 반드시 수술을 한다."]'::jsonb, 3, '퇴행성관절염의 예방과 치료에 대한 올바른 방법을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "가능한 한 움직임을 삼간다는 오히려 관절 기능을 악화시킬 수 있습니다.\n[정답]", "3": "규칙적인 수영은 관절에 부담을 덜 주면서 운동 효과를 볼 수 있는 좋은 방법입니다.", "2": "통증 부위에 냉찜질을 하는 것은 일시적으로 통증을 완화할 수 있지만, 장기적 치료법은 아닙니다.", "4": "고칼슘 섭취는 뼈 건강에 좋지만, 퇴행성관절염과는 직접적인 관련이 없습니다.", "5": "통증이 있다고 해서 반드시 수술이 필요한 것은 아닙니다. 비수술적 치료법이 먼저 시도되어야 합니다."}'::jsonb, '[{"term_ko": "퇴행성관절염", "term_vi": "Viêm khớp thoái hóa", "def_ko": "관절의 퇴행성 변화로 인한 질병", "def_vi": "Bệnh do sự thay đổi thoái hóa của khớp"}, {"term_ko": "예방", "term_vi": "Phòng ngừa", "def_ko": "질병이나 사고를 미리 막는 것", "def_vi": "Ngăn chặn bệnh tật hoặc tai nạn trước khi xảy ra"}, {"term_ko": "치료", "term_vi": "Điều trị", "def_ko": "질병이나 상처를 완화하는 것", "def_vi": "Làm giảm bệnh tật hoặc vết thương"}, {"term_ko": "규칙적인", "term_vi": "Đều đặn", "def_ko": "일정한 규칙을 따르는", "def_vi": "Theo một quy tắc nhất định"}, {"term_ko": "수영", "term_vi": "Bơi lội", "def_ko": "물에서 몸을 움직이는 운동", "def_vi": "Cử động cơ thể trong nước"}, {"term_ko": "냉찜질", "term_vi": "Chườm lạnh", "def_ko": "얼음이나 차가운 물체로 치료하는 방법", "def_vi": "Phương pháp điều trị bằng đá hoặc vật lạnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (115, '5', '골다공증의 관련 요인으로 옳은 것은?', '["충분한 칼슘 섭취", "잦은 음주", "적당한 체중 유지", "비타민 D 섭취", "오전 10시 ~ 오후 2시까지 자외선 쬐기"]'::jsonb, 2, '골다공증과 관련된 요인의 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "충분한 칼슘 섭취는 골밀도를 유지하는 데 도움이 됩니다.\n[정답]", "2": "잦은 음주는 골다공증의 위험을 증가시킵니다.", "3": "적당한 체중 유지는 골다공증 예방에 긍정적으로 작용합니다.", "4": "비타민 D 섭취는 뼈 건강에 중요한 역할을 합니다.", "5": "오전 10시 ~ 오후 2시까지 자외선 쬐기는 비타민 D 생성에 도움이 됩니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈가 약해지는 질환", "def_vi": "Bệnh làm xương trở nên yếu"}, {"term_ko": "칼슘", "term_vi": "Canxi", "def_ko": "뼈를 강화하는 필수 미네랄", "def_vi": "Khoáng chất cần thiết để làm mạnh xương"}, {"term_ko": "비타민 D", "term_vi": "Vitamin D", "def_ko": "뼈 건강에 중요한 비타민", "def_vi": "Vitamin quan trọng cho sức khỏe xương"}, {"term_ko": "자외선", "term_vi": "Tia cực tím", "def_ko": "태양의 광선 중 하나", "def_vi": "Một trong những tia sáng của mặt trời"}, {"term_ko": "체중", "term_vi": "Trọng lượng", "def_ko": "몸무게", "def_vi": "Cân nặng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (114, '5', '골다공증을 예방하는 방법으로 옳은 것은?', '["자외선 차단", "저체중 유지", "체중부하 운동 제한", "부신피질 호르몬 요법", "비타민 D 함유 음식 섭취"]'::jsonb, 5, '골다공증 예방에 필요한 생활습관을 이해하고 있는지를 묻는 문제입니다.', NULL, '{"1": "자외선 차단은 주로 피부암 예방과 관련이 있습니다.\n[정답]", "5": "비타민 D 함유 음식 섭취는 칼슘 흡수를 도와 골다공증 예방에 효과적입니다.", "2": "저체중 유지가 골다공증을 예방한다고 보기 어렵습니다.", "3": "체중부하 운동은 골밀도를 높이는데 도움이 됩니다.", "4": "부신피질 호르몬 요법은 장기 사용 시 오히려 골다공증을 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Bệnh loãng xương", "def_ko": "뼈의 밀도가 감소하여 약해지는 증상", "def_vi": "Tình trạng xương trở nên mỏng và yếu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (113, '5', '골다공증이 있는 노인이 낙상했을 때 발생할 가능성이 높은 질환으로 옳은 것은?', '["추간판 탈출증", "척추측만증", "고관절골절", "강직척추염", "류마티스관절염"]'::jsonb, 3, '골다공증이 있는 노인이 낙상했을 때 발생할 수 있는 질환을 이해하기 위한 문제입니다.', NULL, '{"1": "추간판 탈출증은 주로 젊은 층에서 발생하며 노인의 낙상과는 관련이 적습니다.", "2": "척추측만증은 골다공증과 관련이 없으나 노인에게 흔할 수 있는 질환입니다.\n[정답]", "3": "고관절골절은 골다공증 환자가 낙상했을 때 가장 흔하게 발생하는 부상입니다.", "4": "강직척추염은 염증성 질환으로, 골다공증과 관련이 적습니다.", "5": "류마티스관절염은 관절에 염증을 일으키는 질환이며, 낙상과는 직접적인 연관이 없습니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈의 밀도가 감소하여 취약해지는 질환", "def_vi": "Bệnh làm giảm mật độ xương, làm xương yếu"}, {"term_ko": "낙상", "term_vi": "Ngã", "def_ko": "넘어지는 것", "def_vi": "Bị ngã"}, {"term_ko": "고관절", "term_vi": "Khớp hông", "def_ko": "엉덩이 부위의 관절", "def_vi": "Khớp ở vùng đùi"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병이나 상태", "def_vi": "Tình trạng bệnh lí"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (112, '5', '노화에 따른 여성 생식기계 변화는?', '["난소의 기능 증가", "질의 윤활작용 감소", "난소 크기 증가", "질의 수축력 증가", "여성호르몬 분비 증가"]'::jsonb, 2, '노화가 여성 생식기계에 미치는 영향을 이해하고 확인하기 위함입니다.', NULL, '{"1": "난소의 기능이 증가하는 것은 노화 과정에서 발생하지 않습니다.\n[정답]", "2": "여성의 노화에 따라 질의 윤활작용이 감소합니다.", "3": "난소의 크기는 노화로 인해 오히려 감소합니다.", "4": "질의 수축력은 노화로 인해 감소하지 증가하지 않습니다.", "5": "여성호르몬의 분비는 노화와 함께 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이와 함께 신체의 변화가 일어나는 과정", "def_vi": "Quá trình thay đổi cơ thể theo độ tuổi"}, {"term_ko": "여성", "term_vi": "Phụ nữ", "def_ko": "성별이 여성인 사람", "def_vi": "Người có giới tính nữ"}, {"term_ko": "생식기계", "term_vi": "Hệ thống sinh sản", "def_ko": "생식에 관련된 기관들의 시스템", "def_vi": "Hệ thống các cơ quan liên quan đến sinh sản"}, {"term_ko": "윤활작용", "term_vi": "Chất bôi trơn", "def_ko": "매끄럽게 하는 작용", "def_vi": "Hành động làm mượt mà"}, {"term_ko": "여성호르몬", "term_vi": "Hormone nữ", "def_ko": "여성의 신체에서 주로 생성되는 호르몬", "def_vi": "Hormone chủ yếu được tạo ra trong cơ thể phụ nữ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (111, '5', '남성 노인의 비뇨기계 변화로 옳은 것은?', '["음경이 발기하는 데 시간이 짧게 걸린다.", "대부분의 남성은 전립선 비대를 경험한다.", "잔뇨량이 감소한다.", "방광 용적이 증가한다.", "소변줄기가 굵어진다."]'::jsonb, 2, '남성 노인의 비뇨기계의 일반적인 변화에 대한 이해를 요구하는 문제입니다.', NULL, '{"1": "음경의 발기 시간은 노화로 인해 길어질 수 있습니다.\n[정답]", "2": "많은 남성들이 전립선 비대를 경험합니다.", "3": "잔뇨량은 일반적으로 증가하는 경향이 있습니다.", "4": "방광 용적은 나이가 들수록 감소하는 경향이 있습니다.", "5": "소변줄기는 일반적으로 가늘어지는 경향이 있습니다."}'::jsonb, '[{"term_ko": "비뇨기계", "term_vi": "Hệ tiết niệu", "def_ko": "배설 기관", "def_vi": "Cơ quan đào thải"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (110, '5', '여성 노인에게 나타나는 요실금의 주된 요인으로 옳은 것은?', '["복압감소", "골반근육 조절능력 감소", "요도기능 향상", "호르몬 생산 증가", "방광 저장능력 증가"]'::jsonb, 2, '여성 노인에게 나타나는 요실금의 원인을 이해하기 위한 문제입니다.', NULL, '{"1": "복압의 감소는 요실금과 관련이 없습니다.\n[정답]", "2": "골반근육의 조절능력 감소는 여성 노인에서 요실금을 유발하는 주요 원인입니다.", "3": "요도기능 향상은 요실금과 반대되는 개념입니다.", "4": "호르몬의 생산 증가가 요실금에 도움이 되지는 않습니다.", "5": "방광의 저장능력 증가는 요실금의 발생과 무관합니다."}'::jsonb, '[{"term_ko": "요실금", "term_vi": "Tiểu không tự chủ", "def_ko": "소변을 참지 못하고 새는 증상(한국어)", "def_vi": "Triệu chứng không thể giữ được nước tiểu(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (109, '5', '복압성 요실금의 치료 및 예방법으로 옳은 것은?', '["골반근육 강화운동", "수분 섭취 제한", "과일 섭취 제한", "복부지방 증가", "고단백 식이 식단"]'::jsonb, 1, '복압성 요실금의 치료 및 예방을 위해 어떤 방법이 가장 적절한지를 평가하는 문제입니다.', NULL, '{"1": "골반근육 강화운동은 복압성 요실금에 효과적인 치료법입니다. [정답]", "2": "수분 섭취 제한은 요실금을 악화시킬 수 있습니다.", "3": "과일 섭취 제한은 필요하지 않습니다.", "4": "복부지방 증가는 요실금을 악화할 수 있습니다.", "5": "고단백 식이 식단은 요실금과 관련이 없습니다."}'::jsonb, '[{"term_ko": "복압성", "term_vi": "Béo phì chức năng", "def_ko": "압력이 복부에서 발생하는 상태", "def_vi": "Tình trạng áp lực xảy ra trong bụng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (108, '5', '절박성 요실금이 있는 대상자를 돕는 방법으로 옳은 것은?', '["낮 동안 기저귀를 채워준다.", "골반근육 강화운동을 한다.", "웃음요법 프로그램에 참여하게 한다.", "식이섬유가 적은 음식을 제공한다.", "따뜻한 녹차를 자주 마시게 한다."]'::jsonb, 2, '절박성 요실금에 대한 이해와 적절한 대처 방법을 평가하기 위함입니다.', NULL, '{"1": "기저귀는 일시적인 대처일 뿐, 요실금 치료에 도움이 되지 않는다.\n[정답]", "2": "골반근육 강화운동은 요실금 증상을 완화하는 데 효과적이다.", "3": "웃음요법은 일반적인 스트레스 해소에는 좋지만, 요실금에 직접적인 효과는 없다.", "4": "식이섬유가 적은 음식은 오히려 변비를 유발할 수 있다.", "5": "따뜻한 녹차는 이뇨작용을 촉진할 수 있으므로 요실금에 도움이 되지 않는다."}'::jsonb, '[{"term_ko": "절박성 요실금", "term_vi": "Tiểu không tự chủ cấp bách", "def_ko": "긴급하게 소변이 마려운 상태", "def_vi": "Tình trạng muốn đi tiểu gấp"}, {"term_ko": "골반근육", "term_vi": "Cơ vùng chậu", "def_ko": "골반 부위의 근육", "def_vi": "Các cơ ở vùng chậu"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "소변을 흡수하도록 만든 위생용품", "def_vi": "Sản phẩm vệ sinh dùng để hấp thụ nước tiểu"}, {"term_ko": "식이섬유", "term_vi": "Chất xơ", "def_ko": "장의 건강에 좋은 섬유질", "def_vi": "Chất dinh dưỡng tốt cho sức khỏe ruột"}, {"term_ko": "이뇨작용", "term_vi": "Tác dụng lợi tiểu", "def_ko": "체내의 소변 배출을 촉진하는 작용", "def_vi": "Tác động thúc đẩy việc bài tiết nước tiểu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (107, '5', '전립선비대증의 발생 원인으로 옳은 것은?', '["여성호르몬의 증가", "상행성 요로감염", "복압상승", "방광의 저장능력 감소", "골반근육 조절능력의 약화"]'::jsonb, 1, '전립선비대증의 주요 원인에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "여성호르몬의 증가가 전립선비대증과 관련이 있어 옳은 설명입니다.\n[정답]", "2": "상행성 요로감염은 전립선비대증의 직접적인 원인과는 관련이 적습니다.", "3": "복압상승은 다른 증상과 관련될 수 있으나 전립선비대증의 원인은 아닙니다.", "4": "방광의 저장능력 감소는 결과적으로 나타날 수 있지만 직접적인 원인은 아닙니다.", "5": "골반근육 조절능력의 약화는 관련이 있을 수 있지만 전립선비대증의 주요 원인으로 보기는 어렵습니다."}'::jsonb, '[{"term_ko": "전립선비대증", "term_vi": "Phì đại tuyến tiền liệt", "def_ko": "전립선이 비대해지는 질병", "def_vi": "Bệnh tuyến tiền liệt phì đại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (106, '5', '전립선비대증의 증상에 해당하는 것으로 옳은 것은?', '["소변줄기가 굵어진다.", "배뇨 횟수가 감소한다.", "배뇨 후 잔뇨감이 없다.", "힘을 주어야 소변이 나온다.", "배뇨 후 4시간 이내 소변이 마렵다."]'::jsonb, 4, '전립선비대증의 증상을 이해하고, 각 증상의 구분에 대한 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "전립선비대증에서는 소변줄기가 굵어지지 않습니다.\n[정답]", "2": "전립선비대증에서는 배뇨 횟수가 일반적으로 증가합니다.", "3": "배뇨 후 잔뇨감이 느껴지는 것이 전립선비대증의 증상입니다.", "4": "힘을 주어야만 소변이 나오는 것이 전립선비대증의 증상입니다.", "5": "배뇨 후 4시간 이내 소변이 마렵다는 증상은 전립선비대증과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "전립선비대증", "term_vi": "BPH", "def_ko": "전립선의 크기가 커지는 상태", "def_vi": "Tình trạng kích thước tuyến tiền liệt bị phình to"}, {"term_ko": "배뇨", "term_vi": "Đi tiểu", "def_ko": "소변을 보는 행위", "def_vi": "Hành động đi vệ sinh"}, {"term_ko": "잉여", "term_vi": "Dư", "def_ko": "남은 것", "def_vi": "Cái còn lại"}, {"term_ko": "소변줄기", "term_vi": "Dòng nước tiểu", "def_ko": "소변의 흐름", "def_vi": "Dòng chảy của nước tiểu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (105, '5', '전립선비대증을 관리하는 방법으로 옳은 것은?', '["노화현상이므로 약물은 사용하지 않는다.", "소변량을 증가시키기 위해 맥주를 마신다.", "고지방과 고콜레스테롤 음식 섭취를 피한다.", "소변을 참을 수 있을 때까지 참는다.", "약화된 근육을 강화하기 위해 체중을 늘린다."]'::jsonb, 3, '전립선비대증 관리 방법에 대한 이해를 평가하기 위한 문제이다.', NULL, '{"1": "전립선비대증 관리에 있어 약물 치료는 일반적이지 않다고 할 수 없으며, 필요에 따라 사용해야 한다.\n[정답]", "3": "고지방 및 고콜레스테롤 음식은 전립선 건강에 좋지 않으므로 피해야 한다.", "2": "맥주는 오히려 소변을 자극할 수 있어 바람직하지 않다.", "4": "소변을 지나치게 참는 것은 방광에 해롭고 전립선에 좋지 않다.", "5": "체중을 늘리는 것은 오히려 근육을 약화시킬 수 있으며 건강에 좋지 않다."}'::jsonb, '[{"term_ko": "전립선비대증", "term_vi": "Bệnh phì đại tuyến tiền liệt", "def_ko": "남성의 전립선이 비대해지는 질환", "def_vi": "Bệnh tuyến tiền liệt to lên ở nam giới"}, {"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약을 의미하는 용어", "def_vi": "Từ ngữ dùng để chỉ thuốc"}, {"term_ko": "고지방", "term_vi": "Chất béo cao", "def_ko": "지방이 많은 것", "def_vi": "Đồ ăn giàu chất béo"}, {"term_ko": "고콜레스테롤", "term_vi": "Cholesterol cao", "def_ko": "콜레스테롤이 많은 것", "def_vi": "Đồ ăn chứa nhiều cholesterol"}, {"term_ko": "소변", "term_vi": "Nước tiểu", "def_ko": "인간의 배설물", "def_vi": "Chất thải của cơ thể con người"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (104, '5', '노화에 따른 피부질환의 특성으로 옳은 것은?', '["표피가 얇아져 탄력성이 증가한다.", "상처회복이 지연되고 궤양이 생기기 쉽다.", "손톱과 발톰이 얇아진다.", "피하지방의 증가로 기온에 둔감해진다.", "각질층의 수분함량의 증가로 소양증이 증가한다."]'::jsonb, 2, '노화에 따른 피부질환의 특성을 이해하고 올바른 설명을 찾기 위함입니다.', NULL, '{"1": "표피가 얇아지면 탄력성이 감소합니다.\n[정답]", "2": "노화로 인해 상처회복이 지연되고 궤양이 생기기 쉬워집니다.", "3": "손톱과 발톱이 얇아지는 것은 맞지만, 지문과는 관계가 적습니다.", "4": "피하지방의 감소로 기온에 둔감해지는 것이 더 일반적입니다.", "5": "각질층의 수분함량이 감소하여 소양증이 증가합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 들면서 신체나 정신의 변화", "def_vi": "Sự thay đổi về thể chất hoặc tâm lý theo độ tuổi"}, {"term_ko": "피부질환", "term_vi": "Bệnh da", "def_ko": "피부에서 발생하는 질환", "def_vi": "Các bệnh xảy ra ở da"}, {"term_ko": "상처", "term_vi": "Vết thương", "def_ko": "피부의 손상", "def_vi": "Sự tổn thương trên da"}, {"term_ko": "궤양", "term_vi": "Loét", "def_ko": "깊은 피부 손상", "def_vi": "Tổn thương sâu trên da"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "몸의 방어 반응", "def_vi": "Phản ứng bảo vệ của cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (103, '5', '욕창의 위험성이 높은 대상자로 옳은 것은?', '["영양 부족으로 피하지방이 감소한 대상자", "침상에서 뒤척이는 대상자", "체중을 잘 유지하는 대상자", "요실금이나 변실금이 없는 대상자", "침상 이동시 밀림이 없는 대상자"]'::jsonb, 1, '욕창 발생 위험 인자를 파악하도록 유도하는 문제입니다.', NULL, '{"1": "영양 부족은 피부의 건강에 영향을 미쳐 욕창 위험을 높입니다.\n[정답]", "2": "침상에서 뒤척이는 것은 욕창 위험을 낮추는 요소입니다.", "3": "체중을 잘 유지하는 경우 욕창 발생 위험이 낮습니다.", "4": "요실금이나 변실금이 없는 경우 욕창 위험이 낮습니다.", "5": "침상 이동 시 밀림이 없으면 욕창 위험이 낮아집니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Nguyên nhân gây loét", "def_ko": "압력에 의해 피부가 손상되는 상태(pressure ulcer)", "def_vi": "Nguyên nhân gây ra loét do nằm lâu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (102, '5', '대상자에게 욕창을 발생시킬 가능성이 높은 요양보호사의 행동은?', '["체위를 자주 변경해준다.", "침상 시트의 주름을 펴준다.", "무릎 사이에 베개는 제거한다.", "천골 부위에 도넛 베개 사용을 삼간다.", "목욕 후에 피부를 완전히 말려준다."]'::jsonb, 3, '욕창 예방과 관련된 요양보호사의 행동을 평가하는 것이다.', NULL, '{"1": "체위를 자주 변경해주는 것은 욕창 예방에 도움이 된다.", "2": "침상 시트의 주름을 펴주는 것은 편안함을 제공하고 피부 손상을 예방하는 데 기여한다.\n[정답]", "3": "무릎 사이에 베개는 제거해야 한다. 무릎 사이에 베개가 있으면 압력이 증가해 욕창 발생 가능성이 높아진다.", "4": "천골 부위에 도넛 베개 사용을 삼가는 것은 압력을 분산시켜 욕창 예방에 기여한다.", "5": "목욕 후에 피부를 완전히 말려주는 것은 피부 건강을 유지하는 데 중요하다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét do tì đè", "def_ko": "피부가 오랫동안 압력을 받아 손상되는 상태", "def_vi": "Tình trạng da bị tổn thương do áp lực kéo dài"}, {"term_ko": "체위", "term_vi": "Tư thế", "def_ko": "몸의 자세", "def_vi": "Tư thế của cơ thể"}, {"term_ko": "베개", "term_vi": "Gối", "def_ko": "머리를 받치는 물건", "def_vi": "Đồ vật dùng để đỡ đầu"}, {"term_ko": "천골", "term_vi": "Xương cùng", "def_ko": "척추의 아래쪽 부분", "def_vi": "Phần dưới cùng của cột sống"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (101, '5', '욕창을 예방하는 방법으로 옳은 것은?', '["천골부위에 도넛 베개를 대어준다.", "정해진 시간에 자세변경을 한다.", "단백질을 충분히 보충한다.", "목욕 후 파우더를 사용한다.", "오염물질은 알코올로 닦아낸다."]'::jsonb, 3, '욕창 예방에 대한 이해도를 측정하려는 의도입니다.', NULL, '{"1": "천골부위에 도넛 베개를 대는 것은 도움이 될 수 있지만 반드시 필요하지는 않습니다. \n[정답]", "2": "정해진 시간에 자세변경을 하는 것은 욕창 예방에 매우 중요합니다.", "3": "단백질을 충분히 보충하는 것은 피부 재생에 도움이 되어 욕창 예방에 기여할 수 있습니다.", "4": "목욕 후 파우더를 사용하는 것은 피부를 보호할 수 있지만 욕창 예방의 직접적인 방법은 아닙니다.", "5": "오염물질은 알코올로 닦아내는 것보다 적절한 방법으로 씻어내는 것이 좋습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "압력으로 인한 피부 손상", "def_vi": "Tổn thương da do áp lực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (100, '5', '노인에게 흔한 피부건조증을 예방하기 위한 생활 습관으로 옳은 것은?', '["수분섭취를 줄인다.", "알코올이 함유된 세정제를 사용한다.", "겨울철 실내 제습기를 사용한다.", "때를 밀어 피부의 청결을 유지한다.", "목욕 후 몸에 물기가 마르기 전에 보습제를 바른다."]'::jsonb, 5, '노인에게 피부건조증 예방을 위한 생활습관을 이해하고 적용하는 것.', NULL, '{"1": "수분섭취를 줄이면 피부건조증이 악화된다. 이는 잘못된 선택이다.\n[정답]", "5": "목욕 후 몸에 물기가 마르기 전에 보습제를 바르는 것은 피부의 수분을 유지하는 좋은 방법이다.", "2": "알코올이 함유된 세정제는 피부를 더욱 건조하게 하므로 잘못된 선택이다.", "3": "겨울철 실내 제습기는 습도가 낮아져 피부건조증이 악화될 수 있으므로 잘못된 선택이다.", "4": "때를 밀리면 피부의 보호막이 손상될 수 있으므로 잘못된 선택이다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "어르신(한국어)", "def_vi": "Người già"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (99, '5', '수두를 일으키는 바이러스에 의해 피부와 신경에 ㅇ염증이 생기는 질환으로 옳은 것은?', '["욕창", "피부 건조증", "대상포진", "옴", "머릿니"]'::jsonb, 3, '수두를 일으키는 바이러스에 의해 발생하는 피부와 신경에 염증이 생기는 질환을 묻는 문제입니다.', NULL, '{"1": "욕창: 주로 장시간 눕거나 앉은 자세로 인해 피부 손상이 발생하는 것이므로 정답이 아닙니다.", "2": "피부 건조증: 피부 수분 부족으로 인해 생기는 문제로 염증과는 관련이 없습니다.\n[정답]", "3": "대상포진: 수두 바이러스가 재활성화되어 피부와 신경에 염증을 일으키는 질환입니다.", "4": "옴: 피부 기생충에 의한 질환으로 수두와는 관련이 없습니다.", "5": "머릿니: 두피에 기생하는 이로 인한 감염으로, 수두와는 관계가 없습니다."}'::jsonb, '[{"term_ko": "수두", "term_vi": "Thủy đậu", "def_ko": "물집이 생기는 감염병(한국어)", "def_vi": "Bệnh lây nhiễm có mụn nước"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "상처나 감염으로 인해 생기는 부풀어 오른 상태(한국어)", "def_vi": "Tình trạng sưng tấy xảy ra do vết thương hoặc nhiễm trùng"}, {"term_ko": "대상포진", "term_vi": "Zona", "def_ko": "수두 바이러스 재활성화에 따른 피부와 신경염증(한국어)", "def_vi": "Viêm da và thần kinh do virus gây thuỷ đậu tái hoạt động"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (98, '5', '대상포진의 주요 증상으로 옳은 것은?', '["작열감을 포함한 발진이 생긴다.", "전신에 수포가 생긴다.", "혈관성 질환이다.", "인플루엔자 바이러스가 원인이다.", "물집이 나타난 이후 통증이 발생한다."]'::jsonb, 1, '대상포진의 주요 증상에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "작열감을 포함한 발진이 나타나는 것이 맞습니다.\n[정답]", "2": "전신에 수포가 생기지는 않으며, 특정 피부에 발생합니다.", "3": "혈관성 질환이 아니라 바이러스 감염에 의한 질환입니다.", "4": "인플루엔자 바이러스가 아닌 수두 대상포진 바이러스가 원인입니다.", "5": "물집이 나타난 이후에는 통증이 있을 수 있으나, 초기부터 통증이 발생할 수 있습니다."}'::jsonb, '[{"term_ko": "대상포진", "term_vi": "Zona", "def_ko": "질병명(한국어)", "def_vi": "Tên bệnh"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증상(한국어)", "def_vi": "Triệu chứng"}, {"term_ko": "발진", "term_vi": "Phát ban", "def_ko": "발진(한국어)", "def_vi": "Phát ban"}, {"term_ko": "수포", "term_vi": "Bọng nước", "def_ko": "물집(한국어)", "def_vi": "Bọng nước"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "통증(한국어)", "def_vi": "Đau"}, {"term_ko": "바이러스", "term_vi": "Virus", "def_ko": "바이러스(한국어)", "def_vi": "Virus"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (97, '5', '옴에 감염된 대상자를 돕는 방법으로 옳은 것은?', '["음식 섭취로 인한 알레르기 증상이다.", "가려운 부위에만 연고를 도포한다.", "아침에 약을 바르고 잠자기 전에 씻어낸다.", "감염 부위를 만져서 열감이 있는지 확인한다.", "대상자의 동거 가족은 증상이 없어도 함께 치료 받는다."]'::jsonb, 5, '옴 감염에 대한 올바른 대처 방법을 알고 있는지 확인하기 위함입니다.', NULL, '{"1": "음식 섭취로 인한 알레르기 증상이 아니다. 따라서 옳지 않다.\n[정답]", "5": "대상자의 동거 가족도 증상이 없어도 함께 치료 받아야 한다. 이는 전염성을 고려한 접근이다.", "2": "가려운 부위에만 연고를 도포하는 것은 불완전한 접근법이다. 따라서 옳지 않다.", "3": "아침에 약을 바르고 잠자기 전에 씻어내는 것은 올바른 방식이 아니다. 따라서 옳지 않다.", "4": "감염 부위를 만져서 열감이 있는지 확인하는 것은 감염 확인의 방법이지만, 옳은 치료 방법이 아니다. 따라서 옳지 않다."}'::jsonb, '[{"term_ko": "옴", "term_vi": "Bệnh ghẻ", "def_ko": "병(한국어)", "def_vi": "Bệnh ghẻ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (96, '5', '머릿니에 감염된 대상자의 돕기 방법으로 옳은 것은?', '["1달 간격으로 2회 약물치료를 한다.", "대상자가 사용했던 침구류는 함께 사용한다.", "침구류는 찬물에 5시간 이상 담갔다 세탁한다.", "머리는 대상자가 원할 때 감긴다.", "진공청소기로 방안을 꼼꼼히 청소한다."]'::jsonb, 5, '대상자가 머릿니에 감염되었을 때 적절한 대처 방법을 알고 있는지를 확인하는 문제이다.', NULL, '{"1": "1달 간격으로 약물치료를 하는 것은 적절한 방법이 아니다. 머릿니 제거는 즉각적으로 이루어져야 한다.\n[정답]", "5": "진공청소기로 방안을 청소하는 것은 머릿니와 그 알을 효과적으로 제거하는 방법으로 옳다.", "3": "침구류를 찬물에 5시간 이상 담가 세탁하는 것은 효과적이지 않다. 높은 온도의 물에서 세탁해야 한다.", "4": "머리는 대상자의 원할 때가 아니라 정해진 주기로 세척해야 한다.", "2": "대상자가 사용했던 침구류는 따로 사용해야 한다."}'::jsonb, '[{"term_ko": "머릿니", "term_vi": "Chí đầu", "def_ko": "머리에 감염되는 곤충", "def_vi": "Côn trùng ký sinh trên đầu"}, {"term_ko": "약물치료", "term_vi": "Điều trị bằng thuốc", "def_ko": "약으로 치료하는 방법", "def_vi": "Phương pháp điều trị bằng thuốc"}, {"term_ko": "진공청소기", "term_vi": "Máy hút bụi", "def_ko": "먼지를 빨아들이는 기계", "def_vi": "Thiết bị hút bụi"}, {"term_ko": "침구류", "term_vi": "Đồ dùng giường", "def_ko": "침대에서 사용하는 물품", "def_vi": "Vật phẩm sử dụng trên giường"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "빨래를 하는 것", "def_vi": "Hành động giặt giũ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (95, '5', '기저귀피부염이 있는 대상자의 돕기 방법으로 옳은 것은?', '["회음부 접촉 부위에 생긴다.", "경계가 분명한 병변이 있다.", "멍 자국 같은 푸른 병변이다.", "기저귀를 자주 갈아준다.", "항생제를 처방받아 바른다."]'::jsonb, 4, '기저귀 피부염을 겪고 있는 대상자에게 어떻게 돕는 것이 적절한지를 묻는 문제이다.', NULL, '{"1": "기저귀 피부염은 주로 회음부 접촉 부위에서 발생할 수 있지만, 이 보기는 도움 방법이 아니다.\n[정답]", "4": "기저귀 피부염의 예방과 관리를 위해 기저귀를 자주 갈아주는 것이 중요하다.", "2": "경계가 분명한 병변을 나타낼 수 있으나, 이는 도움 방법이 아니다.", "3": "멍 자국 같은 푸른 병변은 기저귀 피부염의 증상이 아니다.", "5": "항생제는 일반적으로 기저귀 피부염에 대한 치료 방법이 아니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "아기나 노인이 사용하는 보호용 기구", "def_vi": "vật dụng bảo vệ được sử dụng cho trẻ em hoặc người già"}, {"term_ko": "피부염", "term_vi": "Viêm da", "def_ko": "피부의 염증", "def_vi": "viêm nhiễm da"}, {"term_ko": "돕기", "term_vi": "Giúp đỡ", "def_ko": "지원하다, 도와주다", "def_vi": "trợ giúp, giúp đỡ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (94, '5', '다음과 같은 특성이 있을 때 의심할 수 있는 질환으로 옳은 것은?• 과도한 자극, 자외선 노출 등 스테로이드 연고 도포에 의해 생긴 출혈 • 손등, 팔에 경계가 뚜렷한 다양한 크기와 모양', '["건선", "기저귀 습진", "노인성 자반", "대상포진", "우정문신"]'::jsonb, 3, '이 문제는 피부에 나타나는 증상으로 어떤 질환을 의심할 수 있는지를 평가하는 데 목적이 있습니다.', NULL, '{"1": "건선: 만성적인 염증성 피부질환으로, 가려움증과 함께 인설이 생기기 때문에 제외됩니다.", "2": "기저귀 습진: 주로 아기에게 발생하며, 자극과 관련된 질환이지만 해당 특성과는 거리가 멉니다.\n[정답]", "3": "노인성 자반: 노인에게 흔한 피부출혈로, 경계가 뚜렷하고 여러 모양이 나타나는 특성과 일치합니다.", "4": "대상포진: 신경에 의한 통증과 물집이 특징이며, 질문의 해당 특성과는 적합하지 않습니다.", "5": "우정문신: 특정한 문양이나 문신과 관계된 것이므로 해당 증상과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "특성", "term_vi": "Đặc tính", "def_ko": "특점(한국어)", "def_vi": "đặc điểm(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (93, '5', '노화에 따른 신경계 변화로 옳은 것은?', '["신경세포기능의 향상", "근긴장 반응성 향상", "정서 조절의 안정", "운동부족으로 인한 숙면", "단기기억의 감퇴"]'::jsonb, 5, '노화에 따른 신경계의 변화를 이해하고, 그 중 어떠한 변화가 옳은지를 선택하는 것이 목적이다.', NULL, '{"1": "신경세포기능의 향상은 일반적으로 노화와 관련해 옳지 않다.\n[정답]", "5": "단기기억의 감퇴가 노화와 관련된 신경계 변화로 맞다.", "2": "근긴장 반응성 향상은 나이가 들면서 오히려 감소하는 경향이 있다.", "3": "정서 조절의 안정은 노화에 따라 오히려 어려워질 수 있다.", "4": "운동부족으로 인한 숙면은 노화와 관계없이 일반적인 현상이다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 많아짐(한국어)", "def_vi": "Sự tăng tuổi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (92, '5', '노화에 따른 시각의 변화로 옳은 것은?', '["눈물 양의 증가", "각막반사의 증가", "색의 식별능력 증가", "눈부심의 증가", "결막 두께의 증가"]'::jsonb, 4, '노화가 시각에 미치는 영향을 이해하고, 노화로 인해 발생하는 시각적 변화의 올바른 예를 선택하는 것입니다.', NULL, '{"1": "눈물 양의 증가는 노화와 관련해 일반적이지 않습니다.\n[정답]", "4": "눈부심의 증가는 노화로 인해 발생할 수 있는 시각적 변화입니다.", "2": "각막반사의 증가는 노화와 관계가 없습니다.", "3": "색의 식별능력은 노화에 따라 감소하는 경향이 있습니다.", "5": "결막 두께는 노화에 따라 변하지 않거나 감소할 수 있습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙다(한국어)", "def_vi": "Già đi(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (91, '5', '노화에 따른 청각계 변화에 대한 설명으로 옳은 것은?', '["고막이 얇아진다.", "이관이 좁아진다.", "외이도가 습해진다.", "평형감각이 향상된다.", "난청은 여성에게 흔하다."]'::jsonb, 2, '노화에 따른 청각계 변화에 대한 이해와 그에 따른 신체적 변화의 현상을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "고막이 얇아지는 것이 아니라 두꺼워질 수 있습니다.\n[정답]", "2": "노화에 따라 이관(귀와 목을 연결하는 관)이 좁아지는 것이 일반적입니다.", "3": "외이도가 습해지는 것이 아니라 건조해질 수 있습니다.", "4": "평형감각은 노화에 따라 저하될 수 있습니다.", "5": "난청은 남성에게 더 흔하게 발생합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "청각계", "def_ko": "나이듦(già hóa)", "def_vi": "듣는 시스템(hệ thống thính giác)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (90, '5', '노화에 따른 미각의 변화로 옳은 것은?', '["미뢰의 기능 증가", "혀의 유두 돌기 증가", "입술 근육의 탄력성 증가", "구강건조 증상 감소", "구강 점막의 재생 능력 감소"]'::jsonb, 5, '노화에 따른 인체의 미각 변화에 관한 이해를 평가하고자 함.', NULL, '{"1": "미뢰의 기능은 노화에 따라 감소하며, 증가하지 않는다.", "2": "혀의 유두 돌기도 노화로 인해 감소하거나 변화한다.", "3": "입술 근육의 탄력성은 노화에 따라 감소한다.", "4": "구강건조 증상은 노화와 관련하여 증가할 수 있다.\n[정답]", "5": "구강 점막의 재생 능력은 노화에 따라 감소하게 된다."}'::jsonb, '[{"term_ko": "미각", "term_vi": "Vị giác", "def_ko": "맛을 느끼는 능력(한국어)", "def_vi": "Khả năng cảm nhận vị"}, {"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 많아지는 것(한국어)", "def_vi": "Sự gia tăng tuổi tác"}, {"term_ko": "미뢰", "term_vi": "Nụ vị giác", "def_ko": "맛을 느끼는 기관(한국어)", "def_vi": "Cơ quan cảm nhận vị"}, {"term_ko": "구강", "term_vi": "Khoang miệng", "def_ko": "입과 관련된 부분(한국어)", "def_vi": "Phần liên quan đến miệng"}, {"term_ko": "점막", "term_vi": "Niêm mạc", "def_ko": "내장기관을 덮고 있는 얇은 막(한국어)", "def_vi": "Màng mỏng bao phủ cơ quan nội tạng"}, {"term_ko": "재생", "term_vi": "Tái sinh", "def_ko": "다시 살아나는 것(한국어)", "def_vi": "Sự sống lại"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (89, '5', '노화에 따른 감각기계 변화로 옳은 것은?', '["맛에 대한 감지능력이 예민해진다.", "후각세포의 감소로 둔화가 나타난다.", "접촉의 강도가 낮아야 접촉감을 느낄 수 있다.", "통증에 대한 민감성이 증가한다.", "넓은 홀에서는 큰 소리로 소통을 한다."]'::jsonb, 2, '노화에 따른 감각기계의 변화를 인지하고, 올바른 변화를 선택하도록 유도하는 문제입니다.', NULL, '{"1": "노화로 인해 맛에 대한 감지능력은 일반적으로 둔화됩니다.\n[정답]", "2": "후각세포가 감소함에 따라 후각의 둔화가 나타납니다.", "3": "노화로 인해 접촉에 대한 민감성이 떨어지므로, 접촉의 강도가 높아야 감지를 할 수 있습니다.", "4": "통증에 대한 민감성은 노화와 함께 감소하는 경향이 있습니다.", "5": "큰 소리로 소통할 필요가 있는 것은 일반적인 상황이 아닙니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이 때문에 신체의 기능이 퇴화되어 가는 과정", "def_vi": "Quá trình chức năng cơ thể suy giảm do tuổi tác"}, {"term_ko": "감각기계", "term_vi": "Hệ thống cảm giác", "def_ko": "신체에서 감각 정보를 처리하는 시스템", "def_vi": "Hệ thống xử lý thông tin cảm giác trong cơ thể"}, {"term_ko": "후각세포", "term_vi": "Tế bào khứu giác", "def_ko": "냄새를 감지하는 세포", "def_vi": "Tế bào phát hiện mùi"}, {"term_ko": "둔화", "term_vi": "Giảm nhạy cảm", "def_ko": "감각의 반응 속도나 강도가 줄어드는 것", "def_vi": "Sự giảm tốc độ hoặc cường độ phản ứng cảm giác"}, {"term_ko": "민감성", "term_vi": "Độ nhạy cảm", "def_ko": "특정 자극에 반응하는 정도", "def_vi": "Mức độ phản ứng với một kích thích"}, {"term_ko": "소통", "term_vi": "Giao tiếp", "def_ko": "의사 소통을 하는 행위", "def_vi": "Hành động trao đổi thông tin"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (88, '5', '눈의 압력 상승으로 인한 시신경이 손상되어 시력이 점차 약해지고, 안구에 통증이 있는 질환으로 옳은 것은?', '["결막염", "황반변성", "백내장", "녹내장", "수정체 황화현상"]'::jsonb, 4, '눈의 압력 상승과 시신경 손상, 시력 약화 및 안구 통증과 관련된 질환을 묻는 문제입니다.', NULL, '{"1": "결막염은 눈의 결막에 염증이 생기는 질환으로, 압력 상승과는 관련이 없습니다.", "2": "황반변성은 시력의 중심 부위인 황반에 문제가 발생하는 질환으로, 통증을伴わ나 눈의 압력 상승과 관련은 없습니다.", "3": "백내장은 수정체가 혼탁해져 시력이 저하되는 질환으로, 눈의 압력 상승과는 관련이 없습니다.\n[정답]", "4": "녹내장은 눈의 압력이 상승하여 시신경이 손상되고 시력이 약해지는 질환으로, 통증이 동반될 수 있습니다.", "5": "수정체 황화현상은 노화로 인한 수정체의 변화로 시력에 영향을 줄 수 있으나 압력 상승과는 직접적인 연관이 없습니다."}'::jsonb, '[{"term_ko": "압력", "term_vi": "Áp suất", "def_ko": "압력(한국어)", "def_vi": "Áp lực(베트남어)"}, {"term_ko": "시신경", "term_vi": "Dây thần kinh thị giác", "def_ko": "시각을 전달하는 신경(한국어)", "def_vi": "Dây dẫn truyền thị giác(베트남어)"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔(한국어)", "def_vi": "Cảm giác đau(베트남어)"}, {"term_ko": "황반", "term_vi": "Điểm vàng", "def_ko": "시각의 중심부(한국어)", "def_vi": "Điểm trung tâm của thị lực(베트남어)"}, {"term_ko": "녹내장", "term_vi": "Glôcôm", "def_ko": "눈의 질환(한국어)", "def_vi": "Bệnh mắt(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (87, '5', '녹내장 대상자의 바람직한 일상생활 습관으로 옳은 것은?', '["겨울철에 스키를 즐긴다.", "무거운 물건 드는 것을 피한다.", "물구나무 서기로 상체 순환을 돕는다.", "머리를 숙인 자세에서 독서를 한다.", "몸에 꽉 끼는 옷을 입어 체온을 유지한다."]'::jsonb, 2, '녹내장 대상자가 일상생활에서 어떤 습관을 가지는 것이 바람직한지를 물어보는 문제입니다.', NULL, '{"1": "겨울철에 스키를 즐기는 것은 시각에 부담을 줄 수 있어 바람직하지 않습니다.\n[정답]", "2": "무거운 물건 드는 것을 피하는 것은 눈에 부담을 줄일 수 있는 좋은 습관입니다.", "3": "물구나무 서기는 혈압에 영향을 줄 수 있어 추천되지 않습니다.", "4": "머리를 숙인 자세에서 독서는 시야에 부담을 주므로 바람직하지 않습니다.", "5": "몸에 꽉 끼는 옷을 입는 것은 체온을 유지하는 데 도움이 되지 않으며 불편함을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "녹내장", "term_vi": "Glaucom", "def_ko": "눈의 압력이 높아지는 질환(병)", "def_vi": "Bệnh tăng áp lực mắt"}, {"term_ko": "바람직한", "term_vi": "Thích hợp", "def_ko": "좋은, 바람직한", "def_vi": "Tốt, phù hợp"}, {"term_ko": "물구나무서기", "term_vi": "Đứng bằng đầu", "def_ko": "머리를 아래로 하고 서 있는 자세", "def_vi": "Tư thế đứng ngược"}, {"term_ko": "머리를 숙인 자세", "term_vi": "Tư thế cúi đầu", "def_ko": "머리가 아래로 기울어진 자세", "def_vi": "Tư thế nghiêng đầu xuống"}, {"term_ko": "체온", "term_vi": "Nhiệt độ cơ thể", "def_ko": "몸의 온도", "def_vi": "Nhiệt độ của cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (86, '5', '백내장은 ☐ 이(가) 혼탁해져서 빛이 드러가지 못하여 시력장애가 발생하는 질환이다. ☐안에 들어갈 부위로 옳은 것은?', '["각막", "결막", "공막", "수정체", "홍채"]'::jsonb, 4, '백내장에 대한 이해도를 평가하기 위한 문제입니다. 백내장은 눈의 특정 부위가 혼탁해지는 현상으로 시력에 영향을 미치는 질환입니다.', NULL, '{"1": "각막: 외부에서 들어오는 빛을 투과시키는 역할을 하지만 백내장과는 관련이 없습니다.", "2": "결막: 눈꺼풀 안쪽과 안구 표면을 덮고 있는 점막으로, 백내장과 관련이 없습니다.", "3": "공막: 안구의 외벽으로, 백내장과는 관련이 없습니다.\n[정답]", "4": "수정체: 백내장은 수정체가 혼탁해지는 질환으로, 시력장애를 유발합니다.", "5": "홍채: 눈의 색을 결정하고 빛의 양을 조절하지만, 백내장과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "백내장", "term_vi": "혼탁", "def_ko": "질환(병) / bệnh đục thủy tinh thể", "def_vi": "흐림(먼지나 얼룩) / mờ đục"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (85, '5', '백내장의 주요 증상으로 옳은 것은?', '["뿌옇게 혼탁한 각막", "안구의 통증", "두통, 구역질", "심하면 실명됨", "통증이 없으면서 점차 흐려지는 시력"]'::jsonb, 5, '백내장의 주요 증상을 이해하고 식별하는 능력을 평가하기 위함입니다.', NULL, '{"1": "뿌옇게 혼탁한 각막은 백내장과 관련이 없으며 주로 각막 질환과 연관이 있습니다.", "2": "안구의 통증은 백내장으로 인한 주요 증상이 아닙니다.", "3": "두통과 구역질은 백내장과 직접적인 관련이 없습니다.\n[정답]", "4": "심하면 실명됨은 백내장이 심해질 경우의 결과를 설명하나 주요 증상으로는 적합하지 않습니다.", "5": "통증이 없으면서 점차 흐려지는 시력은 백내장의 일반적인 증상으로 맞습니다."}'::jsonb, '[{"term_ko": "백내장", "term_vi": "Thủy tinh thể", "def_ko": "노안의 주요 원인으로 시력이 흐릿해지는 상태", "def_vi": "Trạng thái thị lực bị mờ do nguyên nhân chủ yếu là thoái hóa"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증상, dấu hiệu", "def_vi": "Dấu hiệu"}, {"term_ko": "실명", "term_vi": "Mù", "def_ko": "시력을 잃는 상태", "def_vi": "Trạng thái mất thị lực"}, {"term_ko": "혼탁", "term_vi": "Mờ đục", "def_ko": "깨끗하지 않음, 흐림", "def_vi": "Không rõ ràng, bị đục"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (84, '5', '노화로 나타날 수 있는 내분비계 변화로 옳은 것은?', '["공복 혈당이 감소한다.", "인슐린에 대한 민감성이 감소한다.", "기초대사율이 증가한다.", "근육의 질량이 증가한다.", "갑상선호르몬 분비가 증가한다."]'::jsonb, 2, '노화와 관련된 내분비계의 변화를 이해하고 있는지를 평가하기 위한 질문입니다.', NULL, '{"1": "공복 혈당은 노화로 인해 증가하는 경향이 있습니다.\n[정답]", "2": "노화가 진행됨에 따라 인슐린에 대한 민감성이 감소합니다.", "3": "기초대사율은 대개 노화에 따라 감소합니다.", "4": "근육의 질량은 노화에 따라 감소하는 경향이 있습니다.", "5": "갑상선호르몬의 분비는 일반적으로 노화와 함께 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙음(한국어)", "def_vi": "Sự già đi(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (83, '5', '당뇨병의 주요 증상으로 옳은 것은?', '["음식 섭취량 감소", "감각 민감성 증가", "갈증 감소", "소변 배설량 증가", "수분 섭취량 감소"]'::jsonb, 4, '당뇨병의 주요 증상을 이해하고 이를 정확하게 인식하는지 평가하기 위함입니다.', NULL, '{"1": "음식 섭취량 감소: 당뇨병 환자들은 일반적으로 음식 섭취량이 감소하지 않습니다.\n[정답]", "4": "소변 배설량 증가: 당뇨병의 주요 증상 중 하나로, 혈당 수치가 높아지면 소변으로 배설되는 당분이 많아져 소변 배설량이 증가하게 됩니다.", "2": "감각 민감성 증가: 당뇨병 환자들은 오히려 감각이 둔해질 수 있습니다.", "3": "갈증 감소: 당뇨병 환자는 갈증이 증가하는 것이 일반적입니다.", "5": "수분 섭취량 감소: 당뇨병 환자는 수분 섭취가 늘어나는 경향이 있습니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "질병의 일종으로 인슐린의 분비 이상 또는 인슐린 저항성으로 혈당 조절이 안 되는 상태", "def_vi": "Một loại bệnh do sự rối loạn tiết insulin hoặc kháng insulin dẫn đến không kiểm soát được mức đường trong máu"}, {"term_ko": "갈증", "term_vi": "Cảm giác khát", "def_ko": "목이 마르다는 느낌", "def_vi": "Cảm giác muốn uống nước"}, {"term_ko": "소변", "term_vi": "Nước tiểu", "def_ko": "신장에서 만들어지는 액체", "def_vi": "Chất lỏng được sản xuất bởi thận"}, {"term_ko": "수분", "term_vi": "Thành phần nước", "def_ko": "물의 양", "def_vi": "Lượng nước"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (82, '5', '당뇨병 대상자가 인슐린 주사를 맞고 식사를 하지 않았을 때 증상으로 옳은 것은?', '["땀을 많이 흘림", "배뇨 증가", "식욕 증가", "체온 상승", "피로감"]'::jsonb, 1, '인슐린 주사 후 식사를 하지 않은 경우 발생할 수 있는 증상을 묻는 문제입니다.', NULL, '{"1": "땀을 많이 흘림: 인슐린을 맞고 식사를 하지 않으면 저혈당증이 발생할 수 있으며, 이때 땀을 많이 흘리는 증상이 나타날 수 있습니다.\n[정답]", "2": "배뇨 증가: 식사와 관련이 적고, 저혈당과는 관련이 적습니다.", "3": "식욕 증가: 저혈당 상태에서는 대개 식욕이 증가하기 보다는 감소할 수 있습니다.", "4": "체온 상승: 저혈당 시 체온이 상승하지 않습니다.", "5": "피로감: 피로감은 나타날 수 있지만, 주로 저혈당의 특정 증상으로는 땀을 많이 흘리는 것이 더 적합합니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "혈당 조절이 필요한 질환", "def_vi": "Bệnh cần kiểm soát đường huyết"}, {"term_ko": "인슐린", "term_vi": "Insulin", "def_ko": "혈당을 조절하는 호르몬", "def_vi": "Hormone điều chỉnh đường huyết"}, {"term_ko": "저혈당", "term_vi": "Hạ đường huyết", "def_ko": "혈당이 비정상적으로 낮은 상태", "def_vi": "Tình trạng đường huyết thấp bất thường"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병에 의해 나타나는 신체의 변화", "def_vi": "Sự biến đổi cơ thể do bệnh tật gây ra"}, {"term_ko": "피로감", "term_vi": "Cảm giác mệt mỏi", "def_ko": "피곤한 상태", "def_vi": "Tình trạng mệt mỏi"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (81, '5', '당뇨 환자의 운동 요법으로 옳은 것은?', '["식후 30분에서 1시간경에 시작한다.", "일주일에 2일 운동한다.", "10분 이내로 짧게 운동한다.", "혈당이 300mg/dl 이상인 경우에 운동한다.", "공복에 운동한다."]'::jsonb, 1, '당뇨 환자에게 적합한 운동 요법을 이해하고 있는지를 평가하려는 의도입니다.', NULL, '{"1": "식사 후 30분에서 1시간 경에 시작하는 것이 좋습니다.\n[정답]", "2": "일주일에 2일 운동하는 것은 부족합니다.", "3": "10분 이내로 짧게 운동하는 것은 운동 효과가 적습니다.", "4": "혈당이 300mg/dl 이상인 경우는 운동을 피해야 합니다.", "5": "공복에 운동하는 것은 혈당에 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "당뇨", "term_vi": "Tiểu đường", "def_ko": "통치 증상", "def_vi": "Triệu chứng quản lý"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (80, '5', '당뇨병 대상자의 발 관리 방법으로 옳은 것은?', '["발톱을 일자로 자른다.", "꼭 끼는 신발을 신는다.", "양말을 벗고 맨발로 다닌다.", "발은 건조하게 관리한다.", "바레 열 패드를 대어주어 보온한다."]'::jsonb, 1, '당뇨병 대상자의 발 관리 방법을 이해하고 올바른 발 관리 방법을 선택하는 것이 중요하다.', NULL, '{"1": "발톱을 일자로 자르는 것은 안전하고 일반적인 발 관리 방법이다.\n[정답]", "2": "꼭 끼는 신발을 신는 것은 혈액 순환을 방해할 수 있어 옳지 않다.", "3": "양말을 벗고 맨발로 다니는 것은 발을 보호하지 못하므로 바람직하지 않다.", "4": "발은 항상 건조하게 유지해야 하지만 관리할 때는 적절한 수분도 필요하다.", "5": "바레 열 패드를 대어 보온하는 것은 직접적인 열로 인해 화상을 입을 수 있어 주의해야 한다."}'::jsonb, '[{"term_ko": "발톱", "term_vi": "Móng chân", "def_ko": "손톱(한국어)", "def_vi": "Móng ở chân"}, {"term_ko": "신발", "term_vi": "Giày", "def_ko": "발을 보호하는 도구(한국어)", "def_vi": "Công cụ bảo vệ chân"}, {"term_ko": "양말", "term_vi": "Socks", "def_ko": "발을 보호하는 직물(한국어)", "def_vi": "Vải bảo vệ chân"}, {"term_ko": "건조", "term_vi": "Khô", "def_ko": "수분이 없는 상태(한국어)", "def_vi": "Tình trạng không có độ ẩm"}, {"term_ko": "보온", "term_vi": "Giữ ấm", "def_ko": "체온을 유지하는 것(한국어)", "def_vi": "Giữ nhiệt độ cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (79, '5', '본인 스스로 자각하기 어렵고, 과거 정신과적 병력이 있으며, 두통, 소화불량과 같은 신체적 증상을 호소하는 질환으로 옳은 것은?', '["우울증", "치매", "섬망", "뇌졸증", "파킨슨질환"]'::jsonb, 1, '정신과적 병력이 있고 신체적 증상을 호소하는 환자의 대표적인 질환을 묻는 문제입니다.', NULL, '{"1": "우울증은 자각하기 어려운 증상과 함께 신체적 증상을 동반하기 때문에 정답입니다.\n[정답]", "2": "치매는 기억력 저하가 주요 증상으로, 자각하기 어려운 경우가 많지만 주된 증상은 아닙니다.", "3": "섬망은 일시적인 인지장애로 신체적 증상보다 인지 상태의 변화를 주로 나타냅니다.", "4": "뇌졸증은 신체적 증상이 두드러지며 정신적 병력과는 관련이 적습니다.", "5": "파킨슨질환은 운동장애가 주요 증상이며, 우울증처럼 자각이 어려운 경우가 있을 수 있지만 일반적으로는 정신과적 병리와 병행됩니다."}'::jsonb, '[{"term_ko": "자각", "term_vi": "Nhận thức", "def_ko": "인식(한국어)", "def_vi": "nhận biết(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (78, '5', '우울증 발생 가능성이 높은 대상자의 상황으로 옳은 것은?', '["사회활동을 활발히 하고 있다.", "경로당 프로그램에 참여한다.", "낮에 햇빛을 쐬며 운동을 한다.", "최근 갑상샘기능저하증을 진단받았다.", "식욕과 체중이 변화 없이 유지되고 있다."]'::jsonb, 4, '우울증에 영향을 미치는 다양한 요인을 이해하고, 특히 신체적 건강 문제가 우울증 발생과 어떻게 연관될 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "사회활동을 활발히 하고 있다: 사회적 활동은 보통 긍정적인 기여를 하므로 우울증 발생 가능성을 낮출 수 있음.", "2": "경로당 프로그램에 참여한다: 프로그램 참여는 사회적 연대감을 강화하고 우울증 가능성을 줄임.", "3": "낮에 햇빛을 쐬며 운동을 한다: 햇빛과 운동은 기분 개선에 도움이 되므로 우울증 발생 가능성을 낮출 수 있음.\n[정답]", "4": "최근 갑상샘기능저하증을 진단받았다: 갑상샘기능저하증은 우울증 발생 위험을 증가시킬 수 있는 신체적 질환임.", "5": "식욕과 체중이 변화 없이 유지되고 있다: 변화가 없는 것은 일반적으로 우울증과 관련이 없거나 낮은 가능성을 나타냄."}'::jsonb, '[{"term_ko": "우울증", "term_vi": "Trầm cảm", "def_ko": "정신적 질환의 일종", "def_vi": "Một loại bệnh tâm thần"}, {"term_ko": "사회활동", "term_vi": "Hoạt động xã hội", "def_ko": "사람들과의 상호작용이나 활동", "def_vi": "Sự tương tác hoặc hoạt động với mọi người"}, {"term_ko": "갑상샘기능저하증", "term_vi": "Suy giảm chức năng tuyến giáp", "def_ko": "갑상샘의 호르몬 생산이 부족한 상태", "def_vi": "Tình trạng hormone của tuyến giáp không đủ"}, {"term_ko": "식욕", "term_vi": "Khẩu vị", "def_ko": "음식을 먹고 싶은 욕구", "def_vi": "Mong muốn ăn uống"}, {"term_ko": "체중", "term_vi": "Cân nặng", "def_ko": "몸의 무게", "def_vi": "Trọng lượng cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (77, '5', '우울증 대상자를 돕는 방법으로 옳은 것은?', '["사회적 활동을 줄이게 한다.", "햇볕을 쬐며 걷기 운동을 하게 한다.", "곧 괜찮아질 것이라고 위로한다.", "대상자의 분노 감정을 인정하지 않는다.", "항우울제 용량을 늘려야 한다고 말한다."]'::jsonb, 2, '우울증 대상자를 어떻게 도와야 하는지를 평가하기 위한 문제입니다.', NULL, '{"1": "사회적 활동을 줄이는 것은 우울증을 악화시킬 수 있습니다.\n[정답]", "2": "햇볕을 쬐며 걷기 운동은 기분 개선에 도움을 줄 수 있습니다.", "3": "단순한 위로는 대상자의 상태를 오히려 좋지 않게 만들 수 있습니다.", "4": "대상자의 감정을 인정하지 않으면 신뢰를 잃게 됩니다.", "5": "항우울제의 용량 조정은 전문가의 판단이 필요합니다."}'::jsonb, '[{"term_ko": "우울증", "term_vi": "Trầm cảm", "def_ko": "심리적 장애로 지속적인 슬픔", "def_vi": "Rối loạn tâm lý gây ra sự buồn bã kéo dài"}, {"term_ko": "사회적 활동", "term_vi": "Hoạt động xã hội", "def_ko": "사람들이 함께 어울리는 활동", "def_vi": "Hoạt động mà mọi người tham gia cùng nhau"}, {"term_ko": "햇볕", "term_vi": "Ánh nắng mặt trời", "def_ko": "태양에서 방출되는 빛", "def_vi": "Ánh sáng phát ra từ mặt trời"}, {"term_ko": "걷기 운동", "term_vi": "Đi bộ", "def_ko": "걷기를 포함한 운동 형태", "def_vi": "Hình thức tập thể dục bao gồm việc đi bộ"}, {"term_ko": "전문가", "term_vi": "Chuyên gia", "def_ko": "특정 분야의 지식이 있는 사람", "def_vi": "Người có kiến thức trong một lĩnh vực cụ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (76, '5', '다음에서 설명하는 질병으로 옳은 것은?• 주의력 저하와 인지기능 전반에 장애와 정신병적 증상이 나타날 수 있다. • 수 시간 내지 수일에 걸쳐 급격히 발생한다. • 증상의 기복이 심한 것이 특징이다.', '["섬망", "파킨슨병", "척추질환", "추간판탈출", "알츠하이머병"]'::jsonb, 1, '질병의 증상과 특성을 파악하여 올바른 질병을 선택하도록 돕기 위함입니다.', NULL, '{"1": "섬망은 주의력 저하와 인지 기능 저하, 정신병적 증상이 갑작스럽게 나타나는 것이 특징입니다.\n[정답]", "2": "파킨슨병은 주로 운동 기능에 영향을 주며, 급성 발병과는 거리가 멉니다.", "3": "척추질환은 주의력 저하 및 정신병적 증상과 직접 연관이 없습니다.", "4": "추간판탈출은 통증과 관련된 질병이며, 인지 기능 저하와는 관련이 없습니다.", "5": "알츠하이머병은 점진적으로 증상이 진행되므로 급작스러운 발생과는 다릅니다."}'::jsonb, '[{"term_ko": "주의력", "term_vi": "Chú ý", "def_ko": "집중력(한국어)", "def_vi": "Sự tập trung(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (75, '5', '섬망이 있는 대상자의 치료 및 예방으로 옳은 것은?', '["대상자와 접촉하는 사람의 수를 늘린다.", "텥레비전을 크게 틀어 놓는다.", "주변 환경을 새롭게 바꿔준다.", "낮 동안 커튼을 쳐서 빛을 차단한다.", "가족사진과 달력을 대상자 가까이에 둔다."]'::jsonb, 5, '섬망이 있는 대상자에게 적절한 치료 및 예방 방법을 선택하는 능력을 평가하기 위함입니다.', NULL, '{"1": "대상자와 접촉하는 사람의 수를 늘린다. - 이는 섬망 증상을 악화시킬 수 있습니다.\n[정답]", "5": "가족사진과 달력을 대상자 가까이에 둔다. - 이는 정서적 안정과 방향 감각을 돕는 효과가 있습니다.", "2": "텥레비전을 크게 틀어 놓는다. - 이는 자극이 과해져 증상을 악화시킬 수 있습니다.", "3": "주변 환경을 새롭게 바꿔준다. - 이는 대상자에게 혼란을 줄 수 있습니다.", "4": "낮 동안 커튼을 쳐서 빛을 차단한다. - 이는 일주기 리듬을 방해할 수 있습니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Mê sảng", "def_ko": "혼란을 동반한 의식의 장애", "def_vi": "Rối loạn ý thức đi kèm với sự nhầm lẫn"}, {"term_ko": "예방", "term_vi": "Phòng ngừa", "def_ko": "미연에 막음", "def_vi": "Ngăn chặn trước"}, {"term_ko": "정서적 안정", "term_vi": "Ổn định cảm xúc", "def_ko": "감정을 안정시키는 것", "def_vi": "Làm cho cảm xúc ổn định"}, {"term_ko": "치료", "term_vi": "Điều trị", "def_ko": "병을 고침", "def_vi": "Chữa bệnh"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주변의 상황", "def_vi": "Tình huống xung quanh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (74, '5', '섬망 대상자의 치료 및 대처 방법으로 옳은 것은?', '["안정을 위해 가족이 방문하지 않도록 한다.", "절대 안정을 위해 능동적인 관절운동은 피한다.", "낮 동안에 커튼을 닫아 외부 환경을 차단한다.", "밤에는 커튼을 치고 방안을 어둡게 한다.", "야간 섬망에는 방을 밝게 하고 따뜻하게 한다."]'::jsonb, 5, '섬망 대상자의 적절한 치료와 대처 방법에 대한 이해를 측정하기 위함입니다.', NULL, '{"1": "섬망 환자를 위한 환경은 가족이 함께 할 수 있도록 하여 안정감을 주는 것이 좋습니다.\n[정답]", "5": "야간 섬망 환자는 방을 밝고 따뜻하게 하여 안정감을 주고 혼란을 줄이는 것이 중요합니다.", "2": "능동적인 관절운동은 환자의 상태에 따라 다를 수 있으나, 섬망 상태에서는 신중해야 합니다.", "3": "외부 환경의 차단은 이 환자에게 오히려 혼란을 증가시킬 수 있습니다.", "4": "방 안을 어둡게 하는 것은 섬망을 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Hội chứng lú lẫn", "def_ko": "혼란 상태(한국어)", "def_vi": "Trạng thái nhầm lẫn(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (73, '5', '섬망 대상자의 지남력을 유지하는 방법으로 옳은 것은?', '["낮에 커튼을 쳐 어둡게 한다.", "새 친구를 사귀게 한다.", "가족의 방문을 제한한다.", "식사할 때 시간을 알려준다.", "창문이 없는 밀폐된 공간에서 지낸다."]'::jsonb, 4, '섬망 대상자의 지남력 유지 방법에 대한 이해도를 평가하고자 함.', NULL, '{"1": "낮에 커튼을 쳐 어둡게 한다: 지남력 유지에 도움이 되지 않음.\n[정답]", "4": "식사할 때 시간을 알려준다: 지남력을 유지하는 데 효과적이다.", "2": "새 친구를 사귀게 한다: 불안감을 줄이지 못할 수 있다.", "3": "가족의 방문을 제한한다: 고립감을 유발할 수 있어 좋지 않다.", "5": "창문이 없는 밀폐된 공간에서 지낸다: 이는 지남력에 부정적 영향을 미침."}'::jsonb, '[{"term_ko": "지남력", "term_vi": "Định hướng", "def_ko": "방향감각(한국어)", "def_vi": "nhận thức về phương hướng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (72, '5', '노쇠증후군에 공통된 특징으로 옳은 것은?', '["만성질환자들에게 많이 생긴다.", "삶의 질에 영향을 끼치지 않는다.", "특정 질환의 원인이 된다.", "요로감염 등이 섬망을 유발하기도 한다.", "심리적인 원인이 주요인이 된다."]'::jsonb, 4, '노쇠증후군의 특성과 그 영향을 이해하는지를 평가하고자 하는 의도입니다.', NULL, '{"1": "노쇠증후군은 만성질환자에게 많이 발병하는 경향이 있습니다.\n[정답]", "2": "노쇠증후군은 삶의 질에 부정적인 영향을 미칠 수 있습니다.", "3": "노쇠증후군은 특정 질환의 원인이 되지 않습니다.", "4": "요로감염은 섬망을 유발할 수 있는 중요한 요소입니다.", "5": "심리적인 원인보다 신체적인 원인이 더 큰 요인이 됩니다."}'::jsonb, '[{"term_ko": "노쇠증후군", "term_vi": "Hội chứng suy giảm cơ thể", "def_ko": "노쇠가 진행되는 상태", "def_vi": "Tình trạng suy giảm thể lực"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (71, '6', '치매에 관한 설명으로 옳은 것은?', '["시공간을 파악하는 능력은 정상이다.", "언어소통의 능력에는 변화가 없다.", "혈관성 치매 비율이 가장 높다.", "근래의 일보다 먼 과거의 일을 잘 기억해내지 못한다.", "운동기능은 정상인데 운동활동 수행능력이 손상되는 실행중이 나타난다."]'::jsonb, 5, '치매에 대한 올바른 이해도를 평가하기 위한 문제입니다.', NULL, '{"1": "치매 환자는 시공간을 파악하는 능력이 저하됩니다.", "2": "언어소통 능력은 치매 초기에는 상대적으로 정상이나 진행됨에 따라 변화가 생깁니다.\n[정답]", "3": "혈관성 치매는 비율이 높지만, 알츠하이머병이 가장 흔한 형태입니다.", "4": "치매 환자는 근래의 일은 잘 기억하지 못하고 먼 과거의 일이 더 잘 기억납니다.", "5": "운동기능은 정상일 수 있으나, 수행능력에는 문제가 생길 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력과 인지기능의 저하로 인한 상태", "def_vi": "Tình trạng giảm khả năng nhớ và nhận thức"}, {"term_ko": "혈관성", "term_vi": "Mạch máu", "def_ko": "혈관과 관련된 형태", "def_vi": "Liên quan đến mạch máu"}, {"term_ko": "언어소통", "term_vi": "Giao tiếp ngôn ngữ", "def_ko": "의사소통을 위한 언어 사용", "def_vi": "Sử dụng ngôn ngữ để giao tiếp"}, {"term_ko": "운동기능", "term_vi": "Chức năng vận động", "def_ko": "신체를 움직이는 능력", "def_vi": "Khả năng di chuyển cơ thể"}, {"term_ko": "수행능력", "term_vi": "Khả năng thực hiện", "def_ko": "특정 작업을 수행하는 능력", "def_vi": "Khả năng thực hiện một nhiệm vụ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (70, '6', '알츠하이머병에 관한 설명으로 옳은 것은?', '["중기에는 가족을 알아보지 못한다.", "초기에는 독립적인 생활을 할 수 있다.", "초기부터 장기기억력 저하가 나타난다.", "말기에 새로 외우는 것은 거의 불가능하다.", "말기에는 과거에 대해 힌트를 주면 기억해낸다."]'::jsonb, 2, '알츠하이머병에 대한 기본적인 지식을 평가하기 위함입니다.', NULL, '{"1": "중기에는 가족을 알아보지 못하는 경우가 많지만, 모든 환자에게 해당되는 것은 아닙니다.\n[정답]", "2": "초기에는 독립적인 생활을 할 수 있습니다. 이는 알츠하이머병 초기의 특징입니다.", "3": "초기부터 장기기억력 저하가 나타나는 것이 아니라 단기기억력에서 먼저 저하가 나타납니다.", "4": "말기에는 새로 외우는 것이 거의 불가능한 것이 맞습니다.", "5": "과거에 대해 힌트를 주면 기억해내는 경우가 많지만, 말기의 경우에는 그 정도가 심각하게 저하될 수 있습니다."}'::jsonb, '[{"term_ko": "알츠하이머병", "term_vi": "기억력", "def_ko": "질병(병 Alzheimer)", "def_vi": "기억력(Trí nhớ)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (69, '6', '뇌졸중은 뇌혈관이 막힌 경우를 (A)(이)라고 하고, 뇌혈관이 터진 경우를 (B)(이)라고 한다. () 안에 들어갈 질환으로 옳은 것은?', '["뇌경색 뇌출혈", "뇌출혈 뇌경색", "중풍 뇌출혈", "동맥경화 중풍", "동맥경화 뇌출혈"]'::jsonb, 1, '뇌졸중의 종류에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "뇌졸중은 뇌혈관이 막힌 경우를 뇌경색이라고 하고, 뇌혈관이 터진 경우를 뇌출혈이라고 합니다.\n[정답]", "2": "뇌출혈은 뇌혈관이 터진 경우를 의미하지만, 막힌 경우는 잘못된 설명입니다.", "3": "중풍은 일반적으로 뇌졸중을 지칭하지만, 구체적인 질환명이 아니므로 옳지 않습니다.", "4": "동맥경화는 뇌졸중의 원인으로 작용할 수 있지만, 뇌졸중의 세부 유형이 아닙니다.", "5": "동맥경화 역시 뇌졸중의 원인이 될 수 있으나 정확한 설명이 아닙니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈관이 막히거나 터지는 질환", "def_vi": "Bệnh có liên quan đến mạch máu não"}, {"term_ko": "뇌경색", "term_vi": "Đột quỵ não do tắc mạch", "def_ko": "뇌혈관이 막혀 발생하는 뇌졸중", "def_vi": "Đột quỵ não xảy ra do mạch máu bị tắc"}, {"term_ko": "뇌출혈", "term_vi": "Xuất huyết não", "def_ko": "뇌혈관이 터져 발생하는 뇌졸중", "def_vi": "Đột quỵ não xảy ra do mạch máu bị vỡ"}, {"term_ko": "동맥경화", "term_vi": "Xơ vữa động mạch", "def_ko": "동맥 벽이 두꺼워지는 질환", "def_vi": "Bệnh làm dày thành mạch"}, {"term_ko": "중풍", "term_vi": "Liệt", "def_ko": "뇌졸중을 통칭하는 용어", "def_vi": "Thuật ngữ chung chỉ đột quỵ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (68, '6', '뇌졸중의 증상 중 손상된 뇌의 반대쪽 팔다리, 갑작스런 안면하부의 마비가 오는 후유증으로 옳은 것은?', '["반신마비", "전신마비", "반신감각장애", "언어장애", "운동실조증"]'::jsonb, 1, '뇌졸중의 후유증으로 나타나는 증상을 이해하는 것이 문제의 핵심입니다.', NULL, '{"1": "반신마비는 뇌의 반대쪽 팔다리에 나타나는 마비 증상을 의미합니다.\n[정답]", "2": "전신마비는 모든 팔다리에 마비가 오는 상태로 뇌졸중과는 관련이 없습니다.", "3": "반신감각장애는 뇌졸중 후 부가적으로 나타날 수 있으나, 문제에서 묻는 것은 직접적인 후유증입니다.", "4": "언어장애는 뇌졸중에 의해 발생할 수 있으나, 마비와는 직접적인 관련성이 떨어집니다.", "5": "운동실조증은 조정 능력에서 문제가 생기는 것이며, 뇌졸중의 직접적인 마비와는 다릅니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌에 혈액 공급이 차단되어 발생하는 질환", "def_vi": "Bệnh xảy ra khi cung cấp máu đến não bị ngắt quãng"}, {"term_ko": "반신마비", "term_vi": "Bại nửa người", "def_ko": "신체의 한 쪽 절반에 마비가 오는 증상", "def_vi": "Triệu chứng liệt ở một nửa cơ thể"}, {"term_ko": "전신마비", "term_vi": "Liệt toàn thân", "def_ko": "신체의 전부에 마비가 오는 상태", "def_vi": "Trạng thái liệt ở toàn bộ cơ thể"}, {"term_ko": "운동실조증", "term_vi": "Rối loạn vận động", "def_ko": "운동의 조정이 어려운 증상", "def_vi": "Triệu chứng khó khăn trong việc điều chỉnh vận động"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (67, '6', '뇌졸중의 증상 중 손상된 뇌의 반대쪽의 시각, 촉각, 청각 등의 장애, 남의 살 같은 불쾌한 느낌의 후유증을 남기는 것으로 옳은 것은?', '["반신마비", "전신마비", "반신감각장애", "언어장애", "운동실조증"]'::jsonb, 3, '뇌졸중의 후유증으로 발생하는 다양한 신경학적 증상의 이해를 확인하기 위함입니다.', NULL, '{"1": "반신마비는 한쪽 팔과 다리에 힘이 약해지거나 마비되는 증상입니다.\n[정답]", "3": "반신감각장애는 손상된 뇌의 반대쪽에서 시각, 촉각, 청각 등의 장애와 불쾌한 느낌이 나타나는 현상입니다.", "2": "전신마비는 전체적으로 마비되는 상태를 나타냅니다.", "4": "언어장애는 의사소통에 어려움을 겪는 증상입니다.", "5": "운동실조증은 운동의 조정이 어려워지는 증상입니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "중풍(한국어)", "def_vi": "Bệnh đột quỵ"}, {"term_ko": "손상", "term_vi": "Tổn thương", "def_ko": "피해(한국어)", "def_vi": "Tổn thương"}, {"term_ko": "반신", "term_vi": "Nửa người", "def_ko": "반쪽 몸(한국어)", "def_vi": "Nửa người"}, {"term_ko": "감각", "term_vi": "Cảm giác", "def_ko": "느낌(한국어)", "def_vi": "Cảm giác"}, {"term_ko": "장애", "term_vi": "Khuyết tật", "def_ko": "문제(한국어)", "def_vi": "Khuyết tật"}, {"term_ko": "불쾌한", "term_vi": "Khó chịu", "def_ko": "기분이 나쁜(한국어)", "def_vi": "Khó chịu"}, {"term_ko": "후유증", "term_vi": "Di chứng", "def_ko": "후유증(한국어)", "def_vi": "Di chứng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (66, '6', '좌측뇌가 손상되어 우측마비와 함께 말을 못하거나 남의 말을 이해하지 못하는 실어증의 후유증으로 옳은 것은?', '["반신마비", "전신마비", "반신감각장애", "언어장애", "운동실조증"]'::jsonb, 4, '좌측뇌 손상의 결과로 나타나는 우측마비와 언어장애의 관련성을 이해하는 것.', NULL, '{"1": "반신마비: 좌측뇌 손상으로 인해 우측신체가 마비될 수 있으나, 질문은 언어장애에 초점을 맞추고 있다.\n[정답]", "4": "언어장애: 좌측뇌 손상의 대표적인 후유증 중 하나로, 말을 못하거나 이해하지 못하는 증상이 나타난다.", "3": "반신감각장애: 감각의 문제일 수 있으나, 언어장애가 중심 주제가 아니다.", "2": "전신마비: 좌측뇌 손상이 전신마비로 이어지지는 않는다.", "5": "운동실조증: 운동을 조정하는 문제이나, 언어장애와는 관련성이 적다."}'::jsonb, '[{"term_ko": "좌측뇌", "term_vi": "Não trái", "def_ko": "왼쪽 뇌(부위)", "def_vi": "Phần não bên trái"}, {"term_ko": "우측", "term_vi": "Bên phải", "def_ko": "오른쪽", "def_vi": "Bên phải"}, {"term_ko": "마비", "term_vi": "Liệt", "def_ko": "마비/충혈", "def_vi": "Tê liệt"}, {"term_ko": "실어증", "term_vi": "Rối loạn ngôn ngữ", "def_ko": "언어장애", "def_vi": "Rối loạn ngôn ngữ"}, {"term_ko": "후유증", "term_vi": "Di chứng", "def_ko": "후유증", "def_vi": "Hậu quả"}, {"term_ko": "언어", "term_vi": "Ngôn ngữ", "def_ko": "언어", "def_vi": "Ngôn ngữ"}, {"term_ko": "이해", "term_vi": "Hiểu", "def_ko": "이해하다", "def_vi": "Hiểu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (65, '6', '대상자에게 소뇌 손상이 발생했을 때 나타나는 특징적인 증상으로 옳은 것은?', '["시각장애로 사물을 인지하지 못한다.", "인지기능의 저하가 나타난다.", "말의 내용을 이해하지 못한다.", "한 개의 물체가 두 개로 보인다.", "자세의 균형을 유지하지 못한다."]'::jsonb, 5, '소뇌 손상이 있을 때 나타나는 증상에 대한 이해를 확인하려는 문제입니다.', NULL, '{"1": "시각장애는 주로 대뇌와 관련된 증상입니다.", "2": "인지기능 저하는 대뇌 손상에서 흔히 나타나는 증상입니다.", "3": "말의 내용을 이해하지 못하는 것은 주로 언어 중추와 관련된 문제입니다.", "4": "한 개의 물체가 두 개로 보이는 현상은 복시로, 주로 시각 신경과 관련이 있습니다.\n[정답]", "5": "자세의 균형을 유지하지 못하는 것은 소뇌의 주요 기능 중 하나로, 손상이 있으면 나타날 수 있는 증상입니다."}'::jsonb, '[{"term_ko": "소뇌", "term_vi": "Tiểu não", "def_ko": "뇌의 일부분으로 균형과 운동 조절을 담당하는 기관", "def_vi": "Một phần của não chịu trách nhiệm điều chỉnh thăng bằng và chuyển động"}, {"term_ko": "균형", "term_vi": "Thăng bằng", "def_ko": "물체의 중력을 잘 유지하는 상태", "def_vi": "Trạng thái duy trì trọng lực của một vật"}, {"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "정보를 이해하고 해석하는 능력", "def_vi": "Khả năng hiểu và giải thích thông tin"}, {"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "몸의 위치나 태세", "def_vi": "Vị trí hoặc dáng vẻ của cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (64, '6', '술에 취한 사람처럼 비틀거리고, 자꾸 한쪽으로 쓰러질 때 의심할 수 있는 뇌졸중의 주요 증상으로 옳은 것은?', '["언어장애", "운동실조증", "반신마비", "어지럼증", "평형감각장애"]'::jsonb, 2, '뇌졸중의 주요 증상을 이해하고 있는지를 확인하고자 하는 문제입니다.', NULL, '{"1": "언어장애는 뇌졸중의 증상 중 하나지만, 비틀거리며 한쪽으로 쓰러지기보다는 언어적 문제에 관련됩니다.\n[정답]", "2": "운동실조증은 비틀거리며 한쪽으로 쓰러지는 증상을 직접적으로 나타냅니다.", "3": "반신마비는 몸의 한쪽만 마비되는 증상으로, 비틀거림과 다소 관련이 있지만 결정적인 증상은 아닙니다.", "4": "어지럼증도 뇌졸중 증상일 수 있으나, 주로 비틀거림의 원인으로 운동실조증이 더 적합합니다.", "5": "평형감각장애 역시 관련이 있지만 비틀거림을 주된 표현으로 보기에는 운동실조증이 더 직접적입니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌에서 발생하는 혈류 장애로 인한 증상", "def_vi": "Triệu chứng do rối loạn lưu thông máu ở não"}, {"term_ko": "운동실조증", "term_vi": "Rối loạn vận động", "def_ko": "근육의 협응이 잘 되지 않아 비틀거림", "def_vi": "Sự mất phối hợp của cơ bắp dẫn đến đi không vững"}, {"term_ko": "언어장애", "term_vi": "Khó khăn về ngôn ngữ", "def_ko": "언어 표현이 힘든 상태", "def_vi": "Tình trạng khó khăn trong việc biểu đạt ngôn ngữ"}, {"term_ko": "반신마비", "term_vi": "Liệt nửa người", "def_ko": "몸의 한쪽이 마비된 상태", "def_vi": "Tình trạng một bên cơ thể bị liệt"}, {"term_ko": "어지럼증", "term_vi": "Chóng mặt", "def_ko": "머리가 아찔한 증상", "def_vi": "Triệu chứng đầu óc quay cuồng"}, {"term_ko": "평형감각장애", "term_vi": "Khó khăn về cảm giác thăng bằng", "def_ko": "균형을 잡기 힘든 상태", "def_vi": "Tình trạng khó khăn trong việc duy trì cân bằng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (63, '6', '뇌졸중으로 갑자기 발생하며 갑자기 동작이 서툴러지고, 대소변을 못가리고, 감정조절에 이상이 생길 때 의심해봐야 하는 질환으로 옳은 것은?', '["알츠하이머", "혈관성 치매", "파킨슨병", "섬망", "균형감각장애"]'::jsonb, 2, '뇌졸중으로 인한 증상에 대해 이해하고, 관련 질환을 구별하는 능력을 평가하기 위함입니다.', NULL, '{"1": "알츠하이머: 주로 기억력 감退에 관련된 질환으로, 동작 서툴렷과는 관련이 적습니다.\n[정답]", "2": "혈관성 치매: 뇌졸중과 관련된 증상들이 나타나므로, 이 질환이 정답입니다.", "3": "파킨슨병: 움직임의 느려짐과 함께 특징적인 증상이 있지만, 뇌졸중과 직접 연관되지는 않습니다.", "4": "섬망: 급성 정신상태 변화로, 갑작스러운 증상은 있으나 뇌졸중과의 직접적인 연관은 적습니다.", "5": "균형감각장애: 뇌졸중으로 인해 발생할 수 있지만, 주요 증상은 아닙니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈액 공급이 차단되어 발생하는 질환", "def_vi": "Bệnh xảy ra do cung cấp máu đến não bị chặn"}, {"term_ko": "동작", "term_vi": "Động tác", "def_ko": "움직임", "def_vi": "Sự chuyển động"}, {"term_ko": "서툴러지다", "term_vi": "Trở nên vụng về", "def_ko": "행동이 정확하지 않다", "def_vi": "Hành động không chính xác"}, {"term_ko": "대소변", "term_vi": "Tiểu tiện và đại tiện", "def_ko": "소변과 대변", "def_vi": "Nước tiểu và phân"}, {"term_ko": "감정조절", "term_vi": "Kiểm soát cảm xúc", "def_ko": "감정의 통제가 이루어지다", "def_vi": "Hoạt động điều khiển cảm xúc"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병", "def_vi": "Bệnh tật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (62, '6', '뇌졸중을 의심할 수 있는 전구증상은?', '["가만히 있을 때 떨림증상이 있다.", "가슴이 조이는 흉통이 있다.", "새벽에 속쓰림 증상이 있다.", "한 개의 물체가 둘로 보인다.", "목이 말라서 물을 자주 마신다."]'::jsonb, 4, '뇌졸중의 전구증상을 이해하고 평가하는 것이 중요하다.', NULL, '{"1": "가만히 있을 때 떨림증상은 뇌졸중의 전구증상과 관련이 없다.\n[정답]", "4": "한 개의 물체가 둘로 보이는 것은 뇌졸중의 전구증상으로 나타날 수 있다.", "2": "가슴이 조이는 흉통은 심혈관계의 문제일 수 있다.", "3": "새벽에 속쓰림 증상은 소화계의 문제일 가능성이 높다.", "5": "목이 마르는 것은 일반적인 생리적 현상으로, 뇌졸중과는 관련이 없다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈액 공급이 중단되어 발생하는 질병", "def_vi": "Bệnh xảy ra khi cung cấp máu lên não bị ngừng lại"}, {"term_ko": "전구증상", "term_vi": "Triệu chứng tiền triệu", "def_ko": "증상이 나타나기 전의 신호", "def_vi": "Dấu hiệu trước khi triệu chứng xuất hiện"}, {"term_ko": "흉통", "term_vi": "Đau ngực", "def_ko": "가슴에 통증이 있는 상태", "def_vi": "Tình trạng đau ở ngực"}, {"term_ko": "속쓰림", "term_vi": "Cảm giác nôn", "def_ko": "위장에 불편을 느끼는 증상", "def_vi": "Triệu chứng cảm giác khó chịu trong dạ dày"}, {"term_ko": "물체", "term_vi": "Vật thể", "def_ko": "물건", "def_vi": "Đồ vật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (61, '6', '혈관성 치매 대상자를 돕기 위한 요양보호사의 활동으로 옳은 것은?', '["망상장애가 왔다며 가족과 상의하여 병원에 입원시킨다.", "이상행동을 보일 시 부정, 설득보다 보호, 수용, 지지한다.", "가능한 재활치료보다 침상에서 안정을 취하게 한다.", "보호자의 정서적 지도 및 상담비용을 청구한다.", "적절한 의사소통이 불가능하므로 인내심을 가지고 지도한다."]'::jsonb, 2, '혈관성 치매 대상자를 돕기 위한 요양보호사의 적절한 활동을 판단하는 것.', NULL, '{"1": "망상장애가 있는 경우, 입원이 필요할 수 있으나 가족과 상의하여 결정하는 것은 요양보호사의 역할이 아니다.\n[정답]", "2": "치매 환자가 이상행동을 보일 경우, 보호적이고 수용적인 태도를 통해 환자의 안정감을 증진시키는 것이 중요하다.", "3": "침상에서 안정하는 것보다는 가능한 재활치료를 통해 기능 회복을 도모하는 것이 바람직하다.", "4": "보호자의 정서적 지도 및 상담은 중요하지만, 요양보호사가 비용을 청구하는 것은 적절하지 않다.", "5": "의사소통이 어려운 경우 인내심을 가지고 대하는 것은 중요하지만, 이를 지도하는 것은 요양보호사의 주된 역할이 아니다."}'::jsonb, '[{"term_ko": "혈관성 치매", "term_vi": "Giảm trí nhớ mạch máu", "def_ko": "혈관에 의한 치매(vascular dementia)", "def_vi": "Suy giảm trí nhớ do các vấn đề liên quan đến mạch máu"}, {"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "노인이나 환자를 돌보는 사람", "def_vi": "Người chăm sóc người già hoặc người bệnh"}, {"term_ko": "이상행동", "term_vi": "Hành vi thái quá", "def_ko": "부적절한 행동", "def_vi": "Hành vi không phù hợp"}, {"term_ko": "재활치료", "term_vi": "Điều trị phục hồi", "def_ko": "기능 회복을 위한 치료", "def_vi": "Sự điều trị nhằm phục hồi chức năng"}, {"term_ko": "정서적", "term_vi": "Cảm xúc", "def_ko": "감정과 관련된", "def_vi": "Liên quan đến cảm xúc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (60, '6', '다음에서 설명하는 신경계 질환으로 옳은 것은?• 도파민이라는 물질의 분비 장애로 발생한다. • 떨림 증상으로 움직일 때보다 가만히 있을 때 주로 나타난다. • 행동이 느려지는 것으로 서서히 나타난다.', '["혈관성 치매", "알츠하이머병", "파킨슨병", "뇌졸중", "건망증"]'::jsonb, 3, '신경계 질환의 특성과 증상을 이해하고 구별할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "혈관성 치매: 주로 혈관의 문제로 인한 인지 저하를 의미하며, 도파민과 관련이 없습니다.", "2": "알츠하이머병: 기억력 감퇴가 주 증상이며, 도파민의 문제와는 무관합니다.\n[정답]", "3": "파킨슨병: 도파민의 분비 장애로 인해 발생하며, 떨림과 행동의 느려짐이 주요 증상입니다.", "4": "뇌졸중: 뇌의 혈액 공급 부족으로 발생하는 질환이며, 도파민과 관련이 없습니다.", "5": "건망증: 기억력을 잃는 상태이며, 신경계 질환과는 다릅니다."}'::jsonb, '[{"term_ko": "신경계", "term_vi": "Hệ thần kinh", "def_ko": "신체의 신경과 관련된 시스템", "def_vi": "Hệ thống liên quan đến dây thần kinh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (59, '6', '파킨슨질환의 운동 증상으로 옳은 것은?', '["얼굴 등에서 떨림이 보이고 움직이면 사라진다.", "불안, 피로, 환각, 망상 등 증상이 발생한다.", "과도한 주간 졸림, 기면증이 발생한다.", "통증이나 후각 기능 저하가 발생한다.", "변비, 피로 등의 증상이 나타난다."]'::jsonb, 1, '파킨슨질환의 운동 증상에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "파킨슨질환의 특징적인 운동 증상인 떨림은 정지 시 나타나고, 움직이면 사라지는 경향이 있습니다.\n[정답]", "2": "이것은 비운동 증상에 해당하며, 파킨슨질환의 주요 운동 증상은 아닙니다.", "3": "기면증이나 주간 졸림은 파킨슨환자에게 나타날 수 있지만 운동 증상과는 관련이 없습니다.", "4": "후각 기능 저하는 비운동 증상으로 분류되며, 운동 증상과는 관계가 없습니다.", "5": "변비와 피로 또한 비운동 증상이며, 운동 증상으로 보기는 어렵습니다."}'::jsonb, '[{"term_ko": "파킨슨질환", "term_vi": "Bệnh Parkinson", "def_ko": "파킨슨병(한국어)", "def_vi": "Bệnh Parkinson"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (58, '6', '파킨슨질환의 주요 증상으로 옳은 것은?', '["진전 (떨림)은 가만히 있으면 사라진다.", "행동의 느려짐은 급박하게 진행된다.", "엉거주춤한 자세로 쉽게 넘어져 골절의 원인이 된다.", "밤낮으로 과도한 깊은 수면현상이 나타난다.", "기억력에는 문제가 없다."]'::jsonb, 3, '파킨슨질환의 주요 증상을 이해하고, 옳은 진술을 선택하는 것입니다.', NULL, '{"1": "진전(떨림)은 일반적으로 가만히 있을 때 나타나므로 잘못된 진술입니다.\n[정답]", "3": "엉거주춤한 자세로 쉽게 넘어져 골절의 원인이 될 수 있습니다.", "2": "행동의 느려짐은 서서히 진행되는 특징이 있으므로 잘못된 진술입니다.", "4": "과도한 깊은 수면현상은 파킨슨질환과 관련이 있지만, 일반적인 증상으로 나타나지는 않습니다.", "5": "기억력 문제는 흔히 발생할 수 있습니다."}'::jsonb, '[{"term_ko": "파킨슨질환", "term_vi": "Bệnh Parkinson", "def_ko": "파킨슨병(한국어)", "def_vi": "Bệnh Parkinson (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (57, '6', '파킨슨질환자의 치료 및 관리 방법으로 옳은 것은?', '["대상자가 원하는 시간에 약물복용을 한다.", "서있는 것이 불안정하다면 지팡이를 짚게 한다.", "서있는 자세가 불안정하므로 운동은 삼간다.", "약물흡수를 위해 단백질 식품과 함께 복용한다.", "변비 예방을 위해 과일, 수분 섭취를 한다."]'::jsonb, 5, '파킨슨 질환자의 치료 및 관리 방법에 대한 이해를 확인하기 위한 문제입니다.', NULL, '{"1": "대상자가 원하는 시간에 약물복용을 한다는 것은 비규칙적인 복용이 될 수 있어 좋지 않다.\n[정답]", "5": "변비 예방을 위해 과일과 수분 섭취를 권장하는 것은 적절한 치료 방법이다.", "2": "서 있는 것이 불안정할 경우 지팡이를 짚게 하는 것은 안전을 위해 중요하지만, 그 자체가 치료 방법은 아니다.", "3": "서 있는 자세가 불안정하다고 해서 운동을 삼가는 것은 오히려 해로운 경우가 많다.", "4": "약물 흡수를 위해 단백질 식품과 함께 복용하는 것은 약물의 효과를 저해할 수 있다."}'::jsonb, '[{"term_ko": "파킨슨질환", "term_vi": null, "def_ko": "파킨슨 병(Parkinson''s disease)", "def_vi": null}, {"term_ko": "치료", "term_vi": null, "def_ko": "치료 (Điều trị)", "def_vi": null}, {"term_ko": "관리", "term_vi": null, "def_ko": "관리 (Quản lý)", "def_vi": null}, {"term_ko": "변비", "term_vi": null, "def_ko": "변비 (Táo bón)", "def_vi": null}, {"term_ko": "과일", "term_vi": null, "def_ko": "과일 (Trái cây)", "def_vi": null}, {"term_ko": "수분", "term_vi": null, "def_ko": "수분 (Nước)", "def_vi": null}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (56, '7', '노화에 따른 수분량의 감소와 탈수의 원인으로 옳은 것은?', '["갈증에 대한 반응 저하", "염분 섭취의 증가", "타액 분비 증가", "소화액의 증가", "칼슘 흡수 감소"]'::jsonb, 1, '노화에 따른 생리적 변화와 수분량 감소에 대한 인식을 확인하고자 함.', NULL, '{"1": "갈증에 대한 반응 저하: 노화와 함께 갈증을 느끼는 능력이 저하되어 수분 섭취가 줄어든다.\n[정답]", "2": "염분 섭취의 증가: 염분 섭취 증가가 탈수에 직접적인 영향을 미치지는 않는다.", "3": "타액 분비 증가: 노화로 인해 타액 분비가 증가하지 않는다.", "4": "소화액의 증가: 노화로 인해 소화액이 증가하는 것이 아니다.", "5": "칼슘 흡수 감소: 칼슘 흡수는 수분과 관련이 적다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이 들어감", "def_vi": "Già đi"}, {"term_ko": "수분량", "term_vi": "Lượng nước", "def_ko": "체내 물의 양", "def_vi": "Lượng nước trong cơ thể"}, {"term_ko": "탈수", "term_vi": "Mất nước", "def_ko": "수분 부족 상태", "def_vi": "Tình trạng thiếu nước"}, {"term_ko": "갈증", "term_vi": "Khát", "def_ko": "목마름", "def_vi": "Cảm giác khát"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "반응하다", "def_vi": "Phản ứng"}, {"term_ko": "저하", "term_vi": "Giảm", "def_ko": "감소", "def_vi": "Giảm"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (55, '7', '영양 문제 발생 위험이 가장 높은 대상자로 옳은 것은?', '["인지기능이 저하된 대상자", "배변활동이 양호한 대상자", "거동에 문제가 없는 대상자", "잇몸에 맞는 틀니를 낀 대상자", "시력 교정용 안경을 쓴 대상자"]'::jsonb, 1, '영양 문제 발생 위험이 높은 대상자는 주로 인지 기능이 저하된 환자로, 이들은 영양 섭취에 어려움을 겪을 수 있습니다.', NULL, '{"1": "인지기능이 저하된 대상자는 영양 문제 발생 위험이 높습니다.\n[정답]", "2": "배변활동이 양호한 대상자는 영양 문제와 직접적인 관련이 없습니다.", "3": "거동에 문제가 없는 대상자는 보통 영양 문제가 덜 발생합니다.", "4": "잇몸에 맞는 틀니를 낀 대상자는 씹는데 문제가 없을 수 있어 영양 문제와는 거리가 있습니다.", "5": "시력 교정용 안경을 쓴 대상자는 영양 문제 발생 위험에 영향을 미치지 않습니다."}'::jsonb, '[{"term_ko": "영양", "term_vi": "Dinh dưỡng", "def_ko": "영양(한국어)", "def_vi": "Dinh dưỡng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (54, '7', '노인이 운동을 꺼리는 이유로 옳은 것은?', '["복부지방 감소", "폐활량 감소", "관절의 운동범위 증가", "자극에 대한 반응 증가", "폐활량 증가"]'::jsonb, 2, '노인이 운동을 꺼리는 이유에 대한 이해를 확인하려는 문제입니다.', NULL, '{"1": "복부지방 감소는 운동을 통해 일어날 수 있는 긍정적인 효과입니다.\n[정답]", "2": "폐활량 감소는 노인이 운동을 꺼리는 이유 중 하나입니다.", "3": "관절의 운동범위 증가도 운동의 긍정적인 효과입니다.", "4": "자극에 대한 반응 증가는 운동의 효과가 아닙니다.", "5": "폐활량 증가는 운동이 이루어질 때의 효과입니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người có tuổi cao"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (53, '7', '대상자의 건강증진을 위한 운동 방법으로 옳은 것은?', '["빠르게 방향을 바꾸는 운동을 한다.", "개인의 신체능력에 맞는 운동을 한다.", "고강도에서 중강도 운동으로 진행한다.", "준비 운동은 2 ~ 3분 이내로 짧게 한다.", "호흡곤란, 부정맥, 혈압이 있을 때는 고강도 운동을 한다."]'::jsonb, 2, '대상자의 건강증진을 위한 적절한 운동 방법을 이해하고 선택할 수 있는지를 묻는 문제입니다.', NULL, '{"1": "빠르게 방향을 바꾸는 운동은 부상을 유발할 수 있어 건강증진에 적합하지 않다.\n[정답]", "2": "개인의 신체능력에 맞는 운동은 안전하고 효과적으로 건강증진에 기여할 수 있다.", "3": "고강도에서 중강도 운동으로 진행하는 것은 개인의 체력이 허락할 경우에 적절하더라도 무조건적인 진행은 문제가 될 수 있다.", "4": "준비 운동은 최소 5분 이상이 권장되므로 2~3분은 적절하지 않다.", "5": "호흡곤란, 부정맥, 혈압이 있는 경우에는 고강도 운동을 하면 위험할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Người được chăm sóc"}, {"term_ko": "건강증진", "term_vi": "Cải thiện sức khỏe", "def_ko": "건강의 개선", "def_vi": "Sự nâng cao sức khỏe"}, {"term_ko": "운동 방법", "term_vi": "Phương pháp tập luyện", "def_ko": "운동이 이루어지는 방식", "def_vi": "Cách thức tập luyện"}, {"term_ko": "신체능력", "term_vi": "Khả năng thể chất", "def_ko": "신체의 능력", "def_vi": "Năng lực của cơ thể"}, {"term_ko": "고강도", "term_vi": "Cường độ cao", "def_ko": "높은 강도의 운동", "def_vi": "Mức độ cao"}, {"term_ko": "호흡곤란", "term_vi": "Khó thở", "def_ko": "호흡에 어려움을 겪는 것", "def_vi": "Gặp khó khăn trong việc thở"}, {"term_ko": "부정맥", "term_vi": "Rối loạn nhịp tim", "def_ko": "심장 박동이 불규칙한 상태", "def_vi": "Tình trạng nhịp tim không đều"}, {"term_ko": "혈압", "term_vi": "Huyết áp", "def_ko": "혈액 압력", "def_vi": "Áp lực máu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (52, '7', '노화로 인한 수면양상의 변화로 옳은 것은?', '["수면 중에 자주 깬다.", "수면시간이 늘어난다.", "잠드는 데 시간이 줄어든다.", "낮 동안 졸림 증상이 줄어든다.", "아침에 늦게 일어난다."]'::jsonb, 1, '노화로 인해 수면 양상이 어떻게 변화하는지를 이해하고 있는지를 묻는 문제입니다.', NULL, '{"1": "노화가 진행되면 수면의 질이 저하되어 자주 깨어나는 현상이 나타납니다.\n[정답]", "2": "일반적으로 수면 시간은 감소하는 경향이 있습니다.", "3": "수면의 시작 시간은 오히려 길어질 수 있습니다.", "4": "낮 동안 졸림 증상은 증가하는 경향이 있습니다.", "5": "아침에 일어나는 시간은 오히려 빨라질 수 있습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 들다(한국어)", "def_vi": "Trở nên già"}, {"term_ko": "수면", "term_vi": "Giấc ngủ", "def_ko": "잠자다(한국어)", "def_vi": "Ngủ"}, {"term_ko": "자주", "term_vi": "Thường xuyên", "def_ko": "자주(한국어)", "def_vi": "Thường xuyên"}, {"term_ko": "깬다", "term_vi": "Thức dậy", "def_ko": "깨다(한국어)", "def_vi": "Thức dậy"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증상(한국어)", "def_vi": "Triệu chứng"}, {"term_ko": "일어난다", "term_vi": "Dậy", "def_ko": "일어나다(한국어)", "def_vi": "Dậy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (51, '7', '밤에 잠이 들기까지 시간이 오래 걸리고 자주 깨는 대상자의 수면을 돕는 방법으로 옳은 것은?', '["저녁에 과식하지 않는다.", "가습기를 이용하여 습도를 80%로 맞춘다.", "밤에 땀 흘리는 운동을 하게 한다.", "저녁 식사 후 따뜻한 홍차를 마시게 한다.", "취침 전에 집중할 수 있는 놀이를 함께 한다."]'::jsonb, 1, '대상자의 수면 패턴을 개선할 수 있는 방법을 이해하고 적용할 수 있는지를 평가하기 위함입니다.', NULL, '{"1": "저녁에 과식하지 않는 것은 소화에 도움을 주어 수면의 질을 개선한다.\n[정답]", "2": "가습기를 이용하여 습도를 80%로 맞추는 것은 과도한 습도로 인해 오히려 불편함을 줄 수 있다.", "3": "밤에 땀 흘리는 운동을 하게 하는 것은 오히려 신체의 에너지를 활성화시켜 수면을 방해할 수 있다.", "4": "저녁 식사 후 따뜻한 홍차를 마시는 것은 카페인이 포함되어 있어 수면에 방해가 될 수 있다.", "5": "취침 전에 집중할 수 있는 놀이를 함께 하는 것은 오히려 긴장을 높여 수면을 방해할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "수면", "term_vi": "Giấc ngủ", "def_ko": "잠(한국어)", "def_vi": "Ngủ"}, {"term_ko": "가습기", "term_vi": "Máy tạo độ ẩm", "def_ko": "습도를 조절하는 기기(한국어)", "def_vi": "Thiết bị điều chỉnh độ ẩm"}, {"term_ko": "과식", "term_vi": "Ăn quá no", "def_ko": "너무 많이 먹는 것(한국어)", "def_vi": "Ăn nhiều"}, {"term_ko": "적당한", "term_vi": "Thích hợp", "def_ko": "적절한(한국어)", "def_vi": "Phù hợp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (50, '7', '여성노인의 성적 변화에 관한 설명으로 옳은 것은?', '["질 분비물 증가로 성교 시 통증이 없다.", "유방절제술을 받으면 성기능이 감소한다.", "항 염증성 약물을 복용하면 성기능이 증가한다.", "전립선 절세술은 발기하는 데 문제를 유발한다.", "유방절제술은 성기능에 영향을 주지 않는다."]'::jsonb, 5, '여성 노인의 성적 변화와 관련된 사실을 올바르게 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "질 분비물의 증가가 성교 시 통증의 원인이 되는 경우가 많기 때문에 이 설명은 잘못되었습니다.\n[정답]", "5": "유방절제술이 성기능에 영향을 미치지 않는다는 것은 연구에 의해 지지받는 내용을 반영한 것입니다.", "2": "유방절제술 후 일부 여성은 성기능 변화가 있을 수 있으나, 이는 개인에 따라 다릅니다.", "3": "항 염증성 약물이 성기능을 증가시키는 것은 일반적으로 알려진 바가 아닙니다.", "4": "전립선 절세술은 남성의 성기능에 영향을 줄 수 있지만, 여성의 경우에는 관계가 없습니다."}'::jsonb, '[{"term_ko": "여성", "term_vi": "Phụ nữ", "def_ko": "여자(한국어)", "def_vi": "Nữ giới(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (49, '7', '뇌졸중 대상자가 성생활에 대해 고민할 때 요양보호사의 반응으로 옳은 것은?', '["\"성생활은 뇌졸중 재발의 원인이 돼요.\"", "\"성생활로 뇌졸중이 악화되지 않아요.\"", "\"윤활제는 사용하지 않는 것이 좋아요.\"", "\"뇌졸중 치료제를 드시면 성기능이 좋아져요.\"", "\"체위 변화를 위한 기구는 성생활에 도움이 되지 않아요.\""]'::jsonb, 2, '뇌졸중 환자의 성생활에 대한 이해와 요양보호사의 올바른 반응을 평가하기 위해 출제되었다.', NULL, '{"1": "성생활이 뇌졸중 재발의 원인이 된다는 것은 과학적 증거가 부족하다. \n[정답]", "2": "성생활은 뇌졸중 환자에게 특별한 주의만 기울이면 안전하게 할 수 있다.", "3": "윤활제 사용은 성생활의 질을 향상시킬 수 있다.", "4": "뇌졸중 치료제는 성기능에 영향이 있을 수 있으나, 반드시 좋게 작용하지는 않는다.", "5": "체위 변화를 위한 기구는 성생활에 도움이 될 수 있다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈류가 방해받아 발생하는 질환", "def_vi": "Bệnh xảy ra khi máu đến não bị cản trở"}, {"term_ko": "성생활", "term_vi": "Đời sống tình dục", "def_ko": "성적인 활동", "def_vi": "Hoạt động tình dục"}, {"term_ko": "윤활제", "term_vi": "Chất bôi trơn", "def_ko": "성행위 시 마찰을 줄이기 위해 사용하는 물질", "def_vi": "Chất được sử dụng để giảm ma sát trong quan hệ tình dục"}, {"term_ko": "체위", "term_vi": "Tư thế", "def_ko": "몸의 자세", "def_vi": "Địa điểm hoặc chiều hướng của cơ thể"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (48, '7', '시설에서의 노인의 성생활과 관련된 권리로 옳은 것은?', '["노인도 성적 존재임을 인정한다.", "부부라도 한방을 쓸 수 없도록 한다.", "자신의 성을 인식하고 표현하지 않도록 한다.", "노인부부의 성생활을 흥밋거리로 다룬다.", "노인 개인의 성과 관련된 상담은 하지 않는다."]'::jsonb, 1, '노인의 성생활에 관한 권리를 이해하고 올바른 선택지를 찾기 위한 문제입니다.', NULL, '{"1": "노인은 성적 존재로 인식되어야 하며, 그 권리가 존중받아야 합니다.\n[정답]", "2": "부부는 개인의 사생활을 존중받아야 하므로 한 방을 함께 사용할 수 있어야 합니다.", "3": "노인은 자신의 성을 인식하고 표현할 권리가 있습니다.", "4": "노인의 성생활은 사생활이므로 비하하거나 흥미거리로 삼아서는 안 됩니다.", "5": "노인 개인의 성과 관련된 상담은 그들의 권리를 존중하기 위해 필요할 수 있습니다."}'::jsonb, '[{"term_ko": "성생활", "term_vi": "Cuộc sống tình dục", "def_ko": "성적 활동(한국어)", "def_vi": "Hoạt động tình dục"}, {"term_ko": "권리", "term_vi": "Quyền lợi", "def_ko": "법적으로 보장된 특정한 이점(한국어)", "def_vi": "Lợi ích cụ thể được đảm bảo theo pháp luật"}, {"term_ko": "인식", "term_vi": "Nhận thức", "def_ko": "알고 이해하거나 받아들이는 것(한국어)", "def_vi": "Biết, hiểu hoặc chấp nhận"}, {"term_ko": "상담", "term_vi": "Tư vấn", "def_ko": "전문가와 이야기를 나누는 것(한국어)", "def_vi": "Nói chuyện với chuyên gia"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (47, '7', '편의점에서 구입 가능한 상비약으로 옳은 것은?', '["해열진통제, 소화제, 파스", "감기약, 수면제", "소화제, 항생제", "파스, 스테로이드 연고", "해열제, 혈압약"]'::jsonb, 1, '편의점에서 구매할 수 있는 상비약에 대한 이해를 요구하는 문제입니다.', NULL, '{"1": "해열진통제, 소화제, 파스는 일반적으로 편의점에서 구입할 수 있는 상비약입니다.\n[정답]", "2": "감기약, 수면제는 일반적으로 편의점에서 구입할 수 없는 약입니다.", "3": "소화제, 항생제는 항생제는 처방이 필요하므로 편의점에서 구입할 수 없습니다.", "4": "파스, 스테로이드 연고는 스테로이드 연고는 일반적으로 전문 약국에서 처방받아야 합니다.", "5": "해열제, 혈압약은 혈압약은 처방전이 필요한 약이므로 편의점에서 구매할 수 없습니다."}'::jsonb, '[{"term_ko": "편의점", "term_vi": "Cửa hàng tiện lợi", "def_ko": "소형 매점", "def_vi": "Cửa hàng nhỏ gọn"}, {"term_ko": "상비약", "term_vi": "Thuốc cơ bản", "def_ko": "기본적인 의약품", "def_vi": "Thuốc y tế cơ bản"}, {"term_ko": "해열진통제", "term_vi": "Thuốc giảm đau hạ sốt", "def_ko": "열을 내리고 통증을 완화하는 약", "def_vi": "Thuốc giảm sốt và đau"}, {"term_ko": "소화제", "term_vi": "Thuốc tiêu hóa", "def_ko": "소화불량을 치료하는 약", "def_vi": "Thuốc điều trị rối loạn tiêu hóa"}, {"term_ko": "파스", "term_vi": "Cao dán", "def_ko": "붙이는 약", "def_vi": "Thuốc dán"}, {"term_ko": "감기약", "term_vi": "Thuốc cảm", "def_ko": "감기를 치료하는 약", "def_vi": "Thuốc điều trị cảm cúm"}, {"term_ko": "수면제", "term_vi": "Thuốc ngủ", "def_ko": "잠이 오게 하는 약", "def_vi": "Thuốc giúp ngủ"}, {"term_ko": "항생제", "term_vi": "Kháng sinh", "def_ko": "세균 감염을 치료하는 약", "def_vi": "Thuốc điều trị nhiễm trùng"}, {"term_ko": "스테로이드 연고", "term_vi": "Thuốc mỡ steroid", "def_ko": "피부 질환 치료용 연고", "def_vi": "Thuốc mỡ điều trị bệnh ngoài da"}, {"term_ko": "혈압약", "term_vi": "Thuốc huyết áp", "def_ko": "고혈압 치료약", "def_vi": "Thuốc điều trị huyết áp cao"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (46, '7', '노인 대상자의 약물 복용 방법으로 옳은 것은?', '["위장 장애가 있을 때에는 약의 용량을 줄인다.", "코팅된 약을 삼키기 힘들 때는 분쇄하여 복용한다.", "약이 효과가 없을 때에는 임의로 복용을 중단한다.", "복용 약이 있는 경우 건강기능식품 섭취는 의사와 상의한다.", "약이 없으면 증상이 비슷한 다른 대상자의 약을 먹는다."]'::jsonb, 4, '노인 대상자의 약물 복용 방법에 대한 올바른 이해 여부를 묻는 문제입니다.', NULL, '{"1": "위장 장애가 있을 때에는 의사의 처방에 따라 용량 조절이 필요합니다. 따라서 단순히 줄이는 것은 올바른 방법이 아닙니다.", "2": "코팅된 약물을 분쇄하여 복용하는 것은 약물의 효과에 영향을 줄 수 있어 권장되지 않습니다.\n[정답]", "3": "약물이 효과가 없다고 해서 임의로 중단하는 것은 위험한 행동입니다.", "4": "복용 중인 약물이 있을 경우 건강기능식품 섭취는 반드시 의사와 상의해야 하는 것이 맞습니다.", "5": "약이 없다고 다른 대상자의 약을 복용하는 것은 매우 위험한 행동입니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "Thuốc"}, {"term_ko": "복용", "term_vi": "Uống thuốc", "def_ko": "복용하다(한국어)", "def_vi": "Uống thuốc"}, {"term_ko": "이상", "term_vi": "Triệu chứng", "def_ko": "이상(한국어)", "def_vi": "Triệu chứng"}, {"term_ko": "중단", "term_vi": "Ngừng", "def_ko": "중단하다(한국어)", "def_vi": "Ngừng"}, {"term_ko": "확인", "term_vi": "Kiểm tra", "def_ko": "확인하다(한국어)", "def_vi": "Kiểm tra"}, {"term_ko": "상담", "term_vi": "Tư vấn", "def_ko": "상담하다(한국어)", "def_vi": "Tư vấn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (45, '7', '관절염, 근육통 약으로, 노인에서는 위염, 위궤양, 속쓰림 등의 부작용이 나타나는 약물로 옳은 것은?', '["당뇨병 약", "스테로이드제", "수면제", "소염진통제", "고지혈증 약"]'::jsonb, 4, '노인 환자에게 나타날 수 있는 약물의 부작용을 이해하고, 올바른 약물을 선택하는 능력을 평가하기 위함입니다.', NULL, '{"1": "당뇨병 약: 당뇨병 약물은 주로 혈당 조절을 위한 약물로, 위염이나 위궤양과 관련된 부작용이 일반적이지 않습니다.\n[정답]", "2": "스테로이드제: 스테로이드제는 장기적으로 사용 시 위염, 위궤양과 같은 부작용이 나타날 수 있습니다.", "3": "수면제: 수면제는 주로 수면을 유도하는 약물로, 위장관 부작용이 주가 아닙니다.", "4": "소염진통제: 소염진통제는 관절염 및 근육통 치료에 사용되며, 노인에게 위염과 위궤양을 유발할 수 있습니다.", "5": "고지혈증 약: 고지혈증 약물은 주로 혈중 지방을 조절하지만, 위장관 부작용은 드물게 나타납니다."}'::jsonb, '[{"term_ko": "관절염", "term_vi": "Viêm khớp", "def_ko": "관절의 염증 및 통증(한국어)", "def_vi": "Viêm và đau tại khớp"}, {"term_ko": "근육통", "term_vi": "Đau cơ", "def_ko": "근육의 통증(한국어)", "def_vi": "Đau ở cơ"}, {"term_ko": "위염", "term_vi": "Viêm dạ dày", "def_ko": "위의 염증(한국어)", "def_vi": "Viêm ở dạ dày"}, {"term_ko": "위궤양", "term_vi": "Loét dạ dày", "def_ko": "위에 생기는 궤양(한국어)", "def_vi": "Hình thành loét ở dạ dày"}, {"term_ko": "소염진통제", "term_vi": "Thuốc giảm đau kháng viêm", "def_ko": "염증과 통증을 완화하는 약물(한국어)", "def_vi": "Thuốc giúp giảm viêm và đau"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (44, '7', '와파린고 함께 먹었을 때 약의 효과를 줄일 수 있어 과량 섭취하지 않는 음식으로 옳은 것은?', '["인삼", "시금치", "프로바이오틱스", "알로에", "감마리놀레산"]'::jsonb, 2, '와파린과 함께 섭취할 때 약의 효과를 줄일 수 있는 음식을 알고 있는지를 묻는 문제입니다.', NULL, '{"1": "인삼은 혈액 응고에 영향을 줄 수 있어 주의해야 합니다.\n[정답]", "2": "시금치는 와파린과 함께 섭취해도 안전하며, 과량 섭취하지 않아야 하는 음식입니다.", "3": "프로바이오틱스는 일반적으로 와파린에 영향을 주지 않습니다.", "4": "알로에는 항응고 효과가 있어 주의가 필요합니다.", "5": "감마리놀레산은 혈액 응고에 영향을 미칠 수 있는 물질입니다."}'::jsonb, '[{"term_ko": "와파린", "term_vi": "인삼", "def_ko": "항응고제(thuốc chống đông máu)", "def_vi": "한약재(thuốc đông y)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (43, '7', '약물 복용 방법으로 옳은 것은?', '["쓴 약은 커피우유와 함께 복용한다.", "약이 없으면 증상이 비슷한 다른 사람의 약을 복용한다.", "약 복용 시간을 놓친 경우 용량을 2배 용량으로 복용한다.", "처방이 바뀌면 이전 약을 모두 복용한 후 바뀐 약을 복용한다.", "삼키기 힘든 약이 분할할 수 없는 약이라면 처방을 변경해달라고 한다."]'::jsonb, 5, '약물 복용 방법에 대한 올바른 이해를 평가하기 위한 문제입니다.', NULL, '{"1": "쓴 약은 다른 음료와 함께 복용하는 것이 도움이 될 수 있으나, 반드시 커피우유와 함께 복용해야 하는 것은 아닙니다.\n[정답]", "5": "삼키기 힘든 약은 분할할 수 없으므로 의사에게 처방 변경을 요청하는 것이 바람직합니다.", "2": "타인의 약을 복용하는 것은 안전하지 않으며, 반드시 본인의 처방 약을 복용해야 합니다.", "3": "약 복용 시간을 놓쳤을 경우, 용량을 두 배로 복용하는 것은 위험할 수 있습니다.", "4": "처방이 바뀌더라도 이전 약을 모두 복용한 후 바뀐 약을 복용하는 것은 잘못된 방법입니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "thuốc(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (42, '7', '흡연과 금연에 관한 설명으로 옳은 것은?', '["흡연은 중독성이 없다.", "금연 시기를 놓치면 금연 효과가 없다.", "일시적 금연은 폐기능을 악화시킨다.", "간접흡연도 직접흡연을 하는 경우와 마찬가지다.", "금연 시 혈중 일산화탄소 수치가 증가한다."]'::jsonb, 4, '흡연과 금연에 대한 기본적인 지식을 평가하고자 하는 문제입니다.', NULL, '{"1": "흡연은 중독성이 없다. 이는 잘못된 설명입니다.\n[정답]", "4": "간접흡연도 직접흡연을 하는 경우와 마찬가지다. 간접흡연은 직접흡연처럼 건강에 해롭습니다.", "2": "금연 시기를 놓치면 금연 효과가 없다. 이는 부정확한 설명입니다.", "3": "일시적 금연은 폐기능을 악화시킨다. 이는 올바른 설명이 아닙니다.", "5": "금연 시 혈중 일산화탄소 수치가 증가한다. 이는 잘못된 설명입니다."}'::jsonb, '[{"term_ko": "흡연", "term_vi": "Hút thuốc", "def_ko": "담배를 피우는 것", "def_vi": "Hành động hút thuốc lá"}, {"term_ko": "금연", "term_vi": "Bỏ thuốc", "def_ko": "담배를 끊는 것", "def_vi": "Ngừng hút thuốc lá"}, {"term_ko": "중독성", "term_vi": "Tính gây nghiện", "def_ko": "중독의 성질", "def_vi": "Tính chất của sự nghiện"}, {"term_ko": "일시적", "term_vi": "Tạm thời", "def_ko": "잠깐 동안", "def_vi": "Trong một khoảng thời gian ngắn"}, {"term_ko": "간접흡연", "term_vi": "Hút thuốc thụ động", "def_ko": "다른 사람이 피우는 담배 연기를 흡입", "def_vi": "Hít khói thuốc từ người khác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (41, '7', '금연 후 나타나는 변화로 옳은 것은?', '["정자 수가 감소한다.", "기대수명이 감소한다.", "혈액순환이 감소한다.", "심장병 발생 위험이 감소한다.", "혈중 산소량이 정상보다 감소한다."]'::jsonb, 4, '금연 후 나타나는 긍정적인 변화를 파악하고자 하는 의도입니다.', NULL, '{"1": "금연 후 정자 수는 오히려 증가하는 경향이 있습니다.", "2": "금연은 기대수명을 증가시키는 효과가 있습니다.", "3": "혈액순환은 금연 후 개선됩니다.\n[정답]", "4": "금연 후 심장병 발생 위험이 감소하는 것이 정확한 설명입니다.", "5": "혈중 산소량은 정상으로 회복됩니다."}'::jsonb, '[{"term_ko": "금연", "term_vi": "Bỏ thuốc lá", "def_ko": "담배를 끊는 것", "def_vi": "Ngừng hút thuốc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (40, '7', '음주를 매일 하는 대상자의 절주를 돕는 방법으로 옳은 것은?', '["알코올 도수가 높은 술을 마신다.", "권유받았을 때만 술을 마신다.", "일주일에 술 마시는 날을 정한다.", "절주 의지를 주변 사람들에게 알리게 한다.", "암 예방을 위해 하루 한두 잔의 술을 허용한다."]'::jsonb, 4, '음주를 지속하는 대상자의 절주를 돕기 위한 올바른 방법을 찾는 것.', NULL, '{"1": "알코올 도수가 높은 술을 마신다.", "2": "권유받았을 때만 술을 마신다.", "3": "일주일에 술 마시는 날을 정한다.\n[정답]", "4": "절주 의지를 주변 사람들에게 알리게 한다.", "5": "암 예방을 위해 하루 한두 잔의 술을 허용한다."}'::jsonb, '[{"term_ko": "음주", "term_vi": "Uống rượu", "def_ko": "술을 마시는 것", "def_vi": "Uống rượu"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (39, '7', '금연과 흡연의 금단 증상 대처 및 스트레스 관리로 옳은 것은?', '["적절한 식단보다 영양제를 중심으로 공급한다.", "금단증상이 심하더라도 약물치료는 피한다.", "술 생각이 유발되는 상황을 피한다.", "스트레스 받는 상황에서 적당한 음주와 흡연을 한다.", "불규칙한 생활습관을 통해 스트레스를 관리한다."]'::jsonb, 3, '금연과 관련된 행동 요령 및 대처 방법에 대해 묻는 문제입니다.', NULL, '{"1": "적절한 식단보다는 영양제를 공급하는 것은 금연의 도움에 비효율적입니다.\n[정답]", "3": "술 생각이 유발되는 상황을 피하는 것은 금연을 지속하는 데 도움이 됩니다.", "2": "금단증상이 심하더라도 약물치료는 필요할 수 있으므로 피하는 것이 옳지 않습니다.", "4": "스트레스를 받는 상황에서 음주와 흡연은 오히려 위험합니다.", "5": "불규칙한 생활습관은 스트레스를 오히려 악화시킬 수 있습니다."}'::jsonb, '[{"term_ko": "금연", "term_vi": "Bỏ thuốc lá", "def_ko": "담배를 끊는 것", "def_vi": "Ngừng hút thuốc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (38, '7', '60세 이상 노인에게 권장되는 예방접종에 관한 설명으로 옳은 것은?', '["폐렴구균은 매년 1회 접종한다.", "인플루엔자는 10년마다 1회 접종한다.", "백일해는 10년마다 접종한다.", "파상풍은 1회 접종했다면 10년마다 추갈 접종한다.", "대상포진은 과거에 홍역을 앓았다면 접종할 필요가 없다."]'::jsonb, 4, '60세 이상 노인에게 필요한 예방접종에 대한 기본 지식을 점검하기 위함입니다.', NULL, '{"1": "폐렴구균은 매년 1회 접종하는 것이 아니라, 일정한 기준에 따라 접종합니다.\n[정답]", "4": "파상풍은 1회 접종 후 10년마다 추가 접종이 필요합니다.", "2": "인플루엔자는 매년 접종해야 합니다.", "3": "백일해는 성인이 경우 10년마다 접종할 필요가 없습니다.", "5": "대상포진은 홍역 이력과는 관계없이 접종이 권장됩니다."}'::jsonb, '[{"term_ko": "예방접종", "term_vi": "Tiêm vắc xin", "def_ko": "예방을 위한 백신 접종", "def_vi": "Tiêm phòng để ngăn ngừa"}, {"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "60세 이상의 성인", "def_vi": "Người trên 60 tuổi"}, {"term_ko": "폐렴구균", "term_vi": "Phế cầu khuẩn", "def_ko": "폐렴을 일으키는 세균", "def_vi": "Vi khuẩn gây bệnh viêm phổi"}, {"term_ko": "인플루엔자", "term_vi": "Cúm", "def_ko": "독감", "def_vi": "Bệnh cúm"}, {"term_ko": "대상포진", "term_vi": "Zona", "def_ko": "수두의 바이러스가 재활성화되어 발생", "def_vi": "Bệnh zona (Herpes zoster)"}, {"term_ko": "파상풍", "term_vi": "Uốn ván", "def_ko": "상처로 인한 세균 감염", "def_vi": "Nhiễm khuẩn do vết thương"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (37, '7', '60세 이상 노인에게 매년 1회 권장되는 예방접종으로 옳은 것은?', '["디프테리아", "백일해", "대상포진", "폐렴구균", "인플루엔자"]'::jsonb, 5, '노인을 위한 예방접종의 중요성을 파악하고, 필요한 예방접종에 대한 지식을 평가하기 위함입니다.', NULL, '{"1": "디프테리아: 노인에게 권장되지만 매년 접종할 필요는 없음.", "2": "백일해: 노인에게 권장되지만 매년 접종할 필요는 없음.\n[정답]", "3": "인플루엔자: 60세 이상 노인은 매년 예방접종을 권장받는 중요한 예방접종입니다.", "4": "폐렴구균: 노인에게 권장되지만 매년 접종할 필요는 없음.", "5": "대상포진: 노인에게 권장되지만 매년 접종할 필요는 없음."}'::jsonb, '[{"term_ko": "예방접종", "term_vi": "Tiêm phòng", "def_ko": "예방접종(한국어)", "def_vi": "Tiêm phòng(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (36, '7', '10년마다 추가 접종해야 하는 것으로 옳은 것은?', '["폐렴구균 - 백일해", "파상풍 - 디프테리아", "인플루엔자 - 백일해", "폐렴구균 - 디프테리아", "대상포진 - 인플루엔자"]'::jsonb, 2, '10년마다 추가 접종이 필요한 백신에 대한 지식을 평가하기 위함입니다.', NULL, '{"1": "폐렴구균 - 백일해: 폐렴구균 백신은 10년마다 접종해야 하는 것이 아닙니다.\n[정답]", "2": "파상풍 - 디프테리아: 파상풍과 디프테리아 백신은 10년마다 추가 접종을 권장합니다.", "3": "인플루엔자 - 백일해: 인플루엔자는 매년 접종이 권장되며, 백일해는 추가 접종 대상이 아닙니다.", "4": "폐렴구균 - 디프테리아: 폐렴구균 백신은 10년마다 접종해야 하는 것이 아닙니다.", "5": "대상포진 - 인플루엔자: 대상포진 백신은 1회 접종으로 충분하며, 인플루엔자는 매년 접종이 필요합니다."}'::jsonb, '[{"term_ko": "파상풍", "term_vi": "Uốn ván", "def_ko": "질병명(한국어)", "def_vi": "bệnh"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (35, '7', '여름철 폭염에 대응하는 안전수칙으로 옳은 것은?', '["물을 평소보다 많이 마신다.", "지방이 많은 음식을 섭취한다.", "실내보다 실외에서 운동한다.", "외출 시 챙이 좁은 모자를 쓴다.", "두통이 있으면 뜨거운 차를 마신다."]'::jsonb, 1, '여름철 폭염에 대처하기 위한 올바른 안전수칙을 파악하는 것이다.', NULL, '{"1": "물을 충분히 마시는 것은 여름철 열사병 예방에 중요하다.\n[정답]", "2": "지방이 많은 음식은 체온 상승을 유발할 수 있으므로 적절하지 않다.", "3": "실외에서 운동하는 것은 폭염 시 위험할 수 있다.", "4": "챙이 좁은 모자는 햇빛을 충분히 막지 못해 보호효과가 낮다.", "5": "두통이 있을 때 뜨거운 차를 마시는 것은 추천되지 않는다."}'::jsonb, '[{"term_ko": "폭염", "term_vi": "Nắng nóng", "def_ko": "극심한 더위(한국어)", "def_vi": "Nhiệt độ cao cực độ (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (34, '7', '열사병이 있을 때 대응하는 안전수칙으로 옳은 것은?', '["심한 갈증, 피로감을 호소한다.", "근육경련이 2~3분 동안 지속한다.", "젖은 수건으로 몸을 적신 후 선풍기 바람을 씌워준다.", "땀을 많이 흘린 뒤 발생한다.", "염분과 수분을 보충하도록 한다."]'::jsonb, 3, '열사병 발생 시 적절한 대처 방법을 아는 것이 중요하다는 점을 평가하기 위한 문제입니다.', NULL, '{"1": "심한 갈증과 피로감은 열사병의 증상 중 하나이지만 대응 방법이 아닙니다.", "2": "근육 경련이 지속되는 것은 열사병의 증상이나, 이에 대한 대처법은 아닙니다.\n[정답]", "3": "젖은 수건으로 몸을 적신 후 선풍기 바람을 씌워주는 것은 열사병의 적절한 응급처치 방법입니다.", "4": "땀을 많이 흘린 후 발생할 수 있지만, 이는 대응 방법은 아닙니다.", "5": "염분과 수분 보충은 필요하지만, 응급조치로는 젖은 수건과 선풍기 사용이 더 중요합니다."}'::jsonb, '[{"term_ko": "열사병", "term_vi": "Bệnh say nắng", "def_ko": "고온 상태에서 발생하는 질병", "def_vi": "Bệnh xảy ra khi ở nhiệt độ cao"}, {"term_ko": "안전수칙", "term_vi": "Quy tắc an toàn", "def_ko": "사고를 예방하기 위한 규칙", "def_vi": "Quy tắc để ngăn ngừa tai nạn"}, {"term_ko": "응급처치", "term_vi": "Cấp cứu", "def_ko": "긴급 상황에서의 치료", "def_vi": "Điều trị trong tình huống khẩn cấp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (33, '7', '겨울철 안전수칙으로 옳은 것은?', '["실내운동을 삼가고 실외운동으로 바꾼다.", "운동은 새벽보다는 낮 시간을 이용한다.", "술을 마신 다음날 아침에는 가급적 운동을 한다.", "동상 예방을 위해 손은 주머니에 넣고 다닌다.", "움직임이 둔한 옷으로 보온을 한다."]'::jsonb, 2, '겨울철 안전수칙을 이해하고 있는지를 평가하기 위함입니다.', NULL, '{"1": "실내운동은 겨울철 안전을 위해 추천되지 않으며, 실외운동의 위험이 큽니다.\n[정답]", "2": "낮 시간대에는 햇볕이 있어 체온 유지에 도움이 되므로 운동하기에 적합합니다.", "3": "술의 영향으로 반응속도가 떨어지므로 다음날 아침 운동하는 것은 안전하지 않습니다.", "4": "손을 주머니에 넣고 다니는 것은 동상 예방에 도움이 되지 않으며, 장갑을 착용하는 것이 좋습니다.", "5": "보온을 위해서는 활동적인 움직임을 유지하는 것이 중요하므로 둔한 옷은 피해야 합니다."}'::jsonb, '[{"term_ko": "겨울철", "term_vi": "Mùa đông", "def_ko": "올 겨울", "def_vi": "Mùa đông sắp đến"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (32, '7', '저체온과 같은 한랭질환이 있을 때 대응하는 안전수칙으로 옳은 것은?', '["의식이 있다면 따뜻한 초콜릿 같은 단 음식을 섭취하게 한다.", "젖은 옷 위에 담요로 감싸는 것이 좋다.", "피부색이 창백하고 누런 회색으로 변하면 따뜻한 물에 담그는 것이 좋다.", "대상자를 시원한 곳으로 옮기고 미지근한 물에 담근다.", "의식이 없더라도 따뜻한 차를 마시게 한다."]'::jsonb, 1, '저체온증 및 한랭질환에 대한 올바른 대응 방안을 파악하기 위한 문제입니다.', NULL, '{"1": "의식이 있다면 따뜻한 초콜릿 같은 단 음식을 섭취하게 한다. - 저체온증 환자가 의식이 있을 때 따뜻한 음식을 제공하는 것은 중요한 조치입니다.\n[정답]", "2": "젖은 옷 위에 담요로 감싸는 것이 좋다. - 젖은 옷은 체온 유지에 방해가 되므로 즉시 벗기고 담요로 덮어주는 것이 올바른 대처가 아닙니다.", "3": "피부색이 창백하고 누런 회색으로 변하면 따뜻한 물에 담그는 것이 좋다. - 따뜻한 물에 담그는 것은 부적절하며, 급격한 온도 변화는 위험할 수 있습니다.", "4": "대상자를 시원한 곳으로 옮기고 미지근한 물에 담근다. - 시원한 곳으로 옮기는 것은 잘못된 행동입니다. 적절한 온도로 보존해야 합니다.", "5": "의식이 없더라도 따뜻한 차를 마시게 한다. - 의식이 없는 환자에게 음료를 제공하는 것은 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "저체온", "term_vi": "Hạ thân nhiệt", "def_ko": "저체온증(한국어)", "def_vi": "Bệnh hạ thân nhiệt"}, {"term_ko": "한랭질환", "term_vi": "Bệnh lạnh", "def_ko": "차가운 질병(한국어)", "def_vi": "Bệnh do lạnh"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "인지 상태(한국어)", "def_vi": "Tình trạng nhận thức"}, {"term_ko": "담요", "term_vi": "Chăn", "def_ko": "덮개(한국어)", "def_vi": "Chiếc chăn"}, {"term_ko": "섭취", "term_vi": "Tiêu thụ", "def_ko": "먹다(한국어)", "def_vi": "Tiêu thụ"}, {"term_ko": "온도", "term_vi": "Nhiệt độ", "def_ko": "기온(한국어)", "def_vi": "Nhiệt độ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (31, '8', '대상자와 의사소통하는 방법으로 옳은 것은?', '["대상자와 눈을 마주하기를 피한다.", "호칭을 할 때에는 대상자의 성명을 부른다.", "요양보호사가 알고 있는 전문 용어를 표현한다.", "상황에 맞지 않는 말을 하면 즉시 지적해 준다.", "개인정보 보호를 위해 요양보호사의 소속은 비밀로 한다."]'::jsonb, 2, '대상자와의 효과적인 의사소통 방법을 파악하기 위함입니다.', NULL, '{"1": "대상자와 눈을 마주하기를 피하는 것은 올바른 의사소통 방법이 아니다.\n[정답]", "2": "호칭을 할 때 대상자의 성명을 부르는 것은 존중의 표현으로 적절하다.", "3": "요양보호사가 알고 있는 전문 용어를 표현하는 것은 대상자가 이해하지 못할 수 있으므로 피해야 한다.", "4": "상황에 맞지 않는 말을 하면 즉시 지적하는 것은 관계를 악화시킬 수 있다.", "5": "개인정보 보호를 위해 요양보호사의 소속은 당연히 공개되어야 한다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통, 교류(한국어)", "def_vi": "sự trao đổi, giao lưu(베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (30, '8', '바람직한 비언어적 의사소통 기법으로 옳은 것은?', '["생각할 수 있는 긴 침묵", "대상자보다 높은 눈높이", "대상자로부터 비껴 앉은 자세", "간간히 적절하게 미소 짓기", "적절한 희미한 미소"]'::jsonb, 4, '비언어적 의사소통의 중요성과 효과적인 기법을 이해하는 것.', NULL, '{"1": "생각할 수 있는 긴 침묵은 소통에 도움이 되지 않을 수 있으며, 바람직한 기법이 아니다.\n[정답]", "4": "간간히 적절하게 미소 짓기는 긍정적인 비언어적 의사소통 기법이다.", "2": "대상자보다 높은 눈높이는 상대방에게 위압감을 줄 수 있으므로 바람직하지 않다.", "3": "대상자로부터 비껴 앉은 자세는 상대방과의 직접적인 소통을 방해할 수 있다.", "5": "적절한 희미한 미소는 비언어적 의사소통으로 효과를 줄 수 있지만, 간간히 미소 짓는 것이 더 효과적이다."}'::jsonb, '[{"term_ko": "비언어적", "term_vi": "Giao tiếp phi ngôn ngữ", "def_ko": "비언어적 의사소통", "def_vi": "Giao tiếp không dùng từ ngữ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (29, '8', '장기요양서비스에서 의사소통의 원칙으로 옳은 것은?', '["대상자를 개별화하여 파악한다.", "대상자의 감정을 억제하도록 한다.", "요양보호사의 편견에 따라 대상자를 파악한다.", "대상자의 부적절한 행동에 대해 심판적 태도로 대한다.", "장기요양기관의 결정에 따르도록 한다."]'::jsonb, 1, '장기요양서비스에서 의사소통의 기본 원칙을 이해하고 적용하는 것이다.', NULL, '{"1": "대상자를 개별화하여 파악한다는 것은 의사소통의 핵심 원칙 중 하나로, 개인의 특성에 맞춘 접근이 필요하다.\n[정답]", "2": "대상자의 감정을 억제하도록 한다는 것은 잘못된 원칙으로, 감정 표현의 중요성을 무시한다.", "3": "요양보호사의 편견에 따라 대상자를 파악한다는 것은 부적절한 의사소통을 초래할 수 있다.", "4": "대상자의 부적절한 행동에 대해 심판적 태도로 대한다는 것은 신뢰를 저해할 수 있다.", "5": "장기요양기관의 결정에 따르도록 한다는 것은 상황에 따라 유연성이 필요하다."}'::jsonb, '[{"term_ko": "장기요양서비스", "term_vi": "Dịch vụ chăm sóc dài hạn", "def_ko": "장기적인 요양을 제공하는 서비스", "def_vi": "Dịch vụ chăm sóc kéo dài"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "서로 정보를 주고받는 과정", "def_vi": "quá trình truyền đạt thông tin cho nhau"}, {"term_ko": "개별화", "term_vi": "Cá nhân hóa", "def_ko": "개인의 특성에 맞추어 조정하는 것", "def_vi": "điều chỉnh theo đặc điểm cá nhân"}, {"term_ko": "편견", "term_vi": "Thành kiến", "def_ko": "어떤 대상을 공정하지 않게 판단하는 사고", "def_vi": "suy nghĩ đánh giá sai lệch về một đối tượng"}, {"term_ko": "부적절한", "term_vi": "Không phù hợp", "def_ko": "적합하지 않은 상태", "def_vi": "trạng thái không thích hợp"}, {"term_ko": "심판적", "term_vi": "Thái độ phán xét", "def_ko": "판단하고 평가하는 태도", "def_vi": "thái độ đánh giá và quyết định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (28, '8', '다음의 대화에서 요양보호사의 반응으로 옳은 것은?• 대상자 : 내 스웨터 어디 있어? 왜 자꾸 숨겨 놔! • 요양보호사 : ( )', '["\"제가 스웨터 숨기지 않았어요. 함부로 의심하지 마세요.\"", "\"오늘은 스웨터가 없어서 밖에 못 나가시겠네요.\"", "\"새로 구입한 더 예쁜 스웨터가 있어요. 대신 이걸로 입으세요.\"", "\"잘 안 입으셔서 지난번에 제가 딸에게 보냈어요.\"", "\"스웨터가 입고 싶으신가 봐요. 우리 가지러 가요.\""]'::jsonb, 5, '대상자가 스웨터에 대해 불만을 토로하고 있는 상황에서 요양보호사가 적절하게 반응하는 방안을 찾도록 하는 문제입니다.', NULL, '{"1": "너무 방어적인 태도로, 대상자의 감정을 이해하지 못하고 있습니다.\n[정답]", "5": "대상자의 요구를 수용하고, 함께 행동하자는 긍정적인 반응입니다.", "3": "대상자의 불만을 해소하지 못하고 있으며, 새로운 것을 제안하고 있습니다.", "4": "대상자의 감정에 대한 공감이 부족하고, 자신의 행동을 설명하고 있습니다.", "2": "대상자의 감정을 무시하며, 기분이 좋지 않게 만들 수 있는 응답입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자, 간병을 받는 사람", "def_vi": "Người nhận chăm sóc"}, {"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "응답", "def_vi": "Phản hồi"}, {"term_ko": "스웨터", "term_vi": "Áo len", "def_ko": "겉옷", "def_vi": "Áo khoác"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (27, '8', '의사소통할 때 라포가 형성되엇다고 볼 수 있는 대상자의 반응은?', '["눈은 먼 곳을 응시한다.", "시선을 한 곳에 고정한다.", "몸을 뒤로 젖혀 앉는다.", "무슨 일이라도 털어놓고 말한다.", "마음에 들지 않으면 슬쩍 넘어가 피한다."]'::jsonb, 4, '대상자와의 신뢰 관계 형성을 묻는 문제입니다.', NULL, '{"1": "눈은 멀리 쳐다보는 것은 거리감을 나타내기 때문에 라포가 형성되었다고 볼 수 없습니다.", "2": "시선을 한 곳에 고정하는 것은 불안감을 나타낼 수 있어 긍정적인 라포 형성을 의미하지 않습니다.", "3": "몸을 뒤로 젖히며 앉는 것은 거리를 두는 모습으로 보일 수 있습니다.\n[정답]", "4": "무슨 일이든 털어놓고 말하는 것은 신뢰가 형성된 상태로 라포가 형성되었다고 볼 수 있습니다.", "5": "마음에 들지 않으면 피하는 것은 라포가 형성되지 않았음을 나타냅니다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통의 과정", "def_vi": "Quá trình truyền đạt"}, {"term_ko": "라포", "term_vi": "Rapport", "def_ko": "신뢰 관계", "def_vi": "Mối quan hệ tin cậy"}, {"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "도움을 받는 사람", "def_vi": "Người nhận sự giúp đỡ"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "응답", "def_vi": "Phản hồi"}, {"term_ko": "형성되다", "term_vi": "Hình thành", "def_ko": "만들어지다", "def_vi": "Được hình thành"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (26, '8', '대상자가 오늘따라 여기저기 안 아픈 데가 없네. 갈수록 더 아픈 것 같아.라고 할 때 공감적 표혐으로 옳은 것은?', '["\"연세가 있으신데 당연하지요.\"", "\"어디가 아프세요? 병원에 갈까요?\"", "\"어르신만 아픈 게 아니에요. 저도 아파요.\"", "\"건강하고 싶으신데 아프니까 힘드시죠?\"", "\"드시는 약 잘 챙겨 드셔야 해요.\""]'::jsonb, 4, '대상자의 아픔에 대한 공감적 표현을 이해하고 적절한 반응을 선택하는 것입니다.', NULL, '{"1": "''연세가 있으신데 당연하지요.''는 대상자의 감정을 충분히 이해하지 못하는 표현입니다.\n[정답]", "2": "''어디가 아프세요? 병원에 갈까요?''는 공감은 있지만 적극적인 대처가 필요한 상황에서 덜 적절한 반응입니다.", "3": "''어르신만 아픈 게 아니에요. 저도 아파요.''는 공감적 표현이지만 자신을 지나치게 강조하는 반응입니다.", "4": "''건강하고 싶으신데 아프니까 힘드시죠?''는 대상자의 감정을 잘 표현한 것입니다.", "5": "''드시는 약 잘 챙겨 드셔야 해요.''는 조언 성격이 강하고 공감적 표현이 아닙니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "Người bệnh hoặc người nhận chăm sóc"}, {"term_ko": "공감", "term_vi": "Đồng cảm", "def_ko": "다른 사람의 감정을 이해하고 공유하는 것", "def_vi": "Hiểu và chia sẻ cảm xúc của người khác"}, {"term_ko": "표현", "term_vi": "Biểu hiện", "def_ko": "감정을 나타내는 방식", "def_vi": "Cách thể hiện cảm xúc"}, {"term_ko": "건강", "term_vi": "Sức khỏe", "def_ko": "신체적 상태가 좋음", "def_vi": "Tình trạng cơ thể tốt"}, {"term_ko": "아픔", "term_vi": "Đau", "def_ko": "고통의 느낌", "def_vi": "Cảm giác đau đớn"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (25, '8', '대상자가 요즘은 세월이 어떻게 가는지... 삶의 의미를 모르겠어.라고 할 때 공감의 표현으로 옳은 것은?', '["\"요즘 많이 힘들고 외로우신가 봐요.\"", "\"아드님께 전화라도 드릴까요?\"", "\"나이 먹으면 시간이 빨리 간대요.\"", "\"날씨도 좋은데 산책 가실래요?\"", "\"저도 요즘 그래요.\""]'::jsonb, 1, '대상자의 감정에 공감하고, 그들의 이야기를 이해하려고 하는 것이 중요함을 묻는 문제입니다.', NULL, '{"1": "''요즘 많이 힘들고 외로우신가 봐요.''는 대상자의 감정을 정확히 이해하고 표현한 공감의 예입니다.\n[정답]", "2": "''아드님께 전화라도 드릴까요?''는 공감보다는 해결책을 제안하는 것으로, 감정적 지지를 줄 수 없습니다.", "3": "''나이 먹으면 시간이 빨리 간대요.''는 일반화된 말로, 대상자의 감정에 대한 공감이 부족합니다.", "4": "''날씨도 좋은데 산책 가실래요?''는 행동을 제안하는 것이며 감정을 잘 품어주지 못합니다.", "5": "''저도 요즘 그래요.''는 자신의 경험을 이야기하는 것으로, 대상자의 감정을 소홀히 여기는 느낌을 줍니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자 또는 보살펴야 할 사람", "def_vi": "Bệnh nhân hoặc người cần được chăm sóc"}, {"term_ko": "공감", "term_vi": "Đồng cảm", "def_ko": "상대방의 감정을 이해하고 함께 느끼는 것", "def_vi": "Hiểu và cảm nhận cảm xúc của người khác"}, {"term_ko": "감정", "term_vi": "Cảm xúc", "def_ko": "마음의 상태", "def_vi": "Tình trạng của tâm trí"}, {"term_ko": "의미", "term_vi": "Ý nghĩa", "def_ko": "어떤 것의 가치나 중요성", "def_vi": "Giá trị hoặc tầm quan trọng của một điều"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (24, '8', '다음의 대화를 읽고 요양보호사의 공감적 반응으로 옳은 것은?• 대상자 : 맨날 양치질해라. 속옷 갈아입어라. 머리 빗어라 명령하고, 내가 어린애도 아니고, 귀찮아 죽겠네. • 요양보호사 : _________________', '["\"그런 식으로 말씀하지 마세요. 어린애처럼 스스로 못 책기시잖아요.\"", "\"어르신 말씀하시는 게 맞아요. 그럼 가족들에게 부탁하세요.\"", "\"깨끗하게 지내시라고 챙겨 드리는 거예요.\"", "\"사실은 저도 이렇게까지 챙기기 힘들었어요.\"", "\"어르신의 개인위생에 대해 일일이 간섭하는 것 같아 성가시고 화가 나셨나 봐요.\""]'::jsonb, 5, '요양보호사의 공감적 반응을 평가하는 문제입니다. 대화에서 대상자가 느끼는 감정을 이해하고 적절한 반응을 선택하는 것이 중요합니다.', NULL, '{"1": "그런 식으로 말씀하지 말라는 반응은 공감이 결여되어 있습니다.\n[정답]", "5": "어르신의 개인위생에 대한 간섭이 성가시고 화가 났다는 감정을 공감하며 반응하고 있습니다.", "2": "가족에게 부탁하라는 제안은 공감적이지 않습니다.", "3": "챙겨 드리는 이유를 설명하는 것은 공감이 아닙니다.", "4": "자신의 경험을 이야기하는 것은 공감이 아닌 자기 중심적인 반응입니다."}'::jsonb, '[{"term_ko": "공감", "term_vi": "Sự đồng cảm", "def_ko": "다른 사람의 감정을 이해하고 받아들이는 것", "def_vi": "Hiểu và chấp nhận cảm xúc của người khác"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "특정 상황에 대한 반응이나 행동", "def_vi": "Hành động hoặc phản ứng đối với một tình huống nhất định"}, {"term_ko": "개인위생", "term_vi": "Vệ sinh cá nhân", "def_ko": "개인의 청결과 위생을 유지하는 것", "def_vi": "Duy trì sự sạch sẽ và vệ sinh cá nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (23, '8', '다음의 대화에서 요양보호사의 공감적 반응으로 옳은 것은?• 대상자 : 나를 도와주던 요양보호사는 그만두었습니다? 그 사람이 참 잘했는데...... • 요양보호사 : _________________', '["\"그렇게 그 요양보호사가 잘했으면 그분 모셔다 드려요?\"", "\"그렇게 말씀하시니 기분이 참 나쁘네요.\"", "\"제가 그 사람보다 경력이 많아 더 잘할 수 있어요.\"", "\"제가 맘에 들지 않으시면 다른 사람을 소개해 드릴까요?\"", "\"지난번 요양보호사님이 일을 참 잘하셨나 봐요. 저도 열심히 할게요.\""]'::jsonb, 5, '대화에서 요양보호사가 대상자의 감정을 이해하고 공감하는 반응을 찾는 것입니다.', NULL, '{"1": "대상자의 감정을 존중하지 않는 반응입니다.\n[정답]", "5": "대상자의 긍정적인 경험을 인정하고, 계속해서 노력하겠다는 의지를 나타냅니다.", "2": "부정적인 감정을 드러내며 대화의 흐름을 방해합니다.", "3": "자신의 경력을 강조하여 대상자의 감정에 공감하지 않습니다.", "4": "대상자의 감정에 대한 이해 없이 다른 선택지를 제안하는 것입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 돌보는 전문직", "def_vi": "Người chăm sóc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (22, '8', '다음의 대화에서 요양보호사의 적절한 반응으로 옳은 것은?• 딸 : 엄마, 이제 요리하지 마세요. 맛이 예전 같지 않아요. • 대상자 : (화를 내면서 방으로 들어가며) 그러면 이제 네가 알아서 해 먹든지, 난 안 먹어. • 요양보호사 : (대상자에게 다가가) _________________', '["\"앞으로 음식은 제가 만들어 드릴게요.\"", "\"요리솜씨가 예전 같지 않다고 하니 속상하시지요.\"", "\"이런 일로 식사를 안 하시면 건강만 나빠지세요.\"", "\"이제 음식은 따님한테 하라고 하고 편히 쉬세요.\"", "\"엄마가 음식하기 힘드실까 봐 해 본 말일 거예요.\""]'::jsonb, 2, '요양보호사의 적절한 반응을 평가하기 위한 문제입니다. 대상자의 감정을 이해하고 공감하는 것이 중요합니다.', NULL, '{"1": "''앞으로 음식은 제가 만들어 드릴게요.'' - 이는 대화에 적절하지 않습니다. 간섭으로 비춰질 수 있습니다.\n[정답]", "2": "''요리솜씨가 예전 같지 않다고 하니 속상하시지요.'' - 이는 대상자의 감정을 인정하고 공감하는 반응입니다.", "3": "''이런 일로 식사를 안 하시면 건강만 나빠지세요.'' - 이는 대상자를 압박하는 듯한 표현으로 바람직하지 않습니다.", "4": "''이제 음식은 따님한테 하라고 하고 편히 쉬세요.'' - 이는 대상자의 자존심을 상하게 할 수 있습니다.", "5": "''엄마가 음식하기 힘드실까 봐 해 본 말일 거예요.'' - 이 또한 대상자의 감정을 고려하지 않은 반응입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌보는 사람", "def_vi": "Người chăm sóc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (21, '8', '실금한 대상자가 옷 갈아입기를 거부할 때 ''나-전달법'' 표현으로 옳은 것은?', '["\"벗지 않으면 서비스를 더 이상 진행할 수 없어요.\"", "\"갈아입지 않으면 피부에 발진이 생길까 봐 염려가 돼요.\"", "\"왜 고집을 피우세요. 빨리 당장 벗으세요.\"", "\"왜 갈아입기가 싫으신데요?\"", "\"옷을 벗지 않으면 며느님께 연락드릴 거예요.\""]'::jsonb, 2, '대상자의 감정이나 입장을 고려하여 의사를 전달하는 방법을 이해하고 선택하는 것이 중요함.', NULL, '{"1": "대상자의 의사를 존중하지 않고 서비스 제공을 중단하겠다는 위협적 표현이다.\n[정답]", "2": "대상자의 건강과 안전을 염려하는 표현으로, 나-전달법에 부합한다.", "3": "상대방을 무시하는 듯한 명령조 표현이다.", "4": "질문으로 의사를 물어보지만, 나-전달법의 긍정적인 요소가 부족하다.", "5": "협박처럼 들리는 표현으로, 적절하지 않다."}'::jsonb, '[{"term_ko": "실금", "term_vi": "Tiểu không tự chủ", "def_ko": "소변이나 대변을 의도치 않게 누는 것", "def_vi": "Tiểu tiện hoặc đại tiện không tự chủ"}, {"term_ko": "옷 갈아입기", "term_vi": "Thay đồ", "def_ko": "옷을 바꾸는 과정", "def_vi": "Quá trình thay đổi quần áo"}, {"term_ko": "나-전달법", "term_vi": "Phương pháp truyền đạt ‘Tôi’", "def_ko": "자신의 감정을 표현하는 방법", "def_vi": "Phương pháp diễn đạt cảm xúc của bản thân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (20, '8', '다음의 상황에서 ''나-전달법''을 활용한 요양보호사의 반응으로 옳은 것은?• 요양보호사 : 요즘 식사량이 줄어서 몸무게도 줄어든 것 같아요. 좋아하시는 음식을 준비했으니 좀 맛 좀 보세요. • 대상자 : (조금 먹더니) 입맛이 없어서 더 못 먹겠어요... 미안해요. • 요양보호사 : _________________', '["\"집에서 좋아하는 음식을 만들어 오라고 할까요?\"", "\"드시고 싶은 음식은 따로 없으세요?\"", "\"잘 못 드시는 것 같은데 무슨 걱정이라도 있으세요?\"", "\"위염이 있으신가 봐요. 병원진료를 받으셔야겠어요.\"", "\"식사량이 줄어서 건강이 나빠질까 봐 걱정되네요.\""]'::jsonb, 5, '요양보호사가 대상자의 감정과 걱정을 이해하고 공감하는 반응을 통해, 편안한 대화를 이끌어가는 방법을 확인하고자 한다.', NULL, '{"1": "''집에서 좋아하는 음식을 만들어 오라고 할까요?'' - 대상자의 상황을 직접적으로 이해하지 못하는 제안이다.\n[정답]", "5": "''식사량이 줄어서 건강이 나빠질까 봐 걱정되네요.'' - 대상자의 현재 상황에 공감하며 걱정하는 반응이다.", "3": "''잘 못 드시는 것 같은데 무슨 걱정이라도 있으세요?'' - 이는 대화의 초점을 흐릴 수 있다.", "4": "''위염이 있으신가 봐요. 병원진료를 받으셔야겠어요.'' - 가능한 상황에 대한 주장을 하여 부담을 줄 수 있다.", "2": "''드시고 싶은 음식은 따로 없으세요?'' - 공감보다 질문으로 대화를 이끄는 방식이다."}'::jsonb, '[{"term_ko": "식사량", "term_vi": "입맛", "def_ko": "양 thức ăn (khối lượng thức ăn)", "def_vi": "khẩu vị (vị giác)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (19, '8', '재가대상자가 식탁 위에 밥 먹은 그릇을 그대로 두어 밥풀이 말라붙어 있을 때 ''나-전달법''으로 적절하게 반응한 것은?', '["\"식사를 하신 지 오래되었나 봐요.\"", "\"밥풀이 하나도 안 남게 깨끗이 좀 드세요.\"", "\"그릇이 그대로 있네요. 어디가 불편하세요?\"", "\"밥풀이 말라붙어 있는 것을 보니 맛있게 드셨군요.\"", "\"밥풀이 말라붙어서 설거지하기가 힘들어요. 다 드신 그릇은 싱크대 물에 담가 두셨으면 좋겠어요.\""]'::jsonb, 5, '재가대상자의 식사 후 반응을 아는 것이 중요합니다.', NULL, '{"1": "식사 시간이 오래 지났다며 수동적인 반응을 보이는 것은 부적절합니다.\n[정답]", "5": "밥풀이 말라붙은 상황을 설명하며 부탁하는 것으로 적절한 반응입니다.", "3": "불편함을 묻는 것은 상황을 해결하는데 도움이 되지 않습니다.", "2": "강압적인 표현으로 요양보호사가 아닌 접근입니다.", "4": "긍정적인 해석이지만, 요청을 하지 않아 상황을 개선하지 못합니다."}'::jsonb, '[{"term_ko": "재가대상자", "term_vi": "Người được chăm sóc tại nhà", "def_ko": "가정에서 요양을 받는 사람", "def_vi": "Người nhận sự chăm sóc tại nhà"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (18, '8', '재가 어르신이 업무시간 이외의 시간에 자주 전화를 하여 푸념을 할 때 ''나-전달법''으로 반응한 것은?', '["\"외로우셔서 자꾸 저한테 전화하시는 거예요?\"", "\"저보다는 가족분들에게 전화하시는 게 좋을 것 같아요.\"", "\"자꾸 전화하시니 제가 찾아봬도 되는지 센터장님에게 물어보고 갈게요.\"", "\"요새 스트레스가 많으신가 봐요. 제가 해결해 드릴 수 있는 일이라면 좋을 텐데...\"", "\"업무 시간 외에 전화하시면 제 일을 못 해서 힘들어요. 업무 시간에 말씀해 주시면 좋겠어요.\""]'::jsonb, 5, '어르신의 심리적 상태와 소통 방식에 대한 이해를 평가하기 위해 출제된 문제입니다.', NULL, '{"1": "재가 어르신의 심리적 상태를 이해하려는 긍정적인 접근이지만, ''나-전달법''의 요구에 부합하지 않습니다.\n[정답]", "5": "자신의 입장을 명확히 전달하며 업무 시간을 구분하는 것은 ''나-전달법''의 전형적인 예시입니다.", "2": "가족 권유는 긍정적인 의도로 보이나 본인의 경계를 설정하지 않습니다.", "3": "자신의 경계를 설정하고 대안을 제시했지만 ''나-전달법''의 직접적인 표현이 아닙니다.", "4": "상대방의 심리를 파악하려는 접근은 좋지만 직접적인 ''나-전달법''이 아닙니다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Tại gia", "def_ko": "방문하여 돌보는 것(한국어)", "def_vi": "Chăm sóc tại nhà"}, {"term_ko": "업무시간", "term_vi": "Thời gian làm việc", "def_ko": "일하는 시간(한국어)", "def_vi": "Thời gian làm việc"}, {"term_ko": "푸념", "term_vi": "Than phiền", "def_ko": "불평하는 것(한국어)", "def_vi": "Phàn nàn"}, {"term_ko": "전달법", "term_vi": "Phương pháp truyền đạt", "def_ko": "의사소통 방법(한국어)", "def_vi": "Phương pháp giao tiếp"}, {"term_ko": "가족", "term_vi": "Gia đình", "def_ko": "가까운 친인척(한국어)", "def_vi": "Người thân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (17, '8', '다음 상황에서 요양보호사의 공감적 반응으로 적절한 것은?• 대상자 : 나이를 먹을수록 후회되는 일도 많고, 사는 게 재미도 없고, 외롭네...... • 요양보호사 : _________________', '["\"우울증인 것 같으니 검사를 받으셔야겠어요.\"", "\"요즘 많이 외롭고 힘드신가 봐요.\"", "\"재미있는 프로그램에 참여하시겠어요?\"", "\"부정적인 감성은 건강에 해로워요.\"", "\"나이가 들면 대부분 다 그렇게 느껴요.\""]'::jsonb, 2, '요양보호사가 대상자의 감정을 이해하고 공감해주는 것이 중요함을 평가하기 위한 문제입니다.', NULL, '{"1": "우울증을 언급하며 검사받자고 하는 것은 공감적 반응이라기보다는 진단적인 접근으로 비춰질 수 있습니다.\n[정답]", "2": "대상자의 외로움과 힘듦을 인정하며 공감하는 반응입니다.", "3": "즐거운 활동 참여를 묻는 것은 대상자의 감정에 대한 반응이 아니라 해결책을 제시하는 것입니다.", "4": "부정적인 감성이 건강에 해롭다는 일반적인 진술로, 대상자의 감정을 존중하지 않습니다.", "5": "나이가 들면 공감이 되더라도, 듣는 이의 감정을 적절히 반영하지 않는 일반화된 답변입니다."}'::jsonb, '[{"term_ko": "공감적", "term_vi": "Đồng cảm", "def_ko": "감정이나 느낌을 이해하고 함께 느끼는 것", "def_vi": "Hiểu và cảm nhận cùng cảm xúc"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (16, '8', '난청인 대상자와 의사소통하는 방법으로 옳은 것은?', '["고음의 큰소리로 말한다.", "입력은 작게, 출력은 크게 한다.", "손으로 입을 가리고 말한다.", "밝은 장소에서 입을 크게 벌리며 말한다.", "실물, 그림판, 문자판을 이용하여 설명한다."]'::jsonb, 4, '난청인의 의사소통 방법을 이해하고 실천할 수 있는 능력을 평가하기 위함입니다.', NULL, '{"1": "고음의 큰소리로 말하는 것은 난청인에게 효과적이지 않음.\n[정답]", "4": "밝은 장소에서 입을 크게 벌리며 말하는 것은 난청인이 이야기를 이해하는 데 도움이 됨.", "2": "입력은 작게, 출력은 크게 하는 것은 기본적인 의사소통 방식에서 벗어남.", "3": "손으로 입을 가리고 말하면 난청인이 입 모양을 보지 못해 의사소통에 방해가 됨.", "5": "실물, 그림판, 문자판을 이용하여 설명하는 것은 좋은 방법이지만, 보기 중에서는 4번이 더 적절함."}'::jsonb, '[{"term_ko": "난청인", "term_vi": "Người khiếm thính", "def_ko": "청력이 떨어진 사람", "def_vi": "Người có thính lực kém"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "서로의 생각이나 정보를 주고받는 것", "def_vi": "Trao đổi thông tin hoặc ý tưởng giữa các cá nhân"}, {"term_ko": "입 모양", "term_vi": "Hình dáng môi", "def_ko": "말할 때 입의 모양", "def_vi": "Hình dạng miệng khi nói"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (15, '8', '시각장애 대상자와 이야기하는 방법으로 옳은 것은?', '["몸짓과 얼굴표정을 사용하여 대화한다.", "대상자를 만났을 때 신체접촉 후 말을 건넨다.", "대상자와 반걸음 떨어져 보행한다.", "대상자 중심으로 오른쪽, 왼쪽을 설명하여 원칙을 정해둔다.", "''이쪽'', ''저쪽''과 같은 지시대명사를 많이 사용한다."]'::jsonb, 4, '시각장애인을 효과적으로 의사소통하기 위한 방법을 이해하고 있는지를 평가하고자 하였다.', NULL, '{"1": "몸짓과 얼굴표정을 사용하여 대화한다: 시각장애인에게는 시각적 신호가 부족하므로 비언어적 의사소통 방법이 전통적으로 사용되지만, 주된 의사소통 방식은 아님.\n[정답]", "4": "대상자 중심으로 오른쪽, 왼쪽을 설명하여 원칙을 정해둔다: 방향을 알려주는 것은 시각장애인이 공간을 인식하는 데 도움이 된다.", "2": "대상자를 만났을 때 신체접촉 후 말을 건넨다: 신체접촉은 예기치 않게 이루어질 경우 불안감을 유발할 수 있다.", "3": "대상자와 반걸음 떨어져 보행한다: 너무 간격을 두면 친밀감이 떨어질 수 있으며, 시각장애인에게는 도움이 되지 않는다.", "5": "''이쪽'', ''저쪽''과 같은 지시대명사를 많이 사용한다: 명확한 지시가 필요하기 때문에 이 방법은 적절하지 않다."}'::jsonb, '[{"term_ko": "시각장애", "term_vi": "Khiếm thị", "def_ko": "시각 기능이 제한되거나 상실된 상태", "def_vi": "Trạng thái giảm hoặc mất khả năng thị giác"}, {"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "돌봄을 받는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "신체접촉", "term_vi": "Tiếp xúc cơ thể", "def_ko": "신체를_touch하는 행위", "def_vi": "Hành động chạm vào cơ thể"}, {"term_ko": "보행", "term_vi": "Đi bộ", "def_ko": "걷는 것", "def_vi": "Hành động đi lại"}, {"term_ko": "지시대명사", "term_vi": "Đại từ chỉ định", "def_ko": "방향을 나타내는 대명사", "def_vi": "Đại từ chỉ ra hướng"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (14, '8', '알아듣기는 하나 말을 할 수 없는 대상자와 의사소통하는 방법으로 옳은 것은?', '["몸짓과 얼굴표정을 사용하여 대화한다.", "대상자를 만났을 때 신체접촉 후 말을 건넨다.", "대상자와 반걸음 떨어져 보행한다.", "대상자 중심으로 오른쪽, 왼쪽을 설명하여 원칙을 정해둔다.", "''이쪽'', ''저쪽''과 같은 지시대명사를 많이 사용한다."]'::jsonb, 4, '대상자가 알아듣기는 하지만 말을 할 수 없는 상황에서 어떻게 의사소통을 효과적으로 할 수 있는지에 대한 이해를 평가하기 위함입니다.', NULL, '{"1": "몸짓과 얼굴표정을 사용하여 대화한다. (신체 언어는 의사소통에 도움이 되지만, 단순히 그것만으로는 부족할 수 있다.)\n[정답]", "4": "대상자 중심으로 오른쪽, 왼쪽을 설명하여 원칙을 정해둔다. (대상자가 이해할 수 있도록 방향을 명확히 할 수 있다.)", "3": "대상자와 반걸음 떨어져 보행한다. (거리 유지가 중요한데, 너무 멀어지면 의사소통이 어렵다.)", "2": "대상자를 만났을 때 신체접촉 후 말을 건넨다. (신체 접촉이 항상 좋은 의사소통 방법은 아니다.)", "5": "''이쪽'', ''저쪽''과 같은 지시대명사를 많이 사용한다. (모호한 지시대명사는 이해를 저해할 수 있다.)"}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자나 돌보아야 할 사람", "def_vi": "Bệnh nhân hoặc người cần chăm sóc"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통이나 정보를 교환하는 과정", "def_vi": "Quá trình trao đổi thông tin"}, {"term_ko": "신체접촉", "term_vi": "Tiếp xúc thể chất", "def_ko": "몸이 서로 맞닿는 것", "def_vi": "Khi cơ thể chạm vào nhau"}, {"term_ko": "지시대명사", "term_vi": "Đại từ chỉ hướng", "def_ko": "사람이나 사물을 지시하는 대명사", "def_vi": "Đại từ chỉ người hoặc vật"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (13, '8', '알아듣기는 하나 말을 할 수 없는 대상자와 의사소통하는 방법으로 옳은 것은?', '["친근감 있게 유아어를 쓴다.", "대상자의 옆에서 귀에 대고 말한다.", "긴장하지 않게 음악을 틀어 놓고 말한다.", "그림판, 문자판을 이용하여 의사를 표현하게 한다.", "요양보호사를 중심으로 오른쪽, 왼쪽 방향을 정하여 설명한다."]'::jsonb, 4, '대상자와의 효과적인 의사소통 방법을 알고 있는지를 평가하기 위함입니다.', NULL, '{"1": "친근감 있게 유아어를 쓴다. - 유아어 사용은 적절하지 않으며 상황을 혼란스럽게 할 수 있습니다.\n[정답]", "4": "그림판, 문자판을 이용하여 의사를 표현하게 한다. - 시각적 도구를 사용하여 의사소통하는 것은 효과적인 방법입니다.", "3": "긴장하지 않게 음악을 틀어 놓고 말한다. - 음악이 의사소통에 도움이 되지 않을 수 있습니다.", "2": "대상자의 옆에서 귀에 대고 말한다. - 이렇게 하는 것은 대상을 불편하게 할 수 있습니다.", "5": "요양보호사를 중심으로 오른쪽, 왼쪽 방향을 정하여 설명한다. - 방향지시가 필요하지 않은 경우 오히려 혼동을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "교류(감정, 생각 등)를 하는 것", "def_vi": "Sự trao đổi (cảm xúc, suy nghĩ, v.v.)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (12, '8', '다음과 같은 방법으로 의사소통해야 하는 대상자로 옳은 것은?• 실물, 그림판, 문자판을 이용한다. • 눈을 깜빡이거나 손짓, 고개를 끄덕이는 등으로 의사표현하게 한다. • 말로 잘 표현했을 때 칭찬과 더불어 긍정적 공감을 비언어적으로 표현해 준다.', '["청각장애", "언어장애", "시각장애", "지남력장애", "주의력결핍"]'::jsonb, 2, '대상자의 의사소통 방법에 대한 이해를 평가하기 위한 문제이다.', NULL, '{"1": "청각장애는 주로 청각적 정보에 대한 이해가 어려운 경우로, 실물이나 그림판을 사용할 수 없다.\n[정답]", "2": "언어장애는 언어적 표현에 어려움이 있는 상황으로, 비언어적 의사소통 방법을 통해 소통할 수 있다.", "3": "시각장애는 시각적 정보를 인식할 수 없는 경우로, 실물과 그림판을 사용할 수 없다.", "4": "지남력장애는 시간과 장소에 대한 인지 문제로, 의사소통 방법과 관련이 없다.", "5": "주의력결핍은 집중력 문제로, 의사소통의 방법과는 관련이 적다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통, 나누기", "def_vi": "Truyền đạt, giao tiếp"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (11, '8', '치매 대상자와 의사소통할 때 기본 원칙을 지켜 반응한 것으로 옳은 것은?', '["\"왜 과일을 안 드셨어요?\"", "\"아침 8시예요. 약 드실 시간이에요.\"", "\"아까 그 사람은 누구예요?\"", "\"어디 불편한 곳은 없으세요?\"", "\"점심 드시고 나서 바나나를 간식으로 드세요.\""]'::jsonb, 2, '치매 대상자와의 효과적인 의사소통 원칙을 이해하고 적용하는지를 평가하는 문제입니다.', NULL, '{"1": "''왜 과일을 안 드셨어요?''는 치매 대상자에게 부정적인 감정을 유발할 수 있습니다.\n[정답]", "2": "''아침 8시예요. 약 드실 시간이에요.''는 치매 대상자의 일상 스케줄을 지원하는 긍정적인 의사소통입니다.", "3": "''아까 그 사람은 누구예요?''는 혼란을 줄 수 있는 질문입니다.", "4": "''어디 불편한 곳은 없으세요?''는 직접적인 질문으로 혼동을 줄 수 있습니다.", "5": "''점심 드시고 나서 바나나를 간식으로 드세요.''는 지시적인 언급으로 불편감을 초래할 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "치매(이해력과 기억력이 감소하는 병)", "def_vi": "Bệnh mất khả năng hiểu và ghi nhớ."}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (10, '8', '치매로 인한 이해력장애 대상자와의 이야기하는 방법으로 옳은 것은?', '["실물이나 그림판, 문자판 등은 생략한다.", "요양보호사의 속도에 맞추어 이야기한다.", "친근함을 위해 반말로 이야기한다.", "전문적인 용어를 사용한다.", "짧은 문장으로 천천히 이야기한다."]'::jsonb, 5, '치매로 인한 이해력장애가 있는 대상자와의 효과적인 의사소통 방법에 대한 이해를 묻는 문제입니다.', NULL, '{"1": "실물이나 그림판, 문자판 등은 생략한다. 이 방법은 이해력장애가 있는 대상자에게 도움이 되지 않습니다.\n[정답]", "5": "짧은 문장으로 천천히 이야기한다. 이는 이해를 돕고 소통을 원활하게 합니다.", "2": "요양보호사의 속도에 맞추어 이야기한다. 이는 대상자의 이해를 고려하지 않는 방법입니다.", "3": "친근함을 위해 반말로 이야기한다. 이는 대상자와의 관계를 악화시킬 수 있습니다.", "4": "전문적인 용어를 사용한다. 이해력장애가 있는 대상자에게는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억과 사고 능력이 저하되는 상태", "def_vi": "Tình trạng suy giảm trí nhớ và khả năng suy nghĩ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (9, '8', '치매로 인한 주의력 결핍장애 대상자와 의사소통방법으로 옳은 것은?', '["대상자와 눈을 피한다.", "정확하고 자세하게 설명한다.", "환경적 자극을 최대한 줄인다.", "내용을 빠르고 반복적으로 말한다.", "복잡한 활동을 먼저 제시한다."]'::jsonb, 3, '치매로 인한 주의력 결핍장애를 가진 대상자에게 적절한 의사소통 방법을 이해하고 선택하는 것이 중요하다.', NULL, '{"1": "대상자와 눈을 피하는 것은 의사소통에 비협조적이다.\n[정답]", "2": "정확하고 자세하게 설명하는 것은 좋지만 청취할 준비가 되어 있지 않을 수 있다.", "3": "환경적 자극을 최대한 줄이는 것은 집중력 향상에 도움이 된다.", "4": "내용을 빠르고 반복적으로 말하는 것은 오히려 혼란을 줄 수 있다.", "5": "복잡한 활동을 먼저 제시하는 것은 주의력이 결핍된 대상자에게 불리하다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력과 사고력을 저하시키는 질병", "def_vi": "Bệnh làm suy giảm trí nhớ và khả năng tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (8, '8', '치매로 인한 지남력장애 대상자와 의사소통방법으로 옳은 것은?', '["전문용어로 자세히 설명한다.", "대상자의 미래 계획을 함께 세운다.", "대중 매체에 나오는 신조어를 사용한다.", "장소, 날짜, 시간에 대해 자주 인식시킨다.", "친밀감을 표현하기 위해 별명을 사용한다."]'::jsonb, 4, '치매 환자와의 효과적인 의사소통 방법을 이해하고 적용하기 위한 문제입니다.', NULL, '{"1": "전문용어로 설명하면 혼란을 초래할 수 있습니다.\n[정답]", "4": "장소, 날짜, 시간에 대한 인식은 지남력장애 대상자에게 매우 중요합니다.", "2": "미래 계획을 세우는 것은 어렵고 혼란을 초래할 수 있습니다.", "3": "신조어 사용은 이해를 더욱 어렵게 만듭니다.", "5": "별명 사용은 친밀감을 줄 수 있지만 신뢰를 구축하는 데 한계가 있을 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "알츠하이머(한국어)", "def_vi": "Bệnh mất trí nhớ"}, {"term_ko": "지남력장애", "term_vi": "Rối loạn định hướng", "def_ko": "방향감각 상실(한국어)", "def_vi": "Mất khả năng nhận thức thời gian và không gian"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "커뮤니케이션(한국어)", "def_vi": "Hình thức trao đổi thông tin"}, {"term_ko": "전문용어", "term_vi": "Thuật ngữ chuyên môn", "def_ko": "전문적 용어(한국어)", "def_vi": "Thuật ngữ trong lĩnh vực nhất định"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (7, '8', '다음과 같은 대화를 읽고 지남력 증진을 위한 요양보호사의 표현으로 옳은 것은?• 대상자 : (눈 내리는 창밖을 보며) 벚꽃이 지기 전에 빨리 벚꽃 구경하러 갑시다. • 요양보호사 : _________________', '["\"눈이 와서 미끄러워요. 다음에 가요.\"", "\"놀러가고 싶으신가 봐요?\", \"밖에 나가고 싶으신가 봐요.\"", "\"지금은 져울이에요. 벚꽃 구경은 봅에 가요.\"", "\"지금은 꽃이 핀 데가 없어요.\"", "\"화전이 드시고 싶으신가 봐요.\""]'::jsonb, 3, '지남력 증진을 위해 요양보호사가 어떻게 반응해야 하는지를 묻는 문제입니다.', NULL, '{"1": "눈이 와서 미끄러워서 외출을 권하지 않는 표현으로 대상자의 감정을 무시합니다.\n[정답]", "2": "대상자의 희망을 물어보며 긍정적인 반응을 보입니다.", "3": "현재 상황에 대한 사실을 전달하였으나, 대상자의 감정을 고려하지 않았습니다.", "4": "만약 벚꽃이 핀 곳이 없다는 부정적 표현입니다.", "5": "''화전''이란 언급은 적절하지 않습니다."}'::jsonb, '[{"term_ko": "지남력", "term_vi": null, "def_ko": "인식하여 길을 잘 찾아가는 능력(한국어)", "def_vi": null}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (6, '8', '다음과 같은 상황에서 효과적으로 의사소통하는 방법으로 옳은 것은?• 치매 대상자 : 아이고, 나 죽네...... 배 아파 죽겠어. • 요양보호사 : _________________', '["\"어디가 불편하세요?\"", "(배를 짚으며) \"여기가 아프세요?\"", "\"많이 아프시군요. 장염인가 봐요?\"", "\"간식으로 무엇을 먹었는지 말해보세요.\"", "\"속이 쓰리세요? 더부룩하세요? 콕콕 쑤시나요?\""]'::jsonb, 2, '치매 대상자와의 효과적인 의사소통 방법을 묻고 있습니다. 치매 환자는 자신의 증상을 정확히 표현하기 어려운 경우가 많으므로, 요양보호사는 환자의 표현을 보완하는 방향으로 질문을 해야 합니다.', NULL, '{"1": "''어디가 불편하세요?''는 다소 추상적인 질문으로, 추가적인 정보를 얻기 어렵습니다.\n[정답]", "2": "''(배를 짚으며) 여기가 아프세요?''는 환자의 불편한 부위를 명확히 파악하는 데 도움을 줍니다.", "3": "''많이 아프시군요. 장염인가 봐요?''라는 질문은 정확한 진단이 아닌 추측성 대답으로, 환자의 불안감을 초래할 수 있습니다.", "4": "''간식으로 무엇을 먹었는지 말해보세요.''는 증상과의 직접 연결이 없어, 효과적인 대화로 이어지지 않습니다.", "5": "''속이 쓰리세요? 더부룩하세요? 콕콕 쑤시나요?''와 같은 질문은 복잡하고, 환자가 이해하기 어려울 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Mất trí nhớ", "def_ko": "기억력을 상실하는 질병(한국어)", "def_vi": "Bệnh mất khả năng nhớ"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보를 주고받는 것(한국어)", "def_vi": "Hành động trao đổi thông tin"}, {"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "도움을 받는 사람(한국어)", "def_vi": "Người nhận sự giúp đỡ"}, {"term_ko": "불편하다", "term_vi": "Không thoải mái", "def_ko": "편하지 않다(한국어)", "def_vi": "Không dễ chịu"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병의 나타나는 조짐(한국어)", "def_vi": "Dấu hiệu của bệnh"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인이나 환자의 돌보는 전문가(한국어)", "def_vi": "Người chăm sóc cho người già hoặc bệnh nhân"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (5, '8', '치매 대상자가 환각증상을 보이며 문밖에 우리 딸이 와 있어. 딸한테 가야겠어.라고 할 때 요양보호사의 의사소통 방법으로 옳은 것은?', '["\"문밖에 아무도 없는데요.\"", "\"따님이 많이 그리우신가 봐요.\"", "\"식사하시면 따님께 연락드릴게요.\"", "\"거짓말 하시면 간식 안 드릴 거예요.\"", "\"원래 따님 없으시잖아요?\""]'::jsonb, 2, '치매 대상자의 환각 증상에 대한 올바른 의사소통 방법을 이해하고 선택하는 것이다.', NULL, '{"1": "환각 증상에 대해 부정하는 접근 방식은 대상자의 정서를 더욱 상하게 할 수 있다.\n[정답]", "2": "대상자가 느끼는 감정을 인정하고 공감하는 방식으로, 환자가 안심할 수 있도록 돕는다.", "3": "식사 후 연락하겠다고 하는 것은 즉각적인 감정이나 불안에 대한 반응이 아니다.", "4": "협박적인 말투는 대상자의 불안을 더욱 증폭시킬 수 있다.", "5": "사실 확인을 통한 부정적인 반응은 대상자의 정신적 상태에 도움이 되지 않는다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력 및 사고 능력 저하를 동반한 질환", "def_vi": "Bệnh lý giảm trí nhớ và khả năng tư duy"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (4, '8', '다음을 읽고 요양보호사가 추천하는 여가활동 유형으로 옳은 것은?• 대상자 : 내가 예전에는 글쓰기를 좋아해서 일기를 매일 썼는데...... • 요양보호사 : 글짓기 프로그램이 있는데 참여해 보시는 건 어떠세요?', '["자기계발 활동", "가족중심 활동", "사교오락 활동", "운동 활동", "소일 활동"]'::jsonb, 1, '여가활동 유형에 대한 이해를 평가하고, 요양보호사가 대상자에게 적절한 활동을 추천할 수 있는지를 확인하기 위함입니다.', NULL, '{"1": "자기계발 활동: 글쓰기와 같은 활동은 자기계발의 일환으로 볼 수 있습니다.\n[정답]", "2": "가족중심 활동: 가족과 함께하는 활동이 아니므로 부적절합니다.", "3": "사교오락 활동: 글짓기는 사교와는 거리가 먼 개인적인 활동입니다.", "4": "운동 활동: 운동과 관련된 활동이 아니므로 맞지 않습니다.", "5": "소일 활동: 글쓰기는 소일의 범주에 포함될 수 있으나, 자기계발 활동이 더 적합합니다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가를 활용하는 활동", "def_vi": "Các hoạt động sử dụng thời gian rảnh"}, {"term_ko": "자기계발", "term_vi": "Phát triển bản thân", "def_ko": "자신을 발전시키는 활동", "def_vi": "Các hoạt động để phát triển bản thân"}, {"term_ko": "사교오락", "term_vi": "Giao lưu vui chơi", "def_ko": "서로 만나 즐기는 활동", "def_vi": "Các hoạt động để gặp gỡ và vui chơi"}, {"term_ko": "소일", "term_vi": "Tiêu khiển", "def_ko": "시간을 보내는 개인적인 활동", "def_vi": "Các hoạt động cá nhân để tiêu thời gian"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (3, '8', '다음의 대화에서 요양보호사가 제안하는 여가활동의 유형으로 옳은 것은?• 대상자 : 문화생활? 그런 게 어디 있어? 하루 종일 텔레비전 보는 게 다야...... • 요양보호사 : 어르신, 우리 재미있는 영화 보러 영화관에 갈까요?', '["자기계발 활동", "가족중심 활동", "사교오락 활동", "운동 활동", "소일 활동"]'::jsonb, 3, '요양보호사가 제안하는 여가활동의 유형을 이해하고 그에 맞는 선택지를 고르는 것이다.', NULL, '{"1": "자기계발 활동은 개인의 능력을 향상시키기 위한 활동이며, 영화 관람과는 관계가 없다.\n[정답]", "3": "사교오락 활동은 친구나 가족과 함께 즐기는 놀이 또는 오락을 포함하며, 영화 관람이 이에 해당한다.", "2": "가족중심 활동은 가족과 함께 하는 활동을 의미하며, 여기서는 어르신과 요양보호사 간의 활동이다.", "4": "운동 활동은 신체 활동을 포함하며, 영화 관람과는 관련이 없다.", "5": "소일 활동은 취미나 소소한 일을 의미하므로 영화 관람과는 적합하지 않다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인이나 장애인을 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc người già hoặc người khuyết tật"}, {"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간에 하는 활동", "def_vi": "Hoạt động thực hiện trong thời gian rảnh"}, {"term_ko": "사교오락", "term_vi": "Giải trí xã hội", "def_ko": "친구나 가족과 함께 즐기는 놀이 또는 오락", "def_vi": "Vui chơi hoặc giải trí cùng bạn bè hoặc gia đình"}, {"term_ko": "자기계발", "term_vi": "Phát triển bản thân", "def_ko": "개인의 능력 향상", "def_vi": "Nâng cao khả năng cá nhân"}, {"term_ko": "소일 활동", "term_vi": "Hoạt động tiêu khiển", "def_ko": "취미나 소소한 일", "def_vi": "Sở thích hoặc công việc nhỏ"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (2, '8', '다음의 대화에서 요양보호사가 제안하는 여가활동의 유형으로 옳은 것은?• 대상자 : (지팡이로 이동하며) 하루 종일 갇혀 있는 것 같아. 밖에 나가지도 못하고...... • 요양보호사 : 예전에 농사일 지으셨다면서요. 옥상 텃밭에서 상추를 가꾸어 보시는 건 어떠세요?', '["자기계발 활동", "가족중심 활동", "사교오락 활동", "운동 활동", "소일 활동"]'::jsonb, 5, '대상자가 느끼는 우울감이나 고립감을 해소하기 위한 여가활동의 적절한 예를 찾는 것이며, 요양보호사가 제안한 상추 가꾸기는 소일 활동에 해당함.', NULL, '{"1": "자기계발 활동: 본인의 능력을 개발하는 활동으로, 제안된 내용과는 무관함.", "2": "가족중심 활동: 가족과의 관계를 증진시키는 활동으로, 이 경우에 적합하지 않음.", "3": "사교오락 활동: 사람들과의 교류 및 오락을 포함하는 활동이나, 옥상 텃밭 가꾸기는 그와는 다름.", "4": "운동 활동: 신체 활동을 포함하지만 텃밭 가꾸기는 운동보다는 정원 가꾸기에 더 중점을 둠.\n[정답]", "5": "소일 활동: 제안된 옥상 텃밭에서 상추를 가꾸는 활동은 소일 활동으로서, 적절한 여가활동의 예시이다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간을 활용하는 활동(한국어)", "def_vi": "hoạt động tận dụng thời gian rảnh (베트남어)"}]'::jsonb);
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1, '8', '거동이 불편하고 인지기능이 저하된 대상자의 여가활동으로 옳은 것은?', '["가족의 의견을 중심으로 프로그램을 지원한다.", "낙상의 위험이 있으므로 활동에서 배재한다.", "움직임이 빠르고 활동적인 프로그램을 제공한다.", "어렵지 않고 단순하고 흥미로운 활동으로 진행한다.", "개인보다 단체를 위한 집단 프로그램을 제공한다."]'::jsonb, 4, '대상자의 여가활동에 대한 올바른 이해를 평가하기 위함입니다.', NULL, '{"1": "가족의 의견을 반영하되, 대상자의 개인적 선호도 고려가 필요합니다.\n[정답]", "4": "대상자의 능력과 흥미를 고려하여 어렵지 않고 단순한 활동이 적합합니다.", "3": "거동이 불편한 대상자에게는 활동적인 프로그램이 적합하지 않습니다.", "5": "개인의 선호에 따라 단체 활동보다는 개인에 맞춘 활동이 필요할 수 있습니다.", "2": "대상자는 적절한 여가활동을 통해서도 활동성을 유지할 수 있습니다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Di chuyển", "def_ko": "움직임, 행위", "def_vi": "chuyển động, hành vi"}, {"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "인지 능력", "def_vi": "khả năng nhận biết"}, {"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간에 하는 활동", "def_vi": "hoạt động trong thời gian rảnh"}, {"term_ko": "낙상", "term_vi": "Ngã", "def_ko": "넘어짐", "def_vi": "sự ngã"}, {"term_ko": "프로그램", "term_vi": "Chương trình", "def_ko": "계획된 활동", "def_vi": "hoạt động đã được lập kế hoạch"}, {"term_ko": "단체", "term_vi": "Nhóm", "def_ko": "집단", "def_vi": "tập thể"}, {"term_ko": "개인", "term_vi": "Cá nhân", "def_ko": "개인", "def_vi": "cá nhân"}]'::jsonb);
